/* ============================================================
   Procedure: [dbo].[usp_GetWhtsTemplateDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_GetWhtsTemplateDetails
    @TempId BIGINT
AS
BEGIN
    SET NOCOUNT ON;

    BEGIN TRY
        SELECT 
            template_name,
            template_language
        FROM 
            convtemplates
        WHERE 
            parentid = @TempId;

        -- Optional: Handle case where no result is found, by selecting default values
        IF @@ROWCOUNT = 0
        BEGIN
            SELECT 'DefaultTemplate' AS template_name, 'en' AS template_language;
        END
    END TRY
    BEGIN CATCH
        -- Error handling
        SELECT ERROR_MESSAGE() AS ErrorMessage;
    END CATCH
END



GO

