/* ============================================================
   Procedure: [dbo].[usp_GoogleFormManageOperationByMode]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_GoogleFormManageOperationByMode]  
(  
    @Mode NVARCHAR(25) = 'get',  
    @FormIntegrationId BIGINT,  
    @GoogleKey NVARCHAR(255),  
    @FormName NVARCHAR(255),  
    @SettingJSON NVARCHAR(MAX) = '',  
    @UserId BIGINT = 0  
)  
AS  
BEGIN  
   
 --declare     
 -- @Mode nvarchar(25) = 'save_mapping',    
 -- @FormIntegrationId bigint=3,    
 -- @GoogleKey nvarchar(255)='4885a0efd2f04fa19695efd8e1dacf0f',  
 -- @FormName nvarchar(255)='google form 5',  
 -- @SettingJSON nvarchar(max) = N'{"Status":"3completed","Step":3,"Id":3,"GenerateWebhook":{"FormName":"Google Form 2","FormGUID":"309fc7d3bc53bb63ac42e359260ac740","WebhookUrl":"http://localhost:63178/Webhook/34594/309fc7d3bc53bb63ac42e359260ac740","GoogleKey":"d55cc548b5d542c4ae2b6e6b84616f42"},"TestNdLead":{"LeadId":0},"FieldMap":{"SourceSetting":{"id":"549693","name":"ServiceTicketSignup"},"MediumSetting":{"id":"396132","name":"GoogleApi"},"CampaignSetting":{"id":"56169","name":"new lead add_whatsapp"},"colMappings":[{"country_code":"","Google_field_name":"Full Name{FULL_NAME}","Google_field_path":"FULL_NAME","enquir_col_name":"PersonName","default_value":""},{"country_code":"+91       ","Google_field_name":"User Phone{PHONE_NUMBER}","Google_field_path":"PHONE_NUMBER","enquir_col_name":"MobileNo","default_value":"+91       "},{"country_code":"","Google_field_name":"User Email{EMAIL}","Google_field_path":"EMAIL","enquir_col_name":"EmailID","default_value":""}],"ColMappings":[]},"Filnal":{"Details":{}},"FromGuid":"309fc7d3bc53bb63ac42e359260ac740","GoogleKey":"d55cc548b5d542c4ae2b6e6b84616f42","WebhookUrl":"http://localhost:63178/Webhook/34594/309fc7d3bc53bb63ac42e359260ac740","ParentId":34594}',   
 --@UserId bigint = 34594  
 
    DECLARE @ParentId BIGINT, @FormGUID NVARCHAR(2000), @WebhookUrl NVARCHAR(MAX), @StepStatus NVARCHAR(100);  
    DECLARE @Status BIT = 0, @Message NVARCHAR(255) = 'failed', @Data NVARCHAR(MAX) = '{}';  
  
    -- Begin transaction  
    BEGIN TRANSACTION;  
    BEGIN TRY  
        -- Fetch ParentId based on UserId  
        SELECT @ParentId = ParentID FROM User_Detail(NOLOCK) WHERE User_ID = @UserId;  
          
        -- Parse SettingJSON to extract WebhookUrl and Status  
        SELECT @StepStatus = Status, @WebhookUrl = WebhookUrl  
        FROM OPENJSON(@SettingJSON)  
        WITH (Status NVARCHAR(100) '$.Status', WebhookUrl NVARCHAR(MAX) '$.GenerateWebhook.WebhookUrl');  
  
        IF @Mode = 'get'  
        BEGIN  
            SET @Data = (SELECT * FROM tbl_GoogleFormLeadMapping(NOLOCK)  
                         WHERE FormIntegrationId = @FormIntegrationId AND IsActive = 0 FOR JSON PATH);  
            SET @Status = 1;  
            SET @Message = 'success';  
        END  
        ELSE IF @Mode = 'create'  
        BEGIN  
            IF NOT EXISTS(SELECT 1 FROM tbl_googleFormIntegration(NOLOCK) WHERE Id = @FormIntegrationId)  
            BEGIN  
                INSERT INTO tbl_googleFormIntegration (UserId, CreatedBy, CreatedAt, FormName, GoogleKey)  
                VALUES (@UserId, @UserId, GETDATE(), @FormName, @GoogleKey);  
  
                DECLARE @NewId INT;  
                SET @NewId = SCOPE_IDENTITY();  
                SET @FormGUID = SUBSTRING(LOWER(CONVERT(NVARCHAR(34), HASHBYTES('MD5', CAST(@NewId AS NVARCHAR)), 1)), 3, 32);  
                SET @WebhookUrl = CONCAT(@WebhookUrl, '/Webhook/', @ParentId, '/', @FormGUID);  
  
                -- Update JSON structure with new values  
                SET @Data = JSON_MODIFY(JSON_MODIFY(JSON_MODIFY(JSON_MODIFY(  
                            JSON_MODIFY(@SettingJSON, '$.FromGuid', @FormGUID),  
                        '$.GoogleKey', @GoogleKey), '$.WebhookUrl', @WebhookUrl), '$.ParentId', @ParentId), '$.Id', @NewId);  
  
                -- Update integration table  
                UPDATE tbl_googleFormIntegration SET JsonSetting = @Data, FormGUID = @FormGUID, WebhookUrl = @WebhookUrl WHERE Id = @NewId;  
  
                SET @Status = 1;  
                SET @Message = 'success';  
      END  
            ELSE  
            BEGIN  
                SET @Status = 0;  
                SET @Message = 'exists';  
            END  
        END  
          
 ELSE IF(@Mode = 'update')    
 begin    
  update tbl_googleFormIntegration set FormName = @FormName, JsonSetting=@SettingJSON, Status=@StepStatus where id = @FormIntegrationId  
select  @data = JsonSetting from tbl_googleFormIntegration(nolock) where Id=@FormIntegrationId     

  select @status = 1, @message = 'success'    
 end    
    
 ELSE IF(@Mode = 'mapping')    
 begin    
  select top 1 @data = RequestJson from tbl_googleForm_Webhook(nolock)     
   where ParentId = @ParentId order by id desc    
  select @status = case when len(@data) > 3 then 1 else  0 end,  @message = 'success'    
 end    
    
 ELSE IF(@Mode = 'save_mapping')    
 begin    
  print 'save_mapping'    
    
  declare @fmsId bigint = 0, @SourceId bigint, @MediumId bigint, @CampaignId bigint, @colMappings nvarchar(max)    
;    
  if(exists( select 1 from tbl_GoogleFormLeadMapping(nolock)     
    where FormIntegrationId = @FormIntegrationId and parentid = @ParentId))    
  begin    
   select @fmsId = id from tbl_GoogleFormLeadMapping(nolock)     
    where FormIntegrationId = @FormIntegrationId and parentid = @ParentId    
  end    
    
  select @SourceId = SourceId, @MediumId = MediumId, @CampaignId = CampaignId, @colMappings = colMappings    
   from openjson(@SettingJSON) with(    
    SourceId bigint '$.FieldMap.SourceSetting.id',    
    MediumId bigint '$.FieldMap.MediumSetting.id',    
    CampaignId bigint '$.FieldMap.CampaignSetting.id',    
    colMappings nvarchar(max) '$.FieldMap.colMappings' as json    
   )    
   
   -- @ParentId, @UserId, GETDATE(), 1, GETDATE(), @SettingJSON, SourceId, MediumId, CampaignId, @ApiKeyId, colMappings    
      
  if(@fmsId > 0)    
  begin   
  print 'u'  
   update tbl_GoogleFormLeadMapping set     
    UpdatedAt = GETDATE(),     
    settingJson = @SettingJSON,    
    sourceId = @SourceId,     
    mediumId = @MediumId,     
    campaignId = @CampaignId,    
    FormIntegrationId = @FormIntegrationId,    
    colMappings = @colMappings     
   where id = @fmsId  
   print 'u'  
  end    
  else    
  begin    
   insert into tbl_GoogleFormLeadMapping(parentid, createdby, CreatedAt, isactive, UpdatedAt, settingJson, sourceId, mediumId, campaignId, FormIntegrationId, colMappings)     
   select @ParentId, @UserId, GETDATE(), 1, GETDATE(), @SettingJSON, @SourceId, @MediumId, @CampaignId, @FormIntegrationId, @colMappings    
   set @fmsId = SCOPE_IDENTITY()    
  end    
   UPDATE tbl_googleFormIntegration SET JsonSetting = @SettingJSON,Status= @StepStatus WHERE Id = @FormIntegrationId;  

set @data = (select @SettingJSON as JsonSetting for json path, without_array_wrapper)    

  select @status = 1, @message = 'success'    
 end    
  ELSE IF(@Mode = 'delete')    
 begin    
  if( exists(select * from tbl_googleFormIntegration(nolock) where id = @FormIntegrationId ))   
  begin    
      update tbl_googleFormIntegration set ProgressStep=0 where Id=@FormIntegrationId  
     set @data = (select @FormIntegrationId as Id for json path, without_array_wrapper)    
  
     select @status = 1, @message = 'success'    
  
  end  
  end  
        COMMIT;  
    END TRY  
    BEGIN CATCH  
        -- Rollback transaction in case of errors  
        ROLLBACK;  
        SET @Message = ERROR_MESSAGE();  
        SET @Status = 0;  
    END CATCH;  
  
    -- Return result  
    SELECT @Status AS [status], @Message AS [message], @Data AS [data];  
END  


GO

