/* ============================================================
   Procedure: [dbo].[usp_gs_GetRuleList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_gs_GetRuleList](
	@ParentId bigint = 34594,
	@WorkbookId nvarchar(255)
)
as
begin
	
	--declare 
	--	@ParentId bigint = 34594,
	--	@WorkbookId nvarchar(255) = '1oX0KQEKekDhKlR5LL-w5rEepha1jtW1x35lwIw3iAJQ'


	declare @PGSAutoId bigint = 0;

	select @PGSAutoId = Id from tbl_ge_ParentGoogleSheets(nolock) 
		where WorkbookId = @WorkbookId and ParentId = @ParentId and IsActive = 1

	select 
		sr.Id,
		sr.RuleName,
		sr.CreatedOn,
		sr.IsActive,
		concat( cu.User_Login, ' (', cu.FName, ' ', cu.LName, ')' ) as [CreatedBy],
		sr.ModifiedOn,
		concat( mu.User_Login, ' (', mu.FName, ' ', mu.LName, ')' ) as [ModifiedBy]
	from tbl_ge_SheetRules(nolock) sr 
		left join User_Detail(nolock) cu on sr.CreatedBy = cu.User_ID
		left join User_Detail(nolock) mu on sr.ModifiedBy = mu.User_ID
			where sr.PGSAutoId = @PGSAutoId

end



GO

/* ============================================================
   Procedure: [dbo].[usp_gs_GetUnproccessedGSWebhook]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_gs_GetUnproccessedGSWebhook
as
begin
	
	drop table if exists #tempGsWebhook
	select id, ParentId, WorkbookId, SheetName, IsProcess, ErrorDescription into #tempGsWebhook 
		from tbl_ge_GoogleSheetWebhooks(nolock) where IsProcess = 0

	update g set 
			g.IsProcess = 2
	from #tempGsWebhook(nolock) t 
		inner join tbl_ge_GoogleSheetWebhooks(nolock) g on t.id = g.id

	select * from #tempGsWebhook
end



GO

/* ============================================================
   Procedure: [dbo].[usp_gs_InsertNewGoogleSheet]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_gs_InsertNewGoogleSheet](
	@WorkbookId nvarchar(255),
	@WorkbookName nvarchar(max),
	@UserId bigint,
	@ParentId bigint,
	@Sheets  nvarchar(max) = null
)
as
begin
	if(
		not exists(select * from  tbl_ge_ParentGoogleSheets(nolock) 
		where WorkbookId = @WorkbookId and @ParentId = @ParentId
	))
	begin
		insert into tbl_ge_ParentGoogleSheets( WorkbookId, WorkbookName, ParentId, IntegratedBy, IsActive, ModifiedOn, ModifiedBy)
			values( @WorkbookId, @WorkbookName, @ParentId, @UserId, 1, GETDATE(), @UserId )

		declare @googleSheetAutoId bigint  = SCOPE_IDENTITY()

		if(ISNULL(@Sheets, '') <> '')
		begin
			insert into tbl_ge_GoogleSpreadSheetMapping( SheetName, WorkbookId, ParentId, CreatedBy, CreatedOn, IsActive, GsAutoId )
			select [value], @WorkbookId, @ParentId, @UserId, getdate(), 1, @googleSheetAutoId from string_split(@Sheets, ',')
		end

	end
end



GO

