/* ============================================================
   Procedure: [dbo].[usp_HandleMailOutboxFailed]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE usp_HandleMailOutboxFailed
    @OutboxId BIGINT,
    @ErrorMessage NVARCHAR(1000),
    @MaxAttempts INT
AS
BEGIN
    SET NOCOUNT ON;
    
    DECLARE @AttemptCount INT;
    
    -- Update the failed record with error information and exponential backoff
    UPDATE MailOutbox
    SET Processing = 0,
        LastError = LEFT(@ErrorMessage, 1000),
        NextRetryAt = CASE 
            WHEN ISNULL(AttemptCount, 0) < @MaxAttempts 
            THEN DATEADD(minute, POWER(2, ISNULL(AttemptCount, 0)), getdate())
            ELSE NULL  -- No more retries
        END
    WHERE OutboxId = @OutboxId;
    
    -- Get the current attempt count after update
    SELECT @AttemptCount = ISNULL(AttemptCount, 0)
    FROM MailOutbox 
    WHERE OutboxId = @OutboxId;
    
    -- If max attempts reached, handle as dead letter (optional)
    IF @AttemptCount >= @MaxAttempts
    BEGIN
        -- You can implement additional logic here such as:
        -- 1. Move to dead letter table
        -- 2. Send alert notifications
        -- 3. Set a DeadLetter flag
        
        UPDATE MailOutbox
        SET NextRetryAt = NULL,
            LastError = LEFT('MAX ATTEMPTS REACHED: ' + @ErrorMessage, 1000)
        WHERE OutboxId = @OutboxId;
        
        -- Example: Insert into dead letter table (uncomment if you have such table)
        /*
        INSERT INTO MailOutboxDeadLetter (OutboxId, QueueName, MessageId, Payload, LastError, DeadLetteredAt)
        SELECT OutboxId, QueueName, MessageId, Payload, LastError, getdate()
        FROM MailOutbox
        WHERE OutboxId = @OutboxId;
        */
    END
END



GO

