CREATE   PROCEDURE [dbo].[usp_HandleMessageFailed]
    @MessageDeliveryStatusID BIGINT,
    @ErrorMessage VARCHAR(250)
AS
BEGIN
    SET NOCOUNT ON;
    
    UPDATE [dbo].[Int_MessageDeliveryStatus]
    SET LastError = LEFT(@ErrorMessage, 10),  -- LastError is char(10)
        StatusDescription = @ErrorMessage
    WHERE MessageDeliveryStatusID = @MessageDeliveryStatusID;
END



