/* ============================================================
   Procedure: [dbo].[usp_history_date_uid]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_history_date_uid]                
@uid int,                
@Fromdate varchar(30),               
@ToDate varchar(30)              
            
as                 
BEGIN                
 select convert(nvarchar,convert(datetime,messageinsertdate,104),111) date, count(*) TotalPush from sixdayshistory where u_id=@uid                
 and  convert(nvarchar,convert(datetime,messageinsertdate,104),112)                 
 between convert(nvarchar,convert(datetime,@Fromdate,104),112)                
 and convert(nvarchar,convert(datetime,@ToDate,104),112)             
group by convert(nvarchar,convert(datetime,messageinsertdate,104),111) order by  convert(nvarchar,convert(datetime,messageinsertdate,104),111)               
       
--select batchid,convert(nvarchar,convert(datetime,messageinsertdate,104),111) date from sixdayshistory where u_id=@uid and  convert(nvarchar,convert(datetime,messageinsertdate,104),112)                 
-- between convert(nvarchar,convert(datetime,@Fromdate,104),112)                
-- and convert(nvarchar,convert(datetime,@ToDate,104),112)             
-- group by convert(nvarchar,convert(datetime,messageinsertdate,104),111),batchid order by  convert(nvarchar,convert(datetime,messageinsertdate,104),111)               
    
       
 select convert(nvarchar,convert(datetime,messageinsertdate,104),111) date,  count(*) TotalSent from sixdayshistory where u_id=@uid and                 
 messagestatus is not null AND convert(nvarchar,convert(datetime,messageinsertdate,104),112)                 
 between convert(nvarchar,convert(datetime,@Fromdate,104),112)                
 and convert(nvarchar,convert(datetime,@ToDate,104),112)              
group by convert(nvarchar,convert(datetime,messageinsertdate,104),111) order by  convert(nvarchar,convert(datetime,messageinsertdate,104),111)             
END 



