        SELECT ISNULL(FName, '''') + '' '' + ISNULL(LName, '''') 
        FROM User_Detail (NOLOCK)
        WHERE CAST(REPLACE(ISNULL(countrycode, ''+91''), ''+'', '''') AS NVARCHAR) + CAST(STR(mobile) AS NVARCHAR) = ''' + @waid + '''
    ),
    (
        SELECT [value] 
        FROM OPENJSON(
            (
                SELECT [value] 
                FROM OPENJSON(
                    (
                        SELECT TOP 1 profilejson 
                        FROM convusers (NOLOCK) 
                        WHERE channelprofileid = ''' + @waid + ''' 
                            AND ISNULL(profilejson, '''') <> '''' 
                            AND convuserparentid = 34594 
                        ORDER BY id DESC
                    )
                ) 
                WHERE [key] = ''profile''
            )
        ) 
        WHERE [key] = ''name''
    ),
    ''''
);

';

EXEC usp_clr_GetRemoteStringValue @sqlquery, @retval = @name OUTPUT;

---------------------------------------end clr
insert into wachats(waid,namereturned,sessionid,usertext,flow,createdon,demotime)
select @waid,@name,@sessionid,@text,null,getdate(),null
select @rtext=isnull((select rtext from internal_wa_campaigns (nolock) where ctext=@text and isactive=1),'')
select @name as Name,case when @rtext<>'' then @text else '' end as CustomRequest,@rtext as CustomRequestDetails

if exists(select 1 from leadsettings(nolock) where userid=34594 and status=1 and mode='Whatsapp' )
begin
declare @LeadDetails nvarchar(max)='Name|Mobile|Remarks',@mobile nvarchar(50)=cast(replace(@waid,'91','') as nvarchar),@remarks nvarchar(max)='New Chat on whatsapp. User 
sent a message reading "'+@text+'"' 
exec Usp_insertIntoLeadList_Process 'Whatsapp',@LeadDetails,@name,@mobile,'','','',@remarks,34594,58
end
end



