SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


/*

     exec [USP_IMPORTUSERS_DETAIL]  48311,48311,  61 --34594 , 34594, 14

*/
CREATE   PROC [dbo].[USP_IMPORTUSERS_DETAIL]
(
	@P_SESSION_USER_ID BIGINT , ----Session["userID"]
	@P_SESSION_P_USER_ID BIGINT ,  ------(Session["ParentID"])
	@P_IMPORT_ROW_ID BIGINT
)
AS
BEGIN
     
      /*
	declare @P_SESSION_USER_ID BIGINT  = 48311 , ----Session["userID"]
     	@P_SESSION_P_USER_ID BIGINT = 48311 ,  ------(Session["ParentID"])
    	@P_IMPORT_ROW_ID BIGINT = 61
		*/
	   

	DECLARE @W_ROLE INT = 0, @W_URLTYPE INT = 0 ,@W_URL VARCHAR(100) = 'WWW.KIT19.COM' , @W_TYPE INT = 0 , @W_STATUS VARCHAR(2) ='1' ,
	@W_BANNER_ID INT = 0 , @W_USER_TYPE VARCHAR(2),@W_DEFAULT_HTML VARCHAR(MAX) = '',
	@W_MOBILE_NO VARCHAR(15) , @W_COUNTRY_CODE VARCHAR(5) , @W_VALIDATION_REMARK VARCHAR(MAX), @W_MID INT = 0,
	@W_PUID VARCHAR(30)='', @W_UID VARCHAR(30) ='', @W_USER_NAME VARCHAR(100) ,@W_PASSWORD  VARCHAR(100), @W_RESELLER_ID INT , @W_USER_ID INT,
	@W_NEW_USER_ID VARCHAR(10) = '0',
	@W_FNAME VARCHAR(100) ,@W_LNAME VARCHAR(100) , @W_EMAIL VARCHAR(100), @W_CITY VARCHAR(100),
	@W_STATE VARCHAR(100) ,@W_COUNTRY VARCHAR(100), @W_COMP_NAME VARCHAR(100), @W_TIMEZONE VARCHAR(100),@W_SUPPORT_GROUP VARCHAR(100),
	@W_SUPPORT_ROLE VARCHAR(100),@W_REPORT_TO_USER VARCHAR(100), @W_SUPPORT_ACCESS VARCHAR(100) ,@W_PERMISSION_ROLE VARCHAR(100),
	@W_ADMIN_MOBNO VARCHAR(100),@W_ADMIN_EMAIL VARCHAR(100), @W_ISADMIN BIT = 0, @W_IS_INTERNAL_USER BIT = 1 ,
	@MGroupBy VARCHAR(3000) ='' , @W_SUPPORT_ROLEID INT = 0 , @W_PERMISSION_ID INT = 0 , @W_REPORT_TO_USERID INT = 0, @W_TELEPHONY_ROLE VARCHAR(100);

	DECLARE @IMPORTDATA VARCHAR(MAX), @ROWDATA VARCHAR(MAX), @FIELDNAMES VARCHAR(MAX)='',@FIELD_VALUES NVARCHAR(MAX) = '',
	@ROW_COUNT INT =0 , @LOOP_COUNT INT= 1 ,  @SQLString nvarchar(max), @ResponseText varchar(max) , @ERROR_TEXT VARCHAR(100),
	@SUCESS_COUNT INT = 0 , @FAILED_COUNT INT = 0;

		--- DROP TEMP TABLES
	IF OBJECT_ID('TEMPDB..#TEMP_USER_DETAIL') IS NOT NULL begin DROP TABLE #TEMP_USER_DETAIL   end
	IF OBJECT_ID('TEMPDB..#TEMP_IMPORT_USERDATA') IS NOT NULL begin DROP TABLE #TEMP_IMPORT_USERDATA   end
	IF OBJECT_ID('TEMPDB..#TEMP_FINAL_USERDATA') IS NOT NULL begin DROP TABLE #TEMP_FINAL_USERDATA   end
	IF OBJECT_ID('TEMPDB..#TEMP_DATA') IS NOT NULL begin DROP TABLE #TEMP_DATA   end
	IF OBJECT_ID('TEMPDB..#TMP_IMPORT_RESULT') IS NOT NULL begin DROP TABLE #TMP_IMPORT_RESULT   end
	IF OBJECT_ID('TEMPDB..#TMP_ROLES') IS NOT NULL begin DROP TABLE #TMP_ROLES   end
	

	SELECT @IMPORTDATA=IMPORTDATA FROM TBL_USERIMPORTSUMMARY(NOLOCK) WHERE IMPORTROW_ID=@P_IMPORT_ROW_ID                
	PRINT '@IMPORTDATA: ' + @IMPORTDATA  
	
	SELECT  @ROWDATA= VALUE FROM OPENJSON(@IMPORTDATA)  

	SELECT @FIELDNAMES=@FIELDNAMES+'['+[KEY]+'] NVARCHAR(2000),' FROM OPENJSON(@ROWDATA)                
	PRINT '@FIELDNAMES1: ' + @FIELDNAMES  

	SET @FIELDNAMES =substring( @FieldNames,1 ,LEN( @FieldNames)  -1 )

	 CREATE TABLE #TEMP_IMPORT_USERDATA
	 (
		ID int identity(1,1)
	 )

	 SET @SQLString  = ' ALTER TABLE #TEMP_IMPORT_USERDATA  ADD '+@FIELDNAMES+' '

	 PRINT @SQLSTRING
	 EXEC(@SQLSTRING)

	SET @SQLString  =' DECLARE  @IMPORTDATA VARCHAR(MAX);
	SELECT  @IMPORTDATA=IMPORTDATA FROM TBL_USERIMPORTSUMMARY(NOLOCK) WHERE IMPORTROW_ID= '+ CONVERT( VARCHAR, @P_IMPORT_ROW_ID) +'  
	INSERT INTO #TEMP_IMPORT_USERDATA
	SELECT *  FROM OPENJSON(@IMPORTDATA) WITH ( '+@FIELDNAMES +' ) '
		
    EXEC(@SQLString)
	---SELECT * FROM  #TEMP_IMPORT_USERDATA
	
	SELECT * INTO #TEMP_FINAL_USERDATA FROM  #TEMP_IMPORT_USERDATA WHERE SNO IS NOT NULL  

	SELECT  @ROW_COUNT = COUNT(ID) FROM #TEMP_FINAL_USERDATA WHERE SNO IS NOT NULL  
	

	print 'Mid'

	---SET IMPORT START TIME AND USERCNT IN TBL_USERIMPORTSUMMARY
	UPDATE TBL_USERIMPORTSUMMARY SET importstart = GETDATE() , UserCnt =0 WHERE ImportRow_Id =@P_IMPORT_ROW_ID

	create table #temp_data(
		sno int identity (1,1),
		val_1 varchar(100),
		val_2 varchar(100),
		val_3 varchar(100),
		val_4 varchar(100),
		val_5 varchar(100),
		val_6 varchar(100),
		val_7 varchar(100),
	)

	CREATE TABLE #TMP_IMPORT_RESULT
	(
		SNO INT IDENTITY(1,1),
		Result varchar(100),
		Res_Count int
	)

	--================TEMP ROLES==========================
	CREATE TABLE #TMP_ROLES
	(
		ID INT IDENTITY(0,1),
		ROLE_NAME VARCHAR(10)
	)

	INSERT INTO #TMP_ROLES VALUES('No access') , ('Admin') , ('User')


		/* 	========================================================
			Block for user creation - Cloud User limit
			====================================================== */
		--	UPDATE TBL_USERIMPORTSUMMARY SET Remarks = NULL


		/* ============================================================================*/

		print 'last but one'

		IF OBJECT_ID('TEMPDB..#TEMP_USER_DETAIL') IS NOT NULL begin DROP TABLE #TEMP_USER_DETAIL   END
	
		--SELECT * INTO #TEMP_USER_DETAIL FROM User_Detail WHERE 1=2

		--alter table #TEMP_USER_DETAIL
		--add Partner_Type int null


			IF OBJECT_ID('TEMPDB..#TEMP_USER_DETAIL_1') IS NOT NULL begin DROP TABLE #TEMP_USER_DETAIL_1   END
	
		   SELECT * INTO #TEMP_USER_DETAIL_1 FROM User_Detail WHERE 1=2

		   alter table #TEMP_USER_DETAIL_1
		   add Partner_Type int null

		   select Partner_Type,ID,M_ID,	User_ID,User_Login,	Pwd,FName,	LName,	EMail,	Mobile,	City,	State,	Country,
		   Type,	Stype,	ACType,	Status,	Banner_ID,	Banner_IDR,	Banner_ID_Owner,	Banner_ID_Reseller,	Priority,
		   DateCreated,	DateUpdated	,EmpUpdated,	MachineName	,LastModified,	SmppID,	R_mode,	userfilter,	FilterMode,	ServiceTypeID,
		   ServiceType,	UserGroup,	Gender,	Pincode	,Address,	LoginType,	Merchant_Code,	Merchant_Url,	User_DOB,
		   ProfilePictureName,	ProfilePicturePath,	UserType,	CompnayName	,Office_Name,	CountryCode,	Usercategory,
		   OnlineStatus,	DOE,	DeviceID,	Version,	AccountType,	IsInternalUser,	IsAdmin	,ParentID,
		   LastLogin2,	LastLogin1,	isverify,	randomnumber,	IsSuperReseller	,HasVirtualCredits	,
		   ParentSuperResellerId,	Isdemo	,resetguid,	resetrequested	,resetexpired	,referrerid,	referredcontactid,
		   Source,	Medium,	Campaign,	Timezone,	Country_ID	,Cloudrole,	onduty	,MobileCountryCode,	Support_Access,
		   Image,	isdemoaccount	,Presence,	IsBusyOnCall,	OTP,	OnField,	MACAddress,	AppVersion,	OSVersion,
		   OSName,	ModelName,	IsForceOffFeild,	wa_country_code	,wa_mobile_no,	wa_profile_id	,CompanyType	
		     into #TEMP_USER_DETAIL  from #TEMP_USER_DETAIL_1 where 1=2

		   --select * from #TEMP_USER_DETAIL


		SET IDENTITY_INSERT #TEMP_USER_DETAIL ON
		
		INSERT INTO #TEMP_USER_DETAIL (Partner_Type ,ID, M_ID,	User_ID,	User_Login,	Pwd,	FName,	LName,	EMail,	Mobile,	City,	State,	Country,	Type,	Stype,	ACType,	Status,	Banner_ID,	Banner_IDR,	Banner_ID_Owner,	Banner_ID_Reseller,	Priority,	DateCreated,	DateUpdated,	EmpUpdated,	MachineName,	LastModified,	SmppID,	R_mode,	userfilter,	FilterMode,	ServiceTypeID,	ServiceType,	UserGroup,	Gender,	Pincode,	Address,	LoginType,	Merchant_Code,	Merchant_Url,	User_DOB,	ProfilePictureName,	ProfilePicturePath,	UserType,	CompnayName,	Office_Name,	CountryCode,	Usercategory,	OnlineStatus,	DOE,	DeviceID,	Version,	AccountType,	IsInternalUser,	IsAdmin,	ParentID,	LastLogin2,	LastLogin1,	isverify,	randomnumber,	IsSuperReseller,	HasVirtualCredits,	ParentSuperResellerId,	Isdemo,	resetguid,	resetrequested,	resetexpired,	referrerid,	referredcontactid,	Source,	Medium,	Campaign,	Timezone,	Country_ID,	Cloudrole,	onduty,	MobileCountryCode,	Support_Access,	Image,	isdemoaccount,	Presence,	IsBusyOnCall,	OTP,	OnField,	MACAddress,	AppVersion,	OSVersion,	OSName,	ModelName,	IsForceOffFeild,	wa_country_code,	wa_mobile_no,	wa_profile_id,	CompanyType)
		EXEC usp_select_user_detail @P_SESSION_USER_ID

		SET IDENTITY_INSERT #TEMP_USER_DETAIL OFF

		SELECT TOP 1  @W_USER_TYPE = [TYPE] FROM #TEMP_USER_DETAIL

		---URL TYPE SET
		IF (@W_URL = 'WWW.KIT19.COM'  AND @W_USER_TYPE <> '2' )
		BEGIN  	SET @W_URLTYPE = 1;  END
		ELSE 
		BEGIN 	SET @W_URLTYPE = 0;  END

	SELECT TOP 1 @W_MID = M_ID , @W_PUID = ParentID , @W_UID = [User_ID] ,@W_ADMIN_MOBNO =Mobile, @W_ADMIN_EMAIL= EMail  FROM #TEMP_USER_DETAIL 

	
	BEGIN TRY
	WHILE (@ROW_COUNT >= @LOOP_COUNT)
	BEGIN
		
		SELECT TOP 1 @W_MOBILE_NO = Mobile , @W_COUNTRY_CODE = CountryCode FROM #TEMP_FINAL_USERDATA WHERE SNO = @LOOP_COUNT  ;

		Declare @L_remarks varchar(8000) ='';
		IF  EXISTS( SELECT 1 FROM #TEMP_FINAL_USERDATA WHERE COALESCE( User_Login,'')=''  and  SNO = @LOOP_COUNT)
		BEGIN
			set @L_remarks += 'Fill User login,';
		END
		IF  EXISTS( SELECT 1 FROM #TEMP_FINAL_USERDATA WHERE COALESCE( User_password,'')='' and  SNO = @LOOP_COUNT)
		BEGIN
			set @L_remarks += 'Fill User Password,';
		END
		IF  EXISTS( SELECT 1 FROM #TEMP_FINAL_USERDATA WHERE COALESCE( FName,'')=''  and  SNO = @LOOP_COUNT)
		BEGIN
			set @L_remarks += 'Fill User Fname,';
		END
		--IF  EXISTS( SELECT 1 FROM #TEMP_FINAL_USERDATA WHERE COALESCE( LName,'')=''  and  SNO = @LOOP_COUNT)
		--BEGIN
		--	set @L_remarks += 'Fill User Lname,';
		--END
		IF  EXISTS( SELECT 1 FROM #TEMP_FINAL_USERDATA WHERE COALESCE( EMail,'')=''  and  SNO = @LOOP_COUNT)
		BEGIN
			set @L_remarks += 'Fill User Email,';
		END
		IF  EXISTS( SELECT 1 FROM #TEMP_FINAL_USERDATA WHERE COALESCE( CountryCode,'')=''  and  SNO = @LOOP_COUNT)
		BEGIN
			set @L_remarks += 'Fill Country code,';
		END
		IF  EXISTS( SELECT 1 FROM #TEMP_FINAL_USERDATA WHERE COALESCE( Mobile,'')=''  and  SNO = @LOOP_COUNT)
		BEGIN
			set @L_remarks += 'Fill Mobile No.,';
		END
		--IF  EXISTS( SELECT 1 FROM #TEMP_FINAL_USERDATA WHERE COALESCE( City,'')=''  and  SNO = @LOOP_COUNT)
		--BEGIN
		--	set @L_remarks += 'Fill City name,';
		--END
		--IF  EXISTS( SELECT 1 FROM #TEMP_FINAL_USERDATA WHERE COALESCE( State,'')=''  and  SNO = @LOOP_COUNT)
		--BEGIN
		--	set @L_remarks += 'Fill User State,';
		--END
		--IF  EXISTS( SELECT 1 FROM #TEMP_FINAL_USERDATA WHERE COALESCE( Country,'')=''  and  SNO = @LOOP_COUNT)
		--BEGIN
		--	set @L_remarks += 'Fill User Country,';
		--END
		--IF  EXISTS( SELECT 1 FROM #TEMP_FINAL_USERDATA WHERE COALESCE( CompanyName,'')=''  and  SNO = @LOOP_COUNT)
		--BEGIN
		--	set @L_remarks += 'Fill Company Name,';
		--END
		--IF  EXISTS( SELECT 1 FROM #TEMP_FINAL_USERDATA WHERE COALESCE( Timezone,'')=''  and  SNO = @LOOP_COUNT)
		--BEGIN
		--	set @L_remarks += 'Fill Timezone.,';
		--END
		
		IF   ( @L_remarks  <> '' ) BEGIN
			SET @W_VALIDATION_REMARK = '{"SRNO" :"'+ CONVERT(VARCHAR(10), @LOOP_COUNT) +'" ,"REMARKS":"'+ @L_remarks +'"}' ;
				PRINT @W_VALIDATION_REMARK;
				UPDATE TBL_USERIMPORTSUMMARY SET Remarks = COALESCE( REMARKS+',','') + @W_VALIDATION_REMARK where  IMPORTROW_ID = @P_IMPORT_ROW_ID
				GOTO ENDLABEL
		END
	 

		IF (@W_COUNTRY_CODE = '+91' OR @W_COUNTRY_CODE = '91')
		BEGIN
			-- MOBILE NO. CHECK
			IF(LEN(@W_MOBILE_NO) <> 10 ) BEGIN
				SET @W_VALIDATION_REMARK = '{"SRNO" :"'+ CONVERT(VARCHAR(10), @LOOP_COUNT) +'" ,"REMARKS":"Please provide 10 digit mobile no"}' ;
				PRINT @W_VALIDATION_REMARK;
				UPDATE TBL_USERIMPORTSUMMARY SET Remarks = COALESCE( REMARKS+',','') + @W_VALIDATION_REMARK where  IMPORTROW_ID = @P_IMPORT_ROW_ID
				GOTO ENDLABEL
			END
		END
		ELSE BEGIN
			-- INTERNATIONAL MOBILE NO. CHECK
			IF(LEN(@W_MOBILE_NO) <=5 AND LEN(@W_MOBILE_NO) >=15) BEGIN
				SET @W_VALIDATION_REMARK = '{"SRNO" :"'+ CONVERT(VARCHAR(10), @LOOP_COUNT) +'" ,"REMARKS":"Please provide 5 TO 15 digit mobile no"}' ;
				PRINT @W_VALIDATION_REMARK;
				UPDATE TBL_USERIMPORTSUMMARY SET Remarks = COALESCE( REMARKS+',','') + @W_VALIDATION_REMARK where  IMPORTROW_ID = @P_IMPORT_ROW_ID
				GOTO ENDLABEL
			END
		END

		IF ( SUBSTRING( @W_MOBILE_NO,1,1) = '0') BEGIN
			SET @W_VALIDATION_REMARK = '{"SRNO" :"'+ CONVERT(VARCHAR(10), @LOOP_COUNT) +'" ,"REMARKS":"Make sure your Mobile number first digit is not Zero"}' ;
			PRINT @W_VALIDATION_REMARK;
			UPDATE TBL_USERIMPORTSUMMARY SET Remarks = COALESCE( REMARKS+',','') + @W_VALIDATION_REMARK where  IMPORTROW_ID = @P_IMPORT_ROW_ID
			GOTO ENDLABEL
		END

		ELSE BEGIN
			--SELECT  TOP 1 @W_USER_NAME = LTRIM( RTRIM( COALESCE(USER_LOGIN,''))), @W_FNAME = COALESCE(FNAME,''), @W_LNAME = COALESCE(LNAME,'') , @W_EMAIL = COALESCE(EMAIL,'') ,
			--@W_CITY = COALESCE(city,'') , @W_STATE = COALESCE([STATE],'') , @W_COUNTRY = COALESCE(COUNTRY,''), @W_COMP_NAME = COALESCE(CompanyName,'') , @W_TIMEZONE =
			--COALESCE(Timezone,''), @W_SUPPORT_ROLE = COALESCE(Support_Role,'') ,  @W_SUPPORT_GROUP =  COALESCE(Support_group,'') , @W_SUPPORT_ACCESS = COALESCE(Support_acess,''),
			--@W_PERMISSION_ROLE = COALESCE(Permission_role,'') , @W_REPORT_TO_USER = COALESCE(report_to_user,'') , @W_PASSWORD = COALESCE(user_password,'') , 
			--@W_TELEPHONY_ROLE = COALESCE(Telephony_Role,'')	FROM #TEMP_FINAL_USERDATA WHERE SNO = @LOOP_COUNT

			SELECT TOP 1
    @W_USER_NAME = LTRIM(RTRIM(COALESCE(USER_LOGIN,''))),
    @W_FNAME = COALESCE(FNAME,''),
    @W_LNAME = COALESCE(LNAME,''),
    @W_EMAIL = COALESCE(EMAIL,''),
    @W_CITY = COALESCE(city,''),
    @W_STATE = COALESCE([STATE],''),
    @W_COUNTRY = COALESCE(COUNTRY,''),
    @W_COMP_NAME = COALESCE(CompanyName,''),

    @W_TIMEZONE =
        CASE
            WHEN LTRIM(RTRIM(ISNULL(Timezone,''))) <> ''
                THEN LTRIM(RTRIM(Timezone))

            ELSE
                (
                    SELECT TOP 1
                        ISNULL(
                            NULLIF(LTRIM(RTRIM(Timezone)), ''),
                            'India Standard Time'
                        )
                    FROM User_Detail (NOLOCK)
                    WHERE User_ID = @P_SESSION_P_USER_ID
                )
        END,

    @W_SUPPORT_ROLE = COALESCE(Support_Role,''),
    @W_SUPPORT_GROUP = COALESCE(Support_group,''),
    @W_SUPPORT_ACCESS = COALESCE(Support_acess,''),
    @W_PERMISSION_ROLE = COALESCE(Permission_role,''),
    @W_REPORT_TO_USER = COALESCE(report_to_user,''),
    @W_PASSWORD = COALESCE(user_password,''),
    @W_TELEPHONY_ROLE = COALESCE(Telephony_Role,'')
FROM #TEMP_FINAL_USERDATA
WHERE SNO = @LOOP_COUNT


			--- USER NAME CHECK
			IF (@W_USER_TYPE = 2  AND @W_USER_NAME <> '' ) BEGIN
				DELETE FROM #TEMP_DATA
				INSERT INTO #TEMP_DATA(VAL_1)
				EXEC Usp_UserNameMatchForSubReseller @P_SESSION_USER_ID, @W_USER_NAME
				IF ( SELECT VAL_1 FROM #temp_data ) = 'Exists' BEGIN
						SET @W_VALIDATION_REMARK = '{"SRNO" :"'+ CONVERT(VARCHAR(10), @LOOP_COUNT) +'" ,"REMARKS":"UserName already exists for this subreseller!"}' ;
						PRINT @W_VALIDATION_REMARK;
						UPDATE TBL_USERIMPORTSUMMARY SET Remarks = COALESCE( REMARKS+',','') + @W_VALIDATION_REMARK where  IMPORTROW_ID = @P_IMPORT_ROW_ID
						GOTO ENDLABEL
				END
			END


			IF ((SELECT dbo.ValidateEmail(@W_EMAIL)) = 0)
			BEGIN
				SET @W_VALIDATION_REMARK = '{"SRNO" :"'+ CONVERT(VARCHAR(10), @LOOP_COUNT) +'" ,"REMARKS":"Invalid Email id."}' ;
				PRINT @W_VALIDATION_REMARK;
				UPDATE TBL_USERIMPORTSUMMARY SET Remarks = COALESCE( REMARKS+',','') + @W_VALIDATION_REMARK where  IMPORTROW_ID = @P_IMPORT_ROW_ID
				GOTO ENDLABEL
			END


			DELETE FROM #temp_data
			INSERT INTO #TEMP_DATA(VAL_1)
			EXEC CLOUD_CHECKPLANCONSTRAINTS @P_SESSION_P_USER_ID , 'USER'

			
			SELECT  TOP 1 @W_ROLE = ID FROM #TMP_ROLES WHERE ROLE_NAME =  @W_TELEPHONY_ROLE

			----SELECT 'TEST207' , * FROM #TMP_ROLES WHERE ROLE_NAME =  @W_TELEPHONY_ROLE

			--- USER ADDING CHECK 
			IF (((SELECT VAL_1 FROM #temp_data) = 0 OR (SELECT COUNT(VAL_1) FROM #temp_data) = 0 )AND @W_ROLE <> 0 )
			BEGIN
				PRINT 'You have already exceeded the add Cloud User limit. Please change the plan or contact to Kit19 customer support.'
				UPDATE TBL_USERIMPORTSUMMARY SET Remarks = COALESCE( REMARKS+',','') + '{"SRNO":"'+ CONVERT(VARCHAR(10), @LOOP_COUNT) +'"  , "REMARKS":"You have already exceeded the add Cloud User limit. Please change the plan or contact to Kit19 customer support."}' where  IMPORTROW_ID = @P_IMPORT_ROW_ID

				---SELECT * FROM TBL_USERIMPORTSUMMARY  where  IMPORTROW_ID = @P_IMPORT_ROW_ID 

			END
			ELSE BEGIN
			
			

			---================RESELLER ID AND USERD ID ======================
			DELETE FROM #temp_data
			INSERT INTO #temp_data(val_1,val_2)
			EXEC USP_SELECT_RESELLER_NEW @W_MID , @W_PUID

			SELECT  TOP 1 @W_RESELLER_ID = VAL_1 , @W_USER_ID = val_2 FROM #temp_data
			SELECT @W_USER_NAME = @W_PUID + '-' + @W_USER_NAME

			
			----SELECT 'TEST231' , * FROM #temp_data 
			--=============================================================================

			print 'puid + username'+@W_USER_NAME

			DELETE  FROM TBL_USER_WORKFLOW_RESPONSE WHERE SP_ID = @@SPID AND SNO = @LOOP_COUNT

				
			---SELECT * FROM tbl_user_workflow_response order by srno
			--INSERT INTO #temp_data(val_1,val_2)

			EXEC USP_CREATE_SMS_USER12NEW212  @W_MID, @W_PUID, @W_USER_NAME,@W_PASSWORD,@W_FNAME, @W_LNAME, @W_EMAIL,@W_MOBILE_NO,@W_CITY,
			@W_STATE, @W_COUNTRY, @W_TYPE , @W_STATUS , @W_BANNER_ID, '',@W_URLTYPE, @W_COMP_NAME, @W_DEFAULT_HTML, '','',@W_IS_INTERNAL_USER ,
			@W_ISADMIN, @W_COUNTRY_CODE , @W_TIMEZONE,@LOOP_COUNT 

			

			BEGIN TRY
			SET @ERROR_TEXT = @@ERROR

			print @error_text;

			IF (@ERROR_TEXT <> '0') BEGIN 
				SET @W_VALIDATION_REMARK = '{"SRNO" :"'+ CONVERT(VARCHAR(10), @LOOP_COUNT) +'" ,"REMARKS":"'+@ERROR_TEXT+' PROC_LINE =242 Error line  '+ CONVERT( VARCHAR, ERROR_LINE())+'"}' ;
				PRINT @W_VALIDATION_REMARK;
				UPDATE TBL_USERIMPORTSUMMARY SET REMARKS = COALESCE( REMARKS+',','') + @W_VALIDATION_REMARK WHERE  IMPORTROW_ID = @P_IMPORT_ROW_ID
			END

			---=======SET NEW USER ID VALUE =========
			SELECT TOP 1 @W_NEW_USER_ID = SCOPE_ID FROM tbl_user_workflow_response WHERE SP_ID = @@SPID AND SNO = @LOOP_COUNT AND ResponseId = 1
			PRINT @W_NEW_USER_ID+'@W_NEW_USER_ID'
			--- RESPONSE TEXT FROM ABOVE SP = USP_CREATE_SMS_USER12NEW212
		 

			IF (@W_NEW_USER_ID = 0) BEGIN
				INSERT INTO #TMP_IMPORT_RESULT VALUES ('FAILED' , @FAILED_COUNT+1)
				SET @RESPONSETEXT= ''
				SELECT  @RESPONSETEXT += RESPONSETEXT FROM TBL_USER_WORKFLOW_RESPONSE WHERE SP_ID = @@SPID AND SNO = @LOOP_COUNT AND RESPONSEID = -1
				SET @W_VALIDATION_REMARK = '{"SRNO" :"'+ CONVERT(VARCHAR(10), @LOOP_COUNT) +'" ,"REMARKS":"'+@RESPONSETEXT+'"}' ;
