    --- PERMISSION ROLE  
  
    ----SELECT 'TEST338' , * FROM #temp_data  
  
    ---SELECT TOP 1 @W_PERMISSION_ID = VAL_1 FROM #temp_data WHERE val_2 = @W_PERMISSION_ROLE  
      
