/* ============================================================
   Procedure: [dbo].[usp_ims_cb_InsertAppointment]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ims_cb_InsertAppointment](
	@title nvarchar(255),
	@description nvarchar(1000),
	@address nvarchar(255),
	@startDate datetime,
	@endDate datetime,
	@leadId bigint,
	@assignedTo bigint,
	@remarks nvarchar(max),
	@ownerId bigint,
	@collaborators nvarchar(max)
)
as
begin
	
	--declare 
	--	@title nvarchar(255) = N'd aasdfsdfasd',
	--	@description nvarchar(1000) = N'a sdfasdfasd',
	--	@address nvarchar(255) = N'sd sdfs',
	--	@startDate datetime='2022-11-11 00:19:31.957',
	--	@endDate datetime='2022-11-11 02:19:31.957',
	--	@leadId bigint=616992,
	--	@assignedTo bigint=N'36931',
	--	@isTask bit = 0,
	--	@isAppoitment bit = 1,
	--	@remarks nvarchar(max)=N' asdasdfas',
	--	@ownerId bigint=N'36931',
	--	@collaborators nvarchar(max)=N'34594#36931'

	declare @responseId bigint, @responseText nvarchar(max)

	begin try 

		declare @taskHistoryId bigint = 0, @taskName nvarchar(255), @eventDescription as nvarchar(1000), @userLogin nvarchar(255), @parentId bigint, @userId bigint

		INSERT INTO tbl_tsk_TaskHistory (Title, Description, Address, StartDate, EndDate, LeadId, AssignedTo, IsActive, 
			CreatedOn, TaskId, CreatedBy, OutcomesId, STATUS, IsTask, IsAppointment, TaskType, CompleteAddress, Latitude, Longitude, Remarks)
		select @title as Title, @description as Description, @address as Address, @startDate as StartDate, @endDate as EndDate, @leadId as LeadId, @assignedTo as AssignedTo, 1 as IsActive, GETDATE() as CreatedOn, 8 as TaskId, @ownerId as CreatedBy, 0 as OutcomesId, 'open' as [STATUS], 0 as IsTask, 1 as IsAppointment, '' as TaskType, null as CompleteAddress, null as Latitude, null as Longitude, @remarks as Remarks

	   set @taskHistoryId = SCOPE_IDENTITY()  

	   select @parentId = ParentID, @userLogin = User_Login from User_Detail(nolock) where User_ID = @ownerId

	   select @Title=Title From tbl_tsk_TaskHistory(nolock) Where id=@taskHistoryId  
	   select @taskName = Cast(CreatedOn as varchar) From tbl_tsk_TaskHistory(nolock) Where id = @taskHistoryId
	   set @eventDescription = concat(@userLogin, ' added an appointment with title ', @Title, ' for ', @TasKName  )

	   

	   exec UspSaveLeadActivity_withid @leadId, @ownerId, @parentId, @EventDescription,
					'Appointment Added', 'tbl_tsk_TaskHistory', @taskHistoryId

	   insert into tbl_tsk_CollaborationUserMapping(User_Id,CreatedOn,CreatedBy,TaskHistoryId)   
		select value AS UserId, GETDATE() as CreatedOn, @ownerId as CreatedBy, @taskHistoryId as TaskHistoryId 
			from STRING_SPLIT(@collaborators ,'#')

		select @responseId = 1, @responseText = 'success'
	end try
	begin catch
		 exec usp_InsertErrorInfo  
		 select @responseId = -1, @responseText =  ERROR_MESSAGE()
	end catch
	select @responseId as ResponseId, @responseText as ResponseText


end



GO

/* ============================================================
   Procedure: [dbo].[usp_ims_cb_insertnewcallForBroadcast]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_ims_cb_insertnewcallForBroadcast]
(
	@user_id BIGINT ,
	@route NVARCHAR(20) ,
	@MobileNo1 bit = 0,
	@MobileNo2 bit = 0,
	@MobileNo3 bit = 0,
	@appid INT ,
	@callerid NVARCHAR(20) ,
	@duration INT ,
	@scheduledfor DATETIME = NULL ,
	@EntityName NVARCHAR(255) = '' ,
	@EntityId BIGINT = 0 ,
	@RefHistoryId BIGINT = 0,
	@chatbotEventId BIGINT = NULL
)
AS  
BEGIN

	--declare @user_id bigint = 34594, @route nvarchar(20)= N'promo', @mobile nvarchar(max) = N'9821592374', @appid int=4109,@callerid nvarchar(20) =N'1204759813', @duration int =30,@scheduledfor datetime = null

	declare @responseId bigint, @responseText nvarchar(max), @mobile NVARCHAR(MAX)

	PRINT '------------BEGIN--------------------------- usp_ims_cb_insertnewcallForBroadcast ----------------------------------------------';
	-- DECLARE @tbl_Response AS TBL_RESPONSE;
	BEGIN TRY
		SET @scheduledfor = COALESCE(@scheduledfor , GETDATE());
		DECLARE @batchid BIGINT;
		BEGIN TRAN;
			INSERT INTO Getbatchrecord ([User_id] , RandNum)
			SELECT @user_id , @user_id;
			SELECT @batchid = SCOPE_IDENTITY();
			DELETE FROM GetBatchRecord WHERE BatchID = @batchid;
		COMMIT;

		DROP TABLE IF EXISTS #mobile;
		DROP TABLE IF EXISTS #temp;


		if(@EntityName = 'lead')
		begin
			select STRING_AGG(Mobile, ',') from Userleads_Mobile_Email(nolock) where  email = '1' and ulme_id  = @EntityId
		end

		if(@EntityName = 'enquiry')
		begin
			select STRING_AGG(Mobile, ',') from Userenquiry_Mobile_Email(nolock) where  email = '1' and enquiryid  = @EntityId
		end

		SELECT value
		INTO #mobile
		FROM fn_split ( @mobile , ',');

		DECLARE @mcount INT= ( SELECT COUNT(1) FROM #mobile );
		SELECT * INTO #temp FROM dbo.fn_GetVoiceCreditCalculation ( @route , @user_ID , @duration , @mcount );
		DECLARE @credits NUMERIC(18 , 4) = ( SELECT balance FROM #temp );

		SELECT * FROM #temp WHERE msg = 'ok';

		IF EXISTS ( SELECT 1 FROM #temp WHERE msg = 'ok' )
		BEGIN
		INSERT INTO Clone_VoiceDeliveryStatus --clonemessagedeliverystatus
		( BatchID , didno , Mobile , voiceDuration , AppId , IsDnd , IsPrority , IsAllowDND , price , user_id , VoiceInsertDate , ScheduledDate , voice_type , route)
		SELECT @batchid , @callerid , m.value , @duration , @appid , 0 , 2 , 0 , @credits , @user_id , GETDATE() , @scheduledfor , 1 , @route
		FROM #mobile AS m;
		DECLARE @CloneScopeId BIGINT= SCOPE_IDENTITY();

	
		select @responseId = 1, @responseText = 'success'  
	END
	ELSE
	BEGIN
	--send notification proc to be placed here
	DECLARE @mail NVARCHAR(200)= ( SELECT email FROM user_detail(NOLOCK) WHERE user_id = @user_id );
	-- INSERT INTO @tbl_Response(ScopeId, ResponseId, ResponseText) VALUES( '0', '-2', 'Insufficient Balance' );
		select @responseId = -2, @responseText = 'Insufficient Balance'
	END;


	IF ( @EntityId > 0 )
	BEGIN
	IF ( LOWER(@EntityName) = 'lead' )
	BEGIN
		DECLARE @LeadID BIGINT , @UserID BIGINT , @ParentID BIGINT , @EventDescription NVARCHAR(MAX) , @EventName NVARCHAR(500) , @reftables NVARCHAR(500) , @refid NVARCHAR(100) , @username NVARCHAR(255) , @ivr_name NVARCHAR(255)= '';

		SET @LeadID = @EntityId;
		SET @UserID = @user_id;
		SELECT @ParentID = ParentID , @username = User_Login
		FROM User_Detail(NOLOCK)
		WHERE User_Id = @user_id;
		SET @EventName = 'Voice sent to lead';
		SET @ivr_name = ( SELECT AppName
		FROM Cloud_app_master
		WHERE AppId = @appid
		);
		SET @EventDescription = CONCAT(@username , ' sent an automated call on mobile ' , @mobile , ' with ivr ' , @ivr_name , ' and did no. ' , @callerid , ' to mobile ' , @mobile , '.');
		SET @reftables = 'BatchVoiceInfo';
		SET @refid = @batchid;
		PRINT '@EntityName: ' + CAST(@EntityName AS VARCHAR);
		PRINT '@LeadId: ' + CAST(@LeadId AS VARCHAR);
		PRINT '@UserID: ' + CAST(@UserID AS VARCHAR);
		PRINT '@ParentID: ' + CAST(@ParentID AS VARCHAR);
		PRINT '@EventDescription: ' + CAST(@EventDescription AS VARCHAR);
		PRINT '@EventName: ' + CAST(@EventName AS VARCHAR);
		PRINT '@reftables: ' + CAST(@reftables AS VARCHAR);
		PRINT '@refid: ' + CAST(@refid AS VARCHAR);
		PRINT '@RefHistoryId: ' + CAST(@RefHistoryId AS VARCHAR);
		PRINT '@WorkFlowId: ' + CAST(@chatbotEventId AS VARCHAR);

		EXEC UspSaveEntityActivity_withid @LeadId , @UserID , @ParentID , @EventDescription , @EventName , @reftables , @refid;
	END;
	IF ( LOWER(@EntityName) = 'enquiry' )
	BEGIN
	SET @LeadID = @EntityId;
	SET @UserID = @user_id;
	SELECT @ParentID = ParentID , @username = User_Login
	FROM User_Detail(NOLOCK)
	WHERE User_Id = @user_id;
	SET @EventName = 'Voice sent to Enquiry';
	SET @ivr_name = ( SELECT AppName
	FROM Cloud_app_master
	WHERE AppId = @appid
	);
	SET @EventDescription = CONCAT(@username , ' sent an automated call on mobile ' , @mobile , ' with ivr ' , @ivr_name , ' and did no. ' , @callerid , ' to mobile ' , @mobile , '.');
	SET @reftables = 'BatchVoiceInfo';
	SET @refid = @batchid;
	EXEC UspSaveEntityActivity_withid 'enquiry' , @LeadId , @UserID , @ParentID , @EventDescription , @EventName , @reftables , @refid;
	END;
	PRINT '------------END--------------------------- usp_wf_insertnewcallForBroadcast ----------------------------------------------';
	END;
	
	END TRY
	BEGIN CATCH
	EXEC usp_InsertErrorInfo;
		select @responseId = -1, @responseText =  ERROR_MESSAGE()
	END CATCH;

	select @responseId as ResponseId, @responseText as ResponseText
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_ims_cb_InsertNewFollowUp]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ims_cb_InsertNewFollowUp](      
 @LeadId Bigint,                  
 @FollowUpStatus int,                  
 @NextStatusDate varchar(50),                  
 @Products varchar(1000),                  
 @AmountPaid numeric(18,2),                  
 @Remarks varchar(1000),                  
 @AssignedTo Bigint,                  
 @ParentID bigint,                  
 @CreatedBy bigint,        
 @IsReAssign bit = 0        
      
)      
as      
begin      
print 'entered usp_ims_cb_InsertNewFollowUp'
 declare @responseId bigint, @responseText nvarchar(max)      
 begin try       
  declare @LeadNo bigint       
  select @LeadNo = LeadNo from UserLeads(nolock) where ID = @LeadId       
      
  update UserLeads set       
   AssignedTo = case when isnull(@AssignedTo, 0) = 0 then @ParentID else @AssignedTo end,       
   LastFollowupCreatedBy = @CreatedBy,      
   LastFollowupCreatedOn = getdate(),      
   FollowUpStatus = @FollowUpStatus,      
   FollowupDate = @NextStatusDate,      
   NextStatusDate = @NextStatusDate,      
   Remarks = @Remarks      
  where ID = @LeadId      
      
  declare @FollowupDate Datetime = null, @LeadInterationId bigint  = 0, @UserLogin nvarchar(255) = '',       
   @AssigendToName nvarchar(255) = '', @FollowUpStatusName nvarchar(255) = '', @EventDescription nvarchar(max) = ''      
      
  if(isnull(@NextStatusDate, '') <> '')                  
  Begin       
   set @FollowupDate = @NextStatusDate           
   select @FollowupDate = dbo.[fn_getISTtimefromusertime](@CreatedBy, @FollowupDate)              
   select @NextStatusDate = convert(nvarchar(100),@FollowupDate,121)            
                      
  End               
        
  insert into LeadInteractionHistory ( LeadNo, FollowUpStatus, NextStatusDate, Products,       
   AmountPaid, Remarks, AssignedTo, ParentID, CreatedOn, CreatedBy, FollowupDate, IsReAssign,id_lead )                
  values ( @LeadNo, @FollowUpStatus, @NextStatusDate, @Products, @AmountPaid, @Remarks,       
    @AssignedTo, @ParentID, GETDATE(), @CreatedBy, @FollowupDate, @IsReAssign,@leadid )                     
      
  set @LeadInterationId = SCOPE_IDENTITY();      
      
  select @UserLogin = User_Login from User_Detail(nolock) where User_ID = @CreatedBy      
  select @FollowUpStatusName = FollowupStatus from FollowUp_Status(nolock) where ID =  @FollowUpStatus      
  select @AssigendToName = User_Login from User_Detail(nolock) where User_ID = @AssignedTo      
      
  set @EventDescription = concat(@UserLogin, ' added a followup with status ', @FollowUpStatusName, '. Lead was assigned to ', @AssigendToName)      
            
  exec UspSaveLeadActivity_withid @LeadId, @CreatedBy, @ParentID, @EventDescription,       
    'New Interaction added', 'LeadInteractionHistory', @LeadInterationId            
        
  select @responseId = 1, @responseText = 'success'       
 end try      
 begin catch      
  EXEC usp_InsertErrorInfo;      
  select @responseId = -1, @responseText =  ERROR_MESSAGE()      
 end catch      
 select @responseId as ResponseId, @responseText as ResponseText      
end 


GO

