/* ============================================================
   Procedure: [dbo].[usp_ims_cb_InsertTask]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_ims_cb_InsertTask](
	@title nvarchar(255),
	@description nvarchar(1000),
	@address nvarchar(255),
	@startDate datetime,
	@endDate datetime,
	@leadId bigint,
	@assignedTo bigint,
	@taskId int,
	@remarks nvarchar(max),
	@ownerId bigint,
	@collaborators nvarchar(max)
)
as
begin
	
	--declare 
	--	@title nvarchar(255),
	--	@description nvarchar(1000),
	--	@address nvarchar(255),
	--	@startDate datetime,
	--	@endDate datetime,
	--	@leadId bigint,
	--	@assignedTo bigint,
	--	@taskId int,
	--	@remarks nvarchar(max),
	--	@ownerId bigint,
	--	@collaborators nvarchar(max)

	declare @responseId bigint, @responseText nvarchar(max)

	begin try 

		declare @taskHistoryId bigint = 0, @taskName nvarchar(255), @eventDescription as nvarchar(1000), @userLogin nvarchar(255), @parentId bigint, @userId bigint

		INSERT INTO tbl_tsk_TaskHistory (Title, Description, Address, StartDate, EndDate, LeadId, AssignedTo, IsActive, 
			CreatedOn, TaskId, CreatedBy, OutcomesId, STATUS, IsTask, IsAppointment, TaskType, CompleteAddress, Latitude, Longitude, Remarks)
		select @title as Title, @description as Description, @address as Address, @startDate as StartDate, @endDate as EndDate, @leadId as LeadId, @assignedTo as AssignedTo, 1 as IsActive, GETDATE() as CreatedOn, @taskId as TaskId, @ownerId as CreatedBy, 0 as OutcomesId, 'open' as [STATUS], 1 as IsTask, 0 as IsAppointment, '' as TaskType, null as CompleteAddress, null as Latitude, null as Longitude, @remarks as Remarks

	   set @taskHistoryId = SCOPE_IDENTITY()  

	   select @parentId = ParentID, @userLogin = User_Login from User_Detail(nolock) where User_ID = @ownerId

	   select @taskName=TasKName From tbl_tsk_UserTaskMaster(nolock) Where Id = @taskId
	   set @eventDescription = concat(@userLogin, ' added task of type ', @taskName, ' with title ', @title)

	   exec UspSaveLeadActivity_withid @leadId, @ownerId, @parentId, @EventDescription,
					'Task Added', 'tbl_tsk_TaskHistory', @taskHistoryId

	   insert into tbl_tsk_CollaborationUserMapping(User_Id,CreatedOn,CreatedBy,TaskHistoryId)   
		select value AS UserId, GETDATE() as CreatedOn, @ownerId as CreatedBy, @taskHistoryId as TaskHistoryId 
			from STRING_SPLIT(@collaborators ,'#')

		select @responseId = 1, @responseText = 'success'
	end try
	begin catch
		 Exec usp_InsertErrorInfo  
		 select @responseId = -1, @responseText =  ERROR_MESSAGE()
	end catch
	select @responseId as ResponseId, @responseText as ResponseText
end



GO

/* ============================================================
   Procedure: [dbo].[usp_ims_cb_IntindSMSFromEnquiries_New1_WithDLTTemplateID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_ims_cb_IntindSMSFromEnquiries_New1_WithDLTTemplateID] (
	@ID            VARCHAR(500),   
	@Account       BIGINT,   
	@SenderID      VARCHAR(50),   
	@Message       NVARCHAR(4000),   
	@IsUnicode     BIT,   
	@Mobile        BIT,   
	@mobile1       BIT,   
	@Mobile2       BIT,   
	@DLTTemplateID NVARCHAR(200),   
	@UserId        BIGINT = 0,   
	@RefHistoryId  BIGINT = 0,
	@chatbotEventId	BIGINT = null
)  
AS  
BEGIN  
	declare @responseId bigint, @responseText nvarchar(max)

    -- DECLARE @tbl_Response AS TBL_RESPONSE;  
    BEGIN TRY  
        -- BatchID -- this column value is auto-generated                                                      
  
        PRINT '----------BEGIN------------------- usp_wf_IntindSMSFromLeads_New1_WithDLTTemplateID ---------------------------------';  
        PRINT '@ID: ' + CAST(@ID AS VARCHAR);  
        PRINT '@Account: ' + CAST(@Account AS VARCHAR);  
        PRINT '@SenderID: ' + CAST(@SenderID AS VARCHAR);  
        PRINT '@Message: ' + CAST(@Message AS VARCHAR);  
        PRINT '@IsUnicode: ' + CAST(@IsUnicode AS VARCHAR);  
        PRINT '@Mobile: ' + CAST(@Mobile AS VARCHAR);  
        PRINT '@mobile1: ' + CAST(@mobile1 AS VARCHAR);  
        PRINT '@Mobile2: ' + CAST(@Mobile2 AS VARCHAR);  
        PRINT '@DLTTemplateID: ' + CAST(@DLTTemplateID AS VARCHAR);  
        PRINT '@UserId: ' + CAST(@UserId AS VARCHAR);  
        PRINT '@RefHistoryId: ' + CAST(@RefHistoryId AS VARCHAR); 
        PRINT '@chatbotEventId: ' + CAST(isnull(@chatbotEventId,'') AS VARCHAR); 
		
        DECLARE @BatchID BIGINT;  
        BEGIN TRAN;  
        INSERT INTO GetBatchRecord  
        ([User_id],   
            RandNum  
        )  
        VALUES  
        (@Account,   
            @Account  
        );  
        SELECT @BatchID = SCOPE_IDENTITY();  
        DELETE FROM GetBatchRecord  
        WHERE batchid = @batchid;  
        COMMIT;  
        CREATE TABLE #tmpflint  
        ([BatchID]                     [BIGINT] NULL,   
            [Country_code]                [VARCHAR](10) NULL,   
            [Mobile]                      [VARCHAR](20) NULL,   
            [Message]                     [NVARCHAR](2500) NULL,   
            [MessageStatus]               [VARCHAR](20) NULL,   
            [SenderID]                    [NCHAR](40) NULL,   
            [MessageInsertDate]           [DATETIME] NULL,   
            [ScheduledDate]               [VARCHAR](50) NULL,   
            [ScheduledTime]               [VARCHAR](50) NULL,   
            [SmppID]                      [TINYINT] NULL,   
            [U_ID]                        [INT] NULL,   
            [IsUniCode]                   [BIT] NULL,   
            [IsDnd]                       [BIT] NULL,   
            [IsAirtel]                    [BIT] NULL,   
            [MobileSubSet]                [BIGINT] NULL,   
            [ValidNo]                     [TINYINT] NULL,   
            [IsPrority]                   [TINYINT] NULL,   
            [IsAllowDND]                  [TINYINT] NULL,   
            [DBType]                      [NCHAR](10) NULL,   
            [campaignid]                  [BIGINT] NULL,   
            [Processed]                   [INT] NULL,   
            [Hasvirtualcredits]           [INT] NULL,   
            [HasSufficientvirtualcredits] [INT] NULL,   
            [price]                       [FLOAT] NULL  
        );                                
        --drop table #tmpflind                                
        CREATE TABLE #tmpflind  
        ([BatchID]           [BIGINT] NULL,   
            [Country_code]      [VARCHAR](10) NULL,   
            [Mobile]            [VARCHAR](20) NULL,   
            [Message]           [NVARCHAR](2500) NULL,   
            [MessageStatus]     [VARCHAR](20) NULL,   
            [SenderID]          [NCHAR](40) NULL,   
            [MessageInsertDate] [DATETIME] NULL,   
            [ScheduledDate]     [VARCHAR](50) NULL,   
            [ScheduledTime]     [VARCHAR](50) NULL,   
            [SmppID]            [TINYINT] NULL,   
            [U_ID]              [INT] NULL,   
            [IsUniCode]         [BIT] NULL,   
            [IsDnd]             [BIT] NULL,   
            [IsAirtel]          [BIT] NULL,   
            [MobileSubSet]      [BIGINT] NULL,   
            [ValidNo]           [TINYINT] NULL,   
            [IsPrority]         [TINYINT] NULL,   
            [IsAllowDND]        [TINYINT] NULL,   
            [DBType]            [NCHAR](10) NULL,   
            [LeadId]            [BIGINT], --,                                
        --[campaignid] [bigint] NULL,                                
        --[Processed] [int] NULL,                                
        --[Hasvirtualcredits] [int] NULL,                                
        --[HasSufficientvirtualcredits] [int] NULL                                
        );  
        DECLARE @Uccode VARCHAR(20);  
        SELECT TOP 1 @Uccode = ISNULL(CountryCode, '+91') FROM User_Detail AS ud WHERE ud.[User_ID] = @Account;  
        INSERT INTO #tmpflind  
        (BatchID, Mobile, Country_Code, Message, MessageStatus, SenderID, MessageInsertDate, ScheduledDate, ScheduledTime, SmppID,
		 U_ID, IsUnicode, IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType, LeadId)  
        SELECT BatchID, Mobile, CountryCode, Messagetext, MessageStatus, SenderID, MessageInsertDate, ScheduledDate, ScheduledTime, SmppID,
		U_ID, IsUnicode, IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType, LeadId  
        FROM  
        (  
            SELECT @BatchID AS BatchID,  
                    CASE WHEN @Mobile = 1 THEN ISNULL(NULLIF(ue.MobileNo, ''), '0') ELSE '0' END AS Mobile,  
                    CASE WHEN @Mobile = 1 THEN ISNULL(ue.CountryCode, '') ELSE '' END AS CountryCode,   
                    dbo.fn_getLeadsMessage(ue.ParentID, @Message, ue.MobileNo) AS Messagetext, NULL AS MessageStatus, @SenderID AS SenderID,   
                    GETDATE() AS MessageInsertDate, NULL AS ScheduledDate, NULL AS ScheduledTime,   
					(SELECT TOP 1 ud.SmppID  FROM User_Detail AS ud WHERE ud.[User_ID] = @Account) AS SmppID,   
                    @Account AS U_ID, @IsUnicode AS IsUnicode, 0 AS IsDnd, 0 AS IsAirtel, 0 AS MobileSubSet, 1 AS ValidNo, 1 AS IsPrority,   
                    0 AS IsAllowDND, 0 AS DBType, ue.EnquiryID AS LeadId  
            FROM UserEnquiry AS ue  
            WHERE ue.EnquiryID = @ID AND ISNULL(NULLIF(ue.MobileNo, ''), '') <> '' AND ISNULL(NULLIF(ue.MobileNo, ''), '') NOT IN (  
                SELECT ISNULL(C_UDTemp.Mobile, '') AS MobileNo  
                FROM UserEnquiry AS UETemp INNER JOIN Client_UnSubscribeDetails AS C_UDTemp
				ON	(UeTemp.MobileNo = C_UDTemp.Mobile AND UETemp.CountryCode = C_UDTemp.CountryCode AND C_UDTemp.ParentId = UETemp.ParentID)  
                WHERE UE.EnquiryID = @ID  
            )  
            UNION  
            SELECT @BatchID, CASE WHEN @mobile1 = 1 THEN ISNULL(NULLIF(ue.MobileNo1, ''), '0') ELSE '0' END AS Mobile,  
                    CASE WHEN @Mobile = 1 THEN ISNULL(ue.CountryCode, '') ELSE '' END AS CountryCode,   
                    dbo.fn_getLeadsMessage(ue.ParentID, @Message, ue.MobileNo1),  NULL AS MessageStatus, @SenderID, GETDATE(), NULL, NULL,   
					(SELECT TOP 1 ud.SmppID FROM User_Detail AS ud WHERE ud.[User_ID] = @Account),   
                    @Account, @IsUnicode, 0, 0, 0, 1, 1, 0, 0, ue.EnquiryID AS LeadId  
            FROM UserEnquiry AS ue  
            WHERE ue.EnquiryID = @ID AND ISNULL(NULLIF(ue.MobileNo1, ''), '') <> '' AND ISNULL(NULLIF(ue.MobileNo1, ''), '') NOT IN  
            (SELECT ISNULL(C_UDTemp.Mobile, '') AS MobileNo1
			 FROM UserEnquiry AS UETemp INNER JOIN Client_UnSubscribeDetails AS C_UDTemp 
			 ON	(UeTemp.MobileNo1 = C_UDTemp.Mobile AND UETemp.CountryCode1 = C_UDTemp.CountryCode AND C_UDTemp.ParentId = UETemp.ParentID)
			 WHERE UE.EnquiryID = @ID  
            )  
            UNION  
            SELECT @BatchID, CASE WHEN @Mobile2 = 1 THEN ISNULL(NULLIF(ue.MobileNo2, ''), '0') ELSE '0' END AS Mobile,  
                    CASE WHEN @Mobile = 1 THEN ISNULL(ue.CountryCode, '') ELSE '' END AS CountryCode,   
                    dbo.fn_getLeadsMessage(ue.ParentID, @Message, ue.MobileNo2), NULL AS MessageStatus, @SenderID, GETDATE(), NULL, NULL,   
					(SELECT TOP 1 ud.SmppID  FROM User_Detail AS ud WHERE ud.[User_ID] = @Account),   
                    @Account, @IsUnicode, 0, 0, 0, 1, 1, 0, 0, ue.EnquiryID AS LeadId  
            FROM UserEnquiry AS ue  
            WHERE ue.EnquiryID = @ID AND ISNULL(NULLIF(ue.MobileNo2, ''), '') <> '' AND ISNULL(NULLIF(ue.MobileNo2, ''), '') NOT IN  
            (  SELECT ISNULL(C_UDTemp.Mobile, '') AS MobileNo2  
               FROM UserLeads AS UETemp INNER JOIN Client_UnSubscribeDetails AS C_UDTemp
			   ON	(UeTemp.MobileNo2 = C_UDTemp.Mobile AND UETemp.CountryCode2 = C_UDTemp.CountryCode AND C_UDTemp.ParentId = UETemp.ParentID)
               WHERE UE.EnquiryID = @ID  
            )  
        ) AS A  
        WHERE A.Mobile <> '0';  
        IF @Uccode = '+91'  
        BEGIN  
            INSERT INTO #tmpflint  
            (BatchID, Country_code, Mobile, Message, MessageStatus, SenderID, MessageInsertDate, ScheduledDate, ScheduledTime, SmppID,
			 U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType)  
            SELECT BatchID, Country_code, Mobile, Message, MessageStatus, SenderID, MessageInsertDate, ScheduledDate, ScheduledTime, SmppID, 
			U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType  
            FROM #tmpflind  
            WHERE Country_Code <> '+91';  
            DELETE FROM #tmpflind  
            WHERE Country_Code <> '+91';  
		END;  
        ELSE  
        BEGIN  
            INSERT INTO #tmpflint  
            (BatchID, Country_code, Mobile, Message, MessageStatus, SenderID, MessageInsertDate, ScheduledDate, ScheduledTime, SmppID,
			 U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType)  
            SELECT BatchID, Country_code, Mobile, Message, MessageStatus, SenderID, MessageInsertDate, ScheduledDate, ScheduledTime, SmppID, 
			U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType  
            FROM #tmpflind;  
		END;  
        DECLARE @NoOfSMS BIGINT= 0, @intsms BIGINT= 0;  
        SELECT @intsms = COUNT(*) FROM #tmpflint;  
        DECLARE @intprc INT= 0, @indprc INT= 0;  
        IF @intsms > 0  
        BEGIN  
            UPDATE #tmpflint SET price = (CASE  
                                WHEN IsUniCode = 0 AND LEN(message) <= 160  
                                THEN 1  
                                WHEN IsUniCode = 0 AND LEN(message) > 160  
                                THEN CEILING(LEN(message) / CAST(153 AS FLOAT))  
                                WHEN IsUniCode = 1 AND LEN(message) <= 70  
                                THEN 1  
                                ELSE CEILING(LEN(message) / CAST(67 AS FLOAT))  
                            END) *  
            (  
                SELECT price FROM dbo.IntSMSRateMast WHERE country_code = #tmpflint.country_code  
            );  
            DECLARE @Cr_amt FLOAT, @balance FLOAT;  
            SELECT @Cr_amt = SUM(price)  
            FROM #tmpflint;  
            SELECT TOP 1 @balance = Balance  
            FROM dbo.IntCredit_Details  
            WHERE USER_ID = @Account;  
            IF @balance < @Cr_amt  
                BEGIN  
                    SET @intprc = 1;  
            END;  
		END;  
        IF @intprc = 0  
        BEGIN  
            SELECT @NoOfSMS = COUNT(*)  
            FROM #tmpflind;  
            IF @NoOfSMS > 0  
            BEGIN  
                DECLARE @CurrentBalance BIGINT=  
                (  
                    SELECT TOP 1 ISNULL(cd.Balance, 0)  
                    FROM Credit_Details AS cd(NOLOCK)  
                    WHERE cd.[User_ID] = @Account  
                    ORDER BY cd.Credit_ID DESC  
                );  
                DECLARE @mBalance BIGINT= @CurrentBalance - @NoOfSMS;  
                IF @mBalance >= 0  
                BEGIN  
                    INSERT INTO CloneMessageDeliveryStatus  
                    (BatchID, Mobile, Message, MessageStatus, SenderID, MessageInsertDate, ScheduledDate, 
					 ScheduledTime, SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, 
					 DBType, sms_source)  
                    SELECT BatchID, Mobile, Message, MessageStatus, SenderID, MessageInsertDate, ISNULL(ScheduledDate, ''), 
					ISNULL(ScheduledTime, ''), SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND,
					DBType, 'Mass Send Lead'
					FROM #tmpflind;  
                    BEGIN TRY  
                        EXEC Usp_Save_DLTTemplateID_with_BatchID @batchid, @DLTTemplateID;  
					END TRY  
                    BEGIN CATCH  
                        EXEC usp_InsertErrorInfo;  
					END CATCH;  
				END;  
                ELSE  
                BEGIN  
                    SET @indprc = 1;  
                END;  
			END;  
        END;    
        IF @intprc = 0 AND @indprc = 0  
        BEGIN  
            IF(@UserId > 0)  
            BEGIN  
				DECLARE @leadActivityHistory AS LeadActivity_Tbltype;  
                DECLARE @Username NVARCHAR(255), @ParentId BIGINT= 0;  

                SELECT @Username = User_Login, @ParentId = ParentID  
                FROM User_Detail(NOLOCK)  
                WHERE User_Id = @UserId;  
                        
				INSERT INTO @leadActivityHistory  
                (LeadID, UserID, ParentID, EventDescription, EventName)  
                SELECT leadid, @UserId, @parentid, concat(@Username, ' sent an sms with content ', Message, ' on mobile ', Mobile), 'SMS sent to Enquiry'
				FROM #tmpflind;  
                    
					
				select * from ActivityMaster(nolock) where EventName like '%sms%'
				exec UspSaveLeadActivity_withMultipleValue @leadActivityHistory
            END;  
            select @responseId = 1, @responseText =  'success'
        END;  
        ELSE  
        BEGIN  
            select @responseId = -2, @responseText =  'Insufficient Balance' 
        END;  
        PRINT '----------END------------------- usp_wf_IntindSMSFromLeads_New1_WithDLTTemplateID ---------------------------------';  
    END TRY  
    BEGIN CATCH  
        EXEC usp_InsertErrorInfo;  
        select @responseId = -1, @responseText =  ERROR_MESSAGE()
	END CATCH;  
    select @responseId as ResponseId, @responseText as ResponseText
END  



GO

/* ============================================================
   Procedure: [dbo].[usp_ims_cb_IntindSMSFromLeads_New1_WithDLTTemplateID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_ims_cb_IntindSMSFromLeads_New1_WithDLTTemplateID] (
	@ID            VARCHAR(500),   
	@Account       BIGINT,   
	@SenderID      VARCHAR(50),   
	@Message       NVARCHAR(4000),   
	@IsUnicode     BIT,   
	@Mobile        BIT,   
	@mobile1       BIT,   
	@Mobile2       BIT,   
	@DLTTemplateID NVARCHAR(200),   
	@UserId        BIGINT = 0,   
	@RefHistoryId  BIGINT = 0,
	@chatbotEventId	BIGINT = null
)  
AS  
BEGIN  
	declare @responseId bigint, @responseText nvarchar(max)

    -- DECLARE @tbl_Response AS TBL_RESPONSE;  
    BEGIN TRY  
        -- BatchID -- this column value is auto-generated                                                      
  
        PRINT '----------BEGIN------------------- usp_wf_IntindSMSFromLeads_New1_WithDLTTemplateID ---------------------------------';  
        PRINT '@ID: ' + CAST(@ID AS VARCHAR);  
        PRINT '@Account: ' + CAST(@Account AS VARCHAR);  
        PRINT '@SenderID: ' + CAST(@SenderID AS VARCHAR);  
        PRINT '@Message: ' + CAST(@Message AS VARCHAR);  
        PRINT '@IsUnicode: ' + CAST(@IsUnicode AS VARCHAR);  
        PRINT '@Mobile: ' + CAST(@Mobile AS VARCHAR);  
        PRINT '@mobile1: ' + CAST(@mobile1 AS VARCHAR);  
        PRINT '@Mobile2: ' + CAST(@Mobile2 AS VARCHAR);  
        PRINT '@DLTTemplateID: ' + CAST(@DLTTemplateID AS VARCHAR);  
        PRINT '@UserId: ' + CAST(@UserId AS VARCHAR);  
        PRINT '@RefHistoryId: ' + CAST(@RefHistoryId AS VARCHAR); 
        PRINT '@chatbotEventId: ' + CAST(isnull(@chatbotEventId,'') AS VARCHAR); 
		
        DECLARE @BatchID BIGINT;  
        BEGIN TRAN;  
        INSERT INTO GetBatchRecord  
        ([User_id],   
            RandNum  
        )  
        VALUES  
        (@Account,   
            @Account  
        );  
        SELECT @BatchID = SCOPE_IDENTITY();  
        DELETE FROM GetBatchRecord  
        WHERE batchid = @batchid;  
        COMMIT;  
        CREATE TABLE #tmpflint  
        ([BatchID]                     [BIGINT] NULL,   
            [Country_code]                [VARCHAR](10) NULL,   
            [Mobile]                      [VARCHAR](20) NULL,   
            [Message]                     [NVARCHAR](2500) NULL,   
            [MessageStatus]               [VARCHAR](20) NULL,   
            [SenderID]                    [NCHAR](40) NULL,   
            [MessageInsertDate]           [DATETIME] NULL,   
            [ScheduledDate]               [VARCHAR](50) NULL,   
            [ScheduledTime]               [VARCHAR](50) NULL,   
            [SmppID]                      [TINYINT] NULL,   
            [U_ID]                        [INT] NULL,   
            [IsUniCode]                   [BIT] NULL,   
            [IsDnd]                       [BIT] NULL,   
            [IsAirtel]                    [BIT] NULL,   
            [MobileSubSet]                [BIGINT] NULL,   
            [ValidNo]                     [TINYINT] NULL,   
            [IsPrority]                   [TINYINT] NULL,   
            [IsAllowDND]                  [TINYINT] NULL,   
            [DBType]                      [NCHAR](10) NULL,   
            [campaignid]                  [BIGINT] NULL,   
            [Processed]                   [INT] NULL,   
            [Hasvirtualcredits]           [INT] NULL,   
            [HasSufficientvirtualcredits] [INT] NULL,   
            [price]                       [FLOAT] NULL  
        );                                
        --drop table #tmpflind                                
        CREATE TABLE #tmpflind  
        ([BatchID]           [BIGINT] NULL,   
            [Country_code]      [VARCHAR](10) NULL,   
            [Mobile]            [VARCHAR](20) NULL,   
            [Message]           [NVARCHAR](2500) NULL,   
            [MessageStatus]     [VARCHAR](20) NULL,   
            [SenderID]          [NCHAR](40) NULL,   
            [MessageInsertDate] [DATETIME] NULL,   
            [ScheduledDate]     [VARCHAR](50) NULL,   
            [ScheduledTime]     [VARCHAR](50) NULL,   
            [SmppID]            [TINYINT] NULL,   
            [U_ID]              [INT] NULL,   
            [IsUniCode]         [BIT] NULL,   
            [IsDnd]             [BIT] NULL,   
            [IsAirtel]          [BIT] NULL,   
            [MobileSubSet]      [BIGINT] NULL,   
            [ValidNo]           [TINYINT] NULL,   
            [IsPrority]         [TINYINT] NULL,   
            [IsAllowDND]        [TINYINT] NULL,   
            [DBType]            [NCHAR](10) NULL,   
            [LeadId]            [BIGINT], --,                                
        --[campaignid] [bigint] NULL,                                
        --[Processed] [int] NULL,                                
        --[Hasvirtualcredits] [int] NULL,                                
        --[HasSufficientvirtualcredits] [int] NULL                                
        );  
        DECLARE @Uccode VARCHAR(20);  
        SELECT TOP 1 @Uccode = ISNULL(CountryCode, '+91') FROM User_Detail AS ud WHERE ud.[User_ID] = @Account;  
        INSERT INTO #tmpflind  
        (BatchID, Mobile, Country_Code, Message, MessageStatus, SenderID, MessageInsertDate, ScheduledDate, ScheduledTime, SmppID,
		 U_ID, IsUnicode, IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType, LeadId)  
        SELECT BatchID, Mobile, CountryCode, Messagetext, MessageStatus, SenderID, MessageInsertDate, ScheduledDate, ScheduledTime, SmppID,
		U_ID, IsUnicode, IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType, LeadId  
        FROM  
        (  
            SELECT @BatchID AS BatchID,  
                    CASE WHEN @Mobile = 1 THEN ISNULL(NULLIF(ue.MobileNo, ''), '0') ELSE '0' END AS Mobile,  
                    CASE WHEN @Mobile = 1 THEN ISNULL(ue.CountryCode, '') ELSE '' END AS CountryCode,   
                    dbo.fn_getLeadsMessage(ue.ParentID, @Message, ue.MobileNo) AS Messagetext, NULL AS MessageStatus, @SenderID AS SenderID,   
                    GETDATE() AS MessageInsertDate, NULL AS ScheduledDate, NULL AS ScheduledTime,   
					(SELECT TOP 1 ud.SmppID  FROM User_Detail AS ud WHERE ud.[User_ID] = @Account) AS SmppID,   
                    @Account AS U_ID, @IsUnicode AS IsUnicode, 0 AS IsDnd, 0 AS IsAirtel, 0 AS MobileSubSet, 1 AS ValidNo, 1 AS IsPrority,   
                    0 AS IsAllowDND, 0 AS DBType, ue.ID AS LeadId  
            FROM UserLeads AS ue  
            WHERE ue.ID = @ID AND ISNULL(NULLIF(ue.MobileNo, ''), '') <> '' AND ISNULL(NULLIF(ue.MobileNo, ''), '') NOT IN (  
                SELECT ISNULL(C_UDTemp.Mobile, '') AS MobileNo  
                FROM UserLeads AS UETemp INNER JOIN Client_UnSubscribeDetails AS C_UDTemp
				ON	(UeTemp.MobileNo = C_UDTemp.Mobile AND UETemp.CountryCode = C_UDTemp.CountryCode AND C_UDTemp.ParentId = UETemp.ParentID)  
                WHERE UE.ID = @ID  
            )  
            UNION  
            SELECT @BatchID, CASE WHEN @mobile1 = 1 THEN ISNULL(NULLIF(ue.MobileNo1, ''), '0') ELSE '0' END AS Mobile,  
                    CASE WHEN @Mobile = 1 THEN ISNULL(ue.CountryCode, '') ELSE '' END AS CountryCode,   
                    dbo.fn_getLeadsMessage(ue.ParentID, @Message, ue.MobileNo1),  NULL AS MessageStatus, @SenderID, GETDATE(), NULL, NULL,   
					(SELECT TOP 1 ud.SmppID FROM User_Detail AS ud WHERE ud.[User_ID] = @Account),   
                    @Account, @IsUnicode, 0, 0, 0, 1, 1, 0, 0, ue.ID AS LeadId  
            FROM UserLeads AS ue  
            WHERE ue.ID = @ID AND ISNULL(NULLIF(ue.MobileNo1, ''), '') <> '' AND ISNULL(NULLIF(ue.MobileNo1, ''), '') NOT IN  
            (SELECT ISNULL(C_UDTemp.Mobile, '') AS MobileNo1
			 FROM UserLeads AS UETemp INNER JOIN Client_UnSubscribeDetails AS C_UDTemp 
			 ON	(UeTemp.MobileNo1 = C_UDTemp.Mobile AND UETemp.CountryCode1 = C_UDTemp.CountryCode AND C_UDTemp.ParentId = UETemp.ParentID)
			 WHERE UE.ID = @ID  
            )  
            UNION  
            SELECT @BatchID, CASE WHEN @Mobile2 = 1 THEN ISNULL(NULLIF(ue.MobileNo2, ''), '0') ELSE '0' END AS Mobile,  
                    CASE WHEN @Mobile = 1 THEN ISNULL(ue.CountryCode, '') ELSE '' END AS CountryCode,   
                    dbo.fn_getLeadsMessage(ue.ParentID, @Message, ue.MobileNo2), NULL AS MessageStatus, @SenderID, GETDATE(), NULL, NULL,   
					(SELECT TOP 1 ud.SmppID  FROM User_Detail AS ud WHERE ud.[User_ID] = @Account),   
                    @Account, @IsUnicode, 0, 0, 0, 1, 1, 0, 0, ue.ID AS LeadId  
            FROM UserLeads AS ue  
            WHERE ue.ID = @ID AND ISNULL(NULLIF(ue.MobileNo2, ''), '') <> '' AND ISNULL(NULLIF(ue.MobileNo2, ''), '') NOT IN  
            (  SELECT ISNULL(C_UDTemp.Mobile, '') AS MobileNo2  
               FROM UserLeads AS UETemp INNER JOIN Client_UnSubscribeDetails AS C_UDTemp
			   ON	(UeTemp.MobileNo2 = C_UDTemp.Mobile AND UETemp.CountryCode2 = C_UDTemp.CountryCode AND C_UDTemp.ParentId = UETemp.ParentID)
               WHERE UE.ID = @ID  
            )  
        ) AS A  
        WHERE A.Mobile <> '0';  
        IF @Uccode = '+91'  
        BEGIN  
            INSERT INTO #tmpflint  
            (BatchID, Country_code, Mobile, Message, MessageStatus, SenderID, MessageInsertDate, ScheduledDate, ScheduledTime, SmppID,
			 U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType)  
            SELECT BatchID, Country_code, Mobile, Message, MessageStatus, SenderID, MessageInsertDate, ScheduledDate, ScheduledTime, SmppID, 
			U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType  
            FROM #tmpflind  
            WHERE Country_Code <> '+91';  
            DELETE FROM #tmpflind  
            WHERE Country_Code <> '+91';  
		END;  
        ELSE  
        BEGIN  
            INSERT INTO #tmpflint  
            (BatchID, Country_code, Mobile, Message, MessageStatus, SenderID, MessageInsertDate, ScheduledDate, ScheduledTime, SmppID,
			 U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType)  
            SELECT BatchID, Country_code, Mobile, Message, MessageStatus, SenderID, MessageInsertDate, ScheduledDate, ScheduledTime, SmppID, 
			U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType  
            FROM #tmpflind;  
		END;  
        DECLARE @NoOfSMS BIGINT= 0, @intsms BIGINT= 0;  
        SELECT @intsms = COUNT(*) FROM #tmpflint;  
        DECLARE @intprc INT= 0, @indprc INT= 0;  
        IF @intsms > 0  
        BEGIN  
            UPDATE #tmpflint SET price = (CASE  
                                WHEN IsUniCode = 0 AND LEN(message) <= 160  
                                THEN 1  
                                WHEN IsUniCode = 0 AND LEN(message) > 160  
                                THEN CEILING(LEN(message) / CAST(153 AS FLOAT))  
                                WHEN IsUniCode = 1 AND LEN(message) <= 70  
                                THEN 1  
                                ELSE CEILING(LEN(message) / CAST(67 AS FLOAT))  
                            END) *  
            (  
                SELECT price FROM dbo.IntSMSRateMast WHERE country_code = #tmpflint.country_code  
            );  
            DECLARE @Cr_amt FLOAT, @balance FLOAT;  
            SELECT @Cr_amt = SUM(price)  
            FROM #tmpflint;  
            SELECT TOP 1 @balance = Balance  
            FROM dbo.IntCredit_Details  
            WHERE USER_ID = @Account;  
            IF @balance < @Cr_amt  
                BEGIN  
                    SET @intprc = 1;  
            END;  
		END;  
        IF @intprc = 0  
        BEGIN  
            SELECT @NoOfSMS = COUNT(*)  
            FROM #tmpflind;  
            IF @NoOfSMS > 0  
            BEGIN  
                DECLARE @CurrentBalance BIGINT=  
                (  
                    SELECT TOP 1 ISNULL(cd.Balance, 0)  
                    FROM Credit_Details AS cd(NOLOCK)  
                    WHERE cd.[User_ID] = @Account  
                    ORDER BY cd.Credit_ID DESC  
                );  
                DECLARE @mBalance BIGINT= @CurrentBalance - @NoOfSMS;  
                IF @mBalance >= 0  
                BEGIN  
                    INSERT INTO CloneMessageDeliveryStatus  
                    (BatchID, Mobile, Message, MessageStatus, SenderID, MessageInsertDate, ScheduledDate, 
					 ScheduledTime, SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, 
					 DBType, sms_source)  
                    SELECT BatchID, Mobile, Message, MessageStatus, SenderID, MessageInsertDate, ISNULL(ScheduledDate, ''), 
					ISNULL(ScheduledTime, ''), SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND,
					DBType, 'Mass Send Lead'
					FROM #tmpflind;  
                    BEGIN TRY  
                        EXEC Usp_Save_DLTTemplateID_with_BatchID @batchid, @DLTTemplateID;  
					END TRY  
                    BEGIN CATCH  
                        EXEC usp_InsertErrorInfo;  
					END CATCH;  
				END;  
                ELSE  
                BEGIN  
                    SET @indprc = 1;  
                END;  
			END;  
        END;    
        IF @intprc = 0 AND @indprc = 0  
        BEGIN  
            IF(@UserId > 0)  
            BEGIN  
				DECLARE @leadActivityHistory AS LeadActivity_Tbltype;  
                DECLARE @Username NVARCHAR(255), @ParentId BIGINT= 0;  

                SELECT @Username = User_Login, @ParentId = ParentID  
                FROM User_Detail(NOLOCK)  
                WHERE User_Id = @UserId;  
                        
				INSERT INTO @leadActivityHistory  
                (LeadID, UserID, ParentID, EventDescription, EventName)  
                SELECT leadid, @UserId, @parentid, concat(@Username, ' sent an sms with content ', Message, ' on mobile ', Mobile), 'SMS sent to lead'
				FROM #tmpflind;  
                        
				exec UspSaveLeadActivity_withMultipleValue @leadActivityHistory
            END;  
            select @responseId = 1, @responseText =  'success'
        END;  
        ELSE  
        BEGIN  
            select @responseId = -2, @responseText =  'Insufficient Balance' 
        END;  
        PRINT '----------END------------------- usp_wf_IntindSMSFromLeads_New1_WithDLTTemplateID ---------------------------------';  
    END TRY  
    BEGIN CATCH  
        EXEC usp_InsertErrorInfo;  
        select @responseId = -1, @responseText =  ERROR_MESSAGE()
	END CATCH;  
    select @responseId as ResponseId, @responseText as ResponseText
END  



GO

/* ============================================================
   Procedure: [dbo].[usp_ims_cb_SendMailFromEnquiry_WithTemplateID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_ims_cb_SendMailFromEnquiry_WithTemplateID]
	@IDS varchar(max),  
	@Account bigint,  
	@Email_Subject varchar(1000),  
	@Message_TemplateID bigint,  
	@SenderName varchar(100),  
	@ReplyTo varchar(1000),  
	@EmailId bit,  
	@EmailId1 bit,  
	@EmailId2 bit,  
	@UserId bigint= 0,  
	@RefHistoryId bigint= 0,
	@chatbotEventId bigint=null
	
AS  
BEGIN 
 declare @responseId bigint, @responseText nvarchar(max)
 
 BEGIN TRY  
  
  PRINT '-------BEGIN------------------------------ usp_ims_cb_SendMailFromLeads_WithTemplateID ----------------------------------------';  
  
  PRINT '@IDS: ' + CAST(@IDS AS varchar);  
  PRINT '@Account: ' + CAST(@Account AS varchar);  
  PRINT '@Email_Subject: ' + CAST(@Email_Subject AS varchar);  
  PRINT '@Message_TemplateID: ' + CAST(@Message_TemplateID AS varchar);  
  PRINT '@SenderName: ' + CAST(@SenderName AS varchar);  
  PRINT '@ReplyTo: ' + CAST(@ReplyTo AS varchar);  
  PRINT '@EmailId: ' + CAST(@EmailId AS varchar);  
  PRINT '@EmailId1: ' + CAST(@EmailId1 AS varchar);  
  PRINT '@EmailId2: ' + CAST(@EmailId2 AS varchar);  
  PRINT '@UserId: ' + CAST(@UserId AS varchar);  
  PRINT '@RefHistoryId: ' + CAST(@RefHistoryId AS varchar);  
  PRINT '@chatbotEventId: ' + CAST(isnull(@chatbotEventId,'') AS varchar);  
  
  DECLARE @tname nvarchar(200);  
  SELECT @Email_Subject = ISNULL(NULLIF(@Email_Subject, ''),  
  (  
   SELECT mailsubject  
   FROM UserMailTemplate(NOLOCK)  
   WHERE id = @message_templateID  
  ));  
  
  DECLARE @MailCount bigint, @IsMonitor bit= 1;  
  DECLARE @m_id bigint, @parentid bigint;  
  SELECT @m_id = ud.M_ID, @parentid = parentid  
  FROM User_Detail AS ud(NOLOCK)  
  WHERE ud.[User_ID] = @Account;  
  SELECT @MailCount =  
  (  
   SELECT COUNT(1)  
   FROM dbo.fn_split( @IDS, '#' )  
  );  
  DECLARE @CurrentBalance bigint=  
  (  
   SELECT TOP 1 mcd.Balance  
   FROM MailCreditDetails AS mcd(NOLOCK)  
   WHERE mcd.[User_ID] = @parentid  
   ORDER BY mcd.Credit_ID DESC  
  );  
  
  
  DECLARE @Balance bigint= @CurrentBalance - @MailCount;  
  IF @Balance > 0  
  BEGIN  
  
   DECLARE @Message varchar(max);  
  
   SELECT @Message = MailContent, @tname = Name  
   FROM UserMailTemplate(NOLOCK)  
   WHERE ID = @Message_TemplateID;  
  
   SELECT A.EmailID, A.AccountID, A.SenderName, A.MailContent, A.MailSubject, A.ReplyTo, A.leadid  
   INTO #tempTableSendMailTempId  
   FROM  
   (  
    SELECT ISNULL(A.EmailID, '') AS EmailID, @Account AS AccountID, @SenderName AS SenderName, A.MailContent, @Email_Subject AS MailSubject, @ReplyTo AS ReplyTo, Leadid  
    FROM  
    (  
     SELECT CASE  
         WHEN @EmailId = 1 THEN ul.EmailID  
         ELSE ''  
         END AS EmailID, dbo.fn_getLeadsMailMessage( ul.ParentID, @Message, ul.EmailID ) AS MailContent, ul.EnquiryID AS leadid  
     FROM UserEnquiry AS ul(NOLOCK)  
     WHERE ul.EnquiryID IN  
     (  
      SELECT [value]  
      FROM dbo.fn_Split( @IDS, '#' ) AS fs  
     ) AND   
        ISNULL(NULLIF(CAST(ul.EmailID AS varchar), ''), '') <> '' AND   
        ISNULL(NULLIF(CAST(ul.EmailID AS varchar), ''), '') NOT IN  
     (  
      SELECT ISNULL(C_UDTemp.Email, '') AS EmailID  
      FROM UserEnquiry AS UETemp(NOLOCK)  
        INNER JOIN  
        Client_UnSubscribeDetails AS C_UDTemp(NOLOCK)  
        ON(UETemp.EmailID = C_UDTemp.Email)  
      WHERE ul.EnquiryID IN  
      (  
       SELECT fs.value  
       FROM dbo.fn_Split( @IDS, '#' ) AS fs  
      )  
     )  
     UNION ALL  
     SELECT CASE WHEN @EmailId1 = 1 THEN ul.EmailID1  
         ELSE ''  
         END AS EmailID, dbo.fn_getLeadsMailMessage( ul.ParentID, @Message, ul.EmailID1 ), ul.EnquiryID AS leadid  
     FROM UserEnquiry AS ul(NOLOCK)  
     WHERE ul.EnquiryID IN  
     (  
      SELECT [value]  
      FROM dbo.fn_Split( @IDS, '#' ) AS fs  
     ) AND   
        ISNULL(NULLIF(CAST(ul.EmailID1 AS varchar), ''), '') <> '' AND   
        ISNULL(NULLIF(CAST(ul.EmailID1 AS varchar), ''), '') NOT IN  
     (  
      SELECT ISNULL(C_UDTemp.Email, '') AS EmailID  
      FROM UserEnquiry AS UETemp(NOLOCK)  
        INNER JOIN  
        Client_UnSubscribeDetails AS C_UDTemp(NOLOCK)  
        ON(UETemp.EmailID1 = C_UDTemp.Email)  
      WHERE ul.EnquiryID IN  
      (  
       SELECT fs.value  
       FROM dbo.fn_Split( @IDS, '#' ) AS fs  
      )  
     )  
     UNION ALL  
     SELECT CASE  
         WHEN @EmailId2 = 1 THEN ul.EmailID2  
         ELSE ''  
         END AS EmailID, dbo.fn_getLeadsMailMessage( ul.ParentID, @Message, ul.EmailID2 ), ul.EnquiryID AS leadid  
     FROM UserEnquiry AS ul(NOLOCK)  
     WHERE ul.EnquiryID IN  
     (  
      SELECT [value]  
      FROM dbo.fn_Split( @IDS, '#' ) AS fs  
     ) AND   
        ISNULL(NULLIF(CAST(ul.EmailID2 AS varchar), ''), '') <> '' AND   
        ISNULL(NULLIF(CAST(ul.EmailID2 AS varchar), ''), '') NOT IN  
     (  
      SELECT ISNULL(C_UDTemp.Email, '') AS EmailID  
      FROM UserEnquiry AS UETemp(NOLOCK)  
        INNER JOIN  
        Client_UnSubscribeDetails AS C_UDTemp(NOLOCK)  
        ON(UETemp.EmailID2 = C_UDTemp.Email)  
      WHERE ul.EnquiryID IN  
      (  
       SELECT fs.value  
       FROM dbo.fn_Split( @IDS, '#' ) AS fs  
      )  
     )  
    ) AS A  
    WHERE ISNULL(A.EmailID, '') <> ''  
   ) AS A;  
  
  
  
   DECLARE @Status bigint= 0, @CountLimit bigint= 0;  
   SELECT @Status = STATUS, @CountLimit = Plimit  
   FROM ProcessMailLimit;  
   IF(@Status = 1)  
   BEGIN  
    BEGIN  
     IF(@MailCount > @CountLimit)  
     BEGIN  
      SET @IsMonitor = 0;  
     END;  
    END;  
   END;  
  
  
  
   DECLARE @BatchID bigint;  
   BEGIN TRAN;  
   INSERT INTO GetBatchRecord( [User_id], RandNum )  
   VALUES( @Account, @Account );  
   SELECT @BatchID = SCOPE_IDENTITY();  
   DELETE FROM GetBatchRecord  
   WHERE batchid = @BatchID;  
   COMMIT;  
  
  
   DECLARE @Mail_FromEmail varchar(500)= '';  
  
   SELECT @Mail_FromEmail = COALESCE(  
   (  
    SELECT TOP 1 mail_id  
    FROM defaultmailid(NOLOCK)  
    WHERE user_id = @account  
    ORDER BY datecreated DESC  
   ),  
   (  
    SELECT ud.EMail  
    FROM User_Detail AS ud(NOLOCK)  
    WHERE ud.[User_ID] = @Account  
   ), 'contactus@email19.in');  
  
   INSERT INTO CloneEmailsFilter( Mail_FromEmail, Mail_ToEmail, Mail_Subject, Mail_TempleteName, Messages, Mail_InsertedDate, Mail_UserID, Mail_ParentID, ReplyTo, Mail_BatchID, Mail_Priority, Mail_ScheduleDate, Mail_ScheduledTime, Mail_Attechement, Mail_TempleteBody, IsMonitor, TemplateID, Count, Source )  
       SELECT @Mail_FromEmail, A.EmailID, A.MailSubject, ISNULL(@tname, ''), A.MailContent, GETDATE(), A.AccountID, @parentid, A.ReplyTo, @BatchID, 1, '', '', '', A.MailContent, @ismonitor, 0, @mailcount, 'Lead-MassSend'  
       FROM #tempTableSendMailTempId AS A;  
  
   PRINT '@Mail_FromEmail: ' + CAST(@Mail_FromEmail AS varchar);  
  
  
  
   IF(@UserId > 0)  
   BEGIN  
    DECLARE @leadActivityHistory AS LeadActivity_Tbltype;  
    DECLARE @Username nvarchar(255)=  
    (  
     SELECT User_Login  
     FROM User_Detail(NOLOCK)  
     WHERE User_Id = @UserId  
    );  
	INSERT INTO @leadActivityHistory( LeadID, UserID, ParentID, EventDescription, EventName)  
		SELECT leadid, @UserId, @parentid, concat(@Username, ' sent a mail with subject ', MailSubject, ' to emailid ', EmailID), 'Mail sent to Enquiry'
		FROM #tempTableSendMailTempId;  
  
	exec UspSaveLeadActivity_withMultipleValue @leadActivityHistory

   END;  
  
	select @responseId = 1, @responseText = 'success' 
  END;  
  ELSE  
  BEGIN  
	
	select @responseId = -2, @responseText = 'Insufficient Balance'

  END;  
  
  DROP TABLE IF EXISTS #tempTableSendMailTempId;  
  
  PRINT '-------END------------------------------ usp_wf_SendMailFromLeads_WithTemplateID ----------------------------------------';  
 END TRY  
 BEGIN CATCH  
	  exec  usp_InsertErrorInfo  
	  select @responseId = -1, @responseText = ERROR_MESSAGE()
 END CATCH;  
 
 select @responseId as ResponseId, @responseText as ResponseText

END; 



GO

/* ============================================================
   Procedure: [dbo].[usp_ims_cb_SendMailFromEnquriy]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_ims_cb_SendMailFromEnquriy]
(
	@IDS varchar(max),  
	@Account bigint,  
	@Email_Subject varchar(1000), 
	@Message varchar(max), 
	@SenderName varchar(100), 
	@ReplyTo varchar(1000), 
	@EmailId bit, 
	@EmailId1 bit, 
	@EmailId2 bit, 
	@UserId bigint=0, 
	@RefHistoryId bigint=0,  
	@chatbotEventId bigint=null
 )
AS  
BEGIN   

	 declare @responseId bigint, @responseText nvarchar(max)

	-- DECLARE @tbl_Response AS tbl_response;  
	BEGIN TRY  
	 --select @Email_Subject=isnull(nullif(@Email_Subject,''),(select mailsubject from UserMailTemplate(nolock) where id=@message_templateID))  
	 PRINT '-------------BEGIN------------------------------------ usp_ims_cb_SendMailFromEnquriy ----------------------------------------------';  
	 PRINT '@IDS: ' + CAST(@IDS AS varchar);  
	 PRINT '@Account: ' + CAST(@Account AS varchar);  
	 PRINT '@Email_Subject: ' + CAST(@Email_Subject AS varchar);  
	 PRINT '@Message: ' + CAST(@Message AS varchar);  
	 PRINT '@SenderName: ' + CAST(@SenderName AS varchar);  
	 PRINT '@ReplyTo: ' + CAST(@ReplyTo AS varchar);  
	 PRINT '@EmailId: ' + CAST(@EmailId AS varchar);  
	 PRINT '@EmailId1: ' + CAST(@EmailId1 AS varchar);  
	 PRINT '@EmailId2: ' + CAST(@EmailId2 AS varchar);  
	 PRINT '@UserId: ' + CAST(@UserId AS varchar);  
	 PRINT '@RefHistoryId: ' + CAST(@RefHistoryId AS varchar);  
	 PRINT '@ChatbotEventId: ' + CAST(isnull(@chatbotEventId,'') AS varchar);  
  
	 DECLARE @MailCount bigint, @IsMonitor bit= 1;  
	 DECLARE @m_id bigint, @parentid bigint;  
	 SELECT @m_id = ud.M_ID, @parentid = parentid  
	 FROM User_Detail AS ud(NOLOCK)  
	 WHERE ud.[User_ID] = @Account;  
	 SELECT @MailCount =  
	 (  
	  SELECT COUNT(1)  
	  FROM dbo.fn_split( @IDS, '#' )  
	 );  
	 
	 DECLARE @CurrentBalance bigint= (  
		SELECT TOP 1 mcd.Balance FROM MailCreditDetails AS mcd(NOLOCK) WHERE mcd.[User_ID] = @parentid  
			ORDER BY mcd.Credit_ID DESC  
	 );  
  
	 DECLARE @Balance bigint= @CurrentBalance - @MailCount;  
	 IF @Balance > 0  
	 BEGIN  
  
	  SELECT A.EmailID, A.AccountID, A.SenderName, A.MailContent, A.MailSubject, A.ReplyTo, A.leadid  
	  INTO #tempTableSendMail  
	  FROM  
	  (  
	   SELECT ISNULL(A.EmailID, '') AS EmailID, @Account AS AccountID, @SenderName AS SenderName, A.MailContent, @Email_Subject AS MailSubject, @ReplyTo AS ReplyTo, Leadid  
	   FROM  
	   (  
		SELECT CASE  
			WHEN @EmailId = 1 THEN ul.EmailID  
			ELSE ''  
			END AS EmailID, dbo.fn_getLeadsMailMessage( ul.ParentID, @Message, ul.EmailID ) AS MailContent, ul.EnquiryID AS leadid  
		FROM UserEnquiry AS ul(NOLOCK)  
		WHERE ul.EnquiryID IN  
		(  
		 SELECT [value]  
		 FROM dbo.fn_Split( @IDS, '#' ) AS fs  
		) AND   
		   ISNULL(NULLIF(CAST(ul.EmailID AS varchar), ''), '') <> '' AND   
		   ISNULL(NULLIF(CAST(ul.EmailID AS varchar), ''), '') NOT IN  
		(  
		 SELECT ISNULL(C_UDTemp.Email, '') AS EmailID  
		 FROM UserEnquiry AS UETemp(NOLOCK)  
		   INNER JOIN  
		   Client_UnSubscribeDetails AS C_UDTemp(NOLOCK)  
		   ON(UETemp.EmailID = C_UDTemp.Email)  
		 WHERE ul.EnquiryID IN  
		 (  
		  SELECT fs.value  
		  FROM dbo.fn_Split( @IDS, '#' ) AS fs  
		 )  
		)  
		UNION ALL  
		SELECT CASE  
			WHEN @EmailId1 = 1 THEN ul.EmailID1  
			ELSE ''  
			END AS EmailID, dbo.fn_getLeadsMailMessage( ul.ParentID, @Message, ul.EmailID1 ), ul.EnquiryID AS leadid  
		FROM UserEnquiry AS ul(NOLOCK)  
		WHERE ul.EnquiryID IN  
		(  
		 SELECT [value]  
		 FROM dbo.fn_Split( @IDS, '#' ) AS fs  
		) AND   
		   ISNULL(NULLIF(CAST(ul.EmailID1 AS varchar), ''), '') <> '' AND   
		   ISNULL(NULLIF(CAST(ul.EmailID1 AS varchar), ''), '') NOT IN  
		(  
		 SELECT ISNULL(C_UDTemp.Email, '') AS EmailID  
		 FROM UserEnquiry AS UETemp(NOLOCK)  
		   INNER JOIN  
		   Client_UnSubscribeDetails AS C_UDTemp(NOLOCK)  
		   ON(UETemp.EmailID1 = C_UDTemp.Email)  
		 WHERE ul.EnquiryID IN  
		 (  
		  SELECT fs.value  
		  FROM dbo.fn_Split( @IDS, '#' ) AS fs  
		 )  
		) AND   
		 ISNULL(NULLIF(CAST(ul.EmailID2 AS varchar), ''), '') <> '' AND   
		 ISNULL(NULLIF(CAST(ul.EmailID2 AS varchar), ''), '') NOT IN  
		(  
		 SELECT ISNULL(C_UDTemp.Email, '') AS EmailID  
		 FROM UserEnquiry AS UETemp(NOLOCK)  
		   INNER JOIN  
		   Client_UnSubscribeDetails AS C_UDTemp(NOLOCK)  
		   ON(UETemp.EmailID2 = C_UDTemp.Email)  
		 WHERE ul.EnquiryID IN  
		 (  
		  SELECT fs.value  
		  FROM dbo.fn_Split( @IDS, '#' ) AS fs  
		 )  
		)  
		UNION ALL  
		SELECT CASE  
			WHEN @EmailId2 = 1 THEN ul.EmailID2  
			ELSE ''  
			END AS EmailID, dbo.fn_getLeadsMailMessage( ul.ParentID, @Message, ul.EmailID2 ), ul.EnquiryID AS leadid  
		FROM UserEnquiry AS ul(NOLOCK)  
		WHERE ul.EnquiryID IN  
		(  
		 SELECT [value]  
		 FROM dbo.fn_Split( @IDS, '#' ) AS fs  
		)  
	   ) AS A  
	   WHERE ISNULL(A.EmailID, '') <> ''  
	  ) AS A;  
  
  
  
	  DECLARE @Status bigint= 0, @CountLimit bigint= 0;  
	  SELECT @Status = STATUS, @CountLimit = Plimit  
	  FROM ProcessMailLimit;  
	  IF(@Status = 1)  
	  BEGIN  
	   BEGIN  
		IF(@MailCount > @CountLimit)  
		BEGIN  
		 SET @IsMonitor = 0;  
		END;  
	   END;  
	  END;  
  
  
  
	  DECLARE @BatchID bigint;  
	  BEGIN TRAN;  
	  INSERT INTO GetBatchRecord( [User_id], RandNum )  
	  VALUES( @Account, @Account );  
	  SELECT @BatchID = SCOPE_IDENTITY();  
	  DELETE FROM GetBatchRecord  
	  WHERE batchid = @BatchID;  
	  COMMIT;  
  
  
	  DECLARE @Mail_FromEmail varchar(500)= '';  
  
	  SELECT @Mail_FromEmail = COALESCE(  
	  (  
	   SELECT TOP 1 mail_id  
	   FROM defaultmailid(NOLOCK)  
	   WHERE user_id = @account  
	   ORDER BY datecreated DESC  
	  ),  
	  (  
	   SELECT ud.EMail  
	   FROM User_Detail AS ud(NOLOCK)  
	   WHERE ud.[User_ID] = @Account  
	  ), 'contactus@email19.in');  
  
	  INSERT INTO CloneEmailsFilter( Mail_FromEmail, Mail_ToEmail, Mail_Subject, Mail_TempleteName, Messages, Mail_InsertedDate, Mail_UserID, Mail_ParentID, ReplyTo, Mail_BatchID, Mail_Priority, Mail_ScheduleDate, Mail_ScheduledTime, Mail_Attechement, Mail_TempleteBody, IsMonitor, TemplateID, Count, Source )  
		  SELECT @Mail_FromEmail, A.EmailID, A.MailSubject, '', A.MailContent, GETDATE(), A.AccountID, @parentid, A.ReplyTo, @BatchID, 1, '', '', '', A.MailContent, @ismonitor, 0, @mailcount, 'Leads-MassSend'  
		  FROM #tempTableSendMail AS A;  
  
	  IF(@UserId > 0)  
	  BEGIN  

	  	DECLARE @leadActivityHistory AS LeadActivity_Tbltype;  
	   DECLARE @Username nvarchar(255)=  
	   (  
		SELECT User_Login  
		FROM User_Detail(NOLOCK)  
		WHERE User_Id = @UserId  
	   );  
	    
		INSERT INTO @leadActivityHistory( LeadID, UserID, ParentID, EventDescription, EventName)  
		   SELECT leadid, @UserId, @parentid, concat(@Username, ' sent a mail with subject ', MailSubject, ' to emailid ', EmailID), 'Mail sent to Enquiry'

		   FROM #tempTableSendMail;  

  
		exec UspSaveLeadActivity_withMultipleValue @leadActivityHistory

	  
  
	  
	  END;  
  
		select @responseId = 1, @responseText = 'success'

	 END  
	 ELSE  
	 BEGIN  
	  select @responseId = -2, @responseText = 'Insufficient Balance'
	 END;  
  
	 DROP TABLE #tempTableSendMail;  
  
	 PRINT '-------------END------------------------------------ usp_ims_cb_SendMailFromEnquriy ----------------------------------------------';  
	END TRY  
	BEGIN CATCH  
		Exec  usp_InsertErrorInfo  
		select @responseId = -1, @responseText =  ERROR_MESSAGE() -- ResponseId,ResponseText
	END CATCH

	select @responseId as ResponseId, @responseText as ResponseText
END  



GO

