/* ============================================================
   Procedure: [dbo].[usp_ims_cb_usp_wf_AddDeal_New]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE usp_ims_cb_usp_wf_AddDeal_New
(   
    @LeadID               BIGINT ,   
    @PipelineID           BIGINT ,   
    @PipelineStage        BIGINT ,   
    @Amount               NUMERIC(18 , 2) ,   
    @EstimatedClosureDate DATETIME ,   
    @DealOwner            BIGINT ,   
    @CreatedBy            BIGINT ,   
    @Probability          NUMERIC(18 , 2) ,   
    @RefHistoryId         BIGINT = 0,
	@chatbotEventId			  BIGINT = NULL
)   
AS  
BEGIN  


declare @responseId bigint, @responseText nvarchar(max)


 BEGIN TRY  
  
  PRINT '--------------BEGIN----------------------------- usp_ims_cb_usp_wf_AddDeal_New ------------------------------------------------------';  
  PRINT '@LeadID: ' + CAST(@LeadID AS VARCHAR);  
  PRINT '@PipelineID: ' + CAST(@PipelineID AS VARCHAR);  
  PRINT '@PipelineStage: ' + CAST(@PipelineStage AS VARCHAR);  
  PRINT '@Amount: ' + CAST(@Amount AS VARCHAR);  
  PRINT '@EstimatedClosureDate: ' + CAST(@EstimatedClosureDate AS VARCHAR);  
  PRINT '@DealOwner: ' + CAST(@DealOwner AS VARCHAR);  
  PRINT '@CreatedBy: ' + CAST(@CreatedBy AS VARCHAR);  
  PRINT '@Probability: ' + CAST(@Probability AS VARCHAR);  
  PRINT '@RefHistoryId: ' + CAST(@RefHistoryId AS VARCHAR);  
  PRINT '@chatbotEventId: ' + CAST(isnull(@chatbotEventId,'') AS VARCHAR);  
  
  --declare @Probability numeric(18,2) = 0              
  DECLARE @pname NVARCHAR(100) , @sname NVARCHAR(100);           
  --select  top 1  @Probability = isnull(Probability,0) from PipelineStages(nolock) where               
  -- ID = @PipelineStage  and PipelineID = @pipelineID               
  DECLARE @leadpipelineid BIGINT=0;  
  SELECT @leadpipelineid=PipelineID FROM LeadPipelineMapping(NOLOCK) WHERE LeadID = @LeadID  
        AND PipelineID = @PipelineID AND  PipeLineStage = @PipelineStage AND IsDeleted = 0 
  IF (@leadpipelineid=0)   
  BEGIN  
   INSERT INTO LeadPipelineMapping ( [LeadID] , [PipelineID] , [PipeLineStage] , [Probability] , [Amount] , [Remarks] , [CreatedDate] , [CreatedBy] , [EstimatedClosureDate] , [DealOwner]  )   
   VALUES ( @LeadID , @PipelineID , @PipelineStage , @Probability , @Amount , 'Deal created' , GETDATE() , @Createdby , @EstimatedClosureDate , @DealOwner );  
   SELECT @leadpipelineid = SCOPE_IDENTITY();  
          
   BEGIN TRY  
    SELECT @pname = name FROM Pipeline_Master(NOLOCK) WHERE id = @PipelineID;  
    SELECT @sname = Name FROM PipelineStages(NOLOCK) WHERE id = @PipelineStage;  
    DECLARE @ParentID BIGINT= 0;  
    SELECT @ParentID = ISNULL(ParentID , 0) FROM User_Detail(NOLOCK) WHERE User_ID = @CreatedBy;  
    DECLARE @eventDesc NVARCHAR(500)= [dbo].[fn_getentityfullname] ('lead', @leadid ) + '''s deal created for pipeline :' + CAST(@Pname AS NVARCHAR) + ', Stage :' + @sname;  
  
    EXEC usp_wf_SaveLeadActivity_withid @LeadID , @Createdby , @ParentID , @eventDesc , 'Deal Added' , 'LeadPipelineMapping' , @leadpipelineid , 'ID' , @RefHistoryId, @chatbotEventId;  
   END TRY  
   BEGIN CATCH  
    EXEC usp_InsertErrorInfo;  
    THROW  
   END CATCH;
   
   select @responseId = 1, @responseText = 'success'

  END;  
  ELSE  
  BEGIN  
	select @responseId = -2, @responseText = 'LeadId Already Occupied'
  END;  
 END TRY  
 BEGIN CATCH  
  Exec  usp_InsertErrorInfo  
  select @responseId = -3, @responseText = 'LeadId Already Occupied'
 END CATCH  
 PRINT '--------------END----------------------------- usp_ims_cb_usp_wf_AddDeal_New ------------------------------------------------------';  

 select @responseId as ResponseId, @responseText as ResponseText


END;  



GO

/* ============================================================
   Procedure: [dbo].[usp_ims_ClickToCallWebhookNotification]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_ims_ClickToCallWebhookNotification
as
begin
	if (exists(select id, response_content, refNumber, ProviderName
	from tbl_voip_endpointInteraction(nolock) ei
		where id > 195099 and ISNULL(isNotify, 0)  = 0 
			and webhookReceivedAt is null and ProviderName = 'Mobile Like Number' and DATEDIFF(MINUTE, created_on, GETDATE()) > 5
		
	 ) )
	begin
		declare @body nvarchar(max) = '', @tableSql nvarchar(max), @tableData nvarchar(max)
		set @body = '<html><body><H1>Dear Reader</H1><p>We didn''t receive any webhook-call for below "Call Reference Number"</p>'

		set @tableSql = '<table border = 2><tr><th>Id</th><th>Response Content</th><th>refNumber</th></tr>';  
  
		select 
			@tableData = CONCAT( @tableData,  CONCAT('<tr><td>', id, '</td><td>', response_content,  '</td><td>', refNumber, '</td></tr>'))  
		from tbl_voip_endpointInteraction(nolock) ei
		where id > 195099 and ISNULL(isNotify, 0)  = 0 
			and webhookReceivedAt is null and ProviderName = 'Mobile Like Number'
			and DATEDIFF(MINUTE, created_on, GETDATE()) > 5

		update tbl_voip_endpointInteraction set isNotify  = 1 
			where id > 195099 and ISNULL(isNotify, 0)  = 0
			and webhookReceivedAt is null and ProviderName = 'Mobile Like Number' 
			and DATEDIFF(MINUTE, created_on, GETDATE()) > 5

		set @body = @body + @tableSql + @tableData + '</table></body></html>';  


		select @body

		exec msdb.dbo.sp_send_dbmail
			@profile_name = 'Alerts',   
			@recipients = 'shashi.rana@vispl.in;ajay.koul@vispl.in',
			@copy_recipients = 'karuna@pelsoftlabs.in;mukesh-kumar@pelsoftlabs.in;mayank.nigam@pelsoftlabs.in;animesh.shukla@pelsoftlabs.in;tanweer.alam@pelsoftlabs.in;rishabh.pandey@pelsoftlabs.in;animesh.shukla@pelsoftlabs.in;vaishali.kalra@pelsoftlabs.in',
			@blind_copy_recipients = 'mayank.nigam@pelsoftlabs.in',  
			@subject = 'Smartping ClickToCall Webhook Data Not Recieved', @body = @body, @body_format = 'HTML'

		--Excuting FailedCall Count Notification
		exec usp_voip_NotifiyFailedCallCount 

	end
end



GO

/* ============================================================
   Procedure: [dbo].[usp_ims_FindContactInLeadEnquiry]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_ims_FindContactInLeadEnquiry
	@ParenetId BIGINT,
	@UniqueContact NVARCHAR(500)
as
begin
--	DECLARE @ParenetId BIGINT= 34594, @UniqueContact NVARCHAR(500)= '9876543210';
	
	declare @EntityId bigint = 0, @EntityName nvarchar(100) = '';

	DROP TABLE IF EXISTS #tempLead;
	DROP TABLE IF EXISTS #tempEnquiry;

	SELECT * INTO #tempLead FROM (
		SELECT Id AS LeadId, ISNULL(MobileNo, '') AS Contact FROM MySMS.dbo.UserLeads(NOLOCK) WHERE ParentID = @ParenetId AND MobileNo <> '' 
			UNION
		SELECT Id AS LeadId, ISNULL(MobileNo1, '') AS Contact FROM MySMS.dbo.UserLeads(NOLOCK) WHERE ParentID = @ParenetId AND MobileNo1 <> '' 
			UNION
		SELECT Id AS LeadId, ISNULL(MobileNo2, '') AS Contact FROM MySMS.dbo.UserLeads(NOLOCK) WHERE ParentID = @ParenetId AND MobileNo2 <> '' 
			UNION
		SELECT Id AS LeadId, ISNULL(EmailID, '') AS Contact FROM MySMS.dbo.UserLeads(NOLOCK) WHERE ParentID = @ParenetId AND EmailID <> '' 
			UNION
		SELECT Id AS LeadId, ISNULL(EmailID1, '') AS Contact FROM MySMS.dbo.UserLeads(NOLOCK) WHERE ParentID = @ParenetId AND EmailID1 <> '' 
			UNION
		SELECT Id AS LeadId, ISNULL(EmailID2, '') AS Contact FROM MySMS.dbo.UserLeads(NOLOCK) WHERE ParentID = @ParenetId AND EmailID2 <> '' 
	) lc ORDER BY lc.LeadId DESC;

	SELECT TOP 1 @EntityId = LeadId, @EntityName = 'UserLeads' FROM #tempLead where Contact = @UniqueContact

		if(@EntityId = 0)
		begin
			SELECT * INTO #tempEnquiry FROM (
				SELECT EnquiryId, ISNULL(MobileNo, '') AS Contact FROM MySMS.dbo.Userenquiry(NOLOCK) WHERE ParentID = @ParenetId AND MobileNo <> '' 
					UNION
				SELECT EnquiryId, ISNULL(MobileNo1, '') AS Contact FROM MySMS.dbo.Userenquiry(NOLOCK) WHERE ParentID = @ParenetId AND MobileNo1 <> '' 
					UNION
				SELECT EnquiryId, ISNULL(MobileNo2, '') AS Contact FROM MySMS.dbo.Userenquiry(NOLOCK) WHERE ParentID = @ParenetId AND MobileNo2 <> '' 
					UNION
				SELECT EnquiryId, ISNULL(EmailID, '') AS Contact FROM MySMS.dbo.Userenquiry(NOLOCK) WHERE ParentID = @ParenetId AND EmailID <> '' 
					UNION
				SELECT EnquiryId, ISNULL(EmailID1, '') AS Contact FROM MySMS.dbo.Userenquiry(NOLOCK) WHERE ParentID = @ParenetId AND EmailID1 <> '' 
					UNION
				SELECT EnquiryId, ISNULL(EmailID2, '') AS Contact FROM MySMS.dbo.Userenquiry(NOLOCK) WHERE ParentID = @ParenetId AND EmailID2 <> '' 
			) lc ORDER BY lc.EnquiryId DESC;
			SELECT TOP 1 @EntityId = EnquiryId, @EntityName = 'Userenquiry' FROM #tempEnquiry where Contact = @UniqueContact
		end

	select @EntityId as EntityId, @EntityName as EntityName
end



GO

