/* ============================================================
   Procedure: [dbo].[usp_ims_GetAssociatedMobileNo]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ims_GetAssociatedMobileNo](
	@entity   NVARCHAR(20),     
	@entityid BIGINT    
)
as
begin   
	--declare 
	--	@entity NVARCHAR(20) = 'lead',     
	--	@entityid BIGINT = 16048131
		--@entity NVARCHAR(20) = 'lead',     
		--@entityid BIGINT = 2508095

	DECLARE @query NVARCHAR(MAX);
	DECLARE @parentid BIGINT; 
	
	--DROP TABLE IF EXISTS #temp;
 --   CREATE TABLE #temp (Entity nvarchar(200), Entityid BIGINT, convuserparentid BIGINT, lastactivityby bigint, channelprofileid nvarchar(500),channelid int,isactive bit);

	--SET @query = '
 --       SELECT Entity, Entityid,convuserparentid,lastactivityby, channelprofileid,channelid,isactive
 --       FROM convusers (NOLOCK) ';

 --   -- Execute the query using your CLR procedure
	--INSERT INTO #temp(Entity, Entityid,convuserparentid,lastactivityby, channelprofileid,channelid,isactive)
 --   EXEC usp_clr_FillRemoteData @query;

	IF @entity = 'lead'    
	BEGIN    
		SELECT @parentid = parentid FROM userleads(NOLOCK) WHERE id = @entityid;    
		SELECT 
			c.Id as [ConvUserId],
			a.Mobile as [MobileNo], 
			isnull(c.channelprofileid,  replace(replace(a.mobile, '+', ''), '-', '')) as [ChannelProfileId], 
			isnull(c.entity, @entity) as [EntityName], 
			isnull(c.entityid, @entityid)as [EntityId],
			A.PersonName as [PersonName],
			isnull(isactive, 0) as [IsActive], 
			( case when isnull(c.id, '') <> '' 
					then concat('Associated with ', c.entity)
				else 'free' end) as [Remarks] 
			FROM (    
				SELECT ISNULL(CAST(countrycode AS NVARCHAR) + '-' + CAST(mobileno AS NVARCHAR), '') AS Mobile, PersonName 
					FROM userleads(NOLOCK) WHERE id = @entityid AND NULLIF(MobileNo, '') IS NOT NULL    
				UNION    
				SELECT ISNULL(CAST(countrycode1 AS NVARCHAR) + '-' + CAST(MobileNo1 AS NVARCHAR), '') AS Mobile, PersonName    
					FROM userleads(NOLOCK) WHERE id = @entityid AND NULLIF(MobileNo1, '') IS NOT NULL    
				UNION    
				SELECT ISNULL(CAST(CountryCode2 AS NVARCHAR) + '-' + CAST(MobileNo2 AS NVARCHAR), '') AS Mobile, PersonName   
