/* ============================================================
   Procedure: [dbo].[usp_ims_GetChatbotFlowSessionList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_ims_GetChatbotFlowSessionList(
	@FlowId bigint,
	@UserId bigint,
	@OffsetValue INT = 0,   
	@PagingSize  INT = 20  

)
as
begin

	--declare 
	--	@FlowId bigint = 4,
	--	@UserId bigint = 34594,
	--	@OffsetValue INT    = 10,   
	--	@PagingSize  INT    = 20  

	declare 
		@StartPoint int  = (@OffsetValue + 1),
		@EndPoint int = (@PagingSize + @OffsetValue)



	select cs.* ,
		( case when cs.EntityName = 'enquiry' then ue.PersonName
			when cs.EntityName = 'lead' then ul.PersonName end ) as [PersonName],
		( case when cs.EntityName = 'enquiry' then ue.ProfileImgFileName
			when cs.EntityName = 'lead' then ul.ProfileImgFileName end ) as [ProfileImgFileName],
		'' as [EndDate]
		from ( select  f.Id, f.ConvParentId, f.StartTime, f.ConvUserId, f.ParentId, f.EntityName,  f.EntityId, cu.ChannelProfileId,
			ac.totalActions,
			row_number () over (partition by f.FlowId order by f.Id desc) as [rowNo],
			count(f.FlowId) over (order by f.FlowId desc) as [TotalRows]
		from  tbl_ims_ChatbotSession(nolock) f
			left join vw_FlowActionCount(nolock) ac on f.id = ac.chatbotFlowSessionId
			left join convusers(nolock) cu on isnull(f.ConvUserId, 0 ) > 0 and f.ConvUserId = cu.Id
			where f.FlowId = @FlowId ) cs
		left join MySMS_Dev.dbo.UserEnquiry(nolock) ue on ISNULL(cs.EntityName, '') <> '' and cs.EntityName = 'enquiry' 
			and 1 = (case when cs.EntityId = ue.EnquiryID then 1 else 0 end )
		left join MySMS_Dev.dbo.UserLeads(nolock) ul on ISNULL(cs.EntityName, '') <> '' and cs.EntityName = 'lead'
			and 1 = (case when cs.EntityId = ul.ID then 1 else 0 end )
	where cs. rowNo between @StartPoint and @EndPoint 

	EXEC MySmsAudit_Dev.dbo.Usp_AuditTableDataByParentId @User_id = @UserId    
	,@Activity_type = 'View_chatbotflwSessionlist'    
	,@ActionType = 'S'    
	,@RowJson = ''    
	,@Table_name = 'tbl_ims_ChatbotSession' 
	

end



GO

/* ============================================================
   Procedure: [dbo].[usp_ims_GetChatbotSessionFlow]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ims_GetChatbotSessionFlow](
	@ConvParentId nvarchar(255),
	@ParentId bigint,
	@FlowId bigint,
	@MessageStr nvarchar(255),
	@ChannelName nvarchar(255),
	@ConvUserId bigint,
	@EntityName nvarchar(255),
	@EntityId bigint
)
as
begin
	--declare 
	--	@ConvParentId nvarchar(255) = 'DryRun1666069084792',
	--	@ParentId bigint = 34594,
	--	@FlowId bigint = 11,
	--	@MessageStr nvarchar(255) = '1',
	--	@ChannelName nvarchar(255) = 'whatsapp'

	declare @SessionId bigint, @replyType nvarchar(255), @replyJSON nvarchar(max), @TemplateJSON nvarchar(max), @ChannelTokenId bigint

		select @ChannelTokenId = id from channels(nolock) where Channelname = 'whatsapp'

	if(not exists(select 1 from tbl_ims_ChatbotSession(nolock) where ConvParentId = @ConvParentId and FlowId = @FlowId))
	begin
		insert into tbl_ims_ChatbotSession (ConvParentId, FlowId, StartTime, EndTime, 
			ChannelTokenId, ParentId, Message, ConvUserId, EntityName, EntityId )
			select @ConvParentId, @FlowId, GETDATE(), GETDATE(), @ChannelTokenId, 
				@ParentId, @MessageStr, @ConvUserId, @EntityName, @EntityId
		select @SessionId  = SCOPE_IDENTITY()
	end
	else
	begin
		select @SessionId = Id from tbl_ims_ChatbotSession(nolock) where ConvParentId = @ConvParentId and FlowId = @FlowId
	end

	if(@SessionId > 0)
	begin
		declare @FlowSessionId bigint = 0;
		if(not exists(select 1 from tbl_ims_ChatbotSessionFlow(nolock) where ChatbotSessionId = @SessionId))
		begin
			insert into tbl_ims_ChatbotSessionFlow( ChatbotSessionId, StepName, StepId, NextStepId, PreviousStepId, 
					ReplyJson, ActionJaon, IsActive, IsDefaultFallback, IsStartPoint, ProccessAt, CreatedAt, entityValues, 
					isExecutedLast, nodeType, MenuJson )
			select @SessionId, StepName, StepId, NextStepId, PreviousStepId, 
					ReplyJson, ActionJson, IsActive, IsDefaultFallback, IsStartPoint, ProccessAt, CreatedAt, '', 0, nodeType, MenuJson
				from tbl_ims_ChatbotFlowStep(nolock) where flowId = @FlowId and IsActive = 1
		end
		
		select * from tbl_ims_ChatbotSessionFlow(nolock) 
			where ChatbotSessionId = @SessionId
	end
	else 
	begin
			select * from tbl_ims_ChatbotSessionFlow(nolock) 
			where ChatbotSessionId = 0
	end

	select strMessage from tbl_ims_DetaultFallBackSetting(nolock) where is_active = 1 and flowId = @FlowId

end



GO

/* ============================================================
   Procedure: [dbo].[usp_ims_GetConfictedLeadByMoblieNoNew]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ims_GetConfictedLeadByMoblieNoNew]          
 @SlotId bigint          
as                
begin                 
           
 --declare @SlotId bigint = 5693          
          
 drop table if exists #confilictLeadEnquiry                
           
 declare @RowJson nvarchar(max),@ParentId bigint = 0,@LeadNo int=0, @SourceName bigint=0, @AssignedTo bigint=0, @CreatedBy bigint = 0          
          
 select @RowJson=tis.contactjson, @SourceName=tir.SourceName, @ParentId=tir.ParentId, @CreatedBy = tir.CreatedBy from [10.0.0.135].MySMSConversations.dbo.tbl_ims_ImportSlot tis with (nolock)  
 inner join [10.0.0.135].MySMSConversations.dbo.tbl_imp_ImportRequest tir with (nolock) on tis.requestid = tir.Id  where tis.id = @SlotId          
          

    print concat ('@ParentId: ', @ParentId)
    print concat ('@RowJson: ', @RowJson)

 select SNo as [Id] ,[Name], [CountryCode], [MobileNo], cast('' as varchar(10)) as [EntityName], 0 as [EntityId], cast(''as nvarchar(25)) as [Verified]           
 into #confilictLeadEnquiry    
 from openjson(@RowJson) with           
 (          
     SNo int,          
     Name nvarchar(100),          
     CountryCode nvarchar(10),          
     MobileNo nvarchar(25)          
 ) 
 
update m set m.Verified = 'Duplicate in sheet' from ( select *, ROW_NUMBER() over(partition by c.MobileNo order by c.Id asc) as rno   
 from #confilictLeadEnquiry(nolock) c   
) t inner join #confilictLeadEnquiry m on t.Id = m.Id  
 where t.rno > 1  
  
  
 ;with cql          
 as          
 (          
 select * from (          
 select ROW_NUMBER()over(partition by cfle.mobileno order by ud.User_ID desc) rno, ud.User_ID, cfle.MobileNo, cfle.Verified, cfle.EntityName, cfle.EntityId          
 from #confilictLeadEnquiry cfle inner join           
  MySMS.dbo.User_Detail(nolock) ud on ud.ParentID = @ParentId and trim(cfle.[MobileNo]) in (trim(isnull(str(ud.Mobile),'')), trim(isnull(ud.wa_mobile_no,'')))          
  ) tbl where isnull(tbl.Verified, '') = ''  
)   
update cql set cql.verified=case when isnull(cql.rno,0) > 1 and cql.User_ID > 0 then 'D' else '' end,cql.EntityName='team',cql.EntityId=cql.User_ID  
  
  
 ;with cql          
 as          
 (          
 select * from (          
 select ROW_NUMBER()over(partition by cfle.mobileno order by ul.id desc) rno, ul.id,cfle.mobileno, cfle.Verified, cfle.EntityName, cfle.EntityId          
 from #confilictLeadEnquiry cfle inner join           
  MySMS.dbo.UserLeads(nolock) ul on ul.ParentID = @ParentId and trim(cfle.[MobileNo]) in (trim(isnull(ul.MobileNo,'')), trim(isnull(ul.MobileNo1,'')), trim(isnull(ul.MobileNo2,'')))          
  ) tbl where isnull(tbl.Verified, '') = ''    
            
)          
update cql set cql.verified=case when isnull(cql.rno,0) > 1 and cql.ID > 0 then 'D' else '' end, cql.EntityName='lead',cql.EntityId=cql.ID --where cql.rno>1          
           
         
; with cqe          
 as          
 (          
 select * from (          
 select ROW_NUMBER()over(partition by cfle.mobileno order by ul.EnquiryID desc) rno, ul.EnquiryID,cfle.mobileno, cfle.Verified, cfle.EntityName, cfle.EntityId          
 from #confilictLeadEnquiry cfle inner join           
  MySMS.dbo.UserEnquiry(nolock) ul on ul.ParentID = @ParentId and trim(cfle.[MobileNo]) in (trim(isnull(ul.MobileNo,'')), trim(isnull(ul.MobileNo1,'')), trim(isnull(ul.MobileNo2,'')))          
  ) tbl where isnull(tbl.Verified, '') = ''    
            
)          
update cqe set cqe.verified= case when isnull(cqe.rno,0) > 1 and cqe.EnquiryID > 0 then 'D' else '' end,cqe.EntityName='enquiry',cqe.EntityId=cqe.EnquiryId --where cqe.rno          
           
  
 if(exists(select 1 from #confilictLeadEnquiry where EntityName = '' and isnull(verified, '') = ''))          
 begin          
   
 declare @RowCount int = (select count(id) from #confilictLeadEnquiry)                
          
 set @AssignedTo=@ParentId  
 set @LeadNo = ISNULL((select MAX(LeadNo) from MySMS.dbo.UserLeads(nolock) where ParentId =  @ParentId), 0)  
  
    --select top 1 * from MySMS.dbo.UserLeads(nolock) where ParentId = 31094 order by id desc          
          
  declare @insertedRec table (          
    iLeadId bigint,      
    iLeadNo int,          
    iMobileNo nvarchar(25)          
  );          
      
 if(exists( select 1  From #confilictLeadEnquiry cle    
  Where isnull(cle.EntityName, '') = '' and isnull(verified, '') = '' and isnull(cle.MobileNo, '') <> ''   ))        
 begin   
  
  DECLARE @Cinfo VARBINARY(128);  
  
  SET Context_Info 0x55555  
   
  insert into MySMS.dbo.UserLeads(PersonName, MobileNo, CountryCode, SourceName, ParentID, AssignedTo, CreatedBy, LeadNo, CreatedOn, enquirysource)  
   output inserted.Id, inserted.LeadNo, inserted.MobileNo into  @insertedRec            
  select cle.[Name], cle.[MobileNo],  cle.[CountryCode], @SourceName, @ParentId,    
   isnull((select top 1 value from fn_Split((select agents from mysms.dbo.CRMCampaignSettings(nolock)   
    where userid=@parentid),'#') where position-1=id%position  and ISNULL([value], '') <> '' order by position desc),@parentid),   
   @ParentId, @LeadNo + ROW_NUMBER() over( order by cle.MobileNo), getdate(), 10          
  From #confilictLeadEnquiry cle  Where isnull(cle.EntityName, '') = ''  and isnull(verified, '') = '' and isnull(cle.MobileNo, '') <> ''        
          
  update cle set cle.EntityName = 'lead', cle.EntityId = ir.iLeadId          
  from @insertedRec ir inner join #confilictLeadEnquiry cle on ir.iMobileNo = cle.MobileNo  and isnull(verified, '') = '' and EntityName = ''       
     
  declare @csvLeadId nvarchar(max) = '', @CsvID nvarchar(max) = ''  
  
  select @csvLeadId = STRING_AGG(ire.iLeadId, ',') from @insertedRec  ire  
  
  Exec MySMS.dbo.usp_ExecLeadTriggerTasks @csvLeadId  
      
  if object_id('tempdb..#outputLeadInteraction') is not null begin drop table #outputLeadInteraction end  
  
  create table #outputLeadInteraction(id bigint)    
  
  insert into MySMS.dbo.leadinteractionhistory(LeadNo,FollowUpStatus,NextStatusDate,Products,AmountPaid,Remarks,AssignedTo,ParentID,CreatedOn,CreatedBy,followupdate,id_lead
  )  
   output inserted.ID into #outputLeadInteraction  
  select LeadNo,FollowUpStatus,NextStatusDate,Products,AmountPaid,Remarks,AssignedTo,ParentID,CreatedOn,CreatedBy,followupdate
  ,ul.id
   from MySMS.dbo.userleads(nolock) ul inner join   
    dbo.fn_Split(@csvLeadId,  ',') cui on ul.ID = cui.[value]  
   
  select @CsvID = STRING_AGG(CONVERT(NVARCHAR(max), ID),',') From #outputLeadInteraction  
  
  Exec MySMS.dbo.usp_ExecLeadInteractionTriggerTasks @CsvID  
     
  --exec MySMS.dbo.Usp_insertdefaultfollowup @UserID = @ParentId, @leadid = @csvLeadId  
  
  SET Context_Info 0x  
 end        
      
-- select * from @insertedRec  
  end      

  
 select Id, Name, Name as [PersonName], CountryCode, MobileNo, EntityName, EntityId, Verified  
 from  #confilictLeadEnquiry          
          
end  


