   Procedure: [dbo].[usp_ims_GetContactCountByUserId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_ims_GetContactCountByUserId(  
 @UserId bigint  
)  
as  
begin  
 declare @LeadCount int = 0, @EnquiryCount int = 0, @ContactCount int = 0  
 declare @ParentId bigint  = 0;  
 set @ParentId = (select ParentID from User_Detail(nolock) where User_Id = @UserId)  
 set @LeadCount = ( select count(1) as LeadCount from UserLeads(nolock) where ParentID = @ParentId)  
 set @EnquiryCount = ( select count(1) as EnquiryCount from UserEnquiry(nolock) where ParentID = @ParentId)  
 set @ContactCount =  ( select count(1) as ContactCount from conversationcontacts(nolock) where parentid =  @ParentId)  
  
 select @LeadCount as LeadCount, @EnquiryCount as EnquiryCount, @ContactCount as ContactCount  
end


