SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_ims_GetConversationByHistoryId](
	@HistoryId bigint
)
as
begin
	--declare @HistoryId bigint = 104185

	select 
		0 as Id,
		Historyid as EntityId,
		0 as sId, 
		0 as rId, 
		leh.HistoryID AS EntityId,
		0 as [sId],
		dbo.udf_ims_GetConvUserDetails(LeadID, 'lead') as [Sender],
		0 as [rId],
		dbo.udf_ims_GetConvUserDetails(LeadID, 'lead') as [Recipient],
		'' AS Direction,
		leh.EventDescription AS [Text],
		leh.reftables as [RefTables] ,
		leh.refids as [RefIds] ,
		'text' as [MessageType],
		'' AS [ChannelName],
		'activity' AS [Source],
		ud.User_ID AS [UserId],
		ud.User_Login AS AgentName,
		ud.ParentID AS [ParentId],
		ud.Image AS [AgentImage],
		leh.EventDate AS [CreatedOn],
		'' as [Status],
		'' as [StatusList],
		'' as SendMessageBody,
		'' as SendMessageType,
		'' as SendMessageDatetime,
		'' as [RequestJSON] ,
		'' as [LabelJson],
		0 as [IsDeleted],
		'' as [DeletedBy],
		null as DeletedOn
	from mysms_dev.dbo.tbl_LeadEventHistory(nolock) leh 
	left join mysms_dev.dbo.User_Detail(NOLOCK) ud ON leh.UserID = ud.User_ID
		where HistoryID = @HistoryId
end



