CREATE   PROCEDURE [dbo].[usp_ims_GetCustomSearchNameList] --34594    
(      
 @UserId bigint      
)      
as
begin
  --declare @UserId bigint = 34594 
  select ID, CriteriaName, CriteriaType from tbl_SearchCriteria(nolock)      
    where IsActive = 1 and ParentID = ( select ParentID from User_Detail(nolock) where User_ID = @UserId )     
  union    
    select max(ID) as ID, CriteriaName, CriteriaType from tbl_SearchCriteria(nolock)      
    where IsActive = 1 and isnull(ParentID,0) = 0
	group by CriteriaName, CriteriaType
       
end 


