   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ims_GetEventDetailList](  
	@ParentId bigint,  
	@FilterText nvarchar(max) = '',  
	@OffsetValue INT = 0,  
	@PagingSize  INT = 100,  
	@ActivityId bigint = 0  
)  
as  
begin  
   


 --declare   
 -- @ParentId bigint = 42148,  
 -- @FilterText nvarchar(max) = '',  
 -- @OffsetValue INT = 0,  
 -- @PagingSize  INT = 100,   
 -- @ActivityId bigint = 669  
  
 declare   
  @StartPoint int, @EndPoint int  
   
 set @StartPoint = (@OffsetValue + 1)  
 set @EndPoint = (@StartPoint + @PagingSize - 1)  
   
 select   
  t.id,  
  t.RequestJson,   
  t.ErrorDescription,  
  t.[Status],  
  t.ParentId,   
  t.CreatedOn,  
  t.EntityName,  
  t.EntityId,  
  dbo.udf_ims_GetAssoisatedEntityProfile(t.EntityName, t.EntityId) as [EntityProfile],  
  (case when isnull(t.InterationTable, '') <> '' and isnull(t.InteractionId, 0) > 0
	then dbo.udf_ce_GetEntityActivityDiscription(t.InterationTable, t.InteractionId)
  else '' end) as [EventDescription],
  t.rNo,  
  t.TotalRow  
 from (  
  select   
   e.id,  
   e.RequestJson,   
   e.ErrorDescription,   
   (case e.IsProccess when 0 then 'failure'  
    when 1  then 'success' else 'pending' end ) as [Status],  
   e.ParentId,   
   e.CreatedOn,  
   e.EntityName,  
   e.EntityId,
   e.InterationTable,
   e.InteractionId,
   ROW_NUMBER() over(partition by (select null) order by e.Id desc) as [rNo],  
   COUNT(*) over() as TotalRow  
  from tbl_ce_CustomEventExecutionHistory(nolock) e  
   left join tbl_ce_EventWebhook(nolock) w on e.RefTable = 'tbl_ce_EventWebhook' and e.RefId = w.Id  
   where e.ParentId = @ParentId and (  
    e.RequestJson like '%'+ isnull(@FilterText, '') +'%'  
   ) and 1 = (  
    case when isnull(@ActivityId, 0) = 0 then 1   
     when isnull(@ActivityId, 0) >  0 and  isnull(w.EventId, 0) > 0 and  isnull(w.EventId, 0) = isnull(@ActivityId, 0)  then 1   
    else 0 end  
   )  
 ) t where t.rNo between @StartPoint and @EndPoint  
  
end  



GO

