CREATE   PROCEDURE [dbo].[usp_ims_GetLeadActivityDetails] --110 
(      
 @LeadActivityId bigint      
)      
as      
begin      
 declare @Refid bigint = 0, @RefTables nvarchar(100) = '', @sqlQuery nvarchar(max)       
 select @Refid = refids, @RefTables = reftables from mysms.dbo.tbl_LeadEventHistory  where HistoryID = @LeadActivityId      
      
       
 if(@RefTables = 'tbl_MergeLeadsEnquiry')      
 begin      
