 end      
       
 if(@RefTables = 'Serv_TicketHistory')      
 begin     
	set @sqlQuery = 'select hst.TicketHistoryID, dbo.[fn_getusertimefromindiantime](hst.ParentID,hst.HistoryDate) as  HistoryDate, isnull(stm.Stat_Desc,''New'') [Status], isnull(updb.Login_id,'''')+ '' ''+''(''+isnull(updb.Email,'''')+'')'' [UpdatedBy], hst.Remarks, (case when isnull(aud.Login_id,'''') !='''' then ''Agent : ''+ aud.Login_id+''(''+aud.Email+'')'' else  case when isnull(gm.Group_Name,'''')!='''' then ''Group : ''+ gm.Group_Name else '''' end  end) as [AssignedTo], isnull((select a.Comments from serv_ticket_feedback_tbl a where a.TicketHistoryID = hst.TicketHistoryID),'''') as Feedback, SUBSTRING(hst.Note,0,100) as Note, ''TicketHistory'' as [source] from Serv_TicketMaster tm left outer join  Serv_TicketHistory hst on hst.TicketID = tm.TicketID left outer join Serv_Ticket_Stat_Mast stm on stm.Stat_ID = hst.Status inner join Serv_User_Detail sud   on sud.ser_user_id = tm.User_id left join Serv_User_Detail aud   on aud.ser_user_id = hst.TransferredTo left join Serv_User_Detail updb   on updb.ser_user_id = convert(BigInt,hst.raisedby) left outer join  Serv_Group_Mast gm on gm.Groupid = hst.Assign_Group LEFT OUTER JOIN spt_tkt_attach ta on tm.TicketID = ta.ticketid and hst.TicketHistoryID = ta.tickethistoryid where hst.TicketHistoryID = '  + cast(@Refid as nvarchar)   + ' '         
 end      
      
 if(@RefTables = 'Kit19Calls')      
 begin      
  set @sqlQuery = 'select * from ' + @RefTables + ' where id =  '+ cast(@Refid as nvarchar)      
 end      
      
 if(@RefTables = 'BatchVoiceInfo')      
 begin      
  set @sqlQuery = 'select * from ' + @RefTables + ' where BatchInfoID =  '+ cast(@Refid as nvarchar)      
 end      
      
 if(@RefTables = 'Mysmst.dbo.Tbl_EmailTracking')      
 begin      
  set @sqlQuery = 'select * from ' + @RefTables + ' where BatchInfoID =  '+ cast(@Refid as nvarchar)      
 end      
      
 if(@RefTables = 'WebEntryTbl')      
 begin      
  set @sqlQuery = 'select * from ' + @RefTables + ' where EntryId =  '+ cast(@Refid as nvarchar)      
 end      
      
 if(@RefTables = 'LeadPipelineMapping')      
 begin      
  set @sqlQuery = 'select lpm.ID, lpm.Probability, pm.Name as [PipelineName], ps.Name as [StageName], lpm.Amount, lpm.EstimatedClosureDate,     
 concat(ctb.FName, '''', ctb.LName) AS [CreatedByName], ctb.Image AS [CreatedByImage], ''deal'' as [source],  
 concat(do.FName, '''', do.LName) AS [DealOwnerName], do.Image AS [DealOwnerImage]  
 from LeadPipelineMapping(nolock) lpm   
 inner join  Pipeline_Master(nolock) pm on lpm.PipelineID = pm.ID  
 inner join PipelineStages(nolock) ps on lpm.PipeLineStage = ps.ID  
 inner join User_Detail(nolock) ctb on lpm.CreatedBy =  ctb.User_ID  
 inner join User_Detail(nolock) do on lpm.DealOwner =  do.User_ID  
  where lpm.ID = '+ cast(@Refid as nvarchar)      
 end      
      
 if(@RefTables = 'tbl_es_NewsLetterSubscriber')      
 begin      
  set @sqlQuery = 'select * from ' + @RefTables + ' where Id =  '+ cast(@Refid as nvarchar)      
 end      
      
 if(@RefTables = 'fieldupdated')      
 begin      
  set @sqlQuery = 'select * from ' + @RefTables + ' where id =  '+ cast(@Refid as nvarchar)      
 end      
      
 if(@RefTables = 'Review')      
 begin      
  set @sqlQuery = 'select * from ' + @RefTables + ' where ReviewID =  '+ cast(@Refid as nvarchar)      
 end      
      
 if(@RefTables = 'Customers')      
 begin      
  set @sqlQuery = 'select * from ' + @RefTables + ' where CustomerID =  '+ cast(@Refid as nvarchar)      
 end      
      
 if(@RefTables = 'Batchinfo')      
 begin      
  set @sqlQuery = 'select * from ' + @RefTables + ' where BatchInfoID =  '+ cast(@Refid as nvarchar)      
 end      
      
 if(@RefTables = 'Order')      
 begin      
  set @sqlQuery = 'select * from ' + @RefTables + ' where BatchInfoID =  '+ cast(@Refid as nvarchar)      
 end      
      
 if(@RefTables = 'serv_Ticketmaster')      
 begin      
   --set @sqlQuery = 'select * from ' + @RefTables + ' where TicketID =  '+ cast(@Refid as nvarchar)      
   set @sqlQuery = ' drop table if exists #TempTicketMaster
	CREATE TABLE  #TempTicketMaster( AssignedDateTime nvarchar(max), resolved_dt nvarchar(max), TicketID nvarchar(max), User_id nvarchar(max), ParentID nvarchar(max), TicketNo nvarchar(max), Requester nvarchar(max), Subject	 nvarchar(max), Description nvarchar(max), Status nvarchar(max), Remarks nvarchar(max), Note nvarchar(max), Date_Created nvarchar(max), Priority nvarchar(max), AssignTo nvarchar(max), Assign_Group nvarchar(max), UserResponse nvarchar(max), Active nvarchar(max), Ticket_type nvarchar(max), agrp_unassigned	 nvarchar(max), dataSource nvarchar(max), Product nvarchar(max), Company nvarchar(max), EmailId nvarchar(max), domain nvarchar(max), spam nvarchar(max), deleted nvarchar(max), skip_nticketmail nvarchar(max), tkt_tag	 nvarchar(max), Assignedby nvarchar(max), Stat_Desc nvarchar(max), Date_Creat nvarchar(max), Login_id nvarchar(max), Group_Name nvarchar(max), Question nvarchar(max), shrtdesc nvarchar(max), req_name nvarchar(max), Agent_name nvarchar(max), ldate nvarchar(max), attachfile nvarchar(max), filepath nvarchar(max), Rating nvarchar(max), Cust_Comments nvarchar(max) )
insert into #TempTicketMaster
	exec usp_sm_GetSearchTicketDetails @TicketID = ' + cast ( @Refid as nvarchar) + ', @ParentID=0, @ser_user_id=0, @access_level=''''  
		select ttm.*, p.Priority_Desc, t.Type_Desc,  ''TicketMaster'' as [source] from #TempTicketMaster  ttm
	inner join Serv_Priority_Mast(nolock) p on ttm.Priority = p.Priority_ID 
	inner join Serv_TicketType_Mast(nolock) t on ttm.Ticket_type = t.Type_ID '
 end      
        
 if(@RefTables = 'tbl_LeadNotes')      
 begin      
  set @sqlQuery = ' select ln.NoteID, ln.Notes, CONCAT(ud.FName, '' '', ud.LName) as AgentName, Image as AgentPhoto, ln.CreatedDate, ''note'' as [source] from tbl_LeadNotes(nolock) ln inner join  User_Detail(nolock) ud on ln.UserID = ud.User_ID  where NoteID = '+ cast(@Refid as nvarchar)      
         
 end      
       
 if(@RefTables = 'tbl_tsk_TaskHistory')      
 begin      
  set @sqlQuery = 'SELECT th.Id, th.Title,  th.Description,  th.StartDate,  th.EndDate, th.IsTask, th.IsAppointment, concat(ctb.FName, '' '', ctb.LName) AS [CreatedByName], ctb.Image AS [CreatedByImage], th.CreatedOn, concat(atb.FName, '' '', atb.LName) AS [AssignedToName], ctb.Image AS [AssignedToImage], th.Remarks, uoc.OutcomeName, th.Address, th.CompleteAddress, th.CompletedOn, th.Latitude, th.Longitude, ( SELECT(UD.FName + '' '' + UD.LName) AS CollaboratorName, ud.Image AS CollaboratorImage FROM tbl_tsk_CollaborationUserMapping CUM INNER JOIN user_detail UD ON CUM.User_Id = UD.User_ID WHERE TaskHistoryId = th.Id FOR JSON PATH ) AS [Collaborators], ''task'' as [source]    
     FROM tbl_tsk_TaskHistory(NOLOCK) th    
       INNER JOIN User_Detail(NOLOCK) ctb ON th.CreatedBy = ctb.User_ID    
       INNER JOIN User_Detail(NOLOCK) atb ON th.AssignedTo = atb.User_ID    
       LEFT JOIN tbl_tsk_UserOutcomeMaster(NOLOCK) uoc ON th.OutcomesId = uoc.id    
     WHERE th.Id = '+ cast(@Refid as nvarchar)      
 end      
      
 if(@RefTables = 'Link_smstrack')      
 begin      
  set @sqlQuery = 'select * from ' + @RefTables + ' where trackid =  '+ cast(@Refid as nvarchar)      
 end      
       
 if(@RefTables = 'LeadInteractionHistory')      
 begin    
       declare @ParentID bigint = (select top 1 isnull(ParentID,0)  from LeadInteractionHistory with(nolock) 
	                                            where id = @Refid )
       exec Usp_createProductMasterTable @ParentID

  set @sqlQuery = 'select  lih.ID, fus.FollowupStatus,         
      TRY_CONVERT(DATETIME, CONVERT(VARCHAR(25), dbo.[fn_getuserlocaltime](lih.ParentID, lih.FollowupDate))) AS NextStatusDate,         
       lih.Remarks,         
        --(        
        -- SELECT STUFF(        
        -- (        
        --  SELECT N'', '' + ss.Name        
        --  FROM tbl_ProductMaster_' + Cast(@ParentID as nvarchar(max)) + ' AS ss (NOLOCK)        
        --    INNER JOIN dbo.fn_Split(lih.Products, ''#'') AS fs ON ss.ProductID = fs.[value] FOR XML PATH(''''), TYPE        
        -- ).value(''text()[1]'', ''nvarchar(max)''), 1, 2, N'''')        
        --) AS Products, 
		
		isnull((select isnull((select  
               STRING_AGG(isnull(ProductName,''''),'', '') from openjson([lih].[ProductsJson])  
                with(ProductName nvarchar(max) ''$.ProductName'' )  
          where isnull([lih].[ProductsJson],'''') != '''') , '''')),'''') as Products ,

            lih.AmountPaid,         
            concat(ast.FName, '' '', ISNULL(ast.LName, '''')) AS AssignedTo,     
            ast.Image AS AssignedToImage,    
                      
            --lih.CreatedOn,  
			dbo.[fn_getuserlocaltime](lih.ParentID, lih.CreatedOn) as CreatedOn, 

            concat(cst.FName, '' '', ISNULL(cst.LName, '''')) AS CreatedBy,     
            cst.Image AS CreatedByImage,    
            ''intractionhistory'' as [source]    
      FROM LeadInteractionHistory AS lih(NOLOCK)        
        INNER JOIN UserLeads UL ON lih.ParentID = UL.ParentID      
        AND lih.LeadNo = UL.LeadNo        
        LEFT JOIN FollowUp_Status AS fus(NOLOCK) ON fus.ID = lih.FollowUpStatus        
        LEFT JOIN User_Detail(NOLOCK) ast ON ast.[User_ID] = lih.AssignedTo        
        LEFT JOIN User_Detail(NOLOCK) cst ON cst.[User_ID] = lih.CreatedBy        
       WHERE lih.ID = '+ cast(@Refid as nvarchar)      
 end      
      
 if(@RefTables = 'MySMS.dbo.MySMSConversations')      
 begin      
  set @sqlQuery = 'select * from ' + @RefTables + ' where id =  '+ cast(@Refid as nvarchar)      
 end      
      
 if(@RefTables = 'Mysmsconversations.dbo.convusers')      
 begin      
