 end      
      
 if(@RefTables = 'tbl_LeadDocumentUpload')      
 begin      
  set @sqlQuery =  'SELECT ldu.DocUpID, ldu.DocumentName, ldu.FileType, ldu.UploadedDate, CONCAT(ud.FName, '' '', ud.LName) AS AgentName,    
  Image AS AgentPhoto, ''document'' as [source] FROM MySMS.dbo.tbl_LeadDocumentUpload(NOLOCK) ldu     
  INNER JOIN MySMS.dbo.User_Detail(NOLOCK) ud ON ldu.UserID = ud.User_ID WHERE DocUpID = ' + cast(@Refid as nvarchar)      
