 end      
       
 if(@RefTables = 'Kit19callsdialled')      
 begin      
  set @sqlQuery = 'select * from ' + @RefTables + ' where id =  '+ cast(@Refid as nvarchar)      
 end      
      
 if(@RefTables = 'Batchemail_infos')      
 begin      
