 end      
      
 if(@RefTables = 'tbl_subscription')      
 begin      
  set @sqlQuery = 'select * from ' + @RefTables + ' where ID =  '+ cast(@Refid as nvarchar)      
 end      
      
 if(@RefTables = 'tbl_mergeleads')      
 begin      
  set @sqlQuery = 'select * from ' + @RefTables + ' where id =  '+ cast(@Refid as nvarchar)      
 end      
      
  print @sqlQuery    
      
 EXECUTE sp_executesql   @sqlQuery      
end



