/* ============================================================
   Procedure: [dbo].[usp_ims_GetLECCount]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ims_GetLECCount]  
 @UserId bigint  
 as  
begin  
 declare @LeadCount int = 0, @EnquiryCount int  = 0, @ContactCount int = 0; 
 
 DECLARE @ParentId BIGINT,@isadmin int;                                              
SELECT @parentid=ParentID,@isadmin=IsAdmin  FROM MySMS_Dev.dbo.User_Detail(NOLOCK) WHERE User_ID = @UserId;                      

 Declare @TeamCode varchar(10) = ''  
 Declare @ScopeCode varchar(10) = ''   
Declare @UserIdTeamLst varchar(4000) = '' 
Declare @HierarchyJSON varchar(Max) = ''

 if Exists(select 1 from tbl_UA_UserHierarchy where ParentId = @ParentId) 
 Begin 
 Select @HierarchyJSON = HierarchyJSON from tbl_UA_UserHierarchy where ParentId = @ParentId 

  Create TABLE #TableData2 ([user_id] bigint, team_name Varchar(50), user_login varchar(50), username varchar(50), [parentid] bigint)
  Insert into #TableData2 ([user_id], team_name, user_login,username,[parentid])               
  Select [user_id], '', user_login, username, [parentid] from OPENJSON(@HierarchyJSON) with ([user_id] bigint, user_login Varchar(100), username Varchar(100), [parentid] bigint)

  ;with CTE(user_id) 
 as ( 
  select user_id 
  from #TableData2 where (User_id = @UserId or parentid = @UserId)
  union all 
  -- recursively add children
  select c.user_id
  from #TableData2 c 
  join CTE on c.parentid = CTE.User_id
 ) 
SELECT @UserIdTeamLst = STUFF((SELECT distinct ',' + Cast( a.user_id as varchar(4000)) from #TableData2 a join CTE on CTE.user_id = a.User_id FOR XML PATH('')),1,1,'')
 
--, @UserIdTeamLst = ''
 select @TeamCode = TeamCode, @ScopeCode = ScopeCode from ufn_GetUserRoleScope(@UserId) 

 --select * from #TableData2 
 --select @UserIdTeamLst 
 End
 Else
 Begin
 select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst from ufn_GetUserRoleScope(@UserId) 
 End

 set @LeadCount = ( select Count(1) from MySMS_Dev.dbo.UserLeads ul where ParentID = @ParentId 
 --and isnull(ul.assignedto,0) in (case when @isadmin=1 then isnull(ul.assignedto,0)
 -- when @UserIdTeamLst != '' then (select [value] from dbo.fn_Split(@UserIdTeamLst, ','))
 -- else @UserId
 -- end )
  )  
 set @EnquiryCount = (select Count(1) from MySMS_Dev.dbo.UserEnquiry en where en.ParentID = @ParentId
 --and isnull(en.CreatedBy,0) in (case  when @isadmin=1 then isnull(en.CreatedBy,0) 
 -- when @UserIdTeamLst != '' then (select [value] from dbo.fn_Split(@UserIdTeamLst, ','))
 -- else @UserId
 -- end )
  )  
 set @ContactCount = (select Count(1) from MySMS_Dev.dbo.conversationcontacts where ParentID = @ParentId)  
  
 select @LeadCount as LeadCount, @EnquiryCount  as EnquiryCount, @ContactCount as ContactCount  
  
end  




GO

/* ============================================================
   Procedure: [dbo].[usp_ims_GetLocationSummaryRptByUserIdsDateList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ims_GetLocationSummaryRptByUserIdsDateList] (
  @Mode varchar(10) = '',
  @SearchText nvarchar(max) = '',
  @FromDate varchar(20) = '',
  @ToDate varchar(20) = '',
  @UserId bigint,
  @UserIds varchar(max) = '',
  @ParentId bigint = 0,
  @Contain nvarchar(max) = '',
  @Offset int  = 0,
  @PageSize int = 10
)
AS
SET NOCOUNT ON
BEGIN
BEGIN TRY

--DECLARE
--  @Mode varchar(10) = N'LS',
--  @SearchText nvarchar(max) = N'',  
--  @FromDate varchar(25) = N'01-May-2024',
--  @ToDate varchar(25) = N'31-May-2024',
--  @UserIds varchar(max) = N'',
--  @UserId bigint = 44304,
--  @ParentId bigint = 44304,
--  @Contain nvarchar(max) = '',
--  @Offset int  = 4,
--  @PageSize int = 4

IF (@Mode = 'LS') /*This is for Insert usp_tbl_ET_Attendance Details */
BEGIN

	select top 1 @ParentId = ParentId  from User_Detail(nolock) where USER_ID  = @UserId
	
	
	drop table if exists #tempUsers  
	create table #tempUsers(User_ID bigint, Name nvarchar(255), Image nvarchar(255))  
	insert into #tempUsers(User_ID, Name, Image)  
	exec Use_GetUserDetails @UserID = @UserId  

	if(ISNULL(@UserIds, '') =  '') begin set @UserIds = '' end

	drop table if exists #tempSelectedUser
	create table #tempSelectedUser ( UserId bigint )
	insert into #tempSelectedUser(UserId) select [value] from string_split(@UserIds, ',') where [value] > 0

	if(@SearchText != '') begin set @SearchText = ' and EmployeeName like ''%'+ @SearchText + '%''' end else begin set @SearchText = '' end;
	if(@Contain != '') begin set @Contain = ' and '+ @Contain end else begin set @Contain = '' end;

	declare @StartPoint int  = (@Offset + 1), @EndPoint int  = ( @Offset + @PageSize )


	Declare @query nvarchar(max)
	set @query = concat( N'select * from (select q.SNo, q.TotalRows, q.UserName, q.User_Id as [UserId], ParentID, ',
		N'User_Login, EmployeeName, ManagerParent, ',
		N'Designetion, TeamName, InternalId, ',
		N'PresentDays, HalfDays, WeeklyOffDays, OnLeaveDays, TotalDays, InLateDays, OutEarlyDays, ',
		N'(TotalDays - PresentDays - WeeklyOffDays - OnLeaveDays - (HalfDays * .5)) AbsentDays, ',
		N'TotalAttendanceTime, ',
		N'NumberOfBreaks,  ',
		N'concat(cast(cast(TimeInBreaks/60 as int)as varchar(10)), '':'', ', 
			N'cast(cast((TimeInBreaks%60)as int) as varchar(5)), '' hrs.'') TotalTimeInBreaks, ',
		N'concat(cast(cast(MaxBreakTimes / 60 as int)as varchar(10)), '':'', ',
			N' cast(cast((MaxBreakTimes % 60)as int) as varchar(5)), '' hrs.'') MaxBreakTime, ',
		N' TotalTask,  ',
		N'concat(cast(cast(TimeSpentInTasks/60 as int)as varchar(10)), '':'', ',
			N'cast(cast((TimeSpentInTasks%60)as int) as varchar(5)), '' hrs.'') TotalTimeSpentInTasks, ',
		--N'concat(cast(cast(TotalTimeSpentTravelled / 60 as int)as varchar(10)) +'':'', ',
		--	N'cast(cast((TotalTimeSpentTravelled % 60)as int) as varchar(5)) + '' hrs.'') TotalTimeSpentTravel, ',
		N'TotalTravelTime AS [TotalTimeSpentTravel], ',
		N'TotalClaim, TotalApproved, TotalDistance, TotalTravelTime ',
		N'from ( select ud.SNo, ud.TotalRows, ud.UserName, ud.User_ID, ud.ParentID, ud.User_Login, ud.EmployeeName,',
		N'(udpa.FName + '' '' + udpa.LName) ManagerParent, '''' Designetion,  ', 
		--N' isnull(thia.team_name, '''') 
		N''''' TeamName, '''' InternalId, ',
		--N'isnull(thia.Parentid, 0)
		N'0 HirarchyParentid, ',
		N'dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, ''', @FromDate, ''', ''', @ToDate, ''', ''TotalWorkingDay'') PresentDays,  ',
		N'dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, ''', @FromDate, ''', ''', @ToDate, ''', ''HalfDays'') HalfDays,  ',
		N'dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, ''', @FromDate, ''', ''', @ToDate, ''', ''WeekOff'') WeeklyOffDays,  ',
		N'dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, ''', @FromDate, ''', ''', @ToDate, ''', ''TotalLeave'') OnLeaveDays,  ',
		N'dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, ''', @FromDate, ''', ''', @ToDate, ''', ''TotalDays'') TotalDays,  ',
		N'dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, ''', @FromDate, ''', ''', @ToDate, ''', ''LateSignin'') InLateDays,  ',
		N'dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, ''', @FromDate, ''', ''', @ToDate, ''', ''OutEarlyDays'') OutEarlyDays, ',
		N'dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, ''', @FromDate, ''', ''', @ToDate, ''', ''Totalminutes'') TotalAttendanceTime, ',
		--N'dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, ''', @FromDate, ''', ''', @ToDate, ''', ''NumberOfBreaks'') NumberOfBreaks, ',
		--N'dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, ''', @FromDate, ''', ''', @ToDate, ''', ''TimeInBreaks'') TimeInBreaks, ',
		N'NumberOfBreaks, ',
		N'TimeInBreaks, ',
		N'dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, ''', @FromDate, ''', ''', @ToDate, ''', ''MaxBreakTimes'') MaxBreakTimes, ',
		--N'dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, ''', @FromDate, ''', ''', @ToDate, ''', ''TotalTask'') TotalTask, ',
		--N'dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, ''', @FromDate, ''', ''', @ToDate, ''', ''TimeSpentInTasks'') TimeSpentInTasks, ',
		N'TotalTask, ', 
		N'TimeSpentInTasks, ', 

		N'dbo.fn_TBL_ET_ExpenseTotalSummaryFT(ud.User_ID, ''', @FromDate, ''', ''', @ToDate, ''', ''TotalTimeSpentTravelled'') TotalTimeSpentTravelled, ',
		N'dbo.fn_TBL_ET_ExpenseTotalSummaryFT(ud.User_ID, ''', @FromDate, ''', ''', @ToDate, ''', ''TotalClaim'') TotalClaim, ',
		N'dbo.fn_TBL_ET_ExpenseTotalSummaryFT(ud.User_ID, ''', @FromDate, ''', ''', @ToDate, ''', ''TotalApproved'') TotalApproved, ',
		--N'dbo.fn_TBL_ET_ExpenseTotalSummaryFT(ud.User_ID, ''', @FromDate, ''', ''', @ToDate, ''', ''TotalDistance'') TotalDistance, ',
		--N'dbo.fn_TBL_ET_ExpenseTotalSummaryFT(ud.User_ID, ''', @FromDate, ''', ''', 
		--	@ToDate, ''', ''TotalTravelTime'') TotalTravelTime ',
		N'TotalDistance, ',
		N'TotalTravelTime ',
		N'from ( select pu.* from ( select ROW_NUMBER() over (partition by u.ParentID Order by u.FName asc) as [SNo], ',
				N'count(*) over ( order by u.ParentID) as [TotalRows], ',
				N'concat(u.FName, '' '', u.LName) as [UserName], u.User_ID, u.ParentID, ',
				N'u.User_Login, concat(u.FName, '' '', u.LName, '' ('', u.User_Login, '')'') as [EmployeeName], ',
				N'try_convert(decimal(18,3), ( ut.total_travel_distance /1000)) as  [TotalDistance], ',
				N'ut.total_hours as [TotalTravelTime], ',
				N'bs.TotalBreaks as [NumberOfBreaks], ',
				N'bs.TotalBreakHours as [TimeInBreaks], ',
				N'ua.TotalAppointments as [TotalTask], ',
				N'ua.TotalHoursSpent  as [TimeSpentInTasks] ',
		  N'from User_detail(nolock) u ',
		  N'left join v_tbl_et_GetUserTotalDistanceAndHours ut on u.User_Id = ut.UserId ',
		  N'and ut.month = datepart(month, ''', @FromDate, ''') and ut.year = datepart(year, ''', @FromDate, ''')',		  
		  N'left join v_tbl_et_GetUserBreakSummary bs on u.User_Id = bs.UserId ',
		  N'and bs.month = datepart(month, ''', @FromDate, ''') and bs.year = datepart(year, ''', @FromDate, ''')',
		   N'left join v_tbl_et_UserAppointmentSummary ua on u.User_Id = ua.UserId ',
		  N'and ua.month = datepart(month, ''', @FromDate, ''') and ua.year = datepart(year, ''', @FromDate, ''')',

		  

		N'inner join #tempUsers tu on u.User_Id = tu.User_ID ',

			iif(LEN(@UserIds) > 0, 'inner join #tempSelectedUser su on u.User_Id = su.UserId ', ''),
		 N'where (1=1)  ', @SearchText, ' ', @Contain, ') pu where pu.SNo between ', @StartPoint, ' and ', @EndPoint, ' ) ud  ',
		N'inner join User_detail(nolock) udpa on ud.ParentId = udpa.User_Id ',
		--N' left join #TblHirarchy thia on ud.User_Id = thia.User_Id  ',
		N' ) q ) t ')
	print @query

	execute sp_executesql @query

 End 
END TRY 

BEGIN CATCH 
	exec Usp_InsertErrorInfo
END CATCH 
END



GO

/* ============================================================
   Procedure: [dbo].[usp_ims_GetLocationSummaryRptByUserIdsDateList_Cache]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_ims_GetLocationSummaryRptByUserIdsDateList_Cache] (
  @Mode varchar(10) = '',
  @SearchText nvarchar(max) = '',
  @FromDate varchar(20) = '',
  @ToDate varchar(20) = '',
  @UserId bigint,
  @UserIds varchar(max) = '',
  @ParentId bigint = 0,
  @Contain nvarchar(max) = '',
  @Offset int  = 0,
  @PageSize int = 10
)
AS
SET NOCOUNT ON
BEGIN
BEGIN TRY

IF (@Mode = 'LS') /*This is for Insert usp_tbl_ET_Attendance Details */
BEGIN

				DECLARE @MonthStart DATETIME;
				DECLARE @MonthEnd DATETIME;

			select @ParentID = ParentID from Mysms.[dbo].User_Detail(nolock) where User_ID = @UserId;

			if(ISNULL(@UserIds, '') =  '') begin set @UserIds = '' end

			drop table if exists #tempSelectedUser
			create table #tempSelectedUser ( UserId bigint )
			insert into #tempSelectedUser(UserId) select [value] from string_split(@UserIds, ',') where [value] > 0

			--if(@SearchText != '') begin set @SearchText = ' and EmployeeName like ''%'+ @SearchText + '%''' end else begin set @SearchText = '' end;
			--if(@Contain != '') begin set @Contain = ' and '+ @Contain end else begin set @Contain = '' end;

				-- Get the first and last date of the current month
				--SET @MonthStart = FORMAT(DATEADD(DAY, 1 - DAY(GETDATE()), CAST(GETDATE() AS DATE)), 'dd-MMM-yyyy'); -- First day of current month
				--SET @MonthEnd = FORMAT(EOMONTH(GETDATE()), 'dd-MMM-yyyy'); -- Last day of current month


				Declare @Currentdate  DATE  = GETDATE();  -- Today's date
				SET @MonthStart      = FORMAT(DATEADD(DAY, 1 - DAY(GETDATE()), CAST(GETDATE() AS DATE)), 'dd-MMM-yyyy'); -- First day of current month
				SET @MonthEnd  =  FORMAT(DATEADD(DAY, -1, @Currentdate), 'dd-MMM-yyyy');

				DECLARE @SQL NVARCHAR(MAX);

				-- Check conditions and select data
			IF (@FromDate Between @MonthStart AND @MonthEnd AND @ToDate Between @MonthStart AND @MonthEnd) 
				BEGIN
				 SET @SQL = '
							SELECT 
								[SNo],
								[TotalRows],
								[UserName],
								[UserId],
								[ParentID],
								[User_Login],
								[EmployeeName],
								[ManagerParent],
								[Designetion],
								[TeamName],
								[InternalId],
								[PresentDays],
								[HalfDays],
								[WeeklyOffDays],
								[OnLeaveDays],
								[TotalDays],
								[InLateDays],
								[OutEarlyDays],
								[AbsentDays],
								[TotalAttendanceTime],
								[NumberOfBreaks],
								[TotalTimeInBreaks],
								[MaxBreakTime],
								[TotalTask],
								[TotalTimeSpentInTasks],
								[TotalTimeSpentTravel],
								[TotalClaim],
								[TotalApproved],
								[TotalDistance],
								[TotalTravelTime],
								[User_Id]
							FROM 
								[dbo].[tbl_SummaryReport_Cache] (NOLOCK)
							WHERE 
								[User_Id] = @UserId 
								AND [ParentId] = @ParentId';

							IF (@SearchText != '')
							BEGIN
								SET @SQL = @SQL + '
								AND EmployeeName LIKE ''%'' + @SearchText + ''%''';
							END;

							-- Add the join dynamically if @UserIds is not empty
							IF LEN(@UserIds) > 0
							BEGIN
								SET @SQL = @SQL + '
								INNER JOIN #tempSelectedUser su ON tbl_SummaryReport_Cache.UserId = su.UserId';
							END;

				END
			ELSE IF (@FromDate < @MonthStart OR @ToDate < @MonthStart)
					BEGIN
					SET @SQL = ' 
							SELECT 
								  [SNo]
								  ,[TotalRows]
								  ,[UserName]
								  ,[UserId]
								  ,[ParentID]
								  ,[User_Login]
								  ,[EmployeeName]
								  ,[ManagerParent]
								  ,[Designetion]
								  ,[TeamName]
								  ,[InternalId]
								  ,[PresentDays]
								  ,[HalfDays]
								  ,[WeeklyOffDays]
								  ,[OnLeaveDays]
								  ,[TotalDays]
								  ,[InLateDays]
								  ,[OutEarlyDays]
								  ,[AbsentDays]
								  ,[TotalAttendanceTime]
								  ,[NumberOfBreaks]
								  ,[TotalTimeInBreaks]
								  ,[MaxBreakTime]
								  ,[TotalTask]
								  ,[TotalTimeSpentInTasks]
								  ,[TotalTimeSpentTravel]
								  ,[TotalClaim]
								  ,[TotalApproved]
								  ,[TotalDistance]
								  ,[TotalTravelTime]
								  ,[User_Id]
								  FROM [dbo].[tbl_SummaryReport_Archive](nolock)
								WHERE 
								[User_Id] = @UserId 
								AND [ParentId] = @ParentId';


								IF (@SearchText != '')
							BEGIN
								SET @SQL = @SQL + '
								AND EmployeeName LIKE ''%'' + @SearchText + ''%''';
							END;

							-- Add the join dynamically if @UserIds is not empty
							IF LEN(@UserIds) > 0
							BEGIN
								SET @SQL = @SQL + '
								INNER JOIN #tempSelectedUser su ON tbl_SummaryReport_Cache.UserId = su.UserId';
							END;
					END
			ELSE
				BEGIN
					EXEC [Mysms].[dbo].usp_ims_GetLocationSummaryRptByUserIdsDateList @Mode, @SearchText, @FromDate, @ToDate, @UserId, @UserIds, @ParentId, @Contain, @Offset, @PageSize;
				END

					EXEC sp_executesql @SQL, 
                   N'@UserId INT, @ParentId INT, @SearchText NVARCHAR(MAX)', 
                   @UserId, 
                   @ParentId,
				   @SearchText;

 End 
END TRY 

BEGIN CATCH 
	exec MySMS.dbo.usp_InsertErrorInfo
END CATCH 
END



GO

