/* ============================================================
   Procedure: [dbo].[usp_ims_GetReplacedContactContent]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ims_GetReplacedContactContent](  
	 @MyStirng nvarchar(max),  
	 @EntityId bigint  
)  
as  
begin  
	 --  declare @MyStirng nvarchar(max) = 'This is my name#PersonName#and my#City# is in #State#', @EntityId bigint   = 5
	if( CHARINDEX('#', @MyStirng) > 0)
	begin
		drop table if exists #leadcustomeValue   
		select ROW_NUMBER() over ( order by A.fieldname asc )  as Id,  *   
		into #leadcustomeValue  
		from (  
			select T.fieldname,  
			case when T.fieldname = '#id#' then cast(cc.id as nvarchar)  
					when T.fieldname = '#parentid#' then cast(cc.parentid as nvarchar)  
					when T.fieldname = '#personname#' then cast(cc.personname as nvarchar)  
					when T.fieldname = '#emailid#' then cast(cc.emailid as nvarchar)    
					when T.fieldname = '#countrycode#' then cast(cc.countrycode as nvarchar)  
					when T.fieldname = '#mobile#' then cast(cc.mobile as nvarchar)  
					when T.fieldname = '#InitialRemarks#' then cast(cc.InitialRemarks as nvarchar)    
					when T.fieldname = '#createdon#' then cast(cc.createdon as nvarchar)  
					when T.fieldname = '#img_ext#' then cast(cc.img_ext as nvarchar)  
					when T.fieldname = '#ProfileImgFileName#' then cast(cc.ProfileImgFileName as nvarchar)  
					when T.fieldname = '#channelid#' then cast(cc.channelid as nvarchar)  
					when T.fieldname = '#channelProfileId#' then cast(cc.channelProfileId as nvarchar)    
					when T.fieldname = '#ismerged#' then cast(cc.ismerged as nvarchar)  
					else '' end as [fieldvalue]  
				from MySMS.dbo.conversationcontacts (nolock) cc cross apply (  
				SELECT concat('#', column_name, '#') AS 'fieldname'      
				FROM information_schema.columns      
				WHERE table_name = 'conversationcontacts'
			) T  where cc.id = @EntityId 
		) A


		declare @count int = ( select count(*) from #leadcustomeValue)  
		declare @i int = 1;  
		while(@i<= @count)  
		begin  
			select @MyStirng = REPLACE(@MyStirng, fieldname , cast(isnull(fieldvalue, '') as nvarchar(max))) from #leadcustomeValue where id = @i  
			set @i = @i + 1  
		end  
	end
	select @MyStirng  
end



GO

/* ============================================================
   Procedure: [dbo].[usp_ims_GetReplacedEnquiryContent]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_ims_GetReplacedEnquiryContent](
	@MyStirng nvarchar(max),
	@EnquiryId bigint
)
as
begin
	-- declare @MyStirng nvarchar(max) = 'This is my name#PersonName#and my#City# is in #State#',  @EnquiryId bigint = 3715782
 	if( CHARINDEX('#', @MyStirng) > 0)
	begin
		drop table if exists #leadcustomeValue 
		select ROW_NUMBER() over ( order by A.fieldname asc )  as Id,  * 
		into #leadcustomeValue
		from ( 
		 select T.fieldname,
			case  when T.fieldname = '#EnquiryID#' then str(EN.EnquiryID)
				when T.fieldname = '#PersonName#' then EN.PersonName
				when T.fieldname = '#CompanyName#' then EN.CompanyName
				when T.fieldname = '#MobileNo#' then EN.MobileNo
				when T.fieldname = '#MobileNo1#' then EN.MobileNo1
				when T.fieldname = '#MobileNo2#' then EN.MobileNo2
				when T.fieldname = '#EmailID#' then EN.EmailID
				when T.fieldname = '#EmailID1#' then EN.EmailID1
				when T.fieldname = '#EmailID2#' then EN.EmailID2
				when T.fieldname = '#City#' then EN.City
				when T.fieldname = '#State#' then EN.State
				when T.fieldname = '#Country#' then EN.Country
				when T.fieldname = '#CountryCode#' then EN.CountryCode
				when T.fieldname = '#CountryCode1#' then EN.CountryCode1
				when T.fieldname = '#CountryCode2#' then EN.CountryCode2
				when T.fieldname = '#PinCode#' then cast(EN.PinCode as nvarchar)
				when T.fieldname = '#ResidentialAddress#' then cast(EN.ResidentialAddress as nvarchar)
				when T.fieldname = '#OfficeAddress#' then cast(EN.OfficeAddress as nvarchar)
				when T.fieldname = '#SourceName#' then cast(EN.SourceName as nvarchar)
				when T.fieldname = '#MediumName#' then cast(EN.MediumName as nvarchar)
				when T.fieldname = '#CampaignName#' then cast(EN.CampaignName as nvarchar)
				when T.fieldname = '#InitialRemarks#' then cast(EN.InitialRemarks as nvarchar)
				when T.fieldname = '#ParentID#' then cast(EN.ParentID as nvarchar)
				when T.fieldname = '#CreatedDate#' then cast(EN.CreatedDate as nvarchar)
				when T.fieldname = '#CreatedBy#' then cast(EN.CreatedBy as nvarchar)
				when T.fieldname = '#IsOpen#' then cast(EN.IsOpen as nvarchar)
				when T.fieldname = '#LeadNo#' then cast(EN.LeadNo as nvarchar)
				when T.fieldname = '#img_ext#' then cast(EN.img_ext as nvarchar)
				when T.fieldname = '#ProfileImgFileName#' then cast(EN.ProfileImgFileName as nvarchar)
				when T.fieldname = '#enquirysource#' then cast(EN.enquirysource as nvarchar)
				when T.fieldname = '#WhatsAppNoColName#' then cast(EN.WhatsAppNoColName as nvarchar)
					else '' end as [fieldvalue]
			from MySMS.dbo.UserEnquiry(nolock) EN cross apply (
				SELECT concat('#', column_name, '#') AS 'fieldname'    
				FROM information_schema.columns    
				WHERE table_name = 'UserEnquiry' 
       
		) T
		where EN.EnquiryID = @EnquiryId

		union
		select cf.fieldname, cv.fieldvalue from MySMS.dbo.customfieldEnquiryvalue(nolock) cv
					inner join customfields(nolock) cf on cv.fieldID = cf.field_ID where cv.EnquiryID = @EnquiryId
		union  
        select concat('calculatedfield.', cv.calculatedfield_name) as fieldname, cf.field_value as fieldvalue from MySMS.dbo.calculated_fields_master(nolock) cv  
     inner join calculated_fields(nolock) cf on cv.ID = cf.calculatedfield_id where cf.entity='enquiry' and  cf.entityID = @EnquiryId  

			
		) A

		declare @count int = ( select count(*) from #leadcustomeValue)
		declare @i int = 1;
		while(@i<= @count)
		begin
			select @MyStirng = REPLACE(@MyStirng, fieldname , cast(isnull(fieldvalue, '') as nvarchar)) from #leadcustomeValue where id = @i
			set @i = @i + 1
		end
	end
	select @MyStirng
end



GO

/* ============================================================
   Procedure: [dbo].[usp_ims_GetReplacedEnquiryContentWithHash]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ims_GetReplacedEnquiryContentWithHash](  
 @MyStirng nvarchar(max),  
 @EnquiryId bigint  
)  
as  
begin  
   
 --declare @MyStirng nvarchar(max) = '#Draw_Number#',  @EnquiryId bigint = 6331812  
  
 set @MyStirng = replace(replace(@MyStirng, '#lead.', '#'), '#enquiry.', '#')  
  
 if( CHARINDEX('#', @MyStirng) > 0)  
 begin  
  drop table if exists #leadcustomeValue   
  select ROW_NUMBER() over ( order by A.fieldname asc )  as Id,  *   
  into #leadcustomeValue  
  from (   
   select T.fieldname,  
   case  when T.fieldname = '#EnquiryID#' then str(EN.EnquiryID)  
    when T.fieldname = '#PersonName#' then EN.PersonName  
    when T.fieldname = '#CompanyName#' then EN.CompanyName  
    when T.fieldname = '#MobileNo#' then dbo.fnGetNumericValue(EN.MobileNo)  
    when T.fieldname = '#MobileNo1#' then dbo.fnGetNumericValue(EN.MobileNo1)  
    when T.fieldname = '#MobileNo2#' then dbo.fnGetNumericValue(EN.MobileNo2)  
    when T.fieldname = '#EmailID#' then EN.EmailID  
    when T.fieldname = '#EmailID1#' then EN.EmailID1  
    when T.fieldname = '#EmailID2#' then EN.EmailID2  
    when T.fieldname = '#City#' then EN.City  
    when T.fieldname = '#State#' then EN.State  
    when T.fieldname = '#Country#' then EN.Country  
    when T.fieldname = '#CountryCode#' then EN.CountryCode  
    when T.fieldname = '#CountryCode1#' then EN.CountryCode1  
    when T.fieldname = '#CountryCode2#' then EN.CountryCode2  
    when T.fieldname = '#PinCode#' then cast(EN.PinCode as nvarchar)  
    when T.fieldname = '#ResidentialAddress#' then cast(EN.ResidentialAddress as nvarchar)  
    when T.fieldname = '#OfficeAddress#' then cast(EN.OfficeAddress as nvarchar)  
    when T.fieldname = '#SourceName#' then cast(EN.SourceName as nvarchar)  
    when T.fieldname = '#MediumName#' then cast(EN.MediumName as nvarchar)  
    when T.fieldname = '#CampaignName#' then cast(EN.CampaignName as nvarchar)  
    when T.fieldname = '#InitialRemarks#' then cast(EN.InitialRemarks as nvarchar)  
    when T.fieldname = '#ParentID#' then cast(EN.ParentID as nvarchar)  
    when T.fieldname = '#CreatedDate#' then cast(EN.CreatedDate as nvarchar)  
    when T.fieldname = '#CreatedBy#' then cast(EN.CreatedBy as nvarchar)  
    when T.fieldname = '#IsOpen#' then cast(EN.IsOpen as nvarchar)  
    when T.fieldname = '#LeadNo#' then cast(EN.LeadNo as nvarchar)  
    when T.fieldname = '#img_ext#' then cast(EN.img_ext as nvarchar)  
    when T.fieldname = '#ProfileImgFileName#' then cast(EN.ProfileImgFileName as nvarchar)  
    when T.fieldname = '#enquirysource#' then cast(EN.enquirysource as nvarchar)  
    when T.fieldname = '#WhatsAppNoColName#' then cast(EN.WhatsAppNoColName as nvarchar) 
	when T.fieldname = '#CreatedByName#' then isnull(dbo.fn_getentityfullname('user',u.user_id),'')
    when T.fieldname = '#CreatedByPhone#' then isnull(str(u.mobile),'')
    when T.fieldname = '#CreatedByEmail#' then isnull(u.email,'')

     else '' end as [fieldvalue]  
   from MySMS.dbo.UserEnquiry(nolock) EN 
   left join user_detail(nolock) u on u.user_id=en.CreatedBy
   cross apply (  
    SELECT concat('#', column_name, '#') AS 'fieldname'      
    FROM information_schema.columns      
    WHERE table_name = 'UserEnquiry'   
	union  select '#CreatedByName#' as fieldname  
	union  select '#CreatedByPhone#' as fieldname  
	union  select '#CreatedByEmail#' as fieldname  
         
  ) T  
  where EN.EnquiryID = @EnquiryId  
  
  union  
  select concat('#',cf.fieldname, '#') as fieldname, cv.fieldvalue from MySMS.dbo.customfieldEnquiryvalue(nolock) cv  
     inner join customfields(nolock) cf on cv.fieldID = cf.field_ID where cv.EnquiryID = @EnquiryId  
  union    
        select concat('#calculatedfield.', cv.calculatedfield_name) as fieldname, cf.field_value as fieldvalue from MySMS.dbo.calculated_fields_master(nolock) cv    
     inner join calculated_fields(nolock) cf on cv.ID = cf.calculatedfield_id where cf.entity='enquiry' and  cf.entityID = @EnquiryId    
   
  ) A  
  
  declare @count int = ( select count(*) from #leadcustomeValue)  
  declare @i int = 1;  
  while(@i<= @count)  
  begin  
   select @MyStirng = REPLACE(@MyStirng, fieldname , cast(isnull(fieldvalue, '') as nvarchar(max))) from #leadcustomeValue where id = @i  
   set @i = @i + 1  
  end  
 end  
 select @MyStirng  
  
end  


GO

/* ============================================================
   Procedure: [dbo].[usp_ims_GetReplacedLeadContent]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ims_GetReplacedLeadContent](    
 @MyStirng nvarchar(max),    
 @LeadId bigint    
)    
as    
begin    
    
 --declare @MyStirng nvarchar(max) = 'This is my name#PersonName#and my #SourceName# is in #AssignedTo#', @LeadId bigint = 11910148    
    
 if( CHARINDEX('#', @MyStirng) > 0)    
 begin    
  drop table if exists #leadcustomeValue     
  select ROW_NUMBER() over ( order by A.fieldname asc )  as Id,  *     
  into #leadcustomeValue    
  from (    
   select T.fieldname,    
   case when T.fieldname = '#ID#' then str(UL.ID)    
   when T.fieldname = '#LeadNo#' then str(UL.LeadNo)    
   when T.fieldname = '#PersonName#' then UL.PersonName    
   when T.fieldname = '#CompanyName#' then UL.CompanyName    
   when T.fieldname = '#MobileNo#' then str(UL.MobileNo)    
   when T.fieldname = '#MobileNo1#' then str(UL.MobileNo1)    
   when T.fieldname = '#MobileNo2#' then str(UL.MobileNo2)    
   when T.fieldname = '#EmailID#' then UL.EmailID    
   when T.fieldname = '#EmailID1#' then UL.EmailID1    
   when T.fieldname = '#EmailID2#' then UL.EmailID2    
   when T.fieldname = '#City#' then UL.City    
   when T.fieldname = '#State#' then UL.State    
   when T.fieldname = '#Country#' then UL.Country    
   when T.fieldname = '#CountryCode#' then UL.CountryCode    
   when T.fieldname = '#CountryCode1#' then UL.CountryCode1    
   when T.fieldname = '#CountryCode2#' then UL.CountryCode2    
   when T.fieldname = '#PinCode#' then str(UL.PinCode)    
   when T.fieldname = '#ResidentialAddress#' then UL.ResidentialAddress    
   when T.fieldname = '#OfficeAddress#' then UL.OfficeAddress    
   when T.fieldname = '#AssignedTo#' then UDM.User_Login    
   when T.fieldname = '#SourceName#' then USS.Name    
   when T.fieldname = '#MediumName#' then UMS.Name    
   when T.fieldname = '#CampaignName#' then UCS.Name  
   when T.fieldname = '#InitialRemarks#' then UL.InitialRemarks    
   when T.fieldname = '#ParentID#' then str(UL.ParentID)    
   when T.fieldname = '#FollowUpStatus#' then str(UL.FollowUpStatus)    
   when T.fieldname = '#NextStatusDate#' then cast(UL.NextStatusDate as nvarchar)    
   when T.fieldname = '#Remarks#' then UL.Remarks    
   when T.fieldname = '#Products#' then UL.Products    
   when T.fieldname = '#AmountPaid#' then str(UL.AmountPaid)    
   when T.fieldname = '#CreatedOn#' then cast(UL.CreatedOn as nvarchar)    
   when T.fieldname = '#CreatedBy#' then UD.User_Login    
   when T.fieldname = '#ModifiedOn#' then cast(UL.ModifiedOn as nvarchar)    
   when T.fieldname = '#ModifiedBy#' then UDMO.User_Login    
   when T.fieldname = '#FollowupDate#' then cast(UL.FollowupDate as nvarchar)    
   when T.fieldname = '#LeadImage#' then UL.LeadImage    
   when T.fieldname = '#temp_id#' then str(UL.temp_id)    
   when T.fieldname = '#img_ext#' then UL.img_ext    
   when T.fieldname = '#ProfileImgFileName#' then UL.ProfileImgFileName   
   when T.fieldname = '#AssignedtoName#' then dbo.fn_getentityfullname('user',UDM.user_id)    
  when T.fieldname = '#AssignedtoPhone#' then str(udm.mobile)  
  when T.fieldname = '#AssignedtoEmail#' then isnull(udm.email,'')  
  
   else '' end as [fieldvalue]    
   from MySMS.dbo.UserLeads(nolock) UL   
   left join mysms.dbo.UserSourceSettings(nolock) USS on USS.SourceID=UL.SourceName  
   left join mysms.dbo.UserMediumSettings(nolock) UMS on UMS.MediumID=UL.MediumName  
   left join mysms.dbo.UserCampaignSettings(nolock) UCS on UCS.CampaignID=UL.CampaignName  
   left join mysms.dbo.User_detail(nolock) UD on UD.User_ID=UL.CreatedBy  
   left join mysms.dbo.User_detail(nolock) UDM on UDM.user_id=UL.AssignedTo  
   left join mysms.dbo.User_detail(nolock) UDMO on UDMO.user_id=UL.ModifiedBy  
   cross apply (    
    SELECT concat('#', column_name, '#') AS 'fieldname'        
    FROM information_schema.columns        
    WHERE table_name = 'UserLeads'     
           
  ) T    
  where UL.Id = @LeadId    
  union    
  select concat('#', cf.fieldname, '#') as fieldname, cv.fieldvalue from MySMS.dbo.customfieldLeadvalue(nolock) cv    
     inner join customfields(nolock) cf on cv.fieldID = cf.field_ID where cv.LeadID = @LeadId    
  union    
  select concat('#calculatedfield.', cv.calculatedfield_name, '#') as fieldname, cf.field_value as fieldvalue from MySMS.dbo.calculated_fields_master(nolock) cv    
     inner join calculated_fields(nolock) cf on cv.ID = cf.calculatedfield_id where cf.entity='lead' and  cf.entityID = @LeadId    
     ) A    
    
  declare @count int = ( select count(*) from #leadcustomeValue)    
  declare @i int = 1;    
  while(@i<= @count)    
  begin    
   select @MyStirng = REPLACE(@MyStirng, fieldname , cast(isnull(fieldvalue, '') as nvarchar)) from #leadcustomeValue where id = @i    
   set @i = @i + 1    
  end    
 end    
 select @MyStirng    
    
    
end 


GO

