CREATE   PROCEDURE [dbo].[usp_ims_GetReplacedLeadContentWithHash](  
 @MyStirng nvarchar(max),  
 @LeadId bigint  
)  
as  
begin  
  
 --declare @MyStirng nvarchar(max) = N'{"key":"407324E9C47F4CE9B43A4ED24A444545","username":"gaurclasses955861","name":"whatsapp","whatsapp":{"to":"+917665731666","type":"template","category":"AUTO_REPLY","recipient_type":"individual","template":{"namespa
--ce":"6081e24a_3ac8_407e_a797_b5c7555ce370","language":{"policy":"deterministic","code":"en"},"name":"rpsc_cut_off_2022","components":[]}}}', @LeadId bigint = 3130060  
  
 declare @ParentId bigint = 0 ,@assigned bigint 
 select @ParentId = ParentID,@assigned=assignedto from UserLeads(nolock) where ID = @LeadId  
  
 set @MyStirng = replace(replace(@MyStirng, '#lead.', '#'), '#enquiry.', '#')  
  
   
 declare @tblCustomValue as table (  
  fieldname nvarchar(255),  
  fieldvalue nvarchar(255)  
 )  
 insert into @tblCustomValue(fieldname, fieldvalue)   
  values('#CurrentDateTime#', format(getdate(), 'dd-MMM-yyyy HH:mm:ss')),  
  ('#CurrentDate#', format(getdate(), 'dd-MMM-yyyy')),  
  ('#CurrentTime#', format(getdate(), 'HH:mm:ss'))  
  
 drop table if exists #leadcustomeValue   
 select ROW_NUMBER() over ( order by A.fieldname asc )  as Id,  *   
 into #leadcustomeValue  
 from (  
  select T.fieldname,  
  case when T.fieldname = '#ID#' then str(UL.ID)  
  when T.fieldname = '#LeadNo#' then str(UL.LeadNo)  
  when T.fieldname = '#PersonName#' then UL.PersonName  
  when T.fieldname = '#CompanyName#' then UL.CompanyName  
  when T.fieldname = '#MobileNo#' then dbo.fnGetNumericValue(UL.MobileNo)  
  when T.fieldname = '#MobileNo1#' then dbo.fnGetNumericValue(UL.MobileNo1)  
  when T.fieldname = '#MobileNo2#' then dbo.fnGetNumericValue(UL.MobileNo2)  
  when T.fieldname = '#EmailID#' then UL.EmailID  
  when T.fieldname = '#EmailID1#' then UL.EmailID1  
  when T.fieldname = '#EmailID2#' then UL.EmailID2  
  when T.fieldname = '#City#' then UL.City  
  when T.fieldname = '#State#' then UL.State  
  when T.fieldname = '#Country#' then UL.Country  
  when T.fieldname = '#CountryCode#' then UL.CountryCode  
  when T.fieldname = '#CountryCode1#' then UL.CountryCode1  
  when T.fieldname = '#CountryCode2#' then UL.CountryCode2  
  when T.fieldname = '#PinCode#' then str(UL.PinCode)  
  when T.fieldname = '#ResidentialAddress#' then UL.ResidentialAddress  
  when T.fieldname = '#OfficeAddress#' then UL.OfficeAddress  
  when T.fieldname = '#AssignedTo#' then str(UL.AssignedTo)  
  when T.fieldname = '#SourceName#' then str(UL.SourceName)  
  when T.fieldname = '#MediumName#' then str(UL.MediumName)  
  when T.fieldname = '#CampaignName#' then str(UL.CampaignName)  
  when T.fieldname = '#InitialRemarks#' then UL.InitialRemarks  
  when T.fieldname = '#ParentID#' then str(UL.ParentID)  
  when T.fieldname = '#FollowUpStatus#' then str(UL.FollowUpStatus)  
  when T.fieldname = '#NextStatusDate#' then cast(UL.NextStatusDate as nvarchar)  
  when T.fieldname = '#Remarks#' then UL.Remarks  
  when T.fieldname = '#Products#' then UL.Products  
  when T.fieldname = '#AmountPaid#' then str(UL.AmountPaid)  
  when T.fieldname = '#CreatedOn#' then cast(UL.CreatedOn as nvarchar)  
  when T.fieldname = '#CreatedBy#' then str(UL.CreatedBy)  
  when T.fieldname = '#ModifiedOn#' then cast(UL.ModifiedOn as nvarchar)  
  when T.fieldname = '#ModifiedBy#' then str(UL.ModifiedBy)  
  when T.fieldname = '#FollowupDate#' then cast(UL.FollowupDate as nvarchar)  
  when T.fieldname = '#LeadImage#' then UL.LeadImage  
  when T.fieldname = '#temp_id#' then str(UL.temp_id)  
  when T.fieldname = '#img_ext#' then UL.img_ext  
  when T.fieldname = '#ProfileImgFileName#' then UL.ProfileImgFileName  
  when T.fieldname = '#AssignedtoName#' then U.AssignedtoName  
  when T.fieldname = '#AssignedtoPhone#' then U.AssignedtoPhone  
  when T.fieldname = '#AssignedtoEmail#' then U.AssignedtoEmail  
  else '' end as [fieldvalue]  
  from MySMS.dbo.UserLeads(nolock) UL 
  left join
  (select user_id,dbo.fn_getentityfullname('User',user_id) as AssignedtoName, str(mobile) as AssignedtoPhone, isnull(email,'') as AssignedtoEmail from user_detail u (nolock) where 
  user_id=@assigned
  ) u on 1=1
  cross apply (  
   SELECT concat('#', column_name, '#') AS 'fieldname'      
   FROM information_schema.columns      
   WHERE table_name = 'UserLeads'  
	union  select '#AssignedtoName#' as fieldname  
	union  select '#AssignedtoPhone#' as fieldname  
	union  select '#AssignedtoEmail#' as fieldname     
         
 ) T  
 where UL.Id = @LeadId  
 union  
 --select concat('#',cf.fieldname, '#'), cv.fieldvalue from MySMS.dbo.customfieldLeadvalue(nolock) cv  
 --   inner join customfields(nolock) cf on cv.fieldID = cf.field_ID where cv.LeadID = @LeadId  
   
 select concat('#',cf.fieldname, '#') as fieldname, isnull(cv.fieldvalue, '') [fieldvalue] from   
 (   
  select c.field_ID, c.fieldname from customfields(nolock) c  where c.parentId = @ParentId  
 ) cf  
 left join ( select v.fieldID, v.fieldvalue from  
 customfieldLeadvalue(nolock) v  where v.LeadID = @LeadId )cv on cv.fieldID = cf.field_ID   
   union  
 select fieldname, fieldvalue from @tblCustomValue  
 union    
    select concat('calculatedfield.', cv.calculatedfield_name) as fieldname, cf.field_value as fieldvalue from MySMS.dbo.calculated_fields_master(nolock) cv    
     inner join calculated_fields(nolock) cf on cv.ID = cf.calculatedfield_id where cf.entity='lead' and  cf.entityID = @LeadId    
    
 ) A  
  
 declare @count int = ( select count(*) from #leadcustomeValue)  
 declare @i int = 1;  
 while(@i<= @count)  
 begin  
  select @MyStirng = REPLACE(@MyStirng, fieldname , cast(isnull(fieldvalue, '') as nvarchar(max))) from #leadcustomeValue where id = @i  
  set @i = @i + 1  
 end  
  
 select @MyStirng  
  
  
end  


