/* ============================================================
   Procedure: [dbo].[usp_ims_GetReplacedProductContentdataWithHash]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

   
CREATE   PROCEDURE [dbo].[usp_ims_GetReplacedProductContentdataWithHash](      
 @StrToReplace nvarchar(max),      
 @userId bigint ,
 @ProductId bigint
)      
as      
begin      
 --declare 
	--@ProductId bigint = 10663,
	--@userId bigint = 34594,
	--@StrToReplace nvarchar(max) = ' this is my <i><b>#CreatedOn#</b></i> and <i>123 Main Street</i>'

declare @ParentId bigint
select @ParentId=ParentID from User_Detail(nolock) where User_ID = @userId 
declare @ColumnName nvarchar(max) = '', @castColumnName nvarchar(max) = ''
declare @TableName nvarchar(255)  = concat('tbl_productmaster_', @ParentId)

select @ColumnName  = STRING_AGG(QUOTENAME(COLUMN_NAME), ','),
		@castColumnName = STRING_AGG( concat(' cast(', case when data_type  <> 'nvarchar'
		then  QUOTENAME(COLUMN_NAME) else QUOTENAME(COLUMN_NAME) end, ' as nvarchar) as ', QUOTENAME(COLUMN_NAME)) , ',') 

from INFORMATION_SCHEMA.COLUMNS 
	where TABLE_NAME = @TableName

drop table if exists #tempProduct
create table #tempProduct ( FieldName nvarchar(max), FieldValue nvarchar(max) )

declare @sqlProduct nvarchar(max) = concat( N'insert into #tempProduct (FieldName, FieldValue) select FieldName, FieldValue from ( SELECT ',
		@castColumnName,  N'FROM tbl_productmaster_', @ParentId, ' (nolock) where ProductID = ', @ProductId, 
		' ) as product UNPIVOT ( FieldValue FOR FieldName IN ( ', @ColumnName, ') ) as unvot ')

print @sqlProduct
execute sp_executesql @sqlProduct

select  @StrToReplace = replace(@StrToReplace, concat('#', FieldName, '#'), trim(FieldValue))  from #tempProduct
select @StrToReplace


 end  




GO

/* ============================================================
   Procedure: [dbo].[usp_ims_GetRowDataForEdit]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE usp_ims_GetRowDataForEdit(
	@UserId bigint,
	@PropertyName nvarchar(255),
	@EntityId bigint,
	@EntityName nvarchar(255)
)
as
begin
	declare @CountryName nvarchar(255), @CountryId bigint, @StateName nvarchar(255), @StateId bigint

	if(lower(@EntityName) = 'lead')
	begin
		select @CountryName = Country, @StateName = State from UserLeads(nolock) where ID = @EntityId 
			
	end
		
	if(lower(@EntityName) = 'enquiry')
	begin
		select @CountryName = Country, @StateName = State from UserEnquiry(nolock) where EnquiryID = @EntityId
	end

	if(@PropertyName = 'State')
	begin
		select @CountryId = Country_ID from m_country1(nolock) where Country_Name = @CountryName
		select State_ID as [Code], State_Name as [Text] from m_state1(nolock) where Country_ID = @CountryId
	end

	if(@PropertyName = 'City')
	begin
		select @CountryId = Country_ID from m_country1(nolock) where Country_Name = @CountryName
		select @StateId = State_ID from m_state1(nolock) where Country_ID = @CountryId and State_Name = @StateName
		select City_ID as [Code], City_Name as [Text] from m_city1(nolock) where State_ID = @StateId
	end
end



GO

/* ============================================================
   Procedure: [dbo].[usp_ims_GetRuleDetailByRuleId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-------------------------------------------------------------------------

CREATE   PROCEDURE [dbo].[usp_ims_GetRuleDetailByRuleId]--40031---------------------------------------existing
(
    @RuleId BIGINT
)
AS
BEGIN
    SET NOCOUNT ON;

    -- Rule main details
    SELECT 
        lar.id,
        lar.rule_name,
        lar.selected_users,
        lar.rule_priority,
        lar.logical_operator,
        lar.is_active,
        lar.assignment_expression,
        lar.lam_id,
        lar.lastAssignedUser,
        lar.SettingJSON,
        lar.RuleType,
        lar.ColloborationType,
        lar.CollaborationTeam
    FROM tbl_LeadAssignmentRules (NOLOCK) lar
    WHERE lar.id = @RuleId;

    -- Collaborators for this rule (teams or individuals)
    SELECT 
        lac.TypeId,
        lac.AssignType,
        lac.CollaboratorId,
        ctm.type_name AS CollaboratorTypeName,
        CASE 
            WHEN lac.AssignType = 'team' THEN ct.team_name
            ELSE NULL
        END AS CollaboratorTeamName,
        CASE 
            WHEN lac.AssignType = 'individual' THEN ud.User_Login + ' ' + ud.fname + ' ' + ud.lname
            ELSE NULL
        END AS CollaboratorUserName
    FROM LeadAssignmentCollaborators (NOLOCK) lac
    LEFT JOIN Tbl_coll_CollaboratorTypeMaster ctm WITH(NOLOCK)
        ON lac.TypeId = ctm.id AND ctm.isactive = 1
    LEFT JOIN tbl_coll_CollaboratorTeams ct WITH(NOLOCK)
        ON lac.AssignType = 'team' 
       AND lac.CollaboratorId = ct.id 
       AND ct.isactive = 1
    LEFT JOIN user_detail ud WITH(NOLOCK)
        ON lac.AssignType = 'individual'
       AND lac.CollaboratorId = ud.user_id   -- adjust column name if needed
    WHERE lac.RuleId = @RuleId;
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_ims_GetSetChannelProfileSubscription]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


--Dependency of this usp_ims_GetSetChannelProfileSubscription

--1.MySMSConversations.dbo.channeltokens  -- called by clr
-- 2.MySMSConversations.dbo.convusers(nolock)      -- called by clr
--3. MySMSConversations.dbo.tbl_channelsubscription   -- called by clr



-------------------------------------

CREATE   PROCEDURE [dbo].[usp_ims_GetSetChannelProfileSubscription](  
 @ChannelProfileId nvarchar(255),  
 @UserId bigint,  
 @Unsubscribed bit = 0,  
 @Mode nvarchar(5) = 'get'  
)  
as  
begin  
 --declare   
 -- @ChannelProfileId nvarchar(255) = '919821592374',  
 -- @UserId bigint = 34594,  
 -- @Unsubscribed bit = 0,  
 -- @Mode nvarchar(5) = 'get'  
  DECLARE @sqlquery NVARCHAR(MAX);
 declare  
  @ParentId bigint = 0, @ChannelId bigint = 2, @ChannelTokenId bigint = 0, @ConvUserId bigint = 0  
  
 select @ParentId = ParentID from MySMS.dbo.User_Detail(nolock) where User_ID = @UserId  
  
 if(@Mode = 'set')  
 begin  
   
  --select top 1 @ChannelTokenId = id from MySMSConversations.dbo.channeltokens(nolock)   
  -- where parentid = @ParentId and channelid = @ChannelId and isactive  = 1 
  SET @sqlquery = '
SELECT TOP 1 id 
FROM channeltokens WITH (NOLOCK)
WHERE parentid = ' + CAST(@ParentId AS NVARCHAR) + '
  AND channelid = ' + CAST(@ChannelId AS NVARCHAR) + '
  AND isactive = 1';

-- Execute the query remotely and store result in @ChannelTokenId
EXEC usp_clr_GetRemoteLongValue @sqlquery, @retval = @ChannelTokenId OUT;
   
  --select top 1 @ConvUserId = id from MySMSConversations.dbo.convusers(nolock)   
  -- where convuserparentid = @ParentId and channelprofileid = @ChannelProfileId and isactive = 1 order by id desc  
 SET @sqlquery = '
SELECT TOP 1 id 
FROM convusers WITH (NOLOCK)
WHERE convuserparentid = ' + CAST(@ParentId AS NVARCHAR) + '
  AND channelprofileid = ''' + @ChannelProfileId + '''
  AND isactive = 1
ORDER BY id DESC';

-- Execute the remote SQL and store the result in @ConvUserId
EXEC usp_clr_GetRemoteLongValue @sqlquery, @retval = @ConvUserId OUT;


  --insert into MySMSConversations.dbo.tbl_channelsubscription(channelprofileid, channelid, parentid,    
  -- channeltokenid, unsubscribed, createdon, convuserid, ws_createdby)  
  --select @ChannelProfileId, 2, @ParentId, @ChannelTokenId, @Unsubscribed, GETDATE(), @ConvUserId, @UserId  
  SET @sqlquery = '
INSERT INTO tbl_channelsubscription
    (channelprofileid, channelid, parentid, channeltokenid, unsubscribed, createdon, convuserid, ws_createdby)
VALUES
    (''' + @ChannelProfileId + ''', 2, ' + CAST(@ParentId AS NVARCHAR) + ', ' + CAST(@ChannelTokenId AS NVARCHAR) + ', '
    + CAST(@Unsubscribed AS NVARCHAR) + ', GETDATE(), ' + CAST(@ConvUserId AS NVARCHAR) + ', ' + CAST(@UserId AS NVARCHAR) + ')';

-- Execute the remote query
EXEC usp_clr_ExecuteRemoteQuery @sqlquery;
  
 end  
  
 /*select top 1 id as ID, channelprofileid as ChannelProfileID, channelid as ChannelID, parentid as ParentID, channeltokenid as ChannelTokenID, unsubscribed as Unsubscribed, createdon as CreatedOn, convuserid as ConvUserID, ws_createdby as WsCreatedBy   
 from MySMSConversations.dbo.tbl_channelsubscription(nolock)  where parentid = @ParentId and channelprofileid = @ChannelProfileId order by id desc */ 
 SET @sqlquery = '
SELECT TOP 1 
    id AS ID, 
    channelprofileid AS ChannelProfileID, 
    channelid AS ChannelID, 
    parentid AS ParentID, 
    channeltokenid AS ChannelTokenID, 
    unsubscribed AS Unsubscribed, 
    createdon AS CreatedOn, 
    convuserid AS ConvUserID, 
    ws_createdby AS WsCreatedBy
FROM tbl_channelsubscription WITH (NOLOCK)
WHERE parentid = ' + CAST(@ParentId AS NVARCHAR) + ' AND channelprofileid = ' + CAST(@ChannelProfileId AS NVARCHAR) + '
ORDER BY id DESC'

EXEC usp_clr_GetRemoteData @sqlquery;

  
end 



GO

