 Parentid as [ParentId], country_iso CountryISO  
 from mysms.dbo.User_Detail(nolock)ud       
  left join #temp cu on ud.User_ID = cu.entityid and cu.Entity = 'team'      
  where ud.User_ID= @ContactId and cu.isactive = 1 

end   



