/* ============================================================
   Procedure: [dbo].[usp_ims_GetUnprocessedWaAutomationEntry]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


--Dependency of this usp_ims_GetUnprocessedWaAutomationEntry

--1.MySMSConversations.dbo.convusers (NOLOCK) -- called by clr



-------------------------------------


CREATE   PROCEDURE [dbo].[usp_ims_GetUnprocessedWaAutomationEntry](
	@ServiceIndexId bigint = -1      
)      
as      
begin      
       
	--declare @ServiceIndexId bigint = -1      
       
	drop table if exists #tempWaAction      
    
	select top 100 ms.id, ms.batchid, ms.sequenceid, ms.SequenceActionId, lower(ms.actiontype) actiontype,     
		ms.actiondetails, parentid, 0 as convuserid, scheduledfor, ms.entity, ms.entityid    
		into  #tempWaAction 
	from tbl_mass_mktgsequence(nolock) ms
	where isnull(isprocessed, 0) = 0       
	--and ( scheduledfor < GETDATE()       
	-- or (GETDATE() between DATEADD(MINUTE, - 30, scheduledfor)       
	-- and scheduledfor))      
	and isnull(ms.scheduledfor, ms.createdon) < GETDATE()       
	and 1 = ( case when  @ServiceIndexId = -1 then 1      
	when @ServiceIndexId <> -1 and  (ms.id % 4) = @ServiceIndexId      
	then 1 else 0 end )      
	order by scheduledfor asc
	  
	--update w set       
	--	isprocessed = 2,      
	--	processedat = getdate()      
	--	from  #tempWaAction tw       
	--inner join tbl_mass_mktgsequence(nolock) w on tw.id = w.id      
      
	drop table if exists #parentIds 
	create table #parentIds (ParentId bigint)

	insert into #parentIds(ParentId) select parentid from #tempWaAction
	
	/*;WITH FilteredData AS (
   
   SELECT id, channelprofileid, Entity, Entityid, convuserparentid,
        ROW_NUMBER() OVER (PARTITION BY Entity, Entityid, convuserparentid ORDER BY id DESC) AS rno
    FROM MySMSConversations.dbo.convusers (NOLOCK) WHERE  isactive = 1 and convuserparentid in (select ParentId from #parentIds) )
	
	select ms.id, ms.batchid, ms.sequenceid, ms.SequenceActionId, ms.actiontype, ms.actiondetails, 
		ms.parentid, isnull(cu.id, 0) as convuserid, ms.scheduledfor, ms.entity, ms.entityid
	from #tempWaAction ms left join FilteredData cu  on ms.parentid = cu.convuserparentid 
		and ms.entity = cu.Entity and ms.entityid = cu.Entityid and isnull(ms.entityid, 0) > 0 and cu.rno = 1*/

DECLARE @query NVARCHAR(MAX);

  DROP TABLE IF EXISTS #temp;
    CREATE TABLE #temp (channelprofileid nvarchar(500), convuserparentid BIGINT, ChannelId int, isactive bit, entityid bigint, Entity nvarchar(200), id bigint );


SET @query = '
        SELECT channelprofileid, convuserparentid,ChannelId, isactive, entityid,Entity,id
        FROM convusers (NOLOCK) WHERE isactive = 1 AND convuserparentid IN (SELECT ParentId FROM #parentIds) ';

    -- Execute the query using your CLR procedure
        INSERT INTO #temp(channelprofileid, convuserparentid,ChannelId, isactive, entityid,Entity,id )
	    EXEC usp_clr_FillRemoteData @query;

    ;WITH FilteredData AS (
   
   SELECT id, channelprofileid, Entity, Entityid, convuserparentid,
    --    ROW_NUMBER() OVER (PARTITION BY Entity, Entityid, convuserparentid ORDER BY id DESC) AS rno
    --FROM MySMSConversations.dbo.convusers (NOLOCK) WHERE  isactive = 1 and convuserparentid in (select ParentId from #parentIds) )
	ROW_NUMBER() OVER (
               PARTITION BY Entity, EntityId, convuserparentid
               ORDER BY id DESC
           ) AS rno
    FROM #temp)

	select ms.id, ms.batchid, ms.sequenceid, ms.SequenceActionId, ms.actiontype, ms.actiondetails, 
		ms.parentid, isnull(cu.id, 0) as convuserid, ms.scheduledfor, ms.entity, ms.entityid
	from #tempWaAction ms left join FilteredData cu  on ms.parentid = cu.convuserparentid 
		and ms.entity = cu.Entity and ms.entityid = cu.Entityid and isnull(ms.entityid, 0) > 0 and cu.rno = 1


  
end   



GO

