/* ============================================================
   Procedure: [dbo].[usp_ims_GoogleSheetWebhookProcessor]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ims_GoogleSheetWebhookProcessor]
(
	@gsWebhookId bigint
)
as
begin

	--declare @gsWebhookId bigint = 21

	declare @WorkbookId nvarchar(255), @SheetName nvarchar(255), @ParentId bigint, @RequestJSON nvarchar(max)
	select 
		@WorkbookId = WorkbookId,
		@SheetName = SheetName,
		@ParentId = ParentId,
		@RequestJSON = RequestJSON
	from tbl_ge_GoogleSheetWebhooks(nolock) where id = @gsWebhookId

	print concat('Webhook data ',  @WorkbookId, ' ', @SheetName, ' ', @ParentId, ' ', @RequestJSON )

	if(isnull(@SheetName, '') <> '' and isnull(@WorkbookId, '') <>'')
	begin
		
		drop table if exists #tblRuleList
		create table #tblRuleList (
			Id bigint,
			RuleJSON nvarchar(max),
			isProcess int default 0
		)

		insert into #tblRuleList( Id, RuleJSON, isProcess)
		select Id, RuleJSON, 0 from tbl_ge_SheetRules(nolock) where GSMAutoId in(
			select id from tbl_ge_GoogleSpreadSheetMapping(nolock) where ParentId = @ParentId 
				and WorkbookId= @WorkbookId and SheetName = @SheetName and IsActive = 1
		)

		while(exists(select 1 from #tblRuleList(nolock) where isProcess = 0))
		begin
			
			declare @RuleJSON nvarchar(max), @RuleId bigint, @RequestData nvarchar(max), @RequestMeta nvarchar(max)
			select @RuleId = Id, @RuleJSON = RuleJSON from #tblRuleList

			--select @RuleId, @RuleJSON
			select 
				@RequestData = rData,
				@RequestMeta = rMeta
			from openjson(@RequestJSON) with(
				rData nvarchar(max) '$.data' as json,
				rMeta nvarchar(max) '$.meta' as json
			)

			drop table if exists #tempFormData

			select dbo.udf_DecimalToBase26(d.columnNumber) as colName, * into #tempFormData from ( 
				select ROW_NUMBER() over (partition by (select null) order by (select null) asc  ) as columnNumber, 
				* from openjson(@RequestData)) d

			--select * from openjson(@RequestMeta) with (
			--	columnEnd int '$.range.columnEnd',
			--	columnStart int '$.range.columnStart',
			--	rowStart int '$.range.rowStart',
			--	rowEnd int '$.range.rowEnd'
			--)

			declare 
				@TriggerConditionJSON nvarchar(max), 
				@FilterConditionJSON nvarchar(max), 
				@ActionOptionJSON nvarchar(max)

			select 
				@TriggerConditionJSON = TriggerCondition,
				@FilterConditionJSON = FilterCondition,
				@ActionOptionJSON = ActionOption
			from openjson(@RuleJSON) with(
				TriggerCondition nvarchar(max) '$.TriggerCondition' as json,
				FilterCondition nvarchar(max) '$.FilterCondition' as json,
				ActionOption nvarchar(max) '$.ActionOption' as json )

			drop table if exists #ruleCondition

			select * into #ruleCondition from openjson(@FilterConditionJSON) with (
				ColumnName nvarchar(255) '$.ColumnName',
				OperatorName nvarchar(255) '$.OperatorName',
				ConditionType nvarchar(255) '$.ConditionType',
				ColoumnCondition nvarchar(255) '$.ColoumnCondition',
				ColumnValue nvarchar(255) '$.ColumnValue',
				LogicalOperator nvarchar(255) '$.LogicalOperator'
			)
		
			--select *,
			--	row_number() over(partition by (select null) order by (select null)) as rn,
			--	Lag(LogicalOperator, 1) OVER( ORDER BY (select null) ASC) AS LagLogicalOperator
			--from #ruleCondition

			declare @conditionSql nvarchar(max) = ''
			select @conditionSql = 
				concat( 
					isnull([c].[LagLogicalOperator], ''), ' ',
					@conditionSql, ' ',
					concat( ' [Key]  = ''', trim([f].[Key]), '''' ), ' and ',
					( case 
						when c.OperatorName = 'contain' 
							then concat( ' [value] like ''%', trim([f].[Value]), '%'' ')
						end
					)
				)
			from ( select *,
				row_number() over(partition by (select null) order by (select null)) as rn,
				Lag(LogicalOperator, 1) OVER( ORDER BY (select null) ASC) AS LagLogicalOperator
			from #ruleCondition ) c 
				inner join #tempFormData(nolock) f on c.ColumnName = f.colName

			declare @outIsExists int = 0,		
				@paramDefination nvarchar(500) = '@inIsExists int OUTPUT'

			declare @sqlIsExists nvarchar(max) = concat('if(exists(select * from #tempFormData where ', trim(@conditionSql),
						N' )) begin set @inIsExists = 1 end')
		
			execute sp_executesql @sqlIsExists, @paramDefination, @inIsExists = @outIsExists out

			if(@outIsExists = 1)
			begin
				print 'Rule Certified'

				declare @EventId bigint = ( select EventId from openjson(@ActionOptionJSON) 
					with ( EventId  bigint '$.EventDetail.id'))

				declare @ReplaceEventTemplate nvarchar(max), @EntityName nvarchar(50), @EventTemplate nvarchar(max), @EntityId bigint = 0, @EventName nvarchar(255)


				select @EventName = EventName, 
					@EventTemplate = EventTemplate, @EntityName = context from ActivityMaster(nolock) where ID = @EventId

				if(@EntityName = 'lead')
				begin
					select top 1 @EntityId = ulme_id from Userleads_Mobile_Email(nolock) where Parentid = @ParentId 
						and 1 = ( case when 
									exists( select * from #tempFormData(nolock) where lower(trim([key])) = 'MobileNo')
									and Mobile = (select [value] from #tempFormData(nolock) where lower([Key]) = 'MobileNo') 
												then 1
								when exists(select * from #tempFormData(nolock) where lower(trim([key])) = 'emailid')
									and email = (select [value] from #tempFormData(nolock) where lower(trim([Key])) = 'emailid') 
												then 1
							else 0 end) order by ulme_id desc
				end

				if(@EntityName = 'enquiry')
				begin
					select top 1 @EntityId = enquiryid from Userenquiry_Mobile_Email(nolock) where Parentid = @ParentId 
						and 1 = (case when 
									exists( select * from #tempFormData(nolock) where lower(trim([key])) = 'MobileNo')
									and Mobile = (select [value] from #tempFormData(nolock) where lower([Key]) = 'MobileNo') 
												then 1
								when exists(select * from #tempFormData(nolock) where lower(trim([key])) = 'emailid')
									and email = (select [value] from #tempFormData(nolock) where lower(trim([Key])) = 'emailid') 
												then 1 end
						) order by enquiryid desc
				end

				if(@EntityId > 0)
				begin	
					exec usp_replaceentityplaceholders 
						@EntityId, @EntityName, @EventTemplate , @ReplaceEventTemplate OUTPUT     

					select @ReplaceEventTemplate = REPLACE(@ReplaceEventTemplate, concat('#', @EventName, '.', [key], '#'), [value]) 
						from openjson( @RequestJSON
					) where [key] not in ('EventIdentifier', 'EntityIdentifier', 'MobileNo', 'EmailId', 'EntityNo')

					print @ReplaceEventTemplate
			
					exec UspSaveEntityActivity_withid 
						@EntityName,  
						@EntityID,  
						@ParentId,  
						@ParentId,  
						@ReplaceEventTemplate,                   
						@EventName,  
						'tbl_ge_GoogleSheetWebhooks',  
						@gsWebhookId

				end
					
				update #tblRuleList set isProcess = 1
			end
			else
			begin
				update #tblRuleList set isProcess = 1 where Id = @RuleId
			end
		end
	end
end



GO

/* ============================================================
   Procedure: [dbo].[usp_ims_InsertConversationContact]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ims_InsertConversationContact]
( 
	@ChannelName nvarchar(50),
	@PersonName nvarchar(255)= '',
	@ChannelProfileId nvarchar(500),
	@IntialRemarks nvarchar(max),
	@MoblieNo nvarchar(50),
	@CountryCode nvarchar(10),
	@EmailId nvarchar(255),
	@ParentId bigint
)
AS
BEGIN
	DECLARE @ChannelId bigint= (
		SELECT id
		FROM channels(NOLOCK)
		WHERE Channelname = @ChannelName
	), @entity nvarchar(50), @entityid bigint;

	IF ISNULL(@PersonName, '') = ''
	BEGIN
		SET @PersonName = @ChannelProfileId;
	END;

	IF NOT EXISTS
	(
		SELECT 1 FROM convusers(NOLOCK) WHERE channelprofileid = @channelprofileid AND  convuserparentid = @parentid AND channelid = @channelid  and isactive = 1
	)
	BEGIN
		IF @channelid = 2
		BEGIN
			IF EXISTS(select 1 from MySMS.dbo.User_Detail(nolock)  
				WHERE(  RIGHT(@channelprofileid, LEN(mobile)) = mobile AND 
					   ISNULL(mobile, '') <> '' AND 
					   LEN(ISNULL(mobile, 0)) > 5 OR 
					   RIGHT(@channelprofileid, LEN(wa_mobile_no)) = wa_mobile_no AND 
					   ISNULL(wa_mobile_no, '') <> '' AND 
					   LEN(ISNULL(wa_mobile_no, 0)) > 5 
					 ) AND 
					 ParentID = @ParentId AND 
					 User_ID NOT IN
				(
					SELECT entityid
					FROM convusers(NOLOCK)
					WHERE channelid = @channelid AND 
						  entity = 'team' AND 
						  convuserparentid = @parentid
				)
			
			)
			BEGIN
				print 'user section'
				SELECT TOP 1 @entity = 'team', @entityid = User_ID
				from MySMS.dbo.User_Detail(nolock)  
				WHERE(  RIGHT(@channelprofileid, LEN(mobile)) = mobile AND 
					   ISNULL(mobile, '') <> '' AND 
					   LEN(ISNULL(mobile, 0)) > 5 OR 
					   RIGHT(@channelprofileid, LEN(wa_mobile_no)) = wa_mobile_no AND 
					   ISNULL(wa_mobile_no, '') <> '' AND 
					   LEN(ISNULL(wa_mobile_no, 0)) > 5 
					 ) AND 
					 ParentID = @ParentId AND 
					 User_ID NOT IN
				(
					SELECT entityid
					FROM convusers(NOLOCK)
					WHERE channelid = @channelid AND 
						  entity = 'team' AND 
						  convuserparentid = @parentid
				)
				ORDER BY id DESC;
			END
			ELSE IF EXISTS
			(
				SELECT 1
				FROM MySMS.dbo.userleads(NOLOCK)
				WHERE( RIGHT(@channelprofileid, LEN(mobileno)) = mobileno AND 
					   ISNULL(mobileno, '') <> '' AND 
					   LEN(ISNULL(mobileno, 0)) > 5 OR 
					   RIGHT(@channelprofileid, LEN(mobileno2)) = mobileno2 AND 
					   ISNULL(mobileno2, '') <> '' AND 
					   LEN(ISNULL(mobileno2, 0)) > 5 OR 
					   RIGHT(@channelprofileid, LEN(mobileno1)) = mobileno1 AND 
					   ISNULL(mobileno1, '') <> '' AND 
					   LEN(ISNULL(mobileno1, 0)) > 5
					 ) AND 
					 ParentID = @ParentId AND 
					 id NOT IN
				(
					SELECT entityid
					FROM convusers(NOLOCK)
					WHERE channelid = @channelid AND 
						  entity = 'lead' AND 
						  convuserparentid = @parentid
				)
			)
			BEGIN
				PRINT 'userleads';
				SELECT TOP 1 @entity = 'lead', @entityid = id
				FROM MySMS.dbo.userleads(NOLOCK)
				WHERE( RIGHT(@channelprofileid, LEN(mobileno)) = mobileno AND 
					   ISNULL(mobileno, '') <> '' AND 
					   LEN(ISNULL(mobileno, 0)) > 5 OR 
					   RIGHT(@channelprofileid, LEN(mobileno2)) = mobileno2 AND 
					   ISNULL(mobileno2, '') <> '' AND 
					   LEN(ISNULL(mobileno2, 0)) > 5 OR 
					   RIGHT(@channelprofileid, LEN(mobileno1)) = mobileno1 AND 
					   ISNULL(mobileno1, '') <> '' AND 
					   LEN(ISNULL(mobileno1, 0)) > 5
					 ) AND 
					 ParentID = @ParentId AND 
					 id NOT IN
				(
					SELECT entityid
					FROM convusers(NOLOCK)
					WHERE channelid = @channelid AND 
						  entity = 'lead' AND 
						  convuserparentid = @parentid
				)
				ORDER BY id DESC;
			END;
			ELSE
			BEGIN
				IF EXISTS
				(
					SELECT 1
					FROM MySMS.dbo.userenquiry(NOLOCK)
					WHERE( RIGHT(@channelprofileid, LEN(mobileno)) = mobileno AND 
						   ISNULL(MobileNo, '') <> '' AND 
						   LEN(ISNULL(mobileno, 0)) > 5 OR 
						   RIGHT(@channelprofileid, LEN(mobileno2)) = mobileno2 AND 
						   ISNULL(mobileno2, '') <> '' AND 
						   LEN(ISNULL(mobileno2, 0)) > 5 OR 
						   RIGHT(@channelprofileid, LEN(mobileno1)) = mobileno1 AND 
						   ISNULL(mobileno1, '') <> '' AND 
						   LEN(ISNULL(mobileno1, 0)) > 5
						 ) AND 
						 ParentID = @ParentId AND 
						 enquiryid NOT IN
					(
						SELECT entityid
						FROM convusers(NOLOCK)
						WHERE channelid = @channelid AND 
							  entity = 'enquiry' AND 
							  convuserparentid = @parentid
					)
				)
				BEGIN
					SELECT TOP 1 @entity = 'enquiry', @entityid = enquiryid
					FROM MySMS.dbo.userenquiry(NOLOCK)
					WHERE( RIGHT(@channelprofileid, LEN(mobileno)) = mobileno AND 
						   ISNULL(MobileNo, '') <> '' AND 
						   LEN(ISNULL(mobileno, 0)) > 5 OR 
						   RIGHT(@channelprofileid, LEN(mobileno2)) = mobileno2 AND 
						   ISNULL(mobileno2, '') <> '' AND 
						   LEN(ISNULL(mobileno2, 0)) > 5 OR 
						   RIGHT(@channelprofileid, LEN(mobileno1)) = mobileno1 AND 
						   ISNULL(mobileno1, '') <> '' AND 
						   LEN(ISNULL(mobileno1, 0)) > 5
						 ) AND 
						 ParentID = @ParentId AND 
						 enquiryid NOT IN
					(
						SELECT entityid
						FROM convusers(NOLOCK)
						WHERE channelid = @channelid AND 
							  entity = 'enquiry' AND 
							  convuserparentid = @parentid
					)
					ORDER BY enquiryid DESC;
				END;
			END;
		END;
	END;
	ELSE
	BEGIN
		SELECT @entity = Entity, @entityid = Entityid
		FROM convusers(NOLOCK)
		WHERE channelprofileid = @channelprofileid AND 
			  convuserparentid = @parentid AND 
			  channelid = @channelid and isactive = 1;
	END;
	IF @entityid IS NULL
	BEGIN
		IF NOT EXISTS
		(
			SELECT 1
			FROM MySMS.dbo.conversationcontacts(NOLOCK)
			WHERE channelid = @ChannelId AND 
				  channelProfileId = @ChannelProfileId AND 
				  parentid = @ParentId
		)
		BEGIN
			IF ISNULL(@ChannelProfileId, '') <> ''
			BEGIN
				DECLARE @SourceId bigint;
				SELECT @SourceId = SourceID
				FROM MySMS.dbo.UserSourceSettings(NOLOCK)
				WHERE UserID = @ParentId AND 
					  Name = 'Chat';
				DECLARE @cc nvarchar(10), @waid nvarchar(20)= @ChannelProfileId, @c nvarchar(50), @no nvarchar(20);
				SELECT @cc = countrycode, @c = Country_Name
				FROM MySMS.dbo.m_country1
				WHERE SUBSTRING(@waid, 1, LEN(replace(countrycode, '+', ''))) = replace(countrycode, '+', '');
				SELECT @no = RIGHT(@waid, LEN(@waid) - LEN(replace(@cc, '+', '')));
				DECLARE @LeadNo bigint=
				(
					SELECT IIF(COUNT(1) > 0, MAX(LeadNo) + 1, 1)
					FROM MySMS.dbo.UserLeads(NOLOCK)
					WHERE ParentID = @ParentId
				);            
				--print @LeadNo            
				--select @cc,@c,@no    
				
				declare @AgentId bigint = cast(ISNULL(
				(
					SELECT TOP 1 value
					FROM fn_Split(
					(
						SELECT agents
						FROM MySMS.dbo.CRMCampaignSettings(nolock)
						WHERE userid = @parentid
					), '#' )
					ORDER BY NEWID()
				), @parentid) as bigint)


				Declare @CurrentDatetime datetime = getdate(); 

				INSERT INTO MySMS.dbo.UserLeads( PersonName, CountryCode, MobileNo, Country, CreatedBy, CreatedOn, AssignedTo, ParentID, SourceName, LeadNo, enquirysource, InitialRemarks,LastFollowupCreatedOn,LastFollowupCreatedBy )
				VALUES( @PersonName, @cc, @no, @c, @ParentId, @CurrentDatetime, @AgentId, @ParentId, @SourceId, @LeadNo, 26, @IntialRemarks,@CurrentDatetime,@ParentId );
				--insert into MySMS.dbo.conversationcontacts ( parentid, personname, emailid, countrycode, mobile, InitialRemarks, createdon, channelid, channelProfileId)                        
				--values ( @ParentId, @PersonName, @EmailId, @CountryCode, @MoblieNo, @IntialRemarks, getdate(), @ChannelId, @ChannelProfileId )                        
				DECLARE @LeadId bigint= SCOPE_IDENTITY();
				--EXEC MySMS.dbo.usp_inserleadinteractionhistory @LeadId;

				exec MySMS.dbo.usp_insertdefaultfollowup @AgentId, @LeadId

				SELECT @LeadId AS EntityId, 'lead' AS EntityName;
			END;
		END;
		ELSE
		BEGIN
			SELECT id AS EntityId, 'conversationcontacts' AS EntityName
			FROM MySMS.dbo.conversationcontacts(NOLOCK)
			WHERE channelid = @ChannelId AND 
				  channelProfileId = @ChannelProfileId;
		END;
	END;
	ELSE
	BEGIN
		SELECT @entityid AS EntityId, @entity AS EntityName;
	END;
END



GO

/* ============================================================
   Procedure: [dbo].[usp_ims_InsertLeadEnqiryTags]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_ims_InsertLeadEnqiryTags(
	@EntityId bigint,
	@EntityName nvarchar(50),
	@Tags nvarchar(max),
	@UserId bigint
)
as
begin

	declare @ParentId bigint = ( select ParentId from User_Detail(nolock) where User_ID = @UserId )
	drop table if exists #tempTagName
	select tn.*, tm.ID as tagId, 0 as isProcess  into #tempTagName from ( select [position] as [id],  LTRIM(RTRIM(
		iif(
			CHARINDEX(':', [value],  1 ) = 0 , 
			[value], 
			SUBSTRING([value], 1, CHARINDEX(':', [value],  1 ) - 1)
		))) as [tagName] 
	from fn_Split(@Tags, ',') ) as tn 
	left join TagMaster(nolock) tm on tm.ParentID = @ParentID and lower(tm.Tag) = lower(tagName)

	while(exists(select * from #tempTagName where isProcess = 0))
	begin
		declare @tId int, @tTagName nvarchar(255), @tagId bigint
		select top 1 @tId = id, @tTagName = tagName, @tagId = tagId from #tempTagName where isProcess = 0

		print @tTagName

		if(@tagId is null)
		begin
			insert into TagMaster(Tag, ParentID, CreatedDate, CreatedBy)
				values ( @tTagName, @ParentID, getdate(), @ParentID )

			declare @sId bigint =  scope_identity()
			update #tempTagName set tagId = @sId where id = @tId
		end
		update #tempTagName set isProcess = 1 where id = @tId
	end

	delete EntityTagMapping where EntityID = @EntityId and lower(Entity) = @EntityName

	insert into EntityTagMapping(EntityID, Entity, TagID, CreatedDate)
		select @EntityId, @EntityName, tagId, getdate() from #tempTagName
end



GO

/* ============================================================
   Procedure: [dbo].[usp_ims_IsAttributeExists]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ims_IsAttributeExists](
	@EntityName nvarchar(255) ,
	@EntityId bigint = 616992, 
	@FieldName  nvarchar(255) , 
	@FieldValue nvarchar(max),
	@OperatorName nvarchar(255),
	@isTrue bit = 0 output
)
as
begin
	
	--declare 
	--	@EntityName nvarchar(255) = 'lead',
	--	@EntityId bigint = 5121237, 
	--	@FieldName  nvarchar(255) = 'lead.passcode', 
	--	@FieldValue nvarchar(max) = 'IML',
	--	@OperatorName nvarchar(255) = 'contain',
	--	@isTrue bit = 0
	
	declare @ParentId bigint = ( case when @EntityName = 'lead' then (select ParentID from UserLeads(nolock) where ID = @EntityId)
		when @EntityName = 'enquiry' then (select ParentID from UserEnquiry(nolock) where EnquiryID = @EntityId) else 0 end)

	drop table if exists #tempColName

	if(@ParentId is not null  and @ParentId > 0)
	begin
		SELECT ROW_NUMBER() OVER(ORDER BY [colName] ASC) AS [SRNo], *, 0 AS [isProcess] INTO [#tempColName] FROM  (  
			SELECT concat('#', LOWER([COLUMN_NAME]), '#') AS [colName], 'predefined' AS [columnType], 0 AS [FieldId], UPPER(CASE [column_name] WHEN 'CampaignName' THEN 'VARCHAR' WHEN 'MediumName' THEN 'VARCHAR' WHEN 'SourceName' THEN 'VARCHAR' WHEN 'FollowupStatus' THEN 'VARCHAR' ELSE [DATA_TYPE] END) AS [DATA_TYPE]        
			FROM     INFORMATION_SCHEMA.COLUMNS(NOLOCK) AS colName        
			WHERE   [TABLE_NAME] = 'UserLeads' and [COLUMN_NAME] not in ('Id')       
			UNION        
		SELECT CONCAT('#', [fieldname], '#') AS [colName], 'custom' AS [columnType], [field_ID] AS [FieldId], LOWER(( CASE [datatype] WHEN 'd' THEN 'DateTime' WHEN 'f' THEN 'Numeric' WHEN 'v' THEN 'VARCHAR' WHEN 'm' THEN 'VARCHAR' WHEN 'e' THEN 'VARCHAR' WHEN 'r' THEN 'VARCHAR'    
		  WHEN 'c' THEN 'VARCHAR' WHEN 's' THEN 'VARCHAR' END )) AS [DATA_TYPE]      
		FROM   customfields(NOLOCK)  WHERE  [ParentID] = @ParentId and isActive = 1 ) AS col;   

		
		select @FieldName = replace(
			replace(@FieldName COLLATE SQL_Latin1_General_CP1_CS_AS, 'lead.', '') 
				COLLATE SQL_Latin1_General_CP1_CS_AS, 'enquiry.', '')

		if(exists(select * from #tempColName where replace(colName, '#', '') =   @FieldName))
		begin
			print  'column exists exists'
			declare @colName nvarchar(255), @columnType nvarchar(255), @FieldId bigint,  @dataType nvarchar(255), @paramQuery nvarchar(MAX)
			select 
				@colName = colName,
				@columnType = columnType,
				@fieldId = fieldId,
				@dataType = DATA_TYPE
			from #tempColName where replace(colName, '#', '') =  @FieldName


			declare @retParamValue SQL_VARIANT, @ParmDefinition NVARCHAR(500);        
			set @ParmDefinition = N'@retValInnerOut sql_variant OUTPUT';        
    
			
		set @paramQuery = case when @columnType = 'predefined'        
			 then concat('select @retValInnerOut = ', TRIM('lead.' from(TRIM('#' FROM @colName))), ' from UserLeads(nolock) where ID = ', @EntityId)        
			when @columnType = 'custom'        
			 then concat('select @retValInnerOut = fieldvalue from customfieldLeadvalue(nolock) where LeadID = ',       
			 @EntityId, ' and fieldID = ', @fieldId)        
			END;        

		print @paramQuery 


		execute sp_executesql @paramQuery, @ParmDefinition, @retValInnerOut = @retParamValue OUTPUT;        
        
		SET @retParamValue = (CASE WHEN @colName = '#assignedto#'        
		THEN(SELECT [User_Login] FROM User_Detail(NOLOCK) WHERE User_Id = CAST(@retParamValue AS BIGINT))        
		  WHEN @colName = '#sourcename#'        
		THEN(SELECT [Name] FROM UserSourceSettings(NOLOCK) WHERE [SourceID] = CAST(@retParamValue AS BIGINT))        
		  WHEN @colName = '#mediumname#'        
		THEN(SELECT [Name] FROM UserMediumSettings(NOLOCK) WHERE [MediumID] = CAST(@retParamValue AS BIGINT))        
	  WHEN @colName = '#campaignname#'        
		THEN(SELECT [Name] FROM UserCampaignSettings(NOLOCK) WHERE [CampaignID] = CAST(@retParamValue AS        
		BIGINT))        
		  WHEN @colName = '#parentid#'        
		THEN(SELECT [User_Login] FROM User_Detail(NOLOCK) WHERE User_Id = CAST(@retParamValue AS BIGINT))        
		  WHEN @colName = '#followupstatus#'        
		THEN(SELECT [FollowupStatus] FROM FollowUp_Status(NOLOCK) WHERE [ID] = CAST(@retParamValue AS BIGINT))        
		  WHEN @colName = '#createdby#'        
		THEN(SELECT [User_Login] FROM User_Detail(NOLOCK) WHERE User_Id = CAST(@retParamValue AS BIGINT))        
		  WHEN @colName = '#modifiedby#'        
		THEN(SELECT [User_Login] FROM User_Detail(NOLOCK) WHERE User_Id = CAST(@retParamValue AS BIGINT))        
		  WHEN @colName = '#enquirysource#'        
		THEN(SELECT [Sourcename] FROM enquirysources(NOLOCK) WHERE [id] = CAST(@retParamValue AS INT))        
		  WHEN @colName = '#lastfollowupcreatedby#'        
		THEN(SELECT [User_Login] FROM User_Detail(NOLOCK) WHERE User_Id = CAST(@retParamValue AS BIGINT))        
		  ELSE @retParamValue        
		  END );  

		  declare @retValue nvarchar(max) = cast(@retParamValue  as nvarchar)

		  select @isTrue = (case when @OperatorName in ('equals','=') and @retValue = @FieldValue then 1  
					when @OperatorName in('Does not equal', 'not enqua to') and @retValue <> @FieldValue then 1           
					when @OperatorName in ('contains', 'contain' )and @retValue like '%'+@FieldValue+'%' then 1          
					when @OperatorName in ('Does not contain', 'DoesNotContain') and @retValue not like '%'+@FieldValue+'%' then 1          
					when @OperatorName='Starts with' and @retValue like @FieldValue+'%' then 1          
					when @OperatorName='Does not start with' and @retValue not like @FieldValue+'%' then 1          
					when @OperatorName in ('Ends with','EndWith') and @retValue like '%'+@FieldValue then 1          
					when @OperatorName ='Does not end with' and @retValue not like '%'+@FieldValue then 1          
				else 0 end )


		end

	end

	--select @isTrue

end



GO

