	@WaMobileNo nvarchar(20),
	@UserId bigint
)
as
begin
	--declare
	--	@WaCountryCode nvarchar(10) = '+91',
	--	@WaMobileNo nvarchar(20) = '9821592374',
	--	@UserId bigint = 34594
	DECLARE @sqlquery NVARCHAR(MAX);
	declare @ParentId bigint = (select ParentID from User_Detail(nolock) where User_ID = @UserId)
	if(exists(
		select * from User_Detail(nolock) where 
			wa_country_code = @WaCountryCode and
			wa_mobile_no = @WaMobileNo and
			ParentID = @ParentId
	))
	begin
