	SET @sqlquery = '
SELECT token 
FROM channeltokens (NOLOCK) 
WHERE channelid = (
    SELECT id 
    FROM channels (NOLOCK) 
    WHERE LTRIM(RTRIM(LOWER(Channelname))) = LTRIM(RTRIM(LOWER(''' + @ChannelName + ''')))
) 
AND parentid = ' + CAST(@ParentId AS NVARCHAR);

-- Execute the remote query and get token
EXEC usp_clr_GetRemoteData @sqlquery
		/*select token from MySMSConversations.dbo.channeltokens(nolock) where 
			channelid = ( select id from MySMSConversations.dbo.channels(nolock) where Trim(Lower(Channelname))  = Trim(Lower(@ChannelName))) 
			and parentid = @ParentId*/
	end
end



