CREATE   PROCEDURE [dbo].[usp_ims_LeadEnquiryDetails]      
(          
    @leadid bigint,
		@entityType nvarchar(200)

)          
as                                      
begin
--declare @leadid bigint=1702215,
--		@entityType nvarchar(200)='lead'
set nocount on                                    
declare @uid bigint                                    
declare @cnt_start int                                      
declare @cnt_max int                                      
declare @grp_id int                                      
declare @out varchar(max)='' 
if(@entityType='lead')
begin
select @uid=parentid from UserLeads where ID=@leadid;                                     
end
else
begin
select @uid=parentid from UserEnquiry where EnquiryID=@leadid; 
end
set @cnt_start=0;                                          
select distinct Group_Name, Group_ID into #group from Group_Detail where USER_ID=@uid
select @cnt_max=COUNT(Group_Name) from #group                                          
while (@cnt_start < @cnt_max)                                          
begin                                          
select @grp_id=MAX(group_id) from #group;                                          
if(@cnt_start>0)                                          
begin                                          
select @out=@out+', '+group_name from #group where Group_ID=@grp_id;                                          
end                                          
else                                          
begin                                          
select @out=group_name from #group where Group_ID=@grp_id;                                          
end                                          
delete From #group where Group_ID=@grp_id;                                          
set @cnt_start=@cnt_start+1;                                          
end                                          
drop table #group; 
if(@entityType='lead')
begin                                  
SELECT [ul].[leadno],           
       [ul].[personname],           
       [ul].[companyname],           
       ISNULL([ul].[mobileno], '') AS [mobileno],           
       [ul].[emailid],           
       [ul].[city],           
       [ul].[state],           
       [ul].[country],           
       [ul].[pincode],           
       [ul].[residentialaddress],           
       [ud].[user_login] AS [assigned_to],           
       [src].[name] AS [source],           
       ISNULL([md].[name], '') AS [medium],           
       ISNULL([cmp].[Name], '') AS [campaignname],           
       [ul].[remarks] AS [remark],           
       [fs].[followupstatus],           
       CONVERT(VARCHAR(20), [ul].[createdon], 113) AS [createdon],          
       CASE          
           WHEN [ul].[modifiedon] = ''          
           THEN CONVERT(VARCHAR(20), [ul].[createdon], 113)          
           WHEN [ul].[modifiedon] IS NULL          
           THEN CONVERT(VARCHAR(20), [ul].[createdon], 113)          
           ELSE CONVERT(VARCHAR(20), [ul].[modifiedon], 113)          
       END AS [modifiedon],           
       --CONVERT(VARCHAR(20), [ul].[followupdate], 20) AS [followupdate],           
       dbo.fn_getusertimefromindiantime(@uid, [ul].[followupdate]) AS [followupdate],           
       [ud1].[user_login] AS [createdby],           
       [ud2].[user_login] AS [modifiedby],           
       @out AS [groups],           
       ISNULL([ul].[mobileno1], '') AS [mobileno1],           
       ISNULL([ul].[mobileno2], '') AS [mobileno2],           
       ISNULL([ul].[emailid1], '') AS [emailid1],           
       ISNULL([ul].[emailid2], '') AS [emailid2],           
       [ul].[officeaddress],           
       [ul].[countrycode],           
       [ul].[AssignedTo] AS [assign_id],           
       [ul].[SourceName] AS [source_id],           
       [ul].[MediumName] AS [medium_id],           
       [ul].[CampaignName] AS [camp_id],           
       [ul].[FollowUpStatus] AS [follow_status_id],           
       [ul].[Products],           
       [ul].[AmountPaid],           
       ltrim(ISNULL([ul].[countrycode], '') + ' ' + ISNULL([ul].[MobileNo], '')) +         
   CASE WHEN ISNULL([ul].[MobileNo1], '') <> ''          
    THEN ', ' + ltrim(ISNULL([ul].[countrycode1], '') + ' ' + ISNULL([ul].[MobileNo1], ''))            ELSE '' END +           
   CASE WHEN ISNULL([ul].[MobileNo2], '') <> ''          
    THEN ', ' + ltrim(ISNULL([ul].[countrycode2], '') + ' ' + ISNULL([ul].[MobileNo2], ''))          
    ELSE '' END AS [phones],           
       ISNULL([ul].[CountryCode1], '') AS [CountryCode1],           
       ISNULL([ul].[CountryCode2], '') AS [CountryCode2],           
       ISNULL([ul].[EmailID], '') + CASE WHEN ISNULL([ul].[EmailID1], '') <> ''          
                                        THEN ', ' + ISNULL([ul].[EmailID1], '')          
                                        ELSE '' END       
          + CASE WHEN ISNULL([ul].[EmailID2], '') <> ''          
                                        THEN ', ' + ISNULL([ul].[EmailID2], '')          
                                        ELSE '' END AS [emails],           
       ISNULL([ul].[img_ext], '.abc') as [img_ext],        
 CASE WHEN ISNULL([UL].[CountryCode], '') <> '' THEN ISNULL([UL].[Countrycode], '') + ' ' + ISNULL([UL].[MobileNo], '')      
 ELSE '' END           
    +           
    CASE WHEN ISNULL([UL].[Mobileno1], '') <> ''   THEN ', ...'  ELSE '' END as Mobile,        
 CASE WHEN ISNULL([UL].[Emailid], '') <> ''     THEN ISNULL([UL].[Emailid], '')  ELSE '' END           
    +           
    CASE WHEN ISNULL([UL].[EmailID1], '') <> ''    THEN ', ...'     ELSE '' END  AS Email,      
 InitialRemarks=isnull([UL].InitialRemarks,''),    
 [ul].[ProfileImgFileName],  
 [ul].[ParentID] as [ParentId],  
 ( select STRING_AGG(tm.Tag, ',' ) from EntityTagMapping(nolock) etm  
 inner join  TagMaster(nolock) tm on etm.TagID   = tm.ID  
  where etm.Entity = 'lead' and etm.EntityID = ul.ID ) as [Tags],  
 cn.Shortname as CountryISO  
FROM userleads(nolock) ul LEFT JOIN user_detail(nolock) ud ON  ul.assignedto = ud.user_id   
 LEFT JOIN usersourcesettings(nolock) src ON  ul.sourcename = src.sourceid   
 LEFT JOIN usermediumsettings(nolock) md ON  ul.mediumname = md.mediumid   
 LEFT JOIN UserCampaignSettings(nolock) cmp ON  ul.campaignname = cmp.CampaignID   
 LEFT JOIN followup_status(nolock) fs ON  ul.followupstatus = fs.id  
 LEFT JOIN user_detail(nolock) ud1 ON  ul.createdby = ud1.user_id  
 LEFT JOIN user_detail(nolock) ud2 ON  ul.modifiedby = ud2.user_id  
 left join m_country1(nolock) cn on ul.Country = cn.Country_Name  
WHERE [ul].[id] = @leadid;                                     
end  
if(@entityType='enquiry')
begin                                      
SELECT en.EnquiryID as [leadno],             
       en.PersonName,             
       en.CompanyName,             
       ISNULL(en.MobileNo, '') AS mobileno,             
       en.emailid,             
       ISNULL(en.city, '') AS city,             
       ISNULL(en.[state], '') AS [state],             
       ISNULL(en.country, '') AS country,             
       ISNULL(en.pincode, '') AS pincode,             
       ISNULL(en.residentialaddress, '') AS residentialaddress,             
       src.[name] AS [source],             
       ISNULL(md.[name], '') AS medium,             
       ISNULL(cmp.[Name], '') AS campaignname,             
       en.InitialRemarks AS remark,             
       CONVERT(VARCHAR(20), en.CreatedDate, 113) AS createdon,             
       ud.user_login AS createdby,             
       @out AS groups,             
       ISNULL(en.mobileno1, '') AS mobileno1,             
       ISNULL(en.mobileno2, '') AS mobileno2,             
       ISNULL(en.emailid1, '') AS emailid1,             
       ISNULL(en.emailid2, '') AS emailid2,             
       en.officeaddress,             
       en.countrycode,             
       en.SourceName AS source_id,             
       en.MediumName AS medium_id,             
       en.CampaignName AS camp_id,             
       ISNULL(en.LeadNo, '') AS LeadNo,             
       (Case when ISNULL(en.LeadNo, 0) > 0 then 0 else 1 end) as IsOpen,             
       ltrim(ISNULL(en.countrycode, '') + ' ' + ISNULL(en.MobileNo, '')) + CASE  WHEN ISNULL(en.MobileNo1, '') <> ''THEN ', ' + ltrim(ISNULL(en.countrycode1, '') + ' ' + ISNULL(en.MobileNo1, '')) ELSE ''END + CASE  WHEN ISNULL(en.MobileNo2, '') <> ''  THEN ', ' + ltrim(ISNULL(en.countrycode2, '') + ' ' + ISNULL(en.MobileNo2, ''))   ELSE '' END AS phones,             
       ISNULL(en.CountryCode1, '') AS CountryCode1,             
       ISNULL(en.CountryCode2, '') AS CountryCode2,             
       ISNULL(en.EmailID, '') + CASE            
                                    WHEN ISNULL(en.EmailID1, '') <> ''            
                                    THEN ', ' + ISNULL(en.EmailID1, '')            
                                    ELSE ''            
                                END + CASE            
                                   WHEN ISNULL(en.EmailID2, '') <> ''            
                                          THEN ', ' + ISNULL(en.EmailID2, '')            
                                          ELSE ''            
                                      END AS emails,          
  ltrim(en.Countrycode + ' ' + en.Mobileno) + case when isnull(en.Mobileno1,'') <> '' then ', ...' else '' end as Mobile,          
  ltrim(en.EmailId) + case when isnull(en.EmailId1,'') <> '' then ', ...' else '' end as Email,          
  IsConflictWithLead=dbo.ufn_IsEnquiryConflictsLead(en.EnquiryID),        
  IsLeadDeleted=case when isnull(en.LeadNo,0) > 0 then ~dbo.ufn_IsLeadExists(en.LeadNo,en.ParentID) else cast(0 as bit) end ,      
  en.ProfileImgFileName,    
  en.ParentID as [ParentId],    
 ( select STRING_AGG(tm.Tag, ',' ) from EntityTagMapping(nolock) etm    
 inner join  TagMaster(nolock) tm on etm.TagID   = tm.ID    
  where etm.Entity = 'enquiry' and etm.EntityID = en.EnquiryID ) as [Tags],  
   cn.Shortname as CountryISO    
FROM UserEnquiry(nolock) en            
     LEFT JOIN user_detail ud ON en.CreatedBy = ud.user_id            
     LEFT JOIN usersourcesettings src ON en.sourcename = src.sourceid            
     LEFT JOIN usermediumsettings md ON en.mediumname = md.mediumid            
     LEFT JOIN UserCampaignSettings cmp ON en.campaignname = cmp.CampaignID      
  left join m_country1(nolock) cn on en.Country = cn.Country_Name    
WHERE en.EnquiryID = @leadid; 
end
end


GO

/* ============================================================
   Procedure: [dbo].[usp_ims_ReplaceEntityPlaceholders]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ims_ReplaceEntityPlaceholders](
	@entityid bigint,
	@entity nvarchar(50),
	@string nvarchar(max)
)
as
begin      
	
	--declare @entity nvarchar(50)='lead',@entityid bigint=13641211,@string nvarchar(max)=N'"ParamKey":"bioWaste","ParamValue":" #lead.Biomedical_waste_management#"}'
 
	declare @parentid bigint      
	if @entity='lead'      
	select @parentid=parentid from userleads(nolock) where id=@entityid      
	else      
	select @parentid=parentid from userenquiry(nolock) where enquiryid=@entityid      
      
	drop table if exists #epht      
	drop table if exists #entitydata_replace      
	create table #epht(fieldnameexposed nvarchar(200),fieldnameactual nvarchar(200),fieldtype nvarchar(10))      
	insert into #epht(fieldnameexposed,fieldnameactual,fieldtype)      
	exec usp_getentityplaceholders @parentid,@entity      
      
	alter table #epht add fieldvalue nvarchar(max)      
  
	if @entity='enquiry'
	begin
		set @string = replace(@string, '#lead.', '#enquiry.')
		update e set fieldvalue=isnull(isnull(cast(c.fieldvalue as nvarchar(max)),cast(l.fieldvalue as nvarchar(max))),'') from #epht e       
		left join       
		(select fieldname,isnull(cast(fieldvalue as nvarchar(max)),'') fieldvalue from customfields(nolock) f     
		left join customfieldEnquiryvalue c on c.fieldID=f.field_ID and c.EnquiryID=@entityid  where f.parentid=@parentid)     
		c on @entity+'.'+c.fieldname=e.fieldnameactual and e.fieldtype='custom' 
		left join       
		(select 'calculatedfield.'+calculatedfield_name fieldname,isnull(cast(f.field_value as nvarchar(max)),'') fieldvalue from calculated_fields f (nolock)  join calculated_fields_master m (nolock) on f.calculatedfield_id=m.id where isnull(f.parentid,@parentid)=@parentid	and entity=@entity and entityid=@entityid
		)     
		l on @entity+'.'+c.fieldname=e.fieldnameactual and e.fieldtype='calculated' 
	
	end
	if @entity='lead'
	begin
		set @string = replace(@string, '#enquiry.', '#lead.')
		update e set fieldvalue=isnull(isnull(cast(c.fieldvalue as nvarchar(max)),cast(l.fieldvalue as nvarchar(max))),'') from #epht e       
		left join       
		(select fieldname,isnull(cast(fieldvalue as nvarchar(max)),'') fieldvalue from customfields(nolock) f     
		left join customfieldleadvalue c on c.fieldID=f.field_ID and c.LeadID=@entityid  where f.parentid=@parentid)      
		c on @entity+'.'+c.fieldname=e.fieldnameactual and e.fieldtype='custom'  
		left join       
		(select 'calculatedfield.'+calculatedfield_name fieldname,isnull(cast(f.field_value as nvarchar(max)),'') fieldvalue from calculated_fields f (nolock)  join calculated_fields_master m (nolock) on f.calculatedfield_id=m.id where isnull(f.parentid,@parentid)=@parentid	and entity=@entity and entityid=@entityid
		)     
		l on @entity+'.'+l.fieldname=e.fieldnameactual and e.fieldtype='calculated' 
	end
      
	declare @entitydata nvarchar(max)      
	if @entity='lead'      
		set @entitydata=(select * from (select u.*,isnull(str(d.mobile),'') as AssignedToPhone,isnull(d.email,'') as AssignedToEmail, dbo.fn_getentityfullname('user',d.user_id) as AssignedToName
		from Userleads u(nolock) left join user_detail d(nolock) on d.user_id=u.assignedto where u.id=@entityid) a for json auto,INCLUDE_NULL_VALUES)      
	else      
		set @entitydata=(select * from (select u.*,isnull(str(d.mobile),'') as CreatedByPhone,isnull(d.email,'') as CreatedByEmail, dbo.fn_getentityfullname('user',d.user_id) as CreatedByName
		from UserEnquiry u(nolock)  left join user_detail d(nolock) on d.user_id=u.CreatedBy  where enquiryid=@entityid) a for json auto,INCLUDE_NULL_VALUES) 
      
      
      
	create table #entitydata_replace(k nvarchar(200),v nvarchar(max),t nvarchar(20))      
	insert into #entitydata_replace      
	select * from openjson(replace(replace(@entitydata,'[',''),']',''))     
    
	update  #entitydata_replace set v='' where v is null    
      
	update ed set v=case           
	when k in ('createdby','assignedto','LastFollowupcreatedby') then dbo.fn_getuserlogins(v)           
	when k='sourcename' then s.name          
	when k='mediumname' then m.name          
	when k='campaignname' then c.name   
	when k='Followupstatus' then f.FollowupStatus  
	else v end          
	from #entitydata_replace ed           
	left join UserSourceSettings s on ed.v=cast(s.SourceID as nvarchar)          
	left join UsermediumSettings m on ed.v=cast(m.MediumID as nvarchar)          
	left join UserCampaignSettings c on ed.v=cast(c.CampaignID as nvarchar)   
	left join FollowUp_Status f on ed.v=cast(f.id as nvarchar)   
       
       
	update e set fieldvalue=cast(isnull(c.v,'') as nvarchar(max)) from #epht e       
	join #entitydata_replace c on @entity+'.'+c.k=e.fieldnameactual      
    

	declare @isJSON  bit = ISJSON(@string)

	declare @tbl as recursivereplace    
    
	insert into @tbl(displaykey,[value])    
	select fieldnameexposed, case when @isJSON = 1 then replace(fieldvalue, '"', '\"') else fieldvalue end from #epht    
    
 	declare @Strvalue nvarchar(max) = ''
    
	select @Strvalue=dbo.fn_recursivereplace(@tbl, @string) --as Strvalue    
    
	select @Strvalue

	drop table if exists #epht      
	drop table if exists #entitydata_replace      
      
end



GO

/* ============================================================
