/* ============================================================
   Procedure: [dbo].[usp_ims_UnsnoozedConvUsers]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_ims_UnsnoozedConvUsers
as
begin
	drop table if exists #convuserUnsnooze
	 select id, convuserparentid, 0 as is_process into #convuserUnsnooze from convusers(nolock) where
		SnoozedDateTime is not null and
		DATEDIFF(minute, getdate(), SnoozedDateTime) >= 0

		select * from #convuserUnsnooze

	while(exists(select 1 from #convuserUnsnooze where is_process = 0 ))
	begin
		declare @convId bigint, @ParentId bigint
		select top 1 @convId = id, @ParentId = convuserparentid from #convuserUnsnooze where is_process = 0
		exec usp_ims_UpdateSnoozedConvUser @convId, '', @ParentId
		update #convuserUnsnooze set is_process = 1 where id = @convId
	end

end


