/* ============================================================
   Procedure: [dbo].[usp_ims_UpdateFbTokenStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_ims_UpdateFbTokenStatus(
	@FbUserId bigint,
	@IsValid bit  = 0,
	@dtFbPageToken dtFbPageToken readonly
)
as
begin	
	update tbl_fb_FacebookUsers set
		IsAuthorized = @IsValid,
		LastAuthorizedStatus = IsAuthorized,
		TokenLastSynced = getdate()
			where Id = @FbUserId

	update fp set
		fp.LastAuthorizedStatus = fp.IsAuthorized,
		fp.FbPageLongToken = dp.FbPageLongToken,
		fp.IsAuthorized = dp.IsValid,
		fp.AuthErMessage = dp.AuthError,
		fp.TokenLastSynced = getdate()
	from @dtFbPageToken dp
		inner join tbl_fb_FacebookPages(nolock) fp on dp.Id = fp.Id
end



