   Procedure: [dbo].[usp_ims_UpdateOnBoardWhatsappData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE usp_ims_UpdateOnBoardWhatsappData(
	@ParentId bigint,
	@IntegratedBy bigint,
	@WaNumber nvarchar(255),
	@ClientId nvarchar(255),
	@ChannelId nvarchar(255),
	@ApiUrl nvarchar(255),
	@ApiId nvarchar(255),
	@ApiKey nvarchar(255)
)
as
begin
	--declare 
	--	@ParentId bigint,
	--	@IntegratedBy bigint,
	--	@WaNumber nvarchar(255),
	--	@ClientId nvarchar(255),
	--	@ChannelId nvarchar(255),
	--	@ApiUrl nvarchar(255),
	--	@ApiId nvarchar(255),
	--	@ApiKey nvarchar(255)

	declare 
		@EmailId nvarchar(255),
		@MobileNo nvarchar(255)

	select @EmailId = Email, @MobileNo = Mobile from Mysms_Dev.dbo.User_Detail(nolock) where User_ID = @ParentId

	if(exists(select 1 from tbl_ims_OnBoardRequest(nolock) where parentId = @ParentId))
	begin
		update tbl_ims_OnBoardRequest set 
			emailId = isnull(@EmailId, emailId),
			mobileNo = dbo.fnGetNumericValue(isnull(@MobileNo, emailId)),
			clientId = isnull(@ClientId, emailId),
			isSubmited = 1,
			onBoardedBy = @IntegratedBy,
			onBoardedOn = getdate(),
			WaNumber = @WaNumber,
			ChannelId = @ChannelId,
			ApiUrl = @ApiUrl,
			ApiId = @ApiId,
			ApiKey = @ApiKey
				where parentId = @ParentId
	end
	else
	begin
		insert into tbl_ims_OnBoardRequest( emailId, mobileNo, parentId, clientId, createdOn, createdBy, isSubmited,
			onBoardedBy, onBoardedOn, WaNumber, ChannelId, ApiUrl, ApiId, ApiKey )
		values( @EmailId, dbo.fnGetNumericValue(@MobileNo), @ParentId, @ClientId, GETDATE(), @IntegratedBy, 1, @IntegratedBy, GETDATE(),
					@WaNumber, @ChannelId, @ApiUrl, @ApiId, @ApiKey	)
	end
end



