/* ============================================================
   Procedure: [dbo].[usp_ims_UpgradeEnquiryToLead]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ims_UpgradeEnquiryToLead]
(
    @LeadId BIGINT
)
AS
BEGIN
    
    --DECLARE @LeadId BIGINT = 18788836

    DECLARE @sqlquery NVARCHAR(MAX), @existsFlag BIGINT, @IsAutoUpgrade BIT = 0,
            @ParentId BIGINT, @LeadNo BIGINT, @OldConvUserId BIGINT, @EnquiryId BIGINT = 0,
            @UserName NVARCHAR(255), @EventDescription NVARCHAR(MAX) = '',
            @EventName NVARCHAR(255), @PersonName NVARCHAR(255),
            @MobileNo NVARCHAR(255) = '', @NewConvUserId BIGINT;

    SELECT @LeadNo = LeadNo, @ParentId = ParentID FROM UserLeads (NOLOCK) WHERE ID = @LeadId;

    IF EXISTS (SELECT 1 FROM UserEnquiry (NOLOCK) WHERE ParentID = @ParentId AND LeadNo = @LeadNo)
        SELECT @EnquiryId = EnquiryID FROM UserEnquiry (NOLOCK) WHERE ParentID = @ParentId AND LeadNo = @LeadNo;

    PRINT CONCAT('@EnquiryId ', @EnquiryId);

    SET @sqlquery = 'SELECT TOP 1 id FROM convusers (NOLOCK) WHERE Entityid = ' + CAST(@EnquiryId AS NVARCHAR) + ' AND Entity = ''enquiry'' AND isactive = 1';
    EXEC usp_clr_GetRemoteLongValue @sqlquery, @retval = @existsFlag OUT;

    IF (@existsFlag IS NOT NULL AND @EnquiryId > 0)
    BEGIN
        BEGIN TRY
            SELECT @ParentId = ParentID, @LeadNo = LeadNo FROM UserEnquiry (NOLOCK) WHERE EnquiryID = @EnquiryId;

            SET @sqlquery = 'SELECT TOP 1 UpgradeEntityToLead FROM channeltokens (NOLOCK) WHERE channelid = 2 AND parentid = ' + CAST(@ParentId AS NVARCHAR);
            EXEC usp_clr_GetRemoteBoolValue @sqlquery, @retval = @IsAutoUpgrade OUT;

            IF (@IsAutoUpgrade = 1)
            BEGIN
                PRINT CONCAT('@LeadNo => ', @LeadNo);

                SELECT @LeadId = ID FROM UserLeads (NOLOCK) WHERE ParentID = @ParentId AND LeadNo = @LeadNo;
                PRINT CONCAT('@LeadId => ', @LeadId);

                SET @sqlquery = 'SELECT id FROM convusers (NOLOCK) WHERE Entity = ''enquiry'' AND Entityid = ' + CAST(@EnquiryId AS NVARCHAR) + ' AND isactive = 1';
                EXEC usp_clr_GetRemoteLongValue @sqlquery, @retval = @OldConvUserId OUT;
                PRINT CONCAT('@OldConvUserId => ', @OldConvUserId);

                BEGIN TRY
                    DECLARE @channelProfileId NVARCHAR(25) = '';
                    SELECT @channelProfileId = REPLACE(CONCAT(TRIM(COALESCE(CountryCode, CountryCode1, CountryCode2)), TRIM(COALESCE(MobileNo, MobileNo1, MobileNo2))), '+', '')  
                    FROM MySMS.dbo.UserLeads WITH (NOLOCK) WHERE ID = @LeadId;

                    EXEC [10.0.0.135].MySMSConversations.dbo.usp_ims_AssociateDeissociateWrapper
                        @oldEntityName   = 'enquiry',
                        @oldEntityId     = @EnquiryId,
                        @ChannelName     = 'whatsapp',
                        @EntityName      = 'lead',
                        @EntityId        = @LeadId,
                        @channelProfileid= @channelProfileId,
                        @profileJson     = '{}',
                        @UserId          = @ParentId;
                END TRY
                BEGIN CATCH
                    INSERT INTO ErrorReportNew(ERRORNUMBER, ERRORSEVERITY, ERRORSTATE, ERRORPROCEDURE, ERRORLINE, ERRORMESSAGE, dATE)
                    VALUES(ERROR_NUMBER(), ERROR_SEVERITY(), ERROR_STATE(), CONCAT(ERROR_PROCEDURE(), ' usp_ims_AssociateDeissociateWrapper'), ERROR_LINE(), CONCAT(ERROR_MESSAGE(), ' @NewConvUserId => ', @NewConvUserId), GETDATE());
                END CATCH

                SET @sqlquery = 'UPDATE convusers SET isactive = 0 WHERE id = ' + CAST(@OldConvUserId AS NVARCHAR) + ';';
                EXEC usp_clr_ExecuteRemoteQuery @sqlquery;
            END
        END TRY
        BEGIN CATCH
            EXEC usp_InsertErrorInfo;
        END CATCH
    END
END


GO

/* ============================================================
   Procedure: [dbo].[usp_ims_UpgradeEnquiryToLead_bulk]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_ims_UpgradeEnquiryToLead_bulk
(    
@enquirieswithleadno as enquirieswithleadno readonly
)    
as    
begin
begin try

  declare @UserName  nvarchar(255), @EventDescription nvarchar(max) = '',   @EventName nvarchar(255), @parentid bigint, @enquiryid bigint;      

  select top 1 @enquiryid=enquiryid from @enquirieswithleadno
   select @ParentId = ParentID from UserEnquiry(nolock) where EnquiryID = @EnquiryId    

  select *,cast(0 as bigint) leadid into #enquirieswithleadno from @enquirieswithleadno
  
  update e set leadid=l.id from #enquirieswithleadno e join userleads l on e.leadno=l.leadno and l.parentid=@parentid

  create table #old_newconvid(id int identity(1,1),oldconvid bigint,enquiryid bigint,newconvid bigint,leadid bigint,channelprofileid nvarchar(255))

  insert into #old_newconvid(oldconvid,enquiryid,leadid,channelprofileid)
  select entityid,c.id,e.leadid,channelprofileid from MySMSConversations.dbo.convusers(nolock) c join #enquirieswithleadno e on c.entityid=e.enquiryid  and c.Entity = 'enquiry'and  c.isactive=1 and isnull(e.leadid,0)<>0
  
  update c set isactive=0 from MySMSConversations.dbo.convusers c join #old_newconvid o on c.id=o.oldconvid

  insert into MySMSConversations.dbo.convusers(Channelid, Entity, Entityid, channelprofileid, isactive, createdon, profilejson, lastmodifiedon, convuserparentid, lastactivitytype, lastactivitytext, lastactivityid, lastactivityby, lastactivitydate, lastactivitydirection, unreadconversations, isdeactivatedon)    
    select Channelid, 'lead', LeadId, channelprofileid, 1, getdate(), profilejson, getdate(), convuserparentid, lastactivitytype, lastactivitytext, 
lastactivityid, lastactivityby, lastactivitydate, lastactivitydirection, unreadconversations, isdeactivatedon from MySMSConversations.dbo.convusers(nolock) 
c join #old_newconvid o on c.id=o.oldconvid

update o set newconvid=c.id from MySMSConversations.dbo.convusers c join #old_newconvid o on c.entityid=o.leadid and c.parentid=@parentid

declare @LeadActivitywithid_Tbltype as [LeadActivitywithid_Tbltype]

select @EventDescription = EventTemplate from mysms.dbo.ActivityMaster(nolock) where ID = 202  
select @EventName = 'Enquiry removed from Whatsapp Channel'    
select @username=user_login from user_detail(nolock) where user_id=@parentid
insert into @LeadActivitywithid_Tbltype(leadid,userid,parentid,eventdescription,eventname,reftable,refid)
select enquiryid,@parentid,@parentid,REPLACE(REPLACE(REPLACE(@EventDescription, '#enquiryname#', PersonName), '#username#', @username), '#mobileno#', 
case when RIGHT(o.channelprofileid, len(MobileNo)) = MobileNo          
     then MobileNo          
     when RIGHT(o.channelprofileid, len(MobileNo1)) = MobileNo1          
     then MobileNo1          
     when RIGHT(o.channelprofileid, len(MobileNo2)) = MobileNo2          
     then MobileNo2          
     else '' end  ),@eventname,'MySMSConversations.dbo.convusers',o.oldconvid 
from mysms.dbo.UserEnquiry(nolock) ue join #old_newconvid o on o.enquiryid=ue.enquiryid where isnull(o.leadid,0)<>0

exec mysms.dbo.[UspSaveentityActivity_withMultipleValue_withid_bulk]  @LeadActivitywithid_Tbltype

delete from @leadactivitywithid_tbltype
  
  
 select @EventDescription = EventTemplate from mysms.dbo.ActivityMaster(nolock) where ID = 127           
 set @EventName = 'Lead added to Whatsapp Channel'        
 insert into @LeadActivitywithid_Tbltype(leadid,userid,parentid,eventdescription,eventname,reftable,refid)
select leadid,@parentid,@parentid,REPLACE(REPLACE(REPLACE(@EventDescription, '#leadname#', PersonName), '#username#', @username), '#mobileno#', 
case when RIGHT(o.channelprofileid, len(MobileNo)) = MobileNo          
     then MobileNo          
     when RIGHT(o.channelprofileid, len(MobileNo1)) = MobileNo1          
     then MobileNo1          
     when RIGHT(o.channelprofileid, len(MobileNo2)) = MobileNo2          
     then MobileNo2          
     else '' end  ),@eventname,'MySMSConversations.dbo.convusers',o.newconvid  
from mysms.dbo.Userleads(nolock) ue join #old_newconvid o on o.leadid=ue.id 

exec    [dbo].[UspSaveentityActivity_withMultipleValue_withid_bulk] @leadactivitywithid_tbltype
   

end try    
  begin catch    
   exec usp_InsertErrorInfo    
  end catch    
   
end  


GO

