/* ============================================================
   Procedure: [dbo].[usp_InitiatePaymentDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_InitiatePaymentDetails        
 @UserID INT,        
 @PlanID INT        
AS        
BEGIN  
      declare @PaymentTBLID bigint = 0  
      declare @ParentID bigint = 0
	  select top 1 @ParentID = isnull(ParentId,0) from User_Detail with(nolock) where User_ID =  @UserID


 INSERT INTO Payment_Detail        
   (        
     UserID,        
     CustomerName,        
     CustomerNumber,      
     BillingAddress,      
     ShippingAddress,        
     PlanID,        
     [Status],        
     PaymentDate,        
     CreatedDate        
   )        
 SELECT ud.[User_ID],        
        ud.FName + ud.LName,        
        CONVERT(DECIMAL(20, 0), ud.Mobile),        
        ud.[Address],        
        ud.[Address],      
        @PlanID,        
        'Initiated',        
        GETDATE(),        
        GETDATE()        
 FROM   User_Detail AS ud        
 WHERE 
     --ud.[User_ID] = @UserID                
      ud.[User_ID] = @ParentID                

   Select  @PaymentTBLID = @@IDENTITY       
   Select @PaymentTBLID as ID      
  
    
  
  --SELECT 'Success'        
END 


