/* ============================================================
   Procedure: [dbo].[usp_inserleadinteractionhistory]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_inserleadinteractionhistory](@leadid bigint)  
as  
begin
	 begin try

		declare @AutoLeadFollowup bit = 0 ,@parentid bigint,@UserID bigint ,@leadno bigint    
			declare @FollowupStatus int = 0      
			declare @NextStatusDateAddUnit nvarchar(100) = ''      
			declare @FollowupRemarks nvarchar(max) = ''       
       
			declare @AddDayUnit nvarchar(10) = '00';       
			 declare @AddHrsUnit nvarchar(10) = '00';      
			 declare @AddMinutesUnit nvarchar(10) = '00' ;      
        
				 declare @DtFLP datetime = null      
                    
		  --End add lead followup setting        
		select @ParentID=ParentID, @UserID=CreatedBy,@leadno=leadno from userleads(nolock) where id=@leadid;      
		if(exists (select 1 from UserLeads(nolock) where ID = @LeadID and nullif(FollowUpStatus,0) is null))      
		 Begin      
		 if(exists (select 1 from crmCampaignSettings(nolock) where UserID = @ParentID ))      
			 Begin      
			 select top 1      
				 @AutoLeadFollowup = ISNULL(nullif(AutoLeadFollowup,0),1),      
				 @FollowupStatus = isnull(nullif(FollowupStatus,0),1),      
				 @NextStatusDateAddUnit = ISNULL(NextStatusDateAddUnit,0),      
				 @FollowupRemarks = FollowupRemarks  
			from crmCampaignSettings(nolock) where UserID = @ParentID      
		  End  
		  else  
		  begin  
		  select @AutoLeadFollowup = 1,      
				 @FollowupStatus = 1,      
				 @NextStatusDateAddUnit = 0,      
				 @FollowupRemarks = ''  
		  end  
           
		  if(@AutoLeadFollowup = 1)      
			Begin      
			  if(@NextStatusDateAddUnit <> '')      
			 Begin      
				-- 00:00:00      
			 --set @NextStatusDateAddUnit ='00:00:00'      
           
			 SELECT @AddDayUnit = value from dbo.fn_split(@NextStatusDateAddUnit,':') where position=1-- SUBSTRING(@NextStatusDateAddUnit,1,2)      
			 SELECT @AddHrsUnit = value from dbo.fn_split(@NextStatusDateAddUnit,':') where position=2-- SUBSTRING(@NextStatusDateAddUnit,4,2)      
			 SELECT @AddMinutesUnit = value from dbo.fn_split(@NextStatusDateAddUnit,':') where position=3-- SUBSTRING(@NextStatusDateAddUnit,7,2)      
      
			 if isnumeric(@adddayunit)=1 and isnumeric(@addhrsunit)=1 and isnumeric(@addminutesunit)=1      
			 begin      
			 set @DtFLP =  dateadd(MINUTE,cast(@AddMinutesUnit as int),dateadd(HOUR,cast(@AddHrsUnit as int),DATEADD(DAY,cast(@AddDayUnit as int),GETDATE())))      
			 end      
			 else      
			 set @DtFLP=getdate()      
			 --select @DtFLP       
      
					End      
				  update Userleads set FollowUpStatus = @FollowupStatus       
				,remarks = case when @FollowupRemarks is not null then @FollowupRemarks      
							else remarks       
				end,FollowupDate = @DtFLP       
				  , NextStatusDate = @DtFLP       
			   ,AssignedTo=  
			COALESCE(Assignedto,((select top 1 value from fn_Split((select agents from CRMCampaignSettings where userid=@ParentID),'#')    ORDER BY NEWID())),@userid)       
				where id = @Leadid      
		  declare @assagent bigint=(select assignedto from userleads(nolock) where id=@LeadId)  
        
		   if not exists(select 1 from LeadInteractionHistory(nolock) where parentid=@ParentID and leadno=@leadno)  
		   begin     
			  insert into LeadInteractionHistory(LeadNo,FollowUpStatus,NextStatusDate,Remarks,AssignedTo,ParentID,CreatedOn,CreatedBy,FollowupDate,Id_Lead)  
		   select @leadno,@FollowupStatus,@DtFLP,@FollowupRemarks,@assagent,@parentid,getdate(),@ParentID,@DtFLP, @Leadid 
  
				  update ul set ul.LastFollowupCreatedBy = VL.CreatedBy, ul.LastFollowupCreatedOn = VL.CreatedOn   from UserLeads (nolock) as ul   
			join V_LastFollowup (nolock)  as VL  
					on ul.LeadNo = VL.LeadNo  
			  and ul.ParentID = Vl.ParentID  
			  where ul.ParentID = @parentid and ul.LeadNo = @leadno         
  
  
		   end  
  
			End      
  
		end  
	end try
	begin catch
		exec usp_InsertErrorInfo
	end catch
end



GO

/* ============================================================
   Procedure: [dbo].[Usp_InserProcessTableByOperator]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/****************************************************************************                                                                          
SP_NAME        : USP_INSERPROCESSTABLEBYOPERATOR                                                                                             
AUTHOR         : VINAY                                                                          
CREATED ON     : 20/02/2010 12:42 PM                                                                                
VERSION        : 1                                                                          
ALTER BY       :                                                                                  
ALTER DATE    :                                                                           
LOCATION       : PELSOFT                                                                          
SP DESCRIPTION : THIS SP IS USED TO INSERT RECORDS INTO PROCESS TABLES ACCORDING TO OPERATOR                                                                          
****************************************************************************/                                                                           
CREATE   PROC [dbo].[Usp_InserProcessTableByOperator]    
@BATCHID BIGINT ,                                                                                                
@ISDNDALLOWED  TINYINT,                                                          
@TBLNAME TINYINT                                                                                                                
AS                                                              
BEGIN                                                                                        
SET NOCOUNT ON                         
SET XACT_ABORT ON                
BEGIN TRY                              
DECLARE @AIRTELCOUNT BIGINT                                                                                     
----- 1)GET ALL AIRTEL CREDIT COUNT                                                                                                
-- DECLARE @CREDITCOUNT INT                                                                                                          
-- SELECT @CREDITCOUNT=COUNT(MESSAGE) FROM CLONEMESSAGEDELIVERYSTATUS TMP INNER JOIN AIRTELSERIES AIR ON TMP.MOBILESUBSET=AIR.MOBILESUBSET WHERE TMP.BATCHID=@BATCHID                                                             ----2)GET ALL AIRTELNUBERS NUMBERS INTO THE TEMPAIRTELTABLES                                                                                    
SELECT * INTO #TEMPOPERATOR FROM(SELECT CL.MESSAGEID,CL.BATCHID,CL.MOBILE,CL.MESSAGE,CL.SENDERID,CL.MESSAGEINSERTDATE,                                                    
CL.SCHEDULEDDATE,CL.SCHEDULEDTIME,CL.SMPPID,CL.U_ID,CL.ISUNICODE,CL.ISDND,CL.MOBILESUBSET, ISNULL(OPR.CODE,'UI') AS OPERATOR,NULL AS MESSAGESTATUS  FROM CLONEMESSAGEDELIVERYSTATUS CL  LEFT OUTER JOIN                                                     
OPERATORSERIES OPR                                                                                    
ON CL.MOBILESUBSET=OPR.MOBILESERIES WHERE CL.BATCHID=@BATCHID                                                                                                                  
)AS DOPERATOR                                                                                    
                            
UPDATE #TEMPOPERATOR SET ISDND=1 FROM #TEMPOPERATOR(NOLOCK) JOIN DNDDIRECTORY(NOLOCK) ON #TEMPOPERATOR.MOBILE = DNDDIRECTORY.DNDMOBILENO                            
                                    
SET @AIRTELCOUNT=(SELECT COUNT(MOBILE) FROM #TEMPOPERATOR WHERE ISDND=0)--AND  OPERATOR='AD')                                
UPDATE BATCHINFO SET OPERATOR=@AIRTELCOUNT WHERE BATCHID=@BATCHID AND ISPRORITY=0 AND USERFILTER<>'ON'       BEGIN DISTRIBUTED TRANSACTION                                     
    
UPDATE #TEMPOPERATOR SET MESSAGESTATUS=9 WHERE MOBILE IN(SELECT #TEMPOPERATOR.MOBILE FROM #TEMPOPERATOR JOIN INVALIDNUMBER INNUM ON #TEMPOPERATOR.MOBILE=INNUM.MOBILE)                                             
--SELECT * INTO #TEMPOFCLONE FROM CLONEMESSAGEDELIVERYSTATUS WHERE BATCHID=@BATCHID                                                                              
     IF @ISDNDALLOWED=1                                                                             
         BEGIN                                              
    --ADDED BY VINAY -:UPDATE #TEMOPERATOR WHO'S MOBILE MATCH THE INVALID NUMBER:-                                                 
                        
                             
                            
   --END    
   
   --Commenting insertion in mymds_compare since its no longer needed 050617                
  --INSERT INTO MYMDS_COMPARE                                                       
  --  (                                
  --  MESSAGEID,BATCHID,MOBILE,MESSAGE,SENDERID,MESSAGEINSERTDATE                                                                                    
  --  ,SMPPID,U_ID,ISUNICODE,ISDND,OPERATOR,MESSAGESTATUS,ISALLOWDND,LASTERROR                                                       
  --  )                                                                                    
  --  SELECT MESSAGEID,BATCHID,MOBILE,[MESSAGE],SENDERID,GETDATE(),                                                                                    
  --  SMPPID,U_ID,ISUNICODE,ISDND,OPERATOR,MESSAGESTATUS,@ISDNDALLOWED,(CASE MESSAGESTATUS WHEN 9 THEN 001 ELSE NULL END) FROM                                                                                    
  --  #TEMPOPERATOR WHERE MOBILE NOT IN (SELECT BLACKMOBILENO FROM BLACKLISTEDNO)                     
                     
                   
    INSERT INTO [SMSSTORAGE].STORAGE.DBO.MESSAGEDELIVERYSTATUS                                                       
    (                                
    MESSAGEID,BATCHID,MOBILE,MESSAGE,SENDERID,MESSAGEINSERTDATE                                                                                    
    ,SMPPID,U_ID,ISUNICODE,ISDND,OPERATOR,MESSAGESTATUS,ISALLOWDND,LASTERROR                                                       
    )                                                                                    
    SELECT MESSAGEID,BATCHID,MOBILE,[MESSAGE],SENDERID,GETDATE(),                                                                                    
    SMPPID,U_ID,ISUNICODE,ISDND,OPERATOR,MESSAGESTATUS,@ISDNDALLOWED,(CASE MESSAGESTATUS WHEN 9 THEN 001 ELSE NULL END) FROM                                                                                    
    #TEMPOPERATOR WHERE MOBILE NOT IN (SELECT BLACKMOBILENO FROM BLACKLISTEDNO)                     
                
                               
   --DELETE THE RECORD WHO'S NUMBER MATCH IN INVALID NUMBER                                                
                                                   
  --END                                                                        
       END                                                  
                                                
  DELETE #TEMPOPERATOR FROM #TEMPOPERATOR JOIN  INVALIDNUMBER INNUM ON #TEMPOPERATOR.MOBILE=INNUM.MOBILE                                         
IF @TBLNAME=1                                                                                     
 BEGIN                                                                                    
INSERT INTO PROCESSTABLEFIRST                                                                                    
  (                                                                                    
MESSAGEID,BATCHID,MOBILE,MESSAGE,SENDERID,MESSAGEINSERTDATE,SMPPID,U_ID,ISUNICODE,ISDND,OPERATOR,ISALLOWDND                                                                                    
  )                                                                                    
  SELECT MESSAGEID,BATCHID,MOBILE,MESSAGE,SENDERID,MESSAGEINSERTDATE,SMPPID,U_ID,ISUNICODE,ISDND,OPERATOR,@ISDNDALLOWED                                     
