/* ============================================================
   Procedure: [dbo].[usp_Insert_AgentCallReport_DataTo_Archive]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- select * from MySMSReportCache.[dbo].[tbl_CallReport_Cache]  select * from MySMSReportCache.[dbo].[tbl_CallReport_Archive]

   --TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_CallReport_Cache];  TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_CallReport_Archive];

-- exec [dbo].[usp_Insert_AgentCallReport_DataTo_Archive] 

CREATE   PROCEDURE [dbo].[usp_Insert_AgentCallReport_DataTo_Archive] 

AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	SET NOCOUNT ON;

	DECLARE @userid BIGINT;
    DECLARE @currentRow INT = 1;  -- Variable to track the current row in the temporary table
    DECLARE @totalRows INT;       -- Variable to store the total number of rows to process

    -- Create a temporary table to store the User IDs
    CREATE TABLE #UserIDs (UserID BIGINT);

    -- Insert UserIDs into the temporary table
    INSERT INTO #UserIDs (UserID)
    SELECT agentuserid
    FROM Mysms.dbo.calllog (NOLOCK)
	WHERE agentuserid IS NOT NULL
    GROUP BY agentuserid
    ORDER BY COUNT(*) DESC;
	
    -- Get the total number of rows
    SELECT @totalRows = COUNT(*) FROM #UserIDs;

-- Loop through each User_ID using a WHILE loop
    WHILE @currentRow <= @totalRows
BEGIN
BEGIN TRY
			-- Use a CTE to calculate ROW_NUMBER() and select the current UserID
				WITH CTE_UserIDs AS (
					SELECT UserID, ROW_NUMBER() OVER (ORDER BY UserID) AS RowNum
					FROM #UserIDs
				)
				SELECT @userid = UserID
				FROM CTE_UserIDs
				WHERE RowNum = @currentRow;

   
			Declare 
					@fromdate DATE = NULL,       
					@todate   DATE = NULL,
					@OrderColumn INT = 0,
					@CustomerDisposition NVARCHAR(255) = '',
					@AgentDisposition NVARCHAR(255) = ''; 


			Declare @Currentdate  DATE  = GETDATE();  -- Today's date
			--SET @fromdate      = DATEADD(DAY, -30, @Currentdate); -- 30 days before today
			--SET @todate  = @Currentdate;
			
			--SET @fromdate  = DATEADD(DAY, -1, @Currentdate); -- 1 day before today		
			IF NOT EXISTS ( 
					SELECT 1 
					FROM MySMSReportCache.[dbo].[tbl_CallReport_Archive](NOLOCK)
					WHERE UserId = @userid
				)
				BEGIN

			    declare @ParentId bigint = 0;		
				select @ParentId = ParentID from User_Detail(nolock) where User_ID = @UserId;


				DECLARE @OrderColumnName NVARCHAR(255) = 'Date'

				SET @OrderColumnName = CASE @OrderColumn
						WHEN 0
							THEN 'Date'
						WHEN 1
							THEN 'Agent'
						WHEN 2
							THEN 'Outgoingcalls'
						WHEN 3
							THEN 'Incomingcalls'
						WHEN 4
							THEN 'Outgoingduration'
						WHEN 5
							THEN 'Incomingduration'
						WHEN 6
							THEN 'MissedCalls'
						WHEN 7
							THEN 'TotalDuration'
						ELSE 'Date'
						END

				DECLARE @SqlQuery NVARCHAR(max) = CONCAT (
						' declare @ParentId bigint,@isadmin int;  select @parentid=ParentID,@isadmin=IsAdmin from mysms.dbo.User_Detail(nolock) where User_ID = '
						,@UserId
						,';   declare @TeamCode varchar(10) = ''''  declare @ScopeCode varchar(10) = '''' declare @UserIdTeamLst varchar(500) = ''''   
				select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst from mysms.dbo.ufn_GetUserRoleScope('
						,@UserId
						,
						')
				SELECT * FROM ( SELECT COUNT(*) OVER() AS TotalRow,  c.parentid,
						TRY_CAST(callcreatedon AS DATE) AS Date,  ISNULL(user_login, ''Agent not attempted'') AS Agent, 
						SUM(CASE WHEN direction = ''Outgoing'' THEN 1
								ELSE 0  END) AS Outgoingcalls, 
						SUM(CASE WHEN direction = ''Incoming'' THEN 1
								ELSE 0 END) AS Incomingcalls, 
						SUM(CASE WHEN direction = ''Outgoing'' THEN Calldurationseconds
								ELSE 0  END) AS Outgoingduration, 
						SUM(CASE WHEN direction = ''Incoming'' THEN Calldurationseconds
								ELSE 0 END) AS Incomingduration, 
						SUM(CASE WHEN ISNULL(agentcalldisposition, '''') <> ''Answered'' AND direction = ''Incoming''
								THEN 1 ELSE 0 END) MissedCalls, 
						SUM(calldurationseconds) TotalDuration, c.direction, c.customercalldisposition, c.agentcalldisposition, c.Calldurationseconds  FROM calendar(NOLOCK) ca
					LEFT JOIN calllog(NOLOCK) c ON TRY_CAST(c.callcreatedon AS DATE) = TRY_CAST(ca.start_dts AS DATE)
					LEFT JOIN user_detail u(NOLOCK) ON c.agentuserid = u.User_ID
					WHERE c.parentid = ', @parentid ,' and 1 = (case when @isadmin=1 then 1
								when isnull(c.agentuserid, 0) in (select [value] from dbo.fn_Split(@UserIdTeamLst, '','')) then 1 when isnull(c.agentuserid, 0) = '
						,@UserId
						,' then 1
									else 0 end )'
						,iif(isnull(@CustomerDisposition, '') <> '', CONCAT (
								' and c.customercalldisposition in ('
								,@CustomerDisposition
								,')'
								), '')
						,iif(isnull(@AgentDisposition, '') <> '', CONCAT (
								' and c.agentcalldisposition in ('
								,@AgentDisposition
								,')'
								), '')
						,' GROUP BY TRY_CAST(callcreatedon AS DATE), user_login, c.parentid, TRY_CAST(ca.start_dts AS DATE),c.direction, c.customercalldisposition, c.agentcalldisposition, c.Calldurationseconds ) t  ORDER BY '
						,@OrderColumnName
						,' ') 


				--Create a temporary table to store the query result
						CREATE TABLE #TempCallLogData (
							TotalRow BIGINT,
							ParentId NVARCHAR(100),
							Date DATE,
							Agent NVARCHAR(255),
							OutgoingCalls NVARCHAR(100),
							IncomingCalls NVARCHAR(100),
							OutgoingDuration NVARCHAR(100),
							IncomingDuration NVARCHAR(100),
							MissedCalls NVARCHAR(100),
							TotalDuration NVARCHAR(100),
							direction NVARCHAR(100),
							customercalldisposition NVARCHAR(100),
							agentcalldisposition NVARCHAR(100),
							Calldurationseconds Int
						);

						--Insert the result of the dynamic SQL into the temporary table
							INSERT INTO #TempCallLogData
							EXEC sp_executesql @SqlQuery;

			    -- start data insert into cache tables

				INSERT INTO MySMSReportCache.[dbo].[tbl_CallReport_Archive] 
				(		   
							[TotalRow],
							[ParentId],
							[Date],
							[Agent],
							[Outgoingcalls],
							[Incomingcalls],
							[Outgoingduration],
							[Incomingduration],
							[MissedCalls],
							[TotalDuration],
							[direction],
							[UserId],
							[customercalldisposition],
							[agentcalldisposition],
							[Calldurationseconds]
				)
				SELECT 
						TotalRow,
						ParentId,
						Date, 
						Agent, 
						OutgoingCalls, 
						IncomingCalls,
						OutgoingDuration,
						IncomingDuration,
						MissedCalls, 
						TotalDuration,
						direction,
						@userid as UserId,
						customercalldisposition,
						agentcalldisposition,
						Calldurationseconds
					FROM #TempCallLogData;
					
				-- end data insert into cache tables

    	--Drop the temporary table
			DROP TABLE #TempCallLogData;

END
END TRY
BEGIN CATCH
exec usp_InsertErrorInfo
END CATCH
-- Move to the next row
        SET @currentRow = @currentRow + 1;
END

-- Clean up the temporary table
    DROP TABLE #UserIDs;
		
END



GO

