/* ============================================================
   Procedure: [dbo].[usp_Insert_AttendanceMasterReport_DataTo_Archive]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



-- select * from MySMSReportCache.[dbo].[tbl_AttendanceMaster_Cache]  select * from MySMSReportCache.[dbo].[tbl_AttendanceMaster_Archive]

   --TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_AttendanceMaster_Cache];  TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_AttendanceMaster_Archive];

-- exec [dbo].[usp_Insert_AttendanceMasterReport_DataTo_Archive]

CREATE   PROCEDURE [dbo].[usp_Insert_AttendanceMasterReport_DataTo_Archive] 

AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	SET NOCOUNT ON;

	DECLARE @userid BIGINT;
    DECLARE @currentRow INT = 1;  -- Variable to track the current row in the temporary table
    DECLARE @totalRows INT;       -- Variable to store the total number of rows to process

    -- Create a temporary table to store the User IDs
    CREATE TABLE #UserIDs (UserID BIGINT);

    -- Insert UserIDs into the temporary table
    INSERT INTO #UserIDs (UserID)
    SELECT UserId
    FROM Mysms.dbo.TBL_ET_AttendanceGroupUserMapping (NOLOCK)
	WHERE UserId IS NOT NULL
    GROUP BY UserId
    ORDER BY COUNT(*) DESC;
	
    -- Get the total number of rows
    SELECT @totalRows = COUNT(*) FROM #UserIDs;

-- Loop through each User_ID using a WHILE loop
    WHILE @currentRow <= @totalRows
BEGIN
BEGIN TRY
			-- Use a CTE to calculate ROW_NUMBER() and select the current UserID
				WITH CTE_UserIDs AS (
					SELECT UserID, ROW_NUMBER() OVER (ORDER BY UserID) AS RowNum
					FROM #UserIDs
				)
				SELECT @userid = UserID
				FROM CTE_UserIDs
				WHERE RowNum = @currentRow;

   
			Declare 
					@fromdate DATE = NULL,       
					@todate   DATE = NULL,
					@PageSize int = 0,
					@StartPoint int = 0, 
					@Endpoint int = 0,
					@SearchText varchar(200) = '',
					@UserIds nvarchar(max) = '',
					@AttendanceGroupId bigint = 0,
					@Contain nvarchar(max) = ''; 


			Declare @Currentdate  DATE  = GETDATE();  -- Today's date
			SET @fromdate      = DATEADD(DAY, -9130, @Currentdate); -- 30 days before today
			SET @todate  = @Currentdate;
			
			--SET @fromdate  = DATEADD(DAY, -1, @Currentdate); -- 1 day before today		

			IF NOT EXISTS ( 
					SELECT 1 
					FROM MySMSReportCache.[dbo].[tbl_AttendanceMaster_Archive] (NOLOCK)
					WHERE UserId = @userid
				)
				BEGIN

			    declare @ParentId bigint  
			select @ParentId = ParentID from User_Detail(nolock) u where u.User_ID = @userid  
			
				declare @UserIdTeamLst nvarchar(max) = '', @MonthYearName varchar(20) = ''

				set @MonthYearName = CONCAT(MONTH(@FromDate), ' ', YEAR(@FromDate))

				drop table if exists #tempUsers  
					create table #tempUsers(User_ID bigint, Name nvarchar(255), Image nvarchar(255))  
					insert into #tempUsers(User_ID, Name, Image)  
					exec Use_GetUserDetails @UserID = @UserId  

					if(ISNULL(@UserIds, '') =  '') begin set @UserIds = '' end

					drop table if exists #tempSelectedUser
					create table #tempSelectedUser ( UserId bigint )
					insert into #tempSelectedUser(UserId) select [value] from string_split(@UserIds, ',')


				declare @querySql nvarchar(max)
							set @querySql = concat(N'select * from (select ',
								N'count(t.ParentID) over() as TotalRecords, ',
								N'ROW_NUMBER() over(partition by (select null) order by t.UserName) SNo, ',
								N't.* from ( ',
								N'select teum.AttendanceGroupId, teag.AttendanceGroupName, ',
								N'concat(ud.FName, '' '', ud.LName)  UserName, ud.Mobile, ',
