								N'dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, ''', @FromDate, ''', ''TotalDays'') TotalDays, ',
								N'dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, ''', @FromDate, ''', ''LateSignin'') InLateDays, ',
								N'dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, ''', @FromDate, ''', ''OutEarlyDays'') OutEarlyDays, ',
								N'dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, ''', @FromDate, ''', ''Totalminutes'') TotalAttendanceTime, ',
