								N'dbo.fn_TBL_ET_GeoEntityCheckInOutCount(ud.User_ID, TRY_CAST(''', @FromDate, ''' as varchar(20)), ''CheckOutCount'') CheckOutCount, ',
								N'dbo.fn_TBL_ET_GeoEntityCheckInOutCount(ud.User_ID, TRY_CAST(''', @FromDate, ''' as varchar(20)), ''CheckOutRequest'') CheckOutRequestCount, ',
