CREATE   PROCEDURE [dbo].[usp_Insert_AttendanceMasterReport_DataTo_Cache_Archive] 

AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	SET NOCOUNT ON;

	DECLARE @userid BIGINT;
    DECLARE @currentRow INT = 1;  -- Variable to track the current row in the temporary table
    DECLARE @totalRows INT;       -- Variable to store the total number of rows to process

    -- Create a temporary table to store the User IDs
    CREATE TABLE #UserIDs (UserID BIGINT);

    -- Insert UserIDs into the temporary table
    INSERT INTO #UserIDs (UserID)
    SELECT UserID
    FROM Mysms.dbo.TBL_ET_AttendanceGroupUserMapping (NOLOCK)
	WHERE UserID IS NOT NULL
    GROUP BY UserID
    ORDER BY COUNT(*) DESC;
	
    -- Get the total number of rows
    SELECT @totalRows = COUNT(*) FROM #UserIDs;

-- Loop through each User_ID using a WHILE loop
    WHILE @currentRow <= @totalRows
BEGIN
BEGIN TRY
			-- Use a CTE to calculate ROW_NUMBER() and select the current UserID
				WITH CTE_UserIDs AS (
					SELECT UserID, ROW_NUMBER() OVER (ORDER BY UserID) AS RowNum
					FROM #UserIDs
				)
				SELECT @userid = UserID
				FROM CTE_UserIDs
				WHERE RowNum = @currentRow;

   
			Declare 
					@fromdate DATE = NULL,       
					@todate   DATE = NULL,
					@PageSize int = 0,
					@StartPoint int = 0, 
					@Endpoint int = 0,
					@SearchText varchar(200) = '',
					@UserIds nvarchar(max) = '',
					@AttendanceGroupId bigint = 0,
					@Contain nvarchar(max) = ''; 


			Declare @Currentdate  DATE  = GETDATE();  -- Today's date
			--SET @fromdate      = DATEADD(DAY, -30, @Currentdate); -- 30 days before today
			SET @fromdate  = DATEADD(DAY, -1, @Currentdate); -- 1 day before today
			SET @todate  = @Currentdate;
			

			--IF NOT EXISTS ( 
			--		SELECT 1 
			--		FROM MySMSReportCache.[dbo].[tbl_AttendanceMaster_Cache] (NOLOCK)
			--		WHERE UserId = @userid and MonthYearName between (FORMAT(@FromDate, 'MM yyyy')) and (FORMAT(@todate, 'MM yyyy'))
			--	)
			--	BEGIN

			    declare @ParentId bigint  
			select @ParentId = ParentID from User_Detail(nolock) u where u.User_ID = @userid  
			
				declare @UserIdTeamLst nvarchar(max) = '', @MonthYearName varchar(20) = ''

				set @MonthYearName = CONCAT(MONTH(@FromDate), ' ', YEAR(@FromDate))

				drop table if exists #tempUsers  
					create table #tempUsers(User_ID bigint, Name nvarchar(255), Image nvarchar(255))  
					insert into #tempUsers(User_ID, Name, Image)  
					exec Use_GetUserDetails @UserID = @UserId  

					if(ISNULL(@UserIds, '') =  '') begin set @UserIds = '' end

					drop table if exists #tempSelectedUser
					create table #tempSelectedUser ( UserId bigint )
					insert into #tempSelectedUser(UserId) select [value] from string_split(@UserIds, ',')


				declare @querySql nvarchar(max)
							set @querySql = concat(N'select * from (select ',
								N'count(t.ParentID) over() as TotalRecords, ',
								N'ROW_NUMBER() over(partition by (select null) order by t.UserName) SNo, ',
								N't.* from ( ',
								N'select teum.AttendanceGroupId, teag.AttendanceGroupName, ',
								N'concat(ud.FName, '' '', ud.LName)  UserName, ud.Mobile, ',
								N'ud.User_ID, ud.ParentID, ud.User_Login, ',
								N'isnull(ud.FName,'''') + '' '' + isnull(ud.LName,'''')  as   UserFullName, ',
								N'concat(ud.FName, '' '', ud.LName, '' ('', ud.User_Login, '')'') EmployeeName, ',
								N'concat(udpa.FName, '' '', udpa.LName, '' ('', udpa.User_Login, '')'') ManagerParent, '''' Designetion, ',
								N'ud.Image, ud.ProfilePictureName, ',
								N'''' + @MonthYearName + ''' MonthYearName, ',
								N'dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, ''', @FromDate, ''', ''TotalWorkingDay'') PresentDays, ',
								N'isnull(dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, ''', @FromDate, ''', ''FullDays''),0) FullDays, ',
								N'dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, ''', @FromDate, ''', ''HalfDays'') HalfDays, ',
								N'isnull(dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, ''', @FromDate, ''', ''ShortDays''),0) ShortDays, ',
								N'dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, ''', @FromDate, ''', ''WeekOff'') WeeklyOffDays, ',
								N'dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, ''', @FromDate, ''', ''TotalLeave'') OnLeaveDays, ',
								N'dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, ''', @FromDate, ''', ''TotalDays'') TotalDays, ',
								N'dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, ''', @FromDate, ''', ''LateSignin'') InLateDays, ',
								N'dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, ''', @FromDate, ''', ''OutEarlyDays'') OutEarlyDays, ',
								N'dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, ''', @FromDate, ''', ''Totalminutes'') TotalAttendanceTime, ',
								N'dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, ''', @FromDate, ''', ''NumberOfBreaks'') NumberOfBreaks, ',
								N'dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, ''', @FromDate, ''', ''TimeInBreaks'') TimeInBreaks, ',
								N'dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, ''', @FromDate, ''', ''MaxBreakTimes'') MaxBreakTimes, ',
								N'dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, ''', @FromDate, ''', ''TotalTask'') TotalTask, ',
								N'dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, ''', @FromDate, ''', ''TimeSpentInTasks'') TimeSpentInTasks, ',
								N'isnull(dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, ''', @FromDate, ''', ''HolidayDays''),0) HolidayDays, ',
								N'dbo.fn_TBL_ET_GeoEntityCheckInOutCount(ud.User_ID, TRY_CAST(''', @FromDate, ''' as varchar(20)), ''CheckInCount'') CheckInCount, ',
								N'dbo.fn_TBL_ET_GeoEntityCheckInOutCount(ud.User_ID, TRY_CAST(''', @FromDate, ''' as varchar(20)), ''CheckInRequest'') CheckInRequestCount, ',
								N'dbo.fn_TBL_ET_GeoEntityCheckInOutCount(ud.User_ID, TRY_CAST(''', @FromDate, ''' as varchar(20)), ''CheckOutCount'') CheckOutCount, ',
								N'dbo.fn_TBL_ET_GeoEntityCheckInOutCount(ud.User_ID, TRY_CAST(''', @FromDate, ''' as varchar(20)), ''CheckOutRequest'') CheckOutRequestCount, ',
								N'isnull(dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, ''', @FromDate, ''', ''SignIn''),0) SignInCount, ',
								N'isnull(dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, ''', @FromDate, ''', ''SignInRequest''),0) SignInRequestCount, ',
								N'isnull(dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, ''', @FromDate, ''', ''SignOut''),0) SignOutCount, ',
								N'isnull(dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, ''', @FromDate, ''', ''SignOutRequest''),0) SignOutRequestCount, ',
								N'dbo.fn_TBL_ET_ExpenseTotalSummary(ud.User_ID, ''', @FromDate, ''', ''TotalTimeSpentTravelled'') TotalTimeSpentTravelled, ',
								N'dbo.fn_TBL_ET_ExpenseTotalSummary(ud.User_ID, ''', @FromDate, ''', ''TotalClaim'') TotalClaim, ',
								N'dbo.fn_TBL_ET_ExpenseTotalSummary(ud.User_ID, ''', @FromDate, ''', ''TotalApproved'') TotalApproved, ',
								N'dbo.fn_TBL_ET_ExpenseTotalSummary(ud.User_ID, ''', @FromDate, ''', ''TotalDistance'') TotalDistance, ',
								N'isnull(dbo.fn_TBL_ET_ExpenseTotalSummary(ud.User_ID, ''', @FromDate, ''', ''TotalTravelTime''), 0) TotalTravelTime, ',
								N''''' TeamName,  0 HirarchyParentid ',
								N'from User_Detail(nolock) ud ',
								N'inner join #tempUsers tu on ud.User_ID = tu.User_ID ',
								iif(LEN(@UserIds) > 0, 'inner join #tempSelectedUser  su on ud.User_Id = su.UserId ', ''),
								N'inner join TBL_ET_AttendanceGroupUserMapping(nolock) teum on ud.User_Id = teum.UserId ',
								N'inner join TBL_ET_AttendanceGroup(nolock) teag on teum.AttendanceGroupId = teag.AttendanceGroupId ',
								N'inner join User_Detail(nolock) udpa on ud.ParentId = udpa.User_Id where ',
								--N'inner join #TblHirarchy thia on ud.User_Id = thia.User_Id   ',
								--N'(ud.User_ID in (select [value] from dbo.fn_Split(''' + @UserIdTeamLst + ''', '','')) and  ',
								N'teag.AttendanceGroupId = (case when '''+ TRY_CAST(@AttendanceGroupId as varchar(10)) +''' > 0 then ', 
								N'''' + TRY_CAST(@AttendanceGroupId as varchar(10)) + ''' else teag.AttendanceGroupId end)) ', 
								N' t where ( 1 = 1 ) ', @Contain, N' ) tt where tt.SNo between ', @StartPoint, ' and ', @EndPoint	
							)
	

