/* ============================================================
   Procedure: [dbo].[usp_Insert_CallLogs_DataTo_Archive]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- select * from MySMSReportCache_dev.[dbo].[tbl_CallLogs_Cache]  select * from MySMSReportCache_dev.[dbo].[tbl_CallLogs_Archive]

   --TRUNCATE TABLE MySMSReportCache_dev.[dbo].[tbl_CallLogs_Cache];  TRUNCATE TABLE MySMSReportCache_dev.[dbo].[tbl_CallLogs_Archive];

-- exec [dbo].[usp_Insert_CallLogs_DataTo_Cache_Archive] 

CREATE   PROCEDURE [dbo].[usp_Insert_CallLogs_DataTo_Archive] 

AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	SET NOCOUNT ON;

	DECLARE @userid BIGINT;
    DECLARE @currentRow INT = 1;  -- Variable to track the current row in the temporary table
    DECLARE @totalRows INT;       -- Variable to store the total number of rows to process

    -- Create a temporary table to store the User IDs
    CREATE TABLE #UserIDs (UserID BIGINT);

    -- Insert UserIDs into the temporary table
    INSERT INTO #UserIDs (UserID)
    SELECT clientid
    FROM Mysms.dbo.kit19calls (NOLOCK)
	WHERE clientid IS NOT NULL
    GROUP BY clientid
    ORDER BY COUNT(*) DESC;
	
    -- Get the total number of rows
    SELECT @totalRows = COUNT(*) FROM #UserIDs;

-- Loop through each User_ID using a WHILE loop
    WHILE @currentRow <= @totalRows
BEGIN
BEGIN TRY
			-- Use a CTE to calculate ROW_NUMBER() and select the current UserID
				WITH CTE_UserIDs AS (
					SELECT UserID, ROW_NUMBER() OVER (ORDER BY UserID) AS RowNum
					FROM #UserIDs
				)
				SELECT @userid = UserID
				FROM CTE_UserIDs
				WHERE RowNum = @currentRow;

   
			Declare @parentid as bigint = @userid,
					@fromdate DATE = NULL,       
					@todate   DATE = NULL; 

       
			Declare @Currentdate  DATE  = GETDATE();  -- Today's date
			SET @fromdate      = DATEADD(DAY, -9130, @Currentdate); -- 30 days before today
			SET @todate  = @Currentdate;
			
			  -- Only process if the UserID has not been processed already
				IF NOT EXISTS ( 
					SELECT 1 
					FROM MySMSReportCache.[dbo].[tbl_CallLogs_Archive] (NOLOCK)
					WHERE UserId = @userid
				)
				BEGIN
			    drop table if exists #tempUsers  
				create table #tempUsers(User_ID bigint, Name nvarchar(255), Image nvarchar(255))  
				insert into #tempUsers(User_ID, Name, Image)  
				exec Use_GetUserDetails @UserID = @parentid  

				declare @query1 nvarchar(max)='' 

				-- Define the dynamic query
						SET @query1 = '
						SELECT
							ROW_NUMBER() OVER (ORDER BY a.ID DESC) AS RowNumber1,
							COUNT(*) OVER (ORDER BY b.User_Login) AS rc1,
							a.id,
							a.call_last_dtmf,
							a.call_start_time,
							a.uniqueid,
							a.callerid,
							a.channel,
							a.context,
							a.dnid,
							a.clientid,
							c.AppName AS appid,
							REPLACE(a.recordurl, ''https://'', ''http://'') AS recordurl,
							a.call_end_time,
							b.user_login,
							ISNULL(ul.PersonName, '''') AS name,
							dbo.billduration1(a.uniqueid) AS billduration,
							dbo.callstatus1(a.uniqueid) AS callstatus,
							dbo.callduration(a.uniqueid) AS callduration,
							ISNULL(dbo.lastagentattended(a.uniqueid), '''') AS AgentUser
						FROM
							kit19calls a (NOLOCK)
						INNER JOIN #tempUsers (NOLOCK) tl ON a.clientid = tl.User_Id
						LEFT JOIN cloud_app_master (NOLOCK) c ON c.AppId = a.appid
						LEFT JOIN UserLeads ul (NOLOCK) ON a.clientid = ul.ParentID
							AND CASE
								WHEN a.context <> ''inbound'' AND a.dnid IN (ul.MobileNo, ul.MobileNo1, ul.MobileNo2) THEN 1
								WHEN a.context = ''inbound'' AND a.callerid IN (ul.MobileNo, ul.MobileNo1, ul.MobileNo2) THEN 1
								ELSE 0
							END = 1
						INNER JOIN user_detail (NOLOCK) b ON b.user_id = a.clientid
						WHERE
							b.user_id = ' + TRY_CAST(@parentid AS NVARCHAR) + '
							AND TRY_CAST(a.call_start_time AS DATE) BETWEEN ''' + TRY_CAST(@fromdate AS NVARCHAR) + ''' AND ''' + TRY_CAST(@todate AS NVARCHAR) + '''
							ORDER BY a.ID DESC;';


						-- Create a temporary table to store the query results
							CREATE TABLE #Temp_CallLogs (
								RowNumber1 INT,
								rc1 INT,
								id INT,
								call_last_dtmf NVARCHAR(50),
								call_start_time DATETIME,
								uniqueid NVARCHAR(100),
								callerid NVARCHAR(50),
								channel NVARCHAR(50),
								context NVARCHAR(50),
								dnid NVARCHAR(50),
								clientid NVARCHAR(50),
								appid NVARCHAR(50),
								recordurl NVARCHAR(500),
								call_end_time DATETIME,
								user_login NVARCHAR(50),
								name NVARCHAR(255),
								billduration NVARCHAR(50),
								callstatus NVARCHAR(50),
								callduration NVARCHAR(50),
								AgentUser NVARCHAR(255)
							);


							-- Insert the results of the dynamic query into the temporary table
								INSERT INTO #Temp_CallLogs
								EXEC sp_executesql @query1;

				-- start data insert into archive table

				INSERT INTO MySMSReportCache.[dbo].[tbl_CallLogs_Archive] 
				(		   
							   [RowNumber1]
							  ,[rc1]
							  ,[id]
							  ,[call_last_dtmf]
							  ,[call_start_time]
							  ,[uniqueid]
							  ,[callerid]
							  ,[channel]
							  ,[context]
							  ,[dnid]
							  ,[clientid]
							  ,[appid]
							  ,[recordurl]
							  ,[call_end_time]
							  ,[user_login]
							  ,[name]
							  ,[billduration]
							  ,[callstatus]
							  ,[callduration]
							  ,[AgentUser]
							  ,[UserId]
				)
				SELECT 
						RowNumber1,
						rc1,
						id,
						call_last_dtmf,
						call_start_time,
						uniqueid,
						callerid,
						channel,
						context,
						dnid,
						clientid,
						appid,
						recordurl,
						call_end_time,
						user_login,
						name,
						billduration,
						callstatus,
						callduration,
						AgentUser,
						@parentid AS UserId
					FROM #Temp_CallLogs;

			-- end data insert into archive table

			-- Drop the temporary table
			DROP TABLE #Temp_CallLogs;
			END
END TRY
BEGIN CATCH
exec usp_InsertErrorInfo
END CATCH
-- Move to the next row
        SET @currentRow = @currentRow + 1;
END

-- Clean up the temporary table
    DROP TABLE #UserIDs;
		
END



GO

