--  select * from MySMSReportCache.[dbo].[tbl_AgentCallCountChart_Archive]

   --  TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_AgentCallCountChart_Archive];

-- exec [dbo].[usp_Insert_CallReport_AgentChart_DataTo_Archive] 

CREATE   PROCEDURE [dbo].[usp_Insert_CallReport_AgentChart_DataTo_Archive] 

AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	SET NOCOUNT ON;

	DECLARE @userid BIGINT;
    DECLARE @currentRow INT = 1;  -- Variable to track the current row in the temporary table
    DECLARE @totalRows INT;       -- Variable to store the total number of rows to process

    -- Create a temporary table to store the User IDs
    CREATE TABLE #UserIDs (UserID BIGINT);

    -- Insert UserIDs into the temporary table
    INSERT INTO #UserIDs (UserID)
    SELECT agentuserid
    FROM Mysms.dbo.CallLog (NOLOCK)
	WHERE agentuserid IS NOT NULL
    GROUP BY agentuserid
    ORDER BY COUNT(*) DESC;
	
    -- Get the total number of rows
    SELECT @totalRows = COUNT(*) FROM #UserIDs;

-- Loop through each User_ID using a WHILE loop
    WHILE @currentRow <= @totalRows
BEGIN
BEGIN TRY
			-- Use a CTE to calculate ROW_NUMBER() and select the current UserID
				WITH CTE_UserIDs AS (
					SELECT UserID, ROW_NUMBER() OVER (ORDER BY UserID) AS RowNum
					FROM #UserIDs
				)
				SELECT @userid = UserID
				FROM CTE_UserIDs
				WHERE RowNum = @currentRow;

   
			Declare @fromdate DATE = NULL,       
					@todate   DATE = NULL; 

			Declare @Currentdate  DATE  = GETDATE();  -- Today's date
			SET @fromdate      = DATEADD(DAY, -9130, @Currentdate); -- 30 days before today
			SET @todate  = @Currentdate;

			declare @ParentId bigint,@isadmin int;                                                
			select @parentid=ParentID,@isadmin=IsAdmin  from Mysms.dbo.User_Detail(nolock) where User_ID = @userid;                        
			
			drop table if exists #tempUsers  
			 create table #tempUsers(User_ID bigint, Name nvarchar(255), Image nvarchar(255))  
			 insert into #tempUsers(User_ID, Name, Image)  
			 exec Use_GetUserDetails @UserID = @userid  

			   IF NOT EXISTS (
                SELECT 1 
                FROM MySMSReportCache.dbo.[tbl_AgentCallCountChart_Archive] (NOLOCK)
                WHERE UserId = @userid
            )
            BEGIN
				INSERT INTO MySMSReportCache.[dbo].[tbl_AgentCallCountChart_Archive] 
				(		   
							   [User_Login]
							  ,[agent_outgoing_answered]
							  ,[total_outgoing_call]
							  ,[agent_incoming_answered]
							  ,[agent_incoming_not_answered]
							  ,[UserId]
							  ,[start_dts]
				)
				select 
						User_Login, 
						[agent_outgoing_answered],
						--[agent_outgoing_not_answered], 
						(
							[agent_outgoing_answered] +
							[agent_outgoing_not_answered]
						) as[total_outgoing_call],
						[agent_incoming_answered],
						[agent_incoming_not_answered],
						@userid AS UserId,
						[start_dts]
					from (
						select logs.User_Login, logs.start_dts, logs.custom_disposition from (
							select 
								user_login,	
								case when c.Direction = 'Outgoing' and agentcalldisposition = 'ANSWERED' then 'agent_outgoing_answered'
									 when c.Direction = 'Outgoing' and customercalldisposition <> 'ANSWERED' then 'agent_outgoing_not_answered'
									 when c.Direction = 'Incoming' and agentcalldisposition = 'ANSWERED' then 'agent_incoming_answered'
									 when c.Direction = 'Incoming' and customercalldisposition <> 'ANSWERED' then 'agent_incoming_not_answered'
									 else 'agent_outgoing_not_answered'
								end as [custom_disposition],
								cast(ca.start_dts as date) AS [start_dts]
							from 
							calendar(nolock) ca left join
							calllog(nolock) c on cast(c.callcreatedon as date)=cast(ca.start_dts as date)
							inner join #tempUsers(nolock) tl on c.agentuserid = tl.User_Id 
							left join user_detail(nolock) u on c.agentuserid = u.User_ID
							where   start_dts between @fromdate and @todate and
							 c.parentid=@parentid 
							--and 1 = (case when @isadmin=1 then 1
							--		when isnull(c.agentuserid, 0) in (select [value] from dbo.fn_Split(@UserIdTeamLst, ','))
							--			then 1
							--		when isnull(c.agentuserid, 0) = @UserId then 1
							--			else 0 end )
						) logs where logs.User_Login is not null
					) AS bc
					PIVOT (
						Count(custom_disposition)
						for custom_disposition in ( [agent_outgoing_answered], [agent_outgoing_not_answered], [agent_incoming_answered], [agent_incoming_not_answered] )
					) AS PivotTable; 

		  END
			-- end data insert into archive table
END TRY
BEGIN CATCH
exec usp_InsertErrorInfo
END CATCH
-- Move to the next row
        SET @currentRow = @currentRow + 1;
END

-- Clean up the temporary table
    DROP TABLE #UserIDs;
		
END



