   Procedure: [dbo].[usp_Insert_CallReport_BillingChart_DataTo_Archive]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- select * from MySMSReportCache.[dbo].[tbl_CallReportBillingChart_Cache]  select * from MySMSReportCache.[dbo].[tbl_CallReportBillingChart_Archive]

   --TRUNCATE TABLE MySMSReportCache_dev.[dbo].[tbl_CallReportBillingChart_Cache];  TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_CallReportBillingChart_Archive];

-- exec [dbo].[usp_Insert_CallReport_BillingChart_DataTo_Archive] 

CREATE   PROCEDURE [dbo].[usp_Insert_CallReport_BillingChart_DataTo_Archive] 

AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	SET NOCOUNT ON;

	DECLARE @userid BIGINT;
    DECLARE @currentRow INT = 1;  -- Variable to track the current row in the temporary table
    DECLARE @totalRows INT;       -- Variable to store the total number of rows to process

    -- Create a temporary table to store the User IDs
    CREATE TABLE #UserIDs (UserID BIGINT);

    -- Insert UserIDs into the temporary table
    INSERT INTO #UserIDs (UserID)
    SELECT agentuserid
    FROM Mysms.dbo.CallLog (NOLOCK)
	WHERE agentuserid IS NOT NULL
    GROUP BY agentuserid
    ORDER BY COUNT(*) DESC;
	
    -- Get the total number of rows
    SELECT @totalRows = COUNT(*) FROM #UserIDs;

-- Loop through each User_ID using a WHILE loop
    WHILE @currentRow <= @totalRows
BEGIN
BEGIN TRY
			-- Use a CTE to calculate ROW_NUMBER() and select the current UserID
				WITH CTE_UserIDs AS (
					SELECT UserID, ROW_NUMBER() OVER (ORDER BY UserID) AS RowNum
					FROM #UserIDs
				)
				SELECT @userid = UserID
				FROM CTE_UserIDs
				WHERE RowNum = @currentRow;

             -- Only process if the UserID has not been processed already
            IF NOT EXISTS (
                SELECT 1 
                FROM MySMSReportCache.dbo.tbl_CallReportBillingChart_Archive (NOLOCK)
                WHERE UserId = @userid
            )
            BEGIN
			Declare @fromdate DATE = NULL,       
					@todate   DATE = NULL; 

			Declare @Currentdate  DATE  = GETDATE();  -- Today's date
			SET @fromdate      = DATEADD(DAY, -9130, @Currentdate); -- 30 days before today
			SET @todate  = @Currentdate;
			

			declare @ParentId bigint,@isadmin int;                                                
			select @parentid=ParentID,@isadmin=IsAdmin  from Mysms.dbo.User_Detail(nolock) where User_ID = @userid;                        
			
			drop table if exists #tempUsers  
			 create table #tempUsers(User_ID bigint, Name nvarchar(255), Image nvarchar(255))  
			 insert into #tempUsers(User_ID, Name, Image)  
			 exec Use_GetUserDetails @UserID = @userid  

			  
				INSERT INTO MySMSReportCache.[dbo].[tbl_CallReportBillingChart_Archive] 
				(			
						   [ParentId]
						  ,[Date]
						  ,[Outgoing]
						  ,[Incoming]
						  ,[UserId]
						  ,[start_dts]
				)
				select c.parentid,try_cast(callcreatedon as date) as Date,   
						 sum(case when direction='Outgoing' then t.cost else 0 end) as Outgoing,   
						 sum(case when direction='Incoming' then t.cost else 0 end) as Incoming,
						 @userid AS UserId,
						 try_cast(ca.start_dts as date)
						 --,sum(case when direction='Outgoing' then Calldurationseconds else 0 end) as Outgoingduration,sum(case when direction='Incoming' then Calldurationseconds else 0 end) as Incomingduration  
						 --,sum(case when isnull(agentcalldisposition,'') <>'Answered' and direction='Incoming' then 1 else 0 end) MissedCalls,sum(calldurationseconds) TotalDuration   
						 from calendar(nolock) ca   
						 left join calllog(nolock) c on try_cast(c.callcreatedon as date)=try_cast(ca.start_dts as date) 
						 inner join #tempUsers(nolock) tl on c.agentuserid = tl.User_Id 
							--and TRY_CAST(c.callcreatedon as date) between TRY_CAST(@fromdate as date) and TRY_CAST(@todate as date)
	
						 left join user_detail u (nolock) on c.parentid = u.User_ID  
						 left join TelephonyCostDeducted(nolock) t on t.parentid=c.parentid 
							--and TRY_CAST(t.createdon as date) between TRY_CAST(@fromdate as date) and TRY_CAST(@todate as date)
						  and 1=case when t.gatewaytype<>0 and t.kit19callsdialledid=c.refid then 1  
						   when t.GatewayType=0 and t.uniqueid=c.uniqueid then 1 else 0 end  
						 where -- start_dts between @fromdate and @todate  and 
						   c.parentid=@parentid 
  
						  --and 1 = (case when @isadmin=1 then 1  
						  --   when isnull(c.agentuserid, 0) in (select [value] from dbo.fn_Split(@UserIdTeamLst, ','))  
						  --    then 1  
						  --   when isnull(c.agentuserid, 0) = @UserId then 1  
						  --    else 0 end ) 
	  
						 group by try_cast(callcreatedon as date), user_login,c.parentid,try_cast(ca.start_dts as date)  
						  order by c.parentid,try_cast(callcreatedon as date) desc 
			  END
			-- end data insert into archive table
END TRY
BEGIN CATCH
exec usp_InsertErrorInfo
END CATCH
-- Move to the next row
        SET @currentRow = @currentRow + 1;
END

-- Clean up the temporary table
    DROP TABLE #UserIDs;
		
END



