/* ============================================================
   Procedure: [dbo].[usp_Insert_CallReportDashboard_DataTo_Archive]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


--  select * from MySMSReportCache.[dbo].[tbl_CallReportDashboardCount_Archive]

   -- TRUNCATE TABLE MySMSReportCache_dev.[dbo].[tbl_CallReportDashboardCount_Archive];

-- exec [dbo].[usp_Insert_CallReportDashboard_DataTo_Archive] 
CREATE   PROCEDURE [dbo].[usp_Insert_CallReportDashboard_DataTo_Archive] 

AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	SET NOCOUNT ON;

	DECLARE @userid BIGINT;
    DECLARE @currentRow INT = 1;  -- Variable to track the current row in the temporary table
    DECLARE @totalRows INT;       -- Variable to store the total number of rows to process

    -- Create a temporary table to store the User IDs
    CREATE TABLE #UserIDs (UserID BIGINT);

    -- Insert UserIDs into the temporary table
    INSERT INTO #UserIDs (UserID)
    SELECT agentuserid
    FROM Mysms.dbo.CallLog (NOLOCK)
	WHERE agentuserid IS NOT NULL
    GROUP BY agentuserid
    ORDER BY COUNT(*) DESC;
	
    -- Get the total number of rows
    SELECT @totalRows = COUNT(*) FROM #UserIDs;

-- Loop through each User_ID using a WHILE loop
    WHILE @currentRow <= @totalRows
BEGIN
BEGIN TRY

			-- Use a CTE to calculate ROW_NUMBER() and select the current UserID
				WITH CTE_UserIDs AS (
					SELECT UserID, ROW_NUMBER() OVER (ORDER BY UserID) AS RowNum
					FROM #UserIDs
				)
				SELECT @userid = UserID
				FROM CTE_UserIDs
				WHERE RowNum = @currentRow;

   
			Declare @UserId_para BIGINT = @userid, 
					@fromdate DATE = NULL,       
					@todate   DATE = NULL; 

			Declare @Currentdate  DATE  = GETDATE();  -- Today's date
			SET @fromdate      = DATEADD(DAY, -9130, @Currentdate); -- 30 days before today
			SET @todate  = @Currentdate;
		
			-- Only process if the UserID has not been processed already
            IF NOT EXISTS (
                SELECT 1 
                FROM MySMSReportCache.dbo.tbl_CallReportDashboardCount_Archive (NOLOCK)
                WHERE UserId = @userid
            )
            BEGIN

			DECLARE @OutgoingCount INT = 0
			,@IncomingCount INT = 0
			,@MissedByAgentCount INT = 0
			,@AnsweredByAgentCount INT = 0
			,@MissedByClientCount INT = 0
			,@AnsweredByClientCount INT = 0
			,@TimeoutCallCount INT = 0
			,@TotalAgentDurationOutgoing INT = 0
			,@TotalAgentDurationIncoming INT = 0


			drop table if exists #tempUsers123
			create table #tempUsers123(User_ID bigint, Name nvarchar(255), Image nvarchar(255))
			insert into #tempUsers123(User_ID, Name, Image)
			exec Use_GetUserDetails @UserID = @userid

					DECLARE @ParentId BIGINT, @isadmin INT;

						SELECT @parentid = ParentID, @isadmin = IsAdmin FROM Mysms.dbo.User_Detail(NOLOCK) WHERE User_ID = @userid;

				SELECT @OutgoingCount = Count(*)
						FROM calendar(NOLOCK) ca
						LEFT JOIN CallLog(NOLOCK) c ON try_cast(c.callcreatedon AS DATE) = try_cast(ca.start_dts AS DATE)
						--inner JOIN #tempUsers123(nolock) u on c.agentuserid = u.User_Id
						WHERE TRY_CAST(ca.start_dts as date) between TRY_CAST(@fromdate as date) AND TRY_CAST(@todate as date) AND
						   c.parentid = @ParentId
							AND c.Direction IN ('Outgoing', 'out')
							AND 1 = (
								CASE 
									WHEN @isadmin = 1
										THEN 1
									WHEN isnull(c.agentuserid, 0) IN ( select USER_ID  from #tempUsers123)
										THEN 1
									WHEN isnull(c.agentuserid, 0) = @userid
										THEN 1
									ELSE 0
									END
								)

						SELECT @IncomingCount = Count(*)
						FROM calendar(NOLOCK) ca
						LEFT JOIN CallLog(NOLOCK) c ON try_cast(c.callcreatedon AS DATE) = try_cast(ca.start_dts AS DATE)
						--inner JOIN #tempUsers123(nolock) u on c.agentuserid = u.User_Id 
						WHERE cast(start_dts as date) between cast(@fromdate as date) AND cast(@todate as date) AND
							 c.parentid = @ParentId
							AND c.Direction = 'Incoming'
							AND 1 = (
								CASE 
									WHEN @isadmin = 1
										THEN 1
									WHEN isnull(c.agentuserid, 0) IN ( select USER_ID  from #tempUsers123)
										THEN 1
									WHEN isnull(c.agentuserid, 0) = @userid
										THEN 1
									ELSE 0
									END
								)

						SELECT @AnsweredByAgentCount = Count(*)
						FROM calendar(NOLOCK) ca
						LEFT JOIN CallLog(NOLOCK) c ON try_cast(c.callcreatedon AS DATE) = try_cast(ca.start_dts AS DATE)
						--inner JOIN #tempUsers123(nolock) u on c.agentuserid = u.User_Id
						WHERE cast(start_dts as date) between cast(@fromdate as date) AND cast(@todate as date) AND
							 c.parentid = @ParentId
							AND c.Direction = 'Incoming'
							AND isnull(c.agentcalldisposition, '') IN ( 'ANSWERED', 'ANSWER')
							AND 1 = (
								CASE 
									WHEN @isadmin = 1
										THEN 1
									WHEN isnull(c.agentuserid, 0) IN ( select USER_ID  from #tempUsers123)
										THEN 1
									WHEN isnull(c.agentuserid, 0) = @userid
										THEN 1
									ELSE 0
									END
								)

						SELECT @MissedByAgentCount = Count(*)
						FROM calendar(NOLOCK) ca
						INNER JOIN CallLog(NOLOCK) c ON try_cast(c.callcreatedon AS DATE) = try_cast(ca.start_dts AS DATE)
						--inner JOIN #tempUsers123(nolock) u on c.agentuserid = u.User_Id
						WHERE cast(start_dts as date) between cast(@fromdate as date) AND cast(@todate as date) AND
							 c.parentid = @ParentId
							AND c.Direction = 'Incoming'
							AND isnull(c.agentcalldisposition, '') NOT IN ( 'ANSWERED', 'ANSWER') --'ANSWERED'
							And isnull(c.Agentnumber, '') <> ''
							AND 1 = (
								CASE 
									WHEN @isadmin = 1
										THEN 1
									WHEN isnull(c.agentuserid, 0) IN ( select USER_ID  from #tempUsers123)
										THEN 1
									WHEN isnull(c.agentuserid, 0) = @userid
										THEN 1
									ELSE 0
									END
								)


						SELECT @TimeoutCallCount = count(1)
						FROM calendar(NOLOCK) ca
						LEFT JOIN CallLog(NOLOCK) c ON try_cast(c.callcreatedon AS DATE) = try_cast(ca.start_dts AS DATE)
						--inner JOIN #tempUsers123(nolock) u on c.agentuserid = u.User_Id
						WHERE cast(start_dts as date) between cast(@fromdate as date) AND cast(@todate as date) AND
							 c.parentid = @ParentId
							-- AND c.Direction = 'Incoming'
							AND isnull(c.agentcalldisposition, '') NOT IN ( 'ANSWERED', 'ANSWER') --'ANSWERED'
							AND 1 = (
								CASE 
									WHEN @isadmin = 1
										THEN 1
									WHEN isnull(c.agentuserid, 0) IN ( select USER_ID  from #tempUsers123)
										THEN 1
									WHEN isnull(c.agentuserid, 0) = @userid
										THEN 1
									ELSE 0
									END
								)

						SELECT @MissedByClientCount = Count(*)
						FROM calendar(NOLOCK) ca
						LEFT JOIN CallLog(NOLOCK) c ON try_cast(c.callcreatedon AS DATE) = try_cast(ca.start_dts AS DATE)
						--inner JOIN #tempUsers123(nolock) u on c.agentuserid = u.User_Id
						WHERE cast(start_dts as date) between cast(@fromdate as date) AND cast(@todate as date) AND
							 c.parentid = @ParentId
							AND c.Direction IN ('outgoing', 'out')
							AND isnull(c.agentcalldisposition, '') IN ( 'ANSWERED', 'ANSWER')
							AND isnull(c.customercalldisposition, '') NOT IN ( 'ANSWERED', 'ANSWER')
							AND 1 = (
								CASE 
									WHEN @isadmin = 1
										THEN 1
									WHEN isnull(c.agentuserid, 0) IN ( select USER_ID  from #tempUsers123)
										THEN 1
									WHEN isnull(c.agentuserid, 0) = @userid
										THEN 1
									ELSE 0
									END
								)

						SELECT @AnsweredByClientCount = Count(*)
						FROM calendar(NOLOCK) ca
						LEFT JOIN CallLog(NOLOCK) c ON try_cast(c.callcreatedon AS DATE) = try_cast(ca.start_dts AS DATE)
						--inner JOIN #tempUsers123(nolock) u on c.agentuserid = u.User_Id
						WHERE cast(start_dts as date) between cast(@fromdate as date) AND cast(@todate as date) AND
							 c.parentid = @ParentId
							AND c.Direction IN ('outgoing', 'out')
							AND isnull(c.agentcalldisposition, '') IN ( 'ANSWERED', 'ANSWER')
							AND isnull(c.customercalldisposition, '') IN ( 'ANSWERED', 'ANSWER' )
							AND 1 = (
								CASE 
									WHEN @isadmin = 1
										THEN 1
									WHEN isnull(c.agentuserid, 0) IN ( select USER_ID  from #tempUsers123)
										THEN 1
									WHEN isnull(c.agentuserid, 0) = @userid
										THEN 1
									ELSE 0
									END
								)

						 SELECT @TotalAgentDurationOutgoing = SUM(agentduration)
						FROM calendar(NOLOCK) ca
						LEFT JOIN CallLog(NOLOCK) c ON try_cast(c.callcreatedon AS DATE) = try_cast(ca.start_dts AS DATE)
						--inner JOIN #tempUsers123(nolock) u on c.agentuserid = u.User_Id
						WHERE cast(ca.start_dts as date) between cast(@fromdate as date) AND cast(@todate as date) AND
							 c.parentid = @ParentId
							AND c.Direction IN ('Outgoing', 'out')
							AND 1 = (
								CASE 
									WHEN @isadmin = 1
										THEN 1
									WHEN isnull(c.agentuserid, 0) IN ( select USER_ID  from #tempUsers123)
										THEN 1
									WHEN isnull(c.agentuserid, 0) = @userid
										THEN 1
									ELSE 0
									END
								)

					SELECT @TotalAgentDurationIncoming = SUM(agentduration)
					FROM calendar(NOLOCK) ca
					LEFT JOIN CallLog(NOLOCK) c ON try_cast(c.callcreatedon AS DATE) = try_cast(ca.start_dts AS DATE)
					--inner JOIN #tempUsers123(nolock) u on c.agentuserid = u.User_Id
					WHERE cast(start_dts as date) between cast(@fromdate as date) AND cast(@todate as date) AND
						 c.parentid = @ParentId
						AND c.Direction = 'Incoming'
						AND 1 = (
							CASE 
								WHEN @isadmin = 1
									THEN 1
								WHEN isnull(c.agentuserid, 0) IN ( select USER_ID  from #tempUsers123)
									THEN 1
								WHEN isnull(c.agentuserid, 0) = @userid
									THEN 1
								ELSE 0
								END
							)  

				INSERT INTO MySMSReportCache.[dbo].[tbl_CallReportDashboardCount_Archive] 
				(
						   [OutgoingCount]
						  ,[IncomingCount]
						  ,[MissedByAgentCount]
						  ,[AnsweredByAgentCount]
						  ,[MissedByClientCount]
						  ,[AnsweredByClientCount]
						  ,[TimeoutCallCount]
						  ,[TotalAgentDurationOutgoing]
						  ,[TotalAgentDurationIncoming]
						  ,[UserId]
						  ,[ParentId]
					      ,[start_dts]
				)
				SELECT @OutgoingCount AS OutgoingCount
					,@IncomingCount AS IncomingCount
					,@MissedByAgentCount AS MissedByAgentCount
					,@AnsweredByAgentCount AS AnsweredByAgentCount
					,@MissedByClientCount AS MissedByClientCount
					,@AnsweredByClientCount AS AnsweredByClientCount
					,@TimeoutCallCount as TimeoutCallCount
					,@TotalAgentDurationOutgoing AS TotalAgentDurationOutgoing
					,@TotalAgentDurationIncoming AS TotalAgentDurationIncoming
					,@userid AS UserId
					,@parentid AS ParentId
					,(SELECT start_dts FROM calendar(NOLOCK) WHERE try_cast(start_dts as date) = try_cast(@fromdate as date)) AS start_dts

-- Move to the next row
        END
		END TRY
		BEGIN CATCH
		exec usp_InsertErrorInfo
        END CATCH

        SET @currentRow = @currentRow + 1;
END
-- Clean up the temporary table
    DROP TABLE #UserIDs;
		
END



