							AND c.parentid = @ParentId
							AND c.Direction IN ('Outgoing', 'out')
							AND 1 = (
								CASE 
									WHEN @isadmin = 1
										THEN 1
									WHEN isnull(c.agentuserid, 0) IN ( select USER_ID  from #tempUsers123)
										THEN 1
									WHEN isnull(c.agentuserid, 0) = @userid
										THEN 1
									ELSE 0
									END
								)

					SELECT @TotalAgentDurationIncoming = SUM(agentduration)
					FROM calendar(NOLOCK) ca
					LEFT JOIN CallLog(NOLOCK) c ON TRY_CAST(c.callcreatedon AS DATE) = TRY_CAST(ca.start_dts AS DATE)
					--inner JOIN #tempUsers123(nolock) u on c.agentuserid = u.User_Id
					WHERE TRY_CAST(start_dts as date) between TRY_CAST(@fromdate as date) AND TRY_CAST(@todate as date)
						AND c.parentid = @ParentId
						AND c.Direction = 'Incoming'
						AND 1 = (
							CASE 
								WHEN @isadmin = 1
									THEN 1
								WHEN isnull(c.agentuserid, 0) IN ( select USER_ID  from #tempUsers123)
									THEN 1
								WHEN isnull(c.agentuserid, 0) = @userid
									THEN 1
								ELSE 0
								END
							)  

				INSERT INTO MySMSReportCache.[dbo].[tbl_CallReportDashboardCount_Cache] 
				(
						   [OutgoingCount]
						  ,[IncomingCount]
						  ,[MissedByAgentCount]
						  ,[AnsweredByAgentCount]
						  ,[MissedByClientCount]
						  ,[AnsweredByClientCount]
						  ,[TimeoutCallCount]
						  ,[TotalAgentDurationOutgoing]
						  ,[TotalAgentDurationIncoming]
						  ,[UserId]
						  ,[ParentId]
						  ,[start_dts]
				)
				SELECT @OutgoingCount AS OutgoingCount
					,@IncomingCount AS IncomingCount
					,@MissedByAgentCount AS MissedByAgentCount
					,@AnsweredByAgentCount AS AnsweredByAgentCount
					,@MissedByClientCount AS MissedByClientCount
					,@AnsweredByClientCount AS AnsweredByClientCount
					,@TimeoutCallCount as TimeoutCallCount
					,@TotalAgentDurationOutgoing AS TotalAgentDurationOutgoing
					,@TotalAgentDurationIncoming AS TotalAgentDurationIncoming
					,@userid AS UserId
					,@parentid AS ParentId
					,(SELECT start_dts FROM calendar(NOLOCK) WHERE TRY_CAST(start_dts as date) = TRY_CAST(@fromdate as date)) AS start_dts

				INSERT INTO MySMSReportCache.[dbo].[tbl_CallReportDashboardCount_Archive] 
				(
						   [OutgoingCount]
						  ,[IncomingCount]
						  ,[MissedByAgentCount]
						  ,[AnsweredByAgentCount]
						  ,[MissedByClientCount]
						  ,[AnsweredByClientCount]
						  ,[TimeoutCallCount]
						  ,[TotalAgentDurationOutgoing]
						  ,[TotalAgentDurationIncoming]
						  ,[UserId]
						  ,[ParentId]
					     ,[start_dts]
				)
				SELECT @OutgoingCount AS OutgoingCount
					,@IncomingCount AS IncomingCount
					,@MissedByAgentCount AS MissedByAgentCount
					,@AnsweredByAgentCount AS AnsweredByAgentCount
					,@MissedByClientCount AS MissedByClientCount
					,@AnsweredByClientCount AS AnsweredByClientCount
					,@TimeoutCallCount as TimeoutCallCount
					,@TotalAgentDurationOutgoing AS TotalAgentDurationOutgoing
					,@TotalAgentDurationIncoming AS TotalAgentDurationIncoming
					,@userid AS UserId
				  ,@parentid AS ParentId
					,(SELECT start_dts FROM calendar(NOLOCK) WHERE TRY_CAST(start_dts as date) = TRY_CAST(@fromdate as date)) AS start_dts

-- END		
END TRY
BEGIN CATCH
exec usp_InsertErrorInfo
END CATCH
-- Move to the next row
        SET @currentRow = @currentRow + 1;
END

			DELETE FROM MySMSReportCache.[dbo].[tbl_CallReportDashboardCount_Cache]
			WHERE [start_dts] NOT BETWEEN DATEADD(DAY, -30, TRY_CAST(GETDATE() AS DATE)) AND TRY_CAST(GETDATE() AS DATE);


-- Clean up the temporary table
    DROP TABLE #UserIDs;
		
END



