/* ============================================================
   Procedure: [dbo].[usp_Insert_ClientVisitDetail_DataTo_Archive]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



-- select * from MySMSReportCache.[dbo].[tbl_LocationReport_Cache]  select * from MySMSReportCache.[dbo].[tbl_LocationReport_Archive]

   --TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_LocationReport_Cache];  TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_LocationReport_Archive];

-- exec [dbo].[usp_Insert_ClientVisitDetail_DataTo_Archive]

CREATE   PROCEDURE [dbo].[usp_Insert_ClientVisitDetail_DataTo_Archive] 

AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	SET NOCOUNT ON;

	DECLARE @userid BIGINT;
    DECLARE @currentRow INT = 1;  -- Variable to track the current row in the temporary table
    DECLARE @totalRows INT;       -- Variable to store the total number of rows to process

    -- Create a temporary table to store the User IDs
    CREATE TABLE #UserIDs (UserID BIGINT);

    -- Insert UserIDs into the temporary table
    INSERT INTO #UserIDs (UserID)
    SELECT AssignedTo
    FROM Mysms.dbo.TBL_ET_PhysicalAppointment (NOLOCK)
	WHERE AssignedTo IS NOT NULL
    GROUP BY AssignedTo
    ORDER BY COUNT(*) DESC;
	
    -- Get the total number of rows
    SELECT @totalRows = COUNT(*) FROM #UserIDs;
	
-- Loop through each User_ID using a WHILE loop
    WHILE @currentRow <= @totalRows
BEGIN
BEGIN TRY
			-- Use a CTE to calculate ROW_NUMBER() and select the current UserID
				WITH CTE_UserIDs AS (
					SELECT UserID, ROW_NUMBER() OVER (ORDER BY UserID) AS RowNum
					FROM #UserIDs
				)
				SELECT @userid = UserID
				FROM CTE_UserIDs
				WHERE RowNum = @currentRow;

   
			Declare 
					@fromdate DATE = NULL,       
					@todate   DATE = NULL,
					@Offset int = 0,
					@PageSize int = 100000, 
					@SearchText varchar(200) = '',
					@UserIds nvarchar(max) = ''; 


			Declare @Currentdate  DATE  = GETDATE();  -- Today's date
			--SET @fromdate      = DATEADD(DAY, -30, @Currentdate); -- 30 days before today
			SET @fromdate  = DATEADD(DAY, -9130, @Currentdate); -- 1 day before today
			SET @todate  = @Currentdate;

			    declare @ParentId bigint , @IsAdmin bit, @StartPoint int  = 1, @Endpoint int = 100000;

				select @IsAdmin = IsAdmin, @ParentId = ParentId from User_Detail(NOLOCK) where User_ID = @UserId  
				select @StartPoint = (@Offset + 1), @Endpoint = (@PageSize + @Offset)

				drop table if exists #userTable
				create table #userTable( User_ID bigint,Name nvarchar(100), Image nvarchar(100) )


				declare @UserIdTeamLst varchar(500) = ''     
						declare @tbluser table (User_ID bigint,Name varchar(100), Image varchar(100))
						if(@IsAdmin = 1)
						begin
							set @UserId = 0;
							insert into #userTable
							exec Use_GetUserDetails @ParentId
						end
						else
						begin
							insert into #userTable
							exec Use_GetUserDetails @UserId
						end

						if(@SearchText = '') begin set @SearchText = '' end
						--if(@Contain = '') begin set @Contain = '' end else begin set @Contain =  ' and ' + @Contain end


						if(ISNULL(@UserIds, '') =  '') begin set @UserIds = '' end

						drop table if exists #tempSelectedUser
						create table #tempSelectedUser ( UserId bigint )
						insert into #tempSelectedUser(UserId) select [value] from string_split(@UserIds, ',')

				    DECLARE @sqlQuery NVARCHAR(MAX);

					-- Ensure the dynamic query is built correctly before adding WHERE or AND conditions
							set @sqlQuery = concat( N'select p.SNo, p.TotalRecords, ',
									  N'concat( p.FName, '' '', p.LName, '' ('', p.User_Login, '')'' ) AssignedToName, ',
									  N'p.User_Login,  isnull(p.FName,'''') + '' '' + isnull(p.LName,'''')  as [UserFullName] ,',
									  N'( dbo.udf_GetTerritoryDefination(p.AssignedTo) ) AS [TerritoryDefination], ',
									  N'p.User_Id, p.PhysicalAppointmentId, p.Title, p.Description, p.Address, p.CompleteAddress, ',
									  N'format( p.StartDate, ''dd-MMM-yyyy HH:mm'' ) as [StartDate], ',
									  N'format( p.EndDate, ''dd-MMM-yyyy HH:mm'' ) as [EndDate], ',
									  N'isnull(p.OutcomesId, 0) OutcomesId, isnull(uom.OutcomeName, '''') as [OutcomeName], ',
									  N'isnull(uom.Indent, '''') as [OutcomeIntent], isnull(p.Status, '''') PhyStatus, ',
									  N'p.Image, p.ProfilePictureName, p.Remarks as [PhyRemarks], ',
									  N'coalesce( tege.GeoEntityName, tegs.GeoEntitySiteName ) as [GeoEntitySiteName], ',
									  N'tegs.GeoEntitySiteId as [GeoEntitySiteId], tegs.Latitude as [SiteLatitude], ',
									  N'tegs.Longitude as [SiteLongitude],  tegs.MapAddress as [SiteMapAddress], ',
									  N'tegs.Address as [SiteAddress],  tegs.City as [SiteCity], ',
									  N'tegs.State as [SiteState],  tegs.Country as [SiteCountry], ',
									  N'tege.Mobile as [MobileNo], ',
									  N'tege.EmailId as [EmailId], ',
									  N'tegs.PinCode as [SitePinCode],  tege.GeoEntityType as [SiteGeoEntityType], ',
									  N'dbo.fn_TBL_ET_PhysicalCollebratorUM_PhyId( p.PhysicalAppointmentId, ''Collaborator'' ) Collaboratorlist, ',
									  N'dbo.fn_TBL_ET_PhysicalCollebratorUM_PhyId( p.PhysicalAppointmentId, ''FieldExecutive'' ) FieldExecutivelist, ',
									  N'FORMAT( cast( ( case when p.CheckIn != '''' then p.CheckIn else p.CheckOut end ) as datetime ),  ''dd-MM-yyyy'' ) TravelDate, ',
									  N'format( p.CheckIn, ''dd-MMM-yyyy HH:mm'' ) as [CheckIn], ',
									  N'format( p.CheckOut, ''dd-MMM-yyyy HH:mm'' ) as [CheckOut], ',
									  N'tege.EntityId as [SiteGeoEntityId], ',
									  N'case when '+cast(@pagesize as nvarchar)+'>20 then ''{}'' else isnull( dbo.udf_et_GetPhyAppointmentTravelData( p.AssignedTo, ',
									  N'( case when p.CheckIn != '''' then p.CheckIn else p.CheckOut end ), p.PhysicalAppointmentId ), ''{}'' ) end as [TravelData], ',
									  N'( case when isnull(p.CheckIn, '''') = '''' or '+cast(@pagesize as nvarchar)+'>20 then ''{}'' ',
									  N'else dbo.udf_GetClosestUserLocation( p.AssignedTo, cast(p.CheckIn as datetime) ) end ) as [LocationInfo], ',
									  N'isnull(tege.GeoEntityType, '''') EntityType ',
									N'from ( select t.SNo, t.TotalRecords, ',
										N't.GeoEntitySiteId, t.CheckIn, t.CheckOut, t.Address, t.AssignedTo, t.CompleteAddress, ',
										N't.Description, t.EndDate, t.OutcomesId, t.PhysicalAppointmentId, t.Remarks, t.StartDate, ',
										N't.Status, t.Title, t.FName, t.Image, t.LName, t.ProfilePictureName, t.User_Id, t.User_Login ',
									N'from ( select ',
											N'row_number() over(partition by ud.ParentId order by tepa.PhysicalAppointmentId desc) as SNo, ',
											N'count(tepa.AssignedTo) over() as TotalRecords, ',
											N'geci.CheckIn, geci.CheckOut, tepa.GeoEntitySiteId, tepa.Address, tepa.AssignedTo, tepa.CompleteAddress, tepa.Description, ',
											N'tepa.EndDate, tepa.OutcomesId, tepa.PhysicalAppointmentId, tepa.Remarks, tepa.StartDate, tepa.Status, tepa.Title, ud.FName, ud.Image, ',
											N'ud.LName, ud.ProfilePictureName, ud.User_Id, ud.User_Login ',
									N'from TBL_ET_PhysicalAppointment(nolock) tepa ',
										N'inner join #userTable tu on tepa.AssignedTo = tu.User_Id ',
										iif(LEN(@UserIds) > 0, 'inner join #tempSelectedUser  su on tepa.AssignedTo = su.UserId ', ''),
										N'inner join TBL_ET_GeoEntityCheckInOut(nolock) geci on tepa.PhysicalAppointmentId = geci.PhysicalAppointmentId ',
										N'inner join User_Detail(nolock) ud on tepa.AssignedTo = ud.User_ID ',
									N'where ( ( cast(geci.CheckIn as date) between cast(''',@FromDate, ''' as date) and cast(''', @ToDate,''' as date)) ',
										N'or ( cast(geci.CheckOut as date) between cast(''',@FromDate, ''' as date) and cast(''', @ToDate,''' as date)) ',
										N')  and (  ud.User_Login like ''%', @SearchText, '%'' ',
										N'or ud.FName like ''%', @SearchText, '%'' or ud.LName like ''%', @SearchText, '%'' or tepa.Title like ''%', @SearchText, '%'' ',
									N')) t where t.SNo between ', @StartPoint, ' and ', @Endpoint, ' ) p ',
									N'left join TBL_ET_GeoEntitySiteMaster(nolock) tegs on p.GeoEntitySiteId = tegs.GeoEntitySiteId ',
									N'left join TBL_ET_GeoEntityMaster(nolock) tege on tegs.GeoEntityId = tege.GeoEntityId ',
									N'left join tbl_tsk_UserOutcomeMaster(nolock) uom on p.OutcomesId = uom.Id ',
									N'order by p.SNo asc ')

					drop table if exists #TempLocationReport
					CREATE TABLE #TempLocationReport (
								SNo INT,
								TotalRecords INT,
								AssignedToName NVARCHAR(MAX),
								User_Login NVARCHAR(MAX),
								UserFullName NVARCHAR(MAX),
								TerritoryDefination NVARCHAR(MAX),
								User_Id INT,
								PhysicalAppointmentId INT,
								Title NVARCHAR(MAX),
								Description NVARCHAR(MAX),
								Address NVARCHAR(MAX),
								CompleteAddress NVARCHAR(MAX),
								StartDate DateTime,
								EndDate DateTime,
								OutcomesId INT,
								OutcomeName NVARCHAR(MAX),
								OutcomeIntent NVARCHAR(MAX),
								PhyStatus NVARCHAR(MAX),
								Image NVARCHAR(MAX),
								ProfilePictureName NVARCHAR(MAX),
								PhyRemarks NVARCHAR(MAX),
								GeoEntitySiteName NVARCHAR(MAX),
								GeoEntitySiteId INT,
								SiteLatitude NVARCHAR(MAX),
								SiteLongitude NVARCHAR(MAX),
								SiteMapAddress NVARCHAR(MAX),
								SiteAddress NVARCHAR(MAX),
								SiteCity NVARCHAR(MAX),
								SiteState NVARCHAR(MAX),
								SiteCountry NVARCHAR(MAX),
								MobileNo NVARCHAR(MAX),
								EmailId NVARCHAR(MAX),
								SitePinCode NVARCHAR(MAX),
								SiteGeoEntityType NVARCHAR(MAX),
								Collaboratorlist NVARCHAR(MAX),
								FieldExecutivelist NVARCHAR(MAX),
								TravelDate DateTime,
								CheckIn DateTime,
								CheckOut DateTime,
								SiteGeoEntityId INT,
								TravelData NVARCHAR(MAX),
								LocationInfo NVARCHAR(MAX),
								EntityType NVARCHAR(MAX)
							);

					INSERT INTO #TempLocationReport
					EXEC sp_executesql @sqlQuery;

			IF NOT EXISTS ( 
				SELECT 1 
				FROM MySMSReportCache.[dbo].[tbl_LocationReport_Archive] (NOLOCK)
				WHERE UserId = @userid
			)
			BEGIN
				-- start data insert into archive table
			
				INSERT INTO MySMSReportCache.[dbo].[tbl_LocationReport_Archive] 
				(		   
						   [TravelDate]
						  ,[SNo]
						  ,[TotalRecords]
						  ,[AssignedToName]
						  ,[UserFullName]
						  ,[User_Login]
						  ,[PhysicalAppointmentId]
						  ,[Title]
						  ,[Description]
						  ,[Address]
						  ,[CompleteAddress]
						  ,[StartDate]
						  ,[EndDate]
						  ,[OutcomeName]
						  ,[OutcomeIntent]
						  ,[PhyRemarks]
						  ,[GeoEntitySiteId]
						  ,[GeoEntitySiteName]
						  ,[SiteLatitude]
						  ,[SiteLongitude]
						  ,[SiteMapAddress]
						  ,[SiteAddress]
						  ,[SiteCity]
						  ,[SiteState]
						  ,[SiteCountry]
						  ,[MobileNo]
						  ,[EmailId]
						  ,[SitePinCode]
						  ,[SiteGeoEntityType]
						  ,[SiteGeoEntityId]
						  ,[TerritoryDefination]
						  ,[TravelData]
						  ,[LocationInfo]
						  ,[CheckIn]
						  ,[CheckOut]
						  ,[UserId]
						  ,OutcomesId
						  ,PhyStatus
						  ,Image
						  ,ProfilePictureName
						  ,Collaboratorlist
						  ,FieldExecutivelist
						  ,EntityType
						  ,[ParentId]
				)
				  SELECT 
						TravelDate,
						SNo,
						TotalRecords,
						AssignedToName,
						UserFullName,
						User_Login,
						PhysicalAppointmentId,
						Title,
						Description,
						Address,
						CompleteAddress,
						StartDate,
						EndDate,
						OutcomeName,
						OutcomeIntent,
						PhyRemarks,
						GeoEntitySiteId,
						GeoEntitySiteName,
						SiteLatitude,
						SiteLongitude,
						SiteMapAddress,
						SiteAddress,
						SiteCity,
						SiteState,
						SiteCountry,
						MobileNo,
						EmailId,
						SitePinCode,
						SiteGeoEntityType,
						SiteGeoEntityId,
						TerritoryDefination,
						TravelData,
						LocationInfo,
						CheckIn,
						CheckOut,
						@userid
						,OutcomesId
						  ,PhyStatus
						  ,Image
						  ,ProfilePictureName
						  ,Collaboratorlist
						  ,FieldExecutivelist
						  ,EntityType,
						  @ParentId
					FROM #TempLocationReport;   
					
				-- end data insert into archive table

			-- Clean up the temporary table
				DROP TABLE #TempLocationReport;

END
END TRY
BEGIN CATCH
exec usp_InsertErrorInfo
END CATCH

-- Move to the next row
        SET @currentRow = @currentRow + 1;
END

-- Clean up the temporary table
    DROP TABLE #UserIDs;
		
END



