								Address NVARCHAR(MAX),
								CompleteAddress NVARCHAR(MAX),
								StartDate DateTime,
								EndDate DateTime,
								OutcomesId INT,
								OutcomeName NVARCHAR(MAX),
								OutcomeIntent NVARCHAR(MAX),
								PhyStatus NVARCHAR(MAX),
								Image NVARCHAR(MAX),
								ProfilePictureName NVARCHAR(MAX),
								PhyRemarks NVARCHAR(MAX),
								GeoEntitySiteName NVARCHAR(MAX),
								GeoEntitySiteId INT,
								SiteLatitude NVARCHAR(MAX),
								SiteLongitude NVARCHAR(MAX),
								SiteMapAddress NVARCHAR(MAX),
								SiteAddress NVARCHAR(MAX),
								SiteCity NVARCHAR(MAX),
								SiteState NVARCHAR(MAX),
								SiteCountry NVARCHAR(MAX),
								MobileNo NVARCHAR(MAX),
								EmailId NVARCHAR(MAX),
								SitePinCode NVARCHAR(MAX),
								SiteGeoEntityType NVARCHAR(MAX),
								Collaboratorlist NVARCHAR(MAX),
								FieldExecutivelist NVARCHAR(MAX),
								TravelDate DateTime,
								CheckIn DateTime,
								CheckOut DateTime,
								SiteGeoEntityId INT,
								TravelData NVARCHAR(MAX),
								LocationInfo NVARCHAR(MAX),
								EntityType NVARCHAR(MAX)
							);

					INSERT INTO #TempLocationReport
					EXEC sp_executesql @sqlQuery;

			--IF NOT EXISTS ( 
			--	SELECT 1 
			--	FROM MySMSReportCache.[dbo].[tbl_LocationReport_Cache] (NOLOCK)
			--	WHERE UserId = @userid and TRY_CAST(CheckIn as Date) between @fromdate and @todate and TRY_CAST(CheckOut as Date) between @fromdate and @todate
			--)
			--BEGIN
			    -- start data insert into cache tables

				INSERT INTO MySMSReportCache.[dbo].[tbl_LocationReport_Cache] 
				(		   
						   [TravelDate]
						  ,[SNo]
						  ,[TotalRecords]
						  ,[AssignedToName]
