						,OutcomesId
						  ,PhyStatus
						  ,Image
						  ,ProfilePictureName
						  ,Collaboratorlist
						  ,FieldExecutivelist
						  ,EntityType,
						  @ParentId
					FROM #TempLocationReport;  
					
				-- end data insert into cache tables

				-- start data insert into archive table
			
				INSERT INTO MySMSReportCache.[dbo].[tbl_LocationReport_Archive] 
				(		   
