/* ============================================================
   Procedure: [dbo].[usp_Insert_ClientVisitSummary_DataTo_Archive]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON




-- select * from MySMSReportCache.[dbo].[tbl_ClientVisitReport_Cache]  select * from MySMSReportCache.[dbo].[tbl_ClientVisitReport_Archive]

   --TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_ClientVisitReport_Cache];  TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_ClientVisitReport_Archive];

-- exec [dbo].[usp_Insert_ClientVisitSummary_DataTo_Archive]

CREATE   PROCEDURE [dbo].[usp_Insert_ClientVisitSummary_DataTo_Archive] 

AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	SET NOCOUNT ON;

	DECLARE @userid BIGINT;
    DECLARE @currentRow INT = 1;  -- Variable to track the current row in the temporary table
    DECLARE @totalRows INT;       -- Variable to store the total number of rows to process

    -- Create a temporary table to store the User IDs
    CREATE TABLE #UserIDs (UserID BIGINT);

    -- Insert UserIDs into the temporary table
    INSERT INTO #UserIDs (UserID)
    SELECT ParentId
    FROM Mysms.dbo.TBL_ET_PhysicalAppointment (NOLOCK)
	WHERE ParentId IS NOT NULL
    GROUP BY ParentId
    ORDER BY COUNT(*) DESC;
	
    -- Get the total number of rows
    SELECT @totalRows = COUNT(*) FROM #UserIDs;

-- Loop through each User_ID using a WHILE loop
    WHILE @currentRow <= @totalRows
BEGIN
BEGIN TRY
			-- Use a CTE to calculate ROW_NUMBER() and select the current UserID
				WITH CTE_UserIDs AS (
					SELECT UserID, ROW_NUMBER() OVER (ORDER BY UserID) AS RowNum
					FROM #UserIDs
				)
				SELECT @userid = UserID
				FROM CTE_UserIDs
				WHERE RowNum = @currentRow;

   
			Declare 
					@fromdate DATE = NULL,       
					@todate   DATE = NULL,
					@PageSize int = 100,
					@Offset int = 0,
					@Condition varchar(max) = '',
					@SearchText nvarchar(max) = ''; 


			Declare @Currentdate  DATE  = GETDATE();  -- Today's date
			SET @fromdate      = DATEADD(DAY, -9130, @Currentdate); -- 30 days before today
			SET @todate  = @Currentdate;
			
			--SET @fromdate  = DATEADD(DAY, -1, @Currentdate); -- 1 day before today		

			IF NOT EXISTS ( 
					SELECT 1 
					FROM MySMSReportCache.[dbo].[tbl_ClientVisitReport_Archive](NOLOCK)
					WHERE UserId = @userid
				)
				BEGIN

			    declare @ParentId bigint  
			select @ParentId = ParentID from User_Detail(nolock) u where u.User_ID = @userid  
			
			declare @StartPoint int  = (@Offset + 1), @EndPoint int  = (@Offset + @PageSize)

			drop table if exists #tempUsers  
			create table #tempUsers(User_ID bigint, Name nvarchar(255), Image nvarchar(255))  
			insert into #tempUsers(User_ID, Name, Image)  
			exec Use_GetUserDetails @UserID = @userid  


				declare @SqlQuery nvarchar(max) = concat(N'select * from ( select ',
					N'count(t.User_Id) over() as TotalRecords, ',
					N'ROW_NUMBER() over (partition by (select null) order by (select null) asc  ) as SNo, ',
					N'AssignedToName, User_Id, ',
					N'count(t.PhysicalAppointmentId) TotalAssigned, ',
					N'count(isnull(t.GeoEntityCheckId, 0)) TotalVisit, ',
					N'dbo.fn_TBL_ET_PhysicalAppointmentTypeCount(User_Id, ', 
						N'''', @FromDate, ''', ''', @ToDate, ''', ''Missed'') TotalMissed, ',
					N'dbo.fn_TBL_ET_PhysicalAppointmentTypeCount(User_Id, ', 
						N'''', @FromDate, ''', ''', @ToDate, ''', ''Pending'')  TotalPending, ',
					N' t.User_Login , ', N' t.UserFullName AS [UserFullName], ',
					N'CAST(t.CheckIn AS DATE) AS CheckIn, ',
					N'CAST(t.CheckOut AS DATE) AS CheckOut ',
				N'from ( ',
					N'select distinct tepa.PhysicalAppointmentId, ', 
					N' concat( ud.FName, '' '', ud.LName, '' ('', ud.User_Login, '')'' )  AssignedToName, ',
					 N'ud.User_Login,  isnull(ud.FName,'''') + '' '' + isnull(ud.LName,'''')  as [UserFullName] ,',
					N'ud.User_Id, tepa.Title, tepa.Description, tepa.Address, ',
					N'tepa.CompleteAddress, ',
					N'isnull(geci.GeoEntityCheckId, 0) GeoEntityCheckId, ',
					N'CAST(geci.CheckIn AS DATE) AS CheckIn, ',
					N'CAST(geci.CheckOut AS DATE) AS CheckOut ',
					N'from TBL_ET_PhysicalAppointment(nolock) tepa ',
						N'inner join #tempUsers tu on tepa.AssignedTo = tu.User_ID ',
						N'left join User_Detail(nolock) ud on tepa.AssignedTo = ud.User_ID ',
						N'left join FollowUp_Status(nolock) fuss on tepa.OutcomesId = fuss.ID ',
						N'left join TBL_ET_GeoEntityCheckInOut(nolock) geci on tepa.PhysicalAppointmentId = geci.PhysicalAppointmentId ',
						N'inner join TBL_ET_PhyAppointUserMapping(nolock) trpu on tepa.PhysicalAppointmentId = geci.PhysicalAppointmentId ',
					N'where ((cast(geci.CheckIn as date) between cast(''', @FromDate, ''' as date) and cast(''', @ToDate, ''' as date)) ',
					N'or (cast(geci.CheckOut as date) between cast(''', @FromDate, ''' as date) and cast(''', @ToDate, ''' as date))) ',
					N'and ( concat(ud.FName, '' '', ud.LName, '' ('', ud.User_Login, '')'') like ''%', @SearchText, '%'')  ',
					N' or Title like ''%', @SearchText, '%'' ) ', 
				N' t group by AssignedToName, User_Id, User_Login, UserFullName,CheckIn,CheckOut ) t where t.SNo between ', @StartPoint, ' and ', @EndPoint )

				drop table if exists #TempResult  
						CREATE TABLE #TempResult (
							TotalRecords NVARCHAR(255),
							SNo NVARCHAR(255),
							AssignedToName NVARCHAR(255),
							User_Id NVARCHAR(255),
							TotalAssigned NVARCHAR(255),
							TotalVisit NVARCHAR(255),
							TotalMissed NVARCHAR(255),
							TotalPending NVARCHAR(255),
							[User_Login] NVARCHAR(255),
							[UserFullName] NVARCHAR(255),
							CheckIn Date,
							CheckOut Date
						);

						INSERT INTO #TempResult
						EXEC sp_executesql @SqlQuery;

			    -- start data insert into cache tables

				INSERT INTO MySMSReportCache.[dbo].[tbl_ClientVisitReport_Archive] 
				(		   
						   [TotalRecords]
						  ,[SNo]
						  ,[AssignedToName]
						  ,[User_Id]
						  ,[TotalAssigned]
						  ,[TotalVisit]
						  ,[TotalMissed]
						  ,[TotalPending]
						  ,[User_Login]
						  ,[UserFullName]
						  ,[UserId]
						  ,[ParentId]
						  ,[CheckIn] 
						  ,[CheckOut]
				)
				  SELECT 
						   TotalRecords,
							SNo,
							AssignedToName,
							User_Id,
							TotalAssigned,
							TotalVisit,
							TotalMissed,
							TotalPending,
							[User_Login],
							[UserFullName],
							@userid,
							@ParentId,
							CheckIn,
							CheckOut
					FROM #TempResult;  
					
				-- end data insert into cache tables

			-- Clean up the temporary table
				DROP TABLE #TempResult;


END
END TRY
BEGIN CATCH
exec usp_InsertErrorInfo
END CATCH
-- Move to the next row
        SET @currentRow = @currentRow + 1;
END

-- Clean up the temporary table
    DROP TABLE #UserIDs;
		
END



GO

