			insert into #tempUsers(User_ID, Name, Image)  
			exec Use_GetUserDetails @UserID = @userid  


				declare @SqlQuery nvarchar(max) = concat(N'select * from ( select ',
					N'count(t.User_Id) over() as TotalRecords, ',
					N'ROW_NUMBER() over (partition by (select null) order by (select null) asc  ) as SNo, ',
					N'AssignedToName, User_Id, ',
