						N'inner join TBL_ET_PhyAppointUserMapping(nolock) trpu on tepa.PhysicalAppointmentId = geci.PhysicalAppointmentId ',
					N'where ((TRY_CAST(geci.CheckIn as date) between TRY_CAST(''', @FromDate, ''' as date) and TRY_CAST(''', @ToDate, ''' as date)) ',
					N'or (TRY_CAST(geci.CheckOut as date) between TRY_CAST(''', @FromDate, ''' as date) and TRY_CAST(''', @ToDate, ''' as date))) ',
