							TotalAssigned NVARCHAR(255),
							TotalVisit NVARCHAR(255),
							TotalMissed NVARCHAR(255),
							TotalPending NVARCHAR(255),
							[User_Login] NVARCHAR(255),
							[UserFullName] NVARCHAR(255),
							CheckIn Date,
							CheckOut Date
						);

						INSERT INTO #TempResult
						EXEC sp_executesql @SqlQuery;

			    -- start data insert into cache tables

				INSERT INTO MySMSReportCache.[dbo].[tbl_ClientVisitReport_Cache] 
				(		   
						   [TotalRecords]
						  ,[SNo]
						  ,[AssignedToName]
						  ,[User_Id]
						  ,[TotalAssigned]
						  ,[TotalVisit]
						  ,[TotalMissed]
						  ,[TotalPending]
						  ,[User_Login]
						  ,[UserFullName]
						  ,[UserId]
						  ,[ParentId]
						  ,[CheckIn] 
						  ,[CheckOut]
				)
				  SELECT 
						   TotalRecords,
							SNo,
							AssignedToName,
							User_Id,
							TotalAssigned,
							TotalVisit,
							TotalMissed,
							TotalPending,
							[User_Login],
							[UserFullName],
							@userid,
							@ParentId,
							CheckIn,
							CheckOut
					FROM #TempResult;  
					
				-- end data insert into cache tables

				INSERT INTO MySMSReportCache.[dbo].[tbl_ClientVisitReport_Archive] 
				(		   
						   [TotalRecords]
						  ,[SNo]
						  ,[AssignedToName]
						  ,[User_Id]
						  ,[TotalAssigned]
						  ,[TotalVisit]
						  ,[TotalMissed]
						  ,[TotalPending]
						  ,[User_Login]
						  ,[UserFullName]
						  ,[UserId]
						  ,[ParentId]
						  ,[CheckIn] 
						  ,[CheckOut]
				)
				  SELECT 
						   TotalRecords,
							SNo,
							AssignedToName,
							User_Id,
							TotalAssigned,
							TotalVisit,
							TotalMissed,
							TotalPending,
							[User_Login],
							[UserFullName],
							@userid,
							@ParentId,
							CheckIn,
							CheckOut
					FROM #TempResult;  

			-- Clean up the temporary table
				DROP TABLE #TempResult;


--END
END TRY
BEGIN CATCH
exec usp_InsertErrorInfo
END CATCH
-- Move to the next row
        SET @currentRow = @currentRow + 1;
END

	DELETE FROM MySMSReportCache.[dbo].[tbl_ClientVisitReport_Cache]
	WHERE TRY_CAST([CheckIn] AS DATE) NOT BETWEEN DATEADD(DAY, -30, TRY_CAST(GETDATE() AS DATE)) AND TRY_CAST(GETDATE() AS DATE)
		AND TRY_CAST([CheckOut] AS DATE) NOT BETWEEN DATEADD(DAY, -30, TRY_CAST(GETDATE() AS DATE)) AND TRY_CAST(GETDATE() AS DATE);

-- Clean up the temporary table
    DROP TABLE #UserIDs;
		
END




