CREATE   PROC [dbo].[Usp_Insert_Creditd_SMS_resellerForVoice1]                  
@m_id bigint,                    
@user_id int,   -- from bigint                 
@credits bigint                    
as                  
declare @credit bigint,@balance bigint,@default_credit bigint,@rmid bigint,@ruid bigint,@rbal bigint,@rcid bigint,@FromDate datetime,@ToDate datetime           
          
set @FromDate=getdate()          
set @ToDate=getdate()+99999           
           
set @rmid=(select m_id from reseller_detail where reseller_id=@m_id)              
set @ruid=(select user_id from reseller_detail where reseller_id=@m_id)              
set @rbal=(select top 1 balance from tbl_VoiceSmsUsers where m_id=@rmid and U_ID=@ruid order by VoiceSmsID desc)              
set @rcid=(select top 1 VoiceSmsID from tbl_VoiceSmsUsers where m_id=@rmid and U_ID=@ruid order by VoiceSmsID desc)              
                
set @balance=(select top 1 balance from tbl_VoiceSmsUsers where m_id=@m_id and U_ID=@user_id order by VoiceSmsID desc)                  
set @default_credit=(select top 1 Default_Credits from tbl_VoiceSmsUsers where m_id=@m_id and U_ID=@user_id order by VoiceSmsID desc)                  
set @balance=sum(isnull(@balance,0)+@credits)             
            
if(@rbal<@credits)            
begin            
select 'Insufficient Balance'            
end            
else            
begin            
insert into tbl_VoiceSmsUsers (m_id,U_ID,VoiceSmsCredits,Balance,Validity,Default_Credits,FromDate,ToDate) values(@m_id,@user_id,@credits,@balance,99999,@default_credit,@FromDate,@ToDate)                  
update tbl_VoiceSmsUsers set Balance=@rbal-@credits where m_id=@rmid and U_ID=@ruid and VoiceSmsID=@rcid             
select 'Voice Balance Credited Successfully.'            
end



