/* ============================================================
   Procedure: [dbo].[USP_insert_Custom_Field]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[USP_insert_Custom_Field] (      
 @parentID BIGINT      
 ,@fieldname VARCHAR(100)      
 ,@datatype VARCHAR(1)      
 ,@min SQL_VARIANT      
 ,@max SQL_VARIANT      
 ,@default SQL_VARIANT      
 ,@active VARCHAR(10)      
 ,@mand VARCHAR(10)      
 ,@quick VARCHAR(10)      
 ,@currentdate_ VARCHAR(10)      
 ,@tooltip NVARCHAR(500) = NULL      
 ,@choices NVARCHAR(max) = NULL      
 ,@PDependencyJson nvarchar(max) =null      
 ,@CDependencyJson nvarchar(max) =null,      
 @PCFieldId bigint=0,      
 @CPFieldId bigint=0,    
 @formulaId int=0,    
 @ParamList NVARCHAR(1000) = NULL    
      
 )      
AS      
BEGIN      
 SET NOCOUNT ON;      
      
 DECLARE @seq SMALLINT;      
      
 SELECT @seq = isnull(MAX(sequence), 0) + 1      
 FROM customfields      
 WHERE ParentID = @parentID      
      
 -- if(@min='0')                      
 -- begin            
 -- set @min=null                      
 -- end            
 --if(@max='0')                      
 --begin            
 --set @max=null                      
 --end            
if(@default='0' and @datatype not in ( 'f'))                      
  begin            
 set @default=null                 
 end            
 IF (@currentdate_ = '0')      
 BEGIN      
  SET @currentdate_ = NULL      
 END      
      
 IF (@quick = 'True')      
 BEGIN      
  SET @active = 'True'      
 END      
      
 INSERT INTO customfields (      
  parentID      
  ,fieldname      
  ,datatype      
  ,sequence      
  ,minvalue      
  ,maxvalue      
  ,defaultValue      
  ,isActive      
  ,isMandatory      
  ,quickAdd      
  ,currentDate      
  ,tooltip      
  ,choices    
  ,formulaId    
  ,ParamList    
  --,DependencyJson      
  --,ParentFieldId      
  )      
 VALUES (      
  @parentID      
  ,@fieldname      
  ,@datatype      
  ,@seq      
  ,@min      
  ,@max      
  ,@default      
  ,@active      
  ,@mand      
  ,@quick      
  ,@currentdate_      
  ,@tooltip      
  ,@choices      
   ,@formulaId    
   ,@ParamList    
  --,@PFieldId      
  )      
      
 DECLARE @id BIGINT = Scope_identity()      
 if(@PDependencyJson !='')      
 begin      
 drop table if exists #TempTable      
 SELECT * into #TempTable FROM OPENJSON(@PDependencyJson) WITH (      
 FieldId BIGINT '$.FieldId',      
 ParentChildMapping nvarchar(max) '$.ParentChildMapping' as json      
)      
      
   UPDATE y      
   SET y.DependencyJson = t.ParentChildMapping,      
   y.ParentFieldId=@id      
   FROM customfields y      
   JOIN #TempTable t ON y.field_ID = t.FieldId       
   end      
      
   if(@CDependencyJson!='')      
   begin      
   SET @CDependencyJson = replace(@CDependencyJson, '"data":', '')      
      
      
      
  --update customfields set ParentFieldId=@id,DependencyJson=@PDependencyJson where field_ID=@PCFieldId      
        
        
   update customfields set ParentFieldId=@CPFieldId,DependencyJson=@CDependencyJson where field_ID=@id      
   end      
      
      
 DECLARE @rowJson NVARCHAR(MAX) = (      
   SELECT *      
   FROM customfields      
   WHERE field_ID = @id      
   FOR JSON AUTO      
    ,INCLUDE_NULL_VALUES      
   )      
      
 EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @User_id = @parentID      
  ,@Activity_type = 'Inst_Custfld'      
  ,@ActionType = 'I'      
  ,@RowJson = @rowJson      
  ,@Table_name = 'customfields'      
  
  select @id as ID  
  
END 




GO

/* ============================================================
   Procedure: [dbo].[usp_Insert_CustomDashboard]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--exec [usp_Insert_CustomDashboard]
CREATE   PROCEDURE [dbo].[usp_Insert_CustomDashboard]
AS              
BEGIN 

DECLARE @userid BIGINT;
DECLARE @Id INT;
DECLARE @currentRow INT = 1;  -- Variable to track the current row in the temporary table
DECLARE @totalRows INT;       -- Variable to store the total number of rows to process

-- Drop the temporary table if it exists
DROP TABLE IF EXISTS #UserIDs;

-- Create a temporary table to store the User IDs and their respective Ids
CREATE TABLE #UserIDs (RowID INT IDENTITY(1,1), Id INT, UserID BIGINT);

-- Insert Id and UserID into the temporary table
INSERT INTO #UserIDs (Id, UserID)
SELECT DISTINCT Id, userid
FROM tbl_cd_users (NOLOCK)
WHERE userid IS NOT NULL AND IsDelete = 0;

-- Get the total number of rows
SELECT @totalRows = COUNT(*) FROM #UserIDs;

-- Create a table variable to capture the OUTPUT data
DECLARE @InsertedData TABLE (Id INT, CustomDashboardOrder INT);

-- Loop through each UserID using a WHILE loop
WHILE @currentRow <= @totalRows
BEGIN
    -- Retrieve the current Id and UserID based on the RowID
    SELECT @Id = Id, @userid = UserID
    FROM #UserIDs
    WHERE RowID = @currentRow;

    -- Insert data into tbl_cd_CustomDashboard_Predifine and capture the ID
    INSERT INTO tbl_cd_CustomDashboard_Predifine (CustomDashboard, UserId, IsPredifine, IsVisible, CustomDashboardOrder, IsActive, IsDelete,PreCustomDashboard)
    OUTPUT INSERTED.Id, INSERTED.Id INTO @InsertedData (Id, CustomDashboardOrder)
    SELECT 
        CustomDashboard,
        UserId,
        0 AS IsPredifine,
        1 AS IsVisible,
        NULL AS CustomDashboardOrder, -- Placeholder, updated after insertion
        IsActive,
        IsDelete,
		CustomDashboard
    FROM 
        tbl_cd_users
    WHERE 
        IsDelete = 0 AND UserId = @userid AND Id = @Id;

    -- Update the inserted row with its own ID for CustomDashboardOrder
    UPDATE tbl_cd_CustomDashboard_Predifine
    SET CustomDashboardOrder = Id
    WHERE Id IN (SELECT Id FROM @InsertedData);

    -- Update tbl_cd_TilesMaster
    UPDATE tbl_cd_TilesMaster
    SET CustomDashboardId = (SELECT Id FROM @InsertedData)
    WHERE UserId = @userid 
      AND CustomDashboardId = @Id;

    -- Clear the table variable for the next iteration
    DELETE FROM @InsertedData;

    -- Increment the current row counter
    SET @currentRow = @currentRow + 1;
END;

-- Uncomment below to verify the inserted data
-- SELECT * FROM tbl_cd_CustomDashboard_Predifine;

-- truncate table tbl_cd_CustomDashboard_Predifine 
END



GO

/* ============================================================
   Procedure: [dbo].[usp_Insert_DailyEnquiryReport_DataTo_Archive]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


   -- select * from MySMSReportCache.[dbo].[tbl_DailyEnquiryReport_Cache]  select * from MySMSReportCache.[dbo].[tbl_DailyEnquiryReport_Archive] 

   -- TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_DailyEnquiryReport_Cache];  TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_DailyEnquiryReport_Archive];

   -- exec usp_Insert_DailyEnquiryReport_DataTo_Archive

CREATE   PROCEDURE [dbo].[usp_Insert_DailyEnquiryReport_DataTo_Archive]       

as                      
BEGIN    
SET NOCOUNT ON;

	DECLARE @userid BIGINT;
    DECLARE @currentRow INT = 1;  -- Variable to track the current row in the temporary table
    DECLARE @totalRows INT;       -- Variable to store the total number of rows to process

    -- Create a temporary table to store the User IDs
    CREATE TABLE #UserIDs (UserID BIGINT);

    -- Insert UserIDs into the temporary table
    INSERT INTO #UserIDs (UserID)
    SELECT ParentID
    FROM Mysms.dbo.UserEnquiry(NOLOCK)
	WHERE ParentID IS NOT NULL
    GROUP BY ParentID
    ORDER BY COUNT(*) DESC;
	
    -- Get the total number of rows
    SELECT @totalRows = COUNT(*) FROM #UserIDs;

-- Loop through each User_ID using a WHILE loop
    WHILE @currentRow <= @totalRows
BEGIN
BEGIN TRY

		-- Use a CTE to calculate ROW_NUMBER() and select the current UserID
				WITH CTE_UserIDs AS (
					SELECT UserID, ROW_NUMBER() OVER (ORDER BY UserID) AS RowNum
					FROM #UserIDs
				)
				SELECT @userid = UserID
				FROM CTE_UserIDs
				WHERE RowNum = @currentRow;
				
				DECLARE  @parentid bigint
						 ,@fromdate DATE          
						 ,@todate DATE 
						 ,@strCriteriaName nvarchar(max) = @userid

			 
			 Declare @Currentdate  DATE  = GETDATE();  -- Today's date
			 SET @fromdate  = DATEADD(DAY, -9130, @Currentdate); -- 1 day before today
			 SET @todate  = @Currentdate;

			 select @ParentId = ParentID from User_Detail(nolock) where User_ID = @UserId;

			 IF NOT EXISTS ( 
					SELECT 1 
					FROM MySMSReportCache.[dbo].[tbl_DailyEnquiryReport_Archive](NOLOCK)
					WHERE UserId = @userid
				)
				BEGIN
						INSERT INTO MySMSReportCache.[dbo].[tbl_DailyEnquiryReport_Archive] 
							(
							   [SourceID],
							   [Source],
							   [UserByName],
							   [Today],
							   [MTD],
							   [UserId],
							   [ParentId],
							   [Date],
							   [CreatedBy]
							)
								select distinct SourceID,isnull(Name,'') as Source,isnull(Name,'') as UserByName, isnull(dbo.fn_getDailyenquirysourcecount(a.CreatedBy, getdate(), getdate(), b.Name),0) as Today 
									, isnull(dbo.fn_getDailyenquirysourcecount(a.CreatedBy, @fromdate, getdate(), b.Name),0) as MTD 
									,@userid, @parentid, @fromdate, a.CreatedBy
									 from UserEnquiry(nolock) a
									left join usersourcesettings(nolock) b on a.SourceName=b.SourceID
									where IsActive=1 and ParentID=@Userid-- or 0=@strCriteriaName --and SourceID<>0 
									and SourceID is not null
				END

END TRY
BEGIN CATCH
exec usp_InsertErrorInfo
END CATCH
-- Move to the next row
        SET @currentRow = @currentRow + 1;
END

-- Clean up the temporary table
    DROP TABLE #UserIDs;
   
END 




GO

