/* ============================================================
   Procedure: [dbo].[usp_insert_default_MailID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC dbo.usp_insert_default_MailID @m_id BIGINT
	,@user_id INT
	,-- from bigint      
	@MailID NVARCHAR(200)
AS
BEGIN
DECLARE @activity VARCHAR(MAX) = ''  
  ,@action VARCHAR(1) = ''  
  ,@rowJson NVARCHAR(MAX) = ''  

IF EXISTS (
		SELECT 1
		FROM DefaultMailID
		WHERE m_id = @m_id
			AND user_id = @user_id
		)
BEGIN
	UPDATE DefaultMailID
	SET Mail_ID = @MailID
	WHERE m_id = @m_id
		AND user_id = @user_id

	SELECT 'MailID Updated Successfully'

	 SET @rowJson = (  
     SELECT *  
     FROM DefaultMailID  
     WHERE m_id = @m_id  
     FOR JSON AUTO  
      ,INCLUDE_NULL_VALUES  
     )  
   SET @activity = 'Updt_Mail_dflt'  
   SET @action = 'U'  
END
ELSE
BEGIN
	INSERT INTO DefaultMailID (
		m_id
		,user_id
		,Mail_ID
		,DateCreated
		)
	VALUES (
		@m_id
		,@user_id
		,@MailID
		,GETDATE()
		)

	SELECT 'MailID Set Successfully'
	 SET @rowJson = (  
     SELECT *  
     FROM DefaultMailID  
     WHERE m_id = @m_id  
     FOR JSON AUTO  
      ,INCLUDE_NULL_VALUES  
     )  
   SET @activity = 'Inst_Mail_dflt'  
   SET @action = 'I'  
	
END
 	IF @rowJson IS NOT NULL  
 BEGIN  
  EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @user_id  
   ,@Activity_type = @activity  
   ,@ActionType = @action  
   ,@RowJson = @rowJson  
   ,@Table_name = 'DefaultMailID'  
   END
END



GO

