/* ============================================================
   Procedure: [dbo].[usp_insert_default_sms_count_def]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
  
CREATE   PROC [dbo].[usp_insert_default_sms_count_def]                 
@m_id bigint,                
@user_id int,  -- frm big int 19-08-2010  
@default_credit bigint              
as              
    Declare @ParentID bigint = ( select top 1 isnull(ParentID,0) from User_Detail with(nolock) where User_ID = @user_id )    
	Declare @MID_P bigint = ( select top 1 isnull(M_ID,0) from User_Detail with(nolock) where User_ID = @ParentID )    

declare @mid nvarchar(50),@rid nvarchar(50),@credit bigint,@balance bigint,@credit_id bigint      
set @rid=(select reseller_id from reseller_detail with(nolock) where m_id=@m_id and user_id=@User_ID)           
set @credit=(select top 1 credits  from credit_details with(nolock) where m_id=@MID_P and user_id=@ParentID order by credit_id desc )      
set @balance=(select top 1 balance from credit_details with(nolock) where m_id=@MID_P and user_id=@ParentID order by credit_id desc)       
set @credit_id=(select top 1 credit_id from credit_details with(nolock) where m_id=@MID_P and user_id=@ParentID order by credit_id desc)       
  
if (@default_credit>@balance)      
begin      
select 'Default Credit Not More Then Balance'      
end      
else      
begin      
update credit_details set credits=@credit,balance=@balance,default_credit=@default_credit where m_id=@MID_P and user_id=@ParentID and credit_id=@credit_id      
select 'SMS Credit Has Been Set For Default User Registration'      
end  
  
  


GO

