/* ============================================================
   Procedure: [dbo].[usp_Insert_EmailReport_DataTo_Archive]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- select * from MySMSReportCache.[dbo].[tbl_DeliveredEmail_Archive](nolock) select * from MySMSReportCache.[dbo].[tbl_EmailReportMatrix_Archive](nolock) select * from MySMSReportCache.[dbo].[tbl_EmailReportListView_Archive](nolock) select * from MySMSReportCache.[dbo].tbl_OpenedEmailData_Archive(nolock)  select * from MySMSReportCache.[dbo].tbl_ClickedEmail_Archive(nolock) 

 -- TRUNCATE TABLE MySMSReportCache.[dbo].tbl_DeliveredEmail_Archive; TRUNCATE TABLE MySMSReportCache.[dbo].tbl_EmailReportMatrix_Archive; TRUNCATE TABLE MySMSReportCache.[dbo].tbl_EmailReportListView_Archive; TRUNCATE TABLE MySMSReportCache.[dbo].tbl_OpenedEmailData_Archive; TRUNCATE TABLE MySMSReportCache.[dbo].tbl_ClickedEmail_Archive;


-- exec [dbo].[usp_Insert_EmailReport_DataTo_Archive] 

CREATE   PROCEDURE [dbo].[usp_Insert_EmailReport_DataTo_Archive] 
	-- @parentid BIGINT
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	SET NOCOUNT ON;

	DECLARE @userid BIGINT;
    DECLARE @currentRow INT = 1;  -- Variable to track the current row in the temporary table
    DECLARE @totalRows INT;       -- Variable to store the total number of rows to process

    -- Create a temporary table to store the User IDs
    CREATE TABLE #UserIDs (UserID BIGINT);

    -- Insert UserIDs into the temporary table
    INSERT INTO #UserIDs (UserID)
    SELECT userid
    FROM Mysms.dbo.BatchEmail_Infos (NOLOCK)
    GROUP BY userid
    ORDER BY COUNT(*) DESC;

    -- Get the total number of rows
    SELECT @totalRows = COUNT(*) FROM #UserIDs;

    WHILE @currentRow <= @totalRows
BEGIN
BEGIN TRY

			-- Use a CTE to calculate ROW_NUMBER() and select the current UserID
				WITH CTE_UserIDs AS (
					SELECT UserID, ROW_NUMBER() OVER (ORDER BY UserID) AS RowNum
					FROM #UserIDs
				)
				SELECT @userid = UserID
				FROM CTE_UserIDs
				WHERE RowNum = @currentRow;

   
				Declare @parentid BIGINT = @userid, 
					@campaigntype NVARCHAR(20) =NULL,       
					@campaignname NVARCHAR(100)=NULL,       
					@fromdate DATE = NULL,       
					@todate   DATE = NULL; 

			Declare @Currentdate  DATE  = GETDATE();  -- Today's date
			SET @fromdate      = DATEADD(DAY, -9130, @Currentdate); -- 30 days before today
			SET @todate  = @Currentdate;
		

		DROP TABLE IF EXISTS #batcht;      
		DROP TABLE IF EXISTS #batch;      
		DROP TABLE IF EXISTS #invalidmails;      
		DROP TABLE IF EXISTS #sent;      
		DROP TABLE IF EXISTS #kdelivered;      
		DROP TABLE IF EXISTS #kbounced;      
		DROP TABLE IF EXISTS #kopened;      
		DROP TABLE IF EXISTS #kclicked;      
		DROP TABLE IF EXISTS #adstatus;      
		DROP TABLE IF EXISTS #abstatus;      
		DROP TABLE IF EXISTS #dateinvalidmails;      
		DROP TABLE IF EXISTS #datesent;      
		DROP TABLE IF EXISTS #datekdelivered;      
		DROP TABLE IF EXISTS #datekbounced;      
		DROP TABLE IF EXISTS #datekopened;      
		DROP TABLE IF EXISTS #datekclicked;      
		DROP TABLE IF EXISTS #dateadstatus;      
		DROP TABLE IF EXISTS #dateabstatus;      
		DROP TABLE IF EXISTS #unsubscribed;      
		DROP TABLE IF EXISTS #badmails;      
		DROP TABLE IF EXISTS #inqueue;  

		IF NOT EXISTS ( 
					SELECT 1 
					FROM MySMSReportCache.[dbo].[tbl_OpenedEmailData_Cache] (NOLOCK)
					WHERE UserId = @parentid --and TRY_CAST(Event_Date as Date) between @fromdate and @todate
				)
				BEGIN
				SELECT b.batchid, mail_source, CAST(ISNULL(scheduleddate, batchinserttime) AS DATE) AS batchinserttime,       
					COALESCE(t.cname, c.campaignname, CASE WHEN mail_source IN( 'emails', 'csv' )      
						 THEN CAST( ISNULL( scheduleddate, batchinserttime ) AS NVARCHAR(50) )+'_'+CAST(b.batchid AS NVARCHAR)      
							ELSE 'CRM_'+mail_source END ) AS campaignname,      
							   CASE WHEN t.id IS NOT NULL THEN 'Triggered Campaign'      
								 WHEN c.id IS NOT NULL AND ISNULL( c.IsScheduled, 0 )=1 THEN 'Scheduled Campaign'      
								 WHEN c.id IS NOT NULL AND ISNULL( c.IsScheduled, 0 )=0 THEN 'Event Based Campaign'      
								 WHEN mail_source IN( 'emails', 'csv') THEN 'Bulk Mail Campaign'      
								 ELSE 'CRM Mails'      
							   END AS campaigntype,       
							   CAST( ISNULL( scheduleddate, batchinserttime ) AS DATE) AS CampaignDate,       
							   TotalRecords--,Delivered,Bounced,TotalSent                      
						INTO #batcht      
						FROM Mysms.dbo.BatchEmail_Infos AS b with (nolock) JOIN Mysms.dbo.user_detail AS u with (nolock)      
						ON u.User_ID=b.UserID LEFT JOIN Mysms.dbo.usercampaignmaster AS c with (nolock)      
						ON c.ParentID=u.parentid AND b.mail_source LIKE 'campaign%' AND CAST(c.ID AS NVARCHAR)=replace(b.mail_source, 'Campaign :', '') LEFT JOIN Mysms.dbo.triggeredcampaigns AS t with (nolock)      
						ON c.eventid=t.eventid AND t.mailcampaignid=c.id      
						WHERE u.ParentID=@parentid AND CAST(ISNULL(scheduleddate, batchinserttime) AS DATE) BETWEEN @fromdate AND @todate;      

						SELECT *      
						INTO #batch      
						FROM #batcht      
						WHERE campaigntype=CASE WHEN @campaigntype IS NULL THEN campaigntype ELSE @campaigntype END      
							  AND campaignname=CASE WHEN @campaignname IS NULL THEN campaignname ELSE @campaignname END;      
      
						SELECT t.batchid, COUNT(1) AS TotalUnsubscribed      
						INTO #unsubscribed      
						FROM Mysms.dbo.tbl_subscription AS t with (nolock) JOIN #batch AS b      
						ON b.BatchID=t.batchid      
						GROUP BY t.batchid;    

						SELECT e.BatchID, COUNT(1) AS KDelivered, CAST(ISNULL(e.event_time, createdon) AS DATE) AS event_time      
						INTO #datekdelivered      
						FROM Mysms.dbo.EmailDeliveryStatus AS e with (nolock) JOIN #batch AS b      
						ON e.BatchID=b.BatchID      
						WHERE event_status='001'      
						GROUP BY e.batchid, CAST(ISNULL(e.event_time, createdon) AS DATE);  
      
						SELECT e.BatchID, sum(Kdelivered) AS KDelivered--, CAST(ISNULL(e.event_time, createdon) AS DATE) AS event_time      
						INTO #kdelivered      
						FROM #datekdelivered AS e with (nolock) JOIN #batch AS b      
						ON e.BatchID=b.BatchID      
						GROUP BY e.batchid--, CAST(ISNULL(e.event_time, createdon) AS DATE);      
      
						SELECT e.BatchID, COUNT(1) AS KBounced, try_CAST(ISNULL(try_cast(e.event_time as date), createdon) AS DATE) AS event_time      
						INTO #datekbounced      
						FROM Mysms.dbo.EmailDeliveryStatus AS e with (nolock) JOIN #batch AS b      
						ON e.BatchID=b.BatchID      
						WHERE event_status<>'001'      
						GROUP BY e.batchid, try_CAST(ISNULL(try_cast(e.event_time as date), createdon) AS DATE);         

						SELECT e.BatchID, sum(KBounced) AS KBounced--, CAST(ISNULL(e.event_time, createdon) AS DATE) AS event_time      
						INTO #kbounced      
						FROM #datekbounced AS e with (nolock) JOIN #batch AS b      
						ON e.BatchID=b.BatchID      
						GROUP BY e.batchid--, CAST(ISNULL(e.event_time, createdon) AS DATE);      

						SELECT e.batchid, COUNT(1) AS Delivered, CAST( e.createdon AS DATE ) AS createdon      
						INTO #dateadstatus      
						FROM Mysms.dbo.Maildeliveries AS e with (nolock) JOIN #batch AS b      
						ON e.BatchID=b.BatchID      
						GROUP BY e.batchid, CAST( e.createdon AS DATE )   
      
						SELECT e.batchid, COUNT( 1 ) AS bounced, CAST( e.createdon AS DATE ) AS createdon
						INTO #dateabstatus      
						FROM Mysms.dbo.Mailbounces AS e with (nolock) JOIN #batch AS b      
						ON e.BatchID=b.BatchID      
						GROUP BY e.batchid, CAST( e.createdon AS DATE )

						SELECT e.batchid, sum(delivered) AS Delivered
						INTO #adstatus      
						FROM #dateadstatus AS e with (nolock) JOIN #batch AS b      
						ON e.BatchID=b.BatchID      
						GROUP BY e.batchid
      
						SELECT e.batchid, sum(bounced) bounced--, CAST( e.createdon AS DATE ) AS createdon      
						INTO #abstatus      
						FROM #dateabstatus AS e with (nolock) JOIN #batch AS b      
						ON e.BatchID=b.BatchID      
						GROUP BY e.batchid
      
						SELECT e.batchid, 
						sum(case when tablename='EmailsReportSent' then mailcount else 0 end) AS Sent, 
						sum(case when tablename='invalid_Mail_EmailsReport' then mailcount else 0 end) AS NotSent, 
						sum(case when tablename in ('Mail_EmailsReport00','Mail_EmailsReport01','Mail_EmailsReport02','Mail_EmailsReport03',
						'Mail_EmailsReport04','Mail_EmailsReport05','Mail_EmailsReport1','Mail_EmailsReport2') then mailcount else 0 end) AS EnteredQueue, 
						sum(case when tablename='Bad_emails' then mailcount else 0 end) AS InvalidMails
						INTO #sent      
						FROM emailcountracking AS e (nolock) JOIN #batch AS b      
						ON e.BatchID=b.BatchID      
						GROUP BY e.BatchID      
      
						SELECT e.batchid, COUNT( e.customer_reference_id ) AS Opened, CAST( e.event_date AS DATE ) AS event_date      
						INTO #datekopened      
						FROM Mysms.dbo.EngagementEventOpenClick AS e with (nolock) JOIN #batch AS b      
						ON e.BatchID=b.BatchID AND ISNUMERIC( e.BatchID )=1 AND ISNUMERIC( b.BatchID )=1      
						WHERE ISNULL( e.destination_url, '' )=''      
						GROUP BY e.batchid, CAST( e.event_date AS DATE );      
      
						SELECT e.batchid, COUNT( DISTINCT e.customer_reference_id ) AS Opened      
						INTO #kopened      
						FROM Mysms.dbo.EngagementEventOpenClick AS e with (nolock) JOIN #batch AS b      
						ON e.BatchID=b.BatchID AND ISNUMERIC( e.BatchID )=1 AND ISNUMERIC( b.BatchID )=1      
						WHERE ISNULL( e.destination_url, '' )=''      
						GROUP BY e.batchid;      
      
						SELECT e.batchid, COUNT( e.customer_reference_id ) AS Clicked, e.event_date      
						INTO #datekclicked      
						FROM Mysms.dbo.EngagementEventOpenClick AS e with (nolock) JOIN #batch AS b      
						ON e.BatchID=b.BatchID AND ISNUMERIC( e.BatchID )=1 AND ISNUMERIC( b.BatchID )=1      
						WHERE ISNULL( e.destination_url, '' )<>''      
						GROUP BY e.batchid, e.event_date;      
      
						SELECT e.batchid, COUNT( DISTINCT e.customer_reference_id ) AS Clicked      
						INTO #kclicked      
						FROM Mysms.dbo.EngagementEventOpenClick AS e with (nolock) JOIN #batch AS b      
						ON e.BatchID=b.BatchID AND ISNUMERIC( e.BatchID )=1 AND ISNUMERIC( b.BatchID )=1      
						WHERE ISNULL( e.destination_url, '' )<>''      
						GROUP BY e.batchid;   
  

				INSERT INTO MySMSReportCache.[dbo].[tbl_OpenedEmailData_Archive] 
				(
							   [Event_Date],[Opened],[UserId]
				)
				SELECT k.event_date, SUM( Opened ) AS Opened, @parentid as UserId      
				FROM #datekopened      
				AS k              
				WHERE event_date BETWEEN @fromdate AND @todate      
				GROUP BY event_date      
				ORDER BY event_date ASC;   

				INSERT INTO MySMSReportCache.[dbo].[tbl_ClickedEmail_Archive] 
				(
							   [Event_Date],[clicked],[UserId]
				)
				SELECT k.event_date, SUM( clicked ) AS clicked, @parentid as UserId        
				FROM #datekclicked AS k              
				WHERE event_date BETWEEN @fromdate AND @todate      
				GROUP BY event_date      
				ORDER BY event_date ASC;  

				INSERT INTO MySMSReportCache.[dbo].[tbl_DeliveredEmail_Archive] 
				(
							   [Event_Date]
							  ,[TotalRecords]
							  ,[Sent]
							  ,[SentButNotDelivered]
							  ,[Delivered]
							  ,[Bounced]
							  ,[UserId]
				)
						SELECT cast(c.start_dts as date) AS Event_date, 
				SUM( isnull(totalrecords,0) ) AS TotalRecords,       
				SUM( isnull(totalrecords,0) ) AS Sent, 
				0 AS SentButNotDelivered,       
				SUM( ISNULL( a.delivered, 0 )+ISNULL( kd.KDelivered, 0 ) ) AS Delivered,       
				SUM( ISNULL( ab.bounced, 0 )+ISNULL( kb.KBounced, 0 ) ) AS Bounced,
				@parentid as UserId
				FROM #batch AS b 
				right join calendar as c on cast(c.start_dts as date)=b.batchinserttime
				and cast(c.start_dts as date) between @fromdate AND @todate
				LEFT JOIN #Dateadstatus AS a ON a.batchid=b.batchid AND a.createdon  between @fromdate AND @todate     
				LEFT JOIN #dateabstatus AS ab ON ab.batchid=b.BatchID AND ab.createdon   between @fromdate AND @todate    
				LEFT JOIN #datekdelivered AS kd ON kd.BatchID=b.BatchID AND kd.event_time       between @fromdate AND @todate
				LEFT JOIN #datekbounced AS kb ON kb.BatchID=b.BatchID AND kb.event_time   between @fromdate AND @todate
				where cast(c.start_dts as date) between @fromdate AND @todate            
				GROUP BY cast(c.start_dts as date)      
				ORDER BY cast(c.start_dts as date) ASC;  

				INSERT INTO MySMSReportCache.[dbo].[tbl_EmailReportListView_Archive] 
				(
						   [BatchID]
						  ,[CampaignDate]
						  ,[Mail_Source]
						  ,[CampaignType]
						  ,[CampaignName]
						  ,[Recipients]
						  ,[Delivered]
						  ,[Bounced]
						  ,[Opened]
						  ,[Clicked]
						  ,[Sent]
						  ,[NotSent]
						  ,[TotalUnsubscribed]
						  ,[UserId]
				)
			SELECT batchid, CampaignDate, mail_source, campaigntype, campaignname, SUM( TotalRecords ) AS Recipients,       
			   SUM( ISNULL( delivered, 0 )+ISNULL( Kdelivered, 0 ) ) AS Delivered,       
			   SUM( ISNULL( Bounced, 0 )+ISNULL( kBounced, 0 ) )  AS bounced,       
			   SUM( ISNULL( opened, 0 ) ) AS Opened,  SUM( ISNULL( clicked, 0 ) ) AS Clicked,       
			   SUM( ISNULL( sent, 0 ) ) AS Sent, SUM( ISNULL( notsent, 0 )+ISNULL( invalidnotsent, 0 ) ) AS NotSent,       
			   ISNULL( TotalUnsubscribed, 0 ) AS TotalUnsubscribed, @parentid as UserId      
		FROM      
		(      
		  SELECT b.batchid, CampaignDate, mail_source, campaigntype, campaignname, TotalRecords, Sent, NotSent,       
				 Delivered, Bounced, Kdelivered, Kbounced, Opened, Clicked, s.NotSent InvalidNotSent, TotalUnsubscribed      
		  FROM #batch AS b 
		  LEFT JOIN #sent AS s ON b.BatchID=s.batchid 
		  LEFT JOIN #abstatus AS ab ON ab.batchid=b.BatchID 
		  LEFT JOIN #adstatus AS ad ON ad.batchid=b.BatchID 
		  LEFT JOIN #kdelivered AS k ON k.BatchID=b.BatchID 
		  LEFT JOIN #kbounced AS kb ON kb.BatchID=b.BatchID 
		  LEFT JOIN #kopened AS ko ON ko.BatchID=b.BatchID 
		  LEFT JOIN #kclicked AS kc ON kc.BatchID=b.BatchID 
		  LEFT JOIN #unsubscribed AS u ON u.batchid=b.BatchID      
		)      
		AS a      
		WHERE campaigntype=CASE WHEN @campaigntype IS NULL THEN campaigntype ELSE @campaigntype END      
			  AND campaignname=CASE WHEN @campaignname IS NULL THEN campaignname ELSE @campaignname END      
		GROUP BY batchid,  CampaignDate,  campaigntype,  campaignname,  mail_source,  TotalUnsubscribed      
		ORDER BY CampaignDate DESC; 

				INSERT INTO MySMSReportCache.[dbo].[tbl_EmailReportMatrix_Archive] 
				(
						   [Recipients]
						  ,[Delivered]
						  ,[Bounced]
						  ,[Opened]
						  ,[Clicked]
						  ,[Sent]
						  ,[NotSent]
						  ,[TotalUnsubscribed]
						  ,[InvalidMails]
						  ,[inqueue]
						  ,[Unknown]
						  ,[UserId]
				)
				SELECT SUM( TotalRecords ) AS Recipients, SUM( ISNULL( delivered, 0 )+ISNULL( Kdelivered, 0 ) ) AS Delivered,       
				   SUM( ISNULL( Bounced, 0 )+ISNULL( kBounced, 0 ) ) AS bounced, SUM( ISNULL( opened, 0 ) ) AS Opened,       
				   SUM( ISNULL( clicked, 0 ) ) AS Clicked, SUM( ISNULL( sent, 0 ) ) AS Sent,       
				   SUM( ISNULL( notsent, 0 )) AS NotSent,       
				   SUM( ISNULL( TotalUnsubscribed, 0 ) ) AS TotalUnsubscribed,       
				SUM( ISNULL( InvalidMails, 0 ) ) AS InvalidMails,       
				   SUM( ISNULL( inqueue, 0 ) ) AS inqueue,
				   case when SUM( TotalRecords )- SUM( ISNULL( delivered, 0 )+ISNULL( Kdelivered, 0 ) )-SUM( ISNULL( Bounced, 0 )+ISNULL( kBounced, 0 ) )-
				   SUM( ISNULL( InvalidMails, 0 ) )>0 then  
					 SUM( TotalRecords )- SUM( ISNULL( delivered, 0 )+ISNULL( Kdelivered, 0 ) )-SUM( ISNULL( Bounced, 0 )+ISNULL( kBounced, 0 ) )-
				   SUM( ISNULL( InvalidMails, 0 ) ) else 0 end as Unknown , @parentid as UserId
			FROM      
			(      
			  SELECT CampaignDate, mail_source, campaigntype, campaignname, TotalRecords, Sent, NotSent, Delivered,       
					 Bounced, Kdelivered, Kbounced, Opened, Clicked, TotalUnsubscribed,       
					 InvalidMails, (EnteredQueue-Sent) as inqueue
			  FROM #batch AS b 
			  LEFT JOIN #sent AS s ON b.BatchID=s.batchid 
			  LEFT JOIN #abstatus AS ab ON ab.batchid=b.BatchID 
			  LEFT JOIN #adstatus AS ad ON ad.batchid=b.BatchID 
			  LEFT JOIN #kdelivered AS k ON k.BatchID=b.BatchID 
			  LEFT JOIN #kbounced AS kb ON kb.BatchID=b.BatchID 
			  LEFT JOIN #kopened AS ko ON ko.BatchID=b.BatchID 
			  LEFT JOIN #kclicked AS kc ON kc.BatchID=b.BatchID 
			  LEFT JOIN #unsubscribed AS u ON u.batchid=b.BatchID 
			  WHERE campaigntype=CASE WHEN @campaigntype IS NULL THEN campaigntype ELSE @campaigntype END      
					AND campaignname=CASE WHEN @campaignname IS NULL THEN campaignname ELSE @campaignname END      
			)      
			AS a;  


		DROP TABLE IF EXISTS #batcht;      
		DROP TABLE IF EXISTS #batch;      
		DROP TABLE IF EXISTS #invalidmails;      
		DROP TABLE IF EXISTS #sent;      
		DROP TABLE IF EXISTS #kdelivered;      
		DROP TABLE IF EXISTS #kbounced;      
		DROP TABLE IF EXISTS #kopened;      
		DROP TABLE IF EXISTS #kclicked;      
		DROP TABLE IF EXISTS #adstatus;      
		DROP TABLE IF EXISTS #abstatus;      
		DROP TABLE IF EXISTS #dateinvalidmails;      
		DROP TABLE IF EXISTS #datesent;      
		DROP TABLE IF EXISTS #datekdelivered;      
		DROP TABLE IF EXISTS #datekbounced;      
		DROP TABLE IF EXISTS #datekopened;      
		DROP TABLE IF EXISTS #datekclicked;      
		DROP TABLE IF EXISTS #dateadstatus;      
		DROP TABLE IF EXISTS #dateabstatus;      
		DROP TABLE IF EXISTS #unsubscribed;      
		DROP TABLE IF EXISTS #badmails;      
		DROP TABLE IF EXISTS #inqueue;  

END

END TRY
BEGIN CATCH
exec usp_InsertErrorInfo
END CATCH
-- Move to the next row
        SET @currentRow = @currentRow + 1;
END

-- Clean up the temporary table
    DROP TABLE #UserIDs;
		
END



GO

/* ============================================================
   Procedure: [dbo].[usp_Insert_EmailReport_DataTo_Cache_Archive]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_Insert_EmailReport_DataTo_Cache_Archive] 
	-- @parentid BIGINT
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	SET NOCOUNT ON;

    -- Create a temporary table to store the User IDs
    CREATE TABLE #UserIDs (UserID BIGINT);

    -- Insert UserIDs into the temporary table
    INSERT INTO #UserIDs (UserID)
    SELECT userid
    FROM Mysms.dbo.BatchEmail_Infos (NOLOCK)
	WHERE userid IS NOT NULL
	GROUP BY userid
    ORDER BY COUNT(*) DESC;

	-- Ative ParentID list
	select u.user_id AS ParentID
	INTO #ParentIDs
	from User_Detail(nolock) u 
	join Price_UserSubscriptionDetails p(nolock) 
		on u.user_id=p.UserID       
	INNER JOIN  #UserIDs tu ON tu.UserID = u.User_ID
	where 
		user_id=parentid
		and p.IsNewPlan=1
		and p.PlanEndDate>=cast(getdate() as date)

	BEGIN TRY
			DECLARE
					@campaigntype NVARCHAR(20) =NULL,       
					@campaignname NVARCHAR(100)=NULL,       
					@fromdate DATE = NULL,       
					@todate   DATE = NULL; 

			Declare @Currentdate  DATE  = GETDATE();  -- Today's date
			SET @fromdate  = DATEADD(DAY, -1, @Currentdate); -- 1 day before today
			SET @todate  = @Currentdate;	

			DROP TABLE IF EXISTS #batcht;      
			DROP TABLE IF EXISTS #batch;      
			DROP TABLE IF EXISTS #invalidmails;      
			DROP TABLE IF EXISTS #sent;      
			DROP TABLE IF EXISTS #kdelivered;      
			DROP TABLE IF EXISTS #kbounced;      
			DROP TABLE IF EXISTS #kopened;      
			DROP TABLE IF EXISTS #kclicked;      
			DROP TABLE IF EXISTS #adstatus;      
			DROP TABLE IF EXISTS #abstatus;      
			DROP TABLE IF EXISTS #dateinvalidmails;      
			DROP TABLE IF EXISTS #datesent;      
			DROP TABLE IF EXISTS #datekdelivered;      
			DROP TABLE IF EXISTS #datekbounced;      
			DROP TABLE IF EXISTS #datekopened;      
			DROP TABLE IF EXISTS #datekclicked;      
			DROP TABLE IF EXISTS #dateadstatus;      
			DROP TABLE IF EXISTS #dateabstatus;      
			DROP TABLE IF EXISTS #unsubscribed;      
			DROP TABLE IF EXISTS #badmails;      
			DROP TABLE IF EXISTS #inqueue;  

		--IF NOT EXISTS ( 
		--			SELECT 1 
		--			FROM MySMSReportCache.[dbo].[tbl_OpenedEmailData_Cache] (NOLOCK)
		--			WHERE UserId = @parentid --and TRY_CAST(Event_Date as Date) between @fromdate and @todate
		--		)
		--		BEGIN

				SELECT b.batchid, mail_source, TRY_CAST(ISNULL(scheduleddate, batchinserttime) AS DATE) AS batchinserttime,       
					COALESCE(t.cname, c.campaignname, CASE WHEN mail_source IN( 'emails', 'csv' )      
						 THEN TRY_CAST( ISNULL( scheduleddate, batchinserttime ) AS NVARCHAR(50) )+'_'+TRY_CAST(b.batchid AS NVARCHAR)      
							ELSE 'CRM_'+mail_source END ) AS campaignname,      
							   CASE WHEN t.id IS NOT NULL THEN 'Triggered Campaign'      
								 WHEN c.id IS NOT NULL AND ISNULL( c.IsScheduled, 0 )=1 THEN 'Scheduled Campaign'      
								 WHEN c.id IS NOT NULL AND ISNULL( c.IsScheduled, 0 )=0 THEN 'Event Based Campaign'      
								 WHEN mail_source IN( 'emails', 'csv') THEN 'Bulk Mail Campaign'      
								 ELSE 'CRM Mails'      
							   END AS campaigntype,       
							   TRY_CAST( ISNULL( scheduleddate, batchinserttime ) AS DATE) AS CampaignDate,       
							   TotalRecords--,Delivered,Bounced,TotalSent   
							   ,u.ParentID
						INTO #batcht      
						FROM Mysms.dbo.BatchEmail_Infos AS b with (nolock) JOIN Mysms.dbo.user_detail AS u with (nolock)      
						ON u.User_ID=b.UserID LEFT JOIN Mysms.dbo.usercampaignmaster AS c with (nolock)      
						ON c.ParentID=u.parentid AND b.mail_source LIKE 'campaign%' AND TRY_CAST(c.ID AS NVARCHAR)=replace(b.mail_source, 'Campaign :', '') LEFT JOIN Mysms.dbo.triggeredcampaigns AS t with (nolock)      
						ON c.eventid=t.eventid AND t.mailcampaignid=c.id      
						WHERE TRY_CAST(ISNULL(scheduleddate, batchinserttime) AS DATE) BETWEEN @fromdate AND @todate
						AND EXISTS (SELECT 1 FROM #ParentIDs tp WHERE u.ParentID = tp.ParentID);     

						SELECT *      
						INTO #batch      
						FROM #batcht      
						WHERE campaigntype=CASE WHEN @campaigntype IS NULL THEN campaigntype ELSE @campaigntype END      
							  AND campaignname=CASE WHEN @campaignname IS NULL THEN campaignname ELSE @campaignname END;      
      
						SELECT t.batchid, COUNT(1) AS TotalUnsubscribed      
						INTO #unsubscribed      
						FROM Mysms.dbo.tbl_subscription AS t with (nolock) JOIN #batch AS b      
						ON b.BatchID=t.batchid      
						GROUP BY t.batchid;    

						SELECT e.BatchID, COUNT(1) AS KDelivered, TRY_CAST(ISNULL(e.event_time, createdon) AS DATE) AS event_time      
						INTO #datekdelivered      
						FROM Mysms.dbo.EmailDeliveryStatus AS e with (nolock) JOIN #batch AS b      
						ON e.BatchID=b.BatchID      
						WHERE event_status='001'      
						GROUP BY e.batchid, TRY_CAST(ISNULL(e.event_time, createdon) AS DATE);  
      
						SELECT e.BatchID, sum(Kdelivered) AS KDelivered--, CAST(ISNULL(e.event_time, createdon) AS DATE) AS event_time      
						INTO #kdelivered      
						FROM #datekdelivered AS e with (nolock) JOIN #batch AS b      
						ON e.BatchID=b.BatchID      
						GROUP BY e.batchid--, CAST(ISNULL(e.event_time, createdon) AS DATE);      
      
						SELECT e.BatchID, COUNT(1) AS KBounced, TRY_CAST(ISNULL(e.event_time, createdon) AS DATE) AS event_time      
						INTO #datekbounced      
						FROM Mysms.dbo.EmailDeliveryStatus AS e with (nolock) JOIN #batch AS b      
						ON e.BatchID=b.BatchID      
						WHERE event_status<>'001'      
						GROUP BY e.batchid, TRY_CAST(ISNULL(e.event_time, createdon) AS DATE);         

						SELECT e.BatchID, sum(KBounced) AS KBounced--, CAST(ISNULL(e.event_time, createdon) AS DATE) AS event_time      
						INTO #kbounced      
						FROM #datekbounced AS e with (nolock) JOIN #batch AS b      
						ON e.BatchID=b.BatchID      
						GROUP BY e.batchid--, CAST(ISNULL(e.event_time, createdon) AS DATE);      

						/* -- Commented By DBA
						SELECT e.batchid, COUNT(1) AS Delivered, TRY_CAST( e.createdon AS DATE ) AS createdon      
						INTO #dateadstatus      
						FROM Mysms.dbo.Maildeliveries AS e with (nolock) JOIN #batch AS b      
						ON e.BatchID=b.BatchID      
						GROUP BY e.batchid, TRY_CAST( e.createdon AS DATE )   
						*/

						-- Added By DBA
						;with cte_md
						AS
						(
						SELECT e.batchid
						FROM Mysms.dbo.Maildeliveries AS e with (nolock) 
						WHERE EXISTS (SELECT 1 FROM #batch b WHERE  e.BatchID=b.BatchID)
						)
						SELECT e.batchid, COUNT(1) AS Delivered, TRY_CAST( e.createdon AS DATE ) AS createdon
						INTO #dateadstatus
						FROM Mysms.dbo.Maildeliveries AS e with (nolock) 
						INNER JOIN cte_md t ON t.batchid = e.batchid
						GROUP BY e.batchid, TRY_CAST( e.createdon AS DATE );

						SELECT e.batchid, COUNT( 1 ) AS bounced, TRY_CAST( e.createdon AS DATE ) AS createdon
						INTO #dateabstatus      
						FROM Mysms.dbo.Mailbounces AS e with (nolock) JOIN #batch AS b      
						ON e.BatchID=b.BatchID      
						GROUP BY e.batchid, TRY_CAST( e.createdon AS DATE )

						SELECT e.batchid, sum(delivered) AS Delivered
						INTO #adstatus      
						FROM #dateadstatus AS e with (nolock) JOIN #batch AS b      
						ON e.BatchID=b.BatchID      
						GROUP BY e.batchid
      
						SELECT e.batchid, sum(bounced) bounced--, CAST( e.createdon AS DATE ) AS createdon      
						INTO #abstatus      
						FROM #dateabstatus AS e with (nolock) JOIN #batch AS b      
						ON e.BatchID=b.BatchID      
						GROUP BY e.batchid
      
						SELECT e.batchid, 
						sum(case when tablename='EmailsReportSent' then mailcount else 0 end) AS Sent, 
						sum(case when tablename='invalid_Mail_EmailsReport' then mailcount else 0 end) AS NotSent, 
						sum(case when tablename in ('Mail_EmailsReport00','Mail_EmailsReport01','Mail_EmailsReport02','Mail_EmailsReport03',
						'Mail_EmailsReport04','Mail_EmailsReport05','Mail_EmailsReport1','Mail_EmailsReport2') then mailcount else 0 end) AS EnteredQueue, 
						sum(case when tablename='Bad_emails' then mailcount else 0 end) AS InvalidMails
						INTO #sent      
						FROM emailcountracking AS e (nolock) JOIN #batch AS b      
						ON e.BatchID=b.BatchID      
						GROUP BY e.BatchID      
      
						/* Commended By DBA
						SELECT e.batchid, COUNT( e.customer_reference_id ) AS Opened, TRY_CAST( e.event_date AS DATE ) AS event_date      
						INTO #datekopened      
						FROM Mysms.dbo.EngagementEventOpenClick AS e with (nolock) JOIN #batch AS b      
						ON e.BatchID=b.BatchID AND ISNUMERIC( e.BatchID )=1 AND ISNUMERIC( b.BatchID )=1      
						WHERE ISNULL( e.destination_url, '' )=''      
						GROUP BY e.batchid, TRY_CAST( e.event_date AS DATE );     
						*/

						-- Added By DBA
						SELECT CAST(BatchID AS NVARCHAR(100)) AS BatchID, ParentID
						INTO #b FROM #batch b
						WHERE ISNUMERIC( b.BatchID )=1;

						SELECT e.batchid, b.ParentID, COUNT( e.customer_reference_id ) AS Opened, TRY_CAST( e.event_date AS DATE ) AS event_date      
						INTO #datekopened      
						FROM Mysms.dbo.EngagementEventOpenClick AS e with (nolock) JOIN #b AS b      
						ON e.BatchID=b.BatchID
						WHERE ISNULL( e.destination_url, '' )=''      
						GROUP BY e.batchid, b.ParentID, TRY_CAST( e.event_date AS DATE );

						/* Commented By DBA
						SELECT e.batchid, COUNT( DISTINCT e.customer_reference_id ) AS Opened      
						INTO #kopened      
						FROM Mysms.dbo.EngagementEventOpenClick AS e with (nolock) JOIN #batch AS b      
						ON e.BatchID=b.BatchID AND ISNUMERIC( e.BatchID )=1 AND ISNUMERIC( b.BatchID )=1      
						WHERE ISNULL( e.destination_url, '' )=''      
						GROUP BY e.batchid;      
						*/

						-- Added By DBA
						SELECT e.batchid, COUNT( DISTINCT e.customer_reference_id ) AS Opened      
						INTO #kopened      
						FROM Mysms.dbo.EngagementEventOpenClick AS e with (nolock) JOIN #b AS b      
						ON e.BatchID=b.BatchID
						WHERE ISNULL( e.destination_url, '' )=''      
						GROUP BY e.batchid;

						/* Commented By DBA
						SELECT e.batchid, COUNT( e.customer_reference_id ) AS Clicked, e.event_date      
						INTO #datekclicked      
						FROM Mysms.dbo.EngagementEventOpenClick AS e with (nolock) JOIN #batch AS b      
						ON e.BatchID=b.BatchID AND ISNUMERIC( e.BatchID )=1 AND ISNUMERIC( b.BatchID )=1      
						WHERE ISNULL( e.destination_url, '' )<>''      
						GROUP BY e.batchid, e.event_date;      
						*/

						SELECT e.batchid, b.ParentID, COUNT( e.customer_reference_id ) AS Clicked, e.event_date      
						INTO #datekclicked      
						FROM Mysms.dbo.EngagementEventOpenClick AS e with (nolock) JOIN #b AS b      
						ON e.BatchID=b.BatchID
						WHERE ISNULL( e.destination_url, '' )=''      
						GROUP BY e.batchid, b.ParentID, e.event_date;

						/* Commented By DBA
						SELECT e.batchid, COUNT( DISTINCT e.customer_reference_id ) AS Clicked      
						INTO #kclicked      
						FROM Mysms.dbo.EngagementEventOpenClick AS e with (nolock) JOIN #batch AS b      
						ON e.BatchID=b.BatchID AND ISNUMERIC( e.BatchID )=1 AND ISNUMERIC( b.BatchID )=1      
						WHERE ISNULL( e.destination_url, '' )<>''      
						GROUP BY e.batchid;   
						*/

						SELECT e.batchid, COUNT( DISTINCT e.customer_reference_id ) AS Clicked      
						INTO #kclicked      
						FROM Mysms.dbo.EngagementEventOpenClick AS e with (nolock) JOIN #b AS b      
						ON e.BatchID=b.BatchID
						WHERE ISNULL( e.destination_url, '' )=''      
						GROUP BY e.batchid;

						DROP TABLE IF EXISTS #b;

						INSERT INTO MySMSReportCache.[dbo].[tbl_OpenedEmailData_Cache] 
						(
									   [Event_Date],[Opened],[UserId]
						)
						SELECT k.event_date, SUM( Opened ) AS Opened, ParentID as UserId      
						FROM #datekopened      
						AS k              
						WHERE event_date BETWEEN @fromdate AND @todate      
						GROUP BY event_date, ParentID      
						ORDER BY event_date ASC;   

						INSERT INTO MySMSReportCache.[dbo].[tbl_ClickedEmail_Cache] 
						(
									   [Event_Date],[clicked],[UserId]
						)
						SELECT k.event_date, SUM( clicked ) AS clicked, ParentID as UserId        
						FROM #datekclicked AS k              
						WHERE event_date BETWEEN @fromdate AND @todate      
						GROUP BY event_date, ParentID    
						ORDER BY event_date ASC;  

						INSERT INTO MySMSReportCache.[dbo].[tbl_DeliveredEmail_Cache] 
						(
									   [Event_Date]
									  ,[TotalRecords]
									  ,[Sent]
									  ,[SentButNotDelivered]
									  ,[Delivered]
									  ,[Bounced]
									  ,[UserId]
						)
						SELECT TRY_CAST(c.start_dts as date) AS Event_date, 
						SUM( isnull(totalrecords,0) ) AS TotalRecords,       
						SUM( isnull(totalrecords,0) ) AS Sent, 
						0 AS SentButNotDelivered,       
						SUM( ISNULL( a.delivered, 0 )+ISNULL( kd.KDelivered, 0 ) ) AS Delivered,       
						SUM( ISNULL( ab.bounced, 0 )+ISNULL( kb.KBounced, 0 ) ) AS Bounced,
						b.ParentID as UserId
						FROM #batch AS b 
						right join calendar as c on TRY_CAST(c.start_dts as date)=b.batchinserttime
						and TRY_CAST(c.start_dts as date) between @fromdate AND @todate
						LEFT JOIN #Dateadstatus AS a ON a.batchid=b.batchid AND a.createdon  between @fromdate AND @todate     
						LEFT JOIN #dateabstatus AS ab ON ab.batchid=b.BatchID AND ab.createdon   between @fromdate AND @todate    
						LEFT JOIN #datekdelivered AS kd ON kd.BatchID=b.BatchID AND kd.event_time       between @fromdate AND @todate
						LEFT JOIN #datekbounced AS kb ON kb.BatchID=b.BatchID AND kb.event_time   between @fromdate AND @todate
						where TRY_CAST(c.start_dts as date) between @fromdate AND @todate            
						GROUP BY b.ParentID, TRY_CAST(c.start_dts as date)      
						ORDER BY TRY_CAST(c.start_dts as date) ASC; 

						INSERT INTO MySMSReportCache.[dbo].[tbl_EmailReportListView_Cache] 
						(
								   [BatchID]
								  ,[CampaignDate]
								  ,[Mail_Source]
								  ,[CampaignType]
								  ,[CampaignName]
								  ,[Recipients]
								  ,[Delivered]
								  ,[Bounced]
								  ,[Opened]
								  ,[Clicked]
								  ,[Sent]
								  ,[NotSent]
								  ,[TotalUnsubscribed]
								  ,[UserId]
						)
						SELECT batchid, CampaignDate, mail_source, campaigntype, campaignname, SUM( TotalRecords ) AS Recipients,       
						   SUM( ISNULL( delivered, 0 )+ISNULL( Kdelivered, 0 ) ) AS Delivered,       
						   SUM( ISNULL( Bounced, 0 )+ISNULL( kBounced, 0 ) )  AS bounced,       
						   SUM( ISNULL( opened, 0 ) ) AS Opened,  SUM( ISNULL( clicked, 0 ) ) AS Clicked,       
						   SUM( ISNULL( sent, 0 ) ) AS Sent, SUM( ISNULL( notsent, 0 )+ISNULL( invalidnotsent, 0 ) ) AS NotSent,       
						   ISNULL( TotalUnsubscribed, 0 ) AS TotalUnsubscribed, UserId      
					FROM      
					(      
					  SELECT b.batchid, CampaignDate, mail_source, campaigntype, campaignname, TotalRecords, Sent, NotSent,       
							 Delivered, Bounced, Kdelivered, Kbounced, Opened, Clicked, s.NotSent InvalidNotSent, TotalUnsubscribed, b.ParentID as UserId     
					  FROM #batch AS b 
					  LEFT JOIN #sent AS s ON b.BatchID=s.batchid 
					  LEFT JOIN #abstatus AS ab ON ab.batchid=b.BatchID 
					  LEFT JOIN #adstatus AS ad ON ad.batchid=b.BatchID 
					  LEFT JOIN #kdelivered AS k ON k.BatchID=b.BatchID 
					  LEFT JOIN #kbounced AS kb ON kb.BatchID=b.BatchID 
					  LEFT JOIN #kopened AS ko ON ko.BatchID=b.BatchID 
					  LEFT JOIN #kclicked AS kc ON kc.BatchID=b.BatchID 
					  LEFT JOIN #unsubscribed AS u ON u.batchid=b.BatchID      
					)      
					AS a      
					WHERE campaigntype=CASE WHEN @campaigntype IS NULL THEN campaigntype ELSE @campaigntype END      
						  AND campaignname=CASE WHEN @campaignname IS NULL THEN campaignname ELSE @campaignname END      
					GROUP BY batchid,  UserId, CampaignDate,  campaigntype,  campaignname,  mail_source,  TotalUnsubscribed      
					ORDER BY CampaignDate DESC; 

					INSERT INTO MySMSReportCache.[dbo].[tbl_EmailReportMatrix_Cache] 
					(
							   [Recipients]
							  ,[Delivered]
							  ,[Bounced]
							  ,[Opened]
							  ,[Clicked]
							  ,[Sent]
							  ,[NotSent]
							  ,[TotalUnsubscribed]
							  ,[InvalidMails]
							  ,[inqueue]
							  ,[Unknown]
							  ,[UserId]
					)
					SELECT SUM( TotalRecords ) AS Recipients, SUM( ISNULL( delivered, 0 )+ISNULL( Kdelivered, 0 ) ) AS Delivered,       
					   SUM( ISNULL( Bounced, 0 )+ISNULL( kBounced, 0 ) ) AS bounced, SUM( ISNULL( opened, 0 ) ) AS Opened,       
					   SUM( ISNULL( clicked, 0 ) ) AS Clicked, SUM( ISNULL( sent, 0 ) ) AS Sent,       
					   SUM( ISNULL( notsent, 0 )) AS NotSent,       
					   SUM( ISNULL( TotalUnsubscribed, 0 ) ) AS TotalUnsubscribed,       
					SUM( ISNULL( InvalidMails, 0 ) ) AS InvalidMails,       
					   SUM( ISNULL( inqueue, 0 ) ) AS inqueue,
					   case when SUM( TotalRecords )- SUM( ISNULL( delivered, 0 )+ISNULL( Kdelivered, 0 ) )-SUM( ISNULL( Bounced, 0 )+ISNULL( kBounced, 0 ) )-
					   SUM( ISNULL( InvalidMails, 0 ) )>0 then  
						 SUM( TotalRecords )- SUM( ISNULL( delivered, 0 )+ISNULL( Kdelivered, 0 ) )-SUM( ISNULL( Bounced, 0 )+ISNULL( kBounced, 0 ) )-
					   SUM( ISNULL( InvalidMails, 0 ) ) else 0 end as Unknown , UserId as UserId
				FROM      
				(      
				  SELECT CampaignDate, mail_source, campaigntype, campaignname, TotalRecords, Sent, NotSent, Delivered,       
						 Bounced, Kdelivered, Kbounced, Opened, Clicked, TotalUnsubscribed,       
						 InvalidMails, (EnteredQueue-Sent) as inqueue, b.ParentID as UserId
				  FROM #batch AS b 
				  LEFT JOIN #sent AS s ON b.BatchID=s.batchid 
				  LEFT JOIN #abstatus AS ab ON ab.batchid=b.BatchID 
				  LEFT JOIN #adstatus AS ad ON ad.batchid=b.BatchID 
				  LEFT JOIN #kdelivered AS k ON k.BatchID=b.BatchID 
				  LEFT JOIN #kbounced AS kb ON kb.BatchID=b.BatchID 
				  LEFT JOIN #kopened AS ko ON ko.BatchID=b.BatchID 
				  LEFT JOIN #kclicked AS kc ON kc.BatchID=b.BatchID 
				  LEFT JOIN #unsubscribed AS u ON u.batchid=b.BatchID 
				  WHERE campaigntype=CASE WHEN @campaigntype IS NULL THEN campaigntype ELSE @campaigntype END      
						AND campaignname=CASE WHEN @campaignname IS NULL THEN campaignname ELSE @campaignname END      
				)      
				AS a
				GROUP BY UserId;  


				INSERT INTO MySMSReportCache.[dbo].[tbl_OpenedEmailData_Archive] 
				(
							   [Event_Date],[Opened],[UserId]
				)
				SELECT k.event_date, SUM( Opened ) AS Opened, ParentID as UserId      
				FROM #datekopened      
				AS k              
				WHERE event_date BETWEEN @fromdate AND @todate      
				GROUP BY event_date, ParentID     
				ORDER BY event_date ASC;   

				INSERT INTO MySMSReportCache.[dbo].[tbl_ClickedEmail_Archive] 
				(
							   [Event_Date],[clicked],[UserId]
				)
				SELECT k.event_date, SUM( clicked ) AS clicked, ParentID as UserId        
				FROM #datekclicked AS k              
				WHERE event_date BETWEEN @fromdate AND @todate      
				GROUP BY event_date, ParentID     
				ORDER BY event_date ASC;  

				INSERT INTO MySMSReportCache.[dbo].[tbl_DeliveredEmail_Archive] 
				(
							   [Event_Date]
							  ,[TotalRecords]
							  ,[Sent]
							  ,[SentButNotDelivered]
							  ,[Delivered]
							  ,[Bounced]
							  ,[UserId]
				)
						SELECT TRY_CAST(c.start_dts as date) AS Event_date, 
				SUM( isnull(totalrecords,0) ) AS TotalRecords,       
				SUM( isnull(totalrecords,0) ) AS Sent, 
				0 AS SentButNotDelivered,       
				SUM( ISNULL( a.delivered, 0 )+ISNULL( kd.KDelivered, 0 ) ) AS Delivered,       
				SUM( ISNULL( ab.bounced, 0 )+ISNULL( kb.KBounced, 0 ) ) AS Bounced,
				b.ParentID as UserId
				FROM #batch AS b 
				right join calendar as c on TRY_CAST(c.start_dts as date)=b.batchinserttime
				and TRY_CAST(c.start_dts as date) between @fromdate AND @todate
				LEFT JOIN #Dateadstatus AS a ON a.batchid=b.batchid AND a.createdon  between @fromdate AND @todate     
				LEFT JOIN #dateabstatus AS ab ON ab.batchid=b.BatchID AND ab.createdon   between @fromdate AND @todate    
				LEFT JOIN #datekdelivered AS kd ON kd.BatchID=b.BatchID AND kd.event_time       between @fromdate AND @todate
				LEFT JOIN #datekbounced AS kb ON kb.BatchID=b.BatchID AND kb.event_time   between @fromdate AND @todate
				where TRY_CAST(c.start_dts as date) between @fromdate AND @todate            
				GROUP BY b.ParentID, TRY_CAST(c.start_dts as date)      
				ORDER BY TRY_CAST(c.start_dts as date) ASC; 

				INSERT INTO MySMSReportCache.[dbo].[tbl_EmailReportListView_Archive] 
				(
						   [BatchID]
						  ,[CampaignDate]
						  ,[Mail_Source]
						  ,[CampaignType]
						  ,[CampaignName]
						  ,[Recipients]
						  ,[Delivered]
						  ,[Bounced]
						  ,[Opened]
						  ,[Clicked]
						  ,[Sent]
						  ,[NotSent]
						  ,[TotalUnsubscribed]
						  ,[UserId]
				)
				SELECT batchid, CampaignDate, mail_source, campaigntype, campaignname, SUM( TotalRecords ) AS Recipients,       
				   SUM( ISNULL( delivered, 0 )+ISNULL( Kdelivered, 0 ) ) AS Delivered,       
				   SUM( ISNULL( Bounced, 0 )+ISNULL( kBounced, 0 ) )  AS bounced,       
				   SUM( ISNULL( opened, 0 ) ) AS Opened,  SUM( ISNULL( clicked, 0 ) ) AS Clicked,       
				   SUM( ISNULL( sent, 0 ) ) AS Sent, SUM( ISNULL( notsent, 0 )+ISNULL( invalidnotsent, 0 ) ) AS NotSent,       
				   ISNULL( TotalUnsubscribed, 0 ) AS TotalUnsubscribed, ParentID as UserId      
			FROM      
			(      
			  SELECT b.batchid, b.ParentID, CampaignDate, mail_source, campaigntype, campaignname, TotalRecords, Sent, NotSent,       
					 Delivered, Bounced, Kdelivered, Kbounced, Opened, Clicked, s.NotSent InvalidNotSent, TotalUnsubscribed      
			  FROM #batch AS b 
			  LEFT JOIN #sent AS s ON b.BatchID=s.batchid 
			  LEFT JOIN #abstatus AS ab ON ab.batchid=b.BatchID 
			  LEFT JOIN #adstatus AS ad ON ad.batchid=b.BatchID 
			  LEFT JOIN #kdelivered AS k ON k.BatchID=b.BatchID 
			  LEFT JOIN #kbounced AS kb ON kb.BatchID=b.BatchID 
			  LEFT JOIN #kopened AS ko ON ko.BatchID=b.BatchID 
			  LEFT JOIN #kclicked AS kc ON kc.BatchID=b.BatchID 
			  LEFT JOIN #unsubscribed AS u ON u.batchid=b.BatchID      
			)      
			AS a      
			WHERE campaigntype=CASE WHEN @campaigntype IS NULL THEN campaigntype ELSE @campaigntype END      
				  AND campaignname=CASE WHEN @campaignname IS NULL THEN campaignname ELSE @campaignname END      
			GROUP BY batchid,  ParentID, CampaignDate,  campaigntype,  campaignname,  mail_source,  TotalUnsubscribed      
			ORDER BY CampaignDate DESC;  

			INSERT INTO MySMSReportCache.[dbo].[tbl_EmailReportMatrix_Archive] 
			(
						[Recipients]
						,[Delivered]
						,[Bounced]
						,[Opened]
						,[Clicked]
						,[Sent]
						,[NotSent]
						,[TotalUnsubscribed]
						,[InvalidMails]
						,[inqueue]
						,[Unknown]
						,[UserId]
			)
			SELECT SUM( TotalRecords ) AS Recipients, SUM( ISNULL( delivered, 0 )+ISNULL( Kdelivered, 0 ) ) AS Delivered,       
				SUM( ISNULL( Bounced, 0 )+ISNULL( kBounced, 0 ) ) AS bounced, SUM( ISNULL( opened, 0 ) ) AS Opened,       
				SUM( ISNULL( clicked, 0 ) ) AS Clicked, SUM( ISNULL( sent, 0 ) ) AS Sent,       
				SUM( ISNULL( notsent, 0 )) AS NotSent,       
				SUM( ISNULL( TotalUnsubscribed, 0 ) ) AS TotalUnsubscribed,       
			SUM( ISNULL( InvalidMails, 0 ) ) AS InvalidMails,       
				SUM( ISNULL( inqueue, 0 ) ) AS inqueue,
				case when SUM( TotalRecords )- SUM( ISNULL( delivered, 0 )+ISNULL( Kdelivered, 0 ) )-SUM( ISNULL( Bounced, 0 )+ISNULL( kBounced, 0 ) )-
				SUM( ISNULL( InvalidMails, 0 ) )>0 then  
					SUM( TotalRecords )- SUM( ISNULL( delivered, 0 )+ISNULL( Kdelivered, 0 ) )-SUM( ISNULL( Bounced, 0 )+ISNULL( kBounced, 0 ) )-
				SUM( ISNULL( InvalidMails, 0 ) ) else 0 end as Unknown , ParentID as UserId
		FROM      
		(      
			SELECT CampaignDate, b.ParentID, mail_source, campaigntype, campaignname, TotalRecords, Sent, NotSent, Delivered,       
					Bounced, Kdelivered, Kbounced, Opened, Clicked, TotalUnsubscribed,       
					InvalidMails, (EnteredQueue-Sent) as inqueue
			FROM #batch AS b 
			LEFT JOIN #sent AS s ON b.BatchID=s.batchid 
			LEFT JOIN #abstatus AS ab ON ab.batchid=b.BatchID 
			LEFT JOIN #adstatus AS ad ON ad.batchid=b.BatchID 
			LEFT JOIN #kdelivered AS k ON k.BatchID=b.BatchID 
			LEFT JOIN #kbounced AS kb ON kb.BatchID=b.BatchID 
			LEFT JOIN #kopened AS ko ON ko.BatchID=b.BatchID 
			LEFT JOIN #kclicked AS kc ON kc.BatchID=b.BatchID 
			LEFT JOIN #unsubscribed AS u ON u.batchid=b.BatchID 
			WHERE campaigntype=CASE WHEN @campaigntype IS NULL THEN campaigntype ELSE @campaigntype END      
				AND campaignname=CASE WHEN @campaignname IS NULL THEN campaignname ELSE @campaignname END      
		)      
		AS a
		GROUP BY ParentID; 


		DROP TABLE IF EXISTS #batcht;      
		DROP TABLE IF EXISTS #batch;      
		DROP TABLE IF EXISTS #invalidmails;      
		DROP TABLE IF EXISTS #sent;      
		DROP TABLE IF EXISTS #kdelivered;      
		DROP TABLE IF EXISTS #kbounced;      
		DROP TABLE IF EXISTS #kopened;      
		DROP TABLE IF EXISTS #kclicked;      
		DROP TABLE IF EXISTS #adstatus;      
		DROP TABLE IF EXISTS #abstatus;      
		DROP TABLE IF EXISTS #dateinvalidmails;      
		DROP TABLE IF EXISTS #datesent;      
		DROP TABLE IF EXISTS #datekdelivered;      
		DROP TABLE IF EXISTS #datekbounced;      
		DROP TABLE IF EXISTS #datekopened;      
		DROP TABLE IF EXISTS #datekclicked;      
		DROP TABLE IF EXISTS #dateadstatus;      
		DROP TABLE IF EXISTS #dateabstatus;      
		DROP TABLE IF EXISTS #unsubscribed;      
		DROP TABLE IF EXISTS #badmails;      
		DROP TABLE IF EXISTS #inqueue;  

-- END

END TRY
BEGIN CATCH
	exec usp_InsertErrorInfo
END CATCH

			-- Delete old data
				DELETE FROM MySMSReportCache.[dbo].[tbl_OpenedEmailData_Cache]
				WHERE Event_Date NOT BETWEEN DATEADD(DAY, -30, TRY_CAST(GETDATE() AS DATE)) AND TRY_CAST(GETDATE() AS DATE);

				DELETE FROM MySMSReportCache.[dbo].[tbl_ClickedEmail_Cache]
				WHERE Event_Date NOT BETWEEN DATEADD(DAY, -30, TRY_CAST(GETDATE() AS DATE)) AND TRY_CAST(GETDATE() AS DATE);

				DELETE FROM MySMSReportCache.[dbo].[tbl_DeliveredEmail_Cache]
				WHERE Event_Date NOT BETWEEN DATEADD(DAY, -30, TRY_CAST(GETDATE() AS DATE)) AND TRY_CAST(GETDATE() AS DATE);

				DELETE FROM MySMSReportCache.[dbo].[tbl_EmailReportListView_Cache]
				WHERE CampaignDate NOT BETWEEN DATEADD(DAY, -30, TRY_CAST(GETDATE() AS DATE)) AND TRY_CAST(GETDATE() AS DATE);

				--DELETE FROM MySMSReportCache.[dbo].[tbl_EmailReportMatrix_Cache]
				--WHERE CampaignDate NOT BETWEEN DATEADD(DAY, -30, CAST(GETDATE() AS DATE)) AND CAST(GETDATE() AS DATE);
		  -- end Delete old data

	-- Clean up the temporary table
    DROP TABLE #UserIDs;
	DROP TABLE #ParentIDs;
		
END


GO

/* ============================================================
   Procedure: [dbo].[usp_Insert_EmailReport_DataTo_Cache_Archive_old24032025]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


--select * from MySMSReportCache.[dbo].[tbl_DeliveredEmail_Cache](nolock) select * from MySMSReportCache.[dbo].[tbl_EmailReportMatrix_Cache](nolock) select * from MySMSReportCache.[dbo].[tbl_EmailReportListView_Cache](nolock) select * from MySMSReportCache.[dbo].tbl_OpenedEmailData_Cache(nolock)  select * from MySMSReportCache.[dbo].tbl_ClickedEmail_Cache(nolock) select * from MySMSReportCache.[dbo].[tbl_DeliveredEmail_Archive](nolock) select * from MySMSReportCache.[dbo].[tbl_EmailReportMatrix_Archive](nolock) select * from MySMSReportCache.[dbo].[tbl_EmailReportListView_Archive](nolock) select * from MySMSReportCache.[dbo].tbl_OpenedEmailData_Archive(nolock)  select * from MySMSReportCache.[dbo].tbl_ClickedEmail_Archive(nolock) 

   --TRUNCATE TABLE MySMSReportCache.[dbo].tbl_DeliveredEmail_Cache; TRUNCATE TABLE MySMSReportCache.[dbo].tbl_EmailReportMatrix_Cache; TRUNCATE TABLE MySMSReportCache.[dbo].tbl_EmailReportListView_Cache; TRUNCATE TABLE MySMSReportCache.[dbo].tbl_OpenedEmailData_Cache; TRUNCATE TABLE MySMSReportCache.[dbo].tbl_ClickedEmail_Cache; TRUNCATE TABLE MySMSReportCache.[dbo].tbl_DeliveredEmail_Archive; TRUNCATE TABLE MySMSReportCache.[dbo].tbl_EmailReportMatrix_Archive; TRUNCATE TABLE MySMSReportCache.[dbo].tbl_EmailReportListView_Archive; TRUNCATE TABLE MySMSReportCache.[dbo].tbl_OpenedEmailData_Archive; TRUNCATE TABLE MySMSReportCache.[dbo].tbl_ClickedEmail_Archive;


-- exec [dbo].[usp_Insert_EmailReport_DataTo_Cache_Archive] 

CREATE   PROCEDURE [dbo].[usp_Insert_EmailReport_DataTo_Cache_Archive_old24032025] 
	-- @parentid BIGINT
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	SET NOCOUNT ON;

	DECLARE @userid BIGINT;
    DECLARE @currentRow INT = 1;  -- Variable to track the current row in the temporary table
    DECLARE @totalRows INT;       -- Variable to store the total number of rows to process

    -- Create a temporary table to store the User IDs
    CREATE TABLE #UserIDs (UserID BIGINT);

    -- Insert UserIDs into the temporary table
    INSERT INTO #UserIDs (UserID)
    SELECT userid
    FROM Mysms.dbo.BatchEmail_Infos (NOLOCK)
	WHERE userid IS NOT NULL
	GROUP BY userid
    ORDER BY COUNT(*) DESC;

    -- Get the total number of rows
    SELECT @totalRows = COUNT(*) FROM #UserIDs;

    WHILE @currentRow <= @totalRows
BEGIN
BEGIN TRY
			-- Use a CTE to calculate ROW_NUMBER() and select the current UserID
				WITH CTE_UserIDs AS (
					SELECT UserID, ROW_NUMBER() OVER (ORDER BY UserID) AS RowNum
					FROM #UserIDs
				)
				SELECT @userid = UserID
				FROM CTE_UserIDs
				WHERE RowNum = @currentRow;

   
				Declare @parentid BIGINT = @userid, 
					@campaigntype NVARCHAR(20) =NULL,       
					@campaignname NVARCHAR(100)=NULL,       
					@fromdate DATE = NULL,       
					@todate   DATE = NULL; 

			Declare @Currentdate  DATE  = GETDATE();  -- Today's date
			SET @fromdate  = DATEADD(DAY, -1, @Currentdate); -- 1 day before today
			SET @todate  = @Currentdate;	

		DROP TABLE IF EXISTS #batcht;      
		DROP TABLE IF EXISTS #batch;      
		DROP TABLE IF EXISTS #invalidmails;      
		DROP TABLE IF EXISTS #sent;      
		DROP TABLE IF EXISTS #kdelivered;      
		DROP TABLE IF EXISTS #kbounced;      
		DROP TABLE IF EXISTS #kopened;      
		DROP TABLE IF EXISTS #kclicked;      
		DROP TABLE IF EXISTS #adstatus;      
		DROP TABLE IF EXISTS #abstatus;      
		DROP TABLE IF EXISTS #dateinvalidmails;      
		DROP TABLE IF EXISTS #datesent;      
		DROP TABLE IF EXISTS #datekdelivered;      
		DROP TABLE IF EXISTS #datekbounced;      
		DROP TABLE IF EXISTS #datekopened;      
		DROP TABLE IF EXISTS #datekclicked;      
		DROP TABLE IF EXISTS #dateadstatus;      
		DROP TABLE IF EXISTS #dateabstatus;      
		DROP TABLE IF EXISTS #unsubscribed;      
		DROP TABLE IF EXISTS #badmails;      
		DROP TABLE IF EXISTS #inqueue;  

		--IF NOT EXISTS ( 
		--			SELECT 1 
		--			FROM MySMSReportCache.[dbo].[tbl_OpenedEmailData_Cache] (NOLOCK)
		--			WHERE UserId = @parentid --and TRY_CAST(Event_Date as Date) between @fromdate and @todate
		--		)
		--		BEGIN

				SELECT b.batchid, mail_source, TRY_CAST(ISNULL(scheduleddate, batchinserttime) AS DATE) AS batchinserttime,       
					COALESCE(t.cname, c.campaignname, CASE WHEN mail_source IN( 'emails', 'csv' )      
						 THEN TRY_CAST( ISNULL( scheduleddate, batchinserttime ) AS NVARCHAR(50) )+'_'+TRY_CAST(b.batchid AS NVARCHAR)      
							ELSE 'CRM_'+mail_source END ) AS campaignname,      
							   CASE WHEN t.id IS NOT NULL THEN 'Triggered Campaign'      
								 WHEN c.id IS NOT NULL AND ISNULL( c.IsScheduled, 0 )=1 THEN 'Scheduled Campaign'      
								 WHEN c.id IS NOT NULL AND ISNULL( c.IsScheduled, 0 )=0 THEN 'Event Based Campaign'      
								 WHEN mail_source IN( 'emails', 'csv') THEN 'Bulk Mail Campaign'      
								 ELSE 'CRM Mails'      
							   END AS campaigntype,       
							   TRY_CAST( ISNULL( scheduleddate, batchinserttime ) AS DATE) AS CampaignDate,       
							   TotalRecords--,Delivered,Bounced,TotalSent                      
						INTO #batcht      
						FROM Mysms.dbo.BatchEmail_Infos AS b with (nolock) JOIN Mysms.dbo.user_detail AS u with (nolock)      
						ON u.User_ID=b.UserID LEFT JOIN Mysms.dbo.usercampaignmaster AS c with (nolock)      
						ON c.ParentID=u.parentid AND b.mail_source LIKE 'campaign%' AND TRY_CAST(c.ID AS NVARCHAR)=replace(b.mail_source, 'Campaign :', '') LEFT JOIN Mysms.dbo.triggeredcampaigns AS t with (nolock)      
						ON c.eventid=t.eventid AND t.mailcampaignid=c.id      
						WHERE u.ParentID=@parentid AND TRY_CAST(ISNULL(scheduleddate, batchinserttime) AS DATE) BETWEEN @fromdate AND @todate;      

						SELECT *      
						INTO #batch      
						FROM #batcht      
						WHERE campaigntype=CASE WHEN @campaigntype IS NULL THEN campaigntype ELSE @campaigntype END      
							  AND campaignname=CASE WHEN @campaignname IS NULL THEN campaignname ELSE @campaignname END;      
      
						SELECT t.batchid, COUNT(1) AS TotalUnsubscribed      
						INTO #unsubscribed      
						FROM Mysms.dbo.tbl_subscription AS t with (nolock) JOIN #batch AS b      
						ON b.BatchID=t.batchid      
						GROUP BY t.batchid;    

						SELECT e.BatchID, COUNT(1) AS KDelivered, TRY_CAST(ISNULL(e.event_time, createdon) AS DATE) AS event_time      
						INTO #datekdelivered      
						FROM Mysms.dbo.EmailDeliveryStatus AS e with (nolock) JOIN #batch AS b      
						ON e.BatchID=b.BatchID      
						WHERE event_status='001'      
						GROUP BY e.batchid, TRY_CAST(ISNULL(e.event_time, createdon) AS DATE);  
      
						SELECT e.BatchID, sum(Kdelivered) AS KDelivered--, CAST(ISNULL(e.event_time, createdon) AS DATE) AS event_time      
						INTO #kdelivered      
						FROM #datekdelivered AS e with (nolock) JOIN #batch AS b      
						ON e.BatchID=b.BatchID      
						GROUP BY e.batchid--, CAST(ISNULL(e.event_time, createdon) AS DATE);      
      
						SELECT e.BatchID, COUNT(1) AS KBounced, TRY_CAST(ISNULL(e.event_time, createdon) AS DATE) AS event_time      
						INTO #datekbounced      
						FROM Mysms.dbo.EmailDeliveryStatus AS e with (nolock) JOIN #batch AS b      
						ON e.BatchID=b.BatchID      
						WHERE event_status<>'001'      
						GROUP BY e.batchid, TRY_CAST(ISNULL(e.event_time, createdon) AS DATE);         

						SELECT e.BatchID, sum(KBounced) AS KBounced--, CAST(ISNULL(e.event_time, createdon) AS DATE) AS event_time      
						INTO #kbounced      
						FROM #datekbounced AS e with (nolock) JOIN #batch AS b      
						ON e.BatchID=b.BatchID      
						GROUP BY e.batchid--, CAST(ISNULL(e.event_time, createdon) AS DATE);      

						SELECT e.batchid, COUNT(1) AS Delivered, TRY_CAST( e.createdon AS DATE ) AS createdon      
						INTO #dateadstatus      
						FROM Mysms.dbo.Maildeliveries AS e with (nolock) JOIN #batch AS b      
						ON e.BatchID=b.BatchID      
						GROUP BY e.batchid, TRY_CAST( e.createdon AS DATE )   
      
						SELECT e.batchid, COUNT( 1 ) AS bounced, TRY_CAST( e.createdon AS DATE ) AS createdon
						INTO #dateabstatus      
						FROM Mysms.dbo.Mailbounces AS e with (nolock) JOIN #batch AS b      
						ON e.BatchID=b.BatchID      
						GROUP BY e.batchid, TRY_CAST( e.createdon AS DATE )

						SELECT e.batchid, sum(delivered) AS Delivered
						INTO #adstatus      
						FROM #dateadstatus AS e with (nolock) JOIN #batch AS b      
						ON e.BatchID=b.BatchID      
						GROUP BY e.batchid
      
						SELECT e.batchid, sum(bounced) bounced--, CAST( e.createdon AS DATE ) AS createdon      
						INTO #abstatus      
						FROM #dateabstatus AS e with (nolock) JOIN #batch AS b      
						ON e.BatchID=b.BatchID      
						GROUP BY e.batchid
      
						SELECT e.batchid, 
						sum(case when tablename='EmailsReportSent' then mailcount else 0 end) AS Sent, 
						sum(case when tablename='invalid_Mail_EmailsReport' then mailcount else 0 end) AS NotSent, 
						sum(case when tablename in ('Mail_EmailsReport00','Mail_EmailsReport01','Mail_EmailsReport02','Mail_EmailsReport03',
						'Mail_EmailsReport04','Mail_EmailsReport05','Mail_EmailsReport1','Mail_EmailsReport2') then mailcount else 0 end) AS EnteredQueue, 
						sum(case when tablename='Bad_emails' then mailcount else 0 end) AS InvalidMails
						INTO #sent      
						FROM emailcountracking AS e (nolock) JOIN #batch AS b      
						ON e.BatchID=b.BatchID      
						GROUP BY e.BatchID      
      
						SELECT e.batchid, COUNT( e.customer_reference_id ) AS Opened, TRY_CAST( e.event_date AS DATE ) AS event_date      
						INTO #datekopened      
						FROM Mysms.dbo.EngagementEventOpenClick AS e with (nolock) JOIN #batch AS b      
						ON e.BatchID=b.BatchID AND ISNUMERIC( e.BatchID )=1 AND ISNUMERIC( b.BatchID )=1      
						WHERE ISNULL( e.destination_url, '' )=''      
						GROUP BY e.batchid, TRY_CAST( e.event_date AS DATE );     
      
						SELECT e.batchid, COUNT( DISTINCT e.customer_reference_id ) AS Opened      
						INTO #kopened      
						FROM Mysms.dbo.EngagementEventOpenClick AS e with (nolock) JOIN #batch AS b      
						ON e.BatchID=b.BatchID AND ISNUMERIC( e.BatchID )=1 AND ISNUMERIC( b.BatchID )=1      
						WHERE ISNULL( e.destination_url, '' )=''      
						GROUP BY e.batchid;      
      
						SELECT e.batchid, COUNT( e.customer_reference_id ) AS Clicked, e.event_date      
						INTO #datekclicked      
						FROM Mysms.dbo.EngagementEventOpenClick AS e with (nolock) JOIN #batch AS b      
						ON e.BatchID=b.BatchID AND ISNUMERIC( e.BatchID )=1 AND ISNUMERIC( b.BatchID )=1      
						WHERE ISNULL( e.destination_url, '' )<>''      
						GROUP BY e.batchid, e.event_date;      
      
						SELECT e.batchid, COUNT( DISTINCT e.customer_reference_id ) AS Clicked      
						INTO #kclicked      
						FROM Mysms.dbo.EngagementEventOpenClick AS e with (nolock) JOIN #batch AS b      
						ON e.BatchID=b.BatchID AND ISNUMERIC( e.BatchID )=1 AND ISNUMERIC( b.BatchID )=1      
						WHERE ISNULL( e.destination_url, '' )<>''      
						GROUP BY e.batchid;   


				INSERT INTO MySMSReportCache.[dbo].[tbl_OpenedEmailData_Cache] 
				(
							   [Event_Date],[Opened],[UserId]
				)
				SELECT k.event_date, SUM( Opened ) AS Opened, @parentid as UserId      
				FROM #datekopened      
				AS k              
				WHERE event_date BETWEEN @fromdate AND @todate      
				GROUP BY event_date      
				ORDER BY event_date ASC;   

				INSERT INTO MySMSReportCache.[dbo].[tbl_ClickedEmail_Cache] 
				(
							   [Event_Date],[clicked],[UserId]
				)
				SELECT k.event_date, SUM( clicked ) AS clicked, @parentid as UserId        
				FROM #datekclicked AS k              
				WHERE event_date BETWEEN @fromdate AND @todate      
				GROUP BY event_date      
				ORDER BY event_date ASC;  

				INSERT INTO MySMSReportCache.[dbo].[tbl_DeliveredEmail_Cache] 
				(
							   [Event_Date]
							  ,[TotalRecords]
							  ,[Sent]
							  ,[SentButNotDelivered]
							  ,[Delivered]
							  ,[Bounced]
							  ,[UserId]
				)
						SELECT TRY_CAST(c.start_dts as date) AS Event_date, 
				SUM( isnull(totalrecords,0) ) AS TotalRecords,       
				SUM( isnull(totalrecords,0) ) AS Sent, 
				0 AS SentButNotDelivered,       
				SUM( ISNULL( a.delivered, 0 )+ISNULL( kd.KDelivered, 0 ) ) AS Delivered,       
				SUM( ISNULL( ab.bounced, 0 )+ISNULL( kb.KBounced, 0 ) ) AS Bounced,
				@parentid as UserId
				FROM #batch AS b 
				right join calendar as c on TRY_CAST(c.start_dts as date)=b.batchinserttime
				and TRY_CAST(c.start_dts as date) between @fromdate AND @todate
				LEFT JOIN #Dateadstatus AS a ON a.batchid=b.batchid AND a.createdon  between @fromdate AND @todate     
				LEFT JOIN #dateabstatus AS ab ON ab.batchid=b.BatchID AND ab.createdon   between @fromdate AND @todate    
				LEFT JOIN #datekdelivered AS kd ON kd.BatchID=b.BatchID AND kd.event_time       between @fromdate AND @todate
				LEFT JOIN #datekbounced AS kb ON kb.BatchID=b.BatchID AND kb.event_time   between @fromdate AND @todate
				where TRY_CAST(c.start_dts as date) between @fromdate AND @todate            
				GROUP BY TRY_CAST(c.start_dts as date)      
				ORDER BY TRY_CAST(c.start_dts as date) ASC;  

				INSERT INTO MySMSReportCache.[dbo].[tbl_EmailReportListView_Cache] 
				(
						   [BatchID]
						  ,[CampaignDate]
						  ,[Mail_Source]
						  ,[CampaignType]
						  ,[CampaignName]
						  ,[Recipients]
						  ,[Delivered]
						  ,[Bounced]
						  ,[Opened]
						  ,[Clicked]
						  ,[Sent]
						  ,[NotSent]
						  ,[TotalUnsubscribed]
						  ,[UserId]
				)
			SELECT batchid, CampaignDate, mail_source, campaigntype, campaignname, SUM( TotalRecords ) AS Recipients,       
			   SUM( ISNULL( delivered, 0 )+ISNULL( Kdelivered, 0 ) ) AS Delivered,       
			   SUM( ISNULL( Bounced, 0 )+ISNULL( kBounced, 0 ) )  AS bounced,       
			   SUM( ISNULL( opened, 0 ) ) AS Opened,  SUM( ISNULL( clicked, 0 ) ) AS Clicked,       
			   SUM( ISNULL( sent, 0 ) ) AS Sent, SUM( ISNULL( notsent, 0 )+ISNULL( invalidnotsent, 0 ) ) AS NotSent,       
			   ISNULL( TotalUnsubscribed, 0 ) AS TotalUnsubscribed, @parentid as UserId      
		FROM      
		(      
		  SELECT b.batchid, CampaignDate, mail_source, campaigntype, campaignname, TotalRecords, Sent, NotSent,       
				 Delivered, Bounced, Kdelivered, Kbounced, Opened, Clicked, s.NotSent InvalidNotSent, TotalUnsubscribed, @parentid as UserId     
		  FROM #batch AS b 
		  LEFT JOIN #sent AS s ON b.BatchID=s.batchid 
		  LEFT JOIN #abstatus AS ab ON ab.batchid=b.BatchID 
		  LEFT JOIN #adstatus AS ad ON ad.batchid=b.BatchID 
		  LEFT JOIN #kdelivered AS k ON k.BatchID=b.BatchID 
		  LEFT JOIN #kbounced AS kb ON kb.BatchID=b.BatchID 
		  LEFT JOIN #kopened AS ko ON ko.BatchID=b.BatchID 
		  LEFT JOIN #kclicked AS kc ON kc.BatchID=b.BatchID 
		  LEFT JOIN #unsubscribed AS u ON u.batchid=b.BatchID      
		)      
		AS a      
		WHERE campaigntype=CASE WHEN @campaigntype IS NULL THEN campaigntype ELSE @campaigntype END      
			  AND campaignname=CASE WHEN @campaignname IS NULL THEN campaignname ELSE @campaignname END      
		GROUP BY batchid,  CampaignDate,  campaigntype,  campaignname,  mail_source,  TotalUnsubscribed      
		ORDER BY CampaignDate DESC; 

				INSERT INTO MySMSReportCache.[dbo].[tbl_EmailReportMatrix_Cache] 
				(
						   [Recipients]
						  ,[Delivered]
						  ,[Bounced]
						  ,[Opened]
						  ,[Clicked]
						  ,[Sent]
						  ,[NotSent]
						  ,[TotalUnsubscribed]
						  ,[InvalidMails]
						  ,[inqueue]
						  ,[Unknown]
						  ,[UserId]
				)
				SELECT SUM( TotalRecords ) AS Recipients, SUM( ISNULL( delivered, 0 )+ISNULL( Kdelivered, 0 ) ) AS Delivered,       
				   SUM( ISNULL( Bounced, 0 )+ISNULL( kBounced, 0 ) ) AS bounced, SUM( ISNULL( opened, 0 ) ) AS Opened,       
				   SUM( ISNULL( clicked, 0 ) ) AS Clicked, SUM( ISNULL( sent, 0 ) ) AS Sent,       
				   SUM( ISNULL( notsent, 0 )) AS NotSent,       
				   SUM( ISNULL( TotalUnsubscribed, 0 ) ) AS TotalUnsubscribed,       
				SUM( ISNULL( InvalidMails, 0 ) ) AS InvalidMails,       
				   SUM( ISNULL( inqueue, 0 ) ) AS inqueue,
				   case when SUM( TotalRecords )- SUM( ISNULL( delivered, 0 )+ISNULL( Kdelivered, 0 ) )-SUM( ISNULL( Bounced, 0 )+ISNULL( kBounced, 0 ) )-
				   SUM( ISNULL( InvalidMails, 0 ) )>0 then  
					 SUM( TotalRecords )- SUM( ISNULL( delivered, 0 )+ISNULL( Kdelivered, 0 ) )-SUM( ISNULL( Bounced, 0 )+ISNULL( kBounced, 0 ) )-
				   SUM( ISNULL( InvalidMails, 0 ) ) else 0 end as Unknown , @parentid as UserId
			FROM      
			(      
			  SELECT CampaignDate, mail_source, campaigntype, campaignname, TotalRecords, Sent, NotSent, Delivered,       
					 Bounced, Kdelivered, Kbounced, Opened, Clicked, TotalUnsubscribed,       
					 InvalidMails, (EnteredQueue-Sent) as inqueue, @parentid as UserId
			  FROM #batch AS b 
			  LEFT JOIN #sent AS s ON b.BatchID=s.batchid 
			  LEFT JOIN #abstatus AS ab ON ab.batchid=b.BatchID 
			  LEFT JOIN #adstatus AS ad ON ad.batchid=b.BatchID 
			  LEFT JOIN #kdelivered AS k ON k.BatchID=b.BatchID 
			  LEFT JOIN #kbounced AS kb ON kb.BatchID=b.BatchID 
			  LEFT JOIN #kopened AS ko ON ko.BatchID=b.BatchID 
			  LEFT JOIN #kclicked AS kc ON kc.BatchID=b.BatchID 
			  LEFT JOIN #unsubscribed AS u ON u.batchid=b.BatchID 
			  WHERE campaigntype=CASE WHEN @campaigntype IS NULL THEN campaigntype ELSE @campaigntype END      
					AND campaignname=CASE WHEN @campaignname IS NULL THEN campaignname ELSE @campaignname END      
			)      
			AS a;  


				INSERT INTO MySMSReportCache.[dbo].[tbl_OpenedEmailData_Archive] 
				(
							   [Event_Date],[Opened],[UserId]
				)
				SELECT k.event_date, SUM( Opened ) AS Opened, @parentid as UserId      
				FROM #datekopened      
				AS k              
				WHERE event_date BETWEEN @fromdate AND @todate      
				GROUP BY event_date      
				ORDER BY event_date ASC;   

				INSERT INTO MySMSReportCache.[dbo].[tbl_ClickedEmail_Archive] 
				(
							   [Event_Date],[clicked],[UserId]
				)
				SELECT k.event_date, SUM( clicked ) AS clicked, @parentid as UserId        
				FROM #datekclicked AS k              
				WHERE event_date BETWEEN @fromdate AND @todate      
				GROUP BY event_date      
				ORDER BY event_date ASC;  

				INSERT INTO MySMSReportCache.[dbo].[tbl_DeliveredEmail_Archive] 
				(
							   [Event_Date]
							  ,[TotalRecords]
							  ,[Sent]
							  ,[SentButNotDelivered]
							  ,[Delivered]
							  ,[Bounced]
							  ,[UserId]
				)
						SELECT TRY_CAST(c.start_dts as date) AS Event_date, 
				SUM( isnull(totalrecords,0) ) AS TotalRecords,       
				SUM( isnull(totalrecords,0) ) AS Sent, 
				0 AS SentButNotDelivered,       
				SUM( ISNULL( a.delivered, 0 )+ISNULL( kd.KDelivered, 0 ) ) AS Delivered,       
				SUM( ISNULL( ab.bounced, 0 )+ISNULL( kb.KBounced, 0 ) ) AS Bounced,
				@parentid as UserId
				FROM #batch AS b 
				right join calendar as c on TRY_CAST(c.start_dts as date)=b.batchinserttime
				and TRY_CAST(c.start_dts as date) between @fromdate AND @todate
				LEFT JOIN #Dateadstatus AS a ON a.batchid=b.batchid AND a.createdon  between @fromdate AND @todate     
				LEFT JOIN #dateabstatus AS ab ON ab.batchid=b.BatchID AND ab.createdon   between @fromdate AND @todate    
				LEFT JOIN #datekdelivered AS kd ON kd.BatchID=b.BatchID AND kd.event_time       between @fromdate AND @todate
				LEFT JOIN #datekbounced AS kb ON kb.BatchID=b.BatchID AND kb.event_time   between @fromdate AND @todate
				where TRY_CAST(c.start_dts as date) between @fromdate AND @todate            
				GROUP BY TRY_CAST(c.start_dts as date)      
				ORDER BY TRY_CAST(c.start_dts as date) ASC;  

				INSERT INTO MySMSReportCache.[dbo].[tbl_EmailReportListView_Archive] 
				(
						   [BatchID]
						  ,[CampaignDate]
						  ,[Mail_Source]
						  ,[CampaignType]
						  ,[CampaignName]
						  ,[Recipients]
						  ,[Delivered]
						  ,[Bounced]
						  ,[Opened]
						  ,[Clicked]
						  ,[Sent]
						  ,[NotSent]
						  ,[TotalUnsubscribed]
						  ,[UserId]
				)
			SELECT batchid, CampaignDate, mail_source, campaigntype, campaignname, SUM( TotalRecords ) AS Recipients,       
			   SUM( ISNULL( delivered, 0 )+ISNULL( Kdelivered, 0 ) ) AS Delivered,       
			   SUM( ISNULL( Bounced, 0 )+ISNULL( kBounced, 0 ) )  AS bounced,       
			   SUM( ISNULL( opened, 0 ) ) AS Opened,  SUM( ISNULL( clicked, 0 ) ) AS Clicked,       
			   SUM( ISNULL( sent, 0 ) ) AS Sent, SUM( ISNULL( notsent, 0 )+ISNULL( invalidnotsent, 0 ) ) AS NotSent,       
			   ISNULL( TotalUnsubscribed, 0 ) AS TotalUnsubscribed, @parentid as UserId      
		FROM      
		(      
		  SELECT b.batchid, CampaignDate, mail_source, campaigntype, campaignname, TotalRecords, Sent, NotSent,       
				 Delivered, Bounced, Kdelivered, Kbounced, Opened, Clicked, s.NotSent InvalidNotSent, TotalUnsubscribed      
		  FROM #batch AS b 
		  LEFT JOIN #sent AS s ON b.BatchID=s.batchid 
		  LEFT JOIN #abstatus AS ab ON ab.batchid=b.BatchID 
		  LEFT JOIN #adstatus AS ad ON ad.batchid=b.BatchID 
		  LEFT JOIN #kdelivered AS k ON k.BatchID=b.BatchID 
		  LEFT JOIN #kbounced AS kb ON kb.BatchID=b.BatchID 
		  LEFT JOIN #kopened AS ko ON ko.BatchID=b.BatchID 
		  LEFT JOIN #kclicked AS kc ON kc.BatchID=b.BatchID 
		  LEFT JOIN #unsubscribed AS u ON u.batchid=b.BatchID      
		)      
		AS a      
		WHERE campaigntype=CASE WHEN @campaigntype IS NULL THEN campaigntype ELSE @campaigntype END      
			  AND campaignname=CASE WHEN @campaignname IS NULL THEN campaignname ELSE @campaignname END      
		GROUP BY batchid,  CampaignDate,  campaigntype,  campaignname,  mail_source,  TotalUnsubscribed      
		ORDER BY CampaignDate DESC; 

				INSERT INTO MySMSReportCache.[dbo].[tbl_EmailReportMatrix_Archive] 
				(
						   [Recipients]
						  ,[Delivered]
						  ,[Bounced]
						  ,[Opened]
						  ,[Clicked]
						  ,[Sent]
						  ,[NotSent]
						  ,[TotalUnsubscribed]
						  ,[InvalidMails]
						  ,[inqueue]
						  ,[Unknown]
						  ,[UserId]
				)
				SELECT SUM( TotalRecords ) AS Recipients, SUM( ISNULL( delivered, 0 )+ISNULL( Kdelivered, 0 ) ) AS Delivered,       
				   SUM( ISNULL( Bounced, 0 )+ISNULL( kBounced, 0 ) ) AS bounced, SUM( ISNULL( opened, 0 ) ) AS Opened,       
				   SUM( ISNULL( clicked, 0 ) ) AS Clicked, SUM( ISNULL( sent, 0 ) ) AS Sent,       
				   SUM( ISNULL( notsent, 0 )) AS NotSent,       
				   SUM( ISNULL( TotalUnsubscribed, 0 ) ) AS TotalUnsubscribed,       
				SUM( ISNULL( InvalidMails, 0 ) ) AS InvalidMails,       
				   SUM( ISNULL( inqueue, 0 ) ) AS inqueue,
				   case when SUM( TotalRecords )- SUM( ISNULL( delivered, 0 )+ISNULL( Kdelivered, 0 ) )-SUM( ISNULL( Bounced, 0 )+ISNULL( kBounced, 0 ) )-
				   SUM( ISNULL( InvalidMails, 0 ) )>0 then  
					 SUM( TotalRecords )- SUM( ISNULL( delivered, 0 )+ISNULL( Kdelivered, 0 ) )-SUM( ISNULL( Bounced, 0 )+ISNULL( kBounced, 0 ) )-
				   SUM( ISNULL( InvalidMails, 0 ) ) else 0 end as Unknown , @parentid as UserId
			FROM      
			(      
			  SELECT CampaignDate, mail_source, campaigntype, campaignname, TotalRecords, Sent, NotSent, Delivered,       
					 Bounced, Kdelivered, Kbounced, Opened, Clicked, TotalUnsubscribed,       
					 InvalidMails, (EnteredQueue-Sent) as inqueue
			  FROM #batch AS b 
			  LEFT JOIN #sent AS s ON b.BatchID=s.batchid 
			  LEFT JOIN #abstatus AS ab ON ab.batchid=b.BatchID 
			  LEFT JOIN #adstatus AS ad ON ad.batchid=b.BatchID 
			  LEFT JOIN #kdelivered AS k ON k.BatchID=b.BatchID 
			  LEFT JOIN #kbounced AS kb ON kb.BatchID=b.BatchID 
			  LEFT JOIN #kopened AS ko ON ko.BatchID=b.BatchID 
			  LEFT JOIN #kclicked AS kc ON kc.BatchID=b.BatchID 
			  LEFT JOIN #unsubscribed AS u ON u.batchid=b.BatchID 
			  WHERE campaigntype=CASE WHEN @campaigntype IS NULL THEN campaigntype ELSE @campaigntype END      
					AND campaignname=CASE WHEN @campaignname IS NULL THEN campaignname ELSE @campaignname END      
			)      
			AS a;  


		DROP TABLE IF EXISTS #batcht;      
		DROP TABLE IF EXISTS #batch;      
		DROP TABLE IF EXISTS #invalidmails;      
		DROP TABLE IF EXISTS #sent;      
		DROP TABLE IF EXISTS #kdelivered;      
		DROP TABLE IF EXISTS #kbounced;      
		DROP TABLE IF EXISTS #kopened;      
		DROP TABLE IF EXISTS #kclicked;      
		DROP TABLE IF EXISTS #adstatus;      
		DROP TABLE IF EXISTS #abstatus;      
		DROP TABLE IF EXISTS #dateinvalidmails;      
		DROP TABLE IF EXISTS #datesent;      
		DROP TABLE IF EXISTS #datekdelivered;      
		DROP TABLE IF EXISTS #datekbounced;      
		DROP TABLE IF EXISTS #datekopened;      
		DROP TABLE IF EXISTS #datekclicked;      
		DROP TABLE IF EXISTS #dateadstatus;      
		DROP TABLE IF EXISTS #dateabstatus;      
		DROP TABLE IF EXISTS #unsubscribed;      
		DROP TABLE IF EXISTS #badmails;      
		DROP TABLE IF EXISTS #inqueue;  

-- END

END TRY
BEGIN CATCH
exec usp_InsertErrorInfo
END CATCH
-- Move to the next row
        SET @currentRow = @currentRow + 1;
END
			-- Delete old data
				DELETE FROM MySMSReportCache.[dbo].[tbl_OpenedEmailData_Cache]
				WHERE Event_Date NOT BETWEEN DATEADD(DAY, -30, TRY_CAST(GETDATE() AS DATE)) AND TRY_CAST(GETDATE() AS DATE);

				DELETE FROM MySMSReportCache.[dbo].[tbl_ClickedEmail_Cache]
				WHERE Event_Date NOT BETWEEN DATEADD(DAY, -30, TRY_CAST(GETDATE() AS DATE)) AND TRY_CAST(GETDATE() AS DATE);

				DELETE FROM MySMSReportCache.[dbo].[tbl_DeliveredEmail_Cache]
				WHERE Event_Date NOT BETWEEN DATEADD(DAY, -30, TRY_CAST(GETDATE() AS DATE)) AND TRY_CAST(GETDATE() AS DATE);

				DELETE FROM MySMSReportCache.[dbo].[tbl_EmailReportListView_Cache]
				WHERE CampaignDate NOT BETWEEN DATEADD(DAY, -30, TRY_CAST(GETDATE() AS DATE)) AND TRY_CAST(GETDATE() AS DATE);

				--DELETE FROM MySMSReportCache.[dbo].[tbl_EmailReportMatrix_Cache]
				--WHERE CampaignDate NOT BETWEEN DATEADD(DAY, -30, CAST(GETDATE() AS DATE)) AND CAST(GETDATE() AS DATE);
		  -- end Delete old data

-- Clean up the temporary table
    DROP TABLE #UserIDs;
		
END



GO

/* ============================================================
   Procedure: [dbo].[usp_Insert_EmployeeCalendarReport_DataTo_Archive]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON




-- select * from MySMSReportCache.[dbo].[tbl_EmployeeCalenderReport_Cache]  select * from MySMSReportCache.[dbo].[tbl_EmployeeCalenderReport_Archive]

   --TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_EmployeeCalenderReport_Cache];  TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_EmployeeCalenderReport_Archive];

-- exec [dbo].[usp_Insert_EmployeeCalendarReport_DataTo_Archive]

CREATE   PROCEDURE [dbo].[usp_Insert_EmployeeCalendarReport_DataTo_Archive] 

AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	SET NOCOUNT ON;

	DECLARE @userid BIGINT;
    DECLARE @currentRow INT = 1;  -- Variable to track the current row in the temporary table
    DECLARE @totalRows INT;       -- Variable to store the total number of rows to process

    -- Create a temporary table to store the User IDs
    CREATE TABLE #UserIDs (UserID BIGINT);

    -- Insert UserIDs into the temporary table
    INSERT INTO #UserIDs (UserID)
    SELECT User_ID
    FROM Mysms.dbo.User_Detail (NOLOCK)
	WHERE User_ID IS NOT NULL
    GROUP BY User_ID
    ORDER BY COUNT(*) DESC;
	
    -- Get the total number of rows
    SELECT @totalRows = COUNT(*) FROM #UserIDs;

-- Loop through each User_ID using a WHILE loop
    WHILE @currentRow <= @totalRows
BEGIN
BEGIN TRY
			-- Use a CTE to calculate ROW_NUMBER() and select the current UserID
				WITH CTE_UserIDs AS (
					SELECT UserID, ROW_NUMBER() OVER (ORDER BY UserID) AS RowNum
					FROM #UserIDs
				)
				SELECT @userid = UserID
				FROM CTE_UserIDs
				WHERE RowNum = @currentRow;

   
			Declare 
					@fromdate DATE = NULL,       
					@todate   DATE = NULL,
					@PagingSize int = 100,
					@OffsetValue int = 0,
					@Condition varchar(max) = '',
					@SearchText nvarchar(max) = ''; 


			Declare @Currentdate  DATE  = GETDATE();  -- Today's date
			-- SET @fromdate      = DATEADD(DAY, -30, @Currentdate); -- 30 days before today
			-- SET @todate  = @Currentdate;
			
			--SET @fromdate  = DATEADD(DAY, -1, @Currentdate); -- 1 day before today		
			IF NOT EXISTS ( 
					SELECT 1 
					FROM MySMSReportCache.[dbo].[tbl_EmployeeCalenderReport_Archive](NOLOCK)
					WHERE UserId = @userid
				)
				BEGIN


			    declare @ParentId bigint  
			select @ParentId = ParentID from User_Detail(nolock) u where u.User_ID = @userid  
			

				Declare @query1 nvarchar(max)
					Declare @query2 nvarchar(max)

					set @query1 = ' Select distinct count(t.AttendanceId) over() as TotalRecords, t.*, ''Day Schedule'' DayType
					from (Select dbo.fn_TBL_ET_GetAttendanceStatus(atra.AttendanceGroupId, (case when ((DATEDIFF(minute,TRY_CAST(atra.AttendanceIn AS DATETIME), TRY_CAST(isnull(atra.AttendanceOut, atra.AttendanceIn) AS DATETIME)) * 100)/DATEDIFF(MINUTE, smat.StartTime, smat.EndTime)) > 100 then 100 else ((DATEDIFF(minute,TRY_CAST(atra.AttendanceIn AS DATETIME), TRY_CAST(isnull(atra.AttendanceOut, atra.AttendanceIn) AS DATETIME)) * 100)/DATEDIFF(MINUTE, smat.StartTime, smat.EndTime)) end)) AttendanceStatus, dbo.fn_TBL_ET_AttendanceTotalSummary(atra.UserId, TRY_CAST(CONVERT(VARCHAR(10),TRY_CAST(atra.AttendanceIn AS DATE),105) as varchar(10)), ''TotalCount'') TotalhoursMonth, dbo.fn_TBL_ET_AttendanceTotalSummary(atra.UserId, TRY_CAST(CONVERT(VARCHAR(10),TRY_CAST(atra.AttendanceIn AS DATE),105) as varchar(10)), ''TotalWorkingDay'') TotalWorkingDay, dbo.fn_TBL_ET_AttendanceTotalSummary(atra.UserId, TRY_CAST(CONVERT(VARCHAR(10),TRY_CAST(atra.AttendanceIn AS DATE),105) as varchar(10)), ''TotalLeave'') TotalLeave, dbo.fn_TBL_ET_AttendanceTotalSummary(atra.UserId, TRY_CAST(CONVERT(VARCHAR(10),TRY_CAST(atra.AttendanceIn AS DATE),105) as varchar(10)), ''WeekOff'') WeekOff, dbo.fn_TBL_ET_AttendanceTotalSummary(atra.UserId, TRY_CAST(CONVERT(VARCHAR(10),TRY_CAST(atra.AttendanceIn AS DATE),105) as varchar(10)), ''LateSignin'') LateSignin, atra.AttendanceId, FORMAT(TRY_CAST(tmde.MDate AS DATETIME),''dd-MMM-yyyy'') MDate, atra.AttendanceIn, 
					atra.AttendanceOut, FORMAT(TRY_CAST(atra.AttendanceIn AS DATETIME),''hh:mm tt'') IATime, FORMAT(TRY_CAST(atra.AttendanceOut AS DATETIME),''hh:mm tt'') OATime, 
					(TRY_CAST(DATEDIFF(hour,TRY_CAST(atra.AttendanceIn AS DATETIME), TRY_CAST(isnull(atra.AttendanceOut, atra.AttendanceIn) AS DATETIME)) as varchar(10)) +'':''+ TRY_CAST((DATEDIFF(minute,TRY_CAST(atra.AttendanceIn AS DATETIME), TRY_CAST(isnull(atra.AttendanceOut, atra.AttendanceIn) AS DATETIME))%60) as varchar(10))) +'' Hrs'' TotalHours,
					TRY_CAST(atra.AttendanceIn as date) IADate, TRY_CAST(atra.AttendanceOut as date) OADate, atra.CreatedDate, atra.LatitudeIn, atra.LongitudeIn, atra.LatitudeOut,
					atra.LongitudeOut, atra.DeviceId, atra.RemarksIn, atra.RemarksOut, atra.AttendanceGroupId, atra.ShiftId, smat.ShiftName, agum.UserId, atra.ParentId, (ud2.FName +'' ''+ ud2.LName) UserName,ud2.User_Login, atra.CreatedBy, isnull(atra.UpdatedBy, atra.CreatedBy) UpdatedBy, atra.IsActive,
					smat.StartTime, smat.EndTime, TRY_CAST((TRY_CAST((DATEDIFF(MINUTE, smat.StartTime, smat.EndTime)/60) as varchar(10)) +'':''+ (TRY_CAST(isnull(DATEDIFF(MINUTE, smat.StartTime, smat.EndTime),''00'')%60 as varchar(10)))) as varchar(15)) ShiftTime,
					TRY_CAST(TRY_CAST(DATEDIFF(hour,TRY_CAST(atra.AttendanceIn AS DATETIME), TRY_CAST(isnull(atra.AttendanceOut, atra.AttendanceIn) AS DATETIME)) as varchar(10)) +'':''+ TRY_CAST((DATEDIFF(minute,TRY_CAST(atra.AttendanceIn AS DATETIME), TRY_CAST(isnull(atra.AttendanceOut, atra.AttendanceIn) AS DATETIME))%60) as varchar(10)) as time) WorkingTime, DATEDIFF(MINUTE, smat.StartTime, smat.EndTime) ShiftMinutes,
					DATEDIFF(minute,TRY_CAST(atra.AttendanceIn AS DATETIME), TRY_CAST(isnull(atra.AttendanceOut, atra.AttendanceIn) AS DATETIME)) WorkingMinutes,
					(case when ((DATEDIFF(minute,TRY_CAST(atra.AttendanceIn AS DATETIME), TRY_CAST(isnull(atra.AttendanceOut, atra.AttendanceIn) AS DATETIME)) * 100)/DATEDIFF(MINUTE, smat.StartTime, smat.EndTime)) > 100 then 100 else ((DATEDIFF(minute,TRY_CAST(atra.AttendanceIn AS DATETIME), TRY_CAST(isnull(atra.AttendanceOut, atra.AttendanceIn) AS DATETIME)) * 100)/DATEDIFF(MINUTE, smat.StartTime, smat.EndTime)) end) AttendancePerc, 
					  dbo.fn_TBL_ET_GeoEntityCheckInOutCount(atra.UserId, TRY_CAST(atra.AttendanceIn as varchar(20)), ''CheckIn'') CheckInCount, 
					  dbo.fn_TBL_ET_GeoEntityCheckInOutCount(atra.UserId, TRY_CAST(atra.AttendanceIn as varchar(20)), ''CheckOut'') CheckOutCount,
					  dbo.fn_TBL_ET_BreakTransactionListByUserIdDate(atra.UserId, TRY_CAST(atra.AttendanceIn as varchar(20))) BreakTrans
					 from TBL_ET_TEMPMonthDate(nolock) tmde '


					set @query2 = ' left join TBL_ET_Attendance(nolock) atra on TRY_CAST(tmde.MDate as date) = TRY_CAST(atra.AttendanceIn as date) 
					 inner join TBL_ET_AttendanceGroup(nolock) atgp on atra.AttendanceGroupId = atgp.AttendanceGroupId 
					 left join TBL_ET_AttendanceGroupUserMapping (nolock) agum on atra.UserId = agum.UserId 
					 left join User_Detail(nolock) ud2 on agum.UserId = ud2.User_ID 
					 left join tbl_inv_UserTaxNumber (nolock) iutn on agum.UserBranchId = iutn.Id
					 left join M_City (nolock) ct on iutn.City_Id = ct.City_Id
					 left join M_State (nolock) st on iutn.State_Id = st.State_Id
					 left join M_Country (nolock) co on iutn.Country_Id = co.Country_Id
					 left join TBL_ET_ShiftMaster (nolock) smat on atra.ShiftId = smat.ShiftId
					 where (agum.UserId = ' + TRY_CAST(@UserId as nvarchar(max)) + ') 
					)t where (1=1) ' + @SearchText + ' '+ @Condition + ' 
					 Order By t.AttendanceIn Asc 
					 Offset ' + TRY_CAST(@OffsetValue as varchar(10)) + ' rows fetch next '+ TRY_CAST(@PagingSize as varchar(10)) + ' rows only ' 


						DECLARE @CombinedQuery NVARCHAR(MAX);
							SET @CombinedQuery = @query1 + @query2;

							--  Create Temporary Table
							CREATE TABLE #TempTable (
								TotalRecords NVARCHAR(100),
								AttendanceId NVARCHAR(100),
								DayType NVARCHAR(100),
								AttendanceStatus NVARCHAR(100),
								TotalhoursMonth NVARCHAR(100),
