								UserId NVARCHAR(100),
								ParentId NVARCHAR(100),
								UserName NVARCHAR(100),
								User_Login NVARCHAR(100),
								CreatedBy NVARCHAR(100),
								UpdatedBy NVARCHAR(100),
								IsActive NVARCHAR(100),
								StartTime NVARCHAR(100),
								EndTime NVARCHAR(100),
								ShiftTime NVARCHAR(100),
								WorkingTime NVARCHAR(100),
								ShiftMinutes NVARCHAR(100),
								WorkingMinutes NVARCHAR(100),
								AttendancePerc NVARCHAR(100),
								CheckInCount NVARCHAR(100),
								CheckOutCount NVARCHAR(100),
								BreakTrans NVARCHAR(MAX)
							);
				
						INSERT INTO #TempTable
						EXEC sp_executesql @CombinedQuery;

			    -- start data insert into cache tables

				INSERT INTO MySMSReportCache.[dbo].[tbl_EmployeeCalenderReport_Archive] 
				(		   
						   [TotalRecords]
						  ,[AttendanceId]
						  ,[MDate]
						  ,[AttendanceIn]
						  ,[AttendanceOut]
						  ,[IADate]
						  ,[IATime]
						  ,[OADate]
						  ,[OATime]
						  ,[TotalHours]
						  ,[LatitudeIn]
						  ,[LongitudeIn]
						  ,[LatitudeOut]
						  ,[LongitudeOut]
						  ,[AttendanceGroupId]
						  ,[UserId]
						  ,[ParentId]
						  ,[ShiftId]
						  ,[ShiftName]
						  ,[RemarksIn]
						  ,[RemarksOut]
						  ,[DeviceId]
						  ,[CreatedBy]
						  ,[UpdatedBy]
						  ,[CreatedDate]
						  ,[IsActive]
						  ,[DayType]
						  ,[AttendanceStatus]
						  ,[AttendancePerc]
						  ,[CheckInCount]
						  ,[CheckOutCount]
						  ,[WorkingMinutes]
						  ,[StartTime]
						  ,[BreakTrans]
						  ,[TotalhoursMonth]
						  ,[TotalWorkingDay]
						  ,[TotalLeave]
						  ,[WeekOff]
						  ,[LateSignin]
						  ,[UserName]
						  ,[User_Login]
						  ,[ShiftMinutes]
						  ,[WorkingTime]
						  ,[ShiftTime]
						  ,[EndTime]
				)
				  SELECT 
						   TotalRecords
						  ,AttendanceId
						  ,MDate
						  ,AttendanceIn
						  ,AttendanceOut
						  ,IADate
						  ,IATime
						  ,OADate
						  ,OATime
						  ,TotalHours
						  ,LatitudeIn
						  ,LongitudeIn
						  ,LatitudeOut
						  ,LongitudeOut
						  ,AttendanceGroupId
						  ,UserId
						  ,ParentId
						  ,ShiftId
						  ,ShiftName
						  ,RemarksIn
						  ,RemarksOut
						  ,DeviceId
						  ,CreatedBy
						  ,UpdatedBy
						  ,CreatedDate
						  ,IsActive
						  ,DayType
						  ,AttendanceStatus
						  ,AttendancePerc
						  ,CheckInCount
						  ,CheckOutCount
						  ,WorkingMinutes
						  ,StartTime
						  ,BreakTrans
						  ,TotalhoursMonth
						  ,TotalWorkingDay
						  ,TotalLeave
						  ,WeekOff
						  ,LateSignin
						  ,UserName
						  ,User_Login
						  ,ShiftMinutes
						  ,WorkingTime
						  ,ShiftTime
						  ,EndTime
					FROM #TempTable;  
					
				-- end data insert into cache tables

			-- Clean up the temporary table
				DROP TABLE #TempTable;

END
END TRY
BEGIN CATCH
exec usp_InsertErrorInfo
END CATCH
-- Move to the next row
        SET @currentRow = @currentRow + 1;
