CREATE   PROCEDURE [dbo].[usp_Insert_EmployeeCalendarReport_DataTo_Cache_Archive] 

AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	SET NOCOUNT ON;

	DECLARE @userid BIGINT;
    DECLARE @currentRow INT = 1;  -- Variable to track the current row in the temporary table
    DECLARE @totalRows INT;       -- Variable to store the total number of rows to process

    -- Create a temporary table to store the User IDs
    CREATE TABLE #UserIDs (UserID BIGINT);

    -- Insert UserIDs into the temporary table
    INSERT INTO #UserIDs (UserID)
    SELECT User_ID
    FROM MYSMS.dbo.User_Detail (NOLOCK)
	WHERE User_ID IS NOT NULL
    GROUP BY User_ID
    ORDER BY COUNT(*) DESC;
	
    -- Get the total number of rows
    SELECT @totalRows = COUNT(*) FROM #UserIDs;

-- Loop through each User_ID using a WHILE loop
    WHILE @currentRow <= @totalRows
BEGIN
BEGIN TRY
			-- Use a CTE to calculate ROW_NUMBER() and select the current UserID
				WITH CTE_UserIDs AS (
					SELECT UserID, ROW_NUMBER() OVER (ORDER BY UserID) AS RowNum
					FROM #UserIDs
				)
				SELECT @userid = UserID
				FROM CTE_UserIDs
				WHERE RowNum = @currentRow;

   
			Declare 
					@fromdate DATE = NULL,       
					@todate   DATE = NULL,
					@PagingSize int = 100,
					@OffsetValue int = 0,
					@Condition varchar(max) = '',
					@SearchText nvarchar(max) = ''; 


			Declare @Currentdate  DATE  = GETDATE();  -- Today's date
			--SET @fromdate      = DATEADD(DAY, -30, @Currentdate); -- 30 days before today
			SET @fromdate  = DATEADD(DAY, -1, @Currentdate); -- 1 day before today
			SET @todate  = @Currentdate;
								
			--IF NOT EXISTS ( 
			--		SELECT 1 
			--		FROM MySMSReportCache.[dbo].[tbl_EmployeeCalenderReport_Cache](NOLOCK)
			--		WHERE UserId = @userid and TRY_CAST(MDate as Date) between @fromdate and @todate
			--	)
			--	BEGIN

			    declare @ParentId bigint  
			    select @ParentId = ParentID from User_Detail(nolock) u where u.User_ID = @userid  
			
				Declare @query1 nvarchar(max)
					Declare @query2 nvarchar(max)

					set @query1 = 'Select distinct count(t.AttendanceId) over() as TotalRecords, t.*, ''Day Schedule'' DayType
					from (Select dbo.fn_TBL_ET_GetAttendanceStatus(atra.AttendanceGroupId, (case when ((DATEDIFF(minute,TRY_CAST(atra.AttendanceIn AS DATETIME), TRY_CAST(isnull(atra.AttendanceOut, atra.AttendanceIn) AS DATETIME)) * 100)/DATEDIFF(MINUTE, smat.StartTime, smat.EndTime)) > 100 then 100 else ((DATEDIFF(minute,TRY_CAST(atra.AttendanceIn AS DATETIME), TRY_CAST(isnull(atra.AttendanceOut, atra.AttendanceIn) AS DATETIME)) * 100)/DATEDIFF(MINUTE, smat.StartTime, smat.EndTime)) end)) AttendanceStatus, dbo.fn_TBL_ET_AttendanceTotalSummary(atra.UserId, TRY_CAST(CONVERT(VARCHAR(10),TRY_CAST(atra.AttendanceIn AS DATE),105) as varchar(10)), ''TotalCount'') TotalhoursMonth, dbo.fn_TBL_ET_AttendanceTotalSummary(atra.UserId, TRY_CAST(CONVERT(VARCHAR(10),TRY_CAST(atra.AttendanceIn AS DATE),105) as varchar(10)), ''TotalWorkingDay'') TotalWorkingDay, dbo.fn_TBL_ET_AttendanceTotalSummary(atra.UserId, TRY_CAST(CONVERT(VARCHAR(10),TRY_CAST(atra.AttendanceIn AS DATE),105) as varchar(10)), ''TotalLeave'') TotalLeave, dbo.fn_TBL_ET_AttendanceTotalSummary(atra.UserId, TRY_CAST(CONVERT(VARCHAR(10),TRY_CAST(atra.AttendanceIn AS DATE),105) as varchar(10)), ''WeekOff'') WeekOff, dbo.fn_TBL_ET_AttendanceTotalSummary(atra.UserId, TRY_CAST(CONVERT(VARCHAR(10),TRY_CAST(atra.AttendanceIn AS DATE),105) as varchar(10)), ''LateSignin'') LateSignin, atra.AttendanceId, FORMAT(TRY_CAST(tmde.MDate AS DATETIME),''dd-MMM-yyyy'') MDate, atra.AttendanceIn, 
					atra.AttendanceOut, FORMAT(TRY_CAST(atra.AttendanceIn AS DATETIME),''hh:mm tt'') IATime, FORMAT(TRY_CAST(atra.AttendanceOut AS DATETIME),''hh:mm tt'') OATime, 
					(TRY_CAST(DATEDIFF(hour,TRY_CAST(atra.AttendanceIn AS DATETIME), TRY_CAST(isnull(atra.AttendanceOut, atra.AttendanceIn) AS DATETIME)) as varchar(10)) +'':''+ TRY_CAST((DATEDIFF(minute,TRY_CAST(atra.AttendanceIn AS DATETIME), TRY_CAST(isnull(atra.AttendanceOut, atra.AttendanceIn) AS DATETIME))%60) as varchar(10))) +'' Hrs'' TotalHours,
					TRY_CAST(atra.AttendanceIn as date) IADate, TRY_CAST(atra.AttendanceOut as date) OADate, atra.CreatedDate, atra.LatitudeIn, atra.LongitudeIn, atra.LatitudeOut,
					atra.LongitudeOut, atra.DeviceId, atra.RemarksIn, atra.RemarksOut, atra.AttendanceGroupId, atra.ShiftId, smat.ShiftName, agum.UserId, atra.ParentId, (ud2.FName +'' ''+ ud2.LName) UserName,ud2.User_Login, atra.CreatedBy, isnull(atra.UpdatedBy, atra.CreatedBy) UpdatedBy, atra.IsActive,
					smat.StartTime, smat.EndTime, TRY_CAST((TRY_CAST((DATEDIFF(MINUTE, smat.StartTime, smat.EndTime)/60) as varchar(10)) +'':''+ (TRY_CAST(isnull(DATEDIFF(MINUTE, smat.StartTime, smat.EndTime),''00'')%60 as varchar(10)))) as varchar(15)) ShiftTime,
					TRY_CAST(TRY_CAST(DATEDIFF(hour,TRY_CAST(atra.AttendanceIn AS DATETIME), TRY_CAST(isnull(atra.AttendanceOut, atra.AttendanceIn) AS DATETIME)) as varchar(10)) +'':''+ TRY_CAST((DATEDIFF(minute,TRY_CAST(atra.AttendanceIn AS DATETIME), TRY_CAST(isnull(atra.AttendanceOut, atra.AttendanceIn) AS DATETIME))%60) as varchar(10)) as time) WorkingTime, DATEDIFF(MINUTE, smat.StartTime, smat.EndTime) ShiftMinutes,
					DATEDIFF(minute,TRY_CAST(atra.AttendanceIn AS DATETIME), TRY_CAST(isnull(atra.AttendanceOut, atra.AttendanceIn) AS DATETIME)) WorkingMinutes,
					(case when ((DATEDIFF(minute,TRY_CAST(atra.AttendanceIn AS DATETIME), TRY_CAST(isnull(atra.AttendanceOut, atra.AttendanceIn) AS DATETIME)) * 100)/DATEDIFF(MINUTE, smat.StartTime, smat.EndTime)) > 100 then 100 else ((DATEDIFF(minute,TRY_CAST(atra.AttendanceIn AS DATETIME), TRY_CAST(isnull(atra.AttendanceOut, atra.AttendanceIn) AS DATETIME)) * 100)/DATEDIFF(MINUTE, smat.StartTime, smat.EndTime)) end) AttendancePerc, 
					  dbo.fn_TBL_ET_GeoEntityCheckInOutCount(atra.UserId, TRY_CAST(atra.AttendanceIn as varchar(20)), ''CheckIn'') CheckInCount, 
					  dbo.fn_TBL_ET_GeoEntityCheckInOutCount(atra.UserId, TRY_CAST(atra.AttendanceIn as varchar(20)), ''CheckOut'') CheckOutCount,
					  dbo.fn_TBL_ET_BreakTransactionListByUserIdDate(atra.UserId, TRY_CAST(atra.AttendanceIn as varchar(20))) BreakTrans
					 from TBL_ET_TEMPMonthDate(nolock) tmde '

					set @query2 = 'left join TBL_ET_Attendance(nolock) atra on TRY_CAST(tmde.MDate as date) = TRY_CAST(atra.AttendanceIn as date) 
					 inner join TBL_ET_AttendanceGroup(nolock) atgp on atra.AttendanceGroupId = atgp.AttendanceGroupId 
					 left join TBL_ET_AttendanceGroupUserMapping (nolock) agum on atra.UserId = agum.UserId 
					 left join User_Detail(nolock) ud2 on agum.UserId = ud2.User_ID 
					 left join tbl_inv_UserTaxNumber (nolock) iutn on agum.UserBranchId = iutn.Id
					 left join M_City (nolock) ct on iutn.City_Id = ct.City_Id
					 left join M_State (nolock) st on iutn.State_Id = st.State_Id
					 left join M_Country (nolock) co on iutn.Country_Id = co.Country_Id
					 left join TBL_ET_ShiftMaster (nolock) smat on atra.ShiftId = smat.ShiftId
					 where (Month(TRY_CAST(tmde.MDate as date)) = Month(TRY_CAST('''+ TRY_CAST(@FromDate as varchar(10)) + ''' as date)) and Year(TRY_CAST(tmde.MDate as date)) = Year(TRY_CAST('''+ TRY_CAST(@FromDate as varchar(10)) + ''' as date))) and
					 (agum.UserId = ' + TRY_CAST(@UserId as nvarchar(max)) + ') 
