						  ,[EndTime]
				)
				  SELECT 
						   TotalRecords
						  ,AttendanceId
						  ,MDate
						  ,AttendanceIn
						  ,AttendanceOut
						  ,IADate
						  ,IATime
						  ,OADate
						  ,OATime
						  ,TotalHours
						  ,LatitudeIn
						  ,LongitudeIn
