-- exec [dbo].[usp_Insert_EnquiryStatus_DataTo_Archive]   
  
CREATE   PROCEDURE [dbo].[usp_Insert_EnquiryStatus_DataTo_Archive]   
  
AS  
BEGIN  
 -- SET NOCOUNT ON added to prevent extra result sets from  
 SET NOCOUNT ON;  
  DECLARE @userid BIGINT;  
    DECLARE @currentRow INT = 1;  -- Variable to track the current row in the temporary table  
    DECLARE @totalRows INT;       -- Variable to store the total number of rows to process  
  
    -- Create a temporary table to store the User IDs  
    CREATE TABLE #UserIDs (UserID BIGINT);  
  
    -- Insert UserIDs into the temporary table  
    INSERT INTO #UserIDs (UserID)  
    SELECT User_ID  
    FROM Mysms.dbo.tbl_EnquiryImportSummary (NOLOCK)  
 WHERE User_ID IS NOT NULL  
    GROUP BY User_ID  
    ORDER BY COUNT(*) DESC;  
   
    -- Get the total number of rows  
    SELECT @totalRows = COUNT(*) FROM #UserIDs;  -- Loop through each User_ID using a WHILE loop  
 WHILE @currentRow <= @totalRows 
 BEGIN     -- Use a CTE to calculate ROW_NUMBER() and select the current UserID 
 BEGIN TRY
    WITH CTE_UserIDs AS (  
     SELECT UserID, ROW_NUMBER() OVER (ORDER BY UserID) AS RowNum  
     FROM #UserIDs  
    )  
    SELECT @userid = UserID  
    FROM CTE_UserIDs  
    WHERE RowNum = @currentRow;  
        Declare   
     @fromdate DATE = NULL,         
     @todate   DATE = NULL;   
  
  
   Declare @Currentdate  DATE  = GETDATE();  -- Today's date  
   SET @fromdate      = DATEADD(DAY, -9130, @Currentdate); -- 30 days before today  
    SET @todate  = @Currentdate;        --SET @fromdate  = DATEADD(DAY, -1, @Currentdate); -- 1 day before today    
   -- Only process if the UserID has not been processed already
            IF NOT EXISTS (
                SELECT 1 
                FROM MySMSReportCache.dbo.tbl_ImportEnquiryStatus_Archive (NOLOCK)
                WHERE User_Id = @userid
            )
            BEGIN

       declare @ParentId bigint = 0, @IsAdmin BIT = 0;    
    SELECT @ParentId = ParentID, @IsAdmin = IsAdmin FROM User_Detail (NOLOCK)  
  
  
  
    -- start data insert into archive table  
  
    INSERT INTO MySMSReportCache.[dbo].[tbl_ImportEnquiryStatus_Archive]      (       
        [ImportRow_Id]  
       ,[User_Id]  
       ,[ImportDate]  
       ,[IsProcessed]  
       ,[IsValid]  
       ,[TotalRecords]  
       ,[ImportFilename]  
       ,[totalCount]  
       ,[Status]     )  
     Select  ImportRow_Id, [User_Id], Convert(varchar,ImportDate,0) as ImportDate,     
     IsProcessed = Case when IsProcessed=1 then 'Yes' else 'Under Process' end,     
     IsValid = Case when ISNULL(Remarks,'') = '' and IsProcessed=1 then 'Yes'     
      when ISNULL(Remarks,'') != '' and IsProcessed=1 then 'No' else '' end ,   
      TotalRecords,ImportFilename, EnquiryCnt totalCount,  
      [Status] =Case  when EnquiryCnt = TotalRecords and IsProcessed=1  then 'Successful'   
         when  EnquiryCnt =0 and IsProcessed=1 and Remarks IS NOT NULL  then 'Failure'  
         when  EnquiryCnt < TotalRecords and IsProcessed=1 and Remarks IS NOT NULL then 'Partial'  
         else '' end  
     --,Remarks = ISNULL(Remarks,'')    
     From  tbl_EnquiryImportSummary    
     Where  [User_Id] = @userid and Convert(varchar,ImportDate,106) between @FromDate and @ToDate    
     Order by ImportDate desc    
	 -- end data insert into archive table 
  
        END
		END TRY
		BEGIN CATCH
		exec usp_InsertErrorInfo
        END CATCH
      -- Move to the next row  
        SET @currentRow = @currentRow + 1; END  -- Clean up the temporary table  
    DROP TABLE #UserIDs;     
END  


