CREATE   PROCEDURE [dbo].[usp_Insert_EnquiryUpdateImport_DataTo_Archive] 

AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	SET NOCOUNT ON;

	DECLARE @userid BIGINT;
    DECLARE @currentRow INT = 1;  -- Variable to track the current row in the temporary table
    DECLARE @totalRows INT;       -- Variable to store the total number of rows to process

    -- Create a temporary table to store the User IDs
    CREATE TABLE #UserIDs (UserID BIGINT);

    -- Insert UserIDs into the temporary table
    INSERT INTO #UserIDs (UserID)
    SELECT User_ID
    FROM Mysms.dbo.Tbl_Enquiry_EnquiryUpdateImportData (NOLOCK)
	WHERE User_ID IS NOT NULL
    GROUP BY User_ID
    ORDER BY COUNT(*) DESC;
	
    -- Get the total number of rows
    SELECT @totalRows = COUNT(*) FROM #UserIDs;

-- Loop through each User_ID using a WHILE loop
    WHILE @currentRow <= @totalRows
BEGIN
BEGIN TRY
			-- Use a CTE to calculate ROW_NUMBER() and select the current UserID
				WITH CTE_UserIDs AS (
					SELECT UserID, ROW_NUMBER() OVER (ORDER BY UserID) AS RowNum
					FROM #UserIDs
				)
				SELECT @userid = UserID
				FROM CTE_UserIDs
				WHERE RowNum = @currentRow;

   
			Declare 
					@fromdate DATE = NULL,       
					@todate   DATE = NULL; 


			Declare @Currentdate  DATE  = GETDATE();  -- Today's date
			--SET @fromdate      = DATEADD(DAY, -30, @Currentdate); -- 30 days before today
			--SET @todate  = @Currentdate;
			
			-- Only process if the UserID has not been processed already
            IF NOT EXISTS (
                SELECT 1 
                FROM MySMSReportCache.dbo.tbl_EnquiryUpdateImportStatus_Archive (NOLOCK)
                WHERE User_Id = @userid
            )
            BEGIN

			--SET @fromdate  = DATEADD(DAY, -1, @Currentdate); -- 1 day before today		

			    declare @ParentId bigint = 0, @IsAdmin BIT = 0;		
				SELECT @ParentId = ParentID, @IsAdmin = IsAdmin FROM User_Detail (NOLOCK)


				-- start data insert into archive table

				INSERT INTO MySMSReportCache.[dbo].[tbl_EnquiryUpdateImportStatus_Archive] 
				(		   
					   [ImportRow_Id]
					  ,[User_Id]
					  ,[ImportDate]
					  ,[IsProcessed]
					  ,[IsValid]
					  ,[ImportFilename]
					  ,[TotalRecords]
					  ,[totalCount]
					  ,[Status]
				)
				 SELECT ImportRow_Id, [User_Id] , [dbo].[fn_getusertimefromindiantime](@userid,Importdate) Importdate,   
						Case IsProcessed WHen 0 Then 'No' ELse 'Yes' End IsProcessed,   
						Case ISNULL(IsValid,0) When 0 Then 'No' Else 'Yes' End IsValid , ImportFileName, TotalRecords, EnquiryCnt TotalCount,    
						[Status] = Case  when EnquiryCnt = TotalRecords and IsProcessed=1  then 'Successful'     
						when  EnquiryCnt =0 and IsProcessed=1 and Remarks IS NOT NULL  then 'Failure'    
						when  EnquiryCnt < TotalRecords and IsProcessed=1 and Remarks IS NOT NULL then 'Partial'    
						else '' end   FROM Tbl_Enquiry_EnquiryUpdateImportData   
						WHERE USER_ID = @userid -- and  Convert(varchar,ImportDate,106)  between @fromDate and  @todate  
						order by importdate desc   


			-- end data insert into archive table

        END
		END TRY
		BEGIN CATCH
		exec usp_InsertErrorInfo
        END CATCH
-- Move to the next row
        SET @currentRow = @currentRow + 1;
END

-- Clean up the temporary table
    DROP TABLE #UserIDs;
		
END



