			-- Use a CTE to calculate ROW_NUMBER() and select the current UserID
				WITH CTE_UserIDs AS (
					SELECT UserID, ROW_NUMBER() OVER (ORDER BY UserID) AS RowNum
					FROM #UserIDs
				)
				SELECT @userid = UserID
				FROM CTE_UserIDs
				WHERE RowNum = @currentRow;

   
			Declare 
					@fromdate DATE = NULL,       
					@todate   DATE = NULL,
					@sqlExpQuery nvarchar(max),
					--@columns NVARCHAR(MAX) = '',
					--@pvtColumns nvarchar(max) = '',
					@FilterText nvarchar(255) = '',
					@Offset int = 0,
					@PagingSize int = 100,
					@UserIds nvarchar(max) = ''; 


			Declare @Currentdate  DATE  = GETDATE();  -- Today's date
			--SET @fromdate      = DATEADD(DAY, -5000, @Currentdate); -- 30 days before today
			--SET @todate  = @Currentdate;
			
			--SET @fromdate  = DATEADD(DAY, -1, @Currentdate); -- 1 day before today		

			IF NOT EXISTS ( 
					SELECT 1 
					FROM MySMSReportCache.[dbo].[tbl_ExpenseReport_Archive](NOLOCK)
					WHERE UserId = @userid
				)
				BEGIN

			    declare @ParentId bigint  
			select @ParentId = ParentID from User_Detail(nolock) u where u.User_ID = @userid  
		

		declare @Start int = (@Offset  + 1), @End int =  (@Offset  + @PagingSize)


			drop table if exists #tempUsers   
				create table #tempUsers(User_ID bigint, Name nvarchar(255), Image nvarchar(255))  
				insert into #tempUsers(User_ID, Name, Image)  
				exec Use_GetUserDetails @UserID = @userid  

			if(ISNULL(@UserIds, '') =  '') begin set @UserIds = '' end

					drop table if exists #tempSelectedUser
					create table #tempSelectedUser ( UserId bigint )
					insert into #tempSelectedUser(UserId) select [value] from string_split(@UserIds, ',')

					--		select 
					--	@columns =  STRING_AGG( QUOTENAME(ExpenseHeadName), ','),
					--	@pvtColumns =  STRING_AGG( concat('[pvt].', QUOTENAME(ExpenseHeadName)), ',')
					--from TBL_ET_ExpenseHead(nolock) teeh where teeh.ParentId = @ParentId -- order by ExpenseHeadName Asc

					--print concat('@columns => ', @columns)
					--print concat('@pvtColumns => ', @pvtColumns)

				set  @sqlExpQuery = CONCAT( N'select * from ( select ',
						N'row_number() over (partition by ud.ParentId order by ud.ParentId asc) as [SNo], ',
						N'count(1) over (order by ud.ParentId asc) as [TotalRow], ',
						N'concat(ud.User_Login, ''('', ud.FName, '' '', ud.LName, '')'' ) as ''DisplayName'', ',
						 N'ud.User_Login,  isnull(ud.FName,'''') + '' '' + isnull(ud.LName,'''')  as [UserFullName] ,',
						N'ud.User_ID as [UserId], ',
						N'd.TotalAmount, ',
						N'd.ApprovedAmount, ',
						N'd.RejectedAmount, ',
						N'd.PendingAmount, ',
						N'd.ClaimAmount, ',
						N'd.FromDate,',
						N'd.ToDate ',
						N'from User_Detail(nolock) ud ',
						N'inner join #tempUsers tu on ud.User_Id = tu.User_Id ',
						iif(LEN(@UserIds) > 0, 'inner join #tempSelectedUser  su on ud.User_Id = su.UserId ', ''),
						N'left join ( select ext.UserId, ext.TotalAmount, ext.ApprovedAmount, ext.RejectedAmount, ext.PendingAmount, ext.ClaimAmount,',
						 N'ext.FromDate, ext.ToDate ',
							  N' from ( select ec.UserId, ',
							N'SUM(isnull(ec.TotalAmount, 0)) as [TotalAmount], ',
							N'SUM(case when ea.ApproverStatus = ''Approved'' then ea.ApprovedAmount else 0 end) as [ApprovedAmount], ',
							N'SUM(case when ea.ApproverStatus = ''Rejected'' then ec.TotalAmount else 0 end) as [RejectedAmount], ',
							N'SUM(case when ea.ApproverStatus is null then ec.TotalAmount else 0 end) as [PendingAmount], ',
							N'SUM(isnull(ec.ClaimAmount, 0)) as [ClaimAmount], ',
								N'TRY_CAST((ec.FromDate) AS DATE) AS [FromDate], ',
								N'TRY_CAST((ec.ToDate) AS DATE) AS [ToDate] ',
							N'from TBL_ET_ExpenseClaim(nolock) ec ',
							N'left join TBL_ET_ExpenseApproval(nolock) ea on ec.ExpenseClaimId = ea.ExpenseClaimId ',
						N'where ec.ParentId = ', @ParentId,
						N'group by ec.UserId, ec.FromDate,ec.ToDate) ext ',
						N') d on ud.User_ID = d.UserId ',
						N'where ud.ParentID = ', @ParentId,'  and 1  = (case  ',
						N' when ''', isnull(@FilterText, ''), N''' = '''' then 1 ',
						N' when ud.User_Login like ''%', @FilterText, '%'' then 1 ',
						N'else 0 end )) ot where ot.SNo between ', @Start, ' and ', @End)

						CREATE TABLE #TempResult (
							SNo NVARCHAR(100),
							TotalRow NVARCHAR(100),
							DisplayName NVARCHAR(100),
							User_Login NVARCHAR(100),
							UserFullName NVARCHAR(100),
							UserId NVARCHAR(100),
							TotalAmount NVARCHAR(100),
							ApprovedAmount NVARCHAR(100),
							RejectedAmount NVARCHAR(100),
							PendingAmount NVARCHAR(100),
							ClaimAmount NVARCHAR(100),
							FromDate date,
							ToDate date
						);

						INSERT INTO #TempResult
						EXEC sp_executesql @sqlExpQuery;

			    -- start data insert into cache tables

				INSERT INTO MySMSReportCache.[dbo].[tbl_ExpenseReport_Archive] 
				(		   
						    [SNo]
						  ,[TotalRow]
						  ,[DisplayName]
						  ,[UserFullName]
						  ,[User_Login]
						  ,[UserId]
						  ,[TotalAmount]
						  ,[ApprovedAmount]
						  ,[RejectedAmount]
						  ,[ClaimAmount]
						  ,[ParentId]
						  ,[User_Id]
						  ,[FromDate]
						  ,[ToDate]
				)
				  SELECT 
						   SNo
						  ,TotalRow
						  ,DisplayName
						  ,UserFullName
						  ,User_Login
						  ,UserId
						  ,TotalAmount
						  ,ApprovedAmount
						  ,RejectedAmount
						  ,ClaimAmount
						  ,@ParentId
						  ,@userid
						  ,FromDate
						  ,ToDate
					FROM #TempResult;  
					
				-- end data insert into cache tables

			-- Clean up the temporary table
				DROP TABLE #TempResult;

END
END TRY
BEGIN CATCH
exec usp_InsertErrorInfo
END CATCH
-- Move to the next row
        SET @currentRow = @currentRow + 1;
END

-- Clean up the temporary table
    DROP TABLE #UserIDs;
		
END



