/* ============================================================
   Procedure: [dbo].[usp_Insert_Followup_DataTo_Archive]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- select * from MySMSReportCache.[dbo].[tbl_FollowUp_Cache]  select * from MySMSReportCache.[dbo].[tbl_FollowUp_Archive]

--TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_FollowUp_Cache];  TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_FollowUp_Archive];

-- exec [dbo].[usp_Insert_Followup_DataTo_Cache_Archive] 

CREATE   PROCEDURE [dbo].[usp_Insert_Followup_DataTo_Archive] 

AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	SET NOCOUNT ON;

	DECLARE @userid BIGINT;
    DECLARE @currentRow INT = 1;  -- Variable to track the current row in the temporary table
    DECLARE @totalRows INT;       -- Variable to store the total number of rows to process

    -- Create a temporary table to store the User IDs
    CREATE TABLE #UserIDs (UserID BIGINT);

    -- Insert UserIDs into the temporary table
    INSERT INTO #UserIDs (UserID)
    SELECT CreatedBy
    FROM Mysms.dbo.LeadInteractionHistory (NOLOCK)
	WHERE CreatedBy IS NOT NULL
    GROUP BY CreatedBy
    ORDER BY COUNT(*) DESC;
	
    -- Get the total number of rows
    SELECT @totalRows = COUNT(*) FROM #UserIDs;

-- Loop through each User_ID using a WHILE loop
    WHILE @currentRow <= @totalRows
BEGIN
BEGIN TRY
			-- Use a CTE to calculate ROW_NUMBER() and select the current UserID
				WITH CTE_UserIDs AS (
					SELECT UserID, ROW_NUMBER() OVER (ORDER BY UserID) AS RowNum
					FROM #UserIDs
				)
				SELECT @userid = UserID
				FROM CTE_UserIDs
				WHERE RowNum = @currentRow;

   
			Declare 
					@fromdate DATE = NULL,       
					@todate   DATE = NULL; 


			Declare @Currentdate  DATE  = GETDATE();  -- Today's date
			--SET @fromdate      = DATEADD(DAY, -30, @Currentdate); -- 30 days before today
			--SET @todate  = @Currentdate;
			
			--SET @fromdate  = DATEADD(DAY, -1, @Currentdate); -- 1 day before today		

			IF NOT EXISTS ( 
					SELECT 1 
					FROM MySMSReportCache.[dbo].[tbl_FollowUp_Archive](NOLOCK)
					WHERE UserId = @userid
				)
				BEGIN

			    declare @ParentId bigint = 0;		
				select @ParentId = ParentID from User_Detail(nolock) where User_ID = @UserId;
		
				declare @reportSql nvarchar(max) = concat(N'select * from (select ',
							N'row_number() over ( partition by l.ParentId order by l.CreatedOn desc ) AS LihSN, ',
							N'count(l.ParentId) OVER() AS TotalRow, ',
							N's.name AS Source, ',
							N'isnull(c.name, '''') AS Campaign, ',
							N'ul.Leadno, ',
							N'personName AS Name, ',
							N'MobileNo + isnull('', '' + nullif(MobileNo1, ''''), '''') + isnull('', '' + nullif(MobileNo2, ''''), '''') AS Mobile, ',
							N'isnull(EmailID, '''') + isnull('', '' + nullif(emailid1, ''''), '''') + isnull('', '' + nullif(emailid1, ''''), '''') AS Email, ',
							N'f.FollowupStatus, ',
							N'l.CreatedOn AS LastFollowedOn, ',
							N'isnull(l.Remarks, '''') AS Remarks, ',
							N'l.AmountPaid, ',
							--N'cu.User_Login as [user_login],  isnull(u.FName,'''') + '' '' + isnull(u.LName,'''')  as [User FullName] ',
							N'cu.User_Login as [user_login],  isnull(cu.FName,'''') + '' '' + isnull(cu.LName,'''')  as [User FullName] ',
						N'from ( select ',
						N'lih.ID, lih.LeadNo, lih.FollowUpStatus, lih.NextStatusDate, lih.Remarks, lih.Products,  ',
						N'lih.AmountPaid, lih.AssignedTo, lih.ParentID, lih.CreatedOn, lih.CreatedBy, lih.FollowupDate,  ',
						N'lih.IsReassign, lih.IsAutoEntry ',
					N'from ( select row_number() over(partition by LeadNo order by Id desc) as lrn,  ',
						N'ID, LeadNo, FollowUpStatus, NextStatusDate, Remarks, Products,  ',
						N'AmountPaid, AssignedTo, ParentID, CreatedOn, CreatedBy, FollowupDate,  ',
						N'IsReassign, IsAutoEntry from LeadInteractionHistory(nolock) il ',
						N'where ParentID = ', @ParentId, ' and CreatedBy <> ParentID ',
					N') lih where lih.lrn = 1 ) l   ',
						N'left join UserLeads(nolock) ul on l.LeadNo = ul.LeadNo and l.ParentID = ul.ParentID  ',
						N'left join UserSourceSettings(nolock) s ON s.SourceID = ul.SourceName ',
						N'left join UsercampaignSettings(nolock) c ON c.CampaignID = ul.CampaignName ',
						N'left join FollowUp_Status(nolock) f ON f.ID = l.FollowUpStatus and l.FollowUpStatus <> 6 ',
						N'left join User_Detail(nolock) cu on l.CreatedBy = cu.User_ID ',
						N') t ');
						
						CREATE TABLE #Temp_FollowUp_Cache (
								LihSN INT,
								TotalRow NVARCHAR(255),
								Source NVARCHAR(255),
								Campaign NVARCHAR(255),
								LeadNo NVARCHAR(255),
								Name NVARCHAR(255),
								Mobile NVARCHAR(255),
								Email NVARCHAR(255),
								FollowUpStatus NVARCHAR(255),
								LastFollowedOn DATETIME,
								Remarks NVARCHAR(1000),
								AmountPaid DECIMAL(18, 2),
								user_login NVARCHAR(255),
								[User FullName] NVARCHAR(255)
							);

							-- Insert the results of the dynamic query into the temporary table
								INSERT INTO #Temp_FollowUp_Cache
								EXEC sp_executesql @reportSql;

			    -- start data insert into cache tables

				INSERT INTO MySMSReportCache.[dbo].[tbl_FollowUp_Archive] 
				(		   
								   [LihSN]
								  ,[TotalRow]
								  ,[Source]
								  ,[Campaign]
								  ,[Leadno]
								  ,[Name]
								  ,[Mobile]
								  ,[Email]
								  ,[FollowupStatus]
								  ,[LastFollowedOn]
								  ,[Remarks]
								  ,[AmountPaid]
								  ,[user_login]
								  ,[User FullName]
								  ,[UserId]
				)
				SELECT
						LihSN, 
						TotalRow, 
						Source,
						Campaign,
						LeadNo, 
						Name,
						Mobile,
						Email,
						FollowUpStatus,
						LastFollowedOn,
						Remarks,
						AmountPaid,
						user_login,
						[User FullName],
						@userid as [UserId]
					FROM #Temp_FollowUp_Cache;
				
				-- end data insert into cache tables

			-- Drop the temporary table
			DROP TABLE #Temp_FollowUp_Cache;

END
END TRY
BEGIN CATCH
exec usp_InsertErrorInfo
END CATCH
-- Move to the next row
        SET @currentRow = @currentRow + 1;
END

-- Clean up the temporary table
    DROP TABLE #UserIDs;
		
END



