			-- Use a CTE to calculate ROW_NUMBER() and select the current UserID
				WITH CTE_UserIDs AS (
					SELECT UserID, ROW_NUMBER() OVER (ORDER BY UserID) AS RowNum
					FROM #UserIDs
				)
				SELECT @userid = UserID
				FROM CTE_UserIDs
				WHERE RowNum = @currentRow;

			Declare 
					@fromdate DATE = NULL,       
					@todate   DATE = NULL; 


			Declare @Currentdate  DATE  = GETDATE();  -- Today's date
			--SET @fromdate      = DATEADD(DAY, -30, @Currentdate); -- 30 days before today
			SET @fromdate  = DATEADD(DAY, -1, @Currentdate); -- 1 day before today
			SET @todate  = @Currentdate;
								

			--IF NOT EXISTS ( 
			--		SELECT 1 
			--		FROM MySMSReportCache.[dbo].[tbl_FollowUp_Cache](NOLOCK)
			--		WHERE UserId = @userid and TRY_CAST([LastFollowedOn] AS DATE) between @fromdate and @todate
			--	)
			--	BEGIN

			    declare @ParentId bigint = 0;		
				select @ParentId = ParentID from User_Detail(nolock) where User_ID = @UserId;
		
				declare @reportSql nvarchar(max) = concat(N'select * from (select ',
							N'row_number() over ( partition by l.ParentId order by l.CreatedOn desc ) AS LihSN, ',
							N'count(l.ParentId) OVER() AS TotalRow, ',
							N's.name AS Source, ',
							N'isnull(c.name, '''') AS Campaign, ',
							N'ul.Leadno, ',
							N'personName AS Name, ',
							N'MobileNo + isnull('', '' + nullif(MobileNo1, ''''), '''') + isnull('', '' + nullif(MobileNo2, ''''), '''') AS Mobile, ',
							N'isnull(EmailID, '''') + isnull('', '' + nullif(emailid1, ''''), '''') + isnull('', '' + nullif(emailid1, ''''), '''') AS Email, ',
							N'f.FollowupStatus, ',
							N'l.CreatedOn AS LastFollowedOn, ',
							N'isnull(l.Remarks, '''') AS Remarks, ',
							N'l.AmountPaid, ',
							--N'cu.User_Login as [user_login],  isnull(u.FName,'''') + '' '' + isnull(u.LName,'''')  as [User FullName] ',
							N'cu.User_Login as [user_login],  isnull(cu.FName,'''') + '' '' + isnull(cu.LName,'''')  as [User FullName] ',
						N'from ( select ',
						N'lih.ID, lih.LeadNo, lih.FollowUpStatus, lih.NextStatusDate, lih.Remarks, lih.Products,  ',
						N'lih.AmountPaid, lih.AssignedTo, lih.ParentID, lih.CreatedOn, lih.CreatedBy, lih.FollowupDate,  ',
						N'lih.IsReassign, lih.IsAutoEntry ',
					N'from ( select row_number() over(partition by LeadNo order by Id desc) as lrn,  ',
						N'ID, LeadNo, FollowUpStatus, NextStatusDate, Remarks, Products,  ',
						N'AmountPaid, AssignedTo, ParentID, CreatedOn, CreatedBy, FollowupDate,  ',
						N'IsReassign, IsAutoEntry from LeadInteractionHistory(nolock) il ',
						N'where ParentID = ', @ParentId, ' and CreatedBy <> ParentID ',
					N') lih where lih.lrn = 1 ) l   ',
						N'left join UserLeads(nolock) ul on l.LeadNo = ul.LeadNo and l.ParentID = ul.ParentID  ',
						N'left join UserSourceSettings(nolock) s ON s.SourceID = ul.SourceName ',
						N'left join UsercampaignSettings(nolock) c ON c.CampaignID = ul.CampaignName ',
						N'left join FollowUp_Status(nolock) f ON f.ID = l.FollowUpStatus and l.FollowUpStatus <> 6 ',
						N'left join User_Detail(nolock) cu on l.CreatedBy = cu.User_ID ',
						N') t ',
						N'WHERE TRY_CAST(LastFollowedOn AS DATE) BETWEEN ''', TRY_CAST(@fromdate AS NVARCHAR), ''' AND ''', TRY_CAST(@todate AS NVARCHAR), ''';');
						
						drop table if exists #Temp_FollowUp_Cache
						CREATE TABLE #Temp_FollowUp_Cache (
								LihSN INT,
								TotalRow NVARCHAR(255),
								Source NVARCHAR(255),
								Campaign NVARCHAR(255),
								LeadNo NVARCHAR(255),
								Name NVARCHAR(255),
								Mobile NVARCHAR(255),
								Email NVARCHAR(255),
								FollowUpStatus NVARCHAR(255),
								LastFollowedOn DATETIME,
								Remarks NVARCHAR(1000),
								AmountPaid DECIMAL(18, 2),
								user_login NVARCHAR(255),
								[User FullName] NVARCHAR(255)
							);

							-- Insert the results of the dynamic query into the temporary table
								INSERT INTO #Temp_FollowUp_Cache
								EXEC sp_executesql @reportSql;

			    -- start data insert into cache tables

				INSERT INTO MySMSReportCache.[dbo].[tbl_FollowUp_Cache] 
				(		   
								   [LihSN]
								  ,[TotalRow]
								  ,[Source]
								  ,[Campaign]
								  ,[Leadno]
								  ,[Name]
								  ,[Mobile]
								  ,[Email]
								  ,[FollowupStatus]
								  ,[LastFollowedOn]
								  ,[Remarks]
								  ,[AmountPaid]
								  ,[user_login]
								  ,[User FullName]
								  ,[UserId]
				)
				SELECT
						LihSN, 
						TotalRow, 
						Source,
						Campaign,
						LeadNo, 
						Name,
						Mobile,
						Email,
						FollowUpStatus,
						LastFollowedOn,
						Remarks,
						AmountPaid,
						user_login,
						[User FullName],
						@userid as [UserId]
					FROM #Temp_FollowUp_Cache;
				
				-- end data insert into cache tables

				INSERT INTO MySMSReportCache.[dbo].[tbl_FollowUp_Archive] 
				(		   
								   [LihSN]
								  ,[TotalRow]
								  ,[Source]
								  ,[Campaign]
								  ,[Leadno]
								  ,[Name]
								  ,[Mobile]
								  ,[Email]
								  ,[FollowupStatus]
								  ,[LastFollowedOn]
								  ,[Remarks]
								  ,[AmountPaid]
								  ,[user_login]
								  ,[User FullName]
								  ,[UserId]
				)
				SELECT
						LihSN, 
						TotalRow, 
						Source,
						Campaign,
						LeadNo, 
						Name,
						Mobile,
						Email,
						FollowUpStatus,
						LastFollowedOn,
						Remarks,
						AmountPaid,
						user_login,
						[User FullName],
						@userid as [UserId]
					FROM #Temp_FollowUp_Cache;

			-- Drop the temporary table
			DROP TABLE #Temp_FollowUp_Cache;

--END
END TRY
BEGIN CATCH
exec usp_InsertErrorInfo
END CATCH
-- Move to the next row
        SET @currentRow = @currentRow + 1;
END

	DELETE FROM MySMSReportCache.[dbo].[tbl_FollowUp_Cache]
	WHERE TRY_CAST([LastFollowedOn] AS DATE) NOT BETWEEN DATEADD(DAY, -30, TRY_CAST(GETDATE() AS DATE)) AND TRY_CAST(GETDATE() AS DATE);

-- Clean up the temporary table
    DROP TABLE #UserIDs;
		
END



GO

/* ============================================================
   Procedure: [dbo].[usp_Insert_GetCallLogDetailList_DataTo_Archive]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


   -- select * from MySMSReportCache.[dbo].[tbl_CallLogDetail_Cache]  select * from MySMSReportCache.[dbo].[tbl_CallLogDetail_Archive] 

   -- TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_CallLogDetail_Cache];  TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_CallLogDetail_Archive];

   -- exec usp_Insert_GetCallLogDetailList_DataTo_Archive

CREATE   PROCEDURE [dbo].[usp_Insert_GetCallLogDetailList_DataTo_Archive]       

as                      
BEGIN    
SET NOCOUNT ON;

	DECLARE @userid BIGINT;
    DECLARE @currentRow INT = 1;  -- Variable to track the current row in the temporary table
    DECLARE @totalRows INT;       -- Variable to store the total number of rows to process

    -- Create a temporary table to store the User IDs
    CREATE TABLE #UserIDs (UserID BIGINT);

    -- Insert UserIDs into the temporary table
    INSERT INTO #UserIDs (UserID)
    SELECT agentuserid
    FROM Mysms.dbo.calllog(NOLOCK)
	WHERE agentuserid IS NOT NULL
    GROUP BY agentuserid
    ORDER BY COUNT(*) DESC;
	
    -- Get the total number of rows
    SELECT @totalRows = COUNT(*) FROM #UserIDs;

-- Loop through each User_ID using a WHILE loop
    WHILE @currentRow <= @totalRows
BEGIN
BEGIN TRY

		-- Use a CTE to calculate ROW_NUMBER() and select the current UserID
				WITH CTE_UserIDs AS (
					SELECT UserID, ROW_NUMBER() OVER (ORDER BY UserID) AS RowNum
					FROM #UserIDs
				)
				SELECT @userid = UserID
				FROM CTE_UserIDs
				WHERE RowNum = @currentRow;
				
				DECLARE  @parentid bigint
						 ,@fromdate DATE          
						 ,@todate DATE 
						 ,@isadmin int
						 ,@FilterText nvarchar(max) = '',  
						 @OffsetValue INT = 0,   
						 @PagingSize  INT = 1000000 

			 
			 Declare @Currentdate  DATE  = GETDATE();  -- Today's date
			 SET @fromdate  = DATEADD(DAY, -9130, @Currentdate); -- 1 day before today
			 SET @todate  = @Currentdate;

			 select @ParentId = ParentID, @isadmin = IsAdmin from User_Detail(nolock) where User_ID = @UserId;

			 declare @StartPoint int = @OffsetValue + 1, @EndPoint int  = (@OffsetValue + @PagingSize )

			 declare @TeamCode varchar(10) = ''    
			declare @ScopeCode varchar(10) = ''     
			declare @UserIdTeamLst varchar(500) = ''     
			select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst from MySMS.dbo.ufn_GetUserRoleScope(@UserId)     

			 IF NOT EXISTS ( 
					SELECT 1 
					FROM MySMSReportCache.[dbo].[tbl_CallLogDetail_Archive](NOLOCK)
					WHERE UserId = @userid
				)
				BEGIN
			
				declare @sqlQuery nvarchar(max) = concat(N' select * from ( select ',  
						N' ROW_NUMBER() OVER(order by cl.parentid, TRY_CAST(cl.callcreatedon as datetime) desc) AS sno, ',
						N' COUNT(*) OVER() AS TotalRow, ',
						N'* from ( ', ' select ',
						N' c.id, c.parentid, c.callcreatedon as Date,user_login,  isnull(u.FName,'''') + '' '' + isnull(u.LName,'''')  as UserName, ',
						N' Customernumber, customerentity, ',
						N' customerentityid, isnull (dbo.fn_getentityfullname(customerentity,customerentityid),'''') as CustomerName, ',
						N' isnull(dnid,'''') as DNID, ',
						N'( case when c.gatewayid = 0 then ''Sim'' else s.provider_name end ) as Gateway, ',
						N'isnull(m.AppName,'''') IVRFlow, ',
						N'isnull(user_login,case when c.agentcalldisposition is null then '' '' else ''Agent No Changed'' end) Agent, ',
						N'direction, ',
						N'isnull(c.customercalldisposition, ''Unknown'') as CustomerDisposition, ',
						N'isnull(c.agentcalldisposition, case when c.agentcalldisposition is null then ''NOT ATTEMPTED'' ',
							N'else ''Unknown'' end) as AgentDisposition, ',
						N'( case when isnull(c.Callstarttime, '''') = '''' then ''Unknown'' ',
							N' else format(c.Callstarttime, ''dd-MMM-yyyy HH:mm:ss'') end ) as Callstarttime, ',
						N'(case when isnull(c.callendtime, '''') = '''' then ''Unknown'' ',
							N'else format(c.callendtime, ''dd-MMM-yyyy HH:mm:ss'') end) as CallEndTime, ',
						N'coalesce(customerduration, c.Calldurationseconds, 0) AS CustomerDuration, ',
						N'(case when c.agentcalldisposition is null then 0 ',
							N'when c.agentcalldisposition = ''NOANSWER'' then 0 ',
							N'else coalesce(agentduration, Calldurationseconds, 0) end) as agentDuration, ',
						N'(case when c.agentcalldisposition IS NULL then 0 else isnull (Calldurationseconds, 0) end) as Callduration, ',
						N'c.recordurl as Recording, isnull(c.agentmode,''Mobile'') as AgentMode, isnull(o.outcomename,'''') as Outcome, ',
						N'c.remarks, isnull(c.lastdtmf,'''') LastUserInput, ',
						N'c.callcreatedon, (case when c.customerentity = ''lead'' then ul.LeadNo else en.LeadNo end )as [LeadNo]',
						N' from calendar(nolock) ca ',
						N'left join calllog(nolock) c on TRY_CAST(c.callstarttime as date)=TRY_CAST(ca.start_dts as date) ',
						N'left join user_detail u (nolock) on c.agentuserid = u.User_ID ',
						N'left join UserLeads ul (nolock) on c.customerentity = ''lead'' and c.customerentityid = ul.ID ',
						N'left join UserEnquiry en (nolock) on c.customerentity = ''enquiry'' and c.customerentityid = en.EnquiryID ',
						--N'left join TelephonyCostDeducted(nolock) t on t.parentid=c.parentid and 1=case ',
						--	N'when t.gatewaytype<>0 and t.kit19callsdialledid=c.refid then 1 ',
						--	N'when t.GatewayType=0 and t.uniqueid=c.uniqueid then 1 else 0 end ',
						N'left join tbl_voip_ServiceProvider s on s.id=c.gatewayid ',
						N'left join tbl_CallLogOutcomeMaster(nolock) o on o.id=c.outcomeid ',
						N'left join Cloud_app_master(nolock) m on m.AppId = c.appid ',
						N'where  TRY_CAST(start_dts as date) between TRY_CAST(''',  @fromdate, ''' as date) ',
							N'and TRY_CAST(''', @todate, ''' as date) ',
							N'and c.parentid=', @parentid, ' ',
							N'and 1 = (case when ' , @isadmin ,' = 1 then 1 ',
								N'when isnull(c.agentuserid, 0) in (select [value] from dbo.fn_Split(''', @UserIdTeamLst, ''', '','')) then 1 ',
								N'when isnull(c.agentuserid, 0) = ', @UserId, ' then 1 else 0 end )',  
						--N'group by cast(callcreatedon as date), user_login,c.parentid,cast(ca.start_dts as date)  
						N' ) cl ',   
						iif(isnull(@FilterText, '') = '', ' ', concat(' where ', REPLACE(@FilterText,'''''',''''))),
						N' ) nt where nt.sno between ', @StartPoint, ' and ', @EndPoint 
					)    
				
					drop table if exists #TempCallLogDetail  
					CREATE TABLE #TempCallLogDetail (
							[SNo] [int] ,
							[TotalRow] [int] ,
							[id] [int] ,
							[parentid] [bigint] ,
							[Date] [datetime] ,
							[user_login] [nvarchar](200) ,
							[UserName] [nvarchar](100) ,
							[Customernumber] [nvarchar](20) ,
							[customerentity] [nvarchar](20) ,
							[customerentityid] [bigint] ,
							[CustomerName] [nvarchar](150) ,
							[DNID] [nvarchar](50) ,
							[Gateway] [nvarchar](255) ,
							[IVRFlow] [varchar](100) ,
							[Agent] [nvarchar](200) ,
							[direction] [nvarchar](20) ,
							[CustomerDisposition] [nvarchar](50) ,
							[AgentDisposition] [nvarchar](50) ,
							[Callstarttime] [nvarchar](100) ,
							[CallEndTime] [nvarchar](100) ,
							[CustomerDuration] [int] ,
							[agentDuration] [int] ,
							[Callduration] [nvarchar](100) ,
							[Recording] [nvarchar](max) ,
							[AgentMode] [nvarchar](20) ,
							[Outcome] [nvarchar](255) ,
							[remarks] [nvarchar](max) ,
							[LastUserInput] [nvarchar](100) ,
							[callcreatedon] [datetime],
							[LeadNo] [nvarchar](20)
					);

					INSERT into #TempCallLogDetail
					EXEC sp_executesql @sqlQuery;
				
						INSERT INTO MySMSReportCache.[dbo].[tbl_CallLogDetail_Archive] 
						(
							[SNo],
							[TotalRow],
							[id],
							[parentid],
							[Date],
							[user_login],
							[UserName],
							[Customernumber],
							[customerentity],
							[customerentityid],
							[CustomerName],
							[DNID],
							[Gateway],
							[IVRFlow],
							[Agent],
							[direction],
							[CustomerDisposition],
							[AgentDisposition],
							[Callstarttime],
							[CallEndTime],
							[CustomerDuration],
							[agentDuration],
							[Callduration],
							[Recording],
							[AgentMode],
							[Outcome],
							[remarks],
							[LastUserInput],
							[callcreatedon],
							[UserId],
							[LeadNo] 
						)
						SELECT 
							[SNo],
							[TotalRow],
							[id],
							[parentid],
							[Date],
							[user_login],
							[UserName],
							[Customernumber],
							[customerentity],
							[customerentityid],
							[CustomerName],
							[DNID],
							[Gateway],
							[IVRFlow],
							[Agent],
							[direction],
							[CustomerDisposition],
							[AgentDisposition],
							[Callstarttime],
							[CallEndTime],
							[CustomerDuration],
							[agentDuration],
							[Callduration],
							[Recording],
							[AgentMode],
							[Outcome],
							[remarks],
							[LastUserInput],
							[callcreatedon],
							@userid,
							[LeadNo] 
						FROM #TempCallLogDetail;
				END
				
END TRY
BEGIN CATCH
exec usp_InsertErrorInfo
END CATCH
-- Move to the next row
        SET @currentRow = @currentRow + 1;
END

-- Clean up the temporary table
    DROP TABLE #UserIDs;
   
END 




GO

/* ============================================================
   Procedure: [dbo].[usp_Insert_GetCallLogDetailList_DataTo_Cache_Archive]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


