    DECLARE @totalRows INT;       -- Variable to store the total number of rows to process

    -- Create a temporary table to store the User IDs
    CREATE TABLE #UserIDs (UserID BIGINT);

    -- Insert UserIDs into the temporary table
    INSERT INTO #UserIDs (UserID)
    SELECT agentuserid
    FROM Mysms.dbo.calllog(NOLOCK)
	WHERE agentuserid IS NOT NULL
    GROUP BY agentuserid
    ORDER BY COUNT(*) DESC;
	
    -- Get the total number of rows
    SELECT @totalRows = COUNT(*) FROM #UserIDs;

-- Loop through each User_ID using a WHILE loop
    WHILE @currentRow <= @totalRows
BEGIN
BEGIN TRY

		-- Use a CTE to calculate ROW_NUMBER() and select the current UserID
				WITH CTE_UserIDs AS (
					SELECT UserID, ROW_NUMBER() OVER (ORDER BY UserID) AS RowNum
					FROM #UserIDs
				)
				SELECT @userid = UserID
				FROM CTE_UserIDs
				WHERE RowNum = @currentRow;
				
				DECLARE  @parentid bigint
						 ,@fromdate DATE          
						 ,@todate DATE 
						 ,@isadmin int
						 ,@FilterText nvarchar(max) = '',  
						 @OffsetValue INT = 0,   
						 @PagingSize  INT = 1000000 

			 
			 Declare @Currentdate  DATE  = GETDATE();  -- Today's date
			 SET @fromdate  = DATEADD(DAY, -30, @Currentdate); -- 1 day before today
			 SET @todate  = @Currentdate;

			 select @ParentId = ParentID, @isadmin = IsAdmin from User_Detail(nolock) where User_ID = @UserId;

			 declare @StartPoint int = @OffsetValue + 1, @EndPoint int  = (@OffsetValue + @PagingSize )

			 declare @TeamCode varchar(10) = ''    
			declare @ScopeCode varchar(10) = ''     
			declare @UserIdTeamLst varchar(500) = ''     
			select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst from MySMS.dbo.ufn_GetUserRoleScope(@UserId)     

			 IF NOT EXISTS ( 
					SELECT 1 
					FROM MySMSReportCache.[dbo].[tbl_CallLogDetail_Cache](NOLOCK)
					WHERE UserId = @userid
				)
				BEGIN

				declare @sqlQuery nvarchar(max) = concat(N' select * from ( select ',  
						N' ROW_NUMBER() OVER(order by cl.parentid, TRY_CAST(cl.callcreatedon as datetime) desc) AS sno, ',
						N' COUNT(*) OVER() AS TotalRow, ',
						N'* from ( ', ' select ',
						N' c.id, c.parentid, c.callcreatedon as Date,user_login,  isnull(u.FName,'''') + '' '' + isnull(u.LName,'''')  as UserName, ',
						N' Customernumber, customerentity, ',
						N' customerentityid, isnull (dbo.fn_getentityfullname(customerentity,customerentityid),'''') as CustomerName, ',
						N' isnull(dnid,'''') as DNID, ',
						N'( case when c.gatewayid = 0 then ''Sim'' else s.provider_name end ) as Gateway, ',
						N'isnull(m.AppName,'''') IVRFlow, ',
						N'isnull(user_login,case when c.agentcalldisposition is null then '' '' else ''Agent No Changed'' end) Agent, ',
						N'direction, ',
						N'isnull(c.customercalldisposition, ''Unknown'') as CustomerDisposition, ',
						N'isnull(c.agentcalldisposition, case when c.agentcalldisposition is null then ''NOT ATTEMPTED'' ',
							N'else ''Unknown'' end) as AgentDisposition, ',
						N'( case when isnull(c.Callstarttime, '''') = '''' then ''Unknown'' ',
							N' else format(c.Callstarttime, ''dd-MMM-yyyy HH:mm:ss'') end ) as Callstarttime, ',
						N'(case when isnull(c.callendtime, '''') = '''' then ''Unknown'' ',
							N'else format(c.callendtime, ''dd-MMM-yyyy HH:mm:ss'') end) as CallEndTime, ',
						N'coalesce(customerduration, c.Calldurationseconds, 0) AS CustomerDuration, ',
						N'(case when c.agentcalldisposition is null then 0 ',
							N'when c.agentcalldisposition = ''NOANSWER'' then 0 ',
							N'else coalesce(agentduration, Calldurationseconds, 0) end) as agentDuration, ',
						N'(case when c.agentcalldisposition IS NULL then 0 else isnull (Calldurationseconds, 0) end) as Callduration, ',
						N'c.recordurl as Recording, isnull(c.agentmode,''Mobile'') as AgentMode, isnull(o.outcomename,'''') as Outcome, ',
						N'c.remarks, isnull(c.lastdtmf,'''') LastUserInput, ',
						N'c.callcreatedon, (case when c.customerentity = ''lead'' then ul.LeadNo else en.LeadNo end )as [LeadNo]',
						N' from calendar(nolock) ca ',
						N'left join calllog(nolock) c on TRY_CAST(c.callstarttime as date)=TRY_CAST(ca.start_dts as date) ',
						N'left join user_detail u (nolock) on c.agentuserid = u.User_ID ',
						N'left join UserLeads ul (nolock) on c.customerentity = ''lead'' and c.customerentityid = ul.ID ',
						N'left join UserEnquiry en (nolock) on c.customerentity = ''enquiry'' and c.customerentityid = en.EnquiryID ',
						--N'left join TelephonyCostDeducted(nolock) t on t.parentid=c.parentid and 1=case ',
						--	N'when t.gatewaytype<>0 and t.kit19callsdialledid=c.refid then 1 ',
						--	N'when t.GatewayType=0 and t.uniqueid=c.uniqueid then 1 else 0 end ',
						N'left join tbl_voip_ServiceProvider s on s.id=c.gatewayid ',
						N'left join tbl_CallLogOutcomeMaster(nolock) o on o.id=c.outcomeid ',
						N'left join Cloud_app_master(nolock) m on m.AppId = c.appid ',
						N'where  TRY_CAST(start_dts as date) between TRY_CAST(''',  @fromdate, ''' as date) ',
							N'and TRY_CAST(''', @todate, ''' as date) ',
							N'and c.parentid=', @parentid, ' ',
							N'and 1 = (case when ' , @isadmin ,' = 1 then 1 ',
								N'when isnull(c.agentuserid, 0) in (select [value] from dbo.fn_Split(''', @UserIdTeamLst, ''', '','')) then 1 ',
								N'when isnull(c.agentuserid, 0) = ', @UserId, ' then 1 else 0 end )',  
						--N'group by cast(callcreatedon as date), user_login,c.parentid,cast(ca.start_dts as date)  
						N' ) cl ',   
						iif(isnull(@FilterText, '') = '', ' ', concat(' where ', REPLACE(@FilterText,'''''',''''))),
						N' ) nt where nt.sno between ', @StartPoint, ' and ', @EndPoint 
					)   

