	DELETE FROM MySMSReportCache.[dbo].[tbl_CallLogDetail_Cache]
	WHERE Format(TRY_CAST([callcreatedon] AS DATE), 'YYYY-MM-DD') NOT BETWEEN DATEADD(DAY, -30, TRY_CAST(GETDATE() AS DATE)) AND TRY_CAST(GETDATE() AS DATE);

