/* ============================================================
   Procedure: [dbo].[usp_Insert_getEnquiryReport_DataTo_Cache_Archive]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


   -- select * from MySMSReportCache.[dbo].[tbl_EnquiryReport_Cache]  select * from MySMSReportCache.[dbo].[tbl_EnquiryReport_Archive]

   -- TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_EnquiryReport_Cache];  TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_EnquiryReport_Archive];

   -- exec usp_Insert_getEnquiryReport_DataTo_Cache_Archive

CREATE   PROCEDURE [dbo].[usp_Insert_getEnquiryReport_DataTo_Cache_Archive]       

as                      
BEGIN    
SET NOCOUNT ON;

	DECLARE @userid BIGINT;
    DECLARE @currentRow INT = 1;  -- Variable to track the current row in the temporary table
    DECLARE @totalRows INT;       -- Variable to store the total number of rows to process

    -- Create a temporary table to store the User IDs
    CREATE TABLE #UserIDs (UserID BIGINT);

    -- Insert UserIDs into the temporary table
    INSERT INTO #UserIDs (UserID)
    SELECT CreatedBy
    FROM Mysms.dbo.userenquiry (NOLOCK)
	WHERE CreatedBy IS NOT NULL
    GROUP BY CreatedBy
    ORDER BY COUNT(*) DESC;
	
    -- Get the total number of rows
    SELECT @totalRows = COUNT(*) FROM #UserIDs;

-- Loop through each User_ID using a WHILE loop
    WHILE @currentRow <= @totalRows
BEGIN
BEGIN TRY

		-- Use a CTE to calculate ROW_NUMBER() and select the current UserID
				WITH CTE_UserIDs AS (
					SELECT UserID, ROW_NUMBER() OVER (ORDER BY UserID) AS RowNum
					FROM #UserIDs
				)
				SELECT @userid = UserID
				FROM CTE_UserIDs
				WHERE RowNum = @currentRow;
				
				DECLARE  @parentid bigint,
						 @fromdate date,
						 @todate date,
						 @Isflag bit = '',
						 @strCriteriaName nvarchar(max)  ='',
						 @IsAdmin bit = 0 

			 
			 Declare @Currentdate  DATE  = GETDATE();  -- Today's date
			 SET @fromdate  = DATEADD(DAY, -30, @Currentdate); -- 1 day before today
			 SET @todate  = @Currentdate;

			 select @ParentId = ParentID, @IsAdmin = isnull(IsAdmin,0) from User_Detail(nolock) where User_ID = @UserId;

			 declare @tbluser table (User_ID bigint,Name varchar(100), Image varchar(100)) 

			   if(@IsAdmin = 1)  
				 Begin  
						insert into @tbluser  
						exec Use_GetUserDetails @ParentId  
				 end   
				else  
					Begin  
						   insert into @tbluser  
						   exec Use_GetUserDetails @UserID  
					End  

				DECLARE @HierarchyJSON nvarchar(max);  
				DECLARE @FormattedUsername NVARCHAR(MAX);  
				DECLARE @FormattedHierarchyPath NVARCHAR(MAX); 


			  drop table if exists #HierarchyDetail
			  CREATE TABLE #HierarchyDetail (User_id BIGINT,UserName NVARCHAR(MAX),Parentid BIGINT);  
  
				IF EXISTS (SELECT 1 FROM tbl_UA_UserHierarchy (NOLOCK) WHERE ParentId = @ParentId AND IsActive = 1)  
					BEGIN  
						SELECT @HierarchyJSON = HierarchyJSON   
						FROM tbl_UA_UserHierarchy (NOLOCK)   
						WHERE IsActive = 1 AND ParentId = @ParentId;  
  
						INSERT INTO #HierarchyDetail  
						SELECT DISTINCT uh.User_id, uh.UserName, uh.Parentid  
						FROM OPENJSON(@HierarchyJSON) WITH   
						(  
							parentid BIGINT,  
							username NVARCHAR(500),  
							user_id BIGINT  
						) UH   
						INNER JOIN User_detail (NOLOCK) UD  
							ON UH.user_id = UD.user_ID;  
					END  
				ELSE IF EXISTS (SELECT 1 FROM tbl_UA_RoleHierarchy (NOLOCK) WHERE ParentId = @ParentId AND IsActive = 1)  
					BEGIN  
						PRINT 'Role Hierarchy';          
   
						SELECT @HierarchyJSON = HierarchyJSON   
						FROM tbl_UA_RoleHierarchy (NOLOCK)   
						WHERE IsActive = 1 AND ParentId = @ParentId;  
  
						SELECT DISTINCT parentid  
						INTO #UserRoleHierarchy1  
						FROM OPENJSON(@HierarchyJSON) WITH   
						(  
							parentid BIGINT  
						);  
  
						INSERT INTO #HierarchyDetail  
						SELECT UH.Parentid, FName + ' ' + LName AS username, user_id   
						FROM #UserRoleHierarchy1 UH  
						LEFT JOIN User_Detail UD ON UD.User_ID = UH.parentid    
						WHERE FName IS NOT NULL AND LName IS NOT NULL;  
  
						DROP TABLE #UserRoleHierarchy1;  
					END;  

			 IF NOT EXISTS ( 
					SELECT 1 
					FROM MySMSReportCache.[dbo].[tbl_EnquiryReport_Cache](NOLOCK)
					WHERE User_ID = @userid
				)
				BEGIN
						INSERT INTO MySMSReportCache.[dbo].[tbl_EnquiryReport_Cache] 
							(
								[Date],
								[AgentName],
								[NewEnquiries],
								[EnquiriesConvertedToLeads],
								[EnquiriesmatchingLeads],
								[OpenEnquiries],
								[EnquiriesNotmatchingLeads],
								[CreatedBy],
								[User_ID],
								[parentid]
							)
								select FORMAT( start_dts, 'dd MMM yyyy') as Date,     
									dbo.fn_getentityfullname('user',u.CreatedBy) as AgentName,    
									count(1) as NewEnquiries,    
									count(t.createdby) EnquiriesConvertedToLeads,  
									count(t1.createdbyMatchLeads) EnquiriesmatchingLeads ,  
									count(t2.CreatedByOpenEnquiry) OpenEnquiries,  
									count(t3.CreatedByEnquiriesNotmatchingLeads) EnquiriesNotmatchingLeads,  
									   u.CreatedBy, @userid, @parentid    
									from     
									calendar c (nolock)  join    
									userenquiry u(nolock) on TRY_CAST(start_dts as date)=TRY_CAST(u.createddate as date)    
									left join    
									(select e.createdby,enquiryid--,l.id    
									--from tbl_MergeLeadsEnquiry(nolock) t   
									--join userleads(nolock) l on t.leadno=l.leadno and l.parentid=@parentid    
									 from userenquiry(nolock) e  
									  --on e.EnquiryID=t.EnquiryNo     
									 where isnull( e.IsOpen,0) = 0 and TRY_CAST(e.Createddate as date) between @fromdate and @todate    
									) t on t.createdby=u.createdby and t.EnquiryID=u.EnquiryID  
									left join    
									(select ml.createdby as createdbyMatchLeads ,ml.EnquiryID    
									 from userenquiry(nolock) ml   
									 where isnull( ml.LeadNo,0) <> 0 and TRY_CAST(ml.Createddate as date) between @fromdate and @todate    
									) t1 on t1.createdbyMatchLeads=u.createdby and t1.EnquiryID=u.EnquiryID  
									left join    
									(select OE.createdby as CreatedByOpenEnquiry ,OE.EnquiryID    
									 from userenquiry(nolock) as OE   
									 where isnull( OE.IsOpen,0) = 1 and TRY_CAST(OE.Createddate as date) between @fromdate and @todate    
									) t2 on t2.CreatedByOpenEnquiry=u.createdby and t2.EnquiryID=u.EnquiryID  
									left join    
									(select ENotMatching.createdby as CreatedByEnquiriesNotmatchingLeads ,ENotMatching.EnquiryID    
									 from userenquiry(nolock) as ENotMatching   
									 where isnull( ENotMatching.LeadNo,0) = 0 and TRY_CAST(ENotMatching.Createddate as date) between @fromdate and @todate    
									) t3 on t3.CreatedByEnquiriesNotmatchingLeads=u.createdby and t3.EnquiryID=u.EnquiryID  
									where  
									  ( --u.parentid is null  
										--or   
										u.parentid=@parentid  
									  )  
									 and u.CreatedBy in (select isnull(USER_ID,0) from @tbluser)     
									and c.start_dts between @fromdate and @todate    
									group by dbo.fn_getentityfullname('user',u.CreatedBy),FORMAT( start_dts, 'dd MMM yyyy'),TRY_CAST(u.createddate as date),u.CreatedBy    
									order by FORMAT( start_dts, 'dd MMM yyyy')    

						INSERT INTO MySMSReportCache.[dbo].[tbl_EnquiryReport_Cache] 
							(
								[Date],
								[AgentName],
								[NewEnquiries],
								[EnquiriesConvertedToLeads],
								[EnquiriesmatchingLeads],
								[OpenEnquiries],
								[EnquiriesNotmatchingLeads],
								[CreatedBy],
								[User_ID],
								[parentid]
							)
							select FORMAT( start_dts, 'dd MMM yyyy') as Date,     
								dbo.fn_getentityfullname('user',u.CreatedBy) as AgentName,    
								count(1) as NewEnquiries,    
								count(t.createdby) EnquiriesConvertedToLeads,  
								count(t1.createdbyMatchLeads) EnquiriesmatchingLeads ,  
								count(t2.CreatedByOpenEnquiry) OpenEnquiries,  
								count(t3.CreatedByEnquiriesNotmatchingLeads) EnquiriesNotmatchingLeads,  
								   u.CreatedBy, @userid, @parentid    
								from     
								calendar c (nolock)  join    
								userenquiry u(nolock) on TRY_CAST(c.start_dts as date)=TRY_CAST(u.createddate as date)  and TRY_CAST(u.Createddate as date) between @fromdate and @todate    
								left join    
								(select e.createdby,enquiryid--,l.id    
								--from tbl_MergeLeadsEnquiry(nolock) t   
								--join userleads(nolock) l on t.leadno=l.leadno and l.parentid=@parentid    
								 from userenquiry(nolock) e  
								  --on e.EnquiryID=t.EnquiryNo     
								 where isnull( e.IsOpen,0) = 0 and TRY_CAST(e.Createddate as date) between @fromdate and @todate    
								) t on t.createdby=u.createdby and t.EnquiryID=u.EnquiryID  
								left join    
								(select ml.createdby as createdbyMatchLeads ,ml.EnquiryID    
								 from userenquiry(nolock) ml   
								 where isnull( ml.LeadNo,0) <> 0 and TRY_CAST(ml.Createddate as date) between @fromdate and @todate    
								) t1 on t1.createdbyMatchLeads=u.createdby and t1.EnquiryID=u.EnquiryID  
								left join    
								(select OE.createdby as CreatedByOpenEnquiry ,OE.EnquiryID    
								 from userenquiry(nolock) as OE   
								 where isnull( OE.IsOpen,0) = 1 and TRY_CAST(OE.Createddate as date) between @fromdate and @todate    
								) t2 on t2.CreatedByOpenEnquiry=u.createdby and t2.EnquiryID=u.EnquiryID  
								left join    
								(select ENotMatching.createdby as CreatedByEnquiriesNotmatchingLeads ,ENotMatching.EnquiryID    
								 from userenquiry(nolock) as ENotMatching   
								 where isnull( ENotMatching.LeadNo,0) = 0 and TRY_CAST(ENotMatching.Createddate as date) between @fromdate and @todate    
								) t3 on t3.CreatedByEnquiriesNotmatchingLeads=u.createdby and t3.EnquiryID=u.EnquiryID  
								where  
								  ( --u.parentid is null  
									--or   
									u.parentid=@parentid  
								  )  
								and u.CreatedBy  in (select isnull(USER_ID,0) from #HierarchyDetail where ParentID=@strCriteriaName) or u.CreatedBy =@strCriteriaName    
								and c.start_dts between @fromdate and @todate    
								group by dbo.fn_getentityfullname('user',u.CreatedBy),FORMAT( start_dts, 'dd MMM yyyy'),TRY_CAST(u.createddate as date),u.CreatedBy    
								order by FORMAT( start_dts, 'dd MMM yyyy')    

