						INSERT INTO MySMSReportCache.[dbo].[tbl_EnquiryReport_Cache] 
							(
								[Date],
								[Source],
								[Medium],
								[Campaign],
								[NewEnquiries],
								[EnquiriesConvertedToLeads],
								[EnquiriesmatchingLeads],
								[OpenEnquiries],
								[EnquiriesNotmatchingLeads],
								[User_ID],
								[parentid]
							)
							select FORMAT( start_dts, 'dd MMM yyyy') as Date, s.name as Source,isnull(m.name,'') as Medium,isnull(cs.name,'') as Campaign,  count(1) as NewEnquiries,sum(case when isopen=0 then 1 else 0 end) as EnquiriesConvertedToLeads,    
								sum(case when isnull(leadno,0) <>0 then 1 else 0 end) as EnquiriesmatchingLeads,    
								sum(case when isopen=1 then 1 else 0 end) as OpenEnquiries,    
								sum(case when isnull(leadno,0) =0 then 1 else 0 end) as EnquiriesNotmatchingLeads,
								@userid, @parentid
								from     
								calendar c (nolock)  join    
								userenquiry u(nolock) on TRY_CAST(start_dts as date)=TRY_CAST(u.createddate as date)    
								left join UserSourceSettings (nolock) s on s.SourceID=u.sourcename    
								left join UserMediumSettings (nolock) m on m.MediumID=u.MediumName    
								left join UserCampaignSettings (nolock) cs on cs.CampaignID=u.campaignname 
								left join user_detail UD (nolock) on UD.User_ID=cs.UserID
								where (  
										--u.parentid is null   
								  --or   
									 u.parentid=@parentid  
								   )    
								and c.start_dts between @fromdate and @todate  
  
								and u.CreatedBy in (select isnull(USER_ID,0) from @tbluser)  
    
								group by s.name,m.name,cs.name,FORMAT( start_dts, 'dd MMM yyyy'),TRY_CAST(u.createddate as date)    
								order by FORMAT( start_dts, 'dd MMM yyyy') 

