						--			--and c.start_dts between @fromdate and @todate  
						--			and u.CreatedBy  in (select isnull(USER_ID,0) from #HierarchyDetail where ParentID=@strCriteriaName) or u.CreatedBy =@strCriteriaName
						--			group by s.name,m.name,cs.name,FORMAT( start_dts, 'dd MMM yyyy'),TRY_CAST(u.createddate as date)    
						--			order by FORMAT( start_dts, 'dd MMM yyyy') 
				END

END TRY
BEGIN CATCH
exec usp_InsertErrorInfo
END CATCH
-- Move to the next row
        SET @currentRow = @currentRow + 1;
END

	DELETE FROM MySMSReportCache.[dbo].[tbl_EnquiryReport_Cache]
	WHERE TRY_CAST([Date] AS DATE) NOT BETWEEN DATEADD(DAY, -30, TRY_CAST(GETDATE() AS DATE)) AND TRY_CAST(GETDATE() AS DATE);

-- Clean up the temporary table
    DROP TABLE #UserIDs;
   
END 



