/* ============================================================
   Procedure: [dbo].[usp_Insert_getleadreport_daywise_LeadAndFollowup_DataTo_Cache_Archive]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


   -- select * from MySMSReportCache.[dbo].[tbl_LeadReport_Cache](nolock) select * from MySMSReportCache.[dbo].[tbl_FollowupReport_Cache](nolock) 
   
   -- select * from MySMSReportCache.[dbo].[tbl_LeadReport_Archive](nolock) select * from MySMSReportCache.[dbo].[tbl_FollowupReport_Archive](nolock) 

   -- TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_LeadReport_Cache]; TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_FollowupReport_Cache];  TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_LeadReport_Archive]; TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_FollowupReport_Archive]; 

   -- exec usp_Insert_getleadreport_daywise_LeadAndFollowup_DataTo_Cache_Archive

CREATE   PROCEDURE [dbo].[usp_Insert_getleadreport_daywise_LeadAndFollowup_DataTo_Cache_Archive]       

as                      
BEGIN    
SET NOCOUNT ON;

	DECLARE @userid BIGINT;
    DECLARE @currentRow INT = 1;  -- Variable to track the current row in the temporary table
    DECLARE @totalRows INT;       -- Variable to store the total number of rows to process

    -- Create a temporary table to store the User IDs
    CREATE TABLE #UserIDs (UserID BIGINT);

    -- Insert UserIDs into the temporary table
    INSERT INTO #UserIDs (UserID)
    SELECT User_Id
    FROM Mysms.dbo.User_Detail (NOLOCK)
	WHERE User_Id IS NOT NULL
	group by User_Id
	order by count(*) desc
	
    -- Get the total number of rows
    SELECT @totalRows = COUNT(*) FROM #UserIDs;

-- Loop through each User_ID using a WHILE loop
    WHILE @currentRow <= @totalRows
BEGIN
BEGIN TRY

		-- Use a CTE to calculate ROW_NUMBER() and select the current UserID
				WITH CTE_UserIDs AS (
					SELECT UserID, ROW_NUMBER() OVER (ORDER BY UserID) AS RowNum
					FROM #UserIDs
				)
				SELECT @userid = UserID
				FROM CTE_UserIDs
				WHERE RowNum = @currentRow;
				
				DECLARE  @parentid BIGINT,          
						 @fromdate DATE,          
						 @todate DATE   

			 
			 Declare @Currentdate  DATE  = GETDATE();  -- Today's date
			 SET @fromdate  = DATEADD(DAY, -30, @Currentdate); -- 1 day before today
			 SET @todate  = @Currentdate;
  
			 drop table if exists #followup_statusTemp          
			 drop table if exists #followup_status  
			 drop table if exists #leadinteractionhistory          
			 drop table if exists #leadinteractionhistoryWithdatrange   
			
			DECLARE @tbluser TABLE (User_ID BIGINT,Name VARCHAR(100),IMAGE VARCHAR(100))   
			
			 DECLARE @IsAdmin BIT = 0          
          
					 SELECT @parentid = ParentID, @IsAdmin = IsAdmin          
					 FROM User_Detail(NOLOCK)          
					 WHERE User_ID = @Userid          
          
					 IF (@IsAdmin = 1)          
					 BEGIN          
					  --set @Userid = 0;                    
					  INSERT INTO @tbluser          
					  EXEC Use_GetUserDetails @ParentId          
					 END          
					 ELSE          
					 BEGIN          
					  INSERT INTO @tbluser          
					  EXEC Use_GetUserDetails @UserId          
					 END    

			IF OBJECT_ID(N'tempdb..#followup_status') IS NOT NULL          
			 BEGIN          
			  DROP TABLE #followup_status          
			 END 

			 SELECT *          
				 INTO #followup_status          
				 FROM followup_status(NOLOCK) f          
				 WHERE isactive = 1          
				  AND isnull(parentid, @parentid) = @parentid          
				  AND id = (          
				   SELECT max(id)          
				   FROM followup_status(nolock)          
				   WHERE FollowupStatus = f.FollowupStatus          
					AND isactive = 1          
					AND isnull(parentid, @parentid) = @parentid          
					and isnull(IsConvert,0) <> 1          
				   )          
          
		  DECLARE @UserIdTeamLst VARCHAR(4000) = ''          
			 DECLARE @HierarchyJSON VARCHAR(Max) = ''          
          
		     SELECT @UserIdTeamLst = ISNULL(STRING_AGG(TRY_CAST(User_ID AS NVARCHAR(MAX)), ','), '')
		-- SELECT @UserIdTeamLst = isnull(STRING_AGG(User_ID, ','), '')          
			 FROM @tbluser          
          
			 PRINT '@UserIdTeamLst: ' + @UserIdTeamLst     
			DECLARE @listtopivot NVARCHAR(max),@sql NVARCHAR(max)  
			
			SELECT @listtopivot = coalesce(@listtopivot + ',', '') + '[' + FollowUpStatus + ']'          
				FROM #followup_status(NOLOCK) where FollowupStatus != ''   

				SELECT @sql = 'SELECT * FROM (                                  
							   select    ul.User_ID, user_login,f.followupstatus,                          
							   sum(case when l.createdby=User_ID and l.followupstatus=f.id then 1 else 0 end) as Count              
								, ul.User_Login + '' ('' + isnull(ul.FName,'''') + '' '' + isnull(ul.LName,'''') + '')'' as UserByName  
								,  isnull(ul.FName,'''') + '' '' + isnull(ul.LName,'''')  as UserName  
							   from leadinteractionhistory(nolock) l                             
							   join user_detail(nolock) ul on ul.User_ID=l.createdby                            
							   join #followup_status(nolock) f on f.ID=l.FollowUpStatus                           
							   where l.parentid=' + TRY_CAST(@parentid AS NVARCHAR) + ' and IsReassign=0                           
							   and TRY_CAST(createdon as date) between ''' + TRY_CAST(@fromdate AS NVARCHAR) + ''' and ''' + TRY_CAST(@todate AS NVARCHAR) + '''    and (ul.User_ID in ( case when ''' + TRY_CAST(@IsAdmin AS NVARCHAR) + ''' = ''1'' then ul.User_ID                    
								   end                     
								   )                    
								  or             
								   ul.User_ID in ((select * from STRING_SPLIT(''' + isnull(          
							   @UserIdTeamLst, '') + ''', '','')))             
							   )             
							   group by ul.User_ID,user_login,f.followupstatus,ul.FName,ul.LName      )                           
							   FollowupsDone                                
							   PIVOT (                          
							   SUM([Count])                                  
							   FOR [followupstatus]                                  
							   IN ( ' + @listtopivot + '                          
							   )                          
							   ) AS PivotTable'
							   
			select * into #leadinteractionhistory from LeadInteractionHistory(nolock) where parentid=@parentid and TRY_CAST(CreatedOn as date) between @fromdate and @todate     

			select * into #leadinteractionhistoryWithdatrange from LeadInteractionHistory(nolock) where parentid=@parentid    

			 IF NOT EXISTS ( 
					SELECT 1 
					FROM MySMSReportCache.[dbo].[tbl_LeadReport_Cache](NOLOCK)
					WHERE User_ID = @userid
				)
				BEGIN
					INSERT INTO MySMSReportCache.[dbo].[tbl_LeadReport_Cache] 
						(
							[user_id],
							[user_login],
							[NewLeadsAdded],
							[TotalLeadsAssignedCurrently],
							[UniqueLeadsFollowedUp],
							[TotalFollowupsMarked],
							[TotalFollowupsDue],
							[TotalFollowupsDonefromDue],
							[UntouchedLeads],
							[LeadsOverDue],
							[UserByName],
							[UserName],
							[ParentId]
						)
								SELECT u.user_id          
								  ,u.user_login          
								  ,isnull(NewLeadsAdded, 0) NewLeadsAdded          
								  ,isnull(TotalLeadsAssignedCurrently, 0) TotalLeadsAssignedCurrently          
								  ,isnull(UniqueLeadsFollowedUp, 0) UniqueLeadsFollowedUp          
								  ,isnull(TotalFollowupsMarked, 0) TotalFollowupsMarked      
								   ,isnull(TotalFollowupsDue, 0) TotalFollowupsDue          
									,isnull(TotalFollowupsDonefromDue, 0) TotalFollowupsDonefromDue          
								  ,isnull(UntouchedLeads, 0) UntouchedLeads          
								  ,isnull(LeadsOverDue, 0) LeadsOverDue          
								  ,u.User_Login + ' (' + isnull(u.FName, '') + ' ' + isnull(u.LName, '') + ')' AS UserByName  
									, isnull(u.FName, '') + ' ' + isnull(u.LName, '')  AS UserName
									,@parentid
								 FROM user_detail(NOLOCK) u          
								 LEFT JOIN (          
								  SELECT user_login          
								   ,sum(CASE           
									 WHEN TRY_CAST(u.createdon as date) BETWEEN @fromdate          
									   AND @todate          
									  THEN 1          
									 ELSE 0          
									 END) AS NewLeadsAdded          
								  FROM userleads u(NOLOCK)          
								  JOIN user_detail(NOLOCK) ul ON ul.User_ID = u.CreatedBy          
								  WHERE u.parentid = @parentid          
								  GROUP BY user_login     
								  ) nwl ON nwl.User_Login = u.User_Login          
								 LEFT JOIN (          
								  SELECT user_login          
								   ,sum(CASE           
									 WHEN TRY_CAST(followupdate as date) < TRY_CAST(getdate() as date)          
									  AND isnull(f.IsConvert, 0) <> 1          
									  THEN 1          
									 ELSE 0          
									 END) AS LeadsOverDue          
								   ,count(1) TotalLeadsAssignedCurrently          
								  FROM userleads u(NOLOCK)          
								  JOIN user_detail(NOLOCK) ul ON ul.User_ID = u.AssignedTo          
								  LEFT JOIN FollowUp_Status(NOLOCK) f ON f.id = u.FollowUpStatus          
								  WHERE u.parentid = @parentid          
								  GROUP BY user_login          
								  ) OD ON OD.User_Login = u.User_Login          
								 LEFT JOIN (          
								  SELECT user_login          
								   ,count(1) AS UntouchedLeads          
								  FROM userleads u(NOLOCK)          
								  JOIN user_detail(NOLOCK) ul ON u.AssignedTo = ul.User_ID          
								  WHERE u.parentid = @parentid          
								   AND (          
									isnull(LastFollowupCreatedBy, 0) = 0          
									OR NOT EXISTS (          
									 SELECT 1          
									 FROM #leadinteractionhistoryWithdatrange(NOLOCK)          
									 WHERE isreassign = 0          
									  AND leadno = u.leadno          
									  AND parentid = u.parentid          
									 )          
									)          
								  GROUP BY user_login          
								  ) UL ON UL.User_Login = u.User_Login          
								 LEFT JOIN (          
								  SELECT user_login          
								   ,sum(CASE           
									 WHEN l.createdby = User_ID          
									  THEN 1          
									 ELSE 0          
									 END) AS UniqueLeadsFollowedUp          
								   ,sum(TotalFollowupsMarked) TotalFollowupsMarked --,sum(case when l.createdby is null then 1 else 0 end) as UntouchedLeads                          
								  FROM (          
								   SELECT lih1.leadno          
									,lih1.parentid          
									,lih1.createdby          
									,count(1) AS TotalFollowupsMarked          
								   FROM #leadinteractionhistory(NOLOCK) as lih1          
								   join followup_status(nolock) as fs1          
								   on lih1.FollowUpStatus = fs1.ID          
									WHERE lih1.parentid = @parentid          
									AND lih1.IsReassign = 0          
									AND TRY_CAST(lih1.createdon as date) BETWEEN @fromdate          
									 AND @todate          
												And isnull(fs1.IsConvert,0) <> 1              
								   GROUP BY leadno          
									,lih1.parentid          
									,lih1.createdby          
								   ) l          
								  JOIN user_detail(NOLOCK) ul ON ul.User_ID = l.createdby          
								  WHERE l.parentid = @parentid          
								  GROUP BY User_Login          
								  ) LF ON u.user_login = LF.User_Login       
								  LEFT JOIN (          
								  SELECT user_login          
									  ,sum(TotalFollowupsDue) TotalFollowupsDue       
								   ,   sum(TotalFollowupsDonefromDue) as TotalFollowupsDonefromDue                          
								  FROM (          
								   SELECT lih1.leadno          
									,lih1.parentid          
									,lih1.AssignedTo          
									,count(1) AS TotalFollowupsDue      
								 ,sum(dbo.fn_isleadfollowed_withrange(lih1.id,@fromdate,@todate)) TotalFollowupsDonefromDue      
								   FROM #leadinteractionhistoryWithdatrange(NOLOCK) as lih1          
								   join followup_status(nolock) as fs1          
								   on lih1.FollowUpStatus = fs1.ID      
									WHERE lih1.parentid = @parentid          
									 AND TRY_CAST(lih1.FollowupDate as date) BETWEEN @fromdate          
									 AND @todate          
									 And isnull(fs1.IsConvert,0) <> 1              
								   GROUP BY leadno          
									,lih1.parentid          
									,lih1.AssignedTo          
								   ) l          
								  JOIN user_detail(NOLOCK) ul ON ul.User_ID = l.AssignedTo          
								  WHERE l.parentid = @parentid          
								  GROUP BY User_Login          
								  ) LTF ON u.user_login = LTF.User_Login          
      							WHERE u.parentid = @parentid          
								  AND (          
								   u.User_ID IN (          
									CASE           
									 WHEN @IsAdmin = 1          
									  THEN u.User_ID          
									 END          
									)          
								   OR u.User_ID IN (          
									SELECT User_ID          
									FROM @tbluser          
									)          
								   )    
								   
