					--				AND TRY_CAST(lih1.createdon as date) BETWEEN @fromdate          
					--				 AND @todate          
					--							And isnull(fs1.IsConvert,0) <> 1              
					--			   GROUP BY leadno          
					--				,lih1.parentid          
					--				,lih1.createdby          
					--			   ) l          
					--			  JOIN user_detail(NOLOCK) ul ON ul.User_ID = l.createdby          
					--			  WHERE l.parentid = @parentid          
					--			  GROUP BY User_Login          
					--			  ) LF ON u.user_login = LF.User_Login       
					--			  LEFT JOIN (          
					--			  SELECT user_login          
					--				  ,sum(TotalFollowupsDue) TotalFollowupsDue       
					--			   ,   sum(TotalFollowupsDonefromDue) as TotalFollowupsDonefromDue                          
					--			  FROM (          
					--			   SELECT lih1.leadno          
					--				,lih1.parentid          
					--				,lih1.AssignedTo          
					--				,count(1) AS TotalFollowupsDue      
					--			 ,sum(dbo.fn_isleadfollowed_withrange(lih1.id,@fromdate,@todate)) TotalFollowupsDonefromDue      
					--			   FROM #leadinteractionhistoryWithdatrange(NOLOCK) as lih1          
					--			   join followup_status(nolock) as fs1          
					--			   on lih1.FollowUpStatus = fs1.ID      
					--				WHERE lih1.parentid = @parentid          
					--				 AND TRY_CAST(lih1.FollowupDate as date) BETWEEN @fromdate          
					--				 AND @todate          
					--				 And isnull(fs1.IsConvert,0) <> 1              
					--			   GROUP BY leadno          
					--				,lih1.parentid          
					--				,lih1.AssignedTo          
					--			   ) l          
					--			  JOIN user_detail(NOLOCK) ul ON ul.User_ID = l.AssignedTo          
					--			  WHERE l.parentid = @parentid          
					--			  GROUP BY User_Login          
					--			  ) LTF ON u.user_login = LTF.User_Login          
     -- 							WHERE u.parentid = @parentid          
					--			  AND (          
					--			   u.User_ID IN (          
					--				CASE           
					--				 WHEN @IsAdmin = 1          
					--				  THEN u.User_ID          
					--				 END          
					--				)          
					--			   OR u.User_ID IN (          
					--				SELECT User_ID          
					--				FROM @tbluser          
					--				)          
					--			   )  
				END

				IF NOT EXISTS ( 
					SELECT 1 
					FROM MySMSReportCache.[dbo].[tbl_FollowupReport_Cache](NOLOCK)
					WHERE User_ID = @userid
				)
				BEGIN
					INSERT INTO MySMSReportCache.[dbo].[tbl_FollowupReport_Cache] 
						(
						   [Date]
						  ,[user_id]
						  ,[user_login]
						  ,[FollowupsDue]
						  ,[FollowupsDoneTillDate]
						  ,[FollowupsDoneInTime]
						  ,[FollowedUpByOthers]
						  ,[NotFollowedTillDate]
						  ,[UserByName]
						  ,[UserName]
						  ,[ParentId]
						)
						SELECT TRY_CAST(c.start_dts as date) as Date,u.user_id          
							  ,u.user_login         
							 ,count(1) FollowupsDue          
							 ,sum(dbo.fn_isleadfollowed(lih.id)) FollowupsDoneTillDate       
							 ,sum(dbo.fn_isleadfollowed_withrange(lih.id,@fromdate,@fromdate)) FollowupsDoneInTime    
							 ,sum(dbo.fn_isleadfollowedbyothers(lih.id)) FollowedUpByOthers    
							 ,sum(dbo.fn_isleadnotfollowedtilldate(lih.id)) NotFollowedTillDate    
							 ,u.User_Login + ' (' + isnull(u.FName, '') + ' ' + isnull(u.LName, '') + ')' AS UserByName   
							  , isnull(u.FName, '') + ' ' + isnull(u.LName, '')  AS UserName 
							  ,@parentid
							 FROM user_detail(NOLOCK) u        
							 LEFT JOIN       
							 #leadinteractionhistoryWithdatrange(NOLOCK)  lih on lih.assignedto=u.user_id      
							 left join FollowUp_Status (nolock) f on f.id=lih.FollowUpStatus    
							 left join calendar (nolock) c on TRY_CAST(c.start_dts as date)=TRY_CAST(lih.followupdate as date)      
							 WHERE isreassign = 0  and lih.FollowupDate is not null      
							  AND (u.User_ID IN (CASE WHEN @IsAdmin = 1 THEN u.User_ID END)          
							   OR u.User_ID IN (SELECT User_ID  FROM @tbluser ))          
							 and TRY_CAST(c.start_dts as date) between @fromdate and @todate      
							 and f.IsCallback=1    
							  GROUP BY user_id,user_login ,TRY_CAST(c.start_dts as date),u.FName,u.LName  

					--INSERT INTO MySMSReportCache.[dbo].[tbl_FollowupReport_Archive] 
					--	(
