					--	  ,[NotFollowedTillDate]
					--	  ,[UserByName]
					--	  ,[UserName]
					--	  ,[ParentId]
					--	)
					--	SELECT TRY_CAST(c.start_dts as date) as Date,u.user_id          
					--		  ,u.user_login         
					--		 ,count(1) FollowupsDue          
					--		 ,sum(dbo.fn_isleadfollowed(lih.id)) FollowupsDoneTillDate       
					--		 ,sum(dbo.fn_isleadfollowed_withrange(lih.id,@fromdate,@fromdate)) FollowupsDoneInTime    
					--		 ,sum(dbo.fn_isleadfollowedbyothers(lih.id)) FollowedUpByOthers    
					--		 ,sum(dbo.fn_isleadnotfollowedtilldate(lih.id)) NotFollowedTillDate    
					--		 ,u.User_Login + ' (' + isnull(u.FName, '') + ' ' + isnull(u.LName, '') + ')' AS UserByName   
					--		  , isnull(u.FName, '') + ' ' + isnull(u.LName, '')  AS UserName 
					--		  ,@parentid
					--		 FROM user_detail(NOLOCK) u        
					--		 LEFT JOIN       
					--		 #leadinteractionhistoryWithdatrange(NOLOCK)  lih on lih.assignedto=u.user_id      
					--		 left join FollowUp_Status (nolock) f on f.id=lih.FollowUpStatus    
					--		 left join calendar (nolock) c on TRY_CAST(c.start_dts as date)=TRY_CAST(lih.followupdate as date)      
					--		 WHERE isreassign = 0  and lih.FollowupDate is not null      
					--		  AND (u.User_ID IN (CASE WHEN @IsAdmin = 1 THEN u.User_ID END)          
					--		   OR u.User_ID IN (SELECT User_ID  FROM @tbluser ))          
					--		 and TRY_CAST(c.start_dts as date) between @fromdate and @todate      
					--		 and f.IsCallback=1    
					--		  GROUP BY user_id,user_login ,TRY_CAST(c.start_dts as date),u.FName,u.LName  
				END

				drop table if exists #followup_statusTemp          
				drop table if exists #followup_status    
				drop table if exists #leadinteractionhistory          
				drop table if exists #leadinteractionhistoryWithdatrange 
END TRY
BEGIN CATCH
exec usp_InsertErrorInfo
END CATCH
		
		-- Move to the next row
        SET @currentRow = @currentRow + 1;
END

	DELETE FROM MySMSReportCache.[dbo].[tbl_FollowupReport_Cache]
	WHERE TRY_CAST([Date] AS DATE) NOT BETWEEN DATEADD(DAY, -30, TRY_CAST(GETDATE() AS DATE)) AND TRY_CAST(GETDATE() AS DATE);

	-- Clean up the temporary table
    DROP TABLE #UserIDs;
   
END 





