/* ============================================================
   Procedure: [dbo].[usp_Insert_getleadreport_daywise_Pipeline_DataTo_Archive]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


   -- select * from MySMSReportCache.[dbo].[tbl_UserPipelineReport_Cache]  select * from MySMSReportCache.[dbo].[tbl_AgentPipelineReport_Cache] select * from MySMSReportCache.[dbo].[tbl_UserPipelineReport_Archive]  select * from MySMSReportCache.[dbo].[tbl_AgentPipelineReport_Archive]

   -- TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_UserPipelineReport_Cache];  TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_AgentPipelineReport_Cache]; TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_UserPipelineReport_Archive];  TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_AgentPipelineReport_Archive];

   -- exec usp_Insert_getleadreport_daywise_Pipeline_DataTo_Archive

CREATE   PROCEDURE [dbo].[usp_Insert_getleadreport_daywise_Pipeline_DataTo_Archive]       

as                      
BEGIN    
SET NOCOUNT ON;

	DECLARE @userid BIGINT;
    DECLARE @currentRow INT = 1;  -- Variable to track the current row in the temporary table
    DECLARE @totalRows INT;       -- Variable to store the total number of rows to process

    -- Create a temporary table to store the User IDs
    CREATE TABLE #UserIDs (UserID BIGINT);

    -- Insert UserIDs into the temporary table
    INSERT INTO #UserIDs (UserID)
    SELECT CreatedBy
    FROM Mysms.dbo.LeadPipelineMapping_latest(NOLOCK)
	WHERE CreatedBy IS NOT NULL
    GROUP BY CreatedBy
    ORDER BY COUNT(*) DESC;
	
    -- Get the total number of rows
    SELECT @totalRows = COUNT(*) FROM #UserIDs;

-- Loop through each User_ID using a WHILE loop
    WHILE @currentRow <= @totalRows
BEGIN
BEGIN TRY

		-- Use a CTE to calculate ROW_NUMBER() and select the current UserID
				WITH CTE_UserIDs AS (
					SELECT UserID, ROW_NUMBER() OVER (ORDER BY UserID) AS RowNum
					FROM #UserIDs
				)
				SELECT @userid = UserID
				FROM CTE_UserIDs
				WHERE RowNum = @currentRow;
				
				DECLARE  @parentid bigint
						 ,@fromdate DATE          
						 ,@todate DATE 
						 ,@IsAdmin BIT = 0   

			 
			 Declare @Currentdate  DATE  = GETDATE();  -- Today's date
			 SET @fromdate  = DATEADD(DAY, -9130, @Currentdate); -- 1 day before today
			 SET @todate  = @Currentdate;

			 select @ParentId = ParentID, @IsAdmin = isnull(IsAdmin,0) from User_Detail(nolock) where User_ID = @UserId;

			 DECLARE @tbluser TABLE (User_ID BIGINT, Name VARCHAR(100), IMAGE VARCHAR(100)) 

			 IF (@IsAdmin = 1)          
			 BEGIN          
			  --set @Userid = 0;                    
				  INSERT INTO @tbluser          
				  EXEC Use_GetUserDetails @ParentId          
			 END          
			 ELSE          
			 BEGIN          
				  INSERT INTO @tbluser          
				  EXEC Use_GetUserDetails @UserId          
			 END   

			 IF NOT EXISTS ( 
					SELECT 1 
					FROM MySMSReportCache.[dbo].[tbl_UserPipelineReport_Archive](NOLOCK)
					WHERE User_ID = @userid
				)
				BEGIN
						INSERT INTO MySMSReportCache.[dbo].[tbl_UserPipelineReport_Archive] 
							(
							   [User_ID]
							  ,[user_login]
							  ,[UserByName]
							  ,[NewAdded]
							  ,[Deleted]
							  ,[Expired]
							  ,[Won]
							  ,[Lost]
							  ,[AverageDaysToWin]
							  ,[CurrentlyinPipeline]
							  ,[Stagnant]
							  ,[ParentId]
							  ,[DATE]
							)
								SELECT u.User_ID, u.user_login, u.User_Login + ' (' + isnull(u.FName, '') + ' ' + isnull(u.LName, '') + ')' AS UserByName
									  ,isnull(NewAdded, 0) NewAdded, isnull(Deleted, 0) Deleted, isnull(Expired, 0) Expired, isnull(Won, 0) Won          
									  ,isnull(Lost, 0) Lost, isnull(AverageDaysToWin, 0) AverageDaysToWin, isnull(CurrentlyinPipeline, 0) CurrentlyinPipeline, ISNULL(Stagnant, 0) AS Stagnant, @parentid, @fromdate        
									 FROM user_detail(NOLOCK) u          
									 LEFT JOIN (          
									  SELECT user_login          
									   ,sum(CASE           
										 WHEN TRY_CAST(createddate as date) BETWEEN @fromdate          
										   AND @todate          
										  THEN 1          
										 ELSE 0          
										 END) AS NewAdded          
									   ,sum(CASE           
										 WHEN TRY_CAST(DeletedOn as date) BETWEEN @fromdate          
										   AND @todate          
										  THEN 1          
										 ELSE 0          
										 END) AS Deleted          
									  --FROM LeadPipelineMapping_earliest(NOLOCK) l          
									  FROM LeadPipelineMapping_latest(NOLOCK) l          
									  JOIN user_detail(NOLOCK) u ON u.user_id = l.CreatedBy          
									  WHERE parentid = @parentid          
									  GROUP BY user_login          
									  ) ND ON ND.User_Login = u.user_login          
									 LEFT JOIN (          
									  SELECT user_login          
									   ,sum(CASE           
										 WHEN TRY_CAST(lpm.createddate as date) BETWEEN @fromdate          
										   AND @todate          
										  AND PS.Name = 'Won'          
										  THEN 1          
										 ELSE 0          
										 END) AS Won          
									   ,sum(CASE       
										 WHEN TRY_CAST(lpm.createddate as date) BETWEEN @fromdate          
										   AND @todate          
										  AND PS.Name = 'Lost'          
										  THEN 1          
										 ELSE 0          
										 END) AS Lost          
									   ,sum(CASE           
										 WHEN datediff(d, lpm.createddate, getdate()) >= 30          
										  AND PS.name NOT IN (          
										   'won'          
									 ,'Lost'          
										   )          
										  AND lpm.IsDeleted = 0          
										  THEN 1          
										 ELSE 0          
										 END) AS Stagnant          
									   ,sum(CASE           
										 WHEN PS.name NOT IN (          
										   'won'          
										   ,'Lost'          
										   )          
										  AND lpm.IsDeleted = 0          
										  THEN 1          
										 ELSE 0          
										 END) AS CurrentlyinPipeline          
									   ,sum(CASE           
										 WHEN datediff(d, l.createddate, lpm.createddate) > pm.DealExpiry          
										  THEN 1          
										 ELSE 0          
										 END) AS Expired          
									   ,avg(CASE           
										 WHEN PS.Name = 'Won'          
										  AND l.leadid IS NOT NULL          
										  THEN datediff(d, l.createddate, lpm.createddate)          
										 ELSE - 1          
										 END) AverageDaysToWin          
									  FROM LeadPipelineMapping_latest(NOLOCK) lpm          
									  INNER JOIN Pipeline_Master AS PM WITH (NOLOCK) ON LPM.PipelineID = PM.ID          
									  INNER JOIN PipelineStages AS PS WITH (NOLOCK) ON LPM.PipeLineStage = PS.ID          
									  LEFT JOIN (          
									   SELECT leadid          
										,createddate          
									   --FROM LeadPipelineMapping_earliest(NOLOCK)          
									   FROM LeadPipelineMapping_latest(NOLOCK)          
									   WHERE isdeleted = 0          
									   ) l ON l.leadid = lpm.LeadID          
									  JOIN user_detail(NOLOCK) u ON u.user_id = lpm.DealOwner          
									  WHERE pm.parentid = @parentid          
									  GROUP BY user_login          
									  ) wl ON wl.User_Login = u.User_Login          
									 WHERE u.parentID = @parentid          
									  AND (          
									   u.User_ID IN (          
										CASE           
										 WHEN @IsAdmin = 1          
										  THEN u.User_ID          
										   --else @UserIdTeamLst                     
										 END          
										)          
									   OR u.User_ID IN (          
										SELECT User_ID          
										FROM @tbluser          
										)          
									   )          
									  AND u.STATUS = 1
				END

				IF NOT EXISTS ( 
					SELECT 1 
					FROM MySMSReportCache.[dbo].[tbl_AgentPipelineReport_Archive](NOLOCK)
					WHERE User_ID = @userid
				)
				BEGIN
						INSERT INTO MySMSReportCache.[dbo].[tbl_AgentPipelineReport_Archive] 
							(
							   [User_ID]
							  ,[user_login]
							  ,[UserByName]
							  ,[Pipeline]
							  ,[NewAdded]
							  ,[Deleted]
							  ,[Expired]
							  ,[Won]
							  ,[Lost]
							  ,[AverageDaysToWin]
							  ,[CurrentlyinPipeline]
							  ,[Stagnant]
							  ,[ParentId]
							  ,[DATE]
							)
								SELECT u.User_ID, u.user_login, u.User_Login + ' (' + isnull(u.FName, '') + ' ' + isnull(u.LName, '') + ')' AS UserByName, Pipeline, isnull(NewAdded, 0) NewAdded, isnull(Deleted, 0) Deleted, isnull(Expired, 0) Expired, isnull(Won, 0) Won
									,isnull(Lost, 0) Lost, isnull(AverageDaysToWin, 0) AverageDaysToWin, isnull(CurrentlyinPipeline, 0) CurrentlyinPipeline, ISNULL(Stagnant, 0) Stagnant, @parentid, @fromdate            
									 FROM user_detail(NOLOCK) u          
									 LEFT JOIN (          
									  SELECT id          
									   ,name AS Pipeline          
									   ,ParentID          
									  FROM Pipeline_Master(NOLOCK)          
									  WHERE parentid = @parentid          
									   AND isdeleted = 0          
									  ) p ON p.parentid = u.ParentID          
									 LEFT JOIN (          
									  SELECT user_login          
									   ,pm.Name AS PipelineN          
									   ,sum(CASE           
										 WHEN TRY_CAST(l.createddate as date) BETWEEN @fromdate          
										   AND @todate          
										  THEN 1          
										 ELSE 0          
										 END) AS NewAdded          
									   ,sum(CASE           
										 WHEN TRY_CAST(DeletedOn as date) BETWEEN @fromdate          
										   AND @todate          
										  THEN 1          
										 ELSE 0          
										 END) AS Deleted          
									  --FROM LeadPipelineMapping_earliest(NOLOCK) l          
									  FROM LeadPipelineMapping_latest(NOLOCK) l          
									  INNER JOIN Pipeline_Master AS PM WITH (NOLOCK) ON L.PipelineID = PM.ID          
									  JOIN user_detail(NOLOCK) u ON u.user_id = l.CreatedBy          
									  WHERE u.parentid = @parentid          
									  GROUP BY user_login          
									   ,pm.Name          
									  ) ND ON ND.User_Login = u.user_login          
									  AND ND.PipelineN = p.pipeline          
									 LEFT JOIN (          
									  SELECT user_login          
									   ,pm.Name AS PipelineN          
									   ,sum(CASE           
										 WHEN TRY_CAST( lpm.createddate as date) BETWEEN @fromdate          
										   AND @todate          
										  AND PS.Name = 'Won'          
										  THEN 1          
										 ELSE 0          
										 END) AS Won          
									   ,sum(CASE           
										 WHEN  TRY_CAST(lpm.createddate as date) BETWEEN @fromdate          
										   AND @todate          
										  AND PS.Name = 'Lost'          
										  THEN 1          
										 ELSE 0          
										 END) AS Lost          
									   ,sum(CASE           
										 WHEN datediff(d, lpm.createddate, getdate()) >= 30          
										  AND PS.name NOT IN (          
										   'won'          
										   ,'Lost'          
										   )          
										  AND lpm.IsDeleted = 0          
										  THEN 1          
										 ELSE 0          
										 END) AS Stagnant          
									   ,sum(CASE           
										 WHEN PS.name NOT IN (          
										   'won'          
										   ,'Lost'          
										   )          
										  AND lpm.IsDeleted = 0          
										  THEN 1          
										 ELSE 0          
										 END) AS CurrentlyinPipeline          
									   ,          
									   --sum(case when datediff(d,l.createddate,lpm.createddate)>pm.DealExpiry then 1 else 0 end) as Expired,                
									   sum(CASE           
										 WHEN datediff(DAY, getdate(), lpm.EstimatedClosureDate) <= 0          
										  THEN 1          
										 ELSE 0          
										 END) AS Expired          
									   ,avg(CASE           
										 WHEN PS.Name = 'Won'          
										  AND l.leadid IS NOT NULL          
										  THEN datediff(d, l.createddate, lpm.createddate)          
										 ELSE - 1          
										 END) AverageDaysToWin          
									  FROM LeadPipelineMapping_latest(NOLOCK) lpm          
									  INNER JOIN Pipeline_Master AS PM WITH (NOLOCK) ON LPM.PipelineID = PM.ID          
									  INNER JOIN PipelineStages AS PS WITH (NOLOCK) ON LPM.PipeLineStage = PS.ID          
									  LEFT JOIN (          
									   SELECT leadid          
										,createddate          
									   --FROM LeadPipelineMapping_earliest(NOLOCK)          
									   FROM LeadPipelineMapping_latest(NOLOCK)          
									   WHERE isdeleted = 0          
									   ) l ON l.leadid = lpm.LeadID          
									  JOIN user_detail(NOLOCK) u ON u.user_id = lpm.DealOwner          
									  WHERE pm.parentid = @parentid          
									  GROUP BY user_login          
									   ,pm.Name          
									  ) wl ON wl.User_Login = u.User_Login          
									  AND wl.PipelineN = p.Pipeline          
									 WHERE u.parentID = @parentid          
									  AND (          
									   u.User_ID IN (          
										CASE           
										 WHEN @IsAdmin = 1          
										  THEN u.User_ID          
										   --else @UserIdTeamLst                     
										 END          
										)          
									   OR u.User_ID IN (          
										SELECT User_ID          
										FROM @tbluser          
										)          
									   )          
									  AND u.STATUS = 1          
									 ORDER BY u.User_Login
				END

END TRY
