/* ============================================================
   Procedure: [dbo].[usp_Insert_getleadreport_daywise_TaskAndAppointment_DataTo_Archive]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


   -- select * from MySMSReportCache.[dbo].[tbl_Task_Cache] select * from MySMSReportCache.[dbo].[tbl_Appointment_Cache] select * from MySMSReportCache.[dbo].[tbl_Task_Archive] select * from MySMSReportCache.[dbo].[tbl_Appointment_Archive]

   -- TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_Task_Cache]; TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_Appointment_Cache];TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_Task_Archive]; TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_Appointment_Archive];

   -- exec usp_Insert_getleadreport_daywise_TaskAndAppointment_DataTo_Archive

CREATE   PROCEDURE [dbo].[usp_Insert_getleadreport_daywise_TaskAndAppointment_DataTo_Archive]       

as                      
BEGIN    
SET NOCOUNT ON;

	DECLARE @userid BIGINT;
    DECLARE @currentRow INT = 1;  -- Variable to track the current row in the temporary table
    DECLARE @totalRows INT;       -- Variable to store the total number of rows to process

    -- Create a temporary table to store the User IDs
    CREATE TABLE #UserIDs (UserID BIGINT);

    -- Insert UserIDs into the temporary table
    INSERT INTO #UserIDs (UserID)
    SELECT CreatedBy
    FROM Mysms.dbo.tbl_tsk_TaskHistory (NOLOCK)
	WHERE CreatedBy IS NOT NULL
	group by CreatedBy
	order by count(*) desc
	
    -- Get the total number of rows
    SELECT @totalRows = COUNT(*) FROM #UserIDs;

-- Loop through each User_ID using a WHILE loop
    WHILE @currentRow <= @totalRows
BEGIN
BEGIN TRY

		-- Use a CTE to calculate ROW_NUMBER() and select the current UserID
				WITH CTE_UserIDs AS (
					SELECT UserID, ROW_NUMBER() OVER (ORDER BY UserID) AS RowNum
					FROM #UserIDs
				)
				SELECT @userid = UserID
				FROM CTE_UserIDs
				WHERE RowNum = @currentRow;
				
				DECLARE  @parentid BIGINT,          
						 @fromdate DATE,          
						 @todate DATE   

			 
			 Declare @Currentdate  DATE  = GETDATE();  -- Today's date
			 SET @fromdate  = DATEADD(DAY, -9130, @Currentdate); -- 1 day before today
			 SET @todate  = @Currentdate;
  
			DECLARE @tbluser TABLE (User_ID BIGINT,Name VARCHAR(100),IMAGE VARCHAR(100))   
			
			 DECLARE @IsAdmin BIT = 0          
          
					 SELECT @parentid = ParentID, @IsAdmin = IsAdmin          
					 FROM User_Detail(NOLOCK)          
					 WHERE User_ID = @Userid          
          
					 IF (@IsAdmin = 1)          
					 BEGIN          
					  --set @Userid = 0;                    
					  INSERT INTO @tbluser          
					  EXEC Use_GetUserDetails @ParentId          
					 END          
					 ELSE          
					 BEGIN          
					  INSERT INTO @tbluser          
					  EXEC Use_GetUserDetails @UserId          
					 END    

			 IF NOT EXISTS ( 
					SELECT 1 
					FROM MySMSReportCache.[dbo].[tbl_Task_Archive](NOLOCK)
					WHERE UserId = @userid
				)
				BEGIN
					INSERT INTO MySMSReportCache.[dbo].[tbl_Task_Archive] 
						(
							 [CreatedDate]
						    ,[Executive]
						    ,[TotalCreated]
						    ,[CompletedTillDate]
						    ,[CompletedInTime]
						    ,[Open]
						    ,[UserByName]
						    ,[UserId]
							,[ParentId]
						)
						select TRY_CAST(c.date_id as date) as CreatedDate,user_login as Executive,count(1) TotalCreated      
							,sum(case when t.Status='completed' then 1 else 0 end) as CompletedTillDate      
							,sum(case when t.Status='completed' and TRY_CAST(completedon as date)<=TRY_CAST(t.enddate as date) then 1 else 0 end) as CompletedInTime      
							,sum(case when t.status='Open' then 1 else 0 end) as [Open]      
							 ,u.User_Login + ' (' + isnull(u.FName, '') + ' ' + isnull(u.LName, '') + ')' AS UserByName 
							 ,@userid, @parentid
							from [dbo].[tbl_tsk_TaskHistory] t with (nolock)     
							join user_detail u with (nolock) on t.createdby=u.User_ID     
							right join calendar c with (nolock) on TRY_CAST(c.date_id as date)=TRY_CAST(t.createdon as date)    
							where u.parentid=@parentid and TRY_CAST(c.date_id as date) BETWEEN @fromdate AND @todate     
							and istask=1      
							 AND (u.User_ID IN (CASE WHEN @IsAdmin = 1 THEN u.User_ID END)          
							   OR u.User_ID IN (SELECT User_ID  FROM @tbluser ))          
							group by user_login,TRY_CAST(c.date_id as date),u.FName,u.LName,createdby 
				END

				IF NOT EXISTS ( 
					SELECT 1 
					FROM MySMSReportCache.[dbo].tbl_Appointment_Archive(NOLOCK)
					WHERE UserId = @userid
				)
				BEGIN
					INSERT INTO MySMSReportCache.[dbo].[tbl_Appointment_Archive] 
						(
						   [CreatedDate]
						  ,[Executive]
						  ,[TotalCreated]
						  ,[CompletedTillDate]
						  ,[CompletedInTime]
						  ,[Open]
						  ,[UserByName]
						  ,[UserId]
						  ,[ParentId]
						)
						select TRY_CAST(c.date_id as date) as CreatedDate,user_login as Executive,count(1) TotalCreated      
							,sum(case when t.Status='completed' then 1 else 0 end) as CompletedTillDate      
							,sum(case when t.Status='completed' and TRY_CAST(completedon as date)<=TRY_CAST(t.enddate as date) then 1 else 0 end) as CompletedInTime      
							,sum(case when t.status='Open' then 1 else 0 end) as [Open]      
							 ,u.User_Login + ' (' + isnull(u.FName, '') + ' ' + isnull(u.LName, '') + ')' AS UserByName 
							 ,@userid, @parentid
							from [dbo].[tbl_tsk_TaskHistory] t with (nolock)     
							join user_detail u with (nolock) on t.createdby=u.User_ID     
							right join calendar c with (nolock) on TRY_CAST(c.date_id as date)=TRY_CAST(t.createdon as date)    
							where u.parentid=@parentid and TRY_CAST(c.date_id as date) BETWEEN @fromdate AND @todate     
							and isappointment=1      
							 AND (u.User_ID IN (CASE WHEN @IsAdmin = 1 THEN u.User_ID END)          
							   OR u.User_ID IN (SELECT User_ID  FROM @tbluser ))          
							group by user_login,TRY_CAST(c.date_id as date),u.FName,u.LName,createdby  
				END
END TRY
BEGIN CATCH
exec usp_InsertErrorInfo
END CATCH
		
		-- Move to the next row
        SET @currentRow = @currentRow + 1;
END
	-- Clean up the temporary table
    DROP TABLE #UserIDs;
   
END 





GO

