CREATE   PROCEDURE [dbo].[usp_Insert_GetWhatsappSummeryByUserIdAndDuration_DataTo_Archive] 
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	SET NOCOUNT ON;
