CREATE   PROCEDURE [dbo].[usp_Insert_GetWhatsappSummeryByUserIdAndDuration_DataTo_Cache_Archive] 

AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	SET NOCOUNT ON;

	DECLARE @userid BIGINT;
    DECLARE @currentRow INT = 1;  -- Variable to track the current row in the temporary table
    DECLARE @totalRows INT;       -- Variable to store the total number of rows to process

    -- Create a temporary table to store the User IDs
    CREATE TABLE #UserIDs (UserID BIGINT);

	declare @sqlquery nvarchar(max);

    -- Insert UserIDs into the temporary table
    /*INSERT INTO #UserIDs (UserID)
    SELECT convuserparentid
    FROM [MySMSConversations].dbo.convusers(NOLOCK)
	WHERE convuserparentid IS NOT NULL
    GROUP BY convuserparentid
    ORDER BY COUNT(*) DESC;*/
	SET @sqlquery = '
    SELECT convuserparentid
    FROM convusers (NOLOCK)
    WHERE convuserparentid IS NOT NULL
    GROUP BY convuserparentid
    ORDER BY COUNT(*) DESC;';

    INSERT INTO #UserIDs (UserID)
    EXEC usp_clr_FillRemoteData  @sqlquery;

    -- Get the total number of rows
    SELECT @totalRows = COUNT(*) FROM #UserIDs;

-- Loop through each User_ID using a WHILE loop
    WHILE @currentRow <= @totalRows
BEGIN
BEGIN TRY
			-- Use a CTE to calculate ROW_NUMBER() and select the current UserID
				WITH CTE_UserIDs AS (
					SELECT UserID, ROW_NUMBER() OVER (ORDER BY UserID) AS RowNum
					FROM #UserIDs
				)
				SELECT @userid = UserID
				FROM CTE_UserIDs
				WHERE RowNum = @currentRow;

   
			Declare 
					@fromdate DATE = NULL,       
					@todate   DATE = NULL,
					@ChannelId int = 2; 


			Declare @Currentdate  DATE  = GETDATE();  -- Today's date
			SET @fromdate  = DATEADD(DAY, -30, @Currentdate); -- 1 day before today	
			SET @todate  = @Currentdate;

			IF NOT EXISTS ( 
					SELECT 1 
					FROM MySMSReportCache.[dbo].[tbl_WhatsappRecivedandSent_Cache] (NOLOCK)
					WHERE UserId = @userid
				)
				BEGIN

		declare @ConvSummerySql1 nvarchar(max), 
			@ConvSummerySql2 nvarchar(max), 
			@ConvSummerySql3 nvarchar(max),
			@ConvSummerySql4 nvarchar(max),
			@ConvSummerySql5 nvarchar(max),
			@ConvSummerySql6 nvarchar(max),
			@ConvSummerySql7 nvarchar(max);

			declare @ParentId bigint = (select top 1 ParentId from Mysms.dbo.User_Detail(nolock) where USER_ID = @userid); 
			
			declare 
			@convTableName nvarchar(255) = ''
		--exec [MySMSConversations].dbo.usp_ims_GetConversationTableName @userid, @Tablename = @convTableName output
