				set @ConvSummerySql7 = concat( 'select ScheduledDate, sum(Total)Total from ( select ScheduledDate, Case When Status = ''COMPLETED'' then ''DELIVERED'' When Status = ''PARTIAL'' then ''SENT'' When Status = ''ONHOLD'' then ''ONHOLD'' When Status = ''FAILED'' then ''FAILED'' Else Status End Status, count(Status) Total from ( select Cast(ScheduledDatetime as Date) ScheduledDate, DeliveryPerc, TotalRecepients, FailedCnt, Status from ( SELECT B.BroadCastId, B.BroadcastName, B.ScheduledDatetime, DeliveryPerc = CASE B.DeliveryStatus WHEN ''completed'' THEN 100 WHEN ''failed'' THEN 0 WHEN ''onhold'' THEN 0 ELSE ISNULL( ( SELECT CAST(SUM(IIF(LEN (wa_message_id) > 1, 1, 0)) * 100.0 / COUNT(*) AS NUMERIC(18, 2)) FROM #temp2 WHERE BroadcastId = B.BroadcastId ), 0) END, TotalRecepients = ISNULL( ( SELECT COUNT(*) FROM #temp2 WHERE BroadcastId = B.BroadcastId ), 0), FailedCnt = ISNULL( ( SELECT SUM(IIF(LEN(wa_message_id) = 0, 1, 0)) FROM #temp2 WHERE BroadcastId = B.BroadcastId ), 0), STATUS = ISNULL(UPPER(B.DeliveryStatus), ''FAILED''), isnull(rc.RevertedCount, 0) as RevertedCnt, isnull(((select SUM(IIF(LEN(wa_message_id) > 1, 1, 0)) FROM #temp2 WHERE BroadcastId = B.BroadcastId) - isnull(rc.RevertedCount, 0)), 0) as NotResponded FROM tbl_wsap_BroadcastMsg(NOLOCK) B INNER JOIN Mysms.dbo.User_Detail(NOLOCK) UD ON B.CreatedBy = UD.User_ID LEFT JOIN ( SELECT sm.BroadcastId, COUNT(sm.BroadcastId) RevertedCount FROM ', '[MySMSConversations].dbo.', @convTableName,'(NOLOCK) cn INNER JOIN #temp2 sm ON cn.contextid = sm.wa_message_id WHERE sm.wa_message_id <> '''' AND cn.contextid <> '''' GROUP BY sm.BroadcastId ) rc ON b.BroadcastId = rc.BroadcastId WHERE B.IsProcessed = 1 AND B.IsCancelled = 0 AND UD.ParentID = ', @ParentId, ' AND cast(B.ScheduledDatetime as date) BETWEEN cast(''', @FromDate, ''' as date) AND cast(''', @ToDate, ''' as date) ) t )tt group by ScheduledDate, Status )ttt group by ScheduledDate ')
			

