/* ============================================================
   Procedure: [dbo].[usp_insert_in_entityactivityqueue]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE    proc [dbo].[usp_insert_in_entityactivityqueue]  
@activityid bigint,@entity nvarchar(50)  
as  
begin  
declare @tbl nvarchar(100),@sql nvarchar(max)  
select @tbl=case   
when @entity='lead' then 'tbl_leadeventhistory'  
when @entity='enquiry' then 'tbl_enquiryeventhistory'  
when @entity='user' then 'tbl_usereventhistory'  
when @entity='partner' then 'tbl_partnereventhistory'  
end  
  
select @sql=  
'insert into entityactivityqueue(entityname,entityid,historyid,eventdescription,eventtime)  
select '''+@entity+''','+  
case   
when @entity='lead' then 'leadid'  
when @entity='enquiry' then 'enquiryid'  
when @entity='user' then 'userid'  
when @entity='partner' then 'PartnerParentID' end  
+',historyid,eventdescription,eventdate from '+quotename(@tbl)+' with (nolock) where historyid= '+cast(@activityid as nvarchar)  
+' and eventdescription<>'''''  
--print @sql  
exec sp_executesql @sql  
  
end


GO

/* ============================================================
   Procedure: [dbo].[usp_insert_in_entityactivityqueue_multi]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   proc [dbo].[usp_insert_in_entityactivityqueue_multi]
@multiactivity as multiactivity readonly     
as
begin
declare @tbl nvarchar(100),@sql nvarchar(max),@count int,@activityid bigint=0,@entity nvarchar(50)
select top 1 @entity=context from @multiactivity
select @tbl=case 
when @entity='lead' then 'tbl_leadeventhistory'
when @entity='enquiry' then 'tbl_enquiryeventhistory'
when @entity='user' then 'tbl_usereventhistory'
when @entity='partner' then 'tbl_partnereventhistory'
end

select @count=count(1) from @multiactivity
drop table if exists #multipart
create table #multipart(context nvarchar(50),activityid bigint)

while @count>0
begin
insert into #multipart(context,activityid)
select top 500 Context,ActivityID from @multiactivity where ActivityID>@activityid order by activityid

select @sql=
'insert into entityactivityqueue(entityname,entityid,historyid,eventdescription,eventtime)
select '''+@entity+''','+
case 
when @entity='lead' then 'leadid'
when @entity='enquiry' then 'enquiryid'
when @entity='user' then 'userid'
when @entity='partner' then 'PartnerParentID' end
+',historyid,eventdescription,eventdate from '+quotename(@tbl)+' t with (nolock) join #multipart m on m.activityid=t.historyid where eventdescription<>'''''
print @sql
exec sp_executesql @sql
select @activityid=max(activityid) from #multipart
delete from #multipart
set @count=@count-500
end
end



GO

