SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_Insert_Int_smsprice_exc
(
@user_id bigint,
@tmptbl tbl_Intexcp READONLY 
)
AS
begin

update ex set ex.price= tp.Price from dbo.Int_sms_price_exc ex
inner join @tmptbl tp on tp.country_code = ex.country_code and tp.user_id = ex.user_id

Insert into dbo.Int_sms_price_exc (user_id, country_code, price)
select user_id, country_code, Cast(price as float) 
from @tmptbl where country_code not in (select country_code From Int_sms_price_exc where user_id=@user_id )

Select 'Saved'

end


