/* ============================================================
   Procedure: [dbo].[USP_INSERT_INTO_CLONE_FROM_APPMASTER]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROC [dbo].[USP_INSERT_INTO_CLONE_FROM_APPMASTER]      
as      
declare @batchid nvarchar(200),@M_ID bigint,@USERID nvarchar(25),@Total int,@HTP int,@Balance int,@Message nvarchar(2000),@IsUnicode int,@BroadMessageTime nvarchar(25)     
      
select top 1 @batchid=batchid,@USERID=[UserID] from [SMS19App_MessageMaster](nolock) where datediff(mi,MessageInsertTime,getdate())>1 order by id      
----select @Total=count([UserID]) from [SMS19App_MessageMaster](nolock) where datediff(mi,MessageInsertTime,getdate())>1 and batchid=@batchid      
----SELECT @HTP=count([UserID]) FROM [SMS19App_MessageMaster](nolock) where datediff(mi,MessageInsertTime,getdate())>1 and [UsersNumbers] not in(SELECT [Mobile] FROM [User_Detail](nolock)------where user_login not in(SELECT [username] FROM [chatapp].[dbo].[ofOffline])   
----)----and batchid=@batchid       
    
Select top 1 @Message=Message,@IsUnicode=IsUnicode,@BroadMessageTime=BroadMessageTime from [SMS19App_MessageMaster](nolock) 
where datediff(mi,MessageInsertTime,getdate())>1 and batchid=@batchid    
      
----select @Balance=@Total-@HTP    

select @Balance=count([UserID]) from [chatapp].[dbo].tblRoomChatParsing where UserId=@USERID 
and Messageid=@USERID+'_'+@BroadMessageTime
      
Insert into MySMS.dbo.CloneMessageDeliveryStatus([BatchID],[Mobile],[Message],[SenderID],[MessageInsertDate],[ScheduledDate],[ScheduledTime],[SmppID],[U_ID],[IsUniCode],[IsDnd],[IsAirtel],[IsPrority],[IsAllowDND],[DBType])      
SELECT BatchID,UsersNumbers,[Message],'TXTSMS',[ExpiryTime],[ExpiryTime],[ExpiryTime],1,[UserID],[IsUniCode],0,0,0,0,3 FROM [SMS19App_MessageMaster](nolock) where datediff(mi,MessageInsertTime,getdate())>1 --and [UsersNumbers] not in(SELECT [Mobile] FROM [User_Detail](nolock) 
--where user_login not in(SELECT [username] FROM [chatapp].[dbo].[ofOffline])
--)
and batchid=@batchid       
    
--delete [chatapp].[dbo].[ofOffline] where [username] in(select [UsersName] from [SMS19App_MessageMaster](nolock) where datediff(mi,MessageInsertTime,getdate())>1 and batchid=@batchid )    
    
delete [SMS19App_MessageMaster] where datediff(mi,MessageInsertTime,getdate())>1 and batchid=@batchid      
      
if(@USERID<>'')      
begin      
SELECT @M_ID=ISNULL(M_ID,10043) FROM MySMS.DBO.USER_DETAIL with (nolock) WHERE USER_ID=@USERID        
EXEC proc_RefundCreditDetail @M_ID,@USERID,@Message,@Balance,@IsUnicode    
end   
  
  


GO

/* ============================================================
   Procedure: [dbo].[usp_insert_into_local_credit3]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--alter table [Local_User_Detail] add parentid bigint  
  
CREATE   PROC [dbo].[usp_insert_into_local_credit3]                                        
as                    
begin            
/*changed credit_details_all to credit_details as the query wasn't running fast*/           
declare @c int,@user_id bigint=0        
select @c=count(1) from user_detail(nolock) where m_id=10043        
        
drop table if exists #userid        
create table #userid(user_id bigint)        
      
Truncate Table [Local_User_Detail]                                    
Truncate Table [Local_Credit_Details]                                        
        
while @c>0        
begin        
drop table if exists #Local_User_Detail        
drop table if exists #Local_credit_Details        
        
insert into #userid(user_id)        
select top 5000 user_id from user_detail  with (nolock) where user_id>@user_id and m_id=10043 order by user_id        
        
--select * from   #userid      
select                     
u.M_ID,                    
u.User_ID,                    
User_Login,                    
Pwd,                    
FName,                    
LName,                    
EMail,                    
Mobile,                    
City,                    
State,                    
Country,                    
Type,                    
Stype,                    
ACType,                    
Status,                    
Banner_ID,                    
Banner_IDR,                    
Banner_ID_Owner,                    
Banner_ID_Reseller,                    
Priority,                    
u.DateCreated,                    
u.DateUpdated,                    
u.EmpUpdated,                    
u.MachineName,                    
u.LastModified,                    
SmppID,                    
R_mode,                    
userfilter,                    
FilterMode,                    
ServiceTypeID,                    
ServiceType,                    
UserGroup,                    
Gender,                    
Pincode,                    
Address,                    
LoginType,                    
isnull(c.credits,0) as credits,                    
c.DateCreated as cDatecreated,                    
AVG(isnull(a.debits,0)) as Debits,                    
lastlogin1,[dbo].[fn_parent_getsubscriptionexpiry](u.user_id) as SubscriptionExpiry,u.ParentID                     
into #Local_User_Detail                     
from [User_Detail] u with(nolock)            
join #userid s on s.user_id=u.user_id        
--left join credit_details_all c(nolock) on u.user_id=c.user_id                       
left join credit_details c(nolock) on u.user_id=c.user_id                       
left join (SELECT totalconsumption AS debits,user_id FROM [MySMS].[dbo].MonthlyConsumption with (nolock)                     
where       
datediff(m,FirstDate,getdate())<=3 )a                     
on a.user_id=u.user_id                             
where                     
--u.m_id=10043                     
--and       
(credit_id is null or Credit_ID=(select MAX(Credit_ID) from [MySMS].[dbo].credit_details cd (nolock) where cd.User_ID=c.User_ID ))--and credits>0 and FromUser_ID=335)            
--and Credit_ID=(select MAX(Credit_ID) from [MySMS].[dbo].credit_details_all cd (nolock) where cd.User_ID=c.User_ID and credits>0 and FromUser_ID=335)            
group by u.M_ID,u.User_ID,User_Login,Pwd,FName,LName,EMail,Mobile,City,State,Country,Type,Stype,ACType,Status,Banner_ID,Banner_IDR,Banner_ID_Owner,Banner_ID_Reseller,Priority,u.DateCreated,u.DateUpdated,u.EmpUpdated,                    
u.MachineName,u.LastModified,SmppID,R_mode,userfilter,FilterMode,ServiceTypeID,ServiceType,UserGroup,Gender,Pincode,Address,LoginType,isnull(c.credits,0),c.DateCreated ,u.lastlogin1,u.parentid            
      
--select * from   #Local_User_Detail                     
                        
SELECT                     
[Credit_ID],                    
u.M_ID,                    
[FromUser_ID],                    
c.User_ID,                    
[Debits],                    
[Credits],                    
[Balance],                    
[Validity],                    
[Default_Credit],                    
[FromDate],                    
[ToDate],                    
c.DateCreated,                    
c.DateUpdated,                    
c.EmpUpdated,                    
c.MachineName,                    
c.LastModified,                    
c.typecredit                     
into #Local_Credit_Details                     
from [MySMS].[dbo].[Credit_Details] c with (nolock)                     
join [MySMS].[dbo].user_detail u on u.user_id=c.user_id            
join #userid s on s.user_id=u.user_id        
where       
--u.m_id=10043                     
--and       
Credit_ID =(select max(Credit_ID) from [Credit_Details] with(nolock) where User_ID=c.User_ID)                         
                        
if exists(select 1 from #Local_User_Detail) and exists(select 1 from #Local_Credit_Details)                        
begin                        
RETRY:                        
begin try                        
--begin transaction      
    
Insert Into [Local_User_Detail]([M_ID],[User_ID],[User_Login],[Pwd],[FName],[LName],[EMail],[Mobile],[City],[State],[Country],[Type],[Stype],[ACType],[Status],[Banner_ID],[Banner_IDR],[Banner_ID_Owner],[Banner_ID_Reseller],[Priority],                     
  
   
[DateCreated],[DateUpdated],[EmpUpdated],[MachineName],[LastModified],[SmppID],[R_mode],[userfilter],[FilterMode],[ServiceTypeID],[ServiceType],[UserGroup],[Gender],[Pincode],[Address],[LoginType],LastPurchasedCredits,LastPurchasedDate,                   
  
   
AverageLast3MonthConsumption,LastLogin1,SubscriptionExpiry,TotalEngagementTime,AverageEngagementTime,parentid)                                
 Select         
M_ID,User_ID,User_Login,Pwd,FName,LName,EMail,Mobile,City,State,Country,Type,Stype,ACType,Status,Banner_ID,Banner_IDR,Banner_ID_Owner,Banner_ID_Reseller,Priority,DateCreated,DateUpdated,EmpUpdated,MachineName,LastModified,SmppID,R_mode,userfilter,        
          
            
              
                
                  
                     
FilterMode,ServiceTypeID,ServiceType,UserGroup,Gender,Pincode,Address,LoginType,credits,cDateCreated,debits,lastlogin1,SubscriptionExpiry,dbo.fn_gettotalengagement(user_id,'I',cast(dateadd(d,-7,getdate()) as date),cast(dateadd(d,-1,getdate()) as date),'bo
th'),dbo.fn_getaverageengagement(user_id,'I',cast(dateadd(d,-7,getdate()) as date),cast(dateadd(d,-1,getdate()) as date),'both'),parentid  
from #Local_User_Detail                          
                                     
INsert into [Local_Credit_Details]([Credit_ID],[M_ID],[FromUser_ID],[User_ID],[Debits],[Credits],[Balance],[Validity],[Default_Credit],[FromDate],[ToDate],[DateCreated],[DateUpdated]                                        
,[EmpUpdated],[MachineName],[LastModified],[typecredit])                                        
 SELECT [Credit_ID],M_ID,[FromUser_ID],User_ID,[Debits],[Credits],[Balance],[Validity],[Default_Credit],[FromDate],[ToDate],DateCreated,DateUpdated,EmpUpdated,MachineName,LastModified,typecredit from #Local_Credit_Details                      
                     
COMMIT                                                              
END TRY                                                              
BEGIN CATCH                       
--IF @@TRANCOUNT>0                                                              
--ROLLBACK                                                              
EXECUTE USP_INSERTERRORINFO;                         
IF ERROR_NUMBER() = 1205 -- Deadlock Error Number                        
BEGIN                        
WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms                        
GOTO RETRY -- Go to Label RETRY                        
END                                                                   
END CATCH               
        
        
        
end      
--select @c,'Local_User_Detail',count(1) from Local_User_Detail(nolock)      
--select @c,'Local_credit_Details',count(1) from Local_credit_Details(nolock)      
select @user_id=max(user_id) from #userid        
truncate table #userid        
set @c=@c-5000        
end                    
end       


