   Procedure: [dbo].[usp_insert_intoThirtyDaysHistory]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_insert_intoThirtyDaysHistory    
as  
declare @r bigint=(select count(1) from [MySMSReport].[dbo].[SixDaysHistory1] )
declare @id bigint,@mid bigint=(select min(SixDaysHistory1ID) FROM [MySMSReport].[dbo].[SixDaysHistory1])
while @r>0
begin 
select @id=min(SixDaysHistory1ID) +1000 FROM [MySMSReport].[dbo].[SixDaysHistory1]
insert into [MySMS].[dbo].[ThirtyDaysHistory]([MessageID],[MessageRefID],[Mobile],[Message],[SenderID],[MessageStatus],[MessageInsertDate],    
[U_ID],[LastError],[BatchID],[IsDND],[Operator],[Isallowdnd],[Priority],[Dbtype])    
SELECT top 1000 [MessageID],[MessageRefID],[Mobile],[Message],[SenderID],[MessageStatus],[MessageInsertDate],[U_ID],[LastError],[BatchID],[IsDND],[Operator],    
[Isallowdnd],[Priority],[Dbtype] FROM [MySMSReport].[dbo].[SixDaysHistory1](nolock) where SixDaysHistory1ID between @mid and @id
set @r=@r-1000
set @id=@id+1000
set @mid=@mid+1000
end


