/* ============================================================
   Procedure: [dbo].[Usp_Insert_Lead_Details]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--------Modified By Abhishek Makkar ----------- Time: 8/18/2017 10:14:17 PM                  
--select * from UserLeads where ParentID = 335  
CREATE   PROCEDURE [dbo].[Usp_Insert_Lead_Details]                   
                  
(                  
    @ParentID               BIGINT,                  
    @PersonName             VARCHAR(100),                  
    @CompanyName            VARCHAR(100),                  
    @MobileNo               VARCHAR(100),                  
    @MobileNo1              VARCHAR(100),                  
    @MobileNo2              VARCHAR(100),                  
    @EmailID                VARCHAR(100),                  
    @EmailID1               VARCHAR(100),                  
    @EmailID2               VARCHAR(100),                  
    @City                   VARCHAR(100),                  
    @State                  VARCHAR(100),                  
    @Country                VARCHAR(100),                  
    @CountryCode            VARCHAR(50),                  
    @CountryCode1           VARCHAR(50),                  
    @CountryCode2           VARCHAR(50),                  
    @PinCode                BIGINT,                  
    @ResidentialAddress     VARCHAR(500),                  
    @SourceName             BIGINT,                  
    @MediumName             BIGINT,                  
    @CampaignName           BIGINT,                  
    @Remarks                VARCHAR(1000),                  
    @CreatedBy              BIGINT  ,            
                
    @AssignedTo BIGINT,            
    @FollowUpStatus  int,            
    @NextStatusDate varchar(50),            
    @Products varchar(1000),            
    @AmountPaid  numeric(18,2),             
    @FollowUpRemarks Varchar(1000)                
                    
)                  
AS                  
BEGIN                  
create table #temp(mobile varchar(100),email varchar(100))                
insert into #temp(mobile,email)              
select (cast(isnull(CountryCode,0) as nvarchar)+ cast(isnull(NULLIF(MobileNo,''),0) as nvarchar)),isnull(NULLIF(EmailID,''),0) from UserLeads where ParentID=@PARENTID                
union                 
select (cast(isnull(CountryCode1,0) as nvarchar)+ cast(isnull(NULLIF(MobileNo1,''),0) as nvarchar)),isnull(NULLIF(EmailID1,''),0) from UserLeads where ParentID=@PARENTID               
union                 
select (cast(isnull(CountryCode2,0) as nvarchar)+ cast(isnull(NULLIF(MobileNo2,''),0) as nvarchar)),isnull(NULLIF(EmailID2,''),0) from UserLeads where ParentID=@PARENTID                
              
if exists(select 1 from UserLeads where ParentID=@ParentID and (cast(isnull(@CountryCode,1) as nvarchar)+ cast(isnull(@MobileNo,1) as nvarchar) in (select Mobile from #temp)))                
BEGIN              
select 'Lead with Mobile ' + @mobileno + ' already exists' as [leadid]               
goto LeadNotInserted                
END              
if exists(select 1 from UserLeads where ParentID=@ParentID and (cast(isnull(@CountryCode1,1) as nvarchar)+ cast(isnull(@MobileNo1,1) as nvarchar) in (select Mobile from #temp)))               
BEGIN               
select 'Lead with Mobile ' + @mobileno1 + ' already exists' as [leadid]               
goto LeadNotInserted                 
END              
if exists(select 1 from UserLeads where ParentID=@ParentID and (cast(isnull(@CountryCode2,1) as nvarchar)+ cast(isnull(@MobileNo2,1) as nvarchar) in (select Mobile from #temp)))                
BEGIN              
select 'Lead with Mobile ' + @mobileno2 + ' already exists'  as [leadid]              
goto LeadNotInserted                
END              
if exists(select 1 from UserLeads where ParentID=@ParentID and (cast(isnull(NULLIF(@EmailID,''),1) as nvarchar) in (select email from #temp)))                
BEGIN              
select 'Lead with Email ' + @EmailID + ' already exists' as [leadid]               
goto LeadNotInserted                
END              
if exists(select 1 from UserLeads where ParentID=@ParentID and (cast(isnull(NULLIF(@EmailID1,''),1) as nvarchar) in (select email from #temp)))                
BEGIN              
select 'Lead with Email ' + @EmailID1 + ' already exists'   as [leadid]             
goto LeadNotInserted                 
END              
if exists(select 1 from UserLeads where ParentID=@ParentID and (cast(isnull(NULLIF(@EmailID2,''),1) as nvarchar) in (select email from #temp)))                
BEGIN              
select 'Lead with Email ' + @EmailID2 + ' already exists'   as [leadid]             
goto LeadNotInserted                
END               
                     
DECLARE @Leadno BIGINT = isnull((select MAX(LeadNo)                   
FROM   UserLeads                  
WHERE  ParentID = @ParentID),0)+1                    
                   
INSERT INTO UserLeads                  
   (                  
     ParentID,                  
     LeadNo,                  
     PersonName,                  
     CompanyName,                  
 MobileNo,                  
     MobileNo1,                  
     MobileNo2,                  
     EmailID,                  
     EmailID1,                  
     EmailID2,                  
     City,                  
     STATE,                  
     Country,                  
     CountryCode,                  
     CountryCode1,                  
     CountryCode2,                  
     PinCode,                  
     ResidentialAddress,                  
     SourceName,                  
     MediumName,                  
     CampaignName,                  
 InitialRemarks,                  
     CreatedOn,                  
     CreatedBy,                
                 
     AssignedTo,                
     FollowUpStatus,                
     NextStatusDate,            
     Products ,            
     AmountPaid  ,                 
     Remarks             
   )                  
 VALUES                  
   (                  
     @ParentID,                  
     @LeadNo,                  
     @PersonName,                  
     @CompanyName,                  
     @MobileNo,                  
     @MobileNo1,                  
     @MobileNo2,                  
     @EmailID,                  
     @EmailID1,                  
     @EmailID2,                  
     @City,                  
     @State,                  
     @Country,                  
     @CountryCode,                  
     @CountryCode1,                  
     @CountryCode2,                  
     @PinCode,                  
     @ResidentialAddress,                  
     @SourceName,                  
     @MediumName,                  
     @CampaignName,                  
     @Remarks,                  
     GETDATE(),                  
     @CreatedBy,            
                 
     @AssignedTo,                
     @FollowUpStatus,                
     @NextStatusDate,            
     @Products ,            
     @AmountPaid  ,                 
     @FollowUpRemarks                 
                 
     --@CreatedBy,                
     -- 1,                
     -- cast(DATEPART(yyyy,getdate()) as nvarchar) +'-'+ RIGHT('00' + cast(DATEPART(dd,getdate()) as nvarchar(2)),2) +'-'+ RIGHT('00' + cast(DATEPART(MM,getdate()) as nvarchar(2)),2),                
     -- 'Lead Created'                 
   )                   
                   
                   
     --  AssignedTo,                
     --FollowUpStatus,                
     --NextStatusDate,            
     --Products ,            
     --AmountPaid  ,                 
     --Remarks             
                   
   insert into LeadInteractionHistory([LeadNo]                
      ,[FollowUpStatus]                
      ,[NextStatusDate]                
      ,[Remarks]            
      ,[Products]                
      ,AmountPaid                
      ,[AssignedTo]                
      ,[ParentID]                
      ,[CreatedOn]                
      ,[CreatedBy])                
   select @LeadNo                
      ,@FollowUpStatus             
      ,@NextStatusDate            
 ,@FollowUpRemarks            
      ,@Products            
      ,@AmountPaid            
      ,@AssignedTo            
                     
      --,cast(DATEPART(yyyy,getdate()) as nvarchar) +'-'+ RIGHT('00' + cast(DATEPART(dd,getdate()) as nvarchar(2)),2) +'-'+ RIGHT('00' + cast(DATEPART(MM,getdate()) as nvarchar(2)),2)                
      --,'Lead Created'                
      --,0                
      --,@createdby                
      ,@ParentID                
      ,GETDATE()                
      ,@CreatedBy                       
                   
 SELECT @LeadNo leadid,'Record Inserted'  msg             
           
 LeadNotInserted:         
 --SELECT SCOPE_IDENTITY() AS [leadid];                   
END 


