if exists(select 1 from Userleads_Mobile_Email(nolock) where ParentID=@ParentID and (cast(isnull(@CountryCode1,1) as nvarchar)+ cast(isnull(@MobileNo1,1) as nvarchar) =cast(isnull(CountryCode,1) as nvarchar)+ cast(isnull(Mobile,1) as nvarchar)))          
  
    
                     
BEGIN                           
