if exists(select 1 from Userleads_Mobile_Email(nolock) where ParentID=@ParentID and (cast(isnull(@CountryCode2,1) as nvarchar)+ cast(isnull(@MobileNo2,1) as nvarchar)=cast(isnull(CountryCode,2) as nvarchar)+ cast(isnull(Mobile,2) as nvarchar)))           
  
    
                    
