if exists(select 1 from  Userleads_Mobile_Email(nolock) where ParentID=@ParentID and (cast(isnull(NULLIF(@EmailID2,''),2) as nvarchar)=isnull(NULLIF(Email,''),3)) )                                                                                
BEGIN                                          
