 OfficeAddress,                                         
     SourceName,                                              
     MediumName,                                              
     CampaignName,                                              
     InitialRemarks,                                              
     CreatedOn,                                              
CreatedBy,                                            
                                             
     AssignedTo,                                            
     FollowUpStatus,                                            
     NextStatusDate,                          
     Products ,                                        
     AmountPaid  ,                                             
     Remarks,                            
     FollowupDate,      
  enquirysource                                         
   )                                              
VALUES                                              
   (                                              
     @ParentID,                                              
     @LeadNo,                                              
     @PersonName,                                              
     @CompanyName,                                              
     @MobileNo,                                              
     @MobileNo1,                                              
     @MobileNo2,                       
     @EmailID,                                              
     @EmailID1,                                              
     @EmailID2,                                  
     @City,                                              
     @State,                                              
     @Country,                                              
     @CountryCode,                                              
     @CountryCode1,                                              
     @CountryCode2,                                              
     @PinCode,                                              
     @ResidentialAddress,                
 @OfficialAddress,                                            
     @SourceName,                                              
     @MediumName,                                              
     @CampaignName,                                              
     @Remarks,                                              
     GETDATE(),                                              
     @CreatedBy,                                        
     @AssignedTo,                                            
