CREATE   PROCEDURE [dbo].[Usp_Insert_Lead_Details_ChangeWithFollowupDate2_BlankCheck]
(                                                              
 @ParentID BIGINT,        
 @PersonName NVARCHAR(200),        
 @CompanyName NVARCHAR(500),        
 @MobileNo VARCHAR(100),        
 @MobileNo1 VARCHAR(100),        
 @MobileNo2 VARCHAR(100),        
 @EmailID VARCHAR(100),        
 @EmailID1 VARCHAR(100),        
 @EmailID2 VARCHAR(100),        
 @City VARCHAR(100),        
 @State VARCHAR(100),        
 @Country VARCHAR(100),        
 @CountryCode VARCHAR(50),        
 @CountryCode1 VARCHAR(50),        
 @CountryCode2 VARCHAR(50),        
 @PinCode BIGINT,        
 @ResidentialAddress NVARCHAR(500),        
 @OfficialAddress NVARCHAR(500),        
 @SourceName BIGINT,        
 @MediumName BIGINT,        
 @CampaignName BIGINT,        
 @Remarks NVARCHAR(1000),        
 @CreatedBy BIGINT ,        
 @AssignedTo BIGINT,        
 @FollowUpStatus int,        
 @NextStatusDate varchar(50),        
 @Products varchar(1000),        
 @AmountPaid numeric(18,2),        
 @FollowUpRemarks nVarchar(1000),        
 @custom customleads3 readonly        
)                                                              
AS                                                              
BEGIN                                
               
    set @MobileNo = rtrim(ltrim(@MobileNo))                 
    set @MobileNo1 = rtrim(ltrim(@MobileNo1))        
	set @MobileNo2 = rtrim(ltrim(@MobileNo2))        
	set @EmailID = rtrim(ltrim(@EmailID))
	set @EmailID1 = rtrim(ltrim(@EmailID1))
	set @EmailID2 = rtrim(ltrim(@EmailID2))
        
 --declare @ParentID BIGINT=40204,        
 --@PersonName VARCHAR(100)='rishabh',        
 --@CompanyName VARCHAR(100)='',        
 --@MobileNo VARCHAR(100)='7303590417',        
 --@MobileNo1 VARCHAR(100)='',        
 --@MobileNo2 VARCHAR(100)='',        
 --@EmailID VARCHAR(100)='test2@gmail.com',        
 --@EmailID1 VARCHAR(100)='',        
 --@EmailID2 VARCHAR(100)='',        
 --@City VARCHAR(100)='',        
 --@State VARCHAR(100)='',        
 --@Country VARCHAR(100)='',        
 --@CountryCode VARCHAR(50)='+91',        
 --@CountryCode1 VARCHAR(50)='',        
 --@CountryCode2 VARCHAR(50)='',        
 --@PinCode BIGINT=0,        
 --@ResidentialAddress VARCHAR(500)='',        
 --@OfficialAddress VARCHAR(500)='',        
 --@SourceName BIGINT=550343,        
 --@MediumName BIGINT=391239,        
 --@CampaignName BIGINT=0,        
 --@Remarks VARCHAR(1000)='helloooo',        
 --@CreatedBy BIGINT =40204,        
 --@AssignedTo BIGINT=40240,        
 --@FollowUpStatus int=413,        
 --@NextStatusDate varchar(50)='05-30-2022 19:35:43',        
 --@Products varchar(1000)='',        
 --@AmountPaid numeric(18,2)=0,        
 --@FollowUpRemarks Varchar(1000)='Lead created'        
 --declare @custom customleads1         
 --insert into @custom values(NULL,NULL,N'1997',N'0')        
 --insert into @custom values(NULL,NULL,N'2065',N'0')        
        
    declare @DupMobile varchar(300)
	declare @DupEmail varchar(300)
	declare @DupMsg varchar(1000)
        
	declare @newlead BIGINT
	declare @FollowupDate Datetime = null
	
	if(@NextStatusDate <> '')
	Begin
		set @FollowupDate = @NextStatusDate
	End
                                
  if(@MobileNo = '' and @MobileNo1 = '' and @MobileNo2 = '' and @EmailID = '' and @EmailID1 = '' and @EmailID2 = '' )                   
  Begin                  
   select 'Mobile and Email are blank' as [leadid]                  
   goto LeadNotInserted                  
  End                  
 
