 ;WITH cte_Mobile (MobileNo)  
 AS  
 (  
 SELECT isnull(@MobileNo,'')  
 UNION ALL  
 SELECT isnull(@MobileNo1,'')  
 UNION ALL  
 SELECT isnull(@MobileNo2,'')  
 )  
 
 SELECT @DupMobile = STRING_AGG(MobileNo,',')  
 FROM  
 (  
  SELECT UL.MobileNo           
  FROM Userleads UL WITH(NOLOCK)    
  WHERE UL.Parentid = @ParentID AND EXISTS (SELECT 1 FROM cte_Mobile m WHERE m.MobileNo <> '' AND m.MobileNo = UL.MobileNo) 
  UNION ALL  
  SELECT UL.MobileNo1           
  FROM Userleads UL WITH(NOLOCK)    
  WHERE UL.Parentid = @ParentID AND EXISTS (SELECT 1 FROM cte_Mobile m WHERE m.MobileNo <> '' AND m.MobileNo = UL.MobileNo1)
  UNION ALL  
  SELECT UL.MobileNo2           
  FROM Userleads UL WITH(NOLOCK)    
  WHERE UL.Parentid = @ParentID AND EXISTS (SELECT 1 FROM cte_Mobile m WHERE m.MobileNo <> '' AND m.MobileNo = UL.MobileNo2)
 ) AS t  
  
 ;WITH cte_Email (Email)  
 AS  
 (  
 SELECT isnull(@EmailID,'')  
 UNION ALL  
 SELECT isnull(@EmailID1,'')  
 UNION ALL  
 SELECT isnull(@EmailID2,'')  
 )  

 SELECT @DupEmail = STRING_AGG(EmailID,',')  
 FROM  
 (  
  SELECT UL.EmailID           
  FROM Userleads UL WITH(NOLOCK)    
  WHERE UL.Parentid = @ParentID AND EXISTS (SELECT 1 FROM cte_Email e WHERE e.Email <> '' AND e.Email = UL.EmailID) 
  UNION ALL  
  SELECT UL.EmailID1           
  FROM Userleads UL WITH(NOLOCK)    
  WHERE UL.Parentid = @ParentID AND EXISTS (SELECT 1 FROM cte_Email e WHERE e.Email <> '' AND e.Email = UL.EmailID1) 
  UNION ALL  
  SELECT UL.EmailID2           
  FROM Userleads UL WITH(NOLOCK)    
  WHERE UL.Parentid = @ParentID AND EXISTS (SELECT 1 FROM cte_Email e WHERE e.Email <> '' AND e.Email = UL.EmailID2) 
 ) AS t  
            
   IF len(@DupMobile) > 0         
   BEGIN            
		select @DupMsg=concat('Lead with Mobile already exists ', @DupMobile)
   END            
            
   IF len(@DupEmail) > 0                   
   BEGIN            
		select @DupMsg=concat(' Lead with Email already exists ', @DupEmail)
   END

   If len(@DupMsg) > 0
   Begin
		Select @DupMsg as [leadid]
		goto LeadNotInserted                  
   End

    Begin Transaction
	
		DECLARE @Leadno BIGINT = isnull((select MAX(LeadNo)
		FROM   UserLeads with (updlock,holdlock)
		WHERE  ParentID = @ParentID),0)+1
        
		SET Context_Info 0x55555
        
		INSERT INTO UserLeads
	   (                                                              
		 ParentID,                           
		 LeadNo,                                                              
		 PersonName,                                                              
		 CompanyName,                                                    
		 MobileNo,                                                              
	   MobileNo1,                                                              
		 MobileNo2,                                                              
		 EmailID,                                                              
		 EmailID1,                                                              
		 EmailID2,                                                              
		 City,                                                              
		 STATE,                                                              
		 Country,                                                              
		 CountryCode,                                                              
		 CountryCode1,                                                              
		 CountryCode2,                                             
		 PinCode,                                                              
		 ResidentialAddress,                                   
	  OfficeAddress,                                           
		 SourceName,                                                              
		 MediumName,                                                              
		 CampaignName,                                                              
		 InitialRemarks,                                                             
		 CreatedOn,                                                              
		 CreatedBy,                                                            
                                                             
		 AssignedTo,                                                            
		 FollowUpStatus,                                                            
		 NextStatusDate,                                         
		 Products ,                                                        
		 AmountPaid  ,                                                             
		 Remarks,                                            
		 FollowupDate,                              
	  enquirysource,        
	  LastFollowupCreatedBy,        
	  LastFollowupCreatedOn                    
	   )                                                              
	VALUES                                                              
	   (                                                              
		 @ParentID,                                                              
		 @LeadNo,                                                              
		 @PersonName,                                                              
		 @CompanyName,                                                              
		 @MobileNo,                                                              
		 @MobileNo1,                                                              
		 @MobileNo2,                                       
		 @EmailID,                                                              
		 @EmailID1,                                                              
		 @EmailID2,                                                  
		 @City,                   
		 @State,                                                              
		 @Country,                                                              
		 @CountryCode,                                                              
		 @CountryCode1,                                                              
		 @CountryCode2,                                                              
		 @PinCode,                                                              
		 @ResidentialAddress,                                
	  @OfficialAddress,                                                            
		 @SourceName,                                                              
		 @MediumName,                                                              
		 @CampaignName,                                                      
		 @Remarks,                  
		 GETDATE(),                       
		 @CreatedBy,                           
                      
		 @AssignedTo,                                                            
		 @FollowUpStatus,                                                            
		 @NextStatusDate,                                                        
		 @Products ,                                   
		 @AmountPaid  ,                                                             
		@FollowUpRemarks,                                            
		 @FollowupDate,                                                             
		 17 -- Enquiry API Kit19                                                        
		 --@CreatedBy,                                                            
		 -- 1,                                                            
		 -- cast(DATEPART(yyyy,getdate()) as nvarchar) +'-'+ RIGHT('00' + cast(DATEPART(dd,getdate()) as nvarchar(2)),2) +'-'+ RIGHT('00' + cast(DATEPART(MM,getdate()) as nvarchar(2)),2),                                                            
		 -- 'Lead Created'         
	  ,@CreatedBy        
	  ,getdate()                                                            
	   )
		set @newlead=SCOPE_IDENTITY();

	Commit

 Exec usp_ExecLeadTriggerTasks @newlead        
        
 declare @CreatedOn datetime = getdate()        
        
   insert into LeadInteractionHistory(LeadNo, FollowUpStatus, NextStatusDate, Remarks, Products, AmountPaid, AssignedTo, ParentID, CreatedOn, CreatedBy, FollowupDate, IsReassign,id_lead)          
  select LeadNo, FollowUpStatus, NextStatusDate, InitialRemarks, Products, AmountPaid, AssignedTo, ParentID, @CreatedOn, CreatedBy, FollowupDate, 0,id from userleads(nolock) where id=@newlead          
                                                    
 update t  set LastFollowupCreatedBy = CreatedBy, LastFollowupCreatedOn = @CreatedOn from userleads as t        
  where id=@newlead and FollowUpStatus <> 6                     
                   
                              
 SET Context_Info 0x        
        
 Begin try                           
                       
 Declare @UserID_LDACTV bigint = @CreatedBy                          
 Declare @ParentID_LDACTV bigint = @ParentID                          
                          
 Declare @LeadID_LDACTV bigint = @newlead                          
                          
  create table #tblEventDescrb                          
   (                          
     EVNT_Description nvarchar(max)                           
   )                          
                          
  if( isnull(@LeadID_LDACTV,0) > 0)                          
   Begin                          
                              
   insert into #tblEventDescrb                          
      exec  Usp_EventTemplate_DynamicVarReplacement 'Lead added',@UserID_LDACTV,'','',@LeadID_LDACTV,'',null                          
   ,0,0,'','',0,'',0,null,null,null,null,null,null,null,null,null                          
   ,null,null,null,null,null,null,null,null,                          
   0,0,0,null,null,null,0,null,null,null,0,null,null                          
                               
   declare @evntMessage nvarchar(max) = ''                           
   select @evntMessage = isnull( EVNT_Description,'') from #tblEventDescrb                          
                           
   if(@evntMessage <> '')                          
   Begin                          
	exec UspSaveLeadActivity_withid @LeadID_LDACTV,@UserID_LDACTV,@ParentID_LDACTV,@evntMessage,'Lead added','UserLeads',@newlead                          
   end                          
                          
                          
   End                            
                          
   End try                          
   Begin catch                          
     exec usp_insertErrorInfo                          
   SET Context_Info 0x        
   End Catch                          
                          
    IF OBJECT_ID('tempdb..#tblEventDescrb') IS NOT NULL -- Check for table existence    
   Begin               
        DROP TABLE #tblEventDescrb                            
   End                            
                            
/* End Lead activity Lead added  */                          
                          
                          
                          
                          
                                         
      declare @insertcount smallint                                        
      select @insertcount=isnull(COUNT(fieldID), 0) from @custom                                         
      if(@insertcount >0)                                        
      begin                        
		select * into #temp29 from @custom;                                          
        update #temp29 set LeadID=@newlead;                                          
                                                  
        insert into customfieldLeadvalue (LeadID,EnquiryID,fieldID,fieldvalue) select * from #temp29;                                                                
        drop table #temp29                                                         
      end                                     
      
	  SELECT @LeadNo leadid,'Record Inserted'  msg, @newlead mylead ;

 LeadNotInserted:                                                     
 --SELECT SCOPE_IDENTITY() AS [leadid];                                                               
END 



