   Procedure: [dbo].[Usp_Insert_Lead_Details_ChangeWithFollowupDate2_Replication]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_Insert_Lead_Details_ChangeWithFollowupDate2_Replication] (              
 @ParentID BIGINT              
 ,@PersonName NVARCHAR(200)              
 ,@CompanyName NVARCHAR(500)              
 ,@MobileNo VARCHAR(100)              
 ,@MobileNo1 VARCHAR(100)              
 ,@MobileNo2 VARCHAR(100)              
 ,@EmailID VARCHAR(100)              
 ,@EmailID1 VARCHAR(100)              
 ,@EmailID2 VARCHAR(100)              
 ,@City VARCHAR(100)              
 ,@State VARCHAR(100)              
 ,@Country VARCHAR(100)              
 ,@CountryCode VARCHAR(50)              
 ,@CountryCode1 VARCHAR(50)              
 ,@CountryCode2 VARCHAR(50)              
 ,@PinCode BIGINT              
 ,@ResidentialAddress NVARCHAR(500)              
 ,@OfficialAddress NVARCHAR(500)              
 ,@SourceName BIGINT              
 ,@MediumName BIGINT              
 ,@CampaignName BIGINT              
 ,@Remarks NVARCHAR(2000)              
 ,@CreatedBy BIGINT              
 ,@AssignedTo BIGINT              
 ,@FollowUpStatus INT              
 ,@NextStatusDate VARCHAR(50)              
 ,@Products VARCHAR(1000)              
 ,@AmountPaid NUMERIC(18, 2)              
 ,@FollowUpRemarks NVARCHAR(2000)              
 ,@WhereAddress NVARCHAR(255) = ''              
 ,@WhereLatitude NVARCHAR(255) = ''              
 ,@WhereLongitude NVARCHAR(255) = ''              
 ,@LeadTags NVARCHAR(MAX) = NULL              
 ,@IsReassign INT              
 ,@custom CUSTOMLEADS3 READONLY              
 )              
AS              
BEGIN        
    
    -- declare @products nvarchar(max) = '343#455#222'    
      
  DECLARE @productsJson NVARCHAR(MAX) = (              
    select value as ProductName        
       from fn_split(isnull(@products,''),'#')        
   FOR JSON AUTO              
  ,INCLUDE_NULL_VALUES              
    )      
    
    
    
 SET @MobileNo = rtrim(ltrim(@MobileNo))              
 SET @MobileNo1 = rtrim(ltrim(@MobileNo1))              
 SET @MobileNo2 = rtrim(ltrim(@MobileNo2))              
              
 DECLARE @newlead BIGINT;              
 DECLARE @FollowupDate DATETIME = NULL;              
              
 IF (@NextStatusDate <> '')              
 BEGIN              
  SET @FollowupDate = @NextStatusDate;              
  SET @FollowupDate = [dbo].[fn_getISTtimefromusertime](@CreatedBy, @FollowupDate)              
              
  SELECT @NextStatusDate = CONVERT(NVARCHAR(50), @FollowupDate)              
 END;              
              
 DROP TABLE              
              
 IF EXISTS #temp              
  CREATE TABLE #temp (              
   [mobile] VARCHAR(100)              
   ,[email] VARCHAR(100)              
   );              
              
 BEGIN TRY              
  PRINT '---- SP Called: Usp_Insert_Lead_Details_ChangeWithFollowupDate2 on ' + Convert(VARCHAR, GetDate(), 13) + ' ----'              
              
  INSERT INTO #temp (              
   [mobile]              
   ,[email]              
   )              
  SELECT (CAST(ISNULL(NULLIF([CountryCode], ''), 0) AS NVARCHAR) + CAST(ISNULL(NULLIF([MobileNo], ''), 0) AS NVARCHAR))              
   ,ISNULL(NULLIF([EmailID], ''), 0)              
  FROM UserLeads(NOLOCK)              
  WHERE [ParentID] = @PARENTID              
                
  UNION              
                
  SELECT (CAST(ISNULL(NULLIF([CountryCode1], ''), 0) AS NVARCHAR) + CAST(ISNULL(NULLIF([MobileNo1], ''), 0) AS NVARCHAR))              
   ,ISNULL(NULLIF([EmailID1], ''), 0)              
  FROM UserLeads(NOLOCK)              
  WHERE [ParentID] = @PARENTID              
                
  UNION              
                
  SELECT (CAST(ISNULL(NULLIF([CountryCode2], ''), 0) AS NVARCHAR) + CAST(ISNULL(NULLIF([MobileNo2], ''), 0) AS NVARCHAR))              
   ,ISNULL(NULLIF([EmailID2], ''), 0)              
  FROM UserLeads(NOLOCK)              
  WHERE [ParentID] = @PARENTID;              
              
  IF EXISTS (              
    SELECT 1              
    FROM [#temp]              
    WHERE (CAST(ISNULL(NULLIF(@CountryCode, ''), 1) AS NVARCHAR) + CAST(ISNULL(NULLIF(@MobileNo, ''), 1) AS NVARCHAR) = [Mobile])              
    )              
  BEGIN              
   SELECT 'Lead with Mobile ' + @mobileno + ' already exists' AS [leadid];              
              
   GOTO LeadNotInserted;              
  END;              
              
  IF EXISTS (              
    SELECT 1              
    FROM [#temp]              
    WHERE (CAST(ISNULL(NULLIF(@CountryCode1, ''), 1) AS NVARCHAR) + CAST(ISNULL(NULLIF(@MobileNo1, ''), 1) AS NVARCHAR) = [Mobile])              
    )              
  BEGIN              
   SELECT 'Lead with Mobile ' + @mobileno1 + ' already exists' AS [leadid];              
              
   GOTO LeadNotInserted;              
  END;              
              
  IF EXISTS (              
    SELECT 1              
    FROM [#temp]              
    WHERE (CAST(ISNULL(NULLIF(@CountryCode2, ''), 1) AS NVARCHAR) + CAST(ISNULL(NULLIF(@MobileNo2, ''), 1) AS NVARCHAR) = [Mobile])              
    )              
  BEGIN              
   SELECT 'Lead with Mobile ' + @mobileno2 + ' already exists' AS [leadid];              
              
   GOTO LeadNotInserted;              
  END;              
              
  IF EXISTS (              
    SELECT 1              
    FROM [#temp]              
    WHERE (CAST(ISNULL(NULLIF(@EmailID, ''), 1) AS NVARCHAR) = [email])              
    )              
  BEGIN              
   SELECT 'Lead with Email ' + @EmailID + ' already exists' AS [leadid];              
              
   GOTO LeadNotInserted;              
  END;              
              
  IF EXISTS (              
    SELECT 1              
    FROM [#temp]              
    WHERE (CAST(ISNULL(NULLIF(@EmailID1, ''), 1) AS NVARCHAR) = [email])              
    )              
  BEGIN              
   SELECT 'Lead with Email ' + @EmailID1 + ' already exists' AS [leadid];              
              
   GOTO LeadNotInserted;              
  END;              
              
  IF EXISTS (              
    SELECT 1              
    FROM [#temp]              
    WHERE (CAST(ISNULL(NULLIF(@EmailID2, ''), 1) AS NVARCHAR) = [email])              
    )              
  BEGIN              
   SELECT 'Lead with Email ' + @EmailID2 + ' already exists' AS [leadid];              
              
   GOTO LeadNotInserted;              
  END;              
              
  DECLARE @Leadno BIGINT = ISNULL((              
     SELECT MAX([LeadNo])              
     FROM UserLeads(NOLOCK)              
     WHERE [ParentID] = @ParentID              
     ), 0) + 1;              
  DECLARE @latitude FLOAT = NULL;              
              
  IF (ISNULL(@WhereLatitude, '') <> '')              
  BEGIN              
   SET @latitude = CAST(@WhereLatitude AS FLOAT);              
  END;              
              
  DECLARE @longitude FLOAT = NULL;              
              
  IF (ISNULL(@WhereLatitude, '') <> '')              
  BEGIN              
   SET @longitude = CAST(@WhereLongitude AS FLOAT);              
  END;              
              
  PRINT 'lead inserted'              
  
  set context_info 0x55555
  INSERT INTO UserLeads (              
   ParentID              
   ,LeadNo              
   ,PersonName              
   ,CompanyName              
   ,MobileNo              
   ,MobileNo1              
   ,MobileNo2              
   ,EmailID              
   ,EmailID1              
   ,EmailID2              
   ,City              
   ,STATE              
   ,Country              
   ,CountryCode              
   ,CountryCode1              
   ,CountryCode2              
   ,PinCode              
   ,ResidentialAddress              
   ,OfficeAddress              
   ,SourceName              
   ,MediumName              
   ,CampaignName              
   ,InitialRemarks              
   ,CreatedOn              
   ,CreatedBy              
   ,AssignedTo              
   ,FollowUpStatus              
   ,NextStatusDate              
   --,Products              
   ,ProductsJson    
   ,AmountPaid              
   ,Remarks              
   ,FollowupDate      
   ,enquirysource              
   ,whereAddress              
   ,latitude              
   ,longitude              
   )              
  VALUES (              
   @ParentID              
   ,@LeadNo              
   ,@PersonName              
   ,@CompanyName              
   ,NULLIF(@MobileNo, '0')  
   ,NULLIF(@MobileNo1, '0')              
   ,NULLIF(@MobileNo2, '0')              
   ,IIF(ISNUMERIC(@EmailID) = 1, NULL, @EmailID)              
   ,IIF(ISNUMERIC(@EmailID1) = 1, NULL, @EmailID1)              
   ,IIF(ISNUMERIC(@EmailID2) = 1, NULL, @EmailID2)              
   ,@City              
   ,@State              
   ,@Country              
   ,@CountryCode              
   ,@CountryCode1              
   ,@CountryCode2              
   ,@PinCode              
   ,@ResidentialAddress              
   ,@OfficialAddress              
   ,@SourceName              
   ,@MediumName              
   ,@CampaignName              
   ,@Remarks              
   ,GETDATE()              
   ,@CreatedBy              
   ,@AssignedTo              
   ,@FollowUpStatus              
   ,@NextStatusDate              
   --,@Products              
   ,@productsJson    
   ,@AmountPaid              
   ,@FollowUpRemarks              
   ,@FollowupDate              
   ,12              
   ,-- Manual Desktop Kit19                                                          
   @WhereAddress              
   ,@latitude              
   ,@longitude              
   );              
              
  SET @newlead = SCOPE_IDENTITY();              
  set context_info 0x00000



  declare @lih_id bigint
  set context_info 0x55555

            -- SET Context_Info 0x55555   
  INSERT INTO LeadInteractionHistory (              
   [LeadNo]              
   ,[FollowUpStatus]              
   ,[NextStatusDate]              
   ,[Remarks]              
   --,[Products]              
   ,[ProductsJson]    
   ,[AmountPaid]              
   ,[AssignedTo]              
   ,[IsReassign]              
   ,[ParentID]              
   ,[CreatedOn]              
   ,[CreatedBy]              
   ,[FollowupDate],id_lead              
   )              
  SELECT @LeadNo              
   ,@FollowUpStatus              
   ,@NextStatusDate              
   ,@FollowUpRemarks              
   --,@Products              
   ,@productsJson    
   ,@AmountPaid              
   ,@AssignedTo              
   ,@IsReassign              
   ,@ParentID              
   ,GETDATE()              
   ,@CreatedBy              
   ,@FollowupDate,@newlead;              
   select @lih_id=SCOPE_IDENTITY()
  set context_info 0x00000
   
   exec [dbo].[usp_ExecLeadInteractionTriggerTasks] @lih_id
  /* Start Lead activity Lead added  */              
  IF (ISNULL(@LeadTags, '') <> '')              
  BEGIN              
   DROP TABLE              
              
   IF EXISTS #tempTagName;              
    SELECT [tn].*              
     ,[tm].[ID] AS [tagId]              
     ,0 AS [isProcess]              
    INTO [#tempTagName]              
    FROM (              
     SELECT [position] AS [id]              
      ,LTRIM(RTRIM(IIF(CHARINDEX(':', [value], 1) = 0, [value], SUBSTRING([value], 1, CHARINDEX(':', [value], 1) - 1)))) AS [tagName]              
     FROM fn_Split(@LeadTags, ',')              
     ) AS tn              
    LEFT JOIN TagMaster(NOLOCK) AS tm ON tm.ParentID = @ParentID              
     AND LOWER(tm.Tag) = LOWER(tagName);              
              
   WHILE (              
     EXISTS (              
      SELECT *              
      FROM #tempTagName              
      WHERE [isProcess] = 0              
      )              
     )              
   BEGIN              
    DECLARE @tId INT              
     ,@tTagName NVARCHAR(255)              
     ,@tagId BIGINT;              
              
    SELECT TOP 1 @tId = [id]              
     ,@tTagName = [tagName]              
     ,@tagId = [tagId]              
   FROM #tempTagName              
    WHERE [isProcess] = 0;              
              
    PRINT @tTagName;              
              
    IF (@tagId IS NULL)              
    BEGIN              
     INSERT INTO TagMaster (              
      [Tag]              
      ,[ParentID]              
      ,[CreatedDate]              
      ,[CreatedBy]              
      )              
     VALUES (              
      @tTagName              
      ,@ParentID              
      ,GETDATE()              
      ,@CreatedBy              
      );              
              
     DECLARE @sId BIGINT = SCOPE_IDENTITY();              
              
     UPDATE #tempTagName              
     SET [tagId] = @sId              
     WHERE [id] = @tId;              
    END;              
              
    UPDATE #tempTagName              
    SET [isProcess] = 1              
    WHERE [id] = @tId;              
   END;              
              
   DELETE EntityTagMapping              
   WHERE [EntityID] = @newlead              
    AND LOWER([Entity]) = 'lead';              
              
   INSERT INTO EntityTagMapping (              
    [EntityID]       
    ,[Entity]              
    ,[TagID]              
    ,[CreatedDate]              
    )              
   SELECT @newlead              
    ,'lead'              
    ,[tagId]              
    ,GETDATE()              
   FROM #tempTagName;              
  END;              
              
  DECLARE @UserID_LDACTV BIGINT = @CreatedBy;              
  DECLARE @ParentID_LDACTV BIGINT = @ParentID;              
  DECLARE @LeadID_LDACTV BIGINT = @newlead;              
              
  CREATE TABLE #tblEventDescrb ([EVNT_Description] NVARCHAR(MAX));              
              
  IF (ISNULL(@LeadID_LDACTV, 0) > 0)              
  BEGIN              
   INSERT INTO #tblEventDescrb              
   EXEC Usp_EventTemplate_DynamicVarReplacement 'Lead added'              
    ,@UserID_LDACTV              
    ,''              
    ,''              
    ,@LeadID_LDACTV              
    ,''              
    ,NULL              
    ,0              
    ,0              
    ,''              
    ,''              
    ,0              
    ,''              
    ,0              
    ,NULL              
    ,NULL              
    ,NULL              
    ,NULL              
    ,NULL              
    ,NULL              
    ,NULL              
    ,NULL              
    ,NULL              ,NULL              
    ,NULL              
    ,NULL              
    ,NULL              
    ,NULL              
    ,NULL              
    ,NULL              
    ,NULL              
    ,0              
    ,0              
    ,0              
    ,NULL              
    ,NULL              
    ,NULL              
    ,0              
    ,NULL              
    ,NULL              
    ,NULL              
    ,0              
    ,NULL              
    ,NULL;              
              
   DECLARE @evntMessage NVARCHAR(MAX) = '';              
              
   SELECT @evntMessage = ISNULL([EVNT_Description], '')              
   FROM #tblEventDescrb;              
              
   IF (@evntMessage <> '')              
   BEGIN              
    EXEC UspSaveLeadActivity_withid @LeadID_LDACTV              
     ,@UserID_LDACTV              
     ,@ParentID_LDACTV              
     ,@evntMessage              
     ,'Lead added'              
     ,'UserLeads'              
     ,@newlead;              
   END;              
  END;              
              
  IF OBJECT_ID('tempdb..#tblEventDescrb') IS NOT NULL -- Check for table existence                              
  BEGIN              
   DROP TABLE #tblEventDescrb;              
  END;              
              
  /* End Lead activity Lead added  */              
  DECLARE @insertcount SMALLINT;              
              
  SELECT @insertcount = ISNULL(COUNT([fieldID]), 0)              
  FROM @custom;              
              
  IF (@insertcount > 0)              
  BEGIN              
   SELECT *              
   INTO [#temp29]              
   FROM @custom;              
              
   UPDATE #temp29              
   SET [LeadID] = @newlead;              
              
   INSERT INTO customfieldLeadvalue (              
    [LeadID]              
    ,[EnquiryID]              
    ,[fieldID]              
    ,[fieldvalue]              
    )              
   SELECT *              
   FROM #temp29;              
              
   DROP TABLE #temp29;              
  END;              
 
 exec [dbo].[usp_ExecLeadTriggerTasks] @newlead

  SELECT @LeadNo AS [leadid]              
   ,'Record Inserted' AS [msg]              
   ,@newlead AS [mylead];              
              
  LeadNotInserted:              
              
  SELECT SCOPE_IDENTITY() AS [leadid];              
 END TRY              
              
 BEGIN CATCH              
  PRINT '---- SP Error: Usp_Insert_Lead_Details_ChangeWithFollowupDate2 on ' + Convert(VARCHAR, GetDate(), 13) + ' ----'              
              
  EXEC usp_insertErrorInfo;              
 END CATCH;              
              
 PRINT '---- SP Exited: Usp_Insert_Lead_Details_ChangeWithFollowupDate2 on ' + Convert(VARCHAR, GetDate(), 13) + ' ----'              
              
 DECLARE @rowJson NVARCHAR(MAX) = (              
   select *        
  FROM [dbo].[UserLeads]              
   WHERE ID = @newlead              
   FOR JSON AUTO              
    ,INCLUDE_NULL_VALUES              
   )              
              
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @CreatedBy              
  ,@Activity_type = 'Inst_Lead'              
  ,@ActionType = 'I'              
  ,@RowJson = @rowJson              
  ,@Table_name = 'UserLeads'              
END;     


GO

/* ============================================================
   Procedure: [dbo].[Usp_Insert_Lead_Details_New]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--------Modified By Abhishek Makkar ----------- Time: 8/18/2017 10:14:17 PM                    
--select * from UserLeads where ParentID = 335    
CREATE   PROCEDURE [dbo].[Usp_Insert_Lead_Details_New]                     
(                    
    @ParentID               BIGINT,                    
    @PersonName             VARCHAR(100),                    
    @CompanyName            VARCHAR(100),                    
    @MobileNo               VARCHAR(100),                    
    @MobileNo1              VARCHAR(100),                    
    @MobileNo2              VARCHAR(100),                    
    @EmailID                VARCHAR(100),                    
    @EmailID1               VARCHAR(100),                    
    @EmailID2               VARCHAR(100),                    
    @City                   VARCHAR(100),                    
    @State                  VARCHAR(100),                    
    @Country                VARCHAR(100),                    
    @CountryCode            VARCHAR(50),                    
    @CountryCode1           VARCHAR(50),                    
    @CountryCode2           VARCHAR(50),                    
    @PinCode                BIGINT,                    
    @ResidentialAddress     VARCHAR(500),                    
    @SourceName             BIGINT,                    
    @MediumName             BIGINT,                    
    @CampaignName           BIGINT,                    
    @Remarks                VARCHAR(1000),                    
    @CreatedBy              BIGINT  ,              
                  
    @AssignedTo BIGINT,              
    @FollowUpStatus  int,              
    @NextStatusDate varchar(50),              
    @Products varchar(1000),              
    @AmountPaid  numeric(18,2),               
    @FollowUpRemarks Varchar(1000)                  
                      
)                    
AS                    
BEGIN                    
create table #temp(mobile varchar(100),email varchar(100))                  
insert into #temp(mobile,email)                
select (cast(isnull(CountryCode,0) as nvarchar)+ cast(isnull(NULLIF(MobileNo,''),0) as nvarchar)),isnull(NULLIF(EmailID,''),0) from UserLeads where ParentID=@PARENTID                  
union                   
select (cast(isnull(CountryCode1,0) as nvarchar)+ cast(isnull(NULLIF(MobileNo1,''),0) as nvarchar)),isnull(NULLIF(EmailID1,''),0) from UserLeads where ParentID=@PARENTID                 
union                   
select (cast(isnull(CountryCode2,0) as nvarchar)+ cast(isnull(NULLIF(MobileNo2,''),0) as nvarchar)),isnull(NULLIF(EmailID2,''),0) from UserLeads where ParentID=@PARENTID                  
                
if exists(select 1 from UserLeads where ParentID=@ParentID and (cast(isnull(@CountryCode,1) as nvarchar)+ cast(isnull(@MobileNo,1) as nvarchar) in (select Mobile from #temp)))                  
BEGIN                
select 'Lead with Mobile ' + @mobileno + ' already exists' as [leadid]                 
goto LeadNotInserted                  
END                
if exists(select 1 from UserLeads where ParentID=@ParentID and (cast(isnull(@CountryCode1,1) as nvarchar)+ cast(isnull(@MobileNo1,1) as nvarchar) in (select Mobile from #temp)))                 
BEGIN                 
select 'Lead with Mobile ' + @mobileno1 + ' already exists' as [leadid]                 
goto LeadNotInserted                   
END                
if exists(select 1 from UserLeads where ParentID=@ParentID and (cast(isnull(@CountryCode2,1) as nvarchar)+ cast(isnull(@MobileNo2,1) as nvarchar) in (select Mobile from #temp)))                  
BEGIN                
select 'Lead with Mobile ' + @mobileno2 + ' already exists'  as [leadid]                
goto LeadNotInserted                  
END                
if exists(select 1 from UserLeads where ParentID=@ParentID and (cast(isnull(NULLIF(@EmailID,''),1) as nvarchar) in (select email from #temp)))                  
BEGIN                
select 'Lead with Email ' + @EmailID + ' already exists' as [leadid]                 
goto LeadNotInserted                  
END                
if exists(select 1 from UserLeads where ParentID=@ParentID and (cast(isnull(NULLIF(@EmailID1,''),1) as nvarchar) in (select email from #temp)))                  
BEGIN                
select 'Lead with Email ' + @EmailID1 + ' already exists'   as [leadid]               
goto LeadNotInserted                   
END                
if exists(select 1 from UserLeads where ParentID=@ParentID and (cast(isnull(NULLIF(@EmailID2,''),1) as nvarchar) in (select email from #temp)))                  
BEGIN                
select 'Lead with Email ' + @EmailID2 + ' already exists'   as [leadid]               
goto LeadNotInserted                  
END                 
                       
DECLARE @Leadno BIGINT = isnull((select MAX(LeadNo)                     
FROM   UserLeads                    
WHERE  ParentID = @ParentID),0)+1                      
                     
INSERT INTO UserLeads                    
   (                    
     ParentID,                    
     LeadNo,                    
     PersonName,                    
     CompanyName,                    
 MobileNo,                    
     MobileNo1,                    
     MobileNo2,                    
     EmailID,                    
     EmailID1,                    
     EmailID2,                    
     City,                    
     STATE,                    
     Country,                    
     CountryCode,                    
     CountryCode1,                    
     CountryCode2,                    
     PinCode,                    
     ResidentialAddress,                    
     SourceName,                    
     MediumName,                    
     CampaignName,                    
 InitialRemarks,                    
     CreatedOn,                    
     CreatedBy,                  
                   
     AssignedTo,                  
     FollowUpStatus,                  
     NextStatusDate,              
     Products ,              
     AmountPaid  ,                   
     Remarks               
   )                    
 VALUES                    
   (                    
     @ParentID,                    
     @LeadNo,                    
     @PersonName,                    
     @CompanyName,                    
     @MobileNo,                    
     @MobileNo1,                    
     @MobileNo2,                    
     @EmailID,                    
     @EmailID1,                    
     @EmailID2,                    
     @City,                    
     @State,                    
     @Country,                    
     @CountryCode,                    
     @CountryCode1,                    
     @CountryCode2,                    
     @PinCode,                    
     @ResidentialAddress,                    
     @SourceName,                    
     @MediumName,                    
     @CampaignName,                    
     @Remarks,                    
     GETDATE(),                    
     @CreatedBy,              
                   
     @AssignedTo,                  
     @FollowUpStatus,                  
     @NextStatusDate,              
     @Products ,              
     @AmountPaid  ,                   
     @FollowUpRemarks                   
                   
     --@CreatedBy,                  
     -- 1,                  
     -- cast(DATEPART(yyyy,getdate()) as nvarchar) +'-'+ RIGHT('00' + cast(DATEPART(dd,getdate()) as nvarchar(2)),2) +'-'+ RIGHT('00' + cast(DATEPART(MM,getdate()) as nvarchar(2)),2),                  
     -- 'Lead Created'                   
   )                     
                     
                     
     --  AssignedTo,                  
     --FollowUpStatus,                  
     --NextStatusDate,              
     --Products ,              
     --AmountPaid  ,                   
     --Remarks               
                     
   insert into LeadInteractionHistory([LeadNo]                  
      ,[FollowUpStatus]                  
      ,[NextStatusDate]                  
,[Remarks]              
      ,[Products]                  
      ,AmountPaid                  
      ,[AssignedTo]                  
      ,[ParentID]                  
      ,[CreatedOn]                  
      ,[CreatedBy])                  
   select @LeadNo                  
      ,@FollowUpStatus               
      ,@NextStatusDate              
 ,@FollowUpRemarks              
      ,@Products              
      ,@AmountPaid              
      ,@AssignedTo              
                       
      --,cast(DATEPART(yyyy,getdate()) as nvarchar) +'-'+ RIGHT('00' + cast(DATEPART(dd,getdate()) as nvarchar(2)),2) +'-'+ RIGHT('00' + cast(DATEPART(MM,getdate()) as nvarchar(2)),2)                  
      --,'Lead Created'                  
      --,0                  
      --,@createdby                  
      ,@ParentID                  
      ,GETDATE()                  
      ,@CreatedBy                         
                     
 SELECT @LeadNo leadid,'Record Inserted'  msg               
             
 LeadNotInserted:           
 --SELECT SCOPE_IDENTITY() AS [leadid];                     
END 


GO

/* ============================================================
   Procedure: [dbo].[Usp_Insert_Lead_Details_New_InsertUpdate]
   ============================================================ */

