SET QUOTED_IDENTIFIER ON

--------Modified By Abhishek Makkar ----------- Time: 8/18/2017 10:14:17 PM                                    
--select * from UserLeads where ParentID = 335                    
CREATE   PROCEDURE [dbo].[Usp_Insert_Lead_Details_New_InsertUpdate]                                     
(                                    
    @ParentID               BIGINT,                                    
    @PersonName             VARCHAR(100),                                    
    @CompanyName            VARCHAR(100),                                    
    @MobileNo               VARCHAR(100),                                    
    @MobileNo1              VARCHAR(100),                                    
    @MobileNo2              VARCHAR(100),                                    
    @EmailID                VARCHAR(100),                                    
    @EmailID1               VARCHAR(100),                                    
    @EmailID2               VARCHAR(100),                                    
    @City                   VARCHAR(100),                                    
    @State                  VARCHAR(100),                                    
    @Country                VARCHAR(100),                                    
    @CountryCode            VARCHAR(50),                                    
    @CountryCode1           VARCHAR(50),                                    
    @CountryCode2           VARCHAR(50),                                    
    @PinCode                BIGINT,                                    
    @ResidentialAddress     VARCHAR(500),                                    
    @SourceName             BIGINT,                                    
    @MediumName             BIGINT,                                    
    @CampaignName           BIGINT,                                    
    @Remarks                VARCHAR(1000),                                    
    @CreatedBy              BIGINT  ,                              
                                  
    @AssignedTo BIGINT,                              
    @FollowUpStatus  int,                              
    @NextStatusDate varchar(50),                              
    @Products varchar(1000),                              
    @AmountPaid  numeric(18,2),                               
    @FollowUpRemarks Varchar(1000),              
               
    @LeadNoPRM bigint,              
    @Update int          
                                    
                                      
)                                    
AS                                    
BEGIN                
declare @LeadNoTemp bigint = 0 ,@match nvarchar(100)          
Declare @FollowupDate datetime = null              
if(@NextStatusDate <> '')          
Begin          
select @FollowupDate =  dbo.[fn_getISTtimefromusertime](@ParentID,@NextStatusDate)          
End          
          
          
create table #temp(leadno bigint,mobile varchar(100),email varchar(100))                                  
insert into #temp(leadno,mobile,email)                                
select leadno,(cast(isnull(CountryCode,0) as nvarchar)+ cast(isnull(NULLIF(MobileNo,''),0) as nvarchar)),isnull(NULLIF(EmailID,''),0) from UserLeads(nolock) where ParentID=@PARENTID                                  
union                                   
select leadno,(cast(isnull(CountryCode1,0) as nvarchar)+ cast(isnull(NULLIF(MobileNo1,''),0) as nvarchar)),isnull(NULLIF(EmailID1,''),0) from UserLeads(nolock) where ParentID=@PARENTID                                 
union                                   
select leadno,(cast(isnull(CountryCode2,0) as nvarchar)+ cast(isnull(NULLIF(MobileNo2,''),0) as nvarchar)),isnull(NULLIF(EmailID2,''),0) from UserLeads(nolock) where ParentID=@PARENTID                                  
                  
if(@Update = 0)              
Begin                 
if exists(select 1 from #temp where mobile in (@MobileNo,@MobileNo1,@MobileNo2) or email in (@EmailID,@EmailID1,@EmailID2))  
--if exists(select 1 from UserLeads(nolock) where ParentID=@ParentID and (cast(isnull(@CountryCode,1) as nvarchar)+ cast(isnull(@MobileNo,1) as nvarchar) in (select Mobile from #temp)))                                              
BEGIN              
select top 1 @LeadNoTemp = LeadNo,@match=mobile from #temp where mobile in (@MobileNo,@MobileNo1,@MobileNo2)   
order by leadno desc  
if @LeadNoTemp is not null  
begin  
select 'Lead_No '+ cast(@LeadNoTemp as nvarchar) +' with Mobile ' + @match + ' already exists' as [leadid]                                 
goto LeadNotInserted                                  
end  
else  
begin  
select top 1 @LeadNoTemp = LeadNo,@match=email from #temp where email in (@EmailID,@EmailID1,@EmailID2)  
order by leadno desc  
select 'Lead_No '+ cast(@LeadNoTemp as nvarchar) +' with email ' + @match + ' already exists' as [leadid]                                 
goto LeadNotInserted  
end                                
END                   
                                       
DECLARE @Leadno BIGINT = isnull((select MAX(LeadNo) FROM   UserLeads(nolock) WHERE  ParentID = @ParentID),0)+1                                      
                                     
INSERT INTO UserLeads (                                    
     ParentID,                                    
     LeadNo,                                    
     PersonName,                                    
     CompanyName,                                    
 MobileNo,                         
     MobileNo1,                                    
     MobileNo2,                                    
     EmailID,                                    
     EmailID1,                                    
     EmailID2,              
     City,                                    
     STATE,                                    
     Country,                                    
     CountryCode,                                    
     CountryCode1,                                    
     CountryCode2,                           
     PinCode,                                    
     ResidentialAddress,                                    
     SourceName,                                    
     MediumName,                                    
     CampaignName,                                    
 InitialRemarks,                                    
     CreatedOn,                                    
     CreatedBy,                                  
     FollowupDate,                              
     AssignedTo,                                  
     FollowUpStatus,                                  
     NextStatusDate,                              
     Products ,                              
     AmountPaid  ,                                   
     Remarks,  
  enquirysource                          
   )                                    
 VALUES                                    
   (                                    
     @ParentID,                                    
     @LeadNo,                                    
     @PersonName,                                    
     @CompanyName,                                    
     @MobileNo,                                    
     @MobileNo1,                                    
     @MobileNo2,                                    
     @EmailID,                                    
     @EmailID1,                                    
     @EmailID2,                                    
     @City,                                    
     @State,                                    
     @Country,                                    
     @CountryCode,                                    
     @CountryCode1,                                    
     @CountryCode2,                                    
     @PinCode,                                    
     @ResidentialAddress,                                    
     @SourceName,                                    
     @MediumName,                                    
     @CampaignName,                                    
     @Remarks,                                    
     GETDATE(),                                    
     @CreatedBy,                              
     @FollowupDate,                              
     @AssignedTo,                                  
     @FollowUpStatus,                                  
     --@NextStatusDate,          
  (select isnull(convert(nvarchar(50),@FollowupDate,121),'')),                              
     @Products ,                              
     @AmountPaid  ,                                   
     @FollowUpRemarks,  
  18 --enquirysource for lead api                                   
                                   
     --@CreatedBy,                                  
     -- 1,                                  
     -- cast(DATEPART(yyyy,getdate()) as nvarchar) +'-'+ RIGHT('00' + cast(DATEPART(dd,getdate()) as nvarchar(2)),2) +'-'+ RIGHT('00' + cast(DATEPART(MM,getdate()) as nvarchar(2)),2),                                  
     -- 'Lead Created'                                   
   )                                     
                                     
                                     
     --  AssignedTo,                                  
     --FollowUpStatus,                       
     --NextStatusDate,                              
     --Products ,                              
     --AmountPaid  ,                                   
     --Remarks                   
                                     
   insert into LeadInteractionHistory([LeadNo]                                  
      ,[FollowUpStatus]                                  
      ,[NextStatusDate]                                  
,[Remarks]                              
      ,[Products]                                  
      ,AmountPaid                                  
      ,[AssignedTo]                                  
      ,[ParentID]                                  
      ,[CreatedOn]                                  
      ,[CreatedBy]          
   ,FollowupDate          
   )                                  
   select @LeadNo                                  
      ,@FollowUpStatus                               
      ,@NextStatusDate                              
 ,@FollowUpRemarks                              
      ,@Products                              
      ,@AmountPaid                              
      ,@AssignedTo                              
                                       
      --,cast(DATEPART(yyyy,getdate()) as nvarchar) +'-'+ RIGHT('00' + cast(DATEPART(dd,getdate()) as nvarchar(2)),2) +'-'+ RIGHT('00' + cast(DATEPART(MM,getdate()) as nvarchar(2)),2)                                  
      --,'Lead Created'                                  
      --,0                                  
      --,@createdby                                  
      ,@ParentID                                  
      ,GETDATE()                                  
      ,@CreatedBy                                         
      ,@FollowupDate                               
 SELECT @LeadNo leadid,'Record Inserted'  msg                               
                             
 LeadNotInserted:                           
 --SELECT SCOPE_IDENTITY() AS [leadid];                                     
End              
else if(@Update = 1 and @LeadNoPRM = 0)              
 Begin              
if exists(select 1 from #temp where mobile in (@MobileNo,@MobileNo1,@MobileNo2) or email in (@EmailID,@EmailID1,@EmailID2))  
BEGIN              
select top 1 @LeadNoTemp = LeadNo,@match=mobile from #temp where mobile in (@MobileNo,@MobileNo1,@MobileNo2)   
or email in (@EmailID,@EmailID1,@EmailID2)  
order by leadno desc  
goto LeadNotInserted1  
END                   
LeadNotInserted1:              
if(@LeadNoTemp <> 0)              
    Begin              
     update UserLeads set                
                    
     ParentID = isnull(nullif(@ParentID,0),ParentID),                                    
   PersonName = isnull(nullif(@PersonName,''),PersonName) ,             
     CompanyName = isnull(nullif(@CompanyName,''),CompanyName),                                    
     MobileNo =   isnull(nullif(@MobileNo,''),MobileNo),                                    
     MobileNo1 =  isnull(nullif(@MobileNo1,''),MobileNo1),                                    
     MobileNo2 =  isnull(nullif(@MobileNo2,''),MobileNo2),                                    
     EmailID =  isnull(nullif(@EmailID,''),EmailID) ,                                    
     EmailID1 = isnull(nullif(@EmailID1,''),EmailID1),                                    
     EmailID2 =  isnull(nullif(@EmailID2,''),EmailID2),                                    
     City =   isnull(nullif(@City,''),City),                                    
     STATE =  isnull(nullif(@State,''),STATE),                                    
     Country  = isnull(nullif(@Country,''),Country),                                    
     CountryCode  = isnull(nullif(@CountryCode,''),CountryCode),                                    
     CountryCode1 = isnull(nullif(@CountryCode1,''),CountryCode1),                                    
     CountryCode2 = isnull(nullif(@CountryCode2,''),CountryCode2),                                    
     PinCode =  isnull(nullif(@PinCode,'0'),PinCode) ,                                    
     ResidentialAddress = isnull(nullif(@ResidentialAddress,''),ResidentialAddress),                                    
     SourceName = isnull(nullif(@SourceName,0),SourceName) ,                                    
     MediumName = isnull(nullif(@MediumName,0),MediumName),                                    
     CampaignName = isnull(nullif(@CampaignName,0),CampaignName),                                    
     InitialRemarks = isnull(nullif(@Remarks,''),InitialRemarks),                                    
     AssignedTo  =   isnull(nullif(@AssignedTo,0),AssignedTo),                                  
     FollowUpStatus = isnull(nullif(@FollowUpStatus,0),FollowUpStatus),                                  
    -- NextStatusDate =  isnull(nullif(@NextStatusDate,''),NextStatusDate),                              
     NextStatusDate =  isnull(nullif((select isnull(convert(nvarchar(50),@FollowupDate,121),'')),''),NextStatusDate),                              
  Products  = isnull(nullif(@Products,''),Products),                              
     AmountPaid = isnull(nullif(@AmountPaid,0),AmountPaid),                                   
     Remarks = isnull(nullif(@FollowUpRemarks,''),Remarks) ,             
               
  ModifiedOn = getdate(),          
  ModifiedBy = @CreatedBy,          
  FollowupDate = @FollowupDate           
          
          
          
  where LeadNo = @LeadNoTemp  and ParentID = @ParentID              
                
       insert into LeadInteractionHistory([LeadNo]                                  
      ,[FollowUpStatus]                            
      ,[NextStatusDate]                                  
,[Remarks]                              
      ,[Products]                                  
      ,AmountPaid                                  
      ,[AssignedTo]                                  
      ,[ParentID]                                  
      ,[CreatedOn]                                  
      ,[CreatedBy]          
   ,FollowupDate)                                  
   select @LeadNoTemp                                  
      ,@FollowUpStatus                               
      ,@NextStatusDate                              
