CREATE   PROCEDURE [dbo].[Usp_Insert_Lead_Details_New_InsertUpdate_WithCustomFields]                                         
(                                        
    @ParentID               BIGINT,                                        
    @PersonName             VARCHAR(100),                                        
    @CompanyName            VARCHAR(100),                                        
    @MobileNo               VARCHAR(100),                                        
    @MobileNo1              VARCHAR(100),                                        
    @MobileNo2              VARCHAR(100),                                        
    @EmailID                VARCHAR(100),                                        
    @EmailID1               VARCHAR(100),                                        
    @EmailID2               VARCHAR(100),                                        
    @City                   VARCHAR(100),                                        
    @State                  VARCHAR(100),                                        
    @Country                VARCHAR(100),                                        
    @CountryCode            VARCHAR(50),                                        
    @CountryCode1           VARCHAR(50),                                        
    @CountryCode2           VARCHAR(50),                                        
    @PinCode                BIGINT,                                        
    @ResidentialAddress     VARCHAR(500),                                        
    @SourceName             BIGINT,                                        
    @MediumName             BIGINT,                                        
    @CampaignName           BIGINT,                                        
    @Remarks                VARCHAR(1000),                                        
    @CreatedBy              BIGINT  ,                                  
                                      
    @AssignedTo BIGINT,                                  
    @FollowUpStatus  int,                                  
    @NextStatusDate varchar(50),                                  
    @Products varchar(1000),                                  
    @AmountPaid  numeric(18,2),                                   
    @FollowUpRemarks Varchar(1000),                  
                   
    @LeadNoPRM bigint,                  
    @Update int ,             
    @custom customleads1 readonly                                     
                                          
)                                        
AS                                        
BEGIN                    
declare @LeadNoTemp bigint = 0 ,@match nvarchar(100)              
Declare @FollowupDate datetime = null                  
if(@NextStatusDate <> '')              
Begin              
select @FollowupDate =  dbo.[fn_getISTtimefromusertime](@ParentID,@NextStatusDate)              
End              
              
              
create table #temp(leadno bigint,mobile varchar(100),email varchar(100))                                      
insert into #temp(leadno,mobile,email)                                    
select leadno,(cast(isnull(CountryCode,0) as nvarchar)+ cast(isnull(NULLIF(MobileNo,''),0) as nvarchar)),isnull(NULLIF(EmailID,''),0) from UserLeads(nolock) where ParentID=@PARENTID                                      
union                                       
select leadno,(cast(isnull(CountryCode1,0) as nvarchar)+ cast(isnull(NULLIF(MobileNo1,''),0) as nvarchar)),isnull(NULLIF(EmailID1,''),0) from UserLeads(nolock) where ParentID=@PARENTID                                     
union                                       
select leadno,(cast(isnull(CountryCode2,0) as nvarchar)+ cast(isnull(NULLIF(MobileNo2,''),0) as nvarchar)),isnull(NULLIF(EmailID2,''),0) from UserLeads(nolock) where ParentID=@PARENTID                                      
                      
if(@Update = 0)                  
Begin                     
if exists(select 1 from #temp where mobile in (@MobileNo,@MobileNo1,@MobileNo2) or email in (@EmailID,@EmailID1,@EmailID2))      
--if exists(select 1 from UserLeads(nolock) where ParentID=@ParentID and (cast(isnull(@CountryCode,1) as nvarchar)+ cast(isnull(@MobileNo,1) as nvarchar) in (select Mobile from #temp)))                                                  
BEGIN                  
select top 1 @LeadNoTemp = LeadNo,@match=mobile from #temp where mobile in (@MobileNo,@MobileNo1,@MobileNo2)       
order by leadno desc      
if @LeadNoTemp is not null      
begin      
select 'Lead_No '+ cast(@LeadNoTemp as nvarchar) +' with Mobile ' + @match + ' already exists' as [leadid]                                     
goto LeadNotInserted                                      
end      
else      
begin      
select top 1 @LeadNoTemp = LeadNo,@match=email from #temp where email in (@EmailID,@EmailID1,@EmailID2)      
order by leadno desc      
select 'Lead_No '+ cast(@LeadNoTemp as nvarchar) +' with email ' + @match + ' already exists' as [leadid]                                     
goto LeadNotInserted      
end                                    
END                       
                                           
DECLARE @Leadno BIGINT = isnull((select MAX(LeadNo) FROM   UserLeads(nolock) WHERE  ParentID = @ParentID),0)+1                                          
                                         
INSERT INTO UserLeads (                                        
     ParentID,                                        
