     AssignedTo,                                      
     FollowUpStatus,                                      
     NextStatusDate,                                  
     Products ,                                  
     AmountPaid  ,                                       
     Remarks,      
  enquirysource                              
   )                                        
 VALUES                                        
   (                                        
     @ParentID,                                        
     @LeadNo,                                        
     @PersonName,                                        
     @CompanyName,                                        
     @MobileNo,                                        
     @MobileNo1,                                        
     @MobileNo2,                                        
     @EmailID,                                        
     @EmailID1,                                        
     @EmailID2,                                        
     @City,        
     @State,                                        
     @Country,                                        
     @CountryCode,                                        
     @CountryCode1,                                        
     @CountryCode2,                                        
     @PinCode,                                
     @ResidentialAddress,                                        
     @SourceName,                                        
     @MediumName,                                        
     @CampaignName,                                        
     @Remarks,                                        
     GETDATE(),                                        
     @CreatedBy,                                  
     @FollowupDate,                                  
     @AssignedTo,                                      
     @FollowUpStatus,                                      
     --@NextStatusDate,              
  (select isnull(convert(nvarchar(50),@FollowupDate,121),'')),                                  
     @Products ,                                  
     @AmountPaid  ,                                       
     @FollowUpRemarks,      
  18 --enquirysource for lead api                                       
                                       
     --@CreatedBy,                                      
     -- 1,                                      
     -- cast(DATEPART(yyyy,getdate()) as nvarchar) +'-'+ RIGHT('00' + cast(DATEPART(dd,getdate()) as nvarchar(2)),2) +'-'+ RIGHT('00' + cast(DATEPART(MM,getdate()) as nvarchar(2)),2),                                      
     -- 'Lead Created'                                       
   )                                         
                                         
                                         
     --  AssignedTo,                                      
