and ltrim(rtrim(@EmailID)) = '' and ltrim(rtrim(@EmailID1)) = '' and ltrim(rtrim(@EmailID2)) = '' )           
Begin          
select 'Mobile and Email are blank' as [leadid]          
goto LBL_LeadNotInsertedMobEmailBlank          
