select top 1 @newlead_4 = isnull(id,0) from UserLeads(nolock) where LeadNo =  @LeadNoTemp and ParentID =  @ParentID              
declare @insertcount4 smallint                                    
select @insertcount4=isnull(COUNT(fieldID), 0) from @custom                                     
   
 drop table if exists #temp29_4  
  
if(@insertcount4 >0)                                    
begin                                                       
select * into #temp29_4 from @custom;        
update #temp29_4 set LeadID=@newlead_4;                                      
update cfl  set cfl.fieldvalue = tmp.fieldvalue                
from customfieldLeadvalue(nolock) as cfl inner join  #temp29_4(nolock) as tmp              
on cfl.LeadID = tmp.LeadID and cfl.fieldID = tmp.fieldID              
       
insert into customfieldLeadvalue (LeadID,EnquiryID,fieldID,fieldvalue)            
select tmp1.LeadID,tmp1.EnquiryID,tmp1.fieldID,tmp1.fieldvalue from #temp29_4(nolock) as tmp1 where tmp1.fieldID            
not in ( select  tmp2.fieldID from customfieldLeadvalue(nolock) as cfl_i         
inner join  #temp29_4(nolock) as tmp2 on cfl_i.LeadID = tmp2.LeadID and cfl_i.fieldID = tmp2.fieldID )              
drop table if exists #temp29_4                                                     
end              
end try               
begin catch 
 SET Context_Info 0x 
exec usp_insertErrorInfo              
end catch               
               
   SELECT @LeadNo leadid,'Record Updated'  msg                                         
end        
else         
begin        
select case when @update=0 and nullif(@leadnotemp,0) is not null then        
'Lead_No '+ cast(@LeadNoTemp as nvarchar) +' with ' +@matchtype +' ' + @match + ' already exists'         
when @update=1 and nullif(@leadnotemp,0) is not null and @leadnotemp<>@LeadNoPRM then        
'Lead_No '+ cast(@LeadNoTemp as nvarchar) +' with ' +@matchtype +' ' + @match + ' already exists' end        
as [leadid]                                           
end         
commit        
end try        
begin catch   
 SET Context_Info 0x 
exec usp_InsertErrorInfo        
end catch        
        
  
         
  
if isnull(@leadno,0)<>0        
