union                                                   
select leadno,(cast(isnull(CountryCode1,0) as nvarchar)+ cast(isnull(NULLIF(MobileNo1,''),0) as nvarchar)),isnull(NULLIF(EmailID1,''),0) from UserLeads(nolock) where ParentID=@PARENTID                                                 
union                                                   
select leadno,(cast(isnull(CountryCode2,0) as nvarchar)+ cast(isnull(NULLIF(MobileNo2,''),0) as nvarchar)),isnull(NULLIF(EmailID2,''),0) from UserLeads(nolock) where ParentID=@PARENTID                                                  
          
if exists(select 1 from #temp where mobile in (cast(@countrycode as nvarchar)+cast(@MobileNo as nvarchar),        
cast(@CountryCode1 as nvarchar)+cast(@MobileNo1 as nvarchar),cast(@countrycode2 as nvarchar)+cast(@MobileNo2 as nvarchar))        
 or email in (@EmailID,@EmailID1,@EmailID2))            
