cast(@CountryCode1 as nvarchar)+cast(@MobileNo1 as nvarchar),cast(@countrycode2 as nvarchar)+cast(@MobileNo2 as nvarchar)) then mobile else email end,        
@matchtype=case when mobile in (cast(@countrycode as nvarchar)+cast(@MobileNo as nvarchar),        
cast(@CountryCode1 as nvarchar)+cast(@MobileNo1 as nvarchar),cast(@countrycode2 as nvarchar)+cast(@MobileNo2 as nvarchar)) then 'mobile' else 'email' end        
from #temp where mobile in (cast(@countrycode as nvarchar)+cast(@MobileNo as nvarchar),        
cast(@CountryCode1 as nvarchar)+cast(@MobileNo1 as nvarchar),cast(@countrycode2 as nvarchar)+cast(@MobileNo2 as nvarchar))        
or email in (@EmailID,@EmailID1,@EmailID2)            
order by case when @LeadNoPRM =leadno then 0 else leadno end desc            
end  



