   select top 1 @newlead_3 = isnull(id,0) from UserLeads(nolock) where LeadNo =  @LeadNo and ParentID =  @ParentID              
   declare @insertcount3 smallint                                    
   select @insertcount3=isnull(COUNT(fieldID), 0) from @custom                                     
   if(@insertcount3 >0)                                    
   begin                                                       
   select * into #temp29_3 from @custom;                                      
   update #temp29_3 set LeadID=@newlead_3;                                      
   insert into customfieldLeadvalue (LeadID,EnquiryID,fieldID,fieldvalue) select * from #temp29_3;                                                            
   drop table if exists #temp29_3                                                      
   end              
   End try              
   Begin Catch              
   exec usp_insertErrorInfo              
   End Catch              
   */
   
   Begin try              
declare @newlead_5 bigint =  0              
select top 1 @newlead_5 = isnull(id,0) from UserLeads(nolock) where id=@insertedleadid--LeadNo =  @LeadNo and ParentID =  @ParentID              
declare @insertcount5 smallint                                    
select @insertcount5=isnull(COUNT(fieldID), 0) from @custom                                     
if(@insertcount5 >0)                                    
begin                                                       
select * into #temp29_5 from @custom;        
update #temp29_5 set LeadID=@newlead_5;                                      
update cfl  set cfl.fieldvalue = tmp.fieldvalue                
from customfieldLeadvalue(nolock) as cfl inner join  #temp29_5(nolock) as tmp              
on cfl.LeadID = tmp.LeadID and cfl.fieldID = tmp.fieldID              
        
insert into customfieldLeadvalue (LeadID,EnquiryID,fieldID,fieldvalue)            
select * from #temp29_5(nolock) as tmp1 where tmp1.fieldID            
not in ( select  tmp2.fieldID from customfieldLeadvalue(nolock) as cfl_i         
inner join  #temp29_5(nolock) as tmp2 on cfl_i.LeadID = tmp2.LeadID and cfl_i.fieldID = tmp2.fieldID )              
drop table if exists #temp29_5                                                     
end              
end try               
begin catch              
exec usp_insertErrorInfo              
end catch   

select @leadno=leadno from userleads(nolock) where id=@insertedleadid
print concat('Inserted leadno: ',@leadno)
   
   SELECT @LeadNo leadid,'Record Inserted'  msg                                         
end                            
else if (nullif(@leadnotemp,0) is not null and @leadnoPRM in (0,@leadnotemp) and @update=1)        
begin    

select @leadno=@LeadNoTemp   

update UserLeads set                          
     ParentID = isnull(nullif(@ParentID,0),ParentID),                                              
     PersonName = isnull(nullif(@PersonName,''),PersonName) ,                       
     CompanyName = isnull(nullif(@CompanyName,''),CompanyName),                                              
     MobileNo =   isnull(nullif(@MobileNo,''),MobileNo),                                              
     MobileNo1 =  isnull(nullif(@MobileNo1,''),MobileNo1),                                              
     MobileNo2 =  isnull(nullif(@MobileNo2,''),MobileNo2),                                              
     EmailID =  isnull(nullif(@EmailID,''),EmailID) ,                                              
     EmailID1 = isnull(nullif(@EmailID1,''),EmailID1),                                              
     EmailID2 =  isnull(nullif(@EmailID2,''),EmailID2),                                              
     City =   isnull(nullif(@City,''),City),                                              
     STATE =  isnull(nullif(@State,''),STATE),                                              
     Country  = isnull(nullif(@Country,''),Country),                                              
     CountryCode  = isnull(nullif(@CountryCode,''),CountryCode),                                              
     CountryCode1 = isnull(nullif(@CountryCode1,''),CountryCode1),                                              
     CountryCode2 = isnull(nullif(@CountryCode2,''),CountryCode2),                                              
     PinCode =  isnull(nullif(@PinCode,'0'),PinCode) ,                                              
     ResidentialAddress = isnull(nullif(@ResidentialAddress,''),ResidentialAddress),                                              
     SourceName = isnull(nullif(@SourceName,0),SourceName) ,                                              
     MediumName = isnull(nullif(@MediumName,0),MediumName),                                              
     CampaignName = isnull(nullif(@CampaignName,0),CampaignName),                                              
     InitialRemarks = isnull(nullif(@Remarks,''),InitialRemarks),                                              
     AssignedTo  =   isnull(nullif(@AssignedTo,0),AssignedTo),                                            
     FollowUpStatus = isnull(nullif(@FollowUpStatus,0),FollowUpStatus),                                            
    -- NextStatusDate =  isnull(nullif(@NextStatusDate,''),NextStatusDate),                                        
     NextStatusDate =  isnull(nullif((select isnull(convert(nvarchar(50),@FollowupDate,121),'')),''),NextStatusDate),                                        
     ProductsJson  = isnull(nullif(@ProductsJson,''),ProductsJson),                 
     AmountPaid = isnull(nullif(@AmountPaid,0),AmountPaid),                                             
     Remarks = isnull(nullif(@FollowUpRemarks,''),Remarks) ,                       
     ModifiedOn = getdate(),                    
     ModifiedBy = @CreatedBy,                    
     FollowupDate = @FollowupDate                     
   where LeadNo = @LeadNoTemp  and ParentID = @ParentID                        
        
Begin try              
declare @newlead_4 bigint =  0              
select top 1 @newlead_4 = isnull(id,0) from UserLeads(nolock) where LeadNo =  @LeadNoTemp and ParentID =  @ParentID              
declare @insertcount4 smallint                                    
select @insertcount4=isnull(COUNT(fieldID), 0) from @custom                                     
if(@insertcount4 >0)                                    
begin                                                       
select * into #temp29_4 from @custom;        
update #temp29_4 set LeadID=@newlead_4;                                      
update cfl  set cfl.fieldvalue = tmp.fieldvalue                
from customfieldLeadvalue(nolock) as cfl inner join  #temp29_4(nolock) as tmp              
on cfl.LeadID = tmp.LeadID and cfl.fieldID = tmp.fieldID              
        
insert into customfieldLeadvalue (LeadID,EnquiryID,fieldID,fieldvalue)            
select * from #temp29_4(nolock) as tmp1 where tmp1.fieldID            
not in ( select  tmp2.fieldID from customfieldLeadvalue(nolock) as cfl_i         
inner join  #temp29_4(nolock) as tmp2 on cfl_i.LeadID = tmp2.LeadID and cfl_i.fieldID = tmp2.fieldID )              
drop table if exists #temp29_4                                                     
end              
end try               
begin catch              
exec usp_insertErrorInfo              
end catch               
               
   SELECT @LeadNo leadid,'Record Updated'  msg                                         
end        
else         
begin        
select case when @update=0 and nullif(@leadnotemp,0) is not null then        
'Lead_No '+ cast(@LeadNoTemp as nvarchar) +' with ' +@matchtype +' ' + @match + ' already exists'         
when @update=1 and nullif(@leadnotemp,0) is not null and @leadnotemp<>@LeadNoPRM then        
'Lead_No '+ cast(@LeadNoTemp as nvarchar) +' with ' +@matchtype +' ' + @match + ' already exists' end        
as [leadid]                                           
end         
commit        
end try        
begin catch        
exec usp_InsertErrorInfo        
end catch        
        
if isnull(@leadnotemp,0)<>0        
begin 
 
   SET Context_Info 0x55555      

  declare @lehid bigint=0 ;

   declare @userid bigint,@leadid bigint,@eventdesc nvarchar(1000),          
 @userlogin nvarchar(100),@assignedlogin nvarchar(100),@leadname nvarchar(100),@enquirysource int,@LastFollowupCreatedOn datetime    
 ,@LastRemarks nvarchar(max) = '' ,@isreassign  bit

  insert into LeadInteractionHistory([LeadNo]                                            
      ,[FollowUpStatus]                                            
      ,[NextStatusDate]                                            
      ,[Remarks]                                        
      ,[ProductsJson]                                            
      ,AmountPaid                                            
      ,[AssignedTo]                                            
      ,[ParentID]                                            
      ,[CreatedOn]                                            
      ,[CreatedBy]                    
   ,FollowupDate,Id_Lead                    
   )                                            
   select @leadnotemp                                            
      ,@FollowUpStatus                                         
      ,@NextStatusDate                                        
 ,@FollowUpRemarks                                        
      ,@ProductsJson                                        
      ,@AmountPaid                                        
      ,@AssignedTo                                        
      ,@ParentID                                            
      ,GETDATE()                                            
      ,@CreatedBy                                                   
      ,@FollowupDate,isnull(nullif(@newlead_4,0),nullif(@insertedleadid,0))                                         
end        

     set @lehid = SCOPE_IDENTITY()   
	 
  select @userid= @CreatedBy, @LastFollowupCreatedOn = CreatedOn,@LastRemarks = Remarks     
      ,@isreassign=IsReassign    
 from LeadInteractionHistory where id=@lehid          

   begin try
              
 --select * into #LEHinserted from inserted          
 declare @c int= 1 --(select count(1) from #LEHinserted)          
    
 while @c>0          
 begin          
   select top 1 @leadid=id,@leadname=PersonName,@enquirysource=enquirysource from userleads(nolock) where leadno=@leadnotemp and parentid=@parentid order by id desc          
     
 
  update userleads set LastFollowupCreatedBy=@userid,LastFollowupCreatedOn = @LastFollowupCreatedOn,Remarks = @LastRemarks where id=@leadid     
 and @followupstatus<>6     
    
    
  if not exists (select 1 from tbl_LeadEventHistory(nolock) where eventid=37 and refids=@lehid)   
   and  
   1=   
   case   
   when exists  
   (select 1 from tbl_LeadAssignmentMaster(nolock) where parentid=@parentid and is_active=1)   
   and not exists (select 1 from tbl_lam_UserAssignmentHistory(nolock) where leadid=@leadid and assignedUserId>0)  
   and  (select count(1) from Leadinteractionhistory(nolock) where parentid=@parentid and leadno=@leadnotemp)=1   
   then 0   
   else 1 end  
    
   begin      
    if nullif(@assignedto,'') is not null      
    begin      
     select @userlogin=user_login from User_Detail(nolock) where user_id=@userid      
     select @assignedlogin=user_login from User_Detail(nolock) where user_id=@assignedto      
     select @eventdesc='Lead with '+ case when isnull(nullif(@leadname,''),'')<>'' then 'name '+@leadname      
      else 'leadno '+cast(@leadnotemp as nvarchar) end +' is assigned to '+@Assignedlogin+ ' by '+ @userlogin      
     exec UspSaveLeadActivity_withid @leadid,@userid,@parentid,@eventdesc,'Lead Assigned to','Leadinteractionhistory',@lehid      
    end      
   end      
        
 set @c=@c-1          
 end          

end try          
begin catch  
  SET Context_Info 0x      
 exec usp_InsertErrorInfo          
end catch           

  SET Context_Info 0x      

LBL_LeadNotInsertedMobEmailBlank:             
                              
END 



GO

