--------Modified By Abhishek Makkar ----------- Time: 8/18/2017 10:14:17 PM
CREATE   PROCEDURE [dbo].[Usp_Insert_Lead_Details220817] 

(
    @ParentID               BIGINT,
    @PersonName             VARCHAR(100),
    @CompanyName            VARCHAR(100),
    @MobileNo               VARCHAR(100),
    @MobileNo1              VARCHAR(100),
    @MobileNo2              VARCHAR(100),
    @EmailID                VARCHAR(100),
    @EmailID1               VARCHAR(100),
    @EmailID2               VARCHAR(100),
    @City                   VARCHAR(100),
    @State                  VARCHAR(100),
    @Country                VARCHAR(100),
    @CountryCode            VARCHAR(50),
    @CountryCode1           VARCHAR(50),
    @CountryCode2           VARCHAR(50),
    @PinCode                BIGINT,
    @ResidentialAddress     VARCHAR(500),
    @SourceName             BIGINT,
    @MediumName             BIGINT,
    @CampaignName           BIGINT, 
    @Remarks                VARCHAR(1000),
    @CreatedBy              BIGINT
)
AS
BEGIN
	DECLARE @Leadno BIGINT = 1        
	
	IF (
	       EXISTS(
	           SELECT LeadNo
	           FROM   UserLeads
	           WHERE  ParentID = @ParentID
	       )
	   )
	BEGIN
	    SELECT @Leadno = MAX(ISNULL(LeadNo, 0)) + 1
	    FROM   UserLeads
	    WHERE  ParentID = @ParentID
	END      
	
	
	
	INSERT INTO UserLeads
	  (
	    ParentID,
	    LeadNo,
	    PersonName,
	    CompanyName,
	    MobileNo,
	    MobileNo1,
	    MobileNo2,
	    EmailID,
	    EmailID1,
	    EmailID2,
	    City,
	    STATE,
	    Country,
	    CountryCode,
	    CountryCode1,
	    CountryCode2,
	    PinCode,
	    ResidentialAddress,
	    SourceName,
	    MediumName,
	    CampaignName,
	    Remarks,
	    CreatedOn,
	    CreatedBy
	  )
	VALUES
	  (
	    @ParentID,
	    @LeadNo,
	    @PersonName,
	    @CompanyName,
	    @MobileNo,
	    @MobileNo1,
	    @MobileNo2,
	    @EmailID,
	    @EmailID1,
	    @EmailID2,
	    @City,
	    @State,
	    @Country,
	    @CountryCode,
	    @CountryCode1,
	    @CountryCode2,
	    @PinCode,
	    @ResidentialAddress,
	    @SourceName,
	    @MediumName,
	    @CampaignName,
	    @Remarks,
	    GETDATE(),
	    @CreatedBy
	  )        
	
	
	
	
	SELECT 'Record Inserted'
END


