/* ============================================================
   Procedure: [dbo].[Usp_Insert_linkUrl]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[Usp_Insert_linkUrl]
(
@surl_id bigint, 
@Parent_id bigint, 
@shorturl nvarchar(50), 
@access_type int, 
@CreatedBy int, 
@status int,
@opt int
)
as 
begin
declare @reslt as varchar(100)=''
if @opt =1
begin
if exists(select 1 from Link_urlMaster where shorturl =@shorturl)
	set @reslt	= 'Short Url Already exist'
else
begin
	insert into dbo.Link_urlMaster 
	(Parent_id, shorturl, access_type,  CreatedBy)
	select @Parent_id, @shorturl, @access_type,  @CreatedBy
	if SCOPE_IDENTITY() > 0
		set @reslt	= 'Short Url Saved'
	else
		set @reslt	= 'Error in Saving'
end
end
if @opt =2
begin
	update dbo.Link_urlMaster set access_type= @access_type
	where surl_id = @surl_id
	if @@ROWCOUNT > 0
		set @reslt	= 'Entry Saved'
	else
		set @reslt	= 'Error in Saving'

end
if @opt =3
begin
	update dbo.Link_urlMaster set status= @status
	where surl_id = @surl_id
	if @@ROWCOUNT > 0
		set @reslt	= 'Entry Saved'
	else
		set @reslt	= 'Error in Saving'

end
end



GO

