/* ============================================================
   Procedure: [dbo].[usp_insert_mail_rabbitmq_process]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROC [dbo].[usp_insert_mail_rabbitmq_process]
@queueid bigint,@batchid bigint
as
begin
declare @count int
select @count=count(1) from mail_rabbitmq_process(nolock) where queueid= @queueid and batchid=@batchid
if exists (select 1 from mail_rabbitmq_process(nolock) where queueid= @queueid and batchid=@batchid and is_dlq=1)
begin
select 0 as id,@count as count
end
else
begin
insert into mail_rabbitmq_process(queueid,batchid)
select @queueid,@batchid
select scope_identity() as id,@count+1 as count 
end
end




