/* ============================================================
   Procedure: [dbo].[usp_Insert_MassOperation_DataTo_Archive]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



-- select * from MySMSReportCache.[dbo].[tbl_MassOperationStatus_Cache]  select * from MySMSReportCache.[dbo].[tbl_MassOperationStatus_Archive]

   --TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_MassOperationStatus_Cache];  TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_MassOperationStatus_Archive];

-- exec [dbo].[usp_Insert_MassOperation_DataTo_Archive] 

CREATE   PROCEDURE [dbo].[usp_Insert_MassOperation_DataTo_Archive] 

AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	SET NOCOUNT ON;

	DECLARE @userid BIGINT;
    DECLARE @currentRow INT = 1;  -- Variable to track the current row in the temporary table
    DECLARE @totalRows INT;       -- Variable to store the total number of rows to process

    -- Create a temporary table to store the User IDs
    CREATE TABLE #UserIDs (UserID BIGINT);

    -- Insert UserIDs into the temporary table
    INSERT INTO #UserIDs (UserID)
    SELECT UserID
    FROM Mysms.dbo.Tbl_MassOperationSummary (NOLOCK)
	WHERE UserID IS NOT NULL
    GROUP BY UserID
    ORDER BY COUNT(*) DESC;
	
    -- Get the total number of rows
    SELECT @totalRows = COUNT(*) FROM #UserIDs;

-- Loop through each User_ID using a WHILE loop
    WHILE @currentRow <= @totalRows
BEGIN
BEGIN TRY
			-- Use a CTE to calculate ROW_NUMBER() and select the current UserID
				WITH CTE_UserIDs AS (
					SELECT UserID, ROW_NUMBER() OVER (ORDER BY UserID) AS RowNum
					FROM #UserIDs
				)
				SELECT @userid = UserID
				FROM CTE_UserIDs
				WHERE RowNum = @currentRow;

   
			Declare 
					@fromdate DATE = NULL,       
					@todate   DATE = NULL; 


			Declare @Currentdate  DATE  = GETDATE();  -- Today's date
			--SET @fromdate      = DATEADD(DAY, -30, @Currentdate); -- 30 days before today
			--SET @todate  = @Currentdate;
			
			--SET @fromdate  = DATEADD(DAY, -1, @Currentdate); -- 1 day before today		

			IF NOT EXISTS ( 
					SELECT 1 
					FROM MySMSReportCache.[dbo].[tbl_MassOperationStatus_Archive](NOLOCK)
					WHERE UserId = @userid
				)
				BEGIN

			    declare @ParentId bigint = 0, @IsAdmin BIT = 0;		
				SELECT @ParentId = ParentID, @IsAdmin = IsAdmin FROM User_Detail (NOLOCK)

				IF OBJECT_ID('tempdb..#tblUserIds') IS NOT NULL
					BEGIN
						DROP TABLE #tblUserIds;
					END

					CREATE TABLE #tblUserIds (
						UserId BIGINT NOT NULL
					);

					 DECLARE @TeamCode VARCHAR(20);

					  SELECT @TeamCode = tum.TeamCode
						FROM TBL_UA_TeamUserMappingMaster (NOLOCK) tum
						INNER JOIN TBL_UA_TeamMaster (NOLOCK) tm ON tm.TeamCode = tum.TeamCode
						WHERE tum.UserId = @UserId;

					IF ((@TeamCode IS NULL) AND (@ParentId = @UserId OR @IsAdmin = 1))
							BEGIN
								INSERT INTO #tblUserIds (UserId)
								SELECT User_Id
								FROM User_Detail (NOLOCK)
								WHERE ParentId = @ParentId;
							END
							ELSE IF (@TeamCode IS NOT NULL)
							BEGIN
								INSERT INTO #tblUserIds (UserId)
								SELECT UserId
								FROM TBL_UA_TeamUserMappingMaster (NOLOCK)
								WHERE TeamCode = @TeamCode;
							END
							ELSE
							BEGIN
								INSERT INTO #tblUserIds (UserId)
								SELECT @UserId;
							END
		
			    -- start data insert into cache tables

				INSERT INTO MySMSReportCache.[dbo].[tbl_MassOperationStatus_Archive] 
				(		   
					   [BatchID]
					  ,[Batch]
					  ,[CreatedByUserID]
					  ,[CreatedBy]
					  ,[CreatedDate]
					  ,[Status]
					  ,[ScheduleDate]
					  ,[ProcessDate]
					  ,[StatusReason]
					  ,[ButtonType]
					  ,[MassOperationName]
					  ,[EntityType]
					  ,[UserId]
					  ,[isvalid]
				)
				 SELECT
						mos.BatchID,
						mos.MassOperationName AS Batch,
						mos.UserID AS CreatedByUserID,
						CONCAT(ud.user_login, ' (', ud.fname, ' ', ud.lname, ')') AS CreatedBy,
						mos.CreatedDate,
						CASE
							WHEN mos.ScheduleDateTime IS NOT NULL AND mos.BatchStartTime IS NULL AND mos.IsProcessed = 0 THEN 'Scheduled'
							WHEN mos.IsProcessed = 1 AND mos.ScheduleDateTime IS NOT NULL AND mos.BatchStartTime IS NOT NULL THEN 'UnderProcessed'
							WHEN mos.IsProcessed = 1 AND mos.ScheduleDateTime IS NOT NULL AND mos.BatchStartTime IS NOT NULL AND mos.BatchEndTime IS NOT NULL THEN 'Processed'
							ELSE 'Not Scheduled'
						END AS Status,
						mos.ScheduleDateTime AS ScheduleDate,
						mos.BatchStartTime AS ProcessDate,
						mos.ErrorDetails AS StatusReason,
						'MassOperation' AS ButtonType,
						mos.MassOperationName,
						mos.EntityType,
						@UserId as UserId,
						mos.isvalid
					FROM
						dbo.Tbl_MassOperationSummary mos
					INNER JOIN
						#tblUserIds uids ON mos.UserID = uids.UserId
					INNER JOIN
						User_Detail ud ON mos.UserID = ud.User_ID
					WHERE
						mos.UserID IN (SELECT User_id FROM User_Detail (NOLOCK) WHERE ParentId = @UserId OR User_id = @UserId)
						--AND mos.BatchStartTime  between @fromdate and @todate
					UNION ALL
						-- Query for Webhook related data
						SELECT 
							whs.WebhookID AS BatchID,
							cb.ButtonName AS Batch,
							whs.UserId AS CreatedByUserID,
							CONCAT(ud.user_login, ' (', ud.fname, ' ', ud.lname, ')') AS CreatedBy,
							cb.CreatedDate,
							NULL AS Status,
							NULL AS ScheduleDate,
							whs.ProcessedDate AS ProcessDate,
							whs.ErrorDetails AS StatusReason,
							'CustomButton' AS ButtonType,
							'Custom Button' AS MassOperationName,
							 cb.ModuleCode,
							 @UserId as UserId,
							 ''
						FROM 
							tbl_CB_CustomButtons cb
						--INNER JOIN 
						--    tbl_cb_webhook_restbl wr ON cb.WebhookID = wr.WebhookID
						INNER JOIN 
							Tbl_CB_WebhookSummary whs ON cb.WebhookID = whs.WebhookID
						INNER JOIN 
							User_Detail ud ON cb.UserId = ud.User_ID
						WHERE 
							cb.UserId = @UserId
							--AND whs.ProcessedDate  between @fromdate and @todate
					
				-- end data insert into cache tables


END
END TRY
BEGIN CATCH
exec usp_InsertErrorInfo
END CATCH
-- Move to the next row
        SET @currentRow = @currentRow + 1;
END

-- Clean up the temporary table
    DROP TABLE #UserIDs;
		
END



GO

/* ============================================================
   Procedure: [dbo].[usp_Insert_MassOperation_DataTo_Cache_Archive]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



-- select * from MySMSReportCache.[dbo].[tbl_MassOperationStatus_Cache]  select * from MySMSReportCache.[dbo].[tbl_MassOperationStatus_Archive]

   --TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_MassOperationStatus_Cache];  TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_MassOperationStatus_Archive];

-- exec [dbo].[usp_Insert_MassOperation_DataTo_Cache_Archive] 

CREATE   PROCEDURE [dbo].[usp_Insert_MassOperation_DataTo_Cache_Archive] 

AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	SET NOCOUNT ON;

	DECLARE @userid BIGINT;
    DECLARE @currentRow INT = 1;  -- Variable to track the current row in the temporary table
    DECLARE @totalRows INT;       -- Variable to store the total number of rows to process

    -- Create a temporary table to store the User IDs
    CREATE TABLE #UserIDs (UserID BIGINT);

    -- Insert UserIDs into the temporary table
    INSERT INTO #UserIDs (UserID)
    SELECT UserID
    FROM Mysms.dbo.Tbl_MassOperationSummary (NOLOCK)
	WHERE UserID IS NOT NULL
    GROUP BY UserID
    ORDER BY COUNT(*) DESC;
	
    -- Get the total number of rows
    SELECT @totalRows = COUNT(*) FROM #UserIDs;

-- Loop through each User_ID using a WHILE loop
    WHILE @currentRow <= @totalRows
BEGIN
BEGIN TRY
			-- Use a CTE to calculate ROW_NUMBER() and select the current UserID
				WITH CTE_UserIDs AS (
					SELECT UserID, ROW_NUMBER() OVER (ORDER BY UserID) AS RowNum
					FROM #UserIDs
				)
				SELECT @userid = UserID
				FROM CTE_UserIDs
				WHERE RowNum = @currentRow;

   
			Declare 
					@fromdate DATE = NULL,       
					@todate   DATE = NULL; 


			Declare @Currentdate  DATE  = GETDATE();  -- Today's date
			--SET @fromdate      = DATEADD(DAY, -30, @Currentdate); -- 30 days before today
			SET @fromdate  = DATEADD(DAY, -1, @Currentdate); -- 1 day before today
			SET @todate  = @Currentdate;
			

			--IF NOT EXISTS ( 
			--		SELECT 1 
			--		FROM MySMSReportCache.[dbo].[tbl_MassOperationStatus_Cache](NOLOCK)
			--		WHERE UserId = @userid and TRY_CAST([ProcessDate] AS DATE) between @fromdate and @todate
			--	)
			--	BEGIN

			    declare @ParentId bigint = 0, @IsAdmin BIT = 0;		
				SELECT @ParentId = ParentID, @IsAdmin = IsAdmin FROM User_Detail (NOLOCK)

				IF OBJECT_ID('tempdb..#tblUserIds') IS NOT NULL
					BEGIN
						DROP TABLE #tblUserIds;
					END

					CREATE TABLE #tblUserIds (
						UserId BIGINT NOT NULL
					);

					 DECLARE @TeamCode VARCHAR(20);

					  SELECT @TeamCode = tum.TeamCode
						FROM TBL_UA_TeamUserMappingMaster (NOLOCK) tum
						INNER JOIN TBL_UA_TeamMaster (NOLOCK) tm ON tm.TeamCode = tum.TeamCode
						WHERE tum.UserId = @UserId;

					IF ((@TeamCode IS NULL) AND (@ParentId = @UserId OR @IsAdmin = 1))
							BEGIN
								INSERT INTO #tblUserIds (UserId)
								SELECT User_Id
								FROM User_Detail (NOLOCK)
								WHERE ParentId = @ParentId;
							END
							ELSE IF (@TeamCode IS NOT NULL)
							BEGIN
								INSERT INTO #tblUserIds (UserId)
								SELECT UserId
								FROM TBL_UA_TeamUserMappingMaster (NOLOCK)
								WHERE TeamCode = @TeamCode;
							END
							ELSE
							BEGIN
								INSERT INTO #tblUserIds (UserId)
								SELECT @UserId;
							END
		
			    -- start data insert into cache tables

				INSERT INTO MySMSReportCache.[dbo].[tbl_MassOperationStatus_Cache] 
				(		   
					   [BatchID]
					  ,[Batch]
					  ,[CreatedByUserID]
					  ,[CreatedBy]
					  ,[CreatedDate]
					  ,[Status]
					  ,[ScheduleDate]
					  ,[ProcessDate]
					  ,[StatusReason]
					  ,[ButtonType]
					  ,[MassOperationName]
					  ,[EntityType]
					  ,[UserId]
					  ,[isvalid]
				)
				 SELECT
						mos.BatchID,
						mos.MassOperationName AS Batch,
						mos.UserID AS CreatedByUserID,
						CONCAT(ud.user_login, ' (', ud.fname, ' ', ud.lname, ')') AS CreatedBy,
						mos.CreatedDate,
						CASE
							WHEN mos.ScheduleDateTime IS NOT NULL AND mos.BatchStartTime IS NULL AND mos.IsProcessed = 0 THEN 'Scheduled'
							WHEN mos.IsProcessed = 1 AND mos.ScheduleDateTime IS NOT NULL AND mos.BatchStartTime IS NOT NULL THEN 'UnderProcessed'
							WHEN mos.IsProcessed = 1 AND mos.ScheduleDateTime IS NOT NULL AND mos.BatchStartTime IS NOT NULL AND mos.BatchEndTime IS NOT NULL THEN 'Processed'
							ELSE 'Not Scheduled'
						END AS Status,
						mos.ScheduleDateTime AS ScheduleDate,
						mos.BatchStartTime AS ProcessDate,
						mos.ErrorDetails AS StatusReason,
						'MassOperation' AS ButtonType,
						mos.MassOperationName,
						mos.EntityType,
						@UserId as UserId,
						mos.isvalid
					FROM
						dbo.Tbl_MassOperationSummary mos
					INNER JOIN
						#tblUserIds uids ON mos.UserID = uids.UserId
					INNER JOIN
						User_Detail ud ON mos.UserID = ud.User_ID
					WHERE
						mos.UserID IN (SELECT User_id FROM User_Detail (NOLOCK) WHERE ParentId = @UserId OR User_id = @UserId)
						AND mos.BatchStartTime  between @fromdate and @todate
					UNION ALL
						-- Query for Webhook related data
						SELECT 
							whs.WebhookID AS BatchID,
							cb.ButtonName AS Batch,
							whs.UserId AS CreatedByUserID,
							CONCAT(ud.user_login, ' (', ud.fname, ' ', ud.lname, ')') AS CreatedBy,
							cb.CreatedDate,
							NULL AS Status,
							NULL AS ScheduleDate,
							whs.ProcessedDate AS ProcessDate,
							whs.ErrorDetails AS StatusReason,
							'CustomButton' AS ButtonType,
							'Custom Button' AS MassOperationName,
							 cb.ModuleCode,
							 @UserId as UserId,
							 ''
						FROM 
							tbl_CB_CustomButtons cb
						--INNER JOIN 
						--    tbl_cb_webhook_restbl wr ON cb.WebhookID = wr.WebhookID
						INNER JOIN 
							Tbl_CB_WebhookSummary whs ON cb.WebhookID = whs.WebhookID
						INNER JOIN 
							User_Detail ud ON cb.UserId = ud.User_ID
						WHERE 
							cb.UserId = @UserId
							AND whs.ProcessedDate  between @fromdate and @todate
					
				-- end data insert into cache tables
				INSERT INTO MySMSReportCache.[dbo].[tbl_MassOperationStatus_Archive] 
				(		   
					   [BatchID]
					  ,[Batch]
					  ,[CreatedByUserID]
					  ,[CreatedBy]
					  ,[CreatedDate]
					  ,[Status]
					  ,[ScheduleDate]
					  ,[ProcessDate]
					  ,[StatusReason]
					  ,[ButtonType]
					  ,[MassOperationName]
					  ,[EntityType]
					  ,[UserId]
					  ,[isvalid]
				)
				 SELECT
						mos.BatchID,
						mos.MassOperationName AS Batch,
						mos.UserID AS CreatedByUserID,
						CONCAT(ud.user_login, ' (', ud.fname, ' ', ud.lname, ')') AS CreatedBy,
						mos.CreatedDate,
						CASE
							WHEN mos.ScheduleDateTime IS NOT NULL AND mos.BatchStartTime IS NULL AND mos.IsProcessed = 0 THEN 'Scheduled'
							WHEN mos.IsProcessed = 1 AND mos.ScheduleDateTime IS NOT NULL AND mos.BatchStartTime IS NOT NULL THEN 'UnderProcessed'
							WHEN mos.IsProcessed = 1 AND mos.ScheduleDateTime IS NOT NULL AND mos.BatchStartTime IS NOT NULL AND mos.BatchEndTime IS NOT NULL THEN 'Processed'
							ELSE 'Not Scheduled'
						END AS Status,
						mos.ScheduleDateTime AS ScheduleDate,
						mos.BatchStartTime AS ProcessDate,
						mos.ErrorDetails AS StatusReason,
						'MassOperation' AS ButtonType,
						mos.MassOperationName,
						mos.EntityType,
						@UserId as UserId,
						mos.isvalid
					FROM
						dbo.Tbl_MassOperationSummary mos
					INNER JOIN
						#tblUserIds uids ON mos.UserID = uids.UserId
					INNER JOIN
						User_Detail ud ON mos.UserID = ud.User_ID
					WHERE
						mos.UserID IN (SELECT User_id FROM User_Detail (NOLOCK) WHERE ParentId = @UserId OR User_id = @UserId)
						AND mos.BatchStartTime  between @fromdate and @todate
					UNION ALL
						-- Query for Webhook related data
						SELECT 
							whs.WebhookID AS BatchID,
							cb.ButtonName AS Batch,
							whs.UserId AS CreatedByUserID,
							CONCAT(ud.user_login, ' (', ud.fname, ' ', ud.lname, ')') AS CreatedBy,
							cb.CreatedDate,
							NULL AS Status,
							NULL AS ScheduleDate,
							whs.ProcessedDate AS ProcessDate,
							whs.ErrorDetails AS StatusReason,
							'CustomButton' AS ButtonType,
							'Custom Button' AS MassOperationName,
							 cb.ModuleCode,
							 @UserId as UserId,
							 ''
						FROM 
							tbl_CB_CustomButtons cb
						--INNER JOIN 
						--    tbl_cb_webhook_restbl wr ON cb.WebhookID = wr.WebhookID
						INNER JOIN 
							Tbl_CB_WebhookSummary whs ON cb.WebhookID = whs.WebhookID
						INNER JOIN 
							User_Detail ud ON cb.UserId = ud.User_ID
						WHERE 
							cb.UserId = @UserId
							AND whs.ProcessedDate  between @fromdate and @todate

--END
END TRY
BEGIN CATCH
exec usp_InsertErrorInfo
END CATCH
-- Move to the next row
        SET @currentRow = @currentRow + 1;
END

	DELETE FROM MySMSReportCache.[dbo].[tbl_MassOperationStatus_Archive]
	WHERE TRY_CAST([ProcessDate] AS DATE) NOT BETWEEN DATEADD(DAY, -30, TRY_CAST(GETDATE() AS DATE)) AND TRY_CAST(GETDATE() AS DATE);

-- Clean up the temporary table
    DROP TABLE #UserIDs;
		
END



GO

