   Procedure: [dbo].[USP_INSERT_MESSAGE_DETAILS]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


--select * from CloneMessageDeliveryStatusLess where mobile ='8010809914'
--sp_help CloneMessageDeliveryStatusLess
	CREATE   PROC [dbo].[USP_INSERT_MESSAGE_DETAILS] --'8010809914','tEST MEASSAGE','HELPLV','1',17821,'0','0','0','0','0','0'
	@MOBILE VARCHAR(15),@MESSAGE VARCHAR(500),
	@SENDERID VARCHAR(50),@SMPPID VARCHAR(20),@U_ID BIGINT,@IsUniCode VARCHAR(10),
	@IsDnd VARCHAR(10) , @IsAirtel  VARCHAR(10), 
	@IsPrority VARCHAR(5), @IsAllowDND VARCHAR(5),@DBType VARCHAR(10)
	AS
	BEGIN
	DECLARE @BATCHID BIGINT ,@MobileSubSet VARCHAR(10)	
	SET @BATCHID=(select cast((9000000* Rand() + 1000000) as int ))
	SET @MobileSubSet= (SELECT  LEFT(@MOBILE,5))
	insert into dbo.CloneMessageDeliveryStatusLess([BatchID],[Mobile],[Message],
	[SenderID],	[SmppID],[U_ID],[IsUniCode],[IsDnd],[IsAirtel],[MobileSubSet],[IsPrority],	[IsAllowDND],[DBType]) 
	values(
	@BATCHID,@MOBILE,@MESSAGE,@SENDERID ,@SMPPID,@U_ID,@IsUniCode, @IsDnd,@IsAllowDND , @MobileSubSet,@IsPrority,@IsAllowDND,@DBType  )
	--SELECT * from CloneMessageDeliveryStatusLess where BatchID= @BATCHID;
	select @BATCHID as BatchID;
	
	END




