/* ============================================================
   Procedure: [dbo].[usp_insert_operator_details]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/****** SCRIPT FOR SELECTTOPNROWS COMMAND FROM SSMS  ******/    
CREATE   PROC [dbo].[usp_insert_operator_details]    
AS    

DECLARE @CUSTSENTPRO BIGINT,@CUSTSENTTR BIGINT,@CUSTSENTTRC BIGINT,@CUSTSENTCRITICAL BIGINT,@CUSTSENTKITEVER BIGINT,@VFSENTPRO BIGINT,@VFSENTTR BIGINT,@VFSENTTRC BIGINT,@VFSENTCRITICAL BIGINT,@VFSENTKITEVER BIGINT,@SPICESENTPRO BIGINT,@SPICESENTTR BIGINT,@SPICESENTTRC BIGINT,@SPICESENTCRITICAL BIGINT,@SPICESENTKITEVER BIGINT,@VFDELIVEREDPRO BIGINT,
@VFDELIVEREDTR BIGINT,@VFDELIVEREDTRC BIGINT,@VFDELIVEREDCRITICAL BIGINT,@VFDELIVEREDKITEVER BIGINT,@SPICEDELIVEREDPRO BIGINT,@SPICEDELIVEREDTR BIGINT,@SPICEDELIVEREDTRC BIGINT,@SPICEDELIVEREDCRITICAL BIGINT,
@SPICEDELIVEREDKITEVER BIGINT,@CREATEDDATE DATETIME

SELECT TOP 1 @CREATEDDATE=MESSAGEINSERTDATE FROM MYSMSREPORT.DBO.SIXDAYSHISTORY1(NOLOCK) ORDER BY MESSAGEINSERTDATE DESC
CREATE TABLE #TEMPSENTBYCUSTOMER(MESSAGECOUNT BIGINT,ACCOUNT NVARCHAR(30))
CREATE TABLE #TEMPSENTTOOPERATOR(MESSAGECOUNT BIGINT,ACCOUNT NVARCHAR(30))
CREATE TABLE #TEMPDELIVERED(MESSAGECOUNT BIGINT,ACCOUNT NVARCHAR(30))
/*SENT BY CUSTOMER*/
INSERT INTO #TEMPSENTBYCUSTOMER
SELECT COUNT(*)MESSAGECOUNT,'MTIX_PRO' ACCOUNT FROM MYSMSREPORT.DBO.SIXDAYSHISTORY1(NOLOCK) WHERE  LEN(MESSAGE)<=70 AND ISUNICODE=1 AND U_ID IN(SELECT USER_ID FROM USER_DETAIL(NOLOCK) WHERE USERFILTER='MTIX_PRO')UNION ALL
SELECT COUNT(*)MESSAGECOUNT,'MTIX_TR' ACCOUNT FROM MYSMSREPORT.DBO.SIXDAYSHISTORY1(NOLOCK) WHERE  LEN(MESSAGE)<=70 AND ISUNICODE=1 AND U_ID IN(SELECT USER_ID FROM USER_DETAIL(NOLOCK) WHERE USERFILTER='MTIX_TR')UNION ALL
SELECT COUNT(*)MESSAGECOUNT,'MTIX_TRC' ACCOUNT FROM MYSMSREPORT.DBO.SIXDAYSHISTORY1(NOLOCK) WHERE  LEN(MESSAGE)<=70 AND ISUNICODE=1 AND U_ID IN(SELECT USER_ID FROM USER_DETAIL(NOLOCK) WHERE USERFILTER='MTIX_TRC')UNION ALL
SELECT COUNT(*)MESSAGECOUNT,'CRITICAL' ACCOUNT FROM MYSMSREPORT.DBO.SIXDAYSHISTORY1(NOLOCK) WHERE  LEN(MESSAGE)<=70 AND ISUNICODE=1 AND U_ID IN(SELECT USER_ID FROM USER_DETAIL(NOLOCK) WHERE USERFILTER='CRITICAL')UNION ALL
SELECT COUNT(*)MESSAGECOUNT,'KITEVER' ACCOUNT FROM MYSMSREPORT.DBO.SIXDAYSHISTORY1 WHERE  LEN(MESSAGE)<=70 AND ISUNICODE=1 UNION ALL
SELECT COUNT(*)MESSAGECOUNT,'MTIX_PRO' ACCOUNT FROM MYSMSREPORT.DBO.SIXDAYSHISTORY1(NOLOCK) WHERE  LEN(MESSAGE)<=160 AND ISUNICODE=0 AND U_ID IN(SELECT USER_ID FROM USER_DETAIL(NOLOCK) WHERE USERFILTER='MTIX_PRO')UNION ALL
SELECT COUNT(*)MESSAGECOUNT,'MTIX_TR' ACCOUNT FROM MYSMSREPORT.DBO.SIXDAYSHISTORY1(NOLOCK) WHERE  LEN(MESSAGE)<=160 AND ISUNICODE=0 AND U_ID IN(SELECT USER_ID FROM USER_DETAIL(NOLOCK) WHERE USERFILTER='MTIX_TR')UNION ALL
SELECT COUNT(*)MESSAGECOUNT,'MTIX_TRC' ACCOUNT FROM MYSMSREPORT.DBO.SIXDAYSHISTORY1(NOLOCK) WHERE  LEN(MESSAGE)<=160 AND ISUNICODE=0 AND U_ID IN(SELECT USER_ID FROM USER_DETAIL(NOLOCK) WHERE USERFILTER='MTIX_TRC')UNION ALL
SELECT COUNT(*)MESSAGECOUNT,'CRITICAL' ACCOUNT FROM MYSMSREPORT.DBO.SIXDAYSHISTORY1(NOLOCK) WHERE  LEN(MESSAGE)<=160 AND ISUNICODE=0 AND U_ID IN(SELECT USER_ID FROM USER_DETAIL(NOLOCK) WHERE USERFILTER='CRITICAL')UNION ALL
SELECT COUNT(*)MESSAGECOUNT,'KITEVER' ACCOUNT FROM MYSMSREPORT.DBO.SIXDAYSHISTORY1 WHERE  LEN(MESSAGE)<=160 AND ISUNICODE=0 UNION ALL
SELECT SUM(CEILING(CAST(LEN(MESSAGE) AS DECIMAL(18,2))/67))MESSAGECOUNT,'MTIX_PRO' ACCOUNT FROM MYSMSREPORT.DBO.SIXDAYSHISTORY1(NOLOCK) WHERE  LEN(MESSAGE)>70 AND ISUNICODE=1 AND U_ID IN(SELECT USER_ID FROM USER_DETAIL(NOLOCK) WHERE USERFILTER='MTIX_PRO')UNION ALL
SELECT SUM(CEILING(CAST(LEN(MESSAGE) AS DECIMAL(18,2))/67))MESSAGECOUNT,'MTIX_TR' ACCOUNT FROM MYSMSREPORT.DBO.SIXDAYSHISTORY1(NOLOCK) WHERE  LEN(MESSAGE)>70 AND ISUNICODE=1 AND U_ID IN(SELECT USER_ID FROM USER_DETAIL(NOLOCK) WHERE USERFILTER='MTIX_TR')UNION ALL
SELECT SUM(CEILING(CAST(LEN(MESSAGE) AS DECIMAL(18,2))/67))MESSAGECOUNT,'MTIX_TRC' ACCOUNT FROM MYSMSREPORT.DBO.SIXDAYSHISTORY1(NOLOCK) WHERE  LEN(MESSAGE)>70 AND ISUNICODE=1 AND U_ID IN(SELECT USER_ID FROM USER_DETAIL(NOLOCK) WHERE USERFILTER='MTIX_TRC')UNION ALL
SELECT SUM(CEILING(CAST(LEN(MESSAGE) AS DECIMAL(18,2))/67))MESSAGECOUNT,'CRITICAL' ACCOUNT FROM MYSMSREPORT.DBO.SIXDAYSHISTORY1(NOLOCK) WHERE  LEN(MESSAGE)>70 AND ISUNICODE=1 AND U_ID IN(SELECT USER_ID FROM USER_DETAIL(NOLOCK) WHERE USERFILTER='CRITICAL')UNION ALL
SELECT SUM(CEILING(CAST(LEN(MESSAGE) AS DECIMAL(18,2))/67))MESSAGECOUNT,'KITEVER' ACCOUNT FROM MYSMSREPORT.DBO.SIXDAYSHISTORY1 WHERE  LEN(MESSAGE)>70 AND ISUNICODE=1 UNION ALL
SELECT SUM(CEILING(CAST(LEN(MESSAGE) AS DECIMAL(18,2))/153))MESSAGECOUNT,'MTIX_PRO' ACCOUNT FROM MYSMSREPORT.DBO.SIXDAYSHISTORY1(NOLOCK) WHERE  LEN(MESSAGE)>160 AND ISUNICODE=0 AND U_ID IN(SELECT USER_ID FROM USER_DETAIL(NOLOCK) WHERE USERFILTER='MTIX_PRO')UNION ALL
SELECT SUM(CEILING(CAST(LEN(MESSAGE) AS DECIMAL(18,2))/153))MESSAGECOUNT,'MTIX_TR' ACCOUNT FROM MYSMSREPORT.DBO.SIXDAYSHISTORY1(NOLOCK) WHERE  LEN(MESSAGE)>160 AND ISUNICODE=0 AND U_ID IN(SELECT USER_ID FROM USER_DETAIL(NOLOCK) WHERE USERFILTER='MTIX_TR')UNION ALL
SELECT SUM(CEILING(CAST(LEN(MESSAGE) AS DECIMAL(18,2))/153))MESSAGECOUNT,'MTIX_TRC' ACCOUNT FROM MYSMSREPORT.DBO.SIXDAYSHISTORY1(NOLOCK) WHERE  LEN(MESSAGE)>160 AND ISUNICODE=0 AND U_ID IN(SELECT USER_ID FROM USER_DETAIL(NOLOCK) WHERE USERFILTER='MTIX_TRC')UNION ALL
