	SELECT SUM(CEILING(CAST(LEN(MESSAGE) AS DECIMAL(18,2))/67)) MESSAGECOUNT,'KITEVER' ACCOUNT FROM MYSMSREPORT.DBO.MSGTEMPHISTORY1 WHERE  LEN(MESSAGE)>70 AND ISUNICODE=1 UNION ALL
