	SELECT COUNT(*) MESSAGECOUNT,'KITEVER' ACCOUNT FROM MYSMSREPORT.DBO.MSGTEMPHISTORY1 WHERE  LEN(MESSAGE)<=160 AND ISUNICODE=0 UNION ALL
