	SELECT SUM(CEILING(CAST(LEN(MESSAGE) AS DECIMAL(18,2))/153))MESSAGECOUNT,'KITEVER' ACCOUNT FROM MYSMSREPORT.DBO.MSGTEMPHISTORY1 WHERE LEN(MESSAGE)>160 AND ISUNICODE=0
	/*DELIVERED BY OPERATOR*/
