SELECT COUNT(*) MESSAGECOUNT,'KITEVER' ACCOUNT FROM MYSMSREPORT.DBO.MSGTEMPHISTORY1 WHERE  LEN(MESSAGE)<=70 AND ISUNICODE=1 AND MESSAGESTATUS='DELIVRD' UNION ALL
SELECT SUM(CEILING(CAST(LEN(MESSAGE) AS DECIMAL(18,2))/67)) MESSAGECOUNT,ACCOUNT FROM MYSMSREPORT.DBO.MSGTEMPHISTORY1(NOLOCK) WHERE LEN(MESSAGE)>70 AND ISUNICODE=1 AND MESSAGESTATUS='DELIVRD' GROUP BY ACCOUNT UNION ALL
SELECT SUM(CEILING(CAST(LEN(MESSAGE) AS DECIMAL(18,2))/67)) MESSAGECOUNT,'KITEVER' ACCOUNT FROM MYSMSREPORT.DBO.MSGTEMPHISTORY1 WHERE LEN(MESSAGE)>70 AND ISUNICODE=1 AND MESSAGESTATUS='DELIVRD' UNION ALL
SELECT COUNT(*) MESSAGECOUNT,ACCOUNT FROM MYSMSREPORT.DBO.MSGTEMPHISTORY1(NOLOCK) WHERE  LEN(MESSAGE)<=160 AND ISUNICODE=0 AND MESSAGESTATUS='DELIVRD' GROUP BY ACCOUNT UNION ALL
SELECT COUNT(*) MESSAGECOUNT,'KITEVER' ACCOUNT FROM MYSMSREPORT.DBO.MSGTEMPHISTORY1 WHERE  LEN(MESSAGE)<=160 AND ISUNICODE=0 AND MESSAGESTATUS='DELIVRD' UNION ALL
SELECT SUM(CEILING(CAST(LEN(MESSAGE) AS DECIMAL(18,2))/153))MESSAGECOUNT,ACCOUNT FROM MYSMSREPORT.DBO.MSGTEMPHISTORY1(NOLOCK) WHERE  LEN(MESSAGE)>160 AND ISUNICODE=0 AND MESSAGESTATUS='DELIVRD' GROUP BY ACCOUNT UNION ALL
SELECT SUM(CEILING(CAST(LEN(MESSAGE) AS DECIMAL(18,2))/153))MESSAGECOUNT,'KITEVER' ACCOUNT FROM MYSMSREPORT.DBO.MSGTEMPHISTORY1 WHERE  LEN(MESSAGE)>160 AND ISUNICODE=0 AND MESSAGESTATUS='DELIVRD'

