/* ============================================================
   Procedure: [dbo].[usp_Insert_resailler_new]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
CREATE   PROC [dbo].[usp_Insert_resailler_new]              
@User_ID int,   -- frm big int 19-08-2010            
@Title nvarchar(50),              
@Domain nvarchar(50),              
@Slogan nvarchar(50)        
AS                
declare @M_ID nvarchar(12)                           
set @M_ID=(select m_id from User_Detail where [user_id]=@User_ID)       
if exists(select * from Reseller_Detail where   domain=@Domain)                
begin                
select 'Domain Name Already Exists'                
end                
else             
begin            
             
insert into Reseller_Detail (M_ID,[User_ID],Title,Domain,Slogan) values(@M_ID,@User_ID,@Title,@Domain,@Slogan)              
update User_Detail set Type=1 where [user_id]=@User_ID     
update Credit_Details set Validity=99999,FromDate=getdate(),ToDate=getdate()+99999  where m_id=@M_ID and user_id=@User_ID        
select 'Reseller Registered Succsessfully'            
end





GO

