/* ============================================================
   Procedure: [dbo].[usp_Insert_SalesTargetPagination_by_Filter_DataTo_Archive]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


   -- select * from MySMSReportCache.[dbo].[tbl_SalesTarget_Cache](nolock)  select * from MySMSReportCache.[dbo].[tbl_SalesTarget_Archive](nolock) 

   -- TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_SalesTarget_Cache];  TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_SalesTarget_Archive];

   -- exec usp_Insert_SalesTargetPagination_by_Filter_DataTo_Archive

CREATE   PROCEDURE [dbo].[usp_Insert_SalesTargetPagination_by_Filter_DataTo_Archive]       

as                      
BEGIN    
SET NOCOUNT ON;

	DECLARE @userid BIGINT;
    DECLARE @currentRow INT = 1;  -- Variable to track the current row in the temporary table
    DECLARE @totalRows INT;       -- Variable to store the total number of rows to process

    -- Create a temporary table to store the User IDs
    CREATE TABLE #UserIDs (UserID BIGINT);

    -- Insert UserIDs into the temporary table
    INSERT INTO #UserIDs (UserID)
    SELECT UserId
    FROM Mysms.dbo.TBL_ST_SalesTargetSettingUserTarget(NOLOCK)
	WHERE UserId IS NOT NULL
    GROUP BY UserId
    ORDER BY COUNT(*) DESC;
	
    -- Get the total number of rows
    SELECT @totalRows = COUNT(*) FROM #UserIDs;

-- Loop through each User_ID using a WHILE loop
    WHILE @currentRow <= @totalRows
BEGIN
BEGIN TRY

		-- Use a CTE to calculate ROW_NUMBER() and select the current UserID
				WITH CTE_UserIDs AS (
					SELECT UserID, ROW_NUMBER() OVER (ORDER BY UserID) AS RowNum
					FROM #UserIDs
				)
				SELECT @userid = UserID
				FROM CTE_UserIDs
				WHERE RowNum = @currentRow;
				
				DECLARE  @parentid bigint
						 ,@fromdate DATE          
						 ,@todate DATE 
						 ,@TargetPeriodId int = 0    
						 ,@TargetType int = 0    
						 ,@TargetFor varchar(10) = ''  
						 ,@SrchUserids nvarchar(50) =''  
						 ,@SrchTeamids nvarchar(50) =''  
						 ,@Offsets int = 0  
						 ,@PageSize int = 100000 
						 ,@FilterText nvarchar(255) = null 

			 
			 Declare @Currentdate  DATE  = GETDATE();  -- Today's date
			 SET @fromdate  = DATEADD(DAY, -9130, @Currentdate); -- 1 day before today
			 SET @todate  = @Currentdate;

				declare  @StartPoint int = (@Offsets + 1 ),  
				  @EndPoint int = (@Offsets + @PageSize )  

			 select @ParentId = ParentID from User_Detail(nolock) where User_ID = @UserId;

			 drop table if exists #tempUsers  
				 create table #tempUsers(User_Id bigint, Name nvarchar(255), image nvarchar(255), TeamCode nvarchar(255))  
					insert into #tempUsers exec Use_GetUserDetails_Team @UserId    

			 drop table if exists #tempAchievedData  

			 drop table if exists #agentUserId
			 create table #agentUserId(SalesTargetId bigint,UserId bigint,StartDate datetime,EndDate datetime)

				insert into #agentUserId(SalesTargetId, UserId, StartDate, EndDate)
				select m.SalesTargetId, t.UserId, t.FromDate, t.ToDate from TBL_ST_SalesTargetSettingMaster(nolock) m inner join
					TBL_ST_SalesTargetSettingUserTarget(nolock) t on m.SalesTargetId = t.SalesTargetId
						where t.ParentId = @ParentId and m.TargetFor = 'user'

				;WITH SplitUserDetailCTE AS (
					SELECT id, SalesTargetId, FromDate, ToDate, ParentId,
						JSON_VALUE(value, '$.IsActive') AS SplitUserDetail_IsActive,
						JSON_VALUE(value, '$.UserId') AS SplitUserDetail_UserId
					FROM TBL_ST_SalesTargetSettingUserTarget(nolock)
					CROSS APPLY OPENJSON(UserSplitDetail) 
				)
				insert into #agentUserId(SalesTargetId, UserId, StartDate, EndDate)
				SELECT m.SalesTargetId, SplitUserDetail_UserId, FromDate, ToDate FROM SplitUserDetailCTE s
					inner join TBL_ST_SalesTargetSettingMaster(nolock) m on s.SalesTargetId = m.SalesTargetId
						where s.ParentId = @ParentId and m.TargetFor = 'team' and s.SplitUserDetail_IsActive = 'true'

			 select  m.SalesTargetId, m.UserId, TRY_CAST(a.RecordDate as date) as [RecoredDate], 
				  SUM(case when a.TblRefName = 'invoices' then 1 else 0 end ) as InvoiceCount,  
				  SUM(case when a.TblRefName = 'LeadInteractionHistory' then 1 else 0 end ) as ConverstionCount,  
				  SUM(case when a.TblRefName = 'LeadPipelineMapping' then 1 else 0 end ) as PipelineCount,  
				  SUM(case when a.TblRefName = 'invoices' then a.Amount else 0 end ) as InvoiceAmount,  
				  SUM(case when a.TblRefName = 'LeadInteractionHistory' then a.Amount else 0 end ) as ConverstionAmount,  
				  SUM(case when a.TblRefName = 'LeadPipelineMapping' then a.Amount else 0 end ) as PipelineAmount  
				   into #tempAchievedData  
				  --from TBL_ST_SalesTargetSettingMaster(nolock) m 
				  from #agentUserId(nolock) m 
				  --inner join TBL_ST_SalesTargetSettingChild(nolock) c on m.SalesTargetId = c.SalesTargetId  
				  --inner join #tempUsers s on c.UserId = s.User_Id  
				  inner join Tbl_ST_SalesActivityMaster(nolock) a on a.UserId = m.UserId and m.SalesTargetId = a.SalesTargetId  
				   --and Cast(a.RecordDate as Date) between Cast(m.TargetFromDate as Date) and Cast(m.TargetToDate as Date)  
				   and TRY_CAST(a.RecordDate as Date) between TRY_CAST(m.StartDate as Date) and TRY_CAST(m.EndDate as Date)  
				  where a.ParentId = @ParentId  
				  group by m.SalesTargetId, m.UserId, TRY_CAST(a.RecordDate as date)  

			 IF NOT EXISTS ( 
					SELECT 1 
					FROM MySMSReportCache.[dbo].[tbl_SalesTarget_Archive](NOLOCK)
					WHERE UserId = @userid
				)
				BEGIN
						INSERT INTO MySMSReportCache.[dbo].[tbl_SalesTarget_Archive] 
							(
							
							    [SNo],
								[TotalRows],
								[SalesTargetName],
								[FromDate],
								[TargetTeamUserid],
								[SalesTargetId],
								[TargetType],
								[TargetTypeSearch],
								[Conversions],
								[Pipelines],
								[Invoices],
								[iInvoiceRaised],
								[iInvoicePaid],
								[TargetFor],
								[TeamCodes],
								[UserIds],
								[TargetPeriodId],
								[TargetFromDate],
								[TargetToDate],
								[TargetFromDateSearch],
								[TargetToDateSearch],
								[TargetFromDate1],
								[TargetToDate1],
								[TargetProductIds],
								[TargetPipelineIds],
								[TotalTarget],
								[TestingtTargetType],
								[AchievedTarget],
								[TargetUnit],
								[Currency],
								[UserId],
								[ParentId],
								[Status],
								[IsActive],
								[CreatedBy],
								[CreatedDate],
								[ModifiedBy],
								[ModifiedDate],
								[Duration],
								[CreatedByName],
								[ModifiedByName],
								[UserTargetSettingId],
								[Achievedpercent]
							)
							select *, TRY_CAST(round( ((AchievedTarget/NULLIF(TotalTarget, 0)) * 100),2)as numeric(10,2)) Achievedpercent  
										  from (   
										  select 
										   ROW_NUMBER() over (PARTITION BY (SELECT NULL) Order BY m.SalesTargetId desc) as [SNo],   
										   count(1) over( order by (select null)) AS [TotalRows],   
											m.SalesTargetName,  
											t.FromDate, TRY_CAST(t.UserId as varchar) as TargetTeamUserid, t.SalesTargetId,   
											concat( (case when m.TargetType = '1' then 'Revenue' when m.TargetType = '2' then 'Conversions'  when m.TargetType = '3' then 'Points' else m.TargetType End),  
											 '<br/>',  
											 case when m.Conversions = 1 then '<b>Product</b> ' else '' end,  
											 case when m.Pipelines = 1 then '<b>Pipeline</b> ' else '' end,  
											 case when m.Invoices = 1 then '<b>Invoice</b> ' else '' end )  
											as [TargetType],   
											m.TargetType TargetTypeSearch, m.Conversions, m.Pipelines, m.Invoices, m.iInvoiceRaised, m.iInvoicePaid,
											concat(UPPER(m.TargetFor), ' ',  case when m.TargetFor = 'team' then z.TeamName  
											 when m.TargetFor = 'user' then concat(u.User_Login, '(', u.FName, ' ', u.LName, ')') end, '' ) as [TargetFor],  
											m.TeamCodes, m.UserIds, m.TargetPeriodId, format(t.FromDate, 'dd-MMM-yyyy') as [TargetFromDate], format(t.ToDate, 'dd-MMM-yyyy') as [TargetToDate],   
											 m.TargetFromDate TargetFromDateSearch,  m.TargetToDate TargetToDateSearch,   
											 TRY_CONVERT(varchar, m.TargetFromDate, 23) TargetFromDate1, TRY_CONVERT(varchar, m.TargetToDate, 23) TargetToDate1, TargetProductIds, TargetPipelineIds,  
											 case when m.TargetFor = 'team' then  coalesce(m.TotalTarget,0) else coalesce( t.Target,0) end as TotalTarget,  
											 m.TargetType as [TestingtTargetType],
											 isnull(
											 ( case when m.TargetType = 3  then (   
												 CASE WHEN EXISTS ( SELECT 1   
												  FROM tbl_SM_Employee_Points_History   
												  WHERE TranDate BETWEEN CONCAT(TRY_CONVERT(VARCHAR, t.FromDate, 23), ' 00:00:00')AND CONCAT(TRY_CONVERT(VARCHAR, t.ToDate, 23), ' 23:59:59')
												 ) THEN    
												  (  
												   SELECT COALESCE(SUM(POINTS), 0)   
												   FROM tbl_SM_Employee_Points_History PH   
												   WHERE --PH.UserId IN (SELECT VALUE FROM STRING_SPLIT(COALESCE(m.UserIds, ''), '#'))  
													 (PH.UserId IN (  CASE WHEN m.TargetFor = 'user' THEN (t.UserId)  ELSE  (SELECT VALUE FROM STRING_SPLIT(COALESCE(m.UserIds, ''), '#')) END))
													 AND PH.TranDate BETWEEN CONCAT(TRY_CONVERT(VARCHAR, t.FromDate, 23), ' 00:00:00')   
														  AND CONCAT(TRY_CONVERT(VARCHAR, t.ToDate, 23), ' 23:59:59')  
												  )  
												 ELSE 0 END ) 
											 when m.TargetType = 2  then 
												(  iif(m.Conversions = 1, v.ConverstionCount, 0)   
											   +  iif(m.Invoices = 1, v.InvoiceCount, 0)  
											   +  iif(m.Pipelines = 1, v.PipelineCount , 0))  
											  when m.TargetType = 1  then (   
											   iif(m.Conversions = 1, v.ConverstionAmount, 0)   
											   +  iif(m.Invoices = 1, v.InvoiceAmount, 0)  
											   +  iif(m.Pipelines = 1, v.PipelineAmount , 0))  
											   else 0 end
											 ), 0) as [AchievedTarget], 
											 TargetUnit, Currency, t.UserId, m.ParentId, m.[Status], t.IsActive, m.CreatedBy,   
											 format(m.CreatedDate, 'dd-MMM-yyyyy HH:mm:ss') as CreatedDate, m.ModifiedBy,    
											 format(m.ModifiedDate, 'dd-MMM-yyyyy HH:mm:ss') as ModifiedDate,   
											  ( case when TRY_CAST(getdate() as date) < TRY_CAST(t.FromDate as date) then 'Upcoming'   
											  when TRY_CAST(getdate() as date) > TRY_CAST(t.ToDate as date) then 'Completed'    
											  when TRY_CAST(getdate() as date) between TRY_CAST(t.FromDate as date) and TRY_CAST(t.ToDate as date) then 'Current'   
											  else '' end) Duration,  
											 concat(ud1.FName, ' ', ud1.LName) as [CreatedByName],   
											 '' as ModifiedByName,   
											 t.id as UserTargetSettingId       
										   from TBL_ST_SalesTargetSettingMaster(nolock) m  
											inner join TBL_ST_SalesTargetSettingUserTarget(nolock) t on m.SalesTargetId = t.SalesTargetId  
											--inner join #tempUsers ru on  m.ParentId = @ParentId  
											-- and 1 = ( case when @ParentId = @UserId then 1 when t.UserId = ru.User_Id then 1 else 0 end)  
											left join User_Detail ud1(nolock) on m.CreatedBy = ud1.User_ID     	
											left join #tempAchievedData v on 1  = (case   
											 when m.TargetFor = 'team' and t.SalesTargetId = v.SalesTargetId then 1  
											 when m.TargetFor = 'user' and t.SalesTargetId = v.SalesTargetId and t.UserId = v.UserId then 1  
											 else 0 end  )    
											left join TBL_UA_TeamMaster(nolock) z on 1 = (case when m.TargetFor = 'team' then 1 else 0 end ) and z.TeamCode = m.TeamCodes and z.Active = 1  
											left join User_Detail(nolock) u on 1 = (case when m.TargetFor = 'user' then 1 else 0 end ) and u.User_ID = t.UserId  
										  where m.ParentId = @ParentId   and ( case when @TargetType = 0 then '1' else m.TargetType  end = case when @TargetType = 0 then '1' else     @TargetType end )
										   and 1 = ( case   
											  when @ParentId = @UserId then 1   
											  when t.UserId in (select User_Id from  #tempUsers)then 1   
											 else 0 end)   
										   and ( m.TargetFromDate between @FromDate and @ToDate or m.TargetToDate between @FromDate and @ToDate /*t.ToDate*/ )  
										   and 1 = (case   
											 when ISNULL(@FilterText, '')  = '' then 1   
											 when m.TargetFor = 'team' and z.TeamName like '%'+ @FilterText+ '%' then 1   
											 when m.TargetFor = 'user' and u.User_Login like '%'+ @FilterText+ '%' then 1   
											 else 0 end  
											)  
										 ) t where t.SNo between @StartPoint and @EndPoint 
				END

END TRY
BEGIN CATCH
exec usp_InsertErrorInfo
END CATCH
-- Move to the next row
        SET @currentRow = @currentRow + 1;
END

-- Clean up the temporary table
    DROP TABLE #UserIDs;
   
END 




GO

/* ============================================================
   Procedure: [dbo].[usp_Insert_SalesTargetPagination_by_Filter_DataTo_Cache_Archive]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


   -- select * from MySMSReportCache.[dbo].[tbl_SalesTarget_Cache]  select * from MySMSReportCache.[dbo].[tbl_SalesTarget_Archive] 

   -- TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_SalesTarget_Cache];  TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_SalesTarget_Archive];

   -- exec usp_Insert_SalesTargetPagination_by_Filter_DataTo_Cache_Archive

CREATE   PROCEDURE [dbo].[usp_Insert_SalesTargetPagination_by_Filter_DataTo_Cache_Archive]       

as                      
BEGIN    
SET NOCOUNT ON;

	DECLARE @userid BIGINT;
    DECLARE @currentRow INT = 1;  -- Variable to track the current row in the temporary table
    DECLARE @totalRows INT;       -- Variable to store the total number of rows to process

    -- Create a temporary table to store the User IDs
    CREATE TABLE #UserIDs (UserID BIGINT);

    -- Insert UserIDs into the temporary table
    INSERT INTO #UserIDs (UserID)
    SELECT UserId
    FROM Mysms.dbo.TBL_ST_SalesTargetSettingUserTarget(NOLOCK)
	WHERE UserId IS NOT NULL
    GROUP BY UserId
    ORDER BY COUNT(*) DESC;
	
    -- Get the total number of rows
    SELECT @totalRows = COUNT(*) FROM #UserIDs;

-- Loop through each User_ID using a WHILE loop
    WHILE @currentRow <= @totalRows
BEGIN
BEGIN TRY

		-- Use a CTE to calculate ROW_NUMBER() and select the current UserID
				WITH CTE_UserIDs AS (
					SELECT UserID, ROW_NUMBER() OVER (ORDER BY UserID) AS RowNum
					FROM #UserIDs
				)
				SELECT @userid = UserID
				FROM CTE_UserIDs
				WHERE RowNum = @currentRow;
				
				DECLARE  @parentid bigint
						 ,@fromdate DATE          
						 ,@todate DATE 
						 ,@TargetPeriodId int = 0    
						 ,@TargetType int = 0    
						 ,@TargetFor varchar(10) = ''  
						 ,@SrchUserids nvarchar(50) =''  
						 ,@SrchTeamids nvarchar(50) =''  
						 ,@Offsets int = 0  
						 ,@PageSize int = 100000 
						 ,@FilterText nvarchar(255) = null 

			 
			 Declare @Currentdate  DATE  = GETDATE();  -- Today's date
			 SET @fromdate  = DATEADD(DAY, -30, @Currentdate); -- 1 day before today
			 SET @todate  = @Currentdate;

				declare  @StartPoint int = (@Offsets + 1 ),  
				  @EndPoint int = (@Offsets + @PageSize )  

			 select @ParentId = ParentID from User_Detail(nolock) where User_ID = @UserId;

			 drop table if exists #tempUsers  
				 create table #tempUsers(User_Id bigint, Name nvarchar(255), image nvarchar(255), TeamCode nvarchar(255))  
					insert into #tempUsers exec Use_GetUserDetails_Team @UserId    

			 drop table if exists #tempAchievedData  

			 drop table if exists #agentUserId
			 create table #agentUserId(SalesTargetId bigint,UserId bigint,StartDate datetime,EndDate datetime)

				insert into #agentUserId(SalesTargetId, UserId, StartDate, EndDate)
				select m.SalesTargetId, t.UserId, t.FromDate, t.ToDate from TBL_ST_SalesTargetSettingMaster(nolock) m inner join
					TBL_ST_SalesTargetSettingUserTarget(nolock) t on m.SalesTargetId = t.SalesTargetId
						where t.ParentId = @ParentId and m.TargetFor = 'user'

				;WITH SplitUserDetailCTE AS (
					SELECT id, SalesTargetId, FromDate, ToDate, ParentId,
						JSON_VALUE(value, '$.IsActive') AS SplitUserDetail_IsActive,
						JSON_VALUE(value, '$.UserId') AS SplitUserDetail_UserId
					FROM TBL_ST_SalesTargetSettingUserTarget(nolock)
					CROSS APPLY OPENJSON(UserSplitDetail) 
				)
				insert into #agentUserId(SalesTargetId, UserId, StartDate, EndDate)
				SELECT m.SalesTargetId, SplitUserDetail_UserId, FromDate, ToDate FROM SplitUserDetailCTE s
					inner join TBL_ST_SalesTargetSettingMaster(nolock) m on s.SalesTargetId = m.SalesTargetId
						where s.ParentId = @ParentId and m.TargetFor = 'team' and s.SplitUserDetail_IsActive = 'true'

			 select  m.SalesTargetId, m.UserId, TRY_CAST(a.RecordDate as date) as [RecoredDate], 
				  SUM(case when a.TblRefName = 'invoices' then 1 else 0 end ) as InvoiceCount,  
				  SUM(case when a.TblRefName = 'LeadInteractionHistory' then 1 else 0 end ) as ConverstionCount,  
				  SUM(case when a.TblRefName = 'LeadPipelineMapping' then 1 else 0 end ) as PipelineCount,  
				  SUM(case when a.TblRefName = 'invoices' then a.Amount else 0 end ) as InvoiceAmount,  
				  SUM(case when a.TblRefName = 'LeadInteractionHistory' then a.Amount else 0 end ) as ConverstionAmount,  
				  SUM(case when a.TblRefName = 'LeadPipelineMapping' then a.Amount else 0 end ) as PipelineAmount  
				   into #tempAchievedData  
				  --from TBL_ST_SalesTargetSettingMaster(nolock) m 
				  from #agentUserId(nolock) m 
				  --inner join TBL_ST_SalesTargetSettingChild(nolock) c on m.SalesTargetId = c.SalesTargetId  
				  --inner join #tempUsers s on c.UserId = s.User_Id  
				  inner join Tbl_ST_SalesActivityMaster(nolock) a on a.UserId = m.UserId and m.SalesTargetId = a.SalesTargetId  
				   --and Cast(a.RecordDate as Date) between Cast(m.TargetFromDate as Date) and Cast(m.TargetToDate as Date)  
				   and TRY_CAST(a.RecordDate as Date) between TRY_CAST(m.StartDate as Date) and TRY_CAST(m.EndDate as Date)  
				  where a.ParentId = @ParentId  
				  group by m.SalesTargetId, m.UserId, TRY_CAST(a.RecordDate as date)  

			 IF NOT EXISTS ( 
					SELECT 1 
					FROM MySMSReportCache.[dbo].[tbl_SalesTarget_Cache](NOLOCK)
					WHERE UserId = @userid
				)
				BEGIN
						INSERT INTO MySMSReportCache.[dbo].[tbl_SalesTarget_Cache] 
							(
							
							    [SNo],
								[TotalRows],
								[SalesTargetName],
								[FromDate],
								[TargetTeamUserid],
								[SalesTargetId],
								[TargetType],
								[TargetTypeSearch],
								[Conversions],
								[Pipelines],
								[Invoices],
								[iInvoiceRaised],
								[iInvoicePaid],
								[TargetFor],
								[TeamCodes],
								[UserIds],
								[TargetPeriodId],
								[TargetFromDate],
								[TargetToDate],
								[TargetFromDateSearch],
								[TargetToDateSearch],
								[TargetFromDate1],
								[TargetToDate1],
								[TargetProductIds],
								[TargetPipelineIds],
								[TotalTarget],
								[TestingtTargetType],
								[AchievedTarget],
								[TargetUnit],
								[Currency],
								[UserId],
								[ParentId],
								[Status],
								[IsActive],
								[CreatedBy],
								[CreatedDate],
								[ModifiedBy],
								[ModifiedDate],
								[Duration],
								[CreatedByName],
								[ModifiedByName],
								[UserTargetSettingId],
								[Achievedpercent]
							)
							select *, TRY_CAST(round( ((AchievedTarget/NULLIF(TotalTarget, 0)) * 100),2)as numeric(10,2)) Achievedpercent  
										  from (   
										  select 
										   ROW_NUMBER() over (PARTITION BY (SELECT NULL) Order BY m.SalesTargetId desc) as [SNo],   
										   count(1) over( order by (select null)) AS [TotalRows],   
											m.SalesTargetName,  
											t.FromDate, TRY_CAST(t.UserId as varchar) as TargetTeamUserid, t.SalesTargetId,   
											concat( (case when m.TargetType = '1' then 'Revenue' when m.TargetType = '2' then 'Conversions'  when m.TargetType = '3' then 'Points' else m.TargetType End),  
											 '<br/>',  
											 case when m.Conversions = 1 then '<b>Product</b> ' else '' end,  
											 case when m.Pipelines = 1 then '<b>Pipeline</b> ' else '' end,  
											 case when m.Invoices = 1 then '<b>Invoice</b> ' else '' end )  
											as [TargetType],   
											m.TargetType TargetTypeSearch, m.Conversions, m.Pipelines, m.Invoices, m.iInvoiceRaised, m.iInvoicePaid,
											concat(UPPER(m.TargetFor), ' ',  case when m.TargetFor = 'team' then z.TeamName  
											 when m.TargetFor = 'user' then concat(u.User_Login, '(', u.FName, ' ', u.LName, ')') end, '' ) as [TargetFor],  
											m.TeamCodes, m.UserIds, m.TargetPeriodId, format(t.FromDate, 'dd-MMM-yyyy') as [TargetFromDate], format(t.ToDate, 'dd-MMM-yyyy') as [TargetToDate],   
											 m.TargetFromDate TargetFromDateSearch,  m.TargetToDate TargetToDateSearch,   
											 TRY_CONVERT(varchar, m.TargetFromDate, 23) TargetFromDate1, TRY_CONVERT(varchar, m.TargetToDate, 23) TargetToDate1, TargetProductIds, TargetPipelineIds,  
											 case when m.TargetFor = 'team' then  coalesce(m.TotalTarget,0) else coalesce( t.Target,0) end as TotalTarget,  
											 m.TargetType as [TestingtTargetType],
											 isnull(
											 ( case when m.TargetType = 3  then (   
												 CASE WHEN EXISTS ( SELECT 1   
												  FROM tbl_SM_Employee_Points_History   
												  WHERE TranDate BETWEEN CONCAT(TRY_CONVERT(VARCHAR, t.FromDate, 23), ' 00:00:00')AND CONCAT(TRY_CONVERT(VARCHAR, t.ToDate, 23), ' 23:59:59')
												 ) THEN    
												  (  
												   SELECT COALESCE(SUM(POINTS), 0)   
												   FROM tbl_SM_Employee_Points_History PH   
												   WHERE --PH.UserId IN (SELECT VALUE FROM STRING_SPLIT(COALESCE(m.UserIds, ''), '#'))  
													 (PH.UserId IN (  CASE WHEN m.TargetFor = 'user' THEN (t.UserId)  ELSE  (SELECT VALUE FROM STRING_SPLIT(COALESCE(m.UserIds, ''), '#')) END))
													 AND PH.TranDate BETWEEN CONCAT(TRY_CONVERT(VARCHAR, t.FromDate, 23), ' 00:00:00')   
														  AND CONCAT(TRY_CONVERT(VARCHAR, t.ToDate, 23), ' 23:59:59')  
												  )  
												 ELSE 0 END ) 
											 when m.TargetType = 2  then 
												(  iif(m.Conversions = 1, v.ConverstionCount, 0)   
											   +  iif(m.Invoices = 1, v.InvoiceCount, 0)  
											   +  iif(m.Pipelines = 1, v.PipelineCount , 0))  
											  when m.TargetType = 1  then (   
											   iif(m.Conversions = 1, v.ConverstionAmount, 0)   
											   +  iif(m.Invoices = 1, v.InvoiceAmount, 0)  
											   +  iif(m.Pipelines = 1, v.PipelineAmount , 0))  
											   else 0 end
											 ), 0) as [AchievedTarget], 
											 TargetUnit, Currency, t.UserId, m.ParentId, m.[Status], t.IsActive, m.CreatedBy,   
											 format(m.CreatedDate, 'dd-MMM-yyyyy HH:mm:ss') as CreatedDate, m.ModifiedBy,    
											 format(m.ModifiedDate, 'dd-MMM-yyyyy HH:mm:ss') as ModifiedDate,   
											  ( case when TRY_CAST(getdate() as date) < TRY_CAST(t.FromDate as date) then 'Upcoming'   
											  when TRY_CAST(getdate() as date) > TRY_CAST(t.ToDate as date) then 'Completed'    
											  when TRY_CAST(getdate() as date) between TRY_CAST(t.FromDate as date) and TRY_CAST(t.ToDate as date) then 'Current'   
											  else '' end) Duration,  
											 concat(ud1.FName, ' ', ud1.LName) as [CreatedByName],   
											 '' as ModifiedByName,   
											 t.id as UserTargetSettingId       
										   from TBL_ST_SalesTargetSettingMaster(nolock) m  
											inner join TBL_ST_SalesTargetSettingUserTarget(nolock) t on m.SalesTargetId = t.SalesTargetId  
											--inner join #tempUsers ru on  m.ParentId = @ParentId  
											-- and 1 = ( case when @ParentId = @UserId then 1 when t.UserId = ru.User_Id then 1 else 0 end)  
											left join User_Detail ud1(nolock) on m.CreatedBy = ud1.User_ID     	
											left join #tempAchievedData v on 1  = (case   
											 when m.TargetFor = 'team' and t.SalesTargetId = v.SalesTargetId then 1  
											 when m.TargetFor = 'user' and t.SalesTargetId = v.SalesTargetId and t.UserId = v.UserId then 1  
											 else 0 end  )    
											left join TBL_UA_TeamMaster(nolock) z on 1 = (case when m.TargetFor = 'team' then 1 else 0 end ) and z.TeamCode = m.TeamCodes and z.Active = 1  
											left join User_Detail(nolock) u on 1 = (case when m.TargetFor = 'user' then 1 else 0 end ) and u.User_ID = t.UserId  
										  where m.ParentId = @ParentId   and ( case when @TargetType = 0 then '1' else m.TargetType  end = case when @TargetType = 0 then '1' else     @TargetType end )
										   and 1 = ( case   
											  when @ParentId = @UserId then 1   
											  when t.UserId in (select User_Id from  #tempUsers)then 1   
											 else 0 end)   
										   and ( m.TargetFromDate between @FromDate and @ToDate or m.TargetToDate between @FromDate and @ToDate /*t.ToDate*/ )  
										   and 1 = (case   
											 when ISNULL(@FilterText, '')  = '' then 1   
											 when m.TargetFor = 'team' and z.TeamName like '%'+ @FilterText+ '%' then 1   
											 when m.TargetFor = 'user' and u.User_Login like '%'+ @FilterText+ '%' then 1   
											 else 0 end  
											)  
										 ) t where t.SNo between @StartPoint and @EndPoint 

						--INSERT INTO MySMSReportCache.[dbo].[tbl_SalesTarget_Archive] 
						--	(
							
