---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
CREATE   PROC [dbo].[usp_Insert_shortcort_keyword]    
@M_ID bigint,        
@User_ID int,-- frm big int 19-08-2010     
@Shortcode nvarchar(50),    
@Keyword nvarchar(50),    
@Message nvarchar(1000)  
           
AS          
    Insert into Shortcode_keyword (M_ID,[User_ID],Shortcode,Keyword,Message,type) values(@M_ID,@User_ID,@Shortcode,@Keyword,@Message,'Pending')





