SET QUOTED_IDENTIFIER ON

---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
  
CREATE   PROC [dbo].[usp_Insert_shortcort_keyword_for_AdminOnly] --10043,3377,542425,'SIL','Thank you for contacting us.Our executive will get back to you soon.','19/02/2010','19/08/2010'             
@M_ID bigint,                  
@User_ID int, -- frm big int 19-08-2010  
@Shortcode nvarchar(50),              
@Keyword nvarchar(50),              
@Message nvarchar(2500),  
@Fromdate varchar(100),  
@todate varchar(100)           
                     
AS                    
