-- exec [dbo].[usp_Insert_SiteVisitDetails_DataTo_Archive]

CREATE   PROCEDURE [dbo].[usp_Insert_SiteVisitDetails_DataTo_Archive] 

AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	SET NOCOUNT ON;

	DECLARE @userid BIGINT;
    DECLARE @currentRow INT = 1;  -- Variable to track the current row in the temporary table
    DECLARE @totalRows INT;       -- Variable to store the total number of rows to process

    -- Create a temporary table to store the User IDs
    CREATE TABLE #UserIDs (UserID BIGINT);

    -- Insert UserIDs into the temporary table
    INSERT INTO #UserIDs (UserID)
    SELECT UserId
    FROM Mysms.dbo.TBL_ET_GeoEntityCheckInOut (NOLOCK)
	WHERE UserId IS NOT NULL
    GROUP BY UserId
    ORDER BY COUNT(*) DESC;
	
    -- Get the total number of rows
    SELECT @totalRows = COUNT(*) FROM #UserIDs;

-- Loop through each User_ID using a WHILE loop
    WHILE @currentRow <= @totalRows
BEGIN
BEGIN TRY
			-- Use a CTE to calculate ROW_NUMBER() and select the current UserID
				WITH CTE_UserIDs AS (
					SELECT UserID, ROW_NUMBER() OVER (ORDER BY UserID) AS RowNum
					FROM #UserIDs
				)
				SELECT @userid = UserID
				FROM CTE_UserIDs
				WHERE RowNum = @currentRow;

   
			Declare 
					@fromdate DATE = NULL,       
					@todate   DATE = NULL,
					@Offset int = 0,
					@PageSize int = 10;  


			Declare @Currentdate  DATE  = GETDATE();  -- Today's date
			--SET @fromdate      = DATEADD(DAY, -30, @Currentdate); -- 30 days before today
			--SET @todate  = @Currentdate;
			
			--SET @fromdate  = DATEADD(DAY, -1, @Currentdate); -- 1 day before today		

			IF NOT EXISTS ( 
					SELECT 1 
					FROM MySMSReportCache.[dbo].[tbl_SiteVisitDetails_Archive](NOLOCK)
					WHERE UserId = @userid
				)
				BEGIN

			   declare @ParentId bigint = 0;
		       select @ParentId  = ParentID from User_Detail(nolock) where User_Id = @userid

		drop table if exists #tempUsers   
		create table #tempUsers(User_ID bigint, Name nvarchar(255), Image nvarchar(255))  
		insert into #tempUsers(User_ID, Name, Image)  
		exec Use_GetUserDetails @UserID = @userid 

		declare @StartPoint int = ( @Offset + 1 ), @EndPoint int = ( @Offset + @PageSize )
		print concat('@StartPoint => ', @StartPoint, ' @EndPoint => ', @EndPoint)

				declare @sqlQuery nvarchar(max) =  concat(N'select * from  ( select ',
				N'geco.SNo, geco.TotalRecords, geco.PhysicalAppointmentId, phap.Title, phap.StartDate, phap.EndDate, ',
				N'case when FORMAT( TRY_CAST(phap.StartDate AS DATETIME), ''dd-MMM-yyyy'' ) = FORMAT( ',
					N'TRY_CAST(phap.EndDate AS DATETIME), ''dd-MMM-yyyy'' ) then FORMAT( TRY_CAST(phap.StartDate AS DATETIME),  ''dd-MMM-yyyy'' ) ',
					N'else FORMAT( TRY_CAST(phap.StartDate AS DATETIME),  ''dd-MMM-yyyy'' ) + '' '' + FORMAT( TRY_CAST(phap.EndDate AS DATETIME),  ''DD-MMM-YYYY'' ',
				  N') end ScheduleDate, ',
				N'FORMAT(TRY_CAST(phap.StartDate AS DATETIME), ''hh:mm tt'') StartDateIn, ',
				N'FORMAT(TRY_CAST(phap.EndDate AS DATETIME), ''hh:mm tt'') EndDateOut, ',
				N'FORMAT(TRY_CAST(geco.CheckIn AS DATETIME), ''hh:mm tt'') CheckIn, ',
				N'FORMAT(TRY_CAST(geco.CheckOut AS DATETIME), ''hh:mm tt'') CheckOut, ',
				N'geco.LatitudeIn, geco.LongitudeIn, geco.LatitudeOut, geco.LongitudeOut, geco.RemarksIn, geco.RemarksOut, ',
				N'isnull(phcm.Remarks, '''') AppointmentRemarks, isnull(phap.OutcomesId, 0) OutcomesId, ',
				N'isnull(uocm.OutcomeName, '''') OutcomeName, isnull(phap.CompleteAddress, '''') CompleteAddress, ',
				N'isnull(phap.Status, '''') PhysicalAptStatus, isnull(phap.CompletedOn, '''') CompletedOn, ',
				N'goem.GeoEntityId, goem.GeoEntityName, goem.GeoEntityType, goem.Mobile, goem.EmailId, ',
				N'phap.GeoEntitySiteId, ',
				N'(case when goem.GeoEntityType = ''lead'' then isnull( ( select top 1 ul.LeadNo from ',
						N'UserLeads(nolock) ul where ul.Id = goem.EntityId ), 0 ) else 0 end ) LeadNo, ',
				N'(case when goem.GeoEntityType = ''enquiry'' then isnull(( select top 1 ue.EnquiryId from ',
						  N'UserEnquiry(nolock) ue where ue.EnquiryId = goem.EntityId), 0) else 0 end) EnquiryId, ',
				  N'concat( udpa.FName, '' '', isnull(udpa.LName, '''')) UserName, ',
				  N'udpa.Image, udpa.ProfilePictureName, phap.AssignedTo, ',
				  N'concat( udpaassignto.FName, '' '', isnull(udpaassignto.LName, '''')) AssignedUserName, ',
				  N'udpaassignto.Image AssignedImage, udpa.User_Login,',
				  N'udpaassignto.ProfilePictureName AssignToProfilePictureName, ',
				  N'dbo.fn_TBL_ET_PhysicalCollebratorUM_PhyId(geco.PhysicalAppointmentId, ''Collaborator'') UserCollebratorList, ',
				  N'dbo.fn_TBL_ET_PhysicalCollebratorUM_PhyId(geco.PhysicalAppointmentId, ''FieldExecutive'') FieldExecutivelist ',
				N'from ( select * from ( select ',
						N'row_number() over( partition by (select null) order by g.GeoEntityCheckId desc ) as SNo, ',
						N'count(1) over() as TotalRecords, g.PhysicalAppointmentId, g.UserId, g.CheckIn, ',
						N'g.CheckOut, g.LatitudeIn, g.LongitudeIn, g.LatitudeOut, g.LongitudeOut, g.RemarksIn, g.RemarksOut ',
					N'from TBL_ET_GeoEntityCheckInOut (nolock) g ',
					N'inner join #tempUsers tu on g.UserId = tu.User_Id ',
						N'where g.ParentId = ', @ParentId,') ) p where p.SNo between ', @StartPoint, ' and ', @EndPoint,
				  N') geco ',
				N'inner join User_detail(nolock) udpa on geco.UserId = udpa.User_Id ',
				N'inner join TBL_ET_PhysicalAppointment(nolock) phap on geco.PhysicalAppointmentId = phap.PhysicalAppointmentId ',
				N'inner join TBL_ET_GeoEntityMaster(nolock) goem on goem.GeoEntityId = phap.GeoEntityId ',
				N'left join TBL_ET_PhyAppointComment (nolock) phcm on phap.PhysicalAppointmentId = phcm.PhysicalAppointmentId ',
				N'left join tbl_tsk_UserOutcomeMaster (nolock) uocm on phap.OutcomesId = uocm.Id ',
				N'left join User_detail(nolock) udpaassignto on phap.AssignedTo = udpaassignto.User_Id ',
			N') t ')

			  CREATE TABLE #TempGeoEntityData (
					SNo INT,
					TotalRecords INT,
					PhysicalAppointmentId INT,
					Title NVARCHAR(MAX),
					StartDate DATETIME,
					EndDate DATETIME,
					ScheduleDate NVARCHAR(MAX),
					StartDateIn NVARCHAR(20),
					EndDateOut NVARCHAR(20),
					CheckIn NVARCHAR(20),
					CheckOut NVARCHAR(20),
					LatitudeIn FLOAT,
					LongitudeIn FLOAT,
					LatitudeOut FLOAT,
					LongitudeOut FLOAT,
					RemarksIn NVARCHAR(MAX),
					RemarksOut NVARCHAR(MAX),
					AppointmentRemarks NVARCHAR(MAX),
					OutcomesId INT,
					OutcomeName NVARCHAR(MAX),
					CompleteAddress NVARCHAR(MAX),
					PhysicalAptStatus NVARCHAR(MAX),
					CompletedOn NVARCHAR(MAX),
					GeoEntityId INT,
					GeoEntityName NVARCHAR(MAX),
					GeoEntityType NVARCHAR(MAX),
					Mobile NVARCHAR(MAX),
					EmailId NVARCHAR(MAX),
					GeoEntitySiteId INT,
					LeadNo INT,
					EnquiryId INT,
					UserName NVARCHAR(MAX),
					Image NVARCHAR(MAX),
					ProfilePictureName NVARCHAR(MAX),
					AssignedTo INT,
					AssignedUserName NVARCHAR(MAX),
					AssignedImage NVARCHAR(MAX),
					User_Login NVARCHAR(200),
					AssignToProfilePictureName NVARCHAR(MAX),
					UserCollebratorList NVARCHAR(MAX),
					FieldExecutivelist NVARCHAR(MAX)
				);

				INSERT into #TempGeoEntityData
				EXEC sp_executesql @sqlQuery;
			    -- start data insert into cache tables

				INSERT INTO MySMSReportCache.[dbo].[tbl_SiteVisitDetails_Archive] 
				(		   
						   [TotalRecords]
						  ,[PhysicalAppointmentId]
						  ,[Title]
						  ,[StartDate]
						  ,[EndDate]
						  ,[StartDateIn]
						  ,[EndDateOut]
						  ,[ScheduleDate]
						  ,[CheckIn]
						  ,[CheckOut]
						  ,[LatitudeIn]
						  ,[LongitudeIn]
						  ,[LatitudeOut]
						  ,[LongitudeOut]
						  ,[RemarksIn]
						  ,[RemarksOut]
						  ,[AppointmentRemarks]
						  ,[OutcomesId]
						  ,[OutcomeName]
						  ,[CompleteAddress]
						  ,[PhysicalAptStatus]
						  ,[CompletedOn]
						  ,[GeoEntityId]
						  ,[GeoEntityName]
						  ,[GeoEntityType]
						  ,[LeadNo]
						  ,[EnquiryId]
						  ,[Mobile]
						  ,[EmailId]
						  ,[GeoEntitySiteId]
						  ,[UserName]
						  ,[User_Login]
						  ,[ProfilePictureName]
						  ,[UserCollebratorList]
						  ,[FieldExecutivelist]
						  ,[AssignedTo]
						  ,[AssignedUserName]
						  ,[AssignToProfilePictureName]
						  ,[UserId]
						  ,[ParentId]
				)
					SELECT
						   TotalRecords
						  ,PhysicalAppointmentId
						  ,Title
						  ,StartDate
						  ,EndDate
						  ,StartDateIn
						  ,EndDateOut
						  ,ScheduleDate
						  ,CheckIn
						  ,CheckOut
						  ,LatitudeIn
						  ,LongitudeIn
						  ,LatitudeOut
						  ,LongitudeOut
						  ,RemarksIn
						  ,RemarksOut
						  ,AppointmentRemarks
						  ,OutcomesId
						  ,OutcomeName
						  ,CompleteAddress
						  ,PhysicalAptStatus
						  ,CompletedOn
						  ,GeoEntityId
						  ,GeoEntityName
						  ,GeoEntityType
						  ,LeadNo
						  ,EnquiryId
						  ,Mobile
						  ,EmailId
						  ,GeoEntitySiteId
						  ,UserName
						  ,User_Login
						  ,ProfilePictureName
						  ,UserCollebratorList
						  ,FieldExecutivelist
						  ,AssignedTo
						  ,AssignedUserName
						  ,AssignToProfilePictureName
