/* ============================================================
   Procedure: [dbo].[usp_Insert_SiteVisitList_DataTo_Archive]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON




-- select * from MySMSReportCache.[dbo].[tbl_SiteVisitList_Cache]  select * from MySMSReportCache.[dbo].[tbl_SiteVisitList_Archive]

   --TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_SiteVisitList_Cache];  TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_SiteVisitList_Archive];

-- exec [dbo].[usp_Insert_SiteVisitList_DataTo_Archive]

CREATE   PROCEDURE [dbo].[usp_Insert_SiteVisitList_DataTo_Archive] 

AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	SET NOCOUNT ON;

	DECLARE @userid BIGINT;
    DECLARE @currentRow INT = 1;  -- Variable to track the current row in the temporary table
    DECLARE @totalRows INT;       -- Variable to store the total number of rows to process

    -- Create a temporary table to store the User IDs
    CREATE TABLE #UserIDs (UserID BIGINT);

    -- Insert UserIDs into the temporary table
    INSERT INTO #UserIDs (UserID)
    SELECT UserId
    FROM Mysms.dbo.TBL_ET_GeoEntityCheckInOut (NOLOCK)
	WHERE UserId IS NOT NULL
    GROUP BY UserId
    ORDER BY COUNT(*) DESC;
	
    -- Get the total number of rows
    SELECT @totalRows = COUNT(*) FROM #UserIDs;

-- Loop through each User_ID using a WHILE loop
    WHILE @currentRow <= @totalRows
BEGIN
BEGIN TRY
			-- Use a CTE to calculate ROW_NUMBER() and select the current UserID
				WITH CTE_UserIDs AS (
					SELECT UserID, ROW_NUMBER() OVER (ORDER BY UserID) AS RowNum
					FROM #UserIDs
				)
				SELECT @userid = UserID
				FROM CTE_UserIDs
				WHERE RowNum = @currentRow;

   
			Declare 
					@fromdate DATE = NULL,       
					@todate   DATE = NULL,
					@UserIdTeamLst varchar(500) = ''; 


			Declare @Currentdate  DATE  = GETDATE();  -- Today's date
			SET @fromdate      = DATEADD(DAY, -9130, @Currentdate); -- 30 days before today
			SET @todate  = @Currentdate;
			
			--SET @fromdate  = DATEADD(DAY, -1, @Currentdate); -- 1 day before today		
			--SET @fromdate  = DATEADD(DAY, -1, @Currentdate); -- 1 day before today		
			IF NOT EXISTS ( 
					SELECT 1 
					FROM MySMSReportCache.[dbo].[tbl_SiteVisitList_Archive](NOLOCK)
					WHERE UserId = @userid
				)
				BEGIN

			    Declare @ParentId bigint , @IsAdmin bit 
				Select @IsAdmin = IsAdmin, @ParentId = ParentId from User_Detail(NOLOCK) where User_ID = @UserId  					

			declare @tbluser table (User_ID bigint,Name varchar(100), Image varchar(100))
				if(@IsAdmin = 1)
					begin
						set @UserId = 0;
						insert into @tbluser
						exec Use_GetUserDetails @ParentId
					end
					else
					Begin
						insert into @tbluser
						exec Use_GetUserDetails @UserId
					End

				select @UserIdTeamLst=isnull(STRING_AGG(User_ID,','),'') From @tbluser

			    -- start data insert into cache tables

				INSERT INTO MySMSReportCache.[dbo].[tbl_SiteVisitList_Archive] 
				(		   
						   [TotalRecords]
						  ,[UserName]
						  ,[Image]
						  ,[ProfilePictureName]
						  ,[User_Login]
						  ,[UserFullName]
						  ,[ManagerName]
						  ,[ManagerImage]
						  ,[ManagerProfilePictureName]
						  ,[Designation]
						  ,[City]
						  ,[User_Id]
						  ,[NoOfSiteVisited]
						  ,[ParentId]
						  ,[CheckIn]
						  ,[CheckOut]
						  ,[UserId]
				)
					Select count(User_Id) over() as TotalRecords, * from ( 
				 Select Concat(ud.FName, ' ', isnull(ud.LName, '')) + '(' + ud.User_Login + ')' UserName, ud.Image, ud.ProfilePictureName, 
				 ud.User_Login,Concat(ud.FName, ' ', isnull(ud.LName, '')) [UserFullName],
				 (udpa.FName + ' ' + udpa.LName) ManagerName, udpa.Image ManagerImage, udpa.ProfilePictureName ManagerProfilePictureName, 
				 '' Designation, ud.City, ud.User_Id, 
				isnull((Select count(GeoEntityCheckId) from TBL_ET_GeoEntityCheckInOut(nolock) tege
				where tege.UserId = ud.User_Id 
				and ((Month(cast(tege.CheckIn as date)) =  Month(cast(@FromDate as date)) and 
				 Year(cast(tege.CheckIn as date)) = Year(cast(@FromDate as date)))
				or (Month(cast(tege.CheckOut as date)) = Month(cast(@ToDate as date)) and 
				Year(cast(tege.CheckOut as date)) = Year(cast(@ToDate as date))))),0) NoOfSiteVisited,
				@ParentId as parentid,
				(Select TOP 1 cast(tege.CheckIn as date) from TBL_ET_GeoEntityCheckInOut(nolock) tege where tege.UserId = ud.User_Id) as CheckInDate,
				(Select TOP 1 cast(tege.CheckOut as date) from TBL_ET_GeoEntityCheckInOut(nolock) tege where tege.UserId = ud.User_Id) as CheckOutDate,
				@userid as Userid
				From User_Detail (nolock) ud 
				inner join User_detail(nolock) udpa on ud.ParentId = udpa.User_Id 
				where ud.User_Id in (select [value] from dbo.fn_Split(@UserIdTeamLst, ',')) 
				 )t						
					
				-- end data insert into cache tables


END
END TRY
BEGIN CATCH
exec usp_InsertErrorInfo
END CATCH
-- Move to the next row
        SET @currentRow = @currentRow + 1;
END

-- Clean up the temporary table
    DROP TABLE #UserIDs;
		
END



GO

