/* ============================================================
   Procedure: [dbo].[usp_insert_sms_rabbitmq_process]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_insert_sms_rabbitmq_process] --43,153900906
@queueid bigint,@batchid bigint
as
begin
declare @count int,@lastapiresponse nvarchar(max)
select @count=count(1) from sms_rabbitmq_process(nolock) where queueid= @queueid and batchid=@batchid
select top 1 @lastapiresponse=api_response from sms_rabbitmq_process(nolock) where queueid= @queueid and batchid=@batchid and isnull(api_response,'')<>''
order by id desc

select @lastapiresponse=isnull(@lastapiresponse,'')
print @lastapiresponse
if @count>50
begin
update sms_rabbitmq_process set is_dlq=1,error_description='Forcibly marked dlq on Reaching count 50' where queueid=@queueid
and batchid=@batchid
end
if exists (select 1 from sms_rabbitmq_process(nolock) where queueid= @queueid and batchid=@batchid and is_dlq=1 and @lastapiresponse='')
begin
select 0 as id,@count as count,@lastapiresponse LastResponse
end
else
begin
insert into sms_rabbitmq_process(queueid,batchid)
select @queueid,@batchid
select scope_identity() as id,@count+1 as count ,@lastapiresponse LastResponse
end
end



