/* ============================================================
   Procedure: [dbo].[Usp_Insert_SMSUrl_Link]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[Usp_Insert_SMSUrl_Link]          
(          
@link_id bigint ,          
@BatchId bigint ,       
@Page_nm varchar(50),                       
@tbl SMSUrl_Link READONLY      
)          
as          
begin          
        
select *,ROW_NUMBER() over (order by user_id) srn  into #tmpfl from @tbl        
declare @min int, @max int        
select @min = MIN(srn), @max = MAX(srn) from #tmpfl        
while @min <= @max        
begin        
 declare @url as varchar(max), @user_id bigint        
 select @url = long_url,@user_id = user_id from #tmpfl where srn = @min        
 if not exists(select 1 from dbo.link_orgUrl where org_url=@url)        
 begin        
  insert into dbo.link_orgUrl(org_url,user_id) select @url, @user_id        
 end        
 set @min= @min+1         
end        
if @link_id > 0          
delete from dbo.Link_smsUrl_dtl            
 where ProcessUrl_Id = @link_id          
        
          
          
          
insert into dbo.Link_smsUrl_dtl          
(BatchId, short_url, longurl,Parentid,Page_nm  )          
select @BatchId, short_url, long_url, user_id,@Page_nm     
from @tbl          
        
        
if SCOPE_IDENTITY() > 0        
 select 'Record Saved' msg ,SCOPE_IDENTITY() rslt       
 else        
 select 0 rslt, 'error in save' msg        
end          
        
        
--R20190205120525707        
--R20190205120924903 


GO

