						N'dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, ''', @FromDate, ''', ''', @ToDate, ''', ''HalfDays'') HalfDays,  ',
						N'dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, ''', @FromDate, ''', ''', @ToDate, ''', ''WeekOff'') WeeklyOffDays,  ',
						N'dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, ''', @FromDate, ''', ''', @ToDate, ''', ''TotalLeave'') OnLeaveDays,  ',
						N'dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, ''', @FromDate, ''', ''', @ToDate, ''', ''TotalDays'') TotalDays,  ',
						N'dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, ''', @FromDate, ''', ''', @ToDate, ''', ''LateSignin'') InLateDays,  ',
						N'dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, ''', @FromDate, ''', ''', @ToDate, ''', ''OutEarlyDays'') OutEarlyDays, ',
						N'dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, ''', @FromDate, ''', ''', @ToDate, ''', ''Totalminutes'') TotalAttendanceTime, ',
						--N'dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, ''', @FromDate, ''', ''', @ToDate, ''', ''NumberOfBreaks'') NumberOfBreaks, ',
