/* ============================================================
   Procedure: [dbo].[usp_Insert_SuperResellerNew]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_Insert_SuperResellerNew]                      
@User_ID int,   -- frm big int 19-08-2010                                 
@Domain nvarchar(50),    
@IsVirtualCredits bit 
AS                        
declare @M_ID nvarchar(12)                                   
set @M_ID=(select m_id from User_Detail where [user_id]=@User_ID)               
if exists(select * from Reseller_Detail where   domain=@Domain)                        
begin                        
select 'Domain Name Already Exists'                        
end                        
else                     
begin                    
                     
insert into Reseller_Detail (M_ID,[User_ID],Domain) values(@M_ID,@User_ID,@Domain)                      
update User_Detail set Type=1,HasVirtualCredits= @IsVirtualCredits,ParentSuperResellerId = @User_ID,IsSuperReseller = 1  where [user_id]=@User_ID 
update user_detail set HasVirtualCredits= @IsVirtualCredits where ParentSuperResellerId = @User_ID           
--update Credit_Details set Validity=99999,FromDate=getdate(),ToDate=getdate()+99999  where m_id=@M_ID and user_id=@User_ID                
select 'Super-Reseller Registered Succsessfully'                    
end   
  
    
    
    
    
    
    


GO

/* ============================================================
   Procedure: [dbo].[Usp_Insert_Tbl_ST_SalesActivityMaster_New]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE Usp_Insert_Tbl_ST_SalesActivityMaster_New  
(      
@TblRefId [bigint] NULL,      
@TblRefName [nvarchar](200) NULL,      
@Amount [numeric](18,2) NULL,      
@RecordDate [datetime] null,      
@InvoiceNo [nvarchar](200) NULL,    
@ProductId [bigint] NULL = 0,    
@PipelineId [bigint] NULL = 0,    
@UserId [bigint] NULL,      
@ParentId [bigint] NULL    
)  
as                
  SET NOCOUNT ON                             
  BEGIN TRY                             
Begin                
  
Declare @iInvoiceNo bit = 0  
Declare @iInvoiceRaised bit = 0  
Declare @iInvoicePaid bit = 0  
Declare @iProductId bit = 0    
Declare @iPipelineId bit = 0  
  
select top 1 @iInvoiceNo = Invoices, @iInvoiceRaised = iInvoiceRaised, @iInvoicePaid = IInvoicePaid,   
@iProductId = Conversions, @iPipelineId = Pipelines from [dbo].[TBL_ST_SalesTargetSettingMaster] stt  
 inner join [dbo].[TBL_ST_SalesTargetSettingChild] std on stt.SalesTargetId = std.SalesTargetId  
 where std.UserId = @UserId and (Cast(@RecordDate as datetime) between Cast(stt.TargetFromDate as datetime) and Cast(stt.TargetToDate as datetime))  
  
Declare @iStatuus bit = 0  
 if(@InvoiceNo !='' and @iInvoiceNo = 1)  
 Begin  
 set @iStatuus = 1  
 End  
 if(@ProductId > 0  and @iProductId = 1)  
 Begin  
 set @iStatuus = 1  
 End  
 if(@PipelineId > 0  and @iPipelineId = 1)  
 Begin  
 set @iStatuus = 1  
 End  
if(@iStatuus = 1)  
Begin  
if not exists(select 1 from Tbl_ST_SalesActivityMaster(nolock) where TblRefId = @TblRefId and TblRefName = @TblRefName)      
 Begin      
  insert into Tbl_ST_SalesActivityMaster (TblRefId, TblRefName, Amount, RecordDate, InvoiceNo, projectId, pipelineId, IsActive, UserId, ParentId, CreatedDate)      
  values (@TblRefId, @TblRefName, @Amount, @RecordDate, @InvoiceNo, @ProductId, @PipelineId, 1, @UserId, @ParentId, getdate())      
      
 select 'Saved successfully' [Status]      
 End      
 else       
 Begin      
 select 'Already exists' [Status]      
 End      
end    
else  
 Begin      
 select 'Not Saved' [Status]      
 End      
End  
  
 END TRY         
BEGIN CATCH         
    
 DECLARE @ErrorMessage NVARCHAR(4000);         
 SELECT @ErrorMessage = ERROR_MESSAGE();         
 RAISERROR (@ErrorMessage, 16, 1);         
END CATCH 



GO

/* ============================================================
   Procedure: [dbo].[Usp_Insert_Tbl_ST_SalesActivityMasterNew]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_Insert_Tbl_ST_SalesActivityMasterNew]      
(          
	@TblRefId [bigint] NULL,          
	@TblRefName [nvarchar](200) NULL,          
	@Amount [numeric](18,2) NULL,          
	@RecordDate [datetime] null,          
	@InvoiceNo [nvarchar](200) NULL,        
	@ProductIds [nvarchar](1000) = NULL,        
	@PipelineId [bigint] = 0,        
	@UserId [bigint] NULL,          
	@ParentId [bigint] NULL,   
	@LeadNo [bigint] NULL  
)     
as                    
SET NOCOUNT ON                                 
BEGIN TRY                                 
	begin 
		
		--declare 
		--	@TblRefId [bigint]  = 1500,          
		--	@TblRefName [nvarchar](200)  = 'invoices',          
		--	@Amount [numeric](18,2)  = 15000.00,          
		--	@RecordDate [datetime]  = getdate(),          
		--	@InvoiceNo [nvarchar](200) = 'DIVY-RT-OFFER -53827 -I2024-001/2024-2025/432',        
		--	@ProductIds [nvarchar](1000) = '{}',        
		--	@PipelineId [bigint] = 0,        
		--	@UserId [bigint]  = 40508,          
		--	@ParentId [bigint]  = 31871,   
		--	@LeadNo [bigint]  = 59316  
  
		Declare @iInvoiceNo bit = 0      
		Declare @iInvoiceRaised bit = 0      
		Declare @iInvoicePaid bit = 0      
		Declare @iProductId bit = 0        
		Declare @iPipelineId bit = 0      
		Declare @SalesTargetId bigint = 0      
		Declare @TargetProductIds nvarchar(1000) = ''    
		Declare @TargetPipelineIds nvarchar(1000) = ''    
		Drop Table IF EXISTS #tempSalesTarget 
	
		drop table if exists #agentUserId
		create table #agentUserId(
			SalesTargetId bigint,
			UserId bigint,
			StartDate datetime,
			EndDate datetime
		)

		insert into #agentUserId(SalesTargetId, UserId, StartDate, EndDate)
		select m.SalesTargetId, t.UserId, t.FromDate, t.ToDate from TBL_ST_SalesTargetSettingMaster(nolock) m inner join
			TBL_ST_SalesTargetSettingUserTarget(nolock) t on m.SalesTargetId = t.SalesTargetId
				where t.ParentId = @ParentId and m.TargetFor = 'user'

		;WITH SplitUserDetailCTE AS (
			SELECT id, SalesTargetId, FromDate, ToDate, ParentId,
				JSON_VALUE(value, '$.IsActive') AS SplitUserDetail_IsActive,
				JSON_VALUE(value, '$.UserId') AS SplitUserDetail_UserId
			FROM TBL_ST_SalesTargetSettingUserTarget(nolock)
			CROSS APPLY OPENJSON(UserSplitDetail) 
		)
		insert into #agentUserId(SalesTargetId, UserId, StartDate, EndDate)
		SELECT m.SalesTargetId, SplitUserDetail_UserId, FromDate, ToDate FROM SplitUserDetailCTE s
			inner join TBL_ST_SalesTargetSettingMaster(nolock) m on s.SalesTargetId = m.SalesTargetId
				where s.ParentId = @ParentId and m.TargetFor = 'team' and s.SplitUserDetail_IsActive = 'true'

		select ROW_NUMBER() Over (order by stt.SalesTargetId) RowNo, stt.SalesTargetId,  Invoices,  iInvoiceRaised,     
			IInvoicePaid,  Conversions,  Pipelines,  TargetProductIds, TargetPipelineIds into #tempSalesTarget
			from [dbo].[TBL_ST_SalesTargetSettingMaster] (nolock) stt        
			inner join #agentUserId (nolock) std on stt.SalesTargetId = std.SalesTargetId        
			where std.UserId = @UserId and (Cast(@RecordDate as date) between Cast(std.StartDate as date) and Cast(std.EndDate as date))      

		--select ROW_NUMBER() Over (order by stt.SalesTargetId) RowNo,   stt.SalesTargetId,  Invoices,  iInvoiceRaised,   
		-- IInvoicePaid,  Conversions,  Pipelines,  TargetProductIds ,   
		-- TargetPipelineIds INTO #tempSalesTarget from [dbo].[TBL_ST_SalesTargetSettingMaster] (nolock) stt      
		-- inner join [dbo].[TBL_ST_SalesTargetSettingChild] (nolock) std on stt.SalesTargetId = std.SalesTargetId      
		--where std.UserId = @UserId and 
		--	(Cast(getdate() as datetime) between Cast(stt.TargetFromDate as datetime) and Cast(stt.TargetToDate as datetime))    
      

		if (@TblRefName='LeadInteractionHistory' and ISNULL(@ProductIds, '') = '')
		begin
			select @ProductIds = ProductsJson from LeadInteractionHistory(nolock) where ID = @TblRefId
		end


		Declare @min int = 1 , @max int
		Select @min=MIN(RowNo), @max= MAX(RowNo) from #tempSalesTarget 

		while (@min<=@max)
		BEGIN
			select  @SalesTargetId = SalesTargetId, @iInvoiceNo = Invoices, @iInvoiceRaised = iInvoiceRaised,   
			@iInvoicePaid = IInvoicePaid, @iProductId = Conversions, @iPipelineId = Pipelines, @TargetProductIds = TargetProductIds ,   
			@TargetPipelineIds = TargetPipelineIds from #tempSalesTarget where RowNo=@min 
			Declare @iStatus bit = 0     
		    
			-- if(@InvoiceNo !='' and @iInvoiceNo = 1)      
			-- Begin      
			-- set @iStatus = 1      
			-- End      
			-- if(@ProductIds != '' or @iProductId = 1)      
			-- Begin    
		    
			---- select TargetPeriodId from [dbo].[TBL_ST_SalesTargetSettingMaster] sttt where sttt.SalesTargetId = @SalesTargetId and TargetProductIds = @ProductIds     
			-- set @iStatus = 1      
			-- End     
			-- if(@PipelineId > 0 and @iPipelineId = 1 and @TargetPipelineIds > 0)    
			-- Begin     
			-- set @iStatus = 1      
			-- End     
			if @TblRefName='invoices' and @iInvoiceNo=1
			begin
				set @iStatus = 1   
			end

			if @TblRefName='LeadPipelineMapping' and @iPipelineId=1
			begin
				set @iStatus = 1   
			end

			if @TblRefName='LeadInteractionHistory' and @iProductId=1
			begin
				set @iStatus = 1   
			end

			if(@iStatus = 1)     
			begin     
				if not exists(select 1 from Tbl_ST_SalesActivityMaster(nolock) where TblRefId = @TblRefId and TblRefName = @TblRefName)          
				begin  
		 
					insert into Tbl_ST_SalesActivityMaster (TblRefId, TblRefName, Amount, RecordDate, InvoiceNo, projectIds, 
						pipelineId, LeadNo, IsActive, UserId, ParentId, CreatedDate,SalesTargetID, ProductsJson)   
					select @TblRefId, @TblRefName, @Amount, @RecordDate, @InvoiceNo, @ProductIds, 
						@PipelineId, @LeadNo, 1, @UserId, @ParentId, getdate(),@SalesTargetId, @ProductIds
				
		
					---MOD10.07.2024 by satya sharma  starts  
					DECLARE @saleActivityId int ,@cur_date datetime =  getdate();      
					SELECT @saleActivityId = SCOPE_IDENTITY() ;  
					EXEC usp_sm_InsertscoringRecord 'PointsActivity' , @cur_date , @UserID , 'Tbl_ST_SalesActivityMaster' , @saleActivityId ;  
  
				-- select 'Saved successfully' [Status]          
				end          
				-- else           
				-- Begin          
				---- select 'Already exists' [Status]          
				-- End          
			end        
			--else      
			-- Begin          
			-- select 'Not Saved' [Status]          
			-- End     
			set @min= @min+1
		end

	end
      
END TRY             
BEGIN CATCH
	DECLARE @ErrorMessage NVARCHAR(4000);             
	SELECT @ErrorMessage = ERROR_MESSAGE();             
	RAISERROR (@ErrorMessage, 16, 1);             
END CATCH     



