Declare @iInvoiceRaised bit = 0        
Declare @iInvoicePaid bit = 0        
Declare @iProductId bit = 0          
Declare @iPipelineId bit = 0        
Declare @SalesTargetId bigint = 0        
Declare @TargetProductIds nvarchar(1000) = ''      
Declare @TargetPipelineIds nvarchar(1000) = ''      
Drop Table IF EXISTS #tempSalesTarget   
   

    Declare @QueryProducts nvarchar(max) = ''
    DECLARE @ProductsJson NVARCHAR(4000) = ''

	  begin try
        
		if(isnull(@ProductIds,'') != '')
		 begin
	   	    set @QueryProducts =  CONCAT('select @ProductsJsonTemp = (  
		       select t.Name as ProductName from (select [value] from fn_split('''+ isnull(@ProductIds,'''') +''',''#'')) as tbl
			     join 
			   tbl_ProductMaster_', cast(@ParentID as nvarchar(50)) ,' as t with(nolock)
			     on tbl.[value] = t.ProductID
		     	
			     FOR JSON AUTO          
		        ,INCLUDE_NULL_VALUES  
			  )','')
		
		  exec sp_executesql @QueryProducts, N'@ProductsJsonTemp nvarchar(4000) out ', @ProductsJson out  
         end 

	   end try
	   begin catch
	      exec usp_InsertErrorInfo
	   end catch  
    



select ROW_NUMBER() Over (order by stt.SalesTargetId) RowNo,   stt.SalesTargetId,  Invoices,  iInvoiceRaised,     
 IInvoicePaid,  Conversions,  Pipelines,  TargetProductIds ,     
 TargetPipelineIds INTO #tempSalesTarget from [dbo].[TBL_ST_SalesTargetSettingMaster] (nolock) stt        
 inner join [dbo].[TBL_ST_SalesTargetSettingChild] (nolock) std on stt.SalesTargetId = std.SalesTargetId        
where std.UserId = @UserId and     
(Cast(getdate() as datetime) between Cast(stt.TargetFromDate as datetime) and Cast(stt.TargetToDate as datetime))      
        
Declare @min int = 1 , @max int  
  
Select @min=MIN(RowNo), @max= MAX(RowNo) from #tempSalesTarget   
  
 while (@min<=@max)  
 BEGIN  
  select  @SalesTargetId = SalesTargetId, @iInvoiceNo = Invoices, @iInvoiceRaised = iInvoiceRaised,     
  @iInvoicePaid = IInvoicePaid, @iProductId = Conversions, @iPipelineId = Pipelines, @TargetProductIds = TargetProductIds ,     
  @TargetPipelineIds = TargetPipelineIds from #tempSalesTarget where RowNo=@min   
  Declare @iStatus bit = 0       
        
  -- if(@InvoiceNo !='' and @iInvoiceNo = 1)        
  -- Begin        
  -- set @iStatus = 1        
  -- End        
  -- if(@ProductIds != '' or @iProductId = 1)        
  -- Begin      
        
  ---- select TargetPeriodId from [dbo].[TBL_ST_SalesTargetSettingMaster] sttt where sttt.SalesTargetId = @SalesTargetId and TargetProductIds = @ProductIds       
  -- set @iStatus = 1        
  -- End       
  -- if(@PipelineId > 0 and @iPipelineId = 1 and @TargetPipelineIds > 0)      
  -- Begin       
  -- set @iStatus = 1        
  -- End       
   if @TblRefName='invoices' and @iInvoiceNo=1  
   BEGIN  
   set @iStatus = 1     
   END  
   if @TblRefName='LeadPipelineMapping' and @iPipelineId=1  
   BEGIN  
   set @iStatus = 1     
   END  
   if @TblRefName='LeadInteractionHistory' and @iProductId=1  
   BEGIN  
   set @iStatus = 1     
   END  
  if(@iStatus = 1)       
  Begin       
  if not exists(select 1 from Tbl_ST_SalesActivityMaster(nolock) where TblRefId = @TblRefId and TblRefName = @TblRefName)            
   Begin            
    insert into Tbl_ST_SalesActivityMaster (TblRefId, TblRefName, Amount, RecordDate, InvoiceNo, projectIds, pipelineId, LeadNo, IsActive, UserId, ParentId,
	      CreatedDate,SalesTargetID, ProductsJson )       
    values (@TblRefId, @TblRefName, @Amount, @RecordDate, @InvoiceNo, @ProductIds, @PipelineId, @LeadNo, 1, @UserId, @ParentId, getdate(),@SalesTargetId
	        , @ProductsJson)       
              
	---MOD10.07.2024 by satya sharma  starts
	DECLARE @saleActivityId int ,@cur_date datetime =  getdate();    
	SELECT @saleActivityId = SCOPE_IDENTITY() ;
	EXEC usp_sm_InsertscoringRecord 'SalesActivity' , @cur_date , @UserID , 'Tbl_ST_SalesActivityMaster' , @saleActivityId ;

  -- select 'Saved successfully' [Status]            
   End            
  -- else             
  -- Begin            
  ---- select 'Already exists' [Status]            
  -- End            
  end          
  --else        
  -- Begin            
  -- select 'Not Saved' [Status]            
  -- End       
  set @min= @min+1  
 End  
  
END  
        
 END TRY               
BEGIN CATCH               
          
 DECLARE @ErrorMessage NVARCHAR(4000);               
 SELECT @ErrorMessage = ERROR_MESSAGE();               
 RAISERROR (@ErrorMessage, 16, 1);               
END CATCH 



