/* ============================================================
   Procedure: [dbo].[usp_Insert_UserTracking_DataTo_Archive]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



-- select * from MySMSReportCache.[dbo].[tbl_UserTrackingReport_Cache]  select * from MySMSReportCache.[dbo].[tbl_UserTrackingReport_Archive]

   --TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_UserTrackingReport_Cache];  TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_UserTrackingReport_Archive];

-- exec [dbo].[usp_Insert_UserTracking_DataTo_Archive] 

CREATE   PROCEDURE [dbo].[usp_Insert_UserTracking_DataTo_Archive] 

AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	SET NOCOUNT ON;

	DECLARE @userid BIGINT;
    DECLARE @currentRow INT = 1;  -- Variable to track the current row in the temporary table
    DECLARE @totalRows INT;       -- Variable to store the total number of rows to process

    -- Create a temporary table to store the User IDs
    CREATE TABLE #UserIDs (UserID BIGINT);

    -- Insert UserIDs into the temporary table
    INSERT INTO #UserIDs (UserID)
    SELECT UserId
    FROM Mysms.dbo.TBL_ET_UserLocationTracking_Archived (NOLOCK)
	WHERE UserId IS NOT NULL
    GROUP BY UserId
    ORDER BY COUNT(*) DESC;
	
    -- Get the total number of rows
    SELECT @totalRows = COUNT(*) FROM #UserIDs;

-- Loop through each User_ID using a WHILE loop
    WHILE @currentRow <= @totalRows
BEGIN
BEGIN TRY
			-- Use a CTE to calculate ROW_NUMBER() and select the current UserID
				WITH CTE_UserIDs AS (
					SELECT UserID, ROW_NUMBER() OVER (ORDER BY UserID) AS RowNum
					FROM #UserIDs
				)
				SELECT @userid = UserID
				FROM CTE_UserIDs
				WHERE RowNum = @currentRow;

   
			Declare 
					@fromdate DATE = NULL,       
					@todate   DATE = NULL, 
					@SearchText nvarchar(255) = null,
					@Offset int = 0,
					@PageSize int = 100000,
					@UserIds nvarchar(max) =  '';


			Declare @Currentdate  DATE  = GETDATE();  -- Today's date
			-- SET @fromdate      = DATEADD(DAY, -30, @Currentdate); -- 30 days before today
			SET @fromdate  = DATEADD(DAY, -9130, @Currentdate); -- 1 day before today	
			SET @todate  = @Currentdate;
			
			-- Only process if the UserID has not been processed already
			    declare @ParentId nvarchar(50) = 0, @IsAdmin BIT = 0;		
				select @ParentId = ParentID from User_Detail(nolock) where User_Id = @UserId

				declare @StartPoint int  = (@Offset + 1), @Endpoint int = (@Offset + @PageSize)

				if(ISNULL(@UserIds, '') =  '') begin set @UserIds = '' end

					drop table if exists #tempSelectedUser
					create table #tempSelectedUser ( UserId bigint )
					insert into #tempSelectedUser(UserId) select [value] from string_split(@UserIds, ',') where [value] > 0

				drop table if exists #tempUsers  
				create table #tempUsers(User_ID bigint, Name nvarchar(255), Image nvarchar(255))  
				insert into #tempUsers(User_ID, Name, Image)  
				exec Use_GetUserDetails @UserID = @UserId 

				declare @sqlQuery nvarchar(max) = concat(N'select ',
							N't.[SNo], ',
							N't.[Total], ',
							N't.[Date], ',
							N't.[Name], ',
							N't.[Time], ',
							N't.[Event], ',
							N't.[Address], ',
							N't.[Distance] ,',
							N't.UserFullName,',
							N't.User_Login ',
						N'from ( select  ',
							N'ROW_NUMBER() over(partition by (select null) order by t.LocationDateTime desc) [SNo], ',
							N'count(1) over( order by (select null) desc) [Total], ',
							N'format(t.LocationDateTime, ''dd-MMM-yyy'') as [Date], ',
							N'concat(u.User_Login, '' ('', u.FName, '' '', u.LName, '')'') as [Name], ',
							N' u.User_Login, isnull(u.FName,'''') + '' '' + isnull(u.LName,'''')  as [UserFullName] ,',
							N'format(t.LocationDateTime, ''HH:mm:ss'') as ''Time'', ',
							N't.MovementCode as [Event], ',
							N't.Address, ',
							N'(TRY_CONVERT(decimal(18, 3), t.Distance) /1000) as [Distance] ',
							N'from  ( ',
								N'select LocationDateTime, MovementCode, Address, Distance, UserId  ',
								N' from TBL_ET_UserLocationTracking(nolock) l inner join #tempUsers tu on l.UserId = tu.User_ID ',
								N' where cast(l.LocationDateTime as date) between ''', @FromDate, ''' and ''', @ToDate , '''',
								N' union ',
								N'select LocationDateTime, MovementCode, Address, Distance, UserId  ',
								N' from TBL_ET_UserLocationTracking_Archived(nolock) l inner join #tempUsers tu on l.UserId = tu.User_ID ',
								N' where cast(l.LocationDateTime as date) between ''', @FromDate, ''' and ''', @ToDate , '''',
							N') t ',
							N'inner join #tempUsers tu on t.UserId = tu.User_ID ',
							iif(LEN(@UserIds) > 0, 'inner join #tempSelectedUser su on t.UserId = su.UserId ', ''),
							N'inner join User_Detail(nolock) u on t.UserId = u.User_ID ',
						N'where  ',
							--t.UserId in (
							--	select User_ID from User_Detail(nolock) where ParentID = @ParentId
							--) and
						N'cast(t.LocationDateTime as date) between ''', @FromDate, ''' and ''', @ToDate , '''',
						N' and 1 = ( case  ',
							N'when isnull(''', @SearchText, ''', '''') = '''' then 1 ',
							N'when u.User_Login like ''%', @SearchText, '%'' then 1 ',
							N'when u.FName like ''%', @SearchText, '%''  then 1 ',
							N'when u.LName like ''%', @SearchText, '%''  then 1 ',
							N'when t.Address like ''%', @SearchText, '%''  then 1 ',
							N'else 0 end )  ',
						N') t where t.SNo between ', @StartPoint, ' and ', @Endpoint )

					drop table if exists #TempUserTrackingReport  
					CREATE TABLE #TempUserTrackingReport (
						SNo nvarchar(50),
						Total NVARCHAR(50),
						[Date] DateTime,
						[Name] NVARCHAR(50),
						[Time] Time(7),
						[Event] NVARCHAR(50),
						[Address] NVARCHAR(500),
						[Distance] NVARCHAR(50),
						UserFullName NVARCHAR(50),
						User_Login NVARCHAR(50)
					);

					INSERT INTO #TempUserTrackingReport
					EXEC sp_executesql @sqlQuery;

			IF NOT EXISTS (
                SELECT 1 
                FROM MySMSReportCache.dbo.[tbl_UserTrackingReport_Archive] (NOLOCK)
                WHERE UserId = @userid
            )
            BEGIN	
				-- start data insert into archive table

				INSERT INTO MySMSReportCache.[dbo].[tbl_UserTrackingReport_Archive] 
				(		   
						   [SNo]
						  ,[Total]
						  ,[Date]
						  ,[Name]
						  ,[Time]
						  ,[Event]
						  ,[Address]
						  ,[Distance]
						  ,[User_Login]
						  ,[UserFullName],
						  [UserId],
						  [ParentId]
				)
				 SELECT 
						SNo, 
						Total, 
						[Date],
						[Name],
						[Time], 
						[Event],
						[Address],
						[Distance], 
						User_Login,
						UserFullName,
						@userid,
						@ParentId
						FROM #TempUserTrackingReport; 

			-- end data insert into archive table

			-- Clean up the temporary table
				DROP TABLE #TempUserTrackingReport;
        END
		END TRY
		BEGIN CATCH
		exec usp_InsertErrorInfo
        END CATCH
-- Move to the next row
        SET @currentRow = @currentRow + 1;
END
-- Clean up the temporary table
    DROP TABLE #UserIDs;
		
END



GO

