/* ============================================================
   Procedure: [dbo].[usp_Insert_VisitReport_DataTo_Archive]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



-- select * from MySMSReportCache.[dbo].[tbl_VisitReport_Cache]  select * from MySMSReportCache.[dbo].[tbl_VisitReport_Archive]

   --TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_VisitReport_Cache];  TRUNCATE TABLE MySMSReportCache.[dbo].[tbl_VisitReport_Archive];

-- exec [dbo].[usp_Insert_VisitReport_DataTo_Archive]

CREATE   PROCEDURE [dbo].[usp_Insert_VisitReport_DataTo_Archive] 

AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	SET NOCOUNT ON;

	DECLARE @userid BIGINT;
    DECLARE @currentRow INT = 1;  -- Variable to track the current row in the temporary table
    DECLARE @totalRows INT;       -- Variable to store the total number of rows to process

    -- Create a temporary table to store the User IDs
    CREATE TABLE #UserIDs (UserID BIGINT);

    -- Insert UserIDs into the temporary table
    INSERT INTO #UserIDs (UserID)
    SELECT UserId
    FROM Mysms.dbo.v_VRAttendance (NOLOCK)
	WHERE UserId IS NOT NULL
    GROUP BY UserId
    ORDER BY COUNT(*) DESC;
	
    -- Get the total number of rows
    SELECT @totalRows = COUNT(*) FROM #UserIDs;

-- Loop through each User_ID using a WHILE loop
    WHILE @currentRow <= @totalRows
BEGIN
BEGIN TRY
			-- Use a CTE to calculate ROW_NUMBER() and select the current UserID
				WITH CTE_UserIDs AS (
					SELECT UserID, ROW_NUMBER() OVER (ORDER BY UserID) AS RowNum
					FROM #UserIDs
				)
				SELECT @userid = UserID
				FROM CTE_UserIDs
				WHERE RowNum = @currentRow;

   
			Declare 
					@fromdate DATE = NULL,       
					@todate   DATE = NULL,
					@PageSize int = 0,
					@StartPoint int = 0, 
					@Endpoint int = 0,
					@SearchText varchar(200) = '',
					@UserIds nvarchar(max) = ''; 


			Declare @Currentdate  DATE  = GETDATE();  -- Today's date
			--SET @fromdate      = DATEADD(DAY, -5000, @Currentdate); -- 30 days before today
			--SET @todate  = @Currentdate;
			
			--SET @fromdate  = DATEADD(DAY, -1, @Currentdate); -- 1 day before today		
			IF NOT EXISTS ( 
					SELECT 1 
					FROM MySMSReportCache.[dbo].[tbl_VisitReport_Archive] (NOLOCK)
					WHERE UserId = @userid
				)
				BEGIN

			    declare @ParentId bigint  
			select @ParentId = ParentID from User_Detail(nolock) u where u.User_ID = @userid  

				drop table if exists #userTable
				create table #userTable( User_ID bigint,Name nvarchar(100), Image nvarchar(100) )

				insert into #userTable
				exec Use_GetUserDetails @userid

				if(ISNULL(@UserIds, '') =  '') begin set @UserIds = '' end

				drop table if exists #tempSelectedUser
				create table #tempSelectedUser ( UserId bigint )
				insert into #tempSelectedUser(UserId) select [value] from string_split(@UserIds, ',')

				declare @sqlQuery nvarchar(max) = concat(N'select distinct ',
						N'count(1) over (partition by a.ParentId order by a.ParentId ) as [TotalCount], ',
						N'format(a.AttandanceDate, ''dd-MMM-yyyy'') as [AttandanceDate], ',
						N'a.UserId, ',
						N'format(a.SignIn, ''hh:mm tt'') as [SignIn], ',
						N'format(a.SignOut, ''hh:mm tt'') as [SignOut], ',
						N'(dbo.udf_GetTerritoryDefination(a.UserId)) AS [TerritoryDefination], ',
						N'u.User_ID as [AgentId], ',
						N'concat(u.User_Login, ''('', u.FName, '' '', u.LName, '')'') as [AgentName], ',
						N'c.CheckInCount, ',
						N'c.CheckOutCount, ',
						--N'rm.UserRoleMappingCode, ',
						N'r.RoleName, ',
						--N'ROUND(TRY_CONVERT(decimal(18, 3), isnull((select top 1 Distance from TBL_ET_UserLocationTracking(nolock) ',
						--N'where cast(LocationDateTime as date) = cast(a.AttandanceDate as date) and UserId = a.UserId ',
						--N'order by cast(LocationDateTime as datetime) desc ), 0)) /1000, 3) as [Distance], ',
						N'ROUND(TRY_CONVERT(decimal(18, 3), isnull((select Max(cast(isnull(Distance, 0) as float)) from TBL_ET_UserLocationTracking(nolock) t ',
						N'where cast(t.LocationDateTime as date) = cast(a.AttandanceDate as date) and t.UserId = a.UserId ), 0)) /1000, 3) as [Distance], ',
						N'format(TRY_CONVERT(DATETIME, a.SignOut - a.SignIn), ''HH:mm:ss'') as [Hours] ',
						N'from v_VRAttendance a ',
						N'inner join User_Detail(nolock) u on a.UserId = u.User_ID ',
						iif(LEN(@UserIds) > 0, 'inner join #tempSelectedUser su on u.User_Id = su.UserId ', ''),
						N'left join TBL_UA_UserRoleMappingMaster(nolock) rm on u.User_ID = rm.UserId and rm.Active = 1 ',
						N'left join TBL_UA_RoleMaster(nolock) r on rm.RoleCode = r.RoleCode ',
						N'and rm.ParentID = r.ParentId and rm.Active = 1 ',
						N'left join v_VRACheckInOutCount(nolock) c on a.UserId = c.UserId and a.AttandanceDate = c.CheckInOutDate ',
						N'where a.ParentId = ', @ParentId, 
						N'and 1 = (case ',
						N'when u.User_Login like ''%', @SearchText, '%'' then 1 ',
						N'when u.FName like ''%', @SearchText, '%'' then 1 ',
						N'when u.LName like ''%', @SearchText, '%'' then 1 ',
						N'when u.Mobile like ''%', @SearchText, '%'' then 1 ',
						N'when u.EMail like ''%', @SearchText, '%'' then 1 ',
						N'else 0 end ) ')



						DROP TABLE IF EXISTS #TempTable;
							CREATE TABLE #TempTable (
								TotalCount INT,
								AttandanceDate NVARCHAR(50),
								UserId BIGINT,
								SignIn NVARCHAR(20),
								SignOut NVARCHAR(20),
								TerritoryDefination NVARCHAR(MAX),
								AgentId BIGINT,
								AgentName NVARCHAR(200),
								CheckInCount INT,
								CheckOutCount INT,
								RoleName NVARCHAR(100),
								Distance DECIMAL(18, 3),
								Hours NVARCHAR(20)
							); 

				
						INSERT INTO #TempTable
						EXEC sp_executesql @sqlQuery;

				-- start data insert into archive table

				INSERT INTO MySMSReportCache.[dbo].[tbl_VisitReport_Archive] 
				(		   
						   [TotalCount]
						  ,[AttandanceDate]
						  ,[UserId]
						  ,[SignIn]
						  ,[SignOut]
						  ,[TerritoryDefination]
						  ,[AgentId]
						  ,[AgentName]
						  ,[CheckInCount]
						  ,[CheckOutCount]
						  ,[RoleName]
						  ,[Distance]
						  ,[Hours]
						  ,[ParentId]
				)
				  SELECT 
						TotalCount,
						AttandanceDate,
						UserId,
						SignIn,
						SignOut,
						TerritoryDefination,
						AgentId,
						AgentName,
						CheckInCount,
						CheckOutCount,
						RoleName,
						Distance,
						Hours,
						@ParentId
					FROM #TempTable;   

			-- end data insert into archive table


			-- Clean up the temporary table
				DROP TABLE #TempTable;

END
END TRY
BEGIN CATCH
exec usp_InsertErrorInfo
END CATCH
-- Move to the next row
        SET @currentRow = @currentRow + 1;
END

-- Clean up the temporary table
    DROP TABLE #UserIDs;
		
END



