   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_Insert_WA_CommerceContactInfo] (    
 @WACommerceContactId BIGINT = 0   
 ,@CompanyName [varchar](300)  
 ,@Address [varchar](400)  
 ,@CompanyType [varchar](50)  
 ,@CustomerCareName [varchar](50)  
 ,@CustomerCareMobileNo [varchar](30)  
 ,@CustomerCareLandLine [varchar](20)  
 ,@CustomerCareEmailId [varchar](100)  
 ,@GrievanceOfficerName [varchar](50)  
 ,@GrievanceOfficerMobileNo [varchar](20)  
 ,@GrievanceOfficerLandLine [varchar](20)  
 ,@GrievanceOfficerEmailId [varchar](100)  
 ,@UserId [bigint] NULL    
 ,@ParentId [bigint] NULL    
 ,@CreatedBy BIGINT = NULL   
 )
AS    
SET NOCOUNT ON    
    
BEGIN TRY    
 BEGIN 
 DECLARE @sqlquery NVARCHAR(MAX);
     DECLARE @existsFlag varchar(50);
 if not exists(select * from tbl_WA_CommerceContactInfo (nolock) where CompanyName = @CompanyName and ParentId = @ParentId)  
 --IF (@WACommerceContactId = 0)    
  BEGIN    
 --if exists(select CompanyType from MySMSConversations.dbo.channeltokens (nolock) where ParentId = @ParentId and ChannelId = 2 and CompanyType != @CompanyType)  
 SET @sqlquery = 
    'SELECT TOP 1 CompanyType 
     FROM channeltokens (NOLOCK)
     WHERE ParentId = ' + CAST(@ParentId AS NVARCHAR) + ' 
     AND ChannelId = 2 
     AND CompanyType != ''' + @CompanyType + '''';

EXEC usp_clr_GetRemoteStringValue 
    @sqlquery,
    @retval = @existsFlag OUT;

IF (@existsFlag IS NOT NULL)
Begin  
   --update MySMSConversations.dbo.channeltokens set CompanyType = @CompanyType where ChannelId = 2 and ParentId = @ParentId 
   SET @sqlquery = 
    'UPDATE channeltokens 
     SET CompanyType = ''' + @CompanyType + ''' 
     WHERE ChannelId = 2 
     AND ParentId = ' + CAST(@ParentId AS NVARCHAR);

EXEC usp_clr_ExecuteRemoteQuery  @sqlquery;

   print 'Type'
  End  
 --if exists(select CompanyType from MySMSConversations.dbo.channeltokens (nolock) where ParentId = @ParentId and ChannelId = 2 and company_name != @CompanyName)  

 SET @sqlquery = 
    'SELECT TOP 1 CompanyType 
     FROM channeltokens (NOLOCK)
     WHERE ParentId = ' + CAST(@ParentId AS NVARCHAR) + ' 
     AND ChannelId = 2 
     AND company_name != ''' + @CompanyName + '''';

EXEC usp_clr_GetRemoteStringValue  @sqlquery, @retval = @existsFlag OUT;

IF (@existsFlag IS NOT NULL)
  Begin  
   --update MySMSConversations.dbo.channeltokens set company_name = @CompanyName where ChannelId = 2 and ParentId = @ParentId  
    SET @sqlquery = 
    'UPDATE channeltokens 
     SET company_name = ''' + @CompanyName + ''' 
     WHERE ChannelId = 2 
     AND ParentId = ' + CAST(@ParentId AS NVARCHAR);

EXEC usp_clr_ExecuteRemoteQuery  @sqlquery;
   print 'Company'
  End
 --if exists(select CompanyType from MySMSConversations.dbo.channeltokens (nolock) where ParentId = @ParentId and ChannelId = 2 and address != @Address)  
 SET @sqlquery = 
    'SELECT TOP 1 company_name 
     FROM channeltokens (NOLOCK)
     WHERE ParentId = ' + CAST(@ParentId AS NVARCHAR) + ' 
     AND ChannelId = 2 
     AND company_name != ''' + @CompanyName + '''';

EXEC usp_clr_GetRemoteStringValue  @sqlquery, @retval = @existsFlag OUT;

IF (@existsFlag IS NOT NULL)
  Begin  
   --update MySMSConversations.dbo.channeltokens set address = @Address where ChannelId = 2 and ParentId = @ParentId  
   SET @sqlquery = 
    'UPDATE channeltokens 
     SET address = ''' + @Address + ''' 
     WHERE ChannelId = 2 
     AND ParentId = ' + CAST(@ParentId AS NVARCHAR);

EXEC usp_clr_ExecuteRemoteQuery  @sqlquery;
   print 'address'
  End
 INSERT INTO tbl_WA_CommerceContactInfo(CompanyName, CustomerCareName, CustomerCareMobileNo, CustomerCareLandLine, CustomerCareEmailId, GrievanceOfficerName,  
 GrievanceOfficerMobileNo, GrievanceOfficerLandLine, GrievanceOfficerEmailId, UserId, ParentId, IsActive, CreatedBy, CreatedDate)    
   VALUES (@CompanyName, @CustomerCareName, @CustomerCareMobileNo, @CustomerCareLandLine, @CustomerCareEmailId, @GrievanceOfficerName  
 ,@GrievanceOfficerMobileNo, @GrievanceOfficerLandLine, @GrievanceOfficerEmailId, @UserId, @ParentId, 1, @CreatedBy, GETDATE())
 
   --SELECT 'Saved Successfully.' [Status], (select top 1 LifeTimeAccessToken from MySMSConversations.dbo.tbl_WA_ProductCatalogeType(nolock) where parentid = @ParentId) token, (select top 1 ConnType from MySMSConversations.dbo.tbl_WA_ProductCatalogeType(nolock) where parentid = @ParentId) ConnType
   SET @sqlquery = 
    'SELECT ''Saved Successfully.'' AS [Status], 
            (SELECT TOP 1 LifeTimeAccessToken 
             FROM tbl_WA_ProductCatalogeType (NOLOCK) 
             WHERE ParentId = ' + CAST(@ParentId AS NVARCHAR) + ') AS token, 
            (SELECT TOP 1 ConnType 
             FROM tbl_WA_ProductCatalogeType (NOLOCK) 
             WHERE ParentId = ' + CAST(@ParentId AS NVARCHAR) + ') AS ConnType';

EXEC usp_clr_ExecuteRemoteQuery  @sqlquery;


  END
  ELSE    
  BEGIN    
 
 --SELECT 'Already Exists' [Status], (select top 1 LifeTimeAccessToken from MySMSConversations.dbo.tbl_WA_ProductCatalogeType(nolock) where parentid = @ParentId) token, (select top 1 ConnType from MySMSConversations.dbo.tbl_WA_ProductCatalogeType(nolock) where parentid = @ParentId) ConnType
SET @sqlquery = 
    'SELECT ''Already Exists'' AS [Status], 
            (SELECT TOP 1 LifeTimeAccessToken 
             FROM tbl_WA_ProductCatalogeType (NOLOCK) 
             WHERE ParentId = ' + CAST(@ParentId AS NVARCHAR) + ') AS token, 
            (SELECT TOP 1 ConnType 
             FROM tbl_WA_ProductCatalogeType (NOLOCK) 
             WHERE parentid = ' + CAST(@ParentId AS NVARCHAR) + ') AS ConnType';

EXEC usp_clr_ExecuteRemoteQuery  @sqlquery;

-- (select top 1 token from MySMSConversations.dbo.channeltokens(nolock) where parentid = @ParentId) 
 
  END    
 END    
END TRY    
    
BEGIN CATCH    
 DECLARE @ErrorMessage NVARCHAR(4000);    
    
 SELECT @ErrorMessage = ERROR_MESSAGE();    
    
 RAISERROR (    
   @ErrorMessage    
   ,16    
   ,1    
   );    
END CATCH    
    
DECLARE @rowJson NVARCHAR(MAX) = (    
  SELECT *    
  FROM tbl_WA_CommerceContactInfo WITH(NOLOCK)    
  WHERE WACommerceContactId = @WACommerceContactId    
  FOR JSON AUTO    
   ,INCLUDE_NULL_VALUES    
  )
    
IF @rowJson IS NOT NULL    
BEGIN    
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId    
  ,@Activity_type = 'Inst_WA_CommContInfo'    
  ,@ActionType = 'I'    
  ,@RowJson = @rowJson    
  ,@Table_name = 'tbl_WA_CommerceContactInfo'    
END    



