/* ============================================================
   Procedure: [dbo].[usp_insert_web_site_content]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROC [dbo].[usp_insert_web_site_content]          
@M_ID bigint,              
@User_ID int,              
@Type nvarchar(50),              
@Content nvarchar(4000),
@Image_Url nvarchar(50)               
as             
declare @mid bigint,@rid bigint   
begin    
          
set @rid=(select reseller_id from reseller_detail where m_id=@m_id and user_id=@User_ID)     
    
if exists(select 'x' from   WebSite_Content where M_ID=@rid and  User_ID= @User_ID and Type=@Type)    
begin    
update WebSite_Content set Content=case when @Content='' then Content else @Content end ,Sliderimage=case when @Image_Url='' then Sliderimage else @Image_Url end where M_ID=@rid and Type=@Type    
end     
else    
begin          
insert into WebSite_Content              
(M_ID,User_ID,Type,Content,Sliderimage)              
values              
(@rid,@User_ID,@Type,@Content,@Image_Url)    
end    
end



GO

