SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE  PROCEDURE [dbo].[USP_Insert_webFormap_respTbl_ForDynamic]

(

    @EntryId BIGINT = NULL,

    @FormId BIGINT = NULL,

    @IsDynamic BIT = 0,

    @tbl tbl_webapiType READONLY

)

AS

BEGIN

    SET NOCOUNT ON;
 
    -- Temp table to clean webapi values

    DECLARE @CleanedTbl TABLE (

        apiid BIGINT,

        webapi NVARCHAR(MAX),

        method INT,

        baseapi NVARCHAR(MAX)

    );
 
    -- Clean webapi: remove all #...# placeholders

    INSERT INTO @CleanedTbl (apiid, webapi, method, baseapi)

    SELECT 

        apiid,

        -- Remove all patterns like #text#

        CASE 

            WHEN webapi IS NOT NULL AND CHARINDEX('#', webapi) > 0 THEN

                dbo.fn_RemoveHashPlaceholders(webapi)

            ELSE 

                webapi

        END AS webapi,

        method,

        baseapi

    FROM @tbl;
 
    -- Insert cleaned data

    INSERT INTO dbo.webFormap_respTbl(apiid, EntryId, FormId, webapi, method, baseapi, IsDynamic)

    SELECT 

        apiid,

        @EntryId,

        @FormId,

        webapi,

        CASE 

            WHEN method = 1 THEN 0

            WHEN method = 0 THEN 1

            ELSE method

        END AS method,

        baseapi,

        @IsDynamic

    FROM @CleanedTbl;
 
    SELECT @@ROWCOUNT;

END




GO

