,@DescriptionTwo nvarchar(500)
,@DisplayUrlPath1 varchar(50)
,@DisplayUrlPath2 varchar(50)
,@opt int    
,@Status bit                
as                        
begin                   
if(@opt=1)
begin
declare @campaignid bigint=(select CampAd_id from tblAdGroup where AdwordGroupId=@AdwordGroupId and IsDeleted=0)   
declare @InProcess bit=0

if(@campaignid is null)
begin
	select @campaignid=CampAd_id from tblAdGroup where AdGroupId=@AdwordGroupId and IsDeleted=0
end

if(LEN(@campaignid)>8 and LEN(@AdwordAdsId)>8 and LEN(@AdwordGroupId)>8)
begin
	set @InProcess=1
end
           
--declare @campaignid bigint=(select CampAd_id from tblAdGroup where AdGroupId=@AdwordGroupId)              
          
--Insert Into tblAds(campaignid,User_ID,AdwordAdsId,AdwordGroupId,BusinessName,Description1,Description2,DisplayUrl)values (@campaignid,@User_ID,@AdwordAdsId,@AdwordGroupId,@BusinessName,@Description1,@Description2,@DisplayUrl)                       
--                       select 'success' as result, IDENT_CURRENT('tblAds') as LeadId              
              
Insert Into tblAds
(campaignid,User_ID,AdwordAdsId,AdwordGroupId,BusinessName,Description1,Description2,DisplayUrl,Status,InProcess,Headline3,DescriptionTwo,DisplayUrlPath1,DisplayUrlPath2)
values
(@campaignid,@User_ID,@AdwordAdsId,@AdwordGroupId,@BusinessName,@Description1,@Description2,@DisplayUrl,@Status,@InProcess,@Headline3, @DescriptionTwo, @DisplayUrlPath1, @DisplayUrlPath2)

select 'success' as result, IDENT_CURRENT('tblAds') as LeadId                  

end  
              
if(@opt=2)
begin
      
--update  tblAds set campaignid=@campaignid, Description1=@Description1,Description2=@Description2,DisplayUrl=@DisplayUrl where  AdsId =@AdwordAdsId                
--and User_Id=@User_ID       
      
update  tblAds set Description1=@Description1,Description2=@Description2,DisplayUrl=@DisplayUrl where  AdsId =@AdwordAdsId                
and User_Id=@User_ID  and IsDeleted=0 
               
End   
end



