/* ============================================================
   Procedure: [dbo].[usp_InsertAI_Token_Usage]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_InsertAI_Token_Usage]
    @TokenType     NVARCHAR(100),
    @TotalTokenUsage INT,
    @Remarks       NVARCHAR(MAX),
    @UserId        BIGINT,
    @PromptJson    NVARCHAR(MAX),
    @ResponseJson  NVARCHAR(MAX)
AS
BEGIN
    SET NOCOUNT ON;
    --declare     @TokenType     NVARCHAR(100)='Audio',
    --@TotalTokenUsage INT=4001,
    --@Remarks       NVARCHAR(MAX)='Balance deducted for AI Usage',
    --@UserId        BIGINT=34594,
    --@PromptJson    NVARCHAR(MAX)='',
    --@ResponseJson  NVARCHAR(MAX)=''



    DECLARE 
        @InsertedId BIGINT = 0,
        @ParentId BIGINT = NULL,
        @intCredId BIGINT = 0,
        @Units_Per_Credit NUMERIC(18,4) = NULL,
        @PricePerUnit NUMERIC(18,4) = 0.0000,
        @Unit NVARCHAR(100) = NULL,
        @Cost NUMERIC(18,4) = 0.0000,
        @CreditsNeeded NUMERIC(18,4) = 0.0000,
        @credit_type INT = 23;  -- use provided credit_type (23)

    BEGIN TRY
        BEGIN TRANSACTION;

        -- Resolve parent id for the user; fallback to user id if parent not found
        SELECT @ParentId = ParentID
        FROM dbo.User_Detail WITH (NOLOCK)
        WHERE User_ID = @UserId;

        IF @ParentId IS NULL
            SET @ParentId = @UserId;

        -- Get applicable price row for this token type, prefer Parent-specific then ParentID = 0
        If exists(Select * from Price_Base_AICredits_Rate WITH (NOLOCK) WHERE Type = @TokenType AND ParentID = isnull(@ParentId, 0))
        Begin
            SELECT TOP 1 
                @Units_Per_Credit = Units_Per_Credit,
                @PricePerUnit = PricePerUnit,
                @Unit = Unit
            FROM dbo.Price_Base_AICredits_Rate WITH (NOLOCK)
            WHERE Type = @TokenType
              AND ParentID = isnull(@ParentId, 0) 
            ORDER BY ParentID DESC;  -- priority: parent-specific row first
        End
        Else
        Begin
            SELECT TOP 1 
                @Units_Per_Credit = Units_Per_Credit,
                @PricePerUnit = PricePerUnit,
                @Unit = Unit
            FROM dbo.Price_Base_AICredits_Rate WITH (NOLOCK)
            WHERE Type = @TokenType
            ORDER BY ParentID DESC;  -- priority: parent-specific row first
        End

        print concat('@TokenType: ',@TokenType)
        print concat('@UserId: ',@UserId)
        print concat('@ParentId: ',@ParentId)
        print concat('@Units_Per_Credit: ',@Units_Per_Credit)
        print concat('@PricePerUnit: ',@PricePerUnit)
        print concat('@Unit: ',@Unit)

        IF @PricePerUnit IS NULL OR @PricePerUnit = 0
        BEGIN
            RAISERROR('Price entry not found for TokenType %s', 16, 1, @TokenType);
        END

        -- Compute cost depending on Units_Per_Credit and unit type
        IF @Units_Per_Credit IS NOT NULL AND @Units_Per_Credit > 0
        BEGIN
            SET @CreditsNeeded = CEILING( CAST(@TotalTokenUsage AS FLOAT) / CAST(@Units_Per_Credit AS FLOAT) );
            SET @Cost = CAST(@CreditsNeeded * @PricePerUnit AS NUMERIC(18,4));
        END
        ELSE
        BEGIN
            IF UPPER(ISNULL(@Unit,'')) = 'MINUTE'
            BEGIN
                SET @Cost = CAST(@TotalTokenUsage * @PricePerUnit AS NUMERIC(18,4));
            END
            ELSE
            BEGIN
                SET @Cost = CAST(@TotalTokenUsage * @PricePerUnit AS NUMERIC(18,4));
            END
        END

        print concat('@CreditsNeeded: ',@CreditsNeeded)
        print concat('@Cost: ',@Cost)

        -- 1) Insert AI_Token_Usage first with NULL IntCreditId
        INSERT INTO dbo.AI_Token_Usage
            (TokenType, TotalTokenUsage, Remarks, UserId, PromptJson, ResponseJson, IntCreditId, CreatedOn)
        VALUES
            (@TokenType, @TotalTokenUsage, @Remarks, @UserId, @PromptJson, @ResponseJson, NULL, GETDATE());

        SET @InsertedId = CAST(SCOPE_IDENTITY() AS BIGINT);

        -- 2) Call deduction procedure (will produce IntCredit_Details entry and output id)
        EXEC dbo.usp_remote_deduct_or_refund_int_bal_withOutput
            @parentid = @ParentId,
            @m_id = @UserId,
            @cost_in_inr_credit = 0.0000,
            @cost_in_inr_debit  = @Cost,
            @credit_type = @credit_type,
            @remarks = @Remarks,
            @intCredId = @intCredId OUTPUT;

        -- 3) Update AI_Token_Usage row with returned IntCreditId
        UPDATE dbo.AI_Token_Usage
        SET IntCreditId = @intCredId
        WHERE Id = @InsertedId;

        COMMIT TRANSACTION;

        -- Return both IDs
        SELECT @InsertedId AS InsertedId, @intCredId AS IntCreditId;
    END TRY
    BEGIN CATCH
        IF XACT_STATE() <> 0
        BEGIN
            ROLLBACK TRANSACTION;
        END

        SELECT -1 AS InsertedId, NULL AS IntCreditId;
    END CATCH
END



GO

