   Procedure: [dbo].[usp_InsertbatchRecord]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_InsertbatchRecord
	@UserID BIGINT,
	@RandNumb BIGINT
AS
BEGIN
	INSERT INTO GetBatchRecord
	  (
	    -- BatchID -- this column value is auto-generated
	    
	    [User_id],
	    RandNum
	  )
	VALUES
	  (
	    @UserID,
	    @RandNumb
	  )
	DECLARE @BatchID BIGINT = (
	            SELECT MAX(gbr.BatchID)
	            FROM   GetBatchRecord AS gbr
	            WHERE  gbr.[User_id] = @UserID
	                   AND gbr.RandNum = @RandNumb
	        )
	
	DELETE 
	FROM   GetBatchRecord
	WHERE  [User_id] = @UserID
	
	SELECT @BatchID
END


