CREATE    procedure [dbo].[usp_insertcalculatedfields_bulk] (@multiactivity as multiactivity readonly)  
as  
begin  
declare @context nvarchar(20)=(select top 1 context from @multiactivity)          
if @context='lead'  
begin  
insert into calculated_fields_process(entity,activityid,parentid,icf_eventid)  
select Context,activityid,t.parentid,t.eventid from @multiactivity m join tbl_leadeventhistory(nolock) t on m.activityid=t.historyid  
end  
if @context='enquiry'  
begin  
insert into calculated_fields_process(entity,activityid,parentid,icf_eventid)  
select Context,activityid,t.parentid,t.eventid from @multiactivity m join tbl_enquiryeventhistory(nolock) t on m.activityid=t.historyid  
end  
  
end  


