SET QUOTED_IDENTIFIER ON


 CREATE   PROC [dbo].[Usp_InsertCampaignAndGetCampaignID] --'mkmdim',335       
 (@Name NVARCHAR(100), @UserID INT)        
  AS         
BEGIN
	IF (
	       NOT EXISTS(
	           SELECT 'x'
	           FROM   UserCampaignSettings
	           WHERE  NAME           = @Name
	                  AND UserID     = @UserID
	       )
	   )
	BEGIN
	    INSERT INTO UserCampaignSettings
	      (
	        NAME,
	        UserID,
	        IsEditable,
	        IsActive,
	        CreatedDate,
	        ModifiedDate,
	        ModifiedBy
	      )
	    VALUES
	      (
	        @Name,
	        @UserID,
	        1,
	        1,
	        GETDATE(),
	        GETDATE(),
	        @UserID
	      )
	END
	
	SELECT CampaignID AS CampaignID
	FROM   UserCampaignSettings
	WHERE  NAME           = @Name
	       AND UserID     = @UserID
END



GO

/* ============================================================
   Procedure: [dbo].[Usp_InsertCampaignDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC dbo.Usp_InsertCampaignDetails (      
 @Name NVARCHAR(100)      
 ,@UserID BigINT      
 ,@IsEditable BIT      
 ,@IsActive BIT      
 ,@CreatedBy NVARCHAR(100)      
 )      
AS      
BEGIN  
  
    DECLARE @Campaignid BIGINT 
   
    select @Name =  replace( replace(replace(trim(char(9) from isnull(@Name,'')),char(9),''),char(10),''),char(13),'')   
  
declare @parentid bigint=(select parentid from user_detail(nolock) where user_id=@userid)    
 IF (      
   NOT EXISTS (      
    SELECT 'x'      
    FROM UserCampaignSettings      
    WHERE NAME = @Name      
     AND UserID in (select User_ID  from user_detail(nolock) where parentid=@parentid)    
    )      
   )      
 BEGIN      
  INSERT INTO UserCampaignSettings (      
   NAME      
   ,UserID      
   ,IsEditable      
   ,IsActive      
   ,CreatedDate      
   ,ModifiedDate      
   ,ModifiedBy      
   )      
  VALUES (      
   @Name      
   ,@parentid      
   ,@IsEditable      
   ,@IsActive      
   ,GETDATE()      
   ,GETDATE()      
   ,@CreatedBy      
   )      
      
  SELECT 'Record Saved'      
      
   set @Campaignid  = SCOPE_IDENTITY();      
 END      
 ELSE      
 BEGIN   
  IF(      
     EXISTS (      
  SELECT 'x'      
  FROM UserCampaignSettings      
  WHERE NAME = @Name      
   AND UserID in (select User_ID  from user_detail(nolock) where parentid=@parentid and IsActive = 0)    
  )      
    )          
     begin  
       update  UserCampaignSettings set IsActive = 1 , UserID = @parentid  , ModifiedBy =  @CreatedBy ,ModifiedDate = getdate()  
            WHERE NAME = @Name     
             AND UserID in (select User_ID  from user_detail(nolock) where parentid=@parentid and IsActive = 0)    
  
   SELECT 'Record Saved'      
  
      select top 1 @Campaignid  = CampaignID from UserCampaignSettings (nolock)  
            WHERE NAME = @Name      
             AND UserID in (select User_ID  from user_detail(nolock) where parentid=@parentid)      
   
  end  
  else  
   begin  
        SELECT 'Already Exist'      
      end       
 END      
      
 DECLARE @rowJson NVARCHAR(MAX) = (      
   SELECT *      
   FROM UserCampaignSettings(NOLOCK)      
   WHERE CampaignID = @Campaignid      
   FOR JSON AUTO      
    ,INCLUDE_NULL_VALUES      
   )      
      
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID      
  ,@Activity_type = 'Inst_Cmpgn'      
  ,@ActionType = 'I'      
  ,@RowJson = @rowJson      
  ,@Table_name = 'UserCampaignSettings'      
END 


