   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_InsertCampaignMaster
	@CampaignName VARCHAR(200),
	@Applicabilty VARCHAR(MAX) ,
	@ExclusionsNumber VARCHAR(MAX),
	@InclusionsNumber VARCHAR(MAX),
	@Exclusions VARCHAR(MAX),
	@SenderID VARCHAR(100) = NULL,
	@Message VARCHAR(750) = NULL,
	@MailReplyTo VARCHAR(MAX) = NULL,
	@MailSubject VARCHAR(MAX) = NULL,
	@MailContent VARCHAR(MAX) = NULL,
	@Accounts VARCHAR(MAX),
	@IsSequential BIT,
	@SequentialCampaign NVARCHAR(MAX),
	@ResponseList VARCHAR(MAX),
	@Time INT,
	@TrackResponse VARCHAR(3),
	@ResponseShortURL VARCHAR(MAX),
	@UnsubscribePage VARCHAR(3),
	@UnsubscribeMicrositeURL VARCHAR(MAX),
	@Tags VARCHAR(MAX),
	@Createdby BIGINT,
	@ScheduleTime VARCHAR(50) = NULL,
	@IsUnicode BIT,
	@Expiry VARCHAR(50)
AS
BEGIN
	DECLARE @dtSch DATETIME 
	
	
	IF @ScheduleTime <> ''
	BEGIN
	    SET @dtSch = (CONVERT(VARCHAR(30), @ScheduleTime, 108))
	END
	
	INSERT INTO CampaignMaster
	  (
	    -- ID -- this column value is auto-generated                  
	    CampaignName,
	    Applicabilty,
	    ExclusionsNumber,
	    InclusionsNumber,
	    Exclusions,
	    SenderID,
	    [Message],
	    MailReplyTo,
	    MailSubject,
	    MailContent,
	    Accounts,
	    IsSequential,
	    SequentialCampaign,
	    ResponseList,
	    [Time],
	    TrackResponse,
	    ResponseShortURL,
	    UnsubscribePage,
	    UnsubscribeMicrositeURL,
	    Tags,
	    ScheduleTime,
	    IsActive,
	    CreatedOn,
	    Createdby,
	    IsUnicode,
	    ExpiryDate
	  )
	VALUES
	  (
	    @CampaignName,
	    @Applicabilty,
	    @ExclusionsNumber,
	    @InclusionsNumber,
	    @Exclusions,
	    @SenderID,
	    @Message,
	    @MailReplyTo,
	    @MailSubject,
	    @MailContent,
	    @Accounts,
	    @IsSequential,
	    @SequentialCampaign,
	    @ResponseList,
	    @Time,
	    @TrackResponse,
	    @ResponseShortURL,
	    @UnsubscribePage,
	    @UnsubscribeMicrositeURL,
	    @Tags,
	    @dtSch,
	    1,
	    GETDATE(),
	    @Createdby,
	    @IsUnicode,
	    @Expiry
	  )                
	SELECT 'Success'
END




