/* ============================================================
   Procedure: [dbo].[Usp_insertcartsettingvalue]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON





CREATE   PROCEDURE [dbo].[Usp_insertcartsettingvalue] @ParentID BIGINT,      
                                                @Value    VARCHAR(max),      
                                                @Step     INT,@IsDisplayPromo bit,    
                                                 @DisplayValidCoupons bit,    
                                                 @ValidFor bit,    
                                                  @ValidForDays varchar(10)=''      
AS      
  BEGIN      
      IF EXISTS (SELECT 'x'      
                 FROM   usercartsettings uc      
                 WHERE  uc.parentid = @ParentID)      
        BEGIN      
            IF @Step = 1      
              BEGIN      
                  UPDATE usercartsettings      
                  SET    aboutus = @Value      
                  WHERE  parentid = @ParentID      
              END      
            ELSE IF @Step = 2      
              BEGIN      
                  UPDATE usercartsettings      
                  SET    contactus = @Value      
                  WHERE  parentid = @ParentID      
              END      
            ELSE IF @Step = 3      
              BEGIN      
                  UPDATE usercartsettings      
                  SET    footervalue = @Value      
                  WHERE  parentid = @ParentID      
              END      
            ELSE IF @Step = 4      
              BEGIN      
                  UPDATE usercartsettings      
                  SET    ContentValue = @Value      
                  WHERE  parentid = @ParentID      
              END      
            ELSE IF @Step = 5      
              BEGIN      
                  UPDATE usercartsettings      
                  SET    TermsValue = @Value      
                  WHERE  parentid = @ParentID      
              END      
            ELSE IF @Step = 6      
              BEGIN      
                  UPDATE usercartsettings      
                  SET    PromoText = @Value,IsDisplayPromo=@IsDisplayPromo,DisplayValidCoupons=@DisplayValidCoupons,ValidFor=@ValidFor,      
                  ValidForDays=@ValidForDays WHERE  parentid = @ParentID      
              END      
        END      
      ELSE      
        BEGIN      
            IF @Step = 1      
              BEGIN      
                  insert into UserCartSettings      
                  (AboutUs,ParentID)values(@Value,@ParentID)      
              END      
            ELSE IF @Step = 2      
              BEGIN      
                  insert into UserCartSettings      
                  (contactus,ParentID)values(@Value,@ParentID)      
              END      
            ELSE IF @Step = 3      
              BEGIN      
                  insert into UserCartSettings      
                  (footervalue,ParentID)values(@Value,@ParentID)      
              END      
            ELSE IF @Step = 4      
              BEGIN      
                  insert into UserCartSettings      
                  (ContentValue,ParentID)values(@Value,@ParentID)      
              END      
            ELSE IF @Step = 5      
              BEGIN      
                  insert into UserCartSettings      
                  (TermsValue,ParentID)values(@Value,@ParentID)      
              END      
            ELSE IF @Step = 6      
              BEGIN      
                  insert into UserCartSettings      
                  (PromoText,IsDisplayPromo,ParentID,DisplayValidCoupons,ValidFor,ValidForDays)values(@Value,@IsDisplayPromo,@ParentID,@DisplayValidCoupons,@ValidFor,@ValidForDays)      
              END      
        END      
              
              
        select 'Success'      
  END  



GO

