/* ============================================================
   Procedure: [dbo].[usp_InsertClientLeadDetailsfromCRM]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_InsertClientLeadDetailsfromCRM]
	@CampaignName VARCHAR(250),
	@MobileNo VARCHAR(150),
	@TrackMicosite VARCHAR(50),
	@unsubscribeMicrosite VARCHAR(50),
	@EnqNo VARCHAR(50)
AS
BEGIN
	DECLARE @FirstName     VARCHAR(50),
	        @Email         VARCHAR(50),
	        @Address       VARCHAR(50),
	        @city          VARCHAR(50),
	        @state         VARCHAR(50)
	
	
	SELECT @FirstName = pe.Name,
	       @Address     = pe.O_Address,
	       @Email       = pe.EMail,
	       @city        = pe.city,
	       @state       = pe.[state]
	FROM   CRMDB.dbo.Pre_Enquiry AS pe
	WHERE  pe.EnqNo = @EnqNo
	
	IF @TrackMicosite <> ''
	BEGIN
	    INSERT INTO ClientLeadDetails
	      (
	        cname,
	        CampaignName,
	        FirstName,
	        Email,
	        Mobile,
	        [Address],
	        City,
	        Zip,
	        Remarks,
	        Source,
	        PName,
	        IsCallMicrosite,
	        DateCreated
	      )
	    VALUES
	      (
	        @TrackMicosite,
	        @CampaignName,
	        @FirstName,
	        @Email,
	        @MobileNo,
	        @Address,
	        @city,
	        @state,
	        '',
	        0,
	        '',
	        0,
	        GETDATE()
	      )
	END
	ELSE 
	IF @unsubscribeMicrosite <> ''
	BEGIN
	    INSERT INTO ClientLeadDetails
	      (
	        -- Id -- this column value is auto-generated
	        cname,
	        CampaignName,
	        FirstName,
	        Email,
	        Mobile,
	        [Address],
	        City,
	        Zip,
	        Remarks,
	        Source,
	        PName,
	        IsCallMicrosite,
	        DateCreated
	      )
	    VALUES
	      (
	        @unsubscribeMicrosite,
	        @CampaignName,
	        @FirstName,
	        @Email,
	        @MobileNo,
	        @Address,
	        @city,
	        @state,
	        '',
	        0,
	        '',
	        0,
	        GETDATE()
	      )
	END
	
	SELECT 'Success'
END



