/* ============================================================
   Procedure: [dbo].[Usp_insertclonedeliverycampaign]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_insertclonedeliverycampaign]                
AS                
BEGIN                
 INSERT INTO getbatchrecord                
   (                
     -- BatchID -- this column value is auto-generated                
                     
                     
                     
     [user_id],                
     randnum                
   )                
 SELECT DISTINCT Ucerm.u_id,                
        Ucerm.campaignid                
 FROM   usercampaignexecutionrecipientsmessage Ucerm   (nolock)             
 WHERE  Ucerm.iscompleted = 1                
                 
                 
                 
                 
                 
                 
                 
 SELECT DISTINCT Ucerm.u_id   AS UserID,                
        Ucerm.campaignid,                
        dbo.Fn_createbatchid(Ucerm.campaignid, Ucerm.u_id) AS BatchID,                
        LEN(Ucerm.[message])  AS MessageLen,                
        Ucerm.isunicode,                
        Ucerm.mobile                
                        
                        
                        
        INTO                     #temptable                
 FROM   usercampaignexecutionrecipientsmessage Ucerm  (nolock)                
 WHERE  Ucerm.iscompleted = 1                
                 
                 
                 
                 
                 
                 
                 
 DELETE Kd                
 FROM   getbatchrecord Kd (nolock)                 
        INNER JOIN #temptable Tt                
             ON  Tt.batchid = Kd.batchid                
                 
                 
                 
                 
                 
                 
                 
 UPDATE Kd                
 SET    Kd.batchid = Tt.batchid                
 FROM   usercampaignexecutionrecipientsmessage Kd                  
        INNER JOIN #temptable Tt                
             ON  Tt.campaignid = Kd.campaignid                
             AND Tt.userid = Kd.u_id                
 WHERE  Kd.iscompleted = 1                
                 
                 
                 
                 
                 
                 
                 
 SELECT B.userid,                
        CASE                 
             WHEN B.balance - B.credits >= 0 THEN 1                
             ELSE 0                
        END  AS ValidEntries                
                        
                        
                        
        INTO #tempmobile                
 FROM   (                
            SELECT A.userid,                
                   SUM(                
                       CAST(A.credits AS BIGINT) + CASE (A.credits % 1)                
                                                        WHEN 0 THEN 0                
                                                        ELSE 1                
                                                   END                
                   )  AS Credits,                
                   A.balance                
            FROM   (                
                       SELECT Tt.userid,                
                              (                
                                  CAST(Tt.messagelen AS DECIMAL(18, 2)) / CASE                 
                                                                               WHEN                 
                                                                                    Tt.isunicode                 
                                                                                                    
                                                                                                    
                                                                                                    
                                                                                    =                
                                                                                                    
                        
                                                                                                    
            0 THEN                 
                                                                                    160                
             ELSE                 
                                                                                    70                
                                                                          END                
                              ) * 1  AS Credits,                
                              Tt.mobile,                
                              Tt.batchid,                
                              (                
                               SELECT TOP 1 balance                
                                  FROM   credit_details (nolock)                 
                                  WHERE  USER_ID = Tt.userid                
    ORDER BY                
                                         credit_id DESC                
                              )      AS Balance                
                       FROM   #temptable Tt                
                   )     A                
            GROUP BY                
                   A.userid,                
                   A.balance                
        )       B                
                 
                 
                 
                 
                 
                 
                 
 INSERT INTO clonemessagedeliverystatus                
   (                
     -- MessageID -- this column value is auto-generated                
                     
                     
            batchid,                
     mobile,                
     [message],                
     messagestatus,                
     senderid,                
     messageinsertdate,                
     scheduleddate,                
     scheduledtime,                
     smppid,                
     u_id,                
     isunicode,                
     isdnd,                
     isairtel,                
     mobilesubset,                
     validno,                
     isprority,                
     isallowdnd,                
     dbtype                
   )                
 SELECT DISTINCT Ucerm.batchid,                
        Ucerm.mobile,                
        Ucerm.[message],                
        Ucerm.messagestatus,                
        Ucerm.senderid,                
        Ucerm.messageinsertdate,                
        CONVERT(VARCHAR, GETDATE(), 112),                
        CONVERT(VARCHAR, GETDATE(), 112),                
        Ucerm.smppid,                
        Ucerm.u_id,                
        Ucerm.isunicode,                
        Ucerm.isdnd,                
        Ucerm.isairtel,                
        Ucerm.mobilesubset,                
        Ucerm.validno,                
        Ucerm.isprority,                
        Ucerm.isallowdnd,                
        Ucerm.dbtype                
 FROM   usercampaignexecutionrecipientsmessage Ucerm   (nolock)               
        INNER JOIN #temptable Tt                
             ON  Tt.campaignid = Ucerm.campaignid                
             AND Ucerm.u_id = Tt.userid                
        INNER JOIN #tempmobile Tm                
             ON  Tm.userid = Tt.userid                
             AND validentries = 1                
 WHERE  Ucerm.mobile <> ''                
        AND Ucerm.IsCompleted = 1                
                 
                 
                 
                 
                 
                 
                 
 UPDATE Kd                
 SET    Executiontime = GETDATE(),                
        Noofrecipients = (                
            SELECT COUNT(*)                
            FROM   usercampaignexecutionrecipientsmessage Tt (nolock)                 
            WHERE  Tt.campaignid = Kd.campaignid                
                   AND Tt.parentid = Kd.parentid                
                   AND Tt.mobile <> ''             
                   AND Tt.IsCompleted = 1                
        ),                
        Batchid = Tt.batchid,                
        Ismessages = 1,                
        Isexecuted = 1                
 FROM   usercampaignexecutionhistory Kd    (nolock)              
        INNER JOIN #temptable Tt                
       ON  Tt.campaignid = Kd.campaignid                
        INNER JOIN #tempmobile Tm                
             ON  Tm.userid = Tt.userid                
             AND Validentries = 1                
 WHERE  Kd.batchid IS NULL                
                 
                 
                 
                 
                 
                 
  if OBJECT_ID('tempdb..##campaignrun') is not null   
     begin                 
 UPDATE Kd                
 SET    Kd.step3 = 1 ,Step3DateTime=GETDATE() ,        
 Step3Recipients=(select isnull(noofrecipients,0) from usercampaignexecutionhistory ud (nolock)         
 where ud.CampaignID=Kd.CampaignID and ID=(select MAX(id) from usercampaignexecutionhistory  (nolock)         
 ud2 where ud.CampaignID=ud2.CampaignID))        
 FROM   usercampaignhistory Kd join ##campaignrun c on Kd.ID=c.campaignrunid               
end   
     else  
     begin  
      UPDATE Kd                      
 SET    Kd.step3 = 1 ,Step3DateTime=GETDATE() ,              
 Step3Recipients=(select isnull(noofrecipients,0) from usercampaignexecutionhistory ud (nolock)               
 where ud.CampaignID=Kd.CampaignID and ID=(select MAX(id) from usercampaignexecutionhistory (nolock)                
 ud2 where ud.CampaignID=ud2.CampaignID))              
 FROM   usercampaignhistory Kd join usercampaignexecutionhistory uch on uch.CampaignID=kd.CampaignID where kd.ID =(select MAX(id) from  
 usercampaignhistory kd1 where kd1.CampaignID=kd.CampaignID)  
     end              
                 
                 
                 
                            
                 
 INSERT INTO getbatchrecord                
   (                
     [user_id],                
     randnum                
   )                
 SELECT TOP 1 parentid,                
        mobile                
 FROM   usercampaignexecutionrecipientsmessage  (nolock)                
 WHERE  IsCompleted = 1                
                 
                 
                 
                 
                 
                 
                 
 DECLARE @Batchidmails BIGINT                
                 
                 
                 
                 
                 
                 
                 
 SELECT @Batchidmails = MAX(batchid)                
 FROM   getbatchrecord Gbr                
                 
                 
                 
                 
                 
                 
                 
 DELETE Kd                
 FROM   getbatchrecord Kd               
 WHERE  Kd.batchid = @Batchidmails                
                 
                 
                 
                 
                 
                 
                 
 IF EXISTS (                
        SELECT *                
        FROM   usercampaignexecutionrecipientsmessage  (nolock)                
        WHERE  IsCompleted = 1                
    )                
 BEGIN                
     INSERT INTO batchemail_infos                
       (                
         -- ID -- this column value is auto-generated                
                         
                         
                         
         batchid,                
         userid,                
         sendername,                
    [message],                
         totalrecords,                
         totalprocessed,                
         processtable,                
         isprocess,                
         priority_level,                
         batchinserttime,                
         batchprocesstime,                
         scheduleddate,                
         scheduledtime,                
         templateid,                
         [route],                
         pagename,                
         isscheduled,                
         email_subject,             
         replyto,                
         amount,                
         currency                
       )                
     SELECT @Batchidmails,                
            Ucm.accountused,                
            'Campaign Execution',                
            'As promised , Your ' + CASE                 
                                         WHEN CAST(Ucm.mailreplyto AS NVARCHAR(50))                
                                                              
                                                              
                                                              
                                              <> '' THEN 'Mail'                
                                         ELSE 'SMS'                
                                    END + ' campaign  '                
                            
                            
                            
            + CAST(Ucm.campaignname AS NVARCHAR(500))                
                            
                            
                            
            +                
                            
                            
                     
            ' scheduled for <date time> is executed successfully.                                               You can log in to your & check the delivery report in the campaign history',                
            COUNT(*),                
            0,                
            0,                
            0,                
            1,                
            GETDATE(),                
            GETDATE(),                
            GETDATE(),                
            GETDATE(),                
            0,                
            0,                
            0,                
            0,                
            'Campaign execution alert',                
            '',                
            0,                
            0                
     FROM   usercampaignexecutionrecipientsmessage Tt  (nolock)                
            INNER JOIN usercampaignmaster AS Ucm  (nolock)                
                 ON  Ucm.id = Tt.campaignid                
                 AND Ucm.parentid = Tt.parentid                
     WHERE  mobile <> ''                
     GROUP BY                
            Ucm.accountused,                
            Ucm.mailreplyto,                
            Ucm.campaignname                
                     
                     
                     
                     
                     
                     
                     
     INSERT INTO clientemails                
       (                
         -- Id -- this column value is auto-generated                
                         
                         
                         
         guid,                
         email_id,                
         sentdatetime,                
         userid,                
         replyto,                
         [status],                
         batchid,                
         [message]                
       )                
     SELECT NEWID(),                
            Ucm.notificationmail,                
            GETDATE(),                
            Ucm.accountused,                
            '',                
            '',                
            @Batchidmails,                
            'As promised , Your ' + CASE                 
                                         WHEN CAST(Ucm.mailreplyto AS NVARCHAR(50))                
                                                              
                                                              
                                                              
                                              <> '' THEN 'Mail'                                                 ELSE 'SMS'                
                                    END + ' campaign  '                
                            
                            
                            
            + CAST(Ucm.campaignname AS NVARCHAR(500))                
                            
                            
                            
            +                
                            
                            
                            
            ' scheduled for <date time> is executed successfully.                                               You can log in to your & check the delivery report in the campaign history'                
     FROM   usercampaignexecutionrecipientsmessage Tt    (nolock)              
            INNER JOIN usercampaignmaster AS Ucm     (nolock)             
                 ON  Ucm.id = Tt.campaignid                
                 AND Ucm.parentid = Tt.parentid                
     WHERE  mobile <> ''                
                     
                     
                     
                     
                     
                     
                     
     INSERT INTO emailsfilter                
       (                
         mail_guid,                
         -- Mail_ID -- this column value is auto-generated                
                         
                         
                         
         mail_fromemail,                
         mail_toemail,                
         mail_subject,                
         mail_templetename,                
         messages,                
         mail_inserteddate,                
         mail_userid,                
         replyto,           
         mail_batchid,                
         mail_priority,                
         mail_scheduledate,                
         mail_attechement,                
         mail_templetebody,                
         ismonitor                
       )                
     SELECT NEWID(),                
            'contactus@email19.in',                
            A.notificationmail,                
            'Campaign execution alert',                
        '',                
            'As promised , Your ' + CASE                 
                                         WHEN CAST(A.mailreplyto AS NVARCHAR(50))                
                                                              
                                                              
                                                              
                       <>                
                                                              
                                                              
                                                              
                                              '' THEN 'Mail'                
                                         ELSE 'SMS'                
                                    END + ' campaign  '                
                            
                            
                            
            + CAST(A.campaignname AS NVARCHAR(500))                
                            
                            
                            
            +                
                            
                            
                            
            ' scheduled for <date time> is executed successfully.                                               You can log in to your & check the delivery report in the campaign history',                
         GETDATE(),                
            335,                
            '',                
            @Batchidmails,                
            1,                
            GETDATE(),                
            0,                
            '',                
            1                
     FROM   (                
                SELECT DISTINCT Ucm.accountused,                
                       Ucm.campaignname,                
                       Ucm.mailreplyto,                
                       Ucm.notificationmail                
                FROM   usercampaignmaster AS Ucm   (nolock)               
                WHERE  Ucm.id IN (SELECT Tt.campaignid                
                                  FROM                   
                                 usercampaignexecutionrecipientsmessage                 
                                                         
                                                         
                                                         
                                         Tt  (nolock)                
                                  WHERE  Tt.iscompleted = 1)                
            ) A                
 END                
                 
                 
                 
                 
                 
                 
                 
 DELETE Kd         FROM   usercampaignexecutionrecipientsmessage Kd   (nolock)               
        INNER JOIN #temptable Tt                
             ON  Tt.campaignid = Kd.campaignid                
 WHERE  Kd.iscompleted = 1                
                 
                 
                 
                 
                 
                 
                 
 CREATE TABLE #nextexec1                
 (                
  campaignid        BIGINT,                
  nextexecution     DATETIME                
 )                
                 
                 
                 
                 
                 
                 
                 
 DECLARE @Count BIGINT = (                
             SELECT COUNT(*)                
             FROM   #temptable                
         )                
                 
                 
                 
                 
                 
                 
                 
 SELECT *                
                        
                        
                        
        INTO #tempcampaign                
 FROM   #temptable                
                 
                 
                 
                 
                 
                 
                 
 WHILE @Count > 0                
 BEGIN                
     SET @Count = @Count - 1                
                     
                     
                     
                     
                     
                     
                     
     DECLARE @Campaignid BIGINT = (                
                 SELECT TOP 1 campaignid                
               FROM   #tempcampaign                
             )                
                     
                     
                     
                     
                     
                     
                     
     DELETE                 
     FROM   #tempcampaign                
     WHERE  campaignid = @Campaignid                
                     
                     
                     
                     
                     
                     
                     
     IF EXISTS (                
            SELECT *                
            FROM   usercampaignmaster AS Ucm  (nolock)                
            WHERE  Ucm.id = @Campaignid                
                   AND Ucm.isscheduled = 1                
                   AND Ucm.isschedule = 1                
        )                
     BEGIN                
         INSERT INTO #nextexec1                
           (                
             campaignid,                
             nextexecution                
           )                
         EXEC Usp_getnextscheduledate                
                              
                              
                              
              @Campaignid                
     END                
 END                
                 
                 
                 
                 
                 
                  
                 
                 
                 
                 
 UPDATE Kd                
 SET    Kd.nextexecutedatetime = Ne.nextexecution,ExecutedDateTime = GETDATE()                
 FROM   usercampaignmaster Kd                
        INNER JOIN #nextexec1 AS Ne                
             ON  Ne.campaignid = Kd.id                
                 
                 
                 
                 
                 
                 
                 
 DROP TABLE #tempmobile                
                 
             
              
                 
                 
                 
                 
 DROP TABLE #tempcampaign                
                 
                 
                 
                 
                 
                 
             
 DROP TABLE #temptable  
  if OBJECT_ID('tempdb..##campaignrun') is not null   
     begin             
 delete from ##campaignrun where DATE< (select CampaignExecutedDatetime from UserCampaignExecution where issms=1)                   
 end  
END 


GO

/* ============================================================
   Procedure: [dbo].[Usp_insertclonedeliverycampaignCorrected]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_insertclonedeliverycampaignCorrected] 
(@jobid bigint)
AS
BEGIN                              
 create table #outputb(id int identity(1,1),bid bigint, u_id bigint,campaignid bigint)        
begin tran          
INSERT INTO Getbatchrecord                                                      
([User_id],RandNum)           
OUTPUT inserted.BatchID  as bId,inserted.User_id as u_id,inserted.RandNum as campaignid  INTO #outputb                                    
SELECT DISTINCT Ucerm.u_id,                              
        Ucerm.campaignid                              
 FROM   usercampaignexecutionrecipientsmessageTest2 Ucerm   (nolock)                           
 WHERE  Ucerm.iscompleted = 1 and jobid=@jobid                                                      
               
delete g From GetBatchRecord g join #outputb o on o.bid=g.BatchID        
commit                              
             
 SELECT ROW_NUMBER() Over(order by ucerm.CampaignId,ucerm.ParentId) Id,       Ucerm.CampaignID,                   
     Ucerm.ParentID,              
     o.bid AS        BatchID,                                              
     Ucerm.Senderid,                                              Ucerm.U_ID AS UserID,            
     ucerm.isunicode,                
     SUM(credits) cnt,            
     COUNT(*) RCount            
      INTO   #tempTable                                                
      FROM   usercampaignexecutionrecipientsmessageTest2 Ucerm  join #outputb o on o.u_id=ucerm.ParentID and o.campaignid=ucerm.campaignid       WHERE  Ucerm.IsCompleted = 1 and jobid=@jobid                    
     Group by  Ucerm.CampaignID,                   
     Ucerm.ParentID , Ucerm.SenderID, Ucerm.U_ID,                
                      Ucerm.isunicode ,o.bid                
                                  
SELECT ROW_NUMBER() Over(order by Ucerm.CampaignId,Ucerm.ParentId) Id,       Ucerm.CampaignID,                   
     Ucerm.ParentID,              
     o.bid AS        BatchID,                                              
     Ucerm.Senderid,                                              Ucerm.U_ID AS UserID,            
     ucerm.isunicode,                
     SUM(credits) cnt,            
     COUNT(*) RCount,            
     ParentSuperResellerId            
      INTO   #tempTableVirtual                                                
      FROM   usercampaignexecutionrecipientsmessageTest2 Ucerm  join user_detail u on u.User_ID=ucerm.U_ID          
      join #outputb o on o.u_id=ucerm.u_id and o.campaignid=ucerm.campaignid                 
      WHERE  Ucerm.IsCompleted = 1  and HasVirtualCredits=1  and jobid=@jobid                 
     Group by  Ucerm.CampaignID, u.ParentSuperResellerId,                  
     Ucerm.ParentID , Ucerm.SenderID, Ucerm.U_ID,                
                      Ucerm.isunicode ,o.bid           
                                  
                                                           
SELECT A.UserID,a.CampaignID, a.cnt,A.BatchID, SUM(b.cnt) RunningTotal into #TempTableRunningTotal                
FROM   #tempTable a inner join #tempTable b                
on b.CampaignID <= a.CampaignID                
GROUP BY A.UserID, a.CampaignID, a.cnt,A.BatchID                
ORDER BY a.CampaignID;                
            
SELECT A.UserID,a.CampaignID, a.cnt,A.BatchID, SUM(b.cnt) RunningTotal,a.ParentSuperResellerId into #TempTableRunningTotalVirtual                
FROM   #tempTableVirtual a inner join #tempTableVirtual b                
on b.CampaignID <= a.CampaignID                
GROUP BY A.UserID, a.CampaignID, a.cnt,A.BatchID,a.ParentSuperResellerId                
ORDER BY a.CampaignID;            
                      
drop table #outputb                      
/*DELETE Kd                                                
FROM   Getbatchrecord Kd                                                
INNER JOIN #tempTable Tt                                 
ON Tt.BatchID = Kd.BatchID */        
      --- Calculate credits             
            
SELECT B.UserID,                 
B.CampaignID,                                               
CASE                    
WHEN B.Balance >= B.Credits THEN 1 else 0              
END AS ValidEntries                                                
INTO   #tempMobile                                                
FROM   (SELECT A.UserID,                  
        A.CampaignID,                                              
        (A.Credits)   AS Credits,  --Runningtotal                                
                     A.Balance                                        FROM (SELECT Tt.UserID,TT.RunningTotal AS Credits,            
                      TT.CampaignID,            
                      Tt.BatchID,              (SELECT TOP 1 Balance                                         FROM   credit_details AS Mcd             
               WHERE  Mcd.[User_ID] = Tt.UserID                         
               ORDER  BY Credit_ID DESC)     AS Balance                     FROM   #TempTableRunningTotal Tt) A                          GROUP  BY A.UserID,A.Balance,A.CampaignID,A.credits) B                 
                   
update u set u.ReasonIfNotRun='Insuffcient Balance' from UserCampaignHistory u join #tempMobile t    
on u.campaignid=t.CampaignID and u.jobid=@jobid where t.validentries=0    
                           
SELECT B.UserID,                 
B.CampaignID,                                               
CASE                                                
WHEN B.Balance >= B.Credits THEN 1   ELSE 0             
END AS ValidEntries,            
B.ParentSuperResellerId                                                
INTO   #tempMobileVirtual                                                
FROM   (SELECT A.UserID,                  
        A.CampaignID,                                              
       (A.Credits)   AS Credits,  --Runningtotal                                
        A.Balance,            
        A.ParentSuperResellerId                                                    
        FROM             
        (SELECT Tt.UserID,TT.RunningTotal AS Credits,TT.CampaignID,Tt.BatchID,TT.ParentSuperResellerId,                                     (SELECT TOP 1 Balance FROM   SuperResellerCredit_Details AS Mcd             
               WHERE  Mcd.[User_ID] = Tt.ParentSuperResellerId                         
               ORDER  BY Credit_ID DESC) AS Balance FROM   #TempTableRunningTotalVirtual Tt) A             
               GROUP  BY A.ParentSuperResellerId, A.UserID,A.Balance,A.CampaignID,A.credits) B                              

--Track Code
update b set batchid=tt.batchid from Link_smsUrl_dtl b INNER JOIN #temptable Tt ON  Tt.campaignid = b.ccid INNER JOIN #tempmobile Tm ON  Tm.userid = Tt.userid AND validentries = 1 


               
SELECT DISTINCT tt.batchid,                              
        Ucerm.mobile,                              
        Ucerm.[message],                              
        Ucerm.messagestatus,                              
        Ucerm.senderid,                              
        Ucerm.messageinsertdate,                              
        '' as scheduleddate,                              
        '' as scheduledtime,                              
        U.smppid,                              
        Ucerm.u_id,                              
        Ucerm.isunicode,                              
        Ucerm.isdnd,                              
        Ucerm.isairtel,                              
        Ucerm.mobilesubset,                              
        Ucerm.validno,                              
        Ucerm.isprority,                              
        Ucerm.isallowdnd,                              
        Ucerm.dbtype,            
        tt.CampaignID,            
        tt.RCount,            
        CASe when tmv.CampaignID is not null then 1 else 0 end as HasVirtualCredits,            
        CASe when tmv.ValidEntries =1 then 1 else 0 end as HasSufficientVirtualCredits            
        into #clonemessagedeliverystatus            
 FROM   usercampaignexecutionrecipientsmessageTest2 Ucerm (nolock)             
 INNER JOIN #temptable Tt ON  Tt.campaignid = Ucerm.campaignid AND Ucerm.u_id = Tt.userid             
 INNER JOIN #tempmobile Tm ON  Tm.userid = Tt.userid AND validentries = 1 join user_detail u on u.User_ID=Ucerm.u_id                
 left join #tempMobileVirtual tmv on tmv.CampaignID=tt.CampaignID                  
 WHERE  Ucerm.mobile <> '' AND Ucerm.IsCompleted = 1  and ucerm.jobid=@jobid          
           
 /*Creating indexes for temp table to improve the performance*/          
           
 CREATE NONCLUSTERED INDEX IX_#clonemessagedeliverystatus1 ON #clonemessagedeliverystatus(          
 batchid,mobile,messagestatus,senderid,messageinsertdate)          
           
 CREATE NONCLUSTERED INDEX IX_#clonemessagedeliverystatus2 ON #clonemessagedeliverystatus(          
 smppid,u_id,isunicode,isdnd,isairtel,mobilesubset)                 
           
 CREATE NONCLUSTERED INDEX IX_#clonemessagedeliverystatus3 ON #clonemessagedeliverystatus(          
 validno,isprority,isallowdnd,dbtype,CampaignID,RCount)          
           
 CREATE NONCLUSTERED INDEX IX_#clonemessagedeliverystatus4 ON #clonemessagedeliverystatus(          
 HasVirtualCredits,HasSufficientVirtualCredits )          
           
 /*End index creation*/          
           
select t.*,u.email into #Insufficientresellerbalance from #tempMobileVirtual t join #tempMobile tt on t.CampaignID=tt.CampaignID join user_detail u on u.user_id=t.ParentSuperResellerId where tt.ValidEntries=0            
                                    
 declare @batchcount int= (select count(distinct batchid) from #clonemessagedeliverystatus)-- where RCount>5)            
 while @batchcount>0            
 begin            
 RETRY:                                                     
BEGIN TRY                                                  
BEGIN TRAN             
 declare @batchid bigint= (select min(batchid) from #clonemessagedeliverystatus)-- where RCount>5)            
  INSERT INTO clonemessagedeliverystatus                              
   ( batchid,mobile,[message],messagestatus,senderid,messageinsertdate,scheduleddate,scheduledtime,smppid,u_id,isunicode,isdnd,isairtel,mobilesubset,validno,isprority,isallowdnd,dbtype,campaignid,hasvirtualcredits,HasSufficientVirtualCredits             
  
    
       
       
           
)                          
 SELECT batchid,                              
        Ucerm.mobile,                              
        Ucerm.[message],                              
        Ucerm.messagestatus,                              
        Ucerm.senderid,                              
        GETDATE(),                              
        ScheduledDate,                              
        ScheduledTime,                              
        smppid,                  
        Ucerm.u_id,                              
        Ucerm.isunicode,                              
        Ucerm.isdnd,                              
        Ucerm.isairtel,                              
        Ucerm.mobilesubset,                              
        Ucerm.validno,                              
        Ucerm.isprority,                              
        Ucerm.isallowdnd,                              
        Ucerm.dbtype,            
        CampaignID,            
        hasvirtualcredits,            
        HasSufficientVirtualCredits              
 FROM   #clonemessagedeliverystatus Ucerm where BatchID=@batchid            
 delete FROM #clonemessagedeliverystatus where BatchID=@batchid            
 set @batchcount=@batchcount-1            
-- select @@TRANCOUNT            
--IF @@TRANCOUNT>0                                                  
COMMIT                                                  
END TRY                                                  
BEGIN CATCH                                                                                                      
IF @@TRANCOUNT>0                                                  
ROLLBACK                             
EXECUTE USP_INSERTERRORINFO;             
IF ERROR_NUMBER() = 1205 -- Deadlock Error Number            
BEGIN            
WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms            
GOTO RETRY -- Go to Label RETRY            
END                                                       
END CATCH             
            
end            
             
             
UPDATE Kd                                                
      SET    Executiontime = Getdate(),            
             Noofrecipients = Tt.RCount,                        
             Batchid = Tt.BatchID,                     
             Isexecuted = case when tm.Validentries=1 then 1 else 0 end                                                    
      FROM   Usercampaignexecutionhistory Kd              
             INNER JOIN #tempTable Tt             
             ON Tt.CampaignID = Kd.CampaignID            
             INNER JOIN #tempMobile Tm            
             ON Tm.userID = Tt.userID   and Tm.CampaignID = Tt.CampaignID                                                  --AND Validentries = 1                                                
      WHERE  Jobid=@jobId                              
                              
if exists(select 1 from UserCampaignExecutionHistory where Jobid=@jobid and TemplateSequence<>0)            
begin            
update ucm set TemplateGroupSequence= case when isending=0 then isnull((select top 1 orderno from UserGroupTemplateMix where OrderNo=TemplateSequence+1 and GroupID=ucm.TemplateGroupID),1) else isnull((select top 1 orderno from UserGroupTemplateMix  where
   
    
      
        
         
 OrderNo=TemplateSequence+1 and GroupID=ucm.TemplateGroupID),templategroupsequence) end from UserCampaignmaster ucm join usercampaignexecutionhistory uceh on uceh.CampaignID=ucm.ID join UserGroupTemplateMix ugtm on ugtm.GroupID=ucm.TemplateGroupID where  
  
   
 Jobid=@jobid and TemplateSequence<>0 and IsExecuted=1            
end                        
            
---send notification mail------              
if ((select top 1 iseventbased from UserCampaignHistory where JobId=@jobId)=0)            
      begin            
      INSERT INTO Getbatchrecord                    
                  ([User_id],                                                
                   RandNum)                                                
      SELECT ParentID,                                                
                   CampaignID FROM #tempTable                                                
                                                 
Select BatchID,[User_id] ParentID,RandNum CampaignID into #Batch from Getbatchrecord Gbr                                Order by gbr.BatchID                                   
                                                
      DELETE Kd                                                
      FROM   Getbatchrecord Kd                                                
     Inner join    #Batch B on B.BatchId = Kd.BatchID             
            
INSERT INTO Getbatchrecord                                                
                  ([User_id],                                                
                   RandNum)                                                
      SELECT ParentSuperResellerId,                                                
                   CampaignID FROM #Insufficientresellerbalance                                               
                                                 
Select BatchID,[User_id] ParentSuperResellerId,RandNum CampaignID into #Batch1 from Getbatchrecord Gbr                        Order by gbr.BatchID                                   
                                                
DELETE Kd                                                
      FROM   Getbatchrecord Kd                                                
     Inner join    #Batch1 B on B.BatchId = Kd.BatchID             
                 
                 
                                                     
 INSERT INTO Batchemail_infos                                                
                  (                                                
      -- ID -- this column value is auto-generated                                                
      B.BatchID,                                                
                   UserID,                                                
                   SenderName,                                             
   [Message],                
                   TotalRecords,                                                
                   TotalProcessed,                                                
                   ProcessTable,                                                
                   IsProcess,                                                
                   Priority_Level,                                                
                   BatchInsertTime,                                                
             BatchProcessTime,                                                
                   ScheduledDate,                                                
                   ScheduledTime,                                             
                   TemplateID,                                            
                   [Route],                                                
                   PageName,                                                
                   IsScheduled,                                                
                   Email_Subject,                                                
                   ReplyTo,                                                
                   Amount,                                                
                   Currency)                                                
SELECT B.Batchid,                                                
             335,                                                
             inrc.EMail,                                                
             'We are unable to run some of your users'' campaigns because of insufficient credits. Please refill your mail credits to enjoy uninterrupted services for your users.' as [Message],                                                
1,                                                
0,                                                
0,                                                
0,                                                
1,                                                
Getdate(),                                                
Getdate(),                                                
Getdate(),                                         
Getdate(),                                                
0,                                                
0,                                                
0,                                                
0,                                                
'Failure: Your users'' campaign "' + + UCM.CampaignName + '" failed because of insufficient mail credits in your account.' as email_subject,                
'noreply@email19.in',                                                
0,                                              
0                                  
FROM   #temptable Tt                                                
INNER JOIN Usercampaignmaster AS Ucm                                                
ON Ucm.ID = Tt.CampaignID                                                
AND Ucm.IsScheduled = 1                                                
AND Ucm.ParentID = Tt.ParentID                   
Inner join #tempMobile TM on TM.CampaignID = Tt.CampaignID               
Inner join #Batch1 B on B.CampaignId = Tt.CampaignId                                          
inner join #Insufficientresellerbalance inrc on inrc.CampaignID=tt.CampaignID            
union            
SELECT B.Batchid,                                                
             335,                                                
Ucm.NotificationMail,            
             case when tmv.validentries=0 then             
             'Oops, something went wrong and your campaign couldn''t run. Please contact your administrator for details'             
             when TM.ValidEntries = 0 then             
             'Oops, you don''t have sufficient SMS credits to run your SMS campaign "' + Ucm.CampaignName + '" scheduled for '    + Cast(Getdate() AS VARCHAR(50)) + '. Pl refill your credit balance & rerun the campaign '                 
             else                  
             'As promised , Your SMS campaign "'                       
             + Ucm.CampaignName + '" scheduled for '                                                
             + Cast(Getdate() AS VARCHAR(50))                                                
             + ' is executed successfully. You can log in to your account & check the delivery report in the campaign history' end as [Message],                                                
1,                                                
0,                                                
0,                                                
0,                                                
1,                                                
Getdate(),                                                
Getdate(),                                                
Getdate(),                                          
Getdate(),                                                
0,                                                
0,                                                
0,                                                
0,                                                
case when tmv.validentries=0 then             
'Failure: Your campaign "' + + UCM.CampaignName + '" failed. Please contact your administrator for details.'             
when TM.ValidEntries = 0 then             
'Failure: Your campaign "' + + UCM.CampaignName + '" failed due to insufficient credits'             
else 'Success : Your campaign "' + UCM.CampaignName + '" executed successfully'             
end as email_subject,                
'noreply@email19.in',                                                
0,                                              
0                                  
FROM   #temptable Tt                                                
INNER JOIN Usercampaignmaster AS Ucm                                                
ON Ucm.ID = Tt.CampaignID                                                
AND Ucm.IsScheduled = 1                                                
AND Ucm.ParentID = Tt.ParentID                   
Inner join #tempMobile TM on TM.CampaignID = Tt.CampaignID               
Inner join #Batch B on B.CampaignId = Tt.CampaignId                                          
left join #tempMobileVirtual tmv on tmv.CampaignID=tt.CampaignID            
            
create table #output (GUID nvarchar(100) collate SQL_Latin1_General_CP1_CI_AS ,Email nvarchar(200) collate SQL_Latin1_General_CP1_CI_AS,Batchid bigint)                                            
                
    INSERT INTO Clientemails                       
                (                                  
    -- Id -- this column value is auto-generated                                                
    GUID,                                                
                 Email_Id,                                                
               SentDateTime,                                                
                 UserId,                                                
                 ReplyTo,                                  
                 [Status],                                                
                 BatchID,                                                
                 [Message])              
    output inserted.GUID,inserted.Email_Id,inserted.BatchID into #output                    
    SELECT Newid(),                                                
           Ucm.NotificationMail,                                                
           Getdate(),                                                
           335,                                                
           'noreply@email19.in',                                                
           '',                                                
B.Batchid,                                                
           case when tmv.validentries=0 then             
             'Oops, something went wrong and your campaign couldn''t run. Please contact your administrator for details'            
             when TM.ValidEntries = 0 then             
             'Oops, you don''t have sufficient SMS credits to run your SMS campaign "' + Ucm.CampaignName + '" scheduled for '             + Cast(Getdate() AS VARCHAR(50)) + '. Pl refill your credit balance & rerun the campaign '             
             else                  
             'As promised , Your SMS campaign "' + Ucm.CampaignName + '" scheduled for '+ Cast(Getdate() AS VARCHAR(50))                   + ' is executed successfully. You can log in to your account & check the delivery report in the campaign history'   
 
    
       
       
           
             end as  [Message]                                                 
FROM   #tempTable Tt                                                
INNER JOIN Usercampaignmaster AS Ucm                                                
ON Ucm.ID = Tt.CampaignID                                                
AND Ucm.IsScheduled = 1                                                
AND Ucm.ParentID = Tt.ParentID                  
Inner join #tempMobile TM on TM.CampaignID = Ucm.ID                
Inner join #Batch B on B.CampaignId = Tt.CampaignId            
left join #tempMobileVirtual tmv on tmv.CampaignID=tt.CampaignID            
union            
SELECT Newid(),                                                
           inrc.email,                                                
           Getdate(),                                                
           335,                                                
           'noreply@email19.in',                                                
           '',                                                
   B.Batchid,                                                
           'We are unable to run some of your users'' campaigns because of insufficient credits. Please refill your mail credits to enjoy uninterrupted services for your users.' as [Message]                                                 
FROM   #tempTable Tt                                                
INNER JOIN Usercampaignmaster AS Ucm                                                
ON Ucm.ID = Tt.CampaignID                                                
AND Ucm.IsScheduled = 1                                                
AND Ucm.ParentID = Tt.ParentID                  
Inner join #tempMobile TM on TM.CampaignID = Ucm.ID                
Inner join #Batch1 B on B.CampaignId = Tt.CampaignId            
inner join #Insufficientresellerbalance inrc on inrc.CampaignID=tt.CampaignID            
                                                              
INSERT INTO Emailsfilter                                                
