/* ============================================================
   Procedure: [dbo].[Usp_insertclonedeliverycampaignCorrected_withid]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_insertclonedeliverycampaignCorrected_withid]   
(@jobid bigint)  
AS  
BEGIN                                
 create table #outputb(id int identity(1,1),bid bigint, u_id bigint,campaignid bigint)          
begin tran            
INSERT INTO Getbatchrecord                                                        
([User_id],RandNum)             
OUTPUT inserted.BatchID  as bId,inserted.User_id as u_id,inserted.RandNum as campaignid  INTO #outputb                                      
SELECT DISTINCT Ucerm.u_id,                                
        Ucerm.campaignid                                
 FROM   usercampaignexecutionrecipientsmessageTest2 Ucerm   (nolock)                             
 WHERE  Ucerm.iscompleted = 1 and jobid=@jobid                                                        
                 
delete g From GetBatchRecord g join #outputb o on o.bid=g.BatchID          
commit                                
               
 SELECT ROW_NUMBER() Over(order by ucerm.CampaignId,ucerm.ParentId) Id,       
 Ucerm.CampaignID,                     
     Ucerm.ParentID,                
     o.bid AS        BatchID,                                                
     Ucerm.Senderid,                                              Ucerm.U_ID AS UserID,              
     ucerm.isunicode,                  
     SUM(credits) cnt,              
     COUNT(*) RCount              
      INTO   #tempTable                                                  
      FROM   usercampaignexecutionrecipientsmessageTest2 Ucerm  join #outputb o on o.u_id=ucerm.ParentID and o.campaignid=ucerm.campaignid       WHERE  Ucerm.IsCompleted = 1 and jobid=@jobid                      
     Group by  Ucerm.CampaignID,                     
     Ucerm.ParentID , Ucerm.SenderID, Ucerm.U_ID,                  
                      Ucerm.isunicode ,o.bid                  
                                    
SELECT ROW_NUMBER() Over(order by Ucerm.CampaignId,Ucerm.ParentId) Id,       Ucerm.CampaignID,                     
     Ucerm.ParentID,                
     o.bid AS        BatchID,                                                
     Ucerm.Senderid,                                              Ucerm.U_ID AS UserID,              
     ucerm.isunicode,                  
     SUM(credits) cnt,              
     COUNT(*) RCount,              
     ParentSuperResellerId              
      INTO   #tempTableVirtual                                                  
      FROM   usercampaignexecutionrecipientsmessageTest2 Ucerm  join user_detail u on u.User_ID=ucerm.U_ID            
      join #outputb o on o.u_id=ucerm.u_id and o.campaignid=ucerm.campaignid                   
      WHERE  Ucerm.IsCompleted = 1  and HasVirtualCredits=1  and jobid=@jobid                   
     Group by  Ucerm.CampaignID, u.ParentSuperResellerId,                    
     Ucerm.ParentID , Ucerm.SenderID, Ucerm.U_ID,                  
                      Ucerm.isunicode ,o.bid             
                                    
                                                             
SELECT A.UserID,a.CampaignID, a.cnt,A.BatchID, SUM(b.cnt) RunningTotal into #TempTableRunningTotal                  
FROM   #tempTable a inner join #tempTable b                  
on b.CampaignID <= a.CampaignID                  
GROUP BY A.UserID, a.CampaignID, a.cnt,A.BatchID                  
ORDER BY a.CampaignID;                  
              
SELECT A.UserID,a.CampaignID, a.cnt,A.BatchID, SUM(b.cnt) RunningTotal,a.ParentSuperResellerId into #TempTableRunningTotalVirtual                  
FROM   #tempTableVirtual a inner join #tempTableVirtual b                  
on b.CampaignID <= a.CampaignID                  
GROUP BY A.UserID, a.CampaignID, a.cnt,A.BatchID,a.ParentSuperResellerId                  
ORDER BY a.CampaignID;              
                        
drop table #outputb                        
/*DELETE Kd                                                  
FROM   Getbatchrecord Kd           
INNER JOIN #tempTable Tt                                   
ON Tt.BatchID = Kd.BatchID */          
      --- Calculate credits               
              
SELECT B.UserID,                   
B.CampaignID,                                                 
CASE                      
WHEN B.Balance >= B.Credits THEN 1 else 0                
END AS ValidEntries                                                  
INTO   #tempMobile                                                  
FROM   (SELECT A.UserID,                    
        A.CampaignID,                                                
        (A.Credits)   AS Credits,  --Runningtotal                                  
                     A.Balance                                        FROM (SELECT Tt.UserID,TT.RunningTotal AS Credits,              
                      TT.CampaignID,              
                      Tt.BatchID,              (SELECT TOP 1 Balance                                         FROM   credit_details AS Mcd               
               WHERE  Mcd.[User_ID] = Tt.UserID                           
               ORDER  BY Credit_ID DESC)     AS Balance                     FROM   #TempTableRunningTotal Tt) A                          GROUP  BY A.UserID,A.Balance,A.CampaignID,A.credits) B                   
                     
update u set u.ReasonIfNotRun='Insuffcient Balance' from UserCampaignHistory u join #tempMobile t      
on u.campaignid=t.CampaignID and u.jobid=@jobid where t.validentries=0      
                             
SELECT B.UserID,                   
B.CampaignID,                                                 
CASE                                                  
WHEN B.Balance >= B.Credits THEN 1   ELSE 0               
END AS ValidEntries,              
B.ParentSuperResellerId                                                  
INTO   #tempMobileVirtual                                                  
FROM   (SELECT A.UserID,                    
        A.CampaignID,                                                
       (A.Credits)   AS Credits,  --Runningtotal                                  
        A.Balance,              
        A.ParentSuperResellerId                                                      
        FROM               
        (SELECT Tt.UserID,TT.RunningTotal AS Credits,TT.CampaignID,Tt.BatchID,TT.ParentSuperResellerId,                                     (SELECT TOP 1 Balance FROM   SuperResellerCredit_Details AS Mcd               
               WHERE  Mcd.[User_ID] = Tt.ParentSuperResellerId                           
               ORDER  BY Credit_ID DESC) AS Balance FROM   #TempTableRunningTotalVirtual Tt) A               
               GROUP  BY A.ParentSuperResellerId, A.UserID,A.Balance,A.CampaignID,A.credits) B                                
  
--Track Code  
update b set batchid=tt.batchid from Link_smsUrl_dtl b INNER JOIN #temptable Tt ON  Tt.campaignid = b.ccid INNER JOIN #tempmobile Tm ON  Tm.userid = Tt.userid AND validentries = 1   
  
  
                 
SELECT DISTINCT entityname,entityid,tt.batchid,                                
        Ucerm.mobile,                                
        Ucerm.[message],                                
        Ucerm.messagestatus,                                
        Ucerm.senderid,                                
        Ucerm.messageinsertdate,                                
        '' as scheduleddate,                                
        '' as scheduledtime,                                
        U.smppid,                                
        Ucerm.u_id,                                
        Ucerm.isunicode,                                
        Ucerm.isdnd,                                
        Ucerm.isairtel,                                
        Ucerm.mobilesubset,                                
        Ucerm.validno,                                
        Ucerm.isprority,                                
        Ucerm.isallowdnd,                                
        Ucerm.dbtype,         
        tt.CampaignID,              
        tt.RCount,              
        CASe when tmv.CampaignID is not null then 1 else 0 end as HasVirtualCredits,              
        CASe when tmv.ValidEntries =1 then 1 else 0 end as HasSufficientVirtualCredits              
        into #clonemessagedeliverystatus              
 FROM   usercampaignexecutionrecipientsmessageTest2 Ucerm (nolock)               
 INNER JOIN #temptable Tt ON  Tt.campaignid = Ucerm.campaignid AND Ucerm.u_id = Tt.userid               
 INNER JOIN #tempmobile Tm ON  Tm.userid = Tt.userid AND validentries = 1 join user_detail u on u.User_ID=Ucerm.u_id                  
 left join #tempMobileVirtual tmv on tmv.CampaignID=tt.CampaignID                    
 WHERE  Ucerm.mobile <> '' AND Ucerm.IsCompleted = 1  and ucerm.jobid=@jobid            

              
 /*Creating indexes for temp table to improve the performance*/            
             
 CREATE NONCLUSTERED INDEX IX_#clonemessagedeliverystatus1 ON #clonemessagedeliverystatus(            
 batchid,mobile,messagestatus,senderid,messageinsertdate)            
             
 CREATE NONCLUSTERED INDEX IX_#clonemessagedeliverystatus2 ON #clonemessagedeliverystatus(            
 smppid,u_id,isunicode,isdnd,isairtel,mobilesubset)                   
             
 CREATE NONCLUSTERED INDEX IX_#clonemessagedeliverystatus3 ON #clonemessagedeliverystatus(            
 validno,isprority,isallowdnd,dbtype,CampaignID,RCount)            
             
 CREATE NONCLUSTERED INDEX IX_#clonemessagedeliverystatus4 ON #clonemessagedeliverystatus(            
 HasVirtualCredits,HasSufficientVirtualCredits )   
 


CREATE TABLE #tbl_activity(
	[LeadID] [bigint] NULL,
	[UserID] [bigint] NULL,
	[ParentID] [bigint] NULL,
	[EventDescription] [nvarchar](max) NULL,
	[EventName] [nvarchar](500) NULL
)
insert into #tbl_activity( LeadID , UserID, ParentID , EventDescription , EventName)           
select entityid,m.u_id,u.ParentID,cast(u.user_login as nvarchar) +'sent an sms with content "'+replace(m.[message],'''','"')+ '" on mobile '+cast(m.mobile as nvarchar) +' through automated campaign named '
 + c.CampaignName,'SMS sent to lead'
 from user_detail u join #clonemessagedeliverystatus m on m.u_id=u.User_ID
 join UserCampaignMaster c on c.ID=m.CampaignID
 where entityname='Lead' and isnull(entityid,0)<>0         

exec UspSaveLeadActivity_withMultipleValue #tbl_activity

drop table #tbl_activity 
             
 /*End index creation*/   
 /*
 INSERT INTO tbl_LeadEventHistory ( ParentID , UserID , LeadID , EventDescription , EventDate , EventID                                         )           
 select u.ParentID,m.u_id,entityid,cast(u.user_login as nvarchar) +'sent an sms with content "'+replace(m.[message],'''','"')+ '" on mobile '+cast(m.mobile as nvarchar) +' through automated campaign named '
 + c.CampaignName,getdate(),A.ID
 from user_detail u join #clonemessagedeliverystatus m on m.u_id=u.User_ID
 join UserCampaignMaster c on c.ID=m.CampaignID
 join ActivityMaster a on A.EventName='SMS sent to lead'
 where entityname='Lead' and isnull(entityid,0)<>0
*/             
select t.*,u.email into #Insufficientresellerbalance from #tempMobileVirtual t join #tempMobile tt on t.CampaignID=tt.CampaignID join user_detail u on u.user_id=t.ParentSuperResellerId where tt.ValidEntries=0              
                                      
 declare @batchcount int= (select count(distinct batchid) from #clonemessagedeliverystatus)-- where RCount>5)              
 while @batchcount>0              
 begin              
 RETRY:                                                       
BEGIN TRY                                                    
BEGIN TRAN               
 declare @batchid bigint= (select min(batchid) from #clonemessagedeliverystatus)-- where RCount>5)              
  INSERT INTO clonemessagedeliverystatus                                
   ( batchid,mobile,[message],messagestatus,senderid,messageinsertdate,scheduleddate,scheduledtime,smppid,u_id,isunicode,isdnd,isairtel,mobilesubset,validno,isprority,isallowdnd,dbtype,campaignid,hasvirtualcredits,HasSufficientVirtualCredits             
  
    
      
         
         
             
)                            
 SELECT batchid,                                
        Ucerm.mobile,                                
        Ucerm.[message],                                
        Ucerm.messagestatus,                                
        Ucerm.senderid,                                
        GETDATE(),                                
        ScheduledDate,                                
        ScheduledTime,                                
        smppid,                    
        Ucerm.u_id,                                
        Ucerm.isunicode,                                
        Ucerm.isdnd,                                
        Ucerm.isairtel,                                
        Ucerm.mobilesubset,                                
        Ucerm.validno,                                
        Ucerm.isprority,                                
        Ucerm.isallowdnd,                                
        Ucerm.dbtype,              
        CampaignID,              
        hasvirtualcredits,              
        HasSufficientVirtualCredits                
 FROM   #clonemessagedeliverystatus Ucerm where BatchID=@batchid              
 delete FROM #clonemessagedeliverystatus where BatchID=@batchid          
 set @batchcount=@batchcount-1              
-- select @@TRANCOUNT              
--IF @@TRANCOUNT>0                                                    
COMMIT                                                    
END TRY                                                    
BEGIN CATCH                                                                                                        
IF @@TRANCOUNT>0                                                    
ROLLBACK                               
EXECUTE USP_INSERTERRORINFO;               
IF ERROR_NUMBER() = 1205 -- Deadlock Error Number              
BEGIN              
WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms              
GOTO RETRY -- Go to Label RETRY              
END                                                         
END CATCH               
              
end              
               
               
UPDATE Kd                                                  
      SET    Executiontime = Getdate(),              
             Noofrecipients = Tt.RCount,                          
             Batchid = Tt.BatchID,                       
             Isexecuted = case when tm.Validentries=1 then 1 else 0 end                                                      
      FROM   Usercampaignexecutionhistory Kd                
             INNER JOIN #tempTable Tt               
