CREATE   PROCEDURE [dbo].[Usp_insertclonedeliverycampaignCorrected240118]  @jobid bigint    AS                  
BEGIN                  
 INSERT INTO getbatchrecord                  
   ( -- BatchID auto-generated           
     [user_id],                  
     randnum                  
   )                  
 SELECT DISTINCT Ucerm.u_id,                  
        Ucerm.campaignid                  
 FROM   usercampaignexecutionrecipientsmessageTest2 Ucerm   (nolock)               
 WHERE  Ucerm.iscompleted = 1                  
 
 SELECT ROW_NUMBER() Over(order by CampaignId,ParentId) Id,       Ucerm.CampaignID,       
     Ucerm.ParentID,  
     dbo.Fn_createbatchid(Ucerm.CampaignID, Ucerm.U_ID) AS        BatchID,                                  
     Ucerm.Senderid,                                              Ucerm.U_ID AS UserID,
     ucerm.isunicode,    
     SUM(credits) cnt,
     COUNT(*) RCount
      INTO   #tempTable                                    
      FROM   usercampaignexecutionrecipientsmessageTest2 Ucerm         WHERE  Ucerm.IsCompleted = 1         
     Group by  Ucerm.CampaignID,       
     Ucerm.ParentID , Ucerm.SenderID, Ucerm.U_ID,    
                      Ucerm.isunicode                              
SELECT A.UserID,a.CampaignID, a.cnt,A.BatchID, SUM(b.cnt) RunningTotal into #TempTableRunningTotal    
FROM   #tempTable a join    
       #tempTable b on a.userid=b.userid   
WHERE b.CampaignID <= a.CampaignID    
