GroupID=ucm.TemplateGroupID),templategroupsequence) end from UserCampaignmaster ucm join usercampaignexecutionhistory uceh on uceh.CampaignID=ucm.ID join UserGroupTemplateMix ugtm on ugtm.GroupID=ucm.TemplateGroupID where Jobid=@jobid and TemplateSequence<>0 and IsExecuted=1  
