/* ============================================================
   Procedure: [dbo].[Usp_insertclonedeliverycampaignmails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

      
CREATE   PROCEDURE [Dbo].[Usp_insertclonedeliverycampaignmails]                              
AS                              
  BEGIN 
  if exists(select top 1 1 from Emailsfiltercampaignexecution (nolock))
  begin                             
      INSERT INTO Getbatchrecord                              
                  (                              
      -- BatchID -- this column value is auto-generated                              
      [User_id],                              
                   RandNum)                              
      SELECT DISTINCT Ucerm.ParentID,                              
                      Ucerm.CampaignID                              
      FROM   Emailsfiltercampaignexecution AS Ucerm                              
                              
      SELECT DISTINCT Ucerm.CampaignID,                              
                      Cast(Ucerm.Messages AS VARCHAR(MAX))                   AS                              
                      Messages,                              
                      dbo.Fn_createbatchid(Ucerm.CampaignID, Ucerm.ParentID) AS                              
                      BatchID,                              
                      Ucerm.Mail_FromEmail,                              
                      Ucerm.Mail_UserID                                      AS                              
                      UserID                              
                      ,                              
                      Ucerm.Mail_ToEmail,                              
                      Ucerm.ParentID                              
      INTO   #tempTable                              
      FROM   Emailsfiltercampaignexecution Ucerm                              
      WHERE  Ucerm.IsCompleted = 1                              
                              
      DELETE Kd                              
      FROM   Getbatchrecord Kd                              
             INNER JOIN #tempTable Tt                              
                     ON Tt.BatchID = Kd.BatchID                              
                              
      UPDATE Kd                              
      SET    Kd.Mail_BatchID = Tt.BatchID                              
      FROM   Emailsfiltercampaignexecution Kd                              
             INNER JOIN #tempTable Tt                              
                     ON Tt.CampaignID = Kd.CampaignID                              
                        AND Kd.Mail_FromEmail = Tt.Mail_FromEmail                              
      WHERE  Kd.IsCompleted = 1                              
                              
      --- Calculate credits                              
      SELECT B.UserID,                              
             CASE                              
               WHEN B.Balance > B.Credits THEN 1                              
               ELSE 0                              
             END AS ValidEntries                              
      INTO   #tempMobile                              
      FROM   (SELECT A.UserID,                              
                       SUM(A.Credits)   AS Credits,                              
                     A.Balance                              
              FROM   (SELECT Tt.UserID,                              
                             1 AS Credits,                              
                             Tt.Mail_ToEmail,                              
                             Tt.BatchID,                              
                             (SELECT TOP 1 Balance                              
                              FROM   Mailcreditdetails AS Mcd                              
                              WHERE  Mcd.[User_ID] = Tt.UserID                              
                              ORDER  BY Credit_ID DESC)     AS Balance                              
                      FROM   #tempTable Tt) A                              
              GROUP  BY A.UserID,                              
                        A.Balance) B                              
                              
      INSERT INTO Batchemail_infos                                              (                              
      -- ID -- this column value is auto-generated                              
BatchID,                              
                   UserID,                              
                   SenderName,           
                   [Message],                              
                   TotalRecords,                              
                   TotalProcessed,                              
                   ProcessTable,                              
                   IsProcess,                              
       Priority_Level,                              
                   BatchInsertTime,                              
                   BatchProcessTime,                                     ScheduledDate,                              
                   ScheduledTime,                              
                   TemplateID,                              
            [Route],                              
                   PageName,                              
                   IsScheduled,                              
                   Email_Subject,                           
                   ReplyTo)                              
      SELECT A.BatchID,                              
             A.Mail_UserID,                              
             A.SenderName,                             
             Cast(A.MailContent AS VARCHAR(MAX)),                              
             Count(*),                              
             0,                              
             0,                              
             1,                              
            0,                              
             Getdate(),                              
             NULL,                              
             NULL,                              
             NULL,                              
             0,                              
             0,                              
    0,                              
             0,                              
             A.Mail_Subject,                              
             A.ReplyTo                              
      FROM   (SELECT Tt.BatchID,                              
                     Efce.Mail_UserID,                              
                   (SELECT TOP 1 Isnull(Ud.FName, '') + ' '                              
                                   + Isnull(Ud.LName, '')                              
                      FROM   User_detail AS Ud                              
                      WHERE  Ud.[User_ID] = Efce.Mail_UserID) AS SenderName,                              
                     (SELECT TOP 1 Efce2.Messages                              
                      FROM   Emailsfiltercampaignexecution AS Efce2                              
                      WHERE  Efce2.CampaignID = Efce.CampaignID                              
                             AND Efce2.ParentID = Efce.ParentID                              
                      ORDER  BY Efce2.Mail_ToEmail DESC)      AS MailContent,                              
                     (SELECT TOP 1 Efce2.Mail_Subject                              
                      FROM   Emailsfiltercampaignexecution AS Efce2                              
                      WHERE  Efce2.CampaignID = Efce.CampaignID                              
                             AND Efce2.ParentID = Efce.ParentID                              
                      ORDER  BY Efce2.Mail_ToEmail DESC)      AS Mail_Subject,                              
                     (SELECT TOP 1 Efce2.ReplyTo                              
                      FROM   Emailsfiltercampaignexecution AS Efce2                              
                      WHERE  Efce2.CampaignID = Efce.CampaignID                              
                     AND Efce2.ParentID = Efce.ParentID                              
                      ORDER  BY Efce2.Mail_ToEmail DESC)      AS ReplyTo                              
              FROM   Emailsfiltercampaignexecution AS Efce                              
                     INNER JOIN #tempTable Tt                              
                             ON Tt.CampaignID = Efce.CampaignID                              
                                AND Efce.ParentID = Tt.ParentID                              
                     INNER JOIN #tempMobile Tm                              
                             ON Tm.userID = Efce.Mail_UserID                              
                                AND ValidEntries = 1                              
              WHERE  Efce.IsCompleted = 1) A                              
      GROUP  BY A.BatchID,                              
                A.Mail_UserID,                              
                A.SenderName,                              
                Cast(A.MailContent AS VARCHAR(MAX)),                              
                A.Mail_Subject,                              
                A.ReplyTo                              
                              
      INSERT INTO Clientemails                              
                  (              
      -- Id -- this column value is auto-generated                              
      GUID,                              
                   Email_Id,                              
                   SentDateTime,                              
                   UserId,                              
                   ReplyTo,                  
                   [Status],                              
                   BatchID,                              
                   [Message])                              
      SELECT Newid(),                              
             Efce.Mail_ToEmail,                              
             Getdate(),                              
             Efce.Mail_UserID,                              
             Efce.ReplyTo,                              
             '',                              
             Efce.Mail_BatchID,                              
             Efce.Messages                              
      FROM   Emailsfiltercampaignexecution AS Efce                              
             INNER JOIN #tempMobile Tm                              
      ON Tm.userID = Efce.Mail_UserID                              
                        AND ValidEntries = 1                              
      WHERE  Efce.IsCompleted = 1                              
                              
      INSERT INTO Emailsfilter                              
                  (Mail_GUID,                              
                   Mail_FromEmail,                              
      Mail_ToEmail,                              
                   Mail_Subject,                              
                   Mail_TempleteName,                              
                   Messages,                              
                   Mail_InsertedDate,                              
                   Mail_UserID,                              
                   ReplyTo,                              
                   Mail_BatchID,                              
      Mail_Priority,                              
                   Mail_ScheduleDate,                              
                   Mail_Attechement,                              
                   Mail_TempleteBody,                              
                   IsMonitor)                              
      SELECT Newid(),                              
             Efce.Mail_FromEmail,                              
             Efce.Mail_ToEmail,                              
             Efce.Mail_Subject,                           
             Efce.Mail_TempleteName,                              
             Efce.Messages,                            
             isnull(Efce.Mail_InsertedDate,getdate()),                              
             Efce.Mail_UserID,                              
             Efce.ReplyTo,                              
             Efce.Mail_BatchID,                              
             Efce.Mail_Priority,                              
             isnull(Efce.Mail_ScheduleDate,getdate()),                              
             Efce.Mail_Attechement,                              
             Efce.Mail_TempleteBody,                              
             1 AS Limit                              
      FROM   Emailsfiltercampaignexecution AS Efce                              
             INNER JOIN #tempMobile Tm                              
        ON Tm.userID = Efce.Mail_UserID                    
                        AND ValidEntries = 1                              
      WHERE  Efce.IsCompleted = 1                              
                              
  --update EmailsFilter set EmailsFilter.Mail_Priority=2                            
  --    from   EmailsFilter inner join CustomerEmail on  EmailsFilter.Mail_ToEmail=CustomerEmail.Email                            
                   
      INSERT INTO Mailcreditdetails                              
                  (ID,                              
                   -- Credit_ID -- this column value is auto-generated                              
                   M_ID,                              
                   FromUser_ID,                              
                   [User_ID],                              
                   Debits,                              
                 Credits,                              
                 Balance,                              
                   Validity,                              
                   Default_Credit,                              
                   FromDate,                              
                   ToDate,                              
                   DateCreated,                              
                   DateUpdated,                              
               EmpUpdated,                              
                   MachineName,                              
                   LastModified,                              
                   typecredit)                              
      SELECT Newid(),                              
             (SELECT TOP 1 Ud.M_ID                              
              FROM   User_detail AS Ud                              
              WHERE  Ud.[User_ID] = A.Mail_UserID),                              
             A.Mail_UserID,                              
             A.Mail_UserID,                              
             A.NoofRecipients,                              
             0,                              
             (SELECT TOP 1 Mcd.Balance                              
              FROM   Mailcreditdetails AS Mcd                              
              WHERE  Mcd.[User_ID] = A.Mail_UserID                              
              ORDER  BY Mcd.Credit_ID DESC) - A.NoofRecipients,                              
             99999,                              
       '',                              
             Getdate(),                              
             Getdate(),                              
             Getdate(),                              
             Getdate(),                              
             '',                              
             '',                              
             Getdate(),                              
             ''                              
      FROM   (SELECT DISTINCT Ed.Mail_UserID,                              
                              Count(*) AS NoofRecipients                              
              FROM   Emailsfiltercampaignexecution Ed                              
                     INNER JOIN #tempMobile Tm                              
                  ON Tm.userID = Ed.Mail_UserID                              
                                AND ValidEntries = 1                              
              WHERE  Ed.IsCompleted = 1                              
              GROUP  BY Mail_UserID) A                              
                              
      ----End                              
      UPDATE Kd                              
      SET    Executiontime = Getdate(),                              
             Noofrecipients = (SELECT Count(*)                              
                               FROM   Emailsfiltercampaignexecution AS Tt                              
                               WHERE  Tt.CampaignID = Kd.CampaignID                              
                                      AND Tt.ParentID = Kd.ParentID),                              
             Batchid = Tt.BatchID,                              
             Ismessages = 1,                              
             Isexecuted = 1                              
      FROM   Usercampaignexecutionhistory Kd                              
             INNER JOIN #tempTable Tt                              
          ON Tt.CampaignID = Kd.CampaignID                              
             INNER JOIN #tempMobile Tm                              
                     ON Tm.userID = Tt.userID                              
                        AND Validentries = 1                              
      WHERE  Kd.BatchID IS NULL                              
                              
      ---------------------------------Send Notification mail --------------------                              
      INSERT INTO Getbatchrecord                              
                  ([User_id],                              
                   RandNum)                              
      SELECT TOP 1 ParentID,                              
                   CampaignID              FROM   Emailsfiltercampaignexecution                              
      WHERE  IsCompleted = 1                              
                              
      DECLARE @Batchidmails BIGINT                              
                              
      SELECT @Batchidmails = Max(BatchID)                             
      FROM   Getbatchrecord Gbr                              
                              
      DELETE Kd                              
      FROM   Getbatchrecord Kd                              
      WHERE  Kd.BatchID = @Batchidmails                              
                              
      INSERT INTO Batchemail_infos                              
                  (                              
      -- ID -- this column value is auto-generated                              
      BatchID,                              
                   UserID,                              
                   SenderName,                           
   [Message],                              
                   TotalRecords,                              
                   TotalProcessed,                              
                   ProcessTable,                              
                   IsProcess,                              
                   Priority_Level,                              
                   BatchInsertTime,                              
                   BatchProcessTime,                              
                   ScheduledDate,                              
                   ScheduledTime,                              
                   TemplateID,                              
                   [Route],                              
                   PageName,                              
                   IsScheduled,                              
                   Email_Subject,                              
                   ReplyTo,                              
                   Amount,                              
                   Currency)                              
      SELECT @Batchidmails,                              
             335,                              
             Ucm.NotificationMail,                              
             'As promised , Your ' + CASE WHEN Ucm.MailReplyTo <> '' THEN 'Mail'                              
             ELSE                              
             'SMS'                              
             END + ' campaign '                              
             + Ucm.CampaignName + ' scheduled for '                              
             + Cast(Getdate() AS VARCHAR(50))                              
             +                              
' is executed successfully. You can log in to your & check the delivery report in the campaign history'                              
       ,                              
1,                              
0,                              
0,                              
0,                              
1,                              
Getdate(),                              
Getdate(),                              
Getdate(),                              
Getdate(),                              
0,                              
0,                              
0,                              
0,                              
'Campaign execution alert',                              
'',                              
0,                            
0                
FROM   Emailsfiltercampaignexecution Tt                              
       INNER JOIN Usercampaignmaster AS Ucm                              
               ON Ucm.ID = Tt.CampaignID                              
                  AND Ucm.IsScheduled = 1                              
                  AND Ucm.ParentID = Tt.ParentID                              
WHERE  Tt.IsCompleted = 1                              
GROUP  BY Ucm.NotificationMail,                              
          Ucm.MailReplyTo,                              
          Ucm.CampaignName                              
                              
    INSERT INTO Clientemails                              
                (                
    -- Id -- this column value is auto-generated                              
    GUID,                              
                 Email_Id,                              
               SentDateTime,                              
                 UserId,                              
                 ReplyTo,                              
                 [Status],                              
                 BatchID,                              
                 [Message])                              
    SELECT Newid(),                              
           Ucm.NotificationMail,                              
           Getdate(),                              
           335,                              
           '',                              
           '',                              
@Batchidmails,                              
           'As promised , Your ' + CASE WHEN Ucm.MailReplyTo <> '' THEN 'Mail'                              
           ELSE                              
           'SMS'                              
           END + ' campaign '                              
           + Ucm.CampaignName + ' scheduled for '                              
           + Cast(Getdate() AS VARCHAR(50))                              
           +                              
' is executed successfully. You can log in to your & check the delivery report in the campaign history'                              
FROM   Emailsfiltercampaignexecution Tt                              
       INNER JOIN Usercampaignmaster AS Ucm                              
               ON Ucm.ID = Tt.CampaignID                              
                  AND Ucm.IsScheduled = 1                              
                  AND Ucm.ParentID = Tt.ParentID                              
WHERE  Tt.IsCompleted = 1                              
GROUP  BY Ucm.NotificationMail,   
          Ucm.MailReplyTo,                              
          Ucm.CampaignName                              
                              
    INSERT INTO Emailsfilter                              
                (Mail_GUID,                              
                 -- Mail_ID -- this column value is auto-generated                              
                 Mail_FromEmail,                              
         Mail_ToEmail,                              
                 Mail_Subject,                              
                 Mail_TempleteName,                              
                 Messages,                  
                 Mail_InsertedDate,                              
                 Mail_UserID,                              
                 ReplyTo,                        
                 Mail_BatchID,                              
                 Mail_Priority,                              
                 Mail_ScheduleDate,                              
                 Mail_Attechement,                              
                 Mail_TempleteBody,                              
                 IsMonitor)                              
    SELECT Newid(),                              
           'contactus@email19.in',                              
           A.NotificationMail,                              
           'Campaign execution alert',                              
           '',                              
           'As promised , Your ' + CASE WHEN A.MailReplyTo <> '' THEN 'Mail'                              
           ELSE                              
'SMS' END             
     + ' campaign '                              
           + A.CampaignName + ' scheduled for '                              
           + Cast(Getdate() AS VARCHAR(50))                              
           +                              
' is executed successfully. You can log in to your & check the delivery report in the campaign history'                              
       ,                              
Getdate(),                              
335,                              
'',                              
@Batchidmails,                              
1,                              
Getdate(),                              
0,                              
'',                              
1                              
FROM   (SELECT DISTINCT Ucm.CampaignName,                              
                        Ucm.MailReplyTo,                              
                    Ucm.NotificationMail                              
        FROM   Emailsfiltercampaignexecution Tt                              
               INNER JOIN Usercampaignmaster AS Ucm                   
                       ON Ucm.ID = Tt.CampaignID                              
                          AND Ucm.IsScheduled = 1                              
                          AND Ucm.ParentID = Tt.ParentID                              
        WHERE  Tt.IsCompleted = 1                              
        GROUP  BY Ucm.NotificationMail,                              
                  Ucm.CampaignName,                              
                  Ucm.MailReplyTo) A                              
                                              
           --update u set u.assid = s.assid from ud u inner join sale s on u.id = s.udid                               
                                    
            
      --update EmailsFilter set EmailsFilter.Mail_Priority=2                            
      --from   EmailsFilter inner join CustomerEmail on  EmailsFilter.Mail_ToEmail=CustomerEmail.Email                            
                                              
                                              
                                              
                        
                                              
                              
    INSERT INTO Mailcreditdetails                              
                (ID,                   
                 -- Credit_ID -- this column value is auto-generated                              
                 M_ID,                              
                 FromUser_ID,                              
                 [User_ID],                              
                 Debits,                              
                 Credits,                              
                 Balance,                              
                 Validity,                              
                 Default_Credit,                              
                 FromDate,                              
                 ToDate,                              
                 DateCreated,                              
                 DateUpdated,                              
                 EmpUpdated,                              
                 MachineName,                              
                 LastModified,                              
                 typecredit)                              
    SELECT Newid(),                              
           10001,                              
           335,                              
           335,                           
           Count(*),                              
           0,                              
           (SELECT TOP 1 Mcd.Balance                              
            FROM   Mailcreditdetails AS Mcd                              
            WHERE  Mcd.[User_ID] = 335                              
            ORDER  BY Mcd.Credit_ID DESC) - Count(*),                              
    99999,                              
           0,                              
           Getdate(),                              
           Getdate(),                              
           Getdate(),                              
           Getdate(),                              
           'Campaign Exec',           
           '',                              
           Getdate(),                              
           0                              
    FROM   (SELECT DISTINCT Ucm.CampaignName,                              
                            Ucm.MailReplyTo,                              
                            Ucm.NotificationMail                              
            FROM   Emailsfiltercampaignexecution Tt                              
                   INNER JOIN Usercampaignmaster AS Ucm                              
                           ON Ucm.ID = Tt.CampaignID                              
                              AND Ucm.ParentID = Tt.ParentID                           
                              AND Ucm.IsScheduled = 1                              
            WHERE  Tt.IsCompleted = 1                              
 GROUP  BY Ucm.NotificationMail,                              
                      Ucm.CampaignName,                              
                      Ucm.MailReplyTo) A                              
                              
    ---------------------------------Send Notification Mail End ----------------                               
    DELETE Kd                              
    FROM   Emailsfiltercampaignexecution Kd                              
           INNER JOIN #tempTable Tt                              
                   ON Tt.CampaignID = Kd.CampaignID                        
                                         
 if OBJECT_ID('tempdb..##campaignrunmail') is not null   
     begin               
    UPDATE Kd                      
 SET    Kd.step3 = 1 ,Step3DateTime=GETDATE() ,              
 Step3Recipients=(select isnull(noofrecipients,0) from usercampaignexecutionhistory ud              
 where ud.CampaignID=Kd.CampaignID and ID=(select MAX(id) from usercampaignexecutionhistory               
 ud2 where ud.CampaignID=ud2.CampaignID))              
 FROM   usercampaignhistory Kd join ##campaignrunmail c on Kd.ID=c.campaignrunid             
 end  
 else  
 begin  
 UPDATE Kd                      
 SET  Kd.step3 = 1 ,Step3DateTime=GETDATE() ,              
 Step3Recipients=(select isnull(noofrecipients,0) from usercampaignexecutionhistory ud              
 where ud.CampaignID=Kd.CampaignID and ID=(select MAX(id) from usercampaignexecutionhistory               
 ud2 where ud.CampaignID=ud2.CampaignID))              
 FROM   usercampaignhistory Kd join usercampaignexecutionhistory uch on uch.CampaignID=kd.CampaignID where kd.ID =(select MAX(id) from  
 usercampaignhistory kd1 where kd1.CampaignID=kd.CampaignID)  
 end               
                              
 --   UPDATE Kd                              
 --   SET    Kd.Step3 = 1 ,Step3DateTime=GETDATE()           
 --   FROM   Usercampaignhistory Kd                              
 --          INNER JOIN #tempTable A                              
 --                  ON Kd.CampaignID = A.CampaignID                              
                               
    DROP TABLE #tempMobile                              
                              
    DROP TABLE #tempTable    
     if OBJECT_ID('tempdb..##campaignrunmail') is not null   
     begin                                       
    delete from ##campaignrunmail where DATE< (select CampaignExecutedDatetime from UserCampaignExecution where issms=0)   
    end      
    end
END 


