/* ============================================================
   Procedure: [dbo].[Usp_insertclonedeliverycampaignmails_NewAbdul]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

            
CREATE   PROCEDURE [dbo].[Usp_insertclonedeliverycampaignmails_NewAbdul] (@jobId bigint)                                   
AS                                    
  BEGIN         
        
        
      INSERT INTO Getbatchrecord                                    
                  (                                    
      -- BatchID -- this column value is auto-generated                                    
       [User_id],                                    
                   RandNum)                                    
      SELECT DISTINCT Ucerm.ParentID,                                    
                      Ucerm.CampaignID                                    
      FROM   EmailsfiltercampaignexecutionTest2 AS Ucerm With(nolock)    
                                    
      SELECT     
     ROW_NUMBER() Over(order by CampaignId,ParentId) Id,    
     Ucerm.CampaignID,       
     Ucerm.ParentID                               ,    
                     -- Cast(Ucerm.Messages AS VARCHAR(MAX))  AS  Messages,                                    
                      dbo.Fn_createbatchid(Ucerm.CampaignID, Ucerm.ParentID) AS BatchID,                                  
                     Ucerm.Mail_FromEmail,                                    
                      Ucerm.Mail_UserID AS UserID,    
                      Ucerm.Mail_Subject,    
                      Ucerm.ReplyTo,    
                      Count(*) cnt    
                     -- Ucerm.Mail_ToEmail,                                    
   INTO   #tempTable                                    
      FROM   EmailsfiltercampaignexecutionTest2 Ucerm                                    
      WHERE  Ucerm.IsCompleted = 1         
      Group by  Ucerm.CampaignID,       
     Ucerm.ParentID , Ucerm.Mail_FromEmail,                                    
                      Ucerm.Mail_UserID,    
                      Ucerm.Mail_Subject,    
                      Ucerm.ReplyTo                                
          
      SELECT A.UserID,a.CampaignID, a.cnt,A.BatchID, SUM(b.cnt) RunningTotal into #TempTableRunningTotal    
   FROM   #tempTable a join    
       #tempTable b  on a.userid=b.userid  
   WHERE b.CampaignID <= a.CampaignID    
   GROUP BY A.UserID, a.CampaignID, a.cnt,A.BatchID    
   ORDER BY a.CampaignID;    
          
          
      DELETE Kd                                    
      FROM   Getbatchrecord Kd                                    
             INNER JOIN #tempTable Tt                                    
                     ON Tt.BatchID = Kd.BatchID                                    
                                  
                                    
      --- Calculate credits                                    
      SELECT B.UserID,     
    B.CampaignID,                                   
             CASE                                    
               WHEN B.Balance > B.Credits THEN 1                                    
               ELSE 0 --test, otherwise 0                                    
             END AS ValidEntries                                    
      INTO   #tempMobile                                    
      FROM   (SELECT A.UserID,      
      A.CampaignID,                                  
                       (A.Credits)   AS Credits,  --Runningtotal                                  
                     A.Balance                                    
              FROM   (SELECT Tt.UserID,                                    
                             TT.RunningTotal AS Credits,    
                             TT.CampaignID,                                    
                            -- Tt.Mail_ToEmail,                              
                             Tt.BatchID,                                    
                             (SELECT TOP 1 Balance                                    
                              FROM   Mailcreditdetails AS Mcd                                    
                              WHERE  Mcd.[User_ID] = Tt.UserID                      
                              ORDER  BY Credit_ID DESC)     AS Balance                                    
                      FROM   #TempTableRunningTotal Tt) A                                    
              GROUP  BY A.UserID,                                    
                        A.Balance,A.CampaignID,A.credits) B    
     --select * from #tempmobile    
INSERT INTO Batchemail_infos(BatchID,UserID,SenderName,[Message],TotalRecords,TotalProcessed,ProcessTable,IsProcess,Priority_Level,BatchInsertTime,BatchProcessTime,ScheduledDate,ScheduledTime,TemplateID,[Route],PageName,IsScheduled,Email_Subject,ReplyTo)
                                  
      SELECT A.BatchID,A.UserID,U.Email as SenderName,(select top 1 Cast(e.Messages AS VARCHAR(MAX))     
      from EmailsfiltercampaignexecutionTest2 e     
      where e.CampaignID=a.campaignid),A.cnt,0,0,0,0,Getdate(),NULL,NULL,NULL,0,0,0,0,A.Mail_Subject,A.ReplyTo     
      FROM #tempTable A (nolock)     
      Inner join #tempMobile TM on Tm.CampaignID = A.CampaignID and TM.UserID = A.UserID     
      join user_detail u (nolock) on u.user_id=a.UserID  and TM.ValidEntries = 1    
         
      INSERT INTO Clientemails                                    
                  (                    
      -- Id -- this column value is auto-generated                                    
      GUID,                                    
                   Email_Id,                                    
                   SentDateTime,                                    
                   UserId,                                    
                   ReplyTo,                        
                   [Status],                                    
                   BatchID,                                    
                   [Message])                                    
      SELECT Newid(),                                    
             Efce.Mail_ToEmail,                                    
             Getdate(),                                    
             Efce.Mail_UserID,                                    
             Efce.ReplyTo,                                    
             '',                                    
             TT.BatchID,                                    
             Efce.Messages                                    
      FROM   EmailsfiltercampaignexecutionTest2 AS Efce                                    
             INNER JOIN #tempMobile Tm                                    
      ON Tm.CampaignID = Efce.CampaignID AND ValidEntries = 1   
   inner join #tempTable TT on TT.campaignid=efce.campaignid  
      WHERE  Efce.IsCompleted = 1                                    
                                    
      INSERT INTO Emailsfilter                                   
                  (Mail_GUID,                                    
                   Mail_FromEmail,                                    
                   Mail_ToEmail,                                    
                   Mail_Subject,                                    
                   Mail_TempleteName,                                    
                   Messages,                                    
                   Mail_InsertedDate,                                    
                   Mail_UserID,                                    
                   ReplyTo,                                    
                   Mail_BatchID,                                    
                   Mail_Priority,                                    
                   Mail_ScheduleDate,                                    
                   Mail_Attechement,                                    
                   Mail_TempleteBody,                                    
                   IsMonitor)                                    
      SELECT Newid(),                                    
             Efce.Mail_FromEmail,                                    
             Efce.Mail_ToEmail,                 
             Efce.Mail_Subject,                                 
             Efce.Mail_TempleteName,                                    
             Efce.Messages,                                  
             isnull(Efce.Mail_InsertedDate,getdate()),                                    
             Efce.Mail_UserID,                                    
             Efce.ReplyTo,                                    
             TT.BatchID,                                    
             Efce.Mail_Priority,                                    
             isnull(Efce.Mail_ScheduleDate,getdate()),                                    
             Efce.Mail_Attechement,                                    
             Efce.Mail_TempleteBody,                                    
             1 AS Limit                                    
      FROM   EmailsfiltercampaignexecutionTest2 AS Efce                                    
             INNER JOIN #tempMobile Tm                                    
        ON Tm.userID = Efce.Mail_UserID  and Tm.CampaignID = Efce.CampaignID                        
                        AND ValidEntries = 1   
                        inner join #tempTable TT on TT.campaignid=efce.campaignid                                   
      WHERE  Efce.IsCompleted = 1                                    
                                    
      INSERT INTO Mailcreditdetails                                    
                  (ID,                                    
                   -- Credit_ID -- this column value is auto-generated                                    
                   M_ID,                                    
                   FromUser_ID,                                    
                   [User_ID],                                    
                   Debits,                                    
                 Credits,                                    
                 Balance,                                    
                   Validity,                                    
                   Default_Credit,                                    
                   FromDate,                                    
                   ToDate,                                    
                   DateCreated,                                    
                   DateUpdated,                                    
               EmpUpdated,                                    
                   MachineName,                                    
                   LastModified,                                    
                   typecredit,  
                   campaignid)                                    
      SELECT Newid(),                                    
             (SELECT TOP 1 Ud.M_ID                                    
              FROM   User_detail AS Ud                                    
              WHERE  Ud.[User_ID] = A.UserID),                                    
             A.UserID,                                    
             A.UserID,                                    
             A.NoofRecipients,                                    
             0,                                    
             (SELECT TOP 1 Mcd.Balance                                    
              FROM   Mailcreditdetails AS Mcd                                    
              WHERE  Mcd.[User_ID] = A.UserID                                    
              ORDER  BY Mcd.Credit_ID DESC) - A.NoofRecipients,                                    
             99999,                                    
       '',                                    
             Getdate(),                                    
             Getdate(),                                    
             Getdate(),                                    
             Getdate(),                                    
             '',                                    
             '',                                    
             Getdate(),                                    
             '',  
             A.Campaignid                                    
      FROM   (SELECT DISTINCT Ed.UserID,Ed.CampaignID,Ed.ParentID,                                    
                              SUM(Ed.Cnt) AS NoofRecipients                                    
              FROM   #tempTable Ed                                    
                     INNER JOIN #tempMobile Tm                                    
                  ON Tm.userID = Ed.UserID   and Tm.CampaignID = Ed.CampaignID                                                                              AND ValidEntries = 1                                    
               GROUP  BY Ed.UserID,Ed.CampaignID,Ed.ParentID,ED.UserID) A        
                  
     UPDATE Kd                                    
      SET    Executiontime = Getdate(),                                    
             Noofrecipients = Tt.Cnt,            
             Batchid = Tt.BatchID,                                    
             --Ismessages = 1,                                    
             Isexecuted = case when tm.Validentries=1 then 1 else 0 end                                        
      FROM   Usercampaignexecutionhistory Kd                                    
             INNER JOIN #tempTable Tt                                    
          ON Tt.CampaignID = Kd.CampaignID                                    
             INNER JOIN #tempMobile Tm                                    
                     ON Tm.userID = Tt.userID   and Tm.CampaignID = Tt.CampaignID                                                  --AND Validentries = 1                                    
      WHERE  Jobid=@jobId--Kd.ID = (select MAX(id) from Usercampaignexecutionhistory Kd1 where kd1.CampaignID=kd.CampaignID)    
          
      --select * from UserCampaignExecutionHistory where CampaignID=497 order by id desc                                  
                                    
      ---------------------------------Send Notification mail --------------------                                    
      INSERT INTO Getbatchrecord                                    
                  ([User_id],                                    
                   RandNum)                                    
      SELECT ParentID,                                    
                   CampaignID FROM #tempTable                                    
                                     
       Select BatchID,[User_id] ParentID,RandNum CampaignID into #Batch from Getbatchrecord Gbr                                    Order by gbr.BatchID                       
                                    
      DELETE Kd                                    
      FROM   Getbatchrecord Kd                                    
     Inner join    #Batch B on B.BatchId = Kd.BatchID                                     
                                    
      INSERT INTO Batchemail_infos                                    
                  (                                    
      -- ID -- this column value is auto-generated                                    
      B.BatchID,                                    
                   UserID,                                    
                   SenderName,                                 
   [Message],                                    
                   TotalRecords,                                    
                   TotalProcessed,                                    
                   ProcessTable,                                    
                   IsProcess,                                    
                   Priority_Level,                                    
                   BatchInsertTime,                                    
             BatchProcessTime,                                    
                   ScheduledDate,                                    
                   ScheduledTime,                                    
TemplateID,                                
                   [Route],                                    
                   PageName,                                    
                   IsScheduled,                                    
                   Email_Subject,                                    
                   ReplyTo,                                    
                   Amount,                                    
                   Currency)                                    
      SELECT B.Batchid,                                    
             335,                                    
             Ucm.NotificationMail,                                    
             case when TM.ValidEntries = 0 then 'Oops, you don''t have sufficient mail credits to run your mail campaign "'    
             + Ucm.CampaignName + '" scheduled for '                                    
             + Cast(Getdate() AS VARCHAR(50))                                    
             + '. Pl refill your credit balance & rerun the campaign ' else      
             'As promised , Your Mail campaign "'    
             /*+ CASE WHEN Ucm.MailReplyTo <> '' THEN 'Mail'                                    
             ELSE                                    
             'SMS'                                    
             END + '*/                                     
             + Ucm.CampaignName + '" scheduled for '                                    
             + Cast(Getdate() AS VARCHAR(50))                                    
             +                                    
' is executed successfully. You can log in to your & check the delivery report in the campaign history' end as  [Message]                                  
       ,                                    
1,                                    
0,                                    
0,                                    
0,                                    
1,                                    
Getdate(),                                    
Getdate(),                                    
Getdate(),                                    
Getdate(),                                    
0,                                    
0,                                    
0,                                    
0,                                    
case when TM.ValidEntries = 0 then 'Failure: Your campaign "' + + UCM.CampaignName + '" failed due to insufficient credits' else 'Success : Your campaign "' + UCM.CampaignName + '" executed successfully' end as email_subject,    
'contactus@kit19.com',                                    
0,                                  
0                      
FROM   #temptable Tt                                    
       INNER JOIN Usercampaignmaster AS Ucm                                    
               ON Ucm.ID = Tt.CampaignID                                    
                  AND Ucm.IsScheduled = 1                                    
                  AND Ucm.ParentID = Tt.ParentID       
                  Inner join #tempMobile TM on TM.CampaignID = Tt.CampaignID   
                  Inner join #Batch B on B.CampaignId = Tt.CampaignId   
--WHERE  Tt.IsCompleted = 1  and TM.ValidEntries = 1                                  
/*GROUP  BY Ucm.NotificationMail,                                    
          Ucm.MailReplyTo,                                    
          Ucm.CampaignName,ValidEntries*/        
          --select top 10 * from  Batchemail_infos order by ID desc                             
                                    
    INSERT INTO Clientemails                                    
                (                      
    -- Id -- this column value is auto-generated                                    
    GUID,                                    
                 Email_Id,                                    
               SentDateTime,                                    
                 UserId,                                    
                 ReplyTo,                               
                 [Status],                                    
                 BatchID,                                    
                 [Message])          
    SELECT Newid(),                                    
           Ucm.NotificationMail,                                    
           Getdate(),                                    
           335,                                    
           'contactus@kit19.com',                                    
           '',                                    
B.Batchid,                                    
           case when TM.ValidEntries = 0 then 'Oops, you don''t have sufficient mail credits to run your mail campaign "'    
             + Ucm.CampaignName + '" scheduled for '                                    
             + Cast(Getdate() AS VARCHAR(50))                                    
             + '. Pl refill your credit balance & rerun the campaign ' else      
             'As promised , Your Mail campaign "'    
             /*+ CASE WHEN Ucm.MailReplyTo <> '' THEN 'Mail'                                    
             ELSE                                    
             'SMS'                                    
             END + '*/                                     
             + Ucm.CampaignName + '" scheduled for '                                    
             + Cast(Getdate() AS VARCHAR(50))                                    
             +                                    
' is executed successfully. You can log in to your & check the delivery report in the campaign history' end as  [Message]                                     
FROM   #tempTable Tt                                    
       INNER JOIN Usercampaignmaster AS Ucm                                    
               ON Ucm.ID = Tt.CampaignID                                    
                  AND Ucm.IsScheduled = 1                                    
                  AND Ucm.ParentID = Tt.ParentID      
                  Inner join #tempMobile TM on TM.CampaignID = Ucm.ID    
                  Inner join #Batch B on B.CampaignId = Tt.CampaignId                                
/*WHERE  Tt.IsCompleted = 1                                and TM.ValidEntries =1    
GROUP  BY Ucm.NotificationMail,         
          Ucm.MailReplyTo,                                    
          Ucm.CampaignName */                                   
                                    
    INSERT INTO Emailsfilter                                    
                (Mail_GUID,                                    
                 -- Mail_ID -- this column value is auto-generated                                    
                 Mail_FromEmail,                                    
         Mail_ToEmail,                                    
                 Mail_Subject,                                    
                 Mail_TempleteName,                                    
                 Messages,                        
                 Mail_InsertedDate,                                    
                 Mail_UserID,                                    
                 ReplyTo,                              
                 Mail_BatchID,                                    
                 Mail_Priority,                                    
                 Mail_ScheduleDate,                                    
                 Mail_Attechement,                                    
                 Mail_TempleteBody,                                    
                 IsMonitor)                                    
    SELECT Newid(),                                    
           'contactus@email19.in',                                    
           UCM.NotificationMail,                                    
           case when TM.ValidEntries = 0 then 'Failure: Your campaign "' + + UCM.CampaignName + '" failed due to insufficient credits' else 'Success : Your campaign "' + UCM.CampaignName + '" executed successfully' end as Mail_subject,                   
  
                 
           '',                                    
           case when TM.ValidEntries = 0 then 'Oops, you don''t have sufficient mail credits to run your mail campaign "'    
             + UCM.CampaignName + '" scheduled for '                                    
             + Cast(Getdate() AS VARCHAR(50))                                    
             + '. Pl refill your credit balance & rerun the campaign ' else      
             'As promised , Your Mail campaign "'    
             /*+ CASE WHEN Ucm.MailReplyTo <> '' THEN 'Mail'                                    
             ELSE                                    
             'SMS'                                    
             END + '*/                                     
             + UCM.CampaignName + '" scheduled for '                                    
             + Cast(Getdate() AS VARCHAR(50))                                    
             +                                    
' is executed successfully. You can log in to your & check the delivery report in the campaign history' end as  [Messages]                                     
       ,                                    
Getdate(),                                    
335,                                    
'contactus@kit19.com',                                    
B.Batchid,                                    
1,                                    
Getdate(),                                    
0,                                    
           case when TM.ValidEntries = 0 then 'Oops, you don''t have sufficient mail credits to run your mail campaign "'    
             + UCM.CampaignName + '" scheduled for '                                    
             + Cast(Getdate() AS VARCHAR(50))                                    
             + '. Pl refill your credit balance & rerun the campaign ' else      
             'As promised , Your Mail campaign "'    
             /*+ CASE WHEN Ucm.MailReplyTo <> '' THEN 'Mail'                                    
             ELSE                                    
             'SMS'                                    
             END + '*/                                     
             + UCM.CampaignName + '" scheduled for '                                    
             + Cast(Getdate() AS VARCHAR(50))                                    
             +                                    
' is executed successfully. You can log in to your & check the delivery report in the campaign history' end as mail_templetebody,                                    
1                                    
FROM   #tempTable Tt                                    
               INNER JOIN Usercampaignmaster AS Ucm                         
                       ON Ucm.ID = Tt.CampaignID                                    
                          AND Ucm.IsScheduled = 1                                    
                          AND Ucm.ParentID = Tt.ParentID                                    
                          Inner join #tempMobile TM on TM.CampaignID = Ucm.ID   
                          Inner join #Batch B on B.CampaignId = Tt.CampaignId                                 
  
                                                
    INSERT INTO Mailcreditdetails                                    
                (ID,                         
                 -- Credit_ID -- this column value is auto-generated                                    
                 M_ID,                                    
                 FromUser_ID,                                    
                 [User_ID],                                    
                 Debits,                                    
                 Credits,                                    
                 Balance,                                    
                 Validity,                                    
                 Default_Credit,                           
     FromDate,                                    
                 ToDate,                                    
                 DateCreated,                                    
                 DateUpdated,                                    
                 EmpUpdated,                                    
                 MachineName,                                    
                 LastModified,                                    
                 typecredit)                                    
    SELECT Newid(),                                    
           10001,                                    
           335,                                    
           335,                                 
           Count(*),                                    
           0,                                    
           (SELECT TOP 1 Mcd.Balance                                    
            FROM   Mailcreditdetails AS Mcd                                    
            WHERE  Mcd.[User_ID] = 335                                    
            ORDER  BY Mcd.Credit_ID DESC) - Count(*),                                    
    99999,                                    
           0,                                    
           Getdate(),                                    
           Getdate(),                                    
           Getdate(),                                    
           Getdate(),                                    
           'Campaign Exec',                 
           '',                                    
           Getdate(),                                    
           0                                    
    FROM   #tempTable Tt                                    
                   INNER JOIN Usercampaignmaster AS Ucm                                    
                           ON Ucm.ID = Tt.CampaignID                                    
                              AND Ucm.ParentID = Tt.ParentID                                 
                              AND Ucm.IsScheduled = 1      
                              Inner join #tempMobile TM on TM.CampaignID = Ucm.ID                                                                
         --   WHERE  Tt.IsCompleted = 1  and TM.ValidEntries = 1                                  
 /*GROUP  BY Ucm.NotificationMail,                                    
                      Ucm.CampaignName,                                    
                      Ucm.MailReplyTo,ValidEntries */                                   
                                 
    ---------------------------------Send Notification Mail End ----------------                                     
    DELETE Kd                                    
    FROM   EmailsfiltercampaignexecutionTest2 Kd                                    
           INNER JOIN #tempTable Tt                                    
                   ON Tt.CampaignID = Kd.CampaignID                              
                                               
    UPDATE Kd                            
   SET    Kd.step3 = 1 ,Step3DateTime=GETDATE() ,                    
   Step3Recipients= Case when ValidEntries = 1 then TT.cnt Else 0 End    
   FROM   usercampaignhistory Kd     
   inner join #tempTable TT on TT.CampaignID = Kd.CampaignID    
   inner join #tempMobile TM on TM.CampaignID = Kd.CampaignID    
   Where Kd.JobId = @jobId    
     
   UPDATE Kd                            
   SET    Kd.step3 = 1 ,Step3DateTime=GETDATE() FROM   usercampaignhistory Kd Where Kd.JobId = @jobId  
                 
    DROP TABLE #tempMobile                                    
                                    
    DROP TABLE #tempTable          
 END


GO

/* ============================================================
   Procedure: [dbo].[Usp_insertclonedeliverycampaignmailsCorrected]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_insertclonedeliverycampaignmailsCorrected] (@jobId bigint)
AS                                                
  BEGIN         
  create table #outputb(id int identity(1,1),bid bigint, u_id bigint,campaignid bigint)      
begin tran        
INSERT INTO Getbatchrecord                                                    
([User_id],RandNum)         
OUTPUT inserted.BatchID  as bId,inserted.User_id as u_id,inserted.RandNum as campaignid  INTO #outputb                                  
 SELECT DISTINCT Ucerm.ParentID,                                                
                      Ucerm.CampaignID                                                
      FROM   EmailsfiltercampaignexecutionTEST2 AS Ucerm With(nolock)       
      where jobid=@jobid                                                  
             
delete g From GetBatchRecord g join #outputb o on o.bid=g.BatchID      
commit                           
                   
                                                
     SELECT                 
     ROW_NUMBER() Over(order by Ucerm.CampaignId,Ucerm.ParentId) Id,                
     Ucerm.CampaignID,                   
     Ucerm.ParentID                               ,                
                     -- Cast(Ucerm.Messages AS VARCHAR(MAX))  AS  Messages,                                                
                      o.bid AS BatchID,                                              
                     Ucerm.Mail_FromEmail,                                                
                      Ucerm.Mail_UserID AS UserID,                
                      Ucerm.Mail_Subject,                
                      Ucerm.ReplyTo,                
                      Count(*) cnt                
                     -- Ucerm.Mail_ToEmail,                                                
   INTO   #tempTable                                                
      FROM   EmailsfiltercampaignexecutionTEST2 Ucerm -- join user_detail u on ucerm.Mail_UserID=u.user_id                        
      join #outputb o on o.u_id=ucerm.ParentID and o.campaignid=ucerm.campaignid                            
      WHERE  Ucerm.IsCompleted = 1 and jobid=@jobid  --and u.HasVirtualCredits=0                   
      Group by  Ucerm.CampaignID,                   
     Ucerm.ParentID , Ucerm.Mail_FromEmail,                                                
                      Ucerm.Mail_UserID,                
                      Ucerm.Mail_Subject,                
                      Ucerm.ReplyTo,o.bid               
                                  
    SELECT                 
     ROW_NUMBER() Over(order by Ucerm.CampaignId,Ucerm.ParentId) Id,                
     Ucerm.CampaignID,                   
     Ucerm.ParentID                               ,                
     -- Cast(Ucerm.Messages AS VARCHAR(MAX))  AS  Messages,                                                
      o.bid AS BatchID,                                              
     Ucerm.Mail_FromEmail,                                                
      Ucerm.Mail_UserID AS UserID,                
      Ucerm.Mail_Subject,                
      Ucerm.ReplyTo,                
      Count(*) cnt,            
      ParentSuperResellerId                
                     -- Ucerm.Mail_ToEmail,                                                
    INTO   #tempTableVirtual                                                
      FROM   EmailsfiltercampaignexecutionTEST2 Ucerm  join user_detail u on ucerm.Mail_UserID=u.user_id                      join #outputb o on o.u_id=ucerm.ParentID and o.campaignid=ucerm.campaignid                         
      WHERE  Ucerm.IsCompleted = 1  and u.HasVirtualCredits=1 and jobid=@jobid                   
      Group by  Ucerm.CampaignID,ParentSuperResellerId,                   
     Ucerm.ParentID , Ucerm.Mail_FromEmail,                                                
                      Ucerm.Mail_UserID,                
                      Ucerm.Mail_Subject,                
                      Ucerm.ReplyTo ,o.bid            
                                  
                                                               
                      
   SELECT A.UserID,a.CampaignID, a.cnt,A.BatchID, SUM(b.cnt) RunningTotal into #TempTableRunningTotal                
   FROM   #tempTable a inner join #tempTable b                
   on b.CampaignID <= a.CampaignID                
   GROUP BY A.UserID, a.CampaignID, a.cnt,A.BatchID                
    ORDER BY a.CampaignID;              
               
   SELECT A.UserID,a.CampaignID, a.cnt,A.BatchID, SUM(b.cnt) RunningTotal,a.ParentSuperResellerId into #TempTableRunningTotalVirtual
   FROM  #tempTableVirtual a inner join #tempTableVirtual b                
   on b.CampaignID <= a.CampaignID                
   GROUP BY A.ParentSuperResellerId, a.CampaignID, a.cnt,A.BatchID,A.UserID                
   ORDER BY a.CampaignID;              
                      
    drop table #outputb                  
     /* DELETE Kd                                                
      FROM   Getbatchrecord Kd                                                
             INNER JOIN #tempTable Tt                                                
                     ON Tt.BatchID = Kd.BatchID               
                                 
      DELETE Kd                                                
      FROM   Getbatchrecord Kd                                                
             INNER JOIN #tempTableVirtual Tt                                                
                     ON Tt.BatchID = Kd.BatchID*/                                             
                                              
                                                
      --- Calculate credits                                                
    SELECT B.UserID,                 
    B.CampaignID,                                               
             CASE                                                
               WHEN B.Balance >= B.Credits THEN 1                                                
               ELSE 0 --test, otherwise 0                                                
             END AS ValidEntries                                                
      INTO   #tempMobile                                                
      FROM   (SELECT A.UserID,                  
      A.CampaignID,                                              
                       (A.Credits)   AS Credits,  --Runningtotal                                              
                     A.Balance                                                
              FROM   (SELECT Tt.UserID,                                                
                             TT.RunningTotal AS Credits,                
                             TT.CampaignID,                                                
                            -- Tt.Mail_ToEmail,                                          
                             Tt.BatchID,                                                
                             (SELECT TOP 1 Balance                                                
                              FROM   Mailcreditdetails AS Mcd                                                
                              WHERE  Mcd.[User_ID] = Tt.UserID                         
                              ORDER  BY Credit_ID DESC)     AS Balance                                                
                      FROM   #TempTableRunningTotal Tt) A                                                
              GROUP  BY A.UserID,                                                
                        A.Balance,A.CampaignID,A.credits) B      
                            
update u set u.ReasonIfNotRun='Insuffcient Balance' from UserCampaignHistory u join #tempMobile t    
on u.campaignid=t.CampaignID and u.jobid=@jobid where t.validentries=0              
     --select * from #tempmobile              
                 
     SELECT B.UserID,                 
            B.CampaignID,                                               
            CASE              
               WHEN B.Balance > B.Credits THEN 1                                                
               ELSE 0 --test, otherwise 0                                                
             END AS ValidEntries,            
             B.ParentSuperResellerId                                                
      INTO   #tempMobileVirtual                                                
      FROM   (SELECT A.UserID,                  
      A.CampaignID,                                         
      (A.Credits)   AS Credits,  --Runningtotal                                              
      A.Balance,            
      A.ParentSuperResellerId                                                
      FROM   (SELECT Tt.UserID,                                                
                     TT.RunningTotal AS Credits,                
                     TT.CampaignID,                          
                     -- Tt.Mail_ToEmail,                                          
                     Tt.BatchID,                                                
                     (SELECT TOP 1 Balance                                                
                FROM   SuperResellerMailCreditDetails AS Mcd                                                
                      WHERE  Mcd.[User_ID] = Tt.ParentSuperResellerId                        
                      ORDER  BY Credit_ID DESC)     AS Balance,            
                      tt.ParentSuperResellerId                                                
               FROM   #TempTableRunningTotalVirtual Tt) A                                                
              GROUP  BY A.ParentSuperResellerId,A.UserID,                                               
                        A.Balance,A.CampaignID,A.credits) B             
                 
select t.*,u.email into #Insufficientresellerbalance from #tempMobileVirtual t join #tempMobile tt on t.CampaignID=tt.CampaignID join user_detail u on u.user_id=t.ParentSuperResellerId where tt.ValidEntries=0            
            
INSERT INTO Batchemail_infos(BatchID,UserID,SenderName,[Message],TotalRecords,TotalProcessed,ProcessTable,IsProcess,Priority_Level,BatchInsertTime,          
BatchProcessTime,ScheduledDate,ScheduledTime,TemplateID,[Route],PageName,IsScheduled,Email_Subject,ReplyTo)          
                                         
      SELECT A.BatchID,A.UserID,U.Email as SenderName,(select top 1 Cast(e.Messages AS VARCHAR(MAX))                 
      from EmailsfiltercampaignexecutionTEST2 e                 
      where e.CampaignID=a.campaignid and jobid=@jobid ),A.cnt,0,0,0,case when A.cnt>10 then 0 when A.cnt<=10 then 1 else 0 end,Getdate(),NULL,NULL,NULL,0,0,0,0,A.Mail_Subject,A.ReplyTo                 
      FROM #tempTable A (nolock)                 
      Inner join #tempMobile TM on Tm.CampaignID = A.CampaignID and TM.UserID = A.UserID                 
      join user_detail u (nolock) on u.user_id=a.UserID  and TM.ValidEntries = 1                
                  
            
                     
create table #output (GUID nvarchar(100) collate SQL_Latin1_General_CP1_CI_AS ,Email nvarchar(200) collate SQL_Latin1_General_CP1_CI_AS,Batchid bigint)                
          
 SELECT ROW_NUMBER()Over(Order by mail_ID) AS Id,* into #e from EmailsfiltercampaignexecutionTEST2 where jobid=@jobid           
 declare @mailcount int=(select COUNT(1) from #e)          
 declare @idcount bigint=(select MIN(id) from #e)           
 while @mailcount>0          
 begin           
 INSERT INTO Clientemails                                                
                  (                                
      -- Id -- this column value is auto-generated                                                
      GUID,                                
                   Email_Id,                                                
                   SentDateTime,                                                
                   UserId,                                                
                   ReplyTo,      
                   [Status],                                                
                   BatchID,                                                
                   [Message],            
                   campaignid,            
                   parentid)             
      OUTPUT inserted.GUID  as GUId,inserted.email_id,inserted.batchid as Email INTO #output                                                   
      SELECT Newid(),                                                
             Efce.Mail_ToEmail,                                                
             Getdate(),                                                
             Efce.Mail_UserID,                                                
             Efce.ReplyTo,                                                
             '',                                                
             TT.BatchID,                                                
             Efce.Messages,            
             efce.CampaignID,            
             efce.ParentID                                                
      FROM   #e AS Efce                             
             INNER JOIN #tempMobile Tm                                                
      ON Tm.CampaignID = Efce.CampaignID AND ValidEntries = 1               
   inner join #tempTable TT on TT.campaignid=efce.campaignid              
      WHERE  Efce.IsCompleted = 1 and efce.id<=@idcount+1000            
                                                
                         
      INSERT INTO Emailsfilter                                               
                  (Mail_GUID,                                                
                   Mail_FromEmail,                                                
                   Mail_ToEmail,                                                
                   Mail_Subject,                                                
                   Mail_TempleteName,                                                
                   Messages,                                                
                   Mail_InsertedDate,               
                   Mail_UserID,                                                
                   ReplyTo,                                                
                   Mail_BatchID,                                                
                   Mail_Priority,                                                
                   Mail_ScheduleDate,                                                
                   Mail_Attechement,                                                
                   Mail_TempleteBody,                                                
                   IsMonitor)                                                
      SELECT distinct O.Guid,                                                
             Efce.Mail_FromEmail,                                                
             Efce.Mail_ToEmail,                    
             Efce.Mail_Subject,                                             
             Efce.Mail_TempleteName,                                                
             cast(Efce.Messages as nvarchar(max)),                                              
             isnull(Efce.Mail_InsertedDate,getdate()),                                                
             Efce.Mail_UserID,                                                
             Efce.ReplyTo,                                                
             TT.BatchID,                                                
             case when tt.cnt>10 then Efce.Mail_Priority else 1 end,                                                
             isnull(Efce.Mail_ScheduleDate,getdate()),                                                
             Efce.Mail_Attechement,                                                
             cast(Efce.Mail_TempleteBody as nvarchar(max)),                                                
             1 AS Limit                                                
      FROM   #e AS Efce                                                           INNER JOIN #tempMobile Tm                                                
        ON Tm.userID = Efce.Mail_UserID  and Tm.CampaignID = Efce.CampaignID                                    
                        AND ValidEntries = 1               
                        inner join #tempTable TT on TT.campaignid=efce.campaignid              
                        inner join #output o on o.email=Efce.mail_toemail                                             
      WHERE  Efce.IsCompleted = 1 and o.batchid=tt.batchid and efce.id<=@idcount+1000            
      and not exists            
      (SELECT O.Guid                                               
      FROM   #e AS Efce                                  
             INNER JOIN #tempMobileVirtual Tm                                                
        ON Tm.userID = Efce.Mail_UserID  and Tm.CampaignID = Efce.CampaignID                                    
                        AND ValidEntries = 0               
                        inner join #tempTable TT on TT.campaignid=efce.campaignid              
                        inner join #output o on o.email=Efce.mail_toemail                                             
      WHERE  Efce.IsCompleted = 1 and o.batchid=tt.batchid)            
                  
                  
      INSERT INTO EmailsfilterVirtual                                               
                (Mail_GUID,                                                
                   Mail_FromEmail,                                                
                   Mail_ToEmail,                                                
                   Mail_Subject,                                                
                   Mail_TempleteName,                                                
                   Messages,                                                
                   Mail_InsertedDate,                                                
                   Mail_UserID,                                                
                   ReplyTo,                                                
                   Mail_BatchID,                                                
                   Mail_Priority,                                                
                   Mail_ScheduleDate,                                                
                   Mail_Attechement,                                                
                   Mail_TempleteBody,                                                
                   IsMonitor)                                                
      SELECT O.Guid,                                                
             Efce.Mail_FromEmail,                                                
             Efce.Mail_ToEmail,                    
             Efce.Mail_Subject,                                             
             Efce.Mail_TempleteName,                                                
             Efce.Messages,                                              
             isnull(Efce.Mail_InsertedDate,getdate()),                                                
             Efce.Mail_UserID,                                                
             Efce.ReplyTo,                                                
             TT.BatchID,                                                
             case when tt.cnt>10 then Efce.Mail_Priority else 1 end,                                                
             isnull(Efce.Mail_ScheduleDate,getdate()),                                                
             Efce.Mail_Attechement,                                                
             Efce.Mail_TempleteBody,                                                
             1 AS Limit                                                
      FROM   #e AS Efce                                                
             INNER JOIN #tempMobileVirtual Tm                                                
        ON Tm.userID = Efce.Mail_UserID  and Tm.CampaignID = Efce.CampaignID                                    
              AND ValidEntries = 0               
                        inner join #tempTableVirtual TT on TT.campaignid=efce.campaignid              
                        inner join #output o on o.email=Efce.mail_toemail                                             
      WHERE  Efce.IsCompleted = 1 and o.batchid=tt.batchid  and efce.id<=@idcount+1000            
  delete From #e where ID<=@idcount+1000              
  set @idcount=@idcount+1000          
  set @mailcount=@mailcount-1000          
  end               
                  
  truncate table #output                                             
                                                
      INSERT INTO Mailcreditdetails                                                
                  (ID,                                                
               -- Credit_ID -- this column value is auto-generated                                                
                   M_ID,                                                
                   FromUser_ID,                                                
                   [User_ID],                                                
                   Debits,                                                
                 Credits,                                                
                 Balance,                                                
                   Validity,                                                
                   Default_Credit,                                                
                   FromDate,                                                
                   ToDate,                                                
                   DateCreated,                                                
                   DateUpdated,                                                
               EmpUpdated,                                                
                   MachineName,                                                
                   LastModified,                                    
                   typecredit,              
                   campaignid)                                                
      SELECT Newid(),                                                
             (SELECT TOP 1 Ud.M_ID                                                
              FROM   User_detail AS Ud                                                
              WHERE  Ud.[User_ID] = A.UserID),                                                
             A.UserID,                                                
             A.UserID,                                                
             A.NoofRecipients,                                                
             0,                                                
             (SELECT TOP 1 Mcd.Balance                                                
              FROM   Mailcreditdetails AS Mcd                                                
              WHERE  Mcd.[User_ID] = A.UserID                                                
              ORDER  BY Mcd.Credit_ID DESC) - A.NoofRecipients,                                                
             99999,                                                
       '',                                                
             Getdate(),                                                
             Getdate(),                                                
             Getdate(),     
             Getdate(),                                                
             '',                                                
             '',                                                
             Getdate(),                                       
             '',              
             A.Campaignid                                                
      FROM   (SELECT DISTINCT Ed.UserID,Ed.CampaignID,Ed.ParentID,                                                
                              SUM(Ed.Cnt) AS NoofRecipients                                                
FROM   #tempTable Ed                                                
                     INNER JOIN #tempMobile Tm                                                
                  ON Tm.userID = Ed.UserID   and Tm.CampaignID = Ed.CampaignID             
                  where Ed.Cnt>0 AND ValidEntries = 1                                                
               GROUP  BY Ed.UserID,Ed.CampaignID,Ed.ParentID,ED.UserID) A                
            
      INSERT INTO SuperresellerMailcreditdetails                                                
                  (ID,                                                
                   -- Credit_ID -- this column value is auto-generated                                                
                   M_ID,                                                
                   FromUser_ID,                                                
                   [User_ID],                                                
                   Debits,                                                
    Credits,                                                
    Balance,                                                
                   Validity,                                                
                   Default_Credit,                                                
                   FromDate,                                                
                   ToDate,                                                
                   DateCreated,                                                
                   DateUpdated,                                                
    EmpUpdated,                                                
                   MachineName,                                                
 LastModified,                                                
                   typecredit,              
                   campaignid)                                                
      SELECT Newid(),                                                
             (SELECT TOP 1 Ud.M_ID                                                
              FROM   User_detail AS Ud                                                
              WHERE  Ud.[User_ID] = A.ParentSuperResellerId),                                                
             A.ParentSuperResellerId,                                                
             A.ParentSuperResellerId,                        
             A.NoofRecipients,                                                
             0,                                                
             (SELECT TOP 1 Mcd.Balance                                                
              FROM   SuperResellerMailCreditDetails AS Mcd                                                
              WHERE  Mcd.[User_ID] = A.ParentSuperResellerId                                                
              ORDER  BY Mcd.Credit_ID DESC) - A.NoofRecipients,                                                
             99999,                                                
    '',                                                
             Getdate(),                                                
             Getdate(),                                                
             Getdate(),                                                
             Getdate(),                                                
     '',                                                
             '',                                                
             Getdate(),                                       
             '',              
             A.Campaignid                                                
      FROM   (SELECT DISTINCT tm.ParentSuperResellerId,ed.userid,Ed.CampaignID,Ed.ParentID,SUM(Ed.Cnt) AS NoofRecipients                                                
              FROM   #tempTable Ed                                                
                     INNER JOIN #tempMobileVirtual Tm                                                
                  ON Tm.userID = Ed.UserID   and Tm.CampaignID = Ed.CampaignID             
                  where Ed.Cnt>0 AND ValidEntries = 1                                                
               GROUP  BY Ed.UserID,tm.ParentSuperResellerId,Ed.CampaignID,Ed.ParentID,ED.UserID) A                               
                           
                           
                               
                              
     UPDATE Kd                                                
      SET    Executiontime = Getdate(),                                                
             Noofrecipients = Tt.Cnt,                        
             Batchid = Tt.BatchID,                                                
             --Ismessages = 1,                                                
             Isexecuted = case when tm.Validentries=1 then 1 else 0 end                                                    
      FROM   Usercampaignexecutionhistory Kd                                                
             INNER JOIN #tempTable Tt                     
          ON Tt.CampaignID = Kd.CampaignID                                                
             INNER JOIN #tempMobile Tm                                                
