        'We are unable to run some of your users'' campaigns because of insufficient credits. Please refill your mail credits to enjoy uninterrupted services for your users.' as mail_templetebody,                                                    
        1                                                    
    FROM   #tempTable Tt                   
    inner join #Insufficientresellerbalance inrc on inrc.CampaignID=tt.CampaignID                                                 
       INNER JOIN Usercampaignmaster AS Ucm                                         
           ON Ucm.ID = Tt.CampaignID                                                    
          AND Ucm.IsScheduled = 1                                                    
          AND Ucm.ParentID = Tt.ParentID                                                    
          Inner join #tempMobile TM on TM.CampaignID = Ucm.ID                   
          Inner join #Batch B on B.CampaignId = Tt.CampaignId                 
          inner join #output o on o.Email=ucm.NotificationMail                 
          where o.Batchid=B.BatchID                                             
                  
                                                                
    INSERT INTO Mailcreditdetails                                                    
        (ID,                                         
         -- Credit_ID -- this column value is auto-generated                        
M_ID,                                                    
         FromUser_ID,                                                    
         [User_ID],                                                    
         Debits,                                                    
         Credits,                                                    
         Balance,                                                    
         Validity,                                                    
         Default_Credit,                                           
         FromDate,                                                    
         ToDate,                                                    
         DateCreated,                                                    
         DateUpdated,                                                    
         EmpUpdated,                                                    
         MachineName,                    
         LastModified,                                                    
         typecredit)                                                    
    SELECT Newid(),                                                    
       10001,                                      
       335,                                                    
       335,                                                 
       Count(*),                                                    
       0,                                                    
       (SELECT TOP 1 Mcd.Balance                                                    
        FROM   Mailcreditdetails AS Mcd                                                    
        WHERE  Mcd.[User_ID] = 335                                                    
        ORDER  BY Mcd.Credit_ID DESC) - Count(*),               
        99999,                                                    
       0,                                                    
       Getdate(),                                                    
       Getdate(),                                 
       Getdate(),                                                    
       Getdate(),                                                    
       'Campaign Exec',                                 
       '',                                                    
       Getdate(),                                                    
       0                                                    
    FROM   #tempTable Tt         
       INNER JOIN Usercampaignmaster AS Ucm                                                    
           ON Ucm.ID = Tt.CampaignID                                                    
          AND Ucm.ParentID = Tt.ParentID                                                 
          AND Ucm.IsScheduled = 1                      
          Inner join #tempMobile TM on TM.CampaignID = Ucm.ID                                                            
    union                
                    
      SELECT Newid(),                                                    
       10001,                                                    
       335,                                                    
       335,                                                 
       Count(*),                                                    
       0,                                                    
       (SELECT TOP 1 Mcd.Balance                                                    
        FROM   Mailcreditdetails AS Mcd                                                    
        WHERE  Mcd.[User_ID] = 335                                                    
        ORDER  BY Mcd.Credit_ID DESC) - Count(*),                                                    
        99999,                                                    
       0,                                                    
       Getdate(),                                                    
       Getdate(),                                                    
       Getdate(),                                                    
       Getdate(),                                                    
       'Campaign Exec',                                 
       '',                                                    
       Getdate(),                                                    
       0                                                    
    FROM   #tempTable Tt                  
       inner join #tempMobileVirtual tmv on tmv.CampaignID=tt.CampaignID                                                  
       INNER JOIN Usercampaignmaster AS Ucm                                                    
           ON Ucm.ID = Tt.CampaignID                                        
          AND Ucm.ParentID = Tt.ParentID                                                 
          AND Ucm.IsScheduled = 1                      
          Inner join #tempMobile TM on TM.CampaignID = Ucm.ID                                                             
          where tmv.ValidEntries=0                
                                   
    drop table #Batch                                                    
      end          
                  
    ---------------------------------Send Notification Mail End ----------------                                                     
    declare @emailcount bigint=(select count(1)  FROM   EmailsfiltercampaignexecutionTEST2 Kd                                                    
           INNER JOIN #tempTable Tt                                                    
                   ON Tt.CampaignID = Kd.CampaignID and jobid=@jobid)              
   while @emailcount>0              
   begin              
 DELETE top (1000) Kd                                                    
    FROM   EmailsfiltercampaignexecutionTEST2 Kd                                                    
           INNER JOIN #tempTable Tt                                                    
                   ON Tt.CampaignID = Kd.CampaignID and jobid=@jobid               
 set @emailcount=@emailcount-1000              
    end              
/* DELETE Kd                                                    
    FROM   campaignmessages Kd                                                    
           INNER JOIN #tempTable Tt                                                    
                   ON Tt.CampaignID = Kd.CampaignID and jobid=@jobid  */                
               
                                 
                                       
   UPDATE Kd                                            
   SET    Kd.step3 = 1 ,Step3DateTime=GETDATE() ,                                    
   Step3Recipients= Case when ValidEntries = 1 then TT.cnt Else 0 End                    
   FROM   usercampaignhistory Kd                     
   inner join #tempTable TT on TT.CampaignID = Kd.CampaignID                    
   inner join #tempMobile TM on TM.CampaignID = Kd.CampaignID                    
   Where Kd.JobId = @jobId                    
                     
   UPDATE Kd                                            
   SET    Kd.step3 = 1 ,Step3DateTime=GETDATE() FROM   usercampaignhistory Kd Where Kd.JobId = @jobId                
                 
   update u set executeddatetime=getdate() from usercampaignmaster u join usercampaignhistory Kd on kd.campaignid=u.id and Kd.JobId = @jobId                
                      
    --Code added to update nextexecutiondate in usercampaignhistory Start--                  
    select campaignid into #FindCampaignsNextExecution from #tempTable t join UserCampaignMaster ucm on t.CampaignID=ucm.id    left join userschedules  us on us.id=ucm.scheduleid               
    where ucm.IsActive=1 and ucm.IsSchedule=1 and ucm.IsScheduled=1 and us.IsOnce=0        
                      
 declare @count int =isnull((select COUNT(1) from #FindCampaignsNextExecution),0)                  
 if @count>0                  
 begin                  
    create table #nextexec1(campaignid bigint,nextexecution datetime)                              
    WHILE @Count > 0                                  
  BEGIN                                  
   DECLARE @Campaignid BIGINT = (                                  
       SELECT TOP 1 campaignid                                  
    FROM   #FindCampaignsNextExecution                                  
      )                      
                 
   INSERT INTO #nextexec1                                  
       (                                  
      campaignid,                                  
      nextexecution                                  
       )                                  
    EXEC Usp_getnextscheduledate                              
       @Campaignid                                  
                  
    DELETE                                   
    FROM   #FindCampaignsNextExecution                                  
    WHERE  campaignid = @Campaignid                                  
                  
    SET @Count = @Count - 1                    
  END                  
                 
   update u set NextExecuteDateTime= nextexecution from usercampaignmaster u join #nextexec1 n on n.campaignid=u.id                  
   where u.ExpiryDate > nextexecution or u.ExpiryDate is null                  
    drop table #nextexec1                  
    drop table #FindCampaignsNextExecution                
                    
 end                  
               
    --Code added to update nextexecutiondate in usercampaignhistory end--                             
    DROP TABLE #tempMobile                                                    
    DROP TABLE #tempTable                
    drop table #tempMobileVirtual                
    drop table #tempTableVirtual                
    drop table #Insufficientresellerbalance                
    drop table #TempTableRunningTotal                
    drop table #TempTableRunningTotalVirtual                
    drop table #output                 
                  
     if exists(select 1 from UserCampaignHistory where JobId=@jobId and IsEventBased=0 and isSMS=0)                
    begin              
    update usercampaignexecution set CampaignEnddatetime=GETDATE(),isrunning=0 where isevent=0 and isSMS=0              
    --select 'updated'              
    end              
     if exists(select 1 from UserCampaignHistory where JobId=@jobId and IsEventBased=1 and isSMS=0)              
    begin              
    update usercampaignexecution set CampaignEnddatetime=GETDATE(),isrunning=0 where isevent=1 and isSMS=0              
    end                  
 END     


