/* ============================================================
   Procedure: [dbo].[Usp_insertclonedeliverycampaignmailsCorrected_segregatemail_NoMailBody]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_insertclonedeliverycampaignmailsCorrected_segregatemail_NoMailBody] 
(@jobId bigint)

AS                                          
  BEGIN               
             
      INSERT INTO Getbatchrecord                                          
                  (                                          
      -- BatchID -- this column value is auto-generated                                          
       [User_id],                                          
                   RandNum)                                          
      SELECT DISTINCT Ucerm.ParentID,                                          
                      Ucerm.CampaignID                                          
      FROM   EmailsfiltercampaignexecutionTEST2 AS Ucerm With(nolock) where jobid=@jobid         
                                          
     SELECT           
     ROW_NUMBER() Over(order by Ucerm.CampaignId,Ucerm.ParentId) Id,          
     Ucerm.CampaignID,             
     Ucerm.ParentID                               ,          
                     -- Cast(Ucerm.Messages AS VARCHAR(MAX))  AS  Messages,                                          
                      dbo.Fn_createbatchid(Ucerm.CampaignID, Ucerm.ParentID) AS BatchID,                                        
                     Ucerm.Mail_FromEmail,                                          
                      Ucerm.Mail_UserID AS UserID,          
                      Ucerm.Mail_Subject,          
                      Ucerm.ReplyTo,          
                      Count(*) cnt,ucerm.ispersonalized          
                     -- Ucerm.Mail_ToEmail,                                          
   INTO   #tempTable                                          
      FROM   EmailsfiltercampaignexecutionTEST2 Ucerm -- join user_detail u on ucerm.Mail_UserID=u.user_id                                        
      WHERE  Ucerm.IsCompleted = 1 and jobid=@jobid  --and u.HasVirtualCredits=0             
      Group by  Ucerm.CampaignID,             
     Ucerm.ParentID , Ucerm.Mail_FromEmail,                                          
                      Ucerm.Mail_UserID,          
                      Ucerm.Mail_Subject,          
                      Ucerm.ReplyTo,ucerm.ispersonalized         
                            
    SELECT           
     ROW_NUMBER() Over(order by Ucerm.CampaignId,Ucerm.ParentId) Id,          
     Ucerm.CampaignID,             
     Ucerm.ParentID                               ,          
     -- Cast(Ucerm.Messages AS VARCHAR(MAX))  AS  Messages,                                          
      dbo.Fn_createbatchid(Ucerm.CampaignID, Ucerm.ParentID) AS BatchID,                                        
     Ucerm.Mail_FromEmail,                                          
      Ucerm.Mail_UserID AS UserID,          
      Ucerm.Mail_Subject,          
      Ucerm.ReplyTo,          
      Count(*) cnt,      
      ParentSuperResellerId,ispersonalized          
                     -- Ucerm.Mail_ToEmail,                                          
    INTO   #tempTableVirtual                                          
      FROM   EmailsfiltercampaignexecutionTEST2 Ucerm  join user_detail u on ucerm.Mail_UserID=u.user_id                                        
      WHERE  Ucerm.IsCompleted = 1  and u.HasVirtualCredits=1 and jobid=@jobid             
      Group by  Ucerm.CampaignID,ParentSuperResellerId,             
     Ucerm.ParentID , Ucerm.Mail_FromEmail,                                          
                      Ucerm.Mail_UserID,          
                      Ucerm.Mail_Subject,          
                      Ucerm.ReplyTo , ispersonalized      
                            
                                                         
                
   SELECT A.UserID,a.CampaignID, a.cnt,A.BatchID, SUM(b.cnt) RunningTotal into #TempTableRunningTotal          
   FROM   #tempTable a inner join #tempTable b          
   ON    b.CampaignID <= a.CampaignID          
   GROUP BY A.UserID, a.CampaignID, a.cnt,A.BatchID          
   ORDER BY a.CampaignID;        
         
   SELECT A.UserID,a.CampaignID, a.cnt,A.BatchID, SUM(b.cnt) RunningTotal,a.ParentSuperResellerId into #TempTableRunningTotalVirtual         
   FROM   #tempTableVirtual a inner join  #tempTableVirtual b          
   ON    b.CampaignID <= a.CampaignID          
   GROUP BY A.ParentSuperResellerId, a.CampaignID, a.cnt,A.BatchID,A.UserID          
   ORDER BY a.CampaignID;        
                
                
      DELETE Kd                                          
      FROM   Getbatchrecord Kd                                          
             INNER JOIN #tempTable Tt                                          
                     ON Tt.BatchID = Kd.BatchID         
                           
      DELETE Kd                                          
      FROM   Getbatchrecord Kd                                          
             INNER JOIN #tempTableVirtual Tt                                          
                     ON Tt.BatchID = Kd.BatchID                                       
                                        
                                          
      --- Calculate credits                                          
    SELECT B.UserID,           
    B.CampaignID,                                         
             CASE                                          
               WHEN B.Balance >= B.Credits THEN 1                                          
               ELSE 0 --test, otherwise 0                                          
             END AS ValidEntries                                          
      INTO   #tempMobile                                          
      FROM   (SELECT A.UserID,            
      A.CampaignID,                                        
                       (A.Credits)   AS Credits,  --Runningtotal                                        
                     A.Balance                                          
              FROM   (SELECT Tt.UserID,                                          
                             TT.RunningTotal AS Credits,          
                             TT.CampaignID,                                          
                            -- Tt.Mail_ToEmail,                                    
                             Tt.BatchID,                                          
                             (SELECT TOP 1 Balance                                          
                              FROM   Mailcreditdetails AS Mcd                                          
                              WHERE  Mcd.[User_ID] = Tt.UserID                   
                              ORDER  BY Credit_ID DESC)     AS Balance                                          
                      FROM   #TempTableRunningTotal Tt) A                                          
              GROUP  BY A.UserID,                                          
                        A.Balance,A.CampaignID,A.credits) B          
     --select * from #tempmobile        
           
     SELECT B.UserID,           
            B.CampaignID,                                         
            CASE                                          
               WHEN B.Balance > B.Credits THEN 1                                          
               ELSE 0 --test, otherwise 0                                          
             END AS ValidEntries,      
             B.ParentSuperResellerId                                          
      INTO   #tempMobileVirtual                                          
      FROM   (SELECT A.UserID,            
      A.CampaignID,                                        
      (A.Credits)   AS Credits,  --Runningtotal                                        
      A.Balance,      
      A.ParentSuperResellerId                                          
      FROM   (SELECT Tt.UserID,                                          
   TT.RunningTotal AS Credits,          
                     TT.CampaignID,                                          
                     -- Tt.Mail_ToEmail,                                    
                     Tt.BatchID,                                          
                     (SELECT TOP 1 Balance           
                      FROM   SuperResellerMailCreditDetails AS Mcd                                          
                      WHERE  Mcd.[User_ID] = Tt.ParentSuperResellerId                  
                      ORDER  BY Credit_ID DESC)     AS Balance,      
                      tt.ParentSuperResellerId                                          
               FROM   #TempTableRunningTotalVirtual Tt) A                                          
              GROUP  BY A.ParentSuperResellerId,A.UserID,                                         
                        A.Balance,A.CampaignID,A.credits) B       
           
select t.*,u.email into #Insufficientresellerbalance from #tempMobileVirtual t join #tempMobile tt on t.CampaignID=tt.CampaignID join user_detail u on u.user_id=t.ParentSuperResellerId where tt.ValidEntries=0      
      
INSERT INTO Batchemail_infos(BatchID,UserID,SenderName,[Message],TotalRecords,TotalProcessed,ProcessTable,IsProcess,Priority_Level,BatchInsertTime,    
BatchProcessTime,ScheduledDate,ScheduledTime,TemplateID,[Route],PageName,IsScheduled,Email_Subject,ReplyTo,ispersonalized)    
                                   
      SELECT A.BatchID,A.UserID,U.Email as SenderName,(select top 1 case when e.Messages is null then CAST(dbo.build_mailContent(c.templateid,c.campaignid,c.parentid,c.Messages COLLATE Latin1_General_CI_AI,e.Mail_ToEmail) AS NVARCHAR(MAX))           
      else cast(e.messages as nvarchar(max)) end from EmailsfiltercampaignexecutionTEST2 e join campaignmessages c on c.campaignid=e.CampaignID and c.jobid=e.jobid          
      where e.CampaignID=a.campaignid and e.jobid=@jobid ),A.cnt,0,0,0,case when A.cnt>10 then 0 when A.cnt<=10 then 1 else 0 end,Getdate(),NULL,NULL,NULL,  
   0,0,0,0,(select top 1 case when e.Mail_Subject is null then c.Mail_Subject COLLATE Latin1_General_CI_AI    
      else e.Mail_Subject end from EmailsfiltercampaignexecutionTEST2 e join campaignmessages c on c.campaignid=e.CampaignID and c.jobid=e.jobid          
      where e.CampaignID=a.campaignid and e.jobid=@jobid ),A.ReplyTo,ispersonalized           
      FROM #tempTable A (nolock)           
      Inner join #tempMobile TM on Tm.CampaignID = A.CampaignID and TM.UserID = A.UserID           
      join user_detail u (nolock) on u.user_id=a.UserID  and TM.ValidEntries = 1          
            
      
               
create table #output (GUID nvarchar(100) collate SQL_Latin1_General_CP1_CI_AS ,Email nvarchar(200) collate SQL_Latin1_General_CP1_CI_AS,Batchid bigint)          
    
 SELECT ROW_NUMBER()Over(Order by mail_ID) AS Id,* into #e from EmailsfiltercampaignexecutionTEST2 where jobid=@jobid     
 declare @mailcount int=(select COUNT(1) from #e)    
 declare @idcount bigint=(select MIN(id) from #e)     
 while @mailcount>0    
 begin     
 INSERT INTO Clientemails                                          
                  (                          
      -- Id -- this column value is auto-generated                                          
      GUID,                                          
                   Email_Id,                                          
                   SentDateTime,                                          
                   UserId,                                          
                   ReplyTo,                              
                   [Status],                                          
                   BatchID,                                          
                   --[Message],      
                   campaignid,      
                   parentid)       
      OUTPUT inserted.GUID  as GUId,inserted.email_id,inserted.batchid as Email INTO #output                    
      SELECT Newid(),                                          
             Efce.Mail_ToEmail,                                          
             Getdate(),                                          
             Efce.Mail_UserID,                                          
             Efce.ReplyTo,                                          
             '',                                          
             TT.BatchID,                                  
             --case when Efce.Messages is not null then efce.Messages else c.messages end,       
             efce.CampaignID,      
             efce.ParentID                                          
      FROM   #e AS Efce                                          
             INNER JOIN #tempMobile Tm                                          
      ON Tm.CampaignID = Efce.CampaignID AND ValidEntries = 1         
   inner join #tempTable TT on TT.campaignid=efce.campaignid left join campaignmessages c on  c.campaignid=efce.campaignid and c.jobid=efce.jobid      
      WHERE  Efce.IsCompleted = 1 and efce.id<=@idcount+1000      
                                          
                                          
      INSERT INTO Emailsfilter                                         
                  (Mail_GUID,                                          
                   Mail_FromEmail,                                          
                   Mail_ToEmail,                                          
                   Mail_Subject,                                          
                   Mail_TempleteName,                                          
                   --Messages,                                          
                   Mail_InsertedDate,         
                   Mail_UserID,                                          
                   ReplyTo,                                          
                   Mail_BatchID,                                          
                   Mail_Priority,                                          
                   Mail_ScheduleDate,                                          
                   Mail_Attechement,                                          
                   --Mail_TempleteBody,                                          
                   IsMonitor)                                          
      SELECT O.Guid,                                          
             Efce.Mail_FromEmail,                                          
             Efce.Mail_ToEmail,              
             case when Efce.mail_subject is not null then Efce.mail_subject else c.mail_subject end,                                        
             Efce.Mail_TempleteName,                                          
             --case when Efce.Messages is not null then cast(Efce.Messages as nvarchar(max)) else cast(c.Messages as nvarchar(max)) end,                                        
             isnull(Efce.Mail_InsertedDate,getdate()),                                          
             Efce.Mail_UserID,                                          
             Efce.ReplyTo,                                          
             TT.BatchID,                                          
             case when tt.cnt>10 then Efce.Mail_Priority else 1 end,                                          
             isnull(Efce.Mail_ScheduleDate,getdate()),                                          
             Efce.Mail_Attechement,                                          
             --case when Efce.Messages is not null then cast(Efce.Messages as nvarchar(max)) else cast(c.Messages as nvarchar(max)) end,                                          
             1 AS Limit                                          
      FROM   #e AS Efce                                          
             INNER JOIN #tempMobile Tm                                          
        ON Tm.userID = Efce.Mail_UserID  and Tm.CampaignID = Efce.CampaignID           
                        AND ValidEntries = 1         
                        inner join #tempTable TT on TT.campaignid=efce.campaignid        
                        inner join #output o on o.email=Efce.mail_toemail  left join campaignmessages c on  c.campaignid=efce.campaignid and c.jobid=efce.jobid                                         
      WHERE  Efce.IsCompleted = 1 and o.batchid=tt.batchid and efce.id<=@idcount+1000      
      and not exists      
      (SELECT O.Guid                                         
      FROM   #e AS Efce                                          
             INNER JOIN #tempMobileVirtual Tm                                          
        ON Tm.userID = Efce.Mail_UserID  and Tm.CampaignID = Efce.CampaignID                              
                        AND ValidEntries = 0         
                        inner join #tempTable TT on TT.campaignid=efce.campaignid        
                        inner join #output o on o.email=Efce.mail_toemail                                       
      WHERE  Efce.IsCompleted = 1 and o.batchid=tt.batchid)      
            
            
      INSERT INTO EmailsfilterVirtual                                         
                (Mail_GUID,                                          
                   Mail_FromEmail,                                          
                   Mail_ToEmail,                                          
                   Mail_Subject,                                          
                   Mail_TempleteName,                                          
                   Messages,                                          
                   Mail_InsertedDate,                                          
                   Mail_UserID,                                          
                   ReplyTo,                                          
                   Mail_BatchID,                                          
                   Mail_Priority,                                          
                   Mail_ScheduleDate,                                          
                   Mail_Attechement,                                          
                   Mail_TempleteBody,                                          
                   IsMonitor)                                          
      SELECT O.Guid,                                          
             Efce.Mail_FromEmail,                                          
             Efce.Mail_ToEmail,              
              case when Efce.mail_subject is not null then Efce.mail_subject else c.mail_subject end,                                        
             Efce.Mail_TempleteName,                                          
             case when Efce.Messages is not null then cast(Efce.Messages as nvarchar(max)) else cast(c.Messages as nvarchar(max)) end,                                        
             isnull(Efce.Mail_InsertedDate,getdate()),                                          
             Efce.Mail_UserID,                                          
             Efce.ReplyTo,                                          
             TT.BatchID,                                          
             case when tt.cnt>10 then Efce.Mail_Priority else 1 end,                                          
             isnull(Efce.Mail_ScheduleDate,getdate()),                                          
             Efce.Mail_Attechement,                                          
             case when Efce.Messages is not null then cast(Efce.Messages as nvarchar(max)) else cast(c.Messages as nvarchar(max)) end,                                        
             1 AS Limit                                          
      FROM   #e AS Efce                                          
             INNER JOIN #tempMobileVirtual Tm                                          
        ON Tm.userID = Efce.Mail_UserID  and Tm.CampaignID = Efce.CampaignID                              
         AND ValidEntries = 0         
                        inner join #tempTableVirtual TT on TT.campaignid=efce.campaignid        
                        inner join #output o on o.email=Efce.mail_toemail      left join campaignmessages c on  c.campaignid=efce.campaignid and c.jobid=efce.jobid                                                                       
      WHERE  Efce.IsCompleted = 1 and o.batchid=tt.batchid  and efce.id<=@idcount+1000      
  delete From #e where ID<=@idcount+1000        
  set @idcount=@idcount+1000    
  set @mailcount=@mailcount-1000    
  end         
            
  truncate table #output                                       
                                          
      INSERT INTO Mailcreditdetails                                          
                  (ID,             
