          inner join #tempMobileVirtual tmv on tmv.CampaignID=tt.CampaignID      
          where o.Batchid=B.BatchID and tmv.ValidEntries=0      
    union      
        
    SELECT o.guid,                                          
       'noreply@email19.in',                                          
       inrc.eMail,                              
       'Failure: Your users'' campaign "' + + UCM.CampaignName + '" failed because of insufficient mail credits in your account.' as Mail_subject,                          
       '',                                          
        'We are unable to run some of your users'' campaigns because of insufficient credits. Please refill your mail credits to enjoy uninterrupted services for your users.' as  [Messages]                                           
       ,                                          
        Getdate(),          
        335,                                          
        'noreply@email19.in',                                          
        B.Batchid,                                          
        1,                                          
        Getdate(),                                          
        0,                                          
        'We are unable to run some of your users'' campaigns because of insufficient credits. Please refill your mail credits to enjoy uninterrupted services for your users.' as mail_templetebody,                                          
        1                                          
    FROM   #tempTable Tt         
    inner join #Insufficientresellerbalance inrc on inrc.CampaignID=tt.CampaignID                                       
       INNER JOIN Usercampaignmaster AS Ucm                               
           ON Ucm.ID = Tt.CampaignID                                          
          AND Ucm.IsScheduled = 1                                          
          AND Ucm.ParentID = Tt.ParentID                                          
          Inner join #tempMobile TM on TM.CampaignID = Ucm.ID         
          Inner join #Batch B on B.CampaignId = Tt.CampaignId       
          inner join #output o on o.Email=ucm.NotificationMail       
          where o.Batchid=B.BatchID                                   
        
                                                      
    INSERT INTO Mailcreditdetails                                          
        (ID,                               
         -- Credit_ID -- this column value is auto-generated              
         M_ID,                                          
         FromUser_ID,                                          
         [User_ID],                                          
         Debits,                                          
         Credits,                                          
         Balance,                                          
         Validity,                                          
         Default_Credit,                                 
         FromDate,                                          
         ToDate,                                          
         DateCreated,                                          
         DateUpdated,                                          
         EmpUpdated,                                          
         MachineName,                                          
         LastModified,                                          
         typecredit)                                          
    SELECT Newid(),                                          
       10001,                            
       335,                                          
       335,                                       
       Count(*),                                          
       0,                                          
       (SELECT TOP 1 Mcd.Balance                                          
        FROM   Mailcreditdetails AS Mcd                                          
        WHERE  Mcd.[User_ID] = 335                                          
        ORDER  BY Mcd.Credit_ID DESC) - Count(*),                                          
        99999,                                          
       0,                                          
       Getdate(),                                          
       Getdate(),                                          
       Getdate(),                                          
       Getdate(),                                          
       'Campaign Exec',                       
       '',                                          
       Getdate(),                                          
       0                                          
    FROM   #tempTable Tt                                          
       INNER JOIN Usercampaignmaster AS Ucm                                          
           ON Ucm.ID = Tt.CampaignID                        
          AND Ucm.ParentID = Tt.ParentID                                       
          AND Ucm.IsScheduled = 1            
          Inner join #tempMobile TM on TM.CampaignID = Ucm.ID                                                  
    union      
          
      SELECT Newid(),                                          
       10001,                                          
       335,                                          
       335,                                       
       Count(*),                                          
       0,                                          
       (SELECT TOP 1 Mcd.Balance                                          
        FROM   Mailcreditdetails AS Mcd                                          
        WHERE  Mcd.[User_ID] = 335                                          
        ORDER  BY Mcd.Credit_ID DESC) - Count(*),                                          
        99999,                                          
       0,                                          
       Getdate(),                                          
       Getdate(),                                          
       Getdate(),                                          
       Getdate(),                                          
       'Campaign Exec',                       
       '',                                          
       Getdate(),                                          
       0                                          
    FROM   #tempTable Tt        
       inner join #tempMobileVirtual tmv on tmv.CampaignID=tt.CampaignID                                        
       INNER JOIN Usercampaignmaster AS Ucm                                          
           ON Ucm.ID = Tt.CampaignID                              
          AND Ucm.ParentID = Tt.ParentID                                       
          AND Ucm.IsScheduled = 1            
          Inner join #tempMobile TM on TM.CampaignID = Ucm.ID                                                   
          where tmv.ValidEntries=0      
                         
    drop table #Batch                                          
      end                                 
        
    ---------------------------------Send Notification Mail End ----------------                                           
    declare @emailcount bigint=(select count(1)  FROM   EmailsfiltercampaignexecutionTEST2 Kd                                          
           INNER JOIN #tempTable Tt                                          
                   ON Tt.CampaignID = Kd.CampaignID and jobid=@jobid)    
   while @emailcount>0    
   begin    
 DELETE top (1000) Kd                                          
    FROM   EmailsfiltercampaignexecutionTEST2 Kd                                          
           INNER JOIN #tempTable Tt                                          
                   ON Tt.CampaignID = Kd.CampaignID and jobid=@jobid     
 set @emailcount=@emailcount-1000    
    end    
/* DELETE Kd                                          
    FROM   campaignmessages Kd                                          
           INNER JOIN #tempTable Tt                                          
                   ON Tt.CampaignID = Kd.CampaignID and jobid=@jobid  */      
     
                       
                             
   UPDATE Kd                                  
   SET    Kd.step3 = 1 ,Step3DateTime=GETDATE() ,                          
   Step3Recipients= Case when ValidEntries = 1 then TT.cnt Else 0 End          
   FROM   usercampaignhistory Kd           
   inner join #tempTable TT on TT.CampaignID = Kd.CampaignID          
   inner join #tempMobile TM on TM.CampaignID = Kd.CampaignID          
   Where Kd.JobId = @jobId          
           
   UPDATE Kd                                  
   SET    Kd.step3 = 1 ,Step3DateTime=GETDATE() FROM   usercampaignhistory Kd Where Kd.JobId = @jobId      
       
   update u set executeddatetime=getdate() from usercampaignmaster u join usercampaignhistory Kd on kd.campaignid=u.id and Kd.JobId = @jobId      
            
    --Code added to update nextexecutiondate in usercampaignhistory Start--        
    select campaignid into #FindCampaignsNextExecution from #tempTable t join UserCampaignMaster ucm on t.CampaignID=ucm.id        
    where ucm.IsActive=1 and ucm.IsSchedule=1 and ucm.IsScheduled=1        
            
 declare @count int =isnull((select COUNT(1) from #FindCampaignsNextExecution),0)        
 if @count>0        
 begin        
    create table #nextexec1(campaignid bigint,nextexecution datetime)                    
    WHILE @Count > 0                        
  BEGIN                        
   DECLARE @Campaignid BIGINT = (                        
       SELECT TOP 1 campaignid                        
    FROM   #FindCampaignsNextExecution                        
      )            
       
   INSERT INTO #nextexec1                        
       (                        
      campaignid,                        
      nextexecution                        
       )                        
    EXEC Usp_getnextscheduledate                    
       @Campaignid                        
        
    DELETE                         
    FROM   #FindCampaignsNextExecution                        
    WHERE  campaignid = @Campaignid                        
        
    SET @Count = @Count - 1          
  END        
       
   update u set NextExecuteDateTime= nextexecution from usercampaignmaster u join #nextexec1 n on n.campaignid=u.id        
   where u.ExpiryDate > nextexecution or u.ExpiryDate is null        
    drop table #nextexec1        
    drop table #FindCampaignsNextExecution      
          
 end        
                         
    --Code added to update nextexecutiondate in usercampaignhistory end--                   
    DROP TABLE #tempMobile                                          
    DROP TABLE #tempTable      
    drop table #tempMobileVirtual      
    drop table #tempTableVirtual      
    drop table #Insufficientresellerbalance      
    drop table #TempTableRunningTotal      
    drop table #TempTableRunningTotalVirtual      
    drop table #output       
        
     if exists(select 1 from UserCampaignHistory where JobId=@jobId and IsEventBased=0 and isSMS=0)      
    begin    
    update usercampaignexecution set CampaignEnddatetime=GETDATE(),isrunning=0 where isevent=0 and isSMS=0    
    --select 'updated'    
    end    
     if exists(select 1 from UserCampaignHistory where JobId=@jobId and IsEventBased=1 and isSMS=0)    
    begin    
    update usercampaignexecution set CampaignEnddatetime=GETDATE(),isrunning=0 where isevent=1 and isSMS=0    
    end        
 END 
 



GO

/* ============================================================
   Procedure: [dbo].[Usp_insertclonedeliverycampaignmailsCorrected_segregatemail_withcampaignmessage]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE dbo.Usp_insertclonedeliverycampaignmailsCorrected_segregatemail_withcampaignmessage ( 
                @jobId BIGINT
                                                                                                    ) 
AS
    BEGIN
        INSERT INTO Getbatchrecord (
        -- BatchID -- this column value is auto-generated                                          
        User_id , [RandNum]
                                   ) 
               SELECT DISTINCT 
                      [Ucerm].[ParentID] , [Ucerm].[CampaignID]
               FROM EmailsfiltercampaignexecutionTEST2 AS Ucerm WITH(NOLOCK)
               WHERE [jobid] = @jobid;
        SELECT ROW_NUMBER() OVER(
        ORDER BY [Ucerm].[CampaignId] , [Ucerm].[ParentId]) AS [Id] , [Ucerm].[CampaignID] , [Ucerm].[ParentID] ,
        -- Cast(Ucerm.Messages AS VARCHAR(MAX))  AS  Messages,                                          
        [dbo].[Fn_createbatchid] ( [Ucerm].[CampaignID] , [Ucerm].[ParentID]
                                 ) AS [BatchID] , [Ucerm].[Mail_FromEmail] , [Ucerm].[Mail_UserID] AS [UserID] , [Ucerm].[Mail_Subject] , [Ucerm].[ReplyTo] , COUNT(*) AS [cnt] , [ucerm].[ispersonalized]
        -- Ucerm.Mail_ToEmail,                                          
        INTO [#tempTable]
        FROM EmailsfiltercampaignexecutionTEST2 AS Ucerm -- join user_detail u on ucerm.Mail_UserID=u.user_id                                        
        WHERE [Ucerm].[IsCompleted] = 1
              AND 
              [jobid] = @jobid  --and u.HasVirtualCredits=0             
        GROUP BY [Ucerm].[CampaignID] , [Ucerm].[ParentID] , [Ucerm].[Mail_FromEmail] , [Ucerm].[Mail_UserID] , [Ucerm].[Mail_Subject] , [Ucerm].[ReplyTo] , [ucerm].[ispersonalized];
        SELECT ROW_NUMBER() OVER(
        ORDER BY [Ucerm].[CampaignId] , [Ucerm].[ParentId]) AS [Id] , [Ucerm].[CampaignID] , [Ucerm].[ParentID] ,
        -- Cast(Ucerm.Messages AS VARCHAR(MAX))  AS  Messages,                                          
        [dbo].[Fn_createbatchid] ( [Ucerm].[CampaignID] , [Ucerm].[ParentID]
                                 ) AS [BatchID] , [Ucerm].[Mail_FromEmail] , [Ucerm].[Mail_UserID] AS [UserID] , [Ucerm].[Mail_Subject] , [Ucerm].[ReplyTo] , COUNT(*) AS [cnt] , [ParentSuperResellerId] , [ispersonalized]
        -- Ucerm.Mail_ToEmail,                                          
        INTO [#tempTableVirtual]
        FROM EmailsfiltercampaignexecutionTEST2 AS Ucerm JOIN user_detail AS u ON ucerm.Mail_UserID = u.user_id
        WHERE [Ucerm].[IsCompleted] = 1
              AND 
              [u].[HasVirtualCredits] = 1
              AND 
              [jobid] = @jobid
        GROUP BY [Ucerm].[CampaignID] , [ParentSuperResellerId] , [Ucerm].[ParentID] , [Ucerm].[Mail_FromEmail] , [Ucerm].[Mail_UserID] , [Ucerm].[Mail_Subject] , [Ucerm].[ReplyTo] , [ispersonalized];
        SELECT [A].[UserID] , [a].[CampaignID] , [a].[cnt] , [A].[BatchID] , SUM([b].[cnt]) AS [RunningTotal]
        INTO [#TempTableRunningTotal]
        FROM #tempTable AS a INNER JOIN #tempTable AS b ON b.CampaignID <= a.CampaignID
        GROUP BY [A].[UserID] , [a].[CampaignID] , [a].[cnt] , [A].[BatchID]
        ORDER BY [a].[CampaignID];
        SELECT [A].[UserID] , [a].[CampaignID] , [a].[cnt] , [A].[BatchID] , SUM([b].[cnt]) AS [RunningTotal] , [a].[ParentSuperResellerId]
        INTO [#TempTableRunningTotalVirtual]
        FROM #tempTableVirtual AS a INNER JOIN #tempTableVirtual AS b ON b.CampaignID <= a.CampaignID
        GROUP BY [A].[ParentSuperResellerId] , [a].[CampaignID] , [a].[cnt] , [A].[BatchID] , [A].[UserID]
        ORDER BY [a].[CampaignID];
        DELETE Kd
        FROM [Getbatchrecord] [Kd] INNER JOIN [#tempTable] [Tt] ON [Tt].[BatchID] = [Kd].[BatchID];
        DELETE Kd
        FROM [Getbatchrecord] [Kd] INNER JOIN [#tempTableVirtual] [Tt] ON [Tt].[BatchID] = [Kd].[BatchID];
        --- Calculate credits                                          
        SELECT [B].[UserID] , [B].[CampaignID] ,
                                  CASE
                                      WHEN [B].[Balance] >= [B].[Credits]
                                      THEN 1
                                      ELSE 0 --test, otherwise 0                                          
                                  END AS [ValidEntries]
        INTO [#tempMobile]
        FROM ( SELECT [A].[UserID] , [A].[CampaignID] , [A].[Credits] AS [Credits] , --Runningtotal                                        
               [A].[Balance]
               FROM ( SELECT [Tt].[UserID] , [TT].[RunningTotal] AS [Credits] , [TT].[CampaignID] ,
                      -- Tt.Mail_ToEmail,                                    
                      [Tt].[BatchID] , ( SELECT TOP 1 [Balance]
                                         FROM [Mailcreditdetails] AS [Mcd]
                                         WHERE [Mcd].User_ID = [Tt].[UserID]
                                         ORDER BY [Credit_ID] DESC
                                       ) AS [Balance]
                      FROM #TempTableRunningTotal AS Tt
                    ) AS A
               GROUP BY [A].[UserID] , [A].[Balance] , [A].[CampaignID] , [A].[credits]
             ) AS B;
        --select * from #tempmobile        
        SELECT [B].[UserID] , [B].[CampaignID] ,
                                  CASE
                                      WHEN [B].[Balance] > [B].[Credits]
                                      THEN 1
                                      ELSE 0 --test, otherwise 0                                          
                                  END AS [ValidEntries] , [B].[ParentSuperResellerId]
        INTO [#tempMobileVirtual]
        FROM ( SELECT [A].[UserID] , [A].[CampaignID] , [A].[Credits] AS [Credits] , --Runningtotal                                        
               [A].[Balance] , [A].[ParentSuperResellerId]
               FROM ( SELECT [Tt].[UserID] , [TT].[RunningTotal] AS [Credits] , [TT].[CampaignID] ,
                      -- Tt.Mail_ToEmail,                                    
                      [Tt].[BatchID] , ( SELECT TOP 1 [Balance]
                                         FROM [SuperResellerMailCreditDetails] AS [Mcd]
                                         WHERE [Mcd].User_ID = [Tt].[ParentSuperResellerId]
                                         ORDER BY [Credit_ID] DESC
                                       ) AS [Balance] , [tt].[ParentSuperResellerId]
                      FROM #TempTableRunningTotalVirtual AS Tt
                    ) AS A
               GROUP BY [A].[ParentSuperResellerId] , [A].[UserID] , [A].[Balance] , [A].[CampaignID] , [A].[credits]
             ) AS B;
        SELECT [t].* , [u].[email]
        INTO [#Insufficientresellerbalance]
        FROM #tempMobileVirtual AS t JOIN #tempMobile AS tt ON t.CampaignID = tt.CampaignID
                                     JOIN user_detail AS u ON u.user_id = t.ParentSuperResellerId
        WHERE [tt].[ValidEntries] = 0;
        INSERT INTO Batchemail_infos ( [BatchID] , [UserID] , [SenderName] , [Message] , [TotalRecords] , [TotalProcessed] , [ProcessTable] , [IsProcess] , [Priority_Level] , [BatchInsertTime] , [BatchProcessTime] , [ScheduledDate] , [ScheduledTime] , [TemplateID] , [Route] , [PageName] , [IsScheduled] , [Email_Subject] , [ReplyTo] , [ispersonalized]
                                     ) 
               SELECT [A].[BatchID] , [A].[UserID] , [U].[Email] AS [SenderName] , ( SELECT TOP 1 CASE
                                                                                                      WHEN [e].[templateid] <> 0
                                                                                                      THEN ( SELECT [mailcontent]
                                                                                                             FROM [usermailtemplate]
                                                                                                             WHERE [id] = [e].[templateid]
                                                                                                           )
                                                                                                      WHEN [e].[Messages] IS NULL
                                                                                                      THEN CAST([dbo].[build_mailContent] ( [c].[templateid] , [c].[campaignid] , [c].[parentid] , [c].[Messages] COLLATE Latin1_General_CI_AI , [e].[Mail_ToEmail]
                                                                                                                                          ) AS NVARCHAR(MAX))
                                                                                                      ELSE CAST([e].[messages] AS NVARCHAR(MAX))
                                                                                                  END
                                                                                     FROM [EmailsfiltercampaignexecutionTEST2] AS [e] JOIN [campaignmessages] AS [c] ON [c].[campaignid] = [e].[CampaignID]
                                                                                                                                                                        AND 
                                                                                                                                                                        [c].[jobid] = [e].[jobid]
                                                                                     WHERE [e].[CampaignID] = [a].[campaignid]
                                                                                           AND 
                                                                                           [e].[jobid] = @jobid
                                                                                   ) , [A].[cnt] , 0 , 0 , 0 ,
                                                                                                           CASE
                                                                                                               WHEN [A].[cnt] > 10
                                                                                                               THEN 0
                                                                                                               WHEN [A].[cnt] <= 10
                                                                                                               THEN 1
                                                                                                               ELSE 0
                                                                                                           END , GETDATE() , NULL , NULL , NULL , [e].[templateid] , 0 , 0 , 0 , ( SELECT TOP 1 CASE
                                                                                                                                                                                                    WHEN [e].[templateid] <> 0
                                                                                                                                                                                                    THEN ( SELECT [mailsubject]
                                                                                                                                                                                                           FROM [usermailtem] AS [plate]
                                                                                                                                                                                                           WHERE [id] = [e].[templateid]
                                                                                                                                                                                                         )
                                                                                                                                                                                                    WHEN [e].[Mail_Subject] IS NULL
                                                                                                                                                                                                    THEN [c].[Mail_Subject] COLLATE Latin1_General_CI_AI
                                                                                                                                                                                                    ELSE [e].[Mail_Subject]
                                                                                                                                                                                                END
                                                                                                                                                                                   FROM [EmailsfiltercampaignexecutionTEST2] AS [e] JOIN [campaignmessages] AS [c] ON [c].[campaignid] = [e].[CampaignID]
                                                                                                                                                                                                                                                                      AND 
                                                                                                                                                                                                                                                                      [c].[jobid] = [e].[jobid]
                                                                                                                                                                                   WHERE [e].[CampaignID] = [a].[campaignid]
                                                                                                                                                                                         AND 
                                                                                                                                                                                         [e].[jobid] = @jobid
                                                                                                                                                                                 ) , [A].[ReplyTo] , [ispersonalized]
               FROM #tempTable AS A(NOLOCK) INNER JOIN #tempMobile AS TM ON Tm.CampaignID = A.CampaignID
                                                                            AND 
                                                                            TM.UserID = A.UserID
                                            JOIN user_detail AS u(NOLOCK) ON u.user_id = a.UserID
                                                                             AND 
                                                                             TM.ValidEntries = 1;
        CREATE TABLE #output ( 
                     [GUID]    NVARCHAR(100) COLLATE SQL_Latin1_General_CP1_CI_AS , 
                     [Email]   NVARCHAR(200) COLLATE SQL_Latin1_General_CP1_CI_AS , 
                     [Batchid] BIGINT
                             );
        SELECT ROW_NUMBER() OVER(
        ORDER BY [mail_ID]) AS [Id] , *
        INTO [#e]
        FROM EmailsfiltercampaignexecutionTEST2
        WHERE [jobid] = @jobid;
        DECLARE @mailcount INT= ( SELECT COUNT(1)
                                  FROM #e
                                );
        DECLARE @idcount BIGINT= ( SELECT MIN([id])
                                   FROM #e
                                 );
        WHILE @mailcount > 0
            BEGIN
                INSERT INTO Clientemails (
                -- Id -- this column value is auto-generated                                          
                [GUID] , [Email_Id] , [SentDateTime] , [UserId] , [ReplyTo] , STATUS , [BatchID] , [Message] , [campaignid] , [parentid]
                                         ) 
                OUTPUT [inserted].[GUID] AS [GUId] , [inserted].[email_id] , [inserted].[batchid] AS [Email]
                       INTO #output
                       SELECT NEWID() , [Efce].[Mail_ToEmail] , GETDATE() , [Efce].[Mail_UserID] , [Efce].[ReplyTo] , '' , [TT].[BatchID] ,
                                                                                                                                CASE
                                                                                                                                    WHEN [efce].[ispersonalized] = 1
                                                                                                                                         AND 
                                                                                                                                         [Efce].[Messages] IS NOT NULL
                                                                                                                                    THEN CAST([efce].[Messages] AS NVARCHAR(MAX))
                                                                                                                                    ELSE CAST([dbo].[build_mailContent] ( [c].[templateid] , [c].[campaignid] , [c].[parentid] , [c].[Messages] COLLATE Latin1_General_CI_AI , [efce].[Mail_ToEmail]
                                                                                                                                                                        ) AS NVARCHAR(MAX))
                                                                                                                                END , [efce].[CampaignID] , [efce].[ParentID]
                       FROM #e AS Efce INNER JOIN #tempMobile AS Tm ON Tm.CampaignID = Efce.CampaignID
                                                                       AND 
                                                                       ValidEntries = 1
                                       INNER JOIN #tempTable AS TT ON TT.campaignid = efce.campaignid
                                       LEFT JOIN campaignmessages AS c ON c.campaignid = efce.campaignid
                                                                          AND 
                                                                          c.jobid = efce.jobid
                       WHERE [Efce].[IsCompleted] = 1
                             AND 
                             [efce].[id] <= @idcount + 1000;
                INSERT INTO Emailsfilter ( [Mail_GUID] , [Mail_FromEmail] , [Mail_ToEmail] , [Mail_Subject] , [Mail_TempleteName] , [Messages] , [Mail_InsertedDate] , [Mail_UserID] , [ReplyTo] , [Mail_BatchID] , [Mail_Priority] , [Mail_ScheduleDate] , [Mail_Attechement] , [Mail_TempleteBody] , [IsMonitor]
                                         ) 
                       SELECT [O].[Guid] , [Efce].[Mail_FromEmail] , [Efce].[Mail_ToEmail] ,
                                                                            CASE
                                                                                WHEN [efce].[ispersonalized] = 1
                                                                                     AND 
                                                                                     [Efce].[mail_subject] IS NOT NULL
                                                                                THEN [Efce].[mail_subject]
                                                                                ELSE [c].[Mail_Subject]
                                                                            END , [Efce].[Mail_TempleteName] ,
                                                                                         CASE
                                                                                             WHEN [efce].[ispersonalized] = 1
                                                                                                  AND 
                                                                                                  [Efce].[Messages] IS NOT NULL
                                                                                             THEN CAST([Efce].[Messages] AS NVARCHAR(MAX))
                                                                                             ELSE CAST([dbo].[build_mailContent] ( [c].[templateid] , [c].[campaignid] , [c].[parentid] , [c].[Messages] COLLATE Latin1_General_CI_AI , [efce].[Mail_ToEmail]
                                                                                                                                 ) AS NVARCHAR(MAX))
                                                                                         END , ISNULL([Efce].[Mail_InsertedDate] , GETDATE()) , [Efce].[Mail_UserID] , [Efce].[ReplyTo] , [TT].[BatchID] ,
                                                                                                                                                                                               CASE
                                                                                                                                                                                                   WHEN [tt].[cnt] > 10
                                                                                                                                                                                                   THEN [Efce].[Mail_Priority]
                                                                                                                                                                                                   ELSE 1
                                                                                                                                                                                               END , ISNULL([Efce].[Mail_ScheduleDate] , GETDATE()) , [Efce].[Mail_Attechement] ,
                                                                                                                                                                                                                                                             CASE
                                                                                                                                                                                                                                                                 WHEN [efce].[ispersonalized] = 1
                                                                                                                                                                                                                                                                      AND 
                                                                                                                                                                                                                                                                      [Efce].[Messages] IS NOT NULL
                                                                                                                                                                                                                                                                 THEN CAST([Efce].[Messages] AS NVARCHAR(MAX))
                                                                                                                                                                                                                                                                 ELSE CAST([dbo].[build_mailContent] ( [c].[templateid] , [c].[campaignid] , [c].[parentid] , [c].[Messages] COLLATE Latin1_General_CI_AI , [efce].[Mail_ToEmail]
                                                                                                                                                                                                                                                                                                     ) AS NVARCHAR(MAX))
                                                                                                                                                                                                                                                             END , 1 AS [Limit]
                       FROM #e AS Efce INNER JOIN #tempMobile AS Tm ON Tm.userID = Efce.Mail_UserID
                                                                       AND 
                                                                       Tm.CampaignID = Efce.CampaignID
                                                                       AND 
                                                                       ValidEntries = 1
                                       INNER JOIN #tempTable AS TT ON TT.campaignid = efce.campaignid
                                       INNER JOIN #output AS o ON o.email = Efce.mail_toemail
                                       LEFT JOIN campaignmessages AS c ON c.campaignid = efce.campaignid
                                                                          AND 
                                                                          c.jobid = efce.jobid
                       WHERE [Efce].[IsCompleted] = 1
                             AND 
                             [o].[batchid] = [tt].[batchid]
                             AND 
                             [efce].[id] <= @idcount + 1000
                             AND 
                             NOT EXISTS ( SELECT [O].[Guid]
                                          FROM [#e] AS [Efce] INNER JOIN [#tempMobileVirtual] AS [Tm] ON [Tm].[userID] = [Efce].[Mail_UserID]
                                                                                                         AND 
                                                                                                         [Tm].[CampaignID] = [Efce].[CampaignID]
                                                                                                         AND 
                                                                                                         [ValidEntries] = 0
                                                              INNER JOIN [#tempTable] AS [TT] ON [TT].[campaignid] = [efce].[campaignid]
                                                              INNER JOIN [#output] AS [o] ON [o].[email] = [Efce].[mail_toemail]
                                          WHERE [Efce].[IsCompleted] = 1
                                                AND 
                                                [o].[batchid] = [tt].[batchid]
                                        );
                INSERT INTO EmailsfilterVirtual ( [Mail_GUID] , [Mail_FromEmail] , [Mail_ToEmail] , [Mail_Subject] , [Mail_TempleteName] , [Messages] , [Mail_InsertedDate] , [Mail_UserID] , [ReplyTo] , [Mail_BatchID] , [Mail_Priority] , [Mail_ScheduleDate] , [Mail_Attechement] , [Mail_TempleteBody] , [IsMonitor]
                                                ) 
                       SELECT [O].[Guid] , [Efce].[Mail_FromEmail] , [Efce].[Mail_ToEmail] ,
                                                                            CASE
                                                                                WHEN [Efce].[mail_subject] IS NOT NULL
                                                                                THEN [Efce].[mail_subject]
                                                                                ELSE [c].[mail_subject]
                                                                            END , [Efce].[Mail_TempleteName] ,
                                                                                         CASE
                                                                                             WHEN [efce].[ispersonalized] = 1
                                                                                                  AND 
                                                                                                  [Efce].[Messages] IS NOT NULL
                                                                                             THEN CAST([Efce].[Messages] AS NVARCHAR(MAX))
                                                                                             ELSE CAST([dbo].[build_mailContent] ( [c].[templateid] , [c].[campaignid] , [c].[parentid] , [c].[Messages] COLLATE Latin1_General_CI_AI , [efce].[Mail_ToEmail]
                                                                                                                                 ) AS NVARCHAR(MAX))
                                                                                         END , ISNULL([Efce].[Mail_InsertedDate] , GETDATE()) , [Efce].[Mail_UserID] , [Efce].[ReplyTo] , [TT].[BatchID] ,
                                                                                                                                                                                               CASE
                                                                                                                                                                                                   WHEN [tt].[cnt] > 10
                                                                                                                                                                                                   THEN [Efce].[Mail_Priority]
                                                                                                                                                                                                   ELSE 1
                                                                                                                                                                                               END , ISNULL([Efce].[Mail_ScheduleDate] , GETDATE()) , [Efce].[Mail_Attechement] ,
                                                                                                                                                                                                                                                             CASE
                                                                                                                                                                                                                                                                 WHEN [efce].[ispersonalized] = 1
                                                                                                                                                                                                                                                                      AND 
                                                                                                                                                                                                                                                                      [Efce].[Messages] IS NOT NULL
                                                                                                                                                                                                                                                                 THEN CAST([Efce].[Messages] AS NVARCHAR(MAX))
                                                                                                                                                                                                                                                                 ELSE CAST([dbo].[build_mailContent] ( [c].[templateid] , [c].[campaignid] , [c].[parentid] , [c].[Messages] COLLATE Latin1_General_CI_AI , [efce].[Mail_ToEmail]
                                                                                                                                                                                                                                                                                                     ) AS NVARCHAR(MAX))
                                                                                                                                                                                                                                                             END , 1 AS [Limit]
                       FROM #e AS Efce INNER JOIN #tempMobileVirtual AS Tm ON Tm.userID = Efce.Mail_UserID
                                                                              AND 
                                                                              Tm.CampaignID = Efce.CampaignID
                                                                              AND 
                                                                              ValidEntries = 0
                                       INNER JOIN #tempTableVirtual AS TT ON TT.campaignid = efce.campaignid
                                       INNER JOIN #output AS o ON o.email = Efce.mail_toemail
                                       LEFT JOIN campaignmessages AS c ON c.campaignid = efce.campaignid
                                                                          AND 
                                                                          c.jobid = efce.jobid
                       WHERE [Efce].[IsCompleted] = 1
                             AND 
                             [o].[batchid] = [tt].[batchid]
                             AND 
                             [efce].[id] <= @idcount + 1000;
                DELETE FROM #e
                WHERE [ID] <= @idcount + 1000;
                SET @idcount = @idcount + 1000;
                SET @mailcount = @mailcount - 1000;
            END;
        TRUNCATE TABLE #output;
        INSERT INTO Mailcreditdetails ( [ID] ,
        -- Credit_ID -- this column value is auto-generated                                          
        [M_ID] , [FromUser_ID] , User_ID , [Debits] , [Credits] , [Balance] , [Validity] , [Default_Credit] , [FromDate] , [ToDate] , [DateCreated] , [DateUpdated] , [EmpUpdated] , [MachineName] , [LastModified] , [typecredit] , [campaignid]
                                      ) 
               SELECT NEWID() , ( SELECT TOP 1 [Ud].[M_ID]
                                  FROM [User_detail] AS [Ud]
                                  WHERE [Ud].User_ID = [A].[UserID]
                                ) , [A].[UserID] , [A].[UserID] , [A].[NoofRecipients] , 0 , ( SELECT TOP 1 [Mcd].[Balance]
                                                                                               FROM [Mailcreditdetails] AS [Mcd]
                                                                                               WHERE [Mcd].User_ID = [A].[UserID]
                                                                                               ORDER BY [Mcd].[Credit_ID] DESC
                                                                                             ) - [A].[NoofRecipients] , 99999 , '' , GETDATE() , GETDATE() , GETDATE() , GETDATE() , '' , '' , GETDATE() , '' , [A].[Campaignid]
               FROM ( SELECT DISTINCT 
                             [Ed].[UserID] , [Ed].[CampaignID] , [Ed].[ParentID] , SUM([Ed].[Cnt]) AS [NoofRecipients]
                      FROM #tempTable AS Ed INNER JOIN #tempMobile AS Tm ON Tm.userID = Ed.UserID
                                                                            AND 
                                                                            Tm.CampaignID = Ed.CampaignID
                      WHERE [Ed].[Cnt] > 0
                            AND 
                            [ValidEntries] = 1
                      GROUP BY [Ed].[UserID] , [Ed].[CampaignID] , [Ed].[ParentID] , [ED].[UserID]
                    ) AS A;
        INSERT INTO SuperresellerMailcreditdetails ( [ID] ,
        -- Credit_ID -- this column value is auto-generated                                          
        [M_ID] , [FromUser_ID] , User_ID , [Debits] , [Credits] , [Balance] , [Validity] , [Default_Credit] , [FromDate] , [ToDate] , [DateCreated] , [DateUpdated] , [EmpUpdated] , [MachineName] , [LastModified] , [typecredit] , [campaignid]
                                                   ) 
               SELECT NEWID() , ( SELECT TOP 1 [Ud].[M_ID]
                                  FROM [User_detail] AS [Ud]
                                  WHERE [Ud].User_ID = [A].[ParentSuperResellerId]
                                ) , [A].[ParentSuperResellerId] , [A].[ParentSuperResellerId] , [A].[NoofRecipients] , 0 , ( SELECT TOP 1 [Mcd].[Balance]
                                                                                                                             FROM [SuperResellerMailCreditDetails] AS [Mcd]
                                                                                                                             WHERE [Mcd].User_ID = [A].[ParentSuperResellerId]
                                                                                                                             ORDER BY [Mcd].[Credit_ID] DESC
                                                                                                                           ) - [A].[NoofRecipients] , 99999 , '' , GETDATE() , GETDATE() , GETDATE() , GETDATE() , '' , '' , GETDATE() , '' , [A].[Campaignid]
               FROM ( SELECT DISTINCT 
                             [tm].[ParentSuperResellerId] , [ed].[userid] , [Ed].[CampaignID] , [Ed].[ParentID] , SUM([Ed].[Cnt]) AS [NoofRecipients]
                      FROM #tempTable AS Ed INNER JOIN #tempMobileVirtual AS Tm ON Tm.userID = Ed.UserID
                                                                                   AND 
                                                                                   Tm.CampaignID = Ed.CampaignID
                      WHERE [Ed].[Cnt] > 0
                            AND 
                            [ValidEntries] = 1
                      GROUP BY [Ed].[UserID] , [tm].[ParentSuperResellerId] , [Ed].[CampaignID] , [Ed].[ParentID] , [ED].[UserID]
                    ) AS A;
        UPDATE Kd
               SET [Executiontime] = GETDATE() , [Noofrecipients] = [Tt].[Cnt] , [Batchid] = [Tt].[BatchID] ,
        --Ismessages = 1,                                          
        [Isexecuted] = CASE
                           WHEN [tm].[Validentries] = 1
