                                                                                                         + [UCM].[CampaignName] + '" scheduled for ' + CAST(GETDATE() AS VARCHAR(50)) + ' is executed successfully. You can log in to your account & check the delivery report in the campaign history'
                                                                                                END AS [Messages] , GETDATE() , 335 , 'noreply@email19.in' , [B].[Batchid] , 1 , GETDATE() , 0 ,
                                                                                                                                                                                             CASE
                                                                                                                                                                                                 WHEN [TM].[ValidEntries] = 0
                                                                                                                                                                                                 THEN 'Oops, you don''t have sufficient mail credits to run your mail campaign "' + [UCM].[CampaignName] + '" scheduled for ' + CAST(GETDATE() AS VARCHAR(50)) + '. Pl refill your credit balance & rerun the campaign '
                                                                                                                                                                                                 ELSE 'As promised , Your Mail campaign "'

