         ELSE                                          
         'SMS'                                          
         END + '*/

                                                                                                                                                                                                      + [UCM].[CampaignName] + '" scheduled for ' + CAST(GETDATE() AS VARCHAR(50)) + ' is executed successfully. You can log in to your account & check the delivery report in the campaign history'
                                                                                                                                                                                             END AS [mail_templetebody] , 1
                       FROM #tempTable AS Tt INNER JOIN Usercampaignmaster AS Ucm ON Ucm.ID = Tt.CampaignID
