                       SELECT [o].[guid] , 'noreply@email19.in' , [UCM].[NotificationMail] , 'Failure: Your campaign "' + +[UCM].[CampaignName] + '" failed. Please contact your administrator for details.' AS [Mail_subject] , '' , 'Oops, something went wrong and your campaign couldn''t run. Please contact your administrator for details' AS [Messages] , GETDATE() , 335 , 'noreply@email19.in' , [B].[Batchid] , 1 , GETDATE() , 0 , 'Oops, something went wrong and your campaign couldn''t run. Please contact your administrator for details' AS [mail_templetebody] , 1
                       FROM #tempTable AS Tt INNER JOIN Usercampaignmaster AS Ucm ON Ucm.ID = Tt.CampaignID
                                                                                     AND 
