                                                                                     AND 
                                                                                     Ucm.ParentID = Tt.ParentID
                                             INNER JOIN #tempMobile AS TM ON TM.CampaignID = Ucm.ID
                                             INNER JOIN #Batch AS B ON B.CampaignId = Tt.CampaignId
                                             INNER JOIN #output AS o ON o.Email = ucm.NotificationMail
                                             INNER JOIN #tempMobileVirtual AS tmv ON tmv.CampaignID = tt.CampaignID
                       WHERE [o].[Batchid] = [B].[BatchID]
                             AND 
