                       SELECT [o].[guid] , 'noreply@email19.in' , [inrc].[eMail] , 'Failure: Your users'' campaign "' + +[UCM].[CampaignName] + '" failed because of insufficient mail credits in your account.' AS [Mail_subject] , '' , 'We are unable to run some of your users'' campaigns because of insufficient credits. Please refill your mail credits to enjoy uninterrupted services for your users.' AS [Messages] , GETDATE() , 335 , 'noreply@email19.in' , [B].[Batchid] , 1 , GETDATE() , 0 , 'We are unable to run some of your users'' campaigns because of insufficient credits. Please refill your mail credits to enjoy uninterrupted services for your users.' AS [mail_templetebody] , 1
                       FROM #tempTable AS Tt INNER JOIN #Insufficientresellerbalance AS inrc ON inrc.CampaignID = tt.CampaignID
