                [M_ID] , [FromUser_ID] , User_ID , [Debits] , [Credits] , [Balance] , [Validity] , [Default_Credit] , [FromDate] , [ToDate] , [DateCreated] , [DateUpdated] , [EmpUpdated] , [MachineName] , [LastModified] , [typecredit]
                                              ) 
                       SELECT NEWID() , 10001 , 335 , 335 , COUNT(*) , 0 , ( SELECT TOP 1 [Mcd].[Balance]
                                                                             FROM [Mailcreditdetails] AS [Mcd]
                                                                             WHERE [Mcd].User_ID = 335
                                                                             ORDER BY [Mcd].[Credit_ID] DESC
                                                                           ) - COUNT(*) , 99999 , 0 , GETDATE() , GETDATE() , GETDATE() , GETDATE() , 'Campaign Exec' , '' , GETDATE() , 0
                       FROM #tempTable AS Tt INNER JOIN Usercampaignmaster AS Ucm ON Ucm.ID = Tt.CampaignID
                                                                                     AND 
                                                                                     Ucm.ParentID = Tt.ParentID
                                                                                     AND 
                                                                                     Ucm.IsScheduled = 1
                                             INNER JOIN #tempMobile AS TM ON TM.CampaignID = Ucm.ID
                       UNION
                       SELECT NEWID() , 10001 , 335 , 335 , COUNT(*) , 0 , ( SELECT TOP 1 [Mcd].[Balance]
                                                                             FROM [Mailcreditdetails] AS [Mcd]
                                                                             WHERE [Mcd].User_ID = 335
                                                                             ORDER BY [Mcd].[Credit_ID] DESC
                                                                           ) - COUNT(*) , 99999 , 0 , GETDATE() , GETDATE() , GETDATE() , GETDATE() , 'Campaign Exec' , '' , GETDATE() , 0
                       FROM #tempTable AS Tt INNER JOIN #tempMobileVirtual AS tmv ON tmv.CampaignID = tt.CampaignID
                                             INNER JOIN Usercampaignmaster AS Ucm ON Ucm.ID = Tt.CampaignID
                                                                                     AND 
