        ---------------------------------Send Notification Mail End ----------------                                           
        DECLARE @emailcount BIGINT= ( SELECT COUNT(1)
                                      FROM EmailsfiltercampaignexecutionTEST2 AS Kd INNER JOIN #tempTable AS Tt ON Tt.CampaignID = Kd.CampaignID
                                                                                                                   AND 
                                                                                                                   jobid = @jobid
                                    );
        WHILE @emailcount > 0
            BEGIN
                DELETE TOP (1000)
                Kd
                FROM [EmailsfiltercampaignexecutionTEST2] [Kd] INNER JOIN [#tempTable] [Tt] ON [Tt].[CampaignID] = [Kd].[CampaignID]
                                                                                               AND 
                                                                                               [jobid] = @jobid;
                SET @emailcount = @emailcount - 1000;
            END;

/* DELETE Kd              
    FROM   campaignmessages Kd                                          
           INNER JOIN #tempTable Tt                                          
                   ON Tt.CampaignID = Kd.CampaignID and jobid=@jobid  */

        UPDATE Kd
               SET [Kd].[step3] = 1 , [Step3DateTime] = GETDATE() , [Step3Recipients] = CASE
                                                                                            WHEN [ValidEntries] = 1
                                                                                            THEN [TT].[cnt]
                                                                                            ELSE 0
                                                                                        END
        FROM [usercampaignhistory] [Kd] INNER JOIN [#tempTable] [TT] ON [TT].[CampaignID] = [Kd].[CampaignID]
                                        INNER JOIN [#tempMobile] [TM] ON [TM].[CampaignID] = [Kd].[CampaignID]
        WHERE [Kd].[JobId] = @jobId;
        UPDATE Kd
               SET [Kd].[step3] = 1 , [Step3DateTime] = GETDATE()
        FROM [usercampaignhistory] [Kd]
        WHERE [Kd].[JobId] = @jobId;
        UPDATE u
               SET [executeddatetime] = GETDATE()
        FROM [usercampaignmaster] [u] JOIN [usercampaignhistory] [Kd] ON [kd].[campaignid] = [u].[id]
                                                                         AND 
                                                                         [Kd].[JobId] = @jobId;
        --Code added to update nextexecutiondate in usercampaignhistory Start--        
        SELECT [campaignid]
        INTO [#FindCampaignsNextExecution]
        FROM #tempTable AS t JOIN UserCampaignMaster AS ucm ON t.CampaignID = ucm.id
                             LEFT JOIN userschedules AS us ON us.id = ucm.scheduleid
        WHERE [ucm].[IsActive] = 1
              AND 
              [ucm].[IsSchedule] = 1
              AND 
              [ucm].[IsScheduled] = 1
              AND 
              [us].[IsOnce] = 0;
        DECLARE @count INT= ISNULL( ( SELECT COUNT(1)
                                      FROM #FindCampaignsNextExecution
                                    ) , 0);
        IF @count > 0
            BEGIN
                CREATE TABLE #nextexec1 ( 
                             [campaignid]    BIGINT , 
                             [nextexecution] DATETIME
                                        );
                WHILE @Count > 0
                    BEGIN
                        DECLARE @Campaignid BIGINT= ( SELECT TOP 1 [campaignid]
                                                      FROM #FindCampaignsNextExecution
                                                    );
                        INSERT INTO #nextexec1 ( [campaignid] , [nextexecution]
                                               ) 
                        EXEC Usp_getnextscheduledate @Campaignid;
                        DELETE FROM #FindCampaignsNextExecution
                        WHERE [campaignid] = @Campaignid;
                        SET @Count = @Count - 1;
        END;
                UPDATE u
                       SET [NextExecuteDateTime] = [nextexecution]
                FROM [usercampaignmaster] [u] JOIN [#nextexec1] [n] ON [n].[campaignid] = [u].[id]
                WHERE [u].[ExpiryDate] > [nextexecution]
                      OR 
                      [u].[ExpiryDate] IS NULL;
                DROP TABLE #nextexec1;
                DROP TABLE #FindCampaignsNextExecution;
        END;
        --Code added to update nextexecutiondate in usercampaignhistory end--                   
        DROP TABLE #tempMobile;
        DROP TABLE #tempTable;
        DROP TABLE #tempMobileVirtual;
        DROP TABLE #tempTableVirtual;
        DROP TABLE #Insufficientresellerbalance;
        DROP TABLE #TempTableRunningTotal;
        DROP TABLE #TempTableRunningTotalVirtual;
        DROP TABLE #output;
        IF EXISTS ( SELECT 1
                    FROM UserCampaignHistory
                    WHERE [JobId] = @jobId
                          AND 
                          [IsEventBased] = 0
                          AND 
                          [isSMS] = 0
                  ) 
            BEGIN
                UPDATE usercampaignexecution
                       SET [CampaignEnddatetime] = GETDATE() , [isrunning] = 0
                WHERE [isevent] = 0
                      AND 
                      [isSMS] = 0;
                --select 'updated'    
        END;
        IF EXISTS ( SELECT 1
                    FROM UserCampaignHistory
                    WHERE [JobId] = @jobId
                          AND 
                          [IsEventBased] = 1
                          AND 
                          [isSMS] = 0
                  ) 
            BEGIN
                UPDATE usercampaignexecution
                       SET [CampaignEnddatetime] = GETDATE() , [isrunning] = 0
                WHERE [isevent] = 1
                      AND 
                      [isSMS] = 0;
        END;
    END;



GO

/* ============================================================
   Procedure: [dbo].[Usp_insertclonedeliverycampaignmailsCorrected_segregatemail_withid]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_insertclonedeliverycampaignmailsCorrected_segregatemail_withid]   
(@jobId bigint)                                               
AS                                                  
BEGIN                       
                     
create table #outputb(id int identity(1,1),bid bigint, u_id bigint,campaignid bigint)        
begin tran          
INSERT INTO Getbatchrecord                                                      
([User_id],RandNum)           
OUTPUT inserted.BatchID  as bId,inserted.User_id as u_id,inserted.RandNum as campaignid  INTO #outputb                                    
 SELECT DISTINCT Ucerm.ParentID,                                                  
                      Ucerm.CampaignID                                                  
      FROM   EmailsfiltercampaignexecutionTEST2 AS Ucerm With(nolock)         
      where jobid=@jobid                                                    
               
delete g From GetBatchRecord g join #outputb o on o.bid=g.BatchID        
commit                             
                     
                   
                                                  
     SELECT                   
     ROW_NUMBER() Over(order by Ucerm.CampaignId,Ucerm.ParentId) Id,                  
     Ucerm.CampaignID,                     
     Ucerm.ParentID                               ,                  
                     -- Cast(Ucerm.Messages AS VARCHAR(MAX))  AS  Messages,                                                  
                      o.bid AS BatchID,                                                
                     Ucerm.Mail_FromEmail,                                                  
                      Ucerm.Mail_UserID AS UserID,                  
                      Ucerm.Mail_Subject,                  
                      Ucerm.ReplyTo,                  
                      Count(*) cnt,ucerm.ispersonalized                  
                     -- Ucerm.Mail_ToEmail,                                                  
   INTO   #tempTable                                                  
      FROM   EmailsfiltercampaignexecutionTEST2 Ucerm -- join user_detail u on ucerm.Mail_UserID=u.user_id                            
      join #outputb o on o.u_id=ucerm.parentid and o.campaignid=ucerm.campaignid                             
      WHERE  Ucerm.IsCompleted = 1 and jobid=@jobid  --and u.HasVirtualCredits=0                     
      Group by  Ucerm.CampaignID,                     
     Ucerm.ParentID , Ucerm.Mail_FromEmail,                                                  
                      Ucerm.Mail_UserID,                  
                      Ucerm.Mail_Subject,                  
                      Ucerm.ReplyTo,ucerm.ispersonalized ,o.bid                
                                    
    SELECT                   
     ROW_NUMBER() Over(order by Ucerm.CampaignId,Ucerm.ParentId) Id,                  
     Ucerm.CampaignID,                     
     Ucerm.ParentID                               ,                  
     -- Cast(Ucerm.Messages AS VARCHAR(MAX))  AS  Messages,                                                  
      o.bid AS BatchID,                                                
     Ucerm.Mail_FromEmail,                                                  
      Ucerm.Mail_UserID AS UserID,                  
      Ucerm.Mail_Subject,                  
      Ucerm.ReplyTo,                  
      Count(*) cnt,              
      ParentSuperResellerId,ispersonalized                  
                     -- Ucerm.Mail_ToEmail,                                                  
    INTO   #tempTableVirtual                                                  
      FROM   EmailsfiltercampaignexecutionTEST2 Ucerm  join user_detail u on ucerm.Mail_UserID=u.user_id                     join #outputb o on o.u_id=ucerm.parentid and o.campaignid=ucerm.campaignid                            
      WHERE  Ucerm.IsCompleted = 1  and u.HasVirtualCredits=1 and jobid=@jobid                     
      Group by  Ucerm.CampaignID,ParentSuperResellerId,           
     Ucerm.ParentID , Ucerm.Mail_FromEmail,                                                  
                      Ucerm.Mail_UserID,                  
                      Ucerm.Mail_Subject,                  
                      Ucerm.ReplyTo , ispersonalized ,o.bid            
                                    
                                                                 
                        
   SELECT A.UserID,a.CampaignID, a.cnt,A.BatchID, SUM(b.cnt) RunningTotal into #TempTableRunningTotal                  
   FROM   #tempTable a inner join #tempTable b                  
   on b.CampaignID <= a.CampaignID                  
   GROUP BY A.UserID, a.CampaignID, a.cnt,A.BatchID                  
   ORDER BY a.CampaignID;                
                 
   SELECT A.UserID,a.CampaignID, a.cnt,A.BatchID, SUM(b.cnt) RunningTotal,a.ParentSuperResellerId into #TempTableRunningTotalVirtual             
   FROM   #tempTableVirtual a inner join #tempTableVirtual b                  
   on b.CampaignID <= a.CampaignID                  
   GROUP BY A.ParentSuperResellerId, a.CampaignID, a.cnt,A.BatchID,A.UserID                  
   ORDER BY a.CampaignID;                
                        
   drop table #outputb                     
      /*DELETE Kd                                                  
      FROM   Getbatchrecord Kd                                                  
             INNER JOIN #tempTable Tt                                                  
                     ON Tt.BatchID = Kd.BatchID                 
                                   
      DELETE Kd                                                  
      FROM   Getbatchrecord Kd                                                  
             INNER JOIN #tempTableVirtual Tt                                                  
                     ON Tt.BatchID = Kd.BatchID */                                              
                                                
                                                  
      --- Calculate credits                                                  
    SELECT B.UserID,                   
    B.CampaignID,                                                 
             CASE                                                  
               WHEN B.Balance >= B.Credits THEN 1                                                  
               ELSE 0 --test, otherwise 0                                                  
             END AS ValidEntries                                                  
      INTO   #tempMobile                                                  
      FROM   (SELECT A.UserID,                    
      A.CampaignID,                                                
                       (A.Credits)   AS Credits,  --Runningtotal                                                
                     A.Balance                                                  
              FROM   (SELECT Tt.UserID,                                                  
                             TT.RunningTotal AS Credits,                  
                             TT.CampaignID,                                                  
                            -- Tt.Mail_ToEmail,                                            
                             Tt.BatchID,                                                  
                             (SELECT TOP 1 Balance                                                  
                              FROM   Mailcreditdetails AS Mcd                                                  
                              WHERE  Mcd.[User_ID] = Tt.UserID                           
                              ORDER  BY Credit_ID DESC)     AS Balance                                                  
                      FROM   #TempTableRunningTotal Tt) A                                                  
              GROUP  BY A.UserID,                                                  
                        A.Balance,A.CampaignID,A.credits) B       
                              
update u set u.ReasonIfNotRun='Insuffcient Balance' from UserCampaignHistory u join #tempMobile t      
on u.campaignid=t.CampaignID and u.jobid=@jobid where t.validentries=0                 
     --select * from #tempmobile                
                   
     SELECT B.UserID,                   
            B.CampaignID,                                                 
            CASE                                                  
               WHEN B.Balance > B.Credits THEN 1                                                  
               ELSE 0 --test, otherwise 0                                                  
             END AS ValidEntries,              
             B.ParentSuperResellerId                                                  
      INTO   #tempMobileVirtual                                                  
      FROM   (SELECT A.UserID,                    
      A.CampaignID,                                                
      (A.Credits)   AS Credits,  --Runningtotal                                                
      A.Balance,              
      A.ParentSuperResellerId                                                  
      FROM   (SELECT Tt.UserID,                                                  
                     TT.RunningTotal AS Credits,                  
                     TT.CampaignID,                                                  
                     -- Tt.Mail_ToEmail,                                            
                     Tt.BatchID,                                                  
                     (SELECT TOP 1 Balance                   
                      FROM   SuperResellerMailCreditDetails AS Mcd                                                  
                      WHERE  Mcd.[User_ID] = Tt.ParentSuperResellerId                          
                      ORDER  BY Credit_ID DESC)     AS Balance,              
                      tt.ParentSuperResellerId                                                  
               FROM   #TempTableRunningTotalVirtual Tt) A                                                  
              GROUP  BY A.ParentSuperResellerId,A.UserID,                                                 
                        A.Balance,A.CampaignID,A.credits) B               
                   
select t.*,u.email into #Insufficientresellerbalance from #tempMobileVirtual t join #tempMobile tt on t.CampaignID=tt.CampaignID join user_detail u on u.user_id=t.ParentSuperResellerId where tt.ValidEntries=0              
              
INSERT INTO Batchemail_infos(BatchID,UserID,SenderName,[Message],TotalRecords,TotalProcessed,ProcessTable,IsProcess,Priority_Level,BatchInsertTime,            
BatchProcessTime,ScheduledDate,ScheduledTime,TemplateID,[Route],PageName,IsScheduled,Email_Subject,ReplyTo,ispersonalized)            
                                           
SELECT A.BatchID,A.UserID,U.Email as SenderName,(select top 1 case when e.Messages is null then CAST(dbo.build_mailContent(c.templateid,c.campaignid,c.parentid
,c.Messages COLLATE Latin1_General_CI_AI,e.Mail_ToEmail) AS NVARCHAR(MAX)) else cast(e.messages as nvarchar(max)) end from EmailsfiltercampaignexecutionTEST2 e 
join campaignmessages c on c.campaignid=e.CampaignID and c.jobid=e.jobid                  
      where e.CampaignID=a.campaignid and e.jobid=@jobid ),A.cnt,0,0,0,case when A.cnt>10 then 0 when A.cnt<=10 then 1 else 0 end,Getdate(),NULL,NULL,NULL,          
   0,0,0,0,(select top 1 case when e.Mail_Subject is null then c.Mail_Subject COLLATE Latin1_General_CI_AI            
      else e.Mail_Subject end from EmailsfiltercampaignexecutionTEST2 e join campaignmessages c on c.campaignid=e.CampaignID and c.jobid=e.jobid                  
      where e.CampaignID=a.campaignid and e.jobid=@jobid ),A.ReplyTo,ispersonalized                   
      FROM #tempTable A (nolock)                   
      Inner join #tempMobile TM on Tm.CampaignID = A.CampaignID and TM.UserID = A.UserID                   
      join user_detail u (nolock) on u.user_id=a.UserID  and TM.ValidEntries = 1                  
                    
              
                       
create table #output (GUID nvarchar(100) collate SQL_Latin1_General_CP1_CI_AS ,Email nvarchar(200) collate SQL_Latin1_General_CP1_CI_AS,Batchid bigint)                  
            
 SELECT ROW_NUMBER()Over(Order by mail_ID) AS Id,* into #e from EmailsfiltercampaignexecutionTEST2 where jobid=@jobid             
 declare @mailcount int=(select COUNT(1) from #e)            
 declare @idcount bigint=(select MIN(id) from #e)
 
CREATE TABLE #tbl_activity(
	[LeadID] [bigint] NULL,
	[UserID] [bigint] NULL,
	[ParentID] [bigint] NULL,
	[EventDescription] [nvarchar](max) NULL,
	[EventName] [nvarchar](500) NULL
)
insert into #tbl_activity( LeadID , UserID, ParentID , EventDescription , EventName)           
select entityid,m.Mail_UserID,m.ParentID, cast(u.user_login as nvarchar) +'sent '+
case when m.Mail_TempleteName is not null then Mail_TempleteName else ' a ' end + ' mail with subject "'+replace(m.[mail_subject],'''','"')+ '" to emailid '
+cast(m.mail_id as nvarchar) +' through automated campaign named ' + c.CampaignName
,'Mail sent to lead'
 from user_detail u join #e m on m.Mail_UserID=u.User_ID
 join UserCampaignMaster c on c.ID=m.CampaignID
 where entityname='Lead' and isnull(entityid,0)<>0         

exec UspSaveLeadActivity_withMultipleValue #tbl_activity

drop table #tbl_activity 

 
 
              
 while @mailcount>0            
 begin             
 INSERT INTO Clientemails                                                  
                  (                                  
      -- Id -- this column value is auto-generated                                                  
      GUID,                                                  
                   Email_Id,                                                  
                   SentDateTime,                                                  
                   UserId,                                                  
                   ReplyTo,                                      
                   [Status],                                                  
                   BatchID,                                                  
                   [Message],              
                   campaignid,              
                   parentid)               
      OUTPUT inserted.GUID  as GUId,inserted.email_id,inserted.batchid as Email INTO #output                 
      SELECT Newid(),                                                  
             Efce.Mail_ToEmail,                                                  
             Getdate(),                                                  
             Efce.Mail_UserID,                                                  
             Efce.ReplyTo,                                                  
             '',                                                  
             TT.BatchID,                                          
             case when efce.ispersonalized=1 and Efce.Messages is not null then cast(efce.Messages as nvarchar(max)) else CAST(dbo.build_mailContent(c.templateid,c.campaignid,c.parentid,c.Messages       
             COLLATE Latin1_General_CI_AI,efce.Mail_ToEmail) AS NVARCHAR(MAX))          end,              
             efce.CampaignID,              
             efce.ParentID                                                  
      FROM   #e AS Efce                                                  
             INNER JOIN #tempMobile Tm                                                  
      ON Tm.CampaignID = Efce.CampaignID AND ValidEntries = 1                 
   inner join #tempTable TT on TT.campaignid=efce.campaignid left join campaignmessages c on  c.campaignid=efce.campaignid and c.jobid=efce.jobid              
      WHERE  Efce.IsCompleted = 1 and efce.id<=@idcount+1000              
                                                  
                                                  
      INSERT INTO Emailsfilter                                                 
                  (Mail_GUID,                                                  
                   Mail_FromEmail,                                                  
                   Mail_ToEmail,                                                  
                   Mail_Subject,                                                  
                   Mail_TempleteName,                                                  
                   Messages,                                                  
                   Mail_InsertedDate,                 
                   Mail_UserID,                    
                   ReplyTo,                                                  
                   Mail_BatchID,                                                  
                   Mail_Priority,                                                  
                   Mail_ScheduleDate,                                                  
 Mail_Attechement,                                                  
                   Mail_TempleteBody,                                                  
                   IsMonitor)                                                  
      SELECT O.Guid,                                                  
             Efce.Mail_FromEmail,                                                  
             Efce.Mail_ToEmail,                      
             case when efce.ispersonalized=1 and Efce.mail_subject is not null then Efce.mail_subject else c.Mail_Subject end,                                                
             Efce.Mail_TempleteName,                                                  
             case when efce.ispersonalized=1 and Efce.Messages is not null then cast(Efce.Messages as nvarchar(max)) else CAST(dbo.build_mailContent(c.templateid,c.campaignid,c.parentid,c.Messages       
             COLLATE Latin1_General_CI_AI,efce.Mail_ToEmail) AS NVARCHAR(MAX))          end,                                                
             isnull(Efce.Mail_InsertedDate,getdate()),                                                  
             Efce.Mail_UserID,                                                  
             Efce.ReplyTo,                                                  
             TT.BatchID,                                                  
             case when tt.cnt>10 then Efce.Mail_Priority else 1 end,                                                  
             isnull(Efce.Mail_ScheduleDate,getdate()),                                                  
             Efce.Mail_Attechement,                                                  
             case when efce.ispersonalized=1 and Efce.Messages is not null then cast(Efce.Messages as nvarchar(max)) else CAST(dbo.build_mailContent(c.templateid,c.campaignid,c.parentid,c.Messages         
             COLLATE Latin1_General_CI_AI,efce.Mail_ToEmail) AS NVARCHAR(MAX))          end,                                                  
             1 AS Limit                                                  
      FROM   #e AS Efce                                                  
             INNER JOIN #tempMobile Tm                                                  
        ON Tm.userID = Efce.Mail_UserID  and Tm.CampaignID = Efce.CampaignID                                      
                        AND ValidEntries = 1                 
                        inner join #tempTable TT on TT.campaignid=efce.campaignid                
                        inner join #output o on o.email=Efce.mail_toemail  left join campaignmessages c on  c.campaignid=efce.campaignid and c.jobid=efce.jobid                                                 
      WHERE  Efce.IsCompleted = 1 and o.batchid=tt.batchid and efce.id<=@idcount+1000              
      and not exists              
      (SELECT O.Guid                                                 
      FROM   #e AS Efce                                                  
             INNER JOIN #tempMobileVirtual Tm                                                  
        ON Tm.userID = Efce.Mail_UserID  and Tm.CampaignID = Efce.CampaignID                                      
                        AND ValidEntries = 0                 
                        inner join #tempTable TT on TT.campaignid=efce.campaignid                
                        inner join #output o on o.email=Efce.mail_toemail                                               
      WHERE  Efce.IsCompleted = 1 and o.batchid=tt.batchid)              
                    
                    
      INSERT INTO EmailsfilterVirtual                                                 
                (Mail_GUID,                                                  
                   Mail_FromEmail,                                                  
                   Mail_ToEmail,                                                  
                   Mail_Subject,                                                  
                   Mail_TempleteName,                                 
                   Messages,                                                  
                   Mail_InsertedDate,                                                  
                   Mail_UserID,                                                  
                   ReplyTo,                                                  
                   Mail_BatchID,                                                  
                   Mail_Priority,                                                  
                   Mail_ScheduleDate,                                                  
                   Mail_Attechement,                                                  
                   Mail_TempleteBody,                                                  
                   IsMonitor)                                                  
      SELECT O.Guid,                                                  
             Efce.Mail_FromEmail,                                                  
             Efce.Mail_ToEmail,                      
              case when Efce.mail_subject is not null then Efce.mail_subject else c.mail_subject end,                                                
             Efce.Mail_TempleteName,                                                  
             case when efce.ispersonalized=1 and Efce.Messages is not null then cast(Efce.Messages as nvarchar(max)) else CAST(dbo.build_mailContent(c.templateid,c.campaignid,c.parentid,c.Messages       
             COLLATE Latin1_General_CI_AI,efce.Mail_ToEmail) AS NVARCHAR(MAX))          end,                                                
             isnull(Efce.Mail_InsertedDate,getdate()),                                                  
             Efce.Mail_UserID,                                                  
             Efce.ReplyTo,                                                  
             TT.BatchID,                                                  
             case when tt.cnt>10 then Efce.Mail_Priority else 1 end,                                                  
             isnull(Efce.Mail_ScheduleDate,getdate()),                                      
             Efce.Mail_Attechement,                                                  
             case when efce.ispersonalized=1 and Efce.Messages is not null then cast(Efce.Messages as nvarchar(max)) else CAST(dbo.build_mailContent(c.templateid,c.campaignid,c.parentid,c.Messages         
             COLLATE Latin1_General_CI_AI,efce.Mail_ToEmail) AS NVARCHAR(MAX))          end,                                                
             1 AS Limit                                                  
      FROM   #e AS Efce                                                  
             INNER JOIN #tempMobileVirtual Tm                                                  
        ON Tm.userID = Efce.Mail_UserID  and Tm.CampaignID = Efce.CampaignID                                      
                        AND ValidEntries = 0                 
                        inner join #tempTableVirtual TT on TT.campaignid=efce.campaignid                
                        inner join #output o on o.email=Efce.mail_toemail      left join campaignmessages c on  c.campaignid=efce.campaignid and c.jobid=efce.jobid                                                                               
      WHERE  Efce.IsCompleted = 1 and o.batchid=tt.batchid  and efce.id<=@idcount+1000              
  delete From #e where ID<=@idcount+1000                
  set @idcount=@idcount+1000            
  set @mailcount=@mailcount-1000            
  end                 
                    
  truncate table #output                                               
                                                  
      INSERT INTO Mailcreditdetails                                                  
                  (ID,                     
                   -- Credit_ID -- this column value is auto-generated                                                  
                   M_ID,               
                   FromUser_ID,                                                  
                   [User_ID],                                                  
                   Debits,                                                  
                 Credits,                                                  
                 Balance,                                                  
                   Validity,                                                  
                   Default_Credit,                                                  
                   FromDate,                                                  
      ToDate,                                                  
                   DateCreated,                                                  
                   DateUpdated,                                                  
               EmpUpdated,                                                  
                   MachineName,                                                  
                   LastModified,                                      
                   typecredit,                
                   campaignid)                                                  
      SELECT Newid(),                                                  
             (SELECT TOP 1 Ud.M_ID                                                  
              FROM   User_detail AS Ud                                                  
              WHERE  Ud.[User_ID] = A.UserID),                                                  
             A.UserID,                                         
             A.UserID,                                                  
             A.NoofRecipients,                                                  
             0,                                                  
             (SELECT TOP 1 Mcd.Balance                                                  
              FROM   Mailcreditdetails AS Mcd                                                  
              WHERE  Mcd.[User_ID] = A.UserID                                                  
              ORDER  BY Mcd.Credit_ID DESC) - A.NoofRecipients,                                                  
             99999,                                                  
       '',                                                  
             Getdate(),                                                  
             Getdate(),                     
             Getdate(),                                                  
             Getdate(),                                                  
             '',                                                  
             '',                                                  
             Getdate(),                                         
             '',                
             A.Campaignid                                                  
      FROM   (SELECT DISTINCT Ed.UserID,Ed.CampaignID,Ed.ParentID,                                                  
                              SUM(Ed.Cnt) AS NoofRecipients                                                  
              FROM   #tempTable Ed                                                  
                     INNER JOIN #tempMobile Tm                                                  
                  ON Tm.userID = Ed.UserID   and Tm.CampaignID = Ed.CampaignID               
                  where Ed.Cnt>0 AND ValidEntries = 1                                                  
           GROUP  BY Ed.UserID,Ed.CampaignID,Ed.ParentID,ED.UserID) A                  
              
      INSERT INTO SuperresellerMailcreditdetails                                                  
                  (ID,                                                  
                   -- Credit_ID -- this column value is auto-generated                                                  
                   M_ID,                                                  
                   FromUser_ID,                                                  
                   [User_ID],                                                
                   Debits,                                                  
    Credits,                                                  
    Balance,                         
                   Validity,                                                  
                   Default_Credit,                                                  
                   FromDate,                                                  
                   ToDate,                                                  
                   DateCreated,                                                  
                   DateUpdated,                                                  
    EmpUpdated,                
                   MachineName,                                                  
                   LastModified,                                                  
                   typecredit,                
                   campaignid)                                                  
      SELECT Newid(),                                                  
             (SELECT TOP 1 Ud.M_ID                                                  
              FROM   User_detail AS Ud                                                  
              WHERE  Ud.[User_ID] = A.ParentSuperResellerId),                                                  
             A.ParentSuperResellerId,                                                  
             A.ParentSuperResellerId,                          
             A.NoofRecipients,                                                  
             0,                                                  
             (SELECT TOP 1 Mcd.Balance                                                  
              FROM   SuperResellerMailCreditDetails AS Mcd                                                  
              WHERE  Mcd.[User_ID] = A.ParentSuperResellerId                                                  
              ORDER  BY Mcd.Credit_ID DESC) - A.NoofRecipients,                                                  
             99999,                                                  
    '',                                                  
             Getdate(),                                                  
             Getdate(),                                                  
             Getdate(),                                                  
             Getdate(),                                                  
             '',                                                  
             '',                                                  
             Getdate(),                                         
             '',                
             A.Campaignid                                
      FROM   (SELECT DISTINCT tm.ParentSuperResellerId,ed.userid,Ed.CampaignID,Ed.ParentID,SUM(Ed.Cnt) AS NoofRecipients                                                  
              FROM   #tempTable Ed                                                  
                     INNER JOIN #tempMobileVirtual Tm                                                  
                  ON Tm.userID = Ed.UserID   and Tm.CampaignID = Ed.CampaignID               
                  where Ed.Cnt>0 AND ValidEntries = 1                                                  
               GROUP  BY Ed.UserID,tm.ParentSuperResellerId,Ed.CampaignID,Ed.ParentID,ED.UserID) A                                 
                             
                             
                                 
                                
     UPDATE Kd                                                  
      SET    Executiontime = Getdate(),                                                  
             Noofrecipients = Tt.Cnt,                          
             Batchid = Tt.BatchID,                                                  
             --Ismessages = 1,                                                  
             Isexecuted = case when tm.Validentries=1 then 1 else 0 end                                                      
 FROM   Usercampaignexecutionhistory Kd                                                  
             INNER JOIN #tempTable Tt                                                  
          ON Tt.CampaignID = Kd.CampaignID                                                  
             INNER JOIN #tempMobile Tm                                                  
                     ON Tm.userID = Tt.userID   and Tm.CampaignID = Tt.CampaignID                                                  --AND Validentries = 1                                                  
      WHERE  Jobid=@jobId--Kd.ID = (select MAX(id) from Usercampaignexecutionhistory Kd1 where kd1.CampaignID=kd.CampaignID)                  
                        
      --select * from UserCampaignExecutionHistory where CampaignID=497 order by id desc                                                
                                                  
      ---------------------------------Send Notification mail --------------------               
      if ((select top 1 iseventbased from UserCampaignHistory where JobId=@jobId)=0)              
      begin              
      INSERT INTO Getbatchrecord                                                  
      ([User_id],                                                  
       RandNum)                                                  
      SELECT ParentID,                                                  
       CampaignID FROM #tempTable                                                  
                                                   
   Select BatchID,[User_id] ParentID,RandNum CampaignID into #Batch from Getbatchrecord Gbr            
   Order by gbr.BatchID                                     
                                                  
      DELETE Kd                                                  
      FROM   Getbatchrecord Kd                                                  
      Inner join    #Batch B on B.BatchId = Kd.BatchID                             
                                                  
      INSERT INTO Batchemail_infos                                                  
      (                                                  
      -- ID -- this column value is auto-generated                                                  
        B.BatchID,                                                  
       UserID,                                                  
       SenderName,                                               
        [Message],                                                  
       TotalRecords,                                                  
       TotalProcessed,                                                  
       ProcessTable,                                                  
       IsProcess,                                                  
       Priority_Level,                                                  
       BatchInsertTime,                                                  
        BatchProcessTime,                                                  
       ScheduledDate,                                         
       ScheduledTime,                                                  
       TemplateID,                                              
       [Route],                                                  
       PageName,                                                  
       IsScheduled,                                                  
       Email_Subject,                                                  
       ReplyTo,                                                  
       Amount,                                                  
       Currency)                                                  
      SELECT B.Batchid,                                                  
     335,                                                  
     Ucm.NotificationMail,                                                  
     case when TM.ValidEntries = 0 then 'Oops, you don''t have sufficient mail credits to run your mail campaign "'                  
     + Ucm.CampaignName + '" scheduled for '                                        
     + Cast(Getdate() AS VARCHAR(50))                                                  
     + '. Pl refill your credit balance & rerun the campaign ' else                    
     'As promised , Your Mail campaign "'                  
     /*+ CASE WHEN Ucm.MailReplyTo <> '' THEN 'Mail'                                                  
     ELSE                                                  
     'SMS'                                                  
     END + '*/                                                   
     + Ucm.CampaignName + '" scheduled for '                                                  
     + Cast(Getdate() AS VARCHAR(50))                                                  
     +                                                  
    ' is executed successfully. You can log in to your account & check the delivery report in the campaign history' end as  [Message]                                           
       ,                                                  
    1,                    
    0,                                                  
    0,                                                  
    0,                                                  
    1,                                                  
    Getdate(),                                                  
    Getdate(),                                                  
    Getdate(),                                                  
    Getdate(),                                                  
    0,                                                  
    0,                                                  
    0,                                                  
    0,                                                  
    case when TM.ValidEntries = 0 then 'Failure: Your campaign "' + + UCM.CampaignName + '" failed due to insufficient credits' else 'Success : Your campaign "' + UCM.CampaignName + '" executed successfully' end as email_subject,                  
    'noreply@email19.in',                                                  
    0,                                                
    0                                    
    FROM   #temptable Tt                             
       INNER JOIN Usercampaignmaster AS Ucm                                                  
       ON Ucm.ID = Tt.CampaignID                                                  
          AND Ucm.IsScheduled = 1                                                  
          AND Ucm.ParentID = Tt.ParentID                     
          Inner join #tempMobile TM on TM.CampaignID = Tt.CampaignID                 
