/* ============================================================
   Procedure: [dbo].[Usp_insertclonedeliverycampaignmailsCorrected_segregatemail_withid21102020]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE  PROCEDURE [dbo].[Usp_insertclonedeliverycampaignmailsCorrected_segregatemail_withid21102020]  --4594735          
(@jobId bigint)                                                       
AS                                                          
BEGIN                               
                             
create table #outputb(id int identity(1,1),bid bigint, u_id bigint,campaignid bigint)                
begin tran                  
INSERT INTO Getbatchrecord                                                              
([User_id],RandNum)                   
OUTPUT inserted.BatchID  as bId,inserted.User_id as u_id,inserted.RandNum as campaignid  INTO #outputb                                            
 SELECT DISTINCT Ucerm.ParentID,                                                          
                      Ucerm.CampaignID                                                          
      FROM   EmailsfiltercampaignexecutionTEST2 AS Ucerm With(nolock)                 
      where jobid=@jobid                                                            
                       
delete g From GetBatchRecord g join #outputb o on o.bid=g.BatchID                
commit                                     
                             
                           
                                                          
     SELECT                           
     ROW_NUMBER() Over(order by Ucerm.CampaignId,Ucerm.ParentId) Id,                          
     Ucerm.CampaignID,                             
     Ucerm.ParentID                               ,                          
                     -- Cast(Ucerm.Messages AS VARCHAR(MAX))  AS  Messages,                                                          
                      o.bid AS BatchID,                                                        
                     Ucerm.Mail_FromEmail,                                                          
                      Ucerm.Mail_UserID AS UserID,                          
                     -- Ucerm.Mail_Subject,                          
                      Ucerm.ReplyTo,                          
                      Count(*) cnt,ucerm.ispersonalized,ucerm.templateid                          
                     -- Ucerm.Mail_ToEmail,                                                          
   INTO   #tempTable                                                          
      FROM   EmailsfiltercampaignexecutionTEST2 Ucerm -- join user_detail u on ucerm.Mail_UserID=u.user_id                                    
      join #outputb o on o.u_id=ucerm.parentid and o.campaignid=ucerm.campaignid                                     
      WHERE  Ucerm.IsCompleted = 1 and jobid=@jobid  --and u.HasVirtualCredits=0                             
      Group by  Ucerm.CampaignID,                             
     Ucerm.ParentID , Ucerm.Mail_FromEmail,                                                          
                      Ucerm.Mail_UserID,                          
                      --Ucerm.Mail_Subject,                          
                      Ucerm.ReplyTo,ucerm.ispersonalized ,o.bid ,ucerm.templateid                       
                                            
    SELECT                           
     ROW_NUMBER() Over(order by Ucerm.CampaignId,Ucerm.ParentId) Id,                          
     Ucerm.CampaignID,                             
     Ucerm.ParentID                               ,                          
     -- Cast(Ucerm.Messages AS VARCHAR(MAX))  AS  Messages,                                                          
      o.bid AS BatchID,                                                        
     Ucerm.Mail_FromEmail,                                                          
      Ucerm.Mail_UserID AS UserID,                          
      Ucerm.Mail_Subject,                          
      Ucerm.ReplyTo,                          
      Count(*) cnt,                      
      ParentSuperResellerId,ispersonalized                          
                     -- Ucerm.Mail_ToEmail,                                                          
    INTO   #tempTableVirtual                                                      
      FROM   EmailsfiltercampaignexecutionTEST2 Ucerm (nolock) join user_detail u(nolock) on ucerm.Mail_UserID=u.user_id  
	  join #outputb o on o.u_id=ucerm.parentid and o.campaignid=ucerm.campaignid                                    
      WHERE  Ucerm.IsCompleted = 1  and u.HasVirtualCredits=1 and jobid=@jobid                             
      Group by  Ucerm.CampaignID,ParentSuperResellerId,                   
     Ucerm.ParentID , Ucerm.Mail_FromEmail,                                                          
                      Ucerm.Mail_UserID,                          
                      Ucerm.Mail_Subject,                          
                      Ucerm.ReplyTo , ispersonalized ,o.bid                    
                                            
                                                                         
                                
   SELECT A.UserID,a.CampaignID, a.cnt,A.BatchID, SUM(b.cnt) RunningTotal into #TempTableRunningTotal                          
   FROM   #tempTable a inner join #tempTable b                          
   on b.CampaignID <= a.CampaignID                          
   GROUP BY A.UserID, a.CampaignID, a.cnt,A.BatchID                          
   ORDER BY a.CampaignID;                        
                         
   SELECT A.UserID,a.CampaignID, a.cnt,A.BatchID, SUM(b.cnt) RunningTotal,a.ParentSuperResellerId into #TempTableRunningTotalVirtual                     
   FROM   #tempTableVirtual a inner join #tempTableVirtual b                          
   on b.CampaignID <= a.CampaignID                          
   GROUP BY A.ParentSuperResellerId, a.CampaignID, a.cnt,A.BatchID,A.UserID                          
   ORDER BY a.CampaignID;                        
                                
   drop table #outputb                             
      /*DELETE Kd                                                          
      FROM   Getbatchrecord Kd                                                          
             INNER JOIN #tempTable Tt                                                          
                     ON Tt.BatchID = Kd.BatchID                         
                                           
      DELETE Kd                                                          
      FROM   Getbatchrecord Kd                                                          
             INNER JOIN #tempTableVirtual Tt                                                          
                     ON Tt.BatchID = Kd.BatchID */                                                      
                                                        
                                                          
      --- Calculate credits                                                          
    SELECT B.UserID,                           
    B.CampaignID,                                                         
             CASE                                                          
               WHEN B.Balance >= B.Credits THEN 1                                                          
               ELSE 0 --test, otherwise 0                                                          
             END AS ValidEntries                                                          
      INTO   #tempMobile                                                          
      FROM   (SELECT A.UserID,                            
      A.CampaignID,                                                        
                       (A.Credits)   AS Credits,  --Runningtotal                                                        
                     A.Balance                                                          
              FROM   (SELECT Tt.UserID,                                                          
                             TT.RunningTotal AS Credits,             
                             TT.CampaignID,                                                          
                            -- Tt.Mail_ToEmail,       
                             Tt.BatchID,                                                          
                             (SELECT TOP 1 Balance                                                          
                  FROM   Mailcreditdetails AS Mcd                                                          
                              WHERE  Mcd.[User_ID] = Tt.UserID                                   
ORDER  BY Credit_ID DESC)     AS Balance                                                          
                      FROM   #TempTableRunningTotal Tt) A                                                          
              GROUP  BY A.UserID,                                                          
                        A.Balance,A.CampaignID,A.credits) B               
                                      
update u set u.ReasonIfNotRun='Insufficient Balance' from UserCampaignHistory u join #tempMobile t              
on u.campaignid=t.CampaignID and u.jobid=@jobid where t.validentries=0                         
     --select * from #tempmobile                        
                           
     SELECT B.UserID,                           
            B.CampaignID,                                                         
            CASE                                                          
               WHEN B.Balance > B.Credits THEN 1                                                          
               ELSE 0 --test, otherwise 0                                                          
             END AS ValidEntries,                      
             B.ParentSuperResellerId                                                          
      INTO   #tempMobileVirtual                                                          
      FROM   (SELECT A.UserID,                            
      A.CampaignID,                                                        
      (A.Credits)   AS Credits,  --Runningtotal                                                        
      A.Balance,                      
      A.ParentSuperResellerId                                                          
      FROM   (SELECT Tt.UserID,                                                          
                     TT.RunningTotal AS Credits,                          
                     TT.CampaignID,                                                          
                     -- Tt.Mail_ToEmail,                                                    
                     Tt.BatchID,                                                          
                     (SELECT TOP 1 Balance                           
                      FROM   SuperResellerMailCreditDetails AS Mcd                                                          
                      WHERE  Mcd.[User_ID] = Tt.ParentSuperResellerId                                  
                      ORDER  BY Credit_ID DESC)     AS Balance,                      
                      tt.ParentSuperResellerId                                                          
               FROM   #TempTableRunningTotalVirtual Tt) A                                                          
              GROUP  BY A.ParentSuperResellerId,A.UserID,                                                         
                        A.Balance,A.CampaignID,A.credits) B                       
                           
select t.*,u.email into #Insufficientresellerbalance from #tempMobileVirtual t join #tempMobile tt on t.CampaignID=tt.CampaignID join user_detail u on u.user_id=t.ParentSuperResellerId where tt.ValidEntries=0                      

                     
INSERT INTO Batchemail_infos(BatchID,UserID,SenderName,[Message],TotalRecords,TotalProcessed,ProcessTable,IsProcess,Priority_Level,BatchInsertTime,  
BatchProcessTime,ScheduledDate,ScheduledTime,TemplateID,[Route],PageName,IsScheduled,Email_Subject,ReplyTo,ispersonalized,bmonitor,mail_source)                    
SELECT distinct A.BatchID,A.UserID,A.Mail_FromEmail as SenderName,  
(select top 1 case when e.Messages is null 
then CAST(dbo.build_mailContent(c.templateid,c.campaignid,c.parentid,c.Messages COLLATE Latin1_General_CI_AI,e.Mail_ToEmail) AS NVARCHAR(MAX)) else cast(e.messages as nvarchar(max)) end 
from EmailsfiltercampaignexecutionTEST2 e(nolock)         
join campaignmessages c(nolock) on c.campaignid=e.CampaignID and c.jobid=e.jobid                          
      where e.CampaignID=a.campaignid and e.jobid=@jobid ),  
A.cnt,0,0,0,case when A.cnt>10 then 0 when A.cnt<=10 then 1 else 0 end,  
Getdate(),NULL,NULL,NULL, A.templateid,0,0,0,
(select top 1 case when e.Mail_Subject is null then cast(c.Mail_Subject COLLATE Latin1_General_CI_AI as nvarchar(200))            
else e.Mail_Subject end  from EmailsfiltercampaignexecutionTEST2 e join campaignmessages c on c.campaignid=e.CampaignID and c.jobid=e.jobid              where e.CampaignID=a.campaignid and e.jobid=@jobid ),  
A.ReplyTo,ispersonalized,(select case when status=1 and A.cnt>plimit then 0 else 1 end from ProcessMailLimit)
,'Campaign :'+cast(isnull(a.campaignid,'') as nvarchar)                           
      FROM #tempTable A (nolock)                           
      Inner join #tempMobile TM on Tm.CampaignID = A.CampaignID and TM.UserID = A.UserID                           
      join user_detail u (nolock) on u.user_id=a.UserID  and TM.ValidEntries = 1     
                             
create table #output (GUID nvarchar(100) collate SQL_Latin1_General_CP1_CI_AS ,Email nvarchar(200) collate SQL_Latin1_General_CP1_CI_AS,Batchid bigint)                          
                    
 SELECT ROW_NUMBER()Over(Order by mail_ID) AS Id,* into #e from EmailsfiltercampaignexecutionTEST2(nolock) where jobid=@jobid                     
 declare @mailcount int=(select COUNT(1) from #e)                    
 declare @idcount bigint=(select MIN(id) from #e)     
     
     
 declare @tbl_activity as dbo.LeadActivitywithid_Tbltype    
--CREATE TABLE #tbl_activity(        
-- [LeadID] [bigint] NULL,        
-- [UserID] [bigint] NULL,        
-- [ParentID] [bigint] NULL,        
-- [EventDescription] [nvarchar](max) NULL,        
-- [EventName] [nvarchar](500) NULL        
--)        
insert into @tbl_activity( LeadID , UserID, ParentID , EventDescription , EventName,RefTable,refid)                   
select m.entityid,m.Mail_UserID,m.ParentID, cast(u.user_login as nvarchar(100)) +' sent '+        
case when nullif(cm.TemplateID,0) is not null then ' template with name"' +isnull(umt.Name,'no name') +'"' 
else ' a mail ' end + ' with subject "'+ 
case when nullif(cm.TemplateID,0) is not null then umt.MailSubject   
when cm.Mail_Subject is not null then cm.Mail_Subject  
else isnull(replace(m.[mail_subject],'''','"'),'') end+ '" to emailid '      
+cast(m.Mail_ToEmail as nvarchar(100)) +' through automated campaign named ' + c.CampaignName        
,'Mail sent to '+m.entityname,'Batchemail_infos',tt.BatchID
 from user_detail u     
 join #e m on m.Mail_UserID=u.User_ID       
 join UserCampaignMaster c on c.ID=m.CampaignID        
 left join campaignmessages cm on cm.campaignid=m.campaignid and cm.jobid=m.jobid    
 left join usermailtemplate umt on umt.id=cm.templateid    
 join #tempTable tt on tt.CampaignID=m.CampaignID
 where m.entityname in ('Lead','Enquiry') and isnull(m.entityid,0)<>0                 
     
exec UspSaveEntityActivity_withMultipleValue_withid_bulk @tbl_activity        
         
                      
 while @mailcount>0                    
 begin                     
 INSERT INTO Clientemails                                                          
                  (                                          
