             case when efce.ispersonalized=1 and Efce.Messages is not null then cast(Efce.Messages as nvarchar(max)) else CAST(dbo.build_mailContent(c.templateid,c.campaignid,c.parentid,c.Messages               
             COLLATE Latin1_General_CI_AI,efce.Mail_ToEmail) AS NVARCHAR(MAX))          end,                                                        
             isnull(Efce.Mail_InsertedDate,getdate()),                                                          
             Efce.Mail_UserID,                                                          
             Efce.ReplyTo,                                                          
             TT.BatchID,   
    case when aws.user_id is not null then 2 when tt.cnt>10 then Efce.Mail_Priority when tt.cnt<=10 then 1 else 0 end,                     
    --case when tt.cnt>10 then Efce.Mail_Priority else 1 end,                                                          
             isnull(Efce.Mail_ScheduleDate,getdate()),                                                          
             Efce.Mail_Attechement,                                                          
             case when efce.ispersonalized=1 and Efce.Messages is not null then cast(Efce.Messages as nvarchar(max)) else CAST(dbo.build_mailContent(c.templateid,c.campaignid,c.parentid,c.Messages                 
             COLLATE Latin1_General_CI_AI,efce.Mail_ToEmail) AS NVARCHAR(MAX))          end,  
			 (select case when status=1 and tt.cnt>plimit then 0 else 1 end from ProcessMailLimit)                                                        
             --1 AS Limit                                                          
      FROM   #e AS Efce                                                          
             INNER JOIN #tempMobile Tm                                                          
        ON Tm.userID = Efce.Mail_UserID  and Tm.CampaignID = Efce.CampaignID                                              
                        AND ValidEntries = 1                         
                        inner join #tempTable TT on TT.campaignid=efce.campaignid                        
                        inner join #output o on o.email=Efce.mail_toemail  
						left join campaignmessages c on  c.campaignid=efce.campaignid and c.jobid=efce.jobid 
						left join   
             (select user_id,frommailid from awsmailroute aws (nolock) join user_detail(nolock) u on aws.mailuser=u.user_id where isactive=1) aws on aws.User_ID=efce.Mail_UserID and aws.frommailid=efce.Mail_FromEmail                                      
                 
      WHERE  Efce.IsCompleted = 1 and o.batchid=tt.batchid and efce.id<=@idcount+1000                      
      and not exists                      
      (SELECT O.Guid                                                         
