                   Mail_Priority,                                                          
                   Mail_ScheduleDate,                                                          
                   Mail_Attechement,                                                          
                   Mail_TempleteBody,                                                          
                   IsMonitor)                   
      SELECT O.Guid,                                                          
             Efce.Mail_FromEmail,                                                          
