       '',                                                          
        B.Batchid,                                                          
       'Oops, something went wrong and your campaign couldn''t run. Please contact your administrator for details' as  [Message]                                                           
    FROM   #tempTable Tt                            
       INNER JOIN Usercampaignmaster AS Ucm                                                          
       ON Ucm.ID = Tt.CampaignID                                                          
          AND Ucm.IsScheduled = 1                                                          
          AND Ucm.ParentID = Tt.ParentID                            
          Inner join #tempMobile TM on TM.CampaignID = Ucm.ID                          
          Inner join #Batch B on B.CampaignId = Tt.CampaignId                       
        inner join #tempMobileVirtual tmv on tt.CampaignID=tmv.CampaignID where tmv.ValidEntries=0                      
    union                      
                        
    SELECT Newid(),                                                          
       inrc.eMail,                                       
       Getdate(),                                                          
       335,                                                          
       'noreply@email19.in',                                                          
       '',                                                          
        B.Batchid,                       
       'We are unable to run some of your users'' campaigns because of insufficient credits. Please refill your mail credits to enjoy uninterrupted services for your users.' as  [Message]                                                           
    FROM   #tempTable Tt                                                          
       INNER JOIN Usercampaignmaster AS Ucm                                                          
       ON Ucm.ID = Tt.CampaignID                                                          
          AND Ucm.IsScheduled = 1                                                          
          AND Ucm.ParentID = Tt.ParentID            
          Inner join #tempMobile TM on TM.CampaignID = Ucm.ID                          
          Inner join #Batch B on B.CampaignId = Tt.CampaignId                       
          inner join #tempMobileVirtual tmv on tt.CampaignID=tmv.CampaignID                       
          inner join #Insufficientresellerbalance inrc on inrc.CampaignID=tt.CampaignID                      
          where tmv.ValidEntries=0                    
                                                          
    INSERT INTO Emailsfilter                                                          
        (Mail_GUID,                                                          
         -- Mail_ID -- this column value is auto-generated                                            
         Mail_FromEmail,                                                          
        Mail_ToEmail,                                                          
         Mail_Subject,                                                          
         Mail_TempleteName,                                                          
         Messages,                                              
         Mail_InsertedDate,                                                          
         Mail_UserID,                                                          
         ReplyTo,                                                    
         Mail_BatchID,                                                          
         Mail_Priority,                                                          
         Mail_ScheduleDate,                                                          
         Mail_Attechement,                                                          
         Mail_TempleteBody,                                                          
         IsMonitor)                                                          
    SELECT o.guid,                                                          
       'noreply@email19.in',                         
       UCM.NotificationMail,                                                          
       case when TM.ValidEntries = 0 then 'Failure: Your campaign "' + + UCM.CampaignName + '" failed due to insufficient credits' else 'Success : Your campaign "' + UCM.CampaignName + '" executed successfully' end as Mail_subject,                       
                                 
       '',                       
       case when TM.ValidEntries = 0 then 'Oops, you don''t have sufficient mail credits to run your mail campaign "'                          
     + UCM.CampaignName + '" scheduled for '                                                          
     + Cast(Getdate() AS VARCHAR(50))                                                          
     + '. Pl refill your credit balance & rerun the campaign ' else                            
     'As promised , Your Mail campaign "'                          
     /*+ CASE WHEN Ucm.MailReplyTo <> '' THEN 'Mail'                                                          
     ELSE                                          
     'SMS'                                                          
     END + '*/                                                           
     + UCM.CampaignName + '" scheduled for '                                                          
     + Cast(Getdate() AS VARCHAR(50))                                                          
     +                                                          
        ' is executed successfully. You can log in to your account & check the delivery report in the campaign history' end as  [Messages]                                                           
       ,                                                          
        Getdate(),                                    
        335,                                                          
'noreply@email19.in',                                                          
        B.Batchid,                                                          
        1,                                                
        Getdate(),                                                          
        0,                                                          
       case when TM.ValidEntries = 0 then 'Oops, you don''t have sufficient mail credits to run your mail campaign "'                          
         + UCM.CampaignName + '" scheduled for '                                                          
         + Cast(Getdate() AS VARCHAR(50))                                                          
         + '. Pl refill your credit balance & rerun the campaign ' else                            
         'As promised , Your Mail campaign "'                          
         /*+ CASE WHEN Ucm.MailReplyTo <> '' THEN 'Mail'                                                          
         ELSE                                                          
         'SMS'                                                          
         END + '*/                                                           
         + UCM.CampaignName + '" scheduled for '                                                          
         + Cast(Getdate() AS VARCHAR(50))                            
         +                                                          
        ' is executed successfully. You can log in to your account & check the delivery report in the campaign history' end as mail_templetebody,                                                          
        1                                                          
        FROM   #tempTable Tt                                                        
           INNER JOIN Usercampaignmaster AS Ucm                                               
           ON Ucm.ID = Tt.CampaignID                                                          
          AND Ucm.IsScheduled = 1                                                          
          AND Ucm.ParentID = Tt.ParentID                                                          
          Inner join #tempMobile TM on TM.CampaignID = Ucm.ID                         
          Inner join #Batch B on B.CampaignId = Tt.CampaignId                       
          inner join #output o on o.Email=ucm.NotificationMail                       
          left join #tempMobileVirtual tmv on tmv.CampaignID=tt.CampaignID                      
          where o.Batchid=B.BatchID  and (tmv.ValidEntries is null or tmv.ValidEntries=1)                      
    union                      
                        
    SELECT o.guid,                                                          
        'noreply@email19.in',                                                          
        UCM.NotificationMail,                       
        'Failure: Your campaign "' + + UCM.CampaignName + '" failed. Please contact your administrator for details.' as Mail_subject,                      
        '',                                                          
        'Oops, something went wrong and your campaign couldn''t run. Please contact your administrator for details' as  [Messages]    ,                                                          
        Getdate(),                                                          
        335,                                                          
        'noreply@email19.in',                                                          
        B.Batchid,                                                          
        1,                                                          
        Getdate(),                                                          
        0,                                                          
        'Oops, something went wrong and your campaign couldn''t run. Please contact your administrator for details' as mail_templetebody,                                                 
        1                                                          
    FROM   #tempTable Tt                                                          
       INNER JOIN Usercampaignmaster AS Ucm                                               
           ON Ucm.ID = Tt.CampaignID                                                          
          AND Ucm.IsScheduled = 1                                                        
          AND Ucm.ParentID = Tt.ParentID                                                          
          Inner join #tempMobile TM on TM.CampaignID = Ucm.ID                         
          Inner join #Batch B on B.CampaignId = Tt.CampaignId                       
          inner join #output o on o.Email=ucm.NotificationMail                       
     inner join #tempMobileVirtual tmv on tmv.CampaignID=tt.CampaignID                      
          where o.Batchid=B.BatchID and tmv.ValidEntries=0                   
    union                      
                        
    SELECT o.guid,                                                          
       'noreply@email19.in',                                                          
       inrc.eMail,                                              
       'Failure: Your users'' campaign "' + + UCM.CampaignName + '" failed because of insufficient mail credits in your account.' as Mail_subject,                                          
       '',                                                          
        'We are unable to run some of your users'' campaigns because of insufficient credits. Please refill your mail credits to enjoy uninterrupted services for your users.' as  [Messages]                                                           
       ,                                                          
        Getdate(),                                                          
        335,                            
        'noreply@email19.in',                                                          
        B.Batchid,                                                          
        1,                                                          
        Getdate(),                                                          
        0,                                                          
        'We are unable to run some of your users'' campaigns because of insufficient credits. Please refill your mail credits to enjoy uninterrupted services for your users.' as mail_templetebody,                                                          
        1                                                          
    FROM   #tempTable Tt                         
    inner join #Insufficientresellerbalance inrc on inrc.CampaignID=tt.CampaignID                                                       
       INNER JOIN Usercampaignmaster AS Ucm                                               
           ON Ucm.ID = Tt.CampaignID                                                          
          AND Ucm.IsScheduled = 1                                                          
          AND Ucm.ParentID = Tt.ParentID                                                          
          Inner join #tempMobile TM on TM.CampaignID = Ucm.ID                         
          Inner join #Batch B on B.CampaignId = Tt.CampaignId                       
          inner join #output o on o.Email=ucm.NotificationMail                       
          where o.Batchid=B.BatchID                       
                        
                                                                      
    INSERT INTO Mailcreditdetails                                                          
        (ID,                                               
         -- Credit_ID -- this column value is auto-generated                              
M_ID,                                                          
         FromUser_ID,   
         [User_ID],                                                          
         Debits,                                                          
         Credits,                                                          
         Balance,                                                          
         Validity,                                                          
         Default_Credit,                                                 
         FromDate,                                                          
         ToDate,                                                          
         DateCreated,                                                          
         DateUpdated,                                                          
         EmpUpdated,                                                          
         MachineName,                          
         LastModified,                                                          
         typecredit)                                                          
    SELECT Newid(),                    
       10001,                                            
       335,                                                          
       335,                                                       
       Count(*),                                                          
       0,                                                          
       (SELECT TOP 1 Mcd.Balance                                                          
        FROM   Mailcreditdetails AS Mcd                                                          
        WHERE  Mcd.[User_ID] = 335                                                          
        ORDER  BY Mcd.Credit_ID DESC) - Count(*),                     
        99999,                                                          
       0,                                                          
       Getdate(),                                
       Getdate(),                                                          
       Getdate(),                                                          
       Getdate(),                                                          
       'Campaign Exec',                                       
       '',                                                          
       Getdate(),                                                          
       0                                                          
    FROM   #tempTable Tt               
       INNER JOIN Usercampaignmaster AS Ucm                                                          
           ON Ucm.ID = Tt.CampaignID                                                          
          AND Ucm.ParentID = Tt.ParentID                                                       
          AND Ucm.IsScheduled = 1                            
          Inner join #tempMobile TM on TM.CampaignID = Ucm.ID                                                                  
    union                      
                          
      SELECT Newid(),                                                          
       10001,                                                          
       335,                                                          
       335,                                                       
       Count(*),                                                          
       0,                                                          
       (SELECT TOP 1 Mcd.Balance                                                          
        FROM   Mailcreditdetails AS Mcd                                                          
        WHERE  Mcd.[User_ID] = 335                  
        ORDER  BY Mcd.Credit_ID DESC) - Count(*),                                                          
        99999,                                                          
       0,                                                          
       Getdate(),         
       Getdate(),                                                          
       Getdate(),                                                          
       Getdate(),                                                          
       'Campaign Exec',                                       
       '',                                                          
       Getdate(),                                                          
       0                                                          
    FROM   #tempTable Tt                        
       inner join #tempMobileVirtual tmv on tmv.CampaignID=tt.CampaignID                                                        
       INNER JOIN Usercampaignmaster AS Ucm                                                          
           ON Ucm.ID = Tt.CampaignID                                              
          AND Ucm.ParentID = Tt.ParentID                                                       
          AND Ucm.IsScheduled = 1                            
          Inner join #tempMobile TM on TM.CampaignID = Ucm.ID                                                                   
          where tmv.ValidEntries=0                      
                                         
    drop table #Batch                                                          
      end                
                     
    ---------------------------------Send Notification Mail End ----------------                                                           
    declare @emailcount bigint=(select count(1)  FROM   EmailsfiltercampaignexecutionTEST2 Kd                                                          
           INNER JOIN #tempTable Tt                                                          
                   ON Tt.CampaignID = Kd.CampaignID and jobid=@jobid)                    
   while @emailcount>0                    
   begin                    
 DELETE top (1000) Kd                                                          
    FROM   EmailsfiltercampaignexecutionTEST2 Kd                                                          
           INNER JOIN #tempTable Tt                                                          
                   ON Tt.CampaignID = Kd.CampaignID and jobid=@jobid                     
 set @emailcount=@emailcount-1000                    
    end                    
/* DELETE Kd                                                          
    FROM   campaignmessages Kd                                                          
           INNER JOIN #tempTable Tt                                                          
                   ON Tt.CampaignID = Kd.CampaignID and jobid=@jobid  */                      
                     
                                       
                                             
   UPDATE Kd                                                  
   SET    Kd.step3 = 1 ,Step3DateTime=GETDATE() ,                                          
   Step3Recipients= Case when ValidEntries = 1 then TT.cnt Else 0 End                          
   FROM   usercampaignhistory Kd                           
   inner join #tempTable TT on TT.CampaignID = Kd.CampaignID                          
   inner join #tempMobile TM on TM.CampaignID = Kd.CampaignID                          
   Where Kd.JobId = @jobId                          
                           
   UPDATE Kd                                                  
   SET    Kd.step3 = 1 ,Step3DateTime=GETDATE() FROM   usercampaignhistory Kd Where Kd.JobId = @jobId                      
                       
   update u set executeddatetime=getdate() from usercampaignmaster u join usercampaignhistory Kd on kd.campaignid=u.id and Kd.JobId = @jobId                      
                            
    --Code added to update nextexecutiondate in usercampaignhistory Start--                        
    select campaignid into #FindCampaignsNextExecution from #tempTable t join UserCampaignMaster ucm on t.CampaignID=ucm.id    left join userschedules  us on us.id=ucm.scheduleid                     
    where ucm.IsActive=1 and ucm.IsSchedule=1 and ucm.IsScheduled=1 and us.IsOnce=0              
                            
 declare @count int =isnull((select COUNT(1) from #FindCampaignsNextExecution),0)                        
 if @count>0                        
 begin                        
    create table #nextexec1(campaignid bigint,nextexecution datetime)                                    
    WHILE @Count > 0                                        
  BEGIN                                        
   DECLARE @Campaignid BIGINT = (                                        
       SELECT TOP 1 campaignid                                        
    FROM   #FindCampaignsNextExecution                                        
      )                            
                       
   INSERT INTO #nextexec1                                        
       (                                        
      campaignid,                                        
      nextexecution                                        
       )                                        
    EXEC Usp_getnextscheduledate                                    
       @Campaignid                                        
                        
    DELETE                                         
    FROM   #FindCampaignsNextExecution                                        
    WHERE  campaignid = @Campaignid                                        
                        
    SET @Count = @Count - 1                          
  END                        
                       
   update u set NextExecuteDateTime= nextexecution from usercampaignmaster u join #nextexec1 n on n.campaignid=u.id                        
   where u.ExpiryDate > nextexecution or u.ExpiryDate is null                        
    drop table #nextexec1                        
    drop table #FindCampaignsNextExecution                      
                          
 end                        
                     
    --Code added to update nextexecutiondate in usercampaignhistory end--                                   
    DROP TABLE #tempMobile                                                          
    DROP TABLE #tempTable                      
    drop table #tempMobileVirtual                      
    drop table #tempTableVirtual                      
    drop table #Insufficientresellerbalance                      
    drop table #TempTableRunningTotal                      
    drop table #TempTableRunningTotalVirtual                      
    drop table #output                       
                        
     if exists(select 1 from UserCampaignHistory where JobId=@jobId and IsEventBased=0 and isSMS=0)                      
    begin                    
    update usercampaignexecution set CampaignEnddatetime=GETDATE(),isrunning=0 where isevent=0 and isSMS=0                    
    --select 'updated'                    
    end                    
     if exists(select 1 from UserCampaignHistory where JobId=@jobId and IsEventBased=1 and isSMS=0)                    
    begin                    
    update usercampaignexecution set CampaignEnddatetime=GETDATE(),isrunning=0 where isevent=1 and isSMS=0                    
    end                        
 END 


GO

/* ============================================================
   Procedure: [dbo].[Usp_insertclonedeliverycampaignmailsCorrected030718]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

              
CREATE   PROCEDURE [dbo].[Usp_insertclonedeliverycampaignmailsCorrected030718] (@jobId bigint)                                     
AS                                      
  BEGIN           
         
      INSERT INTO Getbatchrecord                                      
                  (                                      
      -- BatchID -- this column value is auto-generated                                      
       [User_id],                                      
                   RandNum)                                      
      SELECT DISTINCT Ucerm.ParentID,                                      
                      Ucerm.CampaignID                                      
      FROM   EmailsfiltercampaignexecutionTEST2 AS Ucerm With(nolock)      
                                      
      SELECT       
     ROW_NUMBER() Over(order by CampaignId,ParentId) Id,      
     Ucerm.CampaignID,         
     Ucerm.ParentID                               ,      
                     -- Cast(Ucerm.Messages AS VARCHAR(MAX))  AS  Messages,                                      
                      dbo.Fn_createbatchid(Ucerm.CampaignID, Ucerm.ParentID) AS BatchID,                                    
                     Ucerm.Mail_FromEmail,                                      
                      Ucerm.Mail_UserID AS UserID,      
                      Ucerm.Mail_Subject,      
                      Ucerm.ReplyTo,      
                      Count(*) cnt      
                     -- Ucerm.Mail_ToEmail,                                      
   INTO   #tempTable                                      
      FROM   EmailsfiltercampaignexecutionTEST2 Ucerm                                      
      WHERE  Ucerm.IsCompleted = 1           
      Group by  Ucerm.CampaignID,         
     Ucerm.ParentID , Ucerm.Mail_FromEmail,                                      
                      Ucerm.Mail_UserID,      
                      Ucerm.Mail_Subject,      
                      Ucerm.ReplyTo                                  
            
      SELECT A.UserID,a.CampaignID, a.cnt,A.BatchID, SUM(b.cnt) RunningTotal into #TempTableRunningTotal      
   FROM   #tempTable a join      
       #tempTable b  on a.userid=b.userid    
   WHERE b.CampaignID <= a.CampaignID      
   GROUP BY A.UserID, a.CampaignID, a.cnt,A.BatchID      
   ORDER BY a.CampaignID;      
            
            
      DELETE Kd                                      
      FROM   Getbatchrecord Kd                                      
             INNER JOIN #tempTable Tt                                      
                     ON Tt.BatchID = Kd.BatchID                                      
                                    
                                      
      --- Calculate credits                                      
      SELECT B.UserID,       
    B.CampaignID,                                     
             CASE                                      
               WHEN B.Balance > B.Credits THEN 1                                      
               ELSE 0 --test, otherwise 0                                      
             END AS ValidEntries                                      
      INTO   #tempMobile                                      
      FROM   (SELECT A.UserID,        
      A.CampaignID,                                    
                       (A.Credits)   AS Credits,  --Runningtotal                                    
                     A.Balance                                      
              FROM   (SELECT Tt.UserID,                                      
                             TT.RunningTotal AS Credits,      
                             TT.CampaignID,                                      
                            -- Tt.Mail_ToEmail,                                
                             Tt.BatchID,                                      
                             (SELECT TOP 1 Balance                                      
                              FROM   Mailcreditdetails AS Mcd                                      
                              WHERE  Mcd.[User_ID] = Tt.UserID               
                              ORDER  BY Credit_ID DESC)     AS Balance                                      
                      FROM   #TempTableRunningTotal Tt) A                                      
              GROUP  BY A.UserID,                                      
                        A.Balance,A.CampaignID,A.credits) B      
     --select * from #tempmobile      
INSERT INTO Batchemail_infos(BatchID,UserID,SenderName,[Message],TotalRecords,TotalProcessed,ProcessTable,IsProcess,Priority_Level,BatchInsertTime,BatchProcessTime,ScheduledDate,ScheduledTime,TemplateID,[Route],PageName,IsScheduled,Email_Subject,ReplyTo) 
 
                                    
      SELECT A.BatchID,A.UserID,U.Email as SenderName,(select top 1 Cast(e.Messages AS VARCHAR(MAX))       
      from EmailsfiltercampaignexecutionTEST2 e       
      where e.CampaignID=a.campaignid),A.cnt,0,0,0,0,Getdate(),NULL,NULL,NULL,0,0,0,0,A.Mail_Subject,A.ReplyTo       
      FROM #tempTable A (nolock)       
      Inner join #tempMobile TM on Tm.CampaignID = A.CampaignID and TM.UserID = A.UserID       
      join user_detail u (nolock) on u.user_id=a.UserID  and TM.ValidEntries = 1      
           
create table #output (GUID nvarchar(100) collate SQL_Latin1_General_CP1_CI_AS ,Email nvarchar(200) collate SQL_Latin1_General_CP1_CI_AS,Batchid bigint)      
  
           
      INSERT INTO Clientemails                                      
                  (                      
      -- Id -- this column value is auto-generated                                      
      GUID,                                      
                   Email_Id,                                      
                   SentDateTime,                                      
                   UserId,                                      
                   ReplyTo,                          
                   [Status],                                      
                   BatchID,                                      
                   [Message],  
                   campaignid,  
                   parentid)   
      OUTPUT inserted.GUID  as GUId,inserted.email_id,inserted.batchid as Email INTO #output                                         
      SELECT Newid(),                                      
             Efce.Mail_ToEmail,                                      
             Getdate(),                                      
             Efce.Mail_UserID,                                      
             Efce.ReplyTo,                                      
             '',                                      
             TT.BatchID,                                      
             Efce.Messages,  
             efce.CampaignID,  
             efce.ParentID                                      
      FROM   EmailsfiltercampaignexecutionTEST2 AS Efce                                      
             INNER JOIN #tempMobile Tm                                      
      ON Tm.CampaignID = Efce.CampaignID AND ValidEntries = 1     
   inner join #tempTable TT on TT.campaignid=efce.campaignid    
      WHERE  Efce.IsCompleted = 1                                      
                                      
      INSERT INTO Emailsfilter                                     
                  (Mail_GUID,                                      
                   Mail_FromEmail,                                      
                   Mail_ToEmail,                                      
                   Mail_Subject,                                      
                   Mail_TempleteName,                                      
                   Messages,                                      
                   Mail_InsertedDate,                                      
                   Mail_UserID,                                      
                   ReplyTo,                                      
                Mail_BatchID,                                      
                   Mail_Priority,                                      
                   Mail_ScheduleDate,                                      
                   Mail_Attechement,                                      
                   Mail_TempleteBody,                                      
                   IsMonitor)                                      
      SELECT O.Guid,                                      
             Efce.Mail_FromEmail,                                      
             Efce.Mail_ToEmail,          
             Efce.Mail_Subject,                                   
             Efce.Mail_TempleteName,                                      
             Efce.Messages,                                    
             isnull(Efce.Mail_InsertedDate,getdate()),                                      
             Efce.Mail_UserID,                                      
             Efce.ReplyTo,                                      
             TT.BatchID,                                      
             Efce.Mail_Priority,                                      
             isnull(Efce.Mail_ScheduleDate,getdate()),                                      
             Efce.Mail_Attechement,                                      
             Efce.Mail_TempleteBody,                                      
             1 AS Limit                                      
      FROM   EmailsfiltercampaignexecutionTEST2 AS Efce                                      
             INNER JOIN #tempMobile Tm                                      
        ON Tm.userID = Efce.Mail_UserID  and Tm.CampaignID = Efce.CampaignID                          
                        AND ValidEntries = 1     
                        inner join #tempTable TT on TT.campaignid=efce.campaignid    
                        inner join #output o on o.email=Efce.mail_toemail                                   
      WHERE  Efce.IsCompleted = 1 and o.batchid=tt.batchid     
        
      truncate table #output                                   
                                      
      INSERT INTO Mailcreditdetails                                      
                  (ID,                                      
                   -- Credit_ID -- this column value is auto-generated                                      
                   M_ID,                                      
                   FromUser_ID,                                      
                   [User_ID],                                      
                   Debits,                                      
                 Credits,                                      
                 Balance,                                      
                   Validity,                                      
                   Default_Credit,                                      
                   FromDate,                                      
                   ToDate,                                      
                   DateCreated,                                      
                   DateUpdated,                                      
               EmpUpdated,                                      
                   MachineName,                                      
                   LastModified,                                      
                   typecredit,    
                   campaignid)                                      
      SELECT Newid(),                                      
             (SELECT TOP 1 Ud.M_ID                                      
              FROM   User_detail AS Ud                                      
              WHERE  Ud.[User_ID] = A.UserID),                                      
             A.UserID,                                      
             A.UserID,                                      
             A.NoofRecipients,                                      
             0,                
             (SELECT TOP 1 Mcd.Balance                                      
              FROM   Mailcreditdetails AS Mcd                                      
              WHERE  Mcd.[User_ID] = A.UserID                                      
              ORDER  BY Mcd.Credit_ID DESC) - A.NoofRecipients,                                      
             99999,                                      
       '',                                      
             Getdate(),                                      
             Getdate(),                                      
             Getdate(),                                      
             Getdate(),                                      
             '',                                      
             '',                                      
             Getdate(),                             
             '',    
             A.Campaignid                                      
      FROM   (SELECT DISTINCT Ed.UserID,Ed.CampaignID,Ed.ParentID,                                      
                              SUM(Ed.Cnt) AS NoofRecipients                                      
              FROM   #tempTable Ed                                      
                     INNER JOIN #tempMobile Tm                                      
                  ON Tm.userID = Ed.UserID   and Tm.CampaignID = Ed.CampaignID   
                  where Ed.Cnt>0                                                                             AND ValidEntries = 1                                      
               GROUP  BY Ed.UserID,Ed.CampaignID,Ed.ParentID,ED.UserID) A          
                    
     UPDATE Kd                                      
      SET    Executiontime = Getdate(),                                      
             Noofrecipients = Tt.Cnt,              
             Batchid = Tt.BatchID,                                      
             --Ismessages = 1,                                      
             Isexecuted = case when tm.Validentries=1 then 1 else 0 end                                          
      FROM   Usercampaignexecutionhistory Kd                                      
             INNER JOIN #tempTable Tt                                      
          ON Tt.CampaignID = Kd.CampaignID                                      
             INNER JOIN #tempMobile Tm                                      
                     ON Tm.userID = Tt.userID   and Tm.CampaignID = Tt.CampaignID                                                  --AND Validentries = 1                                      
      WHERE  Jobid=@jobId--Kd.ID = (select MAX(id) from Usercampaignexecutionhistory Kd1 where kd1.CampaignID=kd.CampaignID)      
            
      --select * from UserCampaignExecutionHistory where CampaignID=497 order by id desc                                    
                                      
      ---------------------------------Send Notification mail --------------------   
      if ((select top 1 iseventbased from UserCampaignHistory where JobId=@jobId)=0)  
      begin  
      INSERT INTO Getbatchrecord                                      
                  ([User_id],                                      
                   RandNum)                                      
      SELECT ParentID,                                      
                   CampaignID FROM #tempTable                                      
                                       
       Select BatchID,[User_id] ParentID,RandNum CampaignID into #Batch from Getbatchrecord Gbr                                    Order by gbr.BatchID                         
                                      
      DELETE Kd                                      
      FROM   Getbatchrecord Kd                                      
     Inner join    #Batch B on B.BatchId = Kd.BatchID                                       
                                      
      INSERT INTO Batchemail_infos     
                  (                                      
      -- ID -- this column value is auto-generated                                      
      B.BatchID,                                      
                   UserID,                                      
                   SenderName,                                   
   [Message],                                      
                   TotalRecords,                                      
                   TotalProcessed,                                      
                   ProcessTable,                                      
                   IsProcess,                                      
                   Priority_Level,                                      
                   BatchInsertTime,                                      
             BatchProcessTime,                                      
                   ScheduledDate,                                      
                   ScheduledTime,                                      
                   TemplateID,                                  
                   [Route],                                      
                   PageName,                                      
                   IsScheduled,                                      
                   Email_Subject,                                      
                   ReplyTo,                                      
                   Amount,                                      
                   Currency)                                      
      SELECT B.Batchid,                                      
             335,                                      
             Ucm.NotificationMail,                                      
             case when TM.ValidEntries = 0 then 'Oops, you don''t have sufficient mail credits to run your mail campaign "'      
             + Ucm.CampaignName + '" scheduled for '                                      
             + Cast(Getdate() AS VARCHAR(50))                                      
             + '. Pl refill your credit balance & rerun the campaign ' else        
             'As promised , Your Mail campaign "'      
             /*+ CASE WHEN Ucm.MailReplyTo <> '' THEN 'Mail'                                      
             ELSE                                      
             'SMS'                                      
             END + '*/                                       
             + Ucm.CampaignName + '" scheduled for '                                      
             + Cast(Getdate() AS VARCHAR(50))                                      
             +                                      
' is executed successfully. You can log in to your & check the delivery report in the campaign history' end as  [Message]                                    
       ,                                      
1,                                      
0,                                      
