CREATE   PROCEDURE [dbo].[Usp_insertclonedeliverycampaignmailsCorrected240118] (@jobId bigint)                                   
AS                                    
  BEGIN         
       
      INSERT INTO Getbatchrecord                                    
                  (                                    
      -- BatchID -- this column value is auto-generated                                    
       [User_id],                                    
                   RandNum)                                    
      SELECT DISTINCT Ucerm.ParentID,                                    
                      Ucerm.CampaignID                                    
      FROM   EmailsfiltercampaignexecutionTEST2 AS Ucerm With(nolock)    
                                    
      SELECT     
     ROW_NUMBER() Over(order by CampaignId,ParentId) Id,    
     Ucerm.CampaignID,       
     Ucerm.ParentID                               ,    
                     -- Cast(Ucerm.Messages AS VARCHAR(MAX))  AS  Messages,                                    
                      dbo.Fn_createbatchid(Ucerm.CampaignID, Ucerm.ParentID) AS BatchID,                                  
                     Ucerm.Mail_FromEmail,                                    
                      Ucerm.Mail_UserID AS UserID,    
                      Ucerm.Mail_Subject,    
                      Ucerm.ReplyTo,    
                      Count(*) cnt    
                     -- Ucerm.Mail_ToEmail,                                    
   INTO   #tempTable                                    
      FROM   EmailsfiltercampaignexecutionTEST2 Ucerm                                    
      WHERE  Ucerm.IsCompleted = 1         
      Group by  Ucerm.CampaignID,       
     Ucerm.ParentID , Ucerm.Mail_FromEmail,                                    
                      Ucerm.Mail_UserID,    
                      Ucerm.Mail_Subject,    
                      Ucerm.ReplyTo                                
          
      SELECT A.UserID,a.CampaignID, a.cnt,A.BatchID, SUM(b.cnt) RunningTotal into #TempTableRunningTotal    
   FROM   #tempTable a join    
       #tempTable b on a.UserID=b.userid   
   WHERE b.CampaignID <= a.CampaignID    
   GROUP BY A.UserID, a.CampaignID, a.cnt,A.BatchID    
   ORDER BY a.CampaignID;    
          
          
      DELETE Kd                                    
      FROM   Getbatchrecord Kd                                    
             INNER JOIN #tempTable Tt                                    
                     ON Tt.BatchID = Kd.BatchID                                    
                                  
                                    
      --- Calculate credits                                    
      SELECT B.UserID,     
    B.CampaignID,                                   
             CASE                                    
               WHEN B.Balance > B.Credits THEN 1                                    
               ELSE 0 --test, otherwise 0                                    
             END AS ValidEntries                                    
      INTO   #tempMobile                                    
      FROM   (SELECT A.UserID,      
      A.CampaignID,                                  
                       (A.Credits)   AS Credits,  --Runningtotal                                  
                     A.Balance                                    
              FROM   (SELECT Tt.UserID,                                    
                             TT.RunningTotal AS Credits,    
                             TT.CampaignID,                                    
                            -- Tt.Mail_ToEmail,                              
                             Tt.BatchID,                                    
                             (SELECT TOP 1 Balance                                    
                              FROM   Mailcreditdetails AS Mcd                                    
                              WHERE  Mcd.[User_ID] = Tt.UserID             
                              ORDER  BY Credit_ID DESC)     AS Balance                                    
                      FROM   #TempTableRunningTotal Tt) A                                    
              GROUP  BY A.UserID,                                    
                        A.Balance,A.CampaignID,A.credits) B    
     --select * from #tempmobile    
INSERT INTO Batchemail_infos(BatchID,UserID,SenderName,[Message],TotalRecords,TotalProcessed,ProcessTable,IsProcess,Priority_Level,BatchInsertTime,BatchProcessTime,ScheduledDate,ScheduledTime,TemplateID,[Route],PageName,IsScheduled,Email_Subject,ReplyTo)
                                  
      SELECT A.BatchID,A.UserID,U.Email as SenderName,(select top 1 Cast(e.Messages AS VARCHAR(MAX))     
      from EmailsfiltercampaignexecutionTEST2 e     
      where e.CampaignID=a.campaignid),A.cnt,0,0,0,0,Getdate(),NULL,NULL,NULL,0,0,0,0,A.Mail_Subject,A.ReplyTo     
      FROM #tempTable A (nolock)     
      Inner join #tempMobile TM on Tm.CampaignID = A.CampaignID and TM.UserID = A.UserID     
      join user_detail u (nolock) on u.user_id=a.UserID  and TM.ValidEntries = 1    
         
create table #output (GUID nvarchar(100) collate SQL_Latin1_General_CP1_CI_AS ,Email nvarchar(200) collate SQL_Latin1_General_CP1_CI_AS,Batchid bigint)    

         
      INSERT INTO Clientemails                                    
                  (                    
      -- Id -- this column value is auto-generated                                    
      GUID,                                    
                   Email_Id,                                    
                   SentDateTime,                                    
                   UserId,                                    
                   ReplyTo,                        
                   [Status],                                    
                   BatchID,                                    
                   [Message],
                   campaignid,
                   parentid) 
      OUTPUT inserted.GUID  as GUId,inserted.email_id,inserted.batchid as Email INTO #output                                       
      SELECT Newid(),                                    
             Efce.Mail_ToEmail,                                    
             Getdate(),                                    
             Efce.Mail_UserID,                                    
             Efce.ReplyTo,                                    
             '',                                    
             TT.BatchID,                                    
             Efce.Messages,
             efce.CampaignID,
             efce.ParentID                                    
      FROM   EmailsfiltercampaignexecutionTEST2 AS Efce                                    
             INNER JOIN #tempMobile Tm                                    
      ON Tm.CampaignID = Efce.CampaignID AND ValidEntries = 1   
   inner join #tempTable TT on TT.campaignid=efce.campaignid  
      WHERE  Efce.IsCompleted = 1                                    
                                    
      INSERT INTO Emailsfilter                                   
                  (Mail_GUID,                                    
