    --Code added to update nextexecutiondate in usercampaignhistory Start--      
    select campaignid into #FindCampaignsNextExecution from #tempTable t join UserCampaignMaster ucm on t.CampaignID=ucm.id      
    where ucm.IsActive=1 and ucm.IsSchedule=1 and ucm.IsScheduled=1      
          
 declare @count int =isnull((select COUNT(1) from #FindCampaignsNextExecution),0)      
 if @count>0      
 begin      
    create table #nextexec1(campaignid bigint,nextexecution datetime)                  
    WHILE @Count > 0                      
  BEGIN                      
   DECLARE @Campaignid BIGINT = (                      
       SELECT TOP 1 campaignid                      
        FROM   #FindCampaignsNextExecution                      
      )          
   INSERT INTO #nextexec1                      
       (                      
      campaignid,                      
      nextexecution                      
       )                      
    EXEC Usp_getnextscheduledate                  
       @Campaignid                      
    DELETE                       
    FROM   #FindCampaignsNextExecution                      
    WHERE  campaignid = @Campaignid                      
      
    SET @Count = @Count - 1        
  END      
   update u set NextExecuteDateTime= nextexecution from usercampaignmaster u join #nextexec1 n on n.campaignid=u.id      
   where u.ExpiryDate > nextexecution or u.ExpiryDate is null      
    drop table #nextexec1      
    drop table #FindCampaignsNextExecution    
        
 end      
                       
