           inner join #tempMobileVirtual tmv on tmv.CampaignID=tt.CampaignID                                    
                   INNER JOIN Usercampaignmaster AS Ucm                                      
                           ON Ucm.ID = Tt.CampaignID                                      
                              AND Ucm.ParentID = Tt.ParentID                                   
                              AND Ucm.IsScheduled = 1        
                              Inner join #tempMobile TM on TM.CampaignID = Ucm.ID                                               
                              where tmv.ValidEntries=0  
                     
      drop table #Batch                                      
      end                             
    ---------------------------------Send Notification Mail End ----------------                                       
    DELETE Kd                                      
    FROM   EmailsfiltercampaignexecutionTEST2 Kd                                      
           INNER JOIN #tempTable Tt                                      
                   ON Tt.CampaignID = Kd.CampaignID                                
                                                 
   UPDATE Kd                
   SET    Kd.step3 = 1 ,Step3DateTime=GETDATE() ,                      
   Step3Recipients= Case when ValidEntries = 1 then TT.cnt Else 0 End      
   FROM   usercampaignhistory Kd       
   inner join #tempTable TT on TT.CampaignID = Kd.CampaignID      
   inner join #tempMobile TM on TM.CampaignID = Kd.CampaignID      
   Where Kd.JobId = @jobId      
       
   UPDATE Kd                              
   SET    Kd.step3 = 1 ,Step3DateTime=GETDATE() FROM   usercampaignhistory Kd Where Kd.JobId = @jobId    
        
    --Code added to update nextexecutiondate in usercampaignhistory Start--    
    select campaignid into #FindCampaignsNextExecution from #tempTable t join UserCampaignMaster ucm on t.CampaignID=ucm.id    
    where ucm.IsActive=1 and ucm.IsSchedule=1 and ucm.IsScheduled=1    
        
 declare @count int =isnull((select COUNT(1) from #FindCampaignsNextExecution),0)    
 if @count>0    
 begin    
    create table #nextexec1(campaignid bigint,nextexecution datetime)                
    WHILE @Count > 0                    
  BEGIN                    
   DECLARE @Campaignid BIGINT = (                    
       SELECT TOP 1 campaignid                    
        FROM   #FindCampaignsNextExecution                    
      )        
   INSERT INTO #nextexec1                    
       (                    
      campaignid,                    
      nextexecution                    
       )                    
    EXEC Usp_getnextscheduledate                
       @Campaignid                    
    DELETE                     
    FROM   #FindCampaignsNextExecution                    
    WHERE  campaignid = @Campaignid                    
    
    SET @Count = @Count - 1      
  END    
   update u set NextExecuteDateTime= nextexecution from usercampaignmaster u join #nextexec1 n on n.campaignid=u.id    
   where u.ExpiryDate > nextexecution or u.ExpiryDate is null    
    drop table #nextexec1    
    drop table #FindCampaignsNextExecution  
      
 end    
                     
    --Code added to update nextexecutiondate in usercampaignhistory end--               
    DROP TABLE #tempMobile                                      
    DROP TABLE #tempTable  
    drop table #tempMobileVirtual  
    drop table #tempTableVirtual  
    drop table #Insufficientresellerbalance  
    drop table #TempTableRunningTotal  
    drop table #TempTableRunningTotalVirtual  
    drop table #output   
               
 END


GO

/* ============================================================
   Procedure: [dbo].[Usp_insertclonedeliverycampaignVoice]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--sp_helptext Usp_insertclonedeliverycampaignVoice 2085407                    
CREATE   PROCEDURE [dbo].[Usp_insertclonedeliverycampaignVoice] --2709430 --2549189                               
@jobid bigint    AS                                                    
BEGIN                                                    
        
CREATE TABLE #outputb        
([id]         INT IDENTITY(1, 1),        
 [bid]        BIGINT,        
 [u_id]       BIGINT,        
 [campaignid] BIGINT        
);        
        
BEGIN TRAN;        
INSERT INTO Getbatchrecord([User_id], RandNum)        
OUTPUT inserted.BatchID AS bid, inserted.User_id AS u_id, inserted.RandNum AS campaignid        
INTO #outputb        
SELECT DISTINCT Ucerm.u_id, Ucerm.campaignid FROM usercampaignexecutionrecipientVoice2 Ucerm(NOLOCK) WHERE jobid=@jobid and not exists (select 1 from BatchVoiceInfo (nolock) where jobid=@jobid and campaignid=ucerm.campaignid)      
      
;        
        
DELETE g FROM GetBatchRecord g JOIN #outputb o ON o.bid=g.BatchID;        
        
COMMIT;        
        
SELECT ROW_NUMBER() OVER(        
ORDER BY [ucerm].[CampaignId], [ucerm].[ParentId]) [Id], [Ucerm].[CampaignID], [Ucerm].[ParentID], [o].[bid] AS [BatchID], [Ucerm].[Senderid], [Ucerm].[U_ID] AS [UserID], [ucerm].[isunicode], [dbo].[fn_GetVoiceCreditCalculationScalar]([ucerm].[route],    
 
[ucerm].[U_ID], [ucerm].[duration], COUNT([ucerm].[campaignid])) [cnt], --SUM(isnull(credits,0)) cnt,                                  
COUNT(*) [RCount]        
INTO [#tempTable]        
FROM dbo.usercampaignexecutionrecipientVoice2 Ucerm INNER JOIN #outputb o        
ON o.u_id = ucerm.ParentID        
   AND o.campaignid = ucerm.campaignid        
WHERE [jobid] = @jobid        
  AND [IsCompleted] = 1        
  and not exists (select 1 from BatchVoiceInfo (nolock) where jobid=@jobid and campaignid=ucerm.campaignid)      
GROUP BY [Ucerm].[CampaignID], [Ucerm].[ParentID], [Ucerm].[SenderID], [Ucerm].[U_ID], [Ucerm].[isunicode], [o].[bid], [ucerm].[route], [ucerm].[duration];        
        
--select 'san 1',* from #tempTable                         
--drop table #tempTable                        
--SELECT ROW_NUMBER() Over(order by Ucerm.CampaignId,Ucerm.ParentId) Id,                                     
--Ucerm.CampaignID,                                         
--     Ucerm.ParentID,                                    
--     dbo.Fn_createbatchid(Ucerm.CampaignID, Ucerm.U_ID) AS                                      
--     BatchID,                                                                    
--     Ucerm.Senderid,                                                                            
--     Ucerm.U_ID AS UserID,                                  
--     ucerm.isunicode,                                      
--     SUM(credits) cnt,                                  
--     COUNT(*) RCount                                  
--      INTO   #tempTableVirtual                                                                      
--      FROM   usercampaignexecutionrecipientVoice2 Ucerm                                
--      join user_detail u on u.User_ID=ucerm.U_ID                                         
--      WHERE   HasVirtualCredits=1  and jobid=@jobid                                       
--     Group by  Ucerm.CampaignID, u.ParentSuperResellerId,                                        
--     Ucerm.ParentID , Ucerm.SenderID, Ucerm.U_ID,                                      
--                      Ucerm.isunicode                                  
        
SELECT [A].[UserID], [a].[CampaignID], [a].[cnt], [A].[BatchID], SUM([b].[cnt]) [RunningTotal]        
INTO [#TempTableRunningTotal]        
FROM #tempTable a INNER JOIN #tempTable b        
ON b.CampaignID <= a.CampaignID        
GROUP BY [A].[UserID], [a].[CampaignID], [a].[cnt], [A].[BatchID]        
ORDER BY [a].[CampaignID];        
        
DROP TABLE #outputb;        
        
/*DELETE Kd                                                    
FROM   Getbatchrecord Kd                                                         
INNER JOIN #tempTable Tt               
ON Tt.BatchID = Kd.BatchID  */        
--- Calculate credits                                                                      
        
SELECT [B].[UserID], [B].[CampaignID],        
     CASE        
         WHEN [B].[Balance] >= [B].[Credits]        
         THEN 1        
         ELSE 0        
     END AS [ValidEntries]        
INTO [#tempMobile]        
FROM        
(        
    SELECT [A].[UserID], [A].[CampaignID], ISNULL([A].[Credits], 0) AS [Credits], [A].[Balance]        
    FROM        
    (        
    SELECT [Tt].[UserID], [TT].[RunningTotal] AS [Credits], [TT].[CampaignID], [Tt].[BatchID],        
    (        
    SELECT TOP 1 [Balance]        
    FROM [IntCredit_Details] AS [Mcd]        
    WHERE [Mcd].[User_ID] = [Tt].[UserID]        
    ORDER BY [Credit_ID] DESC        
    ) AS [Balance]        
    FROM #TempTableRunningTotal Tt        
    ) A        
    GROUP BY [A].[UserID], [A].[Balance], [A].[CampaignID], [A].[credits]        
) B;        
        
UPDATE u        
  SET        
  [u].[ReasonIfNotRun] = 'Insuffcient Balance'        
FROM [UserCampaignHistory] [u] INNER JOIN [#tempMobile] [t]        
ON [u].[campaignid] = [t].[CampaignID]        
   AND [u].[jobid] = @jobid        
WHERE [t].[validentries] = 0;      
      
        
SELECT DISTINCT        
   [tt].[batchid], [Ucerm].[mobile], [Ucerm].[message], [Ucerm].[messagestatus], [Ucerm].[senderid], [Ucerm].[messageinsertdate], '' AS [scheduleddate], '' AS [scheduledtime],        
   --U.smppid,                                                    
   [Ucerm].[u_id], [Ucerm].[isunicode], [Ucerm].[isdnd],        
   --Ucerm.isairtel,                                                    
   --Ucerm.mobilesubset,                                                    
   [Ucerm].[validno], case when [tt].[RCount] between 1 and 10 then 2 else 0 end as [isprority], [Ucerm].[isallowdnd], [Ucerm].[dbtype], [tt].[CampaignID], [tt].[RCount], ISNULL([Credits], 0) [Credits],        
   --CASe when tmv.CampaignID is not null then 1 else 0 end as HasVirtualCredits,                                  
   --CASe when tmv.ValidEntries =1 then 1 else 0 end as HasSufficientVirtualCredits,                              
   [appid], [duration], [didno], [route], @jobid [jobid]        
INTO [#clonemessagedeliverystatus]        
FROM usercampaignexecutionrecipientVoice2 Ucerm(NOLOCK) INNER JOIN #temptable Tt        
ON Tt.campaignid = Ucerm.campaignid        
   AND Ucerm.u_id = Tt.userid        
            INNER JOIN #tempmobile Tm        
ON Tm.userid = Tt.userid        
            INNER JOIN user_detail u        
ON u.User_ID = Ucerm.u_id        
--left join #tempMobileVirtual tmv on tmv.CampaignID=tt.CampaignID                        
WHERE [Ucerm].[mobile] <> ''        
  AND [ucerm].[jobid] = @jobid        
  AND [tm].[ValidEntries] = 1;        
        
--select 'clone',* from #clonemessagedeliverystatus                          
--drop table #clonemessagedeliverystatus                     
/*Creating indexes for temp table to improve the performance*/        
        
CREATE NONCLUSTERED INDEX IX_#clonemessagedeliverystatus1        
ON #clonemessagedeliverystatus        
(batchid, mobile, messagestatus, senderid, messageinsertdate        
);        
        
--CREATE NONCLUSTERED INDEX IX_#clonemessagedeliverystatus2 ON #clonemessagedeliverystatus(                                
--smppid,u_id,isunicode,isdnd,isairtel,mobilesubset)                                       
        
CREATE NONCLUSTERED INDEX IX_#clonemessagedeliverystatus3        
ON #clonemessagedeliverystatus        
(validno, isprority, isallowdnd, dbtype, CampaignID, RCount        
);        
        
--CREATE NONCLUSTERED INDEX IX_#clonemessagedeliverystatus4 ON #clonemessagedeliverystatus(                                
--HasVirtualCredits,HasSufficientVirtualCredits )                                
/*End index creation*/        
        
--select t.*,u.email into #Insufficientresellerbalance                               
-- from #tempMobileVirtual t join #tempMobile tt                               
--on t.CampaignID=tt.CampaignID join user_detail u on u.user_id=t.ParentSuperResellerId where tt.ValidEntries=0                               
        
DECLARE @batchcount INT=        
(        
    SELECT COUNT(DISTINCT [batchid])        
    FROM #clonemessagedeliverystatus        
);-- where RCount>5)                         
        
SELECT @batchcount AS [batch];        
        
WHILE @batchcount > 0        
    BEGIN        
    RETRY:        
    BEGIN TRY        
    BEGIN TRAN;        
    DECLARE @batchid BIGINT=        
    (        
   SELECT MIN([batchid])        
    FROM #clonemessagedeliverystatus        
    );-- where RCount>5)                                  
    INSERT INTO Clone_VoiceDeliveryStatus --clonemessagedeliverystatus                                                    
    ([BatchID], [didno], [Mobile], [voiceDuration], [AppId], [IsDnd], [IsPrority], [IsAllowDND], [price], user_id, [VoiceInsertDate], [voice_type], [route], [campaignid], [jobid]        
    )        
       SELECT [batchid], [didno], [Ucerm].[mobile], [duration], [appid], [Ucerm].[isdnd], [IsPrority], [Ucerm].[isallowdnd], [Credits], [Ucerm].[u_id], GETDATE(), [Ucerm].[dbtype], [route], [campaignid], [jobid]        
       FROM #clonemessagedeliverystatus Ucerm        
       WHERE [BatchID] = @batchid;        
    DELETE FROM #clonemessagedeliverystatus        
    WHERE [BatchID] = @batchid;        
    SET @batchcount = @batchcount - 1;        
        
    -- SELECT batchid, didno,Ucerm.mobile,duration,appid,Ucerm.isdnd,IsPrority,Ucerm.isallowdnd,                               
    --        Credits,Ucerm.u_id,GETDATE(),Ucerm.dbtype, route                                                   
    --FROM   #clonemessagedeliverystatus Ucerm where BatchID=@batchid                        
    --delete FROM #clonemessagedeliverystatus where BatchID=@batchid                                  
    --set @batchcount=@batchcount-1                               
    --select 'clone 2'                              
    -- select @@TRANCOUNT                                  
    --IF @@TRANCOUNT>0                                                                        
    COMMIT;        
    END TRY        
    BEGIN CATCH        
    IF @@TRANCOUNT > 0        
    BEGIN        
    ROLLBACK        
    END;        
    EXECUTE USP_INSERTERRORINFO;        
    IF ERROR_NUMBER() = 1205 -- Deadlock Error Number                                  
    BEGIN        
    WAITFOR DELAY '00:00:00.05'; -- Wait for 5 ms                                  
    GOTO RETRY; -- Go to Label RETRY                                  
    END;        
    END CATCH;        
        
    END;        
        
UPDATE Kd        
  SET        
  [Executiontime] = GETDATE(),        
  [Noofrecipients] = [Tt].[RCount],        
  [Batchid] = [Tt].[BatchID],        
  [Isexecuted] = CASE        
     WHEN [tm].[Validentries] = 1        
     THEN 1        
     ELSE 0        
     END        
FROM [Usercampaignexecutionhistory] [Kd] INNER JOIN [#tempTable] [Tt]        
ON [Tt].[CampaignID] = [Kd].[CampaignID]        
         INNER JOIN [#tempMobile] [Tm]        
ON [Tm].[userID] = [Tt].[userID]        
   AND [Tm].[CampaignID] = [Tt].[CampaignID]                                                  --AND Validentries = 1                                                                 
WHERE [Jobid] = @jobId;        
        
IF EXISTS        
(        
    SELECT 1        
    FROM UserCampaignExecutionHistory        
    WHERE [Jobid] = @jobid        
  AND [TemplateSequence] <> 0        
)        
    BEGIN        
    UPDATE ucm        
  SET        
      [TemplateGroupSequence] = CASE        
            WHEN [isending] = 0        
            THEN ISNULL(        
    (        
    SELECT TOP 1 [orderno]        
    FROM [UserGroupTemplateMix]        
    WHERE [OrderNo] = [TemplateSequence] + 1        
      AND [GroupID] = [ucm].[TemplateGroupID]        
    ), 1)        
            ELSE ISNULL(        
    (        
    SELECT TOP 1 [orderno]        
    FROM [UserGroupTemplateMix]        
    WHERE [OrderNo] = [TemplateSequence] + 1        
      AND [GroupID] = [ucm].[TemplateGroupID]        
    ), [templategroupsequence])        
        END        
    FROM [UserCampaignmaster] [ucm] INNER JOIN [usercampaignexecutionhistory] [uceh]        
    ON [uceh].[CampaignID] = [ucm].[ID]        
        INNER JOIN [UserGroupTemplateMix] [ugtm]        
    ON [ugtm].[GroupID] = [ucm].[TemplateGroupID]        
    WHERE [Jobid] = @jobid        
      AND [TemplateSequence] <> 0        
      AND [IsExecuted] = 1;        
END;        
        
---send notification mail------                                    
        
IF(        
(        
    SELECT TOP 1 [iseventbased]        
    FROM UserCampaignHistory        
    WHERE [JobId] = @jobId        
) = 0)        
    BEGIN        
    INSERT INTO Getbatchrecord([User_id], [RandNum])        
   SELECT [ParentID], [CampaignID]        
   FROM #tempTable;        
        
  SELECT [BatchID], [User_id] [ParentID], [RandNum] [CampaignID]        
    INTO [#Batch]        
    FROM Getbatchrecord Gbr        
    ORDER BY [gbr].[BatchID];        
        
    DELETE Kd        
    FROM [Getbatchrecord] [Kd] INNER JOIN [#Batch] [B]        
    ON [B].[BatchId] = [Kd].[BatchID];        
        
    --INSERT INTO Getbatchrecord                                                                      
    --               ([User_id],                                                                      
    --                RandNum)                                                                      
    --   SELECT ParentSuperResellerId,                                                                      
    --                CampaignID FROM #Insufficientresellerbalance         
    SELECT [BatchID], [User_id] [ParentSuperResellerId], [RandNum] [CampaignID]        
    INTO [#Batch1]        
    FROM Getbatchrecord Gbr        
    ORDER BY [gbr].[BatchID];        
        
    DELETE Kd        
    FROM [Getbatchrecord] [Kd] INNER JOIN [#Batch1] [B]        
    ON [B].[BatchId] = [Kd].[BatchID];        
        
    INSERT INTO Batchemail_infos        
    (        
    -- ID -- this column value is auto-generated                                                        
    [B].[BatchID], [UserID], [SenderName], [Message], [TotalRecords], [TotalProcessed], [ProcessTable], [IsProcess], [Priority_Level], [BatchInsertTime], [BatchProcessTime], [ScheduledDate], [ScheduledTime], [TemplateID], [Route], [PageName]  
 , [IsScheduled], [Email_Subject], [ReplyTo], [Amount], [Currency]        
    )        
   SELECT [B].[Batchid], 335, [Ucm].[NotificationMail],        
            CASE        
            WHEN [TM].[ValidEntries] = 0        
            THEN 'Oops, you don''t have sufficient Voice credits to run your Voice campaign "' + [Ucm].[CampaignName] + '" scheduled for ' + CAST(GETDATE() AS VARCHAR(50)) + '. Pl refill your credit balance & rerun the campaign '        
            ELSE 'As promised , Your Voice campaign "' + [Ucm].[CampaignName] + '" scheduled for ' + CAST(GETDATE() AS VARCHAR(50)) + ' is executed successfully. You can log in to your account & check the delivery report in the campaign history'        
            END AS [Message], 1, 0, 0, 0, 1, GETDATE(), GETDATE(), GETDATE(), GETDATE(), 0, 0, 0, 0,        
                              CASE        
                              WHEN [TM].[ValidEntries] = 0        
                              THEN 'Failure: Your campaign "' + +[UCM].[CampaignName] + '" failed due to insufficient credits'        
                              ELSE 'Success : Your campaign "' + [UCM].[CampaignName] + '" executed successfully'        
                              END AS [email_subject], 'noreply@email19.in', 0, 0        
   FROM #temptable Tt INNER JOIN Usercampaignmaster AS Ucm        
   ON Ucm.ID = Tt.CampaignID        
      AND Ucm.IsScheduled = 1        
      AND Ucm.ParentID = Tt.ParentID        
          INNER JOIN #tempMobile TM        
   ON TM.CampaignID = Tt.CampaignID        
          INNER JOIN #Batch B        
   ON B.CampaignId = Tt.CampaignId;        
        
    CREATE TABLE #output        
    ([GUID]    NVARCHAR(100) COLLATE SQL_Latin1_General_CP1_CI_AS,        
     [Email]   NVARCHAR(200) COLLATE SQL_Latin1_General_CP1_CI_AS,        
     [Batchid] BIGINT        
    );        
        
    INSERT INTO Clientemails        
    (        
    -- Id -- this column value is auto-generated                           
    [GUID], [Email_Id], [SentDateTime], [UserId], [ReplyTo], [Status], [BatchID], [Message]        
    )        
    OUTPUT [inserted].[GUID], [inserted].[Email_Id], [inserted].[BatchID]        
   INTO #output        
   SELECT NEWID(), [Ucm].[NotificationMail], GETDATE(), 335, 'noreply@email19.in', '', [B].[Batchid],        
                       CASE        
                       WHEN [TM].[ValidEntries] = 0        
                       THEN 'Oops, you don''t have sufficient Voice credits to run your Voice campaign "' + [Ucm].[CampaignName] + '" scheduled for ' + CAST(GETDATE() AS VARCHAR(50)) + '. Pl refill your credit balance & rerun the campaign '        
                       ELSE 'As promised , Your Voice campaign "' + [Ucm].[CampaignName] + '" scheduled for ' + CAST(GETDATE() AS VARCHAR(50)) + ' is executed successfully. You can log in to your account & check the delivery report in the campaign histor
  
y    
      
'        
                       END AS [Message]        
   FROM #tempTable Tt INNER JOIN Usercampaignmaster AS Ucm        
   ON Ucm.ID = Tt.CampaignID        
      AND Ucm.IsScheduled = 1        
      AND Ucm.ParentID = Tt.ParentID        
          INNER JOIN #tempMobile TM        
   ON TM.CampaignID = Ucm.ID        
          INNER JOIN #Batch B        
   ON B.CampaignId = Tt.CampaignId;        
        
    INSERT INTO Emailsfilter        
    ([Mail_GUID],        
    -- Mail_ID -- this column value is auto-generated                                                        
    [Mail_FromEmail], [Mail_ToEmail], [Mail_Subject], [Mail_TempleteName], [Messages], [Mail_InsertedDate], [Mail_UserID], [ReplyTo], [Mail_BatchID], [Mail_Priority], [Mail_ScheduleDate], [Mail_Attechement], [Mail_TempleteBody], [IsMonitor]        
    )        
   SELECT [o].[guid], 'contactus@email19.in', [UCM].[NotificationMail],        
                CASE        
                WHEN [TM].[ValidEntries] = 0        
                THEN 'Failure: Your campaign "' + +[UCM].[CampaignName] + '" failed due to insufficient credits'        
                ELSE 'Success : Your campaign "' + [UCM].[CampaignName] + '" executed successfully'        
                END AS [Mail_subject], '',        
                   CASE        
                   WHEN [TM].[ValidEntries] = 0        
                   THEN 'Oops, you don''t have sufficient Voice credits to run your Voice campaign "' + [UCM].[CampaignName] + '" scheduled for ' + CAST(GETDATE() AS VARCHAR(50)) + '. Pl refill your credit balance & rerun the campaign '        
                   ELSE 'As promised , Your Voice campaign "' + [UCM].[CampaignName] + '" scheduled for ' + CAST(GETDATE() AS VARCHAR(50)) + ' is executed successfully. You can log in to your account & check the delivery report in the campaign history'   
  
    
     
                   END AS [Messages], GETDATE(), 335, 'noreply@email19.in', [B].[Batchid], 1, GETDATE(), 0,        
                                     CASE        
                                     WHEN [TM].[ValidEntries] = 0        
                                     THEN 'Oops, you don''t have sufficient Voice credits to run your Voice campaign "' + [UCM].[CampaignName] + '" scheduled for ' + CAST(GETDATE() AS VARCHAR(50)) + '. Pl refill your credit balance & rerun the campaign ' 
  
    
     
        
                                     ELSE 'As promised , Your Voice campaign "' + [UCM].[CampaignName] + '" scheduled for ' + CAST(GETDATE() AS VARCHAR(50)) + ' is executed successfully. You can log in to your account & check the delivery report in the ca
  
    
      
mpaign history'        
                                     END AS [mail_templetebody], 1        
   FROM #tempTable Tt INNER JOIN Usercampaignmaster AS Ucm        
   ON Ucm.ID = Tt.CampaignID        
      AND Ucm.IsScheduled = 1        
      AND Ucm.ParentID = Tt.ParentID        
          INNER JOIN #tempMobile TM        
   ON TM.CampaignID = Ucm.ID        
          INNER JOIN #Batch B        
   ON B.CampaignId = Tt.CampaignId        
          INNER JOIN #output o        
   ON o.Email = ucm.NotificationMail      
   WHERE [o].[Batchid] = [b].[BatchID];        
        
    INSERT INTO Mailcreditdetails        
    ([ID],        
    -- Credit_ID -- this column value is auto-generated                                                        
    [M_ID], [FromUser_ID], [User_ID], [Debits], [Credits], [Balance], [Validity], [Default_Credit], [FromDate], [ToDate], [DateCreated], [DateUpdated], [EmpUpdated], [MachineName], [LastModified], [typecredit]        
    )        
   SELECT NEWID(), 10001, 335, 335, COUNT(*), 0,        
   (        
       SELECT TOP 1 [Mcd].[Balance]        
       FROM [Mailcreditdetails] AS [Mcd]        
       WHERE [Mcd].[User_ID] = 335        
       ORDER BY [Mcd].[Credit_ID] DESC        
   ) - COUNT(*), 99999, 0, GETDATE(), GETDATE(), GETDATE(), GETDATE(), 'Campaign Exec', '', GETDATE(), 0        
   FROM #tempTable Tt INNER JOIN Usercampaignmaster AS Ucm        
 ON Ucm.ID = Tt.CampaignID        
      AND Ucm.ParentID = Tt.ParentID        
      AND Ucm.IsScheduled = 1        
          INNER JOIN #tempMobile TM        
   ON TM.CampaignID = Ucm.ID;        
        
    DROP TABLE #Batch;        
    DROP TABLE #Batch1;        
    DROP TABLE #output;        
END;        
---------------------------------Send Notification Mail End ----------------                   
        
DECLARE @tbdeleted BIGINT=        
(        
    SELECT COUNT(1)        
    FROM usercampaignexecutionrecipientVoice2 Kd(NOLOCK) INNER JOIN #temptable Tt        
    ON Tt.campaignid = Kd.campaignid        
    WHERE [Kd].[iscompleted] = 1        
  AND [kd].[jobid] = @jobid        
);        
        
WHILE @tbdeleted > 0        
    BEGIN        
    DELETE TOP (1000)        
    Kd        
    FROM [usercampaignexecutionrecipientVoice2] [Kd](NOLOCK) INNER JOIN [#temptable] [Tt]        
    ON [Tt].[campaignid] = [Kd].[campaignid]        
    WHERE [Kd].[iscompleted] = 1        
      AND [kd].[jobid] = @jobid;        
    SET @tbdeleted = @tbdeleted - 1000;        
    END;        
        
UPDATE Kd        
  SET        
  [Kd].[step3] = 1,        
  [Step3DateTime] = GETDATE(),        
  [Step3Recipients] = CASE        
      WHEN [ValidEntries] = 1        
      THEN [TT].[RCount]        
      ELSE 0        
      END        
FROM [usercampaignhistory] [Kd] INNER JOIN [#tempTable] [TT]        
ON [TT].[CampaignID] = [Kd].[CampaignID]        
        INNER JOIN [#tempMobile] [TM]        
ON [TM].[CampaignID] = [Kd].[CampaignID]        
WHERE [Kd].[JobId] = @jobId;        
        
UPDATE Kd        
  SET        
  [Kd].[step3] = 1,        
  [Step3DateTime] = GETDATE()        
FROM [usercampaignhistory] [Kd]        
WHERE [Kd].[JobId] = @jobId;        
        
UPDATE u        
  SET        
  [executeddatetime] = GETDATE()        
FROM [usercampaignmaster] [u] JOIN [usercampaignhistory] [Kd]        
ON [kd].[campaignid] = [u].[id]        
   AND [Kd].[JobId] = @jobId;        
--Code added to update nextexecutiondate in usercampaignhistory Start--                      
        
SELECT [campaignid]        
INTO [#FindCampaignsNextExecution]        
FROM #tempTable t INNER JOIN UserCampaignMaster ucm        
ON t.CampaignID = ucm.id        
      LEFT JOIN userschedules us        
ON us.id = ucm.scheduleid        
WHERE [ucm].[IsActive] = 1        
  AND [ucm].[IsSchedule] = 1        
  AND [ucm].[IsScheduled] = 1        
  AND [us].[isonce] = 0;        
        
DECLARE @count INT= ISNULL(        
(        
    SELECT COUNT(1)        
    FROM #FindCampaignsNextExecution        
), 0);        
        
IF @count > 0        
    BEGIN        
    CREATE TABLE #nextexec1        
    ([campaignid]    BIGINT,        
     [nextexecution] DATETIME        
    );        
    WHILE @Count > 0        
    BEGIN        
    DECLARE @Campaignid BIGINT=        
    (        
    SELECT TOP 1 [campaignid]        
    FROM #FindCampaignsNextExecution        
    );        
    INSERT INTO #nextexec1([campaignid], [nextexecution])        
    EXEC Usp_getnextscheduledate        
     @Campaignid;        
    DELETE FROM #FindCampaignsNextExecution        
    WHERE [campaignid] = @Campaignid;        
        
    SET @Count = @Count - 1;        
END;        
    UPDATE u        
  SET        
      [NextExecuteDateTime] = [nextexecution]        
    FROM [usercampaignmaster] [u] INNER JOIN [#nextexec1] [n]        
    ON [n].[campaignid] = [u].[id]        
    WHERE [u].[ExpiryDate] > [nextexecution]        
      OR [u].[ExpiryDate] IS NULL;        
    DROP TABLE #nextexec1;        
    DROP TABLE #FindCampaignsNextExecution;        
END;        
        
DROP TABLE #tempmobile;        
        
DROP TABLE #temptable;        
        
DROP TABLE #TempTableRunningTotal;        
        
DROP TABLE #clonemessagedeliverystatus;        
        
IF EXISTS        
(        
    SELECT 1        
    FROM UserCampaignHistory        
    WHERE [JobId] = @jobId        
  AND [IsEventBased] = 0        
  AND [isSMS] = 2        
)        
    BEGIN        
    UPDATE usercampaignexecution        
  SET        
      [CampaignEnddatetime] = GETDATE(),        
      [isrunning] = 0        
    WHERE [isevent] = 0        
      AND [isSMS] = 2;        
END;        
        
IF EXISTS        
(        
    SELECT 1        
    FROM UserCampaignHistory        
    WHERE [JobId] = @jobId        
  AND [IsEventBased] = 1        
  AND [isSMS] = 2        
)        
    BEGIN        
    UPDATE usercampaignexecution        
  SET        
      [CampaignEnddatetime] = GETDATE(),        
      [isrunning] = 0        
    WHERE [isevent] = 1        
      AND [isSMS] = 2;        
       
END;                                                             
end 


GO

/* ============================================================
   Procedure: [dbo].[Usp_insertclonedeliverycampaignVoice_withid]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--sp_helptext Usp_insertclonedeliverycampaignVoice 2085407                  
CREATE   PROCEDURE [dbo].[Usp_insertclonedeliverycampaignVoice_withid] --2709430 --2549189                             
@jobid bigint    AS                                                  
BEGIN                                                  
      
CREATE TABLE #outputb      
([id]         INT IDENTITY(1, 1),      
 [bid]        BIGINT,      
 [u_id]       BIGINT,      
 [campaignid] BIGINT      
);      
      
BEGIN TRAN;      
INSERT INTO Getbatchrecord([User_id], RandNum)      
OUTPUT inserted.BatchID AS bid, inserted.User_id AS u_id, inserted.RandNum AS campaignid      
INTO #outputb      
SELECT DISTINCT Ucerm.u_id, Ucerm.campaignid FROM usercampaignexecutionrecipientVoice2 Ucerm(NOLOCK) WHERE jobid=@jobid and not exists (select 1 from BatchVoiceInfo (nolock) where jobid=@jobid and campaignid=ucerm.campaignid)    
    
;      
      
DELETE g FROM GetBatchRecord g JOIN #outputb o ON o.bid=g.BatchID;      
      
COMMIT;      
      
SELECT ROW_NUMBER() OVER(      
ORDER BY [ucerm].[CampaignId], [ucerm].[ParentId]) [Id], [Ucerm].[CampaignID], [Ucerm].[ParentID], [o].[bid] AS [BatchID], [Ucerm].[Senderid], [Ucerm].[U_ID] AS [UserID], [ucerm].[isunicode], [dbo].[fn_GetVoiceCreditCalculationScalar]([ucerm].[route],   
[ucerm].[U_ID], [ucerm].[duration], COUNT([ucerm].[campaignid])) [cnt], --SUM(isnull(credits,0)) cnt,                                
COUNT(*) [RCount]      
INTO [#tempTable]      
FROM dbo.usercampaignexecutionrecipientVoice2 Ucerm INNER JOIN #outputb o      
ON o.u_id = ucerm.ParentID      
   AND o.campaignid = ucerm.campaignid      
WHERE [jobid] = @jobid      
  AND [IsCompleted] = 1      
  and not exists (select 1 from BatchVoiceInfo (nolock) where jobid=@jobid and campaignid=ucerm.campaignid)    
GROUP BY [Ucerm].[CampaignID], [Ucerm].[ParentID], [Ucerm].[SenderID], [Ucerm].[U_ID], [Ucerm].[isunicode], [o].[bid], [ucerm].[route], [ucerm].[duration];      
      
--select 'san 1',* from #tempTable                       
--drop table #tempTable                      
--SELECT ROW_NUMBER() Over(order by Ucerm.CampaignId,Ucerm.ParentId) Id,                                   
--Ucerm.CampaignID,                                       
--     Ucerm.ParentID,                                  
--     dbo.Fn_createbatchid(Ucerm.CampaignID, Ucerm.U_ID) AS                                    
--     BatchID,                                                                  
--     Ucerm.Senderid,                                                                          
--     Ucerm.U_ID AS UserID,                                
--     ucerm.isunicode,                                    
--     SUM(credits) cnt,                                
--     COUNT(*) RCount                                
--      INTO   #tempTableVirtual                                                                    
--      FROM   usercampaignexecutionrecipientVoice2 Ucerm                              
--      join user_detail u on u.User_ID=ucerm.U_ID                                       
--      WHERE   HasVirtualCredits=1  and jobid=@jobid                                     
--     Group by  Ucerm.CampaignID, u.ParentSuperResellerId,                                      
--     Ucerm.ParentID , Ucerm.SenderID, Ucerm.U_ID,                                    
--                      Ucerm.isunicode                                
      
SELECT [A].[UserID], [a].[CampaignID], [a].[cnt], [A].[BatchID], SUM([b].[cnt]) [RunningTotal]      
INTO [#TempTableRunningTotal]      
FROM #tempTable a INNER JOIN #tempTable b      
ON b.CampaignID <= a.CampaignID      
GROUP BY [A].[UserID], [a].[CampaignID], [a].[cnt], [A].[BatchID]      
ORDER BY [a].[CampaignID];      
      
DROP TABLE #outputb;      
      
/*DELETE Kd                                                  
FROM   Getbatchrecord Kd                                                                    
INNER JOIN #tempTable Tt             
ON Tt.BatchID = Kd.BatchID  */      
--- Calculate credits                                                                    
      
SELECT [B].[UserID], [B].[CampaignID],      
     CASE      
         WHEN [B].[Balance] >= [B].[Credits]      
         THEN 1      
         ELSE 0      
     END AS [ValidEntries]      
INTO [#tempMobile]      
FROM      
(      
    SELECT [A].[UserID], [A].[CampaignID], ISNULL([A].[Credits], 0) AS [Credits], [A].[Balance]      
    FROM      
    (      
    SELECT [Tt].[UserID], [TT].[RunningTotal] AS [Credits], [TT].[CampaignID], [Tt].[BatchID],      
    (      
    SELECT TOP 1 [Balance]      
    FROM [IntCredit_Details] AS [Mcd]      
    WHERE [Mcd].[User_ID] = [Tt].[UserID]      
    ORDER BY [Credit_ID] DESC      
    ) AS [Balance]      
    FROM #TempTableRunningTotal Tt      
    ) A      
    GROUP BY [A].[UserID], [A].[Balance], [A].[CampaignID], [A].[credits]      
) B;      
      
UPDATE u      
  SET      
  [u].[ReasonIfNotRun] = 'Insuffcient Balance'      
FROM [UserCampaignHistory] [u] INNER JOIN [#tempMobile] [t]      
ON [u].[campaignid] = [t].[CampaignID]      
   AND [u].[jobid] = @jobid      
WHERE [t].[validentries] = 0;    
    
      
SELECT DISTINCT entityname,entityid,     
   [tt].[batchid], [Ucerm].[mobile], [Ucerm].[message], [Ucerm].[messagestatus], [Ucerm].[senderid], [Ucerm].[messageinsertdate], '' AS [scheduleddate], '' AS [scheduledtime],      
   --U.smppid,                                                  
   [Ucerm].[u_id], [Ucerm].[isunicode], [Ucerm].[isdnd],      
   --Ucerm.isairtel,                                                  
   --Ucerm.mobilesubset,                                                  
   [Ucerm].[validno], case when [tt].[RCount] between 1 and 10 then 1 else 0 end as [isprority], [Ucerm].[isallowdnd], [Ucerm].[dbtype], [tt].[CampaignID], [tt].[RCount], ISNULL([Credits], 0) [Credits],      
   --CASe when tmv.CampaignID is not null then 1 else 0 end as HasVirtualCredits,                                
   --CASe when tmv.ValidEntries =1 then 1 else 0 end as HasSufficientVirtualCredits,                            
   [appid], [duration], [didno], [route], @jobid [jobid]      
INTO [#clonemessagedeliverystatus]      
FROM usercampaignexecutionrecipientVoice2 Ucerm(NOLOCK) INNER JOIN #temptable Tt      
ON Tt.campaignid = Ucerm.campaignid      
   AND Ucerm.u_id = Tt.userid      
            INNER JOIN #tempmobile Tm      
ON Tm.userid = Tt.userid      
            INNER JOIN user_detail u      
ON u.User_ID = Ucerm.u_id      
--left join #tempMobileVirtual tmv on tmv.CampaignID=tt.CampaignID                      
WHERE [Ucerm].[mobile] <> ''      
  AND [ucerm].[jobid] = @jobid      
  AND [tm].[ValidEntries] = 1;      
      
--select 'clone',* from #clonemessagedeliverystatus                        
--drop table #clonemessagedeliverystatus                   
/*Creating indexes for temp table to improve the performance*/      
      
CREATE NONCLUSTERED INDEX IX_#clonemessagedeliverystatus1      
ON #clonemessagedeliverystatus      
(batchid, mobile, messagestatus, senderid, messageinsertdate      
);      
      
--CREATE NONCLUSTERED INDEX IX_#clonemessagedeliverystatus2 ON #clonemessagedeliverystatus(                              
--smppid,u_id,isunicode,isdnd,isairtel,mobilesubset)                                     
      
CREATE NONCLUSTERED INDEX IX_#clonemessagedeliverystatus3      
ON #clonemessagedeliverystatus      
(validno, isprority, isallowdnd, dbtype, CampaignID, RCount      
);      

CREATE TABLE #tbl_activity(
	[LeadID] [bigint] NULL,
	[UserID] [bigint] NULL,
	[ParentID] [bigint] NULL,
	[EventDescription] [nvarchar](max) NULL,
	[EventName] [nvarchar](500) NULL
)
insert into #tbl_activity( LeadID , UserID, ParentID , EventDescription , EventName)           
select entityid,m.u_id,u.ParentID, cast(u.user_login as nvarchar) +'sent an automated call with ivr '+i.appname+ ' and did no. '++' to mobile '+cast(m.mobile as nvarchar) +' through automated campaign named '
 + c.CampaignName,'Voice sent to lead'
 from user_detail u join #clonemessagedeliverystatus m on m.u_id=u.User_ID
  join UserCampaignMaster c on c.ID=m.CampaignID
  join cloud_app_master i on i.appid=m.appid
 where entityname='Lead' and isnull(entityid,0)<>0         

exec UspSaveLeadActivity_withMultipleValue #tbl_activity

drop table #tbl_activity 

      
--CREATE NONCLUSTERED INDEX IX_#clonemessagedeliverystatus4 ON #clonemessagedeliverystatus(                              
--HasVirtualCredits,HasSufficientVirtualCredits )                              
/*End index creation*/      
      
--select t.*,u.email into #Insufficientresellerbalance                             
-- from #tempMobileVirtual t join #tempMobile tt                             
--on t.CampaignID=tt.CampaignID join user_detail u on u.user_id=t.ParentSuperResellerId where tt.ValidEntries=0                             
      
DECLARE @batchcount INT=      
(      
    SELECT COUNT(DISTINCT [batchid])      
    FROM #clonemessagedeliverystatus      
);-- where RCount>5)                       
      
SELECT @batchcount AS [batch];      
      
WHILE @batchcount > 0      
    BEGIN      
    RETRY:      
    BEGIN TRY      
    BEGIN TRAN;      
    DECLARE @batchid BIGINT=      
    (      
   SELECT MIN([batchid])      
    FROM #clonemessagedeliverystatus      
    );-- where RCount>5)                                
    INSERT INTO Clone_VoiceDeliveryStatus --clonemessagedeliverystatus                                                  
    ([BatchID], [didno], [Mobile], [voiceDuration], [AppId], [IsDnd], [IsPrority], [IsAllowDND], [price], user_id, [VoiceInsertDate], [voice_type], [route], [campaignid], [jobid]      
    )      
       SELECT [batchid], [didno], [Ucerm].[mobile], [duration], [appid], [Ucerm].[isdnd], [IsPrority], [Ucerm].[isallowdnd], [Credits], [Ucerm].[u_id], GETDATE(), [Ucerm].[dbtype], [route], [campaignid], [jobid]      
       FROM #clonemessagedeliverystatus Ucerm      
       WHERE [BatchID] = @batchid;      
    DELETE FROM #clonemessagedeliverystatus      
    WHERE [BatchID] = @batchid;      
    SET @batchcount = @batchcount - 1;      
      
    -- SELECT batchid, didno,Ucerm.mobile,duration,appid,Ucerm.isdnd,IsPrority,Ucerm.isallowdnd,                             
    --        Credits,Ucerm.u_id,GETDATE(),Ucerm.dbtype, route                                                 
    --FROM   #clonemessagedeliverystatus Ucerm where BatchID=@batchid                      
    --delete FROM #clonemessagedeliverystatus where BatchID=@batchid                                
    --set @batchcount=@batchcount-1                             
    --select 'clone 2'                            
    -- select @@TRANCOUNT                                
    --IF @@TRANCOUNT>0                                                                      
    COMMIT;      
    END TRY      
    BEGIN CATCH      
    IF @@TRANCOUNT > 0      
    BEGIN      
    ROLLBACK      
    END;      
    EXECUTE USP_INSERTERRORINFO;      
    IF ERROR_NUMBER() = 1205 -- Deadlock Error Number                                
    BEGIN      
    WAITFOR DELAY '00:00:00.05'; -- Wait for 5 ms                                
    GOTO RETRY; -- Go to Label RETRY                                
    END;      
    END CATCH;      
      
    END;      
      
UPDATE Kd      
  SET      
  [Executiontime] = GETDATE(),      
  [Noofrecipients] = [Tt].[RCount],      
  [Batchid] = [Tt].[BatchID],      
  [Isexecuted] = CASE      
     WHEN [tm].[Validentries] = 1      
     THEN 1      
     ELSE 0      
     END      
FROM [Usercampaignexecutionhistory] [Kd] INNER JOIN [#tempTable] [Tt]      
ON [Tt].[CampaignID] = [Kd].[CampaignID]      
         INNER JOIN [#tempMobile] [Tm]      
ON [Tm].[userID] = [Tt].[userID]      
   AND [Tm].[CampaignID] = [Tt].[CampaignID]                                                  --AND Validentries = 1                                                               
WHERE [Jobid] = @jobId;      
      
IF EXISTS      
(      
    SELECT 1      
    FROM UserCampaignExecutionHistory      
    WHERE [Jobid] = @jobid      
  AND [TemplateSequence] <> 0      
)      
    BEGIN      
    UPDATE ucm      
  SET      
      [TemplateGroupSequence] = CASE      
            WHEN [isending] = 0      
            THEN ISNULL(      
    (      
    SELECT TOP 1 [orderno]      
    FROM [UserGroupTemplateMix]      
    WHERE [OrderNo] = [TemplateSequence] + 1      
      AND [GroupID] = [ucm].[TemplateGroupID]      
    ), 1)      
            ELSE ISNULL(      
    (      
    SELECT TOP 1 [orderno]      
    FROM [UserGroupTemplateMix]      
    WHERE [OrderNo] = [TemplateSequence] + 1      
      AND [GroupID] = [ucm].[TemplateGroupID]      
    ), [templategroupsequence])      
        END      
    FROM [UserCampaignmaster] [ucm] INNER JOIN [usercampaignexecutionhistory] [uceh]      
    ON [uceh].[CampaignID] = [ucm].[ID]      
        INNER JOIN [UserGroupTemplateMix] [ugtm]      
    ON [ugtm].[GroupID] = [ucm].[TemplateGroupID]      
    WHERE [Jobid] = @jobid      
      AND [TemplateSequence] <> 0      
      AND [IsExecuted] = 1;      
END;      
      
---send notification mail------                                  
      
IF(      
(      
    SELECT TOP 1 [iseventbased]      
    FROM UserCampaignHistory      
    WHERE [JobId] = @jobId      
) = 0)      
    BEGIN      
    INSERT INTO Getbatchrecord([User_id], [RandNum])      
   SELECT [ParentID], [CampaignID]      
   FROM #tempTable;      
      
  SELECT [BatchID], [User_id] [ParentID], [RandNum] [CampaignID]      
    INTO [#Batch]      
    FROM Getbatchrecord Gbr      
    ORDER BY [gbr].[BatchID];      
      
    DELETE Kd      
    FROM [Getbatchrecord] [Kd] INNER JOIN [#Batch] [B]      
    ON [B].[BatchId] = [Kd].[BatchID];      
      
    --INSERT INTO Getbatchrecord                                                                    
    --               ([User_id],                                                                    
    --                RandNum)                                                                    
    --   SELECT ParentSuperResellerId,                                                                    
    --                CampaignID FROM #Insufficientresellerbalance       
    SELECT [BatchID], [User_id] [ParentSuperResellerId], [RandNum] [CampaignID]      
    INTO [#Batch1]      
    FROM Getbatchrecord Gbr      
    ORDER BY [gbr].[BatchID];      
      
    DELETE Kd      
    FROM [Getbatchrecord] [Kd] INNER JOIN [#Batch1] [B]      
    ON [B].[BatchId] = [Kd].[BatchID];      
      
    INSERT INTO Batchemail_infos      
    (      
    -- ID -- this column value is auto-generated                                                      
    [B].[BatchID], [UserID], [SenderName], [Message], [TotalRecords], [TotalProcessed], [ProcessTable], [IsProcess], [Priority_Level], [BatchInsertTime], [BatchProcessTime], [ScheduledDate], [ScheduledTime], [TemplateID], [Route], [PageName], [IsSchedule
d  
], [Email_Subject], [ReplyTo], [Amount], [Currency]      
    )      
   SELECT [B].[Batchid], 335, [Ucm].[NotificationMail],      
            CASE      
            WHEN [TM].[ValidEntries] = 0      
            THEN 'Oops, you don''t have sufficient Voice credits to run your Voice campaign "' + [Ucm].[CampaignName] + '" scheduled for ' + CAST(GETDATE() AS VARCHAR(50)) + '. Pl refill your credit balance & rerun the campaign '      
            ELSE 'As promised , Your Voice campaign "' + [Ucm].[CampaignName] + '" scheduled for ' + CAST(GETDATE() AS VARCHAR(50)) + ' is executed successfully. You can log in to your account & check the delivery report in the campaign history'      
            END AS [Message], 1, 0, 0, 0, 1, GETDATE(), GETDATE(), GETDATE(), GETDATE(), 0, 0, 0, 0,      
                              CASE      
                              WHEN [TM].[ValidEntries] = 0      
                              THEN 'Failure: Your campaign "' + +[UCM].[CampaignName] + '" failed due to insufficient credits'      
                              ELSE 'Success : Your campaign "' + [UCM].[CampaignName] + '" executed successfully'      
                              END AS [email_subject], 'noreply@email19.in', 0, 0      
   FROM #temptable Tt INNER JOIN Usercampaignmaster AS Ucm      
   ON Ucm.ID = Tt.CampaignID      
      AND Ucm.IsScheduled = 1      
      AND Ucm.ParentID = Tt.ParentID      
          INNER JOIN #tempMobile TM      
   ON TM.CampaignID = Tt.CampaignID      
          INNER JOIN #Batch B      
   ON B.CampaignId = Tt.CampaignId;      
      
    CREATE TABLE #output      
    ([GUID]    NVARCHAR(100) COLLATE SQL_Latin1_General_CP1_CI_AS,      
     [Email]   NVARCHAR(200) COLLATE SQL_Latin1_General_CP1_CI_AS,      
     [Batchid] BIGINT      
    );      
      
    INSERT INTO Clientemails      
    (      
    -- Id -- this column value is auto-generated                         
    [GUID], [Email_Id], [SentDateTime], [UserId], [ReplyTo], [Status], [BatchID], [Message]      
    )      
    OUTPUT [inserted].[GUID], [inserted].[Email_Id], [inserted].[BatchID]      
   INTO #output      
   SELECT NEWID(), [Ucm].[NotificationMail], GETDATE(), 335, 'noreply@email19.in', '', [B].[Batchid],      
                       CASE      
                       WHEN [TM].[ValidEntries] = 0      
                       THEN 'Oops, you don''t have sufficient Voice credits to run your Voice campaign "' + [Ucm].[CampaignName] + '" scheduled for ' + CAST(GETDATE() AS VARCHAR(50)) + '. Pl refill your credit balance & rerun the campaign '      
                       ELSE 'As promised , Your Voice campaign "' + [Ucm].[CampaignName] + '" scheduled for ' + CAST(GETDATE() AS VARCHAR(50)) + ' is executed successfully. You can log in to your account & check the delivery report in the campaign histor
y  
    
'      
                       END AS [Message]      
   FROM #tempTable Tt INNER JOIN Usercampaignmaster AS Ucm      
   ON Ucm.ID = Tt.CampaignID      
      AND Ucm.IsScheduled = 1      
      AND Ucm.ParentID = Tt.ParentID      
          INNER JOIN #tempMobile TM      
   ON TM.CampaignID = Ucm.ID      
          INNER JOIN #Batch B      
   ON B.CampaignId = Tt.CampaignId;      
      
    INSERT INTO Emailsfilter      
    ([Mail_GUID],      
    -- Mail_ID -- this column value is auto-generated                                                      
    [Mail_FromEmail], [Mail_ToEmail], [Mail_Subject], [Mail_TempleteName], [Messages], [Mail_InsertedDate], [Mail_UserID], [ReplyTo], [Mail_BatchID], [Mail_Priority], [Mail_ScheduleDate], [Mail_Attechement], [Mail_TempleteBody], [IsMonitor]      
    )      
   SELECT [o].[guid], 'contactus@email19.in', [UCM].[NotificationMail],      
                CASE      
                WHEN [TM].[ValidEntries] = 0      
                THEN 'Failure: Your campaign "' + +[UCM].[CampaignName] + '" failed due to insufficient credits'      
                ELSE 'Success : Your campaign "' + [UCM].[CampaignName] + '" executed successfully'      
                END AS [Mail_subject], '',      
                   CASE      
                   WHEN [TM].[ValidEntries] = 0      
                   THEN 'Oops, you don''t have sufficient Voice credits to run your Voice campaign "' + [UCM].[CampaignName] + '" scheduled for ' + CAST(GETDATE() AS VARCHAR(50)) + '. Pl refill your credit balance & rerun the campaign '      
                   ELSE 'As promised , Your Voice campaign "' + [UCM].[CampaignName] + '" scheduled for ' + CAST(GETDATE() AS VARCHAR(50)) + ' is executed successfully. You can log in to your account & check the delivery report in the campaign history'   
  
   
                   END AS [Messages], GETDATE(), 335, 'noreply@email19.in', [B].[Batchid], 1, GETDATE(), 0,      
                                     CASE      
                                     WHEN [TM].[ValidEntries] = 0      
                                     THEN 'Oops, you don''t have sufficient Voice credits to run your Voice campaign "' + [UCM].[CampaignName] + '" scheduled for ' + CAST(GETDATE() AS VARCHAR(50)) + '. Pl refill your credit balance & rerun the campaign ' 
  
   
      
                                     ELSE 'As promised , Your Voice campaign "' + [UCM].[CampaignName] + '" scheduled for ' + CAST(GETDATE() AS VARCHAR(50)) + ' is executed successfully. You can log in to your account & check the delivery report in the ca
  
    
mpaign history'      
                                     END AS [mail_templetebody], 1      
   FROM #tempTable Tt INNER JOIN Usercampaignmaster AS Ucm      
   ON Ucm.ID = Tt.CampaignID      
      AND Ucm.IsScheduled = 1      
      AND Ucm.ParentID = Tt.ParentID      
          INNER JOIN #tempMobile TM      
   ON TM.CampaignID = Ucm.ID      
          INNER JOIN #Batch B      
   ON B.CampaignId = Tt.CampaignId      
          INNER JOIN #output o      
   ON o.Email = ucm.NotificationMail    
   WHERE [o].[Batchid] = [b].[BatchID];      
      
    INSERT INTO Mailcreditdetails      
    ([ID],      
    -- Credit_ID -- this column value is auto-generated                                                      
    [M_ID], [FromUser_ID], [User_ID], [Debits], [Credits], [Balance], [Validity], [Default_Credit], [FromDate], [ToDate], [DateCreated], [DateUpdated], [EmpUpdated], [MachineName], [LastModified], [typecredit]      
    )      
   SELECT NEWID(), 10001, 335, 335, COUNT(*), 0,      
   (      
       SELECT TOP 1 [Mcd].[Balance]      
       FROM [Mailcreditdetails] AS [Mcd]      
       WHERE [Mcd].[User_ID] = 335      
       ORDER BY [Mcd].[Credit_ID] DESC      
   ) - COUNT(*), 99999, 0, GETDATE(), GETDATE(), GETDATE(), GETDATE(), 'Campaign Exec', '', GETDATE(), 0      
   FROM #tempTable Tt INNER JOIN Usercampaignmaster AS Ucm      
 ON Ucm.ID = Tt.CampaignID      
      AND Ucm.ParentID = Tt.ParentID      
      AND Ucm.IsScheduled = 1      
          INNER JOIN #tempMobile TM      
   ON TM.CampaignID = Ucm.ID;      
      
    DROP TABLE #Batch;      
    DROP TABLE #Batch1;      
    DROP TABLE #output;      
END;      
---------------------------------Send Notification Mail End ----------------                 
      
DECLARE @tbdeleted BIGINT=      
(      
    SELECT COUNT(1)      
    FROM usercampaignexecutionrecipientVoice2 Kd(NOLOCK) INNER JOIN #temptable Tt      
    ON Tt.campaignid = Kd.campaignid      
    WHERE [Kd].[iscompleted] = 1      
  AND [kd].[jobid] = @jobid      
);      
      
WHILE @tbdeleted > 0      
    BEGIN      
    DELETE TOP (1000)      
    Kd      
    FROM [usercampaignexecutionrecipientVoice2] [Kd](NOLOCK) INNER JOIN [#temptable] [Tt]      
    ON [Tt].[campaignid] = [Kd].[campaignid]      
    WHERE [Kd].[iscompleted] = 1      
      AND [kd].[jobid] = @jobid;      
    SET @tbdeleted = @tbdeleted - 1000;      
    END;      
      
UPDATE Kd      
  SET      
  [Kd].[step3] = 1,      
  [Step3DateTime] = GETDATE(),      
  [Step3Recipients] = CASE      
      WHEN [ValidEntries] = 1      
      THEN [TT].[RCount]      
      ELSE 0      
      END      
FROM [usercampaignhistory] [Kd] INNER JOIN [#tempTable] [TT]      
ON [TT].[CampaignID] = [Kd].[CampaignID]      
        INNER JOIN [#tempMobile] [TM]      
ON [TM].[CampaignID] = [Kd].[CampaignID]      
WHERE [Kd].[JobId] = @jobId;      
      
UPDATE Kd      
  SET      
  [Kd].[step3] = 1,      
  [Step3DateTime] = GETDATE()      
FROM [usercampaignhistory] [Kd]      
WHERE [Kd].[JobId] = @jobId;      
      
UPDATE u      
  SET      
  [executeddatetime] = GETDATE()      
FROM [usercampaignmaster] [u] JOIN [usercampaignhistory] [Kd]      
ON [kd].[campaignid] = [u].[id]      
   AND [Kd].[JobId] = @jobId;      
--Code added to update nextexecutiondate in usercampaignhistory Start--                    
      
SELECT [campaignid]      
INTO [#FindCampaignsNextExecution]      
FROM #tempTable t INNER JOIN UserCampaignMaster ucm      
ON t.CampaignID = ucm.id      
      LEFT JOIN userschedules us      
ON us.id = ucm.scheduleid      
WHERE [ucm].[IsActive] = 1      
  AND [ucm].[IsSchedule] = 1      
  AND [ucm].[IsScheduled] = 1      
  AND [us].[isonce] = 0;      
      
DECLARE @count INT= ISNULL(      
(      
    SELECT COUNT(1)      
    FROM #FindCampaignsNextExecution      
), 0);      
      
IF @count > 0      
    BEGIN      
    CREATE TABLE #nextexec1      
    ([campaignid]    BIGINT,      
     [nextexecution] DATETIME      
    );      
    WHILE @Count > 0      
    BEGIN      
    DECLARE @Campaignid BIGINT=      
    (      
    SELECT TOP 1 [campaignid]      
    FROM #FindCampaignsNextExecution      
    );      
    INSERT INTO #nextexec1([campaignid], [nextexecution])      
    EXEC Usp_getnextscheduledate      
     @Campaignid;      
    DELETE FROM #FindCampaignsNextExecution      
    WHERE [campaignid] = @Campaignid;      
      
    SET @Count = @Count - 1;      
END;      
    UPDATE u      
  SET      
      [NextExecuteDateTime] = [nextexecution]      
    FROM [usercampaignmaster] [u] INNER JOIN [#nextexec1] [n]      
    ON [n].[campaignid] = [u].[id]      
    WHERE [u].[ExpiryDate] > [nextexecution]      
      OR [u].[ExpiryDate] IS NULL;      
    DROP TABLE #nextexec1;      
    DROP TABLE #FindCampaignsNextExecution;      
END;      
      
DROP TABLE #tempmobile;      
      
DROP TABLE #temptable;      
      
DROP TABLE #TempTableRunningTotal;      
      
DROP TABLE #clonemessagedeliverystatus;      
      
IF EXISTS      
(      
    SELECT 1      
    FROM UserCampaignHistory      
    WHERE [JobId] = @jobId      
  AND [IsEventBased] = 0      
  AND [isSMS] = 2      
)      
    BEGIN      
    UPDATE usercampaignexecution      
  SET      
      [CampaignEnddatetime] = GETDATE(),      
      [isrunning] = 0      
    WHERE [isevent] = 0      
      AND [isSMS] = 2;      
END;      
      
IF EXISTS      
(      
    SELECT 1      
    FROM UserCampaignHistory      
    WHERE [JobId] = @jobId      
  AND [IsEventBased] = 1      
  AND [isSMS] = 2      
)      
    BEGIN      
    UPDATE usercampaignexecution      
  SET      
      [CampaignEnddatetime] = GETDATE(),      
      [isrunning] = 0      
    WHERE [isevent] = 1      
      AND [isSMS] = 2;      
     
END;                                                           
end 


GO

/* ============================================================
   Procedure: [dbo].[Usp_insertclonedeliverycampaignVoice_withid21102020]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--sp_helptext Usp_insertclonedeliverycampaignVoice 2085407                        
CREATE   PROCEDURE [dbo].[Usp_insertclonedeliverycampaignVoice_withid21102020] --8961767--8923047 --2709430 --2549189                                   
@jobid bigint    AS                                                        
BEGIN                                                        
begin try            
CREATE TABLE #outputb            
([id]         INT IDENTITY(1, 1),            
 [bid]        BIGINT,            
 [u_id]       BIGINT,            
 [campaignid] BIGINT            
);            
            
BEGIN TRAN;            
print 'enter insert proc tran'
INSERT INTO Getbatchrecord([User_id], RandNum)            
OUTPUT inserted.BatchID AS bid, inserted.User_id AS u_id, inserted.RandNum AS campaignid            
INTO #outputb            
SELECT DISTINCT Ucerm.u_id, Ucerm.campaignid FROM usercampaignexecutionrecipientVoice2 Ucerm(NOLOCK) WHERE jobid=@jobid and not exists (select 1 from BatchVoiceInfo (nolock) where jobid=@jobid and campaignid=ucerm.campaignid)          
          
;            
            
DELETE g FROM GetBatchRecord g JOIN #outputb o ON o.bid=g.BatchID;            
            
COMMIT;            
            
SELECT ROW_NUMBER() OVER(            
ORDER BY [ucerm].[CampaignId], [ucerm].[ParentId]) [Id], [Ucerm].[CampaignID], [Ucerm].[ParentID], [o].[bid] AS [BatchID], [Ucerm].[Senderid], [Ucerm].[U_ID] AS [UserID], [ucerm].[isunicode], [dbo].[fn_GetVoiceCreditCalculationScalar]([ucerm].[route],    
  
    
     
[ucerm].[U_ID], [ucerm].[duration], COUNT([ucerm].[campaignid])) [cnt], --SUM(isnull(credits,0)) cnt,                                      
COUNT(*) [RCount]            
INTO [#tempTable]            
FROM dbo.usercampaignexecutionrecipientVoice2 Ucerm INNER JOIN #outputb o            
ON o.u_id = ucerm.ParentID            
   AND o.campaignid = ucerm.campaignid            
WHERE [jobid] = @jobid            
  AND [IsCompleted] = 1            
  and not exists (select 1 from BatchVoiceInfo (nolock) where jobid=@jobid and campaignid=ucerm.campaignid)          
GROUP BY [Ucerm].[CampaignID], [Ucerm].[ParentID], [Ucerm].[SenderID], [Ucerm].[U_ID], [Ucerm].[isunicode], [o].[bid], [ucerm].[route], [ucerm].[duration];            
            
--select 'san 1',* from #tempTable                             
--drop table #tempTable                            
--SELECT ROW_NUMBER() Over(order by Ucerm.CampaignId,Ucerm.ParentId) Id,                                         
--Ucerm.CampaignID,                                             
--     Ucerm.ParentID,                                        
--     dbo.Fn_createbatchid(Ucerm.CampaignID, Ucerm.U_ID) AS                                          
--     BatchID,                                                                        
--     Ucerm.Senderid,                                                                                
--     Ucerm.U_ID AS UserID,                                      
--     ucerm.isunicode,                                          
--     SUM(credits) cnt,                                      
--     COUNT(*) RCount                                      
--      INTO   #tempTableVirtual                                                                          
--      FROM   usercampaignexecutionrecipientVoice2 Ucerm                                    
--      join user_detail u on u.User_ID=ucerm.U_ID                                             
--      WHERE   HasVirtualCredits=1  and jobid=@jobid                                           
--     Group by  Ucerm.CampaignID, u.ParentSuperResellerId,                                            
--     Ucerm.ParentID , Ucerm.SenderID, Ucerm.U_ID,                                          
--                      Ucerm.isunicode                                      
            
SELECT [A].[UserID], [a].[CampaignID], [a].[cnt], [A].[BatchID], SUM([b].[cnt]) [RunningTotal]            
INTO [#TempTableRunningTotal]            
FROM #tempTable a INNER JOIN #tempTable b            
ON b.CampaignID <= a.CampaignID            
GROUP BY [A].[UserID], [a].[CampaignID], [a].[cnt], [A].[BatchID]            
ORDER BY [a].[CampaignID];            
        
DROP TABLE #outputb;            
            
/*DELETE Kd                                                        
FROM   Getbatchrecord Kd                                                                    
INNER JOIN #tempTable Tt                   
ON Tt.BatchID = Kd.BatchID  */            
--- Calculate credits                                                                          
            
SELECT [B].[UserID], [B].[CampaignID],            
     CASE            
         WHEN [B].[Balance] >= [B].[Credits]            
         THEN 1            
         ELSE 0            
     END AS [ValidEntries]            
INTO [#tempMobile]            
FROM            
(            
    SELECT [A].[UserID], [A].[CampaignID], ISNULL([A].[Credits], 0) AS [Credits], [A].[Balance]            
    FROM            
    (            
    SELECT [Tt].[UserID], [TT].[RunningTotal] AS [Credits], [TT].[CampaignID], [Tt].[BatchID],            
    (            
    SELECT TOP 1 [Balance]            
    FROM [IntCredit_Details] AS [Mcd]            
    WHERE [Mcd].[User_ID] = [Tt].[UserID]            
    ORDER BY [Credit_ID] DESC            
    ) AS [Balance]            
    FROM #TempTableRunningTotal Tt            
    ) A            
    GROUP BY [A].[UserID], [A].[Balance], [A].[CampaignID], [A].[credits]            
) B;            
            
UPDATE u            
  SET            
  [u].[ReasonIfNotRun] = 'Insuffcient Balance'            
FROM [UserCampaignHistory] [u] INNER JOIN [#tempMobile] [t]            
ON [u].[campaignid] = [t].[CampaignID]            
   AND [u].[jobid] = @jobid            
WHERE [t].[validentries] = 0;          
          
            
SELECT DISTINCT entityname,entityid,           
   [tt].[batchid], [Ucerm].[mobile], [Ucerm].[message], [Ucerm].[messagestatus], [Ucerm].[senderid], [Ucerm].[messageinsertdate], '' AS [scheduleddate], '' AS [scheduledtime],            
   [Ucerm].[u_id], [Ucerm].[isunicode], [Ucerm].[isdnd],            
   [Ucerm].[validno], case when [tt].[RCount] between 1 and 10 then 1 else 0 end as [isprority], [Ucerm].[isallowdnd], [Ucerm].[dbtype], [tt].[CampaignID], [tt].[RCount], ISNULL([Credits], 0) [Credits],            
   [appid], [duration], [didno], [route], @jobid [jobid] ,'Campaign: '+cast(tt.campaignid as nvarchar) as voice_source           
INTO [#clonemessagedeliverystatus]            
FROM usercampaignexecutionrecipientVoice2 Ucerm(NOLOCK) INNER JOIN #temptable Tt            
ON Tt.campaignid = Ucerm.campaignid            
   AND Ucerm.u_id = Tt.userid            
            INNER JOIN #tempmobile Tm            
ON Tm.userid = Tt.userid            
            INNER JOIN user_detail u            
ON u.User_ID = Ucerm.u_id            
--left join #tempMobileVirtual tmv on tmv.CampaignID=tt.CampaignID                            
WHERE [Ucerm].[mobile] <> ''            
  AND [ucerm].[jobid] = @jobid            
  AND [tm].[ValidEntries] = 1;            
            
--select 'clone',* from #clonemessagedeliverystatus                              
--drop table #clonemessagedeliverystatus                         
/*Creating indexes for temp table to improve the performance*/            
            
CREATE NONCLUSTERED INDEX IX_#clonemessagedeliverystatus1            
ON #clonemessagedeliverystatus            
(batchid, mobile, messagestatus, senderid, messageinsertdate            
);            
            
--CREATE NONCLUSTERED INDEX IX_#clonemessagedeliverystatus2 ON #clonemessagedeliverystatus(                     
--smppid,u_id,isunicode,isdnd,isairtel,mobilesubset)                                           
            
CREATE NONCLUSTERED INDEX IX_#clonemessagedeliverystatus3            
ON #clonemessagedeliverystatus            
(validno, isprority, isallowdnd, dbtype, CampaignID, RCount            
);            
      
declare @tbl_activity as dbo.LeadActivitywithid_Tbltype  
--CREATE TABLE #tbl_activity(      
-- [LeadID] [bigint] NULL,      
-- [UserID] [bigint] NULL,      
-- [ParentID] [bigint] NULL,      
-- [EventDescription] [nvarchar](max) NULL,      
-- [EventName] [nvarchar](500) NULL      
--)      
insert into @tbl_activity( LeadID , UserID, ParentID , EventDescription , EventName,reftable,refid)                 
select distinct entityid,m.u_id,u.ParentID, cast(u.user_login as nvarchar) +' sent an automated call with ivr '+i.appname+ ' and did no. '+cast(m.didno as nvarchar(20))+' to mobile '+cast(m.mobile as nvarchar) +' through automated campaign named '      
 + c.CampaignName,'Voice sent to '+entityname,'BatchVoiceInfo',m.BatchID      
 from user_detail u join #clonemessagedeliverystatus m on m.u_id=u.User_ID      
  join UserCampaignMaster c on c.ID=m.CampaignID      
  join cloud_app_master i on i.appid=m.appid      
 where entityname in ('Lead','Enquiry') and isnull(entityid,0)<>0               
      
exec UspSaveEntityActivity_withMultipleValue_withid @tbl_activity      
      
--drop table #tbl_activity       
      
            
--CREATE NONCLUSTERED INDEX IX_#clonemessagedeliverystatus4 ON #clonemessagedeliverystatus(                                    
--HasVirtualCredits,HasSufficientVirtualCredits )                                    
/*End index creation*/            
            
--select t.*,u.email into #Insufficientresellerbalance                                   
-- from #tempMobileVirtual t join #tempMobile tt                                   
--on t.CampaignID=tt.CampaignID join user_detail u on u.user_id=t.ParentSuperResellerId where tt.ValidEntries=0                                   
            
DECLARE @batchcount INT=            
(            
    SELECT COUNT(DISTINCT [batchid])            
    FROM #clonemessagedeliverystatus            
);-- where RCount>5)                             
            
SELECT @batchcount AS [batch];            
            
WHILE @batchcount > 0            
    BEGIN            
    RETRY:            
    BEGIN TRY            
    BEGIN TRAN;            
    DECLARE @batchid BIGINT=            
    (            
   SELECT MIN([batchid])            
    FROM #clonemessagedeliverystatus            
    );-- where RCount>5)                                      
    INSERT INTO Clone_VoiceDeliveryStatus --clonemessagedeliverystatus                                                        
    ([BatchID], [didno], [Mobile], [voiceDuration], [AppId], [IsDnd], [IsPrority], [IsAllowDND], [price], user_id, [VoiceInsertDate], [voice_type], 
	[route], [campaignid], [jobid],voice_source            
    )            
       SELECT distinct [batchid], [didno], [Ucerm].[mobile], [duration], [appid], [Ucerm].[isdnd], [IsPrority], [Ucerm].[isallowdnd], [Credits], [Ucerm].[u_id], GETDATE(), [Ucerm].[dbtype], 
	   [route], [campaignid], [jobid] ,voice_source           
       FROM #clonemessagedeliverystatus Ucerm            
       WHERE [BatchID] = @batchid;            
    DELETE FROM #clonemessagedeliverystatus            
    WHERE [BatchID] = @batchid;            
    SET @batchcount = @batchcount - 1;            
            
    -- SELECT batchid, didno,Ucerm.mobile,duration,appid,Ucerm.isdnd,IsPrority,Ucerm.isallowdnd,                                   
    --        Credits,Ucerm.u_id,GETDATE(),Ucerm.dbtype, route                                                       
    --FROM   #clonemessagedeliverystatus Ucerm where BatchID=@batchid                            
    --delete FROM #clonemessagedeliverystatus where BatchID=@batchid                                      
    --set @batchcount=@batchcount-1                                   
    --select 'clone 2'                                  
    -- select @@TRANCOUNT                                
    --IF @@TRANCOUNT>0                                                                            
    COMMIT;            
    END TRY            
    BEGIN CATCH            
    IF @@TRANCOUNT > 0            
    BEGIN            
    ROLLBACK            
    END;            
    EXECUTE USP_INSERTERRORINFO;            
    IF ERROR_NUMBER() = 1205 -- Deadlock Error Number                                      
    BEGIN            
    WAITFOR DELAY '00:00:00.05'; -- Wait for 5 ms                                      
    GOTO RETRY; -- Go to Label RETRY                                      
    END;            
    END CATCH;            
            
    END;            
            
UPDATE Kd            
  SET            
  [Executiontime] = GETDATE(),            
  [Noofrecipients] = [Tt].[RCount],            
  [Batchid] = [Tt].[BatchID],            
  [Isexecuted] = CASE            
     WHEN [tm].[Validentries] = 1            
     THEN 1            
     ELSE 0            
     END            
FROM [Usercampaignexecutionhistory] [Kd] INNER JOIN [#tempTable] [Tt]            
ON [Tt].[CampaignID] = [Kd].[CampaignID]            
         INNER JOIN [#tempMobile] [Tm]            
ON [Tm].[userID] = [Tt].[userID]            
   AND [Tm].[CampaignID] = [Tt].[CampaignID]                                                  --AND Validentries = 1                                                                     
WHERE [Jobid] = @jobId;            
            
IF EXISTS            
(            
    SELECT 1            
    FROM UserCampaignExecutionHistory            
    WHERE [Jobid] = @jobid            
  AND [TemplateSequence] <> 0            
)            
    BEGIN            
    UPDATE ucm            
  SET            
      [TemplateGroupSequence] = CASE            
            WHEN [isending] = 0            
            THEN ISNULL(            
    (            
    SELECT TOP 1 [orderno]            
    FROM [UserGroupTemplateMix]            
    WHERE [OrderNo] = [TemplateSequence] + 1            
      AND [GroupID] = [ucm].[TemplateGroupID]            
    ), 1)            
            ELSE ISNULL(            
    (            
    SELECT TOP 1 [orderno]            
    FROM [UserGroupTemplateMix]            
    WHERE [OrderNo] = [TemplateSequence] + 1            
      AND [GroupID] = [ucm].[TemplateGroupID]            
    ), [templategroupsequence])            
        END            
    FROM [UserCampaignmaster] [ucm] INNER JOIN [usercampaignexecutionhistory] [uceh]            
    ON [uceh].[CampaignID] = [ucm].[ID]            
        INNER JOIN [UserGroupTemplateMix] [ugtm]            
    ON [ugtm].[GroupID] = [ucm].[TemplateGroupID]            
    WHERE [Jobid] = @jobid            
      AND [TemplateSequence] <> 0            
      AND [IsExecuted] = 1;            
END;            
            
---send notification mail------                                        
            
IF(            
(            
    SELECT TOP 1 [iseventbased]            
    FROM UserCampaignHistory            
    WHERE [JobId] = @jobId            
) = 0)            
    BEGIN            
    INSERT INTO Getbatchrecord([User_id], [RandNum])            
   SELECT [ParentID], [CampaignID]            
   FROM #tempTable;            
            
  SELECT [BatchID], [User_id] [ParentID], [RandNum] [CampaignID]            
    INTO [#Batch]            
    FROM Getbatchrecord Gbr            
    ORDER BY [gbr].[BatchID];            
            
    DELETE Kd            
    FROM [Getbatchrecord] [Kd] INNER JOIN [#Batch] [B]            
    ON [B].[BatchId] = [Kd].[BatchID];            
            
    --INSERT INTO Getbatchrecord                                                                          
    --               ([User_id],                                                                          
    --                RandNum)                                                                          
    --   SELECT ParentSuperResellerId,                                   
    --                CampaignID FROM #Insufficientresellerbalance             
    SELECT [BatchID], [User_id] [ParentSuperResellerId], [RandNum] [CampaignID]            
    INTO [#Batch1]            
    FROM Getbatchrecord Gbr            
    ORDER BY [gbr].[BatchID];            
            
    DELETE Kd            
    FROM [Getbatchrecord] [Kd] INNER JOIN [#Batch1] [B]            
    ON [B].[BatchId] = [Kd].[BatchID];            
            
    INSERT INTO Batchemail_infos            
    (            
    -- ID -- this column value is auto-generated                                                            
    [B].[BatchID], [UserID], [SenderName], [Message], [TotalRecords], [TotalProcessed], [ProcessTable], [IsProcess], [Priority_Level], [BatchInsertTime], [BatchProcessTime], [ScheduledDate], [ScheduledTime], [TemplateID], [Route], [PageName], [IsScheduled], [Email_Subject], 
	[ReplyTo], [Amount], [Currency],bmonitor,mail_source            
    )            
   SELECT [B].[Batchid], 335, [Ucm].[NotificationMail],            
            CASE            
            WHEN [TM].[ValidEntries] = 0            
            THEN 'Oops, you don''t have sufficient Voice credits to run your Voice campaign "' + [Ucm].[CampaignName] + '" scheduled for ' + CAST(GETDATE() AS VARCHAR(50)) + '. Pl refill your credit balance & rerun the campaign '            
            ELSE 'As promised , Your Voice campaign "' + [Ucm].[CampaignName] + '" scheduled for ' + CAST(GETDATE() AS VARCHAR(50)) + ' is executed successfully. You can log in to your account & check the delivery report in the campaign history'          
  
            END AS [Message], 1, 0, 0, 0, 1, GETDATE(), GETDATE(), GETDATE(), GETDATE(), 0, 0, 0, 0,            
                              CASE            
                              WHEN [TM].[ValidEntries] = 0            
                              THEN 'Failure: Your campaign "' + +[UCM].[CampaignName] + '" failed due to insufficient credits'            
                              ELSE 'Success : Your campaign "' + [UCM].[CampaignName] + '" executed successfully'            
                              END AS [email_subject], 'noreply@email19.in', 0, 0 ,1,'Internal Notification'           
   FROM #temptable Tt INNER JOIN Usercampaignmaster AS Ucm            
   ON Ucm.ID = Tt.CampaignID            
      AND Ucm.IsScheduled = 1            
      AND Ucm.ParentID = Tt.ParentID            
          INNER JOIN #tempMobile TM            
   ON TM.CampaignID = Tt.CampaignID            
          INNER JOIN #Batch B            
   ON B.CampaignId = Tt.CampaignId;            
            
    CREATE TABLE #output            
    ([GUID]    NVARCHAR(100) COLLATE SQL_Latin1_General_CP1_CI_AS,            
     [Email]   NVARCHAR(200) COLLATE SQL_Latin1_General_CP1_CI_AS,            
     [Batchid] BIGINT            
    );            
            
    INSERT INTO Clientemails            
    (            
    -- Id -- this column value is auto-generated                               
    [GUID], [Email_Id], [SentDateTime], [UserId], [ReplyTo], [Status], [BatchID], [Message]            
    )            
    OUTPUT [inserted].[GUID], [inserted].[Email_Id], [inserted].[BatchID]            
   INTO #output            
   SELECT NEWID(), [Ucm].[NotificationMail], GETDATE(), 335, 'noreply@email19.in', '', [B].[Batchid],            
                       CASE            
                       WHEN [TM].[ValidEntries] = 0            
                       THEN 'Oops, you don''t have sufficient Voice credits to run your Voice campaign "' + [Ucm].[CampaignName] + '" scheduled for ' + CAST(GETDATE() AS VARCHAR(50)) + '. Pl refill your credit balance & rerun the campaign '            
                       ELSE 'As promised , Your Voice campaign "' + [Ucm].[CampaignName] + '" scheduled for ' + CAST(GETDATE() AS VARCHAR(50)) + ' is executed successfully. You can log in to your account & check the delivery report in the campaign histor 
  
    
     
y        
          
'            
                END AS [Message]            
   FROM #tempTable Tt INNER JOIN Usercampaignmaster AS Ucm            
   ON Ucm.ID = Tt.CampaignID            
      AND Ucm.IsScheduled = 1            
      AND Ucm.ParentID = Tt.ParentID            
          INNER JOIN #tempMobile TM            
   ON TM.CampaignID = Ucm.ID            
          INNER JOIN #Batch B            
   ON B.CampaignId = Tt.CampaignId;            
            
    INSERT INTO Emailsfilter            
    ([Mail_GUID],            
    -- Mail_ID -- this column value is auto-generated                                                            
    [Mail_FromEmail], [Mail_ToEmail], [Mail_Subject], [Mail_TempleteName], [Messages], [Mail_InsertedDate], [Mail_UserID], [ReplyTo], [Mail_BatchID], [Mail_Priority], [Mail_ScheduleDate], [Mail_Attechement], [Mail_TempleteBody], [IsMonitor]          
    )            
   SELECT [o].[guid], 'contactus@email19.in', [UCM].[NotificationMail],            
                CASE            
                WHEN [TM].[ValidEntries] = 0            
                THEN 'Failure: Your campaign "' + +[UCM].[CampaignName] + '" failed due to insufficient credits'            
                ELSE 'Success : Your campaign "' + [UCM].[CampaignName] + '" executed successfully'            
                END AS [Mail_subject], '',            
                   CASE            
                   WHEN [TM].[ValidEntries] = 0            
                   THEN 'Oops, you don''t have sufficient Voice credits to run your Voice campaign "' + [UCM].[CampaignName] + '" scheduled for ' + CAST(GETDATE() AS VARCHAR(50)) + '. Pl refill your credit balance & rerun the campaign '            
                   ELSE 'As promised , Your Voice campaign "' + [UCM].[CampaignName] + '" scheduled for ' + CAST(GETDATE() AS VARCHAR(50)) + ' is executed successfully. You can log in to your account & check the delivery report in the campaign history'   
 
     
      
        
         
                   END AS [Messages], GETDATE(), 335, 'noreply@email19.in', [B].[Batchid], 1, GETDATE(), 0,            
                                     CASE            
                                     WHEN [TM].[ValidEntries] = 0            
                                     THEN 'Oops, you don''t have sufficient Voice credits to run your Voice campaign "' + [UCM].[CampaignName] + '" scheduled for ' + CAST(GETDATE() AS VARCHAR(50)) + '. Pl refill your credit balance & rerun the campaign ' 
  
    
      
        
         
            
                                     ELSE 'As promised , Your Voice campaign "' + [UCM].[CampaignName] + '" scheduled for ' + CAST(GETDATE() AS VARCHAR(50)) + ' is executed successfully. You can log in to your account & check the delivery report in the ca
  
    
      
        
          
mpaign history'            
                                     END AS [mail_templetebody], 1            
   FROM #tempTable Tt INNER JOIN Usercampaignmaster AS Ucm            
   ON Ucm.ID = Tt.CampaignID            
      AND Ucm.IsScheduled = 1            
      AND Ucm.ParentID = Tt.ParentID            
          INNER JOIN #tempMobile TM            
   ON TM.CampaignID = Ucm.ID            
          INNER JOIN #Batch B            
   ON B.CampaignId = Tt.CampaignId            
          INNER JOIN #output o            
   ON o.Email = ucm.NotificationMail          
   WHERE [o].[Batchid] = [b].[BatchID];            
            
    INSERT INTO Mailcreditdetails            
    ([ID],            
    -- Credit_ID -- this column value is auto-generated                                                            
    [M_ID], [FromUser_ID], [User_ID], [Debits], [Credits], [Balance], [Validity], [Default_Credit], [FromDate], [ToDate], [DateCreated], [DateUpdated], [EmpUpdated], [MachineName], [LastModified], [typecredit]            
    )            
   SELECT NEWID(), 10001, 335, 335, COUNT(*), 0,            
   (            
       SELECT TOP 1 [Mcd].[Balance]            
       FROM [Mailcreditdetails] AS [Mcd]            
       WHERE [Mcd].[User_ID] = 335            
       ORDER BY [Mcd].[Credit_ID] DESC            
   ) - COUNT(*), 99999, 0, GETDATE(), GETDATE(), GETDATE(), GETDATE(), 'Campaign Exec', '', GETDATE(), 0            
   FROM #tempTable Tt INNER JOIN Usercampaignmaster AS Ucm            
 ON Ucm.ID = Tt.CampaignID            
      AND Ucm.ParentID = Tt.ParentID            
      AND Ucm.IsScheduled = 1            
          INNER JOIN #tempMobile TM            
   ON TM.CampaignID = Ucm.ID;            
            
    DROP TABLE #Batch;            
    DROP TABLE #Batch1;            
    DROP TABLE #output;            
END;            
---------------------------------Send Notification Mail End ----------------                       
            
DECLARE @tbdeleted BIGINT=            
(            
    SELECT COUNT(1)            
    FROM usercampaignexecutionrecipientVoice2 Kd(NOLOCK) INNER JOIN #temptable Tt            
    ON Tt.campaignid = Kd.campaignid            
    WHERE [Kd].[iscompleted] = 1            
  AND [kd].[jobid] = @jobid            
);            
            
WHILE @tbdeleted > 0            
    BEGIN            
    DELETE TOP (1000)            
    Kd            
    FROM [usercampaignexecutionrecipientVoice2] [Kd](NOLOCK) INNER JOIN [#temptable] [Tt]            
    ON [Tt].[campaignid] = [Kd].[campaignid]            
    WHERE [Kd].[iscompleted] = 1            
      AND [kd].[jobid] = @jobid;            
    SET @tbdeleted = @tbdeleted - 1000;            
    END;            
            
UPDATE Kd            
  SET            
  [Kd].[step3] = 1,            
  [Step3DateTime] = GETDATE(),            
  [Step3Recipients] = CASE            
      WHEN [ValidEntries] = 1            
      THEN [TT].[RCount]            
      ELSE 0            
      END            
FROM [usercampaignhistory] [Kd] INNER JOIN [#tempTable] [TT]            
ON [TT].[CampaignID] = [Kd].[CampaignID]            
        INNER JOIN [#tempMobile] [TM]            
ON [TM].[CampaignID] = [Kd].[CampaignID]           
WHERE [Kd].[JobId] = @jobId;            
            
UPDATE Kd            
  SET            
  [Kd].[step3] = 1,            
  [Step3DateTime] = GETDATE()            
FROM [usercampaignhistory] [Kd]            
WHERE [Kd].[JobId] = @jobId;            
            
UPDATE u            
  SET            
  [executeddatetime] = GETDATE()            
FROM [usercampaignmaster] [u] JOIN [usercampaignhistory] [Kd]            
ON [kd].[campaignid] = [u].[id]            
   AND [Kd].[JobId] = @jobId;            
--Code added to update nextexecutiondate in usercampaignhistory Start--                          
            
SELECT [campaignid]            
INTO [#FindCampaignsNextExecution]            
FROM #tempTable t INNER JOIN UserCampaignMaster ucm            
ON t.CampaignID = ucm.id            
      LEFT JOIN userschedules us            
ON us.id = ucm.scheduleid            
WHERE [ucm].[IsActive] = 1            
  AND [ucm].[IsSchedule] = 1            
  AND [ucm].[IsScheduled] = 1            
  AND [us].[isonce] = 0;            
            
DECLARE @count INT= ISNULL(            
(            
    SELECT COUNT(1)            
    FROM #FindCampaignsNextExecution            
), 0);            
            
IF @count > 0            
    BEGIN            
    CREATE TABLE #nextexec1            
    ([campaignid]    BIGINT,            
     [nextexecution] DATETIME            
    );            
    WHILE @Count > 0            
    BEGIN            
    DECLARE @Campaignid BIGINT=            
    (            
    SELECT TOP 1 [campaignid]            
    FROM #FindCampaignsNextExecution            
    );            
    INSERT INTO #nextexec1([campaignid], [nextexecution])            
    EXEC Usp_getnextscheduledate            
     @Campaignid;            
    DELETE FROM #FindCampaignsNextExecution            
    WHERE [campaignid] = @Campaignid;            
            
    SET @Count = @Count - 1;            
END;            
    UPDATE u            
  SET            
      [NextExecuteDateTime] = [nextexecution]            
    FROM [usercampaignmaster] [u] INNER JOIN [#nextexec1] [n]            
    ON [n].[campaignid] = [u].[id]            
    WHERE [u].[ExpiryDate] > [nextexecution]            
      OR [u].[ExpiryDate] IS NULL;            
    DROP TABLE #nextexec1;            
    DROP TABLE #FindCampaignsNextExecution;            
END;            
            
DROP TABLE #tempmobile;            
            
DROP TABLE #temptable;            
            
DROP TABLE #TempTableRunningTotal;            
            
DROP TABLE #clonemessagedeliverystatus;            
            
IF EXISTS            
(            
    SELECT 1            
    FROM UserCampaignHistory            
    WHERE [JobId] = @jobId            
  AND [IsEventBased] = 0            
  AND [isSMS] = 2            
)            
    BEGIN            
    UPDATE usercampaignexecution            
  SET            
      [CampaignEnddatetime] = GETDATE(),            
      [isrunning] = 0            
    WHERE [isevent] = 0            
      AND [isSMS] = 2;            
END;            
            
IF EXISTS            
(            
    SELECT 1            
    FROM UserCampaignHistory            
    WHERE [JobId] = @jobId            
  AND [IsEventBased] = 1            
  AND [isSMS] = 2        
)            
    BEGIN    
	print 'Updating usercampaignexecution'
    UPDATE usercampaignexecution            
  SET            
      [CampaignEnddatetime] = GETDATE(),            
      [isrunning] = 0            
    WHERE [isevent] = 1            
      AND [isSMS] = 2;            
           
END;

  end try
  begin catch
  exec usp_inserterrorinfo
  end catch                                                                 
end 




