 FROM   usercampaignexecutionrecipientVoice2 Ucerm (nolock)                     
 INNER JOIN #temptable Tt ON  Tt.campaignid = Ucerm.campaignid AND Ucerm.u_id = Tt.userid                    
 INNER JOIN #tempmobile Tm ON  Tm.userid = Tt.userid join user_detail u                 
 on u.User_ID=Ucerm.u_id                        
 --left join #tempMobileVirtual tmv on tmv.CampaignID=tt.CampaignID                          
 WHERE  Ucerm.mobile <> '' and ucerm.jobid=@jobid                  
          
--select 'clone',* from #clonemessagedeliverystatus            
