   Procedure: [dbo].[usp_InsertcommissionSlabs]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_InsertcommissionSlabs]    
@slabname nvarchar(30),    
@ServiceReferred nvarchar(50),    
@CommissionAmount numeric(18,2),    
@CommissionPercent numeric(18,2),    
@IsAmount bit,    
@userGroup int =null,    
@Description nvarchar(200),    
@ValidFrom date,    
@ValidTill date ,  
@minimumorderamount numeric(18,2)=null   
as        
begin    
declare @duplicatecommission int=(select id from Referrer_Payout_Rates r where @ServiceReferred=ServiceReferred and (@userGroup is null or @UserGroup=usergroup ) and status=1 and (@ValidFrom between cast(ValidFrom as DATE) and CAST(ValidTill as DATE) or  
  
@Validtill between cast(ValidFrom as DATE) and CAST(ValidTill as DATE) or cast(ValidFrom as date) between @ValidFrom and @validtill or cast(validtill as date) between @ValidFrom and @ValidTill))    
if @duplicatecommission is not null    
begin    
Select 'Your values coincide with Slab ' + (select slabname from Referrer_Payout_Rates where ID=@duplicatecommission) + ' . Kindly change the service,usergroup or validity or deactive the last slab first'    
end    
else    
begin    
insert into Referrer_Payout_Rates(slabname,ServiceReferred,CommissionAmount,CommissionPercent,IsAmount,[userGroup],[Description],ValidFrom,DateCreated,ValidTill,status,MinimumOrderAmount)    
select @slabname,@ServiceReferred,@CommissionAmount,@CommissionPercent,@IsAmount,@userGroup,@Description,@ValidFrom,GETDATE(),@ValidTill,1,@minimumorderamount     
Select 'New slab inserted successfully'    
end    
end    



GO

