/* ============================================================
   Procedure: [dbo].[Usp_InsertCRMCampaignSetting]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

    
CREATE   PROC [dbo].[Usp_InsertCRMCampaignSetting]     
(    
    @UserID INT,    
    @AutoLeadDistribution BIT,    
    @Agents NVARCHAR(MAX),    
    @IsStickyAgents BIT,    
    @ActiveUsers BIT,    
    @UserAdmin NVARCHAR(MAX),    
    @IsActive BIT,    
    @AdminRight BIT,    
    @CreatedBy NVARCHAR(50)    
)        
  AS         
BEGIN   
      declare @ParentID bigint = 0 
	  
	  select @ParentID = isnull(ParentID,0) from User_Detail(nolock) where User_ID = @UserID
	          
 
 IF (    
        NOT EXISTS(    
            SELECT 'x'    
            FROM   CRMCampaignSettings    
            WHERE  UserID = @UserID    
        )    
    )    
 BEGIN    
     INSERT INTO CRMCampaignSettings    
       (    
         UserID,    
         AutoLeadDistribution,    
         Agents,    
         IsStickyAgents,    
         ActiveUsers,    
         UserAdmin,    
         IsActive,    
         AdminRight,    
         CreateDate,    
         ModifiedDate,    
         ModifiedBy    
       )    
     VALUES    
       (    
         @UserID,    
         @AutoLeadDistribution,    
         @Agents,    
         @IsStickyAgents,    
         @ActiveUsers,    
         @UserAdmin,    
         @IsActive,    
         @AdminRight,    
         GETDATE(),    
         GETDATE(),    
         @CreatedBy    
       )  
	   
	   if(@AdminRight = 1 )
	     Begin
		   
		   update User_Detail set IsAdmin = 1
		   where USER_ID in (select value from  dbo.[fn_Split](@UserAdmin,'#') ) 
		   
		   update User_Detail set IsAdmin = 0
		   where USER_ID not in (select value from  dbo.[fn_Split](@UserAdmin,'#')) 
		   and ParentID = @ParentID 
		   and USER_ID <>  @ParentID

	     End

	   	   
	   
	           
     SELECT 'Record Saved'    
 END    
 ELSE    
 BEGIN    
     UPDATE CRMCampaignSettings    
     SET    AutoLeadDistribution = @AutoLeadDistribution,    
            Agents = @Agents,    
            IsStickyAgents = @IsStickyAgents,    
            ActiveUsers = @ActiveUsers,    
            UserAdmin = @UserAdmin,    
            IsActive = @IsActive,    
            AdminRight = @AdminRight,    
            CreateDate = GETDATE(),    
            ModifiedDate = GETDATE(),    
            ModifiedBy = @CreatedBy    
     WHERE  UserID = @UserID    
         
  Declare @LastAssignedUserID int = 0    
  
  select top 1  @LastAssignedUserID = isnull(LastUserAssigned,0) from CRMCampaignSettings where USERID = @UserID  
  
  if(not exists (select value from dbo.[fn_Split](@Agents,'#') where value = @LastAssignedUserID))  
    Begin  
         update CRMCampaignSettings set LastUserAssigned = isnull((select top 1 value from dbo.[fn_Split](@Agents,'#')),null) where  UserID = @UserID   
    end  
  
    
	 if(@AdminRight = 1 )
	     Begin
		   
		   update User_Detail set IsAdmin = 1
		   where USER_ID in (select value from  dbo.[fn_Split](@UserAdmin,'#') ) 
		   
		   update User_Detail set IsAdmin = 0
		   where USER_ID not in (select value from  dbo.[fn_Split](@UserAdmin,'#')) 
		   and ParentID = @ParentID 
		   and User_id <>  @ParentID

	     End


     SELECT 'Record Updated'    
 END    
END 


GO

/* ============================================================
   Procedure: [dbo].[Usp_InsertCRMCampaignSetting_New]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC dbo.Usp_InsertCRMCampaignSetting_New
(  

  @UserID INT  
 ,@AutoLeadDistribution BIT  
 ,@Agents NVARCHAR(MAX)  
 ,@IsStickyAgents BIT  
 ,@ActiveUsers BIT  
 ,@UserAdmin NVARCHAR(MAX)  
 ,@IsActive BIT  
 ,@AdminRight BIT  
 ,@CreatedBy NVARCHAR(50)  
 ,@AutoLeadFollowupSetting BIT  
 ,@FollowupStatus INT  
 ,@NextStatusDateAddUnit NVARCHAR(100)  
 ,@FollowupRemarks NVARCHAR(max)  

 )  
AS  
BEGIN  
 DECLARE @ParentID BIGINT = 0  
  ,@activity VARCHAR(MAX)  
  ,@action VARCHAR(1)  
  
 SELECT @ParentID = isnull(ParentID, 0)  
 FROM User_Detail(NOLOCK)  
 WHERE User_ID = @UserID  
  
 IF (  
   NOT EXISTS (  
    SELECT 'x'  
    FROM CRMCampaignSettings  
    WHERE UserID = @UserID  
    )  
   )  
 BEGIN  
  INSERT INTO CRMCampaignSettings (  
    UserID  
   ,AutoLeadDistribution  
   ,Agents  
   ,IsStickyAgents  
   ,ActiveUsers  
   ,UserAdmin  
   ,IsActive  
   ,AdminRight  
   ,CreateDate  
   ,ModifiedDate  
   ,ModifiedBy  
   ,AutoLeadFollowup  
   ,FollowupStatus  
   ,NextStatusDateAddUnit  
   ,FollowupRemarks  
   )  
  VALUES (  
   @UserID  
   ,@AutoLeadDistribution  
   ,@Agents  
   ,@IsStickyAgents  
   ,@ActiveUsers  
   ,@UserAdmin  
   ,@IsActive  
   ,@AdminRight  
   ,GETDATE()  
   ,GETDATE()  
   ,@CreatedBy  
   ,@AutoLeadFollowupSetting  
   ,@FollowupStatus  
   ,@NextStatusDateAddUnit  
   ,@FollowupRemarks  
   )  
  
  IF (@AdminRight = 1)  
  BEGIN  
   UPDATE User_Detail  
   SET IsAdmin = 1  
   WHERE USER_ID IN (  
     SELECT value  
     FROM dbo.[fn_Split](@UserAdmin, '#')  
     )  
  
   UPDATE User_Detail  
   SET IsAdmin = 0  
   WHERE USER_ID NOT IN (  
     SELECT value  
     FROM dbo.[fn_Split](@UserAdmin, '#')  
     )  
    AND ParentID = @ParentID  
    AND USER_ID <> @ParentID  
  END  
  else 
    begin
	     if(exists(select 1 from CRMCampaignSettings with(nolock) where UserID = @UserID))  
			begin  
			 if(exists(select 1 from CRMCampaignSettings with(nolock) where UserID = @UserID and isnull(AdminRight,0) = 0 ))  
				  begin  
   		       DECLARE @IsAdmin BIT = 0   
			   SELECT @IsAdmin = IsAdmin  
			FROM User_Detail(NOLOCK)  
			WHERE User_ID = @Userid  
  
			   IF(@IsAdmin = 1)  
			 BEGIN  
				declare @UserCollectionString nvarchar(max) = ''  
			  select @UserCollectionString = STRING_AGG(USER_ID,'#')  
				   from User_Detail with(nolock) where ParentID = @ParentID and ISNULL(IsAdmin,0) = 1  
       
				  if(trim(@UserCollectionString) <> '')  
				  begin  
                     
					update CRMCampaignSettings set AdminRight = 1 , UserAdmin = trim(@UserCollectionString) where UserID = @UserID   
         
			   end  
			  END  
			end   
	    end  

    end
   

  SELECT 'Record Saved'  
  
  SET @action = 'I'  
  SET @activity = 'Inst_CRMcmpgn_Sttng'  
 END  
 ELSE  
 BEGIN  
  UPDATE CRMCampaignSettings  
  SET AutoLeadDistribution = @AutoLeadDistribution  
   ,Agents = @Agents  
   ,IsStickyAgents = @IsStickyAgents  
   ,ActiveUsers = @ActiveUsers  
   ,UserAdmin = @UserAdmin  
   ,IsActive = @IsActive  
   ,AdminRight = @AdminRight  
   ,CreateDate = GETDATE()  
   ,ModifiedDate = GETDATE()  
   ,ModifiedBy = @CreatedBy  
   ,AutoLeadFollowup = @AutoLeadFollowupSetting  
   ,FollowupStatus = @FollowupStatus  
   ,NextStatusDateAddUnit = @NextStatusDateAddUnit  
   ,FollowupRemarks = @FollowupRemarks  
  WHERE UserID = @UserID  
  
  DECLARE @LastAssignedUserID INT = 0  
  
  SELECT TOP 1 @LastAssignedUserID = isnull(LastUserAssigned, 0)  
  FROM CRMCampaignSettings  
  WHERE USERID = @UserID  
  
  IF (  
    NOT EXISTS (  
     SELECT value  
     FROM dbo.[fn_Split](@Agents, '#')  
     WHERE value = @LastAssignedUserID  
     )  
    )  
  BEGIN  
   UPDATE CRMCampaignSettings  
   SET LastUserAssigned = isnull((  
      SELECT TOP 1 value  
      FROM dbo.[fn_Split](@Agents, '#')  
      ), NULL)  
   WHERE UserID = @UserID  
  END  
  
  IF (@AdminRight = 1)  
  BEGIN  
   UPDATE User_Detail  
   SET IsAdmin = 1  
   WHERE USER_ID IN (  
     SELECT value  
     FROM dbo.[fn_Split](@UserAdmin, '#')  
     )  
  
   UPDATE User_Detail  
   SET IsAdmin = 0  
   WHERE USER_ID NOT IN (  
     SELECT value  
     FROM dbo.[fn_Split](@UserAdmin, '#')  
     )  
    AND ParentID = @ParentID  
    AND User_id <> @ParentID  
  END
  else
    begin
	     if(exists(select 1 from CRMCampaignSettings with(nolock) where UserID = @UserID))  
			begin  
			 if( exists(select 1 from CRMCampaignSettings with(nolock) where UserID = @UserID and isnull(AdminRight,0) = 0 ))  
				  begin  
   		       DECLARE @IsAdmin1 BIT = 0   
			   SELECT @IsAdmin1 = IsAdmin  
			FROM User_Detail(NOLOCK)  
			WHERE User_ID = @Userid  
  
			   IF(@IsAdmin1 = 1)  
			 BEGIN  
				declare @UserCollectionString1 nvarchar(max) = ''  
			  select @UserCollectionString1 = STRING_AGG(USER_ID,'#')  
				   from User_Detail with(nolock) where ParentID = @ParentID and ISNULL(IsAdmin,0) = 1  
       
				  if(trim(@UserCollectionString1) <> '')  
				  begin  
                     
					update CRMCampaignSettings set AdminRight = 1 , UserAdmin = trim(@UserCollectionString1) where UserID = @UserID   
         
			   end  
			  END  
			end   
	    end  

    end
  
  SELECT 'Record Updated'  
  
  SET @action = 'U'  
  SET @activity = 'Updt_CRMcmpgn_Sttng'  
 END  
  
 DECLARE @rowJson NVARCHAR(MAX) = (  
   SELECT *  
   FROM CRMCampaignSettings(NOLOCK)  
   WHERE UserID = @UserID  
   FOR JSON AUTO  
    ,INCLUDE_NULL_VALUES  
   )  
  
 IF @RowJson IS NOT NULL  
 BEGIN  
  EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId  
   ,@Activity_type = @activity  
   ,@ActionType = @action  
   ,@RowJson = @rowJson  
   ,@Table_name = 'CRMCampaignSettings'  
 END  
END  


GO

