/* ============================================================
   Procedure: [dbo].[usp_InsertCustomizationEmail_Metadata]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_InsertCustomizationEmail_Metadata]
    @jsondata NVARCHAR(MAX)
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @ResellerId BIGINT = 0; 
    DECLARE @userid BIGINT;
    DECLARE @mid BIGINT;
    DECLARE @newId INT; -- Variable to store the new identity value
    DECLARE @existingId INT; -- Variable to check if the record already exists
	DECLARE @message NVARCHAR(255); 

    BEGIN TRY
        -- Extract the userid from the jsondata column
        -- Assuming the jsondata has a structure where userid is a key (e.g., {"userid": 123})
        --SET @userid = JSON_VALUE(@jsondata, '$.userid');
        Select @userid=USERID
   
	From openjson(@jsondata)
	With 
	(
		
		UserId	bigint			'$.USERID'
		
	)
        -- Check if userid is valid
        IF @userid IS NULL
        BEGIN
            THROW 50000, 'Invalid or missing userid', 1;
        END

        -- Fetch the corresponding mid from the User_Detail table based on the userid
        SELECT @ResellerId = M_ID   
        FROM User_Detail with(nolock) 
        WHERE user_id = @userid;  

        -- If ResellerId (mid) is found, proceed to check if record exists in tbl_pt_CustomizationMetadata
        IF @ResellerId IS NOT NULL
        BEGIN
            -- Check if a record already exists for the given userid
            SELECT @existingId = id
            FROM tbl_pt_CustomizationMetadata with(nolock)
            WHERE userid = @userid;

            IF @existingId IS NOT NULL
            BEGIN
                -- Record exists, so perform an UPDATE on jsondata
                UPDATE tbl_pt_CustomizationMetadata
                SET jsonEmailData = @jsondata, createdon = GETDATE(), createdby = @userid
                WHERE id = @existingId;

                SET @message = 'Record updated successfully.';

                -- Return the existing id and message
                SELECT @existingId AS UpdatedId, @message AS Message;
            END
            ELSE
            BEGIN
                -- Record does not exist, perform an INSERT
                INSERT INTO tbl_pt_CustomizationMetadata (mid, userid, jsonEmailData, createdon, createdby)
                VALUES (@ResellerId, @userid, @jsondata, GETDATE(), @userid);

                -- Get the identity value of the last inserted row
                SET @newId = SCOPE_IDENTITY();
                
                SET @message = 'New record inserted successfully.';

                -- Return the new identity value and message
                SELECT @newId AS NewId, @message AS Message;
            END
        END
        ELSE
        BEGIN
            THROW 50000, 'No matching reseller found for the given userid', 1;
        END

    END TRY
    BEGIN CATCH
        -- Handle errors, e.g., log them or call another procedure
        EXEC usp_InsertErrorInfo;
    END CATCH
END;

--------------------------------------------------------------------



GO

