   Procedure: [dbo].[usp_InsertCustomizationMetadata]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-------------------------------------------------------




--   Go

-------------------------------------------------------------------------------------------
CREATE   PROCEDURE usp_InsertCustomizationMetadata
    @jsondata NVARCHAR(MAX)
   -- @createdby BIGINT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @userid BIGINT;
    DECLARE @mid BIGINT;
    DECLARE @newId INT; -- Variable to store the new identity value

    BEGIN TRY
        -- Extract the userid from the jsondata column
        -- Assuming the jsondata has a structure where userid is a key (e.g., {"userid": 123})
        SET @userid = JSON_VALUE(@jsondata, '$.userid');
        
        -- Check if userid is valid
        IF @userid IS NULL
        BEGIN
            THROW 50000, 'Invalid or missing userid in jsondata', 1;
        END

        -- Fetch the corresponding mid from the reseller_detail table
        SELECT @mid = rd.m_id
        FROM reseller_detail rd with(nolock)
        WHERE rd.user_id = @userid;

        -- If mid is found, insert the data into tbl_pt_CustomizationMetadata
        IF @mid IS NOT NULL
        BEGIN
            -- Insert into tbl_pt_CustomizationMetadata table
            INSERT INTO tbl_pt_CustomizationMetadata (mid, userid, jsondata,createdon, createdby)
            VALUES (@mid, @userid, @jsondata,getdate(), @userid);

            -- Get the identity value of the last inserted row
            SET @newId = SCOPE_IDENTITY();
            
            -- Return the new identity value (ID of the inserted row)
            SELECT @newId AS NewId;
        END
        ELSE
        BEGIN
            THROW 50000, 'No matching mid found for the given userid', 1;
        END

    END TRY
    BEGIN CATCH
         EXEC usp_InsertErrorInfo;
    END CATCH
END;

