Version        : 1          
Alter by       :                 
Alter Date    :            
Location       : PelSoftLab          
SP Description : This SP is Used to Insert Records Into MessageSource by selecting Records from ProcessTableFirst,          
                 ProcessTableTwo,ProcessTableThree,ProcessTableFour and Also Delete Records from ProcessTableFirst,          
                 ProcessTableTwo,ProcessTableThree,ProcessTableFour          
****************************************************************************/           
          
CREATE   PROC [dbo].[USP_InsertDeleteNormalRecordsByBatchID]   --2456253,0,0,1         
@BatchID BIGINT,--frm int 17-08-2010            
@Priority TINYINT,            
@AllowDND BIT,            
@ProcessTable int           
           
AS            
BEGIN            
     IF (@ProcessTable = 1)            
     BEGIN            
       IF (@AllowDND = 1)            
       BEGIN               
     INSERT INTO MessageSource(MessageID,MessageBatchID,Mobile,[Message],SenderID, SmppID, U_ID, Priority,            
     IsUniCode,IsDND,Operator,Isallowdnd)            
     SELECT MessageID,BatchID,Mobile,[Message],SenderID,SmppID,U_ID, @Priority ,IsUniCode,IsDND,Operator,Isallowdnd            
     FROM ProcessTableFirst WHERE BatchID = @BatchID            
            
     DELETE FROM ProcessTableFirst WHERE BatchID = @BatchID            
       END            
       ELSE IF (@AllowDND = 0)            
       BEGIN            
     INSERT INTO MessageSource(MessageID,MessageBatchID,Mobile,[Message],SenderID, SmppID, U_ID, Priority,            
     IsUniCode,IsDND,Operator,Isallowdnd)            
