     FROM ProcessTableFour WHERE BatchID = @BatchID-- AND IsDND = 0            
            
--   insert into MessageDND(MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                                  
--   IsDND,Operator,BatchID)  SELECT MessageID,Mobile,[Message],SenderID,SmppID, @Priority ,U_ID,IsUniCode,IsDND,Operator                 
--     ,BatchID FROM ProcessTableFour WHERE BatchID = @BatchID AND IsDND = 1  
  
     DELETE FROM ProcessTableFour WHERE BatchID = @BatchID               
      END            
     END             
END 




GO

