                and delete records from  ProcessTableFirst,ProcessTableTwo,ProcessTableThree,ProcessTableFour            
                                 
****************************************************************************/              
CREATE   PROC [dbo].[USP_InsertDeleteNormalRecordsForMonitor]              
@BatchID bigint,      -- frm int 17-08-2010
@Priority tinyint,              
@AllowDND tinyint, --alter by vinay : 12-02-2010 change bit to tinyint             
@ProcessTable int              
AS              
BEGIN
begin try 
	begin transaction              
       IF (@ProcessTable = 1)              
       BEGIN               
         IF (@AllowDND = 1)              
         BEGIN              
     INSERT INTO MessageMonitor(MessageID,BatchID,Mobile,[Message],SenderID, SmppID, U_ID, Priority,              
     IsUniCode,IsDND,Operator,Isallowdnd)              
     SELECT MessageID,BatchID,Mobile,[Message],SenderID,SmppID,U_ID, @Priority ,IsUniCode,IsDND,Operator,Isallowdnd              
     FROM ProcessTableFirst WHERE BatchID = @BatchID              
              
           DELETE FROM ProcessTableFirst WHERE BatchID = @BatchID              
         END              
         ELSE IF (@AllowDND = 0)              
         BEGIN              
            INSERT INTO MessageSource(MessageID,MessageBatchID,Mobile,[Message],SenderID, SmppID, U_ID, Priority,              
            IsUniCode,IsDND,Operator,Isallowdnd)              
            SELECT MessageID,BatchID,Mobile,[Message],SenderID,SmppID,U_ID, @Priority ,IsUniCode,IsDND,Operator,Isallowdnd              
            FROM ProcessTableFirst WHERE BatchID = @BatchID And IsDND = 0              
            --added by vinay to insert dnd number into MessageDND  
            INSERT INTO MessageDND(MessageID,BatchID,Mobile,[Message],SenderID, SmppID, U_ID, Priority,              
            IsUniCode,IsDND,Operator,Isallowdnd)              
            SELECT MessageID,BatchID,Mobile,[Message],SenderID,SmppID,U_ID, @Priority ,IsUniCode,IsDND,Operator,Isallowdnd              
            FROM ProcessTableFirst WHERE BatchID = @BatchID And IsDND = 1   
  
            DELETE FROM ProcessTableFirst WHERE BatchID = @BatchID               
