        END              
        ELSE IF (@ProcessTable = 2)              
        BEGIN               
         IF (@AllowDND = 1)              
         BEGIN              
     INSERT INTO MessageMonitor(MessageID,BatchID,Mobile,[Message],SenderID, SmppID, U_ID, Priority,              
     IsUniCode,IsDND,Operator,Isallowdnd)              
     SELECT MessageID,BatchID,Mobile,[Message],SenderID,SmppID,U_ID, @Priority ,IsUniCode,IsDND,Operator,Isallowdnd             
     FROM ProcessTableTwo WHERE BatchID = @BatchID              
              
           DELETE FROM ProcessTableTwo WHERE BatchID = @BatchID              
         END              
         ELSE IF (@AllowDND = 0)              
         BEGIN              
            INSERT INTO MessageSource(MessageID,MessageBatchID,Mobile,[Message],SenderID, SmppID, U_ID, Priority,              
   IsUniCode,IsDND,Operator,Isallowdnd)              
            SELECT MessageID,BatchID,Mobile,[Message],SenderID,SmppID,U_ID, @Priority ,IsUniCode,IsDND,Operator,Isallowdnd              
            FROM ProcessTableTwo WHERE BatchID = @BatchID And IsDND = 0              
            --added by vinay to insert dnd number into MessageDND  
            INSERT INTO MessageDND(MessageID,BatchID,Mobile,[Message],SenderID, SmppID, U_ID, Priority,              
            IsUniCode,IsDND,Operator,Isallowdnd)              
            SELECT MessageID,BatchID,Mobile,[Message],SenderID,SmppID,U_ID, @Priority ,IsUniCode,IsDND,Operator,Isallowdnd              
            FROM ProcessTableTwo WHERE BatchID = @BatchID And IsDND = 1   
  
            DELETE FROM ProcessTableTwo WHERE BatchID = @BatchID               
         END              
        END              
        ELSE IF (@ProcessTable = 3)              
        BEGIN               
         IF (@AllowDND = 1)              
         BEGIN              
     INSERT INTO MessageMonitor(MessageID,BatchID,Mobile,[Message],SenderID, SmppID, U_ID, Priority,              
     IsUniCode,IsDND,Operator,Isallowdnd)              
     SELECT MessageID,BatchID,Mobile,[Message],SenderID,SmppID,U_ID, @Priority ,IsUniCode,IsDND,Operator,Isallowdnd              
     FROM ProcessTableThree WHERE BatchID = @BatchID              
              
           DELETE FROM ProcessTableThree WHERE BatchID = @BatchID              
         END          
         ELSE IF (@AllowDND = 0)              
         BEGIN              
            INSERT INTO MessageSource(MessageID,MessageBatchID,Mobile,[Message],SenderID, SmppID, U_ID, Priority,              
   IsUniCode,IsDND,Operator,Isallowdnd)              
            SELECT MessageID,BatchID,Mobile,[Message],SenderID,SmppID,U_ID, @Priority ,IsUniCode,IsDND,Operator,Isallowdnd              
            FROM ProcessTableThree WHERE BatchID = @BatchID And IsDND = 0              
             --added by vinay to insert dnd number into MessageDND  
            INSERT INTO MessageDND(MessageID,BatchID,Mobile,[Message],SenderID, SmppID, U_ID, Priority,              
            IsUniCode,IsDND,Operator,Isallowdnd)              
            SELECT MessageID,BatchID,Mobile,[Message],SenderID,SmppID,U_ID, @Priority ,IsUniCode,IsDND,Operator,Isallowdnd              
            FROM ProcessTableThree WHERE BatchID = @BatchID And IsDND = 1   
  
            DELETE FROM ProcessTableThree WHERE BatchID = @BatchID               
         END              
        END              
  ELSE IF (@ProcessTable = 4)              
        BEGIN               
         IF (@AllowDND = 1)              
         BEGIN              
     INSERT INTO MessageMonitor(MessageID,BatchID,Mobile,[Message],SenderID, SmppID, U_ID, Priority,              
     IsUniCode,IsDND,Operator,Isallowdnd)              
     SELECT MessageID,BatchID,Mobile,[Message],SenderID,SmppID,U_ID, @Priority ,IsUniCode,IsDND,Operator,Isallowdnd              
     FROM ProcessTableFour WHERE BatchID = @BatchID              
              
           DELETE FROM ProcessTableFour WHERE BatchID = @BatchID              
         END              
         ELSE IF (@AllowDND = 0)              
         BEGIN              
            INSERT INTO MessageSource(MessageID,MessageBatchID,Mobile,[Message],SenderID, SmppID, U_ID, Priority,              
             IsUniCode,IsDND,Operator,Isallowdnd)              
            SELECT MessageID,BatchID,Mobile,[Message],SenderID,SmppID,U_ID, @Priority ,IsUniCode,IsDND,Operator,Isallowdnd              
            FROM ProcessTableFour WHERE BatchID = @BatchID And IsDND = 0              
             --added by vinay to insert dnd number into MessageDND  
            INSERT INTO MessageDND(MessageID,BatchID,Mobile,[Message],SenderID, SmppID, U_ID, Priority,              
            IsUniCode,IsDND,Operator,Isallowdnd)              
            SELECT MessageID,BatchID,Mobile,[Message],SenderID,SmppID,U_ID, @Priority ,IsUniCode,IsDND,Operator,Isallowdnd              
            FROM ProcessTableFour WHERE BatchID = @BatchID And IsDND = 1   
            DELETE FROM ProcessTableFour WHERE BatchID = @BatchID               
         END              
        END              
 if @@TRANCOUNT > 0 
commit ;         
end try 

begin catch 
if @@TRANCOUNT > 0 
rollback;       
exec usp_InsertErrorInfo      
END CATCH             
  END 




