/* ============================================================
   Procedure: [dbo].[Usp_insertDeliveryMails_WebFrom]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

        
CREATE   PROCEDURE [dbo].[Usp_insertDeliveryMails_WebFrom] (@entryid bigint, @Formid bigint,
@MailBody nvarchar(max) )                                               
AS                                                
  BEGIN             
 declare @userId bigint          
 declare @Isemail bit          
 declare @emailtemplateid bigint          
-- declare @MailBody nvarchar(max) ='';          
 declare @MailSubject nvarchar(max) ='';          
 select @userId =userId, @Isemail=Isemail, @emailtemplateid = emailtemplateid,            
@MailSubject = MailSubject          
 from webformtbl where formid=@Formid          
 if (@Isemail = 1)          
 begin          
  declare @batchid bigint             
  INSERT INTO Getbatchrecord(User_id,RandNum)                                                
  SELECT entryid, RAND()                                              
  FROM  WebentryTbl where entryid= @entryid           
  set @batchid=SCOPE_IDENTITY()          
          
  declare @ValidEntries int          
   SELECT @ValidEntries =                 
    CASE                                                
      WHEN Balance >0 THEN 1                                                
      ELSE 0 --test, otherwise 0                                                
    END                                                 
    FROM   (SELECT TOP 1 Balance, User_ID, Credits                                                
      FROM   Mailcreditdetails AS Mcd                                                
      WHERE  Mcd.[User_ID] = @userId                        
      ORDER  BY Credit_ID DESC) A             
            
  declare @SuperValidEntries int =0;          
  declare @Superuser_id bigint =0;          
  declare @HasVirtualCredits int =0;          
  declare @M_ID bigint = 0;          
  declare @usr_email as nvarchar(max) = '';          
        
          
  select @usr_email=Email, @M_ID = M_ID, @HasVirtualCredits = isnull(HasVirtualCredits,0) ,          
   @Superuser_id =ParentSuperResellerId           
  from User_detail where USER_ID = @userId --and HasVirtualCredits = 1          
  if (@HasVirtualCredits = 1)          
  begin           
   select @SuperValidEntries=  CASE                                                
        WHEN Balance > 0 THEN 1                                                
        ELSE 0  END            
   from User_detail ud          
   inner join dbo.SuperResellerMailCreditDetails sup          
   on sup.User_ID = ud.ParentSuperResellerId          
   where ud.USER_ID = @userId and HasVirtualCredits = 1          
  end           
  if (@ValidEntries = 1)          
  Begin          
   INSERT INTO Batchemail_infos(BatchID,UserID,SenderName,[Message],TotalRecords,TotalProcessed,          
    ProcessTable, IsProcess,Priority_Level,BatchInsertTime, BatchProcessTime,ScheduledDate,          
    ScheduledTime,TemplateID,[Route], PageName,IsScheduled,Email_Subject,ReplyTo)            
    SELECT @batchid,@userId,SenderEmail,MailBody,1,0,0,0,0,Getdate(),NULL,NULL,NULL,0,0,0,0,          
    MailSubject, ReplyEmail FROM webformtbl where formid=@Formid                
          
    declare @toEmail_Id varchar(max)= '';                  
    select @toEmail_Id =Email, @MailBody =mail_body from dbo.WebEntryTbl where EntryId=@EntryId          
    declare @TempName varchar(max) = '';          
    --if (@emailtemplateid > 0)          
    --select @MailSubject = MailSubject, @MailBody = MailContent, @TempName =Name          
    --  from UserMailTemplate where ID = @emailtemplateid          
          
    create table #output (GUID nvarchar(100) collate SQL_Latin1_General_CP1_CI_AS ,Formid bigint)      INSERT INTO Clientemails (GUID,Email_Id,SentDateTime,UserId,ReplyTo,[Status],BatchID,          
    [Message],parentid)             
    OUTPUT inserted.GUID  as GUId, @Formid  as Formid INTO #output                        
    SELECT Newid(), @toEmail_Id,Getdate(), EmailAccountName,ReplyEmail,          
     '',@batchid,@MailBody, ParentID                     
    FROM   WebFormTbl where formid=@Formid          
    if (@HasVirtualCredits =1 and @SuperValidEntries = 1)  or           
   (@HasVirtualCredits =0 and @ValidEntries = 1)                      
    BEGIN          
    INSERT INTO Emailsfilter                                               
        (Mail_GUID,                                               
         Mail_FromEmail,                                                
         Mail_ToEmail,                     
         Mail_Subject,                                                
         Messages,                                                
         Mail_InsertedDate,               
         Mail_UserID,                                                
         ReplyTo,                                                
         Mail_BatchID,                                                
         Mail_Priority,                                                
         Mail_ScheduleDate,                                                
         Mail_Attechement,                                                
         Mail_TempleteBody,                                                
         IsMonitor)                                                
    SELECT O.Guid,                                                
      @usr_email, -- emailid from user details                                          
      @toEmail_Id,                    
      @MailSubject,                                             
      @MailBody,                                              
      getdate(),           
       EmailAccountName ,                                             
      ReplyEmail,                                                
      @batchid,                                                
      1,getdate(),                                                
      '',                                                
      @MailBody,  ---cast(Efce.Mail_TempleteBody as nvarchar(max)),          
      1 AS Limit                                                
    FROM   WebFormTbl AS Efce                                                
      inner join #output o on o.Formid=Efce.Formid                                             
    WHERE  Efce.formid=@Formid             
    END          
    if (@HasVirtualCredits =1 and @SuperValidEntries = 0)                                                   
     INSERT INTO EmailsfilterVirtual                                               
        (Mail_GUID,                                                
           Mail_FromEmail,                                                
           Mail_ToEmail,                                                
           Mail_Subject,                                                
           Messages,                                                
           Mail_InsertedDate,               
           Mail_UserID,                                                
           ReplyTo,                                                
           Mail_BatchID,                                                
           Mail_Priority,                                                
           Mail_ScheduleDate,                                                
           Mail_Attechement,                                                
           Mail_TempleteBody,                                                
           IsMonitor)                                                
       SELECT O.Guid,                                                
        @usr_email, -- emailid from user details                                          
        @toEmail_Id,                    
        @MailSubject,                                             
        @MailBody,                                              
        getdate(),           
         EmailAccountName ,                                             
        ReplyEmail,                                                
        @batchid,     
        1,getdate(),                                                
        '',                                                
        @MailBody,  ---cast(Efce.Mail_TempleteBody as nvarchar(max)),          
        1 AS Limit           
       FROM   WebFormTbl AS Efce                                                
        inner join #output o on o.Formid=Efce.Formid                                             
       WHERE  Efce.formid=@Formid          
                      
       truncate table #output           
       DELETE Kd                                     
       FROM   Getbatchrecord Kd                                                
        where BatchID = @BatchID               
                                                    
       INSERT INTO Mailcreditdetails                
        (ID,                                                
         M_ID,                                                
         FromUser_ID,                                                
         [User_ID],                                                
         Debits,                                               Credits,                                                
       Balance,                                                
         Validity,                                                
         Default_Credit,                                                
         FromDate,                                                
         ToDate,                                                
         DateCreated,                                                
         DateUpdated,                                                
        EmpUpdated,                                                
         MachineName,                                                
         LastModified,                                    
         typecredit,              
         campaignid)                                                
       SELECT Newid(),@M_ID,                                                
       @UserID,                                                
       @UserID,                                                
       1,                                                
       0,                                                
       (SELECT TOP 1 Mcd.Balance                                                
        FROM   Mailcreditdetails AS Mcd                                                
        WHERE  Mcd.[User_ID] = @UserID ORDER BY Mcd.Credit_ID DESC) - 1,           
        99999,  '',                                                
       Getdate(),                                                
       Getdate(),                                                
       Getdate(),                                                
       Getdate(),                                                
       '',                                                
       '',                                                
       Getdate(),                                       
       '',              
       EmailCampaignId --Campaignid                                                
       FROM   WebFormTbl WHERE  formid=@Formid          
       if (@HasVirtualCredits =1 and @SuperValidEntries = 1)            
       INSERT INTO SuperresellerMailcreditdetails                                                
        (ID,                                                
         M_ID,                                                
         FromUser_ID,                                                
         [User_ID],                                                
         Debits,                                                
       Credits,                                                
       Balance,                                                
         Validity,                                                
         Default_Credit,                                                
         FromDate,                                                
    ToDate,                                                
         DateCreated,                                                
         DateUpdated,                                                
        EmpUpdated,                                                
         MachineName,                                                
         LastModified,                                               
         typecredit,              
         campaignid)                                                
       SELECT Newid(),                                                
        (SELECT TOP 1 Ud.M_ID                                                
         FROM   User_detail AS Ud                                                
         WHERE  Ud.[User_ID] = @Superuser_id),                                  
        @Superuser_id,                                                
        @Superuser_id,                        
       1,                                                
        0,                                                
        (SELECT TOP 1 Mcd.Balance                                                
         FROM   SuperResellerMailCreditDetails AS Mcd                                                
         WHERE  Mcd.[User_ID] = @Superuser_id                                                
         ORDER  BY Mcd.Credit_ID DESC) -1,                                                
        99999,                                                
       '',                                                
        Getdate(),                                                
        Getdate(),                       
        Getdate(),                                                
        Getdate(),                                                
        '',                                                
        '',                                                
        Getdate(),                                       
        '',              
        EmailCampaignId                                                
       FROM   WebFormTbl WHERE  formid=@Formid          
                              
  end          
 end          
  end


GO

