         Mail_Subject,                                                
         Messages,                                                
         Mail_InsertedDate,               
         Mail_UserID,                                                
         ReplyTo,                                                
         Mail_BatchID,                                                
         Mail_Priority,                                                
         Mail_ScheduleDate,                                                
         Mail_Attechement,                                                
         Mail_TempleteBody,                                                
         IsMonitor)                                                
    SELECT O.Guid,                                                
      @usr_email, -- emailid from user details                                          
      @toEmail_Id,                    
      @MailSubject,                                             
      @MailBody,                                              
      getdate(),           
       EmailAccountName ,                                             
      ReplyEmail,                                                
      @batchid,                                                
      1,getdate(),                                                
      '',                                                
      @MailBody,  ---cast(Efce.Mail_TempleteBody as nvarchar(max)),          
      1 AS Limit                                                
    FROM   WebFormTbl AS Efce                                                
      inner join #output o on o.Formid=Efce.Formid                                             
    WHERE  Efce.formid=@Formid             
    END          
    if (@HasVirtualCredits =1 and @SuperValidEntries = 0)                                                   
     INSERT INTO EmailsfilterVirtual                                               
        (Mail_GUID,                                                
           Mail_FromEmail,                                                
           Mail_ToEmail,                                                
           Mail_Subject,                                                
           Messages,                                                
           Mail_InsertedDate,               
           Mail_UserID,                                                
           ReplyTo,                                                
           Mail_BatchID,                                                
           Mail_Priority,                                                
           Mail_ScheduleDate,                                                
           Mail_Attechement,                                                
           Mail_TempleteBody,                                                
           IsMonitor)                                                
       SELECT O.Guid,                                                
        @usr_email, -- emailid from user details                                          
        @toEmail_Id,                    
        @MailSubject,                                             
        @MailBody,                                              
        getdate(),           
         EmailAccountName ,                                             
        ReplyEmail,                                                
        @batchid,     
        1,getdate(),                                                
        '',                                                
        @MailBody,  ---cast(Efce.Mail_TempleteBody as nvarchar(max)),          
        1 AS Limit           
       FROM   WebFormTbl AS Efce                                                
        inner join #output o on o.Formid=Efce.Formid                                             
       WHERE  Efce.formid=@Formid          
                      
       truncate table #output           
       DELETE Kd                                     
       FROM   Getbatchrecord Kd                                                
        where BatchID = @BatchID               
                                                    
       INSERT INTO Mailcreditdetails                
        (ID,                                                
         M_ID,                                                
         FromUser_ID,                                                
         [User_ID],                                                
         Debits,                                               Credits,                                                
       Balance,                                                
         Validity,                                                
         Default_Credit,                                                
         FromDate,                                                
         ToDate,                                                
         DateCreated,                                                
         DateUpdated,                                                
        EmpUpdated,                                                
         MachineName,                                                
         LastModified,                                    
         typecredit,              
         campaignid)                                                
       SELECT Newid(),@M_ID,                                                
       @UserID,                                                
       @UserID,                                                
       1,                                                
       0,                                                
       (SELECT TOP 1 Mcd.Balance                                                
        FROM   Mailcreditdetails AS Mcd                                                
        WHERE  Mcd.[User_ID] = @UserID ORDER BY Mcd.Credit_ID DESC) - 1,           
        99999,  '',                                                
       Getdate(),                                                
       Getdate(),                                                
       Getdate(),                                                
       Getdate(),                                                
       '',                                                
       '',                                                
       Getdate(),                                       
       '',              
       EmailCampaignId --Campaignid                                                
       FROM   WebFormTbl WHERE  formid=@Formid          
       if (@HasVirtualCredits =1 and @SuperValidEntries = 1)            
       INSERT INTO SuperresellerMailcreditdetails                                                
        (ID,                                                
         M_ID,                                                
         FromUser_ID,                                                
         [User_ID],                                                
         Debits,                                                
       Credits,                                                
       Balance,                                                
         Validity,                                                
         Default_Credit,                                                
         FromDate,                                                
    ToDate,                                                
         DateCreated,                                                
         DateUpdated,                                                
        EmpUpdated,                                                
         MachineName,                                                
         LastModified,                                               
         typecredit,              
         campaignid)                                                
       SELECT Newid(),                                                
        (SELECT TOP 1 Ud.M_ID                                                
         FROM   User_detail AS Ud                                                
         WHERE  Ud.[User_ID] = @Superuser_id),                                  
        @Superuser_id,                                                
        @Superuser_id,                        
       1,                                                
        0,                                                
        (SELECT TOP 1 Mcd.Balance                                                
         FROM   SuperResellerMailCreditDetails AS Mcd                                                
         WHERE  Mcd.[User_ID] = @Superuser_id                                                
         ORDER  BY Mcd.Credit_ID DESC) -1,                                                
        99999,                                                
       '',                                                
        Getdate(),                                                
        Getdate(),                       
        Getdate(),                                                
        Getdate(),                                                
        '',                                                
        '',                                                
        Getdate(),                                       
        '',              
        EmailCampaignId                                                
       FROM   WebFormTbl WHERE  formid=@Formid          
                              
  end          
 end          
  end


GO

/* ============================================================
   Procedure: [dbo].[Usp_insertDeliverySMS_WebFrom]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE [dbo].[Usp_insertDeliverySMS_WebFrom]   
(@entryid bigint, @Formid bigint,  
@smsbody varchar(max))                                               
AS                                                
  BEGIN          
 declare @userId bigint          
 declare @Issms bit          
 declare @smstemplateid bigint =0          
 --declare @smsbody nvarchar(max) ='';          
 declare @MailSubject nvarchar(max) ='';
 declare @DLTTemplateID nvarchar(200) = ''
           
 select @userId =userId, @Issms=Issms, @smstemplateid = smstemplateid,          
   @MailSubject = MailSubject, @DLTTemplateID = isnull(DLTTemplateID,'')          
   from webformtbl with (nolock) where formid=@Formid          
 if (@Issms = 1)          
      BEGIN          
  declare @batchid bigint            
  INSERT INTO Getbatchrecord(User_id,RandNum)                                                
  SELECT entryid, RAND()                                              
  FROM  WebentryTbl where entryid= @entryid           
  set @batchid=SCOPE_IDENTITY()          
  --- Calculate credits                                                
            
  declare @ValidEntries int          
  SELECT @ValidEntries =           
  (CASE WHEN Balance > 0 THEN 1  ELSE 0 END)                                               
  FROM   (SELECT TOP 1 Balance                                                
     FROM   credit_details AS Mcd                                                
     WHERE  Mcd.[User_ID] = @userId                         
     ORDER  BY Credit_ID DESC) A          
          
  declare @SuperValidEntries int =0;          
  declare @Superuser_id bigint =0;          
  declare @HasVirtualCredits int =0;          
  declare @M_ID bigint = 0;          
  declare @SmppID bigint = 0;          
  declare @usr_email as nvarchar(max) = '';          
  select @usr_email=Email, @M_ID = M_ID, @HasVirtualCredits = isnull(HasVirtualCredits,0) ,          
   @Superuser_id =ParentSuperResellerId, @SmppID= SmppID           
  from User_detail where USER_ID = @userId and HasVirtualCredits = 1          
  if (@HasVirtualCredits = 1)          
  BEGIN          
   SELECT @SuperValidEntries = (CASE WHEN Balance >0 THEN 1   ELSE 0 END)          
   FROM  (SELECT TOP 1 Balance FROM SuperResellerCredit_Details AS Mcd           
    WHERE  Mcd.[User_ID] = @Superuser_id                       
    ORDER  BY Credit_ID DESC) AS A           
  end          
  declare @toMobile varchar(max)= '';                  
    select @toMobile =Mobile from dbo.WebEntryTbl where EntryId=@EntryId          
  --if (@smstemplateid > 0)          
  --begin          
  --  select @MailSubject = MailSubject, @smsbody = MailContent          
  --    from UserMailTemplate where ID = @smstemplateid          
              
    INSERT INTO clonemessagedeliverystatus ( batchid,mobile,[message],messagestatus,senderid,          
      messageinsertdate,scheduleddate,scheduledtime,smppid,u_id,isunicode,isdnd,isairtel,          
      mobilesubset,validno,isprority,isallowdnd,dbtype,campaignid,hasvirtualcredits,          
      HasSufficientVirtualCredits )                        
              
    SELECT @batchid,                            
     @toMobile, --Userentry mobile no                           
     @smsbody,                            
     '',                            
     SenderEmail, --Ucerm.senderid,                            
     GETDATE(),                            
     '',                            
     '',                            
     @SmppID,                            
     Ucerm.SmsAccountName,  -- field                          
     IsUniCode,                            
     0, ---field                           
     0, --Ucerm.isairtel,  ---field                             
     0, --Ucerm.mobilesubset, ---field                            
     0, --Ucerm.validno,     ---field                        
     1, ---Ucerm.isprority,                            
     0, --Ucerm.isallowdnd,  ---field                           
     0, --Ucerm.dbtype, ---field          
     '',          
     @HasVirtualCredits,  --hasvirtualcredits,          
     @SuperValidEntries --HasSufficientVirtualCredits           
                 
    FROM   webformtbl Ucerm where formid=@Formid           
     
	 insert into DLT_Template_MSG(BatchID,DLT_TemplateID,DLT_MSG_CreatedOn)
	                             values(@batchid,@DLTTemplateID,getdate()) 
	            
                
       DELETE Kd                                                
       FROM   Getbatchrecord Kd              
        where BatchID = @BatchID             
                  
  --END          
              
      END          
                
  END


GO

