   Procedure: [dbo].[usp_InsertDemoRequestDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_InsertDemoRequestDetails] -- 'Me','karuna@pelsoftlabs.in',null,null,null,null                 
(                  
   @Name nvarchar(200),                  
   @Email nvarchar(200),                
   @CountryCode nvarchar(10),                  
   @PhoneNo nvarchar(50),                
   @CompanyName nvarchar(200),                  
   @Description nvarchar(500),  
   @RequestUrl nvarchar(max)  
)                  
as                   
Begin                  
declare @did bigint      
    
  insert into DemoEnquiry(Name,Email,CountryCode,PhoneNo,CompanyName,Description,EntryDate,RequestUrl) values(@Name,@Email,@CountryCode,@PhoneNo,@CompanyName,@Description,GETDATE(),@RequestUrl)                  
  select 'Inserted Successfully'              
  select @did=SCOPE_IDENTITY()            
            
 if @name not like '%aYlNlfdX%'    
begin --Start Request Demo          
     exec UspRequestDemoLeadList @Name,@Email,@CountryCode,@PhoneNo,@CompanyName,@Description           
  --End Request Demo          
    declare @descrip nvarchar(1000)='New Demo request received. Details : Name- '+isnull(@Name,'')+', Email- '+isnull(@Email,'')+', Mobile- '+cast(isnull(@CountryCode,'') as nvarchar)+'-'+      
 cast(isnull(@PhoneNo,'') as nvarchar)+', Company- '+isnull(@CompanyName,'')+', Description- '+isnull(@Description     ,'')+ ', from url: '+isnull(@RequestUrl,'')      
 exec Usp_InsertUserEventDetails 'User Requested demo',0,@descrip,'DemoEnquiry',@did,'Mobile',@phoneno      
              
  begin tran              
  declare @batchid bigint              
  insert into GetBatchRecord(User_id,RandNum)              
  select 335,335              
  select @batchid=scope_identity()              
  commit              
            
 --select  newid(),'contactus@kit19.com',d.Email,'Your Request for Kit19 demo',1,REPLACE(n.content,'#name#',isnull(d.name,'')) ,getdate(),335,335,'contactus@kit19.com',2,getdate(),getdate(),1,0,1,'RequestDemo' from demoenquiry d join notifications        
  
    
     
--n on 1=1 where d.id=1 and n.id=6 and isnull(email,'') <>''              
                
declare @subject nvarchar(100),@message nvarchar(max),@email2 nvarchar(100)            
select @subject='Your Request for Kit19 demo',@message=REPLACE(n.content,'#name#',isnull(d.name,'')),@email2=d.email from notifications(nolock) n 
join demoenquiry d on 1=1 where n.ID=6 and d.id=@did and isnull(email,'') <>''            
            
if isnull(@email  ,'')<>''            
begin            
INSERT INTO Batchemail_infos(BatchID,UserID,SenderName,[Message],TotalRecords,TotalProcessed,ProcessTable,IsProcess,Priority_Level,BatchInsertTime,                    
BatchProcessTime,ScheduledDate,ScheduledTime,TemplateID,[Route],PageName,IsScheduled,Email_Subject,ReplyTo,ispersonalized,mail_source        
,bmonitor)                    
SELECT @batchid,335,'contactus@kit19.com' as SenderName,@message,1,0,0,0,2,Getdate(),NULL,NULL,NULL,                  
   0,0,0,0,@subject,'contactus@kit19.com',1,'Demo Enquiry',1            
               
               
create table #output (GUID nvarchar(100) collate SQL_Latin1_General_CP1_CI_AS ,Email nvarchar(200) collate SQL_Latin1_General_CP1_CI_AS,Batchid bigint)                          
                    
INSERT INTO Clientemails                                                          
                  (                                          
      -- Id -- this column value is auto-generated                                                          
      GUID,                                                          
                   Email_Id,                                                          
                   SentDateTime,                                                          
                   UserId,                                                          
                   ReplyTo,                                              
                   [Status],                                                          
                   BatchID,                                     
                   [Message],                      
                   parentid)                       
      OUTPUT inserted.GUID  as GUId,inserted.email_id as Email,inserted.batchid INTO #output                                                             
      SELECT Newid(),                                                   
             @email2,                                                          
             Getdate(),                                                          
             335,                                                          
             'contactus@kit19.com',                                                          
             '',                                                          
             @BatchID,                                                  
             @message,                      
          335                   
                                                                   
                                                          
      INSERT INTO Emailsfilter                                                 
                  (Mail_GUID,                                                          
                   Mail_FromEmail,                                                          
                   Mail_ToEmail,                                                          
                Mail_Subject,                                                          
                   Mail_TempleteName,                                                          
                   Messages,                                                          
                   Mail_InsertedDate,                         
                   Mail_UserID,                                                          
                   ReplyTo,                                                          
                   Mail_BatchID,                                                          
                   Mail_Priority,                                                          
                   Mail_ScheduleDate,                                                          
                   Mail_Attechement,                                                          
                   Mail_TempleteBody,                                                          
                   IsMonitor)                                                          
      SELECT O.Guid,                              
             'contactus@kit19.com',                                              
             @Email2,                                                          
             @subject,                                                        
             '',                                                          
             @message,                                                  
             getdate(),                                                          
             335,                                                          
             'contactus@kit19.com',                                                          
             @BatchID,                                                          
             2,                                                          
             getdate(),                                                          
             '',                                                          
             @message,                                                          
             1 AS Limit                                                          
      from #output o                 
                        
--select * from emailsfilter where mail_batchid=30089968                  
      INSERT INTO Mailcreditdetails                                           
                  (ID,                             
                   -- Credit_ID -- this column value is auto-generated                                                          
     M_ID,                                                          
                   FromUser_ID,                                                          
                   [User_ID],                                                          
                   Debits,                                                          
                 Credits,                                                          
                 Balance,                                                          
                   Validity,                                                    
                   Default_Credit,                                                          
                   FromDate,                                                          
                   ToDate,                                                          
                   DateCreated,                                                          
                   DateUpdated,                                                          
               EmpUpdated,                                                          
                   MachineName,                                                          
       LastModified,                                              
                   typecredit)                                                          
      SELECT Newid(),                                                          
             (SELECT TOP 1 Ud.M_ID                              
              FROM   User_detail AS Ud                                                          
   WHERE  Ud.[User_ID] = 335),                                                          
             335,                                                          
             335,                                                          
             1,                                                          
    0,                                                          
             (SELECT TOP 1 Mcd.Balance                                                          
              FROM   Mailcreditdetails AS Mcd                                                          
              WHERE  Mcd.[User_ID] = 335                                                          
              ORDER  BY Mcd.Credit_ID DESC) - 2,                                                          
             99999,                                                          
       '',                                                          
             Getdate(),                                                          
             Getdate(),                                                          
             Getdate(),                                                          
             Getdate(),                                                          
             '',                                                          
             '',                                                          
             Getdate(),                                                 
             ''                  
end                
               
               
     end               
End   


GO

