CREATE   PROCEDURE dbo.usp_InsertDetailsM_Couponwith_int                        
 @CouponCode VARCHAR(100),                        
 @Route VARCHAR(50),                        
 @MinVolume BIGINT,                        
 @MaxVolume BIGINT,                        
 @Validity INT,                        
 @ValidFrom DATETIME,                        
 @ValidTo DATETIME,                        
                     
 @Discount VARCHAR(50),                        
                     
 @Status TINYINT,                        
 @Remarks VARCHAR(750),                        
 @CreatedBy BIGINT,                        
 @SavedSearch VARCHAR(1000),                    
 @MinMailVolume Bigint,                    
 @MaxMailVolume Bigint,                    
 @SMSCredits varchar(50),                    
 @MailCredits varchar(50),                    
 @IsAmount Bit,                    
 @IsSMSCredit Bit,                    
 @IsMailCredit Bit,            
 @IsIntCredit Bit,            
 @IntSmsCredit varchar(50),             
 @MinIntVolume bigint,            
 @MaxIntVolume bigint,        
 @IsSMS BIT,                      
 @IsMail BIT,        
 @isintsms  BIT, @iscloud  bit ,  
  @tbl tbl_Cloud_Plan_Coupen READONLY                       
             
AS                        
BEGIN             
                   
 INSERT INTO M_Coupon                        
   (                        
     -- ID -- this column value is auto-generated                              
     CouponCode,                        
     [Route],                        
     MinVolume,                        
     MaxVolume,                        
     Validity,                        
     ValidFrom,                        
     ValidTo,                        
     Discount,                        
     [Status],                        
     Remarks,                        
     SavedSearch,                      
     DateCreated,                        
     CreatedBy,                        
     ModifiedOn,                        
     ModifiedBy ,                     
     MinMailVolume ,                    
     MaxMailVolume ,                    
     SMSCredits ,                    
     MailCredits ,                    
     IsAmount ,                    
     IsSMSCredit ,                    
     IsMailCredit,            
     IsIntSMSCredit ,            
     IntSmsCredit, MinIntVolume, MaxIntVolume ,      
     IsSMS,                      
     IsMail,         
     isintsms,         
     iscloud                   
            
   )                        
 VALUES                        
   (                        
     @CouponCode,                        
     @Route,                        
     @MinVolume,                        
     @MaxVolume,                        
     @Validity,                        
     @ValidFrom,                        
     @ValidTo,                        
     @Discount,                        
     @Status,                        
     @Remarks,                        
     @SavedSearch,                      
     --@IsSMS,                      
    -- @IsMail,                        
     GETDATE(),                        
     @CreatedBy,                        
     GETDATE(),                        
     @CreatedBy,                    
     @MinMailVolume ,                    
     @MaxMailVolume ,                    
     @SMSCredits ,                    
     @MailCredits ,                    
     @IsAmount ,                    
     @IsSMSCredit ,                    
     @IsMailCredit,            
     @IsIntCredit,             
     @IntSmsCredit, @MinIntVolume, @MaxIntVolume,        
     @IsSMS,                      
     @IsMail,         
     @isintsms,         
     @iscloud                        
   )                              
       
 if (select COUNT(*) from @tbl) > 0  
 begin  
   
 insert into dbo.Cloud_Plan_Coupen(CoupenCode, Planid)       
 select CoupenCode, Planid from @tbl    
 end            
                         
 SELECT 'Successfully Inserted'   
END 


