 ,[createdby] 
 ,[Activestatus] 
 ,[expirydate] 
 ,[remarks] 
 ,[EntityName] from dltdetails with(nolock) where id=@dltid 
 
 end try 
 begin catch 
 exec usp_inserterrorinfo 
 end catch 
 */
 
end 
else 
begin 
Select 'Parentid does not exist' 
end 
end 
else 
begin 
select 'Entity already exists' 
end 
end




