/* ============================================================
   Procedure: [dbo].[usp_InsertDomainVerification]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_InsertDomainVerification    
    @userid BIGINT,    
    @domain NVARCHAR(200) = NULL,  -- Optional, default NULL    
    @createdby BIGINT,    
  @domaintype NVARCHAR(50) = NULL    
AS    
BEGIN    
    -- Declare variables    
    DECLARE @record_value NVARCHAR(256);    
    DECLARE @exists INT;    
    
    -- Start of TRY block    
    BEGIN TRY    
        -- Check if a record already exists for the given userid and domain    
        SELECT @exists = COUNT(1)    
        FROM tbl_pt_DomainVerification with(nolock)    
        WHERE userid = @userid    
          AND (dbo.fn_removewww(domain) = dbo.fn_removewww(@domain) OR @domain IS NULL) and DomainType=@domaintype;     
    
        IF (@exists > 0)    
        BEGIN    
            -- If a record exists, return a status message    
            SELECT 'Record already exists for the given UserID and Domain.' AS Message;    
            RETURN;    
        END    
    
        -- Generate a GUID and concatenate it with the prefix 'kit19_'    
        SET @record_value = 'TXT_' + CAST(NEWID() AS NVARCHAR(50));    
    
        -- Ensure the record_value is exactly 256 characters    
        SET @record_value = LEFT(@record_value, 256); -- Trim to 256 characters if the GUID exceeds the length    
    
        -- Insert the data into tbl_pt_DomainVerification    
        INSERT INTO tbl_pt_DomainVerification (userid, domain, record_value, createdby,DomainType)    
        VALUES (@userid, dbo.fn_removewww(@domain), @record_value, @createdby,@domaintype);    
    
        -- Optionally, return the newly inserted ID and record_value    
        SELECT SCOPE_IDENTITY() AS [NewID];    
    
    -- End of TRY block    
    END TRY    
    
    -- Start of CATCH block    
    BEGIN CATCH    
        -- Log the error using a predefined error logging procedure    
        EXEC usp_InsertErrorInfo;    
    END CATCH    
END;


GO

