   Procedure: [dbo].[usp_InsertEmail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_InsertEmail  
 @Mail_BatchId bigint,  
 @BaseTable varchar(100),  
 @Email dbo.Email READONLY,
 @CampaignId bigint=0  
AS  
BEGIN  
 Declare @StrQuery nvarchar(max)='',@p_id bigint, @Source varchar(100)='Campaign : ' + cast(@CampaignId as varchar) 
  
 select top 1 @p_id=Mail_ParentID from @Email  
  
 If(isnull(@BaseTable,'')='')  
 Begin  
  Drop table if exists #clonet  
    
  CREATE TABLE #clonet  
  (  
   [tablename] NVARCHAR(100)  
  );  
  
  INSERT INTO #clonet([tablename])  
  EXEC [usp_CreateCloneEmailTable111_New] @p_id;  
  SELECT TOP 1 @BaseTable=[tablename] FROM #clonet;    
 End  
  
 Set @StrQuery =concat( N'INSERT INTO ',@BaseTable,N'(Mail_FromEmail,Mail_ToEmail,Mail_Subject,Mail_TempleteName,Messages,Mail_InsertedDate,Mail_UserID,Mail_ParentID,ReplyTo,Mail_BatchID,Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime,Mail_Attechement,
Mail_TempleteBody,IsMonitor,TemplateID,Count,Source,mailroute)   
     SELECT Mail_FromEmail,Mail_ToEmail,Mail_Subject,Mail_TempleteName,Messages,Mail_InsertedDate,Mail_UserID,Mail_ParentID,ReplyTo,',@Mail_BatchId,' as Mail_BatchID,Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime,Mail_Attechement,Mail_TempleteBody,IsMonitor,TemplateID,Count,',@Source,' as Source,mailroute  
     FROM @p2')  
  
  print concat('@BaseTable: ',@BaseTable)  
  print @StrQuery  
  Exec sp_ExecuteSql @StrQuery,N'@p2 dbo.Email READONLY',@p2=@Email  
END  



