 @ReplyEmail nvarchar (max) = '',                                    
 @MailSubject nvarchar (max) = '',                                    
 @MailBody nvarchar (max) = '',                                    
 @Isemail bit  = false,                                    
 @isEnquiry bit  = false,      
 @emailtemplate bit = 0,                                   
 @emailtemplateid bigint = 0,                                         
 @CreatedBy bigint = null                              
)                                                           
                                                            
as                                     
                                    
Begin                                
 declare @oldissms bit,@oldismail bit, @oldisenq bit, @oldsmstemplateid bigint,      
  @oldemailtemplateid bigint, @oldSmsCampaignId bigint,@oldEmailCampaignId bigint      
  declare @sourceId bigint=0;                          
  declare @mediumId bigint =0;                          
  declare @SmsCampaignId bigint=0;                          
  declare @emailcampaignid bigint =0;        
        
  select @oldissms =Issms ,@oldismail = Isemail, @oldisenq= isEnquiry,      
  @oldsmstemplateid = smstemplateid, @oldemailtemplateid = emailtemplateid,       
  @oldSmsCampaignId =SmsCampaignId,@oldEmailCampaignId = EmailCampaignId,      
  @sourceId=sourceid, @mediumId=mediumid, @SmsCampaignId =SmsCampaignId,                          
  @emailcampaignid = EmailCampaignId      
  from WebFormTbl  where FormId= @FormId                              
      
  update WebFormTbl set FilePath=@FilaePath ,FormName=@FormName ,             
  EmailAccountName = @EmailAccountName ,ReplyEmail=@ReplyEmail,      
  MailSubject=@MailSubject ,MailBody=@MailBody,UserID = @UserID ,               
  Isemail=@Isemail ,isEnquiry=@isEnquiry , CreatedBy =@CreatedBy,                          
  emailtemplate=@emailtemplate, emailtemplateid=@emailtemplateid             
  where FormId= @FormId           
  
 if @oldisenq = 0 and @isEnquiry = 1      
  begin      
  if @Isemail <>0 
            
  exec [Usp_InsertPreDefinedUserCampaignMaster_NEW]  @PrentId,@UserID,@FormId,@FormName,'',      
  0,@ReplyEmail,@MailSubject,@MailBody,'',0,@IsEmail,'',      
  @EmailAccountName,0,@eMailtemplateid, 'Web Form' 
      
  end      
 if  @oldisenq = 1 and @isEnquiry = 0      
  begin      
   --if @mediumId > 0                          
   -- update UserMediumSettings set IsActive = 0 where mediumId = @MediumID      
   if @emailcampaignid > 0                           
    Update UserCampaignMaster set IsActive = 0 where ID = @emailcampaignid                            
  end           
 if @oldismail =1 and @Isemail =0      
   Update UserCampaignMaster set IsActive = 0 where ID = @emailcampaignid      
  if @oldismail =0 and @Isemail =1      
   exec [Usp_InsertPreDefinedUserCampaignMaster_NEW]  @PrentId,@UserID,@FormId,@FormName,'',      
     0,@ReplyEmail,@MailSubject,@MailBody,'',0,@IsEmail,'',      
     @EmailAccountName,0,@eMailtemplateid, 'Web Form'          
  if @oldismail =1 and @Isemail =1      
  begin 
   
        
   Update  UserCampaignMaster set IsEventBased=1,IsScheduled=0,ExclusionsNumber='',       
    Exclusions='',InclusionsNumber='',AccountUsed=@EmailAccountName,      
    TemplateID=case when isnull(@eMailtemplateid,0)=0 then 0 else @eMailtemplateid end,       
    TemplateGroupID=0, Medium='Mail',MailReplyTo=@ReplyEmail,      
    MailSubject=@MailSubject,MailContent=@MailBody,TrackResponse='',TrackShortURL='',      
  UnsubscribePage='',UnsubscribeShortURL='',Tags='',IsRunAfter=0,      
    IsSchedule=0, ScheduleID=0,ExecutedDateTime=GETDATE(),NextExecuteDateTime=GETDATE(),      
    IsActive=1,CreatedOn=GETDATE(),Createdby=@PrentId,ModifiedOn=GETDATE(),ModifiedBy=0,      
    StartDate=GETDATE()-1,ExpiryDate=GETDATE(),EventsName='',ApplicabiltyGroupList='',      
    ExclusionsGroupList='',NotificationMail='',SuccessNotificationEmail='',FailureNotificationEmail='',      
    IsRecurring=0, IsEnding=0, TemplateGroupSequence=0, IsNeverExpire=1,      
    RunAtHours='',RunAtMin='',IsSurplusExclusions=0       
    where  ID = @emailcampaignid      
  end   
    
  select 'Saved'     
end 


GO

