/* ============================================================
   Procedure: [dbo].[usp_insertenagagementactivity]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_insertenagagementactivity]
@activityid bigint,@entity nvarchar(20)
as
begin
DECLARE @sqlquery NVARCHAR(MAX);
declare @eventid int,@reftables nvarchar(250),@refid nvarchar(100),@cust_sql nvarchar(max),@event_time datetime,
@batchtable nvarchar(100)
if @entity='lead'
select @eventid=eventid,@reftables=reftables,@refid=refids,@event_time=EventDate from tbl_leadeventhistory(nolock) where historyid=@activityid
else if @entity='enquiry'
select @eventid=eventid,@reftables=reftables,@refid=refids,@event_time=EventDate from tbl_enquiryeventhistory(nolock) where historyid=@activityid

declare @channel varchar(50),@profile_id nvarchar(500),@batchid bigint,@customid bigint,@cust_var nvarchar(1000),
@cust_var2 nvarchar(1000),@engagement_type varchar(50)

select @channel=case when @eventid in (2,112) then 'SMS' 
when @eventid in (4,5,57,58,114,115) then 'Mail'
when @eventid in (8,118,132,133) then 'Call' 
when @eventid in (99,100,103,104,129,130) then 'Whatsapp' end

begin try
if @channel is not null
begin
if @channel='SMS' and @reftables='Link_smstrack'
begin
select @profile_id=mobile,@customid=link_id,@engagement_type='Clicked link',@batchtable='batchinfo' from Link_smstrack(nolock) where trackid=@refid
select @batchid=batchid from link_smsmobile(nolock) where mobile_url_id=@customid
end
else if @channel='Mail'
begin
select @batchtable='batchemail_infos'
if @reftables='EmailOpenTracker'
begin
select @batchid=batch_id,@cust_var=mail_guid,@engagement_type='Opened mail' from EmailOpenTracker(nolock) where id=@refid
select profile_id=email_id from clientemails(nolock) c where BatchID=@batchid and cast(c.guid as nvarchar(100))=@cust_var
end
else if @reftables='EngagementEventOpenclick'
begin
select @batchid=batchid,@profile_id=to_email,@engagement_type=case when action_type='Open' then 'Opened Mail' else 'Clicked link' end from EngagementEventOpenclick(nolock) where id=@refid
end
else if @reftables='Mysmst.dbo.tbl_email'
begin
select @profile_id=fromaddr,@engagement_type='Replied' from Mysmst.dbo.tbl_email(nolock) where id=@refid
end
end
else if @channel='Call'
begin
select @batchtable='batchevoiceinfo'

if @reftables='Kit19calls'
begin
select @profile_id=case when context in ('inbound','goinbound') then callerid else dnid end,
@engagement_type=case when context in ('inbound','goinbound') then 'Called up' else 'Answered' end,
@cust_var=case when context in ('inbound','goinbound') then null else kit19uniqueid end from kit19calls(nolock) where 
id=@refid
select @batchid=batchid from kit19cloudvoicefinaltbl(nolock) where kit19uniqueid=@cust_var
end
else if @reftables='kit19callsdialled'
begin
select @cust_var=puniqueid from kit19callsdialled(nolock) where id=@refid
select @profile_id=case when context in ('inbound','goinbound') then callerid else dnid end,
@engagement_type=case when context in ('inbound','goinbound') then 'Called up' else 'Answered' end,
@cust_var=case when context in ('inbound','goinbound') then null else kit19uniqueid end from kit19calls(nolock) where 
uniqueid=@cust_var
select @batchid=batchid from kit19cloudvoicefinaltbl(nolock) where kit19uniqueid=@cust_var
end
end
else if @channel='Whatsapp'
begin
select @batchtable='wbatchinfo'
select @cust_sql='SELECT @cust_var=senderid,@cust_var2=parentconvid,@profile_id=customer_channelprofileid FROM '+QUOTENAME(@reftables)+' WHERE id = @refid'
EXECUTE sp_executesql @cust_sql, N'@refid bigint, @cust_var nvarchar(1000), @cust_var2 nvarchar(1000) OUTPUT,@profile_id
nvarchar(500) OUTPUT', @refid = @refid, @cust_var = @cust_var OUTPUT, @cust_var2 = @cust_var2 OUTPUT,@profile_id=@profile_id output

--select @engagement_type=case when responseto_convparentid is null then 'Initiated Chat' else 'Replied' end from mysmsconversations.dbo.convparentid(nolock) where id=@cust_var2
SET @sqlquery = 
    'SELECT TOP 1 engagement_type = CASE WHEN responseto_convparentid IS NULL THEN ''Initiated Chat'' ELSE ''Replied'' END 
     FROM convparentid (NOLOCK) 
     WHERE id = ' + CAST(@cust_var2 AS NVARCHAR);

-- Executing the dynamic SQL query via CLR function
EXEC usp_clr_GetRemoteStringValue   @sqlquery, @retval = @engagement_type OUT;

select @engagement_type=isnull(@engagement_type,'Initiated Chat')
end


insert into engagement_time(profile_id,channel,engagement_type,engagement_time,batchtable,batchid)
select @profile_id,@channel,@engagement_type,@event_time,@batchtable,@batchid
end
end try
begin catch
exec usp_inserterrorinfo
end catch
end


GO

/* ============================================================
   Procedure: [dbo].[Usp_InsertEnquiryLead_AutoDistributionLead2]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

----sp_helptext Usp_InsertEnquiryLead_AutoDistributionLead2


--sp_helptext Usp_InsertEnquiryLead_AutoDistributionLead2  
  
CREATE   PROCEDURE dbo.Usp_InsertEnquiryLead_AutoDistributionLead2           
(              
 @EnquiryData   EnquiryDetailsType readonly,              
 @ParentID Bigint,              
 @CreatedBy Bigint              
 )              
 as               
 Begin              
 create table #EnquiryDetailsAll(id int identity(1,1),            
    [PersonName] [varchar](100) NULL,            
 [CompanyName] [varchar](100) NULL,            
 [MobileNo] [varchar](100) NULL,            
 [MobileNo1] [varchar](100) NULL,            
 [MobileNo2] [varchar](100) NULL,            
 [EmailID] [varchar](100) NULL,            
 [EmailID1] [varchar](100) NULL,            
 [EmailID2] [varchar](100) NULL,            
 [City] [varchar](100) NULL,            
 [State] [varchar](100) NULL,            
 [Country] [varchar](100) NULL,            
 [CountryCode] [varchar](50) NULL,            
 [CountryCode1] [varchar](50) NULL,            
 [CountryCode2] [varchar](50) NULL,            
 [PinCode] [varchar](50) NULL,            
 [ResidentialAddress] [varchar](500) NULL,            
 [OfficeAddress] [varchar](500) NULL,            
 [SourceName] [varchar](50) NULL,            
 [MediumName] [varchar](50) NULL,            
 [CampaignName] [varchar](50) NULL,            
 [InitialRemarks] [varchar](1000) NULL,          
 [CreatedBy] bigint)            
        
   
        
insert into #EnquiryDetailsAll([PersonName],[CompanyName],[MobileNo],[MobileNo1],[MobileNo2],[EmailID],  
[EmailID1],[EmailID2],[City], [State] ,[Country],[CountryCode],[CountryCode1],[CountryCode2],[PinCode],  
[ResidentialAddress],[OfficeAddress],[SourceName],[MediumName],[CampaignName],[InitialRemarks],[CreatedBy])            
select Distinct [PersonName],[CompanyName],[MobileNo],[MobileNo1],[MobileNo2],[EmailID],[EmailID1],  
[EmailID2],[City], [State] ,[Country],[CountryCode],[CountryCode1],[CountryCode2],[PinCode],  
[ResidentialAddress],[OfficeAddress],[SourceName],[MediumName],[CampaignName],[InitialRemarks],  
@CreatedBy from @EnquiryData            
         
            
select * into #EnquiryDetailsNonConflicting from #EnquiryDetailsAll            
            
create table #temp(mobile varchar(100),email varchar(100))                    
insert into #temp(mobile,email)                  
select (cast(isnull(CountryCode,0) as nvarchar)+ cast(isnull(NULLIF(MobileNo,''),0) as nvarchar)),  
isnull(NULLIF(EmailID,''),0) from UserLeads where ParentID=@PARENTID                    
union                     
select (cast(isnull(CountryCode1,0) as nvarchar)+ cast(isnull(NULLIF(MobileNo1,''),0) as nvarchar)),  
isnull(NULLIF(EmailID1,''),0) from UserLeads where ParentID=@PARENTID                   
union                     
select (cast(isnull(CountryCode2,0) as nvarchar)+ cast(isnull(NULLIF(MobileNo2,''),0) as nvarchar)),  
isnull(NULLIF(EmailID2,''),0) from UserLeads where ParentID=@PARENTID              
            
          
            
delete E from #EnquiryDetailsNonConflicting e join #temp t on CAST(ISNULL(nullif(e.countrycode,''),1)   
as nvarchar)+ CAST( ISNULL(nullif(e.mobileno,''),1)as nvarchar) = t.Mobile            
delete E from #EnquiryDetailsNonConflicting e join #temp t on CAST(ISNULL(nullif(e.countrycode1,''),1)   
as nvarchar)+CAST( ISNULL(nullif(e.mobileno1,''),1)as nvarchar ) = t.Mobile            
delete E from #EnquiryDetailsNonConflicting e join #temp t on CAST( ISNULL(nullif(e.countrycode2,''),1)   
as nvarchar)+ cast(ISNULL(nullif(e.mobileno2,''),1) as nvarchar) = t.Mobile            
delete E from #EnquiryDetailsNonConflicting e join #temp t on ISNULL(nullif(e.emailID,''),1) = t.email            
delete E from #EnquiryDetailsNonConflicting e join #temp t on ISNULL(nullif(e.emailID1,''),1) = t.email            
delete E from #EnquiryDetailsNonConflicting e join #temp t on ISNULL(nullif(e.emailID2,''),1) = t.email          
          
          
declare @outputenq table(enqid bigint,id int)          
declare @outputlead table(leadid bigint,id int)    
         
        
          
Insert into userenquiry (PersonName,CompanyName,MobileNo,MobileNo1,MobileNo2,EmailID,  
EmailID1,EmailID2,City,State,Country,CountryCode,CountryCode1,CountryCode2,PinCode,  
ResidentialAddress,OfficeAddress,SourceName,MediumName,CampaignName,InitialRemarks,  
ParentID,CreatedDate,CreatedBy,leadno)          
      
OUTPUT inserted.leadno,inserted.enquiryID INTO @outputenq(id,enqid)       
         
SELECT PersonName,CompanyName,MobileNo,MobileNo1,MobileNo2,EmailID,EmailID1,  
EmailID2,City,State,Country,CountryCode,CountryCode1,CountryCode2,PinCode,  
ResidentialAddress,OfficeAddress,SourceName,MediumName,CampaignName,InitialRemarks,  
@ParentID,GETDATE(),@CreatedBy,id FROM #EnquiryDetailsAll          
          
  --select 'step after insert enquiry'        
--Put assignedto code here--          
         
declare @StartValue int          
SELECT @StartValue = MAX(leadno)+1 FROM UserLeads where ParentID=@ParentID           
              
 create table #EnquiryDetailsNonConflicting2(leadno int identity(1,1) primary key,        
   id int,        
 [PersonName] [varchar](100) NULL,            
 [CompanyName] [varchar](100) NULL,            
 [MobileNo] [varchar](100) NULL,            
 [MobileNo1] [varchar](100) NULL,            
 [MobileNo2] [varchar](100) NULL,            
 [EmailID] [varchar](100) NULL,            
 [EmailID1] [varchar](100) NULL,            
 [EmailID2] [varchar](100) NULL,            
 [City] [varchar](100) NULL,            
 [State] [varchar](100) NULL,            
 [Country] [varchar](100) NULL,            
 [CountryCode] [varchar](50) NULL,            
 [CountryCode1] [varchar](50) NULL,            
 [CountryCode2] [varchar](50) NULL,            
 [PinCode] [varchar](50) NULL,            
 [ResidentialAddress] [varchar](500) NULL,            
 [OfficeAddress] [varchar](500) NULL,            
 [SourceName] [varchar](50) NULL,            
 [MediumName] [varchar](50) NULL,            
 [CampaignName] [varchar](50) NULL,            
 [InitialRemarks] [varchar](1000) NULL,          
 [CreatedBy] bigint)         
set identity_insert #EnquiryDetailsNonConflicting2 ON        
insert #EnquiryDetailsNonConflicting2 (leadno) values (@StartValue-1)        
set identity_insert #EnquiryDetailsNonConflicting2 OFF        
delete #EnquiryDetailsNonConflicting2        
             
--  select 'step-conflict2'        
insert into #EnquiryDetailsNonConflicting2(id,[PersonName],[CompanyName],[MobileNo],[MobileNo1],[MobileNo2],  
[EmailID],[EmailID1],[EmailID2],[City],  [State] ,[Country],[CountryCode],[CountryCode1],[CountryCode2],  
[PinCode],[ResidentialAddress],[OfficeAddress],[SourceName]        
 ,[MediumName],[CampaignName],[InitialRemarks],[CreatedBy])            
select id,[PersonName],[CompanyName],[MobileNo],[MobileNo1],[MobileNo2],[EmailID],[EmailID1],  
[EmailID2],[City], [State] ,[Country],[CountryCode],[CountryCode1],[CountryCode2],[PinCode],  
[ResidentialAddress],[OfficeAddress],[SourceName],[MediumName],[CampaignName],[InitialRemarks],  
   @CreatedBy from #EnquiryDetailsNonConflicting         
        
--select 'step -last'         
        
Insert into userleads (LeadNo,PersonName,CompanyName,MobileNo,MobileNo1,MobileNo2,EmailID,EmailID1,  
EmailID2,City,State,Country,CountryCode,CountryCode1,CountryCode2,PinCode,ResidentialAddress,  
OfficeAddress,AssignedTo,SourceName,MediumName,CampaignName,InitialRemarks,ParentID,FollowUpStatus,  
NextStatusDate,Remarks,CreatedOn,CreatedBy)        
      
--OUTPUT inserted.leadno,inserted.ID INTO @outputlead(id,leadid)       
      
 select leadno,PersonName,CompanyName,MobileNo,MobileNo1,MobileNo2,EmailID,EmailID1,EmailID2,City,  
 State,Country,CountryCode,CountryCode1,CountryCode2,PinCode,ResidentialAddress,OfficeAddress,  
 (select top 1 value from fn_Split((select agents from CRMCampaignSettings where userid=@ParentID),'#')   
 ORDER BY NEWID()),SourceName,MediumName,CampaignName,InitialRemarks,@ParentID,1,GETDATE(),  
 InitialRemarks,GETDATE(),CreatedBy From #EnquiryDetailsNonConflicting2        
    
  -- lead updation      
  update UserEnquiry Set LeadNo = tblCommon.LeadNo ,IsOpen = 1      
  from UserEnquiry as EnqMain(nolock)      
     inner join      
     ( select ENQ.enqid,NNConflct.leadno From @outputenq as ENQ inner join      
           #EnquiryDetailsNonConflicting2 as NNConflct(nolock)      
           on ENQ.id = NNConflct.id          
     ) as  tblCommon       
           
     on EnqMain.EnquiryID = tblCommon.enqid      
        
  -- insertion of MergeleadsEnquiry      
        
    insert into tbl_MergeLeadsEnquiry(EnquiryNo,LeadNo,IsOpen,CreatedDate)      
     select tblCommon.enqid,tblCommon.leadno,case when isnull(tblCommon.leadno,0) = 0 then 1 else 0 end ,GETDATE()  from      
     ( select ENQ.enqid,NNConflct.leadno From @outputenq as ENQ left outer join      
        #EnquiryDetailsNonConflicting2 as NNConflct(nolock)      
        on ENQ.id = NNConflct.id          
     ) as  tblCommon       
        
        
select 'Success'        
           
 End 


GO

/* ============================================================
   Procedure: [dbo].[usp_InsertErrorInfo]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_InsertErrorInfo]                  
as        
begin        
if ERROR_PROCEDURE() <>'usp_InsertErrorInfo'        
--declare @A int=1              
begin  
 DECLARE @ERROR_NUMBER NVARCHAR(100)=ERROR_NUMBER(),@ERROR_SEVERITY NVARCHAR(100)= ERROR_SEVERITY(),@ERROR_STATE NVARCHAR(100)=ERROR_STATE(),@ERROR_PROCEDURE NVARCHAR(100)=ERROR_PROCEDURE(),@ERROR_LINE NVARCHAR(100)= ERROR_LINE(),@ERROR_MESSAGE NVARCHAR(2000)=ERROR_MESSAGE()
RETRY:                                           
BEGIN TRY                                        
BEGIN TRAN         
insert into ErrorReportNew(ERRORNUMBER,ERRORSEVERITY,ERRORSTATE,ERRORPROCEDURE,ERRORLINE,ERRORMESSAGE,dATE)           values( @ERROR_NUMBER,@ERROR_SEVERITY,@ERROR_STATE,@ERROR_PROCEDURE,@ERROR_LINE,@ERROR_MESSAGE,getdate())       
COMMIT                                        
END TRY                                        
BEGIN CATCH    
IF @@TRANCOUNT>0                                        
ROLLBACK                                        
IF ERROR_NUMBER() = 1205 -- Deadlock Error Number  
BEGIN  
WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms  
GOTO RETRY -- Go to Label RETRY  
END                                             
END CATCH
 
if @ERROR_PROCEDURE  ='USP_INSERTINTOBATCHINFONewTestNew1' and not exists(select 1 from ErrorReportnEW(nolock)  
where ERRORPROCEDURE='USP_INSERTINTOBATCHINFONewTestNew1' and datediff(mi,date,getdate())<5)  
begin  
--declare @body nvarchar(max)='Error '+ ERROR_MESSAGE() +' found at '+ cast(cast(getdate() as date) as nvarchar)  
EXEC usp_enqueueemail          
@profile_name='Alerts',           
@recipients='animesh@pelsoftlabs.in',          
@blind_copy_recipients='karuna@pelsoftlabs.in',          
@subject='Urgent: Error in batch, duplicate deduction may happen',          
@body = 'Error, pl fix urgently',          
@body_format ='HTML'     
end  
end        
end



GO

