CREATE   PROCEDURE dbo.Usp_InsertExporterLeadsDataFromService      
(      
  @tbl ExporterAPILeadTableType READONLY          
)      
as      
Begin      
declare @c int=(select COUNT(1) from @tbl as tbl where isnull(tbl.Exporter_inq_id,'') <> '' 
             and  tbl.Exporter_inq_id not in ( select Exporter_inq_id from tbl_exporterLeads as expL with(nolock) where expl.ExporterKey = tbl.ExporterKey
			)) 
			     
   insert into tbl_exporterLeads      
   (   
       [ExporterKey]
      ,[Exporter_inq_id]
      ,[Exporter_enq_date]
      ,[name]
      ,[mobile]
      ,[email]
      ,[subject]
      ,[product]
      ,[detail_req]
      ,[company]
      ,[country]
      ,[state]
      ,[city] 
	)      
      
 select      
       [ExporterKey]
      ,[Exporter_inq_id]
      ,[Exporter_enq_date]
      ,[name]
      ,[mobile]
      ,[email]
      ,[subject]
      ,[product]
      ,[detail_req]
      ,[company]
      ,[country]
      ,[state]
      ,[city]       
          
    from @tbl t where isnull(t.Exporter_inq_id,'') <> ''
	      and  t.Exporter_inq_id not in ( select Exporter_inq_id from tbl_exporterLeads as expL with(nolock) where expl.ExporterKey = t.ExporterKey)
    -- where  not exists (select 1 From IndiamartLeads(nolock) where QUERY_ID=t.query_id and INDIAMARTKEY=t.INDIAMARTKEY)   
    
select @c    
      
end    
    
    


