   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_InsertFbFeedUpdateJson]-------------------------------------in mysms  66972
    @WebhookJsonId BIGINT,  
    @JsonData NVARCHAR(MAX),  
    @FbPageId NVARCHAR(100),  
  @FbPage nvarchar(max),  
    @Item NVARCHAR(50),  
    @Verb NVARCHAR(50),  
    @PostId NVARCHAR(100),  
    @CommentId NVARCHAR(100)=null,  
    @ParentId NVARCHAR(100)=null,  
    @CreatedTime datetime=null,  
    @UserId NVARCHAR(100) = NULL,  
    @UserName NVARCHAR(200) = NULL,  
    @Message NVARCHAR(MAX) = NULL,  
    @ReactionType NVARCHAR(50) = NULL,  
    @IsProcessed BIT,  
    @FailedReason NVARCHAR(500),  
   @PhotoId NVARCHAR(500)=null,  
     @VideoId NVARCHAR(500)=null,  
  
   -- New Instagram-related params  
    @PlatformId INT = 1, -- 1 = FB, 2 = Instagram  
    @SelfIGScopedId NVARCHAR(100) = NULL,  
    @MediaId NVARCHAR(100) = NULL,  
    @MediaProductType NVARCHAR(50) = NULL  
AS  
BEGIN  
    SET NOCOUNT ON;  
  
   /* BEGIN TRY  
        /*INSERT INTO Kit19Social.dbo.tbl_soc_FbFeedUpdateJson  
        (  
            WebhookJsonId, JsonData, FbPageId,FbPage, Item, Verb, PostId,  
            CommentId, ParentId, CreatedTime, UserId, UserName, Message, ReactionType,  
            IsProcessed, FailedReason,PhotoId,VideoId  
        )  
        VALUES  
        (  
            @WebhookJsonId, @JsonData, @FbPageId,@FbPage, @Item, @Verb, @PostId,  
            @CommentId, @ParentId, @CreatedTime, @UserId, @UserName, @Message, @ReactionType,  
            @IsProcessed, @FailedReason,@PhotoId,@VideoId  
        );*/  
  INSERT INTO Kit19Social.dbo.tbl_soc_FbFeedUpdateJson  
        (  
            WebhookJsonId,  
            JsonData,  
            FbPageId,  
            FbPage,  
            Item,  
            Verb,  
            PostId,  
            CommentId,  
            ParentId,  
            CreatedTime,  
            UserId,  
            UserName,  
            Message,  
            ReactionType,  
            IsProcessed,  
            FailedReason,  
            PhotoId,  
            VideoId,  
            plateformId,  
            SelfIGScopedId,  
            MediaId,  
            MediaProductType  
        )  
        VALUES  
        (  
            @WebhookJsonId,  
            @JsonData,  
            @FbPageId,  
            @FbPage,  
            @Item,  
            @Verb,  
            @PostId,  
            @CommentId,  
            @ParentId,  
            @CreatedTime,  
            @UserId,  
            @UserName,  
            @Message,  
            @ReactionType,  
            @IsProcessed,  
            @FailedReason,  
            @PhotoId,  
            @VideoId,  
            @PlatformId,  
            @SelfIGScopedId,  
            @MediaId,  
            @MediaProductType  
        );  
        -- Return the inserted identity value  
        SELECT SCOPE_IDENTITY() AS InsertedId;  
    END TRY*/  
  
 BEGIN TRY  
        -- Check if record already exists (by WebhookJsonId or natural key)  
        IF NOT EXISTS (  
            SELECT 1  
            FROM Kit19Social.dbo.tbl_soc_FbFeedUpdateJson WITH (NOLOCK)  
            WHERE WebhookJsonId = @WebhookJsonId  
               --OR (  
               --     FbPageId = @FbPageId  
               --     AND PostId = @PostId  
               --     AND ISNULL(CommentId, '') = ISNULL(@CommentId, '')  
               --     AND ISNULL(Verb, '') = ISNULL(@Verb, '')  
               --     AND ISNULL(Item, '') = ISNULL(@Item, '') and userid = @UserId  
               --  )  
        )  
        BEGIN  
            INSERT INTO Kit19Social.dbo.tbl_soc_FbFeedUpdateJson  
            (  
                WebhookJsonId,  
                JsonData,  
                FbPageId,  
                FbPage,  
                Item,  
                Verb,  
                PostId,  
                CommentId,  
                ParentId,  
                CreatedTime,  
                UserId,  
                UserName,  
                Message,  
                ReactionType,  
                IsProcessed,  
                FailedReason,  
                PhotoId,  
                VideoId,  
                plateformId,  
                SelfIGScopedId,  
                MediaId,  
                MediaProductType  
            )  
            VALUES  
            (  
                @WebhookJsonId,  
                @JsonData,  
                @FbPageId,  
                @FbPage,  
                @Item,  
                @Verb,  
                @PostId,  
                @CommentId,  
                @ParentId,  
                @CreatedTime,  
                @UserId,  
                @UserName,  
                @Message,  
                @ReactionType,  
                @IsProcessed,  
                @FailedReason,  
                @PhotoId,  
                @VideoId,  
                @PlatformId,  
                @SelfIGScopedId,  
                @MediaId,  
                @MediaProductType  
            );  
   
            SELECT SCOPE_IDENTITY() AS InsertedId;  
        END  
        ELSE  
        BEGIN  
            -- Return existing ID for reference (optional)  
            SELECT TOP 1 WebhookJsonId AS ExistingId  
            FROM Kit19Social.dbo.tbl_soc_FbFeedUpdateJson  
            WHERE WebhookJsonId = @WebhookJsonId  
               OR (  
                    FbPageId = @FbPageId  
                    AND PostId = @PostId  
                    AND ISNULL(CommentId, '') = ISNULL(@CommentId, '')  
                    AND ISNULL(Verb, '') = ISNULL(@Verb, '')  
                    AND ISNULL(Item, '') = ISNULL(@Item, '')  
                 )  
        END  
    END TRY  
   
  
    BEGIN CATCH  
         EXEC usp_insertErrorInfo;  
    END CATCH  
END;



GO

