SET QUOTED_IDENTIFIER ON

 CREATE   PROCEDURE Usp_InsertFeedback --4639610,678633,'any','any','any'            
  (            
    @FID bigint,            
    @RefID bigint ,            
    @AttributeComments nvarchar(20),            
    @ActivityFeedback nvarchar(100) ,            
    @Comments nvarchar(500)            
   )            
  as            
  Begin           
  declare @result nvarchar(50) ,@feedbackid int          
  EXEC GetStatusofLinkedServerwithoutput 'CRM',@result output              
  if isnull(@result,'0') <> 'Server is currently Offline!!' --is not null           
  Begin           
  --RETRY:                                               
  --BEGIN TRY                                            
  --BEGIN TRAN    
    insert into crm.crmdb.dbo.FeedbackActivity            
    (            
      FID,             
      RefID ,            
      AttributeComments ,            
      ActivityFeedback  ,            
      Comments                
    )            
    values(            
      @FID,             
      @RefID ,            
      @AttributeComments ,            
      @ActivityFeedback  ,            
      @Comments                
    )       
    set @feedbackid=(select MAX(feedbackid) from crm.crmdb.dbo.FeedbackActivity  where fid=@FID AND REFID=@REFID
    and AttributeComments=@AttributeComments and activityfeedback=@ActivityFeedback and comments=@Comments)
    --set @feedbackid=SCOPE_IDENTITY()           
    EXEC crm.crmdb.dbo.usp_sendnewfeedbackmail @feedbackid         
    update  crm.crmdb.dbo.FeedbackActivity set mailsent= 1 where feedbackid=@feedbackid      
--    COMMIT                                            
--END TRY                                            
                  
--BEGIN CATCH                                                                                                
--IF @@TRANCOUNT>0                                            
--ROLLBACK                                            
--EXECUTE USP_INSERTERRORINFO;       
--IF ERROR_NUMBER() = 1205 -- Deadlock Error Number      
--BEGIN      
--WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms      
--GOTO RETRY -- Go to Label RETRY      
--END                                                 
--END CATCH           
            
  end          
  else          
   begin           
             
  insert into FeedbackActivity            
    (            
      FID,             
      RefID ,            
      AttributeComments ,            
      ActivityFeedback  ,            
      Comments                
    )            
    values(            
      @FID,             
      @RefID ,            
      @AttributeComments ,            
      @ActivityFeedback  ,            
      @Comments                
    )            
             
             
   end          
            
                
    select 'Record Saved'            
            
            
                 
  End 


