/* ============================================================
   Procedure: [dbo].[usp_InsertForwading]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_InsertForwading @UserID BIGINT
	,@ParentID BIGINT
	,@ForwadingEmail VARCHAR(500)
AS
BEGIN
	IF EXISTS (
			SELECT 'x'
			FROM UserMailbox AS um
			WHERE um.ForwadingEmail = @ForwadingEmail
				AND um.IsStep6 = 1
			)
	BEGIN
		SELECT 'Forwading already Assigned' AS ActMessage
			,(
				SELECT TOP 1 um.UserID
				FROM UserMailbox AS um
				WHERE um.ForwadingEmail = @ForwadingEmail
					AND um.IsStep6 = 1
				) AS UserID
	END
	ELSE
	BEGIN
		DECLARE @id BIGINT

		UPDATE UserMailbox
		SET isLatest = 0
		WHERE ParentID = @ParentID
			AND UserID = @UserID
			AND ForwadingEmail = @ForwadingEmail

		INSERT INTO UserMailbox (
			-- ID -- this column value is auto-generated  
			UserID
			,ParentID
			,EmailID
			,ForwadingEmail
			,IsVerified
			,IsFiltered
			,LastExtracted
			,LastFiltered
			,CreatedOn
			,CreatedBy
			,IsStep1
			,IsStep2
			,IsStep3
			,isLatest
			)
		VALUES (
			@UserID
			,@ParentID
			,NULL
			,@ForwadingEmail
			,0
			,0
			,NULL
			,NULL
			,GETDATE()
			,@UserID
			,1
			,0
			,0
			,1
			)

		SELECT @id = SCOPE_IDENTITY()

		DECLARE @count INT = (
				SELECT COUNT(1)
				FROM UserMailbox(NOLOCK)
				WHERE ParentID = @parentid
				)
		DECLARE @m_id BIGINT
			,@user_login NVARCHAR(50)

		SELECT @m_id = m_id
			,@user_login = user_login
		FROM user_detail(NOLOCK)
		WHERE USER_ID = @parentid

		IF @m_id = 10043
			AND @count = 1
		BEGIN
			DECLARE @description NVARCHAR(200) = 'User ' + @user_login + ' attempted to forward mail for the first time'

			EXEC Usp_InsertUserEventDetails 'Mail Forwarded'
				,@parentID
				,@Description
				,'UserMailbox'
				,@ID
		END

		SELECT 'Success' AS ActMessage
			,0 AS UserID
	END

	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM UserMailbox(NOLOCK)
			WHERE ID = @id
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID
		,@Activity_type = 'Inst_UsrMail'
		,@ActionType = 'I'
		,@RowJson = @rowJson
		,@Table_name = 'UserMailbox'
END



GO

/* ============================================================
   Procedure: [dbo].[usp_insertGeneralGroup]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_insertGeneralGroup]
	@ParentID BIGINT
AS
BEGIN
	IF NOT EXISTS (
	       SELECT 'x'
	       FROM   UserTemplateGroupDetails utgd
	       WHERE  utgd.ParentID = @ParentID
	              AND utgd.GroupName = 'General'
	   )
	BEGIN
	    INSERT INTO UserTemplateGroupDetails
	      (
	        -- ID -- this column value is auto-generated  
	        ParentID,
	        GroupName,
	        IsEditable,
	        IsSMS,
	        IsMail,
	        CreatedOn,
	        CreatedBy
	      )
	    VALUES
	      (
	        @ParentID,
	        'General',
	        0,
	        1,
	        1,
	        GETDATE(),
	        @ParentID
	      )
	END
END



