  --declare @q2 nvarchar(500)='set '+@isflash+ '= isnull((select top 1 isflash from  '+@TableName + ' where BatchID= '+@BATCHID +'),0)'      
  --execute @q2      
  if not exists(select 1 from batchinfo(nolock) where batchid=@batchid)                                      
  begin                                                 
  INSERT INTO                                            
  dbo.BatchInfo(UserID,BatchID,TotalRecords,ProcessTable,IsPrority,IsAllowDND,ScheduledDate,ScheduledTime,IsUniCode,PageName,userfilter,TableName,  
  DBType,bmessage,isprocess,isflash,sms_source,bsender_id,BI_CreatedBy)                                                    
  VALUES(@USERID,@BATCHID,@TOTALRECORDS,@PROCESSTABLE,@PRIORITY,@ALLOWDND,@ScheduleDate,@ScheduleTime,@IsUnicode,@PageName,@UserFilter,@TableName,  
  @DBType,@message,case when @PROCESSTABLE=0 then 1 when @eli=0 then 2 else Null end,@isflash,@sms_source,@senderid,@USERID)                             
  end        
      COMMIT                                                                
END TRY                                                                
                                     
BEGIN CATCH          
IF (XACT_STATE()) = -1          
    --BEGIN          
        --PRINT 'The transaction is in an uncommittable state.' +          
        --      ' Rolling back transaction.'          
        ROLLBACK TRANSACTION;         
        --EXECUTE USP_INSERTERRORINFO;                           
 --IF ERROR_NUMBER() = 1205 -- Deadlock Error Number                          
 --BEGIN                          
 --WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms                          
 --GOTO RETRY1 -- Go to Label RETRY                          
 --END          
    --END;          
          
    -- Test whether the transaction is active and valid.          
    IF (XACT_STATE()) = 1          
    BEGIN          
        --PRINT 'The transaction is committable.' +           
        --      ' Committing transaction.'          
        COMMIT TRANSACTION;             
    END;                                                                                                                    
--IF @@TRANCOUNT>0                                                   
--ROLLBACK                                                                
                                                                    
END CATCH                         
END  


