/* ============================================================
   Procedure: [dbo].[usp_insertintoenquiryleadactivity_bulk]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_insertintoenquiryleadactivity_bulk
(@tbl Enquiryforla readonly)
as
begin
declare @c int=(select count(1) from @tbl),@id bigint=1
while @c>0
begin

insert into enquiryprocessleadactivity(enquiryid,parentid)
select top 500 enquiryid,parentid from @tbl where id between @id and @id+500
set @id=@id+500
set @c=@c-500
end
end


