-------------------------------------


CREATE   PROCEDURE [dbo].[Usp_insertIntoLeadList]      
(      
   @Source  nvarchar(200)      
  ,@LeadDetails nvarchar(max)      
  ,@Name nvarchar(200)      
  ,@Mobile nvarchar(50)      
  ,@EmailID nvarchar(500)      
  ,@Company nvarchar(500)      
  ,@Address nvarchar(max)      
  ,@Remarks nvarchar(max)      
  ,@ParentID bigint    
)      
as      
Begin 
DECLARE @sqlquery NVARCHAR(MAX);
declare @lid bigint
    insert into LeadList      
  (      
    [Source]      
      ,[LeadDetails]      
      ,[Name]      
      ,[Mobile]      
      ,[EmailID]      
      ,[Company]      
      ,[Address]      
      ,[Remarks]      
   ,[CreatedDate]      
      ,[IsProcessed]     
   ,[ParentID]     
  )      
  values      
  (      
    @Source        
      ,@LeadDetails       
      ,@Name       
      ,@Mobile       
      ,@EmailID       
      ,@Company       
      ,@Address       
      ,@Remarks      
   ,getdate()      
   ,0     
   ,@ParentID       
  )      
select @lid=scope_identity()
begin try
 declare  @whatsappno nvarchar(20)  ='91' +@mobile,@wadate datetime
 
 if not exists (select 1 from leadlist(nolock) where mobile=@mobile and welcome_wa_date is not null)
 begin
/*exec mysmsconversations.dbo.[usp_sendwhatsapp_templateid] '919910025145',@whatsappno,3531,
'[{"SectionType":"HEADER","FieldName":"IMAGE","FieldValue":"https://www.vnmtsolutions.com/wp-content/uploads/2022/01/Automate-your-Amazon-Business-with-NetSuite-Integration-1.jpg"},
{"SectionType":"BODY","FieldName":"CustomPlaceholder1","FieldValue":"https://bit.ly/3TQAUDm"},
{"SectionType":"BODY","FieldName":"CustomPlaceholder2","FieldValue":"https://bit.ly/3FoG97e"}]'*/
SET @sqlquery = 
    'EXEC [usp_sendwhatsapp_templateid] ''919910025145'', ' + 
    CAST(@whatsappno AS NVARCHAR) + ', 3531, 
    ''[{"SectionType":"HEADER","FieldName":"IMAGE","FieldValue":"https://www.vnmtsolutions.com/wp-content/uploads/2022/01/Automate-your-Amazon-Business-with-NetSuite-Integration-1.jpg"},
    {"SectionType":"BODY","FieldName":"CustomPlaceholder1","FieldValue":"https://bit.ly/3TQAUDm"},
    {"SectionType":"BODY","FieldName":"CustomPlaceholder2","FieldValue":"https://bit.ly/3FoG97e"}]''';

-- Executing the dynamic SQL query via CLR function
EXEC usp_clr_ExecuteRemoteQuery  @sqlquery;

update leadlist set welcome_wa_date=getdate() where id=@lid
end
else
begin
select @wadate=min(welcome_wa_date) from leadlist(nolock) where mobile=@Mobile and welcome_wa_date is not null
update leadlist set welcome_wa_date=@wadate where id=@lid
end
end try
begin catch
exec usp_InsertErrorInfo
end catch


         
End 



GO

