/* ============================================================
   Procedure: [dbo].[usp_insertintounsubscribedetail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_insertintounsubscribedetail --'7777777777' --'7840002738'  
@mobile varchar(20)  
as   
begin  
declare @result nvarchar(50)  
  EXEC GetStatusofLinkedServerwithoutput 'CRM',@result output  
  if isnull(@result,'0') <> 'Server is currently Offline!!' --is not null  
  begin  
   insert into crm.crmdb.dbo.UnSubscribeDetails(mobileno,datecreated)  
   select cast(@mobile as bigint),GETDATE() where @mobile not in (select mobileno from  crm.crmdb.dbo.UnSubscribeDetails)
   insert into crm.crmdb.dbo.UnSubscribeDetails(mobileno,datecreated)  
   select mobileno,datecreated from UnsubscribeCRMOffline uc where not exists (select 1 from crm.crmdb.dbo.UnSubscribeDetails u where u.mobileno=uc.mobileno)
   delete from UnsubscribeCRMOffline  
  end  
  else  
  begin  
   insert into UnsubscribeCRMOffline (mobileno,datecreated)  
   select cast(@mobile as bigint),GETDATE()  
  end  
end


GO

