@parentid bigint ,@campaignid bigint,@jobid bigint ,@voice_source nvarchar(100)=null,@v_activityid bigint=null,@v_entity nvarchar(20)=null                                                             
AS                                                                  
BEGIN                                                     
 --SET nocount  ON                                                           
                                                   
                                                             
DECLARE @PROCESSTABLE INT                                                                  
DECLARE @IDENTITYCOLUMN INT                                                   
        BEGIN TRY                                                     
   --SELECT  @IDENTITYCOLUMN=ISNULL(MAX(BatchInfoID),0) FROM BatchIntInfo WITH(NOLOCK)                                                                 
   --IF (@IDENTITYCOLUMN+1)%4 =1                                                                  
   --  BEGIN                                                                   
   --  SET @PROCESSTABLE=1                                                                  
   --  END                                                                  
                                                                     
   --IF (@IDENTITYCOLUMN+1)%4 =2                                                                  
   --  BEGIN                                                                   
   --  SET @PROCESSTABLE=2                                                                  
   --  END                                                                  
                                                                     
   --IF (@IDENTITYCOLUMN+1)%4 =3                                                                  
   --  BEGIN                                                                   
   --  SET @PROCESSTABLE=3                                                                  
   --  END                                                                  
                                                                     
   --IF (@IDENTITYCOLUMN+1)%4 =0                                                                  
   --  BEGIN                                                                   
   --  SET @PROCESSTABLE=4                                                                  
   --  END                                                                  
                                                      
 SET @PROCESSTABLE=2                         
           
          
                                                                
  INSERT INTO  dbo.BatchVoiceInfo                                                        
  (UserID,BatchID,TotalRecords,ProcessTable,IsPrority,IsAllowDND,ScheduledDate,                    
    IsUniCode,PageName,userfilter,TableName,DBType,VoiceCredit,AppId,route,PulseRate, Price, parentid,campaignid,jobid,voice_source
	,v_activityid,v_entity)                 
    VALUES(@USERID,@BATCHID,@TOTALRECORDS,@PROCESSTABLE,@PRIORITY,@ALLOWDND,@ScheduleDate,                    
    @IsUnicode,@PageName,@UserFilter,@TableName,@DBType,  @Credit, @AppId,@route,          
    @PulseRate, @Price, @parentid,@campaignid,@jobid,@voice_source,@v_activityid,@v_entity)                         
                                                
                          
      END TRY                                                                           
        BEGIN CATCH                                           
 IF (XACT_STATE()) = -1        
    --BEGIN        
        --PRINT 'The transaction is in an uncommittable state.' +        
        --      ' Rolling back transaction.'        
        ROLLBACK TRANSACTION;       
        EXECUTE USP_INSERTERRORINFO;                         
 --IF ERROR_NUMBER() = 1205 -- Deadlock Error Number                        
 --BEGIN                        
 --WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms                        
 --GOTO RETRY1 -- Go to Label RETRY                        
 --END        
    --END;        
        
    -- Test whether the transaction is active and valid.        
    IF (XACT_STATE()) = 1        
    BEGIN        
        --PRINT 'The transaction is committable.' +         
        --      ' Committing transaction.'        
        COMMIT TRANSACTION;           
    END;                                                                           
        END CATCH                                                   
END 


GO

