/* ============================================================
   Procedure: [dbo].[Usp_InsertinWebform]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_InsertinWebform (
	@UserID BIGINT = 0
	,@PrentId BIGINT = 0
	,@FilaePath NVARCHAR(MAX) = ''
	,@FormName NVARCHAR(MAX) = ''
	,@FormType NVARCHAR(MAX) = ''
	,@CreatedBy BIGINT = NULL
	,@SequenceNumber BIGINT = 0
	)
AS
BEGIN
	--declare @IsUniCode as bit = 0                                  
	IF NOT EXISTS (
			SELECT 1
			FROM WebFormTbl
			WHERE ParentId = @PrentId
				AND FormName = @FormName
			)
	BEGIN
		INSERT INTO WebFormTbl (
			UserID
			,ParentId
			,FilePath
			,FormName
			,CreatedBy
			,isticket
			,Issms
			,Isemail
			,isEnquiry
			,FormType
			,SequenceNumber
			)
		VALUES (
			@UserID
			,@PrentId
			,@FilaePath
			,@FormName
			,@CreatedBy
			,0
			,0
			,0
			,0
			,@FormType
			,iif(@SequenceNumber = 0, 1, @SequenceNumber)
			);

		DECLARE @idInst AS BIGINT;

		SET @idInst = SCOPE_IDENTITY();

		DECLARE @count INT = (
				SELECT COUNT(1)
				FROM WebFormTbl(NOLOCK)
				WHERE ParentID = @prentid
				);
		DECLARE @m_id BIGINT
			,@user_login NVARCHAR(50);

		SELECT @m_id = m_id
			,@user_login = user_login
		FROM user_detail(NOLOCK)
		WHERE USER_ID = @prentid;

		IF @m_id = 10043
			AND @count = 1
		BEGIN
			DECLARE @description NVARCHAR(200) = 'User ' + CAST(@user_login AS NVARCHAR) + ' created a web form "' + CAST(@FormName AS NVARCHAR) + '" for the first time';

			EXEC Usp_InsertUserEventDetails 'webform Created'
				,@prentID
				,@Description
				,'WebFormTbl'
				,@IDinst;
		END;

		EXEC [Price_DeductfromIntCredit] 1
			,@UserID
			,'webform';

		SELECT *
		FROM WebFormTbl
		WHERE FormId = @idInst;
	END;
	ELSE
	BEGIN
		SELECT *
		FROM WebFormTbl
		WHERE ParentId = @PrentId
			AND FormName = @FormName;
	END;

	IF @idInst > 0
	BEGIN
		DECLARE @rowJson VARCHAR(MAX) = (
				SELECT *
				FROM WebFormTbl(NOLOCK)
				WHERE FormId = @idInst
				FOR JSON AUTO
					,INCLUDE_NULL_VALUES
				)

		IF @rowJson IS NOT NULL
		BEGIN
			EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @userid
				,@Activity_type = 'Inst_WebForm'
				,@ActionType = 'I'
				,@RowJson = @rowJson
				,@Table_name = 'WebFormTbl'
		END
	END
END;



GO

