--sp_helptext [Usp_InsertLandingClientPageDetail]            
CREATE   PROCEDURE [dbo].[Usp_InsertLandingClientPageDetail] @User_ID BIGINT    
 ,@PageName VARCHAR(200)    
 ,@HtmlContent NTEXT = NULL    
 ,@ShortUrl VARCHAR(200) = NULL    
 ,@SiteVisits BIGINT = NULL    
 ,@SiteLeads BIGINT = NULL    
 ,@WebFromID BIGINT = NULL    
 ,@IsSms BIT    
 ,@SmsAccountName NVARCHAR(100)    
 ,@SmsSenderName NVARCHAR(100)    
 ,@SmsMessage NVARCHAR(200)    
 ,@SmsTemplateId BIGINT    
 ,@IsSmsTemplate BIT    
 ,@IsEmail BIT    
 ,@EmailAccountName NVARCHAR(100)    
 ,@EmailReplyTo NVARCHAR(100)    
 ,@EmailSubject NVARCHAR(100)    
 ,@EmailMessgae NVARCHAR(200)    
 ,@EmailTemplateId BIGINT    
 ,@IsTemplate BIT    
 ,@IsWebHook BIT    
 ,@WebHook NVARCHAR(100)    
 ,@Lead_Unsubscribe NVARCHAR(100)    
 ,@IsUniCode BIT    
 ,@recvmobile NVARCHAR(MAX) = ''    
 ,@recvemail NVARCHAR(MAX) = ''    
 ,@IsProfile BIT
 ,@IsNewMailbuilder bit = 0
AS    
BEGIN    

    --set @IsNewMailbuilder = 0   

 DECLARE @parentid BIGINT = (    
   SELECT Parentid    
   FROM user_detail    
   WHERE USER_ID = @User_ID    
   )    
 DECLARE @MID BIGINT    
  ,@user_login NVARCHAR(50)    
    
 SELECT @MID = M_ID    
  ,@user_login = user_login    
 FROM User_Detail    
 WHERE USER_ID = @parentid    
    
 IF EXISTS (    
   SELECT 'x'    
   FROM ClientPageDetail    
   WHERE PageName = 'www.kit19.com/' + @PageName    
   )    
 BEGIN    
  SELECT 'Already Exists'    
 END    
 ELSE    
 BEGIN    
  DECLARE @id BIGINT    
    
  INSERT INTO ClientPageDetail (    
   User_ID    
   ,M_ID    
   ,PageName    
   ,HtmlContent    
   ,ShortUrl    
   ,SiteVisits    
   ,SiteLeads    
   ,DateCreated    
   ,DateUpdated    
   ,WebFromID    
   ,IsSms    
   ,SmsAccountName    
   ,SmsSenderName    
   ,SmsMessage    
   ,SmsTemplateId    
   ,IsSmsTemplate    
   ,IsEmail    
   ,EmailAccountName    
   ,EmailReplyTo    
   ,EmailSubject    
   ,EmailMessgae    
   ,EmailTemplateId    
   ,IsTemplate    
   ,IsWebHook    
   ,WebHook    
   ,Lead_Unsubscribe    
   ,IsUniCode    
   ,CreatedBy    
   ,recvmobile    
   ,recvemail    
   ,IsProfile
   ,IsNewMailBuilder
   )    
  VALUES (    
   @parentid    
   ,@MID    
   ,'www.kit19.com/' + @PageName    
   ,@HtmlContent    
   ,@ShortUrl    
   ,@SiteVisits    
   ,@SiteLeads    
   ,GETDATE()    
   ,''    
   ,@WebFromID    
   ,@IsSms    
   ,@SmsAccountName    
   ,@SmsSenderName    
   ,@SmsMessage    
   ,@SmsTemplateId    
   ,@IsSmsTemplate    
   ,@IsEmail    
   ,@EmailAccountName    
   ,@EmailReplyTo    
   ,@EmailSubject    
   ,@EmailMessgae    
   ,@EmailTemplateId    
   ,@IsTemplate    
   ,@IsWebHook    
   ,@WebHook    
   ,@Lead_Unsubscribe    
   ,@IsUniCode    
   ,@User_ID    
   ,@recvmobile    
   ,@recvemail    
   ,@IsProfile
   ,@IsNewMailbuilder
   )    
    
  SELECT @id = SCOPE_IDENTITY()    
    
  DECLARE @count INT = (    
    SELECT COUNT(1)    
    FROM ClientPageDetail(NOLOCK)    
    WHERE User_ID = @parentid    
    )    
    
  IF @mid = 10043    
   AND @count = 1    
  BEGIN    
   DECLARE @description NVARCHAR(200) = 'User ' + cast(@user_login AS NVARCHAR) + ' created a landing page for the first time'    
    
   EXEC Usp_InsertUserEventDetails 'Landing page Added'    
    ,@parentID    
    ,@Description    
    ,'ClientPageDetail'    
    ,@ID    
  END    
    
  EXEC [Price_DeductfromIntCredit] 1    
   ,@User_id    
   ,'landingpage'    
    
  EXEC Usp_InsertPreDefinedUserCampaignMaster @User_ID    
   ,@PageName    
   ,@SmsMessage    
   ,@IsUniCode    
   ,@EmailReplyTo    
   ,@EmailSubject    
   ,@EmailMessgae    
   ,@SmsSenderName    
   ,@IsSms    
   ,@IsEmail    
   ,@SmsAccountName    
   ,@EmailAccountName    
   ,@SMStemplateid    
   ,@eMailtemplateid    
    
  SELECT 'Success'    
 END    
    
 DECLARE @rowJson NVARCHAR(MAX) = (    
   SELECT *    
   FROM ClientPageDetail WITH(NOLOCK)    
   WHERE Id = @id    
   FOR JSON AUTO    
    ,INCLUDE_NULL_VALUES    
   )    
    
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @User_ID    
  ,@Activity_type = 'Inst_landpg'    
  ,@ActionType = 'I'    
  ,@RowJson = @rowJson    
  ,@Table_name = 'ClientPageDetail'    
END 


