/* ============================================================
   Procedure: [dbo].[usp_insertlastdayengagement]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_insertlastdayengagement
as
begin
insert into user_daily_engagement(user_id,parentid,date_of_usage,mode,timeinSeconds,timeinMin)
select s.userid,dbo.ufn_getuserparentid(s.userid),cast(t.createddate as date),mode,sum(spendtime),cast(sum(spendtime)/cast(60 as float) as int) from tbl_user_engagement_track_details (nolock) t   
join tbl_user_engagement_track_master (nolock) s on t.UserEngMasterId=s.EngagementID  WHERE  isnull(ImpersonatorID,0)=0 and SpendTime>0 and cast(t.createddate as date)=cast(dateadd(d,-1,getdate()) as date) 
and not exists(select 1 from user_daily_engagement(nolock) where user_id=s.UserID and date_of_usage=cast(t.createddate as date))
group by s.userid,dbo.ufn_getuserparentid(s.userid),cast(t.createddate as date),mode
declare @id bigint
begin try
select @id=max(id) from CRM.CRMDB.dbo.user_daily_engagement
select @id=isnull(@id,0)
insert into CRM.CRMDB.dbo.user_daily_engagement(id,user_id,parentid,date_of_usage,mode,timeinSeconds,timeinMin)
select id,user_id,parentid,date_of_usage,mode,timeinSeconds,timeinMin from user_daily_engagement  WHERE  id>@id

end try
begin catch
exec usp_inserterrorinfo
end catch

end


GO

/* ============================================================
   Procedure: [dbo].[usp_insertlasttransactionincreditdetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_insertlasttransactionincreditdetails
as
begin
declare @c bigint=
(select count(1) from MySMSReport.dbo.credit_detailshistory(nolock) c left join credit_details(nolock) cd on c.User_ID=cd.user_id
 where cd.User_ID is null and c.credit_id =(select max(credit_id) from MySMSReport.dbo.credit_detailshistory(nolock) where user_id=c.User_ID))
 create table #temp(credit_id bigint)
 while @c>0
 begin
 Set IDENTITY_INSERT credit_details ON;
 insert into Credit_Details(ID,Credit_ID,M_ID,FromUser_ID,User_ID,Debits,Credits,Balance,Validity,Default_Credit,FromDate,ToDate,DateCreated,DateUpdated,EmpUpdated,MachineName,LastModified,typecredit,
batchid,CreatedBy) output inserted.credit_id into #temp
select top 1000 c.ID,c.Credit_ID,c.M_ID,c.FromUser_ID,c.User_ID,c.Debits,c.Credits,c.Balance,c.Validity,c.Default_Credit,c.FromDate,c.ToDate,c.DateCreated,c.DateUpdated,c.EmpUpdated,c.MachineName,c.LastModified
,c.typecredit,c.batchid,c.CreatedBy from MySMSReport.dbo.credit_detailshistory(nolock) c left join credit_details(nolock) cd on c.User_ID=cd.user_id
 where cd.User_ID is null and c.credit_id =(select max(credit_id) from MySMSReport.dbo.credit_detailshistory(nolock) where user_id=c.User_ID) order by credit_id 
 delete m from MySMSReport.dbo.credit_detailshistory m join #temp t on m.Credit_ID=t.credit_id
 delete from #temp
 Set IDENTITY_INSERT credit_details OFF;
 set @c=@c-1000
 end
 end


GO

