/* ============================================================
   Procedure: [dbo].[Usp_InsertLeadAssignTo_Followup_MassOperation]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

      
CREATE   PROCEDURE [dbo].[Usp_InsertLeadAssignTo_Followup_MassOperation] (      
 @IDS VARCHAR(Max)      
 ,@AssignedTo BIGINT      
 ,@FollowUpStatus INT      
 ,@NextStatusDate VARCHAR(50)      
 ,@Products VARCHAR(1000)      
 ,@AmountPaid NUMERIC(18, 2)      
 ,@Remarks VARCHAR(1000)      
 ,@ParentID BIGINT      
 ,@ModifiedBy BIGINT  ,    
 @BatchID BIGINT = 0     
 --,@CreatedBy          BIGINT         
 )      
AS      
BEGIN      
 BEGIN TRY      
  /* FollowUp start*/     
  declare @count_f int,@sno bigint=1  
  CREATE TABLE #TableData3 (Sno int identity(1,1), ID BIGINT)      
         
  if @BatchID IS NOT NULL AND @BatchID <> 0    
  BEGIN    
 INSERT INTO #TableData3 (ID)      
   select  Entityid as ID from Tbl_MassOperationDetails (nolock) where SummaryId=@BatchID     
   Update  Tbl_MassOperationSummary set BatchStartTime= GetDate()  where BatchID=@BatchID     
  END    
  else     
  begin    
 INSERT INTO #TableData3 (ID)      
 SELECT fs.[value]      
 FROM dbo.fn_Split(@IDS, ',') fs      
  end    
  DECLARE @FollowupDate DATETIME = NULL      
   
  
  IF (      
    @NextStatusDate <> ''      
    AND @NextStatusDate IS NOT NULL      
    )      
  BEGIN      
   BEGIN TRY      
    SET @FollowupDate = convert(DATETIME, @NextStatusDate)      
   END TRY      
      
   BEGIN CATCH      
    IF (@FollowupDate IS NULL)      
    BEGIN      
     INSERT INTO followupDateError (      
      IDs      
      ,nextstatusdate      
      ,parentid      
      )      
     VALUES (      
      @IDS      
      ,@NextStatusDate      
      ,NULL      
      )      
    END      
   END CATCH      
  END      
    
  select @count_f=count(1) from #TableData3  
  while @count_f>0  
  begin  
  IF (@FollowupDate IS NOT NULL)      
  BEGIN      
   SET Context_Info 0x55555    
   UPDATE UL      
   SET AssignedTo = @AssignedTo      
    ,FollowUpStatus = @FollowUpStatus      
    ,NextStatusDate = convert(NVARCHAR(100), dbo.[fn_getISTtimefromusertime](@ModifiedBy, @FollowupDate), 121)      
    ,Products = @Products      
    ,AmountPaid = @AmountPaid      
    ,Remarks = @Remarks      
    ,ModifiedBy = @ModifiedBy      
    ,FollowupDate = dbo.[fn_getISTtimefromusertime](@ModifiedBy, @FollowupDate)      
   FROM UserLeads UL      
   INNER JOIN #TableData3 tb2 ON UL.ID = tb2.ID where tb2.sno between @sno and @sno+100      
    --WHERE  ID IN (SELECT fs.[value]              
    --              FROM   dbo.fn_Split(@IDS, ',') fs)      
  SET Context_Info 0x    
  END      
  ELSE      
  BEGIN      
   SET Context_Info 0x55555    
   UPDATE UL      
   SET AssignedTo = @AssignedTo      
    ,FollowUpStatus = @FollowUpStatus      
    ,NextStatusDate = @NextStatusDate      
    ,Products = @Products      
    ,AmountPaid = @AmountPaid      
    ,Remarks = @Remarks      
    ,ModifiedBy = @ModifiedBy      
    ,FollowupDate = @FollowupDate      
   FROM UserLeads UL      
   INNER JOIN #TableData3 tb2 ON UL.ID = tb2.ID   where tb2.sno between @sno and @sno+100     
    --WHERE  ID IN (SELECT fs.[value]              
    --              FROM   dbo.fn_Split(@IDS, ',') fs)         
  SET Context_Info 0x    
  END  
  set @sno=@sno+100  
 set @count_f=@count_f-100     
end  
  -- Declare @ParentID bigint;      
  SELECT @ParentID = UD.ParentID      
  FROM User_Detail UD(nolock)      
  WHERE UD.User_ID = @ModifiedBy      
      
  -- declare @FollowupDate   Datetime = null            
  DECLARE @conversion VARCHAR(50) = NULL      
      
  IF (      
    @NextStatusDate <> ''      
    AND @NextStatusDate IS NOT NULL      
    )      
  BEGIN      
   BEGIN TRY      
    SET @FollowupDate = convert(DATETIME, @NextStatusDate)      
      
    SELECT @FollowupDate = dbo.[fn_getISTtimefromusertime](@ModifiedBy, @FollowupDate)      
      
    SELECT @NextStatusDate = convert(NVARCHAR(100), @FollowupDate, 121)      
   END TRY      
      
   BEGIN CATCH      
    SET @conversion = 'Invalid Date'      
   END CATCH      
  END      
      
  DROP TABLE IF EXISTS #output      
  select @count_f=count(1),@sno=min(sno) from #TableData3  
   CREATE TABLE #output (      
    lihid BIGINT      
    ,leadno BIGINT      
    ,parentid BIGINT      
    ,fs INT      
    )      
 while @count_f>0  
 begin  
   SET Context_Info 0x55555    
  INSERT INTO LeadInteractionHistory (      
   LeadNo      
   ,FollowUpStatus      
   ,NextStatusDate      
   ,Products      
   ,AmountPaid      
   ,Remarks      
   ,AssignedTo      
   ,ParentID      
   ,CreatedOn      
   ,CreatedBy      
   ,FollowupDate      
   ,IsReassign      
   )      
  OUTPUT inserted.id AS lihid      
   ,inserted.LeadNo AS leadno      
   ,inserted.parentid AS parentid      
   ,inserted.FollowUpStatus AS fs      
  INTO #output        
  SELECT LeadNo      
   ,isnull(followupstatus, 0)      
   ,NextStatusDate      
   ,Products      
   ,AmountPaid      
   ,Remarks      
   ,AssignedTo      
   ,ParentID      
   ,GETDATE()      
   ,@ModifiedBy      
   ,FollowupDate      
   ,1      
  FROM UserLeads u1(NOLOCK)      
  INNER JOIN #TableData3 tb2 ON u1.ID = tb2.ID     where tb2.sno between @sno and @sno+100  
   SET Context_Info 0x    
   set @sno=@sno+100  
   set @count_f=@count_f-100  
   end  
  -- UPDATE  UL                         
  -- SET    UL.AssignedTo = @AssignedTo,                  
  --   UL.modifiedon=GETDATE(),UL.modifiedby=@ModifiedBy               
  --from UserLeads UL      
  --inner join #TableData3 tb2 on UL.ID = tb2.ID       
    
     
  BEGIN TRY      
   DECLARE @createdlogin NVARCHAR(100)      
    ,@assignedlogin NVARCHAR(100)      
    ,@fs NVARCHAR(50)      
      
   SELECT @createdlogin = user_login      
   FROM user_detail(NOLOCK)      
   WHERE user_id = @ModifiedBy      
      
   SELECT @Assignedlogin = user_login      
   FROM user_detail(NOLOCK)      
   WHERE user_id = @AssignedTo      
      
   SELECT id AS leadid      
    ,personname      
    ,u.LeadNo      
    ,lihid      
    ,fs      
   INTO #leadid      
   FROM userleads(NOLOCK) u      
   JOIN #output t ON t.LeadNo = u.leadno      
    AND u.ParentID = t.ParentID      
      
   DECLARE @tbl1 AS LeadActivitywithid_Tbltype      
    
   select @count_f=count(1),@sno=min(lihid) from #leadid  
  
   while @count_f>0  
   begin  
  INSERT INTO @tbl1 (      
    leadid      
    ,userid      
    ,parentid      
    ,eventdescription      
    ,eventname      
    ,reftable      
    ,refid      
    )      
   SELECT leadid      
    ,@ModifiedBy      
    ,@ParentID      
 ,'Lead with name '+isnull(PersonName,'')+' is assigned to ' + @assignedlogin  + ' by '+@createdlogin    
    ,'Lead Assigned to'      
    ,'leadInteractionHistory'      
    ,lihid      
   FROM #leadid l      
   JOIN FollowUp_Status f(nolock) ON f.ID = l.fs  where lihid between @sno and @sno+100    
      
   --EXEC [UspSaveLeadActivity_withMultipleValue_withid] @tbl1     
     
  
  EXEC UspSaveentityActivity_withMultipleValue_withid_bulk @tbl1      
  delete from @tbl1  
  set @sno=@sno+100  
  set @count_f=@count_f-100  
  end  
   DROP TABLE IF EXISTS #leadid      
    DROP TABLE IF EXISTS #output      
    /* ReAssign End */      
    END TRY      
   BEGIN CATCH      
   SET Context_Info 0x    
    EXEC usp_InsertErrorInfo      
      
   END CATCH      
      
   --COMMIT TRANSACTION      
  END TRY      
      
  BEGIN CATCH      
   SELECT ERROR_NUMBER() AS ErrorNumber      
    ,ERROR_SEVERITY() AS ErrorSeverity      
    ,ERROR_STATE() AS ErrorState      
    ,ERROR_PROCEDURE() AS ErrorProcedure      
    ,ERROR_LINE() AS ErrorLine      
    ,ERROR_MESSAGE() AS ErrorMessage;      
  SET Context_Info 0x    
  END CATCH      
    SELECT 'Record Updated'      
   if @BatchID IS NOT NULL AND @BatchID <> 0    
BEGIN    
 Update  Tbl_MassOperationSummary set BatchEndTime= GetDate() , Remarks = 'Record Saved ', IsProcessed=1 where BatchID=@BatchID     
END    
  DECLARE @rowJson NVARCHAR(MAX) = (      
    SELECT *      
    FROM UserLeads ul      
    WHERE ID IN (      
      SELECT fs.[value]      
      FROM dbo.fn_Split(@IDS, ',') fs      
      )      
    FOR JSON AUTO      
     ,INCLUDE_NULL_VALUES      
    )      
      
  IF @rowJson IS NOT NULL      
  BEGIN      
   EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @ModifiedBy      
    ,@Activity_type = 'Updt_msasgn_lead'      
    ,@ActionType = 'U'      
    ,@RowJson = @rowJson      
    ,@Table_name = 'UserLeads'      
  END      
 END 


GO

