CREATE   PROCEDURE [dbo].[Usp_InsertLeadAssignTo_Followup_MassOperation_Replication]            
(                    
 @IDS VARCHAR(Max)                    
 ,@AssignedTo BIGINT                    
 ,@FollowUpStatus bigINT                    
 ,@NextStatusDate VARCHAR(50)                    
 ,@Products VARCHAR(1000)                    
 ,@AmountPaid NUMERIC(18, 2)                    
 ,@Remarks VARCHAR(1000)                    
 ,@ParentID BIGINT                    
 ,@ModifiedBy BIGINT  ,                  
 @BatchID BIGINT = 0  ,        
 @Assigndatetime VARCHAR(50)=''        
 --,@CreatedBy          BIGINT                       
 )                    
AS                    
BEGIN                    
 BEGIN TRY                    
  /* FollowUp start*/               
      
      	Select @AssignedTo=case when IsCallback=1 or IsConvert=1 then @AssignedTo else 0 end From FollowUp_Status(nolock) Where ID=@FollowupStatus  	  

 
                   
     DECLARE @productsJson NVARCHAR(MAX) = (                      
    select value as ProductName                
       from fn_split(@products,'#')                
   FOR JSON AUTO                      
  ,INCLUDE_NULL_VALUES                      
    )            
            
            
  declare @count_f int,@sno bigint=1  
  drop table if exists #TableData3
  CREATE TABLE #TableData3 (Sno int identity(1,1), ID BIGINT)                    
                       
  if @BatchID IS NOT NULL AND @BatchID <> 0                  
  BEGIN                  
 INSERT INTO #TableData3 (ID)                    
   select  Entityid as ID from Tbl_MassOperationDetails (nolock) where SummaryId=@BatchID                   
   --Update  Tbl_MassOperationSummary set BatchStartTime= GetDate(),ScheduleDateTime= @Assigndatetime where BatchID=@BatchID        
   UPDATE Tbl_MassOperationSummary      
        SET BatchStartTime = GETDATE(),      
            ScheduleDateTime = CASE       
                                 WHEN ScheduleDateTime IS NULL OR ScheduleDateTime = '' OR ScheduleDateTime = '1900-01-01 00:00:00.000'      
                                 THEN @Assigndatetime      
                                 ELSE ScheduleDateTime      
                               END      
        WHERE BatchID = @BatchID; 
		print concat(format(getdate(),'d-MM-yyyy HH:mm.sss'),': table 3 populated, batchstarttime updated in summary ')
  END                  
  else                   
  begin                  
  declare @ctd int
 INSERT INTO #TableData3 (ID)                    
 SELECT fs.[value]                    
 FROM dbo.fn_Split(@IDS, ',') fs  
 select @ctd=count(1) from #TableData3
print concat(format(getdate(),'d-MM-yyyy HH:mm.sss'),': table 3 populated with hashed ids, no. of records: ',@ctd )

  end                  
  DECLARE @FollowupDate DATETIME = NULL                    
                 
                
  IF (                    
    @NextStatusDate <> ''                    
    AND @NextStatusDate IS NOT NULL                    
    )                    
  BEGIN                    
   BEGIN TRY                    
    SET @FollowupDate = convert(DATETIME, @NextStatusDate)                    
   END TRY                    
                    
   BEGIN CATCH                    
    IF (@FollowupDate IS NULL)                    
    BEGIN                    
     INSERT INTO followupDateError (                    
      IDs                    
      ,nextstatusdate                    
      ,parentid                    
      )                    
     VALUES (                    
      @IDS                    
      ,@NextStatusDate                    
      ,NULL                    
      )                    
    END                    
   END CATCH                    
  END                    
                  
  select @count_f=count(1) from #TableData3                
  while @count_f>0                
  begin                
  IF (@FollowupDate IS NOT NULL)                    
  BEGIN                    
   SET Context_Info 0x55555                  
   UPDATE UL                    
   SET AssignedTo = @AssignedTo                    
    ,FollowUpStatus = @FollowUpStatus                    
    ,NextStatusDate = convert(NVARCHAR(100), dbo.[fn_getISTtimefromusertime](@ModifiedBy, @FollowupDate), 121)                    
    --,Products = @Products                    
    ,ProductsJson = @ProductsJson                    
 ,AmountPaid = @AmountPaid                    
    ,Remarks = @Remarks                    
    ,ModifiedBy = @ModifiedBy                    
    ,FollowupDate = dbo.[fn_getISTtimefromusertime](@ModifiedBy, @FollowupDate)                    
   FROM UserLeads UL                    
   INNER JOIN #TableData3 tb2 ON UL.ID = tb2.ID where tb2.sno between @sno and @sno+100  
   		print concat(format(getdate(),'d-MM-yyyy HH:mm.sss'),': updated records in userleads: ',@@Rowcount)

    --WHERE  ID IN (SELECT fs.[value]                            
    --              FROM   dbo.fn_Split(@IDS, ',') fs)                    
  SET Context_Info 0x                  
  END                    
  ELSE                    
  BEGIN                    
   SET Context_Info 0x55555                  
   UPDATE UL                    
   SET AssignedTo = @AssignedTo                    
    ,FollowUpStatus = @FollowUpStatus                    
    ,NextStatusDate = @NextStatusDate                    
    --,Products = @Products                    
    ,ProductsJson = @ProductsJson            
 ,AmountPaid = @AmountPaid                    
    ,Remarks = @Remarks                    
    ,ModifiedBy = @ModifiedBy                    
    ,FollowupDate = @FollowupDate                    
   FROM UserLeads UL                    
   INNER JOIN #TableData3 tb2 ON UL.ID = tb2.ID   where tb2.sno between @sno and @sno+100                   
      		print concat(format(getdate(),'d-MM-yyyy HH:mm.sss'),': updated records in userleads: ',@@Rowcount)

    --WHERE  ID IN (SELECT fs.[value]                            
    --              FROM   dbo.fn_Split(@IDS, ',') fs)                       
  SET Context_Info 0x                
  END                
  set @sno=@sno+100                
 set @count_f=@count_f-100                   
end                
  -- Declare @ParentID bigint;                    
  SELECT @ParentID = UD.ParentID                    
  FROM User_Detail UD(nolock)                    
  WHERE UD.User_ID = @ModifiedBy                    
                    
  -- declare @FollowupDate   Datetime = null                          
  DECLARE @conversion VARCHAR(50) = NULL                    
                    
  IF (                    
    @NextStatusDate <> ''                    
    AND @NextStatusDate IS NOT NULL                    
    )                    
  BEGIN                    
   BEGIN TRY                    
    SET @FollowupDate = convert(DATETIME, @NextStatusDate)                    
                    
    SELECT @FollowupDate = dbo.[fn_getISTtimefromusertime](@ModifiedBy, @FollowupDate)                    
                    
    SELECT @NextStatusDate = convert(NVARCHAR(100), @FollowupDate, 121)                    
   END TRY                    
                    
   BEGIN CATCH                    
    SET @conversion = 'Invalid Date'                    
   END CATCH                    
  END                    
                    
  DROP TABLE IF EXISTS #output                    
  select @count_f=count(1),@sno=min(sno) from #TableData3                
   CREATE TABLE #output (                    
    lihid BIGINT                    
    ,leadno BIGINT                    
    ,parentid BIGINT                    
    ,fs INT                    
    )                    
 while @count_f>0                
 begin                
   SET Context_Info 0x55555                  
  INSERT INTO LeadInteractionHistory (                    
   LeadNo                    
   ,FollowUpStatus                    
   ,NextStatusDate                    
   --,Products                    
   ,ProductsJson                    
   ,AmountPaid                    
   ,Remarks                    
   ,AssignedTo                    
   ,ParentID                    
   ,CreatedOn                    
   ,CreatedBy                    
   ,FollowupDate                    
   ,IsReassign,id_lead                    
   )                    
