   SET Context_Info 0x                  
   set @sno=@sno+100                
   set @count_f=@count_f-100                
   end                
  -- UPDATE  UL                                       
  -- SET    UL.AssignedTo = @AssignedTo,                    
  --   UL.modifiedon=GETDATE(),UL.modifiedby=@ModifiedBy                             
  --from UserLeads UL                    
  --inner join #TableData3 tb2 on UL.ID = tb2.ID                     
                  
                   
  BEGIN TRY                    
   DECLARE @createdlogin NVARCHAR(100)                    
    ,@assignedlogin NVARCHAR(100)                    
    ,@fs NVARCHAR(50)                    
                    
   SELECT @createdlogin = user_login                    
   FROM user_detail(NOLOCK)                    
   WHERE user_id = @ModifiedBy                    
                    
   SELECT @Assignedlogin = user_login                    
   FROM user_detail(NOLOCK)                    
   WHERE user_id = @AssignedTo                    
                    
   SELECT id AS leadid                    
    ,personname                    
    ,u.LeadNo                    
    ,lihid                    
    ,fs                    
   INTO #leadid                    
   FROM userleads(NOLOCK) u                    
   JOIN #output t ON t.LeadNo = u.leadno                    
    AND u.ParentID = t.ParentID                    
                    
   DECLARE @tbl1 AS LeadActivitywithid_Tbltype                    
                  
   select @count_f=count(1),@sno=min(lihid) from #leadid                
                
   while @count_f>0                
   begin                
  INSERT INTO @tbl1 (                    
    leadid                    
    ,userid                    
    ,parentid                    
    ,eventdescription                    
    ,eventname                    
    ,reftable                    
    ,refid                    
    )               SELECT leadid                    
    ,@ModifiedBy                    
    ,@ParentID                    
 ,'Lead with name '+isnull(PersonName,'')+' is assigned to ' + @assignedlogin  + ' by '+@createdlogin                  
    ,'Lead Assigned to'                    
    ,'leadInteractionHistory'                    
    ,lihid                    
   FROM #leadid l                    
   JOIN FollowUp_Status f(nolock) ON f.ID = l.fs  where lihid between @sno and @sno+100                  
                    
   --EXEC [UspSaveLeadActivity_withMultipleValue_withid] @tbl1                
                   
     		print concat(format(getdate(),'d-MM-yyyy HH:mm.sss'),': created @tbl for activity proc with records: ',@@Rowcount)
              
  EXEC UspSaveentityActivity_withMultipleValue_withid_bulk @tbl1  
     		print concat(format(getdate(),'d-MM-yyyy HH:mm.sss'),': Ran UspSaveentityActivity_withMultipleValue_withid_bulk ')

  delete from @tbl1                
  set @sno=@sno+100                
  set @count_f=@count_f-100                
  end                
   DROP TABLE IF EXISTS #leadid                    
    DROP TABLE IF EXISTS #output                    
    /* ReAssign End */                    
    END TRY                    
   BEGIN CATCH                    
   SET Context_Info 0x                  
    EXEC usp_InsertErrorInfo                    
                    
   END CATCH                    
                    
   --COMMIT TRANSACTION                    
  END TRY                    
                    
  BEGIN CATCH                    
   SELECT ERROR_NUMBER() AS ErrorNumber                    
    ,ERROR_SEVERITY() AS ErrorSeverity                    
    ,ERROR_STATE() AS ErrorState                    
    ,ERROR_PROCEDURE() AS ErrorProcedure                    
    ,ERROR_LINE() AS ErrorLine                    
    ,ERROR_MESSAGE() AS ErrorMessage;                    
  SET Context_Info 0x                  
  END CATCH                    
    SELECT 'Record Updated'                    
   if @BatchID IS NOT NULL AND @BatchID <> 0                  
BEGIN                  
 --Update  Tbl_MassOperationSummary set BatchEndTime= GetDate(), ScheduleDateTime= @Assigndatetime , Remarks = 'Record Saved ', IsProcessed=1 where BatchID=@BatchID      
 UPDATE Tbl_MassOperationSummary      
        SET BatchEndTime = GETDATE(),      
            ScheduleDateTime = CASE       
                                 WHEN ScheduleDateTime IS NULL OR ScheduleDateTime = '' OR ScheduleDateTime = '1900-01-01 00:00:00.000'      
                                 THEN @Assigndatetime      
                                 ELSE ScheduleDateTime      
                               END,      
            Remarks = 'Record Saved',      
            IsProcessed = 1      
        WHERE BatchID = @BatchID; 
     		print concat(format(getdate(),'d-MM-yyyy HH:mm.sss'),': updated batchendtime in summary table ')
		
END                  
  DECLARE @rowJson NVARCHAR(MAX) = (                    
    SELECT *                    
    FROM UserLeads ul                    
    WHERE ID IN (                    
      SELECT fs.[value]                    
      FROM dbo.fn_Split(@IDS, ',') fs                    
      )                    
    FOR JSON AUTO                    
     ,INCLUDE_NULL_VALUES                    
    )                    
      		print concat(format(getdate(),'d-MM-yyyy HH:mm.sss'),': created @rowjson ')
                   
  IF @rowJson IS NOT NULL                    
  BEGIN                    
   EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @User_id = @ModifiedBy                    
    ,@Activity_type = 'Updt_msasgn_lead'                    
    ,@ActionType = 'U'                    
