/* ============================================================
   Procedure: [dbo].[Usp_InsertLeadAssignTo_MassOperation]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--select top 10 * from followupin_mass_assign(nolock) order by id desc    Temp table
CREATE   PROCEDURE [dbo].[Usp_InsertLeadAssignTo_MassOperation]                    
(                    
    @IDS                VARCHAR(Max),                    
    @FollowUpStatus     INT,                    
    @NextStatusDate     VARCHAR(50),                    
    @Products           VARCHAR(1000),                    
    @AmountPaid         NUMERIC(18, 2),                    
    @Remarks            VARCHAR(1000),                    
    @AssignedTo         BIGINT,                    
    @ParentID           BIGINT,                    
    @CreatedBy          BIGINT                    
)                    
AS                    
 -- =============================================                    
 -- Author:      Name Vishal Kumar Srivastava                    
 -- Create date: 30-8-2017                    
 -- Description: MassOperation of Add follow up                    
 -- =============================================                    
BEGIN                    
 DECLARE @IDValue INT = 0;                    
  SELECT @IDValue = ID                    
  FROM   FollowUp_Status                    
  WHERE  FollowupStatus = 'Re-Assigned'                    
          
insert into followupin_mass_assign(IDS,FollowUpStatus,IDValue,NextStatusDate,Products,AmountPaid,Remarks,AssignedTo,ParentID,              
CreatedBy)              
select @IDS,@FollowUpStatus,@IDValue,@NextStatusDate,@Products,@AmountPaid,@Remarks,@AssignedTo,@ParentID,              
@CreatedBy              
     
 BEGIN TRY                    
  BEGIN TRANSACTION                    
                        
 declare @FollowupDate datetime = null               
 declare @conversion varchar(50)=null                         
 if(@NextStatusDate <> '' and @NextStatusDate is not null)                      
   Begin                      
    begin try              
    set @FollowupDate=convert(datetime,@NextStatusDate)              
    select @FollowupDate = dbo.[fn_getISTtimefromusertime](@ParentID,@FollowupDate)              
    select @NextStatusDate = convert(nvarchar(100),@FollowupDate,121)                 
    end try              
    begin catch              
    set @conversion= 'Invalid Date'              
    end catch               
   End                     
                      
                      
/*                      
  DECLARE @TableData TABLE                     
          (                    
              LeadNo BIGINT,                    
              FollowUpStatus BIGINT,                    
              NextStatusDate VARCHAR(50),                    
              Products VARCHAR(1000),                    
              AmountPaid NUMERIC(18, 2),                    
              Remarks VARCHAR(1000),                    
              AssignedTo BIGINT,                    
              ParentID BIGINT,                    
              CreatedOn DATETIME,                    
              CreatedBy BIGINT,                
              FollowupDate datetime                    
          )                    
                      
  INSERT INTO @TableData                    
    (                    
      LeadNo,                    
      FollowUpStatus,                    
      NextStatusDate,                    
      Products,                    
      AmountPaid,                    
      Remarks,                    
      AssignedTo,                    
      ParentID,                    
      CreatedOn,                    
      CreatedBy,                
      FollowupDate                    
    )                    
  SELECT L.LeadNo,                    
         L.FollowUpStatus,                    
         L.NextStatusDate,                    
         L.Products,                    
         L.AmountPaid,                    
         L.Remarks,                    
         L.AssignedTo,                    
         L.ParentID,                    
         L.CreatedOn,                    
         L.CreatedBy,               
         L.FollowupDate                    
  FROM   LeadInteractionHistory L                    
         INNER JOIN UserLeads u1                    
              ON  u1.LeadNo = L.LeadNo                    
  WHERE  u1.ID IN (SELECT fs.[value]                    
                   FROM   dbo.fn_Split(@IDS, ',') fs)               
                          
  ORDER BY                    
         L.CreatedOn DESC                
*/                      
  ---------------------For Add Assign To--------------------                    
CREATE TABLE #TableData2 
          (                    
              ID BIGINT
          )
		  
INSERT INTO #TableData2 (ID)           
SELECT fs.[value]                    
                FROM   dbo.fn_Split(@IDS, ',') fs
  
  --INSERT INTO #TableData2            
  --  (                    
  --    LeadNo,                    
  --    FollowUpStatus,                    
  --    NextStatusDate,                    
  --    Products,                    
  --    AmountPaid,                    
  --    Remarks,                    
  --    AssignedTo,                    
  --    ParentID,                    
  --    CreatedOn,                    
  --    CreatedBy,                
  --    FollowupDate                      
  --  )                    
  --SELECT LeadNo,                    
  --       followupstatus,              
  --       --@IDValue,                    
  --       NextStatusDate,                    
  --       Products,                    
  --       AmountPaid,                    
  --       Remarks,                    
  --       AssignedTo,                    
  --       ParentID,                    
  --       GETDATE(),                    
  --       @CreatedBy,                
  --       FollowupDate                      
  --FROM   UserLeads u1  (nolock)                  
  --WHERE  ID IN (SELECT fs.[value]                    
  --              FROM   dbo.fn_Split(@IDS, ',') fs)

 drop table if exists #output         
  create table #output(lihid bigint,leadno bigint,parentid bigint,fs int)                   
  INSERT INTO LeadInteractionHistory                    
    (                    
      LeadNo,                    
      FollowUpStatus,                    
      NextStatusDate,                    
      Products,                    
      AmountPaid,                    
      Remarks,                    
      AssignedTo,                    
      ParentID,                    
      CreatedOn,                    
      CreatedBy,                
      FollowupDate                    
    ) output inserted.id as lihid,inserted.LeadNo as leadno,inserted.parentid as parentid,inserted.FollowUpStatus as fs into #output                   

  SELECT LeadNo,                    
         isnull(followupstatus, 0),              
         --@IDValue,                    
         NextStatusDate,                    
         Products,                    
         AmountPaid,                    
         Remarks,                    
         AssignedTo,                    
         ParentID,                    
         GETDATE(),                    
         @CreatedBy,                
         FollowupDate                      
  FROM   UserLeads u1  (nolock)                  
  inner join #TableData2 tb2 on u1.ID = tb2.ID
  --WHERE  ID 
  --IN (SELECT fs.[value]                    
  --              FROM   dbo.fn_Split(@IDS, ',') fs)
  --SELECT LeadNo,                    
  --       isnull(FollowUpStatus, 0),                    
  --       NextStatusDate,                    
  --       Products,                    
  --       AmountPaid,                    
  --       Remarks,                    
  --       AssignedTo,                    
  --       ParentID,                    
  --       CreatedOn,                    
  --       CreatedBy,                
  --       FollowupDate                    
  --FROM   @TableData1                    
  -----------------------------------------------------------------                    
/*                      
  INSERT INTO LeadInteractionHistory                    
    (                    
      LeadNo,                    
      FollowUpStatus,                    
      NextStatusDate,                    
      Products,                    
  AmountPaid,                    
      Remarks,                    
      AssignedTo,                    
      ParentID,                    
      CreatedOn,                    
      CreatedBy,                
      FollowupDate                    
    )                    
  SELECT LeadNo,                    
         @FollowUpStatus,                    
         NextStatusDate,        
         Products,                    
         AmountPaid,                    
         Remarks,                    
         AssignedTo,                    
         ParentID,                    
         CreatedOn,                    
         CreatedBy,                
         FollowupDate                    
  FROM   @TableData                    
  WHERE  CreatedOn = (                    
             SELECT MAX(CreatedOn)                    
             FROM   @TableData                    
         )                    
  ORDER BY                    
         CreatedOn DESC                    
  */                 

 UPDATE  UL                   
 SET    UL.AssignedTo = @AssignedTo,            
 --followupstatus=isnull(nullif(@followupstatus,0),FollowUpStatus),nextstatusdate=@NextStatusDate,Products=@Products,    
         --AmountPaid=@AmountPaid,Remarks=@Remarks,followupdate=@FollowupDate                         
   UL.modifiedon=GETDATE(),UL.modifiedby=@CreatedBy         
from UserLeads UL
inner join #TableData2 tb2 on UL.ID = tb2.ID 

 --WHERE  ID IN (Select ID from #TableData2 tb2)
 --(SELECT fs.[value]                    
 --              FROM   dbo.fn_Split(@IDS, ',') fs)                    
                                    
  SELECT 'Record Saved'                    
        
  begin try          
declare @createdlogin nvarchar(100),@assignedlogin nvarchar(100) ,@fs nvarchar(50)         
select @createdlogin=user_login from user_detail(nolock) where user_id=@CreatedBy          
select @Assignedlogin=user_login from user_detail(nolock) where user_id=@AssignedTo          
      
select id as leadid,personname,u.LeadNo,lihid,fs into #leadid           
from userleads(nolock) u join #output t on t.LeadNo=u.leadno and u.ParentID=t.ParentID           
declare @tbl1 as LeadActivitywithid_Tbltype          
insert into @tbl1(leadid,userid,parentid,eventdescription,eventname,reftable,refid)          
select leadid,@createdby,@ParentID,        
@createdlogin + ' added a new followup with status '+followupstatus+ case when isnull(@assignedlogin,'')<>'' then         
'. Lead was assigned to '+@assignedlogin else '' end        
,'New Interaction added','leadInteractionHistory',lihid from #leadid l join FollowUp_Status f on f.ID=l.fs          
exec [UspSaveLeadActivity_withMultipleValue_withid] @tbl1          
drop table if exists #leadid          
drop table if exists #output          
 end try          
 begin catch          
 exec usp_InsertErrorInfo          
 end catch          
         
          
COMMIT TRANSACTION                    
 END TRY                    
 BEGIN CATCH                    
  ROLLBACK TRANSACTION                    
  SELECT ERROR_NUMBER()     AS ErrorNumber,                    
         ERROR_SEVERITY()   AS ErrorSeverity,                    
         ERROR_STATE()      AS ErrorState,                    
         ERROR_PROCEDURE()  AS ErrorProcedure,                    
         ERROR_LINE()       AS ErrorLine,                    
         ERROR_MESSAGE()    AS ErrorMessage;                    
  exec usp_InsertErrorInfo          
 END CATCH                    
          
END           




