/* ============================================================
   Procedure: [dbo].[Usp_InsertLeadAssignTo_MassOperation_INTDateTime]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_InsertLeadAssignTo_MassOperation_INTDateTime]      
(      
    @IDS                VARCHAR(500),      
    @FollowUpStatus     INT,      
    @NextStatusDate     VARCHAR(50),      
    @Products           VARCHAR(1000),      
    @AmountPaid         NUMERIC(18, 2),      
    @Remarks            VARCHAR(1000),      
    @AssignedTo         BIGINT,      
    @ParentID           BIGINT,      
    @CreatedBy          BIGINT      
)      
AS      
 -- =============================================      
 -- Author:      Name Vishal Kumar Srivastava      
 -- Create date: 30-8-2017      
 -- Description: MassOperation of Add follow up      
 -- =============================================      
BEGIN      
 BEGIN TRY      
  BEGIN TRANSACTION      
  DECLARE @IDValue INT = 0;      
  SELECT @IDValue = ID      
  FROM   FollowUp_Status      
  WHERE  FollowupStatus = 'Re-Assigned'      
        
        
 declare @FollowupDate datetime = null
declare @conversion varchar(50)=null            
if(@NextStatusDate <> '' and @NextStatusDate is not null)        
   Begin        
    begin try
    set @FollowupDate=convert(datetime,@NextStatusDate)
    select @FollowupDate = dbo.[fn_getISTtimefromusertime](@ParentID,@FollowupDate)
    select @NextStatusDate = convert(nvarchar(100),@FollowupDate,121)   
    end try
    begin catch
    set @conversion= 'Invalid Date'
    end catch 
   End       
        
        
        
  DECLARE @TableData TABLE       
          (      
              LeadNo BIGINT,      
              FollowUpStatus BIGINT,      
              NextStatusDate VARCHAR(50),      
              Products VARCHAR(1000),      
              AmountPaid NUMERIC(18, 2),      
              Remarks VARCHAR(1000),      
              AssignedTo BIGINT,      
              ParentID BIGINT,      
              CreatedOn DATETIME,      
              CreatedBy BIGINT,  
              FollowupDate datetime      
          )      
        
  INSERT INTO @TableData      
    (      
      LeadNo,      
      FollowUpStatus,      
      NextStatusDate,      
      Products,      
      AmountPaid,      
      Remarks,      
      AssignedTo,      
      ParentID,      
      CreatedOn,      
      CreatedBy,  
      FollowupDate      
    )      
  SELECT L.LeadNo,      
         L.FollowUpStatus,      
         L.NextStatusDate,      
         L.Products,      
         L.AmountPaid,      
         L.Remarks,      
         L.AssignedTo,      
         L.ParentID,      
         L.CreatedOn,      
         L.CreatedBy,  
         L.FollowupDate      
  FROM   LeadInteractionHistory L      
         INNER JOIN UserLeads u1      
              ON  u1.LeadNo = L.LeadNo      
  WHERE  u1.ID IN (SELECT fs.[value]      
                   FROM   dbo.fn_Split(@IDS, ',') fs)      
  ORDER BY      
         L.CreatedOn DESC      
        
  ---------------------For Add Assign To--------------------      
  DECLARE @TableData1 TABLE       
          (      
              LeadNo BIGINT,      
              FollowUpStatus BIGINT,      
              NextStatusDate VARCHAR(50),      
              Products VARCHAR(1000),      
              AmountPaid NUMERIC(18, 2),      
              Remarks VARCHAR(1000),      
              AssignedTo BIGINT,      
              ParentID BIGINT,      
              CreatedOn DATETIME,      
              CreatedBy BIGINT ,  
              FollowupDate datetime       
          )      
        
  INSERT INTO @TableData1      
    (      
      LeadNo,      
      FollowUpStatus,      
      NextStatusDate,      
      Products,      
      AmountPaid,      
      Remarks,      
      AssignedTo,      
      ParentID,      
      CreatedOn,      
      CreatedBy,  
      FollowupDate        
    )      
  SELECT LeadNo,      
         @IDValue,      
         @NextStatusDate,      
         @Products,      
         @AmountPaid,      
         @Remarks,      
         @AssignedTo,      
         @ParentID,      
         GETDATE(),      
         @CreatedBy,  
         @FollowupDate        
  FROM   UserLeads u1      
  WHERE  ID IN (SELECT fs.[value]      
                FROM   dbo.fn_Split(@IDS, ',') fs)      
        
  INSERT INTO LeadInteractionHistory      
    (      
      LeadNo,      
      FollowUpStatus,      
      NextStatusDate,      
      Products,      
      AmountPaid,      
      Remarks,      
      AssignedTo,      
      ParentID,      
      CreatedOn,      
      CreatedBy,  
      FollowupDate      
    )      
  SELECT LeadNo,      
         FollowUpStatus,      
         NextStatusDate,      
         Products,      
         AmountPaid,      
         Remarks,      
         AssignedTo,      
         ParentID,      
         CreatedOn,      
         CreatedBy,  
         FollowupDate      
  FROM   @TableData1      
  -----------------------------------------------------------------      
        
        
  INSERT INTO LeadInteractionHistory      
    (      
      LeadNo,      
      FollowUpStatus,      
      NextStatusDate,      
      Products,      
      AmountPaid,      
      Remarks,      
      AssignedTo,      
      ParentID,      
      CreatedOn,      
      CreatedBy,  
      FollowupDate      
    )      
  SELECT LeadNo,      
         @FollowUpStatus,      
         NextStatusDate,      
         Products,      
         AmountPaid,      
         Remarks,      
         AssignedTo,      
         ParentID,      
         CreatedOn,      
         CreatedBy,  
         FollowupDate      
  FROM   @TableData      
  WHERE  CreatedOn = (      
             SELECT MAX(CreatedOn)      
             FROM   @TableData      
         )      
  ORDER BY      
         CreatedOn DESC      
     
 UPDATE UserLeads      
 SET    AssignedTo = @AssignedTo      
 WHERE  ID IN (SELECT fs.[value]      
               FROM   dbo.fn_Split(@IDS, ',') fs)      
                      
  SELECT 'Record Saved'      
  COMMIT TRANSACTION      
 END TRY      
 BEGIN CATCH      
  ROLLBACK TRANSACTION      
  SELECT ERROR_NUMBER()     AS ErrorNumber,      
         ERROR_SEVERITY()   AS ErrorSeverity,      
         ERROR_STATE()      AS ErrorState,      
         ERROR_PROCEDURE()  AS ErrorProcedure,      
         ERROR_LINE()       AS ErrorLine,      
         ERROR_MESSAGE()    AS ErrorMessage;      
 END CATCH      
END 



