/* ============================================================
   Procedure: [dbo].[Usp_InsertLeadDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


/*    
  Created by : Santosh Kumar    
  Created Date :31-05-2017 8:00 PM    
  SP For Insert Lead Details                
  Alter Date:    
  Altered By :     
*/    
    
CREATE   PROC [dbo].[Usp_InsertLeadDetails] 
(
    @SearchName NVARCHAR(250),
    @IsActive BIT,
    @MicrositeName NVARCHAR(1050),
    @FromDate NVARCHAR(50) = NULL,
    @ToDate NVARCHAR(50) = NULL,
    @Kit19LeadType NVARCHAR(3),
    @CreatedBy BIGINT
)    
AS    
BEGIN
	INSERT INTO SearchDetails
	  (
	    SearchName,
	    IsKit19,
	    IsUsers,
	    IsActive,
	    IsLeads,
	    MicrositeName,
	    FromDate,
	    ToDate,
	    Kit19LeadType,
	    CreatedBy,
	    CreatedDate,
	    ModifiedBy,
	    ModifiedDate
	  )
	VALUES
	  (
	    @SearchName,
	    1,
	    0,
	    @IsActive,
	    1,
	    @MicrositeName,
	    @FromDate,
	    @ToDate,
	    @Kit19LeadType,
	    @CreatedBy,
	    GETDATE(),
	    @CreatedBy,
	    GETDATE()
	  )    
	
	SELECT 'Record Inserted'
END



GO

