 insert into LeadInteractionHistory(LeadNo,FollowUpStatus,NextStatusDate,Products,AmountPaid,Remarks,AssignedTo,ParentID,CreatedOn,CreatedBy)values(@LeadNo,@FollowUpStatus,@NextStatusDate,@Products,@AmountPaid,@Remarks,@AssignedTo,@ParentID,GETDATE(),@CreatedBy)   
   
