/* ============================================================
   Procedure: [dbo].[Usp_InsertLeadIntractionHistory_ChangeWithFollowupDate]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

    
CREATE   PROCEDURE [dbo].[Usp_InsertLeadIntractionHistory_ChangeWithFollowupDate]              
(              
 @LeadNo Bigint,              
 @FollowUpStatus int,              
 @NextStatusDate varchar(50),              
 @Products varchar(1000),              
 @AmountPaid numeric(18,2),              
 @Remarks varchar(1000),              
 @AssignedTo Bigint,              
 @ParentID bigint,              
 @CreatedBy bigint,    
 @IsReAssign bit = 0    
)              
as              
Begin           
        
   declare @FollowupDate   Datetime = null,@leadid bigint
   select top 1 @leadid=id from userleads(nolock) where leadno=@leadno and parentid=@ParentID
  if(@NextStatusDate <> '')            
   Begin     
              
    set @FollowupDate = @NextStatusDate     
    select @FollowupDate = dbo.[fn_getISTtimefromusertime](@CreatedBy,@FollowupDate)        
    select @NextStatusDate = convert(nvarchar(100),@FollowupDate,121)      
                
   End         
           
 insert into LeadInteractionHistory          
 (          
 LeadNo,FollowUpStatus,          
 NextStatusDate,Products,          
 AmountPaid,Remarks,          
 AssignedTo,ParentID,          
 CreatedOn,CreatedBy,          
 FollowupDate,    
 IsReAssign,id_lead    
 )          
 values          
 (@LeadNo,@FollowUpStatus,          
 @NextStatusDate,@Products,          
 @AmountPaid,@Remarks,          
 @AssignedTo,@ParentID,          
 GETDATE(),@CreatedBy,          
 @FollowupDate,          
 @IsReAssign,@leadid    
 )               
               
 select 'Record Saved'               
                   
End 


GO

