-- exec Usp_InsertLeadIntractionHistory_ChangeWithFollowupDateNew_Replication_AppModkit19 @LeadNo=179774,@FollowUpStatus=35,@NextStatusDate=N'14-May-2025 12:51:00',@Products=N'',@AmountPaid=56,@Remarks=N'test',@AssignedTo=32222,@ParentID=32222,@CreatedBy=
--32222,@IsReAssign=0  
CREATE   PROCEDURE [dbo].[Usp_InsertLeadIntractionHistory_ChangeWithFollowupDateNew_Replication_AppModkit19]                    
(                    
 @LeadNo Bigint,                    
 @FollowUpStatus int,                    
 @NextStatusDate varchar(50),                    
 @Products varchar(1000),                    
 @AmountPaid numeric(18,2),                    
 @Remarks nvarchar(2000),                    
 @AssignedTo Bigint,                    
 @ParentID bigint,                    
 @CreatedBy bigint,          
 @IsReAssign bit = 0          
)                    
as                    
Begin                 
              
  -- declare @FollowupDate   Datetime = null                
  --if(@NextStatusDate <> '')                  
  -- Begin           
                    
  --  set @FollowupDate = @NextStatusDate           
  --  select @FollowupDate = dbo.[fn_getISTtimefromusertime](@CreatedBy,@FollowupDate)              
  --  select @NextStatusDate = convert(nvarchar(100),@FollowupDate,121)            
                      
  -- End      
        
     Declare @QueryProducts nvarchar(max) = ''      
     DECLARE @ProductsJson NVARCHAR(4000) = ''      
      
   begin try       
   if(isnull(@Products,'') != '')      
   begin      
         set @QueryProducts =  CONCAT('select @ProductsJsonTemp = (        
         select t.Name as ProductName from (select [value] from fn_split('''+ isnull(@Products,'''') +''',''#'')) as tbl      
        join       
      tbl_ProductMaster_', cast(@ParentID as nvarchar(50)) ,' as t with(nolock)      
        on tbl.[value] = t.ProductID      
              
        FOR JSON AUTO                
          ,INCLUDE_NULL_VALUES        
     )','')      
        
    exec sp_executesql @QueryProducts, N'@ProductsJsonTemp nvarchar(4000) out ', @ProductsJson out        
         end       
      end try           
      begin catch      
      exec usp_insertErrorInfo         
   end catch            
         
      
      
  Declare @Id bigint         
 select top 1 @Id = Id from UserLeads(nolock) where LeadNo = @LeadNo and ParentID = @ParentID        
 Declare @IsCallback bit, @IsConvert bit        
         
 select @IsCallback = IsCallback, @IsConvert = IsConvert from         
 FollowUp_Status(nolock) where Id = @FollowUpStatus and ParentID = @ParentID        
 if((@IsCallback = 0) and (@IsConvert = 0))        
 Begin        
 set @AssignedTo = 0        
 End        
        
 DECLARE @FollowupDate DATETIME = NULL        
  --,@LeadNo BIGINT = 0        
  --,@ParentID BIGINT = 0        
        
 IF (@NextStatusDate <> '')        
 BEGIN        
  SET @FollowupDate = @NextStatusDate        
 END        
        
 IF (@NextStatusDate <> '')        
 BEGIN        
  UPDATE UserLeads        
  SET AssignedTo = @AssignedTo        
   ,FollowUpStatus = @FollowUpStatus        
   ,NextStatusDate = convert(NVARCHAR(100), dbo.[fn_getISTtimefromusertime](@CreatedBy, @FollowupDate), 121)        
   ,ProductsJson = @ProductsJson        
   ,AmountPaid = @AmountPaid        
   ,Remarks = @Remarks        
   ,ModifiedBy = @CreatedBy        
   ,FollowupDate = dbo.[fn_getISTtimefromusertime](@CreatedBy, @FollowupDate)        
   ,@LeadNo = LeadNo        
   ,@ParentID = ParentID  
   ,LastFollowupCreatedOn = getdate()  
   ,LastFollowupCreatedBy = @CreatedBy  
  WHERE ID = @ID        
 END        
 ELSE        
 BEGIN        
  UPDATE UserLeads        
  SET AssignedTo = @AssignedTo        
   ,FollowUpStatus = @FollowUpStatus        
   ,NextStatusDate = @NextStatusDate        
   ,ProductsJson = @ProductsJson        
   ,AmountPaid = @AmountPaid        
   ,Remarks = @Remarks        
   ,ModifiedBy = @CreatedBy        
   ,FollowupDate = @FollowupDate        
   ,@LeadNo = LeadNo        
   ,@ParentID = ParentID    
    ,LastFollowupCreatedOn = getdate()  
   ,LastFollowupCreatedBy = @CreatedBy  
  WHERE ID = @ID        
 END        
        
 DECLARE @lihid BIGINT        
  
 SET Context_Info 0x55555  
  
 IF (@NextStatusDate <> '')        
 BEGIN        
  INSERT INTO LeadInteractionHistory (        
   LeadNo        
   ,FollowUpStatus        
   ,NextStatusDate        
   ,IsReassign        
   ,ProductsJson        
   ,AmountPaid        
   ,Remarks        
   ,AssignedTo        
   ,ParentID        
   ,CreatedOn        
   ,CreatedBy        
   ,FollowupDate,id_lead        
   )        
  VALUES (        
   @LeadNo        
   ,@FollowUpStatus        
   ,convert(NVARCHAR(100), dbo.[fn_getISTtimefromusertime](@CreatedBy, @FollowupDate), 121)        
   ,@IsReassign        
   ,@ProductsJson        
   ,@AmountPaid        
   ,@Remarks        
   ,@AssignedTo        
   ,@ParentID        
   ,GETDATE()        
   ,@CreatedBy        
   ,dbo.[fn_getISTtimefromusertime](@CreatedBy, @FollowupDate),@id        
   )        
 END   
 ELSE        
 BEGIN        
  INSERT INTO LeadInteractionHistory (        
   LeadNo        
   ,FollowUpStatus        
   ,NextStatusDate        
   ,IsReassign        
   ,ProductsJson        
   ,AmountPaid        
   ,Remarks        
   ,AssignedTo        
   ,ParentID        
   ,CreatedOn        
   ,CreatedBy        
   ,FollowupDate,Id_Lead        
   )        
  VALUES (        
   @LeadNo        
   ,@FollowUpStatus        
   ,@NextStatusDate        
   ,@IsReassign        
   ,@ProductsJson        
   ,@AmountPaid        
   ,@Remarks        
   ,@AssignedTo        
   ,@ParentID        
   ,GETDATE()        
   ,@CreatedBy        
   ,@FollowupDate,@id        
   )        
 END        
        
 SELECT @lihid = SCOPE_IDENTITY()        
SET Context_Info 0x   
    
 --if(@lihid > 0)                    
 --begin                    
 --if(isnull(@EpUniqueIdentity, '') <> '')                    
 --begin                    
 -- declare @GatewayName nvarchar(255), @EntityName nvarchar(255)                    
 -- select @GatewayName = ProviderName, @EntityName = EntityName from tbl_voip_endpointInteraction(nolock)                     
 --  where id = cast(@EpUniqueIdentity as bigint)                    
 -- insert into tbl_c2c_EventActivityMapping( gateway_name, ep_interaction_id, event_history_id, EntityName )                    
 --  values( @GatewayName, cast( @EpUniqueIdentity as bigint), @lihid, @EntityName )                    
 --end                    
 --end                    
 if(isnull(@lihid,0) > 0)                              
 --IF (@@RowCount > 0)        
 BEGIN        
  SELECT 'Record Saved' AS Msg        
   ,@LeadNo AS LeadNo        
        
  --SELECT 'Lead Followup Added Successfully' AS Msg        
  -- ,@LeadNo AS LeadNo        
        
  DECLARE @Nextprocess BIT = 0        
        
  BEGIN TRY        
   IF (@FollowUpStatus = 5)        
   BEGIN        
    SET @Nextprocess = 1        
   END        
   ELSE IF EXISTS (        
     SELECT 1        
     FROM FollowUp_Status fs(NOLOCK)        
     WHERE fs.IsConvert = 1        
      AND fs.ID = @FollowUpStatus        
      AND fs.ParentId = @ParentId        
     )        
   BEGIN        
    SET @Nextprocess = 1        
   END        
        
   IF (@Nextprocess = 1)        
   BEGIN        
    DECLARE @CreateDate DATETIME = GETDATE()        
        
    EXEC Usp_Insert_Tbl_ST_SalesActivityMasterNew_Replication      
   @lihid        
     ,'LeadInteractionHistory'        
     ,@AmountPaid        
     ,@CreateDate        
     ,''        
     ,@ProductsJson        
     ,0        
     ,@CreatedBy        
     ,@ParentID        
     ,@LeadNo        
   END        
  END TRY        
        
  BEGIN CATCH        
   EXEC usp_InsertErrorInfo      
 SET Context_Info 0x   
  
  END CATCH        
        
  /* Start Lead Activity */        
  BEGIN TRY        
   DECLARE @UserID_LDACTV BIGINT = @CreatedBy        
   DECLARE @ParentID_LDACTV BIGINT = @ParentID        
   DECLARE @LeadID_LDACTV BIGINT = @ID        
   DECLARE @FollowupStatusID_LDACTV INT = @FollowUpStatus        
   DECLARE @AssingedTo_LDACTV BIGINT = isnull(@AssignedTo, 0)        
        
   CREATE TABLE #tblEventDescrb (EVNT_Description NVARCHAR(max))        
        
   IF (isnull(@LeadID_LDACTV, 0) > 0)        
   BEGIN        
    INSERT INTO #tblEventDescrb        
    EXEC Usp_EventTemplate_DynamicVarReplacement 'New Interaction added'        
     ,@UserID_LDACTV        
     ,''        
     ,''        
     ,@LeadID_LDACTV        
     ,''        
     ,NULL        
     ,0        
     ,0        
     ,''        
     ,''        
     ,0        
     ,''        
     ,0        
     ,NULL        
     ,NULL        
     ,NULL        
     ,NULL        
     ,@FollowupStatusID_LDACTV        
     ,@AssingedTo_LDACTV        
     ,NULL        
     ,NULL        
     ,NULL        
     ,NULL        
     ,NULL        
     ,NULL        
     ,NULL        
     ,NULL        
     ,NULL        
     ,NULL        
     ,NULL        
     ,0        
     ,0        
     ,0        
     ,NULL        
     ,NULL        
     ,NULL        
     ,0        
     ,NULL        
     ,NULL        
     ,NULL        
     ,0        
     ,NULL        
     ,NULL        
        
    DECLARE @evntMessage NVARCHAR(max) = ''        
        
    SELECT @evntMessage = isnull(EVNT_Description, '')        
    FROM #tblEventDescrb        
        
    IF (@evntMessage <> '')        
    BEGIN        
     EXEC UspSaveLeadActivity_withid @LeadID_LDACTV        
      ,@UserID_LDACTV        
      ,@ParentID_LDACTV        
      ,@evntMessage        
      ,'New Interaction added'        
      ,'LeadInteractionHistory'        
      ,@lihid        
    END        
   END        
  END TRY        
        
  BEGIN CATCH        
   EXEC usp_InsertErrorInfo        
  END CATCH            
  IF OBJECT_ID('tempdb..#tblEventDescrb') IS NOT NULL -- Check for table existence                              
  BEGIN        
   DROP TABLE #tblEventDescrb        
  END        
    /* End Lead Activity */        
 END        
 ELSE        
 BEGIN        
  SELECT 'Lead Followup not Added Successfully' AS Msg        
   ,@LeadNo AS LeadNo        
 END        
        
 DECLARE @rowJson NVARCHAR(MAX) = (        
   SELECT *        
   FROM LeadInteractionHistory lih        
   WHERE lih.ID = @lihid        
   FOR JSON AUTO        
    ,INCLUDE_NULL_VALUES        
   )        
        
 IF @rowJson IS NOT NULL        
 BEGIN        
  EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @CreatedBy        
   ,@Activity_type = 'Inst_flwup'        
   ,@ActionType = 'I'        
   ,@RowJson = @rowJson        
   ,@Table_name = 'leadinteractionhistory'        
 END                 
 --insert into LeadInteractionHistory                
 --(                
 --LeadNo,FollowUpStatus,                
 --NextStatusDate,Products,                
 --AmountPaid,Remarks,                
 --AssignedTo,ParentID,                
 --CreatedOn,CreatedBy,                
 --FollowupDate,          
 --IsReAssign          
 --)                
 --values                
 --(@LeadNo,@FollowUpStatus,                
 --@NextStatusDate,@Products,                
 --@AmountPaid,@Remarks,                
 --@AssignedTo,@ParentID,                
 --GETDATE(),@CreatedBy,                
 --@FollowupDate,                
 --@IsReAssign          
 --)                     
                     
 select 'Record Saved'                     
                         
End   


