/* ============================================================
   Procedure: [dbo].[Usp_InsertLeadIntractionHistory_MassOperation]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_InsertLeadIntractionHistory_MassOperation]
(
    @IDS                VARCHAR(500),
    @FollowUpStatus     INT,
    @NextStatusDate     VARCHAR(50),
    @Products           VARCHAR(1000),
    @AmountPaid         NUMERIC(18, 2),
    @Remarks            VARCHAR(1000),
    @AssignedTo         BIGINT,
    @ParentID           BIGINT,
    @CreatedBy          BIGINT
)
AS
	-- =============================================
	-- Author:      Name Vishal Kumar Srivastava
	-- Create date: 30-8-2017
	-- Description: MassOperation of Add follow up
	-- =============================================
BEGIN
	BEGIN TRY
		DECLARE @TableData TABLE 
		        (
		            LeadNo BIGINT,
		            FollowUpStatus BIGINT,
		            NextStatusDate VARCHAR(50),
		            Products VARCHAR(1000),
		            AmountPaid NUMERIC(18, 2),
		            Remarks VARCHAR(1000),
		            AssignedTo BIGINT,
		            ParentID BIGINT,
		            CreatedOn DATETIME,
		            CreatedBy BIGINT
		        )
		
		INSERT INTO @TableData
		  (
		    LeadNo,
		    FollowUpStatus,
		    NextStatusDate,
		    Products,
		    AmountPaid,
		    Remarks,
		    AssignedTo,
		    ParentID,
		    CreatedOn,
		    CreatedBy
		  )
		SELECT LeadNo,
		       @FollowUpStatus,
		       @NextStatusDate,
		       @Products,
		       @AmountPaid,
		       @Remarks,
		       @AssignedTo,
		       @ParentID,
		       GETDATE(),
		       @CreatedBy
		FROM   UserLeads u1
		WHERE  ID IN (SELECT fs.[value]
		              FROM   dbo.fn_Split(@IDS, ',') fs)
		
		INSERT INTO LeadInteractionHistory
		  (
		    LeadNo,
		    FollowUpStatus,
		    NextStatusDate,
		    Products,
		    AmountPaid,
		    Remarks,
		    AssignedTo,
		    ParentID,
		    CreatedOn,
		    CreatedBy
		  )
		SELECT LeadNo,
		       FollowUpStatus,
		       NextStatusDate,
		       Products,
		       AmountPaid,
		       Remarks,
		       AssignedTo,
		       ParentID,
		       CreatedOn,
		       CreatedBy
		FROM   @TableData
		
		SELECT 'Record Saved'
	END TRY
	BEGIN CATCH
		SELECT ERROR_NUMBER()     AS ErrorNumber,
		       ERROR_SEVERITY()   AS ErrorSeverity,
		       ERROR_STATE()      AS ErrorState,
		       ERROR_PROCEDURE()  AS ErrorProcedure,
		       ERROR_LINE()       AS ErrorLine,
		       ERROR_MESSAGE()    AS ErrorMessage;
	END CATCH
END



GO

