   Procedure: [dbo].[usp_InsertLicenceTransDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON




CREATE   PROCEDURE [dbo].[usp_InsertLicenceTransDetails]
    --@ID UNIQUEIDENTIFIER,
    @M_ID BIGINT = NULL,
	@UserId BIGINT,
    @FromUser_ID BIGINT = NULL,
    @ToUser_ID INT,
    @Debits BIGINT = NULL,
    @Credits BIGINT = NULL,
    @Balance BIGINT = NULL,
    @Validity BIGINT = NULL,
    @Default_Credit BIGINT = NULL,
    @FromDate DATETIME = NULL,
    @ToDate DATETIME = NULL,
    @typecredit NVARCHAR(50) = NULL,
	@remarks NVARCHAR(max) = NULL,
    @batchid BIGINT = NULL,
	@Monthly bit = 0,
    @Annual bit = 0,
   -- @CreatedBy BIGINT = NULL,
    @CreatedDate DATETIME = NULL,
    @ModifiedDate DATETIME = NULL,
   @LastModified DATETIME = NULL,
   @TotalLicence BIGINT = 0
AS
BEGIN
    SET NOCOUNT ON;

    BEGIN TRY
	 DECLARE @M_ID1 BIGINT;

        -- Step 1: Retrieve M_ID for the given UserID
        SELECT TOP 1 @M_ID1 = M_ID
        FROM [dbo].[User_Detail] with(nolock)
        WHERE [User_ID] = @UserID;

        -- Step 2: If M_ID is found, retrieve the associated details
        IF @M_ID1 IS NOT NULL
		BEGIN
        -- Insert the record into the table
        INSERT INTO [dbo].[Licence_Trans_Details] (
            --[ID],
            [M_ID],
            [FromUser_ID],
            [ToUser_ID],
            [Debits],
            [Credits],
            [Balance],
            [Validity],
            [Default_Credit],
            [FromDate],
            [ToDate],
            [typecredit],
            [batchid],
            [CreatedBy],
            [CreatedDate],
            [ModifiedDate],
            [LastModified],
			[IsActive],
			 [Monthly],
			[Annual],
			[Remarks],
			[TotalLicence]
        )
        VALUES (
            --@ID,
            @M_ID1,
            @FromUser_ID,
            @ToUser_ID,
            @Debits,
            @Credits,
            @Balance,
            @Validity,
            @Default_Credit,
            @FromDate,
            @ToDate,
            @typecredit,
            @batchid,
            @UserId,
            @CreatedDate,
            @ModifiedDate,
            @LastModified,
			1,
			@Monthly,
			@Annual,
			@remarks,
			@TotalLicence
        );

        -- Return success message
        SELECT 
            'Success' AS [Status],
            'Record inserted successfully.' AS [Message];
			end
			ELSE
        BEGIN
            -- If no M_ID is found, return a message
            SELECT 
                'Data not saved.' AS Message;
        END
    END TRY
    BEGIN CATCH
        exec usp_InsertErrorInfo  
        SELECT 
            'Error' AS [Status],
            ERROR_MESSAGE() AS [Message];
    END CATCH
END;

-----------------------------------------------



GO

