/* ============================================================
   Procedure: [dbo].[usp_insertloginhistory]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_insertloginhistory           
(          
 @user_id      BIGINT,           
    @IP           NVARCHAR(50)  = NULL,           
    @Browser      NVARCHAR(50)  = NULL,           
    @Device       NVARCHAR(500) = NULL,           
    @ActivityType NVARCHAR(50)  = NULL,          
    @MACAddress VARCHAR(50)  = NULL,          
    @AppVersion VARCHAR(100)  = NULL,          
    @OSVersion VARCHAR(100)  = NULL,          
    @OSName VARCHAR(100)  = NULL,          
    @ModelName VARCHAR(100)  = NULL          
)          
AS          
BEGIN          
    DECLARE @m_id BIGINT=(SELECT m_id FROM user_detail(NOLOCK) WHERE user_id = @user_id);          
    DECLARE @id BIGINT, @ldate DATETIME;          
 DECLARE @Description NVARCHAR(200);          
        
 if exists(select 1 from [loginhistory](nolock) WHERE user_id = @user_id AND ActivityType = 'Login')      
    SELECT @ldate = MAX(datecreated) FROM [loginhistory](nolock) WHERE user_id = @user_id AND ActivityType = 'Login';          
          
    INSERT INTO [loginhistory]          
    ([user_id], [m_id], IP, Browser, Device, ActivityType, Datecreated, MACAddress, AppVersion, OSVersion, OSName, ModelName)          
    SELECT @user_id, @m_id, @IP, @Browser, @Device, @ActivityType, GETDATE(), @MACAddress, @AppVersion, @OSVersion, @OSName, @ModelName;          
              
 SELECT @id = SCOPE_IDENTITY();  
 
 declare @EventDescription nvarchar(1000),@EventName nvarchar(100),@parentid bigint,@username nvarchar(100)
 select @parentid=parentid,@username=User_Login from user_detail(nolock) where user_id=@user_id
 select @EventName=
 case when @ActivityType='Login' then 'User signs in' else 'User signs out' end,
 @EventDescription=
 case when @ActivityType='Login' then @username+' signed in on device ' 
 else  @username +' signs out from device ' end +
 case when @device is null then 'Desktop' else 'Mobile' end
  
 exec uspsaveuseractivity_withid    @user_id,@user_id,@ParentID,@EventDescription,@EventName,'loginhistory',@id   
              
 DECLARE @count INT=(SELECT COUNT(1) FROM [loginhistory](NOLOCK) WHERE user_id = @user_id);          
              
 IF @m_id = 10043 AND @ActivityType = 'Login'          
 BEGIN          
  IF @count = 1          
  BEGIN          
   SELECT @Description = 'User ' + user_login + ' Logged in for the first time in Kit19'          
   FROM user_detail(NOLOCK)          
   WHERE USER_ID = @user_id;          
             
   EXEC Usp_InsertUserEventDetails 'First Time Login', @User_ID, @Description, 'loginhistory', @ID;          
  END;          
 ELSE          
  IF DATEDIFF(day, @ldate, GETDATE()) >= 15          
  BEGIN          
   SELECT @Description = 'User ' + user_login + ' Logged in after more than 15 days in Kit19. The last login recorded for user was ' + CAST(@ldate AS NVARCHAR)          
   FROM user_detail(NOLOCK)          
   WHERE USER_ID = @user_id;          
             
   EXEC Usp_InsertUserEventDetails 'User logged in after 15 or more days', @User_ID, @Description, 'loginhistory', @ID;          
  END;       
   IF not exists(select 1 from UserEvent(nolock) where event='User logged in kit19 today' and userid=@user_id and cast(createdon as date)=cast(getdate() as date)) and @ldate is not null       
  BEGIN          
   SELECT @Description = 'User ' + user_login + ' Logged in Kit19 today for the first time. The last login recorded for user was ' + CAST(@ldate AS NVARCHAR)          
   FROM user_detail(NOLOCK)          
   WHERE USER_ID = @user_id;          
             
   EXEC Usp_InsertUserEventDetails 'User logged in kit19 today', @User_ID, @Description, 'loginhistory', @ID;          
  END;             
 END;          
END;   
  
  


GO

