CREATE   PROC usp_InsertMailError  
@service nvarchar(20),@isevent nvarchar(20),@Errormessage nvarchar(max)  
as  
begin  
declare @errorid bigint  
insert into MailError(ErrorDate,AffectedService,TableName,ErrorMessage)  
select GETDATE(),@service,@isevent,@Errormessage  
set @errorid=SCOPE_IDENTITY()
declare @error nvarchar(max)=(select errormessage from mailerror where ID=@errorid)
 
 
if not exists(select 1 from mailerror where datediff(mi,errordate,getdate())<=5 and errormessage=@error)
begin 
exec usp_sendmailerrormail @errorid  
end

end







