/* ============================================================
   Procedure: [dbo].[usp_insertmassmktgsequence]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



--Dependency of this usp_insertmassmktgsequence

 

--1.MySMSConversations.dbo.fn_getnextschedule  -- called by clr
--1.MySMSConversations.dbo.tbl_WA_SequenceActionMaster (nolock)  -- called by clr

 

 

-------------------------------------

 

 

-------------------------------------------------------

 

 

CREATE   PROCEDURE [dbo].[usp_insertmassmktgsequence]      
@batchid bigint      
as      
begin      
declare @parentid bigint,@createdby bigint,@sequenceid bigint,@entity nvarchar(20),@totalrecords int,  @ids NVARCHAR(MAX)      

select @parentid=parentid,@createdby=userid,@sequenceid=json_value(metadata,'$[0].SequenceId'), @ids = JSON_VALUE(metadata,'$[0].IDS'),     
@entity=entitytype from tbl_massoperationsummary      
(nolock) where batchid=@batchid  


select @totalrecords=count(1) from tbl_massoperationdetails(nolock) where summaryid=@batchid    

 

 

DECLARE @query NVARCHAR(MAX);

 

DROP TABLE IF EXISTS #EntityIds;

 

SELECT value AS entityid
INTO #EntityIds
FROM STRING_SPLIT(@ids, ',');

 

DROP TABLE IF EXISTS #tempInsert;
CREATE TABLE #tempInsert (
    sequenceid BIGINT,
    SequenceActionId BIGINT,
    actiontype VARCHAR(50),
    actiondetails NVARCHAR(MAX),
    scheduledfor DATETIME

);

 

-- Prepare the dynamic SQL with INSERT INTO #tempInsert
SET @query = '
    SELECT 
        sequenceid,
        sequenceactionid,
        actiontype,
        actiondetails,
        ISNULL(dbo.fn_getnextschedule(sequenceactionid), GETDATE()) AS scheduledfor

    FROM tbl_WA_SequenceActionMaster (NOLOCK)
    WHERE IsActive = 1 AND IsDeleted = 0
';

 

-- Execute the CLR procedure to run the dynamic SQL
INSERT INTO #tempInsert (
        sequenceid,
        sequenceactionid,
        actiontype,
        actiondetails,
        scheduledfor

    )
EXEC usp_clr_FillRemoteData @query;

 

 

insert into tbl_mass_mktgsequence      
(batchid,sequenceid,SequenceActionId,actiontype,actiondetails,parentid,createdon,scheduledfor,      
isprocessed,processedat,taskstatus,statusreason,internal_error,entity,entityid,isstopped,stoppedby,stoppedon,      
audience_check,rule_check,entityplaceholders,createdby,totalrecords)

 

SELECT     @batchid, t.sequenceid, t.sequenceactionid,  t.actiontype, t.actiondetails, @parentid, GETDATE(), t.scheduledfor, 0, NULL, 0, NULL,
    NULL,  @entity,  e.entityid,  0,  NULL, NULL,  0, NULL, NULL, @createdby, @totalrecords FROM #tempInsert t
JOIN tbl_massoperationdetails d (NOLOCK)
    ON 1 = 1
  CROSS JOIN #EntityIds e
WHERE 
    d.summaryid = @batchid 
    AND t.sequenceid = @sequenceid;

 

 

UPDATE Tbl_MassOperationSummary  
        SET BatchEndTime = GETDATE(),  
            --ScheduleDateTime = CASE   
            --                     WHEN ScheduleDateTime IS NULL OR ScheduleDateTime = '' OR ScheduleDateTime = '1900-01-01 00:00:00.000'  
            --                     THEN @Mail_ScheduleDate  
            --                     ELSE ScheduleDateTime  
            --                   END,  
            Remarks = 'Record Saved',  
            IsProcessed = 1  
        WHERE BatchID = @batchid;  

end




