CREATE   PROC [dbo].[Usp_InsertMediumAndGetMediumID] --'annk',335         
 (@Name NVARCHAR(100), @UserID bigINT)          
  AS           
BEGIN  
 select @UserID=Parentid from user_detail(nolock) where USER_ID=@userid  
 IF (  
        NOT EXISTS(  
            SELECT 'x'  
            FROM   UserMediumSettings  
            WHERE  NAME           = @Name  
                   AND UserID     = @UserID  
        )  
    )  
 BEGIN  
     INSERT INTO UserMediumSettings  
       (  
         NAME,  
         UserID,  
         IsEditable,  
         IsActive,  
         CreatedDate,  
         ModifiedDate,  
         ModifiedBy  
       )  
     VALUES  
       (  
         @Name,  
         @UserID,  
         1,  
         1,  
         GETDATE(),  
         GETDATE(),  
         @UserID  
       )  
 END  
   
 SELECT MediumID AS MediumID  
 FROM   UserMediumSettings  
 WHERE  NAME           = @Name  
        AND UserID     = @UserID  
END  


