/* ============================================================
   Procedure: [dbo].[Usp_InsertMediumDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC dbo.Usp_InsertMediumDetails (      
 @Name NVARCHAR(100)      
 ,@UserID bigINT      
 ,@IsEditable BIT      
 ,@IsActive BIT      
 ,@CreatedBy NVARCHAR(100)      
 )      
AS      
BEGIN     
  
     DECLARE @MediumId BIGINT = 0  
  
    select @Name =  replace( replace(replace(trim(char(9) from isnull(@Name,'')),char(9),''),char(10),''),char(13),'')     

 declare @parentid bigint=    
 (SELECT Parentid      
 FROM user_detail(NOLOCK)      
 WHERE USER_ID = @userid  )    
      
 IF (      
   NOT EXISTS (      
    SELECT 'x'      
    FROM UserMediumSettings      
    WHERE NAME = @Name      
       AND UserID in (select User_ID  from user_detail(nolock) where parentid=@parentid)    
    )      
   )      
 BEGIN      
  INSERT INTO UserMediumSettings (      
   NAME      
   ,UserID      
   ,IsEditable      
   ,IsActive      
   ,CreatedDate      
   ,ModifiedDate      
   ,ModifiedBy      
   )      
  VALUES (      
   @Name      
   ,@parentid      
   ,@IsEditable      
   ,@IsActive      
   ,GETDATE()      
   ,GETDATE()      
   ,@CreatedBy      
   )      
      
  SELECT 'Record Saved'      
      
   set @MediumId = SCOPE_IDENTITY();      
 END      
 ELSE      
 BEGIN  
   
      IF(      
     EXISTS (      
  SELECT 'x'      
  FROM UserMediumSettings      
  WHERE NAME = @Name      
   AND UserID in (select User_ID  from user_detail(nolock) where parentid=@parentid and IsActive = 0)    
  )      
    )          
     begin  
       update  UserMediumSettings set IsActive = 1 , UserID = @parentid  , ModifiedBy =  @CreatedBy ,ModifiedDate = getdate()  
            WHERE NAME = @Name      
             AND UserID in (select User_ID  from user_detail(nolock) where parentid=@parentid and IsActive = 0)    
  
   SELECT 'Record Saved'      
  
      select top 1 @MediumId  = MediumId from UserMediumSettings (nolock)  
            WHERE NAME = @Name      
             AND UserID in (select User_ID  from user_detail(nolock) where parentid=@parentid)      
   
  end  
  else  
   begin  
        SELECT 'Already Exist'      
      end        
  
  --SELECT 'Already Exist'      
 END      
      
 DECLARE @rowJson NVARCHAR(MAX) = (      
   SELECT *      
   FROM UserMediumSettings(NOLOCK)      
   WHERE MediumID = @MediumId      
   FOR JSON AUTO      
    ,INCLUDE_NULL_VALUES      
   )      
      
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID      
  ,@Activity_type = 'Inst_Med_Sttng'      
  ,@ActionType = 'I'      
  ,@RowJson = @rowJson      
  ,@Table_name = 'UserMediumSettings'      
END 


GO

