SET QUOTED_IDENTIFIER ON

/**********************      
SP use for Insert Record in Message_Detail      
********************/      
CREATE   PROC Usp_InsertMessageDetail      
(@BATCHID bigint      
)      
As      
Begin      
Declare @UserId int,@dnd int,@invalid int,@total int      
SELECT top(1) @dnd=isnull(operator,0), @total=TotalRecords,@UserId=userid,@invalid=InvalidCount FROM batchinfo with(nolock) WHERE batchid=@BATCHID                  
if @total<>''  
begin      
if exists(select 'X' from message_detail with(nolock) where Batchid=@BATCHID)      
Begin      
update message_detail set dnd=@dnd,Invalid=@invalid,total=@total where Batchid=@BATCHID      
End      
Else      
Begin      
Insert into message_detail(UserId,Batchid,total,Dnd,Invalid)      
Values(@UserId,@Batchid,@total,@Dnd,@Invalid)      
End      
End  
End 


