/* ============================================================
   Procedure: [dbo].[USP_INSERTMESSAGESOURCETEMP]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [DBO].USP_INSERTMESSAGESOURCETEMP     --112327,0,0,1 --1148,0,0,2                                               
           @BATCHID      BIGINT,                     
           @PRIORITY     TINYINT,                     
           @ALLOWDND     BIT,                     
           @PROCESSTABLE INT                     
AS                     
  SET NOCOUNT ON              
  BEGIN                     
           
 DECLARE  @COUNTROW BIGINT            
 DECLARE  @TABLE_NAME VARCHAR(20)            
 DECLARE  @QUERYFORID NVARCHAR(MAX)          
 DECLARE  @QUERYTEMP NVARCHAR(MAX)   
 DECLARE  @QUERYSOURCE NVARCHAR(MAX)          
                             
    DECLARE  @FROMID    BIGINT,                     
             @MAXID     BIGINT,                     
             @TOID      BIGINT,                     
             @BATCHSIZE BIGINT                     
                         
    SET @BATCHSIZE = 50000 -- BATCHSIZE CAN BE CHANGED                        
                         
    SET @COUNTROW = 0             
           
 IF @PROCESSTABLE=1          
  BEGIN          
   SET @TABLE_NAME='PROCESSTABLEFIRST'           
  END          
 ELSE IF @PROCESSTABLE=2          
  BEGIN          
   SET @TABLE_NAME='PROCESSTABLETWO'           
  END              
 ELSE IF @PROCESSTABLE=3          
  BEGIN          
   SET @TABLE_NAME='PROCESSTABLETHREE'           
  END              
 ELSE IF @PROCESSTABLE=4          
  BEGIN          
   SET @TABLE_NAME='PROCESSTABLEFOUR'           
  END              
          
SET @QUERYFORID=' SELECT @FROMID = MIN(PROCESSID),@MAXID = MAX(PROCESSID) FROM '+@TABLE_NAME+' WHERE BATCHID = '+CAST(@BATCHID AS VARCHAR(20))+''    EXEC SP_EXECUTESQL @QUERYFORID,N'@FROMID BIGINT OUTPUT,@MAXID BIGINT OUTPUT', @FROMID OUTPUT,@MAXID OUTPUT;           
 SET TRANSACTION ISOLATION LEVEL SNAPSHOT ;                            
 SET XACT_ABORT ON ;                
 SET @TOID = @FROMID + @BATCHSIZE                             
    IF @TOID > @MAXID  -- CHECK CONDITION                             
      SET @TOID = @MAXID  -- SET TO ID                             
WHILE @FROMID < = @MAXID -- USED WHILE LOOP                             
BEGIN                             
BEGIN TRY                             
  BEGIN TRAN                             
    BEGIN             
	 SET @QUERYTEMP='INSERT INTO MESSAGEDELIVERYSTATUSTEMP(MESSAGEID,BATCHID,MOBILE,MESSAGE,SENDERID,SMPPID,U_ID,PRIORITY,ISUNICODE,MESSAGESTATUS,			MESSAGEINSERTDATE,OPERATOR,DATECREATED)                     
		SELECT MESSAGEID,BATCHID,MOBILE,[MESSAGE],SENDERID,SMPPID,U_ID,PRIORITY,ISUNICODE,''DND'',MESSAGEINSERTDATE,OPERATOR,GETDATE() FROM 
		'+@TABLE_NAME+' WHERE  BATCHID = '+CONVERT(NVARCHAR,@BATCHID)+' AND ISDND = 1 AND PRIORITY <> 2 AND ISNULL(MESSAGESTATUS,'''')=''''                  AND ISNULL(SPAM,0) = 0 AND PROCESSID >='+ CONVERT(NVARCHAR,@FROMID)+' AND PROCESSID <='+CONVERT(NVARCHAR, @TOID)+''             
	SET @QUERYSOURCE='INSERT INTO MESSAGESOURCE(MESSAGEID,MESSAGEBATCHID,MOBILE,[MESSAGE], SENDERID,SMPPID,U_ID,PRIORITY,ISUNICODE,ISDND,OPERATOR,			ISALLOWDND)                     
		SELECT MESSAGEID,BATCHID,MOBILE,[MESSAGE],SENDERID,SMPPID,U_ID,PRIORITY,ISUNICODE,ISDND,OPERATOR,ISALLOWDND FROM '+@TABLE_NAME+'                     WHERE BATCHID = '+CONVERT(NVARCHAR,@BATCHID)+' AND ISDND = 0 AND PRIORITY <> 2 AND ISNULL(MESSAGESTATUS,'''')='''' AND ISNULL(SPAM,0) = 0            AND PROCESSID >='+ CONVERT(NVARCHAR,@FROMID)+' AND PROCESSID <='+CONVERT(NVARCHAR, @TOID)+''             
        EXEC (@QUERYTEMP)
        EXEC (@QUERYSOURCE)                           
   END              
          IF @@TRANCOUNT > 0                             
            COMMIT                             
        END TRY                             
        BEGIN CATCH                             
          PRINT 'INSERT AND DELETE ERROR'                        
          IF @@TRANCOUNT > 0                             
            ROLLBACK                             
EXEC USP_INSERTERRORINFO
    END CATCH                             
    IF @TOID >= @MAXID                             
      BREAK                             
    SET @FROMID = @TOID + 1                             
    SET @TOID = @FROMID + @BATCHSIZE                             
    IF @TOID > @MAXID                             
      SET @TOID = @MAXID                             
  END                   
END 


GO

