   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_insertmissingleadinteraction
as
begin
DECLARE @c int=0
select @c=(select 
count(1) from userleads(nolock) u 
where 
not exists(select 1 from LeadInteractionHistory(nolock) where leadno=u.leadno and parentid=u.parentid))


select 
top 10 u.id from userleads(nolock) u 
where 
not exists(select 1 from LeadInteractionHistory(nolock) where leadno=u.leadno and parentid=u.parentid)--11662963,11947798,11647187

while @c>0
begin
set Context_Info 0x55555
insert into LeadInteractionHistory(LeadNo,FollowUpStatus,NextStatusDate,Remarks,Products,AmountPaid,AssignedTo,ParentID,CreatedOn,CreatedBy,
FollowupDate,IsReassign,id_lead)
select top 100 LeadNo,isnull(FollowUpStatus,1),isnull(FollowupDate,createdon),Remarks,Products,AmountPaid,AssignedTo,ParentID,CreatedOn,CreatedBy,
isnull(FollowupDate,createdon),0,id from userleads(nolock) u 
--join
--enquirysources e on e.id=u.enquirysource
where 
not exists(select 1 from LeadInteractionHistory(nolock) where leadno=u.leadno and parentid=u.parentid)
--and parentid=38738
--and u.enquirysource not in (12,13,14)
order by createdon
set Context_Info 0x

set @c=@c-1000
select @c,getdate()
end

end


