/* ============================================================
   Procedure: [dbo].[usp_insertnewcall]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_insertnewcall]
@user_id bigint,
@route nvarchar(20),
@mobile nvarchar(max),
@appid int,
@callerid nvarchar(20),
@duration int,
@callsid bigint
as
begin
declare @batchid bigint
begin tran
INSERT INTO Getbatchrecord                                                
([User_id],RandNum)     
select @user_id,@user_id
select @batchid=SCOPE_IDENTITY()
delete From GetBatchRecord where BatchID=@batchid
commit
select value into #mobile from fn_split(@mobile,',')
declare @mcount int=
(select COUNT(1) from #mobile)
        
 select * into #temp from dbo.fn_GetVoiceCreditCalculation(@route,@user_ID,@duration,@mcount)  
 declare @credits numeric(18,4) =(select balance from #temp)                      
 if exists(select 1 from #temp where msg='ok')
 begin
  INSERT INTO  Clone_VoiceDeliveryStatus --clonemessagedeliverystatus                                        
   ( BatchID,  didno, Mobile, voiceDuration, AppId, IsDnd, IsPrority, IsAllowDND,   price, user_id, VoiceInsertDate, voice_type,route)                  
 SELECT @batchid, @callerid,m.value,@duration,@appid,0,2,0,@credits,@user_id,GETDATE(),1, @route                       FROM   #mobile m                    
  end
  else
  begin
  select 1--send notification proc to be placed here
  end
                 
                      
end                      


GO

/* ============================================================
   Procedure: [dbo].[usp_insertnewcallForBroadcast]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_insertnewcallForBroadcast --335,'trans','7840002738',659,'1204862660',120,null          
	@user_id BIGINT
	,@route NVARCHAR(20)
	,@mobile NVARCHAR(max)
	,@appid INT
	,@callerid NVARCHAR(20)
	,@duration INT
	,@scheduledfor DATETIME = NULL
	,@EntityName NVARCHAR(255) = ''
	,@EntityId BIGINT = 0
AS
BEGIN
	--declare @user_id bigint = 34594, @route nvarchar(20)= N'promo', @mobile  nvarchar(max) = N'9821592374', @appid int=4109,@callerid nvarchar(20) =N'1204759813', @duration int =30,@scheduledfor datetime = null    
	SET @scheduledfor = coalesce(@scheduledfor, getdate())

	DECLARE @batchid BIGINT

	BEGIN TRAN

	INSERT INTO Getbatchrecord (
		[User_id]
		,RandNum
		)
	SELECT @user_id
		,@user_id

	SELECT @batchid = SCOPE_IDENTITY()

	DELETE
	FROM GetBatchRecord
	WHERE BatchID = @batchid

	COMMIT

	DROP TABLE

	IF EXISTS #mobile
		DROP TABLE

	IF EXISTS #temp
		SELECT value
		INTO #mobile
		FROM fn_split(@mobile, ',')

	DECLARE @mcount INT = (
			SELECT COUNT(1)
			FROM #mobile
			)

	SELECT *
	INTO #temp
	FROM dbo.fn_GetVoiceCreditCalculation(@route, @user_ID, @duration, @mcount)

	DECLARE @credits NUMERIC(18, 4) = (
			SELECT balance
			FROM #temp
			)

	SELECT *
	FROM #temp
	WHERE msg = 'ok'

	IF EXISTS (
			SELECT 1
			FROM #temp
			WHERE msg = 'ok'
			)
	BEGIN
		INSERT INTO Clone_VoiceDeliveryStatus --clonemessagedeliverystatus                                                  
			(
			BatchID
			,didno
			,Mobile
			,voiceDuration
			,AppId
			,IsDnd
			,IsPrority
			,IsAllowDND
			,price
			,user_id
			,VoiceInsertDate
			,ScheduledDate
			,voice_type
			,route
			)
		SELECT @batchid
			,@callerid
			,m.value
			,@duration
			,@appid
			,0
			,2
			,0
			,@credits
			,@user_id
			,GETDATE()
			,@scheduledfor
			,1
			,@route
		FROM #mobile m

		SELECT SCOPE_IDENTITY();
	END
	ELSE
	BEGIN
		--send notification proc to be placed here          
		DECLARE @mail NVARCHAR(200) = (
				SELECT email
				FROM user_detail(NOLOCK)
				WHERE user_id = @user_id
				)
	END

	IF (@EntityId > 0)
	BEGIN
		IF (LOWER(@EntityName) = 'lead')
		BEGIN
			DECLARE @LeadID BIGINT
				,@UserID BIGINT
				,@ParentID BIGINT
				,@EventDescription NVARCHAR(MAX)
				,@EventName NVARCHAR(500)
				,@reftables NVARCHAR(500)
				,@refid NVARCHAR(100)
				,@username NVARCHAR(255)
				,@ivr_name NVARCHAR(255) = ''

			SET @LeadID = @EntityId;
			SET @UserID = @user_id;

			SELECT @ParentID = ParentID
				,@username = User_Login
			FROM User_Detail(NOLOCK)
			WHERE User_Id = @user_id

			SET @EventName = 'Voice sent to lead'
			SET @ivr_name = (
					SELECT AppName
					FROM Cloud_app_master
					WHERE AppId = @appid
					)
			SET @EventDescription = CONCAT (
					@username
					,' sent an automated call on mobile '
					,@mobile
					,' with ivr '
					,@ivr_name
					,' and did no. '
					,@callerid
					,' to mobile '
					,@mobile
					,'.'
					)
			SET @reftables = 'BatchVoiceInfo'
			SET @refid = @batchid

			EXEC UspSaveLeadActivity_withid @LeadId
				,@UserID
				,@ParentID
				,@EventDescription
				,@EventName
				,@reftables
				,@refid
		END

		IF (LOWER(@EntityName) = 'enquiry')
		BEGIN
			SET @LeadID = @EntityId;
			SET @UserID = @user_id;

			SELECT @ParentID = ParentID
				,@username = User_Login
			FROM User_Detail(NOLOCK)
			WHERE User_Id = @user_id

			SET @EventName = 'Voice sent to Enquiry'
			SET @ivr_name = (
					SELECT AppName
					FROM Cloud_app_master
					WHERE AppId = @appid
					)
			SET @EventDescription = CONCAT (
					@username
					,' sent an automated call on mobile '
					,@mobile
					,' with ivr '
					,@ivr_name
					,' and did no. '
					,@callerid
					,' to mobile '
					,@mobile
					,'.'
					)
			SET @reftables = 'BatchVoiceInfo'
			SET @refid = @batchid

			EXEC UspSaveEntityActivity_withid 'enquiry'
				,@LeadId
				,@UserID
				,@ParentID
				,@EventDescription
				,@EventName
				,@reftables
				,@refid
		END
	END

	DECLARE @rowJson VARCHAR(MAX) = (
			SELECT *
			FROM Clone_VoiceDeliveryStatus
			WHERE BatchID = @batchid
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)
			,@Activity_type NVARCHAR(MAX) = 'Inst_voice_'+@EntityName

	IF @rowJson IS NOT NULL
	BEGIN
		EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @user_id
			,@Activity_type = '@Activity_type'
			,@ActionType = 'I'
			,@RowJson = @rowJson
			,@Table_name = 'custm_Analytics'
	END
END



GO

/* ============================================================
   Procedure: [dbo].[usp_insertnewcallForBroadcast_bulk]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_insertnewcallForBroadcast_bulk] --335,'trans','7840002738',659,'1204862660',120,null        
@entities as entities readonly,
@user_id bigint,        
@route nvarchar(20),        
@appid int,        
@callerid nvarchar(20),        
@duration int,        
@scheduledfor datetime=null,  
@batchid bigint output  
as        
begin        
set @scheduledfor=coalesce(@scheduledfor,getdate())        
--declare @batchid bigint
declare @entity nvarchar(20)=(select top 1 entity from @entities)
begin tran        
INSERT INTO Getbatchrecord                                                        
([User_id],RandNum)             
select @user_id,@user_id        
select @batchid=SCOPE_IDENTITY()        
delete From GetBatchRecord where BatchID=@batchid        
commit   
drop table if exists #mobile
create table #mobile(mobile nvarchar(20))
if @entity='lead'
begin
insert into #mobile(mobile)
select mobile from Userleads_Mobile_Email u join @entities e on u.ulme_id=e.entityid and mobile<>'0'
end
else
begin
insert into #mobile(mobile)
select mobile from Userenquiry_Mobile_Email u join @entities e on u.enquiryid=e.entityid and mobile<>'0'

end

declare @mcount int=        
(select COUNT(1) from #mobile)        
                
 select * into #temp from dbo.fn_GetVoiceCreditCalculation(@route,@user_ID,@duration,@mcount)          
 declare @credits numeric(18,4) =(select balance from #temp)      
     
    
 if exists(select 1 from #temp where msg='ok')        
 begin    
 
  INSERT INTO  Clone_VoiceDeliveryStatus --clonemessagedeliverystatus                                                
   ( BatchID,  didno, Mobile, voiceDuration, AppId, IsDnd, IsPrority, IsAllowDND,   price, user_id, VoiceInsertDate,ScheduledDate, voice_type,route)                          
 SELECT @batchid, @callerid,m.mobile,@duration,@appid,0,2,0,@credits,@user_id,GETDATE(),@scheduledfor,1, @route                       FROM   #mobile m      
     
 --SELECT SCOPE_IDENTITY()    
    
  end        
  else        
  begin        
  --send notification proc to be placed here        
  declare @mail nvarchar(200)= (select email from user_detail(nolock) where user_id=@user_id)      
  end        
                         
                              
end 


GO

/* ============================================================
   Procedure: [dbo].[usp_insertnewcallForBroadcast_vsource]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_insertnewcallForBroadcast_vsource --335,'trans','7840002738',659,'1204862660',120,null            
 @user_id BIGINT    
 ,@route NVARCHAR(20)    
 ,@mobile NVARCHAR(max)    
 ,@appid INT    
 ,@callerid NVARCHAR(20)    
 ,@duration INT    
 ,@scheduledfor DATETIME = NULL    
 ,@vsource NVARCHAR(100) = NULL    
 ,@entity NVARCHAR(50) = NULL    
 ,@id BIGINT = NULL    
AS    
BEGIN    
 SET @scheduledfor = coalesce(@scheduledfor, getdate())    
    
 DECLARE @batchid BIGINT    
  ,@eventdescription NVARCHAR(1000)    
  ,@eventname NVARCHAR(100)    
  ,@ivrname NVARCHAR(100)    
  ,@parentid BIGINT    
    
 SELECT @parentid = parentid    
 FROM User_Detail(NOLOCK)    
 WHERE user_id = @user_id    
    
 BEGIN TRAN    
    
 INSERT INTO Getbatchrecord (    
  [User_id]    
  ,RandNum    
  )    
 SELECT @user_id    
  ,@user_id    
    
 SELECT @batchid = SCOPE_IDENTITY()    
    
 DELETE    
 FROM GetBatchRecord    
 WHERE BatchID = @batchid    
    
 COMMIT    
    
 SELECT value    
 INTO #mobile    
 FROM fn_split(@mobile, ',')    
    
 DECLARE @mcount INT = (    
   SELECT COUNT(1)    
   FROM #mobile    
   )    
    
 DROP TABLE    
    
 IF EXISTS #temp    
  SELECT *    
  INTO #temp    
  FROM dbo.fn_GetVoiceCreditCalculation(@route, @parentid, @duration, @mcount)    
    
 DECLARE @credits NUMERIC(18, 4) = (    
   SELECT balance    
   FROM #temp    
   )    
    
 SELECT @ivrname = AppName    
 FROM Cloud_app_master(NOLOCK)    
 WHERE AppId = @appid    
    
 IF EXISTS (    
   SELECT 1    
   FROM #temp    
   WHERE msg = 'ok'    
   )    
 BEGIN    
  INSERT INTO Clone_VoiceDeliveryStatus --clonemessagedeliverystatus                                                    
   (    
   BatchID    
   ,didno    
   ,Mobile    
   ,voiceDuration    
   ,AppId    
   ,IsDnd    
   ,IsPrority    
   ,IsAllowDND    
   ,price    
   ,user_id    
   ,VoiceInsertDate    
   ,ScheduledDate    
   ,voice_type    
   ,route    
   ,voice_source    
   ,parentid    
   )    
  SELECT @batchid    
   ,@callerid    
   ,m.value    
   ,@duration    
   ,@appid    
   ,0    
   ,2    
   ,0    
   ,@credits    
   ,@user_id    
   ,GETDATE()    
   ,@scheduledfor    
   ,1    
   ,@route    
   ,@vsource    
   ,@parentid    
  FROM #mobile m    
    
  SELECT SCOPE_IDENTITY()    
    
  IF isnull(@entity, '') <> ''    
  BEGIN    
   SELECT @eventname = 'Voice sent to ' + @entity    
    ,@eventdescription = dbo.fn_getentityfullname('user', @user_id) + ' sent an automated call to ' + @entity + ' Name: ' + dbo.fn_getentityfullname(@entity, @id) + ' with ivr ' + @ivrname + ' and didno ' + cast(@callerid AS NVARCHAR)    
    
   EXEC UspSaveEntityActivity_withid @entity    
    ,@id    
    ,@user_id    
    ,@parentid    
    ,@eventdescription    
    ,@eventname    
    ,'BatchVoiceInfo'    
    ,@batchid    
  END    
 END    
 ELSE    
 BEGIN    
  --send notification proc to be placed here            
  DECLARE @mail NVARCHAR(200) = (    
    SELECT email    
    FROM user_detail(NOLOCK)    
    WHERE user_id = @user_id    
    )    
 END    
    
 DECLARE @rowJson NVARCHAR(MAX) = (    
   SELECT *    
   FROM Clone_VoiceDeliveryStatus WITH(NOLOCK)    
   WHERE BatchID = @batchid    
   FOR JSON AUTO    
    ,INCLUDE_NULL_VALUES    
   )    
  ,@Activity_type NVARCHAR(MAX) = 'Inst_voice_'+@entity    
    
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @user_id = @user_id    
  ,@Activity_type = @Activity_type    
  ,@ActionType = 'I'    
  ,@RowJson = @rowJson    
  ,@Table_name = 'Clone_VoiceDeliveryStatus'    
END 


GO

