/* ============================================================
   Procedure: [dbo].[usp_insertnotification]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_insertnotification](@activityid bigint,@entityname nvarchar(100))                                                      
as                                                      
begin       
    
--insert into notificationerrortrace(activityid,entity)                                      
--select @activityid,@entityname   
  
declare @parentid bigint ,@eventid int,@refid bigint,@reftables nvarchar(100),@leadid bigint,@ename nvarchar(100),@edescription nvarchar(2000),@entityid bigint                                              
if @entityname='lead'                                                    
select @parentid= parentid,@eventid=EventID,@refid=refids,@reftables=reftables,@leadid=leadid,@edescription=eventdescription,@entityid=leadid from tbl_leadeventhistory(nolock) where historyid=@activityid                                                    
else if @entityname='enquiry'                                                     
select @parentid= parentid,@eventid=EventID,@edescription=eventdescription,@entityid=enquiryid from tbl_enquiryeventhistory(nolock) where historyid=@activityid                                                    
else if @entityname='user'                                                     
select @parentid= parentid,@eventid=EventID from tbl_usereventhistory(nolock) where historyid=@activityid                                                    
else if @entityname='contact'                                                     
select @parentid= parentid,@eventid=EventID from tbl_contacteventhistory(nolock) where historyid=@activityid                                                    
        
select @ename=eventname from activitymaster(nolock) where id=@eventid           
if exists (select 1 from adminnotificationsettings(nolock) a                              
where a.parentid=@parentid and a.isactive=1 and ans_eventid=@eventid)  
begin  
insert into scheduledtodos(parentid,eventid,activityid,createdon,reftable,refid,isnotified,refcolumn,scheduledfor,isvalid)                              
select @ParentID,@eventid,@activityid,getdate(),@reftables,@refid,0,'',getdate(),1     
end  
                            
                              
if @entityname='lead' and @eventid in (41,43,54,50,51,55,10,42,44,45,46,56)                             
begin                              
declare @typeofevent nvarchar(100)                              
select @typeofevent=EventType FROM   ActivityMaster(nolock) WHERE @eventid=id                              
if (@typeofevent in ('task','appointment','deal') or @eventid=10)                              
and                              
(                              
exists(select 1 from adminnotificationsettings(nolock) a                                
where a.parentid=@parentid and a.isactive=1 and ans_eventid=case when @typeofevent='task' then 151 when @typeofevent                              
='Appointment' then 152 when @typeofevent='Deal' then 154 when @eventid=10 then 153 end))                               
begin                              
  --,151,152,153,154                              
 declare @duedate datetime,@refcolumn nvarchar(100)='',@duetype nvarchar(20)=case when @eventid=10 then 'FollowUp' else @typeofevent end                              
 select @duedate=case when IsAppointment=1 then startdate else enddate end,@refcolumn=case when IsAppointment=1 then 'startdate' else 'enddate' end                               
 from tbl_tsk_TaskHistory(nolock) where id=@refid and @typeofevent in ('task','appointment')                              
 select @duedate=followupdate,@refcolumn='followupdate'                              
 from leadinteractionhistory(nolock) where id=@refid and @eventid =10                              
 select top 1  @duedate=dateadd(dd,p.DealExpiry,min(l.createddate))                              
 from leadpipelinemapping(nolock) l join Pipeline_Master p (nolock) on p.id=l.PipelineID                              
 where leadid=@leadid and l.IsDeleted=0 and @typeofevent ='Deal'                              
 group by LeadID,l.PipelineID,p.DealExpiry                              
                              
If @EventID in (41,43,54,50,51,55,10) --activity added or edited                              
begin                              
if exists(select 1 from scheduledtodos(nolock) where reftable=@reftables and refid=@refid and parentid=parentid)                              
and @EventID in (41,43,54,50,51,55)                              
begin                              
update scheduledtodos set scheduledfor=@duedate,isnotified=0,isvalid=1                              
where reftable=@reftables and refid=@refid and parentid=parentid  and eventid in (151,152,153,154)                            
end                              
else if exists (select 1 from scheduledtodos (nolock) s where isnotified=0 and s.eventid=153 and         
activityid in (select historyid from tbl_leadeventhistory(nolock) t where t.leadid=@leadid and eventid=10) and @eventid=10)                              
 begin                              
update s set scheduledfor=@duedate,isnotified=0,isvalid=case when @duedate is not null then 1 else 0 end,      
activityid=@activityid,reftable=@reftables,refid=@refid,refcolumn=@refcolumn         
from scheduledtodos s where isnotified=0 and s.eventid=153 and         
activityid in (select historyid from tbl_leadeventhistory(nolock) t where t.leadid=@leadid and eventid=10)        
end                              
else                              
begin                              
insert into scheduledtodos(parentid,eventid,activityid,createdon,reftable,refid,isnotified,refcolumn,scheduledfor,isvalid)                              
select @ParentID,case when @typeofevent='task' then 151 when @typeofevent                              
='Appointment' then 152 when @typeofevent='Deal' then 154 when @eventid=10 then 153 end,      
@activityid,getdate(),@reftables,@refid,0,          
@refcolumn,@duedate,1                              
end                              
end                              
else if @eventid in (42,44,45,46,56)                              
begin                              
update scheduledtodos set isvalid=0 where reftable=@reftables and refid=@refid and parentid=@parentid and eventid between 151 and 154                             
end                              
end                              
end                              
  
/* Commented below code so the notification could go from scheduledtodos  
DECLARE @nid TABLE                                                          
  (                                                          
   [modeid]         INT,                                                          
   [notificationid] BIGINT,                                                          
   [roleid]         INT,                                                          
   [activityid]     INT                                                        
  );                                                         
  
                                                    
INSERT INTO @nid([modeid], [notificationid], [roleid], [activityid])                                                          
SELECT [modeid], n.[id], n.[roleid], [activityid]                                                           
FROM   notificationsmaster(NOLOCK) n                        
join  adminnotificationsettings(nolock) a on a.notificationid=n.id and a.parentid=@parentid and a.isactive=1                      
WHERE  [activityid] = @eventid;                                                    
                                                
drop table if exists #nusers                                              
create table #nusers(nuserids nvarchar(max),nroleid int)                                              
declare @t int=(select count(1) from @nid),@rolename nvarchar(50),@rid int=0                                              
while @t>0                                              
begin                                             
select @rid=min(roleid) from @nid where roleid>@rid                                              
select @rolename=s.rolename from systemroles(nolock) s where s.id=@rid                                              
insert into #nusers(nuserids,nroleid)                                              
select f.value,@rid from dbo.fn_split(dbo.fn_GetUseridFromRole(@entityname,@activityid,@rolename),',') f where f.value<>'0'                                              
set @t=@t-1                                              
end                                         
                                                    
begin try                                                       
if exists(select 1 from adminnotificationsettings (nolock) a join @nid n on n.notificationid=a.notificationid and n.modeid=2                                                 and a.parentid=@parentid and a.isactive=1)                                       
  
     
            
begin                                              
drop table if exists #a                                                
declare @allrole nvarchar(max)                                        
select @allrole=coalesce(@allrole+',','')+s.rolename from adminnotificationsettings (nolock) a                                         
join @nid n on n.notificationid=a.notificationid and n.modeid=2 and a.parentid=@parentid and a.isactive=1                                                  
join systemroles s on s.id=a.roleid                                                  
                                        
select distinct str(mobile,10) mobile into #a                                                   
from                                         
user_detail(nolock) u where u.user_id in                                            
(select roleuserid from dbo.fn_GetTBLUseridFromRole(@entityname,@activityid,@allrole) where roleuserid<>0)         
        
        
                                   
                                        
/*                           
select a.*,'' as smscontent,str(mobile,10) mobile into #a                                                     
from adminnotificationsettings (nolock) a join @nid n on n.notificationid=a.notificationid and n.modeid=2                                                     
and a.parentid=@parentid and a.isactive=1                                                    
join systemroles s on s.id=a.roleid                                    
join user_detail(nolock) u on u.user_id in                                                     
(select value from dbo.fn_split(dbo.fn_getuseridfromrole(@entityname,@activityid,s.rolename),',') where value<>0)                                
*/                                        
                                                    
declare @smsn nvarchar(2000),@dltid nvarchar(100)         
select @smsn=smscontent,@dltid=DLTTemplateID from DLTMappedEvent(nolock) where eventid=@eventid           
        
if @smsn is null begin if @entityname='lead'  begin select @dltid='1707163185631378512',@edescription=eventdescription,@entityid=leadid from tbl_leadeventhistory(nolock)      
where historyid=@activityid select @smsn='New event for lead: '+cast(l.LeadNo as nvarchar)+', Name: '+isnull(personname,' ')+'.Event:'        
+left(@ename,30)+ '.Details:'+left(isnull(@edescription,''),120)+': Team Kit19'        
from userleads(nolock) l where l.id=@entityID end else  if @entityname='enquiry' begin  select @dltid='1707163185643541025',@edescription=eventdescription,@entityid=enquiryid from tbl_enquiryeventhistory(nolock) where historyid=@activityid select @smsn='N
  
    
      
ew event for enquiry: '+cast(l.enquiryid as nvarchar)+', Name: '+isnull(personname,' ')+'.Event:'        
+left(@ename,30)+ '.Details:'+left(isnull(@edescription,''),120)+': Team Kit19'        
 from userenquiry(nolock) l where l.enquiryid=@entityID end GOTO RESUME end        
        
        
               
drop table if exists #activitymetadata                                       
create table #activitymetadata(entitydetails nvarchar(max),activitydetails nvarchar(max),userdetails nvarchar(max))                                        
insert into #activitymetadata(entitydetails,activitydetails,userdetails)                              
exec usp_getmetadata_foractivity @activityid,@entityname                                                    
                                                    
declare @e nvarchar(max),@a nvarchar(max),@u nvarchar(max)                                                    
select @e=substring(entitydetails,2,len(entitydetails)-1),@a=substring(activitydetails,2,len(activitydetails)-1)                                                    
,@u=substring(userdetails,2,len(userdetails)-1)              
--replace(replace(userdetails,'[',''),']','')                                                    
from #activitymetadata                                                    
drop table if exists #metadata                                           
create table #metadata(id int identity(1,1),keyv nvarchar(500) null,valuev nvarchar(max) null,typev int null)                                                    
if isnull(@e,'')<>'' and isnull(@a,'')<>''                                                    
begin                                                    
insert into #metadata(keyv,valuev,typev)                                        
select '#'+[key]+'#',cast(value as nvarchar),type from openjson(@e)                                                    
union all                                                    
select '#'+[key]+'#',cast(value as nvarchar),type from openjson(@a)                                                    
union all                                                    
select '#'+[key]+'#',cast(value as nvarchar),type from openjson(@u)                                                    
update #metadata set valuev='' where valuev is null                                                    
end                                             
if exists(select 1 from #metadata)                          
begin                                 
--select * from #metadata                                                    
declare @s int=0,@sid int=(select count(1) from systemroles)                                                    
--select * from systemroles                                                    
if exists (select 1 from systemroles where @smsn like '%#Role.'+rolename+'#%')                                                    
begin                                                    
while @s<=@sid                
begin                                                    
select @s=min(id) from systemroles where id>@s                                                    
--select @s,rolename,@smsn  from systemroles where id=@s                                                    
select @smsn=replace(@smsn,'#Role.'+rolename+'#',user_login) from systemroles s (nolock)                                                    
join user_detail u(nolock) on cast(u.user_id as nvarchar)=dbo.fn_GetUseridFromRole('lead',@activityid,s.rolename) and s.id=@s                                                    
--select @smsn                                                    
end                                                    
end                                                    
if exists (select 1 from #metadata where @smsn like '%'+keyv+'%')                                                    
begin                                                    
declare @mid int=0,@max int=(select count(1) from #metadata)                                                    
while @mid<=@max                                                     
begin                                                    
select @mid=min(id) from #metadata where id>@mid                               
select @smsn=replace(@smsn,keyv,isnull(cast(valuev as nvarchar),'')) from #metadata where @mid=id                                                    
end                                                    
end                                                    
                                  
end         
RESUME:        
drop table if exists #b                                          
select distinct mobile into #b from #a                                          
declare @mobile nvarchar(max)                                            
select @mobile=coalesce(@mobile+',','')+cast(mobile as nvarchar) from #b where isnull(nullif(cast(mobile as nvarchar),'0'),'')<>''                                                                     
end                                                  
end try                    
begin catch                                                    
exec usp_inserterrorinfo                                        
insert into notificationerrortrace(activityid,entity)                                      
select @activityid,@entityname                                       
end catch          
        
--RESUME:        
        
                                                   
