eventtype,eventname,t.parentid,t.reftables,t.refids,t.eventid,activityid,a.id,t.enquiryid,t.userid,t.eventdescription,t.eventdate       
  from tbl_enquiryeventhistory(nolock) t join @multiactivity a on t.historyid=a.ActivityID      
  join activitymaster(nolock) m on m.id=t.eventid      
  end      
  else if @entity='user'      
  begin      
  insert into #activityinfo(typeofevent,ename,parentid,reftables,refids,eventid,activityid,id,entityid,user_id,activitytext,activitydate)      
  select eventtype,eventname,t.parentid,t.reftables,t.refids,t.eventid,activityid,a.id,t.userid,t.userid,t.eventdescription,t.eventdate       
  from tbl_usereventhistory(nolock) t join @multiactivity a on t.historyid=a.ActivityID      
  join activitymaster(nolock) m on m.id=t.eventid      
  end      

