while @minid<@maxid      
begin      
insert into scheduledtodos(parentid,eventid,activityid,createdon,reftable,refid,isnotified,refcolumn,scheduledfor,isvalid,std_entity_name,std_entity_id)                                      
select ParentID,eventid,activityid,getdate(),reftables,refids,0,'',getdate(),1,@entity,i.entityid from #activityinfo i where       
exists (select 1 from adminnotificationsettings(nolock) a  where a.parentid=i.parentid and a.isactive=1 and ans_eventid=i.eventid)      
and id between @minid and @minid+100 
