/* ============================================================
   Procedure: [dbo].[usp_insertnotification_multi_original]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_insertnotification_multi_original]    
( @multiactivity as multiactivity readonly  )                                                            
as                                                            
begin             
          
  declare @cnt int=(select count(1) from @multiactivity),@entity nvarchar(20),@id bigint=0,@minid bigint,@maxid bigint  
  select top 1 @entity=context from @multiactivity    
  drop table if exists #activityinfo    
  create table #activityinfo(typeofevent nvarchar(50),s_eventid int,duedate datetime,ename nvarchar(100),parentid bigint,  
  reftables nvarchar(1000),refids nvarchar(1000),eventid int,id bigint,entityid bigint,user_id bigint,activitytext nvarchar(max),  
  activitydate datetime,activityid bigint)    
    
  if @entity='lead'    
  begin    
  insert into #activityinfo(typeofevent,ename,parentid,reftables,refids,eventid,activityid,id,entityid,user_id,activitytext,activitydate)    
  select eventtype,eventname,t.parentid,t.reftables,t.refids,activityid,t.eventid,a.id,t.leadid,t.userid,t.eventdescription,t.eventdate     
  from tbl_leadeventhistory(nolock) t join @multiactivity a on t.historyid=a.ActivityID    
  join activitymaster(nolock) m on m.id=t.eventid    
  end    
  else if @entity='enquiry'    
  begin    
  insert into #activityinfo(typeofevent,ename,parentid,reftables,refids,eventid,activityid,id,entityid,user_id,activitytext,activitydate)    
  select eventtype,eventname,t.parentid,t.reftables,t.refids,t.eventid,activityid,a.id,t.enquiryid,t.userid,t.eventdescription,t.eventdate     
  from tbl_enquiryeventhistory(nolock) t join @multiactivity a on t.historyid=a.ActivityID    
  join activitymaster(nolock) m on m.id=t.eventid    
  end    
  else if @entity='user'    
  begin    
  insert into #activityinfo(typeofevent,ename,parentid,reftables,refids,eventid,activityid,id,entityid,user_id,activitytext,activitydate)    
  select eventtype,eventname,t.parentid,t.reftables,t.refids,t.eventid,activityid,a.id,t.userid,t.userid,t.eventdescription,t.eventdate     
  from tbl_usereventhistory(nolock) t join @multiactivity a on t.historyid=a.ActivityID    
  join activitymaster(nolock) m on m.id=t.eventid    
  end    
    
while @cnt>0    
begin    
insert into scheduledtodos(parentid,eventid,activityid,createdon,reftable,refid,isnotified,refcolumn,scheduledfor,isvalid)                                    
select ParentID,eventid,activityid,getdate(),reftables,refids,0,'',getdate(),1 from #activityinfo i where     
exists (select 1 from adminnotificationsettings(nolock) a  where a.parentid=i.parentid and a.isactive=1 and ans_eventid=i.eventid)    
and id between @id and @id+100    
set @id=@id+100   
set @cnt=@cnt-100
end    
select @cnt=count(1),@minid=min(id),@maxid=max(id) from @multiactivity

while @minid<@maxid
begin
if @entity='lead' and exists (select 1 from #activityinfo(nolock) where eventid in (41,43,54,50,51,55,10,42,44,45,46,56) )    
begin    
update i set duedate=case when IsAppointment=1 then startdate else enddate end,s_eventid=    
case when i.typeofevent='task' then 151 when i.typeofevent ='Appointment' then 152 end    
from #activityinfo i join tbl_tsk_TaskHistory t on i.refids=t.id            
where i.typeofevent in ('task','appointment') and i.EventID in (41,43,54,50,51,55,10)    
and exists (select 1 from adminnotificationsettings(nolock) a  where a.parentid=i.parentid and a.isactive=1 and     
ans_eventid=case when i.typeofevent='task' then 151 when i.typeofevent ='Appointment' then 152 end)    
and i.id between @minid and @minid+100    

update i set duedate=followupdate,s_eventid=153     
from #activityinfo i join leadinteractionhistory(nolock) t on i.refids=t.id            
where i.eventid=10    
and exists (select 1 from adminnotificationsettings(nolock) a  where a.parentid=i.parentid and a.isactive=1 and     
ans_eventid=153)
and i.id between @minid and @minid+100
    
update i set duedate=dbo.fn_getleadexpiry(i.entityid,p.id),s_eventid=154     
from #activityinfo i join LeadPipelineMapping_latest(nolock) l  on i.entityid=l.leadid     
and l.pipelineid =(select pipelineid from leadpipelinemapping(nolock) where id=i.refids)    
join Pipeline_Master p (nolock) on p.id=l.PipelineID    
where i.typeofevent='Deal'    
and exists (select 1 from adminnotificationsettings(nolock) a  where a.parentid=i.parentid and a.isactive=1 and     
ans_eventid=153)    
and i.id between @minid and @minid+100
    
    
    
update s set scheduledfor=a.duedate,isnotified=0,isvalid=1     
from scheduledtodos s join #activityinfo a on     
a.parentid=s.parentid and s.refid=a.refids and s.reftable=a.reftables    
where a.EventID in (41,43,54,50,51,55) and s.eventid in (151,152,154)    
and a.id between @minid and @minid+100
  
update s set isvalid=0  from scheduledtodos s where isnotified=0 and s.eventid=153 and s.activityid in   
(select historyid from tbl_leadeventhistory(nolock) t join #activityinfo a on t.leadid=a.entityid and a.eventid=t.eventid  
where t.EventID=10 and a.id between @minid and @minid+100)              
  
insert into scheduledtodos(parentid,eventid,activityid,createdon,reftable,refid,isnotified,refcolumn,scheduledfor,isvalid)                                    
select i.ParentID,153,i.activityid,getdate(),i.reftables,i.refids,0,'',duedate,case when duedate is not null then 1 else 0 end from   
#activityinfo i join leadinteractionhistory(nolock) t on i.refids=t.id            
where i.eventid=10    
and exists (select 1 from adminnotificationsettings(nolock) a  where a.parentid=i.parentid and a.isactive=1 and     
ans_eventid=153)  
and i.id between @minid and @minid+100
  
    
insert into scheduledtodos(parentid,eventid,activityid,createdon,reftable,refid,isnotified,refcolumn,scheduledfor,isvalid)                                    
select ParentID,case when typeofevent='task' then 151 when typeofevent ='Appointment' then 152     
when typeofevent='Deal' then 154 when eventid=10 then 153 end,activityid,getdate(),reftables,refids,0,'',duedate,1    
from #activityinfo a(nolock) where duedate is not null and a.EventID in (41,43,54,50,51,55,10)    
and not exists    
(select 1 from scheduledtodos(nolock) where activityid=a.activityid and reftable=a.reftables and refid=a.refids and isnotified=0    
and eventid=a.s_eventid    
)    
and a.id between @minid and @minid+100
    
--update s set isvalid=0     
--from scheduledtodos s join #activityinfo a on s.leadid=a.entityid and s.parentid=a.parentid    
--where s.eventid between 151 and 154  and  a.eventid in (42,44,45,46,56) and isnotified=0 and    
--reftable=a.reftables and refid=a.refids     
    
end
set @minid=@minid+100
set @cnt=@cnt-100
end

end 


