/* ============================================================
   Procedure: [dbo].[usp_insertnotification_part1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_insertnotification_part1]      
(@activityid bigint,@entityname nvarchar(100),@parentid bigint=null,@eventid int=null)                                
as                                
begin         
declare @refid bigint,@reftables nvarchar(100),@leadid bigint,@enquiryid bigint      
 
 if @parentid is null or @eventid is null
 begin
 if @entityname='lead'
 begin
 select @parentid=coalesce(@parentid,parentid),@eventid=coalesce(@eventid,eventid) from tbl_leadeventhistory(nolock) where historyid=@activityid
 end
 else if @entityname='enquiry'
 begin
  select @parentid=coalesce(@parentid,parentid),@eventid=coalesce(@eventid,eventid) from tbl_leadeventhistory(nolock) where historyid=@activityid
 end


 end



if exists(select 1 from adminnotificationsettings (nolock) a join notificationsmaster n(nolock) on n.id=a.notificationid      
where a.parentid=@parentid and a.isactive=1 and n.activityid=@eventid      
)          
begin      
if @entityname='lead'      
begin      
insert into scheduledtodos(parentid,eventid,activityid,createdon,reftable,refid,isnotified,refcolumn,scheduledfor,isvalid,std_entity_name,std_entity_id)        
select ParentID,eventid,@activityid,getdate(),reftables,refids,0,'',getdate(),1,'lead',leadid  from tbl_LeadEventHistory(nolock)      
where Historyid=@activityid and eventdate>dateadd(d,-1,getdate())      
end      
if @entityname='enquiry'      
begin      
insert into scheduledtodos(parentid,eventid,activityid,createdon,reftable,refid,isnotified,refcolumn,scheduledfor,isvalid,std_entity_name,std_entity_id)        
select ParentID,eventid,@activityid,getdate(),reftables,refids,0,'',getdate(),1,'enquiry',enquiryid  from tbl_EnquiryEventHistory(nolock)      
where Historyid=@activityid and eventdate>dateadd(d,-1,getdate())          
end      
if @entityname='user'      
begin      
insert into scheduledtodos(parentid,eventid,activityid,createdon,reftable,refid,isnotified,refcolumn,scheduledfor,isvalid,std_entity_name,std_entity_id)        
select ParentID,eventid,@activityid,getdate(),reftables,refids,0,'',getdate(),1,'user',userid  from tbl_UserEventHistory(nolock)      
where Historyid=@activityid  and eventdate>dateadd(d,-1,getdate())         
end      
end      
      
if @entityname='lead'          
begin          
declare @typeofevent nvarchar(100),@scheduledaction nvarchar(50)='' ,@campaignid bigint,@seventid int         
select @typeofevent=EventType FROM   ActivityMaster(nolock) WHERE @eventid=id          
select @seventid=case when @typeofevent='task' then 151 when @typeofevent          
='Appointment' then 152 when @typeofevent='Deal' then 153 when @eventid=10 then 154 end      
select @leadid=leadid,@reftables=reftables,@refid=refids from tbl_LeadEventHistory(nolock) where historyid=@activityid and eventdate>dateadd(d,-1,getdate())         
if (@typeofevent in ('task','appointment','deal') or @eventid=10)          
begin      
if exists(select 1 from adminnotificationsettings(nolock) a join notificationsmaster(nolock) n on n.id=a.notificationid           
where a.parentid=@parentid and a.isactive=1 and n.activityid=@seventid)           
begin      
set @scheduledaction='notify'      
end      
if exists(select 1 from triggeredcampaigns(nolock) where isactive=1 and eventid=@seventid)          
begin      
set @scheduledaction=@scheduledaction+',TriggeredCampaign'      
select id as tid into #triggeredcampaigns from triggeredcampaigns where isactive=1 and eventid=@seventid      
end      
if @scheduledaction<>''                
  begin          
  --,151,152,153,154          
 declare @duedate datetime,@refcolumn nvarchar(100)='',@duetype nvarchar(20)=case when @eventid=10 then 'FollowUp' else @typeofevent end          
 select @duedate=case when IsAppointment=1 then startdate else enddate end,@refcolumn=case when IsAppointment=1 then 'startdate' else 'enddate' end           
 from tbl_tsk_TaskHistory(nolock) where id=@refid and @typeofevent in ('task','appointment')          
 select @duedate=followupdate,@refcolumn='followupdate'          
 from leadinteractionhistory(nolock) where id=@refid and @eventid =10          
 select @duedate=dbo.fn_getleadpipelineexpirydate(leadid,pipelineid)           
 from leadpipelinemapping(nolock) l where l.id=@refid      
  and @typeofevent ='Deal'          
       
          
If @EventID in (41,43,54,50,51,55,10) --activity added or edited          
begin          
if exists (select 1 from scheduledtodos (nolock) s join tbl_LeadEventHistory(nolock) t on isnotified=0 and s.eventid=@seventid and         
 t.historyid=s.activityid and t.eventid=10 and t.leadid=@leadid) and @eventid=10          
 begin          
update s set isvalid=0 from scheduledtodos s       
join tbl_LeadEventHistory t on isnotified=0 and t.historyid=s.activityid and s.eventid=@seventid and t.eventid=10 and t.leadid=@leadid          
end       
insert into scheduledtodos(parentid,eventid,activityid,createdon,reftable,refid,isnotified,refcolumn,scheduledfor,isvalid,      
scheduledaction,tcampaignid,std_entity_name,std_entity_id)       
select parentid,eventid,activityid,createdon,reftable,refid,isnotified,refcolumn,scheduledfor,isvalid,      
scheduledaction,tcampaignid,'lead',@leadid from         
(select @ParentID as parentid,@seventid as eventid,@activityid as activityid,      
getdate() as createdon,@reftables as reftable,@refid refid,0 isnotified,@refcolumn refcolumn,@duedate scheduledfor,1 as isvalid,      
'TriggeredCampaign' as scheduledaction,tid as Tcampaignid from #triggeredcampaigns t       
union      
select @ParentID as parentid,@seventid as eventid,@activityid as activityid,      
getdate() as createdon,@reftables as reftable,@refid refid,0 isnotified,@refcolumn refcolumn,@duedate scheduledfor,1 as isvalid,      
'notify' as scheduledaction,0 as Tcampaignid,'lead',@leadid from dbo.fn_split(@scheduledaction,',') f where f.value='notify'          
) a where not exists      
(select 1 from scheduledtodos(nolock) where eventid=a.eventid and reftable=a.reftable and refid=a.refid and parentid=a.parentid and       
scheduledaction=a.scheduledaction and tcampaignid=a.Tcampaignid)      
    
if @eventid<>10      
begin      
update s set scheduledfor=@duedate,isnotified=0,isvalid=1,activityid=@activityid from scheduledtodos s      
where reftable=@reftables and refid=@refid and parentid=@parentid and eventid=@seventid  --and @duedate>getdate()         
end      
end          
else if @eventid in (42,44,45,46,56)  --completed or deleted        
begin          
update scheduledtodos set isvalid=0 where reftable=@reftables and refid=@refid and parentid=@parentid and eventid=@seventid         
end          
end          
end          
end      
      
      
end                
                
--create table notificationerrortrace(id bigint identity(1,1),activityid bigint,entity nvarchar(20),createddate datetime default getdate())          
          
--select top 10 * from ErrorReportNew(nolock) order by id desc;select top 10 * from tbl_LeadEventHistory(nolock) order by historyid desc          
--select top 10 * from ProductMaster          
--select * from adminnotificationsettings          
--sp_depends adminnotificationsettings          
--sp_helptext usp_updatenotifications1


GO

