/* ============================================================
   Procedure: [dbo].[Usp_InsertOfflineEnquiryDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_InsertOfflineEnquiryDetails]
    @EnquiryData dbo.OfflineEnquiryType READONLY,
    @Custom dbo.OfflineCustFieldsType READONLY
AS
BEGIN
    SET NOCOUNT ON;

    PRINT '--- START: Usp_InsertOfflineEnquiryDetails ---';
    
    ----------------------------------------------------------------
    -- Temp table for inserted leads
    ----------------------------------------------------------------
    IF OBJECT_ID('tempdb..#InsertedLeads') IS NOT NULL
        DROP TABLE #InsertedLeads;

    CREATE TABLE #InsertedLeads (
        ID INT,                    -- EnquiryID
        ParentID BIGINT,
        LeadNo BIGINT,
        MobileNo VARCHAR(100),
        EmailId VARCHAR(100),
        CountryCode VARCHAR(50),
        CountryCode1 VARCHAR(50),
        CountryCode2 VARCHAR(50),
        MobileNo1 VARCHAR(100),
        MobileNo2 VARCHAR(100),
        EmailId1 VARCHAR(100),
        EmailId2 VARCHAR(100)
    );

    ----------------------------------------------------------------
    -- 1. Deduplicate Enquiries and insert
    ----------------------------------------------------------------
    PRINT 'Step 1: Deduplicating Enquiries...';
    
    ;WITH Deduped AS
    (
        SELECT e.*
        FROM @EnquiryData e
        WHERE NOT EXISTS (
            SELECT 1
            FROM UserEnquiry ue
            WHERE ue.PersonName = e.PersonName
              AND ue.MobileNo   = e.MobileNo
              AND ue.MobileNo1  = e.MobileNo1
              AND ue.MobileNo2  = e.MobileNo2
              AND ue.EmailID    = e.EmailID
              AND ue.EmailID1   = e.EmailID1
              AND ue.EmailID2   = e.EmailID2
              AND ue.CountryCode  = e.CountryCode
              AND ue.CountryCode1 = e.CountryCode1
              AND ue.CountryCode2 = e.CountryCode2
              AND ue.SourceName = e.SourceName
              AND ue.ParentID   = e.ParentID
              AND ue.CreatedBy  = e.CreatedBy
        )
    )
    INSERT INTO UserEnquiry
    (
        PersonName, CompanyName, MobileNo, MobileNo1, MobileNo2,
        EmailID, EmailID1, EmailID2,
        City, State, Country,
        CountryCode, CountryCode1, CountryCode2,
        ResidentialAddress, OfficeAddress, PinCode,
        SourceName, Stages, ReminderDate, Remark,
        Owner, MediumName, CampaignName, InitialRemarks,
        ParentID, CreatedDate, CreatedBy,
        LeadNo, enquirysource,
        whereAddress, latitude, longitude, StagesId
    )
    OUTPUT 
        INSERTED.EnquiryID, 
        INSERTED.ParentID, 
        INSERTED.LeadNo, 
        INSERTED.MobileNo, 
        INSERTED.EmailID,
        INSERTED.CountryCode,
        INSERTED.CountryCode1,
        INSERTED.CountryCode2,
        INSERTED.MobileNo1,
        INSERTED.MobileNo2,
        INSERTED.EmailID1,
        INSERTED.EmailID2
    INTO #InsertedLeads(ID, ParentID, LeadNo, MobileNo, EmailId, CountryCode, CountryCode1, CountryCode2, MobileNo1, MobileNo2, EmailId1, EmailId2)
    SELECT 
        PersonName, CompanyName, MobileNo, MobileNo1, MobileNo2,
        EmailID, EmailID1, EmailID2,
        City, State, CountryName,
        CountryCode, CountryCode1, CountryCode2,
        ResidentialAddress, OfficeAddress, PinCode,
        SourceName, Stage, ReminderDate, Remark,
        Owner, Medium, Campaign, InitialRemarks,
        ParentID, GETDATE(), CreatedBy,
        NULL, 12,  -- LeadNo will be filled below
        WhereAddress,
        TRY_CAST(NULLIF(WhereLatitude, '') AS FLOAT),
        TRY_CAST(NULLIF(WhereLongitude, '') AS FLOAT),
        Stage
    FROM Deduped;

    PRINT 'Step 1 Completed. Enquiries inserted into UserEnquiry = ' + CAST(@@ROWCOUNT AS NVARCHAR);

    ----------------------------------------------------------------
    -- 1.a Build flattened contact list for UserLeads (for relevant ParentIDs)
    ----------------------------------------------------------------
    IF OBJECT_ID('tempdb..#UserLeadsContacts') IS NOT NULL
        DROP TABLE #UserLeadsContacts;

    CREATE TABLE #UserLeadsContacts (
        ParentID BIGINT,
        LeadNo BIGINT,
        Mobile VARCHAR(200),
        Email VARCHAR(200)
    );

    INSERT INTO #UserLeadsContacts (ParentID, LeadNo, Mobile, Email)
    SELECT ParentID, LeadNo,
        CAST(ISNULL(CountryCode,'') + ISNULL(NULLIF(MobileNo,''),'') AS VARCHAR(200)),
        ISNULL(NULLIF(EmailID,''),'')
    FROM UserLeads
    WHERE ParentID IN (SELECT DISTINCT ParentID FROM #InsertedLeads)

    UNION ALL

    SELECT ParentID, LeadNo,
        CAST(ISNULL(CountryCode1,'') + ISNULL(NULLIF(MobileNo1,''),'') AS VARCHAR(200)),
        ISNULL(NULLIF(EmailID1,''),'')
    FROM UserLeads
    WHERE ParentID IN (SELECT DISTINCT ParentID FROM #InsertedLeads)

    UNION ALL

    SELECT ParentID, LeadNo,
        CAST(ISNULL(CountryCode2,'') + ISNULL(NULLIF(MobileNo2,''),'') AS VARCHAR(200)),
        ISNULL(NULLIF(EmailID2,''),'')
    FROM UserLeads
    WHERE ParentID IN (SELECT DISTINCT ParentID FROM #InsertedLeads);

    ----------------------------------------------------------------
    -- 1.b For each inserted enquiry, find a matching LeadNo (from #UserLeadsContacts)
    --     Matching order: any mobile combination OR any email (first match wins)
    ----------------------------------------------------------------
    PRINT 'Step 1.b: Resolving LeadNo for inserted enquiries...';

    select * from #UserLeadsContacts;
    select * from #InsertedLeads;

    -- Update #InsertedLeads.LeadNo by finding a matching LeadNo from #UserLeadsContacts
    ;WITH IL AS (
        SELECT *
        FROM #InsertedLeads
    )
    UPDATE IL
    SET LeadNo = matched.LeadNo
    FROM #InsertedLeads IL
    CROSS APPLY (
        SELECT TOP 1 ULC.LeadNo
        FROM #UserLeadsContacts ULC
        WHERE ULC.ParentID = IL.ParentID
          AND (
                ULC.Mobile = CAST(ISNULL(IL.CountryCode,'') + ISNULL(NULLIF(IL.MobileNo,''),'') AS VARCHAR(200))
             OR ULC.Mobile = CAST(ISNULL(IL.CountryCode1,'') + ISNULL(NULLIF(IL.MobileNo1,''),'') AS VARCHAR(200))
             OR ULC.Mobile = CAST(ISNULL(IL.CountryCode2,'') + ISNULL(NULLIF(IL.MobileNo2,''),'') AS VARCHAR(200))
             OR ULC.Email = ISNULL(NULLIF(IL.EmailId,''),'')
             OR ULC.Email = ISNULL(NULLIF(IL.EmailId1,''),'')
             OR ULC.Email = ISNULL(NULLIF(IL.EmailId2,''),'')
              )
        ORDER BY ULC.LeadNo
    ) AS matched
    WHERE matched.LeadNo IS NOT NULL;

    -- Now propagate LeadNo to UserEnquiry table
    UPDATE U
    SET U.LeadNo = IL.LeadNo
    FROM UserEnquiry U
    INNER JOIN #InsertedLeads IL ON U.EnquiryID = IL.ID
    WHERE ISNULL(IL.LeadNo, 0) <> 0;

    PRINT 'Step 1.b Completed. LeadNo resolved and updated for inserted enquiries.';

    ----------------------------------------------------------------
    -- 2. Handle Tags
    ----------------------------------------------------------------
    PRINT 'Step 2: Processing Tags...';

    INSERT INTO EntityTagMapping (EntityID, Entity, TagID, CreatedDate)
    SELECT e.EnquiryID, 'Enquiry', tm.ID, GETDATE()
    FROM UserEnquiry e
    JOIN @EnquiryData d 
         ON e.PersonName = d.PersonName AND e.MobileNo = d.MobileNo
    CROSS APPLY STRING_SPLIT(d.EnquiryTags, ',') s
    LEFT JOIN TagMaster tm 
         ON tm.Tag = LTRIM(RTRIM(s.value)) AND tm.ParentID = d.ParentID
    WHERE ISNULL(d.EnquiryTags,'') <> '';

    PRINT 'Step 2 Completed. Tag mappings inserted = ' + CAST(@@ROWCOUNT AS NVARCHAR);

    ----------------------------------------------------------------
    -- 3. Handle Custom Fields
    ----------------------------------------------------------------
    PRINT 'Step 3: Processing Custom Fields...';

    INSERT INTO customfieldEnquiryvalue (EnquiryID, fieldID, fieldvalue)
    SELECT IL.ID, C.fieldID, C.fieldvalue
    FROM @custom C
    INNER JOIN #InsertedLeads IL ON (IL.MobileNo = C.MobileNo OR IL.EmailId = C.EmailId);

    PRINT 'Step 3 Completed. Custom field values inserted = ' + CAST(@@ROWCOUNT AS NVARCHAR);

    ----------------------------------------------------------------
    -- Final Log
    ----------------------------------------------------------------
    PRINT '--- END: Usp_InsertOfflineEnquiryDetails ---';
    SELECT 'Insert Completed Successfully' AS Message;

    -- optionally return inserted leads for debugging
    -- SELECT * FROM #InsertedLeads;
END



GO

/* ============================================================
   Procedure: [dbo].[Usp_InsertOfflineLeadDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE [dbo].[Usp_InsertOfflineLeadDetails] 
(
	@TempTable dbo.OfflineLeadType READONLY,
    @custom dbo.OfflineCustFieldsType READONLY            
)              
AS              
BEGIN       
    SET NOCOUNT ON;

    PRINT '=== Lead process started ===';

    ----------------------------------------------------------------
    -- Temp table for inserted leads
    ----------------------------------------------------------------
    IF OBJECT_ID('tempdb..#InsertedLeads') IS NOT NULL
        DROP TABLE #InsertedLeads;

    CREATE TABLE #InsertedLeads (
        ID INT,
        ParentID BIGINT,
        LeadNo BIGINT,
		MobileNo varchar(100),
		EmailId varchar(100)
    );

	declare @Leads_Cleaned as dbo.OfflineLeadType;

    ----------------------------------------------------------------
    -- 1. Clean data and prepare follow-up dates
    ----------------------------------------------------------------
    PRINT 'Step 1: Cleaning data...';

    INSERT INTO @Leads_Cleaned(LeadId, ParentID, PersonName, CompanyName, MobileNo, MobileNo1, 
	MobileNo2, EmailID, EmailID1, EmailID2, City, State, Country, CountryCode, CountryCode1, 
	CountryCode2, PinCode, ResidentialAddress, OfficialAddress, SourceName, MediumName, CampaignName, 
	Remarks, CreatedBy, AssignedTo, FollowUpStatus, NextStatusDate, Products, AmountPaid, 
	FollowUpRemarks, WhereAddress, WhereLatitude, WhereLongitude, FollowupDate)
    SELECT 
    LeadId, ParentID, PersonName, CompanyName, MobileNo, MobileNo1, MobileNo2, EmailID, EmailID1, 
	EmailID2, City, State, Country, CountryCode, CountryCode1, CountryCode2, PinCode, 
	ResidentialAddress, OfficialAddress, SourceName, MediumName, CampaignName, Remarks, 
	CreatedBy, AssignedTo, FollowUpStatus, NextStatusDate, Products, AmountPaid, FollowUpRemarks, 
	WhereAddress, WhereLatitude, WhereLongitude,
    CASE 
        WHEN ISNULL(T.NextStatusDate,'') <> '' 
        THEN dbo.fn_getISTtimefromusertime(T.CreatedBy, TRY_CAST(T.NextStatusDate AS DATETIME))
        ELSE NULL
    END AS FollowupDate
    FROM @TempTable T;

     ;WITH Leads_WithLeadNo AS (
        SELECT 
            L.*,
            ISNULL((
                SELECT MAX(UL.LeadNo) 
                FROM UserLeads UL 
                WHERE UL.ParentID = L.ParentID
            ),0) + ROW_NUMBER() OVER(PARTITION BY L.ParentID ORDER BY (SELECT NULL)) AS LeadNo
        FROM @Leads_Cleaned L
    )

    ----------------------------------------------------------------
    -- 2. Insert into UserLeads
    ----------------------------------------------------------------
	--select * from @Leads_Cleaned
    --PRINT 'Step 2: Inserting into UserLeads...';

    INSERT INTO UserLeads
    (
        ParentID, LeadNo, PersonName, CompanyName,
        MobileNo, MobileNo1, MobileNo2,
        EmailID, EmailID1, EmailID2,
        City, State, Country, CountryCode, CountryCode1, CountryCode2,
        PinCode, ResidentialAddress, OfficeAddress,
        SourceName, MediumName, CampaignName, InitialRemarks,
        CreatedOn, CreatedBy, AssignedTo,
        FollowUpStatus, NextStatusDate, ProductsJson, AmountPaid,
        Remarks, FollowupDate, enquirysource,
        WhereAddress, latitude, longitude
    )
    OUTPUT INSERTED.ID, INSERTED.ParentID, INSERTED.LeadNo, INSERTED.MobileNo, INSERTED.EmailID INTO #InsertedLeads(ID, ParentID, LeadNo, MobileNo, EmailId)
    SELECT
        L.ParentID,
        L.LeadNo,
        L.PersonName, L.CompanyName,
        L.MobileNo, L.MobileNo1, L.MobileNo2,
        L.EmailID, L.EmailID1, L.EmailID2,
        L.City, L.State, L.Country, L.CountryCode, L.CountryCode1, L.CountryCode2,
        L.PinCode, L.ResidentialAddress, L.OfficialAddress,
        L.SourceName, L.MediumName, L.CampaignName, L.Remarks,
        GETDATE(), L.CreatedBy, L.AssignedTo,
        L.FollowUpStatus, L.NextStatusDate,
        JSON_QUERY(
            (SELECT value FROM fn_split(ISNULL(L.Products,''),'#') 
             FOR JSON PATH, INCLUDE_NULL_VALUES)
        ),
        L.AmountPaid, L.FollowUpRemarks,
        L.FollowupDate,
        12, -- enquiry source
        L.WhereAddress,
        TRY_CAST(NULLIF(L.WhereLatitude,'') AS FLOAT),
        TRY_CAST(NULLIF(L.WhereLongitude,'') AS FLOAT)
    FROM Leads_WithLeadNo L;

    ----------------------------------------------------------------
    -- 3. Insert into LeadInteractionHistory
    ----------------------------------------------------------------
    PRINT 'Step 3: Inserting into LeadInteractionHistory...';

	--select * from @TempTable;
	--select * from @Leads_Cleaned;
	--select * from #InsertedLeads;
	
    INSERT INTO LeadInteractionHistory
    (
        LeadNo, FollowUpStatus, NextStatusDate, Remarks,
        ProductsJson, AmountPaid, AssignedTo, IsReassign,
        ParentID, CreatedOn, CreatedBy, FollowupDate, id_lead
    )
    SELECT 
		IL.LeadNo,
		T.FollowUpStatus,
		T.NextStatusDate,
		T.FollowUpRemarks,
		JSON_QUERY(
			(SELECT value 
			 FROM fn_split(ISNULL(T.Products,''),'#') 
			 FOR JSON PATH, INCLUDE_NULL_VALUES)
		) AS ProductsJson,
		T.AmountPaid,
		T.AssignedTo,
		T.IsReassign,
		T.ParentID,
		GETDATE() AS CreatedOn,
		T.CreatedBy,
		LC.FollowupDate, -- because no L table
		IL.ID
	FROM @TempTable T
	INNER JOIN UserLeads UL ON (T.MobileNo = UL.MobileNo OR T.EmailID = UL.EmailID)
	INNER JOIN #InsertedLeads IL ON IL.ParentID = T.ParentID AND IL.LeadNo  = UL.LeadNo
	INNER JOIN @Leads_Cleaned LC ON (LC.MobileNo = T.MobileNo OR LC.EmailID = T.EmailID);

    ----------------------------------------------------------------
    -- 4. Tags
    ----------------------------------------------------------------
    PRINT 'Step 4: Processing tags...';

    ---- STEP 4 (replacement) : Tags (set-based, no loop, no MERGE)
	PRINT 'Step 4.1: Extracting tags...';

	IF OBJECT_ID('tempdb..#TagsTemp') IS NOT NULL DROP TABLE #TagsTemp;
	CREATE TABLE #TagsTemp (LeadID BIGINT, ParentID BIGINT, CreatedBy BIGINT, TagName NVARCHAR(400));

	INSERT INTO #TagsTemp (LeadID, ParentID, CreatedBy, TagName)
	SELECT DISTINCT
		IL.ID AS LeadID,
		T.ParentID,
		T.CreatedBy,
		LTRIM(RTRIM(
			CASE
				WHEN CHARINDEX(':', s.value) = 0 THEN s.value
				ELSE LEFT(s.value, CHARINDEX(':', s.value) - 1)
			END
		)) AS TagName
	FROM @TempTable T
	INNER JOIN #InsertedLeads IL ON IL.ParentID = T.ParentID
	CROSS APPLY STRING_SPLIT(T.LeadTags, ',') AS s
	WHERE ISNULL(LTRIM(RTRIM(T.LeadTags)), '') <> ''
		AND ISNULL(LTRIM(RTRIM(s.value)), '') <> '';

	IF NOT EXISTS (SELECT 1 FROM #TagsTemp)
	BEGIN
		PRINT 'Step 4: No tags to process. Skipping tag insert/mapping.';
	END
	ELSE
	BEGIN
		PRINT 'Step 4.2: Distinct tag count:';
		SELECT COUNT(*) AS DistinctTagRows FROM (SELECT DISTINCT TagName, ParentID, CreatedBy FROM #TagsTemp) AS x;

		-- get distinct tag names per parent
		IF OBJECT_ID('tempdb..#DistinctTags') IS NOT NULL DROP TABLE #DistinctTags;
		SELECT DISTINCT TagName, ParentID, CreatedBy
		INTO #DistinctTags
		FROM #TagsTemp;

		-- Find which tags already exist (case-insensitive match).  Avoid applying LOWER() on the table column in large tables if possible.
		IF OBJECT_ID('tempdb..#ExistingTags') IS NOT NULL DROP TABLE #ExistingTags;
		SELECT d.TagName, d.ParentID, d.CreatedBy, tm.ID AS TagID
		INTO #ExistingTags
		FROM #DistinctTags d
		LEFT JOIN TagMaster tm
			ON LOWER(tm.Tag) = LOWER(d.TagName) AND tm.ParentID = d.ParentID;

		-- Insert missing tags and capture new IDs
		IF OBJECT_ID('tempdb..#NewTags') IS NOT NULL DROP TABLE #NewTags;
		CREATE TABLE #NewTags (TagID BIGINT, TagName NVARCHAR(400), ParentID BIGINT);

		INSERT INTO TagMaster (Tag, ParentID, CreatedDate, CreatedBy)
		OUTPUT inserted.ID, inserted.Tag, inserted.ParentID INTO #NewTags(TagID, TagName, ParentID)
		SELECT d.TagName, d.ParentID, GETDATE(), d.CreatedBy
		FROM #DistinctTags d
		LEFT JOIN TagMaster tm
			ON LOWER(tm.Tag) = LOWER(d.TagName) AND tm.ParentID = d.ParentID
		WHERE tm.ID IS NULL;

		PRINT 'Step 4.3: New tags inserted:';
		SELECT COUNT(*) AS NewTagsInserted FROM #NewTags;

		-- Build final mapping of TagName -> TagID using up-to-date TagMaster (includes newly inserted rows)
		IF OBJECT_ID('tempdb..#FinalTagIDs') IS NOT NULL DROP TABLE #FinalTagIDs;
		SELECT DISTINCT
			tt.TagName,
			tt.ParentID,
			tm.ID AS TagID
		INTO #FinalTagIDs
		FROM #DistinctTags tt
		INNER JOIN TagMaster tm
			ON LOWER(tm.Tag) = LOWER(tt.TagName) AND tm.ParentID = tt.ParentID;

		PRINT 'Step 4.4: FinalTagIDs count:';
		SELECT COUNT(*) AS FinalTagCount FROM #FinalTagIDs;

		-- Delete old mappings only for leads that provided tags in this batch
		PRINT 'Step 4.5: Deleting old mappings for these leads...';
		DELETE ETM
		FROM EntityTagMapping ETM
		INNER JOIN (SELECT DISTINCT LeadID FROM #TagsTemp) LT ON ETM.EntityID = LT.LeadID
		WHERE LOWER(ETM.Entity) = 'lead';

		PRINT 'Step 4.6: Inserting fresh mappings...';
		INSERT INTO EntityTagMapping (EntityID, Entity, TagID, CreatedDate)
		SELECT DISTINCT
			t.LeadID,
			'lead',
			f.TagID,
			GETDATE()
		FROM #TagsTemp t
		INNER JOIN #FinalTagIDs f
			ON LOWER(f.TagName) = LOWER(t.TagName) AND f.ParentID = t.ParentID;

		PRINT 'Step 4 completed: inserted mappings count:';
		SELECT COUNT(*) AS MappingsInserted FROM EntityTagMapping
		WHERE CreatedDate >= DATEADD(MINUTE, -5, GETDATE()) -- rough heuristic (optional)
		AND LOWER(Entity) = 'lead';
	END

	-- cleanup temp tables (optional)
	IF OBJECT_ID('tempdb..#TagsTemp') IS NOT NULL DROP TABLE #TagsTemp;
	IF OBJECT_ID('tempdb..#DistinctTags') IS NOT NULL DROP TABLE #DistinctTags;
	IF OBJECT_ID('tempdb..#ExistingTags') IS NOT NULL DROP TABLE #ExistingTags;
	IF OBJECT_ID('tempdb..#NewTags') IS NOT NULL DROP TABLE #NewTags;
	IF OBJECT_ID('tempdb..#FinalTagIDs') IS NOT NULL DROP TABLE #FinalTagIDs;

    ----------------------------------------------------------------
    -- 5. Custom fields
    ----------------------------------------------------------------
    PRINT 'Step 5: Inserting custom fields...';



    INSERT INTO customfieldLeadvalue (LeadID, EnquiryID, fieldID, fieldvalue)
    SELECT IL.ID, C.EnquiryID, C.fieldID, C.fieldvalue
    FROM @custom C
    INNER JOIN #InsertedLeads IL ON (IL.MobileNo = C.MobileNo or IL.EmailId = C.EmailId) ;

    ----------------------------------------------------------------
    -- 6. Lead Activity
    ----------------------------------------------------------------
    PRINT 'Step 6: Inserting activity log...';

    --INSERT INTO LeadActivityLog(LeadID, ParentID, UserID, Activity, CreatedOn)
    --SELECT 
    --    IL.ID, IL.ParentID, T.CreatedBy,
    --    'Lead added', GETDATE()
    --FROM @TempTable T
    --INNER JOIN #InsertedLeads IL ON IL.ParentID = T.ParentID;

    ----------------------------------------------------------------
    -- Return inserted leads
    ----------------------------------------------------------------
    PRINT '=== Lead process completed ===';
    SELECT * FROM #InsertedLeads;        
END;



GO

/* ============================================================
   Procedure: [dbo].[Usp_InsertOfflineLeadFollowupDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_InsertOfflineLeadFollowupDetails]
    @LeadFollowups dbo.OfflineLeadFollowupType READONLY
AS
BEGIN
    SET NOCOUNT ON;

    PRINT 'Followup SP Called';

    ------------------------------------------------------
    ---- Prepare ProductsJson using derived table
    ---- Use a temp table so results can be reused by multiple statements
    ------------------------------------------------------
    -- Materialize TVP rows into a temp table along with ProductsJson
    SELECT lf.*,
           (
               SELECT value AS ProductName
               FROM dbo.fn_split(lf.Products, '#')
               FOR JSON AUTO, INCLUDE_NULL_VALUES
           ) AS ProductsJson
    INTO #LF
    FROM @LeadFollowups lf;

    ------------------------------------------------------
    ---- Update UserLeads
    ------------------------------------------------------
    UPDATE ul
    SET ul.AssignedTo     = lf.AssignedTo,
        ul.FollowUpStatus = lf.FollowUpStatus,
        ul.NextStatusDate =
            CASE 
                WHEN ISNULL(lf.NextStatusDate, '') <> '' 
                    THEN CONVERT(NVARCHAR(100),
                         dbo.fn_getISTtimefromusertime(lf.UserId, lf.NextStatusDate), 121)
                ELSE lf.NextStatusDate 
            END,
        ul.ProductsJson    = lf.ProductsJson,
        ul.AmountPaid      = lf.AmountPaid,
        ul.Remarks         = lf.Remarks,
        ul.ModifiedBy      = lf.UserId,
        ul.FollowupDate =
            CASE 
                WHEN ISNULL(lf.NextStatusDate, '') <> '' 
                    THEN dbo.fn_getISTtimefromusertime(lf.UserId, lf.NextStatusDate)
                ELSE NULL 
            END
    FROM UserLeads ul
    INNER JOIN #LF lf ON ul.Id = lf.LeadId;

    ------------------------------------------------------
    ---- Insert into LeadInteractionHistory
    ------------------------------------------------------
    INSERT INTO LeadInteractionHistory
    (
        LeadNo,
        FollowUpStatus,
        NextStatusDate,
        IsReassign,
        ProductsJson,
        AmountPaid,
        Remarks,
        AssignedTo,
        ParentID,
        CreatedOn,
        CreatedBy,
        FollowupDate
    )
    SELECT 
        ul.LeadNo,
        lf.FollowUpStatus,
        CASE 
            WHEN ISNULL(lf.NextStatusDate, '') <> '' 
                THEN CONVERT(NVARCHAR(100),
                     dbo.fn_getISTtimefromusertime(lf.UserId, lf.NextStatusDate), 121)
            ELSE lf.NextStatusDate 
        END,
        lf.IsReassign,
        lf.ProductsJson,
        lf.AmountPaid,
        lf.Remarks,
        lf.AssignedTo,
        ul.ParentID,
        GETDATE(),
        lf.UserId,
        CASE 
            WHEN ISNULL(lf.NextStatusDate, '') <> '' 
                THEN dbo.fn_getISTtimefromusertime(lf.UserId, lf.NextStatusDate)
            ELSE NULL 
        END
    FROM #LF lf
    INNER JOIN UserLeads ul ON ul.ID = lf.LeadId;

    ------------------------------------------------------
    ---- Return confirmation for each row
    ------------------------------------------------------
    SELECT 
        'Lead Followup Added Successfully' AS Msg,
        ul.LeadNo AS LeadNo
    FROM #LF lf
    INNER JOIN UserLeads ul ON lf.LeadId = ul.ID;

    -- cleanup
    IF OBJECT_ID('tempdb..#LF') IS NOT NULL
        DROP TABLE #LF;

END



GO

/* ============================================================
   Procedure: [dbo].[Usp_InsertOfflineTaskOrAppointmentDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE [dbo].[Usp_InsertOfflineTaskOrAppointmentDetails]
    @Tasks dbo.OfflineTaskType READONLY
AS
BEGIN
    SET NOCOUNT ON;

    PRINT 'Insert all tasks into TaskHistory in one go';

    ----------------------------------------------------------------
    -- Create temp table for OUTPUT INTO (MISSING EARLIER)
    ----------------------------------------------------------------
    CREATE TABLE #InsertedTasks
    (
        TaskHistoryId BIGINT,
        Title NVARCHAR(500),
        Status NVARCHAR(100),
        CreatedBy BIGINT,
        AssignedTo BIGINT,
        CollabratoerUserIds NVARCHAR(MAX),
        IsSMS BIT,
        IsEmail BIT,
        SmsSchedule NVARCHAR(100),
        EmailSchedule NVARCHAR(100),
        LeadId BIGINT,
        DLTTemplateIDForSMSReminder NVARCHAR(200),
        DLTTemplateIDForNotification NVARCHAR(200),
        IsAppointment BIT,
        NotifyMe INT
    );

    ----------------------------------------------------------------
    -- Insert all tasks into TaskHistory
    ----------------------------------------------------------------
    INSERT INTO tbl_tsk_TaskHistory
    (
        Title, Description, Address, StartDate, EndDate, LeadId,
        AssignedTo, IsActive, CreatedOn, TaskId, CreatedBy, OutcomesId,
        Status, IsTask, IsAppointment, TaskType, CompleteAddress,
        Latitude, Longitude, Remarks
    )
    OUTPUT 
        inserted.Id, 
        inserted.Title,
        inserted.Status,
        inserted.CreatedBy,
        inserted.AssignedTo,
        --T.CollabratoerUserIds,
        --T.IsSMS,
        --T.IsEmail,
        --T.SmsSchedule,
        --T.EmailSchedule,
        --inserted.LeadId,
        --T.DLTTemplateIDForSMSReminder,
        --T.DLTTemplateIDForNotification,
        inserted.IsAppointment
        --T.NotifyMe
    INTO #InsertedTasks (
        TaskHistoryId, Title, Status, CreatedBy, AssignedTo, 
		--CollabratoerUserIds,
        --IsSMS, IsEmail, SmsSchedule, EmailSchedule, LeadId,
        --DLTTemplateIDForSMSReminder, DLTTemplateIDForNotification, 
		IsAppointment
		--NotifyMe
    )
    SELECT
        T.Title, T.Description, T.Address, T.StartDate, T.EndDate, T.LeadId,
        T.AssignedTo, T.IsActive, GETDATE(), T.TaskId, T.CreatedBy, T.OutcomesId,
        T.Status, T.IsTask, T.IsAppointment, T.TaskType, T.CompleteAddress,
        T.Latitude, T.Longitude, T.Remarks
    FROM @Tasks T;

    ----------------------------------------------------------------
    -- Mark completed ones
    ----------------------------------------------------------------
    UPDATE H
    SET CompletedOn = GETDATE()
    FROM tbl_tsk_TaskHistory H
    INNER JOIN #InsertedTasks IT ON H.Id = IT.TaskHistoryId
    WHERE IT.Status = 'completed';

    ----------------------------------------------------------------
    -- Insert collaboration mapping
    ----------------------------------------------------------------
    INSERT INTO tbl_tsk_CollaborationUserMapping(User_Id, CreatedOn, CreatedBy, TaskHistoryId)
    SELECT V.value, GETDATE(), IT.CreatedBy, IT.TaskHistoryId
    FROM #InsertedTasks IT
    CROSS APPLY STRING_SPLIT(IT.CollabratoerUserIds, '#') V
    WHERE LTRIM(RTRIM(V.value)) <> '';

    ----------------------------------------------------------------
    -- Insert reminders
    ----------------------------------------------------------------
    INSERT INTO tbl_tsk_Reminder
    (
        Description, Status, Schedule, CreatedOn, CreatedBy,
        IsSMS, IsEmail, CollaborationUserMappingId
    )
    SELECT 
        'You are now a Collaborater of a task with title ' + IT.Title +
        ' for LeadId ' + CAST(IT.LeadId AS VARCHAR) + 
        ' scheduled for ' + CAST(H.EndDate AS NVARCHAR(50)),
        'open',
        CASE WHEN IT.IsSMS = 1 THEN IT.SmsSchedule ELSE IT.EmailSchedule END,
        GETDATE(),
        IT.CreatedBy,
        IT.IsSMS,
        IT.IsEmail,
        M.Id
    FROM #InsertedTasks IT
    INNER JOIN tbl_tsk_TaskHistory H ON H.Id = IT.TaskHistoryId
    INNER JOIN tbl_tsk_CollaborationUserMapping M ON M.TaskHistoryId = IT.TaskHistoryId;

    ----------------------------------------------------------------
    -- Call Reminder SP row-by-row
    ----------------------------------------------------------------
    DECLARE @TaskId BIGINT, @DLT nvarchar(200);

    DECLARE c CURSOR FOR 
        SELECT TaskHistoryId, DLTTemplateIDForSMSReminder
        FROM #InsertedTasks;

    OPEN c;

    FETCH NEXT FROM c INTO @TaskId, @DLT;

    WHILE @@FETCH_STATUS = 0
    BEGIN
        EXEC usp_tsk_InsertReminder_WithDLTTemplateID @TaskId, @DLT;
        FETCH NEXT FROM c INTO @TaskId, @DLT;
    END

    CLOSE c;
    DEALLOCATE c;

    ----------------------------------------------------------------
    -- Return inserted TaskHistoryIds
    ----------------------------------------------------------------
    SELECT TaskHistoryId FROM #InsertedTasks;


END



GO

