Author         : Ratnakar Sahoo                         
Created ON     : 05/01/2016 06:47 PM                              
Version        : 1                        
Alter by       :  Ratnakar Sahoo                             
Alter Date    :   -                       
Location       : PelSoftLab                        
SP Description : This SP is Used to Insert Payment Details for KIT19                         
                                                 
****************************************************************************/    
    
    
CREATE   PROC [dbo].[Usp_InsertOnlinePaymentDetails]                   
(                     
@UserID bigint,                   
@CustomerName nvarchar(50),           
@CustomerNumber varchar(15),    
@Planid  nvarchar(5),         
@TotalAmount decimal(18, 4),           
@CcAvenueOderNumber nvarchar(200),           
@Status nvarchar(100),           
@BillingAddress nvarchar(200),           
@PaymentThrough tinyint,           
@PaymentMode nvarchar(50),           
@BankTransactionId nvarchar(200),           
@Currency nvarchar(50),           
@Country nvarchar(100),      
@AmountWithoutTax nvarchar(100),    
@Quantity nvarchar(100),
@CouponCode nvarchar(100), 
@DiscountAmount nvarchar(100)       
)                        
AS                        
Begin                       
          declare @InvoiceNo nvarchar(200),@InvoiceNoNew nvarchar(200)        
      
set @InvoiceNo=(select max(InvoiceNo) from Payment_Detail where UserID=@UserID)      
      
if((@InvoiceNo is null) or @InvoiceNo='')       
begin      
      
set @InvoiceNoNew=( @UserID+ convert(nvarchar(100),getdate(),112)+ '1')      
      
end      
else      
begin       
      
set @InvoiceNoNew = (CAST(@InvoiceNo AS BIGINT)+1)      
      
end       
      
INSERT INTO Payment_Detail                
           (UserID,CustomerName, CustomerNumber,PlanID, TotalAmount, CcAvenueOderNumber, [Status], BillingAddress, PaymentThrough, PaymentMode, BankTransactionId, Currency, Country,InvoiceNo,AmountWithoutTax,Quantity,CouponCode,DiscountAmount)                
     VALUES                
           (@UserID,@CustomerName, @CustomerNumber,@Planid, @TotalAmount, @CcAvenueOderNumber, @Status, @BillingAddress,           
@PaymentThrough, @PaymentMode, @BankTransactionId, @Currency, @Country,@InvoiceNo,@AmountWithoutTax,@Quantity,@CouponCode,@DiscountAmount)   
    
    if((@CouponCode is not null) or @CouponCode!='')       
begin      
      
update CustomerCouponDetails set status=1 where UserId=@UserID    
      
end     
          
select 'Record Inserted'                        
End



