/* ============================================================
   Procedure: [dbo].[usp_InsertOrUpdateConsent]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_InsertOrUpdateConsent]
    @UserId BIGINT,
    @IsActive INT = 1
AS
BEGIN
    SET NOCOUNT ON;

    BEGIN TRY
        DECLARE @ParentId BIGINT;
        DECLARE @NewConsentId BIGINT;
        DECLARE @Message NVARCHAR(100);

        -- Get the ParentId from the User_Detail table
        SELECT @ParentId = ParentID 
        FROM User_Detail (NOLOCK) 
        WHERE User_ID = @UserID;

        -- Check if the ParentId already exists
        IF EXISTS (SELECT 1 FROM dbo.Consent WHERE ParentId = @ParentId)
        BEGIN
            -- Update existing consent record
            UPDATE dbo.Consent
            SET ConsentBy = @ParentId,
                IsActive = @IsActive,
                ConsentDate = GETDATE()
            WHERE ParentId = @ParentId;

            -- Get the updated consent ID and set the message
            SELECT @NewConsentId = Id 
            FROM dbo.Consent 
            WHERE ParentId = @ParentId;

            SET @Message = 'Consent record updated successfully.';
        END
        ELSE
        BEGIN
            -- Insert new consent record
            INSERT INTO dbo.Consent (ParentId, ConsentBy, IsActive, ConsentDate)
            VALUES (@ParentId, @ParentId, @IsActive, GETDATE());

            -- Get the newly inserted consent ID and set the message
            SET @NewConsentId = SCOPE_IDENTITY();
            SET @Message = 'Consent record inserted successfully.';
        END

        -- Return the result as a table
        SELECT @NewConsentId AS ConsentId, @Message AS Message;
    END TRY
    BEGIN CATCH
        -- Return error message on failure
        SELECT ERROR_MESSAGE() AS ErrorMessage;
    END CATCH
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_InsertOrUpdateDLTMappedEvent]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


--select * from User_Detail where user_login ='Abhi01'
--select * from User_Detail where user_login ='kmukesh343'



CREATE   PROCEDURE [dbo].[usp_InsertOrUpdateDLTMappedEvent]
    @Event NVARCHAR(500),
    @DLTTemplateID NVARCHAR(200),
    @UserID BIGINT,
    @isactive INT,
    @smscontent NVARCHAR(4000),
    @eventid INT,
    @senderid VARCHAR(10)
AS
BEGIN
    SET NOCOUNT ON;
	--declare 
--@Event NVARCHAR(500)='Change mobile',
--    @DLTTemplateID NVARCHAR(200)=3453454354353534543,
--    @UserID BIGINT=335,
--   -- @MappedDate DATETIME,
--    @isactive INT=1,
--    @smscontent NVARCHAR(4000)='Dear #var#, Please use OTP #var# to confirm mobile number change in #var#.',
--    @eventid INT=16,
--    --@event_type NVARCHAR(200) = 'System',-
--    @senderid VARCHAR(10)='chaful'


    DECLARE @ResellerID BIGINT;
    DECLARE @Result NVARCHAR(100);

    BEGIN TRY
        -- Get ResellerID from Reseller table based on UserID
       SELECT @ResellerID = Reseller_ID
        FROM [dbo].reseller_detail (NOLOCK)
        WHERE User_ID = @UserID;

        -- Check if the record already exists
        IF EXISTS (
            SELECT 1
            FROM [dbo].[DLTMappedEvent] (NOLOCK)
            WHERE 
			[Event] = @Event and
              --AND [DLTTemplateID] = @DLTTemplateID
               [ResellerID] = @ResellerID 
			  --[eventid] = @eventid
        )
        BEGIN
            -- Update the existing record's status
            UPDATE [dbo].[DLTMappedEvent]
            SET [isactive] = @isactive,
                [MappedDate] = GETDATE(),
				 [Event]=@Event, [DLTTemplateID]=@DLTTemplateID, [ResellerID]=@ResellerID,
                 [smscontent]=@smscontent, [eventid]=@eventid, [senderid]=@senderid
            WHERE 
			 [Event] = @Event and
              --AND [DLTTemplateID] = @DLTTemplateID
               [ResellerID] = @ResellerID 
               --[eventid] = @eventid;

            SET @Result = 'Record exists, status updated successfully.';
        END
        ELSE
        BEGIN
            -- Insert a new record
            INSERT INTO [dbo].[DLTMappedEvent] (
                [Event], [DLTTemplateID], [ResellerID], [MappedDate],
                [isactive], [smscontent], [eventid], [event_type], [senderid]
            )
            VALUES (
                @Event, @DLTTemplateID, @ResellerID, GETDATE(),
                @isactive, @smscontent, @eventid, 'System', @senderid
            );

            SET @Result = 'New record inserted successfully.';
        END

        -- Return success result
        SELECT @Result AS ResultMessage;
    END TRY
    BEGIN CATCH
        -- Handle errors and return error message
        SELECT ERROR_MESSAGE() AS ResultMessage;
    END CATCH
END




GO

/* ============================================================
   Procedure: [dbo].[USP_InsertPackage]
