AS          
Declare @Totalc money,@taxtCost bigint,@price money,@tax money        
--set @price=0.10        
--set @tax=10.30        
--set @taxtCost=((@Quintity*@price)*0.103)            
--set @Totalc=(@taxtCost+(@Quintity*@price))   
