/* ============================================================
   Procedure: [dbo].[usp_InsertPaymentDetailsAfterFailure]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_InsertPaymentDetailsAfterFailure
	@UserID INT,
	@PlanID INT
AS
BEGIN
	INSERT INTO Payment_Detail
	  (
	    UserID,
	    CustomerName,
	    CustomerNumber,
	    PlanID,
	    [Status],
	    PaymentDate,
	    CreatedDate
	  )
	SELECT ud.[User_ID],
	       ISNULL(ud.FName, '') + ISNULL(ud.LName, ''),
	       CONVERT(DECIMAL(20, 0), ud.Mobile),
	       0,
	       'Failure',
	       GETDATE(),
	       GETDATE()
	FROM   User_Detail AS ud
	WHERE  ud.[User_ID] = @UserID        
	
	
	SELECT 'Success'
END


GO

/* ============================================================
   Procedure: [dbo].[usp_InsertPaymentDetailsAfterSuccess]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_InsertPaymentDetailsAfterSuccess        
 @UserID INT ,        
 @PlanID INT ,        
 @TransactionID VARCHAR(550),        
 @Actual_Amount NUMERIC(18, 2),        
 @Coupon_Code NVARCHAR(100)        
AS        
BEGIN        
      
    Declare @ParentID bigint = 0      
    Declare @MID_P bigint = 0      
    Select top 1  @ParentID = isnull(ParentID,0) from User_detail with(nolock) where User_ID =    @UserID      
    Select top 1  @MID_P = isnull(M_ID,0)  from User_detail with(nolock) where User_ID = @ParentID       
      
      
 IF NOT EXISTS(        
        SELECT *        
        FROM   Payment_Detail AS pd with(nolock)        
        WHERE  pd.BankTransactionId = @TransactionID        
    )        
 BEGIN        
     DECLARE @Amount         DECIMAL,        
             @Credits        DECIMAL,        
             @UserFilter     VARCHAR(50),        
             @M_ID           BIGINT,        
             @ToM_ID         BIGINT,        
             @Balance1       DECIMAL,        
             @Balance2       DECIMAL                          
             
     SELECT top 1  @UserFilter = ud.userfilter,        
            @m_ID = ud.M_ID        
     FROM   User_Detail AS ud with(nolock)         
     WHERE  ud.[User_ID] = @ParentID                          
             
     SELECT @ToM_ID = ud.M_ID        
     FROM   User_Detail AS ud with(nolock)        
     WHERE  ud.[User_ID] = '335'                          
             
     SELECT @Amount = Price,        
            @Credits     = Quantity        
     FROM   PlanMaster with(nolock)       
     WHERE  ID           = @PlanID                          
             
             
             
     SELECT TOP 1 @Balance1 = cd.Balance        
     FROM   Credit_Details AS cd with(nolock)        
     WHERE  cd.[User_ID] = @ParentID        
     ORDER BY        
            cd.Credit_ID DESC              
             
     SELECT TOP 1 @Balance2 = cd.Balance        
     FROM   Credit_Details AS cd with(nolock)       
     WHERE  cd.[User_ID] = 335        
     ORDER BY        
            cd.Credit_ID DESC                  
             
             
             
     INSERT INTO AddCreditDetails        
       (        
         UserID,        
         AccountType,        
         Validity,        
         Amount,        
         Credits,        
         DNDRefundType,        
         FilterMode,        
         Reason,        
         Remarks,        
         CreditAgentID,        
         PricePerSMS,        
         CreatedDate--,      
   --CreatedBy   
         ,ACD_CreatedBy        
       )        
     VALUES        
       (        
         @ParentID,        
         @UserFilter,        
         'Unlimited',        
         @Amount,        
         @Credits,        
         'NR',        
         '10',        
         'Purchase',        
         'Bank Transaction ID :' + @TransactionID +        
         ' ,  Payment Done By : PayUMoney ',        
         335,        
         CAST(@Amount / @Credits AS DECIMAL(18, 4)),        
         GETDATE()--,      
   --@UserID 
        ,@UserID       
       )                          
             
     INSERT INTO Credit_Details        
       (        
         ID,        
         M_ID,        
         FromUser_ID,        
         [User_ID],        
         Debits,        
         Credits,        
         Balance,        
         Validity,        
         FromDate,        
         ToDate,        
         DateCreated,        
         DateUpdated,        
         EmpUpdated,        
         LastModified--,      
    -- CreatedBy
	    , CD_CreatedBy        
       )        
     VALUES        
       (        
         NEWID(),        
         @MID_P,        
         335,        
         @ParentID,        
         0,        
         @Credits,        
         ISNULL(@Balance1, 0) + @Credits,        
         '999999',        
         GETDATE(),        
         GETDATE(),        
         GETDATE(),        
         GETDATE(),        
         GETDATE(),        
         GETDATE() --,      
       -- @UserID 
	     ,@UserID       
       )                          
             
             
     INSERT INTO Credit_Details        
       (        
         ID,        
         M_ID,       
         FromUser_ID,        
         [User_ID],        
         Debits,        
         Credits,        
         Balance,        
         Validity,        
         FromDate,        
         ToDate,        
         DateCreated,        
         DateUpdated,        
         EmpUpdated,        
         LastModified --,      
       -- CreatedBy
	     ,CD_CreatedBy        
       )        
     VALUES        
       (        
         NEWID(),        
         @ToM_ID,        
         @ParentID,        
         335,        
         @Credits,        
         0,        
         ISNULL(@Balance2, 0) -@Credits,        
         '999999',        
         GETDATE(),        
         GETDATE(),        
     GETDATE(),        
         GETDATE(),        
         GETDATE(),        
         GETDATE() --,      
    --@UserID
	    ,@UserID        
       )                          
             
     INSERT INTO Payment_Detail        
       (        
         UserID,        
         CustomerName,        
         CustomerNumber,        
         PlanID,        
         TotalAmount,        
         InvoiceNo,        
         [Status],        
         BillingAddress,        
         ShippingAddress,        
         PaymentThrough,        
         PaymentMode,        
         BankTransactionId,        
         PaymentDate,        
         CreatedDate,        
         AmountWithoutTax,        
         Quantity,        
         CouponCode,        
         DiscountAmount,        
         OldSmsBalance,        
         NewSmsBalance,        
         Actual_Amount        
       )        
     SELECT ud.[User_ID],        
            ud.FName + ud.LName,        
            CONVERT(DECIMAL(20, 0), ud.Mobile),        
            @PlanID,        
            @Amount,        
            NEWID(),        
            'Success',        
            ud.[Address],        
            ud.[Address],        
            1,        
            'PayuMoney',        
            @TransactionID,        
            GETDATE(),        
            GETDATE(),        
            @Actual_Amount,        
            @Credits,        
            @Coupon_Code,        
            CASE         
                 WHEN @Coupon_Code <> '' THEN (        
                          SELECT TOP 1 mc.Discount        
                          FROM   M_Coupon AS mc        
                          WHERE  mc.CouponCode = @Coupon_Code        
                      )        
                 ELSE NULL        
            END,        
            ISNULL(@Balance1, 0),        
            ISNULL(@Balance1, 0) + @Credits,        
            @Actual_Amount        
     FROM   User_Detail AS ud with(nolock)        
     WHERE  ud.[User_ID] = @UserID        
 END        
         
 SELECT 'Success'        
END


GO

