/* ============================================================
   Procedure: [dbo].[Usp_InsertPaymentGatawaySetting]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_InsertPaymentGatawaySetting (
	@SaltKey VARCHAR(50)
	,@MerchantKey VARCHAR(50)
	,@PaymentsGateWayName VARCHAR(50)
	,@IsDefault BIT
	,@status INT
	,@ParentID BIGINT
	,@CreatedBy BIGINT
	)
AS
BEGIN
	IF (
			NOT EXISTS (
				SELECT 1
				FROM UserPaymentGateway
				WHERE ParentID = @ParentID
					AND PaymentsGateWayName = @PaymentsGateWayName
				)
			)
	BEGIN
		INSERT INTO UserPaymentGateway (
			ParentID
			,SaltKey
			,MerchantKey
			,PaymentsGateWayName
			,IsDefault
			,CreatedOn
			,CreatedBy
			,STATUS
			)
		VALUES (
			@ParentID
			,@SaltKey
			,@MerchantKey
			,@PaymentsGateWayName
			,@IsDefault
			,GETDATE()
			,@CreatedBy
			,@status
			)

		SELECT 'Record Saved'

		DECLARE @rowJson NVARCHAR(MAX) = (
				SELECT *
				FROM UserPaymentGateway(NOLOCK)
				WHERE ParentId = @ParentID
					AND PaymentsGateWayName = @PaymentsGateWayName
				FOR JSON AUTO
					,INCLUDE_NULL_VALUES
				)

		IF @RowJson IS NOT NULL
		BEGIN
			EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @CreatedBy
				,@Activity_type = 'Inst_Pymnt_Gtwy'
				,@ActionType = 'I'
				,@RowJson = @rowJson
				,@Table_name = 'UserPaymentGateway'
		END
	END
	ELSE
	BEGIN
		SELECT 'This payment gateway already exists'
	END
END



GO

