CREATE   PROCEDURE dbo.usp_InsertPaymentGateway    
 @ParentID BIGINT,    
 @SaltKey VARCHAR(50),    
 @MerchantKey VARCHAR(50),    
 @IsDefault BIT,    
 @CreatedBy BIGINT    
AS    
BEGIN    
 IF @IsDefault = 1    
 BEGIN    
     UPDATE UserPaymentGateway    
     SET    IsDefault     = 0    
     WHERE  ParentID      = @ParentID    
 END    
     
 INSERT INTO UserPaymentGateway    
   (    
     -- ID -- this column value is auto-generated    
     ParentID,    
     SaltKey,    
     MerchantKey,    
     IsDefault,    
     CreatedOn,    
     CreatedBy    
   )    
 VALUES    
   (    
     @ParentID,    
     @SaltKey,    
     @MerchantKey,    
     @IsDefault,    
     GETDATE(),    
     @CreatedBy    
   )    
     
   declare @UserSalt1 varchar(50)=(select top 1 SaltKey from UserPaymentGateway   
     WHERE  ParentID      = @ParentID and isdefault=1  )  
  declare @MerchantKey2 varchar(50)=(select top 1 MerchantKey from UserPaymentGateway   
     WHERE  ParentID      = @ParentID and isdefault=1  )  
     
   update usercartSettings  
   set UserSalt=@UserSalt1,UserKey=@MerchantKey2 where ParentID=@ParentID  
     
 SELECT 'Success'    
END


GO

