     @PaymentsGateWayName            
   )       
   insert into usercartSettings(usersalt,userkey,ParentID) values (@SaltKey,@MerchantKey,@ParentID)      
    SELECT 'Success'         
   end       
         
   else        
   begin          
             
  -- declare @UserSalt1 varchar(50)=(select top 1 SaltKey from UserPaymentGateway           
