/* ============================================================
   Procedure: [dbo].[usp_InsertPayoutTracked]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROC [dbo].[usp_InsertPayoutTracked]          
@referredcontactid bigint,@commissionid int,@remarks nvarchar(2000),@status bit,             
@conversionamount numeric(18,2),@commissionamount numeric(18,2) = null      
as          
begin          
declare @Referrerid int=(select  referrerid from ReferredContacts where ID=@referredcontactid )          
set @commissionamount = coalesce(@commissionamount,(select case when isamount=0 then commissionamount else commissionpercent*@conversionamount/100 end from Referrer_Payout_Rates where ID=@commissionid and @conversionamount>=minimumorderamount),0)     
if not exists(select 1 from PayoutTracking where ReferredContactId=@referredcontactid and Status='Payment Approved')     
begin        
insert into PayoutTracking(Commissionid,ReferredContactId,CommissionAmount,DateCreated,Status,Remarks)          
Select @commissionid,@referredcontactid,@commissionamount,GETDATE(),'Payment Approved',''         
end    
else    
begin    
declare @payoutid bigint=(select id from PayoutTracking where ReferredContactId=@referredcontactid and Status='Payment Approved' )    
update PayoutTracking set Commissionid=@commissionid,CommissionAmount=@commissionamount,DateCreated=GETDATE(),Remarks=@remarks where ID=@payoutid    
end    
declare @id bigint= isnull((select max(ID) from PayoutStatus where Referrerid=@Referrerid),0)        
declare @Commissiondue numeric(18,2) =isnull((select CommissionDueAfterPayout from PayoutStatus where ID=@id),0)        
if @status=1       
begin      
if not exists(select 1 from PayoutStatus where ReferredContactId=@referredcontactid and Type='Payout Approved')     
begin    
insert into PayoutStatus(Referrerid,CommissionDue,CommissionAdded,PaymentRequested,CommissionDueAfterPayout,DateCreated,Type,referredcontactid) select @Referrerid,@Commissiondue+@commissionamount,@commissionamount,0,@Commissiondue+@commissionamount,GETDATE(),'Payout Approved',@referredcontactid       
end    
else    
begin    
declare @payoutstatusid bigint=(select  id from Payoutstatus where ReferredContactId=@referredcontactid and Type='Payout Approved' )    
update Payoutstatus set CommissionDue=@Commissiondue+@commissionamount,CommissionAdded=@commissionamount,PaymentRequested=0,CommissionDueAfterPayout=@Commissiondue+@commissionamount,DateCreated=GETDATE(),Type='Payout Approved' where ID=@payoutstatusid    
end    
update ReferredContacts set PayoutEligible=1 where ID= @referredcontactid      
exec usp_UpdateUserActivity @Referrerid,'PayoutApproved',0      
end      
else      
begin      
insert into PayoutStatus(Referrerid,CommissionDue,CommissionAdded,PaymentRequested,CommissionDueAfterPayout,DateCreated,Type,referredcontactid,Remarks)       
select @Referrerid,@Commissiondue,0,0,@Commissiondue,GETDATE(),'Payout Rejected',@referredcontactid,@remarks        
update ReferredContacts set PayoutEligible=0 where ID= @referredcontactid      
exec usp_UpdateUserActivity @Referrerid,'PayoutRejected',0      
end      
Select 'Payment Status updated successfully'      
end 






GO

