/* ============================================================
   Procedure: [dbo].[usp_InsertPostRequestQueueLog]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_InsertPostRequestQueueLog
    @Url NVARCHAR(MAX),
    @FormattedText NVARCHAR(MAX),
    @SenderMobile NVARCHAR(50),
    @ToMobile NVARCHAR(50),
    @ParentId BIGINT,
    @ReportJson NVARCHAR(MAX)
AS
BEGIN
    SET NOCOUNT ON;

    BEGIN TRY
        INSERT INTO tbl_Ai_PostRequestLog
        (
            Url,
            FormattedText,
            SenderMobile,
            ToMobile,
            ParentId,
            ReportJson,
            IsProcessed,
            ProcessedAt
        )
        VALUES
        (
            @Url,
            @FormattedText,
            @SenderMobile,
            @ToMobile,
            @ParentId,
            @ReportJson,
            0, -- not processed yet
            NULL
        );

        -- Return the new Id
        SELECT CAST(SCOPE_IDENTITY() AS BIGINT) AS NewId;
    END TRY
    BEGIN CATCH
        EXEC usp_InsertErrorInfo 
    END CATCH
END


GO

/* ============================================================
   Procedure: [dbo].[usp_InsertPostRequestQueueLogProcess]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_InsertPostRequestQueueLogProcess
    @Url NVARCHAR(MAX),
    @FormattedText NVARCHAR(MAX),
    @SenderMobile NVARCHAR(50),
    @ToMobile NVARCHAR(50),
    @ParentId BIGINT,
    @ReportJson NVARCHAR(MAX)
AS
BEGIN
    SET NOCOUNT ON;

    BEGIN TRY
        IF EXISTS (
            SELECT 1 
            FROM tbl_Ai_PostRequestLog 
            WHERE SenderMobile = @SenderMobile 
              AND ToMobile = @ToMobile 
              AND ParentId = @ParentId
        )
        BEGIN
            -- Row already exists → update instead of insert
            UPDATE tbl_Ai_PostRequestLog
            SET IsProcessed = 1,
                ProcessedAt = GETDATE(),
                ReportJson = @ReportJson -- optional: update JSON if needed
            WHERE SenderMobile = @SenderMobile 
              AND ToMobile = @ToMobile 
              AND ParentId = @ParentId;
        END
        ELSE
        BEGIN
            -- Insert new row
            INSERT INTO tbl_Ai_PostRequestLog
            (
                Url,
                FormattedText,
                SenderMobile,
                ToMobile,
                ParentId,
                ReportJson,
                IsProcessed,
                ProcessedAt
            )
            VALUES
            (
                @Url,
                @FormattedText,
                @SenderMobile,
                @ToMobile,
                @ParentId,
                @ReportJson,
                1, -- not processed yet
                GETDATE()
            );
        END
    END TRY
    BEGIN CATCH
        EXEC usp_InsertErrorInfo;
    END CATCH
END


GO

/* ============================================================
   Procedure: [dbo].[usp_InsertPredefineDashboard]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


 -- exec usp_InsertPredefineDashboard
CREATE   PROCEDURE [dbo].[usp_InsertPredefineDashboard]
AS              
BEGIN 
	DECLARE @userid BIGINT;
    DECLARE @currentRow INT = 1;  -- Variable to track the current row in the temporary table
    DECLARE @totalRows INT;       -- Variable to store the total number of rows to process
	drop table if exists #UserIDs  
    -- Create a temporary table to store the User IDs
    CREATE TABLE #UserIDs (UserID BIGINT);

    -- Insert UserIDs into the temporary table
    INSERT INTO #UserIDs (UserID)
    SELECT distinct User_ID
    FROM User_Detail (NOLOCK)
	WHERE User_ID IS NOT NULL
    GROUP BY User_ID;
	
    -- Get the total number of rows
    SELECT @totalRows = COUNT(*) FROM #UserIDs;
	
-- Loop through each User_ID using a WHILE loop
    WHILE @currentRow <= @totalRows
	BEGIN
		-- Use a CTE to calculate ROW_NUMBER() and select the current UserID
				WITH CTE_UserIDs AS (
					SELECT UserID, ROW_NUMBER() OVER (ORDER BY UserID) AS RowNum
					FROM #UserIDs
				)
				SELECT @userid = UserID
				FROM CTE_UserIDs
				WHERE RowNum = @currentRow;

				IF NOT EXISTS (              
					SELECT 'x'              
					FROM   tbl_cd_CustomDashboard_Predifine AS uss              
					WHERE  uss.UserID = @userid              
				) 
		 BEGIN  
				INSERT INTO tbl_cd_CustomDashboard_Predifine(CustomDashboard,UserId,IsPredifine,IsVisible,CustomDashboardOrder,IsActive,IsDelete,PreCustomDashboard)       
				VALUES('Lead',@userid,1,1,1,1,0,'Lead')   
				
				INSERT INTO tbl_cd_CustomDashboard_Predifine(CustomDashboard,UserId,IsPredifine,IsVisible,CustomDashboardOrder,IsActive,IsDelete,PreCustomDashboard)       
				VALUES('Enquiries',@userid,1,1,2,1,0,'Enquiries')   

				INSERT INTO tbl_cd_CustomDashboard_Predifine(CustomDashboard,UserId,IsPredifine,IsVisible,CustomDashboardOrder,IsActive,IsDelete,PreCustomDashboard)  
				  VALUES('Conversions',@userid,1,1,3,1,0,'Conversions') 
				 
				 INSERT INTO tbl_cd_CustomDashboard_Predifine(CustomDashboard,UserId,IsPredifine,IsVisible,CustomDashboardOrder,IsActive,IsDelete,PreCustomDashboard)  
				  VALUES('Follow-ups',@userid,1,1,4,1,0,'Follow-ups') 
				 
				 INSERT INTO tbl_cd_CustomDashboard_Predifine(CustomDashboard,UserId,IsPredifine,IsVisible,CustomDashboardOrder,IsActive,IsDelete,PreCustomDashboard)  
				  VALUES('Tasks',@userid,1,1,5,1,0,'Tasks')           
				              
				 INSERT INTO tbl_cd_CustomDashboard_Predifine(CustomDashboard,UserId,IsPredifine,IsVisible,CustomDashboardOrder,IsActive,IsDelete,PreCustomDashboard)  
				  VALUES('Appointments',@userid,1,1,6,1,0,'Appointments')
				          
				INSERT INTO tbl_cd_CustomDashboard_Predifine(CustomDashboard,UserId,IsPredifine,IsVisible,CustomDashboardOrder,IsActive,IsDelete,PreCustomDashboard)  
				  VALUES('Calls',@userid,1,1,7,1,0,'Calls')
				              
				 INSERT INTO tbl_cd_CustomDashboard_Predifine(CustomDashboard,UserId,IsPredifine,IsVisible,CustomDashboardOrder,IsActive,IsDelete,PreCustomDashboard)  
				  VALUES('Support Tickets',@userid,1,1,8,1,0,'Support Tickets')
				             
				 INSERT INTO tbl_cd_CustomDashboard_Predifine(CustomDashboard,UserId,IsPredifine,IsVisible,CustomDashboardOrder,IsActive,IsDelete,PreCustomDashboard)  
				  VALUES('Mails',@userid,1,1,9,1,0,'Mails')
				            
				INSERT INTO tbl_cd_CustomDashboard_Predifine(CustomDashboard,UserId,IsPredifine,IsVisible,CustomDashboardOrder,IsActive,IsDelete,PreCustomDashboard)  
				  VALUES('Engagement Center',@userid,1,1,10,1,0,'Engagement Center')
				              
				 INSERT INTO tbl_cd_CustomDashboard_Predifine(CustomDashboard,UserId,IsPredifine,IsVisible,CustomDashboardOrder,IsActive,IsDelete,PreCustomDashboard)  
				  VALUES('Webpages',@userid,1,1,11,1,0,'Webpages')

				INSERT INTO tbl_cd_CustomDashboard_Predifine(CustomDashboard,UserId,IsPredifine,IsVisible,CustomDashboardOrder,IsActive,IsDelete,PreCustomDashboard)  
				  VALUES('Webforms',@userid,1,1,12,1,0,'Webforms')           
				
				INSERT INTO tbl_cd_CustomDashboard_Predifine(CustomDashboard,UserId,IsPredifine,IsVisible,CustomDashboardOrder,IsActive,IsDelete,PreCustomDashboard)  
				  VALUES('Employee Time Tracking',@userid,1,1,13,1,0,'Employee Time Tracking')
				  
				INSERT INTO tbl_cd_CustomDashboard_Predifine(CustomDashboard,UserId,IsPredifine,IsVisible,CustomDashboardOrder,IsActive,IsDelete,PreCustomDashboard)  
				  VALUES('Campaigns',@userid,1,1,14,1,0,'Campaigns') 
				  
				INSERT INTO tbl_cd_CustomDashboard_Predifine(CustomDashboard,UserId,IsPredifine,IsVisible,CustomDashboardOrder,IsActive,IsDelete,PreCustomDashboard)  
				  VALUES('Pipeline',@userid,1,1,15,1,0,'Pipeline')  
				 				  
			 END 
				 -- Move to the next row
        SET @currentRow = @currentRow + 1;
	END
	-- select * from tbl_cd_CustomDashboard_Predifine

	--  select * from SortTabs
END	
	




