/* ============================================================
   Procedure: [dbo].[Usp_InsertPreDefinedUserCampaignMaster]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE [dbo].[Usp_InsertPreDefinedUserCampaignMaster] --17626,'atultest','',0,'','','','',0,0,'','',0,0                         
(                          
@ParentID Bigint, --pass userid here                         
@PageName varchar(200),                          
@SmsMessage nvarchar(200),                      
@IsUniCode bit,                      
@EmailReplyTo nvarchar(100),                      
@EmailSubject nvarchar(100),                      
@EmailMessgae nvarchar(200),                      
@SmsSenderName nvarchar(100),                      
@IsSms bit,                       
@IsEmail bit,                    
@SmsAccountName nvarchar(100),                    
@EmailAccountName nvarchar(100),      
@SMStemplateid bigint,      
@Mailtemplateid bigint      
)                       
                        
as             
Begin        
declare @C_uid bigint   --@c_uid= Actual parentid                         
select @C_uid = User_ID from ClientPageDetail where PageName = 'www.kit19.com/'+@PageName    
--select @C_uid = User_ID from ClientPageDetail where PageName = 'localhost:3517/SMS19COM291217/'+@PageName                           
declare @pagename1 nvarchar(100)='Microsite-'+@PageName       
declare @medium nvarchar(100)                      
DECLARE @Name table(Mediumname nvarchar(100))      
insert into @Name      
exec GetNewNameuserid @c_uid,'UserMediumSettings','NAME',@pagename1      
set @medium=(select top 1 mediumname from @name)      
                   
--Create medium for microsite       
declare @mediumId bigint          
INSERT INTO UserMediumSettings                            
       (                            
         -- MediumID -- this column value is auto-generated                            
         NAME,                            
         UserID,                            
         IsEditable,                            
         IsActive,                            
         CreatedDate,      
         ModifiedDate,                            
         ModifiedBy                            
       )                     
     VALUES                            
       (                            
         @medium,                            
         @C_uid,                            
         0,                            
         1,                            
         GETDATE(),                            
         GETDATE(),                            
         @ParentID                            
       )                    
                   
select  @mediumId = SCOPE_IDENTITY()                  
                           
 --Create source for microsite      
declare @sourceId bigint                                            
IF NOT EXISTS (                            
        SELECT 'x'                            
        FROM   UserSourceSettings AS uss                            
        WHERE  uss.UserID = @C_uid                         
        and Name ='Landing Page'                          
    )                        
 begin                        
       INSERT INTO UserSourceSettings                            
       (                            
         -- SourceID -- this column value is auto-generated                            
         NAME,                            
         UserID,                         
         IsEditable,                            
         IsActive,                            
         CreatedDate,                            
         ModifiedDate,                            
         ModifiedBy                            
       )                            
     VALUES                            
       (                            
      'Landing Page',                            
         @C_uid,                            
         0,                            
         1,                            
         GETDATE(),                            
         GETDATE(),                            
         @parentid                            
       )                     
 select  @sourceId = SCOPE_IDENTITY()                          
 END      
 else      
 begin      
 select  @sourceId = sourceid                            
        FROM   UserSourceSettings AS uss               
        WHERE  uss.UserID = @C_uid                         
         and Name ='Landing Page'      
 end      
       
 declare @SmsCampaignId bigint       
 declare @emailcampaignid bigint      
 if @issms<>0 or @isemail<>0      
 begin      
 --Create applicability for Campaign      
declare @searchid bigint                  
declare @pagename2 nvarchar(100)=@PageName + ' - Enquiries'      
declare @Searchids nvarchar(100)                      
DECLARE @Search table(SearchName nvarchar(100))      
insert into @search      
exec GetNewName @ParentID,'UserSearchList','SearchName',@pagename2      
set @SearchIds=(select top 1 SearchName from @Search)         
                  
 INSERT INTO UserSearchList                            
       --(  ParentID,SearchName,SearchType,Medium,Source,       
          (  ParentID,SearchName,SearchType,Medium,Source,                            
         Campaign,SpecificName,SpecificAddress,SpecificMobileNo,                  
         SpecificEmail,SpecificCity,SpecificState,SpecificCountry,                            
         CurrentlyAssignedTo,FollowUpStatus,CreatedBetweenFrom,CreatedBetweenTo,                            
         NextFollowUpDateFrom,NextFollowUpDateTo,ConvertedWithinFrom,ConvertedWithinTo,                            
         DataListName,IsPredefined,IsResponse,IsUnsubscribe,                            
         IsSearch,IsCustom,CreatedOn,CreatedBy,                            
         ModifiedOn,ModifiedBy )                           
        values                  
         (@C_uid,@SearchIds,'EN',@mediumId,@sourceId,                             
            '','','','',                            
            '','','','',                            
            '','','','',                            
            '','','','',                            
            '',1,0,0,                            
            1,0,GETDATE(),@ParentID,                            
            '',@ParentID                   
            )                          
                                    
 select  @SearchId = SCOPE_IDENTITY()                         
       
 --Create campaigns for microsite                        
if(@IsSms=1)                      
 begin      
 declare @smscampaignname nvarchar(50) =@PageName + ' - EnquiryAddSMS'      
DECLARE @smscampaignNametbl table(smsCampaignname nvarchar(100))      
insert into @smscampaignNametbl      
exec GetNewName @Parentid,'UserCampaignmaster','CampaignName',@smscampaignname      
set @smscampaignname=(select top 1 smsCampaignname from @smscampaignNametbl)      
                          
 insert into UserCampaignMaster(       
