CREATE   PROC [dbo].[USP_insertPriceDetail]       
@M_Id bigint=10001,      
@user_id int=335,    -- frm bigint 19-08-2010  
@Quintitytext nvarchar(300),      
@Quintity bigint,      
@priceText nvarchar(150),      
@price money=10.3,      
@taxText nvarchar(150),      
@tax money      
as      
Declare @Totalc bigint,@taxtCost bigint    
set @taxtCost=((@Quintity*@price)*0.103)    
set @Totalc=(@taxtCost+(@Quintity*@price))    
print (@taxtCost)    
print (@Totalc)    
insert into packageDetail values(@M_Id,@user_id,@Quintitytext,@Quintity,@priceText,@price,@taxText,@taxtCost,@tax,'Price',@Totalc)      
select '1'    
