CREATE   PROCEDURE [dbo].[Usp_InsertProductDetails]  
 @Name NVARCHAR(100),  
 @Image NVARCHAR(100),  
 @Description NVARCHAR(200),  
 @Price NUMERIC(18, 2),  
 @IsPublished BIT,  
 @UserID INT,  
 @CreatedBy BIGINT,  
 @FullPath VARCHAR(MAX),  
 @IsFeatured BIT  
AS  
BEGIN  
 IF (  
        NOT EXISTS (  
            SELECT 'x'  
            FROM   ProductMaster  
            WHERE  NAME           = @Name  
                   AND UserID     = @UserID  
        )  
    )  
 BEGIN  
     INSERT INTO ProductMaster  
       (  
         NAME,  
         [Image],  
         [Description],  
         Price,  
         IsPublished,  
         IsActive,  
         UserID,  
         CreatedOn,  
         CreatedBy,  
         FullPath ,IsFeatured  
       )  
     VALUES  
       (  
         @Name,  
         @Image,  
         @Description,  
         @Price,  
         @IsPublished,  
         1,  
         @UserID,  
         GETDATE(),  
         @CreatedBy,  
         @FullPath,@IsFeatured  
       )          
       
     SELECT 'Record Saved Successfully'  
 END  
 ELSE  
 BEGIN  
     SELECT 'Record Already Exists'  
 END  
END  



