/* ============================================================
   Procedure: [dbo].[Usp_InsertProductFieldDisplayJson]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_InsertProductFieldDisplayJson] @displayJson NVARCHAR(MAX)
	,@parentID BIGINT
	,@mode VARCHAR(20) = NULL
	,@default NVARCHAR(max) = NULL
	,@isman BIT = 0
	,@choices NVARCHAR(max) = NULL
	,@customField NVARCHAR(max) = NULL
	,@oldcustomField NVARCHAR(max) = NULL
AS
BEGIN
	DECLARE @data NVARCHAR(MAX)

	DROP TABLE

	IF EXISTS #temp
		CREATE TABLE #temp (
			FieldName NVARCHAR(max)
			,DataType NVARCHAR(Max)
			,DefaultValue NVARCHAR(Max)
			,Mandatory BIT
			,FieldType NVARCHAR(Max)
			,MaxValue NVARCHAR(Max)
			,MinValue NVARCHAR(MAX)
			,Choices NVARCHAR(MAX)
			)

	IF @mode = 'Save'
	BEGIN
		IF NOT EXISTS (
				SELECT 1
				FROM tbL_ProductCustomFieldDisplayJson
				WHERE ParentId = @parentID
				)
		BEGIN
			INSERT INTO tbL_ProductCustomFieldDisplayJson (
				ParentId
				,DisplayJson
				)
			VALUES (
				@parentid
				,@displayJson
				)
		END
		ELSE
		BEGIN
			SELECT @data = DisplayJson
			FROM tbL_ProductCustomFieldDisplayJson
			WHERE ParentId = @parentid

			INSERT INTO #temp (
				FieldName
				,DataType
				,DefaultValue
				,Mandatory
				,FieldType
				,MaxValue
				,MinValue
				,Choices
				)
			SELECT FieldName
				,DataType
				,DefaultValue
				,Mandatory
				,FieldType
				,MaxValue
				,MinValue
				,Choices
			FROM OPENJSON(@data) WITH (
					FieldName NVARCHAR(max) '$.FieldName'
					,DataType NVARCHAR(Max) '$.DataType'
					,DefaultValue NVARCHAR(Max) '$.DefaultValue'
					,Mandatory NVARCHAR(Max) '$.Mandatory'
					,FieldType NVARCHAR(Max) '$.FieldType'
					,MaxValue NVARCHAR(Max) '$.MaxValue'
					,MinValue NVARCHAR(MAX) '$.MinValue'
					,Choices NVARCHAR(MAX) '$.Choices'
					)
			
			UNION ALL
			
			SELECT FieldName
				,DataType
				,DefaultValue
				,Mandatory
				,FieldType
				,MaxValue
				,MinValue
				,Choices
			FROM OPENJSON(@displayJson) WITH (
					FieldName NVARCHAR(max) '$.FieldName'
					,DataType NVARCHAR(Max) '$.DataType'
					,DefaultValue NVARCHAR(Max) '$.DefaultValue'
					,Mandatory NVARCHAR(Max) '$.Mandatory'
					,FieldType NVARCHAR(Max) '$.FieldType'
					,MaxValue NVARCHAR(Max) '$.MaxValue'
					,MinValue NVARCHAR(MAX) '$.MinValue'
					,Choices NVARCHAR(MAX) '$.Choices'
					)

			SET @displayJson = (
					SELECT *
					FROM #temp
					FOR json Auto
						,INCLUDE_NULL_VALUES
					)

			UPDATE tbL_ProductCustomFieldDisplayJson
			SET DisplayJson = @displayJson
			WHERE ParentId = @parentID
		END
	END
	ELSE IF @mode = 'Update'
	BEGIN
		SELECT @data = DisplayJson
		FROM tbL_ProductCustomFieldDisplayJson
		WHERE ParentId = @parentid

		INSERT INTO #temp (
			FieldName
			,DataType
			,DefaultValue
			,Mandatory
			,FieldType
			,MaxValue
			,MinValue
			,Choices
			)
		SELECT FieldName
			,DataType
			,DefaultValue
			,Mandatory
			,FieldType
			,MaxValue
			,MinValue
			,Choices
		FROM OPENJSON(@data) WITH (
				FieldName NVARCHAR(max) '$.FieldName'
				,DataType NVARCHAR(Max) '$.DataType'
				,DefaultValue NVARCHAR(Max) '$.DefaultValue'
				,Mandatory NVARCHAR(Max) '$.Mandatory'
				,FieldType NVARCHAR(Max) '$.FieldType'
				,MaxValue NVARCHAR(Max) '$.MaxValue'
				,MinValue NVARCHAR(MAX) '$.MinValue'
				,Choices NVARCHAR(MAX) '$.Choices'
				)

		--select * from #temp  
		IF @oldcustomField IS NOT NULL
		BEGIN
			UPDATE #temp
			SET FieldName = @customField
			WHERE FieldName = @oldcustomField
		END

		IF @default IS NOT NULL
		BEGIN
			UPDATE #temp
			SET DefaultValue = @default
			WHERE FieldName = @customField
		END

		IF @isman = 0
		BEGIN
			UPDATE #temp
			SET Mandatory = @isman
			WHERE FieldName = @customField
		END

		IF @choices IS NOT NULL
			UPDATE #temp
			SET Choices = @choices
			WHERE FieldName = @customField

		SET @displayJson = (
				SELECT *
				FROM #temp
				FOR json Auto
					,INCLUDE_NULL_VALUES
				)

		UPDATE tbL_ProductCustomFieldDisplayJson
		SET DisplayJson = @displayJson
		WHERE ParentId = @parentID
	END
END



GO

