CREATE   PROC [dbo].[USP_InsertRecordforTransaction]       
@ROWS INT,    
@SELECTTABLE VARCHAR(200),    
@INSERTTABLE VARCHAR(200),    
@SEARCHPRM VARCHAR(150),    
@CRITERIA VARCHAR(100),    
@SEARCHVALUE NVARCHAR(MAX),    
@IPADDRESS VARCHAR(50)    
AS    
BEGIN    
INSERT INTO RollBackTransaction(Rows,SelectTable,InsertTable,SearchParameters,    
Criteria,[Value],IPAddress,SubmitDate)    
VALUES(@ROWS,@SELECTTABLE,@INSERTTABLE,@SEARCHPRM,@CRITERIA,@SEARCHVALUE,@IPADDRESS,GETDATE())    
END  



