/* ============================================================
   Procedure: [dbo].[USP_INSERTRECORDINMESSAGEQUEUEIN_ALLowSenderid]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[USP_INSERTRECORDINMESSAGEQUEUEIN_ALLowSenderid]                  
@senderid VARCHAR(MAX)                                            
AS                                            
BEGIN TRANSACTION                                           
SET NOCOUNT ON                                         
DECLARE @sqlInsertmsgqueue NVARCHAR(MAX)                                      
DECLARE @sqlInsertmsgsource NVARCHAR(MAX)                                                              
DECLARE @sqlDelete NVARCHAR(MAX)                                        
declare @sqlInsertmsgqueueAirtel varchar(max)                                  
  
SET @sqlInsertmsgqueueAirtel= 'insert into MessageQueueAirtelpri(MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                            
IsDND,Operator,Isallowdnd,BatchID) SELECT MessageID,Mobile,[Message],SENDerID,2,Priority,U_ID,IsUniCode,                                            
IsDND,Operator,Isallowdnd,BatchID FROM MessageMonitor WHERE Priority=1  and  SENDerID = '   --and   Operator=''AD''                                               
SET @sqlInsertmsgqueueAirtel=@sqlInsertmsgqueueAirtel + '''' + @senderid + ''''                                  
                                  
                   
                                  
                                    
SET @sqlInsertmsgsource= 'insert into Messagesource(MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                      
IsDND,Operator,Isallowdnd,MessageBatchID) SELECT MessageID,Mobile,[Message],SENDerID,SmppID,Priority,U_ID,IsUniCode,                                      
IsDND,Operator,Isallowdnd,BatchID FROM MessageMonitor WHERE Priority=0 and  SENDerID = '                                            
SET @sqlInsertmsgsource=@sqlInsertmsgsource + '''' + @senderid + ''''                                       
                                      
                                   
                                  
                                  
                                  
                                      
SET @sqlDelete='DELETE FROM MessageMonitor WHERE SENDerID = '                                        
SET @sqlDelete=@sqlDelete + '''' + @senderid + ''''                      
                       
                
                    
exec(@sqlInsertmsgqueueAirtel)                     
                                       
EXEC(@sqlInsertmsgsource)                        
                                    
EXEC(@sqlDelete)                                        
                        
                
                        
IF @@error<>0                                            
BEGIN                                      
  -- Rollback the TRANSACTION                                            
    ROLLBACK                                         
    -- Raise an error and return           
    RAISERROR ('PleASe try again.', 16, 1)                                            
    RETURN                                            
END                                            
IF @@error=0                                            
BEGIN                                            
COMMIT TRANSACTION                                      
END 


GO

