/* ============================================================
   Procedure: [dbo].[Usp_InsertRecordsIntoProcessTablesNew]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
  
    
/****************************************************************************                        
SP_Name        : Usp_InsertRecordsIntoProcessTables                                           
Author         : vinay                        
Created ON     : 24/12/2009 04:30 PM                              
Version        : 1                        
Alter BY       :                                
Alter Date    :                         
Location       : PELSOFT                        
SP Description : This SP is Used to Insert Records Into Process Tables                        
****************************************************************************/                         
CREATE   PROC [dbo].[Usp_InsertRecordsIntoProcessTablesNew] --10801177,0                                            
@BatchID BIGINT ,                                              
@IsDndAllowed  TINYINT                                                              
AS                                           
SET NOCOUNT ON                                          
----- 1)Get All Airtel credit COUNT                                              
 DECLARE @CreditCount INT         
BEGIN try                                                       
        
 SELECT @CreditCount=COUNT(Message) FROM CloneMessageDeliveryStatus tmp inner join AirTELSEries Air on tmp.MobileSubSET=Air.MobileSubSET WHERE tmp.BatchID=@batchID                                                                
----2)GET ALL AIRTELNUBERS NUMBERS INTO THE TEMPAIRTELTABLES                                  
SELECT * INTO #TEMPAIRTEL FROM(SELECT CLONE.* FROM CloneMessageDeliveryStatus CLONE JOIN                                   
AirTELSEries Air                                  
ON CLONE.MobileSubSET=Air.MobileSubSET where BatchID=@BatchID                                                                
)AS DAirtel                                  
UPDATE #TEMPAIRTEL SET ISAIRTEL=1                                
                                  
--3) DELETE ALL AIRTEL NUMBERS FROM THE CloneMessageDeliveryStatus TABLE.                                  
  DELETE CloneMessageDeliveryStatus FROM  CloneMessageDeliveryStatus JOIN #TEMPAIRTEL                                                                         
  ON #TEMPAIRTEL.MESSAGEID=CloneMessageDeliveryStatus.MESSAGEID                                      
--4)                                   
  INSERT INTO CloneMessageDeliveryStatus                                  
 (                                  
 BatchID,Mobile,Message,SENDerID,MessageInsertDate,                                  
 ScheduledDate,ScheduledTime,SmppID,U_ID,IsUniCode,IsDnd,IsAirtel                                  
 ,MobileSubSET                                  
 )                                          
 SELECT  BatchID,Mobile,[Message],SENDerID,MessageInsertDate,ScheduledDate,ScheduledTime,SmppID,U_ID,IsUniCode,IsDnd,IsAirtel,                                  
 MobileSubSET FROM #TEMPAIRTEL                                  
                                      
DROP TABLE #TEMPAIRTEL                                  
----5)GET ALL DND NUMBERS INTO #TEMPDND                                  
SELECT * INTO #TEMPDND FROM(SELECT CLONE.* FROM CloneMessageDeliveryStatus CLONE JOIN                                   
DNDDirectory DNDIR                                  
ON CLONE.Mobile=DNDIR.DNDMobileNo where BatchID=@BatchID                                                              
)AS DNDDIR                                  
UPDATE #TEMPDND SET ISDND=1                                  
---6) DELETE ALL DND MESSAGES  FROM CloneMessageDeliveryStatus                                  
  DELETE CloneMessageDeliveryStatus FROM  CloneMessageDeliveryStatus JOIN #TEMPDND                                                                         
  ON #TEMPDND.MESSAGEID=CloneMessageDeliveryStatus.MESSAGEID                                    
---7)                                   
 INSERT INTO CloneMessageDeliveryStatus                                  
 (                                  
 BatchID,Mobile,Message,SENDerID,MessageInsertDate,                                  
 ScheduledDate,ScheduledTime,SmppID,U_ID,IsUniCode,IsDnd,IsAirtel                                  
 ,MobileSubSET                                  
 )           
 SELECT  BatchID,Mobile,[Message],SENDerID,MessageInsertDate,                                               
 ScheduledDate,ScheduledTime,SmppID,U_ID,IsUniCode,IsDnd,IsAirtel,                                  
 MobileSubSET FROM #TEMPDND               
DROP TABLE #TEMPDND                                  
--**********************Manoj 28-01-1010***TO SEND SCHEDULE MESSAGE TO PROCESSTABLE*********************                   
SELECT * INTO #TEMPOFCLONE FROM CloneMessageDeliveryStatus where BatchID=@BatchID --and ScheduledDate='' AND ScheduledTime=''                     
                  
                                        
--SELECT * INTO #TEMPOFCLONE FROM CloneMessageDeliveryStatus where BatchID=@BatchID                            
     IF @IsDndAllowed=1                           
         BEGIN             
 --INSERT INTO MDS_COMPARE                                
 --   (                                  
 --   MessageID,BatchID,Mobile,Message,SENDerID,MessageInsertDate                                  
 --   ,SmppID,U_ID,IsUniCode,IsDND,operator,MessageStatus                                  
 --   )                                  
 --   SELECT MessageID,BatchID,Mobile,[Message],SENDerID,MessageInsertDate,                                  
 --   SmppID,U_ID,IsUniCode,IsDnd,IsAirtel,2 FROM                                  
 --   #TEMPOFCLONE  where ScheduledDate='' AND ScheduledTime=''         
                 
    INSERT INTO MessageDeliveryStatus                                  
    (                                  
    MessageID,BatchID,Mobile,Message,SENDerID,MessageInsertDate                                  
    ,SmppID,U_ID,IsUniCode,IsDND,operator,MessageStatus                                  
    )                                  
    SELECT MessageID,BatchID,Mobile,[Message],SENDerID,MessageInsertDate,                                  
    SmppID,U_ID,IsUniCode,IsDnd,IsAirtel,2 FROM                                  
    #TEMPOFCLONE  where ScheduledDate='' AND ScheduledTime=''              
        
                   
         END                                           
      ELSE                    
                            
        BEGIN                        
 --INSERT INTO MDS_COMPARE        
 --   (                                  
 --   MessageID,BatchID,Mobile,Message,SENDerID,MessageInsertDate                                  
 --   ,SmppID,U_ID,IsUniCode,IsDND,operator,MessageStatus                                  
 --   )                                  
 --   SELECT MessageID,BatchID,Mobile,[Message],SENDerID,MessageInsertDate,                                  
 --   SmppID,U_ID,IsUniCode,IsDnd,IsAirtel,cASe IsDnd when 0 then 2 ELSE 3 END FROM                                  
 --   #TEMPOFCLONE where ScheduledDate='' AND ScheduledTime=''                          
    
      
    INSERT INTO MessageDeliveryStatus                                  
    (                                  
    MessageID,BatchID,Mobile,Message,SENDerID,MessageInsertDate                                  
    ,SmppID,U_ID,IsUniCode,IsDND,operator,MessageStatus                                  
    )                                  
    SELECT MessageID,BatchID,Mobile,[Message],SENDerID,MessageInsertDate,                                  
    SmppID,U_ID,IsUniCode,IsDnd,IsAirtel,cASe IsDnd when 0 then 2 ELSE 3 END FROM                                  
    #TEMPOFCLONE where ScheduledDate='' AND ScheduledTime=''                          
        
              
                 
END                          
                               
                                 
DECLARE @TBLNAME INT                   
SELECT @TBLNAME=ProcessTable FROM BatchInfo WHERE BatchID=@BatchID                                  
IF @TBLNAME=1                                   
 BEGIN                                  
  INSERT INTO ProcessTableFirst       
  (                                  
  MessageID,BatchID,Mobile,Message,SENDerID,MessageInsertDate,SmppID,U_ID,IsUniCode,IsDND
  )                                  
  SELECT MessageID,BatchID,Mobile,Message,SENDerID,MessageInsertDate,SmppID,U_ID,IsUniCode,IsDnd                                  
  FROM #TEMPOFCLONE  order by MessageID asc--Added by Shekhar from and mobile no                          
                         
END                                  
                                  
IF @TBLNAME=2                                  
 BEGIN                                  
  INSERT INTO ProcessTableTwo                                  
  (                                  
  MessageID,BatchID,Mobile,Message,SENDerID,MessageInsertDate,SmppID,U_ID,IsUniCode,IsDND
  )                                  
  SELECT MessageID,BatchID,Mobile,Message,SENDerID,MessageInsertDate,SmppID,U_ID,IsUniCode,IsDnd                                
  FROM #TEMPOFCLONE order by MessageID asc--Added by Shekhar from and mobile no                                 
END                                  
                                  
IF @TBLNAME=3                                  
 BEGIN                                  
  INSERT INTO ProcessTableThree                                  
  (                                  
    MessageID,BatchID,Mobile,Message,SENDerID,MessageInsertDate,SmppID,U_ID,IsUniCode,IsDND
  )                                  
  SELECT MessageID,BatchID,Mobile,Message,SENDerID,MessageInsertDate,SmppID,U_ID,IsUniCode,IsDnd                                  
   FROM #TEMPOFCLONE   order by MessageID asc--Added by Shekhar from and mobile no                                   
END                                  
IF @TBLNAME=4                                  
 BEGIN                    
  INSERT INTO ProcessTableFour                                  
  (                                  
  MessageID,BatchID,Mobile,Message,SENDerID,MessageInsertDate,SmppID,U_ID,IsUniCode,IsDND
  )                                  
  SELECT MessageID,BatchID,Mobile,Message,SENDerID,MessageInsertDate,SmppID,U_ID,IsUniCode,IsDnd                                  
  FROM #TEMPOFCLONE  order by MessageID asc--Added by Shekhar from and mobile no                                
                                  
END                                  
  --ADDED BY VINAY TO DELETE RECORDS FROM CloneMessageDeliveryStatus INSTEAD OF SCHEDULE MESSAGE                            
    -- DELETE FROM CloneMessageDeliveryStatus WHERE BatchID=@BatchID AND ScheduledDate='' AND ScheduledTime=''                            
                  
Drop table #TEMPOFCLONE                  
  --END                                
 SELECT @CreditCount          
END TRY        
BEGIN CATCH        
  EXECUTE usp_InsertErrorInfo;        
End CATCH        
          
          


GO

