 INSERT INTO [10.0.0.135].mysmstrans.dbo.MessageQueueCritical(MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,U_ID,PRIORITY,ISUNICODE,ISDND,OPERATOR,BATCHID,isprocessed)         
