 SELECT MESSAGEID, MOBILE,[MESSAGE],SENDERID,2, U_ID,2,ISUNICODE,ISDND,'UI',BATCHID,1,getdate() FROM dbo.CLONEMESSAGEDELIVERYSTATUSLESS with (nolock) WHERE BATCHID=@BATCHID AND MESSAGESTATUS=''     
 print concat('Inserted into MessageQueueNew: ',@@Rowcount)                 
