CREATE   PROCEDURE [dbo].[Usp_InsertRecordsIntoQueuelessthanFIVE_API] --11967459   
@BATCHID BIGINT   
AS   
if exists(select 1 from CloneMessageDeliveryStatusLess with (nolock) where BatchID=@BATCHID)   
begin   
--VF-1,SPICE-2,DEMO:PROMOSPICE-4,TRANSSPICE-5,TRCSPICE-6,PROMOVF-7,TRANSVF-8,TRCVF-9   
DECLARE @FILTERMODE NVARCHAR(100),@SMPPID NVARCHAR(100)   
DECLARE @DBTYPE INT   
SET NOCOUNT ON   
   
 SET @DBTYPE=(SELECT TOP(1) DBTYPE FROM dbo.CLONEMESSAGEDELIVERYSTATUSLESS with (nolock) WHERE BATCHID=@BATCHID )   
   
 SELECT @FILTERMODE=USERFILTER,@SMPPID=isnull(SMPPID,2) FROM dbo.USER_DETAIL with (nolock) WHERE USER_ID IN(SELECT U_ID FROM dbo.CLONEMESSAGEDELIVERYSTATUSLESS WHERE BATCHID=@BATCHID)   
   
   
--SET XACT_ABORT ON ;   
--ALTER DATABASE MySMStrans   
--SET ALLOW_SNAPSHOT_ISOLATION ON;   
RETRY:   
BEGIN TRY   
--BEGIN TRAN   
   
 INSERT INTO dbo.MESSAGEDELIVERYSTATUS(MESSAGEID,BATCHID,MOBILE,MESSAGE,SENDERID,MESSAGEINSERTDATE,SMPPID,U_ID, ISUNICODE,ISDND,OPERATOR,PRIORITY,MESSAGESTATUS,ISALLOWDND ,DBTYPE)   
 SELECT MESSAGEID,BATCHID,MOBILE,[MESSAGE],SENDERID,MESSAGEINSERTDATE,SMPPID,U_ID,ISUNICODE,ISDND,'UI',ISNULL (ISPRORITY,0),case when len(mobile)=10 and isnumeric(mobile)=1   
 and replace(mobile,'+','')=mobile then MESSAGESTATUS else '6' end,1,ISNULL(DBTYPE,0) FROM dbo.CLONEMESSAGEDELIVERYSTATUSLESS with (nolock) WHERE   
 BATCHID=@BATCHID   
   
--delete from CLONEMESSAGEDELIVERYSTATUSLESS where BATCHID=@BATCHID and (len(mobile)<>10 or isnumeric(mobile)<>1 or replace(mobile,'+','')<>mobile )   
   
if exists(select top 1 'x' from Link_smsUrl_dtl where BatchID =@BATCHID)   
begin   
;WITH cte AS (SELECT mobile,batchid,ROW_NUMBER() OVER (PARTITION BY mobile,batchid ORDER BY mobile) row_num   
FROM CLONEMESSAGEDELIVERYSTATUSLESS where batchid=@batchid)   
DELETE FROM cte WHERE row_num > 1;   
;WITH cte1 AS (SELECT mobile,batchid,ROW_NUMBER() OVER (PARTITION BY mobile,batchid ORDER BY mobile) row_num   
FROM link_smsmobile where batchid=@batchid)   
DELETE FROM cte1 WHERE row_num > 1;   
end   
   
