 SELECT c.MESSAGEID, MOBILE,[MESSAGE],SENDERID,@SMPPID, U_ID,2,ISUNICODE,ISDND,'UI',BATCHID FROM dbo.CLONEMESSAGEDELIVERYSTATUSLESS c with (nolock) WHERE BATCHID=@BATCHID AND MESSAGESTATUS=''   
