 SELECT MESSAGEID, MOBILE,[MESSAGE],SENDERID,@SMPPID, U_ID,2,ISUNICODE,ISDND,'UI',BATCHID FROM dbo.CLONEMESSAGEDELIVERYSTATUSLESS with (nolock) WHERE BATCHID=@BATCHID AND MESSAGESTATUS='' AND (SMPPID=1 OR SMPPID=2)   
   
   
