 /*
 Else   
 BEGIN   
 INSERT INTO MessageQueueNoFilter(MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,U_ID,PRIORITY,ISUNICODE,ISDND,OPERATOR,BATCHID,ISALLOWDND)   
