/* ============================================================
   Procedure: [dbo].[Usp_InsertRecordsIntoQueuelessthanFIVE_NewForService_WhileSync]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

     
CREATE   PROCEDURE [dbo].[Usp_InsertRecordsIntoQueuelessthanFIVE_NewForService_WhileSync]-- 123142070--123142069--123142068-- 1035     
     
@BATCHID BIGINT=null -- CHANGE FROM INT TO BIGINT GAURAV 17-08-2010     
AS     
set @BATCHID=coalesce(@batchid,0)     
print @batchid  
if exists(select 1 from CloneMessageDeliveryStatusLess with (nolock) where BatchID=@BATCHID)     
begin     
print 'Entered if block'      
  
DECLARE @FILTERMODE NVARCHAR(100),@SMPPID NVARCHAR(100)     
DECLARE @DBTYPE INT     
     
SET NOCOUNT ON     
     
RETRY:     
BEGIN TRY     
 SET @DBTYPE=(SELECT TOP(1) DBTYPE FROM CLONEMESSAGEDELIVERYSTATUSLESS with (nolock) WHERE BATCHID=@BATCHID )     
 IF(@DBTYPE=0)     
 BEGIN     
 SELECT @FILTERMODE=USERFILTER,@SMPPID=SMPPID FROM USER_DETAIL with (nolock) WHERE USER_ID IN(SELECT U_ID FROM     
 CLONEMESSAGEDELIVERYSTATUSLESS with (nolock) WHERE BATCHID=@BATCHID)     
  END     
   print 'Filtermode: '+@filtermode      
  
  
if not exists  
 (select 1 from mysms.dbo.MESSAGEDELIVERYSTATUS with (nolock) where batchid=@batchid)  
begin      
 INSERT INTO mysms.dbo.MESSAGEDELIVERYSTATUS (MESSAGEID,BATCHID,MOBILE,MESSAGE,SENDERID,MESSAGEINSERTDATE,SMPPID,U_ID,ISUNICODE,ISDND,OPERATOR,PRIORITY, MESSAGESTATUS,ISALLOWDND    
   ,DBTYPE)     
 SELECT MESSAGEID,BATCHID,MOBILE,[MESSAGE],SENDERID,MESSAGEINSERTDATE,@SMPPID,U_ID,ISUNICODE,ISDND,'UI',2, MESSAGESTATUS,1,ISNULL(DBTYPE,0) FROM CLONEMESSAGEDELIVERYSTATUSLESS with (nolock) WHERE BATCHID=@BATCHID     
 print concat('Inserted into messagedeliverystatus: ',@@Rowcount)        
  
IF(@FILTERMODE='MTIX_TR')     
 BEGIN     
 INSERT INTO [10.0.0.135].[mysmstrans].[dbo].MessageQueueNew(MESSAGEID, MOBILE,[MESSAGE],SENDERID, SMPPID, U_ID, PRIORITY,ISUNICODE, ISDND,OPERATOR,BATCHID)     
 SELECT MESSAGEID, MOBILE,[MESSAGE],SENDERID,@SMPPID, U_ID,2,ISUNICODE,ISDND,'UI',BATCHID FROM CLONEMESSAGEDELIVERYSTATUSLESS with (nolock)     
 WHERE BATCHID=@BATCHID AND MESSAGESTATUS='' --AND MOBILE NOT IN('7860804804','7042075358','7860975764')     
 AND (@SMPPID=1 OR @SMPPID=2)--AND ISNULL(DBO.FN_FINDSPAM(MESSAGE),0) = 0    
  print concat('Inserted into MessageQueueNew: ',@@Rowcount)        
  
 END     
     
 ELSE IF(@FILTERMODE='MTIX_PRO')     
 BEGIN     
 INSERT INTO [10.0.0.135].[mysmstrans].[dbo].MessageQueueProROUTE(MESSAGEID, MOBILE,[MESSAGE],SENDERID, SMPPID, U_ID, PRIORITY,ISUNICODE, ISDND,OPERATOR,BATCHID)     
 SELECT MESSAGEID, MOBILE,[MESSAGE],SENDERID,@SMPPID, U_ID,2,ISUNICODE,ISDND,'UI',BATCHID FROM CLONEMESSAGEDELIVERYSTATUSLESS with (nolock)     
 WHERE BATCHID=@BATCHID AND MESSAGESTATUS='' --AND MOBILE NOT IN('7860804804','7042075358','7860975764')     
 AND (@SMPPID=1 OR @SMPPID=2)--AND ISNULL(DBO.FN_FINDSPAM(MESSAGE),0) = 0   
   print concat('Inserted into MessageQueueProROUTE: ',@@Rowcount)        
 END     
     
 ELSE IF(@FILTERMODE='MTIX_TRC')     
 BEGIN     
  INSERT INTO [10.0.0.135].[mysmstrans].[dbo].MessageQueueTrcRoute(MESSAGEID, MOBILE,[MESSAGE],SENDERID, SMPPID, U_ID, PRIORITY,ISUNICODE, ISDND,OPERATOR,BATCHID)     
 SELECT c.MESSAGEID, MOBILE,[MESSAGE],SENDERID,SMPPID, U_ID,2,ISUNICODE,ISDND,'UI',BATCHID FROM dbo.CLONEMESSAGEDELIVERYSTATUSLESS c     
 with (nolock) WHERE BATCHID=@BATCHID AND MESSAGESTATUS='' --AND MOBILE NOT IN('7860804804','7042075358','7860975764','9111087844')     
 AND (SMPPID=1 OR SMPPID=2) --AND not exists(SELECT 1 FROM #output o WHERE o.messageid=c.messageid)     
      print concat('Inserted into MessageQueueTrcRoute: ',@@Rowcount)        
  
  END     
  ELSE IF(@FILTERMODE='CRITICAL')     
 BEGIN     
 INSERT INTO [10.0.0.135].[mysmstrans].[dbo].MessageQueueCritical(MESSAGEID,MOBILE,[MESSAGE],SENDERID,SMPPID,U_ID,PRIORITY,ISUNICODE,ISDND,OPERATOR,BATCHID)     
 SELECT MESSAGEID, MOBILE,[MESSAGE],SENDERID,@SMPPID, U_ID,2,ISUNICODE,ISDND,'UI',BATCHID FROM dbo.CLONEMESSAGEDELIVERYSTATUSLESS with (nolock) WHERE BATCHID=@BATCHID AND MESSAGESTATUS='' AND (@SMPPID=1 OR @SMPPID=2)     
       print concat('Inserted into MessageQueueCritical: ',@@Rowcount)        
 END   
 end  
    
 --DELETE FROM CLONEMESSAGEDELIVERYSTATUSLESS WHERE BATCHID=@BATCHID     
     
--IF @@TRANCOUNT>0     
 --COMMIT     
 END TRY     
BEGIN CATCH     
 --IF @@TRANCOUNT>0     
 --ROLLBACK     
 --EXECUTE mysmstrans.dbo.USP_INSERTERRORINFO;     
  EXECUTE  USP_INSERTERRORINFO;     
 IF ERROR_NUMBER() = 1205 -- Deadlock Error Number     
 BEGIN     
 WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms     
 GOTO RETRY -- Go to Label RETRY     
 end     
END CATCH     
END     
     
     


