set @BATCHID=coalesce(@batchid,0) 
if exists(select 1 from CloneMessageDeliveryStatusLess where BatchID=@BATCHID) 
begin 
--VF-1,SPICE-2,DEMO:PROMOSPICE-4,TRANSSPICE-5,TRCSPICE-6,PROMOVF-7,TRANSVF-8,TRCVF-9 
