 BEGIN 
 SELECT @FILTERMODE=USERFILTER,@SMPPID=SMPPID FROM USER_DETAIL WHERE USER_ID IN(SELECT U_ID FROM CLONEMESSAGEDELIVERYSTATUSLESS WHERE BATCHID=@BATCHID) 
