CREATE   PROC [dbo].[USP_InsertRecordSubmitDetail]        
@ResultCode nvarchar(100),        
@SequenceNumber nvarchar(100),        
@Reference nvarchar(100),    
@CreatedDate datetime,    
@SubReference nvarchar(50),  
@ServiceName nvarchar(100),  
@textFileName nvarchar(100)     
AS      
BEGIN      
 INSERT INTO SubmitDetail(ResultCode,SequenceNumber,Reference,CreatedDate,SubReference,ServiceName,TextFileName)        
 Values(@ResultCode,@SequenceNumber,@Reference,@CreatedDate,@SubReference,@ServiceName,@textFileName)      
END




