/* ============================================================
   Procedure: [dbo].[usp_InsertReportSummaryStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-----------------------------------------------------
CREATE   PROCEDURE [dbo].[usp_InsertReportSummaryStatus]
    @reportdate DATE,
    @parentid INT,
    @summary NVARCHAR(MAX),
    @Whatsappsendid BIGINT = NULL,
    @error NVARCHAR(255) = NULL
AS
BEGIN
    DECLARE @NewID BIGINT; -- Variable to capture the inserted ID

    BEGIN TRY
        -- Insert the data into the ReportSummaryStatus table
        INSERT INTO ReportSummaryStatus (reportdate, parentid, summary, Whatsappsendid, error)
        VALUES (@reportdate, @parentid, @summary, @Whatsappsendid, @error);

        -- Capture the inserted ID
        SET @NewID = SCOPE_IDENTITY();

        -- Return success message with the new ID
        SELECT 'Insert Successful' AS 'Message',@NewID AS 'InsertedID' ;
    END TRY
    BEGIN CATCH
	 exec usp_InsertErrorInfo   
        -- Return error message
        SELECT 
            ERROR_MESSAGE() AS ErrorMessage,
            ERROR_NUMBER() AS ErrorNumber,
            ERROR_SEVERITY() AS ErrorSeverity,
            ERROR_STATE() AS ErrorState,
            ERROR_LINE() AS ErrorLine,
            ERROR_PROCEDURE() AS ErrorProcedure;
    END CATCH
END;




GO

/* ============================================================
   Procedure: [dbo].[usp_InsertReportSummaryStatus_bulk]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_InsertReportSummaryStatus_bulk]
   @tbl parentids readonly,@reportdate date
AS
BEGIN
    
    BEGIN TRY
        -- Insert the data into the ReportSummaryStatus table
        INSERT INTO ReportSummaryStatus (reportdate, parentid)
        select @reportdate, parentid from @tbl;
		select 1 as status, null as error
    END TRY
    BEGIN CATCH
	 select 0 as status, ERROR_MESSAGE() as error
	 exec usp_InsertErrorInfo   
    END CATCH
END;


GO

/* ============================================================
   Procedure: [dbo].[usp_InsertSalesTargetSettingMaster]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_InsertSalesTargetSettingMaster] (    
 @TargetType VARCHAR(30)    
 ,@Conversions BIT = NULL    
 ,@Pipelines BIT = NULL    
 ,@Invoices BIT = NULL    
 ,@iInvoiceRaised BIT = NULL    
 ,@iInvoicePaid BIT = NULL    
 ,@TargetFor VARCHAR(30)    
 ,@TeamCodes VARCHAR(4000) = NULL    
 ,@UserIds NVARCHAR(max) = NULL    
 ,@TargetPeriodId INT = NULL    
 ,@TargetFromDate DATETIME = NULL    
 ,@TargetToDate DATETIME = NULL    
 ,@TargetProductIds NVARCHAR(MAX) = NULL    
 ,@TargetPipelineIds NVARCHAR(MAX) = NULL    
 ,@TotalTarget NUMERIC(18, 2) = NULL    
 ,@TargetUnit VARCHAR(30) = NULL    
 ,@Currency VARCHAR(30) = NULL    
 ,@UserId BIGINT = NULL    
 ,@ParentId BIGINT = NULL    
 ,@Status BIT = NULL    
 ,@IsActive BIT = NULL    
 ,@CreatedBy BIGINT = NULL    
 ,@dtChildMaster NVARCHAR(max) = NULL    
 )    
AS    
SET NOCOUNT ON    
    
BEGIN    
 BEGIN TRY    
  BEGIN    
   DECLARE @SalesTargetId BIGINT = 0;    
   DECLARE @ialready INT = 0;    
   DECLARE @Id BIGINT, @AreadyExistsMessage nvarchar(max) =  '', @UserNames nvarchar(max) = ''
    
   IF EXISTS (  SELECT 1 FROM TBL_ST_SalesTargetSettingMaster(NOLOCK) 
		WHERE IsActive = 1 and TargetType = @TargetType AND TeamCodes = @TeamCodes  AND ParentId = @ParentId    
			AND TargetFromDate BETWEEN @TargetFromDate AND @TargetToDate 
			AND TargetToDate BETWEEN @TargetFromDate AND @TargetToDate )    
   BEGIN    
		SET @Id = ( SELECT TOP 1 SalesTargetId FROM TBL_ST_SalesTargetSettingMaster 
			WHERE TargetType = @TargetType AND IsActive = 1 
				AND TeamCodes = @TeamCodes AND ParentId = @ParentId    
				AND TargetFromDate BETWEEN @TargetFromDate AND @TargetToDate    
				AND TargetToDate BETWEEN @TargetFromDate AND @TargetToDate    
		  )    
		print concat('@Id => ', @Id)
		IF EXISTS ( SELECT * FROM TBL_ST_SalesTargetSettingChild(nolock) 
				WHERE SalesTargetId = @Id AND USERID IN ( 
					SELECT UserId FROM openjson(@dtChildMaster) WITH ([UserId] BIGINT '$.UserId') t))    
		BEGIN
			select @UserNames = STRING_AGG( CONCAT(ud.FName, ' ', ud.LName, '(', ud.User_Login, ')'), ',')  
				FROM TBL_ST_SalesTargetSettingChild(nolock) sm 
				inner join User_Detail(nolock) ud on sm.UserId = ud.User_ID WHERE sm.SalesTargetId = @Id

			select @AreadyExistsMessage = concat('SaleTarget ', ( case TargetType when 1 then 'Revenue' when  2 then 'Conversions' else '' end ), 
				' overlapping for date between ', format(TargetFromDate, 'dd-MMM-yyyy HH:mm'),
					' to ', format(TargetFromDate, 'dd-MMM-yyyy HH:mm'),
					' already exists for ', @UserNames )
			from TBL_ST_SalesTargetSettingMaster(nolock) sm
					where sm.SalesTargetId = @Id

			SET @ialready = 1
		END    
	END    
  
   IF (@ialready = 0)    
   BEGIN    
    INSERT INTO TBL_ST_SalesTargetSettingMaster (    
     TargetType    
     ,Conversions    
     ,Pipelines    
     ,Invoices    
     ,iInvoiceRaised    
     ,iInvoicePaid    
     ,TargetFor    
     ,TeamCodes    
     ,UserIds    
     ,TargetPeriodId    
     ,TargetFromDate    
     ,TargetToDate    
     ,TargetProductIds    
     ,TargetPipelineIds    
     ,TotalTarget    
     ,TargetUnit    
     ,Currency    
     ,UserId    
     ,ParentId    
     ,[Status]    
     ,IsActive    
     ,CreatedBy    
     ,CreatedDate    
     )    
    VALUES (    
     @TargetType    
     ,@Conversions    
     ,@Pipelines    
     ,@Invoices    
     ,@iInvoiceRaised    
     ,@iInvoicePaid    
     ,@TargetFor    
     ,@TeamCodes    
     ,@UserIds    
     ,@TargetPeriodId    
     ,@TargetFromDate    
     ,@TargetToDate    
     ,@TargetProductIds    
     ,@TargetPipelineIds    
     ,@TotalTarget    
     ,@TargetUnit    
     ,@Currency    
     ,@UserId    
     ,@ParentId    
     ,@Status    
     ,@IsActive    
     ,@CreatedBy    
     ,GETDATE()    
     )    
    
    SET @SalesTargetId = SCOPE_IDENTITY()    
    
    INSERT INTO TBL_ST_SalesTargetSettingChild (    
     SalesTargetId    
     ,TeamCode    
     ,UserId    
     ,[Target]    
     ,IsActive    
     )    
    SELECT @SalesTargetId    
     ,TeamCode    
     ,UserId    
     ,[Target]    
     ,IsActive    
    FROM openjson(@dtChildMaster) WITH (    
      [TeamCode] NVARCHAR(50) '$.TeamCode'    
      ,[UserId] BIGINT '$.UserId'    
      ,[Target] FLOAT '$.Target'    
      ,[IsActive] BIT '$.IsActive'    
      ) t    
    
    SELECT 'Saved Successfully'    
   END    
   ELSE    
   BEGIN    
    SELECT @AreadyExistsMessage    
   END    
  END /*End here for details*/    
 END TRY    
    
 BEGIN CATCH    
  DECLARE @ErrorMessage NVARCHAR(4000);    
    
  SELECT @ErrorMessage = ERROR_MESSAGE();    
    
  RAISERROR (    
    @ErrorMessage    
    ,16    
    ,1    
    );    
 END CATCH    
    
 DECLARE @rowJson NVARCHAR(MAX) = (    
   SELECT *    
   FROM TBL_ST_SalesTargetSettingMaster(NOLOCK)    
   WHERE SalesTargetId = @SalesTargetId    
   FOR JSON AUTO    
    ,INCLUDE_NULL_VALUES    
   )    
    
 IF @rowJson IS NOT NULL    
 BEGIN    
  EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID    
   ,@Activity_type = 'Inst_SaleTrgt'    
   ,@ActionType = 'I'    
   ,@RowJson = @rowJson    
   ,@Table_name = 'TBL_ST_SalesTargetSettingMaster'    
