/* ============================================================
   Procedure: [dbo].[usp_InsertSchedule]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_InsertSchedule]
    @schedule_name NVARCHAR(100) = NULL,
    @is_daily INT = NULL,
    @dayfreq NVARCHAR(10) = NULL,
    @is_weekly INT = NULL,
    @weekno NVARCHAR(20) = NULL,
    @weekdays NVARCHAR(max) = NULL, -- Increased length to accommodate numbers
    @is_monthly INT = NULL,
    @months NVARCHAR(max) = NULL,
    @monthdates NVARCHAR(100) = NULL,
    @lastmonthday INT = NULL,
    @is_once INT = NULL,
    @recur_int INT = NULL,
    @recur_unit NVARCHAR(10) = NULL,
    @start_time TIME(7) = NULL,
    @end_time TIME(7) = NULL,
    @parentid BIGINT = NULL,
    @createdby BIGINT = NULL,
    @is_active INT = NULL,
    @startdate datetime = NULL,
    @expiry datetime = NULL,
    @defaultDate datetime = NULL,
    @id BIGINT = NULL
AS
BEGIN
    BEGIN TRY
        SET NOCOUNT ON;

        -- Convert weekdays from text to numeric values
        DECLARE @weekdays_numeric NVARCHAR(50);

        -- Replace weekday names with corresponding numbers
        SET @weekdays_numeric = 
            REPLACE(
                REPLACE(
                    REPLACE(
                        REPLACE(
                            REPLACE(
                                REPLACE(
                                    REPLACE(@weekdays, 'Monday', '1'),
                                    'Tuesday', '2'),
                                'Wednesday', '3'),
                            'Thursday', '4'),
                        'Friday', '5'),
                    'Saturday', '6'),
                'Sunday', '7'
            );

        -- Step 1: Check if schedule with the same name exists (excluding the current ID in case of an update)
        IF EXISTS (
            SELECT 1 FROM [dbo].[schedules] nolock
            WHERE schedule_name = NULLIF(@schedule_name, '') 
            AND (@id IS NULL OR id <> @id)
        )
        BEGIN
            SELECT 'Schedule name already exists' AS Result, NULL AS ScheduleID;
            RETURN;
        END

        -- Step 2: Check if updating an existing record
        IF EXISTS (SELECT 1 FROM [dbo].[schedules] nolock WHERE id = @id)
        BEGIN
            -- Update the existing record
            UPDATE [dbo].[schedules]
            SET 
                schedule_name = NULLIF(@schedule_name, ''),
                is_daily = NULLIF(@is_daily, ''),
                dayfreq = NULLIF(@dayfreq, ''),
                is_weekly = NULLIF(@is_weekly, ''),
                weekno = NULLIF(@weekno, ''),
                weekdays = NULLIF(@weekdays_numeric, ''),  -- Insert numeric weekdays
                is_monthly = NULLIF(@is_monthly, ''),
                months = NULLIF(@months, ''),
                monthdates = NULLIF(@monthdates, ''),
                lastmonthday = @lastmonthday,
                is_once = @is_once,
                recur_int = @recur_int,
                recur_unit = NULLIF(@recur_unit, ''),
                start_time = @start_time,
                end_time = @end_time,
                parentid = @parentid,
                createdby = @createdby,
                is_active = ISNULL(@is_active, 1),
                startdate = ISNULL(@startdate, GETDATE()),
                DefaultDate = ISNULL(@defaultDate, GETDATE()),
                expiry = @expiry
            WHERE id = @id;

            -- Return success message
            SELECT 'Updated successfully' AS Result, @id AS ScheduleID;
            RETURN;
        END

        -- Step 3: Insert new record
        INSERT INTO [dbo].[schedules] (
            schedule_name, is_daily, dayfreq, is_weekly, weekno, weekdays, 
            is_monthly, months, monthdates, lastmonthday, is_once, 
            recur_int, recur_unit, start_time, end_time, parentid, 
            createdby, is_active, startdate, expiry, DefaultDate
        ) 
        VALUES (
            NULLIF(@schedule_name, ''), NULLIF(@is_daily, ''), NULLIF(@dayfreq, ''), 
            NULLIF(@is_weekly, ''), NULLIF(@weekno, ''), NULLIF(@weekdays_numeric, ''),  -- Insert numeric weekdays
            NULLIF(@is_monthly, ''), NULLIF(@months, ''), NULLIF(@monthdates, ''), 
            @lastmonthday, @is_once, @recur_int, NULLIF(@recur_unit, ''), 
            @start_time, @end_time, @parentid, @createdby, 
            ISNULL(@is_active, 1), ISNULL(@startdate, GETDATE()), @expiry, ISNULL(@defaultDate, GETDATE())
        );

        -- Return success message
        SELECT 'Save successfully' AS Result, SCOPE_IDENTITY() AS ScheduleID;
    END TRY
    BEGIN CATCH
        -- Handle errors
        EXEC usp_InsertErrorInfo;  
    END CATCH;
END;





GO

