/* ============================================================
   Procedure: [dbo].[USP_InsertServiceError]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[USP_InsertServiceError]            
@ErrorMessage varchar(300),            
@Time varchar(25),            
@ErrorCode varchar(500)            
AS             
BEGIN
declare @id bigint,@lid bigint  
declare @ltime datetime
select @lid=max(id) from ServiceErrorInfoNew(nolock) where ErrorMsg=@ErrorMessage and ErrorCode=@ErrorCode
select @ltime= case when isdate(Time)=1 then Time else DATEADD(mi,-6,getdate()) end from ServiceErrorInfoNew(nolock) where id=@lid

INSERT INTO ServiceErrorInfoNew(ErrorMsg,[Time],ErrorCode)            
VALUES ( @ErrorMessage,GETDATE(),@ErrorCode)            
select @id=SCOPE_IDENTITY()
select @Time=Time from  ServiceErrorInfoNew(nolock) where id=@id

declare @subject nvarchar(200)= 'Error in SMS service '+@errorcode,@body nvarchar(500)=
'Error "' +@errormessage + '" occured in SMS service '+ @errorcode +'. Pl restart the service if the error continues'
if (right(@ErrorCode,5) like '36%' or @ErrorMessage like '4%deadlock%') and DATEDIFF(mi,@ltime,@Time)>5
begin           
EXEC msdb.dbo.sp_send_dbmail      
@profile_name='Alerts',       
@recipients='animesh.@pelsoftlabs.in;sms@pelsoftlabs.in',      
--@blind_copy_recipients='karuna@pelsoftlabs.in',      
@subject=@subject,      
@body = @body,      
@body_format ='HTML'      
end

END 






