Author         : Mukesh     
Created ON     : 25/12/2009 04:30 PM            
Version        : 1      
Alter BY       :              
Alter Date     :    
Location       : PELSOFT      
SP Description : Proc is executing another procedure Named Usp_GetBatchID1  
               ; Proc is inserting records MessageSource  
               : proc is also updating records into MessageQueue    
                                
****************************************************************************/      
CREATE   PROC [dbo].[usp_InsertSingleMessages]--    10000,1,'2134212344' ,'your Login ID Is :ritusss Password Is :22807 URL : www.localhost,' ,'','','websms','','',1                
(                     
@MID BIGINT,                                                                            
@userID INT,   -- frm bigint 19-08-2010                                                                         
@MobNos VARCHAR(max),        
@Message VARCHAR(2500),        
@ScheduleDate VARCHAR(20),                                                                            
@ScheduleTime VARCHAR(20),                                                                    
@SenderId varchar(20)                ,                                                        
@smppID SMALLINT =1,     --THIS CAN BE TINYINT                        -  
@Priority SMALLINT =3,  --THIS CAN BE TINYINT                   
@flg bit=0                 
)                        
As         
begin                   
SET NOCOUNT ON            
DECLARE  @batchID int                        
exec Usp_GetBatchID1 @batchID out         
 DECLARE @MessageID BIGINT                      
 EXEC USP_GetRandomNumbers @MessageID out               
  
 INSERT INTO MessageSource                        
  (MessageID,MessageBatchID,Mobile,[Message],M_ID,U_ID,SenderID,SmppID,ScheduleDate,                      
  ScheduleTime,Priority) values        
(@MessageID,@batchID,@MobNos,@Message,@MID,@userID,@SenderId,@smppID,@ScheduleDate,        
@ScheduleTime,1)        
                  
   INSERT  INTO MessageQueue                      
   ( MessageID,[Message],Mobile,SenderID,SmppID,Priority,U_ID)         
values        
(@MessageID,@Message,@MobNos,@SenderId,@smppID,0,@userID)                     
                    
END                      
     
  


