   Procedure: [dbo].[Usp_InsertsmsinWebform]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE [dbo].[Usp_InsertsmsinWebform]                                                    
(                                  
 @FormId bigint = 0,                                
 @UserID bigint = 0,                                
 @PrentId bigint = 0,                                
 @FilaePath nvarchar (max) = '' ,                                
 @FormName nvarchar (max) = '',  
 @Issms bit  = false,                                
 @SmsAccountName nvarchar (max) = '',    
 @smstemplate bit = 0,                               
 @smstemplateid bigint = 0,                              
 @smsbody nvarchar(max) = '',     
 @IsUniCode bit = false,                               
 @isEnquiry bit  = false,                               
 @CreatedBy bigint = null,
 @SmsSenderid nvarchar(100)                        
)                                                       
                                                        
as                                 
                                
Begin                            
 declare @oldissms bit,@oldismail bit, @oldisenq bit, @oldsmstemplateid bigint,  
  @oldemailtemplateid bigint, @oldSmsCampaignId bigint,@oldEmailCampaignId bigint  
  declare @sourceId bigint=0;                      
  declare @mediumId bigint =0;                      
  declare @SmsCampaignId bigint=0;                      
  declare @emailcampaignid bigint =0;    
    
  select @oldissms =Issms ,@oldismail = Isemail, @oldisenq= isEnquiry,  
  @oldsmstemplateid = smstemplateid, @oldemailtemplateid = emailtemplateid,   
  @oldSmsCampaignId =SmsCampaignId,@oldEmailCampaignId = EmailCampaignId,  
  @sourceId=sourceid, @mediumId=mediumid, @SmsCampaignId =SmsCampaignId,                      
  @emailcampaignid = EmailCampaignId  
  from WebFormTbl  where FormId= @FormId                          
  
 update WebFormTbl set FilePath=@FilaePath ,FormName=@FormName ,          
  SmsAccountName=@SmsAccountName, UserID = @UserID ,         
  Issms=@Issms ,isEnquiry=@isEnquiry ,SenderEmail=@SmsSenderid ,         
  CreatedBy =@CreatedBy, smstemplate = @smstemplate, smstemplateid=@smstemplateid,  
  IsUniCode = @IsUniCode,          
  smsbody = @smsbody  where FormId= @FormId   
  
if @oldisenq = 0 and @isEnquiry = 1  
  begin  
  if @Issms <>0   
   exec [Usp_InsertPreDefinedUserCampaignMaster_NEW]  @PrentId,@PrentId,@FormId,@FormName,  
   @smsbody,@IsUniCode,'','','',@SmsSenderid,1,0,  
   @SmsAccountName, '',@SMStemplateid,0, 'Web Form'   
  end  
 if  @oldisenq = 1 and @isEnquiry = 0  
  begin  
   --if @mediumId > 0                      
   -- update UserMediumSettings set IsActive = 0 where mediumId = @MediumID  
   if @SmsCampaignId > 0                       
    Update UserCampaignMaster set IsActive = 0 where ID = @SmsCampaignId  
     
        
  end       
 if @oldisenq = 1 and @isEnquiry = 1  
  begin  
  if @oldissms =1 and @Issms = 0  
   Update UserCampaignMaster set IsActive = 0 where ID = @SmsCampaignId  
  if @oldissms =0 and @Issms = 1  
   exec [Usp_InsertPreDefinedUserCampaignMaster_NEW]  @PrentId,@PrentId,@FormId,@FormName,  
    @smsbody,@IsUniCode,'','','',@SmsSenderid,1,0,  
    @SmsAccountName, '',@SMStemplateid,0, 'Web Form'   
  if @oldissms =1 and @Issms = 1  
    begin  
    Update UserCampaignMaster set IsEventBased=1,IsScheduled=0,  
    ExclusionsNumber='', Exclusions='',InclusionsNumber='',AccountUsed=@SmsAccountName,  
    [Message]=@smsbody, TemplateID=case   
    when isnull(@smstemplateid,0)<>0 then @smstemplateid else 0 end, TemplateGroupID=0,  
    IsUnicode=@IsUniCode,Medium='SMS', TrackResponse='',TrackShortURL='',  
    UnsubscribePage='',UnsubscribeShortURL='',Tags='',IsRunAfter=0,  
    IsSchedule=0, ScheduleID=0,ExecutedDateTime=GETDATE(),  
    NextExecuteDateTime=GETDATE(),IsActive=1,CreatedOn=GETDATE(),  
    Createdby=@UserID,ModifiedOn=GETDATE(),ModifiedBy=0,StartDate=GETDATE()-1,  
    ExpiryDate=GETDATE(),EventsName='',ApplicabiltyGroupList='',ExclusionsGroupList='',  
    NotificationMail='',SuccessNotificationEmail='',FailureNotificationEmail='',  
    IsRecurring=0, IsEnding=0, TemplateGroupSequence=0, IsNeverExpire=1,  
    RunAtHours='',RunAtMin='',IsSurplusExclusions=0 where ID = @SmsCampaignId  
     
   end  
   end  
    select 'Saved'                               
end  
  


GO

