   Procedure: [dbo].[Usp_InsertSourceAndGetSourceID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
 CREATE   PROC [dbo].[Usp_InsertSourceAndGetSourceID]   
(@Name NVARCHAR(100), @UserID BigINT)          
  AS           
BEGIN  
select @UserID=Parentid from user_detail(nolock) where USER_ID=@UserID
 IF (  
        NOT EXISTS(  
            SELECT 'x'  
            FROM   UserSourceSettings  
            WHERE  NAME           = @Name  
                   AND UserID     = @UserID  
        )  
    )  
 BEGIN  
     INSERT INTO UserSourceSettings  
       (  
         NAME,  
         UserID,  
         IsEditable,  
         IsActive,  
         CreatedDate,  
         ModifiedDate,  
         ModifiedBy  
       )  
     VALUES  
       (  
         @Name,  
         @UserID,  
         1,  
         1,  
         GETDATE(),  
         GETDATE(),  
         @UserID  
       )  
 END  
   
 SELECT SourceID AS sourceID  
 FROM   UserSourceSettings  
 WHERE  NAME           = @Name  
        AND UserID     = @UserID  
END  


GO

/* ============================================================
   Procedure: [dbo].[Usp_InsertSourceDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC dbo.Usp_InsertSourceDetails (      
 @Name NVARCHAR(100)      
 ,@UserID BIGINT      
 ,@IsEditable BIT      
 ,@IsActive BIT      
 ,@CreatedBy NVARCHAR(100)      
 )      
AS      
BEGIN
       select @Name =  replace( replace(replace(trim(char(9) from isnull(@Name,'')),char(9),''),char(10),''),char(13),'')     
declare @parentid bigint=    
 (SELECT Parentid      
 FROM user_detail(NOLOCK)      
 WHERE USER_ID = @userid  )    
      
 IF (      
   NOT EXISTS (      
    SELECT 'x'      
    FROM UserSourceSettings      
    WHERE NAME = @Name      
   AND UserID in (select User_ID  from user_detail(nolock) where parentid=@parentid)    
    )      
   )      
 BEGIN      
  INSERT INTO UserSourceSettings (      
   NAME      
   ,UserID      
   ,IsEditable      
   ,IsActive      
   ,CreatedDate      
   ,ModifiedDate      
   ,ModifiedBy      
   )      
  VALUES (      
    @Name      
   ,@parentid      
   ,@IsEditable      
   ,@IsActive      
   ,GETDATE()      
   ,GETDATE()      
   ,@CreatedBy      
   )      
      
  SELECT 'Record Saved'      
 END      
 ELSE      
 BEGIN    
    IF(      
     EXISTS (      
  SELECT 'x'      
  FROM UserSourceSettings      
  WHERE NAME = @Name      
   AND UserID in (select User_ID  from user_detail(nolock) where parentid=@parentid and IsActive = 0)    
  )      
    )          
     begin  
       update  UserSourceSettings set IsActive = 1  , UserID = @parentid  , ModifiedBy =  @CreatedBy ,ModifiedDate = getdate()  
            WHERE NAME = @Name      
             AND UserID in (select User_ID  from user_detail(nolock) where parentid=@parentid and IsActive = 0)    
  
   SELECT 'Record Saved'      
  
  end  
  else  
   begin  
        SELECT 'Already Exist'      
      end  
    --SELECT 'Already Exist'      
 END      
      
 DECLARE @rowJson NVARCHAR(MAX) = (      
   SELECT *      
   FROM UserSourceSettings(NOLOCK)      
   WHERE UserID = @UserID and NAME = @Name      
   FOR JSON AUTO      
    ,INCLUDE_NULL_VALUES      
   )      
      
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID      
  ,@Activity_type = 'Inst_Srce_sttng'      
  ,@ActionType = 'I'      
  ,@RowJson = @rowJson      
  ,@Table_name = 'UserSourceSettings'      
END 


GO

