   Procedure: [dbo].[usp_InsertSuperResellerCreditDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_InsertSuperResellerCreditDetails    
(    
    
@FromUserID int,    
@ToUserID int,    
@Credits  bigint,    
@Debits bigint    
    
)    
as    
Begin    
Declare @SMSBalance bigint = 0;    
Declare @MID bigint = 0;    
    
select @MID = isnull(m_id,0) from User_Detail where [user_id]=@ToUserID      
     
select top 1 @SMSBalance = isnull(Balance,0) from SuperResellerCredit_Details where USER_ID = @ToUserID order by Credit_ID     desc     
    
set @SMSBalance = @SMSBalance + @Credits    
set @SMSBalance = @SMSBalance - @Debits    
    
if(@Credits>0)  
 Begin     
  insert into SuperResellerCredit_Details(      
  M_ID,FromUser_ID,User_ID,Debits,Credits,Balance,Validity,FromDate,ToDate,DateCreated,DateUpdated,   EmpUpdated,LastModified      
  )values(@MID,@FromUserID,@ToUserID,@Debits,@Credits,@SMSBalance,0,GETDATE(),GETDATE(),GETDATE(),GETDATE(),GETDATE(),GETDATE())      
     
  select 'Success'      
 end   
    
  if(@Debits>0)  
    Begin  
        if(@Debits<=@SMSBalance)   
          Begin  
    insert into SuperResellerCredit_Details(      
  M_ID,FromUser_ID,User_ID,Debits,Credits,Balance,Validity,FromDate,ToDate,DateCreated,DateUpdated,   EmpUpdated,LastModified      
  )values(@MID,@FromUserID,@ToUserID,@Debits,@Credits,@SMSBalance,0,GETDATE(),GETDATE(),GETDATE(),GETDATE(),GETDATE(),GETDATE())      
     
  select 'Success'  
              
            End   
         else  
            Begin  
               select 'Balance is not sufficient.'  
            End     
    End  
    
    
End








   

















GO

