   Procedure: [dbo].[Usp_InsertToAddCreditDetails_NewwithRefno]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

            
            
/**************************                        
Created by : Santosh Kumar                        
Date : 06-05-2017 2:07 PM                        
                            
This SP is Used for Insert Detail when Agent Insert Credit                             
************************/                            
CREATE   PROC [dbo].[Usp_InsertToAddCreditDetails_NewwithRefno]                            
(                         
@UserID INT,                            
@AccountType nvarchar(50),                            
@Validity nvarchar(50),                            
@Amount numeric(18,2),                            
@Credits bigint,                        
@DNDRefundType nvarchar(50),                            
@FilterMode nvarchar(50),                        
@Reason nvarchar(50),                        
@Remarks nvarchar(300),                        
@CreditAgentID bigint,                        
@PricePerSMS numeric(18,2),                             
@Paymode nvarchar(50),                        
@TransactionID nvarchar(50),                      
@IsSMS bit,                      
@IsMail bit,                
@RefNo bigint,                
@InvoiceName nvarchar(200)                
                        
                            
)                            
AS                            
Begin                 
        declare @IntReseller tinyint = 0        
               
    if(@IsSMS= 0 and @IsMail = 0)      
    Begin      
       set  @IntReseller = 1      
    End        
                  
 CREATE TABLE #TempLinked                              
    (                              
      Result VARCHAR(200)                              
    )                
              
              
 declare  @AddCreditID bigint = 0 ;                
 declare @LinkedStatusOfServer nvarchar(200) = '';                       
set @AccountType=(select userfilter from user_detail (NOLOCK) where USER_ID=@UserID)                        
Insert into AddCreditDetails(UserID,AccountType,Validity,Amount,Credits,DNDRefundType,FilterMode,Reason,Remarks,    
CreditAgentID,PricePerSMS,PayMode,TransactionID,CreatedDate,IsSMS,IsMail,IntCredit)values(@UserID,@AccountType,@Validity,@Amount,@Credits,@DNDRefundType,      
                
@FilterMode,@Reason,@Remarks,@CreditAgentID,@PricePerSMS,@Paymode,@TransactionID,GETDATE(),@IsSMS,@IsMail,@IntReseller)                 
                
 select @AddCreditID = SCOPE_IDENTITY()                
 if(@RefNo <> 0 )                
   Begin   
    INSERT INTO #TempLinked                              
     EXEC GetStatusofLinkedServer 'CRM'                              
     IF NOT EXISTS(                              
        SELECT 'x'                              
        FROM   #TempLinked                              
    )                   
    begin              
  update CRM.CRMDB.dbo.LinkedAccount set RefrenceNo = @RefNo ,Verified = 1 where User_ID = @UserID              
  
  update MYSMS.dbo.LinkedAccount set RefrenceNo = @RefNo ,Verified = 1 where User_ID = @UserID              
    end              
 else              
  Begin              
                  
    insert into  Account_Info_Mid_Level              
    (UserLogin,RefNo,IsProcessed,CreatedDate)                 
    values(@UserID,@RefNo,0,GETDATE())              
              
  End              
              
              
  -- select  @LinkedStatusOfServer = isnull((EXEC GetStatusofLinkedServer '172.16.4.30\R2'),'')--'CRM'              
                       
   End                
                 
  if(@InvoiceName <> '')              
    begin              
    insert into Invoice_Info_with_AddCredit              
    (              
    [InvoiceName]              
      ,[RefNo]              
      ,[UserLogin]              
      ,[NoOfCredit]              
      ,[Reason]              
      ,[Add_CreditID]              
      ,[Remarks]              
      ,[UserID]              
      ,[Datetime])              
   values              
   (         
    @InvoiceName + '.pdf',              
    @RefNo,              
    @UserID,              
    @Credits,              
    @Reason,              
    @AddCreditID,              
    @Remarks,              
    335,              
    getdate()              
   )              
                 
                  
 End          
 else          
    Begin          
    insert into Invoice_Info_with_AddCredit              
    (              
    [InvoiceName]              
      ,[RefNo]              
      ,[UserLogin]              
      ,[NoOfCredit]              
      ,[Reason]              
      ,[Add_CreditID]              
      ,[Remarks]              
      ,[UserID]              
      ,[Datetime])              
   values              
   (              
    '',              
    @RefNo,              
    @UserID,              
    @Credits,              
    @Reason,              
    @AddCreditID,             
    @Remarks,              
    335,              
    getdate()              
   )          
                  
  End          
               
              
                
drop table #TempLinked;              
                           
select 'Record Inserted'              
              
                            
End 


