/* ============================================================
   Procedure: [dbo].[Usp_InsertToAddCreditDetailsR190318]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/**************************        
Created by : Santosh Kumar        
Date : 06-05-2017 2:07 PM        
            
This SP is Used for Insert Detail when Agent Insert Credit             
************************/            
CREATE   PROC [dbo].[Usp_InsertToAddCreditDetailsR190318]            
(         
@UserID INT,            
@AccountType nvarchar(50),            
@Validity nvarchar(50),            
@Amount numeric(18,2),            
@Credits bigint,        
@DNDRefundType nvarchar(50),            
@FilterMode nvarchar(50),        
@Reason nvarchar(50),        
@Remarks nvarchar(300),        
@CreditAgentID bigint,        
@PricePerSMS numeric(18,2),             
@Paymode nvarchar(50),        
@TransactionID nvarchar(50),      
@IsSMS bit,      
@IsMail bit        
            
)            
AS            
Begin       
set @AccountType=(select userfilter from user_detail where USER_ID=@UserID)  
declare @referrerid bigint,@referredContactid bigint,@SERVICE varchar(30) =(select case when @issms=1 then 'SMS' when @ismail=1 then 'Mails' else 'Subscriptions' end)          
if not exists(select 1 from AddCreditDetails where UserID=@UserID and Reason='Purchase')  
begin  
select @referrerid=isnull(referrerid,0),@referredContactid=ISNULL(referredcontactid,0) from user_detail where user_id=@userid   
end  
Insert into AddCreditDetails(UserID,AccountType,Validity,Amount,Credits,DNDRefundType,FilterMode,Reason,Remarks,CreditAgentID,PricePerSMS,PayMode,TransactionID,CreatedDate,IsSMS,IsMail)values(@UserID,@AccountType,@Validity,@Amount,@Credits,@DNDRefundType,
  
@FilterMode,@Reason,@Remarks,@CreditAgentID,@PricePerSMS,@Paymode,@TransactionID,GETDATE(),@IsSMS,@IsMail)            
  
if isnull(@referrerid,0)<>0  
begin  
update ReferredContacts set ConversionStatus=1,Conversiondate=GETDATE(),ConversionAmount=@amount,PayoutEligible=0 where ID=@referredcontactid  
declare @commissionid int=isnull((select ID from Referrer_Payout_Rates where Servicereferred=@SERVICE and status=1 and getdate() between validfrom and validtill),0)  
declare @minimumamount numeric(18,2) = isnull((select MinimumOrderAmount from Referrer_Payout_Rates where ID=@commissionid),0) 
  
if isnull(@commissionid,0)<>0  and isnull(@minimumamount,0)>=@Amount  
begin  
declare @isamount int=(select isamount from Referrer_Payout_Rates where ID=@commissionid)  
declare @commissionamount numeric(18,2)=(select case when isamount=1 then CommissionAmount else (CommissionPercent*@Amount/100) end from Referrer_Payout_Rates where ID=@commissionid)  
insert into PayoutTracking(Referrerid,Commissionid,ReferredContactId,CommissionAmount,DateCreated,Status)  
select @referrerid,@commissionid,@referredContactid,@commissionamount,GETDATE(),'Payout Tracked'  
exec usp_UpdateUserActivity @referrerid,'PayoutTracked',0  
end  
end  
  
  
  
  
select 'Record Inserted'            
End 


GO

/* ============================================================
   Procedure: [dbo].[USP_InsertTop_ButtomFiveInQue_Cond3]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
  
  
/**************************************************************************************                    
*******************************                    
                    
SP_Name        : USP_InsertTop_ButtomFiveInQue_Cond3                                       
Author         : Pawan                     
Created ON     : 14/01/2009 04:30 PM                          
Version        : 1                    
Alter by       :                           
Alter Date    :                      
Location       : PelSoftLab                    
SP Description : This SP is Used to Select Records From ProcessTableFirst                      
               : This Sp is also Used to Insert Records Into MessageQueue by                    
                 Selecting Records From ProcessTableFirst.and also Executng                    
                 Another Procedure Which is Deleting Records From ProcessTableFirst                    
                 ProcessTableTwo,ProcessTableThree,ProcessTablefour Based On various                    
                 condition.                    
                                     
               : This SP is also Used to Select Records From ProcessTableTwo                      
               : This Sp is also Used to Insert Records Into MessageQueue by                     
                 Selecting Records From ProcessTableTwo And Also Deletes records From                     
                 ProcessTableTwo.                    
                                     
               : This SP is also Used to Select Records From ProcessTableThree                      
               : This Sp is also Used to Insert Records Into MessageQueue by                     
                 Selecting Records From ProcessTableThree And Also Deleting Records From                    
                 ProcessTableThree                    
                                     
               : This SP is also Used to Select Records From ProcessTableFour                      
               : This Sp is also Used to Insert Records Into MessageQueue by                     
                 Selecting Records From ProcessTableThree And Also Deleting Records From                    
                 ProcessTableFour                    
                                              
*********************************************************************************                    
**************************************/                     
CREATE   PROC [dbo].[USP_InsertTop_ButtomFiveInQue_Cond3]                      
@BatchID BIGINT,     -- frm int 19-08-2010  
@Priority TINYINT,                      
@ProcessTable int                      
AS                      
BEGIN                      
                      
DECLARE @Total INT                      
begin try   
begin  transaction                       
IF (@ProcessTable = 1)                      
BEGIN                      
 SELECT @Total = count(*) FROM ProcessTableFirst WHERE BatchID = @BatchID                       
 IF (@Total > 5)                      
 BEGIN                      
     With CTETemp                      
     AS                      
     (                      
         SELECT ProcessID ,ROW_NUMBER() OVER (Order BY ProcessID) as TopFive,ROW_NUMBER() OVER (Order BY ProcessID Desc) as BottomFive                      
         FROM   ProcessTableFirst                      
         WHERE BatchID = @BatchID AND Operator <> 'AD'                     
      )                      
                      
         INSERT INTO MessageQueue(MessageID, Mobile,[Message],SenderID, SmppID, U_ID, Priority,IsUniCode,IsDND,Operator,BatchID,Isallowdnd)                      
         SELECT MessageID,Mobile,[Message],SenderID,SmppID,U_ID, @Priority ,IsUniCode,IsDND,Operator,@BatchID,Isallowdnd                      
         FROM ProcessTableFirst WHERE ProcessID IN ( Select ProcessID From CTETemp Where TopFive <= 3 or BottomFive <= 2)                      
                      
         EXEC USP_DeleteTop_ButtomFiveInQue_Cond3 @BatchID,@ProcessTable                      
  END                      
  ELSE                       
  BEGIN        
         INSERT INTO MessageQueue(MessageID, Mobile,[Message],SenderID, SmppID, U_ID, Priority,IsUniCode,IsDND,Operator,BatchID,Isallowdnd)                      
         SELECT MessageID,Mobile,[Message],SenderID,SmppID,U_ID, @Priority ,IsUniCode,IsDND,Operator,@BatchID,Isallowdnd                      
         FROM ProcessTableFirst WHERE BatchID = @BatchID  --AND Operator =0  --\* Updated by Shekhar 060110 11:03 AM                    
        -- modified by vinay 08-02-2010 5:13 pm              
--         INSERT INTO MessageQueueAirtel(MessageID, Mobile,[Message],SenderID, SmppID, U_ID, Priority,IsUniCode,IsDND,Operator,BatchID,Isallowdnd)                      
--         SELECT MessageID,Mobile,[Message],SenderID,SmppID,U_ID, @Priority ,IsUniCode,IsDND,Operator,@BatchID,Isallowdnd                      
--         FROM ProcessTableFirst WHERE BatchID = @BatchID  AND Operator =1              
              
         DELETE FROM ProcessTableFirst WHERE BatchID = @BatchID --AND Operator =0  \* Updated by Shekhar 060110 11:03 AM                    
  END                      
END                      
ELSE IF (@ProcessTable = 2)                      
BEGIN                      
 SELECT @Total = count(*) FROM ProcessTableTwo WHERE BatchID = @BatchID                      
 IF (@Total > 5)                      
 BEGIN                      
     WITH CTETemp                      
     AS                      
     (                      
         SELECT ProcessID ,ROW_NUMBER() OVER (ORDER BY ProcessID) AS TopFive ,ROW_NUMBER() OVER (ORDER BY ProcessID Desc) AS BottomFive                      
         FROM   ProcessTableTwo                      
