/* ============================================================
   Procedure: [dbo].[Usp_InsertTriggerCampaign]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_InsertTriggerCampaign]
(
    @Cname              NVARCHAR(100),
    @EventID            INT,
    @Audience           NVARCHAR(MAX),
    @UserID             BIGINT,
    @datefield          NVARCHAR(100) = NULL,
    @datefieldtype      VARCHAR(20)   = NULL,
    @dateformattomatch  VARCHAR(50)   = NULL,
    @tc_timeafterevent  INT           = NULL,
    @tc_timeunit        VARCHAR(20)   = NULL,
    @fixedtime          TIME          = NULL
)
AS
BEGIN
    DECLARE @ParenID BIGINT = 0;

    SELECT TOP 1 @ParenID = ISNULL(ParentID, User_ID)
    FROM User_Detail (NOLOCK)
    WHERE User_ID = @UserID;

    IF NOT EXISTS (
        SELECT 1
        FROM triggeredcampaigns (NOLOCK)
        WHERE cname = @Cname AND parentid = @ParenID
    )
    BEGIN
        INSERT INTO triggeredcampaigns
        (cname, eventid, parentid, isactive, createdon, createdby, Audience,
         datefield, datefieldtype, dateformattomatch, tc_timeafterevent, tc_timeunit,
         fixedtime)
        VALUES (@Cname, @EventID, @ParenID, 1, GETDATE(), @UserID, @Audience,
                @datefield, @datefieldtype, @dateformattomatch, @tc_timeafterevent, @tc_timeunit,
                @fixedtime);

        SELECT 'Trigger Campaign Saved';
    END
    ELSE
    BEGIN
        SELECT 'Trigger Campaign Name Already Exists';
    END
END


GO

