   Procedure: [dbo].[Usp_InsertUnsubscribeDetailsToSearchDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


/*      
  Created By : Santosh Kumar      
  Created Date: 05/06/2017 05:44 PM      
  SP For : Insertion for Unsubscribe Details      
  Alter By:      
  Alter Date:       
        
*/      
CREATE   PROC [dbo].[Usp_InsertUnsubscribeDetailsToSearchDetails] 
(
    @SearchName NVARCHAR(250),
    @PhoneNumber NVARCHAR(MAX),
    @FromDate NVARCHAR(100),
    @ToDate NVARCHAR(100),
    @IsActive BIT,
    @CRMUnsubscribeType NVARCHAR(3),
    @CreatedBy BIGINT
)      
AS       
BEGIN
	INSERT INTO SearchDetails
	  (
	    SearchName,
	    IsCRMDB,
	    IsUnsubscribe,
	    PhoneNumber,
	    FromDate,
	    ToDate,
	    IsActive,
	    CRMUnsubscribeType,
	    CreatedDate,
	    CreatedBy,
	    ModifiedDate,
	    ModifiedBy
	  )
	VALUES
	  (
	    @SearchName,
	    1,
	    1,
	    @PhoneNumber,
	    @FromDate,
	    @ToDate,
	    @IsActive,
	    @CRMUnsubscribeType,
	    GETDATE(),
	    @CreatedBy,
	    GETDATE(),
	    @CreatedBy
	  )       
	
	SELECT 'Record Inserted'
END 



