AS    
BEGIN  
if exists(select ID from UnSubscribeUserWebForms where WebFormName=@WebFormName and ParentID=@ParentID)  
begin  
update UnSubscribeUserWebForms set status=@status where WebFormName=@WebFormName and ParentID=@ParentID 
 SELECT 'Success'   
end  
else  
begin    
 INSERT INTO UnSubscribeUserWebForms    
   (    
     WebFormName,    
     ParentID,    
     status    
   )    
 VALUES    
   (    
     @WebFormName,    
     @ParentID,    
     @status    
   )    
     
 SELECT 'Success'    
 end  
END 



GO

/* ============================================================
   Procedure: [dbo].[usp_InsertUpdateBannerSetting]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE [dbo].[usp_InsertUpdateBannerSetting](  
    @User_ID bigint,  
    @SettingJson nvarchar(Max)  
)  
AS  
BEGIN  

--declare  @User_ID  bigint  =335, @SettingJson  nvarchar(max) =N'{"Id":0,"BannerName":"satya created bannner_2025021720354355408","Content":"","BannerType":"","BannerBg":"#000000","DismissOption":true,"IsActive":true,"BannerBehaviour":"showalltime","Disappearafter":"","DisappearafterUnit":"","DisplayTimer":true,"UserSegments":""}'

    DECLARE @M_ID nvarchar(12), @Id bigint, @BannerName nvarchar(255), @Contents nvarchar(Max), @BannerType nvarchar(50), @DismissOption bit, @BannerBg nvarchar(500), @ParentId bigint , @BannerBehaviour nvarchar(500), @DisappearTime nvarchar(500), @UserSegment nvarchar(500)
, @DisappearTimeUnit nvarchar(100), @DisplayTime bit , @IsActive bit ,@errMsg nvarchar(500)='',@successMsg nvarchar(500)=''
    

	
	--activity vars
	Declare @InsertedId int =0;
	DECLARE @UserName varchar(255), @PartnerUserName varchar(255) , @ChildPartnerName varchar(255);
	Declare @Eventdata varchar(max);
	---activity vars

   select @ParentId=ParentID,@M_ID=M_ID from User_Detail where user_id=@User_ID  
    SET @Id = JSON_VALUE(@SettingJson, '$.Id');  
    SET @BannerName = JSON_VALUE(@SettingJson, '$.BannerName');  
    SET @Contents = JSON_VALUE(@SettingJson, '$.Content');  
    SET @BannerType = JSON_VALUE(@SettingJson, '$.BannerType');  
    SET @DismissOption = JSON_VALUE(@SettingJson, '$.DismissOption');  
	 SET @BannerBg = JSON_VALUE(@SettingJson, '$.BannerBg');  
	 SET @BannerBehaviour = JSON_VALUE(@SettingJson, '$.BannerBehaviour');  
	 SET @DisappearTime = JSON_VALUE(@SettingJson, '$.Disappearafter');  
	 SET @DisappearTimeUnit = JSON_VALUE(@SettingJson, '$.DisappearafterUnit');  
	 SET @DisplayTime = JSON_VALUE(@SettingJson, '$.DisplayTimer'); 
	Set @UserSegment= JSON_VALUE(@SettingJson, '$.UserSegments'); 
  if exists(select 1 from tbl_banner_details(nolock) where bannerName=@BannerName and @id=0)
  begin
  set @errMsg= (select ' Banner Name is already exists.')
  select @successMsg  as messagetext, @errMsg  as errmessage
  return 
  end
  if exists(select 1 from tbl_banner_details(nolock) where DisappearTime=@DisappearTime and DisappearTimeUnit=@DisappearTimeUnit and LastModifiedDate=getdate() and isactive=1)
  begin
   set @errMsg=(select ' Disappear Time is already exists.')
   select @successMsg  as messagetext, @errMsg  as errmessage
  return 
  end
	 if(@DismissOption=1)  
	 begin  
	  UPDATE tbl_Banner_Details set Isactive=0 where  parentId=@parentId  
	 end 
		IF (@Id > 0)  
		BEGIN  
			UPDATE tbl_Banner_Details  
			SET BannerName = @BannerName, BannerBackground=@BannerBg, LastModifiedDate = GETDATE(), Contents = @Contents, DismissOption=@DismissOption, DisappearTime=@DisappearTime, DisappearTimeUnit=@DisappearTimeUnit, BannerBehaviour=@BannerBehaviour , IsActive=1,UserSegment=@UserSegment  
  
			WHERE Id = @Id;  
			set @successMsg=(select ' Update data Successfully')

				-----  activity start   -----
						
			select @UserName = User_login from User_Detail with(nolock) where User_ID = @User_ID;
			select @PartnerUserName = User_login from User_Detail with(nolock) where User_ID = @M_Id;
			select @ChildPartnerName = User_login from User_Detail with(nolock) where User_ID = @ParentId;
			SET @Eventdata = '{"#partnername#":"'+ @UserName +'","#bannername#":"'+@BannerName+'"}';
			---select * from ActivityMaster  where EventName like '%partner%' 
			--#partnername# created a banner named #bannername#
			exec usp_pm_PartnerActivity  @ParentId, @ParentId,@User_ID, 'Partner Created Banner',@Eventdata, 'tbl_Banner_Details',@Id;

			----- activity end  ---

		END  
		ELSE  
		BEGIN  
			INSERT INTO tbl_Banner_Details (M_Id, ParentId, UserId, BannerName, BannerBackground, Contents, BannerType, DismissOption, LastModifiedDate, CreatedBy, BannerBehaviour, DisappearTime, DisappearTimeUnit, IsActive, DisplayTime,UserSegment)  
			VALUES (@M_Id, @ParentId, @User_ID, @BannerName, @BannerBg, @Contents, @BannerType, @DismissOption, getdate(), @User_ID, @BannerBehaviour, @DisappearTime, @DisappearTimeUnit, 1, @DisplayTime,@UserSegment); 

			set @InsertedId = SCOPE_IDENTITY();

			set @successMsg=(select ' Save data Successfully')


			
				-----  Activity Start   -----

				-- Assign values properly
				SELECT @UserName = User_login FROM User_Detail WHERE User_ID = @ParentId;
				SELECT @PartnerUserName = User_login FROM User_Detail WHERE User_ID = @ParentId;
				SELECT @ChildPartnerName = User_login FROM User_Detail WHERE User_ID = @User_ID;

				-- Handle NULL values and ensure proper concatenation for JSON
				SET @UserName = ISNULL(@UserName, '');
				SET @BannerName = ISNULL(@BannerName, '');

				SET @Eventdata = '{"#partnername#":"' + @UserName + '","#bannername#":"' + @BannerName + '"}';

				-- Execute stored procedure
				EXEC usp_pm_PartnerActivity  
					@ParentId, 
					@ParentId, 
					@User_ID, 
					'Partner Created Banner', 
					@Eventdata, 
					'tbl_Banner_Details', 
					@InsertedId;
			----- activity end  ---


		END  

select @successMsg  as messagetext, @errMsg  as errmessage
END; 





GO

/* ============================================================
   Procedure: [dbo].[usp_InsertUpdateLeadDocuments]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC dbo.usp_InsertUpdateLeadDocuments (    
 @DocUpID INT    
 ,@ParentID INT    
 ,@UserID INT    
 ,@LeadID INT    
 ,@DocumentName VARCHAR(500)    
 ,@FileType VARCHAR(11)    
 ,@FileLocation VARCHAR(500)    
 ,@IPAddress VARCHAR(50)    
 )    
AS    
BEGIN    
 DECLARE @EventDesc INT    
 DECLARE @EventDescrip VARCHAR(50)    
    
 IF @DocUpID = 0    
 BEGIN    
  DECLARE @docid BIGINT    
    
  INSERT INTO tbl_LeadDocumentUpload (    
   ParentID    
   ,UserID    
   ,LeadID    
   ,DocumentName    
   ,FileType    
   ,FileLocation    
   ,UploadedDate    
   ,ISDeleted    
   )    
  VALUES (    
   @ParentID    
   ,@UserID    
   ,@LeadID    
   ,@DocumentName    
   ,@FileType    
   ,@FileLocation    
   ,GETDATE()    
   ,0    
   )    
    
  SELECT @docid = SCOPE_IDENTITY()    
    
  SET @EventDesc = 0    
 END    
    
 /*         
IF @DocUpID>0        
  BEGIN        
  UPDATE tbl_LeadDocumentUpload SET DocumentName=@DocumentName,FileType=@FileType,FileLocation=@FileLocation,UpdatedDate=GETDATE()        
    WHERE ParentID=@ParentID and UserID=@UserID and LeadID=@LeadID        
 --select @docid=SCOPE_IDENTITY()     
        
   set @EventDesc=1        
  END        
        
  if @EventDesc=0        
  set @EventDescrip='Document Inserted'        
          
  if @EventDesc=1        
  set @EventDescrip='Document Updated'        
        
  INSERT INTO tbl_LeadEventHistory(ParentID,UserID,LeadID,EventDescription,EventDate,IPAddress)     
  Values(@ParentID,@UserID,@LeadID,@EventDescrip,GETDATE(),@IPAddress)        
  */    
 /*start lead activity   Doc uploaded */    
 BEGIN TRY    
  DECLARE @UserID_LDACTV BIGINT = @UserID    
  DECLARE @DocName_LDACTV NVARCHAR(500) = @DocumentName    
  DECLARE @evntMessage NVARCHAR(max) = ''    
  DECLARE @ParentID_LDACTV BIGINT = @ParentID    
  DECLARE @LeadID_LDACTV BIGINT = @LeadID    
    
  CREATE TABLE #tblEventDescrb (EVNT_Description NVARCHAR(max))    
    
  IF (isnull(@LeadID_LDACTV, 0) > 0)    
  BEGIN    
   INSERT INTO #tblEventDescrb    
   EXEC Usp_EventTemplate_DynamicVarReplacement 'Doc uploaded'    
    ,@UserID_LDACTV    
    ,''    
    ,''    
    ,0    
    ,''    
    ,NULL    
    ,0    
    ,0    
    ,''    
    ,''    
    ,0    
    ,''    
    ,0    
    ,NULL    
    ,NULL    
    ,NULL    
    ,NULL    
    ,NULL    
    ,NULL    
    ,NULL    
    ,NULL    
    ,NULL    
    ,NULL    
    ,NULL    
    ,NULL    
    ,NULL    
    ,NULL    
    ,NULL    
    ,NULL    
    ,NULL    
    ,0    
    ,0    
    ,0    
    ,NULL    
    ,NULL    
    ,NULL    
    ,0    
    ,NULL    
    ,NULL    
    ,NULL    
    ,0    
    ,@DocName_LDACTV    
    ,NULL    
    
   SELECT @evntMessage = isnull(EVNT_Description, '')    
   FROM #tblEventDescrb    
    
   SELECT @evntMessage    
    
   IF (@evntMessage <> '')    
   BEGIN    
    EXEC UspSaveLeadActivity_withid @LeadID_LDACTV    
     ,@UserID_LDACTV    
     ,@ParentID_LDACTV    
     ,@evntMessage    
     ,'Doc uploaded'    
     ,'tbl_LeadDocumentUpload'    
     ,@docid    
   END    
  END    
 END TRY    
    
 BEGIN CATCH    
  EXEC usp_insertErrorInfo    
 END CATCH    
    
 IF OBJECT_ID('tempdb..#tblEventDescrb') IS NOT NULL -- Check for table existence        
 BEGIN    
  DROP TABLE #tblEventDescrb    
 END    
    
 /* End Lead activity */    
 DECLARE @rowJson NVARCHAR(MAX) = (    
    SELECT *
   FROM tbl_LeadDocumentUpload(NOLOCK)    
   WHERE DocUpID = @docid    
   FOR JSON AUTO    
    ,INCLUDE_NULL_VALUES    
   )    
    
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID    
  ,@Activity_type = 'Inst_Docu_Lead'    
  ,@ActionType = 'I'    
  ,@RowJson = @rowJson    
  ,@Table_name = 'tbl_LeadDocumentUpload'    
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_InsertUpdateLeadNotes]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_InsertUpdateLeadNotes (    
 @HistoryID INT = 0    
 ,@ParentID BIGINT = 0    
 ,@UserID BIGINT    
 ,@LeadID BIGINT    
 ,@Notes TEXT    
 ,@IPAddress VARCHAR(50) = ''    
 )    
AS    
BEGIN    
 IF (@UserID = 0)    
 BEGIN    
  SELECT @UserID = AssignedTo    
  FROM UserLeads(NOLOCK)    
  WHERE ID = @LeadID    
 END    
    
 IF (@ParentID = 0)    
 BEGIN    
  SELECT @ParentID = ParentID    
  FROM User_Detail(NOLOCK)    
  WHERE User_ID = @UserID    
 END    
    
 DECLARE @EventDesc INT    
 DECLARE @EventDescrip VARCHAR(50)    
    
 IF @HistoryID = 0    
 BEGIN    
  DECLARE @nid BIGINT    
    
  INSERT INTO tbl_LeadNotes (    
   ParentID    
   ,UserID    
   ,LeadID    
   ,Notes    
   ,CreatedDate    
   ,UpdatedDate    
   ,ISDeleted    
   )    
  VALUES (    
   @ParentID    
   ,@UserID    
   ,@LeadID    
   ,@Notes    
   ,GETDATE()    
   ,GETDATE()    
   ,0    
   )    
    
  SELECT @nid = SCOPE_IDENTITY()    
    
  SELECT 'Notes Inserted' AS MSG    
   ,@nid AS NoteId    
    
  SET @EventDesc = 0    
 END    
    
 IF @HistoryID > 0    
 BEGIN    
  UPDATE tbl_LeadNotes    
  SET Notes = @Notes    
   ,UpdatedDate = GETDATE()    
  WHERE ParentID = @ParentID    
   AND UserID = @UserID    
   AND LeadID = @LeadID    
   AND NoteID = @HistoryID    
    
  SELECT @nid = @HistoryID    
    
  SET @EventDesc = 1    
 END    
    
 IF @EventDesc = 0    
  SET @EventDescrip = 'Notes Inserted'    
    
 IF @EventDesc = 1    
  SET @EventDescrip = 'Notes Updated'    
    
 /*                
  INSERT INTO tbl_LeadEventHistory(ParentID,UserID,LeadID,EventDescription,EventDate,IPAddress) Values(@ParentID,@UserID,@LeadID,@EventDescrip,GETDATE(),@IPAddress)                  
  */    
 SELECT @EventDescrip AS Msg    
  ,1 AS Id    
    
 IF (@EventDescrip = 'Notes Inserted')    
 BEGIN    
  /* Start lead activity Add Notes  */    
  BEGIN TRY    
   DECLARE @UserID_LDACTV BIGINT = @UserID    
   DECLARE @evntMessage NVARCHAR(max) = ''    
   DECLARE @ParentID_LDACTV BIGINT = @ParentID    
   DECLARE @LeadID_LDACTV BIGINT = @LeadID    
    
   CREATE TABLE #tblEventDescrb (EVNT_Description NVARCHAR(max))    
    
   IF (isnull(@LeadID_LDACTV, 0) > 0)    
   BEGIN    
    INSERT INTO #tblEventDescrb    
    EXEC Usp_EventTemplate_DynamicVarReplacement 'Notes added'    
     ,@UserID_LDACTV    
     ,''    
     ,''    
     ,0    
     ,''    
     ,NULL    
     ,0    
     ,0    
     ,''    
     ,''    
     ,0    
     ,''    
     ,0    
     ,NULL    
     ,NULL    
     ,NULL    
     ,NULL    
     ,NULL    
     ,NULL    
     ,NULL    
     ,NULL    
     ,NULL    
     ,NULL    
     ,NULL    
     ,NULL    
     ,NULL    
     ,NULL    
     ,NULL    
     ,NULL    
     ,NULL    
     ,0    
     ,0    
     ,0    
     ,NULL    
     ,NULL    
     ,NULL    
     ,0    
     ,NULL    
     ,NULL    
     ,NULL    
     ,0    
     ,NULL    
     ,NULL    
    
    SELECT @evntMessage = isnull(EVNT_Description, '')    
    FROM #tblEventDescrb    
    
    SELECT @evntMessage    
    
    IF (@evntMessage <> '')    
    BEGIN    
     EXEC UspSaveLeadActivity_withid @LeadID_LDACTV    
      ,@UserID_LDACTV    
      ,@ParentID_LDACTV    
      ,@evntMessage    
      ,'Notes added'    
      ,'tbl_LeadNotes'    
      ,@nid    
    END    
   END    
  END TRY    
    
  BEGIN CATCH    
   EXEC usp_InsertErrorInfo    
  END CATCH    
    
  IF OBJECT_ID('tempdb..#tblEventDescrb') IS NOT NULL -- Check for table existence              
  BEGIN    
   DROP TABLE #tblEventDescrb    
  END    
    /* End lead activity Add Notes  */    
 END    
    
 IF (@EventDescrip = 'Notes Updated')    
 BEGIN    
  /* Start lead activity  Edit Notes */    
  BEGIN TRY    
   DECLARE @UserID_LDACTV_1 BIGINT = @UserID    
   DECLARE @evntMessage_1 NVARCHAR(max) = ''    
   DECLARE @NotesID_LDACTV_1 INT = 99    
   DECLARE @CreatedOn_LDACTV_1 NVARCHAR(50) = ''    
   DECLARE @ParentID_LDACTV_1 BIGINT = @ParentID    
   DECLARE @LeadID_LDACTV_1 BIGINT = @LeadID    
    
   SELECT TOP 1 @CreatedOn_LDACTV_1 = isnull(CreatedDate, GETDATE())    
   FROM tbl_LeadNotes --where  NoteID = @NotesID_LDACTV_1            
   WHERE ParentID = @ParentID_LDACTV_1    
    AND UserID = @UserID_LDACTV_1    
    AND LeadID = @LeadID_LDACTV_1    
   ORDER BY NoteID DESC    
    
   CREATE TABLE #tblEventDescrb_1 (EVNT_Description NVARCHAR(max))    
    
   IF (isnull(@LeadID_LDACTV_1, 0) > 0)    
   BEGIN    
    INSERT INTO #tblEventDescrb_1    
    EXEC Usp_EventTemplate_DynamicVarReplacement 'Notes edited'    
     ,@UserID_LDACTV_1    
     ,''    
     ,''    
     ,0    
     ,''    
     ,NULL    
     ,0    
     ,0    
     ,''    
     ,''    
     ,0    
     ,''    
     ,0    
     ,NULL    
     ,NULL    
     ,NULL    
     ,NULL    
     ,NULL    
     ,NULL    
     ,NULL    
     ,NULL    
     ,NULL    
     ,NULL    
     ,NULL    
     ,NULL    
     ,NULL    
     ,NULL    
     ,NULL    
     ,NULL    
     ,NULL    
     ,0    
     ,0    
     ,0    
     ,NULL    
     ,NULL    
     ,NULL    
     ,0    
     ,NULL    
     ,NULL    
     ,NULL    
     ,0    
     ,NULL    
     ,@CreatedOn_LDACTV_1    
    
    SELECT @evntMessage_1 = isnull(EVNT_Description, '')    
    FROM #tblEventDescrb_1    
    
    SELECT @evntMessage_1    
    
    IF (@evntMessage_1 <> '')    
    BEGIN    
     EXEC UspSaveLeadActivity_withid @LeadID_LDACTV_1    
      ,@UserID_LDACTV_1    
      ,@ParentID_LDACTV_1    
      ,@evntMessage_1    
      ,'Notes edited'    
      ,'tbl_LeadNotes'    
      ,@nid    
    END    
   END    
  END TRY    
    
  BEGIN CATCH    
   EXEC usp_insertErrorInfo    
  END CATCH    
    
  IF OBJECT_ID('tempdb..#tblEventDescrb_1') IS NOT NULL -- Check for table existence              
  BEGIN    
   DROP TABLE #tblEventDescrb_1    
  END    
    /* End lead activity  Edit Notes */    
 END    
    
 DECLARE @rowJson NVARCHAR(MAX)    
    
 IF @EventDesc = 0    
 BEGIN    
  SET @rowJson = (    
    select *
  FROM [tbl_LeadNotes](NOLOCK)  
    WHERE NoteID = @nid    
    FOR JSON AUTO    
     ,INCLUDE_NULL_VALUES    
    )    
    
  EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId    
   ,@Activity_type = 'Inst_Notes_Lead'    
   ,@ActionType = 'I'    
   ,@RowJson = @rowJson    
   ,@Table_name = 'tbl_LeadNotes'    
 END    
    
 IF @EventDesc = 1    
 BEGIN    
  SET @rowJson = (    
    select *
  FROM [tbl_LeadNotes](NOLOCK)  
    WHERE NoteID = @nid    
    FOR JSON AUTO    
     ,INCLUDE_NULL_VALUES    
    )    
    
  EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId    
   ,@Activity_type = 'Updt_Notes_Lead'    
   ,@ActionType = 'U'    
   ,@RowJson = @rowJson    
   ,@Table_name = 'tbl_LeadNotes'    
 END    
END 


GO

