/* ============================================================
   Procedure: [dbo].[usp_InsertUpdateUserSegmentAndConditions]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_InsertUpdateUserSegmentAndConditions]
    @Id BIGINT = 0,
    @UserId BIGINT = NULL,
    @SegmentName NVARCHAR(100),
    @ApplyTo NVARCHAR(100),   
    @Conditions NVARCHAR(MAX),
	@SettingJSON NVARCHAR(MAX)
AS
BEGIN

	--DECLARE
	--	@Id BIGINT = 0,
	--	@UserId BIGINT = 335,
	--	@SegmentName NVARCHAR(100) = N'sadf asdfaf',
	--	@ApplyTo NVARCHAR(100) = N'and',   
	--	@Conditions NVARCHAR(MAX) = N'[{"FieldId":1,"FieldName":"Title","FieldText":"Title","OperatorId":1,"OperatorDataType":"VARCHAR","OperatorText":"Contain","OperatorSymbol":"like","ValuePlaceHolder":"''%value%''","FieldValue":"asfdafaf"}]',
	--	@SettingJSON NVARCHAR(MAX) =N'{"Id":0,"SegmentName":"sadf asdfaf","LogicalOperator":"and","Conditions":[{"FieldId":1,"FieldName":"Title","FieldText":"Title","OperatorId":1,"OperatorDataType":"VARCHAR","OperatorText":"Contain","OperatorSymbol":"like","ValuePlaceHolder":"''%value%''","FieldValue":"asfdafaf"}]}'

	
    DECLARE @ParentId BIGINT = 0;
    SELECT TOP 1 @ParentId = ISNULL(ParentId, User_ID) FROM User_Detail WITH (NOLOCK) WHERE User_ID = @UserId;

	DECLARE @Status int = 0, @Message nvarchar(255) = 'Invalid Operation', @Description nvarchar(max) = null, @IsValid bit = 1

    BEGIN TRY

        BEGIN TRANSACTION;

        IF EXISTS (SELECT 1  FROM tbl_UserSegments(NOLOCK) WHERE SegmentName = @SegmentName  AND ParentId = @ParentId AND @Id = 0)
        BEGIN
            SELECT @IsValid = 0
            SELECT @Status = 0, @Message = 'SegmentName must be unique'
        END

        IF(@IsValid = 1)
        BEGIN
        
			DECLARE @SegmentID BIGINT;

			IF(@Id = 0)
			BEGIN
				INSERT INTO tbl_UserSegments (ParentId, UserId, SegmentName, ApplyTo, CreatedBy, Status, SettingJSON)
				VALUES (@ParentId, @UserId, @SegmentName, @ApplyTo, @UserId, 'active', @SettingJSON);
				SET @SegmentID = SCOPE_IDENTITY();
			END
			ELSE
			BEGIN
				UPDATE tbl_UserSegments SET 
					ParentId = @ParentId, UserId = @UserId, SegmentName = @SegmentName,
					ApplyTo = @ApplyTo, UpdatedAt = GETDATE(), UpdatedBy = @UserId, Status = 'active',
					SettingJSON = @SettingJSON
				WHERE ID = @Id;

				SET @SegmentID = @Id;
			END

			SELECT @SettingJSON = JSON_MODIFY(@SettingJSON, '$.Id', @SegmentID)

			UPDATE  tbl_UserSegments set SettingJSON = @SettingJSON WHERE ID = @SegmentID;


			DECLARE @json NVARCHAR(MAX) = @Conditions;

			DECLARE @tbl_SegmentConditions AS TABLE(
				FieldId bigint, FieldName nvarchar(255), FieldText nvarchar(255), OperatorDataType nvarchar(255), OperatorText nvarchar(255), 
                OperatorSymbol nvarchar(255), ValuePlaceHolder nvarchar(255), FieldValue nvarchar(255), SegmentId bigint, ParentId bigint, CreatedBy bigint, 
                CreatedOn datetime default getdate(), UpdateOn datetime default getdate(), UpdateBy bigint
			)

			INSERT INTO @tbl_SegmentConditions( FieldName, FieldText, OperatorDataType, 
				OperatorText, OperatorSymbol, ValuePlaceHolder, FieldValue, SegmentId, ParentId, CreatedBy, UpdateBy, FieldId )
			SELECT FieldName, FieldText,  OperatorDataType, OperatorText, OperatorSymbol, ValuePlaceHolder,
				FieldValue, @SegmentID, @ParentId, @UserId, @UserId, FieldId
			FROM OPENJSON(@json) WITH (
				FieldId BIGINT,
				FieldName NVARCHAR(100),
				FieldText NVARCHAR(100),
				OperatorDataType NVARCHAR(50),
				OperatorText NVARCHAR(50),
				OperatorSymbol NVARCHAR(10),
				ValuePlaceHolder NVARCHAR(100),
				FieldValue NVARCHAR(100)
			)	



			DELETE IC FROM tbl_SegmentConditions IC WHERE SegmentId = @SegmentID
			

			INSERT INTO tbl_SegmentConditions( FieldName, FieldText, OperatorDataType, 
				OperatorText, OperatorSymbol, ValuePlaceHolder, FieldValue, SegmentId, ParentId, CreatedBy, UpdateBy, FieldId, IsActive)
			SELECT FieldName, FieldText,  OperatorDataType, OperatorText, OperatorSymbol, ValuePlaceHolder,
				FieldValue, @SegmentID, @ParentId, @UserId, @UserId, FieldId, 1 FROM @tbl_SegmentConditions

			SELECT @Status = 1, @Message = 'Data saved successfully'
		
        END

        COMMIT TRANSACTION;

    END TRY
    BEGIN CATCH
        ROLLBACK TRANSACTION;
		EXEC usp_InsertErrorInfo
		SELECT @Status = 0, @Message = 'Some error occurred. Please contact the administrator or support team.'
    END CATCH

	SELECT @Status AS [Status], @Message AS [Message], @Description AS [Description]
END;



GO

