   Procedure: [dbo].[usp_InsertUpdateWebsiteClientLogo]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_InsertUpdateWebsiteClientLogo]              
@M_ID bigint,                  
@User_ID int,                  
@Type nvarchar(50),                  
@Image_CLogo1 nvarchar(100),                   
@Image_CLogo2 nvarchar(100),  
@Image_CLogo3 nvarchar(100),  
@Image_CLogo4 nvarchar(100),  
@Image_CLogo5 nvarchar(100),  
@Image_CLogo6 nvarchar(100),  
@Image_CLogo7 nvarchar(100),  
@Image_CLogo8 nvarchar(100),  
@Image_CLogo9 nvarchar(100),  
@Image_CLogo10 nvarchar(100),  
@Image_CLogo11 nvarchar(100),  
@Image_CLogo12 nvarchar(100)  
as                 
declare @mid bigint,@rid bigint       
begin        
              
set @rid=(select reseller_id from reseller_detail where m_id=@m_id and user_id=@User_ID)         
        
if exists(select 'x' from   WebSite_Content where M_ID=@rid and  User_ID= @User_ID and Type=@Type)        
begin        
  
 update WebSite_Content  
     
   set ClientLogo1 = case when @Image_CLogo1='' then ClientLogo1 else @Image_CLogo1 end ,  
    ClientLogo2 = case when @Image_CLogo2='' then ClientLogo2 else @Image_CLogo2 end ,  
    ClientLogo3 = case when @Image_CLogo3='' then ClientLogo3 else @Image_CLogo3 end ,  
    ClientLogo4 = case when @Image_CLogo4='' then ClientLogo4 else @Image_CLogo4 end ,  
    ClientLogo5 = case when @Image_CLogo5='' then ClientLogo5 else @Image_CLogo5 end ,  
    ClientLogo6 = case when @Image_CLogo6='' then ClientLogo6 else @Image_CLogo6 end ,  
    ClientLogo7 = case when @Image_CLogo7='' then ClientLogo7 else @Image_CLogo7 end ,  
    ClientLogo8 = case when @Image_CLogo8='' then ClientLogo8 else @Image_CLogo8 end ,  
    ClientLogo9 = case when @Image_CLogo9='' then ClientLogo9 else @Image_CLogo9 end ,  
    ClientLogo10 = case when @Image_CLogo10='' then ClientLogo10 else @Image_CLogo10 end ,  
    ClientLogo11 = case when @Image_CLogo11='' then ClientLogo11 else @Image_CLogo11 end ,  
    ClientLogo12 = case when @Image_CLogo12='' then ClientLogo12 else @Image_CLogo12 end  
     
   where M_ID=@rid and USER_ID = @User_ID and               
   Type=@Type        
  
end         
  
else        
begin              
 insert into WebSite_Content                  
 (M_ID,User_ID,Type,ClientLogo1,ClientLogo2,ClientLogo3,ClientLogo4,ClientLogo5,ClientLogo6,ClientLogo7,ClientLogo8,ClientLogo9,ClientLogo10,ClientLogo11,ClientLogo12)                  
 values                  
 (@rid,@User_ID,@Type,@Image_CLogo1,@Image_CLogo2,@Image_CLogo3,@Image_CLogo4,@Image_CLogo5,@Image_CLogo6,@Image_CLogo7,@Image_CLogo8,@Image_CLogo9,@Image_CLogo10,@Image_CLogo11,@Image_CLogo12)        
 end       
   
 select 'Success'  
    
end 



