/* ============================================================
   Procedure: [dbo].[usp_InsertUserAccountsCRM]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_InsertUserAccountsCRM @ParentID BIGINT
	,@AccountName VARCHAR(250)
	,@UserName VARCHAR(100)
	,@UserID BIGINT
	,@CreatedBy BIGINT
AS
BEGIN
	DECLARE @pid BIGINT = (
			SELECT parentid
			FROM user_detail(NOLOCK)
			WHERE user_id = @CreatedBy
			)

	DROP TABLE

	IF EXISTS #userid
		SELECT user_id
		INTO #userid
		FROM user_detail(NOLOCK)
		WHERE parentid = @pid

	INSERT INTO UserAccounts (
		-- ID -- this column value is auto-generated  
		ParentID
		,AccountName
		,UserName
		,UserID
		,CreatedOn
		,CreatedBy
		)
	SELECT @ParentID
		,@AccountName
		,@UserName
		,@UserID
		,GETDATE()
		,@CreatedBy
	WHERE @userid NOT IN (
			SELECT user_id
			FROM #userid
			)

	DROP TABLE

	IF EXISTS #userid
		DECLARE @ID BIGINT = SCOPE_IDENTITY();

	SELECT 'Success'

	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM UserAccounts(NOLOCK)
			WHERE ID = @ID
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @CreatedBy
		,@Activity_type = 'Inst_UsrAccnt_Sttng'
		,@ActionType = 'I'
		,@RowJson = @rowJson
		,@Table_name = 'UserAccounts'
END



GO

