         @UnsubscribeShortURL,              
         @Tags,              
         @IsRunAfter,              
         @IsSchedule,              
         @ScheduleID,              
           
         --@NextExecuteDateTime,              
         dbo.[fn_getISTtimefromusertime](@ParentID,@NextExecuteDateTime),  
         @IsActive,              
         GETDATE(),              
         @Createdby,              
           
         --@ExpiryDate,  
         dbo.[fn_getISTtimefromusertime](@ParentID,@ExpiryDate),  
                       
         @EventsName,              
         @ApplicabilityGroup,              
         @ExclusionsGroup,              
         @NotificationEmail,              
         @SuccessNotificationEmail,              
         @FailureNotificationEmail,              
         @IsRecurring,              
         @IsEnding,              
         @TemplateGroupSequence,              
         @IsNeverExpire,              
         @RunAfterHr,              
         @RunAfterMin,              
         --@StartDate,              
         dbo.[fn_getISTtimefromusertime](@ParentID,@StartDate),  
         @IsSurplusExclusions ,          
         @MediumSMSORMail,    
         isnull(nullif(@FromMailID,''),'contactus@email19.in')             
       )                
                   
                   
                   
     DECLARE @CID BIGINT = @@identity       
    
  if (select isschedule from UserCampaignMaster where id=@cid)=1  
  begin  
  create table #temp(campaignid bigint,nextexecution datetime)  
  insert into #temp(campaignid,nextexecution)  
  exec usp_getNextScheduleDate @cid  
  update u set NextExecuteDateTime=dbo.fn_getISTtimefromusertime(@Createdby,isnull(nextexecution,getdate())) from UserCampaignMaster u join #temp t on u.id=t.campaignid  
  where u.id=@CID  
  drop table #temp  
  end           
                   
  declare @lnkct int    
     select @lnkct= COUNT(*) from @tbl    
     if @lnkct >0    
     insert into dbo.Link_smsurl_Campaign (CampaignId, longurl, short_url, parentid, page_nm)    
     select @CID, long_url, short_url,@ParentID, 'Campaign  SMS' from @tbl                                  
                   
     INSERT INTO UserCampaignSettings              
       (              
         NAME,              
         UserID,              
         IsEditable,              
         IsActive,              
         CreatedDate,              
         ModifiedDate,              
         ModifiedBy,              
         UserCampaignMasterID              
       )              
     VALUES              
       (              
         @CampaignName,              
         @ParentID,              
         0,              
         1,              
         GETDATE(),              
         GETDATE(),              
         @createdby,              
         @CID              
       )                
                   
                   
                   
     DECLARE @CampaignID BIGINT = (              
                 SELECT TOP 1 ucs.CampaignID      
                 FROM   UserCampaignSettings ucs              
                 WHERE  ucs.Name = @CampaignName              
                        AND ucs.UserID = @ParentID              
             )                
                   
                   
                   
     INSERT INTO UserSearchList              
       (              
         ParentID,              
         SearchName,              
         SearchType,              
         Medium,              
         Source,              
         Campaign,              
         CurrentlyAssignedTo,              
         FollowUpStatus,              
         IsPredefined,              
         IsResponse,              
         IsUnsubscribe,              
         IsSearch,              
         IsCustom,              
         CreatedOn,              
         CreatedBy              
       )              
     VALUES              
       (              
         @ParentID,              
         'Response - ' + @CampaignName,              
         'AL',              
         0,              
         0,              
         @CampaignID,              
         0,              
         0,              
         0,              
 1,              
         0,              
         0,              
         0,              
         GETDATE(),              
         @createdby              
       )                
                   
                   
                   
     --INSERT INTO UserSearchList              
     --  (              
     --    ParentID,              
     --    SearchName,              
     --    SearchType,              
     --    Medium,              
     --    Source,              
     --    Campaign,              
     --    CurrentlyAssignedTo,              
     --    FollowUpStatus,              
     --    IsPredefined,              
     --    IsResponse,              
     --    IsUnsubscribe,              
     --    IsSearch,              
     --    IsCustom,              
     --    CreatedOn,              
     --    CreatedBy              
     --  )              
     --VALUES              
     --  (              
     --    @ParentID,              
     --    'Unsubscribe - ' + @CampaignName,              
     --    'AL',              
     --    0,              
     --    0,              
     --    @CampaignID,              
     --    0,              
     --    0,              
     --    0,              
     --    0,              
     --    1,              
     --    0,              
     --    0,              
     --    GETDATE(),              
     --    @createdby              
     --  )                
                   
                   
              
     SELECT 'Success'              
 END              
END      
    
    


GO

