CREATE   PROCEDURE [dbo].[usp_InsertUserCampaignMaster_voice]                      
 @ParentID BIGINT,                      
 @CampaignName VARCHAR(500),                      
 @IsEventBased BIT,                      
 @IsScheduled BIT,                      
 @Applicabilty VARCHAR(500),                      
 @ExclusionsNumber VARCHAR(MAX),                      
 @Exclusions VARCHAR(500),                      
 @InclusionsNumber VARCHAR(MAX),                      
 @AccountUsed BIGINT,                      
 @SenderID VARCHAR(500),                      
 @Message NVARCHAR(2000),                      
 @TemplateID BIGINT,                      
 @TemplateGroupID BIGINT,                      
 @IsUnicode BIT,                      
 @MailReplyTo NVARCHAR(500),                      
 @MailSubject NVARCHAR(500),                      
 @MailContent NVARCHAR(MAX),                      
 @TrackResponse NVARCHAR(500),                      
 @TrackShortURL NVARCHAR(100),                      
 @UnsubscribePage NVARCHAR(500),                      
 @UnsubscribeShortURL NVARCHAR(100),                      
 @Tags VARCHAR(500),                      
 @IsRunAfter BIT,                      
 @IsSchedule BIT,                      
 @ScheduleID BIGINT,                      
 @NextExecuteDateTime VARCHAR(50),                      
 @IsActive BIT,                      
 @Createdby BIGINT,                      
 @ExpiryDate VARCHAR(50),                      
 @EventsName VARCHAR(500),                      
 @ApplicabilityGroup VARCHAR(500),                      
 @ExclusionsGroup VARCHAR(500),                      
 @NotificationEmail VARCHAR(250),                      
 @SuccessNotificationEmail VARCHAR(250),                      
 @FailureNotificationEmail VARCHAR(250),                      
 @IsEnding BIT,                      
 @IsRecurring BIT,                      
 @TemplateGroupSequence INT,                      
 @IsNeverExpire BIT,                      
 @RunAfterHr VARCHAR(10),                      
 @RunAfterMin VARCHAR(10),                      
 @StartDate VARCHAR(50),                      
 @IsSurplusExclusions BIT,                  
 @MediumSMSORMail  varchar(50),            
 @FromMailID nvarchar(500),                        
 @route varchar(10),        
 @didno varchar(20),         
 @appid bigint,         
 @duration bigint                   
        
AS                      
BEGIN                      
 IF NOT EXISTS (                      
        SELECT 'x'                      
        FROM   UserCampaignMaster AS ucm                      
        WHERE  ucm.ParentID = @ParentID                      
               AND ucm.CampaignName = @CampaignName                      
    )                      
 BEGIN                      
     IF (@ExpiryDate = '')                      
     BEGIN                      
         SET @ExpiryDate = NULL                      
     END                        
                           
                           
                           
     IF (@StartDate = '')                      
     BEGIN                      
         SET @StartDate = CAST(GETDATE() AS VARCHAR)                      
     END                        
                           
                          
   if dbo.[fn_getISTtimefromusertime](@ParentID,@NextExecuteDateTime) < getdate()            
      begin            
      set @nextexecutedatetime=dateadd(ss,15,getdate())            
      end            
        
     INSERT INTO UserCampaignMaster                      
       (                      
         ParentID,                      
         CampaignName,                      
         IsEventBased,                      
         IsScheduled,                      
         Applicabilty,                      
         ExclusionsNumber,                      
         Exclusions,                      
         InclusionsNumber,                      
         AccountUsed,                      
         SenderID,                      
         [Message],                      
         TemplateID,                      
         TemplateGroupID,                      
         IsUnicode,                      
         MailReplyTo,                      
         MailSubject,      
         MailContent,                      
         TrackResponse,                      
         TrackShortURL,                      
         UnsubscribePage,                      
         UnsubscribeShortURL,                      
         Tags,                      
         IsRunAfter,                      
         IsSchedule,                      
         ScheduleID,                      
         NextExecuteDateTime,          
         IsActive,                      
         CreatedOn,                      
         Createdby,                      
         ExpiryDate,                      
         EventsName,                      
         ApplicabiltyGroupList,                      
         ExclusionsGroupList,                      
  NotificationMail,                      
         SuccessNotificationEmail,                      
         FailureNotificationEmail,                      
         IsRecurring,                      
         IsEnding,                      
         TemplateGroupSequence,                      
         IsNeverExpire,             
         RunAtHours,                      
         RunAtMin,                      
         StartDate,                      
         IsSurplusExclusions,                  
         Medium,            
         FromMailID,        
         route, didno, appid, duration                   
       )                      
     VALUES                      
       (                      
         @ParentID,                      
         @CampaignName,                      
         @IsEventBased,                      
         @IsScheduled,                      
         @Applicabilty,                      
         @ExclusionsNumber,                    
         @Exclusions,                      
         @InclusionsNumber,                      
         @AccountUsed,                      
         @SenderID,                      
         @Message,                      
         @TemplateID,                      
         @TemplateGroupID,                      
         @IsUnicode,                      
         @MailReplyTo,                      
         @MailSubject,                      
         @MailContent,                      
         @TrackResponse,                      
         @TrackShortURL,                      
         @UnsubscribePage,                      
         @UnsubscribeShortURL,                      
         @Tags,                      
         @IsRunAfter,                      
         @IsSchedule,                      
         @ScheduleID,                      
                   
         --@NextExecuteDateTime,                      
         dbo.[fn_getISTtimefromusertime](@ParentID,@NextExecuteDateTime),          
         @IsActive,                      
         GETDATE(),                      
         @Createdby,                      
                   
        -- @ExpiryDate,          
         dbo.[fn_getISTtimefromusertime](@ParentID,@ExpiryDate),          
                               
         @EventsName,                      
         @ApplicabilityGroup,                      
         @ExclusionsGroup,                      
         @NotificationEmail,                      
         @SuccessNotificationEmail,                      
         @FailureNotificationEmail,                      
         @IsRecurring,                      
         @IsEnding,                      
         @TemplateGroupSequence,                      
         @IsNeverExpire,                      
         @RunAfterHr,                      
         @RunAfterMin,                      
         --@StartDate,                      
         dbo.[fn_getISTtimefromusertime](@ParentID,@StartDate),          
         @IsSurplusExclusions ,                  
         @MediumSMSORMail,            
         isnull(nullif(@FromMailID,''),'contactus@email19.in'),        
         @route, @didno, @appid, @duration                   
                    
       )                        
                           
                           
                           
     DECLARE @CID BIGINT = @@identity               
            
  if (select isschedule from UserCampaignMaster where id=@cid)=1          
  begin          
  create table #temp(campaignid bigint,nextexecution datetime)          
  insert into #temp(campaignid,nextexecution)          
  exec usp_getNextScheduleDate @cid          
  update u set NextExecuteDateTime=dbo.fn_getISTtimefromusertime(@Createdby,isnull(nextexecution,getdate())) from UserCampaignMaster u join #temp t on u.id=t.campaignid          
  where u.id=@CID          
  drop table #temp          
  end                   
     INSERT INTO UserCampaignSettings                      
       (                      
         NAME,                      
         UserID,                      
         IsEditable,                      
         IsActive,                      
         CreatedDate,                      
         ModifiedDate,                      
         ModifiedBy,                      
         UserCampaignMasterID                  
       )                      
     VALUES                      
       (                      
         @CampaignName,                      
         @ParentID,                      
         0,                      
         1,                      
         GETDATE(),                      
         GETDATE(),                      
         @createdby,                      
         @CID                      
       )                        
     DECLARE @CampaignID BIGINT = (                      
                 SELECT TOP 1 ucs.CampaignID              
                 FROM   UserCampaignSettings ucs                      
                 WHERE  ucs.Name = @CampaignName                      
                        AND ucs.UserID = @ParentID                      
             )                        
 --    INSERT INTO UserSearchList                      
 --      (                      
 --        ParentID,                      
 --        SearchName,                      
 --        SearchType,                      
 --        Medium,                      
 --        Source,                      
 --        Campaign,                      
 --        CurrentlyAssignedTo,                      
 --        FollowUpStatus,                      
 --        IsPredefined,                      
 --        IsResponse,                      
 --        IsUnsubscribe,                      
 --        IsSearch,                      
 --        IsCustom,                      
 --        CreatedOn,                      
