/* ============================================================
   Procedure: [dbo].[usp_InsertUserCampaignMaster_voice_FromTRGCmpgn]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_InsertUserCampaignMaster_voice_FromTRGCmpgn] (
	@UserID BIGINT
	,@TRGCampaignID BIGINT
	,@AccountUsed BIGINT
	,@IsActive BIT
	,@route VARCHAR(10)
	,@didno VARCHAR(20)
	,@appid BIGINT
	,@duration BIGINT
	,@TimeBeforeEvent INT
	,@TimeUnit NVARCHAR(20)
	)
AS
BEGIN
	DECLARE @ParentID BIGINT = 0
	DECLARE @CampaignName NVARCHAR(200) = ''
	DECLARE @EventID INT = 0
	DECLARE @Applicability NVARCHAR(max) = ''

	SELECT TOP 1 @ParentID = isnull(ParentID, User_ID)
	FROM User_Detail(NOLOCK)
	WHERE User_ID = @UserID


	   if(isnull(@ParentID,0) = 0 or isnull(@UserID,0) = 0 )
	    begin
		     select 'May be Session expired: unexpected userid & Parentid value' as Status , '0' as ID        
		     goto Label1  
		end     


	SELECT TOP 1 @CampaignName = (CAST(isnull(cname, '') AS NVARCHAR) + '_Voice')
		,@EventID = isnull(eventid, 0)
		,@Applicability = isnull(Audience, '')
	FROM triggeredcampaigns(NOLOCK)
	WHERE id = @TRGCampaignID

	--if(@EventID not in (152,153,154,155))        
	--Begin        
	--    set @TimeBeforeEvent = null        
	--    set @TimeUnit = null        
	--End        
	IF (rtrim(ltrim(@TimeUnit)) = '')
	BEGIN
		SET @TimeBeforeEvent = NULL
		SET @TimeUnit = NULL
	END

	IF NOT EXISTS (
			SELECT 'x'
			FROM UserCampaignMaster AS ucm
			WHERE ucm.ParentID = @ParentID
				AND ucm.CampaignName = @CampaignName
			)
	BEGIN
		DECLARE @ExpiryDate NVARCHAR(50) = ''
		DECLARE @StartDate NVARCHAR(50) = ''
		DECLARE @NextExecuteDateTime NVARCHAR(50) = dateadd(ss, 5, getdate())

		IF (@ExpiryDate = '')
		BEGIN
			SET @ExpiryDate = NULL
		END

		--IF (@StartDate = '')
		--BEGIN
		--	SET @StartDate = CAST(GETDATE() AS NVARCHAR)
		--END

		   IF(isnull(@StartDate,'') = '')                                              
			 BEGIN                                              
				 SET @StartDate = CAST(GETDATE() AS nvarchar)                                              
			 END
			 else
			  begin
				 SET @StartDate = dbo.[fn_getISTtimefromusertime](@ParentID,@StartDate);
			  end



		INSERT INTO UserCampaignMaster (
			ParentID
			,CampaignName
			,IsEventBased
			,IsScheduled
			,Applicabilty
			,ExclusionsNumber
			,Exclusions
			,InclusionsNumber
			,AccountUsed
			,SenderID
			,[Message]
			,TemplateID
			,TemplateGroupID
			,IsUnicode
			,MailReplyTo
			,MailSubject
			,MailContent
			,TrackResponse
			,TrackShortURL
			,UnsubscribePage
			,UnsubscribeShortURL
			,Tags
			,IsRunAfter
			,IsSchedule
			,ScheduleID
			,NextExecuteDateTime
			,IsActive
			,CreatedOn
			,Createdby
			,ExpiryDate
			,EventsName
			,ApplicabiltyGroupList
			,ExclusionsGroupList
			,NotificationMail
			,SuccessNotificationEmail
			,FailureNotificationEmail
			,IsRecurring
			,IsEnding
			,TemplateGroupSequence
			,IsNeverExpire
			,RunAtHours
			,RunAtMin
			,StartDate
			,IsSurplusExclusions
			,Medium
			,FromMailID
			,route
			,didno
			,appid
			,duration
			,eventid
			,TimeBeforeEvent
			,TimeUnit
			)
		VALUES (
			@ParentID
			,@CampaignName
			,1
			,-- @IsEventBased,                            
			0
			,--@IsScheduled,                            
			@Applicability
			,''
			,--@ExclusionsNumber,                          
			''
			,--@Exclusions,                            
			''
			,--@InclusionsNumber,                            
			@AccountUsed
			,''
			,--@SenderID,                            
			''
			,--@Message,                            
			0
			,--@TemplateID,                            
			0
			,--@TemplateGroupID,                            
			0
			,--@IsUnicode,                            
			''
			,--@MailReplyTo,                            
			''
			,--@MailSubject,                            
			''
			,--@MailContent,                            
			''
			,--@TrackResponse,                            
			''
			,--@TrackShortURL,                            
			''
			,--@UnsubscribePage,                            
			''
			,--@UnsubscribeShortURL,                            
			''
			,--@Tags,                            
			1
			,--@IsRunAfter,                            
			0
			,--@IsSchedule,                            
			0
			,--@ScheduleID,                            
			--@NextExecuteDateTime,                            
			dbo.[fn_getISTtimefromusertime](@ParentID, @NextExecuteDateTime)
			,@IsActive
			,GETDATE()
			,@UserID
			,
			-- @ExpiryDate,                
			dbo.[fn_getISTtimefromusertime](@ParentID, @ExpiryDate)
			,''
			,--@EventsName,                            
			''
			,--@ApplicabilityGroup,                            
			''
			,--@ExclusionsGroup,                            
			''
			,--@NotificationEmail,                            
			''
			,--@SuccessNotificationEmail,                            
			''
			,--@FailureNotificationEmail,                            
			0
			,--@IsRecurring,                            
			1
			,--@IsEnding,                            
			1
			,--@TemplateGroupSequence,                            
			1
			,--@IsNeverExpire,                            
			''
			,--@RunAfterHr,                            
			''
			,--@RunAfterMin,                            
			 @StartDate      
			--dbo.[fn_getISTtimefromusertime](@ParentID, @StartDate)
			,0
			,--@IsSurplusExclusions ,                        
			'VOICE'
			,--@MediumSMSORMail,                  
			''
			,--isnull(nullif(@FromMailID,''),'contactus@email19.in'),              
			@route
			,@didno
			,@appid
			,@duration
			,@EventID
			,@TimeBeforeEvent
			,@TimeUnit
			)

		DECLARE @CID BIGINT = @@identity

		UPDATE triggeredcampaigns
		SET voicecampaignid = @CID
		WHERE id = @TRGCampaignID

		--       INSERT INTO UserCampaignSettings                            
		--      (                            
		--        NAME,            
		--        UserID,                            
		--        IsEditable,                            
		--        IsActive,                            
		--        CreatedDate,                            
		--        ModifiedDate,                            
		--        ModifiedBy,                            
		--        UserCampaignMasterID                        
		--      )                            
		--    VALUES                            
		--      (                            
		--        @CampaignName,                            
		--        @ParentID,                            
		--        0,                            
		--        1,                            
		--        GETDATE(),                            
		--GETDATE(),                            
		--        @UserID,                            
		--        @CID                            
		--      )                              
		--    DECLARE @CampaignID BIGINT = (                            
		--                SELECT TOP 1 ucs.CampaignID                    
		--                FROM   UserCampaignSettings ucs                            
		--                WHERE  ucs.Name = @CampaignName                            
		--                       AND ucs.UserID = @ParentID                            
		--            )                              
		--INSERT INTO UserSearchList                            
		--  (                            
		--    ParentID,                            
		--    SearchName,                            
		--    SearchType,                            
		--    Medium,                            
		--    Source,                            
		--    Campaign,                            
		--    CurrentlyAssignedTo,                            
		--    FollowUpStatus,                            
		--    IsPredefined,                            
		--    IsResponse,                            
		--    IsUnsubscribe,                            
		--    IsSearch,                            
		--    IsCustom,                            
		--    CreatedOn,                            
		--    CreatedBy                            
		--  )                            
		--VALUES                            
		--  (                            
		--    @ParentID,                            
		--    'Response - ' + @CampaignName,                            
		--    'AL',                            
		--    0,                            
		--    0,                            
		--    @CampaignID,                            
		--    0,                            
		--    0,                            
		--    0,                            
		--    1,                            
		--    0,                            
		--    0,                            
		--    0,                            
		--    GETDATE(),                            
		--    @UserID                            
		--  )         
		SELECT 'Success' AS STATUS
			,@CID AS ID

		DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM UserCampaignMaster
			WHERE id = @CID
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID
		,@Activity_type = 'Inst_voicebrd_trggrcamp'
		,@ActionType = 'U'
		,@RowJson = @rowJson
		,@Table_name = 'UserCampaignMaster'

	END -- end of uppermost if        
	ELSE
	BEGIN
		SELECT 'Campaign Name Already Exists' AS STATUS
			,'0' AS ID
	END

	Label1:

END



GO

/* ============================================================
   Procedure: [dbo].[usp_InsertUserCampaignMaster_voice_FromTRGCmpgn_1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


----------------------------------------
CREATE   PROCEDURE [dbo].[usp_InsertUserCampaignMaster_voice_FromTRGCmpgn_1]      
(      
  @UserID bigint,         
  @TRGCampaignID bigint,                                          
  @AccountUsed BIGINT,      
  @IsActive bit,      
  @route varchar(10),            
  @didno varchar(20),             
  @appid bigint,             
  @duration bigint,    
  @TimeBeforeEvent int,        
  @TimeUnit nvarchar(20),
  @MaxLimit int
)      
as      
Begin      
      begin try
         Declare @ParentID bigint = 0         
         Declare @CampaignName nvarchar(200) = ''          
   Declare @EventID int = 0  
   Declare @ScheduleIdID int = 0 
   Declare @IsScheduled BIT 
    Declare @IsEventBased BIT 

   Declare @Applicability nvarchar(max) = ''         
        
        select  top 1 @ParentID = isnull(ParentID,User_ID) from User_Detail(nolock) where User_ID = @UserID              
        select top 1  @CampaignName = ( CAST(isnull(cname,'') as nvarchar)+ '_Voice')        
        ,@EventID = isnull(eventid,0),@ScheduleIdID = isnull(Schedule,0) , @Applicability = isnull(Audience,'')  from triggeredcampaigns(nolock) where id = @TRGCampaignID       
           
   --if(@EventID not in (152,153,154,155))      
   --Begin      
   --    set @TimeBeforeEvent = null      
   --    set @TimeUnit = null      
   --End      
   IF @ScheduleIdID > 0
BEGIN
    SET @IsScheduled = 1; 
    SET @IsEventBased = 0; 
END
ELSE
BEGIN
    SET @IsScheduled = 0; 
    SET @IsEventBased = 1; 
END
    
    IF NOT EXISTS (                                          
        SELECT 'x'                                          
        FROM   UserCampaignMaster AS ucm                                          
        WHERE  ucm.ParentID = @ParentID                                          
               AND ucm.CampaignName = @CampaignName                                          
             )                                          
         BEGIN           
                 Declare @ExpiryDate nvarchar(50) = ''          
                    Declare @StartDate nvarchar(50) = ''         
                    Declare @NextExecuteDateTime nvarchar(50) = dateadd(ss,5,getdate())         
                                           
      IF (@ExpiryDate = '')                                          
      BEGIN                                          
       SET @ExpiryDate = NULL                                          
      END                                            
                                               
                                               
                                               
      IF (@StartDate = '')                                          
      BEGIN                                          
       SET @StartDate = CAST(GETDATE() AS nvarchar)                                          
      END                                            
        
       INSERT INTO UserCampaignMaster                          
       (                          
         ParentID,                          
         CampaignName,                          
         IsEventBased,                          
         IsScheduled,                          
         Applicabilty,                          
         ExclusionsNumber,                          
         Exclusions,                          
         InclusionsNumber,                          
         AccountUsed,                          
         SenderID,                          
         [Message],                          
         TemplateID,                          
         TemplateGroupID,                          
         IsUnicode,                          
         MailReplyTo,                          
         MailSubject,          
         MailContent,                          
         TrackResponse,                          
         TrackShortURL,                          
         UnsubscribePage,                          
         UnsubscribeShortURL,                          
         Tags,                          
         IsRunAfter,                          
         IsSchedule,                          
         ScheduleID,                          
         NextExecuteDateTime,              
         IsActive,                          
         CreatedOn,                          
