         '',--@Tags,                          
         1,--@IsRunAfter,                          
         @IsScheduled,--@IsSchedule,                          
         @ScheduleIdID,--@ScheduleID,                          
                       
         --@NextExecuteDateTime,                          
         dbo.[fn_getISTtimefromusertime](@ParentID,@NextExecuteDateTime),              
         @IsActive,                          
         GETDATE(),                          
         @UserID,                          
                       
        -- @ExpiryDate,              
         dbo.[fn_getISTtimefromusertime](@ParentID,@ExpiryDate),              
                                   
         '',--@EventsName,                          
         '',--@ApplicabilityGroup,                          
         '',--@ExclusionsGroup,                          
         '',--@NotificationEmail,                          
         '',--@SuccessNotificationEmail,                          
         '',--@FailureNotificationEmail,                          
         0,--@IsRecurring,                          
         1,--@IsEnding,                          
         1,--@TemplateGroupSequence,                          
         1,--@IsNeverExpire,                          
         '',--@RunAfterHr,                          
         '',--@RunAfterMin,                          
         --@StartDate,                          
         dbo.[fn_getISTtimefromusertime](@ParentID,@StartDate),              
         0,--@IsSurplusExclusions ,                      
         'VOICE',--@MediumSMSORMail,                
         '',--isnull(nullif(@FromMailID,''),'contactus@email19.in'),            
         @route,      
   @didno,      
   @appid,      
   @duration,                       
         @EventID,    
         @TimeBeforeEvent,    
         @TimeUnit,
		 @MaxLimit
       )                       
                               
        DECLARE @CID BIGINT = @@identity       
      
  update triggeredcampaigns set  voicecampaignid =  @CID where id = @TRGCampaignID        
      
      
                           
        INSERT INTO UserCampaignSettings                          
       (                          
         NAME,          
         UserID,                          
         IsEditable,                          
         IsActive,                          
