 @RunAfterHr VARCHAR(10),                
 @RunAfterMin VARCHAR(10),                
 @StartDate VARCHAR(50),                
 @IsSurplusExclusions BIT,            
 @MediumSMSORMail  varchar(50),      
 @FromMailID nvarchar(500)                  
AS                
BEGIN                
 IF NOT EXISTS (                
        SELECT 'x'                
        FROM   UserCampaignMaster AS ucm                
        WHERE  ucm.ParentID = @ParentID                
               AND ucm.CampaignName = @CampaignName                
    )                
 BEGIN                
     IF (@ExpiryDate = '')                
     BEGIN                
         SET @ExpiryDate = NULL                
     END                  
                     
                     
                     
     IF (@StartDate = '')                
     BEGIN                
         SET @StartDate = CAST(GETDATE() AS VARCHAR)                
     END                  
                     
                    
   if dbo.[fn_getISTtimefromusertime](@ParentID,@NextExecuteDateTime) < getdate()      
      begin      
      set @nextexecutedatetime=dateadd(ss,15,getdate())      
      end      
            
            
                     
     INSERT INTO UserCampaignMaster                
       (                
         ParentID,                
         CampaignName,                
         IsEventBased,                
         IsScheduled,                
         Applicabilty,                
         ExclusionsNumber,                
         Exclusions,                
         InclusionsNumber,                
         AccountUsed,                
         SenderID,                
         [Message],                
         TemplateID,                
         TemplateGroupID,                
         IsUnicode,                
         MailReplyTo,                
         MailSubject,                
         MailContent,                
         TrackResponse,                
         TrackShortURL,                
         UnsubscribePage,                
         UnsubscribeShortURL,                
         Tags,                
         IsRunAfter,                
         IsSchedule,                
         ScheduleID,                
         NextExecuteDateTime,                
         IsActive,                
         CreatedOn,               
         Createdby,                
         ExpiryDate,                
         EventsName,                
         ApplicabiltyGroupList,                
         ExclusionsGroupList,                
  NotificationMail,                
         SuccessNotificationEmail,                
         FailureNotificationEmail,                
         IsRecurring,                
         IsEnding,                
         TemplateGroupSequence,                
         IsNeverExpire,       
         RunAtHours,                
         RunAtMin,                
         StartDate,                
         IsSurplusExclusions,            
         Medium,      
         FromMailID                
       )                
     VALUES                
       (                
         @ParentID,                
         @CampaignName,                
         @IsEventBased,                
         @IsScheduled,                
         @Applicabilty,                
         @ExclusionsNumber,              
         @Exclusions,                
         @InclusionsNumber,                
         @AccountUsed,                
         @SenderID,                
         @Message,                
         @TemplateID,                
         @TemplateGroupID,                
         @IsUnicode,                
