         @IsRunAfter,                
         @IsSchedule,                
         @ScheduleID,                
             
         --@NextExecuteDateTime,                
         dbo.[fn_getISTtimefromusertime](@ParentID,@NextExecuteDateTime),    
         @IsActive,                
         GETDATE(),                
         @Createdby,                
             
         --@ExpiryDate,    
         dbo.[fn_getISTtimefromusertime](@ParentID,@ExpiryDate),    
                         
         @EventsName,                
         @ApplicabilityGroup,                
         @ExclusionsGroup,                
         @NotificationEmail,                
         @SuccessNotificationEmail,                
         @FailureNotificationEmail,                
         @IsRecurring,                
         @IsEnding,                
         @TemplateGroupSequence,                
         @IsNeverExpire,                
         @RunAfterHr,                
         @RunAfterMin,                
         --@StartDate,                
         dbo.[fn_getISTtimefromusertime](@ParentID,@StartDate),    
         @IsSurplusExclusions ,            
         @MediumSMSORMail,      
         isnull(nullif(@FromMailID,''),'contactus@email19.in')               
       )                  
                     
                     
                     
     DECLARE @CID BIGINT = scope_identity()   

declare @count int=(select COUNT(1) from UserCampaignMaster(nolock) where ParentID=@parentid)
 declare @m_id bigint,@user_login nvarchar(50)
 select @m_id=m_id,@user_login=user_login from user_detail (nolock) where USER_ID=@parentid
 if @m_id=10043 and @count=1
 begin
 declare @description nvarchar(200)='User '+cast(@user_login as nvarchar)+' created a campaign for the first time'
 exec Usp_InsertUserEventDetails 'First Campaign Created',@parentID,@Description,'Usercampaignmaster',@CID 
 end  


       
EXEC usp_updatevoicecampaignroute @CID        
      
  if (select isschedule from UserCampaignMaster where id=@cid)=1    
  begin    
  create table #temp(campaignid bigint,nextexecution datetime)    
  insert into #temp(campaignid,nextexecution)    
  exec usp_getNextScheduleDate @cid    
  update u set NextExecuteDateTime=dbo.fn_getISTtimefromusertime(@Createdby,isnull(nextexecution,getdate())) from UserCampaignMaster u join #temp t on u.id=t.campaignid    
  where u.id=@CID    
  drop table #temp    
  end             
                     
                     
                     
     INSERT INTO UserCampaignSettings                
       (                
         NAME,                
         UserID,                
         IsEditable,                
         IsActive,                
         CreatedDate,                
         ModifiedDate,                
         ModifiedBy,                
         UserCampaignMasterID                
       )                
     VALUES           
       (                
         @CampaignName,                
         @ParentID,                
         0,                
         1,                
         GETDATE(),                
         GETDATE(),                
         @createdby,                
         @CID                
       )                  
                     
                     
                     
     DECLARE @CampaignID BIGINT = (                
                 SELECT TOP 1 ucs.CampaignID        
                 FROM   UserCampaignSettings ucs                
                 WHERE  ucs.Name = @CampaignName                
                        AND ucs.UserID = @ParentID                
             )                  
                     
                     
                     
     INSERT INTO UserSearchList                
       (                
         ParentID,                
         SearchName,                
         SearchType,                
         Medium,                
         Source,                
         Campaign,                
         CurrentlyAssignedTo,                
         FollowUpStatus,                
         IsPredefined,                
         IsResponse,                
         IsUnsubscribe,                
         IsSearch,                
         IsCustom,                
         CreatedOn,                
         CreatedBy                
       )                
     VALUES                
       (                
         @ParentID,                
         'Response - ' + @CampaignName,                
         'AL',                
         0,                
         0,                
         @CID,                
         0,                
         0,                
         0,                
 1,                
         0,                
         0,                
         0,                
         GETDATE(),                
         @createdby                
       )                  
                     
                     
                     
     --INSERT INTO UserSearchList                
     --  (                
     --    ParentID,                
     --    SearchName,                
     --    SearchType,                
     --    Medium,                
     --    Source,                
     --    Campaign,                
     --    CurrentlyAssignedTo,                
     --    FollowUpStatus,                
     --    IsPredefined,                
     --    IsResponse,                
     --    IsUnsubscribe,                
     --    IsSearch,                
     --    IsCustom,                
     --    CreatedOn,                
     --    CreatedBy                
     --  )                
     --VALUES                
     --  (                
     --    @ParentID,                
     --    'Unsubscribe - ' + @CampaignName,                
     --    'AL',                
     --    0,                
     --    0,                
     --    @CampaignID,                
     --    0,                
     --    0,                
     --    0,                
     --    0,                
     --    1,                
     --    0,                
     --    0,                
     --    GETDATE(),                
     --    @createdby                
     --  )                  
                     
                     
                
     SELECT 'Success'                
 END                
END        
      


